window.TARTIB_MAFATIH = {"articles":[{"id":"mf_ar_intro","bookId":"مفاتيح_الجنان","book":"مفاتيح الجنان","section":"","title":"مقدمة الكتاب","blocks":[{"type":"Text","content":"بسم الله الرحمن الرحيم"},{"type":"Text","content":"جَعَلَ الْحَمْدَ مفْتَاحاً لذِكْرِهِ وَخَلَقَ الاشْيَاءَ نَاطِقَةً بحَمْدِه وَشُكرِهِ وَالصَّلاةُ وَالسَّلامُ عَلى نَبِيِّهِ مُحَمَّد الْمُشتَقِّ اسْمُهُ مِنْ اسْمِهِ الَْمحْمُودِ وَعَلى آلهِ الطَّاهِرينَ اُولِي الْمَكارِمِ وَالْجُوِد"},{"type":"Text","content":"وبعد يقول البائس الفقير المتمسّك بأحاديث أهل البيت (عليهم السلام) عبّاس بن محمّد رضا القمّي ختم الله لهما بالحسنى والسّعادة قد سألني بعض الاخوان من المؤمنين أن أراجع كتاب مفتاح الجنان المتداول بين النّاس فأؤلّف كتاباً على غراره خلواً ممّا احتواه ممّا لم أعثر على سنده مقتطفاً منه ما كان له سند يدعمه مضيفاً الى ذلك أدعية وزيارات معتبرة لم ترد في ذلك الكتاب فأجبتهم الى سؤلهم فكان هذا الكتاب وسمّيته «مفاتيح الجنان» ورتّبته على ثلاثة أبواب :"},{"type":"Text","content":"في تعقيب الصلوات ودعوات أيام الاسبوع ، وأعمال ليلة الجمعة وعدة أدعية مشهورة والمناجيات الخمس عشرة وغيرها ويحتوي على عدّة فصُول :"},{"type":"Text","content":"في التعقيبات العامّة"},{"type":"Text","content":"عن كتاب مصباح المتهجّد وغيره فإذا سلّمت وفرغت من الصلاة فقل اللهُ اَكْبَرُ ثلاث مرّات ; رافعاً عند كلّ تكبيرة يديك الى حيال أذنيك ثمّ قل :"},{"type":"Text","content":"لا اِلـهَ إلاَّ اللهُ اِلهاً واحِداً وَنَحْنُ لَهُ مُسْلِمُونَ لا اِلـهَ إلاَّ اللهُ وَلا نَعْبُدُ إلاّ اِيّاهُ مُخْلِصينَ لَهُ الدّينَ وَلَوْ كَرَهَ الْمُشْرِكُونَ لا اِلـهَ اِلاَّ اللهُ رَبُّنا وَرَبُّ آبائنَا الاَْوَّلينَ لا اِلـهَ اِلاَّ اللهُ وَحْدَهُ وَحْدَهُ وَحْدَهُ اَنْجَزَ وَعْدَهُ وَنَصَرَ عَبْدَهُ وَاَعَزَّ جُنْدَهُ وَهَزَمَ الاَْحْزابَ وَحْدَهُ فَلَهُ الْمُلْكُ وَلَهُ الْحَمْدُ يُحْيي وَيُميتُ وَيُميتُ وَيُحْيي وَهُوَ حَىٌّ لا يَمُوتُ بِيَدِهِ الْخَيْرُ وَهُوَ عَلى كُلِّ شَيْء قَديرٌ ثمّ قل : اَسْتَغْفِرُ اللهَ الَّذي لا اِلـهَ اِلاّ هُوَ الْحَيُّ الْقَيُّومُ وَاَتُوبُ اِلَيْهِ ثمّ قل : اَللّـهُمَّ اهْدِني مِنْ عِنْدِكَ وَاَفِضْ عَلَيَّ مِنْ فَضْلِكَ وَانْشُرْ عَلَيَّ مِنْ رَحْمَتِكَ وَاَنْزِلْ عَلَيَّ مِنْ بَرَكاتِكَ سُبْحانَكَ لا اِلـهَ اِلاّ اَنْتَ اغْفِرْ لي ذُنُوبي كُلَّها جَميعاً فَاِنَّهُ لا يَغْفِرُ الذُّنُوبَ كُلَّها جَميعاً اِلاّ اَنْتَ اَللّـهُمَّ اِنّي أسْأَلُكَ مِنْ كُلِّ خَيْر اَحاطَ بِهِ عِلْمُكَ وَاَعُوذُ بِكَ مِنْ كُلِّ شَرٍّ اَحاطَ بِهِ عِلْمُكَ اَللّـهُمَّ اِنّي أسْأَلُكَ عافِيَتَكَ في اُمُوري كُلِّها وأعوذُ بك من خزي الدنيا وعذابِ الآخرةِ وأعوُذُ بِوَجْهِكَ الْكَريمِ وَعِزَّتِكَ الَّتي لا تُرامُ وَقُدْرَتِكَ الَّتي لا يَمْتَنِعُ مِنْها شَيْءٌ مِنْ شَرِّ الدُّنْيا وَالآخِرَةِ وَمِنْ شَرِّ الأوْجاعِ كُلِّها ومن شرِّ كلِّ دابة أنت آخذٌ بناصيتها انّ ربّي على صراط مستقيم وَلا حَوْلَ وَلا قُوَّةَ إلاّ بِاللهِ الْعَلِيِّ الْعَظيمِ تَوَّكَلْتُ عَلَى الْحَيِّ الَّذي لا يَمُوتُ وَالْحَمْدُ للهِِ الَّذى لَمْ يَتَّخِذْ وَلَداً وَلَمْ يَكُنْ لَهُ شَريكٌ فِي الْمُلْكِ وَلَمْ يَكُنْ لَهُ وَلِيٌّ مِنَ الذُّلِّ وَكَبِّرْهُ تَكْبيراً ثمّ سبّح تسبيح الزّهراء (عليها السلام) وقل عشر مرّات قبل أن تتحرّك من موضعك : اَشْهَدُ اَنْ لا اِلـهَ اِلاَّ اللهُ وَحْدَهُ لا شَريكَ لَهُ اِلهاً واحِداً أحَداً فَرْداً صَمَداً لَمْ يَتَّخِذْ صاحِبَةً وَلا وَلَداً أقول: روي لهذا التهليل فضل كثير سيّما اذا عقب به صلاة الصّبح والعشاء وإذا قرى عند طلوع الشّمس وغروبها، ثمّ تقول :"},{"type":"Text","content":"سُبْحانَ اللهِ كُلَّما سَبَّحَ اللهَ شَيءٌ وَكَما يُحِبُّ اللهُ اَنْ يُسَبَّحَ وَكَما هُوَ اَهْلُهُ وَكما يَنْبَغي لِكَرَمِ وَجْهِهِ وَعِزِّ جَلالِهِ وَالْحَمْدُ للهِ كُلَّما حَمِدَ اللهَ شَيءٌ وَكَما يُحِبُّ اللهُ اَنْ يُحْمَدَ وَكَما هُوَ اَهْلُهُ وَكَما يَنْبَغي لِكَرَمِ وَجْهِهِ وَعِزِّ جَلالِهِ وَلا اِلـهَ اِلاّ اللهُ كُلَّما هَلَّلَ اللهَ شَيءٌ وَكَما يُحِبُّ اللهُ اَنْ يُهَلَّلَ وَكَما هُوَ اَهْلُهُ وَكَما يَنْبَغي لِكَرَمِ وَجْهِهِ وَعِزِّ جَلالِهِ وَاللهُ اَكْبَرُ كُلَّما كَبَّرَ اللهَ شَيءٌ وَكَما يُحِبُّ اللهُ اَنْ يُكَبَّرَ وَكَما هُوَ اَهْلُهُ وَكَما يَنْبَغي لِكَرَمِ وَجْهِهِ وَعِزِّ جَلالِهِ سُبْحانَ اللهِ وَالْحَمْدُ للهِ وَلا اِلـهَ اِلاَّ اللهُ وَاللهُ اَكْبَرُ عَلى كُلِّ نِعْمَة اَنْعَمَ بِها عَلَىَّ وَعَلى كُلِّ اَحَد مِنْ خَلْقِهِ مِمَّنْ كانَ أوْ يَكُونُ اِلى يَوْمِ الْقِيامَةِ اَللّـهُمَّ اِنّي أسْألُكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد وَأسْأَلُكَ مِنْ خَيْرِ ما أَرْجُو وَخَيْرِ ما لا أرْجُو وَاَعُوذُ بِكَ مِنْ شَرِّ ما أحْذَرُ وَمِنْ شَرِّ ما لا أحْذَرُ ."},{"type":"Text","content":"ثمّ تقرأ سورة الحمد وآية الكرسي وشَهِدَ اللهُ وآية قُلِ اَللّـهُمَّ مالِكِ الْمُلْكِ وآية السّخرة وهي آيات ثلاث من سورة الاعراف أوّلها اِنَّ رَبَّكُمُ اللهُ وآخرها مِنَ الْمُحْسِنينَ ثمّ تقول ثلاثاً : سُبْحانَ رَبِّكَ رَبِّ الْعِزَّةِ عَمّا يَصِفُونَ وَسَلامٌ عَلَى الْمُرْسَلينَ وَالْحَمْدُ للهِ رَبِّ الْعالَمينَ ثم تقول ثلاث مرّات : اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاجْعَلْ لي مِنْ اَمْري فَرَجاً وَمَخْرَجاً وَارْزُقْنى مِنْ حَيْثُ أَحْتَسِبُ وَمِنْ حَيْثُ لا أحْتَسِبُ وهذا دعاء علّمه جبرئيل يوسف (عليه السلام) في السّجن. ثمّ خذ لحيتك بيدك اليمنى وابسط يدك اليسرى الى السّماء وقل سبع مرّات : يا رَبَّ مُحَمَّد وَآلِ مُحَمَّد صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَعَجِّلْ فَرَجَ آلِ مُحَمَّد وقل ثلاثاً وأنت على ذلك الحال : يا ذَا الْجَلالِ وَالاِكْرامِ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَارْحَمْني وَاَجِرْني مِنَ النّارِ ثمّ تقرأ اثنتي عشرة مرّة سورة قُلْ هُوَ اللهُ اَحَدٌ وتقول : اَللّـهُمَّ اِنّي أَسْأَلُكَ بِاسْمِكَ الْمَكْنُونِ الَْمخْزُونِ الطّاهِرِ الطُّهْرِ الْمُبارَكِ وَأسْأَلُكَ بِاْسمِكَ الْعَظيمِ وَسُلْطانِكَ الْقَديمِ يا واهِبَ الْعَطايا وَيا مُطْلِقَ الاُسارى وَيا فَكّاكَ الرِّقابِ مِنَ النّارِ أَسْأَلُكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاْنَ تُعْتِقَ رَقَبَتي مِنَ النّارِ وَاَنْ تُخْرِجَني مِنَ الدُّنْيا سالِماً وَتُدْخِلَنِي الْجَنَّةَ آمِناً وَاَنْ تَجْعَلَ دُعآئي اَوَّلَهُ فَلاحاً وَاَوْسَطَهُ نَجاحاً وَآخِرَهُ صَلاحاً اِنَّكََ أنْتَ عَلاّمُ الْغُيُوبِ ."}],"preview":"بسم الله الرحمن الرحيم","hasTranslate":false},{"id":"mf_ar_2","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الأوّل :","title":"وورد في الصّحيفة العلويّة لتعقيب الفرائض :","blocks":[{"type":"Text","content":"يا مَنْ لا يَشْغَلُهُ سَمْعٌ عن سمع وَيا مَنْ لا يُغَلِّطُهُ السّائِلُونَ وَيا مَنْ لا يُبْرِمُهُ اِلْحاحُ المُلِحِّينَ اَذِقْني بَرْدَ عَفْوِكَ وَحَلاوَةَ رَحْمَتِكَ وَمَغْفِرَتِكَ وَتقول أيضاً : اِلـهي هذه صَلاتي صَلَّيْتُها لا لحاجَة منْكَ اليْها وَلا رَغْبَة مِنْكَ فيها اِلاّ تَعْظيماً وَطاعَةً وَاِجابَةً لَكَ اِلى ما اَمَرْتَني بِهِ الـهي اِنْ كانَ فيها خَلَلٌ اَوْ نَقْصٌ مِنْ رُكُوعِها أوْ سُجُودِها فَلا تؤاخذني وَتَفَضَّلْ عَلَيَّ بِالْقَبُولِ وَالْغُفْرانِ ."},{"type":"Text","content":"وتدعو أيضاً عقيب الصّلوات بهذا الدّعاء الّذي علّمه النّبي (صلى الله عليه وآله وسلم) أمـير المؤمنين للذّاكرة :"},{"type":"Text","content":"سُبْحانَ مَنْ لا يَعْتَدي عَلى أهْلِ مَمْلَكَتِهِ سُبْحانَ مَنْ لا يَأخُذُ اَهْلَ الاَْرْضِ بأَلْوانِ الْعَذابِ سُبْحانَ الرَّؤوُفِ الرَّحيمِ اَللّـهُمَّ اْجَعلْ لي في قَلْبى نُوراً وَبَصَراً وَفَهْماً وَعِلْماً اِنَّكَ عَلى كُلِّ شَي قَديرٌ ."},{"type":"Text","content":"وقال الكفعمي في المِصباح: قُل ثلاث مرّات عقيب الصّلوات :"},{"type":"Text","content":"اُعيذُ نَفْسي وَديني وَاَهْلي وَمالي وَوَلَدي وَاِخْواني في ديني وَما رَزَقَني رَبِّي وَخَواتيمَ عَمَلي وَمَنْ يَعْنيني اَمْرُهُ بِاللهِ الْواحِدِ الاَحَدِ الصَّمَدِ الَّذي لَمْ يَلِدْ وَلَمْ يُولَدْ وَلَمْ يَكُنْ لَهُ كُفواً اَحَدٌ وَبِرَبِّ الْفَلَقِ مِنْ شَرِّ ما خَلَقَ وَمِنْ شَرِّ غاسِق اِذا وَقَبَ وَمِنْ شَرِّ النَّفّاثاتِ فِي الْعُقَدْ وَمِنْ شَرِّ حاسِد اِذا حَسَدَ وَبِرَبِّ النّاسِ مَلِكِ النّاسِ إلـهِ النّاسِ مِنْ شَرِّ الْوَسْواسِ الْخَنّاسِ الَّذى يُوَسْوِسُ في صُدُورِ النّاسِ مِنَ الْجِنَّةِ وَالنّاسِ ."},{"type":"AboutText","content":"وعن خطّ الشّيخ الشّهيد انّ رسُول الله (صلى الله عليه وآله وسلم) قال : من أراد أن لا يطلعه الله يوم القيامة على قبيح اعماله ولا يفتح ديوان سيّئاته فليقل بعد كلّ صلاة :"},{"type":"Text","content":"اَللّـهُمَّ إنَّ مَغْفِرَتَكَ اَرْجى مِنْ عَمَلى وَاِنَّ رَحْمَتِكَ أوْسَعُ مِنْ ذَنْبي اَللّـهُمَّ إن كانَ ذَنبي عِنْدَكَ عَظيماً فَعَفْوُكَ اَعْظَمُ مِنْ ذَنْبي اَللّـهُمَّ إنْ لَمْ اَكُنْ أهْلاً أنْ اَبْلُغَ رَحْمَتُكَ فرحمتك اَهْلٌ اَنْ تَبْلُغَني وَتَسَعَني لاَِنَّها وَسِعَتْ كُلَّ شَيْء بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ ."},{"type":"AboutText","content":"وعن ابن بابويه (رحمه الله) قال : اذا فرغت من تسبيح الزّهراء صلوات الله عليها فقل :"},{"type":"Text","content":"اَللّـهُمَّ اَنْتَ السَّلامُ وَمِنْكَ السَّلامُ وَلَكَ السَّلامُ وَاِلَيْكَ يَعُودُ السَّلامُ سُبْحانَ رَبِّكَ رَبِّ الْعِزَّةِ عَمّا يَصِفُونَ وَسَلامٌ عَلَى الْمُرْسَلينَ وَالْحَمْدُ للهِِ رَبِّ الْعالَمينَ اَلسَّلامُ عَلَيْكَ اَيُّهَا النَّبِيُّ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ السَّلامُ عَلَى الاَْئِمَّةِ الْهادينَ الْمَهْدِيّينَ اَلسَّلامُ عَلى جَميعِ اَنْبِيآءِ اللهِ وَرُسُلِهِ وَمَلائِكَتِهِ اَلسَّلامُ عَلَيْنا وَعَلى عِبادِ اللهِ الصّالِحينَ اَلسَّلامُ عَلى عَلِيٍّ اَميرِ الْمُؤْمِنينَ اَلسَّلامُ عَلَى الْحَسَنِ وَالْحُسَيْنِ سَيِّدَيْ شَبابِ اَهْلِ الْجَنَّةِ اَجْمَعينَ اَلسَّلامُ عَلى عَلِيِّ بْنِ الْحُسَيْنِ زَيْنِ الْعابِدينَ اَلسَّلامُ عَلى مُحَمَّدِ بْنِ عَلِيٍّ باقِرِ عِلْمِ النَّبِيّينَ اَلسَّلامُ عَلى جَعْفَرِ بْنِ مُحَمَّد الصّادِقِ اَلسَّلام عَلى مُوسَى بْنِ جَعْفَر الْكاظِمِ اَلسَّلامُ عَلى عَلِيِّ بْنِ مُوسَى الرِّضا اَلسَّلامُ عَلى مُحَمَّدِ بْنِ عَلِيٍّ الْجَوادِ اَلسَّلامُ عَلى عَلِيِّ بْنِ مُحَمَّد الْهادي اَلسَّلامُ عَلَى الْحَسَنِ بْنِ عَلِيٍّ الزَّكِيِّ الْعَسْكَرِيِ اَلسَّلامُ عَلَى الْحُجَّةِ بْنِ الْحَسَنِ الْقآئِمِ الْمَهْدِيِّ صَلَواتُ اللهِ عَلَيْهِمْ اَجْمَعينَ . ثمّ سل الله ما شئت ."}],"preview":"يا مَنْ لا يَشْغَلُهُ سَمْعٌ عن سمع وَيا مَنْ لا يُغَلِّطُهُ السّائِلُونَ وَيا مَنْ لا يُبْرِمُهُ اِلْحاحُ المُلِحِّينَ اَذِقْني بَرْدَ عَفْوِكَ وَحَلاوَةَ رَحْمَتِكَ وَمَغْفِرَتِك","hasTranslate":false},{"id":"mf_ar_3","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الأوّل :","title":"وقال الكفعمي تقول بعد الصّلوات :","blocks":[{"type":"Text","content":"رَضيتُ بِاللهِ رَبّاً وبِالاِْسْلامِ ديناً وَبِمُحَمَّد صَلَّى اللهُ عَلَيْهِ وآلِهِ نَبِيّاً وَبِعَلِيٍّ اِماماً وَبِالْحَسَنِ وَالْحُسَيْنِ وَعَلِيٍّ وَمُحَمَّد وَجَعْفَر وَمُوسى وَعَلِيٍّ وَمُحَمَّد وَعَلِيٍّ وَالْحَسَنِ وَالْخَلَفِ الصّالِحِ عليهم السلام اَئِمَّةً وَسادَةً وَقادَةً بِهِمْ اَتَولّى وَمِنْ اَعْدآئِهِمْ اَتَبَرَّأُ ثمَّ تَقولُ ثلاثاً : اَللّـهُمَّ اِنّي أَسْأَلُكَ الْعَفْوَ وَالْعافِيَةَ وَالْمُعافاةَ فِي الدُّنْيا وَالاْخِرَةِ ."}],"preview":"رَضيتُ بِاللهِ رَبّاً وبِالاِْسْلامِ ديناً وَبِمُحَمَّد صَلَّى اللهُ عَلَيْهِ وآلِهِ نَبِيّاً وَبِعَلِيٍّ اِماماً وَبِالْحَسَنِ وَالْحُسَيْنِ وَعَلِيٍّ وَمُحَمَّد وَجَعْفَر وَمُوسى","hasTranslate":false},{"id":"mf_ar_4","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الثاني :","title":"في التّعقيبات الخاصّة:","blocks":[{"type":"Text","content":"قل في تعقيب الظّهر كما في المتهجّد :"},{"type":"Text","content":"لا اِلـهَ اِلاَّ اللهُ الْعَظيمُ الْحَليمُ لا اِلـهَ اِلاَّ اللهُ رَبُّ الْعَرْشِ الْكَريمُ اَلْحَمْدُ للهِِ رَبِّ الْعالَمينَ اَللّـهُمَّ اِنّي أَسْأَلُكَ مُوجِباتِ رَحْمَتِكَ وَ عَزائِمَ مَغْفِرَتِكَ وَالْغَنيمَةَ مِنْ كُلِّ بِرٍّ وَالسَّلامَةَ مِنْ كُلِّ اِثْم اَللّـهُمَّ لا تَدَعْ لي ذَنْباً اِلاّ غَفَرْتَهُ وَلا هَمّاً اِلاّ فَرَّجْتَهُ وَلا سُقْماً اِلاّ شَفَيْتَهُ وَلا عَيْباً اِلاّ سَتَرْتَهُ وَلا رِزْقاً اِلاّ بَسَطْتَهُ وَلا خَوْفاً اِلاّ امَنْتَهُ وَلا سُوءاً اِلاّ صَرَفْتَهُ وَلا حاجَةً هِيَ لَكَ رِضاً وَلِيَ فيها صَلاحٌ اِلاّ قَضَيْتَها يآ اَرْحَمَ الرّاحِمينَ أمينَ رَبَّ الْعالَمينَ وتقول عشر مرّات: بِاللهِ اعْتَصَمْتُ وَبِاللهِ اَثِقُ وَعَلَى اللهِ اَتَوَكَّلُ ثمّ تقول: اَللّـهُمَّ اِنْ عَظُمَتْ ذُنُوبي فَأَنْتَ اَعْظَمُ وَاِنْ كَبُرَ تَفْريطي فأَنْتَ اَكْبَرُ وَاِنْ دامَ بُخْلي فَأنْتَ اَجْوَدُ اَللّـهُمَّ اغْفِرْ لي عَظيمَ ذُنُوبي بِعَظيمِ عَفْوِكَ وَكَثيرَ تَفْريطي بِظاهِرِ كَرَمِكَ وَاقْمَعْ بُخْلى بِفَضْلِ جُودِكَ اَللّـهُمَّ ما بِنا مِنْ نِعْمَة فَمِنْكَ لا اِلـهَ اِلاّ اَنْتَ اَسْتَغْفِرُكَ وَاَتُوبُ اِلَيْكَ ."}],"preview":"قل في تعقيب الظّهر كما في المتهجّد :","hasTranslate":false},{"id":"mf_ar_5","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الثاني :","title":"تعقيب صلاة العَصر نقلاً عَن المتهجّد","blocks":[{"type":"Text","content":"اَسْتَغْفِرُ اللهَ الَّذي لا اِلـهَ اِلاّ هُوَ الْحَيُّ الْقَيُّومُ الرَّحْمنُ الرَّحيمُ ذُو الْجَلالِ وَالاِْكْرامِ وَأَسْأَلُهُ اَنْ يَتُوبَ عَلَيَّ تَوْبَةَ عَبْدٍٍِِ ذَليل خاضِع فَقير بائِس مِسْكين مُسْتَكين مُسْتَجير لا يَمْلِكُ لِنَفْسِهِ نَفْعاً وَلا ضَرّاً وَلا مَوْتاً وَلا حَياةً وَلا نُشُوراً ثمّ تقول : اَللّـهُمَّ اِنّي اَعُوذُ بِكَ مِنْ نَفْس لا تَشْبَعُ وَمِنْ قَلْب لا يَخْشَعُ وَمِنْ عِلْمٍ لا يَنْفَعُ وِ مِنْ صلاةٍ لا تُرْفَعُ وَمِنْ دُعآءٍ لا يُسْمَعُ اَللّـهُمَّ اِنّي أَسْأَلُكَ الْيُسْرَ بَعْدَ الْعُسْرِ وَالْفَرَجَ بَعْدَ الْكَرْبِ وَالرَّخاءَ بَعْدَ الشِّدَّةِ اَللّـهُمَّ ما بِنا مِنْ نِعْمَة فَمِنْكَ لا اِلـهَ اِلاّ اَنْتَ اَسْتَغْفِرُكَ وَاَتُوبُ اَلِيْكَ ."},{"type":"AboutText","content":"وعن الصادق (عليه السلام) قال : من استغفر الله تعالى بعد صلاة العصر سبعين مرّة غفر الله له سبعمائة ذنب وروي عن الامام محمّد التّقي (عليه السلام) قال : من قرأ إنا اَنْزَلْنَاهُ فِي لَيْلَةِ الْقَدْرِ بعد العصر عشر مرّات مرّت له على مثل أعمال الخلايق في ذلك اليوم ويستحبّ دعاء العشرات في كلّ صباح ومساء وأفضل أوقاته بعد العصر يوم الجمعة وسيأتي الدّعاء فيما بعد."}],"preview":"اَسْتَغْفِرُ اللهَ الَّذي لا اِلـهَ اِلاّ هُوَ الْحَيُّ الْقَيُّومُ الرَّحْمنُ الرَّحيمُ ذُو الْجَلالِ وَالاِْكْرامِ وَأَسْأَلُهُ اَنْ يَتُوبَ عَلَيَّ تَوْبَةَ عَبْدٍٍِِ ذَليل خاضِ","hasTranslate":false},{"id":"mf_ar_6","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الثاني :","title":"تعقيب صلاة المَغرب عَن مِصْباح المتهجّد","blocks":[{"type":"Text","content":"تقول بعد تسبيح الزّهراء (عليها السلام) : اِنَّ اللهَ وَمَلائِكَتَهُ يُصَلُّون عَلَى النَّبِيِّ يا اَيُّهَا الَّذينَ امَنُوا صَلُّوا عَلَيْهِ وَسَلِّمُوا تَسْليماً اَللّـهُمَّ صَلِّ عَلى مُحَمَّد النَّبِيِّ وَعَلى ذُرِّيَّتِهِ وَعَلى اَهـْلِ بَـيْتِـهِ ثمّ تقول سبع مرّات : بِسْمِ اللهِ الرَّحْمنِ الرَّحيمِ وَلا حَوْلَ وَلا قُوَّةَ اِلاّ بِاللهِ الْعَلِيِّ الْعَظيمِ وثلاثاً : اَلْحَمْدُ للهِِ الَّذي يَفْعَلُ ما يَشاءُ وَلا يَفْعَلُ ما يَشاءُ غَيْرُهُ ثمّ قُل : سُبْحانَكَ لا اِلـهَ اِلاّ اَنْتَ اغْفِرْ لي ذُنُوبي كُلَّها جَميعاً فَاِنَّهُ لا يَغْفِرُ الذُّنُوبَ كُلَّها جَميعاً اِلاّ اَنْتَ ."},{"type":"Text","content":"ثمّ تصلّي نافلة المغرب وهي أربع ركعات بسلامين ولا تتكلّم بينهما بشيء وقال الشّيخ: روي انّه يقرأ في الرّكعة الاُولى سورة قُلْ يا اَيُّهَا الْكافِرُونَ وفي الثّانية قُلْ هُوَ اللهُ اَحَدٌ ويقرأ في الاُخريين ما شاء وروي انّ الإمام علي النّقي (عليه السلام) كان يقرأ في الرّكعة الثّالثة سورة الحمد وأوّل سورة الحديد الى وهُوَ عَليمٌ بِذاتِ الصُّدُور وفي الرّابعة الحمد وآخر سورة الحشر أي من لَوْ اَنْزَلْنا هذا الْقُرْانَ الى آخر السّورِة ، ويستحبّ أن تقول في السّجدة الأخيرة من النّوافل في كلّ ليلة سيّما في ليلة الجمعة سبع مرّات : اَللّـهُمَّ اِنّي أَسْأَلُكَ بِوَجْهِكَ الْكَريمِ وَاسْمِكَ الْعَظيمِ وَمُلْكِكَ الْقَديمِ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِهِ وَاَنْ تَغْفِرَ لي ذَنْبِيَ الْعَظيمَ اِنَّهُ لا يَغْفِرُ الْعَظيمَ اِلاَّ الْعَظيمُ فإذا فرغت من النّافلة فعقّب بما شئت وتقول عشراً : ما شاءَ اللهُ لا قُوَّةَ اِلاّ بِاللهِ اَسْتَغْفِرُ اللهَ ثمّ تقول : اَللّـهُمَّ اِنّي أَسْأَلُكَ مُوجِباتِ رَحْمَتِكَ وَعَزائِمِ مَغْفِرَتِكَ وَالنَّجاةُ مِنَ النّارِ وَمِنْ كُلِّ بِلِيَّة وَالْفَوْزَ بِالْجَنَّةِ وَالرِّضْوانِ في دارِ السَّلامِ وَجَوارِ نَبِيِّكَ مُحَمَّد عَلَيْهِ وَآلِهِ اَلسَّلامُ اَللّـهُمَّ ما بِنا مِنْ نِعْمَة فَمِنْكَ لا اِلـهَ اِلاّ اَنْتَ اَسْتَغْفِرُكَ وَاَتُوبُ اِلَيْكَ."},{"type":"Text","content":"وتُصلّي الغُفيلة بين المغرب والعشاء وهي ركعتان تقرأ بعد الحمد في الاولى : و ذَا النُّونِ اِذْ ذَهَبَ مُغاضِباً فَظَنَّ اَنْ لَنْ نَقْدِرَ عَلَيْهِ فَنادى فِي الظُّلَماتِ اَنْ لا اِلـهَ اِلاّ اَنْتَ سُبْحانَكَ اِنّي كُنْتُ مِنَ الظّالِمينَ فَاسْتَجَبْنا لَهُ وَنَجّيْناهُ مِنَ الْغَمِّ وَكَذلِكَ نُنْجِي الْمُؤْمِنينَ وفي الثّانية : وَعِنْدَهُ مِفاتِحُ الْغَيْبِ لا يَعْلَمُها اِلاّ هُوَ وَيَعْلَمُ ما فِي الْبَّرِ وَالْبَحْرِ وَما تَسْقُطُ مِنْ وَرَقَة اِلاّ يَعْلَمُها وَلا حَبَّة في ظُلِماتِ الاَْرْضِ وَلا رَطْب وَلا يابِس اِلاّ فِي كِتاب مُبين ثمّ تأخذ يديك للقنُوت وتقول : اَللّـهُمَّ اِنّي أَسْأَلُكَ بِمَفاتِحِ الْغَْيِبِ الَّتي لا يَعْلَمُها اِلاّ اَنْتَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِهِ وَاَنْ تَفْعَلَ بي كَذا وَكَذا وتذكر حاجتك عوض هذه الكلمة ثمّ تقول : اَللّـهُمَّ اَنْتَ وَلِيُّ نِعْمَتي وَالْقادِرُ عَلى طَلِبَتي تَعْلَمُ حاجَتي فَأَسْأَلُكَ بِحَقِّ مُحَمَّد وَآلِهِ عَلَيْهِ وَ عليهم السلام لَمّا قَضَيْتَها لي وتسأل حاجتك فقد روي انّ من أتى بهذه الصّلاة وسأل الله حاجته أعطاه الله ما سأل ."}],"preview":"تقول بعد تسبيح الزّهراء (عليها السلام) : اِنَّ اللهَ وَمَلائِكَتَهُ يُصَلُّون عَلَى النَّبِيِّ يا اَيُّهَا الَّذينَ امَنُوا صَلُّوا عَلَيْهِ وَسَلِّمُوا تَسْليماً اَللّـهُمَّ صَلِّ","hasTranslate":false},{"id":"mf_ar_7","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الثاني :","title":"تعقيب صلاة العشاء نقلاً عَن المتهجّد","blocks":[{"type":"Text","content":"اَللّـهُمَّ اِنَّهُ لَيْسَ لي عِلْمٌ بِمَوْضِعِ رِزْقي وَاِنَّما اَطْلُبُهُ بِخَطَرات تَخْطُرُ عَلى قَلْبي فَاَجُولُ فى طَلَبِهِ الْبُلْدانَ فَاَنَا فيما اَنَا طالِبٌ كَالْحَيْرانِ لا اَدْري اَفى سَهْل هَوُ اَمْ في جَبَل اَمْ في اَرْض اَمْ في سَماء اَمْ في بَرٍّ اَمْ في بَحْر وَعَلى يَدَيْ مَنْ وَمِنْ قِبَلِ مَنْ وَقَدْ عَلِمْتُ اَنَّ عِلْمَهُ عِنْدَكَ وَاَسْبابَهُ بِيَدِكَ وَاَنْتَ الَّذي تَقْسِمُهُ بِلُطْفِكَ وَتُسَبِّبُهُ بِرَحْمَتِكَ اَللّـهُمَّ فَصَلِّ عَلى مُحَمَّد وَآلِهِ وَاجْعَلْ يا رَبِّ رِزْقَكَ لي واسِعاً وَمَطْلَبَهُ سَهْلاً وَمَأخَذَهُ قَريباً وَلا تُعَنِّني بِطَلَبِ ما لَمْ تُقَدِّرْ لي فيهِ رِزْقاً فَاِنَّكَ غَنِىٌّ عَنْ عَذابي وَاَنَا فَقيرٌ اِلى رَحْمَتِكَ فَصَلِّ عَلى مُحَمَّد وَآلِهِ وَجُدْ عَلى عَبْدِكَ بِفَضْلِكَ اِنَّكَ ذُو فَضْل عَظيم."},{"type":"AboutText","content":"أقول: هذا من أدعية الرّزق ويستحبّ أيضاً أن يقرأ عقيبَ العشاء سُورة إنا اَنْزَلْنَاهُ سبع مرّات وأن يقرأ في الوتيرة وهي الرّكعتان جالساً بعد العشاء مائة آية من القرآن ويستحبّ أن يعتاض عن المائة آية سُورة اِذا وَقَعَتِ الْواقِعَةُ في ركعة وسورة قُلْ هُوَ اللهُ اَحَدٌ في الرّكعة الأخرى."},{"type":"Text","content":"تعقيب صَلاة الصّبح عَن مِصْباح المتهجّد"},{"type":"Text","content":"اَللّـهُمَّ صَلِّ علَى مُحَمَّد وَآلِ مُحَمَّد وَاهْدِني لِمَا اخْتُلِفَ فيهِ مِنَ الْحَقِّ بِاِذْنِكَ اِنَّكَ تَهْدي مَنْ تَشاءُ اِلى صِراط مُسْتَقيم وتقول عشر مرّات : اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد الاَْوْصِياءِ الرّاضينَ المَرْضِيّينَ بِاَفْضَلِ صَلَواتِكَ وَبارِكْ عَلَيْهِمْ بِاَفْضَلِ بَرَكاتِكَ وَالسَّلامُ عَلَيْهِمْ وَعَلى اَرْواحِهِمْ وَاَجْسادِهِمْ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ وهذه الصّلاة واردة يوم الجمعة أيضاً عصراً بفضل عظيم. وقل أيضاً : اَللّـهُمَّ اَحْيِنى عَلى ما اَحْيَيْتَ عَلَيْهِ عَلِيِّ بْنَ اَبي طالِب وَاَمِتْني عَلى ما ماتَ عَلَيْهِ عَلِيُّ ابن اَبي طالِب (عليه السلام) وقل مائة مرّة : اَسْتَغْفِرُ اللهَ وَاَتُوبُ اِلَيْهِ ومائة مرّة أَسْأَلُ اللهَ الْعافِيَةَ ومائة مرّة : اَسْتَجيرُ بِاللهِ مِنَ النّارِ ومائة مرّة : وَأَسْأَلُهُ الْجَنَّةَ ومائة مرّة : أَسْأَلُ اللهَ الْحُورَ الْعينَ ومائة مرّة : لا اِلـهَ اِلاَّ اللهُ الْمَلِكُ الْحَقُّ الْمُبينُ ومائة مرّة التّوحيد ومائة مرّة : صَلَّى اللهُ عَلى مُحَمَّد وَآلِ مُحَمَّد ومائة مرّة: سُبْحانَ اللهِ وَاَلْحَمْدُ للهِ وَلا اِلـهَ اِلاَّ اللهُ وَاَللهُ اَكْبَرُ وَلا حَوْلَ وَلا قُوَّةَ اِلاّ بِاللهِ الْعَلِيِّ الْعَظيمِ ومائة مرّة : ما شاءَ اللهُ كانَ وَلا حَوْلَ وَلا قُوَّةَ اِلاّ بِاللهِ الْعَلِيِّ الْعَظيمِ ثمّ قل : اَصْبَحْتُ اَللّـهُمَّ مُعْتَصِماً بِذِمامِكَ الْمَنيعِ الَّذي لا يُطاوَلُ وَلا يُحاوَلُ مِنْ شَرِّ كُلِّ غاشِم وَطارِق مِنْ سائِرِ مَنْ خَلَقْتَ وَما خَلَقْتَ مِنْ خَلْقِكَ الصّامِتِ وَالنّاطِقِ في جُنَّة مِنْ كُلِّ مَخُوف بِلِباس سابِغَة وَلاءِ اَهْلِ بَيْتِ نَبِيِّكَ مُحْتَجِباً مِنْ كُلِّ قاصِد لي اِلى اَذِيَّة بِجِدار حَصين الاِْخْلاصِ فِي الاِْعْتِرافِ بِحَقِّهِمْ وَالَّتمَسُّكِ بَحَبْلِهِمْ مُوقِناً اَنَّ الْحَقَّ لَهُمْ وَمَعَهُمْ وَفيهِمْ وَبِهِمْ اُوالي مَنْ والَوْا وَاُجانِبُ مَنْ جانَبُوا فَاَعِذْني اَللّـهُمَّ بِهِمْ مِنْ شَرِّ كُلِّ ما اَتَّقيهِ يا عَظيمُ حَجَزْتُ الاَْعادِيَ عَنّي بِبَديعِ السَّمواتِ وَالاَْرْضِ اِنّا جَعَلْنا مِنْ بَيْنِ اَيْديهِمِ سَدّاً وَمِنْ خَلْفِهِمْ سَدّاً فَاَغْشَيْناهُمْ فَهُمْ لا يُبْصِرُونَ ."},{"type":"Text","content":"وَهذا دُعاء يدعى به في كلّ صباح ومساء وهو دُعاء أمير المؤمنين (عليه السلام) ليلة المبيت وروي في التهذيب انّ من قال بعد فريضة الفجر عشر مرّات : سُبْحانَ اللهِ الْعَظِيمِ وَبِحَمْدِهِ وَلا حَوْلَ وَلا قُوَةَ اِلاّ بِاللهِ الْعَلِيِ الْعَظِيمِ عافاه الله تعالى من العمى والجنون والجذام والفقر والهدم (انهدام الدار) أو الهرم (الخرافة عند الهرم) وروى الكليني عن الصّادق (عليه السلام) انّ من قال بعد فريضة الصّبح وفريضة المغرب سبع مرّات : بِسْمِ اللهِ الرَّحْمـنِ الرّحَيـمِ لا حَوْلَ وَلا قُوَةَ اِلاّ بِاللهِ الْعَلِىِ الْعَظِيمِ دَفع الله عنهُ سَبعين نوعاً من أنواع البلاء أهونها الرّيح والبرص والجنون وإن كان شقيّاً محى من الاشقياء وكتب من السّعداء وروي عنه (عليه السلام) أيضاً للدّينا والآخرة ولوجعِ العَين هذا الدُعاء بعد فريضتي الصّبح والمغرب : اَللّـهُمَّ اِنّي أَسْأَلُكَ بِحَقِّ مُحَمَّد وَآلِ مُحَمَّد عَلَيْكَ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاجْعَلِ النُّورَ في بَصَري وَالْبَصيرَةَ في ديني وَالْيَقينَ في قَلْبي وَالاِْخْلاصَ في عَمَلي وَالسَّلامَةَ في نَفْسي وَالسَّعَةَ في رِزْقي وَالشُّكْرَ لَكَ اَبَداً ما اَبْقَيْتَني ."},{"type":"AboutText","content":"أقول : روى الشيخ ابن فهد في عدّة الداعي عن الرّضا (عليه السلام) انّ من قال عقيب صلاة الصّبح هذا القول ما سأل الله حاجة إلاّ تيسّرت له وكفاه الله ما أهمّه :"},{"type":"Text","content":"بِسْمِ اللهِ وَصَلَّى اللهُ عَلى مُحَمَّد وآلِهِ وَاُفَوِّضُ اَمْريى اِلَى اللهِ اِنَّ اللهَ بَصيرٌ بِالْعِبادِ فَوَقاهُ اللهُ سَيِّئاتِ ما مَكَرُوا لا اِلـهَ إلاّ أَنْتَ سُبْحانَكَ اِنّي كُنْتُ مِنَ الظّالِمينَ فَاسْتَجَبْنا لَهُ وَنَجَّيْناهُ مِنَ الْغَمِّ وَكَذلِكَ نُنْجِي الْمُؤْمِنينَ حَسْبُنَا اللهُ وَنِعْمَ الْوَكيلُ فَاْنَقَلَبُوا بِنِعْمَة مِنَ اللهِ وَفَضْل لَمْ يَمْسَسْهُمْ سُوءٌ ما شاء اللهُ لا حَوْلَ وَلا قُوَّةَ اِلاّ بِالله ما شاءَ اللهُ لا ما شاءَ النّاسُ ما شاءَ اللهُ وَاِنْ كَرِهَ النّاسُ حَسْبِيَ الرَّبُّ مِنَ الْمَرْبُوبينَ حَسْبِيَ الْخالِقُ مِنَ الَْمخْلُوقينَ حَسْبِيَ الرّازِقُ مِنَ الْمَرْزُوقينَ حَسْبِيَ اللهُ رَب الْعالَمينَ حَسْبى مَنْ هُوَ حَسْبي، حَسْبي مَنْ لَمْ يَزَلْ حَسْبي، حَسْبي مَنْ كانَ مُذْ كُنْتُ لَمْ يَزَلْ حَسْبي، حَسْبِيَ اللهُ لااِلـهَ اِلاّ هُوَ عَلَيْهِ تَوَكَّلْتُ وَهُوَ رَبُّ الْعَرْشِ الْعَظيمِ ."},{"type":"AboutText","content":"أقول: حكى شيخنا ثقة الاسلام النّوري نوّر الله مرقده في كتاب دار السّلام عن شيخه المرحوم العالم الرّبانيّ الحاج المولى فتحعليّ السّلطان آبادي (رحمه الله) انّ الأخوند المولى محمّد صادق العراقي كان في غاية الضّيق والعُسرة والضّرّاء ومضى عليهِ كذلك زمان فلم يجد من كربه فرجاً ولا من ضيقه مخرجاً الى أن رأى ليلة في المنام كأنّه في واد يتراءى فيه خيمة عظيمة عليها قبّة فسأل عن صاحبها فقيل فيه الكهف الحصين وغياث المضطرّ المستكين الحجّة القائم المهديّ المنتظر عجّل الله تعالى فرجه فأسرع الذّهاب اليها فلمّا وافاه صلوات الله عليه شكى عنده سوء حاله وسأل عنه دعاء يفرج به همّه ويدفع به غمّه فأحاله (عليه السلام) الى سيّد من ولده والى خيمته فخرج من حضرته ودخل في تلك الخيمة فرأى السّيّد السّند والحبر المعتمد العالم الأمجد المؤيّد جناب السيّد محمّد السّلطان آبادي قاعداً على سجادته مشغولاً بدعائه وقراءته فذكر له بعد السّلام ما أحال عليه حجّة الملك العلاّم فعلّمه دعاء يستكفي به ضيقه ويستجلب به رزقه فانتبه من نومه والدّعاء محفوظ في خاطره فقصد بيت جناب السّيد وكان قبل تلك الرّؤيا نافراً عنه لوجه لا يذكره فلمّا أتاه ودخل عليه رآه كما في النّوم على مُصلاّه ذاكراً ربّه مستغفراً ذنبه فلمّا سلّم عليه أجابه وتبسّم في وجهه كأنّه عرف القضيّة فسأل عنه ما سأل عنه في الرّؤيا فعلّمه من حينه عين ذاك الدّعاء فدعا به في قليل من الزّمان فصبت عليه الدّنيا من كلّ ناحية ومكان وكان المرحوم الحاج المولى فتحعلي (رحمه الله) يثني على السّيد ثناءً بليغاً وقد أدركه في أواخر عمره وتلمّذ عليه شطراً من الزّمان وأمّا ما علّمه السّيد في اليقظة والمنام فثلاثة اُمور :"}],"preview":"اَللّـهُمَّ اِنَّهُ لَيْسَ لي عِلْمٌ بِمَوْضِعِ رِزْقي وَاِنَّما اَطْلُبُهُ بِخَطَرات تَخْطُرُ عَلى قَلْبي فَاَجُولُ فى طَلَبِهِ الْبُلْدانَ فَاَنَا فيما اَنَا طالِبٌ كَالْحَيْرانِ","hasTranslate":false},{"id":"mf_ar_8","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الثاني :","title":"الاوّل : أن يذكر عقيب الفجر سبعين مرّة واضعاً يده على صدره يا فَتَّاحُ","blocks":[{"type":"Text","content":"الثاني : أن يواظب على هذا الدّعاء المروي في الكافي وقد علّمه النبيّ (صلى الله عليه وآله وسلم) رجلاً من أصحابه مُبتلىً بالسّقم والفقر فما لبث أن ذهب عنه السّقم والفقر لا حَوْلَ وَلا قُوَّةَ اِلاّ بِاللهِ تَوَكَّلْتُ عَلَى الْحَيِّ الَّذى لا يَمُوتُ وَالْحَمْدُ للهِ الَّذى لَمْ يَتَّخِذْ وَلَداً وَلَمْ يَكُنْ لَهُ شَريكٌ فِى الْمُلْكِ وَلَمْ يَكُنْ لَهُ وَلِىٌّ مِنَ الذُّلِّ وَكَبِّرْهُ تَكْبيراً ."},{"type":"Text","content":"الثالث : أن يدعو في دبر صلاة الغداة بالدّعاء الّذي رواه ابن فهد ص 8 وينبغي أن يغتنم هذه الأوراد وَيداوم عليها ولا يغفل عن آثارها واعلم انّه يستحبّ سجدة الشّكر عقيب الصّلوات استحباباً اكيداً والدّعوات والاذكار المأثورة فيها كثيرة وقد روي عن الرّضا (عليه السلام) قال : ان شئت فقل فيها مائة مرّة شكراً شكراً وإن شئت فقل مائة مرّة عفواً عفواً وعنه (عليه السلام) قال : أدنى ما يجزي في سجدة الشّكر أن يقول ثلاثاً: شكراً لله واعلم ايضاً انّ لنا أدعية وأذكاراً كثيرة واردة عند طلوع الشّمس وعند غروبها مأثورة عن النّبي (صلى الله عليه وآله وسلم)والائمة الطّاهرين (عليهم السلام) وقد حرضت الآيات والأخبار تحريضاً ورغبت ترغيباً في المحافظة على هاتين السّاعتين ونحن نقتصر هُنا على ذكر عدّة من الادعية المعتبرة ."},{"type":"Text","content":"الاوّل : روى مشايخ الحديث بإسناد مُعتبرة عن الصادق (عليه السلام(انّه قال : فريضة على كلّ مسلم أن يقول قبل طُلوع الشّمس عشراً وقبل غروبها عشراً : لا اِلـهَ اِلاّ اللهُ وَحْدَهُ لا شَريكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ يُحيي وَيُميتُ وَيُميتُ وَيُحْيي وَهُوَ حَيٌّ لا يَمُوتُ بِيَدِهِ الْخَيْر وَهُوَ عَلى كُلِّ شَيء قَديرٌ . وورد في بعض الرّوايات إنّ ذلك يقضى قضاء إذا ترك فإنّه لازم ."},{"type":"Text","content":"الثاني : وروي بطرق مُعتبرة عنه (عليه السلام) ايضاً قل قبل طلُوع الشّمس وقبل غرُوبها عَشر مرّات : اَعُوذُ بِاللهِ السَّميعِ الْعَليمِ مِنْ هَمَزاتِ الشَّياطينِ وَاَعُوذُ باللهِ اَنْ يَحْضُرُونِ اِنَّ اللهَ هُوَ السَّميعُ الْعَليمُ ."},{"type":"Text","content":"الثالث : ايضاً عنه (عليه السلام) قال : ما يمنعكم أن تقولوا في كلّ صباح ومساء ثلاث مرّات :"},{"type":"Text","content":"اَللّـهُمَّ مُقَلِّبَ الْقُلُوبِ وَالاَبْصارِ ثَبِّتْ قَلْبى عَلى دينِكَ وَلاتُزِغْ قَلْبى بَعْدَ اِذْ هَدَيْتَنى وَهْبْ لى مِنْ لَدُنْكَ رَحْمَةً اِنَّكَ اَنْتَ الْوهّابُ وَاَجِرْنى مِنَ النّارِ بِرَحْمَتِكَ اَللّـهُمَّ امْدُدْ لى فى عُمْرى وَاَوْسِعْ عَلَىَّ فى رِزْقى وَانْشُرْ عَلَىَّ رَحْمَتَكَ وَاِنْ كُنْتُ عِنْدَكَ فى اُمِّ الْكِتابِ شَقِيّاً فَاْجَعْلنى سَعيداً فَاِنَّكَ تَمْحُو ما تَشاءُ وَتُثْبِتُ وَعِنْدَكَ اُمُّ الْكِتابِ ."},{"type":"Text","content":"الرابع : ايضاً عنه (عليه السلام) قل في كلّ صباح ومساء :"},{"type":"Text","content":"اَلْحَمدُ للهِ الَّذى يَفْعَلُ ما يَشاءُ وَلا يَفْعَلُ ما يَشاءُ غَيْرُهُ اَلْحَمْدُ للهِ كَما يُحِبُّ اللهُ اَنْ يُحْمَدَ الْحَمْدُ للهِ كَما هُوَ اَهْلُهُ اَللّـهُمَّ اَدْخِلْنى فى كُلِّ خَيْر اَدْخَلْتَ فيهِ مُحَمَّداً وَآلَ مُحَمَّد وَاَخْرِجْنى مِنْ كُلِّ شَرٍّ اَخْرَجْتَ مِنْهُ مُحَمَّداً وَآلَ مُحَمَّد صَلَّى اللهُ عَلى مُحَمَّد وآلِ مُحَمَّد ."},{"type":"Text","content":"الخامس : قل في كلّ صباح ومساء عشر مرّات : سُبْحانَ اللهِ وَاَلْحَمْدُ للهِ وَلا اِلـهَ اِلاَّ اللهُ وَاَللهُ اَكْبَرُ ومن دَعوات الصّباح والمساء دُعاء العَشَرات وسيأتي ذِكرهُ في دَعَواتِ أيّام الاسبُوع نقلاً عن مُلحقات الصّحيفة السّجاديّة ."}],"preview":"الثاني : أن يواظب على هذا الدّعاء المروي في الكافي وقد علّمه النبيّ (صلى الله عليه وآله وسلم) رجلاً من أصحابه مُبتلىً بالسّقم والفقر فما لبث أن ذهب عنه السّقم والفقر لا حَوْلَ وَلا","hasTranslate":false},{"id":"mf_ar_9","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الثالث :","title":"دُعاءُ يَوْمِ الاحَد","blocks":[{"type":"Text","content":"بِسْمِ اللهِ الَّذى لا اَرْجُو اِلاّ فَضْلَهُ وَلا اَخْشى اِلاّ عَدْلَهُ وَلا اَعْتَمِدُ اِلاّ قَوْلَهُ وَلا اُمْسِكُ اِلاّ بِحَبْلِهِ بِكَ اَسْتَجيرُ يا ذَا الْعَفْوِ وَ الرِّضْوانِ مِنَ الظُّلْمِ وَالْعُدْوانِ وَمِنْ غِيَرِ الزَّمانِ وَتَواتُرِ الاَْحْزانِ وَطَوارِقِ الْحَدَثانِ وَمِنِ انْقِضآءِ الْمُدَّةِ قَبْلَ التَّاَهُّبِ وَ الْعُدَّةِ وَاِيّاكَ اَسْتَرْشِدُ لِما فيهِ الصَّلاحُ وَالاِْصْلاحُ وَبِكَ اَسْتَعينُ فيما يَقْتَرِنُ بِهِ النَّجاحُ وَالاِْنْجاحُ وَاِيّاكَ اَرْغَبُ فى لِباسِ الْعافِيَةِ وَتَمامِها وَشُمُولِ السَّلامَةِ وَدَوامِها وَاَعُوذُ بِكَ يا رَبِّ مِنْ هَمَزاتِ الشَّياطينِ وَاَحْتَرِزُ بِسُلْطانِكَ مِنْ جَوْرِ السَّلاطينِ فَتَقَبَّلْ ما كانَ مِنْ صَلاتى وَصَوْمى وَاجْعَلْ غَدى وَما بَعْدَهُ اَفْضَلَ مِنْ ساعَتى وَيَوْمى وَاَعِزَّنى فى عَشيرَتي وَقَوْمى وَاحْفَظْنى فى يَقْظَتى وَنَوْمى فَانْتَ اللهُ خَيْرٌ حافِظاً وَاَنْتَ اَرْحَمُ الرّاحِمينَ اَللّـهُمَّ اِنّى اَبْرَأ اِلَيْكَ فى يَوْمى هذا وَما بَعْدَهُ مِنَ الاْحادِ مِنَ الشِّرْكِ وَالاِْلْحادِ وَاُخْلِصُ لَكَ دُعائى تَعَرُّضاً لِلاِْجابَةِ وَاُقيمُ عَلى طاعَتِكَ رَجاءً لِلاِثابَةِ فَصَلِّ عَلى مُحَمَّد خَيْرِ خَلْقِكَ الدّاعى اِلى حَقِّكَ وَاَعِزَّنى بِعِزِّكَ الَّذى لا يُضامُ وَاحْفَظْنى بِعَيْنِكَ الَّتى لا تَنامُ وَاخْتِمْ بِالاِنْقِطاعِ اِلَيْكَ اَمْرى وَ بِالْمَغْفِرَةِ عُمْرى اِنَّكَ اَنْتَ الْغَفُورُ الرَّحيمُ ."}],"preview":"بِسْمِ اللهِ الَّذى لا اَرْجُو اِلاّ فَضْلَهُ وَلا اَخْشى اِلاّ عَدْلَهُ وَلا اَعْتَمِدُ اِلاّ قَوْلَهُ وَلا اُمْسِكُ اِلاّ بِحَبْلِهِ بِكَ اَسْتَجيرُ يا ذَا الْعَفْوِ وَ الرِّضْوا","hasTranslate":false},{"id":"mf_ar_10","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الثالث :","title":"دُعاءُ يَوْمِ الاثنين","blocks":[{"type":"Text","content":"اَلْحَمْدُ للهِِ الَّذى لَمْ يُشْهِدْ اَحَداً حينَ فَطَرَ السَّمواتِ وَالاَْرْضَ وَلاَاتَّخَذَ مُعيناً حينَ بَرَأ النَّسَماتِ لَمْ يُشارَكْ فِى الاِْلهِيَّةِ وَلَمْ يُظاهَرْ فِي الْوَحْدانِيَّةِ كَلَّتِ الاَْلْسُنُ عَنْ غايَةِ صِفَتِهِ وَالْعُقُولُ عَنْ كُنْهِ مَعْرِفَتِهِ وَتَواضَعَتِ الْجَبابِرَةُ لِهَيْبَتِهِ وَعَنَتِ الْوُجُوهُ لِخَشْيَتِهِ وَانْقادَ كُلُّ عَظيم لِعَظَمَتِهِ فَلَكَ الْحَمْدُ مُتَواتِراً مُتَّسِقاً وَمُتَوالِياً مُسْتَوْسِقاً وَصَلَواتُهُ عَلى رَسُولِهِ اَبَداً وَسَلامُهُ دائِماً سَرْمَداً اَللّـهُمَّ اجْعَلْ اَوَّلَ يَوْمى هذا صَلاحاً وَاَوْسَطَهُ فَلاحاً وَآخِرَهُ نَجاحاً وَاَعُوذُ بِكَ مِنْ يَوْم اوَّلُهُ فَزَعٌ وَاَوسَطُهُ جَزَعٌ وَ آخِرُهُ وَجَعٌ اَللّـهُمَّ اِنّى اَسْتَغْفِرُكَ لِكُلِّ نَذْر نَذَرْتُهُ وَكُلِّ وَعْد وَعَدْتُهُ وَكُلِّ عَهْد عاهَدْتُهُ ثُمَّ لَمْ اَفِ بِهِ وَأَسْأَلُكَ فى مَظالِمِ عِبادِكَ عِنْدى فَاَيَّما عَبْد مِنْ عَبيدِكَ اَوْ اَمَة مِنْ اِمائِكَ كانَتْ لَهُ قِبَلى مَظْلِمَةٌ ظَلَمْتُها اِيّاهُ فى نَفْسِهِ اَوْ فى عِرْضِهِ اَوْ فى مالِهِ اَوْ فى اَهْلِهِ وَوَلَدِهِ اَوْ غيبَةٌ اغْتَبْتُهُ بِها اَوْ تَحامُلٌ عَلَيْهِ بِمَيْل اَوْ هَوىً اَوْ اَنَفَة اَوْ حَمِيَّة اَوْ رِياءاَوْ عَصَبِيَّة غائِباً كانَ اَوْ شاهِداً وَحَيّاً كانَ اَوْ مَيِّتاً فَقَصُرَتْ يَدى وَضاقَ وُسْعى عَنْ رَدِّها اِلَيْهِ وَاْلتَحَلُّلِ مِنْهُ فَأَسْأَلُكَ يا مَنْ يَمْلِكُ الْحاجاتِ وَهِىَ مُسْتَجيبَةٌ لِمَشِيَّتِهِ وَمُسْرِعَةٌ اِلى اِرادَتِهِ اَنْ تُصَلِيَّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاَنْ تُرْضِيَهُ عَنّى بِما شِئْتْ وَتَهَبَ لى مِنْ عِنْدِكَ رَحْمَةً اِنَّهُ لا تَنْقُصُكَ الْمَغْفِرَةُ وَلا تَضُرُّكَ الْمَوْهِبَةُ يا اَرْحَمَ الرّاحِمينَ اَللّـهُمَّ اَوْلِنى فى كُلِّ يَوْم اثْنَيْنِ نِعْمَتَيْنِ مِنْكَ ثِنْتَيْنِ سَعادَةً فى اَوَّلِهِ بِطاعَتِكَ وَنِعْمَةً فى اخِرِهِ بِمَغْفِرَتِكَ يا مَنْ هُوَ الاِْلهُ وَلا يَغْفِرُ الذُّنُوبَ سِواهُ ."}],"preview":"اَلْحَمْدُ للهِِ الَّذى لَمْ يُشْهِدْ اَحَداً حينَ فَطَرَ السَّمواتِ وَالاَْرْضَ وَلاَاتَّخَذَ مُعيناً حينَ بَرَأ النَّسَماتِ لَمْ يُشارَكْ فِى الاِْلهِيَّةِ وَلَمْ يُظاهَرْ فِي ال","hasTranslate":false},{"id":"mf_ar_11","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الثالث :","title":"دُعاءُ يَوْمِ الثّلاثاء","blocks":[{"type":"Text","content":"اَلْحَمْدُ للهِِ وَالْحَمْدُ حَقُّهُ كَما يَسْتَحِقُّهُ حَمْداً كَثيراً وَاَعُوذُ بِهِ مِنْ شَرِّ نَفْسى اِنَّ النَّفْسَ لاََمّارَةٌ بِالسُّوءِ اِلاّ ما رَحِمَ رَبّى وَاَعُوذُ بِهِ مِنْ شَرِّ الشَّيْطانِ الَّذى يَزيدُنى ذَنْباً اِلى ذَنْبى وَاَحْتَرِزُ بِهِ مِنْ كُلِّ جَبّار فاجِر وَسُلْطان جائِر وَعَدُوّ قاهِر اَللّـهُمَّ اجْعَلْنى مِنْ جُنْدِكَ فَاِنَّ جُنْدَكَ هُمُ الْغالِبُونَ وَاجْعَلْنى مِنْ حِزْبِكَ فَاِنَّ حِزْبَكَ هُمُ الْمُفْلِحُونَ وَاجْعَلْنى مِنْ اَوْلِيآئِكَ فَاِنَّ أولياءك لا خَوْفٌ عَلَيْهِمْ وَلا هُمْ يَحْزَنُونَ اَللّـهُمَّ اَصْلِحْ لى دينى فَاِنَّهُ عِصْمَةُ اَمْرى وَاَصْلِحْ لى اخِرَتى فَاِنَّها دارُ مَقَرّى وَاِلَيْها مِنْ مُجاوَرَةِ اللِّئامِ مَفَرّى وَاجْعَلِ الْحَيوةَ زِيادَةً لى فى كُلِّ خَيْر وَالْوَفاةَ راحَةً لى مِنْ كُلِّ شَرٍّ اَللّـهُمَّ صَلِّ عَلى مُحَمَّد خاتَمِ النَّبِيّينَ وَ تَمامِ عِدَّةِ الْمُرْسَلينَ وَعَلى آلِهِ الطَّيِّبينَ الطّاهِرينَ وَاَصْحابِهِ الْمُنْتَجَبينَ وَهَبْ لى فِى الثُّلاثاءِ ثَلاثاً لا تَدَعْ لى ذَنْباً اِلاّ غَفَرْتَهُ وَلا غَمّاً اِلاّ اَذْهَبْتَهُ وَلا عَدُوّاً اِلاّ دَفَعْتَهُ بِبِسْمِ اللهِ خَيْرِ الاَْسْماءِ بِسْمِ اللهِ رَبِّ الاَْرْضِ وَالسَّماءِ اَسْتَدْفِعُ كُلَّ مَكْروه اَوَّلُهُ سَخَطُهُ وَاَسْتَجْلِبُ كُلَّ مَحْبُوب اَوَّلُهُ رِضاهُ فَاخْتِمْ لى مِنْكَ بِالْغُفْرانِ يا وَلِيَّ الاِْحْسانِ ."}],"preview":"اَلْحَمْدُ للهِِ وَالْحَمْدُ حَقُّهُ كَما يَسْتَحِقُّهُ حَمْداً كَثيراً وَاَعُوذُ بِهِ مِنْ شَرِّ نَفْسى اِنَّ النَّفْسَ لاََمّارَةٌ بِالسُّوءِ اِلاّ ما رَحِمَ رَبّى وَاَعُوذُ بِهِ","hasTranslate":false},{"id":"mf_ar_12","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الثالث :","title":"دُعاءُ يَوْمِ الاربَعاء","blocks":[{"type":"Text","content":"اَلْحَمْدُ للهِِ الَّذى جَعَلَ اللَّيْلَ لِباساً وَالنَّوْمَ سُباتاً وَجَعَلَ النَّهارَ نُشُوراً لَكَ الْحَمْدُ اَنْ بَعَثْتَنى مِنْ مَرْقَدى وَلَوْ شِئْتَ جَعَلْتَهُ سَرْمَداً حَمْداً دائِماً لا يَنْقَطِعُ اَبَداً وَلا يُحْصى لَهُ الْخَلائِقُ عَدَداً اَللّـهُمَّ لَكَ الْحَمْدُ اَنْ خَلَقْتَ فَسَوَّيْتَ وَقَدَّرْتَ وَقَضَيْتَ وَاَمَتَّ وَاَحْيَيْتَ وَاَمْرَضْتَ وَشَفَيْتَ وَعافَيْتَ وَاَبْلَيْتَ وَعَلَى الْعَرْشِ اسْتَوَيْتَ وَعَلَى الْمُلْكِ احْتَوَيْتَ اَدْعُوكَ دُعاءَ مَنْ ضَعُفَتْ وَسيلَتُهُ وَانْقَطَعَتْ حيلَتُهُ وَاقْتَرَبَ اَجَلُهُ وَتَدانى فِى الدُّنْيا اَمَلُهُ وَاشْتَدَّتْ اِلى رَحْمَتِكَ فاقَتُهُ وَعَظُمَتْ لِتَفْريطِهِ حَسْرَتُهُ وَ كَثُرَتْ زَلَّتُهُ وَعَثْرَتُهُ وَخَلُصَتْ لِوَجْهِكَ تَوْبَتُهُ فَصَلِّ عَلى مُحَمَّد خاتَمِ النَّبِيّينَ وَعَلى اَهْلِ بَيْتِهِ الطَّيِّبينَ الطّاهِرينَ وَارْزُقْنى شَفاعَةَ مُحَمَّد صَلَّى اللهُ عَلَيْهِ وَآلِهِ وَلا تَحْرِمْنى صُحْبَتَهُ اِنَّكَ اَنْتَ اَرْحَمُ الرّاحِمينَ اَللّـهُمَّ اقْضِ لى فِى الاَْرْبَعاءِ اَرْبَعاً اِجْعَلْ قُوَّتى فى طاعَتِكَ وَنَشاطى فى عِبادَتِكَ وَرَغْبَتى فى ثَوابِكَ وَزُهْدى فيما يُوجِبُ لى اَليمَ عِقابِكَ اِنَّكَ لَطيفٌ لِما تَشاءُ ."}],"preview":"اَلْحَمْدُ للهِِ الَّذى جَعَلَ اللَّيْلَ لِباساً وَالنَّوْمَ سُباتاً وَجَعَلَ النَّهارَ نُشُوراً لَكَ الْحَمْدُ اَنْ بَعَثْتَنى مِنْ مَرْقَدى وَلَوْ شِئْتَ جَعَلْتَهُ سَرْمَداً حَم","hasTranslate":false},{"id":"mf_ar_13","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الثالث :","title":"دُعاءُ يَوْمِ الخَمِيس","blocks":[{"type":"Text","content":"اَلْحَمْدُ للهِِ الَّذى اَذْهَبَ اللَّيْلَ مُظْلِماً بِقُدْرَتِهِ وَجاءَ بِالنَّهارُ مُبْصِراً بِرَحْمَتِهِ وَكَسانى ضياءه وَاَنا فى نِعْمَتِهِ اَللّـهُمَّ فَكَما اَبْقَيْتَنى لَهُ فَاَبْقِنى لاَِمْثالِهِ وَصَلِّ عَلَى النَّبِىِّ مُحَمَّد وَآلِهِ وَلا تَفْجَعْنى فيهِ وَفى غَيْرِهِ مِنَ اللَّيالى وَالاَْيّامِ بِارْتِكابِ الَْمحارِمِ وَاكْتِسابِ الْمَآثِمِ وَارْزُقْنى خَيْرَهُ وَخَيْرَ ما فيهِ وَخَيْرَ ما بَعْدَهُ وَاصْرِفْ عَنّى شَرَّهُ وَشَرَّ ما فيهِ وَشَرَّما بَعْدَهُ اَللّـهُمَّ اِنّى بِذِمَّةِ الاِْسْلامِ اَتَوَسَّلُ اِلَيْكَ وَبِحُرْمَةِ الْقُرْآنِ اَعْتَمِدُ عَلَيْكَ وَبِمُحَمَّد الْمُصْطَفى صَلَّى اللهُ عَلَيْهِ وَآلِهِ اَسْتَشْفِعُ لَدَيْكَ فَاعْرِفِ اَللّـهُمَّ ذِمَّتِىَ الَّتى رَجَوْتُ بِها قَضاءَ حاجَتى يا اَرْحَمَ الرّاحِمينَ اَللّـهُمَّ اقْضِ لى فِى الْخَميسِ خَمْساً لا يَتَّسِعُ لَها اِلاّ كَرَمُكَ وَلا يُطيقُها اِلاّ نِعَمُكَ سَلامَةً اَقْوى بِها عَلى طاعَتِكَ وَعِبادَةً اَسْتَحِقُّ بِها جَزيلَ مَثُوبَتِكَ وَسَعَةً فِى الْحالِ مِنَ الرِّزْقِ الْحَلالِ وَاَنْ تُؤْمِنَنى فى مَواقِفِ الْخَوْفِ بِاَمْنِكَ وَتَجْعَلَنى مِنْ طَوارِقِ الْهُمُومِ وَالْغُمُومِ فى حِصْنِكَ وَصَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاجْعَلْ تَوَسُّلى بِهِ شافِعاً يَوْمَ الْقِامَةِ نافِعاً اِنَّكَ اَنْتَ اَرْحَمُ الرّحِمينَ ."}],"preview":"اَلْحَمْدُ للهِِ الَّذى اَذْهَبَ اللَّيْلَ مُظْلِماً بِقُدْرَتِهِ وَجاءَ بِالنَّهارُ مُبْصِراً بِرَحْمَتِهِ وَكَسانى ضياءه وَاَنا فى نِعْمَتِهِ اَللّـهُمَّ فَكَما اَبْقَيْتَنى لَهُ","hasTranslate":false},{"id":"mf_ar_14","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الثالث :","title":"دُعاءُ يَوْمِ الجُمعَة","blocks":[{"type":"Text","content":"اَلْحَمْدُ للهِِ الاَْوَّلِ قَبْلَ الاِْنْشاءِ وَالاِْحْياءِ وَالاْخِرِ بَعْدَ فَناءِ الاَْشْياءِ الْعَليمِ الَّذى لا يَنْسى مَنْ ذَكَرَهُ وَلا يَنْقُصُ مَنْ شَكَرَهُ وَلا يَخيبُ مَنْ دَعاهُ وَلا يَقْطَعُ رَجاءَ مَنْ رَجاهُ اَللّـهُمَّ اِنّى اُشْهِدُكَ وَكَفى بِكَ شَهيداً وَاُشْهِدُ جَميعَ مَلائِكَتِكَ وَسُكّانَ سَمواتِكَ وَ حَمَلَةَ عَرْشِكَ وَمَنْ بَعَثْتَ مِنْ اَنْبِيائِكَ وَرُسُلِكَ وَاَنْشَأْتَ مِنْ اَصْنافِ خَلْقِكَ اَنّي اَشْهَدُ اَنَّكَ اَنْتَ اللهُ لا اِلـهَ اِلاّ اَنْتَ وَحْدَكَ لا شَريكَ لَكَ وَلا عَديلَ وَلا خُلْفَ لِقَوْلِكَ وَلا تَبْديلَ وَاَنَّ مُحَمَّداً صَلَّى اللهُ عَلَيْهِ وَآلِهِ عَبْدُكَ وَرَسُولُكَ اَدّى ما حَمَّلْتَهُ اِلَى العِبادِ وَجاهَدَ فِي اللهِ عَزَّ وَجَلَّ حَقَّ الْجِهادِ وَاَنَّهُ بَشَّرَ بِما هُوَ حَقٌّ مِنَ الثَّوابِ وَاَنْذَرَ بِما هُوَ صِدْقٌ مِنَ الْعِقابِ اَللّـهُمَّ ثَبِّتْني عَلى دينِكَ ما اَحْيَيْتَني وَلا تُزِغْ قَلْبي بَعْدَ اِذْ هَدَيْتَني وَهَبْ لي مِنْ لَدُنْكَ رَحْمَةً اِنَّكَ اَنْتَ الْوَهّابُ صَلِّ عَلى مُحَمَّد وَعَلى آلِ مُحَمَّد وَاجْعَلْني مِنْ اَتْباعِهِ وَشيعَتِهِ وَاحْشُرْني في زُمْرَتِهِ وَوَفِّقْني لاَِداءِ فَرْضِ الْجُمُعاتِ وَما اَوْجَبْتَ عَلَيَّ فيها مِنَ الطّاعاتِ وَقَسَمْتَ لاَِهْلِها مِنَ الْعَطاءِ في يَوْمِ الْجَزاءِ اِنَّكَ اَنْتَ الْعَزيزُ الْحَكيمُ ."}],"preview":"اَلْحَمْدُ للهِِ الاَْوَّلِ قَبْلَ الاِْنْشاءِ وَالاِْحْياءِ وَالاْخِرِ بَعْدَ فَناءِ الاَْشْياءِ الْعَليمِ الَّذى لا يَنْسى مَنْ ذَكَرَهُ وَلا يَنْقُصُ مَنْ شَكَرَهُ وَلا يَخيبُ م","hasTranslate":false},{"id":"mf_ar_15","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الثالث :","title":"دُعاءُ يَوْمِ السَّبْتِ","blocks":[{"type":"Text","content":"بِسْمِ اللهِ كَلِمَةُ الْمُعْتَصِمينَ وَمَقالَةُ الْمُتَحَرِّزينَ وَاَعُوذُ بِاللهِ تَعالى مِنْ جَوْرِ الْجائِرينَ وَكَيْدِ الْحاسِدينَ وَبَغْيِ الظّالِمينَ وَاَحْمَدُهُ فَوْقَ حَمْدِ الْحامِدينَ اَللّـهُمَّ اَنْتَ الْواحِدُ بِلا شَريكِ وَالْمَلِكُ بِلا تَمْليك لا تُضادُّ فى حُكْمِكَ وَلا تُنازَعُ فى مُلْكِكَ أَسْأَلُكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد عَبْدِكَ وَرَسُولِكَ وَاَنْ تُوزِعَنى مِنْ شُكْرِ نُعْماكَ ما تَبْلُغُ بى غايَةَ رِضاكَ وَاَنْ تُعينَنى عَلى طاعَتِكَ وَلُزُومِ عِبادَتِكَ وَاسْتِحْقاقِ مَثُوبَتِكَ بِلُطْفِ عِنايَتِكَ وَتَرْحَمَني بِصَدّى عَنْ مَعاصيكَ ما اَحْيَيْتَنى وَتُوَفِّقَنى لِما يَنْفَعُني ما اَبْقَيْتَني وَاَنْ تَشْرَحَ بِكِتابِكَ صَدْري وَتَحُطَّ بِتِلاوَتِهِ وِزْري وَتَمْنَحَنِيَ السَّلامَةَ فى دينى وَنَفْسى وَلا تُوحِشَ بى اَهْلَ اُنْسي وَتُتِمَّ اِحْسانَكَ فيما بَقِىَ مِنْ عُمْرى كَما اَحْسَنْتَ فيما مَضى مِنْهُ يا اَرْحَمَ الرّاحِمينَ ."}],"preview":"بِسْمِ اللهِ كَلِمَةُ الْمُعْتَصِمينَ وَمَقالَةُ الْمُتَحَرِّزينَ وَاَعُوذُ بِاللهِ تَعالى مِنْ جَوْرِ الْجائِرينَ وَكَيْدِ الْحاسِدينَ وَبَغْيِ الظّالِمينَ وَاَحْمَدُهُ فَوْقَ حَم","hasTranslate":false},{"id":"mf_ar_16","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"في فضل ليلة الجمة ونهارها وأعمالها :","blocks":[{"type":"AboutText","content":"اعلم انّ ليلة الجُمعة ونهارها يمتازان على ساير اللّيالي والايّام سموّاً وشرفاً ونباهة ، روي عن النّبيّ (صلى الله عليه وآله وسلم) قال : انّ ليلة الجمعة ونهارها أربع وعشرون ساعة، لله عزّ وجلّ في كلّ ساعة ستمائة ألف عتيق من النّار. وعن الصّادق (عليه السلام) قال : مَن مَات ما بين زوال الشّمس من يوم الخميس الى زوال الشّمس من يوم الجُمعة اعاذه الله من ضغطة القبر وعنه (عليه السلام) أيضاً قال : انّ للجمعة حقّاً فايّاك أن تضيّع حرمته أو تقصر في شيء من عبادة الله والتقرّب اليه بالعمل الصّالح وترك المحارم كلّها فانّ الله تعالى يضاعف فيه الحسنات ويمحو السّيئات ويرفع فيه الدّرجات ويومه مثل ليلته فان استطعت أن تحييها بالدّعاء والصلاة فافعل فانّ الله تعالى يرسل فيها الملائكة الى السّماء الدّنيا لتضاعف فيها الحَسَنات وتمحو فيها السّيئات وانّ الله واسِع كريم. وأيضاً في حديث معتبر عنه (عليه السلام) قال : انّ المؤمن ليدعو في الحاجة فيؤخّر الله حاجته الّتي سأل الى يوم الجمعة ليخصّه بفضله (أي ليضاعف له بسبب فضل يوم الجمعة) وقال لمّا سأل اخوة يوسف يعقُوب أن يستغفر لهم ، قال : (سَوْفَ اَسْتَغْفِرُ لَكُمْ رَبّي) ثمّ أخّر الاستغفار الى السّحر من ليلة الجمعة كي يستجاب له ."},{"type":"AboutText","content":"وعنه أيضاً قال : اذا كان ليلة الجمعة رفعت حيتان البحور رؤوسها ودواب البراري ثمّ نادت بصوت طلق رَبّنا لا تُعَذِّبْنا بِذُنُوب الادميّين وعن الباقِر (عليه السلام) قال : انّ الله تعالى ليأمر ملكاً فينادي كلّ ليلة جمعة من فوق عرشه من أوّل الليل الى آخره: الا عبد مؤمن يدعوني لاخرته ودنياه قبل طلُوع الفجر فأجيبه ؟ ألا عبد مؤمن يتوب اليّ من ذنوبه قبل طلوع الفجر فأتوب عليهم ألا عبد مؤمن قد قتّرت عليهِ رزقه فيسألني الزّيادة في رزقه قبل طلوع الفجر فأزيده وأوسع عليه؟ ألا عبد مؤمن سقيم فيسألني أن أشفيه قبل طلوع الفجر فاعافيه؟ الا عبد مؤمن مغموم محبوس يسألني أن اطلقه من حبسه وأفرّج عنه قبل طلوع الفجر فأطلقه واخلّي سبيله؟ ألا عبد مؤمن مظلوم يسألني أن آخذ له بظلامته قبل طلوع الفجر فأنتصر له وآخذ بظلامته ؟ قال : فلا يزال ينادي حتّى يطلع الفجر. وعن أمير المؤمنين (عليه السلام) قال : انّ الله اختار الجُمعة فجعل يومها عيداً واختار ليلتها فجعلها مثلها وانّ من فضلها أن لا يسأل الله عزّوجلّ أحد يوم الجُمعة حاجة الاّ استجيب له وان استحقّ قوم عقاباً فصادفوا يوم الجمعة وليلتها صرف عنهم ذلك ولم يبق شيء ممّا احكمه الله وفضّله الاّ أبرمه في ليلة الجمعة، فليلة الجمعة أفضل اللّيالي ويومها أفضل الايّام ، وعن الصّادق (عليه السلام) قال : اجتنبوا المعاصي ليلة الجمعة فانّ السّيئة مضاعفة والحسنة مضاعفة ومن ترك معصية الله ليلة الجُمعة غفر الله له كلّ ما سلف ومَن بارز الله ليلة الجُمعة بمعصية أخذه الله بكلّ ما عمل في عُمره وضاعف عليه العذاب بهذه المعصية ."},{"type":"Text","content":"وبسند معتبر عن الرّضا (عليه السلام) قال : قال رسول الله (صلى الله عليه وآله) : انّ يوم الجُمعة سيّد الايّام يضاعف الله عزّوجلّ فيه الحسنات ويمحو فيه السّيّئات ويرفع فيه الدّرجات ويستجيب فيه الدّعوات ويكشف فيه الكربات ويقضي فيهِ الحوائج العظام وهو يوم المزيد لله فيهِ عتقاء وطلقاء من النّار، ما دعا فيه أحد من النّاس وعرف حقّه وحرمته الاّ كان حقّاً على الله عزّوجلّ أن يجعله من عتقائه وطُلقائه من النّار، فان مات في يومه أو ليلته مات شهيداً وبعث آمناً وما استخفّ أحد بحرمته وضيع حقّه الاّ كان حقّاً على الله عزّوجلّ أن يصليه نار جهنّم الاّ أن يتوب وباسناد معتبرة عن الباقر (عليه السلام) قال : ما طلعت الشّمس بيوم أفضل من يوم الجمعة وانّ كلام الطّير اذا لقي بعضها بعضاً سلام سلام يوم صالح وبسند معتبر عن الصّادق (عليه السلام)قال : من وافق منكم يوم الجُمعة فلا يشتغلنّ بشيء غير العبادة فانّ فيه يُغفر للعباد وتنزل عليهم الرّحمة وفضل ليلة الجُمعة ونهارها أكثر من أن يُورد في هذه الوجيزة ."}],"preview":"اعلم انّ ليلة الجُمعة ونهارها يمتازان على ساير اللّيالي والايّام سموّاً وشرفاً ونباهة ، روي عن النّبيّ (صلى الله عليه وآله وسلم) قال : انّ ليلة الجمعة ونهارها أربع وعشرون ساعة، لله","hasTranslate":false},{"id":"mf_ar_17","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"فكثيرة وهُنا نقتصر على عدّة منها :","blocks":[{"type":"Text","content":"الاول : الاكثار من قول سُبْحانَ اللهِ وَاللهُ اَكْبَرُ وَلا اِلـهَ إلاّ اللهُ والاكثار من الصلاة على محمّد وآله فقد روي انّ ليلة الجمعة ليلتها غرّاء ويومها يوم زاهِر فاكثروا من قول سُبْحانَ اللهِ وَاللهُ اَكْبَرُ وَلا اِلـهَ إلاّ اللهُ واكثروا من الصلاة على محمّد وآل محمّد (عليهم السلام) وفي رواية اُخرى انّ أقلّ الصلاة على محمّد وآله في هذه الليلة مائة مرّة وما زدت فهو أفضل وعن الصّادق (عليه السلام) انّ الصلاة على محمّد وآله في ليلة الجمعة تعدل ألف حسنة وتمحو ألف سيّئة وترفع ألف درجة ويستحبّ الاستكثار فيها من الصلاة على محمّد وآل محمّد صلوات الله عليهم من بعد صلاة العصر يوم الخميس الى آخر نهار يوم الجمعة. وروى بسند صحيح عن الصّادق (عليه السلام) قال : اذا كان عصر الخميس نزل من السّماء ملائكة في أيديهم أقلام الذّهب وقراطيس الفضّة لا يكتبُون الى ليلة السّبت الاّ الصلاة على محمّد وآله محمّد وقال الشّيخ الطّوسي ويستحبّ في يوم الخميس الصلاة على النّبيّ (صلى الله عليه وآله) ألف مرّة ويستحبّ أن يقول فيه : اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَعَجِّلْ فَرَجَهُمْ وَأَهْلِكْ عَدُوَّهُمْ مِنَ الْجِنِّ وَالاِنْسِ مِنَ الاَْوَّلينَ وَالاخِرينَ وان قال ذلك من بعد العصر يوم الخميس الى آخر نهار يوم الجمعة كان له فضل كثير وقال الشيخ ايضاً: ويستحبّ أن تستغفر آخر نهار يوم الخميس فتقول : اَسْتَغْفِرُ اللهَ الَّذي لا اِلـهَ إلاّ هُوَ الْحَيُّ الْقَيُّومُ وَاَتُوبُ اِلَيْهِ تَوْبَةَ عَبْد خاضِع مِسْكين مُسْتَكين لا يَسْتَطيعُ لِنَفْسِهِ صَرْفاً وَلا عَدْلاً وَلا نَفْعاً وَلا ضَرّاً وَلا حَياةً وَلا مَوْتاً وَلا نُشُوراً وَصَلَّى اللهُ عَلى مُحَمَّد وَعِتْرَتِهِ الطَّيِّبينَ الطّاهِرينَ الاَْخْيارِ الاَبْرارِ وَسَلَّمَ تَسْليماً ."},{"type":"Text","content":"الثاني : أن يقرأ ليلة الجُمعة سورة بني اسرائيل والكهف والسّور الثلاث المبدوءة بطس وسورة الم السّجدة ويس وص والاحقاف والواقعة وحم السّجدة وحم الدّخان والطور واقتربت والجمعة فان لم تسنح له الفرصة فليختار من هذه السّور الواقعة وما قبلها ، فقد روي عن الصّادق (عليه السلام) قال : من قرأ بني اسرائيل في كلّ ليلة جمعة لم يمت حتّى يدرك القائم (عليه السلام) فيكون من أصحابه ، وقال (عليه السلام) : من قرأ سورة الكهف كلّ ليلة جمعة لم يمت الاّ شهيداً وبعثه الله مع الشّهداء ووقف يوم القيامة مع الشّهداء ، وقال (عليه السلام) : من قرأ الطّواسين الثّلاثة في ليلة الجُمعة كان من أوليآء الله وفي جوار الله وفي كنفه ولم يصبه في الدّنيا بؤس أبداً واعطي في الاخرة من الجنّة حتّى يرضى وفوق رضاه وزوّجه الله مائة زوجة من الحور العين، وقال (عليه السلام): من قرأ سورة السّجدة في كلّ ليلة جمعة أعطاه الله كتابه بيمينه ولم يحاسبه بما كان منه وكان مِن رفقآء محمّد وأهل بيته (عليهم السلام). وبسند معتبر عن الباقِر (عليه السلام) قال : مَنْ قرأ سورة ص في ليلة الجُمعة أعطي من خير الدّنيا والاخرة ما لم يُعط أحدٌ من النّاس الاّ نبيّاً مُرسلاً أو ملكاً مقرّباً وأدخله الله الجنّة، وكلّ من أحبّ من أهل بيته حتّى خادمه الذي يخدمه وان لم يكن في حدّ عياله ولا في حدّ من يشفع له، وعن الصّادق (عليه السلام) قال : من قرأ في ليلة الجُمعة أو يوم الجُمعة سُورة الاحقاف لم يصبه الله بروعة في الحياة الدّنيا وامّنه من فزع يوم القيامة، وقال (عليه السلام) مَن قرأ الواقعة كلّ ليلة جُمعة أحبّه الله تعالى وأحبّه الى النّاس اجمعين ولم ير في الدّنيا بؤساً أبداً ولا فقراً ولا فاقة ولا آفة من آفات الدّنيا وكان من رفقاء أمير المؤمنين (عليه السلام) وهذه السّورة سورة أمير المؤمنين (عليه السلام) وروي انّ من قرأ سُورة الجُمعة كلّ ليلة جمعة كانت كفّارة له ما بين الجمعة الى الجُمعة، وروي مثله فيمن قرأ سورة الكهف في كلّ ليلة جمعة وفيمن قرأها بعد فريضتي الظّهر والعصر يوم الجُمعة. واعلم انّ الصّلوات المأثورة في ليلة الجُمعة عديدة منها صلاة أمير المؤمنين (عليه السلام) ومنها الصلاة ركعتان يقرأ في كلّ ركعة الحمد وسورة اذا زلزلت خمس عشرة مرّة فقد روي انّ من صلاّها أمّنه الله تعالى من عذاب القبر وأهوال يوم القيامة ."},{"type":"Text","content":"الثالث : أن يقرأ سورة الجُمعة في الرّكعة الاُولى من فريضتي المغرب والعشاء، ويقرأ التّوحيد في الثّانية من المغرب، والاعلى في الثّانية من العشآء ."},{"type":"Text","content":"الرّابع : ترك انشاد الشّعر، ففي الصّحيح عن الصّادق صَلوات الله وَسلامُه عليه انّه يكره رواية الشّعر للصّائم والمحرم وفي الحرم وفي يوم الجُمعة وفي اللّيالي ، قال الراوي : وان كان شعراً حقّاً؟ فأجاب (عليه السلام) : وان كان حقّاً. وفي حديث معتبر عن الصّادق (عليه السلام) انّ النّبي (صلى الله عليه وآله) قال : من أنشد بيتاً من الشّعر في ليلة الجُمعة أو نهارها لم يكن له سواه نصيب من الثّواب في تلك الليلة ونهارها، وعلى رواية اُخرى لم تقبل صلاته في تلك الليلة ونهارها"},{"type":"Text","content":"الخامس : أن يكثر من الدّعاء لاخوانه المؤمنين كما كانت تصنع الزّهراء)عليها السلام)، واذا دعا لعشر من الاموات منهم فقد وجبت له الجنّة كما في الحديث ."},{"type":"Text","content":"السّادس : أن يدعو بالمأثور من أدعيتها وهي كثيرة ونحن نقتصر على ذكر نبذ يسيرة منها. بسند صحيح عن الصّادق (عليه السلام) انّ من دعا بهذا الدّعاء ليلة الجُمعة في السّجدة الاخيرة من نافلة العشاء سبع مرّات فرغ مغفوراً له والافضل أن يكرّر العمل في كلّ ليلة :"},{"type":"Text","content":"اَللّـهُمَّ اِنّي أَسْأَلُكَ بِوَجْهِكَ الْكَريمِ وَاسْمِكَ الْعَظيمِ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِهِ وَاَنْ تَغْفِرَ لي ذَنْبِيَ الْعَظيمَ وعن النّبيّ قال : من قال هذه الكلمات سبع مرّات في ليلة الجمعة فمات ليلته دخل الجنّة ومن قالها يوم الجمعة فمات في ذلك اليوم دخل الجنّة، من قال :"},{"type":"Text","content":"اَللّـهُمَّ اَنْتَ رَبّي لا اِلـهَ إلاّ اَنْتَ خَلَقْتَني وَاَنَا عَبْدُكَ وَابْنُ اَمَتِكَ وَفي قَبْضَتِكَ وَناصِيَتي بِيَدِكَ اَمْسَيْتُ عَلى عَهْدِكَ وَوَعْدِكَ مَا اسْتَطَعْتُ اَعُوذُ بِرِضاكَ مِنْ شَرِّ ما صَنَعْتُ اَبُوءُ بِنِعْمَتِكَ (بِعَمَلى) وَاَبُوءُ بِذَنْبى (بِذُنُوبى) فَاغْفِرْ لى ذُنُوبى اِنَّهُ لا يَغْفِرُ الذُّنُوبَ إلاّ اَنْتَ ."},{"type":"Text","content":"وقال الشّيخ الطّوسي والسيّد والكفعمي والسيّد ابن باقي يستحبّ أن يدعى بهذا الدّعاء في ليلة الجمعة ونهارها وفي ليلة عرفة ونهارها ونحن نروي الدّعاء عن كتاب المصباح للشّيخ وهو :"},{"type":"Text","content":"اَللّـهُمَّ مَنْ تَعَبَّأَ وَتَهَيّأَ وَاَعَدَّ وَاسْتَعَدَّ لِوِفادَة اِلى مَخْلُوق رَجاءَ رِفْدِهِ وَطَلَبَ نائِلِهِ وَجائِزَتِهِ فَاِلَيْكَ يا رَبِّ تَعْبِيَتى وَاسْتِعْدادي رَجاءَ عَفْوِكَ وَطَلَبَ نائِلِكَ وَجائِزَتِكَ فَلا تُخَيِّبْ دُعائي يا مَنْ لا يَخيبُ عَلَيْهِ سائِلٌ (السّائِلُ) وَلا يَنْقُصُهُ نائِلٌ فَاِنّي لَمْ آتِكَ ثِقَةً بِعَمَل صالِح عَمِلْتُهُ وَلا لِوِفادَةِ مَخْلُوق رَجَوْتُهُ اَتَيْتُكَ مُقِرّاً عَلى نَفْسي بِالاِْساءةِ وَالظُّلْمِ مُعْتَرِفاً بِاَنْ لا حُجَّةَ لي وَلا عُذْرَ اَتَيْتُكَ اَرْجُو عَظيمَ عَفْوِكَ الَّذى عَفَوْتَ (عَلَوْتَ) بِهِ (عَلى) عَنِ الْخاطِئينَ (الْخَطّائينَ) فَلَمْ يَمْنَعْكَ طُولُ عُكُوفِهِمْ عَلى عَظيمِ الْجُرْمِ اَنْ عُدْتَ عَلَيْهِمْ بِالرَّحْمَةِ فَيا مَنْ رَحْمَتُهُ واسِعَةٌ وَعَفْوُهُ عَظيمٌ يا عَظيمُ يا عَظيمُ يا عَظيمُ لا يَرُدُّ غَضَبَكَ إلاّ حِلْمُكَ وَلا يُنْجي مِنْ سَخَطِكَ إلاَّ التَّضَرُّعُ اِلَيْكَ فَهَبْ لي يا اِلـهي فَرَجاً بِالْقُدْرَةِ الَّتي تُحْيي بِها مَيْتَ الْبِلادِ وَلا تُهْلِكْني غَمّاً حَتّى تَسْتَجيبَ لي وَتُعَرِّفَنِي الاِجابَةَ في دُعائي وَاَذِقْني طَعْمَ الْعافِيَةِ إلى مُنَتَهى اَجَلي وَلا تُشْمِتْ بي عَدُوّى وَلا تُسلّطهُ عَلَيَّ وَلا تُمَكِّنْهُ مِنْ عُنُقي اَللّـهُمَّ (اِلـهي) اِنْ وَضَعْتَني فَمَنْ ذَا الَّذي يَرْفَعُني وَاِنْ رَفَعْتَني فَمَنْ ذَا الَّذي يَضَعُني وَاِنْ اَهْلَكْتَني فَمَنْ ذَا الَّذي يَعْرِضُ لَكَ في عَبْدِكَ اَوْ يَسْأَلُكَ عَنْ اَمْرِهِ وَقَدْ عَلِمْتُ اَنَّهُ لَيْسَ فى حُكْمِكَ ظُلْمٌ وَلا فى نَقَمَتِكَ عَجَلَةٌ وَاِنَّما يَعْجَلُ مَنْ يَخافُ الْفَوْتَ وَاِنَّما يَحْتاجُ اِلَى الظُّلْمِ الضَّعيفُ وَقَدْ تَعالَيْتَ يا اِلـهى عَنْ ذلِكَ عُلُوّاً كَبيراً اَللّـهُمَّ اِنّى اَعُوذُ بِكَ فَاَعِذْنى وَاَسْتَجيرُ بِكَ فَاَجِرْنى وَاَسْتَرْزِقُكَ فَارْزُقْنى وَاَتَوَكَّلُ عَلَيْكَ فَاكْفِنى وَاَستَنْصِركَ عَلى عَدُوّى (عدوّك) فَانْصُرْنى وَاَسْتَعينُ بِكَ فَاَعِنّى وَاَسْتَغْفِرُكَ يا اِلـهى فَاغْفِرْ لى آمينَ آمينَ آمينَ ."}],"preview":"الاول : الاكثار من قول سُبْحانَ اللهِ وَاللهُ اَكْبَرُ وَلا اِلـهَ إلاّ اللهُ والاكثار من الصلاة على محمّد وآله فقد روي انّ ليلة الجمعة ليلتها غرّاء ويومها يوم زاهِر فاكثروا من قول","hasTranslate":false},{"id":"mf_ar_18","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"السابع : أن يدعو بدعاء كميل وَسَيذكر في الفصل الاتي ان شاء الله تعالى","blocks":[{"type":"Text","content":"الثامن : أن يقرأ الدّعاء : اَللّـهُمَّ يا شاهِدَ كُلِّ نَجْوى ويدعى به ليلة عرفة أيضاً وسيأتي ان شاء الله تعالى ."},{"type":"Text","content":"التاسع : أن يقول عشر مرّات يا دائِمَ الْفَضْلِ عَلى الْبَريِّةِ يا باسِطَ الْيَدَيْنِ بِالْعَطِيَّةِ يا صاحِبَ الْمَواهِبِ السَّنِيَّةِ صَلِّ عَلى مُحَمِّد وَآلِهِ خَيْرِ الْوَرىْ سَجِيَّةً وَاغْفِرْ لَنا يا ذَا الْعُلى فى هذِهِ الْعَشِيَّةِ وهذا الذّكر الشّريف وارد في ليلة عيد الفطر أيضاً."},{"type":"Text","content":"العاشِر : أن يأكل الرُّمّان كما كانَ يعمل الصّادق (عليه السلام) في كلّ ليلة الجُمعة ولعلّ الاحسن أن يجعل الاكل عند النّوم ، فقد روي انّ من أكل الرُّمان عند النّوم أمن في نفسه الى الصّباح وينبغي أن يبسط لاكل الرّمّان منديلاً يحتفظ بما يتساقط من حبّه فيجمعه ويأكله وكما ينبغي أن لا يشرك أحداً في رُمّانته. روى الشيخ جعفر بن احمد القمّي في كتاب العروس عن الصّادق (عليه السلام) انّ من قال بين نافلة الصّبح وفريضته مائة مرّة: سُبْحانَ رَبِّيَ الْعَظيمِ وَبِحَمْدِهِ اَسْتَغْفِرُ اللهَ رَبّى وَاَتُوبُ اِلَيْهِ بنى الله له بيتاً في الجنّة، وهذا الدّعاء رواه الشّيخ والسّيد وغيرهما وقالوا : يستحبّ أن يدعى به في السّحر ليلة الجُمعة، وهذا هو الدّعاء :"},{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وآلِهِ وَهَبْ لِيَ الْغَداةَ رِضاكَ وَاَسْكِنْ قَلْبى خَوْفَكَ وَاقْطَعْهُ عَمَّنْ سِواكَ حَتّى لا اَرْجُوَ وَلا اَخافَ إلاّ إِيّاكَ اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وآلِهِ وَهَبْ لى ثَباتَ الْيَقينِ وَمَحْضَ الاِخْلاصِ وَشَرَفَ التَّوْحيدِ وَدَوامَ الاِسْتِقاَمة وَمَعْدِنَ الصِّبْرِ والرِّضا بِالْقَضاءِ وَالْقَدَرِ يا قاضِيَ حَوائِجِ السّائِلينَ يا مَنْ يَعْلَمُ ما في ضَميرِ الصّامِتينَ صَلِّ عَلى مُحَمَّد وآلِهِ وَاسْتَجِبْ دُعائى وَاغْفِرْ ذَنْبى وَاَوْسِعْ رِزْقي وَاقْضِ حَوائِجي في نَفْسي وَاِخْواني في ديني وَاَهْلي اِلـهي طُمُوحُ الامالِ قَدْ خابَتْ إلاّ لَدَيْكَ وَمَعاكِفُ الْهِمَمِ قَدْ تَعَطَّلَتْ إلاّ عَلَيْكَ وَمَذاهِبُ الْعُقُولِ قَدْ سَمَتْ إلاّ اِلَيْكَ فَاَنْتَ الَّرجاءُ وَاِلَيْكَ الْمُلْتَجَأُ يا اَكْرَمَ مَقْصُود وَاَجْوَدَ مَسْؤُول هَرَبْتُ اِلَيْكَ بِنَفْسى يا مَلْجَاَ الْهارِبينَ بِاَثْقالِ الذُّنُوبِ اَحْمِلُها عَلى ظَهْرى لا اَجِدُ لى اِلَيْكَ شافِعاً سِوى مَعْرِفَتي بِاَنَّكَ اَقْرَبُ مَنْ رَجاهُ الطّالِبُونَ وَاَمَّلَ مالَدَيْهِ الرّاغِبُونَ يا مَنْ فَتَقَ الْعُقُولَ بِمَعْرِفَتِهِ وَاَطْلَقَ الاَلْسُنَ بِحَمْدِهِ وَجَعَلَ مَا امْتَنَّ بِهِ عَلى عِبادِهِ في كِفاء لِتَاْدِيَةِ حَقِّهِ (اَنالَ بِهِ حَقّه) صَلِّ عَلى مُحَمَّد وآلِهِ وَلا تَجْعَلْ لِلشَّيْطانِ عَلى عَقْلى سَبيلاً وَلا لِلْباطِلِ على عَمَلى دَليلاً فاذا طلع الفجر يوم الجمعة فليقل : اَصْبَحْتُ فى ذِمَّةِ اللهِ وَذِمَّةِ مَلائِكَتِهِ وَذِمَمِ اَنْبِيائِهِ وَرُسُلِهِ عليهم السلام وَذِمَّةِ مُحمَّد صَلَّى اللهُ عَلَيْهِ وَآلِهِ وَذِمَمِ الاَوصياءِ مِنْ آلِ محَمَّد عليهم السلام آمَنْتُ بِسِرّ آلِ مُحَمَّد عليهم السلام وَعَلانِيَتِهِمْ وَظاهِرِهِمْ وَباطِنِهِمْ وَاَشْهَدُ اَنَّهُمْ فى عِلْمِ اللهِ وَطاعَتِهِ كَمُحَمَّد صَلَّى اللهُ عَلَيْهِ وآلِهِ ."},{"type":"Text","content":"وروي انّ مَنْ قال يوم الجمعة قبل صلاة الصّبح ثلاث مرّات : اَسْتَغْفِرُ اللهَ الَّذي لا اِلـهَ إلاّ هُوَ الْحَيُّ الْقَيُّومُ وَاَتُوبُ اِلَيْهِ غُفِرَتْ ذنوبه ولو كانت اكثر من زَبَد البحر ."},{"type":"Text","content":"وَأمّا أعْمال نَهارِ الجُمعة"},{"type":"Text","content":"فكثيرة ونحن هُنا نقتصر على عدّة منها :"},{"type":"Text","content":"الاوّل : أن يقرأ في الرّكعة الاُولى من صلاة الفجر سورة الجمعة وفي الثّانية سورة التّوحيد ."},{"type":"Text","content":"الثاني : أن يدعو بهذا الدُعاء بعد صلاة الغداة قبل أن يتكلّم ليكون ذلك كفّارة ذنوبه من جمعة الى جُمعة:"},{"type":"Text","content":"اَللّـهُمَّ ما قُلْتُ فى جُمُعَتى هذِهِ مِنْ قَوْل اَوْ حَلَفْتُ فيها مِنْ حَلْف اَوْ نَذَرْتُ فيها مِنْ نَذْر فَمَشِيَّتُكَ بَيْنَ يَدَيْ ذلِكَ كُلِّهِ فَما شِئْتَ مِنْهُ اَنْ يَكُونَ كانَ وَما لَمْ تَشَأْ مِنْهُ لَمْ يَكُن اَللّـهُمَّ اغْفرْ لى وَتَجاوَزْ عَنّى اَللّـهُمَّ مَنْ صَلَّيْتَ عَلَيْهِ فَصَلاتى عَلَيْهِ وَمَنْ لَعَنْتَ فَلَعْنَتي عَلَيْهِ ."},{"type":"Text","content":"وليؤدّ هذا العمل لا أقلّ من مرّة في كلّ شهر، وروي انّ من جلس يوم الجمعة يعقّب الى طلوع الشّمس رفع له سَبعون درجة في الفِردوس الاعلى، وروى الشّيخ الطوسي انّ من المسنُون هذا الدّعاء في تعقيب فريضة الفجر يوم الجُمعة :"},{"type":"Text","content":"اَللّـهُمَّ اِنّى تَعَمَّدْتُ اِلَيْكَ بِحاجَتى وَاَنْزَلْتُ اِلَيْكَ الْيَوْمَ فَقْرى وَفاقَتى وَمَسْكَنَتى فَاَنَا لِمَغْفِرَتِكَ اَرْجى مِنّى لِعَمَلى وَلَمَغْفِرَتُكَ وَرَحْمَتُكَ اَوْسَعُ مِنْ ذُنُوبي فَتَولَّ قَضاءَ كُلِّ حاجَة لي بِقُدْرَتِكَ عَلَيْها وَتَيسيرِ (وَتَيَسَر) ذلِكَ عَلَيْكَ وَلِفَقْري اِلَيْكَ فَاِنّي لَمْ اُصِبْ خَيْراً قَطُّ إلاّ مِنَك وَلَمْ يَصْرِفْ عَنّي سُوءاً قَطُّ اَحَدٌ سِواكَ وَلَسْتُ (وَلَيْسَ) اَرْجُو لاخِرَتي وَدُنْيايَ وَلا لِيَوْمِ فَقْرى يَوْمَ يُفْرِدُني النّاسُ في حُفْرَتي وَاُفْضي اِلَيْكَ بِذَنْبي سِواكَ ."},{"type":"Text","content":"الثالث : روي انّ مَن قال بعد فريضة الظّهر وفريضة الفجر في يوم الجُمعة وغيره من الايّام: اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَعَجِّلْ فَرَجَهُمْ لم يمت حتّى يدرك القائم (عليه السلام) وان قاله مائة مرّة قضى الله له ستّين حاجة ثلاثين من حاجات الدّنيا وثلاثين من حاجات الاخرة ."},{"type":"Text","content":"الرابع : أن يقرأ سُورة الرَّحمن بعد فريضة الصّبح فيقول بعد فَبِأيِّ آلاءِ رَبِّكُما تُكَذِّبانِ: لا بشيء مِنْ آلائكَ رَبِّ اُكَذِّبُ ."},{"type":"Text","content":"الخامس : قال الشّيخ الطوسي (رحمه الله): من المسنون بعد فريضة الصّبح يوم الجُمعة أن يقرأ التّوحيد مائة مرّة، وَيُصلّي على محمّد وآل مُحمّد مائة مرّة، ويستغفر مائة مرّة، ويقرأ سورة النّساء وهُود والكهف والصّافات والرّحمن ."},{"type":"Text","content":"السادس : أن يقرأ سورة الاحقاف والمؤمنُون، فعن الصّادق (عليه السلام)قال: مَنْ قرأ كلّ ليلة من ليالي الجمعة أو كلّ يوم من أيّامها سورة الاحقاف لم يصبه الله بروعة في الحياة الدّنيا وأمّنه من فزع يوم القيامة ان شاء الله، وقال ايضاً: من قرأ سورة المؤمنون ختم الله له بالسّعادة اذا كان يدمن قراءتها في كلّ جمعة وكان منزله في الفردوس الاعلى مع النّبيّين والمرسلين ."},{"type":"Text","content":"السّابع : أن يقرأ سُورة (قُل يا أيُّها الْكافِرُونَ) قبل طلوع الشّمس عشر مرّات ثمّ يدعو ليستجاب دعاؤه وروي انّ الامام زين العابدين (عليه السلام) كان اذا أصبح الصّباح يوم الجمعة أخذ في قراءة آية الكرسى الى الظّهر ثمّ اذا فرغ من الصلاة أخذ في قراءة سُورَة (اِنّا اَنْزَلْناهُ) واعلم انّ لقراءة آية الكرسى على التّنزيل في يوم الجُمعة فضلاً كثيراً ."},{"type":"Text","content":"(قال العلامة المجلسي: آية الكرسي على التنزيل على رواية عليّ بن ابراهيم والكليني هي كما يلي: الله لا اله إلاّ هو الحيّ القيوم لا تأخذه سنة ولا نوم له ما في السماوات والارض وما بينهما وما تحت الثرى عالم الغيب والشهادة الرحمن الرحيم من ذا الذي ... الى هم فيها خالدون)."},{"type":"Text","content":"الثامن : أن يغتسل وذلك من وكيد السّنن وروى عن النّبي (صلى الله عليه وآله وسلم)انّه قال لعليّ (عليه السلام) : يا علي اغتسل في كلّ جمعة ولو انّك تشتري المآء بقوت يومك وتطويه فانّه ليس شيء من التطوّع اعظم منه، وعن الصّادق صلواتُ الله وسلامه عليه قال : من اغتسل يوم الجُمعة فقال : اَشْهَدُ اَنْ لا اِلـهَ إلاّ اللهُ وَحْدَهُ لا شَريكَ لَهُ وَاَشْهَدُ اَنَّ مُحَمَّداً عَبْدُهُ وَرَسُولُهُ اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاجْعَلْني مِنَ التَّوّابينَ واجْعَلْني مِنَ المُتَطَهِّرينَ كان طهراً من الجمعة الى الجُمعة أي طهراً من ذنوبه أو انّ أعماله وقعت على طهر معنوي وقبلت والاحوط أن لا يدع غُسل الجُمعة ما تمكّن منه، ووقته من بعد طلُوع الفجر الى زوال الشّمس وكلّما قرب الوقت الى الزّوال كان أفضل ."},{"type":"Text","content":"التّاسع : أن يغسل الرأس بالخطمي فانّه أمان من البرص والجُنون ."},{"type":"Text","content":"العاشر : أن يقص شاربه ويقلّم أظفاره فلذلك فضل كثير يزيد في الرّزق ويمحو الذّنوب الى الجمعة القادمة، ويوجب الامن من الجنون والجُذام والبرص، وليقل حينئذ: بِسْمِ اللهِ وَبِاللهِ وِعلى سُنَّةِ مُحَمَّد وَآلِ مُحَمَّد وليبدء في تقليم الاظفار بالخنصر من اليد اليسرى ويختم بالخنصر من اليد اليمنى وكذا في تقليم أظفار الرّجل ثمّ ليدفن فضُول الاظافير ."},{"type":"Text","content":"الحادي عشر : أن يتطيّب ويلبس صالح ثيابه ."},{"type":"Text","content":"الثاني عشر : أن يتصدّق فالصّدقة تضاعف على بعض الرّوايات في ليلة الجُمعة ونهارها ألف ضعفها في سائر الاوقات ."},{"type":"Text","content":"الثالث عشر : أن يطرف أهله في كلّ جمعة بشيء من الفاكهة واللّحم حتّى يفرحُوا بالجمعة ."},{"type":"Text","content":"الرّابع عشر : أكل الرُّمّان على الرّيق وأكل سبعة أوراق من الهندباء قبل الزّوال، وعن مُوسى بن جعفر (عليهما السلام) قال : مَنْ أكل رُمّانة يوم الجُمعة على الرّيق نوّرت قلبه أربعين صباحاً فإن أكل رُمّانتين فثمانين يوماً فإنّ أكل ثلاثاً فمائة وعشرين يوماً وطردت عنه وسوسة الشّيطان، ومن طردت عنه وسوسة الشّيطان لم يعص الله ومن لم يعص الله أدخله الله الجنّة ."}],"preview":"الثامن : أن يقرأ الدّعاء : اَللّـهُمَّ يا شاهِدَ كُلِّ نَجْوى ويدعى به ليلة عرفة أيضاً وسيأتي ان شاء الله تعالى .","hasTranslate":false},{"id":"mf_ar_19","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"وقال الشيخ في المصباح: وروي في أكل الرُّمان في يوم الجُمعة وليلتها فضل كثير","blocks":[{"type":"Text","content":"الخامس عشر : أن يتفرّغ فيه لتعلّم أحكام دينه، لا أن ينفق يومه هذا في التجوال في بساتين النّاس ومزارعهم، ومصاحبة الاراذل والاوباش، والتهكم والتحدّث عن عيوب النّاس، والاستغراق في الضحك والقهقهة، وإنشاء القريض والخوض في الباطِل وأمثال ذلك فانّ ما يترتّب على ذلك من المفاسد أكثر من أن يذكر، وعن الصّادق (عليه السلام) قال : أفّ على مسلم لم ينفق من اسبُوعه يوم الجُمعة في تعلّم دينه ولم يتفرّغ فيه لذلك، وعن النّبي (صلى الله عليه وآله وسلم) انّه قال : اذا رأيتم يوم الجُمعة شيخاً يقصّ على النّاس تاريخ الكفر والجاهليّة فأرموا رأسه بالحصى ."},{"type":"Text","content":"السادس عشر : أن يصلّي على النّبي وآله ألف مرّة، وعن الباقر (عليه السلام) قال : ما من شيء من العبادة يوم الجُمعة أحبّ اليّ من الصلاة على محمّد وآله الاطهار صلّى الله عليهم أجمعين ."},{"type":"AboutText","content":"أقول : فإن لم تسنح له الفرصة بالصلاة ألف مرّة فلا أقلّ من المائة مرّة ليكون وجهه يوم الحساب مشرقاً، وروي انّ من صلّى على محمّد وآله يوم الجُمعة مائة مرّة وقال مائة مرّة: اَسْتَغْفِرُ اللهَ رَبّى واَتُوبُ اِلَيْهِ وقرأ التّوحيد مائة مرّة غفر له البتّة، وروى ايضاً انّ الصلاة على محمّد وآله بين الظّهر والعصر تعدل سبعين حجّة ."},{"type":"Text","content":"السابع عشر : أن يزُور النّبي والائمة الطاهرين سلام الله عليهم أجمعين وستأتي كيفيّة الزّيارة في باب الزّيارات ."},{"type":"Text","content":"الثامن عشر : أن يزور الاموات ويزور قبر أبويه أو أحدهما وعن الباقر (عليه السلام) قال : زوروا الموتى يوم الجُمعة فانّهم يعلمون بمن أتاهم ويفرحون ."},{"type":"Text","content":"التّاسع عشر : أن يقرأ دعاء النّدبة وَهُو من أعمال الاعياد الاربعة وسيأتي في محلّه ان شاء الله ."},{"type":"Text","content":"العشرون : اعلم انّه قد ذكر ليومِ الجُمعة صلوات كثيرة سوى نافلة الجُمعة التي هي عشرون ركعة وصفتها على المشهور أن يصلّي ستّ ركعات منها عند انبساط الشّمس، وستّاً عند ارتفاعها، وستّاً قبل الزّوال، وركعتين بعد الزّوال قبل الفريضة، أو أن يصلّي الستّ ركعات الاولى بعد صلاة الجُمعة أو الظّهر على ما هُو مذكور في كتب الفقهاء وفي المصابيح، وينبغي هُنا ايراد عدّة من تلك الصّلوات المذكورة ليوم الجُمعة وإن كان أكثرها لا يخص يوم الجُمعة ولكنّها في يوم الجُمعة أفضل . من تلك الصّلوات الصلاة الكاملة التي رواها الشّيخ والسّيد والشّهيد والعلاّمة وغيرهم باسناد عديدة معتبرة عن الامام جعفر بن محمّد الصّادق صلوات الله وسلامه عليهما عن آبائه الكرام عن رسول الله (صلى الله عليه وآله وسلم) قال : مَن صلّى يو م الجُمعة قبل الزّوال أربع ركعات يقرأ في كلّ ركعة الحمد عشر مرّات وكلاًّ مِن (قُلْ اَعُوذُ بِرَبِّ النّاسِ وقُلْ اَعُوذُ بِرَبِّ الْفَلَقِ وقُلْ هُوَ اللهُ اَحَدٌ وقُلْ يا أيُّها الْكافِرُونَ) ومثلها آية الكرسى، وفي رواية اُخرى يقرأ أيضاً عشر مرّات (اِنّا اَنْزَلْناهُ فى لَيلةِ الْقَدر) وعشر مرّات آية (شَهِدَ الله) وبعد فراغه من الصلاة يستغفر الله مائة مرّة ويقول : سُبْحانَ اللهِ وَالْحَمْدُ للهِ وَلا اِلـهَ إلاّ اللهُ وَاَللهُ اَكْبَرُ وَلا حَوْلَ وَلا قُوةَ إلاّ بِالله الْعَليِّ الْعَظيمِ مائة مرّة ويصلّي على محمّد وآل محمّد مائة مرّة . من صلّى هذه الصلاة دفع الله عنه شَرِّ أهل السّماء وأهل الارض وشرّ الشّيطان وشرّ كلّ سُلطان جابر ."},{"type":"Text","content":"صلوة اُخرى : روى الحارث الهمداني عن أمير المؤمنين (عليه السلام) انّه قال : اِنِ استطعت أن تصلّي يوم الجُمعة عشر ركعات تتمّ سجودهنّ وركوعهنّ وتقُول فيما بين كلّ ركعتين (سُبْحانَ اللهِ وَبِحَمْدِهِ) مائة مرّة فافعل فانّ لها فضلاً عظيماً ."},{"type":"Text","content":"صلاة اُخرى : بسند معتبر عن الصّادق (عليه السلام) قال : مَن قرأ سُورة ابراهيم وسورة الحجر في ركعتين جميعاً في يوم الجُمعة لم يصبه فقر أبداً ولا جنون ولا بلوى ."}],"preview":"الخامس عشر : أن يتفرّغ فيه لتعلّم أحكام دينه، لا أن ينفق يومه هذا في التجوال في بساتين النّاس ومزارعهم، ومصاحبة الاراذل والاوباش، والتهكم والتحدّث عن عيوب النّاس، والاستغراق في الض","hasTranslate":false},{"id":"mf_ar_20","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"وَمنها صلاة النّبيّ (صلى الله عليه وآله وسلم)","blocks":[{"type":"Text","content":"رَوى السّيد ابن طاووس (رحمه الله) بسند معتبر عن الرّضا صلوات الله عليه انّه سئل عن صلاة جعفر الطّيّار (رحمه الله)فقال : أين أنت عن صلاة النّبي (صلى الله عليه وآله وسلم) فعسى رسُول الله (صلى الله عليه وآله وسلم) لم يصلّ صلاة جعفر قطّ، ولعلّ جعفراً لم يصلّ صلاة رسُول الله (صلى الله عليه وآله وسلم) قطّ ، فقلت : علّمنيها ، قال : تصلّي ركعتين تقرأ في كلّ ركعة فاتحة الكتاب وانّا أنزلناهُ في ليلة القدر خمس عشرة مرّة ثم تركع فتقرأها خمس عشرة مرة، وخمس عشرة مرة اذا استويت قائماً، وخمس عشرة مرّة اذا سجدت، وخمس عشرة مرّة اذا رفعت رأسك من السّجود، وخمس عشرة مرّة في السّجدة الثانية، وخمس عشرة مرّة اذا رفعت رأسك من الثّانية، ثمّ تنصرف وليس بينك وبين الله تعالى ذنب الاّ وقد غفر لك وتعطى جميع ما سألت، والدّعاء بعدها :"},{"type":"Text","content":"لا اِلـهَ إلاّ اللهُ رَبُّنا وَرَبُّ آبائِنَا الاَوَّلينَ لا اِلـهَ إلاّ اللهُ اِلهاً واحِداً وَنَحْنُ لَهُ مُسْلِمُونَ لا اِلـهَ إلاّ اللهُ لا نَعْبُدُ إلاّ اِيّاهُ مُخْلِصينَ لَهُ الدِّينَ وَلَوْ كَرِهَ الْمُشْرِكُونَ لا اِلـهَ إلاّ اللهُ وَحْدَهُ وَحْدَهُ وَحْدَهُ اَنْجَزَ وَعْدَهُ وَنَصَرَ عَبْدَهُ وَاَعَزَّ جُنْدَهُ وَهَزَمَ الاَحْزابَ وَحْدَهُ فَلَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلى كُلِّ شَيء قَديرٌ اَللّـهُمَّ اَنْتَ نُورُ السَّمواتِ وَالاَرْضِ وَمَنْ فيهِنَّ فَلَكَ الْحَمْدُ وَاَنْتَ قَيّامُ السَّمواتِ وَالاَرْضِ وَمَنْ فيهِنَّ فَلَكَ الْحَمْدُ وَاَنْتَ الْحَقُّ وَوَعْدُكَ الْحَقُّ (حَقٌّ) وَقَوْلُكَ حَقٌّ وِاِنْجازُكَ حَقٌّ وَالْجَنَّةُ حَقٌّ وَالنّارُ حَقٌّ اَللّـهُمَّ لَكَ أَسْلَمْتُ وَبِكَ آمَنْتُ وَعَلَيْكَ تَوَكَّلْتُ وَبِكَ خاصَمْتُ وَاِلَيْكَ حاكَمْتُ يا رَبِّ يا رَبِّ يا ربِّ اِغْفِرْ لى ما قَدَّمْتُ وَاَخَّرْتُ وَاَسْرَرْتُ وَاَعْلَنْتُ اَنْتَ اِلـهي لا اِلـهَ إلاّ اَنْتَ صَلِّ عَلى مُحَمّد وَآلِ مُحَمَّد وَاغْفِرْ لى وَارْحَمْنى وَتُبْ عَلَيَّ اِنَّكَ اَنْتَ التَّوابُ الرَّحيمُ . وفي المتهجّد كَريمٌ رَؤوفٌ رَحيمٌ بدل التَّوابُ الرَّحيمُ ."},{"type":"AboutText","content":"قال المجلسي (رحمه الله) : انّ هذه الصلاة مِنَ الصلوات المشهورة وقد رواها العامّة والخاصّة وعدّها بعضهم مِن صلوات يَوم الجُمعة ولم يظهر من الرّواية اختصاص به ويجزى عَلى الظّاهر أن يؤتى بها في سائر الايّام ."}],"preview":"رَوى السّيد ابن طاووس (رحمه الله) بسند معتبر عن الرّضا صلوات الله عليه انّه سئل عن صلاة جعفر الطّيّار (رحمه الله)فقال : أين أنت عن صلاة النّبي (صلى الله عليه وآله وسلم) فعسى رسُول","hasTranslate":false},{"id":"mf_ar_21","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"وَمنها صلاة أمير المؤمِنين (عليه السلام(","blocks":[{"type":"Text","content":"روى الشّيخ والسيّد عن الصّادق (عليه السلام): انّه قال من صلّى منكم أربع ركعات صلاة أمير المؤمنين (عليه السلام)خَرَج من ذُنوبه كيوم ولدته أمّه وقضيت حوائجه ."},{"type":"Text","content":"يقرأ في كلِّ رَكعة الحَمد مرّة وخمسين مرّة الاخلاص(قُلْ هُوَ اللهُ أحَدٌ) فاذا فرغ مِنها دعا بهذا الدّعاء وَهو تسبيحُه (عليه السلام) :"},{"type":"Text","content":"سُبْحانَ مَنْ لا تَبيدُ مَعالِمُهُ سُبْحانَ مَنْ لا تَنْقُصُ خَزائنُهُ سُبْحانَ مَنْ لاَ اضْمِحْلالَ لِفَخْرِهِ سُبْحانَ مَنْ لا يَنْفَدُ ما عِنْدَهُ سُبحانَ مَنْ لاَ انْقِطاعَ لِمُدَّتِهِ سُبْحانَ مَنْ لا يُشارِكُ اَحَداً فى اَمْرِهِ سُبْحانَ مَنْ لا اِلـهَ غَيْرُهُ ويَدعُو بعد ذلك ويقول :"},{"type":"Text","content":"يا مَنْ عَفا عَنِ السَّيِئاتِ وَلَمْ يُجازِ بِهَا ارْحَمْ عَبْدَكَ يا اَللهُ، نَفْسى نَفْسى اَنَا عَبْدُكَ يا سَيِّْداهُ اَنَا عَبْدُكَ بَيْنَ يَدَيْكَ يا رَبّاهُ اِلـهى بِكَيْنُونَتِكَ يا اَمَلاهُ يا رَحْماناهُ يا غِياثاهُ عَبْدُكَ عَبْدُكَ لا حيلَةَ لَهُ يا مُنتَهى رَغْبَتاهُ يا مُجْرِيَ الدَّمِ في عُرُوقي يا سَيِّداهُ يا مالِكاهُ اَيا هُوَ اَيا هُوَ يا رَبّاهُ، عَبْدُكَ عبدك لا حيلَةَ لي وَلا غِنى بي عَنْ نَفسْي وَلا اَسْتَطيعُ لَها ضَرّاً وَلا نَفْعاً وَلا اَجِدُ مَنْ اُصانِعُهُ تَقَطَّعَتْ اَسْبابُ الْخَدائِعِ عَنّي وَاضْمَحَلَّ كُلُّ مَظْنُون عّنى اَفْرَدَنِى الدَّهْرُ اِلَيْكَ فَقُمْتُ بَيْنَ يَدَيْكَ هذَا الْمَقامَ، يا اِلـهى بِعِلْمِكَ كانَ هذا كُلُّهُ فَكَيْفَ اَنْتَ صانِعٌ بي وَلَيْتَ شِعْري كَيْفَ تَقُولُ لِدُعائي اَتَقُولُ نَعْمَ اَمْ تَقُولُ لا، فَاِنْ قُلْتَ لافَيا وَيْلى يا وَيْلى يا ويْلى يا عَوْلى يا عَوْلى يا عَوْلى يا شِقْوَتى يا شِقْوَتى يا شِقْوَتى يا ذُلّي يا ذُلّى يا ذُلّى اِلى مَنْ وَمِمَّنْ اَوْ عِنْدَ مَنْ اَوْ كَيْفَ اَوْ ماذا اَوْ اِلى اَيِّ شَيء اَلْجَأ وَمَنْ اَرْجُو وَمَنْ يَجُودُ عَليَّ بِفَضْلِهِ حينِ تَرْفُضُنى يا واسِعَ الْمَغْفِرَةِ، وَاِنْ قُلْتَ نَعَمْ كَما هُوَ الظَّنُّ بِكَ وَالرَّجاءُ لَكَ فَطُوبى لي اَنَا السَّعيدُ وَاَناَ الْمَسْعُودُ فَطُوبى لى وَاَنَا الْمَرْحُومُ يا مُتَرَحِّمُ يامُتَرَئّفُ يا مُتَعَطِّفُ يا مُتَجَبِّرُ (يا متحنّن) يا مُتَمَلِّكُ يا مُقْسِطُ لا عَمَلَ لى اَبْلُغُ بِهِ نَجاحَ حاجَتى أَسْأَلُكَ بِاْسمِكَ الَّذي جَعَلْتَهُ فى مَكْنُونِ غَيْبِكَ وَاسْتَقَرَّ عِنْدَكَ فَلا يَخْرُجُ مِنْكَ اِلى شَيء سِواكَ أَسْأَلُكَ بِهِ وَبِكَ (بك وبه) فَاِنَّهُ اَجَلُّ وَاَشْرَفُ اَسْمائِكَ لا شَيءَ لي غَيْرُ هذا وَلا اَحَدَ اَعْوَدُ عَليَّ مِنْكَ يا كَيْنُونُ يا مُكَوِّنُ يا مَنْ عَرَّفَنى نَفْسَهُ يا مَنْ اَمَرَنى بِطاعَتِهِ يا مَنْ نَهانى عَنْ مَعْصِيَتِهِ وَيا مَدْعُوُّ يا مَسْؤوُلُ يا مَطْلُوباً اِلَيْهِ رَفَضْتُ وَصِيَّتَكَ الَّتى اَوْصَيْتَنى وَلَمْ اُطِعْكَ وَلَوْ اَطَعْتُكَ فيما اَمَرْتَنى لَكَفَيْتَنى ما قُمْتُ اِلَيْكَ فيهِ وَاَنَا مَعَ مَعْصِيَتى لَكَ راج فَلا تَحُلْ بَيْنى وَبَيْنَ ما رَجَوْتُ يا مُتَرَحِّماً لى اَعِذْني مِنْ بَيْنِ يَدَيَّ وَمِنْ خَلْقى وَمِنْ فَوْقى وَمِنْ تَحْتى وَمِنْ كُلِّ جِهاتِ الاِحاطَةِ بى اَللّـهُمَّ بِمُحَمَّد سَيِّدي وَبِعَلِيٍّ وَلِيّى وَبِالاَْئِمَةِ الرّاشِدينَ عليهم السلام اجْعَلْ عَلَيْنَا صَلَواتِكَ وَرَأْفَتَكَ وَرَحْمتَكَ وَأْوسِعْ عَلَيْنا مِنْ رِزْقِكَ وَاقْضِ عَنَّا الدَّيْنَ وَجَميعَ حَوائِجِنا يا اَللهُ يا اَللهُ يا اَللهُ اِنَّكَ عَلى كُلِّ شَيْء قَديرٌ ."},{"type":"Text","content":"ثمّ قال (عليه السلام): مَن صلّى هذه الصلاة ودعا بهذا الدّعاء انفتل وَلم يبق بينه وَبين الله تعالى ذنبٌ الاَّ غفره لَه ."},{"type":"AboutText","content":"أقول: وردتنا أحاديث كثيرة في فضل هذه الاربع ركعات في يوم الجمعة واذا قال المُصلّي بعدما فرغ مِنها (اَللّـهُمَّ صَلِّ عَلى النَّبِيِّ الْعَرَبِيِّ وَالِهِ) ففي الحديث انّه يغفر لَه ما تقدّم مِن ذنبِه وما تأخّر وكان كمن ختم القرآن اثنتي عشرة ختمة ورفع الله عنه عطشِ يوم القِيامة ."}],"preview":"روى الشّيخ والسيّد عن الصّادق (عليه السلام): انّه قال من صلّى منكم أربع ركعات صلاة أمير المؤمنين (عليه السلام)خَرَج من ذُنوبه كيوم ولدته أمّه وقضيت حوائجه .","hasTranslate":false},{"id":"mf_ar_22","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"وَمنها صلاة فاطِمة صَلَواتُ الله عَلَيها","blocks":[{"type":"AboutText","content":"رُوي انّه كانت لفاطمة (عليها السلام) ركعتان تصلّيهما علّمها جبرئيل (عليه السلام)"},{"type":"Text","content":"تقرأ في الرّكعة الاُولى بَعد الفاتِحة سُورة القدر مائة مرّة وفي الثّانية بعد الحمد تقرأ سُورة التّوحيد واذا سلمت قالت :"},{"type":"Text","content":"سُبحانَ ذِي الْعِزِّ الشّامِخِ المُنيفِ سُبحانَ ذِي الْجَلالِ الْباذِخِ الْعَظيمِ سُبحانَ ذِي الْمُلْكِ الْفاخِرِ الْقَديمِ سُبحانَ مَنْ لَبِسَ الْبَهْجَةَ وَالْجَمالَ سُبحانَ مَنْ تَرَدّى بِالنُّورِ وَالْوَقارِ سُبحانَ مَنْ يَرى اَثَرَ الَّنمْلِ فى الصَّفا سُبحانَ مَنْ يَرى وَقْعَ الطَّيْرِ فِى الْهَواءِ سُبحانَ مَنْ هُوَ هكَذا لا هكَذا غَيْرُهُ ."},{"type":"AboutText","content":"قال السّيد: وروي انّه يُسبح بعد الصلاة تسبيحها المنقول عقيب كلّ فريضة، ثمّ يصلّي على محمّد وآل محمّد مائة مرّة، وقال الشّيخ في كتاب مِصباح المتهجدين: انّ صلاة فاطمة (عليها السلام) ركعتان تقرأ في الاُولى الحمد وسورة القدر مائة مرّة، وفي الثانية بعد الحمد سورة التّوحيد مائة مرّة، فاذا سلّمت سبّحت تسبيحُ الزّهراء (عليها السلام) ثمّ تقول (سُبْحَانَ ذِي الْعِزِّ الشّامِخِ) الى آخر ما مرّ من التّسبيح ثمّ قالَ : وينبغي لمَن صلّى هذه الصلاة وفرغ من التّسبيح أن يكشف رُكبتيه وذراعَيْه ويُباشر بجميع مَساجده الارض بغير حاجز يحْجز بَيْنه وبيْنها ويَدعو ويسأل حاجته وما شاءَ مِنَ الدّعاء ويقول وَهو ساجِدٌ :"},{"type":"Text","content":"يا مَنْ لَيْسَ غَيْرَهُ رُبٌّ يُدْعى، يا مَنْ لَيْسَ فَوْقَهُ اِلهٌ يُخْشى، يا مَنْ لَيْسَ دُونَهُ مَلِكٌ يُتَّقى، يا مَنْ لَيْسَ لَهُ وَزيْرٌ يُؤْتى، يا مَنْ لَيْسَ لَهُ حاجِبٌ يُرْشى، يا مَنْ لَيْسَ لَهُ بَوّابٌ يُغْشى، يا مَنْ لا يَزْدادُ عَلى كَثْرَةِ السُّؤالِ إلاّ كَرَماً وَجُوداً وَعَلى كَثْرَةِ الذُّنُوبِ إلاّ عَفْواً وَصُفْحاً صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَافْعَلْ بى كَذا وَكَذا . ويسأل حاجته ."},{"type":"Text","content":"صلاة اُخرى لها (عليها السلام) روى الّشيخ والسّيد عن صفوان قال : دخل محمّد بن عليّ الحلبي على الصّادق (عليه السلام) في يوم الجُمعة فقال له : تعلّمني أفضل ما أصنع في هذا اليوم ، فقال : يا محمّد ما أعلم انّ أحداً كان أكبر عند رسول الله (صلى الله عليه وآله وسلم) من فاطِمة ولا أفضل ممّا علّمها أبوها محمّد بن عبد الله (صلى الله عليه وآله وسلم) قال : من أصبح يوم الجمعة فاغتسل وصفّ قدَميْه وصلّى أربع ركعات مثنى مثنى يقرأ في أوّل ركعة فاتحة الكتاب وقل هو الله أحد خمسين مرّة، وفي الثانية فاتحة الكتاب والعاديات خمسين مرّة، وفي الثّالثة فاتحة الكتاب واذا زلزلت خمسين مرّة، وفي الرّابعة فاتحة الكتاب واذَا جاءَ نصرُ اللهِ خمسين مرّة وهذه سورة النّصر وهي آخر سورة نزلت فاذا فرغ منها دعا فقال :"},{"type":"Text","content":"يا اِلـهي وَسَيِّدي مَنْ تَهَيَّأَ أو تَعَّبَأ اَوْ اَعَدَّ اَوِ اسْتَعَدَّ لِوِفادَةِ مَخْلُوق رَجاءَ رِفْدِهِ وَفَوائِدِهِ وَنائِلِهِ وَفَواضِلِهِ وَجَوائِزِهِ فَاِلَيْكَ يا اِلـهي كانَتْ َتهيئتي وتعبئتي وَاِعْدادي وَاسْتِعْدادي رَجاءَ فَوائِدِكَ وَمَعْرُوفِكَ وَنائِلِكَ وَجَوائِزِكَ فَلا تُخَيِّبْني مِنْ ذلِكَ يا مَنْ لا تَخيبُ عَلَيْهِ مَسْأَلةُ السّائِل وَلا تَنْقُصُهُ عَطِيَّةُ نائِل، فَانّى لَمْ آتِكَ بعَمَل صالِح قَدَّمْتُهُ وَلا شَفاعَةِ مَخْلُوق رَجَوْتُهُ اَتَقَرَّبُ اِلَيْكَ بِشَفاعَتِهِ إلاّ مُحَمَّداً وَاَهْلَ بَيْتِهِ صََواتُكَ عَلَيْهِ وَعَلَيْهِمْ اَتَيْتُكَ اَرْجُو عَظيمَ عَفْوِكَ الَّذي عُدْتَ بِهِ عَلَى الْخَطّائينَ عِنْدَ عُكُوفِهِمْ عَلَى الَْمحارِمِ، فَلَمْ يَمْنَعْكَ طُولُ عُكُوفِهِمْ عَلَى الَْمحارِمِ اَنْ جُدْتَ عَلَيْهِمْ بِالْمَغْفِرَةِ وَاَنْتَ سَيِّدي الْعَوّادُ بِالنَّعْماء وَاَنَا الْعَوّادُ بِالْخَطاءِ أَسْأَلُكَ بِحَقِّ مُحَمَّد وآلِهِ الطّاهِرِينَ اَنْ تَغْفِرَ لي ذَنْبي الْعَظيمَ فَاِنَّهُ لا يَغْفِرُ الْعَظيمَ إلاّ الْعَظيمُ يا عَظيمُ يا عَظيمُ يا عَظيمُ يا عَظيمُ يا عَظيمُ يا عَظيمُ يا عَظيمُ ."},{"type":"AboutText","content":"أقول قد روى السّيد بن طاوس (رحمه الله) في كتاب جمال الاسبوع لكلّ من الائمة (عليهم السلام) صلاة خاصّة ودعاءً وينبغي لنا ذكرها هُنا قال :"}],"preview":"رُوي انّه كانت لفاطمة (عليها السلام) ركعتان تصلّيهما علّمها جبرئيل (عليه السلام)","hasTranslate":false},{"id":"mf_ar_23","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"دُعاء الحَسن (عليه السلام)","blocks":[{"type":"Text","content":"اَللّهُمَّ اِنّي اَتَقَرَّبُ اِلَيْكَ بِجُودِكَ وَكَرَمِكَ وَاَتَقرَّبُ اِلَيْكَ بِمُحَمَّد عَبْدِكَ وَرَسُولِكَ وَاَتَقَرَّبُ اِلَيْكَ بِمَلائِكَتِكَ الْمُقَرَّبينَ وَاَنْبِيائِكَ وَرُسُلِكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد عَبْدِكَ وَرَسُولِكَ وَعَلى آلِ مُحَمَّد وَاْنَ تُقيلَني عَثْرَتي وَتَسْتُرَ عَلَيَّ ذُنُوبي وَتَغْفِرَها لي وَتَقْضِيَ لي حَوائجي وَلا تُعَذِّبْني بِقَبيح كانَ مِنّي فَاِنَّ عَفْوَكَ وَجُودَكَ يَسَعُني اِنَّكَ على كُلِّ شَيء قَديرٌ ."}],"preview":"اَللّهُمَّ اِنّي اَتَقَرَّبُ اِلَيْكَ بِجُودِكَ وَكَرَمِكَ وَاَتَقرَّبُ اِلَيْكَ بِمُحَمَّد عَبْدِكَ وَرَسُولِكَ وَاَتَقَرَّبُ اِلَيْكَ بِمَلائِكَتِكَ الْمُقَرَّبينَ وَاَنْبِيائِكَ","hasTranslate":false},{"id":"mf_ar_24","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"صلاة الحُسين (عليه السلام)","blocks":[{"type":"Text","content":"أربع ركعات تقرأ في كلّ ركعة كلا من الفاتحة والتّوحيد خمسين مرّة واذا ركعت في كلّ ركعة تقرأ الفاتحة عشراً والاخلاص عشراً وكذلك اذا رفعت رأسك من الرّكوع وكذلك في كلّ سجدة وبين كلّ سجدتين ، فاذا سلمت فادعُ بهذا الدّعآء : اَللّـهُمَّ اَنْتَ الَّذي اسْتَجَبْتَ لادَمَ وَحَوّاءَ الى آخر الدعاء وهي طويلة ."}],"preview":"أربع ركعات تقرأ في كلّ ركعة كلا من الفاتحة والتّوحيد خمسين مرّة واذا ركعت في كلّ ركعة تقرأ الفاتحة عشراً والاخلاص عشراً وكذلك اذا رفعت رأسك من الرّكوع وكذلك في كلّ سجدة وبين كلّ سج","hasTranslate":false},{"id":"mf_ar_25","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"صلاة الامامِ زينِ العابِدينَ (عليه السلام)","blocks":[{"type":"Text","content":"أربع ركعات كلّ ركعة بالفاتحة مرّة والاخلاص مائة مرّة ."}],"preview":"أربع ركعات كلّ ركعة بالفاتحة مرّة والاخلاص مائة مرّة .","hasTranslate":false},{"id":"mf_ar_26","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"دُعاؤهُ(عليه السلام)","blocks":[{"type":"Text","content":"يا مَنْ اَظْهَرَ الْجَميلَ وَسَتَرَ الْقَبيحَ يا مَنْ لَمْ يُؤاخِذْ بِالْجَريرَةِ وَلَمْ يَهْتِكِ السِّتْرَ يا عَظيمَ الْعَفْوِ يا حَسَنَ التَّجاوُزِ يا واسِعَ الْمَغْفِرَةِ يا باسِطَ الْيَدَيْنِ بِالرَّحْمَةِ يا صاحِبَ كُلِّ نَجْوى يا مُنْتَهى كُلِّ شَكْوى يا كَريمَ الصَّفْحِ يا عَظيمَ الرَّجاءِ يا مُبْتَدِئاً باِلنِّعَمِ قَبْلَ اسْتِحْقاقِها يا رَبنا وَسَيِّدَنا وَمَوْلانا يا غايَهَ رَغْبَتِنا أَسْأَلُكَ اَللّـهُمَّ اَنْ تُصَلِّيَ عَلَى مُحَمَّد وآلِ مُحَمَّد ."}],"preview":"يا مَنْ اَظْهَرَ الْجَميلَ وَسَتَرَ الْقَبيحَ يا مَنْ لَمْ يُؤاخِذْ بِالْجَريرَةِ وَلَمْ يَهْتِكِ السِّتْرَ يا عَظيمَ الْعَفْوِ يا حَسَنَ التَّجاوُزِ يا واسِعَ الْمَغْفِرَةِ يا باس","hasTranslate":false},{"id":"mf_ar_27","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"صلاة الباقِرِ (عليه السلام)","blocks":[{"type":"Text","content":"ركعتان كلّ ركعة بالحمد مرّة و سُبْحانَ اللهِ وَاَلْحَمْدُ للهِ وَلا اِلـهَ إلاّ اللهُ وَاَللهُ اَكْبَرُ مائة مرّة ."}],"preview":"ركعتان كلّ ركعة بالحمد مرّة و سُبْحانَ اللهِ وَاَلْحَمْدُ للهِ وَلا اِلـهَ إلاّ اللهُ وَاَللهُ اَكْبَرُ مائة مرّة .","hasTranslate":false},{"id":"mf_ar_28","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"دُعاءُ الباقِرِ (عليه السلام)","blocks":[{"type":"Text","content":"اَللّـهُمَّ اِنّي أَسْأَلُكَ يا حَليمُ ذُو اَناة غَفُورٌ وَدُودٌ اَنْ تَتَجاوَزَ عَنْ سَيِّئاتى وَما عِنْدى بِحُسْنِ ما عِنْدَكَ وَاَنْ تُعْطِيَنى مِنْ عَطائِكَ ما يَسَعُنى وَتُلْهِمَنى فيمااَعْطَيْتَنى الْعَمَلَ فيهِ بِطاعَتِكَ وَطاعَةِ رَسُولِكَ وَاَنْ تُعْطِيَنى مِنْ عَفْوِكَ ما اَسْتَوْجِبُ بِهِ كَرامَتَكَ اَللّـهُمَّ اَعْطِنى ما اَنْتَ أهْلُهُ وَلا تَفْعَلْ بى ما اَنَا اَهْلُهُ فَاِنَّما اَنَا بِكَ وَلَمْ اُصِبْ خَيْراً قَطُّ إلاّ مِنْكَ يا اَبْصَرَ الاَبْصَرينَ وَيا اَسْمَعَ السّامِعِينَ وَيا اَحْكَمَ الْحاكِمينَ وَيا جارَ الْمُسْتَجيرينَ وَيا مُجيبَ دَعْوَةِ الْمُضْطَرّينَ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد ."}],"preview":"اَللّـهُمَّ اِنّي أَسْأَلُكَ يا حَليمُ ذُو اَناة غَفُورٌ وَدُودٌ اَنْ تَتَجاوَزَ عَنْ سَيِّئاتى وَما عِنْدى بِحُسْنِ ما عِنْدَكَ وَاَنْ تُعْطِيَنى مِنْ عَطائِكَ ما يَسَعُنى وَتُلْه","hasTranslate":false},{"id":"mf_ar_29","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"صلاة الصّادقِ (عليه السلام)","blocks":[{"type":"Text","content":"ركعتان كلّ ركعة بالفاتحة مرّة وآية شَهِدَ الله مائة مرّة ."}],"preview":"ركعتان كلّ ركعة بالفاتحة مرّة وآية شَهِدَ الله مائة مرّة .","hasTranslate":false},{"id":"mf_ar_30","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"دُعاءُ الصّادقِ (عليه السلام)","blocks":[{"type":"Text","content":"يا صانِعَ كُلِّ مَصْنُوع يا جابِرَ كُلِّ كَسير (كَسْر) وَيا حاضِرَ كُلِّ مَلاء وَيا شاهِدَ كُلِّ نَجْوى وَيا عالِمَ كُلِّ خَفِيَّة وَيا شاهِدُ غَيْرُ غائب وَغالِبُ غَيْرُ مَغْلُوب وَيا قَريبُ غَيْرُ بَعيد وَيا مُونِسَ كُلِّ وَحيد وَيا حَيُّ مُحْيِي الْمَوْتى وَمُميتَ الاَحْياءِ الْقائِمُ عَلى كُلِّ نَفْس بِما كَسَبَتْ وَيا حَيّاً حينَ لا حَيَّ لا إله إلاّ اَنْتَ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد ."}],"preview":"يا صانِعَ كُلِّ مَصْنُوع يا جابِرَ كُلِّ كَسير (كَسْر) وَيا حاضِرَ كُلِّ مَلاء وَيا شاهِدَ كُلِّ نَجْوى وَيا عالِمَ كُلِّ خَفِيَّة وَيا شاهِدُ غَيْرُ غائب وَغالِبُ غَيْرُ مَغْلُوب","hasTranslate":false},{"id":"mf_ar_31","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"صلاة الكاظِم (عليه السلام)","blocks":[{"type":"Text","content":"ركعتان تقرأ في كلّ ركعة الحمد مرّة والتّوحيد اثنتي عشرة مرّة ."}],"preview":"ركعتان تقرأ في كلّ ركعة الحمد مرّة والتّوحيد اثنتي عشرة مرّة .","hasTranslate":false},{"id":"mf_ar_32","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"دُعاؤه (عليه السلام)","blocks":[{"type":"Text","content":"اِلـهى خَشَعَتِ الاصْواتُ لَكَ وَضَلَّتِ الاَحْلامُ فيكَ وَوَجِلَ كُلُّ شَيء مِنْكَ وَهرَبَ كُلُّ شَيء اِلَيْكَ وَضاقَتِ الاَشْياءُ دُونَكَ وَمَلاَ كُلَّ شَيء نُورُكَ فَأَنْتَ الرَّفيعُ في جَلالِكَ وَاَنْتَ الْبَهِيُّ فى جَمالِكَ وَاَنْتَ الْعَظيمُ فى قُدْرَتِكَ وَاْنَتَ الَّذى لا يَؤودُكَ شَيءٌ يامُنْزِلَ نِعْمَتى يا مُفَرِّجَ كُرْبَتى وَيا قاضِي حاجَتي اَعْطِني مَسْأَلَتي بِلا اِلـهَ إلاّ اَنْتَ آمَنْتُ بِكَ مُخْلِصاً لَكَ ديني، اَصْبَحْتُ عَلى عَهْدِكَ وَوَعْدِكَ مَا اسْتَطَعْتُ، اَبُوءُ لَكَ بِالنِّعْمَةِ وَاَسْتَغْفِرُكَ مِنْ الذُّنُوبِ الَّتى لايَغْفِرُها غَيْرُكَ يا مَنْ هُوَ في عُلُوِّهِ دان وَفي دُنُوِّهِ عال وَفي اِشْراقِهِ مُنيرٌ وفي سُلْطانِهِ قَوِيٌّ صَلِّ عَلى مُحَمَّد وَآلِهِ ."}],"preview":"اِلـهى خَشَعَتِ الاصْواتُ لَكَ وَضَلَّتِ الاَحْلامُ فيكَ وَوَجِلَ كُلُّ شَيء مِنْكَ وَهرَبَ كُلُّ شَيء اِلَيْكَ وَضاقَتِ الاَشْياءُ دُونَكَ وَمَلاَ كُلَّ شَيء نُورُكَ فَأَنْتَ الرّ","hasTranslate":false},{"id":"mf_ar_33","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"صلاة الرِّضا (عليه السلام)","blocks":[{"type":"Text","content":"ستّ ركعات كل ركعة بالفاتحة مرّة و (هَلْ أتى على الانْسانِ) عشر مرّات ."}],"preview":"ستّ ركعات كل ركعة بالفاتحة مرّة و (هَلْ أتى على الانْسانِ) عشر مرّات .","hasTranslate":false},{"id":"mf_ar_35","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"صلاة الجواد (عليه السلام)","blocks":[{"type":"Text","content":"ركعتان كلّ ركعة بالفاتحة مرّة والاخلاص سبعين مرّة ."}],"preview":"ركعتان كلّ ركعة بالفاتحة مرّة والاخلاص سبعين مرّة .","hasTranslate":false},{"id":"mf_ar_36","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"دُعاؤُه (عليه السلام)","blocks":[{"type":"Text","content":"اَللّـهُمَّ رَبَّ الاَرْواحِ الْفانِيَةِ وَالاَجْسادِ الْبالِيَةِ أَسْأَلُكَ بِطاعَةِ الاَرْواحِ الرّاجِعَةِ اِلى اَجْسادِها وَبِطاعَةِ الاَجْسادِ الْمُلْتَئِمَةِ بِعُرُوقِها وَبِكَلِمَتِكَ النّافِذَةِ بَيْنَهُمْ وَاَخْذِكَ الْحَقَّ مِنْهُمْ وَالْخَلائقُ بَيْنَ يَدَيْكَ يَنْتَظِرُونَ فَصْلَ قَضائِكَ وَيَرْجُونَ رَحْمَتَكَ وَيَخافُونَ عِقابِكَ، صَلِّ عَلى مُحَمَّد وَاجْعَلِ النُّورَ فى بَصَرى وَالْيَقينَ فى قَلْبى وَذِكْرَكَ باِللَّيْلِ وَالنَّهارِ على لِسانى، وَعَملاً صالِحاً فَارْزُقْني ."}],"preview":"اَللّـهُمَّ رَبَّ الاَرْواحِ الْفانِيَةِ وَالاَجْسادِ الْبالِيَةِ أَسْأَلُكَ بِطاعَةِ الاَرْواحِ الرّاجِعَةِ اِلى اَجْسادِها وَبِطاعَةِ الاَجْسادِ الْمُلْتَئِمَةِ بِعُرُوقِها وَبِك","hasTranslate":false},{"id":"mf_ar_37","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"صلاة الهادى (عليه السلام)","blocks":[{"type":"Text","content":"ركعتان تقرأ في الاولى الفاتحة ويس وفي الثّانية الحمد والرّحمن ."}],"preview":"ركعتان تقرأ في الاولى الفاتحة ويس وفي الثّانية الحمد والرّحمن .","hasTranslate":false},{"id":"mf_ar_39","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"صلاة الحَسنِ العَسكرىِّ (عليه السلام)","blocks":[{"type":"Text","content":"أربع ركعات الرّكعتان الاوليان بالحمد مرّة واذا زلزلت خمس عشرة مرّة والاخيرتان كلّ ركعة بالحمد مرّة والاخلاص خمس عشرة مرّة ."}],"preview":"أربع ركعات الرّكعتان الاوليان بالحمد مرّة واذا زلزلت خمس عشرة مرّة والاخيرتان كلّ ركعة بالحمد مرّة والاخلاص خمس عشرة مرّة .","hasTranslate":false},{"id":"mf_ar_41","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"صلاة الحُجّةِ القائمِ عَجَّلَ اللهُ تعالى فَرَجهُ الشّريفَ","blocks":[{"type":"Text","content":"ركعتان تقرأ في كلّ ركعة فاتحة الكتاب الى (إيّاكَ نَعْبُدُ وَإيّاكَ نَسْتَعينُ) ثمّ تكرّر هذه الاية مائة مرّة ثمّ تتمّ قراءة الفاتحة وتقرأ بعدها الاخلاص (قُلْ هُوَ اللهُ اَحَدٌ) مرّة واحدة وتدعو عقيبهما فتقول :"},{"type":"Text","content":"اَللّـهُمَّ عَظُمَ الْبَلاءُ وَبَرِحَ الْخَفاءُ وَانْكَشَفَ الْغِطاءُ وَضاقَتِ الاَرْضُ بِما وَسِعَتِ السَّماءُ وَاِلَيْكَ يا رَبِّ الْمُشْتَكى وَعَلَيْكَ الْمُعَوَّلُ فِي الشِّدَةِ وَالرَّخاءِ اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد الَّذينَ اَمَرْتَنا بِطاعَتِهِمْ وَعَجِّل اَللّـهُمَّ فَرَجَهُمْ بِقائِمِهِمْ وَاَظْهِرْ اِعْزازَهُ يا مُحَمَّدُ يا عَليُّ يا عَلِيُّ يا مُحَمَّدُ اِكْفِياني فَاِنَّكُما كافِيايَ يا مُحَمَّدُ يا عَليُّ يا عَلِيُّ يا مُحَمَّدُ اُنْصُراني فَاِنَّكُما ناصِرايَ يا مُحَمَّدُ يا عَليُّ يا عَلِيُّ يا مُحَمَّدُ اِحْفِظاني فَاِنَّكُما حافِظايَ يامَوْلايَ يا صاحِبَ الزَّمانِ يا مَوْلايَ يا صاحِبَ الزَّمانِ يا مَوْلايَ يا صاحِبَ الزَّمانِ الْغَوْثَ الْغَوْثَ الْغَوْثَ، اَدْرِكْني اَدْرِكْني اَدْرِكْني، الاَمانَ الاَمانَ الاَمانَ ."}],"preview":"ركعتان تقرأ في كلّ ركعة فاتحة الكتاب الى (إيّاكَ نَعْبُدُ وَإيّاكَ نَسْتَعينُ) ثمّ تكرّر هذه الاية مائة مرّة ثمّ تتمّ قراءة الفاتحة وتقرأ بعدها الاخلاص (قُلْ هُوَ اللهُ اَحَدٌ) مرّ","hasTranslate":false},{"id":"mf_ar_42","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"صلاة جَعفر الطّيّارِ (عليه السلام)","blocks":[{"type":"Text","content":"وهي الاكسير الاعظم والكبريت الاحمر وهي مرويّة بما لها من الفضل العظيم باسناد معتبرة غاية الاعتبار واهمّ ما لها من الفضل غفران الذّنوب العظام وأفضل أوقاتها صدر النّهار يوم الجمعة وهي أربع ركعات بتشهّدين وتسليمتين يقرأ في الرّكعة الاُولى سورة الحمد واذا زلزلت وفي الرّكعة الثانية سورة الحمد والعاديات وفي الثّالثة الحمد واِذا جآءَ نصرُ اللهِ وفي الرابعة الحمد وقُلْ هوَ اللهُ احدٌ فاذا فرغ من القراءة في كلّ ركعة فليقل قبل الرّكوع خمس عشرة مرّة سُبْحانَ اللهِ وَاَلْحَمْدُ للهِ وَلا اِلـهَ إلاّ اللهُ وَاَللهُ اَكْبَرُ ويقولها في ركوعه عشراً واذا اسْتوى من الرّكوع قائماً قالها عشراً فاذا سجد قالها عشراً فاذا جلس بين السّجدتين قالها عشراً فاذا سجد الثّانية قالها عشراً فاذا جلس ليقوم قالها قبل أن يقومُ عشراً يفعل ذلك في الاربع ركعات فتكون ثلاثمائة تسبيحة ."},{"type":"Text","content":"روى الكليني عن أبي سعيد المدائني قال : قال الصادق (عليه السلام) : ألا أعلّمك شيئاً تقوله في صلاة جعفر (عليه السلام) ، قلت : بلى ، قال : قل اذا فرغت من التّسبيحات في السّجدة الثانية من الرّكعة الرابعة : سُبْحانَ مَنْ لَبِسَ الْعِزَّ وَالْوَقارَ سُبْحانَ مَنْ تَعَطَّفَ بِالَْمجْدِ وَتَكَرَّمَ بِهِ سُبْحانَ مَنْ لا يَنْبَغِي التَّسْبيحُ إلاّ لَهُ سُبْحانَ مَنْ اَحْصى كُلِّ شَىْء عِلْمُهُ سُبْحانَ ذِي الْمَنِّ وَالنِّعَمِ سُبْحانَ ذِي الْقُدْرَةِ وَالْكَرَمِ اَللّـهُمَّ اِنّي أَسْأَلُكَ بِمَعاقِدِ الْعِزِّ مِنْ عَرْشِكَ وَمُنْتَهَى الرَّحْمَةِ مِنْ كِتابِكَ وَاسْمِكَ الاَْعْظَمِ وَكَلِماتِكَ التّامَّةِ الَّتى تَمَّتْ صِدْقاً وَعَدْلاً صَلِّ عَلى مُحَمَّد وَاَهْلِ بَيْتِهِ وَافْعَلْ بى كَذا وَكَذا وتطلب حاجتك عوض كلمة كذا وكذا ."},{"type":"Text","content":"روى الشيخ والسيّد عن المفضّل بن عمر قال رأيت الصّادق (عليه السلام) صلّى صلاة جعفر بن أبي طالب (عليه السلام)ورفع يديه ودعا بهذا الدّعاء :"},{"type":"Text","content":"يا رَبِّ يا رَبِّ حتّى انقطع النّفس يا ربّاهُ يا ربّاهُ حتّى انقطع النّفس رَبِّ رَبِّ حتّى انقطع النّفس يا اَللّهُ يا اَللّهُ حتّى انقطع النّفس يا حَيُّ يا حَيُّ حتّى انقطع النّفس يا رَحيمُ يا رَحيمُ حتّى انقطع النّفس يا رَحْمنُ يا رَحْمنُ سبع مرّات يا اَرْحَمَ الرّاحِمينَ سبع مرّات ثمّ قال :"},{"type":"Text","content":"اَللّـهُمَّ اِنّي اَفْتَتِحُ الْقَوْلَ بِحَمْدِكَ وَاَنْطِقُ بِالثَّناءِ عَلَيْكَ وَاُمَجِّدُكَ وَلاغايَةَ لِمَدْحِكَ وَاُثْني عَلَيْكَ وَمَنْ يَبْلُغُ غايَةَ ثَنائِكَ وَاَمَدَ مَجْدِكَ وَاَنّى لِخَليقَتِكَ كُنْهُ مَعْرِفَةِ مَجْدِكَ وَاَيَّ زَمَن لَمْ تَكُنْ مَمْدُوحاً بِفَضْلِكَ مَوْصُوفاً بِمَجْدِكَ عَوّاداً عَلَى الْمُذْنِبينَ بِحِلْمِكَ تَخَلَّفَ سُكّانُ اَرْضِكَ عَنْ طاعَتِكَ فَكُنْتَ عَلَيْهِمْ عَطُوفاً بِجُودِكَ جَواداً بِفَضْلِكَ عَوّاداً بِكَرَمِكَ يا لا اِلـهَ إلاّ اَنْتَ الْمَنّانُ ذُوالْجَلالِ وَالاِْكْرامِ ."},{"type":"Text","content":"وقال لي يا مفضّل اذا كانت لك حاجة مُهمّة فَصلِّ هذه الصلاة وادع بهذا الدّعاء وسل حاجتك يقضى الله لك ان شاء الله تعالى ."},{"type":"AboutText","content":"أقول : روى الطوسي لقضاء الحوائج عن الصّادق (عليه السلام) قال : صم يوم الاربعاء والخميس والجُمعة فاذا كان عشيّة يوم الخميس تصدّقت على عشرة مساكين مدّاً مُدّاً من الطّعام فاذا كان يوم الجمعة اغتسلت وبرزت الى الصّحراء فصلّ صلاة جعفر بن أبي طالب واكشف عن ركبتيك وألصقهما بالارض وقل :"},{"type":"Text","content":"يا مَنْ اَظْهَرَ الْجَميلَ وَسَتَرَ (عَليَّ) الْقَبيحَ يا مَنْ لَمْ يُؤاخِذْ بِالْجَريرَةِ وَلَمْ يَهْتِكِ السِّتْرِ يا عَظيمَ الْعَفْوِ يا حَسَنَ التَّجاوُزِ يا واسِعَ الْمَغْفِرَةِ يا باسِطَ الْيَدَيْنِ بِالرَّحْمَةِ يا صاحِبَ كُلِّ نَجْوى يا مُنْتَهى كُلِّ شَكْوى يا مُقيلَ الْعَثَراتِ يا كَريمَ الصَّفْحِ يا عَظيمَ الْمَنِّ يا مُبْتَدِئاً باِلنِّعَمِ قَبْلَ اسْتِحْقاقِها يا رَبّاهُ يا رَبّاهُ يا رَبّاهُ عشراً يا اَللهُ يا اَللهُ يا اَللهُ عشراً يا سَيِّداهُ يا سَيِّداهُ يا سَيِّداهُ عشراً يا مَوْلاهُ يا مَوْلاهُ عشراً يا غياثاه عشراً يا غاية رغبتاه عشراً يا رحمان عشراً يا رحيم عشراً يا رَجاءاهُ عشراً يا مُعْطِىَ الْخَيْراتِ عشراً صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد كَثيراً طَيِّباً كَاَفْضَلِ ما صَلَّيْتَ عَلى اَحَد مِنْ خَلْقِكَ عشراً ، واطلب حاجتك ."},{"type":"AboutText","content":"أقول : في روايات كثيرة انّه لقضاء الحوائج تصام هذه الايّام الثّلاثة ثمّ تصلّى ركعتان عند زوال الجمعة ."},{"type":"Text","content":"الحادي والعشرون : من أعمال يوم الجُمعة أن يدعو اذا زالت الشّمس بما رواه محمّد بن مُسلم عن الصّادق صلوات الله وسلامُه عليه وهُو على ما أورده الشّيخ في المصباح أن يقول :"},{"type":"Text","content":"لا اِلـهَ إلاّ اللهُ وَاللهُ اَكْبَرُ وَسُبْحانَ اللهِ اَلْحَمْدُ للهِ الَّذي لَمْ يَتَّخِذْ وَلَداً وَلَمْ يَكُنْ لَهُ شَريكٌ فِي الْمُلْكِ وَلَمْ يَكُنْ لَهُ وَلِيٌّ مِنَ الذُّلِّ وَكَبِّرْهُ تَكْبيراً ثمّ يقولُ : يا سابِغَ النِّعَمِ يا دافِعَ النِّقَمِ يا بارِئَ النَّسَمِ يا عَلِيَّ الْهِمَمِ يا مُغْشِىَ الظُّلَمِ يا ذَا الْجُودِ والْكَرَمِ يا كاشِفَ الضُّرِّ وَالاَلَمِ يا مُونِسَ الْمُسْتَوْحِشينَ فِي الظُّلَمِ يا عالِماً لا يُعَلَّمُ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَافْعَلْ بي ما اَنْتَ اَهْلُهُ يا مَنِ اسْمُهُ دَواءٌ وَذِكْرُهُ شِفاءٌ وَطاعَتُهُ غَناءٌ اِرْحَمْ مَنْ رَأسُ مالِهِ الرَّجاءُ وَسِلاحُهُ الْبُكاءُ سُبْحانَكَ لا اِلـهَ إلاّ اَنْتَ يا حَنّانُ يا مَنّانُ يا بَديعَ السَّماواتِ وَالاَرْضِ يا ذَا الْجَلالِ وَالاِكْرامِ ."},{"type":"Text","content":"الثّاني والعشرون : أن يصلّي فريضة الظّهر يوم الجمعة بسورة الجمعة والمنافقين والعصر بالجمعة والتّوحيد ."},{"type":"Text","content":"روى الشّيخ الصّدوق عن الصّادق (عليه السلام) قال : من الواجب على كلّ مؤمن اذا كان لنا شيعة أن يقرأ في ليلة الجُمعة بالجمعة وسبّح اسم ربّك الاعلى وفي صلاة الظّهر بالجمعة والمنافقين، فاذا فعل ذلك كأنّما يعمل بعمل رسول الله (عليه السلام) وكان جزاؤه وثوابه على الله الجنّة ، وروى الكليني بسند كالصحيح عن الحلبي قال : سألت الصّادق (عليه السلام) عن القراءة في الجمعة اذا صلّيت وحدى (أي لم أصل الجمعة وصلّيت صلاة الظّهر) أربعاً، أجهر بالقراءة ؟ فقال : نعم وقال: اقرأ بسورة الجمعة والمنافقين في يوم الجمعة ."},{"type":"Text","content":"الثالث والعشرون : روى الشّيخ الطوسي (رحمه الله) عند ذكر تعقيب صلاة الظّهر يوم الجُمعة عن الصّادق صَلوات الله وسَلامه عليه ، قال : من قرأ يوم الجمعة حين يسلم الحمد سبع مرّات و (قل اَعُوذُ بِرَبِّ النّاسِ) سبع مرّات وَ (قُلْ اَعُوذُ بربّ الفَلَقِ) سبع مرّات و (قُلْ هُوَ اللهُ اَحَدٌ) سبع مرّات و (قُلْ يا أيُّها الْكافِروُنَ) سبع مرّات وآخر البراءة وهو آية (لَقَدْ جاءَكُمْ رسُولٌ مِنْ اَنفُسِكم) وآخر سورة الحشر (لَوْ أنْزَلْنا هذَا القُرآن) الى آخر السّورة والخمس من آل عمران (اِنَّ في خَلْقِ السَّماواتِ والارضِ) الى (انّك لا تُخلِفُ الميعاد) كفى ما بين الجُمعة الى الجُمعة ."},{"type":"Text","content":"الرّابع والعشرون : وروى عنه (عليه السلام) قال: من قال بعد صلاة الفجر أو بعد صلاة الظّهر: اَللّـهُمَّ اجْعَلْ صَلاتَكَ وَصَلاةَ مَلائكَتِكَ وَرُسُلِكَ على مُحَمَّد وآلِ مُحَمَّد لم يكتب عليه ذنب سنة وقال أيضاً من قال بعد صلاة الفجر أو بعد صلاة الظهر: اللهم صلّ على محمد وآل محمد وعجّل فرجهم، لم يمت حتى يدك القائم(عليه السلام) ."},{"type":"AboutText","content":"أقول: الدعاء الاول من هذين هو اللهم اجعل (الى آخره) يورث الامن من البلاء إلى الجمعة القادمة اذا دُعي به ثلاث مرات بعد فريضة الظهر يوم الجمعة. وروي ايضاً من صلّى على النبيّ وآله(عليهم السلام)بين فريضتين يوم الجمعة كان له من الاجر مثل الصلاة سبعين ركعة."},{"type":"Text","content":"الخامس والعشرون : أن يقرأ الدّعاء يا مَنْ يَرْحَمُ مَنْ لا تَرْحَمُهُ الْعِبادُ والدّعاء اَللّـهُمَّ هـذا يَوْمٌ مُبارَكٌ وهذان من أدعية الصّحيفة الكاملة ."},{"type":"Text","content":"السّادس والعشرون : قال الشّيخ في المصباح: روي عن الائمة (عليهم السلام) انّ من صلّى الظّهر يوم الجُمعة وصلّى بعدها ركعتين يقرأ في الاُولى الحمد وقُل هُوَ الله اَحدٌ سبع مرّات وفي الثّانية مثل ذلك وبعد فراغه: اَللّـهُمَّ اجْعَلْني مِنْ اَهْلِ الْجَنَّةِ الَّتي حَشُوهَا الْبَرَكةُ وَعُمّارُهَا الْمَلائِكَةُ مَعَ نَبِيِّنا مُحَمَّد صَلَّى اللهُ عَلَيْهِ وَآلِهِ وَاَبينا اِبراهيمَ(عليه السلام) لم تضرّه بليّة ولم تصبه فتنة الى الجمعة الاُخرى وجمع الله بينه وبين محمّد وبين ابراهيم (عليهما السلام) ."},{"type":"AboutText","content":"قال العلاّمة المجلسي (رحمه الله) اذا دعا بهذا الدّعاء من لم يكن من سلالة النّبي (صلى الله عليه وآله وسلم) فليقل عوض وأبينا وأبيه ."},{"type":"Text","content":"السّابع والعشرون : روى انّ أفضل ساعات يوم الجمعة بعد العصر وتقول مائة مرّة: اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَعَجِّلْ فَرَجَهُمْ وقال الشيخ يستحبّ أن يقول مائة مرّة: صَلَواتُ اللهِ وَملائِكَتِهِ وَاَنْبِيائِهِ وَرُسُلِهِ وَجَميعِ خَلْقِهِ عَلى مُحَمَّد وَآلِ مُحَمَّد وَالسَّلامُ عَلَيْهِ وَعَلَيْهِمْ وَعَلى اَرْواحِهِمْ وَاَجْسادِهِمْ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ ."},{"type":"AboutText","content":"وروى الشيخ الجليل ابن ادريس في السّرائر عن جامع البزنطي عن أبي بصير قال : سمعت جعفر الصّادق صلوات الله وسلامُه عليهِ يقول : الصلاة على محمّد وآل محمّد فيما بين الظّهر والعصر تعدل سبعين حجّة ومن قال بعد العصر يوم الجمعة: اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد الاَْوْصِياءِ الْمَرْضيّينَ بِاَفْضَلِ صَلَواتِكَ وَبارِكْ عَلَيْهِمْ بِاَفْضَلِ بَرَكاتِكَ وَالسَّلامُ عَلَيْهِمْ وَعَلى اَرْواحِهِمْ وَاَجْسادِهِمْ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ كان له مثل ثواب عمل الثّقلين في ذلك اليوم ."},{"type":"AboutText","content":"أقول: هذه صلاة مرويّة بما لها من الفضل الكثير في كتب مشايخ الحديث باسناد معتبرة جدّاً والافضل أن يكرّرها سبع مرّات وأفضل منه عشر مرّات، فعن الصّادق صلوات الله وسلامه عليه قال : من صلّى بهذه الصلاة حين يصلّي العصر يوم الجُمعة قبل أن ينفتل من صلاته عشر مرّات صلّت عليه الملائكة من تلك الجُمعة الى الجمعة المُقبلة في تلك السّاعة . وعنه (عليه السلام) أيضاً قال : اذا صلّيت العصر يوم الجمعة فصلّ بهذه الصلوة سبع مرّات. وروى الكليني في الكافي انّه اذا صلّيت العصر يوم الجمعة فقل : اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد الاَْوْصِياءِ الْمَرْضيّينَ بِاَفْضَلِ صَلَواتِكَ وَبارِكْ عَلَيْهِمْ بِاَفْضَلِ بَرَكاتِكَ وَالسَّلامُ عَلَيْهِ وَعَلَيْهِمْ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ فانّ من قالها بعد العصر كتب الله عزوجل له مائة ألف حسنة، ومحا عنه مائة ألف سيّئة، وقضى له بها مائة ألف حاجة، ورفع له بها مائة الف درجة، وقال أيضاً، روي انّ من صلّى بهذه الصلاة سبع مرّات ردّ الله اليه بعدد كلّ عبد من العباد حسنة وتَقبّل منه عَمله في ذلك اليوم، وجاء يوم القيامة وبين عينيه النّور، وَسيأتي في خلال أعمال يوم عرفة صلوات، من صلّى بها على محمّد وآل محمّد صلوات الله وسلامُه عليهم سرّهم ."},{"type":"Text","content":"الثّامن والعشرون : أن يقول بعد العصر سبعين مرّة اَسْتَغْفِرُ اللهَ رَبّى وَاَتُوبُ اِلَيْهِ ليغفر الله ذُنوبه ."},{"type":"Text","content":"التّاسع والعشرون : قراءة إنّا أنزلناه مائة مرّة ، روي عن الامام موسى (عليه السلام) قال : انّ لله يوم الجمعة ألف نفحة من رحمته يعطي كلّ عبد منها ما شاء فمن قرأ بعد العصر يوم الجمعة انّا أنزلناه مائة مرّة وَهب الله له تلك الالف ومثلها ."}],"preview":"وهي الاكسير الاعظم والكبريت الاحمر وهي مرويّة بما لها من الفضل العظيم باسناد معتبرة غاية الاعتبار واهمّ ما لها من الفضل غفران الذّنوب العظام وأفضل أوقاتها صدر النّهار يوم الجمعة وه","hasTranslate":false},{"id":"mf_ar_43","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"الثّلاثون : قراءة دعاء العشرات الاتي","blocks":[{"type":"Text","content":"الحادي والثّلاثون : قال الشّيخ الطّوسي (رحمه الله): آخر ساعة يوم الجمعة الى غروب الشّمس هي السّاعة التي يستجاب فيها الدّعاء، فينبغي أن يستكثر من الدّعاء في تلك السّاعة، وروي انّ تلك السّاعة هي اذا غاب نصف القرص وبقي نصفه، وكانت فاطمة (عليها السلام) تدعو في ذلك الوقت، فيتسحبّ الدّعاء فيها ويستحبّ أن يدعو بالدّعاء المروي عن النّبي في ساعة الاستجابة: سُبْحانَكَ لا اِلـهَ إلاّ اَنْتَ يا حَنّانُ يا مَنّانُ يا بَديعَ السَّماواتِ وَالاَْرْضِ يا ذا الْجَلالِ وَالاِْكْرامِ. ويستحبّ دعاء السّمات في آخر ساعة من نهار الجُمعة وسيأتي ان شاء الله تعالى واعلم انّ ليوم الجُمعة نسبة وانتماء الى امام العصر عجّل الله تعالى فرجه من نواحي عديدة ففيه كانت ولادته السّعيدة وفيه يفيض السّرور بظهوره، وترقّب الفرج وانتظاره فيه أشدّ ممّا سواه من الايّام وستجد فيما سنورده منْ زيارته الخاصّة في يوم الجُمعة هذه الكلمة هذا يَوْمُ الْجُمُعَةِ وَهُوَ يَوْمُكَ الْمُتَوَقَّعُ فيهِ ظُهُورُكَ وَالْفَرَجُ فيهِ لِلْمُؤْمِنينَ عَلى يَدِكَ والواقع انّ الجمعة انّما عُدّت عيداً من الاعياد الاربعة لما سيتّفق فيها من ظهور الحجّة (عليه السلام) وتطهيره الارض من ادران الشّرك والكفر وأقذار المعاصي والذّنوب ومن الجبابرة والملحدين والكفّار والمنافقين فتقرّ عيون الخاصّة من المؤمنين وتسرّ أفئدتهم باظهاره كلمة الحقّ واعلاء الدّين وشرايع الايمان (وَأشْرَقَتِ الاَرْضُ بِنُورِ رَبِّها)، وينبغي في هذا اليوم أن يدعى بالصلاة الكبيرة ويدعي ايضاً بما أمر الرّضا (عليه السلام) بأن يدعى به لصاحب الامر (عليه السلام) اَللّـهُمَّ ادْفَعْ عَنْ وَليِّكَ وَخَليفَتِكَ (الدُّعاء) وسيأتي هذا الدّعاء في باب الزّيارات في نهاية أعمال السّرداب وأن يدعى أيضاً بما أملاه الشّيخ أبو عمرو العمروي قدّس الله روحه على أبي علي بن همام وقال ليدعى به في غيبة القائم من آل محمّد عليه وعليهم السلام وهو دعاء طويل كتلك الصلاة ووجيزتنا هذه لا تسعهما فاطلبهما من مِصباح المتهجّد وجمال الاسبُوع، وينبغي أن لا نهمل ذكر الصلاة المنسوبة الى أبي الحسن الّضرّاب الاصبهاني، وقد رواها الشّيخ والسّيد في أعمال عصر يوم الجمعة، وقال السّيد: هذه الصلاة مروية عن مولانا المهدي صلوات الله عليه وأن تركت تعقيب العصر يوم الجمعة لعُذر من الاعذار فلا تترك هذه الصلاة أبداً لامر أطلعنا الله جلّ جلاله عليه ثمّ ذكر الصلاة بسندها، وقال الشّيخ في المصباح هذه صلاة مرويّة عن صاحب الزّمان (عليه السلام) خرجت الى أبي الحسن الضّراب الاصبهاني بمكّة ونحن لم نذكر سندها رعاية للاختصار وهي :"},{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلى مُحَمَّد سَيِّدِ الُمُرْسَلينَ وَخاتَمِ النَّبِيّينَ وَحُجَّهِ رَبِّ الْعالَمينَ الْمُنْتَجَبِ في الْميثاقِ الْمُصْطَفى فيِ الظِّلالِ الْمُطَهَّرِ مِنْ كُلِّ آفَة الْبَريءِ مِنْ كُلِّ عَيْب الْمُؤَمَّلِ لِلنَّجاةِ الْمُرْتَجى لِلشَّفاعَةِ الْمُفَوَّضِ اِلَيْهِ دينُ اللهِ، اَللّـهُمَّ شَرِّفْ بُنْيانَهُ وَعَظِّمْ بُرْهانَهُ وَأَفْلِحْ حُجَّتَهُ وَارْفَعْ دَرَجَتَهُ وَاَضِئْ نُورَهُ وَبَيِّضْ وَجْهَهُ وَاَعْطِهِ الْفَضْلَ وَالْفَضيلَةَ وَالْمَنْزِلَةَ وَالْوَسيلَةَ وَالَّدرَجَةَ الرَّفيعَةَ وَابْعَثْهُ مَقاماً مَحْمُوداً يَغْبِطُهُ بِهِ الاَْوَّلُونَ وَالاخِرُونَ وَصَلِّ عَلى اَميْرِ الْمُؤْمِنينَ َوارِثِ الْمُرْسَلينَ وَقائِدِ الْغُرِّ الُمحَجَّلينَ وَسَيِّدِ الْوَصِيّينَ وَحُجَّةِ رَبِّ الْعالَمينَ، وَصَلِّ عَلَى الْحَسَنِ بْنِ عَلِيٍّ اِمامِ الْمُؤْمِنينَ وَوارِثِ الْمُرْسَلينَ وَحُجَّةِ رَبِّ الْعالَمينَ، وَصَلِّ عَلَى الْحُسَيْنِ بْنِ عَلِيٍّ اِمامِ الْمُؤْمِنينَ وَوارِثِ الْمُرْسَلينَ وَحُجَّةِ رَبِّ الْعالَمينَ، وَصَلِّ عَلى عَلِيِّ بْنِ الْحُسَيْنِ اِمامِ الْمُؤْمِنينَ وَوارِثِ الْمُرْسَلينَ وَحُجَّةِ رَبِّ الْعالَمينَ، وَصَلِّ عَلى مُحَمَّدِ بْنِ عَلِيٍّ اِمامِ الْمُؤْمِنينَ وَوارِثِ الْمُرْسَلينَ وَحُجَّةِ رَبِّ الْعالَمينَ، وَصَلِّ عَلى جَعْفَرِ بْنِ مُحَمَّد اِمامِ الْمُؤْمِنينَ وَوارِثِ الْمُرْسَلينَ وَحُجَّةِ رَبِّ الْعالَمينَ، وَصَلِّ عَلى مُوسَى بْنِ جَعْفَر اِمامِ الْمُؤْمِنينَ وَوارِثِ الْمُرْسَلينَ وَحُجَّةِ رَبِّ الْعالَمينَ، وَصَلِّ عَلى عَلِيِّ بْنِ مُوسى اِمامِ الْمُؤْمِنينَ وَوارِثِ الْمُرْسَلينَ وَحُجَّةِ رَبِّ الْعالَمينَ، وَصَلِّ عَلى مُحَمَّدِ بْنِ عَلِيٍّ اِمامِ الْمُؤْمِنينَ وَوارِثِ الْمُرْسَلينَ وَحُجَّةِ رَبِّ الْعالَمينَ، وَصَلِّ عَلى عَلِيِّ بْنِ مُحَمَّد اِمامِ الْمُؤْمِنينَ وَوارِثِ الْمُرْسَلينَ وَحُجَّةِ رَبِّ الْعالَمينَ، وَصَلِّ عَلَى الْحَسَنِ بْنِ عَلِيٍّ اِمامِ الْمُؤْمِنينَ وَوارِثِ الْمُرْسَلينَ وَحُجَّةِ رَبِّ الْعالَمينَ، وَصَلِّ عَلَى الْخَلَفِ الْهادِي الْمَهْدِيِّ اِمامِ الْمُؤْمِنينَ وَوارِثِ الْمُرْسَلينَ وَحُجَّةِ رَبِّ الْعالَمينَ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد واَهْلِ بَيْتِهِ الاَْئِمَّةِ الْهادينَ الْعُلَماء الصّادِقينَ الاَْبْرارِ المُتَّقينَ دَعائِمِ دينك وَاَرْكانِ تَوْحيدِكَ وَتَراجِمَةِ وَحْيِكَ وَحُجَجِكَ عَلى خَلْقِكَ وَخُلَفائِكَ فى اَرْضِكَ الَّذينَ اخْتَرْتَهُمْ لِنَفْسِكَ وَاصْطَفَيْتَهُمْ عَلى عِبادِكَ وَارْتَضَيْتَهُمْ لِدينِكَ وَخَصَصْتَهُمْ بِمَعْرِفَتِكَ وَجَلَّلْتَهُمْ بِكَرامَتِكَ وَغَشَّيْتَهُمْ بِرَحْمَتِكَ وَرَبَّيْتَهُمْ بِنِعْمَتِكَ وَغَذَّيْتَهُمْ بِحِكْمَتِكَ وَاَلْبَسْتَهُمْ نُورَكَ وَرَفَعْتَهُمْ فى مَلَكُوتِكَ وَحَفَفْتَهُمْ بِمَلائِكَتِكَ وَشَرَّفْتَهُمْ بِنَبِيِّكَ صَلَواتُكَ عَلَيْهِ وَآلِهِ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَعَلَيْهِمْ صلاةً زاكِيَةً نامِيَةً كَثيرَةً دائِمَةً طَيِّبَةً لا يُحيطُ بِها إلاّ اَنْتَ وَلا يَسَعُها إلاّ عِلْمُكَ وَلا يُحْصيها اَحَدٌ غَيْرُكَ، اَللّـهُمَّ وَصَلِّ عَلى وَلِيِّكَ الُْمحْيي سُنَّتَكَ الْقائِمِ بِاَمْرِكَ الدّاعى اِلَيْكَ الدَّليلِ عَلَيْكَ، حُجَّتِكَ عَلى خَلْقِكَ وَخَليفَتِكَ في اَرْضِكَ وَشاهِدِكَ عَلى عِبادِكَ، اَللّـهُمَّ اَعِزَّ نَصْرَهُ وَمُدَّ فى عُمْرِهِ وَزَيِّنِ الاَْرْضَ بِطُولِ بَقائِهِ، اَللّـهُمَّ اكْفِهِ بَغْيَ الْحاسِدينَ وَاَعِذْهُ مِنْ شَرِّ الْكائِدينَ وَازْجُرْ عَنْهُ اِرادَةَ الظّالِمينَ وَخَلِّصْهُ مِنْ اَيْدِي الْجَبّارِينَ، اَللّـهُمَّ اَعْطِهِ في نَفْسِهِ وَذُرِّيَّتِهِ وَشيعَتِهِ وَرَعِيَّتِهِ وَخاصَّتِهِ وَعامَّتِهِ وَعَدُوِّهِ وَجَميعِ اَهْلِ الدُّنْيا ما تُقِرُّ بِهِ عَيْنَهُ وَتَسُرُّ بِهِ نَفْسَهُ وَبَلِّغْهِ اَفْضَلَ ما اَمَّلَهُ فِي الدُّنْيا وَالاْخِرَةِ اِنَّكَ عَلى كُلِّ شَيْء قَديرٌ اَللّـهُمَّ جَدِّدْْ بِهِ مَا اْمَتَحى مِنْ دينِكََ اَحْيِ بِهِ ما بُدِّلَ مِنْ كِتابِكَ وَاَظْهِرْ بِهِ ما غُيِّرَ مِنْ حُكْمِكَ حَتّى يَعُودَ دينُكَ بِهِ وَعَلى يَدَيْهِ غَضّاً جَديداً خالِصاً مُخْلَصاً لا شَكَّ فيهِ وَلا شُبْهَةَ مَعَهُ وَلا باطِلَ عِنْدَهُ وَلا بِدْعَةَ لَدَيْهِ، اَللّـهُمَّ نَوِّرْ بِنُورِهِ كُلَّ ظُلْمَةِ وَهُدَّ بِرُكْنِهِ كُلَّ بِدْعَة وَاهْدِمْ بِعِزِّهِ كُلَّ ضَلالَة وَاقْصِمْ بِهِ كُلَّ جَبّار وَاَخْمِدْ بِسَيْفِهِ كُلَّ نار وَاَهْلِكْ بِعَدْلِهِ جَوْرَ كُلِّ جائِر واجْرِ حُكْمَهُ عَلى كُلِّ حُكْم وَاَذِلَّ بِسُلْطانِهِ كُلَّ سُلْطان، اَللّـهُمَّ اَذِلَّ كُلَّ مَنْ ناواهُ وَاَهْلِكْ كُلَّ مَنْ عاداهُ وَامْكُرْ بِمَنْ كادَهْ وَاسْتَأصِلْ مَنْ جَحَدَهُ حَقَّهُ وَاسْتَهانَ بِاَمْرِهِ وَسَعى في اِطْفاءِ نُورِهِ وَاَرادَ اِخْمادَ ذِكْرِهِ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد الْمُصْطَفى وَعَلِيٍّ الْمُرْتَضى وَفاطِمَةَ الزَّهْراءِ وَالْحَسَنِ الرِّضا وَالْحُسَيْنِ الْمُصَفَّى وَجَميعِ الاَْوْصِياءِ مَصابيحِ الدُّجى وَاَعْلامِ الْهُدى وَمَنارِ التُّقى وَالْعُرْوَةِ الْوُثْقى وَالْحَبْلِ الْمَتينِ وَالصِّراطِ الْمُسْتَقيمِ، وَصَلِّ عَلى وَلِيِّكَ وَوُلاةِ عَهْدِكَ وَالاَْئِمَّةِ مِنْ وُلْدِهِ وَمُدَّ في اَعْمارِهِمْ وَزِدْ في آجالِهِمْ وَبَلِّغْهُمْ اَقْصى آمالِهِمْ ديناً وَدُنْيا وَآخِرَةً اِنَّكَ عَلى كُلِّ شَيء قَديرٌ ."},{"type":"AboutText","content":"واعلم انّ ليلة السّبت هي كَليلَة الجُمعة على بعض الرّوايات فينبغي أن يقرأ فيها ما يقرأ في ليلة الجُمعة ."}],"preview":"الحادي والثّلاثون : قال الشّيخ الطّوسي (رحمه الله): آخر ساعة يوم الجمعة الى غروب الشّمس هي السّاعة التي يستجاب فيها الدّعاء، فينبغي أن يستكثر من الدّعاء في تلك السّاعة، وروي انّ تل","hasTranslate":false},{"id":"mf_ar_44","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"الفَصْلُ الخامِسْ :","blocks":[{"type":"Text","content":"في تَعيين اسْماء النّبيّ وَالائمّة المعصُومين (عليهم السلام) بأيّام الاسْبُوع والزيارات لهم في كلّ يوم ."},{"type":"AboutText","content":"قال السيّد ابن طاووس في جمال الاسبُوع: روى ابن بابويه مُسنداً عن الصّقر بن أبي دلف قال : لمّا حمل المتوكّل سيّدنا عليّ بن محمّد النّقي إلى سرّ مَن رَأى جئت أسأل عَنْ خبره وكانَ سجيناً عند الزراقي حاجب المتوكّل فادخلت عَليه ، فقال : يا صقر ما شأنك؟ فقلت : خير ، فقال : اقعد ، قال : فأخذنا فيما تقدّم وَما تأخّر الى أن زجر النّاس عَنْه ثمّ قال لي : ما شأنك وفيم جئت ؟ قلت : لخير ما ، قال : لعلّك جئت تسأل عَن خَبَر مولاك؟ فقلت له : مولاي أمير المؤمنين ، قال : اسكت مَولاكَ هُو الحقّ لا تحتشمني فانّي على مذهبِكَ ، فقلت : الحمد لله ، فقال : أتُحِبّ أن تراه؟ قُلت : نعم ، قال : اجلس حتّى يخرج صاحِب البريد من عندِه ، قال : فجَلَست فلمّا خرج قال لغلام له : خذ بيد الصّقر واَدخله إلى الحُجرة وأومأ إلى بَيْت، فَدخلت فاذا هُو جالِس على صَدر حصير وَبحذائه قَبر محفُور، قَال : فسلّمت عَليه فردّ علي ثمّ أمَرني بالجُلوس ثمّ قال لي : يا صقر ما أتى بك؟ قُلت : جئت أتعرّف خَبَرك ، قال : ثمّ نَظَرت إلى القَبْر فَبَكيت، فنَظر اليّ فقال : يا صقر لا عَلَيْك لنْ يصلوا الَينا بسوء، فقلت : الحمدُ لله ، ثمّ قلت : يا سيّدي حديث يروى عَنِ النبيّ (صلى الله عليه وآله وسلم) لا أعرف مَعناه ، قال : وَما هُو ، قُلت : قوله : « لا تُعادُوا الايّام فتُعاديكم » ما مَعناه؟ فقال : نَعم الايّام نَحن ما قامَتِ السّماوات والارض، فَالسَّبت اِسم رَسول اللهِ (صلى الله عليه وآله وسلم)، وَالاحد أمير المؤمنين (عليه السلام)، وَالاثْنان الحَسَن وَالحُسين (عليهما السلام)، والثّلاثاء عليّ بن الحسين وَمحمّد بن عليّ وجَعفر بن محمّد (عليهم السلام)، والاربعاء مُوسى بن جعفر وعليّ بن مُوسى ومحمّد بن عليّ وَأنا والخميس ابني الحَسَن (عليه السلام)، والجُمعة ابنْ ابني واليه تجتمع عصابة الحقّ، فهذا مَعنى الايّام فَلا تُعادوهم في الدّنيا فيُعادوكم في الاخرة ثمّ قال : وَدع واخرُج. ثمّ روى السيّد هذا الحديث بسند آخر عَنِ القُطب الرّاوندي ثمّ قال :"}],"preview":"في تَعيين اسْماء النّبيّ وَالائمّة المعصُومين (عليهم السلام) بأيّام الاسْبُوع والزيارات لهم في كلّ يوم .","hasTranslate":false},{"id":"mf_ar_45","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"وَهُوَ يَومُ السّبتِ :","blocks":[{"type":"Text","content":"اَشْهَدُ اَنْ لا اِلـهَ إلاّ اللهُ وَحْدَهُ لا شَريكَ لَهُ وَاَشْهَدُ اَنَّكَ رَسُولُهُ وَاَنَّكَ مُحَمَّدُ بْنُ عَبْدِ اللهِ وَاَشْهَدُ اَنَّكَ قَدْ بَلَّغْتَ رِسالاتِ رَبِّكَ وَنَصَحْتَ لاُِمَّتِكَ وَجاهَدْتَ فى سَبيلِ اللهِ بِالْحِكْمَةِ وَالمَوْعِظَةِ الْحَسَنَةِ وَاَدَّيْتَ الَّذى عَلَيْكَ مِنَ الْحَقِّ وَاَنَّكَ قَدْ رَؤُفْتَ بِالْمُؤْمِنينَ وَغَلَظْتَ عَلَى الْكافِرينَ وَعَبَدْتَ اللهَ مُخْلِصاً حَتّى أتاكَ اليَقينُ فَبَلَغَ اللهُ بِكَ اشَرَفَ مَحَلِّ الْمُكَرَّمينَ اَلْحَمْدُ للهِِ الَّذِي اسْتَنْقَذَنا بِكَ مِنَ الشِّرْكِ وَالضَّلالِ اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِهِ وَاجْعَلْ صَلَواتِكَ وَصَلَواتِ مَلائِكَتِكَ الْمُقَرَّبينَ وَاَنْبِيائِكَ الْمـُرْسَلينَ وَعِبادِكَ الصّالِحينَ وَاَهْلِ السَّماواتِ وَالاَْرَضينَ وَمَنْ سَبَّحَ لَكَ يا رَبَّ الْعالَمينَ مِنَ الاَْوَّلينَ وَالاخِرينَ عَلى مُحَمَّد عَبْدِكَ وَرَسُوِلِكَ وَنَبِيِّكَ وَاَمينِكَ وَنَجِيبِكَ وَحَبيبِكَ وَصَفِيِّكَ وَ صَفْوَتِكَ وَخاصَّتِكَ وَخالِصَتِكَ وَخِيَرَتِكَ مِنْ خَلْقِكَ وَاَعْطِهِ الْفَضْلَ وَالْفَضيلَةَ وَالْوَسيلَةَ وَالدَّرَجَةَ الرَّفيعَةَ وَابْعَثْهُ مَقاماً مَحَمْوُداً يَغْبِطُهُ بِهِ الاَْوَّلُونَ وَالاخِرُونَ اَللّـهُمَّ اِنَّكَ قُلْتَ وَلَوْ اَنَّهُمْ اِذْ ظَلَمُوا اَنْفُسَهُمْ جاؤوكَ فَاسْتَغْفَرُوا اللهَ وَاسْتَغْفَرَ لَهُمُ الرَّسُولُ لَوَجَدُوا اللهَ تَوّاباً رَحيماً اِلـهى فَقَدْ اَتَيْتُ نَبِيَّكَ مُسْتَغْفِراً تائِباً مِنْ ذُنُوبى فَصَلِّ عَلى مُحَمَّد وَآلِهِ وَ اْغِفْرها لي، يا سَيِّدَنا اَتَوَجَّهُ بِكَ وَبِاَهْلِ بَيْتِكَ اِلَى اللهِ تَعالى رَبِّكَ وَرَبّى لِيَغْفِرَ لى ثمّ قل ثلاثاً : اِنّا للهِِ وَاِنّا اِلَيْهِ راجِعُونَ ثمّ قل : اُصِبْنا بِكَ يا حَبيبَ قُلُوبِنا فَما اَعْظَمَ الْمُصيبَةَ بِكَ حيَْثُ انْقَطَعَ عَنّا الْوَحْيُ وَحَيْثُ فَقَدْناكَ فَاِنّا للهِِ وَاِنّا اِلَيْهِ راجِعُونَ يا سَيِّدَنا يا رَسُولَ اللهِ صَلَواتُ اللهِ عَلَيْكَ وَعَلى آلِ بَيْتِكَ الطّاهِرينَ هذا يَوْمُ السَّبْتِ وَهُوَ يَوْمُكَ وَاَنَا فيهِ ضَيْفُكَ وَجارُكَ فَاَضِفْنى وَاجِرْنى فَاِنَّكَ كَريمٌ تُحِبُّ الضِّيافَةَ وَمَأْمُورٌ بِالاِْجارَةِ فَاَضِفْني وَأحْسِنْ ضِيافَتى وَاَجِرْنا وَاَحْسِنْ اِجارَتَنا بِمَنْزِلَةِ اللهِ عِنْدَكَ وَعِنْدَ آلِ بَيْتِكَ وَبِمَنْزِلَتِهِمْ عِنْدَهُ وَبِما اسْتَوْدَعَكُمْ مِنْ عِلْمِهِ فَاِنَّهُ اَكْرَمُ الاَْكْرَمينَ ."},{"type":"Text","content":"يقول مؤلّف الكتاب عبّاس القُمّي عُفى عَنْه: انّي كلّما زرته (صلى الله عليه وآله وسلم)بهذه الزّيارة بَدَأت بزيارته عَلى نحو ما علّمه الامام الرّضا (عليه السلام)البزنطي ثمّ قرأت هذِهِ الزّيارة، فَقَدْ رُوي بسند صحيح إنّ ابن أبي بصير سأل الرّضا (عليه السلام)كيف يُصلّى على النبيّ (صلى الله عليه وآله وسلم) ويسلّم عليه بَعد الصلاة فأجابَ (عليه السلام) بقوله :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا رَسُولَ اللهِ وَرَحْمةُ اللهِ وَبَرَكاتُهُ اَلسَّلامُ عَلَيْكَ يا مُحَمَّدُ بْنَ عَبْدِ اللهِ اَلسَّلامُ عَلَيْكَ يا خِيَرَةَ اللهِ اَلسَّلامُ عَلَيْكَ يا حَبيبَ اللهِ اَلسَّلامُ عَلَيْكَ يا صِفْوَهَ اللهِ اَلسَّلامُ عَلَيْكَ يا اَمينَ اللهِ اَشْهَدُ اَنَّكَ رَسُولُ اللهِ وَاَشْهَدُ اَنَّكَ مُحمَّدُ بْنُ عَبْدِ اللهِ وَاَشْهَدُ اَنَّكَ قَدْ نَصَحْتَ لاُِمَّتِكَ وَجاهَدْتَ فى سَبيلِ رَبِّكِ وَعَبَدْتَهُ حَتّى أتاكَ الْيَقينُ فَجَزاكَ اللهُ يا رَسُولَ اللهِ اَفْضَلَ ما جَزى نَبِيّاً عَنْ اُمَّتِهِ اَللّـهُمَّ صَلِّ عَلى مَحَمِّد وآلِ مُحَمِّد اَفْضَلَ ما صَلَّيْتَ عَلى اِبْرهِيمَ وَآلِ إبراهيمَ اِنَّكَ حَميدٌ مَجيدٌ ."}],"preview":"اَشْهَدُ اَنْ لا اِلـهَ إلاّ اللهُ وَحْدَهُ لا شَريكَ لَهُ وَاَشْهَدُ اَنَّكَ رَسُولُهُ وَاَنَّكَ مُحَمَّدُ بْنُ عَبْدِ اللهِ وَاَشْهَدُ اَنَّكَ قَدْ بَلَّغْتَ رِسالاتِ رَبِّكَ وَن","hasTranslate":false},{"id":"mf_ar_46","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"زيارةُ أميرِ المؤمنينَ(عليه السلام)","blocks":[{"type":"Text","content":"برواية من شاهد صاحِب الزّمان (عليه السلام) وهُو يزوره بها في اليقظة لا في النّوم يوم الاحد وهوَ يومُه :"},{"type":"Text","content":"اَلسَّلامُ عَلَى الشَّجَرَةِ النَّبَوِيَّةِ وَالدَّوْحَةِ الْهاشِمِيَّةِ المُضيئَةِ المُثْمِرَةِ بِالنَّبُوَّةِ الْمُونِقَةِ بِالاِْمامَةِ وَعَلى ضَجيعَيْكَ آدَمَ وَنُوح عليهما السلام، اَلسَّلامُ عَلَيْكَ وَعَلى اَهْلِ بَيْتِكَ الطَّيِّبينَ الطّاهِرينَ، اَلسَّلامُ عَلَيْكَ وَ عَلَى الْمَلائِكَةِ الُْمحْدِقينَ بِكَ وَالْحافّينَ بِقَبْرِكَ يا مَوْلايَ يا اَميرَ الْمُوْمِنينَ هذا يَوْمُ الاَْحَدِ وَهُوَ يَوْمُكَ وَبِاسْمِكَ وَاَنَا ضَيْفُكَ فيهِ وَ جارُكَ فَاَضِفْنى يا مَوْلاىَ وَاَجِرْنى فَاِنَّكَ كَريمٌ تُحِبُّ الضِّيافَةَ وَ مَأْمُورٌ بِالاِْجارَةِ فَافْعَلْ ما رَغِبْتُ اِلَيْكَ فيهِ وَرَجَوْتُهُ مِنْكَ بِمَنْزِلَتِكَ وَ آلِ بَيْتِكَ عِنْدَاللهِ وَمَنْزِلَتِهِ عِنْدَكُمْ وَبِحَقِّ ابْنِ عَمِّكَ رَسُولِ اللهِ صلى الله عليه وآله وسلم وَعَلَيْهِمْ اَجْمَعينَ ."}],"preview":"برواية من شاهد صاحِب الزّمان (عليه السلام) وهُو يزوره بها في اليقظة لا في النّوم يوم الاحد وهوَ يومُه :","hasTranslate":false},{"id":"mf_ar_47","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"زيارةُ الزّهْرَاءِ سَلامُ اللهِ عَليها","blocks":[{"type":"Text","content":"اَلسَّلامُ عَلَيْكِ يا مُمْتَحَنَةُ امْتَحَنَكِ الَّذى خَلَقَكِ فَوَجَدَكِ لِمَا امْتَحَنَكِ صابِرَةً اَنَا لَكِ مُصَدِّقٌ صابِرٌ عَلى ما اَتى بِهِ اَبُوكِ وَوَصِيُّهُ صَلَواتُ اللهِ عَلَيْهِما وَاَنَا أَسْأَلُكِ اِنْ كُنْتُ صَدَّقْتُكِ إلاّ اَلْحَقْتِنى بِتَصْديقى لَهُما لِتُسَرَّ نَفْسى فَاشْهَدى اَنّى ظاهِرٌ بِوَلايَتِكِ وَوَلايَةِ آلِ بَيْتِكِ صَلَواتُ اللهِ عَلَيْهِمْ اَجْمَعينَ ."},{"type":"Text","content":"أيضاً زِيارَتُها بِرواية اُخرى"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكِ يا مُمْتَحَنَةُ اِمْتَحَنَكِ الَّذى خَلَقَكِ قَبْلَ اَنْ يَخْلُقَكِ وَكُنْتِ لِما امْتَحَنَكِ بِه صابِرَةً وَنَحْنُ لَكِ اَولِياءُ مُصَدِّقُونَ وَلِكُلِّ ما اَتى بِهِ اَبُوكِ صلى الله عليه وآله وسلم وَاَتى بِهِ وَصِيُّهُ عليه السلام مُسَلِّمُونَ وَ نَحْنُ نَسْأَلُكَ اَللّـهُمَّ اِذْ كُنّا مُصَدِّقينَ لَهُمْ اَنْ تُلْحِقَنا بِتَصْديقِنا بِالدَّرَجَةِ الْعالِيَةِ لِنُبَشِّرَ اَنْفُسَنا بِاَنّا قَدْ طَهُرْنا بِوَلايَتِهِمْ عليهم السلام ."},{"type":"Text","content":"يَوْم الاثنينِ وَهُوَ بِاسْمِ الحسنِ وَالحُسينِ (عليهما السلام)"}],"preview":"اَلسَّلامُ عَلَيْكِ يا مُمْتَحَنَةُ امْتَحَنَكِ الَّذى خَلَقَكِ فَوَجَدَكِ لِمَا امْتَحَنَكِ صابِرَةً اَنَا لَكِ مُصَدِّقٌ صابِرٌ عَلى ما اَتى بِهِ اَبُوكِ وَوَصِيُّهُ صَلَواتُ الل","hasTranslate":false},{"id":"mf_ar_48","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"زِيارةُ الحَسَنِ (عليه السلام)","blocks":[{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يَابْنَ رَسُولِ رَبِّ الْعالَمينَ اَلسَّلامُ عَلَيْكَ يَابْنَ اَميرِ الْمُؤْمِنينَ اَلسَّلامُ عَلَيْكَ يَابْنَ فاطِمَةَ الزَّهْراءِ اَلسَّلامُ عَلَيْكَ يا حَبيبَ اللهِ اَلسَّلامُ عَلَيْكَ يا صِفْوَةَ اللهِ اَلسَّلامُ عَلَيْكَ يا اَمينَ اللهِ اَلسَّلامُ عَلَيْكَ يا حُجَّةَ اللهِ اَلسَّلامُ عَلَيْكَ يا نُورَ اللهِ اَلسَّلامُ عَلَيْكَ يا صِراطَ اللهِ اَلسَّلامُ عَلَيْكَ يا بَيانَ حُكْمِ اللهِ اَلسَّلامُ عَلَيْكَ يا ناصِرَ دينِ اللهِ اَلسَّلامُ عَلَيْكَ اَيُّهَا السَّيِدُ الزَّكِيُّ اَلسَّلامُ عَلَيْكَ اَيُّهَا الْبَرُّ الْوَفِيُّ اَلسَّلامُ عَلَيْكَ اَيُّهَا الْقائِمُ الاَْمينُ اَلسَّلامُ عَلَيْكَ اَيُّهَا الْعالِمُ بِالتَّأْويلِ اَلسَّلامُ عَلَيْكَ اَيُّهَا الْهادِي الْمَهْديُّ اَلسَّلامُ عَلَيْكَ اَيُّهَا الطّاهِرُ الزَّكِيُّ اَلسَّلامُ عَلَيْكَ اَيُّهَا التَّقِيُّ النَّقِيُّ السَّلامُ عَلَيْكَ اَيُّهَا الْحَقُّ الْحَقيقُ اَلسَّلامُ عَلَيْكَ اَيُّهَا الشَّهيدُ الصِّدّيقُ اَلسَّلامُ عَلَيْكَ يا اَبا مُحَمَّد الْحَسَنَ بْنَ عَلِيٍّ وَ رَحْمَةُ اللهِ وَبَرَكاتُهُ ."}],"preview":"اَلسَّلامُ عَلَيْكَ يَابْنَ رَسُولِ رَبِّ الْعالَمينَ اَلسَّلامُ عَلَيْكَ يَابْنَ اَميرِ الْمُؤْمِنينَ اَلسَّلامُ عَلَيْكَ يَابْنَ فاطِمَةَ الزَّهْراءِ اَلسَّلامُ عَلَيْكَ يا حَبيب","hasTranslate":false},{"id":"mf_ar_49","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل الرابع :","title":"زِيارة الحُسَينِ (عليه السلام)","blocks":[{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يَابْنَ رَسُولِ اللهِ اَلسَّلامُ عَلَيْكَ يَابْنَ اَميرِ الْمُؤْمِنينَ اَلسَّلامُ عَلَيْكَ يَابْنَ سَيِّدَةِ نِساءِ الْعالَمينَ اَشْهَدُ اَنـَّكَ اَقَمْتَ الصلاةَ وَ آتَيْتَ الزَّكوةَ وَاَمَرْتَ بِالْمَعْرُوفِ وَنَهَيْتَ عَنِ الْمُنْكَرِ وَعَبَدْتَ اللهَ مُخْلِصاً وَجاهَدْتَ فِي اللهِ حَقَّ جِهادِهِ حَتّى أتاكَ الْيَقينُ فَعَلَيْكَ السَّلامُ مِنّي ما بَقيتُ وَبَقِيَ اللَّيْلُ وَالنَّهارُ وَعَلى آلِ بَيْتِكَ الطَّيِّبينَ الطّاهِرينَ، اَنَا يا مَوْلايَ مَوْلىً لَكَ وَلاِلِ بَيْتِكَ سِلْمٌ لِمَنْ سالَمَكُمْ وَحَرْبٌ لِمَنْ حارَبَكُمْ مُؤْمِنٌ بِسِرِّكُمْ وَجَهْرِكُمْ وَظاهِرِكُمْ وَباطِنِكُمْ لَعَنَ اللهُ اَعْداءَكُمْ مِنَ الاَْوَّلينَ وَالاْخِرينَ وَاَنـَا أبْرَأُ اِلَى اللهِ تَعالى مِنْهُمْ يا مَوْلايَ يا اَبا مُحَمَّد يا مَوْلايَ يا اَبا عَبْدِ اللهِ هذا يَوْمُ الاِْثْنَيْنِ وَهُوَ يَوْمُكُما وَبِاسْمـِكُما وَاَنـَا فيهِ ضَيْفُكُما فَاَضيفانى وَاَحْسِنا ضِيافَتى فَنِعْمَ مَنِ اسْتُضيفَ بِهِ اَنْتُما وَاَنـَا فيهِ مِنْ جِوارِكُما فَاَجيرانى فَاِنَّكُما مَأْمُورانِ بِالضِّيافَةِ وَالاِْجارَةِ فَصَلَّى اللهُ عَلَيْكُما وَآلِكُمَا الطَّيِّبينَ ."},{"type":"Text","content":"يَوْمُ الثّلاثاءِ"},{"type":"Text","content":"وَهُو باسم عليّ بن الحسين ومحمّد بن عليّ الباقر وجعفر بن محمّد الصّادق صلوات الله عليهم أجمعين ; زيارتهم (عليهم السلام) :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكُمْ يا خُزّانَ عِلْمِ اللهِ اَلسَّلامُ عَلَيْكُمْ يا تَراجِمَةَ وَحْيِ اللهِ اَلسَّلامُ عَلَيْكُمْ يا اَئِمَّةَ الْهُدى اَلسَّلامُ عَلَيْكُمْ يا اَعْلامَ التُّقى اَلسَّلامُ عَلَيْكُمْ يا اَوْلادَ رَسُولِ اللهِ اَنَا عارِفٌ بِحَقِّكُمْ مُسْتَبْصِرٌ بِشَأْنِكُمْ مُعاد لاَِعْدائِكُمْ مُوال لاَِوْلِيائِكُمْ بِاَبى اَنْتُمْ وَاُمّى صَلَواتُ اللهِ عَلَيْكُمْ اَللّهُمَّ اِنّى اَتَوالى آخِرَهُمْ كَما تَوالَيْتُ اَوَّلَهُمْ وَاَبْرَأُ مِنْ كُلِّ وَليجَة دُونَهُمْ وَاَكْفُرُ بِالْجِبْتِ وَالطّاغُوتِ وَاللاتِ وَالْعُزّى صَلَواتُ اللهِ عَلَيْكُمْ يا مَوالِيَّ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ اَلسَّلامُ عَلَيْكَ يا سَيِّدَ الْعابِدينَ وَسُلالَةَ الْوَصِيّينَ اَلسَّلامُ عَلَيْكَ يا باقِرَ عِلْمِ النَّبِيّينَ اَلسَّلامُ عَلَيْكَ يا صادِقاً مُصَدِّقاً فِي الْقَوْلِ وَالْفِعْلِ يا مَوالِيَّ هذا يَوْمُكُمْ وَهُوَ يَوْمُ الثلاثاء وَاَنَا فيهِ ضَيْفٌ لَكُمْ وَمُسْتَجيرٌ بِكُمْ فَاَضيفُوني وَاَجيرُوني بِمَنْزِلَةِ اللهِ عِنْدَكُمْ وَآلِ بَيْتِكُمُ الطَّيِّبينَ الطّاهِرينَ ."},{"type":"Text","content":"يَوْمُ الاربعاءِ"},{"type":"Text","content":"وَهُو باسم مُوسى بن جعفر وعلي بن مُوسى الرّضا ومحمّد التقي وعلي النقي ; زيارتهم (عليهم السلام) :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكُمْ يا اَوْلِياءَ اللهِ اَلسَّلامُ عَلَيْكُمْ يا حُجَجَ اللهِ اَلسَّلامُ عَلَيْكُمْ يا نُورَ اللهِ فى ظُلُماتِ الاَْرْضِ اَلسَّلامُ عَلَيْكُمْ صَلَواتُ اللهِ عَلَيْكُمْ وَعَلى آلِ بَيْتِكُمُ الطَّيِّبينَ الطّاهِرينَ بِاَبى اَنْتُمْ وَاُمّى لَقَدْ عَبَدْتُمُ اللهَ مُخْلِصينَ وَجاهَدْتُمْ فِي اللهِ حَقَّ جِهادِهِ حَتّى أتاكم الْيَقينُ فَلَعَنَ اللهُ اَعْداءكُمْ مِنَ الْجِنِّ وَالاِْنْسِ اَجَمْعَينَ وَاَنَا اَبْرَأُ اِلَى اللهِ وَاِلَيْكُمْ مِنْهُمْ، يا مَوْلايَ يا اَبا اِبْراهيمَ مُوسَى بْنَ جَعْفَر يا مَوْلايَ يا اَبَا الْحَسَنِ عَلِيَّ بْنَ مُوسى يا مَوْلايَ يا اَبا جَعْفَر مُحَمَّدَ بْنَ عَلِيٍّ يا مَوْلايَ يا اَبَا الْحَسَنِ عَلِيَّ بْنَ مُحَمَّد اَنَا مَوْلىً لَكُمْ مُؤْمِنٌ بِسِرِّكُمْ وَجَهْرِكُمْ مُتَضَيِّفٌ بِكُمْ في يَوْمِكُمْ هذا وَهُوَ يَوْمُ الاَْرْبَعاءِ وَمُسْتَجيرٌ بِكُمْ فَاَضيفُوني وَ اَجيرُوني بِـآلِ بَيْتِـكُـمُ الطَّيـِّبيـنَ الطّاهِـريـنَ ."},{"type":"Text","content":"يَوْمُ الْخَميسِ"},{"type":"Text","content":"وَهُو يَوم الحسن بن علي العسكري صلوات الله عليه ; فقل في زيارته :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا وَلِيَّ اللهِ اَلسَّلامُ عَلَيْكَ يا حُجَّةَ اللهِ وَخالِصَتَهُ، اَلسَّلامُ عَلَيْكَ يا اِمامَ الْـمُؤْمِنينَ وَوارِثَ الْمُرْسَلينَ وَحُجَّةَ رَبِّ الْعالَمينَ، صَلَّى اللهُ عَلَيْكَ وَعَلى آلِ بَيْتِكَ الطَّيِّبينَ الطّاهِرينَ، يا مَوْلايَ يا اَبا مُحَمَّد الْحَسَنَ بْنَ عَلِيٍّ اَنَا مَوْلىً لَكَ وَلاِلِ بَيْتِكَ وَهذا يَوْمُكَ وَهُوَ يَوْمُ الْخَميسِ وَاَنـَا ضَيْفُكَ فيهِ وَمُسْتَجيرٌ بِكَ فيهِ فَاَحْسِنْ ضيافتي واِجارَتي بِحَقِّ آلِ بَيْتِكَ الطَّيِّبينَ الطّاهِرينَ ."},{"type":"Text","content":"يَوْمُ الجُمعةِ"},{"type":"Text","content":"وَهُو يَوم صاحِب الزّمان صلوات الله عليه وباسمه وهُو اليوم الذي يظهر فيه عجّل الله فرجه ; فقل في زيارته :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا حُجَّةَ اللهِ في اَرْضِهِ، اَلسَّلامُ عَلَيْكَ يا عَيْنَ اللهِ في خَلْقِهِ، اَلسَّلامُ عَلَيْكَ يا نُورَ اللهِ الَّذي يَهْتَدي بِهِ الْمُهْتَدُونَ وَيُفَرَّجُ بِهِ عَنِ الْمُؤْمِنينَ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الْمُهَذَّبُ الْخائِفُ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الْوَلِيُّ النّاصِحُ، اَلسَّلامُ عَلَيْكَ يا سَفينَةَ النَّجاةِ، اَلسَّلامُ عَلَيْكَ يا عَيْنَ الْحَياةِ، اَلسَّلامُ عَلَيْكَ صَلَّى اللهُ عَلَيْكَ وَعَلى آلِ بَيْتِكَ الطَّيِّبينَ الطّاهِرينَ، اَلسَّلامُ عَلَيْكَ عَجَّلَ اللهُ لَكَ ما وَعَدَكَ مِنَ النَّصْرِ وَظُهُورِ الاَْمْرِ، اَلسَّلامُ عَلَيْكَ يا مَوْلايَ، اَنَا مَوْلاكَ عارِفٌ بِاُولاكَ وَاُخْراكَ اَتَقَرَّبُ اِلَى اللهِ تَعالى بِكَ وَبِآلِ بَيْتِكَ، وَاَنْتَظِرُ ظُهُورَكَ وَظُهُورَ الْحَقِّ عَلى يَدَيْكَ وَأَسْأَلُ اللهَ اَنْ يُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاَنْ يَجْعَلَنى مِنَ الْمُنْتَظِرينَ لَكَ وَالتّابِعينَ وَالنّاصِرينَ لَكَ عَلى اَعْدائِكَ وَالْمُسْتَشْهَدينَ بَيْنَ يَدَيْكَ في جُمْلَةِ اَوْلِيائِكَ، يا مَوْلايَ يا صاحِبَ الزَّمانِ صَلَواتُ اللهِ عَلَيْكَ وَعَلى آلِ بَيْتِكَ هذا يَوْمُ الْجُمُعَةِ وَهُوَ يَوْمُكَ الْمُتَوَقَّعُ فيهِ ظُهُورُكَ وَالْفَرَجُ فيهِ لِلْمُؤْمِنينَ عَلى يَدَيْكَ وَقَتْلُ الْكافِرينَ بِسَيْفِكَ وَاَنَا يا مَوْلايَ فيهِ ضَيْفُكَ وَجارُكَ وَاَنْتَ يا مَوْلايَ كَريمٌ مِنْ اَوْلادِ الْكِرامِ وَمَأْمُورٌ بِالضِّيافَةِ وَالاِْجارَةِ فَاَضِفْني وَاَجِرْني صَلَواتُ اللهِ عَلَيْكَ وَعَلى اَهْلِ بَيْتِكَ الطّاهِرينَ ."},{"type":"AboutText","content":"قال السيّد ابن طاووس وأنا اتمثّل بعد هذه الزّيارة بهذا الشعر واشير اليه (عليه السلام)وأقول :"},{"type":"Text","content":"نَـزيلُكَ حَيـْثُ مَا اتَّجَهَتْ رِكابى وَ ضَيْفـُكَ حَيْثُ كُنْتُ مـِنَ الْبِلادِ"},{"type":"Text","content":"في ذِكر نبذ مِن الدّعواتِ المَشهورة ."}],"preview":"اَلسَّلامُ عَلَيْكَ يَابْنَ رَسُولِ اللهِ اَلسَّلامُ عَلَيْكَ يَابْنَ اَميرِ الْمُؤْمِنينَ اَلسَّلامُ عَلَيْكَ يَابْنَ سَيِّدَةِ نِساءِ الْعالَمينَ اَشْهَدُ اَنـَّكَ اَقَمْتَ الصلا","hasTranslate":false},{"id":"mf_ar_50","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل السادس :","title":"مِن تلك الدّعوات دُعاءُ الصّباح لامير المؤمنين وهو هذا الدُعاء :","blocks":[{"type":"Text","content":"اَللّـهُمَّ يا مَنْ دَلَعَ لِسانَ الصَّباحِ بِنُطْقِ تَبَلُّجِهِ، وَسَرَّحَ قِطَعَ الّلَيْلِ الْمُظْلِمِ بِغَياهِبِ تَلَجْلُجِهِ، وَاَتْقَنَ صُنْعَ الْفَلَكِ الدَّوّارِ في مَقاديرِ تَبَرُّجِهِ، وَشَعْشَعَ ضِياءَ الشَّمْسِ بِنُورِ تَاَجُّجِهِ، يا مَنْ دَلَّ عَلى ذاتِهِ بِذاتِهِ وَتَنَزَّهَ عَنْ مُجانَسَةِ مَخْلُوقاتِهِ وَجَلَّ عَنْ مُلاءَمَةِ كَيْفِيّاتِهِ، يا مَنْ قَرُبَ مِنْ خَطَراتِ الظُّنُونِ وَبَعُدَ عَنْ لَحَظاتِ الْعُيُونِ وَعَلِمَ بِما كانَ قَبْلَ اَنْ يَكُونَ، يا مَنْ اَرْقَدَني في مِهادِ اَمْنِهِ وَاَمانِهِ وَاَيْقَظَني اِلى ما مَنَحَني بِهِ مِنْ مِنَنِهِ وَاِحْسانِهِ وَكَفَّ اَكُفَّ السُّوءِ عَنّي بِيَدِهِ وَسُلْطانِهِ، صَلِّ اللّـهُمَّ عَلَى الدَّليلِ اِلَيْكَ فِي اللَّيْلِ الاَْلْيَلِ، وَالْماسِكِ مِنْ اَسْبَابِكَ بِحَبْلِ الشَّرَفِ الاَْطْوَلِ، وَالنّاصِعِ الْحَسَبِ في ذِرْوَةِ الْكاهِلِ الاَْعْبَلِ، وَالثّابِتِ الْقَدَمِ عَلى زَحاليفِها فِي الزَّمَنِ الاَْوَّلِ، وَعَلى آلِهِ الاَْخْيارِ الْمُصْطَفِيْنَ الاَْبْرارِ، وَافْتَحِ اللّـهُمَّ لَنا مَصاريعَ الصَّباحِ بِمَفاتيحِ الرَّحْمَةِ وَالْفَلاحِ، وَاَلْبِسْنِي اللّـهُمَّ مِنْ اَفْضَلِ خِلَعِ الْهِدايَةِ وَالصَّلاحِ، وَاَغْرِسِ اللّـهُمَّ بِعَظَمَتِكَ في شِرْبِ جَناني يَنابيعَ الخُشُوعِ، وَاَجْرِ اللّـهُمَّ لِهَيْبَتِكَ مِنْ اماقي زَفَراتِ الدُّمُوعِ، وَاَدِّبِ اللّـهُمَّ نَزَقَ الْخُرْقِ مِنّي بِاَزِمَّةِ الْقُنُوعِ، اِلـهي اِنْ لَمْ تَبْتَدِئنِي الرَّحْمَةُ مِنْكَ بِحُسْنِ التَّوْفيقِ فَمَنِ السّالِكُ بي اِلَيْكَ في واضِحِ الطَّريقِ، وَاِنْ اَسْلَمَتْني اَناتُكَ لِقائِدِ الاَْمَلِ وَالْمُني فَمَنِ الْمُقيلُ عَثَراتي مِنْ كَبَواـِ الْهَوى، وَاِنْ خَذَلَني نَصْرُكَ عِنْدَ مُحارَبَةِ النَّفْسِ وَالشَّيْطانِ فَقَدْ وَكَلَني خِذْلانُكَ اِلى حَيْثُ النَّصَبُ وَالْحِرْمانُ، اِلـهي اَتَراني ما اَتَيْتُكَ إلاّ مِنْ حَيْثُ الاْمالِ اَمْ عَلِقْتُ بِاَطْرافِ حِبالِكَ إلاّ حينَ باعَدَتْني ذُنُوبي عَنْ دارِ الْوِصالِ، فَبِئْسَ الْمَطِيَّةُ الَّتي امْتَطَتْ نَفْسي مِنْ هَواهـا فَواهاً لَها لِما سَوَّلَتْ لَها ظُنُونُها وَمُناها، وَتَبّاً لَها لِجُرْاَتِها عَلى سَيِّدِها وَمَوْلاها اِلـهي قَرَعْتُ بابَ رَحْمَتِكَ بِيَدِ رَجائي وَهَرَبْتُ اِلَيْكَ لاجِئاً مِنْ فَرْطِ اَهْوائي، وَعَلَّقْتُ بِاَطْرافِ حِبالِكَ اَنامِلَ وَلائى، فَاْصْفَحِ اللّـهُمَّ عَمّا كُنْتُ (كانَ) اَجْرَمْتُهُ مِنْ زَلَلي وَخَطائي، وَاَقِلْني مِنْ صَرْعَةِ رِدائي فَاِنَّكَ سَيِّدي وَمَوْلاي وَمُعْتَمَدي وَرَجائي وَاَنْتَ غايَةُ مَطْلُوبي وَمُناي في مُنْقَلَبي وَمَثْواىَ، اِلـهي كَيْفَ تَطْرُدُ مِسْكيناً الْتَجَأَ اِلَيْكَ مِنَ الذُّنُوبِ هارِباً، اَمْ كَيْفَ تُخَيِّبُ مُسْتَرْشِداً قَصَدَ اِلى جَنابِكَ ساعِياً، اَمْ كَيْفَ تَرُدُّ ظَمآناً وَرَدَ اِلى حِياضِكَ شارِباً كَلاّ وَحِياضُكَ مُتْرَعَةٌ في ضَنْكِ الُْمحُولِ، وَبابُكَ مَفْتُوحٌ لِلطَّلَبِ وَالْوُغُولِ، وَاَنْتَ غايَةُ الْمَسْؤولِ (السُّؤْلِ) وَنِهايَةُ الْمَأمُولِ، اِلـهي هذِهِ اَزِمَّةُ نَفْسي عَقَلْتُها بِعِقالِ مَشِيَّتِكَ وَهذِهِ اَعْباءُ ذُنُوبي دَرَأتُها بِعَفْوِكَ وَرَحْمَتِكَ وَهذِهِ اَهْوائِي الْمُضِلَّةُ وَكَلْتُها اِلى جَنابِ لُطْفِكَ وَرَأفَتِكَ، فَاجْعَلِ اللّـهُمَّ صَباحي هذا ناِزلاً عَلَي بِضِياءِ الْهُدى وَبِالسَّلامَةِ بالسلام فِي الدّينِ وَالدُّنْيا، وَمَسائي جُنَّةً مِنْ كَيْدِ الْعِدى (الاَْعْداءِ) وَوِقايَهً مِنْ مُرْدِياتِ الْهَوى اِنَكَ قادِرٌ عَلى ما تَشاءُ تُؤتِي الْمُلْكَ مَنْ تَشاءُ وَتَنْزِ عُ الْمُلْكَ مِمَّنْ تَشاءُ وَتُعِزُّ مَنْ تَشاءُ وَتُذِلُّ مَنْ تَشاءُ، بِيَدِكَ الْخَيْرُ اِنَّـكَ عَلى كُلِّ شَيْء قَديرٌ، تُولِجُ اللَيْلَ في النَّهارِ وَتُولِجُ النَّهارَ فِي اللَّيْلِ وَتُخْرِجُ الْحَيَّ مِنَ الْمَيِّتِ وَتُخْرِجُ الْمَيِّتَ مِنَ الْحَي وَتَرْزُقُ مَنْ تَشاءُ بِغَيْرِ حِساب، لا اِلـهَ إلاّ اَنْتَ سُبْحانَكَ اللّـهُمَّ وَبِحَمْدِكَ مَنْ ذا يَعْرِفُ قَدْرَكَ فَلا يَخافُكَ، وَمَن ذا يَعْلَمُ ما اَنْتَ فَلا يَهابُكَ، اَلَّفْتَ بِقُدْرَتِكَ الْفِرَقَ، وَفَلَقْتَ بِلُطْفِكَ الْفَلَقَ، وَاَنَرْتَ بِكَرَمِكَ دَياجِي الْغَسَقِ، وَاَنْهَرْتَ الْمِياهَ مِنَ الصُّمِّ الصَّياخيدِ عَذْباً وَاُجاجاً، وَاَنْزَلْتَ مِنَ الْمُعْصِراتِ ماءً ثَجّاجاً، وَجَعَلْتَ الشَّمْسَ وَالْقَمَرَ لِلْبَرِيَّةِ سِراجاً وَهّاجاً مِنْ غَيْرِ اَنْ تُمارِسَ فيما ابْتَدَأتَ بِهِ لُغُوباً وَلا عِلاجاً، فَيا مَنْ تَوَحَّدَ بِالْعِزِّ وَالْبَقاءِ، وَقَهَرَ عِبادَهُ بِالْمَوْتِ وَالْفَناءِ صَلِّ عَلى مُحَمَّد وَآلِهِ الاَْتْقِياءِ، وَاسْمَعْ نِدائي وَاسْتَجِبْ دُعائي وَحَقِّقْ بِفَضْلِكَ اَمَلي وَرَجائي يا خَيْرَ مَنْ دُعِي لِكَشْفِ الضُّرِّ وَالْمَأمُولِ لِكُلِّ عُسْر وَيُسْر بِكَ اَنْزَلْتُ حاجَتي فَلا تَرُدَّني مِنْ سَنِيِّ مَواهِبِكَ خائِباً يا كَريمُ يا كَريمُ يا كَريمُ بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ وَصَلَّى اللهُ عَلى خَيْرِ خَلْقِهِ مُحَمَّد وَآلِهِ اَجْمَعينَ ثمّ اسجد وقل : اِلـهي قَلْبي مَحْجُوبٌ، وَنَفْسي مَعْيُوبٌ، وَعَقْلي مَغْلُوبٌ، وَهَوائي غالِبٌ، وَطاعَتي قَليلٌ، وَمَعْصِيَتي كَثيرٌ، وَلِساني مُقِرٌّ بِالذُّنُوبِ فَكَيْفَ حيلَتي يا سَتّارَ الْعُيُوبِ وَيا عَلاّمَ الْغُيُوبِ وَيا كاشِفَ الْكُرُوبِ، اِغْفِرْ ذُنُوبي كُلَّها بِحُرْمَةِ مُحَمَّد وَآلِ مُحَمَّد يا غَفّارُ يا غَفّارُ يا غَفّارُ بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ ."},{"type":"AboutText","content":"أقول قد أورد العلامة المجلسي (رحمه الله) هذا الدّعاء في كتابي الدّعاء والصلاة من البحار وذيّله في كتاب الصلاة بشرح وتوضيح وقال: انّ هذا الدّعاء من الادعية المشهورة ولكن لم أجده في كتاب يعتمد عليه سوى كتاب المصباح للسيّد ابن باقي رضوان الله عليه، وقال أيضاً: انّ المشهور هو أن يدعى به بعد فريضة الصّبح ولكن السيّد ابن باقي رواه بعد نافلة الصّبح والعمل بأيّها كان حسنٌ ."}],"preview":"اَللّـهُمَّ يا مَنْ دَلَعَ لِسانَ الصَّباحِ بِنُطْقِ تَبَلُّجِهِ، وَسَرَّحَ قِطَعَ الّلَيْلِ الْمُظْلِمِ بِغَياهِبِ تَلَجْلُجِهِ، وَاَتْقَنَ صُنْعَ الْفَلَكِ الدَّوّارِ في مَقاديرِ","hasTranslate":false},{"id":"mf_ar_51","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل السادس :","title":"دُعَاء كُميل بن زياد (رحمه الله)","blocks":[{"type":"Text","content":"وهُو من الدّعوات المعروفة ، قال العلامة المجلسي (رحمه الله) : انّه أفضل الادعية وهُو دُعاء خضر (عليه السلام) وقد علّمه أمير المؤمنين (عليه السلام)كميلاً، وهُو من خواصّ أصحابه ويدعى به في ليلة النّصف مِن شعبان وليلة الجمعة ويجدي في كفاية شرّ الاعداء، وفي فتح باب الرّزق، وفي غفران الذّنوب، وقد رواه الشّيخ والسيّد كلاهما (قدس سرهما) وأنا أرويه عن كتاب مصباح المتهجّد، وهو هذا الدّعاء :"},{"type":"Text","content":"اَللّـهُمَّ اِنّي أَسْأَلُكَ بِرَحْمَتِكَ الَّتي وَسِعَتْ كُلَّ شَيْء، وَبِقُوَّتِكَ الَّتي قَهَرْتَ بِها كُلَّ شَيْء، وَخَضَعَ لَها كُلُّ شَيء، وَذَلَّ لَها كُلُّ شَيء، وَبِجَبَرُوتِكَ الَّتي غَلَبْتَ بِها كُلَّ شَيء، وَبِعِزَّتِكَ الَّتي لا يَقُومُ لَها شَيءٌ، وَبِعَظَمَتِكَ الَّتي مَلاََتْ كُلَّ شَيء، وَبِسُلْطانِكَ الَّذي عَلا كُلَّ شَيء، وَبِوَجْهِكَ الْباقي بَعْدَ فَناءِ كُلِّ شَيء، وَبِأَسْمائِكَ الَّتي مَلاََتْ اَرْكانَ كُلِّ شَيء، وَبِعِلْمِكَ الَّذي اَحاطَ بِكُلِّ شَيء، وَبِنُورِ وَجْهِكَ الَّذي اَضاءَ لَهُ كُلُّ شيء، يا نُورُ يا قُدُّوسُ، يا اَوَّلَ الاَْوَّلِينَ وَيا آخِرَ الاْخِرينَ، اَللّهُمَّ اغْفِرْ لِي الذُّنُوبَ الَّتي تَهْتِكُ الْعِصَمَ، اَللّـهُمَّ اغْفِـرْ لِي الذُّنُوبَ الَّتي تُنْزِلُ النِّقَمَ، اَللّهُمَّ اغْفِرْ لِي الذُّنُوبَ الَّتي تُغَيِّـرُ النِّعَمَ، اَللّـهُمَّ اغْفِرْ لي الذُّنُوبَ الَّتي تَحْبِسُ الدُّعاءَ، اَللّـهُمَّ اغْفِرْ لِي الذُّنُوبَ الَّتي تُنْزِلُ الْبَلاءَ، اَللّهُمَّ اغْفِرْ لي كُلَّ ذَنْب اَذْنَبْتُهُ، وَكُلَّ خَطيئَة اَخْطَأتُها، اَللّهُمَّ اِنّي اَتَقَرَّبُ اِلَيْكَ بِذِكْرِكَ، وَاَسْتَشْفِعُ بِكَ اِلى نَفْسِكَ، وَأَسْأَلُكَ بِجُودِكَ اَنْ تُدْنِيَني مِنْ قُرْبِكَ، وَاَنْ تُوزِعَني شُكْرَكَ، وَاَنْ تُلْهِمَني ذِكْرَكَ، اَللّهُمَّ اِنّي أَسْأَلُكَ سُؤالَ خاضِع مُتَذَلِّل خاشِع اَنْ تُسامِحَني وَتَرْحَمَني وَتَجْعَلَني بِقِسْمِكَ راضِياً قانِعاً وَفي جَميعِ الاَْحْوالِ مُتَواضِعاً، اَللّهُمَّ وَأَسْأَلُكَ سُؤالَ مَنِ اشْتَدَّتْ فاقَتُهُ، وَاَنْزَلَ بِكَ عِنْدَ الشَّدائِدِ حاجَتَهُ، وَعَظُمَ فيما عِنْدَكَ رَغْبَتُهُ، اَللّـهُمَّ عَظُمَ سُلْطانُكَ وَعَلا مَكانُكَ وَخَفِي مَكْرُكَ وَظَهَرَ اَمْرُكَ وَغَلَبَ قَهْرُكَ وَجَرَتْ قُدْرَتُكَ وَلا يُمْكِنُ الْفِرارُ مِنْ حُكُومَتِكَ، اَللّهُمَّ لا اَجِدُ لِذُنُوبي غافِراً، وَلا لِقَبائِحي ساتِراً، وَلا لِشَيء مِنْ عَمَلِي الْقَبيحِ بِالْحَسَنِ مُبَدِّلاً غَيْرَكَ لا اِلـهَ إلاّ اَنْتَ سُبْحانَكَ وَبِحَمْدِكَ ظَلَمْتُ نَفْسي، وَتَجَرَّأْتُ بِجَهْلي وَسَكَنْتُ اِلى قَديمِ ذِكْرِكَ لي وَمَنِّكَ عَلَيَّ، اَللّهُمَّ مَوْلاي كَمْ مِنْ قَبيح سَتَرْتَهُ وَكَمْ مِنْ فادِح مِنَ الْبَلاءِ اَقَلْتَهُ (اَمَلْتَهُ) وَكَمْ مِنْ عِثار وَقَيْتَهُ، وَكَمْ مِنْ مَكْرُوه دَفَعْتَهُ، وَكَمْ مِنْ ثَناء جَميل لَسْتُ اَهْلاً لَهُ نَشَرْتَهُ، اَللّهُمَّ عَظُمَ بَلائي وَاَفْرَطَ بي سُوءُ حالي، وَقَصُرَتْ (قَصَّرَتْ) بي اَعْمالي وَقَعَدَتْ بي اَغْلالى، وَحَبَسَني عَنْ نَفْعي بُعْدُ اَمَلي (آمالي)، وَخَدَعَتْنِي الدُّنْيا بِغُرُورِها، وَنَفْسي بِجِنايَتِها (بِخِيانَتِها) وَمِطالي يا سَيِّدي فَأَسْأَلُكَ بِعِزَّتِكَ اَنْ لا يَحْجُبَ عَنْكَ دُعائي سُوءُ عَمَلي وَفِعالي، وَلا تَفْضَحْني بِخَفِي مَا اطَّلَعْتَ عَلَيْهِ مِنْ سِرّى، وَلا تُعاجِلْني بِالْعُقُوبَةِ عَلى ما عَمِلْتُهُ في خَلَواتي مِنْ سُوءِ فِعْلي وَإساءَتي وَدَوامِ تَفْريطي وَجَهالَتي وَكَثْرَةِ شَهَواتي وَغَفْلَتي، وَكُنِ اللّهُمَّ بِعِزَّتِكَ لي في كُلِّ الاَْحْوالِ (فِي الاَْحْوالِ كُلِّها) رَؤوفاً وَعَلَي في جَميعِ الاُْمُورِ عَطُوفاً اِلـهي وَرَبّي مَنْ لي غَيْرُكَ أَسْأَلُهُ كَشْفَ ضُرّي وَالنَّظَرَ في اَمْري، اِلهي وَمَوْلاي اَجْرَيْتَ عَلَي حُكْماً اِتَّبَعْتُ فيهِ هَوى نَفْسي وَلَمْ اَحْتَرِسْ فيهِ مِنْ تَزْيينِ عَدُوّي، فَغَرَّني بِما اَهْوى وَاَسْعَدَهُ عَلى ذلِكَ الْقَضاءُ فَتَجاوَزْتُ بِما جَرى عَلَي مِنْ ذلِكَ بَعْضَ حُدُودِكَ، وَخالَفْتُ بَعْضَ اَوامِرِكَ فَلَكَ الْحَمْدُ (اَلْحُجَّةُ) عَلي في جَميعِ ذلِكَ وَلا حُجَّةَ لي فيما جَرى عَلَيَّ فيهِ قَضاؤُكَ وَاَلْزَمَني حُكْمُكَ وَبَلاؤُكَ، وَقَدْ اَتَيْتُكَ يا اِلـهي بَعْدَ تَقْصيري وَاِسْرافي عَلى نَفْسي مُعْتَذِراً نادِماً مُنْكَسِراً مُسْتَقيلاً مُسْتَغْفِراً مُنيباً مُقِرّاً مُذْعِناً مُعْتَرِفاً لا اَجِدُ مَفَرّاً مِمّا كانَ مِنّي وَلا مَفْزَعاً اَتَوَجَّهُ اِلَيْهِ في اَمْري غَيْرَ قَبُولِكَ عُذْري وَاِدْخالِكَ اِيّايَ في سَعَة (مِنْ) رَحْمَتِكَ اَللّـهُمَّ (اِلـهي) فَاقْبَلْ عُذْري وَارْحَمْ شِدَّةَ ضُرّي وَفُكَّني مِنْ شَدِّ وَثاقي، يا رَبِّ ارْحَمْ ضَعْفَ بَدَني وَرِقَّةَ جِلْدي وَدِقَّةَ عَظْمي، يا مَنْ بَدَأَ خَلْقي وَذِكْري وَتَرْبِيَتي وَبِرّى وَتَغْذِيَتي هَبْني لاِبـْتِداءِ كَرَمِكَ وَسالِفِ بِرِّكَ بي يا اِلـهي وَسَيِّدي وَرَبّي، اَتُراكَ مُعَذِّبي بِنارِكَ بَعْدَ تَوْحيدِكَ وَبَعْدَ مَا انْطَوى عَلَيْهِ قَلْبي مِنْ مَعْرِفَتِكَ وَلَهِجَ بِهِ لِساني مِنْ ذِكْرِكَ، وَاعْتَقَدَهُ ضَميري مِنْ حُبِّكَ، وَبَعْدَ صِدْقِ اعْتِرافي وَدُعائي خاضِعاً لِرُبُوبِيَّتِكَ، هَيْهاتَ اَنْتَ اَكْرَمُ مِنْ اَنْ تُضَيِّعَ مَنْ رَبَّيْتَهُ اَوْ تُبْعِدَ (تُبَعِّدَ) مَنْ اَدْنَيْتَهُ اَوْ تُشَرِّدَ مَنْ اوَيْتَهُ اَوْ تُسَلِّمَ اِلَى الْبَلاءِ مَنْ كَفَيْتَهُ وَرَحِمْتَهُ، وَلَيْتَ شِعْرى يا سَيِّدي وَاِلـهي وَمَوْلايَ اَتُسَلِّطُ النّارَ عَلى وُجُوه خَرَّتْ لِعَظَمَتِكَ ساجِدَةً، وَعَلى اَلْسُن نَطَقَتْ بِتَوْحيدِكَ صادِقَةً، وَبِشُكْرِكَ مادِحَةً، وَعَلى قُلُوب اعْتَرَفَتْ بِاِلهِيَّتِكَ مُحَقِّقَةً، وَعَلى ضَمائِرَ حَوَتْ مِنَ الْعِلْمِ بِكَ حَتّى صارَتْ خاشِعَةً، وَعَلى جَوارِحَ سَعَتْ اِلى اَوْطانِ تَعَبُّدِكَ طائِعَةً وَاَشارَتْ بِاسْتِغْفارِكَ مُذْعِنَةً، ما هكَذَا الظَّنُّ بِكَ وَلا اُخْبِرْنا بِفَضْلِكَ عَنْكَ يا كَريمُ يا رَبِّ وَاَنْتَ تَعْلَمُ ضَعْفي عَنْ قَليل مِنْ بَلاءِ الدُّنْيا وَعُقُوباتِها وَما يَجْري فيها مِنَ الْمَكارِهِ عَلى اَهْلِها، عَلى اَنَّ ذلِكَ بَلاءٌ وَمَكْرُوهٌ قَليلٌ مَكْثُهُ، يَسيرٌ بَقاؤُهُ، قَصيرٌ مُدَّتُهُ فَكَيْفَ احْتِمالي لِبَلاءِ الاْخِرَةِ وَجَليلِ (حُلُولِ) وُقُوعِ الْمَكارِهِ فيها وَهُوَ بَلاءٌ تَطُولُ مُدَّتُهُ وَيَدُومُ مَقامُهُ وَلا يُخَفَّفُ عَنْ اَهْلِهِ لاَِنَّهُ لا يَكُونُ إلاّ عَنْ غَضَبِكَ وَاْنتِقامِكَ وَسَخَطِكَ، وَهذا ما لا تَقُومُ لَهُ السَّمـاواتُ وَالاَْرْضُ يا سَيِّدِي فَكَيْفَ لي (بي) وَاَنَا عَبْدُكَ الضَّعيـفُ الـذَّليـلُ الْحَقيـرُ الْمِسْكيـنُ الْمُسْتَكينُ، يا اِلهي وَرَبّي وَسَيِّدِي وَمَوْلايَ لاَِيِّ الاُْمُورِ اِلَيْكَ اَشْكُو وَلِما مِنْها اَضِجُّ وَاَبْكي لاَِليمِ الْعَذابِ وَشِدَّتِهِ، اَمْ لِطُولِ الْبَلاءِ وَمُدَّتِهِ، فَلَئِنْ صَيَّرْتَنى لِلْعُقُوباتِ مَعَ اَعْدائِكَ وَجَمَعْتَ بَيْني وَبَيْنَ اَهْلِ بَلائِكَ وَفَرَّقْتَ بَيْني وَبَيْنَ اَحِبّائِكَ وَاَوْليائِكَ، فَهَبْني يا اِلـهى وَسَيِّدِي وَمَوْلايَ وَرَبّي صَبَرْتُ عَلى عَذابِكَ فَكَيْفَ اَصْبِرُ عَلى فِراقِكَ، وَهَبْني (يا اِلـهي) صَبَرْتُ عَلى حَرِّ نارِكَ فَكَيْفَ اَصْبِرُ عَنِ النَّظَرِ اِلى كَرامَتِكَ اَمْ كَيْفَ اَسْكُنُ فِي النّارِ وَرَجائي عَفْوُكَ فَبِعِزَّتِكَ يا سَيِّدى وَمَوْلايَ اُقْسِمُ صادِقاً لَئِنْ تَرَكْتَني ناطِقاً لاَِضِجَّنَّ اِلَيْكَ بَيْنَ اَهْلِها ضَجيجَ الاْمِلينَ (الاْلِمينَ) وَلاََصْرُخَنَّ اِلَيْكَ صُراخَ الْمَسْتَصْرِخينَ، وَلاََبْكِيَنَّ عَلَيْكَ بُكاءَ الْفاقِدينَ، وَلاَُنادِيَنَّكَ اَيْنَ كُنْتَ يا وَلِيَّ الْمُؤْمِنينَ، يا غايَةَ آمالِ الْعارِفينَ، يا غِياثَ الْمُسْتَغيثينَ، يا حَبيبَ قُلُوبِ الصّادِقينَ، وَيا اِلهَ الْعالَمينَ، اَفَتُراكَ سُبْحانَكَ يا اِلهى وَبِحَمْدِكَ تَسْمَعُ فيها صَوْتَ عَبْد مُسْلِم سُجِنَ (يُسْجَنُ) فيها بِمُخالَفَتِهِ، وَذاقَ طَعْمَ عَذابِها بِمَعْصِيَتِهِ وَحُبِسَ بَيْنَ اَطْباقِها بِجُرْمِهِ وَجَريرَتِهِ وَهُوَ يَضِجُّ اِلَيْكَ ضَجيجَ مُؤَمِّل لِرَحْمَتِكَ، وَيُناديكَ بِلِسانِ اَهْلِ تَوْحيدِكَ، وَيَتَوَسَّلُ اِلَيْكَ بِرُبُوبِيَّتِكَ، يا مَوْلايَ فَكَيْفَ يَبْقى فِي الْعَذابِ وَهُوَ يَرْجُو ما سَلَفَ مِنْ حِلْمِكَ، اَمْ كَيْفَ تُؤْلِمُهُ النّارُ وَهُوَ يَأْملُ فَضْلَكَ وَرَحْمَتَكَ اَمْ كَيْفَ يُحْرِقُهُ لَهيبُها وَاَنْتَ تَسْمَعُ صَوْتَهُ وَتَرى مَكانَه اَمْ كَيْفَ يَشْتَمِلُ عَلَيْهِ زَفيرُها وَاَنْتَ تَعْلَمُ ضَعْفَهُ، اَمْ كَيْفَ يَتَقَلْقَلُ بَيْنَ اَطْباقِها وَاَنْتَ تَعْلَمُ صِدْقَهُ، اَمْ كَيْفَ تَزْجُرُهُ زَبانِيَتُها وَهُوَ يُناديكَ يا رَبَّهُ، اَمْ كَيْفَ يَرْجُو فَضْلَكَ في عِتْقِهِ مِنْها فَتَتْرُكُهُ فيها هَيْهاتَ ما ذلِكَ الظَّنُ بِكَ وَلاَ الْمَعْرُوفُ مِنْ فَضْلِكَ وَلا مُشْبِهٌ لِما عامَلْتَ بِهِ الْمُوَحِّدينَ مِنْ بِرِّكَ وَاِحْسانِكَ، فَبِالْيَقينِ اَقْطَعُ لَوْ لا ما حَكَمْتَ بِهِ مِنْ تَعْذيبِ جاحِديكَ، وَقَضَيْتَ بِهِ مِنْ اِخْلادِ مُعانِدِيكَ لَجَعَلْتَ النّارَ كُلَّها بَرْداً وَسَلاماً وَما كانَت لاَِحَد فيها مَقَرّاً وَلا مُقاماً لكِنَّكَ تَقَدَّسَتْ اَسْماؤُكَ اَقْسَمْتَ اَنْ تَمْلاََها مِنَ الْكافِرينَ مِنَ الْجِنَّةِ وَالنّاسِ اَجْمَعينَ، وَاَنْ تُخَلِّدَ فيهَا الْمُعانِدينَ وَاَنْتَ جَلَّ ثَناؤُكَ قُلْتَ مُبْتَدِئاً، وَتَطَوَّلْتَ بِالاًِنْعامِ مُتَكَرِّماً اَفَمَنْ كانَ مُؤْمِناً كَمَنْ كانَ فاسِقاً لا يَسْتَوُونَ، اِلهى وَسَيِّدى فَأَسْأَلُكَ بِالْقُدْرَةِ الَّتى قَدَّرْتَها، وَبِالْقَضِيَّةِ الَّتي حَتَمْتَها وَحَكَمْتَها وَغَلَبْتَ مَنْ عَلَيْهِ اَجْرَيْتَها اَنْ تَهَبَ لى فى هذِهِ اللَّيْلَةِ وَفي هذِهِ السّاعَةِ كُلَّ جُرْم اَجْرَمْتُهُ، وَكُلَّ ذَنْب اَذْنَبْتُهُ، وَكُلَّ قَبِيح اَسْرَرْتُهُ، وَكُلَّ جَهْل عَمِلْتُهُ، كَتَمْتُهُ اَوْ اَعْلَنْتُهُ اَخْفَيْتُهُ اَوْ اَظْهَرْتُهُ، وَكُلَّ سَيِّئَة اَمَرْتَ بِاِثْباتِهَا الْكِرامَ الْكاتِبينَ الَّذينَ وَكَّلْتَهُمْ بِحِفْظِ ما يَكُونُ مِنّي وَجَعَلْتَهُمْ شُهُوداً عَلَيَّ مَعَ جَوارِحي، وَكُنْتَ اَنْتَ الرَّقيبَ عَلَيَّ مِنْ وَرائِهِمْ، وَالشّاهِدَ لِما خَفِيَ عَنْهُمْ، وَبِرَحْمَتِكَ اَخْفَيْتَهُ، وَبِفَضْلِكَ سَتَرْتَهُ، وَاَنْ تُوَفِّرَ حَظّي مِنْ كُلِّ خَيْر اَنْزَلْتَهُ (تُنَزِّلُهُ) اَوْ اِحْسان فَضَّلْتَهُ اَوْ بِرٍّ نَشَرْتَهُ (تَنْشُرُهُ) اَوْ رِزْق بَسَطْتَهُ (تَبْسُطُهُ) اَوْ ذَنْب تَغْفِرُهُ اَوْ خَطَأ تَسْتُرُهُ، يا رَبِّ يا رَبِّ يا رَبِّ يا اِلهي وَسَيِّدي وَمَوْلايَ وَمالِكَ رِقّى، يا مَنْ بِيَدِهِ ناصِيَتى يا عَليماً بِضُرّى (بِفَقْرى) وَمَسْكَنَتى، يا خَبيراً بِفَقْرى وَفاقَتى يا رَبِّ يا رَبِّ يا رَبِّ أَسْأَلُكَ بِحَقِّكَ وَقُدْسِكَ وَاَعْظَمِ صِفاتِكَ وَاَسْمائِكَ اَنْ تَجْعَلَ اَوْقاتي مِنَ (فِي) اللَّيْلِ وَالنَّهارِ بِذِكْرِكَ مَعْمُورَةً، وَبِخِدْمَتِكَ مَوْصُولَةً، وَاَعْمالى عِنْدَكَ مَقْبُولَةً حَتّى تَكُونَ اَعْمالي وَاَوْرادى (وَاِرادَتي) كُلُّها وِرْداً واحِداً وَحالى فى خِدْمَتِكَ سَرْمَداً، يا سَيِّدي يا مَنْ عَلَيْهِ مُعَوَّلي يا مَنْ اِلَيْهِ شَكَوْتُ اَحْوالي يا رَبِّ يا رَبِّ يا رَبِّ، قَوِّ عَلى خِدْمَتِكَ جَوارِحى وَاشْدُدْ عَلَى الْعَزيمَةِ جَوانِحي وَهَبْ لِيَ الْجِدَّ في خَشْيَتِكَ، وَالدَّوامَ فِي الاِْتِّصالِ بِخِدْمَتِكَ، حَتّى اَسْرَحَ اِلَيْكَ في مَيادينِ السّابِقينَ وَاُسْرِعَ اِلَيْكَ فِي الْبارِزينَ (الْمُبادِرينَ) وَاَشْتاقَ اِلى قُرْبِكَ فِي الْمُشْتاقينَ وَاَدْنُوَ مِنْكَ دُنُوَّ الُْمخْلِصينَ، وَاَخافَكَ مَخافَةَ الْمُوقِنينَ، وَاَجْتَمِعَ فى جِوارِكَ مَعَ الْمُؤْمِنينَ، اَللّهُمَّ وَمَنْ اَرادَني بِسُوء فَاَرِدْهُ وَمَنْ كادَني فَكِدْهُ، وَاجْعَلْني مِنْ اَحْسَنِ عَبيدِكَ نَصيباً عِنْدَكَ، وَاَقْرَبِهِمْ مَنْزِلَةً مِنْكَ، وَاَخَصِّهِمْ زُلْفَةً لَدَيْكَ، فَاِنَّهُ لا يُنالُ ذلِكَ إلاّ بِفَضْلِكَ، وَجُدْ لي بِجُودِكَ وَاعْطِفْ عَلَيَّ بِمَجْدِكَ وَاحْفَظْني بِرَحْمَتِكَ، وَاجْعَلْ لِسانى بِذِكْرِكَ لَهِجَاً وَقَلْبي بِحُبِّكَ مُتَيَّماً وَمُنَّ عَلَيَّ بِحُسْنِ اِجابَتِكَ، وَاَقِلْني عَثْرَتي وَاغْفِرْ زَلَّتي، فَاِنَّكَ قَضَيْتَ عَلى عِبادِكَ بِعِبادَتِكَ، وَاَمَرْتَهُمْ بِدُعائِكَ، وَضَمِنْتَ لَهُمُ الاِْجابَةَ، فَاِلَيْكَ يا رَبِّ نَصَبْتُ وَجْهي وَاِلَيْكَ يا رَبِّ مَدَدْتُ يَدي، فَبِعِزَّتِكَ اسْتَجِبْ لي دُعائي وَبَلِّغْني مُنايَ وَلا تَقْطَعْ مِنْ فَضْلِكَ رَجائي، وَاكْفِني شَرَّ الْجِنِّ وَالاِْنْسِ مِنْ اَعْدائي، يا سَريعَ الرِّضا اِغْفِرْ لِمَنْ لا يَمْلِكُ إلاّ الدُّعاءَ فَاِنَّكَ فَعّالٌ لِما تَشاءُ، يا مَنِ اسْمُهُ دَواءٌ وَذِكْرُهُ شِفاءٌ وَطاعَتُهُ غِنىً، اِرْحَمْ مَنْ رَأْسُ مالِهِ الرَّجاءُ وَسِلاحُهُ الْبُكاءُ، يا سابِـغَ النِّعَمِ، يا دافِعَ النِّقَمِ، يا نُورَ الْمُسْتَوْحِشينَ فِي الظُّلَمِ، يا عالِماً لا يُعَلَّمُ، صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَافْعَلْ بي ما اَنْتَ اَهْلُهُ وَصَلَّى اللهُ عَلى رَسُولِهِ وَالاَْئِمَّةِ الْمَيامينَ مِنْ آلِهِ (اَهْلِهِ) وَسَلَّمَ تَسْليماً كَثيراً ."}],"preview":"وهُو من الدّعوات المعروفة ، قال العلامة المجلسي (رحمه الله) : انّه أفضل الادعية وهُو دُعاء خضر (عليه السلام) وقد علّمه أمير المؤمنين (عليه السلام)كميلاً، وهُو من خواصّ أصحابه ويدعى","hasTranslate":false},{"id":"mf_ar_52","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل السادس :","title":"دُعاءُ العَشَراتِ","blocks":[{"type":"Text","content":"وهُو دعاء في غاية الاعتبار وفي نسخ رواياته اختلاف وأنا أرويه عن مصباح الشيخ، ويستحب الدّعاء به في كلّ صباح ومساء وأفضل أوقاته بعد العَصر مِنْ يوم الجمعة :"}],"preview":"وهُو دعاء في غاية الاعتبار وفي نسخ رواياته اختلاف وأنا أرويه عن مصباح الشيخ، ويستحب الدّعاء به في كلّ صباح ومساء وأفضل أوقاته بعد العَصر مِنْ يوم الجمعة :","hasTranslate":false},{"id":"mf_ar_53","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل السادس :","title":"دُعاء العَشَرات","blocks":[{"type":"Text","content":"سُبْحانَ اللهِ وَالْحَمْدُ للهِ وَلا اِلـهَ إلاّ اللهُ وَاللهُ اَكبَرُ وَلا حَوْلَ ولا قُوَّةَ إلاّ بِاللهِ الْعَلِيِّ الْعَظِيم، سُبْحانَ اللهِ آناءَ اللَّيْلِ وَاَطْرافَ النَّهارِ، سُبْحانَ اللهِ بِالْغُدُوِّ وَالاصالِ، سُبْحانَ اللهِ بِالْعَشِيِّ وَالاِْبكارِ، سُبْحانَ اللهِ حينَ تُمْسُونَ وَحينَ تُصْبِحُونَ وَلَهُ الْحَمْدُ فِي السَّماواتِ وَالاَْرْضِ وَعَشِيَّاً وَحينَ تُظْهِرُونَ، يُخْرِجَ الْحَيَّ مِنَ الْمَيِّتِ وَيُخْرِجُ الْمَيِّتَ مِنَ الْحَيِّ وَيُحْييِ الاَْرْضَ بَعْدَ مَوْتِها وَكَذلِكَ تُخْرَجُونَ، سُبْحانَ رَبِّكَ رَبِّ الْعِزَّةِ عَمّا يَصِفُونَ وَسَلامٌ عَلَى المُرْسَلينَ وَالْحَمْدُ للهِ رَبِّ الْعالَمِينَ، سُبْحانَ ذِي المُلْكِ وَالْمَلَكُوتِ، سُبْحانَ ذِي الْعِزَّةِ وَالْجَبَرُوتِ، سُبْحَانَ ذِي الْكِبْرِياءِ وَالْعَظَمَةِ الْمَلِكِ الْحَقِّ المُهَيْمِنِ (الْمُبينِ) الْقُدُّوسِ، سُبْحانَ الله الْمَلِكِ الْحَيِّ الَّذِي لا يَمُوتُ، سُبْحانَ اللهِ الْمَلِكِ الْحَيِّ الْقُدُّوسِ، سُبْحانَ الْقائِمِ الْدّائِمِ، سُبْحانَ الْدّائِمِ القائِمِ، سُبحَانَ رَبِّيَ الْعَظيِمِ، سُبْحانَ رَبِّيَ الاَْعْلى، سُبْحانَ الْحَيِّ القَيُّومِ، سُبْحانَ الْعَلِيِّ الاَْعْلى، سُبْحانَهُ وَتَعالى، سُبُّوحٌ قُدُّوسٌ رَبُّنا وَرَبُّ الْمَلائِكَةِ وَالرُّوحِ، سُبْحانَ الدّائِمِ غَيْرِ الْغَافِلِ، سُبْحانَ الْعالِمِ بِغَيْرِ تَعْلِيم، سُبْحانَ خالِقِ ما يُرى، ومَا لا يُرى سُبْحانَ الَّذي يُدْرِكُ الاَْبْصارَ وَلا تُدْرِكُهُ الاْبْصارُ وَهُوَ اللَّطيفُ الْخَبِيرُ، اَللّـهُمَّ إنّي اَصْبَحْتُ مِنْكَ في نِعْمَة وَخَيْر وَبَرَكَة وَعافِيَة فَصَلِّ عَلى مُحَمَّد وَآلِهِ وَاَتْمِمْ عَلَيَّ نِعْمَتَكَ وَخَيْرَكَ وَبَرَكاتِكَ وَعافِيَتِكَ بِنَجاة مِنَ الْنَّارِ، وَارْزُقْنِي شُكْرَكَ وَعافِيَتَكَ وَفَضْلَكَ وَكَرامَتَكَ اَبَداً ما اَبْقَيْتَنِي، اَللّـهُمَّ بِنُورِكَ اهْتَدَيْتُ وَبِفَضْلِكَ اسْتَغْنَيْتُ وَبِنِعْمَتِكَ اَصْبَحْتُ وَاَمْسَيْتُ، اَللّـهُمَّ اِنّي اُشْهِدُكَ وَكَفى بِكَ شَهِيداً وَاُشْهِدُ مَلائِكَتِكَ واَنْبِياءِكَ وَرُسُلَكَ وَحَمَلَةَ عَرْشِكَ وَسُكَّانَ سَماواتِكَ وَاَرْضِكَ (وَاَرَضيكَ) وَجَميعَ خَلْقِكَ بِاَنَّكَ اَنْتَ اللهُ لا اِلـهَ إلاّ اَنْتَ وَحْدَكَ لا شَرِيكَ لَكَ واَنَّ مُحَمَّداً صَلَّى اللهُ عَلَيْهِ وَآلِهِ عَبْدُكَ وَرَسُولُكَ وَاَنَّكَ عَلى كُلِّ شَيء قَدِيرٌ، تُحْيي وَتُميتُ وَتُميتُ وتُحْيي وَاَشْهَدُ اَنَّ الْجَنَّةَ حَقٌّ وَاَنَّ النَّارَ حَقٌّ، وَ (اَنَّ) النُّشُورَ حَقٌّ، وَالْسَّاعَهَ اتِيَةٌ لا رَيْبَ فيهَا، وَاَنَّ اللهَ يَبْعَثُ مَنْ فِي القُبُورِ، وَاَشْهَدُ اَنَّ عَلِيَّ بْنَ اَبي طالِب اَميرُ الْمُؤْمِنِينَ حَقّاً حَقّاً، وَاَنَّ الاْئِمَّةَ مِنْ وُلْدِهِ هُمُ الاْئمَّةُ الهُداةُ الْمَهْدِيُّونَ غَيْرُ الضّالّينَ وَلاَ المُضِلِّينَ وَاَنَّهُمْ أَوْلِياؤٌكَ الْمُصْطَفَوْنَ وَحِزْبُكَ الْغالِبُونَ وَصِفْوَتُكَ وَخِيَرَتُكَ مِنْ خَلْقِكَ وَنُجَباؤُكَ الَّذِينَ انْتَجَبْتَهُمْ لِدينِكَ وَاخْتَصَصْتَهُمْ مِنْ خَلْقِكَ، واصْطَفْيَتَهُمْ عَلى عِبادِكَ، وَجَعَلْتَهُمْ حُجَّةً عَلَى العالَمينَ صَلَواتُكَ عَلَيْهِمْ والسَّلامُ وَرَحْمةُ اللهِ وَبَرَكاتُهُ، اَللّـهُمَّ اكْتُبْ لي هذِهِ الشَّهادَهَ عِنْدَكَ حَتّى تُلَقِّنّيهاَ يَوْمَ الْقِيامَةِ وَانْتَ عَنّى راض اِنَّكَ عَلى ما تَشاءُ قَديرٌ، اَللّـهُمَّ لَكَ الْحَمدُ حَمداً يَصْعَدُ اَوَّلُهُ وَلا يَنْفَدُ اخِرُهُ، اَللّـهُمَّ لَكَ الْحَمدُ حَمْداً تَضَعُ لَكَ السَّماءُ كَنَفَيْها (كَتْفَيْها) وَتُسَبِّحُ لَكَ الاْرْضُ وَمَنْ عَلَيْها، اَللّـهُمَّ لَكَ الْحَمْدُ حَمْداً سَرْمَداً اَبَداً لاَ انْقِطاعَ لَهُ وَلا نَفادَ وَلَكَ يَنْبَغي وَاِلَيْكَ يَنْتَهي فِيَّ وَعَلَيَّ وَلَدَيَّ وَمَعي وَقَبْلي وَبَعْدي وَاَمامِي وَفَوْقي وَتَحْتي وَاِذا مِتُّ وَبَقيتُ فَرْداً وَحيداً ثُمَّ فَنيِتُ، وَلَكَ الْحَمْدُ اِذا نُشِرْتُ وَبُعِثْتُ يا مَوْلايَ. اَللّـهُمَّ وَلَكَ الْحَمْدُ وَلَكَ الشُّكْرُ بِجَميعِ مَحامِدِكَ كُلِّها عَلى جَميعِ نَعْمائِكَ كُلِّها حَتّى يَنْتَهِيَ الْحَمْدُ اِلى ما تُحِبُّ رَبَّنا وَتَرْضى، اَللّـهُمَّ لَكَ الْحَمْدُ عَلى كُلِّ اَكْلَة وَشِربَة وَبَطْشَة وَقَبْضَة وَبَسْطَة وَفي كُلِّ مَوْضِعِ شَعْرَة، اَللّـهُمَّ لَكَ الْحَمْدُ حَمْداً خالِداً مَعَ خُلُودِكَ ولَكَ الْحَمْدُ حَمْداً لا مُنْتَهى لَهُ دُونَ عِلْمِكَ وَلَكَ الْحَمْدُ حمداً أمدَ لهُ دُونَ مشيَّتِكَ، وَلَكَ الحمدُ حَمداً لا أخرَ لقائِلهِ إلاّ رِضاكَ وَلَكَ الْحَمْدُ عَلى حِلْمِكَ بَعْدَ عِلْمِكَ وَلَكَ الْحَمْدُ عَلى عَفِْوكَ بَعْدَ قُدرَتِكَ وَلَكَ الْحَمْدُ باعِثَ الْحَمْدِ وَلَكَ الْحَمْدِ وارِثَ الْحَمْدُ ولَكَ الْحَمْدُ بَديعَ الْحَمْدِ وَلَكَ الْحَمْدُ مُنْتَهَى الْحَمْدِ وَلَكَ الْحَمْدِ مُبتَدِعَ الْحَمْدِ وَلَكَ الْحَمْدُ مُشْتَرِيَ الْحَمْدِ وَلَكَ الْحَمْدُ وَلِيَّ الْحَمْدِ وَلَكَ الْحَمْدُ قَديمَ الْحَمْدِ وَلَكَ الْحَمْدُ صادِقَ الوَعْدِ وَفِيَّ الْعَهْدِ عَزيزَ الجُنْدِ قائِمَ الَْمجْدِ وَلَكَ الْحَمْدُ رَفيعَ الدَّرَجاتِ مُجيبَ الدَّعَواتِ مُنزِلَ (مُنَزَّلِ) الاْياتِ مِنْ فَوْقِ سَبْعِ سَماوات عَظيمَ الْبَرَكاتِ مُخْرِجَ النُّورِ مِنَ الظُّلُماتِ مَنْ فِي الظُّلُماتِ ومٌخْرِجَ اِلىَ النُّورِ، مُبَدِّلَ السَّيِّئاتِ حَسَنات، وَجاعِلَ الْحَسَناتِ دَرَجات، اَللّـهُمَّ لَكَ الْحَمْدُ غافِرَ الذَّنْبِ وَقابِلَ التَّوْبِ شَديدَ الْعِقابِ ذَا الطَّوْلِ، لا اِلـهَ إلاّ اَنْتَ اِلَيْكَ الْمَصيرُ، اَللّـهُمَّ لَكَ الْحَمْدُ فِي الَّليْلِ اِذا يَغْشى، وَلَكَ الْحَمْدُ فِي النَّهارِ اِذا تَجَلّى، وَلَكَ الْحَمْدُ فِي الاخِرَةِ وَالاُْولى، وَلَكَ الْحَمْدُ عَدَدَ كُلِّ نَجْم وَمَلَك فِي السَّماءِ، وَلَكَ الْحَمْدُ عَدَدَ الثَّرى وَالْحَصى وَالنَّوى، وَلَكَ الْحَمْدُ عَدَدَ ما في جَوِّ الَّسماءِ، وَلَكَ الْحَمْدُ عَدَدَ ما فى جَوْفِ الارْضِ، وَلَكَ الْحَمْدُ عَدَدَ اَوْزانِ مِياهِ الْبِحارِ، وَلَكَ الْحَمْدُ عَدَدَ اَوْراقِ الاَْشْجارِ، وَلَكَ الْحَمْدُ عَدَدَ ما عَلى وَجْهِ الاَْرْضِ، وَلَكَ الْحَمْدُ عَدَدَ ما اَحْصى كِتابُكَ، وَلَك الْحَمْدُ عَدَدَ ما اَحاطَ بِهِ عِلْمُكَ، وَلَكَ الْحَمْدُ عَدَدَ الاِْنْسِ وَالْجِنِّ وَالْهَوامِّ وَالطَّيْرِ وَالْبَهائِمِ والسِّباعِ، حَمْداً كثيراً طَيِّباً مُباركاً فِيهِ كَما تُحِبُّ رَبَّنا وَتَرْضى، وَكَما يَنْبَغي لِكَرَمِ وَجْهِكَ وَعِزِّ جَلالِكَ. ثمّ تقول عشراً : لا اِلـهَ إلاّ اللهُ وَحْدَهُ لا شَريكَ لَهُ، لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ اللَّطيفُ الْخَبيرُ. وعشراً : لا اِلـهَ إلاّ اللهُ وَحْدَهُ لا شَريكَ لَهُ، لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ يُحْيي وَيُميتُ ويُميتُ وَيُحْيي وَهُوَ حَيٌّ لا يَمُوتُ بِيَدِهِ الْخَيْرُ وَهُوَ عَلى كُلِّ شَيء قَديرٌ. وعشراً : اَسْتَغْفِرُ اللهَ الَّذِي لا اِلـهَ إلاّ هُوَ الْحَيُّ الْقَيُّومُ وَاَتُوبُ اِلَيْهِ. وعشراً : يا اَللهُ يا اَللهُ، وعشراً : يا رَحْمنُ يا رَحْمنُ وعشراً : يا رَحيمُ يا رَحيمُ وعشراً : يا بَديعُ السَّماواتِ وَالاَْرْضِ وعشراً : يا ذَا الْجَلالِ وَالاِْكْرامِ وَعشراً : يا حَنّانُ يا مَنّانُ وَعَشراً : يا حيُّ يا قَيُّومُ وعشراً : يا حَيُّ لا اِلـهَ إلاّ اَنْتَ وعشراً : يا اَللهُ يا لا اِلـهَ إلاّ اَنْتَ وَعشراً : بِسْمِ اللهِ الرَّحْمنِ الرَّحِيمِ وعشراً : اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وعشراً : اَللّـهُمَّ افْعَلْ بي ما اَنْتَ اَهْلُهُ وعشراً : آمينَ آمين َوعشراً : قُلْ هُوَ اللهُ اَحَدٌ ثمّ تقول : اَللّـهُمَّ اصْنَعْ بي ما اَنتَ اَهْلُهُ وَلا تَصْنَعُ بي ما اَنَا اَهْلُهُ فَاِنَّكَ اَهْلُ التَّقْوى وَاَهْلُ الْمَغْفِرَةِ، وَاَنَا اَهْلُ الذُّنُوبِ وَالْخَطايا فَارْحَمْني يا مَوْلايَ وَاَنْتَ اَرْحَمُ الرّاحِمينَ. وايضاً تقولُ عشراً : لا حَْوَلَ وَلا قُوَّهَ إلاّ بِاللهِ تَوَكَّلْتُ عَلَى الْحَيِّ الَّذي لا يَمُوُتُ وَالْحَمْدُ للهِ الَّذي لَمْ يَتَّخِذْ وَلَداً وَلَمْ يَكُنْ لَهُ شَريكٌ في الْمُلْكِ وَلَمْ يَكُنْ لَهُ وَلِيٌّ مِنَ الذُّلِّ وَكَبِّرْهُ تَكْبيراً ."}],"preview":"سُبْحانَ اللهِ وَالْحَمْدُ للهِ وَلا اِلـهَ إلاّ اللهُ وَاللهُ اَكبَرُ وَلا حَوْلَ ولا قُوَّةَ إلاّ بِاللهِ الْعَلِيِّ الْعَظِيم، سُبْحانَ اللهِ آناءَ اللَّيْلِ وَاَطْرافَ النَّهار","hasTranslate":false},{"id":"mf_ar_54","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل السادس :","title":"دُعاءُ السّماتِ","blocks":[{"type":"Text","content":"المَعروف بدُعاء الشّبور، ويُستحبّ الدّعاء بِه في آخر ساعة مِنْ نَهار الجُمعة وَلا يخفى انّه منَ الادعية المشهورة وقد واظب عليه اكثر العلماء السّلف وهو مَرويّ في مصباحِ الشّيخ الطّوسي، وفي جمال الاسبوع للسيّد ابن طاووس وكتب الكفعمي باسناد مُعتبرة عن مُحمّد بن عثمان العُمري رضوان الله عليه وهُو من نوّاب الحجّة الغائب (عليه السلام) وقد رُوِي الدعاء أيضاً عن الباقِر والصّادق (عليهما السلام)وَرواه المجلسي (رحمه الله)، في البحار فشرحه، وهذا هو الدّعاء على رواية المِصباح للّشيخ :"},{"type":"Text","content":"اَللّـهُمَّ اِنّى اَسْأَلُكَ بِاسْمِكَ الْعَظيمِ الاَْعْظَمِ الاَْعَزِّ الاَْجَلِّ الاَْكْرَمِ الَّذى اِذا دُعيتَ بِهِ عَلى مَغالِقِ اَبْوابِ السَّمآءِ لِلْفَتْحِ بِالرَّحْمَةِ انْفَتَحَتْ، وَاِذا دُعيتَ بِهِ عَلى مَضآئِقِ اَبْوابِ الاَْرْضِ لِلْفَرَجِ انْفَرَجَتْ، وَاِذا دُعيتَ بِهِ عَلَى العُسْرِ لِلْيُسْرِ تَيَسَّرَتْ، وَاِذا دُعيتَ بِهِ عَلَى الاَْمْواتِ لِلنُّشُورِ انْتَشَرَتْ، وَاِذا دُعيتَ بِهِ عَلى كَشْفِ الْبَأسآءِ وَالضَّرّاءِ انْكَشَفَتْ، وَبِجَلالِ وَجْهِكَ الْكَريمِ اَكْرَمِ الْوُجُوهِ وَاَعَزِّ الْوُجُوهِ الَّذى عَنَتْ لَهُ الْوُجُوهُ وَخَضَعَتْ لَهُ الرِّقابُ وَخَشَعَتْ لَهُ الاَْصْواتُ وَوَجِلَتْ لَهُ الْقُلُوبُ مِنْ مَخافَتِكَ، وَبِقُوَّتِكَ الَّتى بِها تُمْسِكُ السَّمآءَ اَنْ تَقَعَ عَلَى الاَْرْضِ إلاّ بِاِذْنِكَ، وَتُمْسِكُ السَّماواتِ وَالاَْرْضَ اَنْ تَزُولا، وَبِمَشِيَّتِكَ الَّتى دانَ (كانَ) لَهَا الْعالَمُونَ، وَبِكَلِمَتِكَ الَّتى خَلَقْتَ بِهَا السَّماواتِ وَالاَْرْضَ، وَبِحِكْمَتِكَ الَّتى صَنَعْتَ بِهَا الْعَجآئِبَ وَخَلَقْتَ بِهَا الظُّلْمَةَ وَجَعَلْتَها لَيْلاً وَجَعَلْتَ اللَّيْلَ سَكَناً (مَسْكَناً) وَخَلَقْتَ بِهَا النُّورَ وَجَعَلْتَهُ نَهاراً وَجَعَلْتَ النَّهارَ نُشُوراً مُبْصِراً، وَخَلَقْتَ بِهَا الشَّمْسَ وَجَعَلْتَ الشَّمْسَ ضِيآءً، وَخَلَقْتَ بِهَا الْقَمَرَ وَجَعَلْتَ الْقَمَرَ نُوراً، وَخَلَقْتَ بِهَا الْكَواكِبَ وَجَعَلْتَها نُجُوماً وَبُرُوجاً وَمَصابيحَ وَزينَةً وَرُجُوماً، وَجَعَلْتَ لَها مَشارِقَ وَمَغارِبَ وَجَعَلْتَ لَها مَطالِعَ وَمَجارِىَ، وَجَعَلْتَ لَها فَلَكاً وَمَسابِـحَ وَقَدَّرْتَها فِى السَّمآءِ مَنازِلَ فَاَحْسَنْتَ تَقْديرَها، وَصَوَّرْتَها فَاَحْسَنْتَ تَصْويرَها وَاَحْصَيْتَها بِاَسْمآئِكَ اِحْصآءً وَدَبَّرْتَها بِحِكْمَتِكَ تَدْبيراً فأحْسَنْتَ تَدْبيرَها وَسَخَّرْتَها بِسُلْطانِ اللَّيْلِ وَسُلْطانِ النَّهارِ وَالسّاعاتِ وَعَدَدَ السِّنينَ وَالْحِسابِ، وَجَعَلْتَ رُؤْيَتَها لِجَميعِ النّاسِ مَرْئً واحِداً وَاَسْأَلُكَ اللّهُمَّ بِمَجْدِكَ الَّذى كَلَّمْتَ بِهِ عَبْدَكَ وَرَسُولَكَ مُوسَى بْنَ عِمْرانَ عليه السلام فِى الْمُقَدَّسينَ فَوْقَ اِحْساسِ الْكَرُّوبينَ (الْكَرُّوبِيّينَ) فَوْقَ غَمآئِمِ النُّورِ فَوْقَ تابُوتِ الشَّهادَةِ فى عَمُودِ النّارِ وَفى (وَاِلى) طُورِ سَيْنآءَ وَفى جَبَلِ حُوريثَ فِى الْوادِ الْمُقَدَّسِ فِى الْبُقْعَةِ الْمُبارَكَةِ مِنْ جانِبِ الطُّورِ الاَْيْمَنِ مِنَ الشَّجَرَةِ وَفى اَرْضِ مِصْرَ بِتِسْعِ ايات بَيِّنات، وَيَوْمَ فَرَقْتَ لِبَنى اِسْرآئيلَ الْبَحْرَ وَفِى الْمُنْبَجِساتِ الَّتى صَنَعْتَ بِهَا الْعَجآئِبَ فى بَحْرِ سُوف، وَعَقَدْتَ مآءَ الْبَحْرِ فى قَلْبِ الْغَمْرِ كَالْحِجارَةِ، وَجاوَزْتَ بِبَنى اِسْرائيلَ الْبَحْرَ وَتَمَّتْ كَلِمَتُكَ الْحُسْنى عَلَيْهِمْ بِما صَبَرُوا وَاَوْرَثْتَهُمْ مَشارِقَ الاَْرْضِ وَمَغارِبَهَا الَّتى بارَكْتَ فيها لِلْعالَمينَ، وَاَغْرَقْتَ فِرْعَوْنَ وَجُنُودَهُ وَمَراكِبَهُ فِى الْيَمِّ، و بِاسْمِكَ الْعَظيمِ الاَْعْظَمِ الاَْعَزِّ الاَْجَلِّ الاَْكْرَمِ وَبِمَجْدِكَ الَّذى تَجَلَّيْتَ بِهِ لِمُوسى كَليمِكَ عليه السلام فى طُورِ سَيْناءَ، وَلاِِبْراهيمَ عليه السلام خَليلِكَ مِنْ قَبْلُ فى مَسْجِدِ الْخَيْفِ، وَلاِِسْحقَ صَفِيِّكَ عليه السلام فى بِئْرِ شِيع (سَبْع) وَلِيَعْقُوبَ نَبِيِّكَ عليه السلام فى بَيْتِ ايل، وَاَوْفَيْتَ لاِِبْراهيمَ عليه السلام بِميثاقِكَ وَلاِِسْحقَ بِحَلْفِكَ وَلِيَعْقُوبَ بِشَهادَتِكَ وَلِلْمُؤْمِنينَ بِوَعْدِكَ وَلِلدّاعينَ بِاَسْمائِكَ فَاَجَبْتَ، وَبِمَجْدِكَ الَّذى ظَهَرَ لِمُوسَى بْنِ عِمْرانَ عليه السلام عَلى قُبَّةِ الرُّمّانِ (الزَّمانِ) وَبِاياتِكَ الَّتى وَقَعَتْ عَلى اَرْضِ مِصْرَ بِمَجْدِ الْعِزَّةِ وَالْغَلَبَةِ بِايات عَزيزَة وَ بِسُلْطانِ الْقُوَّةِ وَبِعِزَّةِ الْقُدْرَةِ وَبِشَأْنِ الْكَلِمَةِ التّآمَّةِ، وَبِكَلِماتِكَ الَّتى تَفَضَّلْتَ بِها عَلى اَهْلِ السَّماواتِ وَالاَْرْضِ وَاَهْلِ الدُّنْيا وَاَهْلِ الاْخِرَةِ، وَبِرَحْمَتِكَ الَّتى مَنَنْتَ بِها عَلى جَميعِ خَلْقِكَ، وَبِاسْتِطاعَتِكَ الَّتى اَقَمْتَ بِها عَلَى الْعالَمينَ، وَبِنُورِكَ الَّذى قَدْ خَرَّمِنْ فَزَعِهِ طُورُ سَيْنآءَ، وَبِعِلْمِكَ وَجَلالِكَ وَكِبْرِيآئِكَ وَ عِزَّتِكَ وَجَبَرُوتِكَ الَّتى لَمْ تَسْتَقِلَّهَا الاَْرْضُ وَانْخَفَضَتْ لَهَا السَّماواتُ وَانْزَجَرَ لَهَا الْعُمْقُ الاَْكْبَرُ، وَرَكَدَتْ لَهَا الْبِحارُ وَالاَْنْهارُ، وَ خَضَعَتْ لَهَا الْجِبالُ وَسَكَنَتْ لَهَا الاَْرْضُ بِمَناكِبِها، وَاسْتَسْلَمَتْ لَهَا الْخَلائِقُ كُلُّها، وَ خَفَقَتْ لَهَا الرِّياحُ فى جَرَيانِها، وَخَمَدَتْ لَهَا النّيرانُ فى اَوْطانِها، وَبِسُلْطانِكَ الَّذى عُرِفَتْ لَكَ بِهِ الْغَلَبَةُ دَهْرَ الدُّهُورِ وَحُمِدْتَ بِهِ فِى السَّماواتِ وَالاَْرَضينَ، وَبِكَلِمَتِكَ كَلِمَةِ الصِّدْقِ الَّتى سَبَقَتْ لاَِبينا ادَمَ عليه السلام وَذُرِّيَّتِهِ بِالرَّحْمَةِ وَاَسْأَلُكَ بِكَلِمَتِكَ الَّتى غَلَبَتْ كُلَّ شَىْء، وَبِنُورِ وَجْهِكَ الَّذى تَجَلَّيْتَ بِهِ لِلْجَبَلِ فَجَعَلْتَهُ دَكّاً وَخَرَّ مُوسى صَعِقاً، وَبِمَجْدِكَ الَّذى ظَهَرَ عَلى طُورِ سَيْنآءَ فَكَلَّمْتَ بِهِ عَبْدَكَ وَرَسُولَكَ مُوسَى بْنَ عِمْرانَ، وَبِطَلْعَتِكَ فى ساعيرَ وَظُهُورِكَ فى جَبَلِ فارانَ بِرَبَواتِ الْمُقَدَّسينَ وَجُنُودِ الْمَلائِكَةِ الصّافّينَ وَخُشُوعِ الْمَلائِكَةِ الْمُسَبِّحينَ، وَبِبَرَكاتِكَ الَّتى بارَكْتَ فيها عَلى اِبْراهيمَ خَليلِكَ عليه السلام فى اُمَّةِ مُحَمَّد صَلَّى اللهُ عَلَيْهِ وَآلِهِ، وَبارَكْتَ لاِِسْحقَ صَفِيِّكَ فى اُمَّةِ عيسى عليهما السلام، وَبارَكْتَ لِيَعْقُوبَ اِسْرآئيلِكَ فى اُمَّةِ مُوسى عليهما السلام، وَبارَكْتَ لِحَبيبِكَ مُحَمَّد صَلَّى اللهُ عَلَيْهِ وَآلِهِ فى عِتْرَتِهِ وَذُرِّيَّتِهِ وَاُمَّتِهِ، اَللّـهُمَّ وَكَما غِبْنا عَنْ ذلِكَ وَلَمْ نَشْهَدْهُ وَآمَنّا بِهِ وَلَمْ نَرَهُ صِدْقاً وَعَدْلاً اَنْ تُصَلِّىَ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاَنْ تُبارِكَ عَلى مُحَمَّد وَآلِ مُحَمَّد وَتَرَحَّمَ عَلى مُحَمَّد وَآلِ مُحَمَّد كَاَفْضَلِ ما صَلَّيْتَ وَبارَكْتَ وَتَرَحَّمْتَ عَلى اِبْراهيمَ وَآلِ اِبْراهيمَ اِنَّكَ حَميدٌ مَجيدٌ فَعّالٌ لِما تُريدُ وَاَنْتَ عَلى كُلِّ شَىْء قَديرٌ (شَهيدٌ) ."}],"preview":"المَعروف بدُعاء الشّبور، ويُستحبّ الدّعاء بِه في آخر ساعة مِنْ نَهار الجُمعة وَلا يخفى انّه منَ الادعية المشهورة وقد واظب عليه اكثر العلماء السّلف وهو مَرويّ في مصباحِ الشّيخ الطّو","hasTranslate":false},{"id":"mf_ar_55","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل السادس :","title":"ثمَّ تذكر حاجتك وَتقول :","blocks":[{"type":"Text","content":"اَللّـهُمَّ بِحَقِّ هذَا الدُّعآءِ، وَبِحَقِّ هذِهِ الاَْسْمآءِ الَّتى لا يَعْلَمُ تَفْسيرَها وَلا يَعْلَمُ باطِنَها غَيْرُكَ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَافْعَلْ بى ما اَنْتَ اَهْلُهُ، وَلا تَفْعَلْ بى ما اَنَا اَهْلُهُ وَاغْفِرْ لى مِنْ ذُنُوبى ما تَقَدَّمَ مِنْها وَما تَأَخَّرَ، وَوَسِّعْ عَلَىَّ مِنْ حَلالِ رِزْقِكَ وَاكْفِنى مَؤُنَةَ اِنْسانِ سَوْء، وَجارِ سَوْء وَقَرينِ، سَوْء وَسُلْطانِ سَوْء، اِنَّكَ عَلى ما تَشآءُ قَديرٌ وَبِكُلِّ شَيْء عَليمٌ آمينَ رَبَّ الْعالَمينَ ."}],"preview":"اَللّـهُمَّ بِحَقِّ هذَا الدُّعآءِ، وَبِحَقِّ هذِهِ الاَْسْمآءِ الَّتى لا يَعْلَمُ تَفْسيرَها وَلا يَعْلَمُ باطِنَها غَيْرُكَ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَافْعَلْ بى ما اَن","hasTranslate":false},{"id":"mf_ar_56","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل السادس :","title":"أقول في بعض النسخ بعد وَاَنْتَ عَلى كُلِّ شَىْء قَديرٌ ثمّ اذكر حاجتك وَقُلْ :","blocks":[{"type":"Text","content":"يا اَللهُ يا حَنّانُ يا مَنّانُ يا بَديعَ السَّماواتِ وَالارضِ، يا ذَا الْجَلالِ وَالاِكْرامِ، يا اَرْحَمَ الرّاحِمينَ اَللّهُمَّ بِحَقِّ هَذا الدُّعآءِ ."},{"type":"Text","content":"إلى آخر الدّعاء، وروى المجلسي عن مِصباحِ السيّد ابن باقي انه قال: قل بعد دعاء السماتِ :"},{"type":"Text","content":"اَللّـهُمَّ بِحَقِّ هذَا الدُّعآءِ وَبِحَقِّ هذِهِ الاَْسْمآءِ الَّتى لا يَعْلَمُ تَفْسيرَها وَلا تَأْويلَها وَلا باطِنَها وَلا ظاهِرَها غَيْرُكَ اَنْ تُصَلِّىَ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاَنْ تَرْزُقَنى خَيْرَ الدُّنْيا وَالاْخِرَةِ ."}],"preview":"يا اَللهُ يا حَنّانُ يا مَنّانُ يا بَديعَ السَّماواتِ وَالارضِ، يا ذَا الْجَلالِ وَالاِكْرامِ، يا اَرْحَمَ الرّاحِمينَ اَللّهُمَّ بِحَقِّ هَذا الدُّعآءِ .","hasTranslate":false},{"id":"mf_ar_57","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل السادس :","title":"ثُمّ اطْلُب حاجتك وَقُل :","blocks":[{"type":"Text","content":"وَافْعَلْ بى ما اَنْتَ اَهْلُهُ وَلا تَفْعَلْ بى ما اَنـَا اَهْلُهُ، وَاْنتَقِمْ لى مِنْ فُلانِ بْنِ فُلان وسمّ عَدوّك وَاغْفِرْ لى مِنْ ذُنُوبى ما تَقَدَّمَ مِنْها وَما تَأَخَّرَ، وَلِوالِدَىَّ وَلِجَميعِ الْمُؤْمِنينَ وَالْمُؤْمِناتِ، وَوَسِّعْ عَلَىَّ مِنْ حَلالِ رِزْقِكَ وَاكْفِنى مَؤُنَةَ، اِنْسانِ سَوْء، وَجارِ سَوْء، وَسُلْطانِ سَوْء، وَقَرينِ سَوْء، وَيَوْمِ سَوْء، وَساعَةِ سَوْء، وَانْتَقِمْ لى مِمَّنْ يَكيدُنى وَمِمَّنْ يَبْغى عَلَىَّ وَيُريدُ بى وَبِاَهْلى وَاَوْلادى وَاِخْوانى وَجيرانى وَقَراباتى مِنَ الْمُؤْمِنينَ وَالْمُؤْمِناتِ ظُلْماً اِنَّكَ عَلى ما تَشآءُ قَديرٌ وَبِكُلِّ شَىْء عَليمٌ آمينَ رَبَّ الْعالَمينَ ."}],"preview":"وَافْعَلْ بى ما اَنْتَ اَهْلُهُ وَلا تَفْعَلْ بى ما اَنـَا اَهْلُهُ، وَاْنتَقِمْ لى مِنْ فُلانِ بْنِ فُلان وسمّ عَدوّك وَاغْفِرْ لى مِنْ ذُنُوبى ما تَقَدَّمَ مِنْها وَما تَأَخَّرَ،","hasTranslate":false},{"id":"mf_ar_58","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل السادس :","title":"ثمّ قلْ :","blocks":[{"type":"Text","content":"اَللّـهُمَّ بِحَقِّ هذَا الدُّعآءِ تَفَضَّلْ عَلى فُقَرآءِ الْمُؤْمِنينَ وَالْمُؤْمِناتِ بِالْغِنى وَالثَّرْوَةِ، وَعَلى مَرْضَى الْمُؤْمِنينَ وَالْمُؤْمِناتِ بِالشِّفآءِ وَالصِّحَةِ، وَعَلى اَحْيآءِ الْمُؤْمِنينَ وَالْمُؤْمِناتِ بِاللُّطْفِ وَالْكَرامَةِ، وَعَلى اَمْواتِ الْمُؤْمِنينَ وَالْمُؤْمِناتِ بِالْمَغْفِرَةِ وَالرَّحْمَةِ، وَعَلى مُسافِرِى الْمُؤْمِنينَ وَالْمُؤْمِناتِ بِالرَّدِّ اِلى اَوْطانِهِمْ سالِمينَ غانِمينَ بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ وَصَلَّى اللهُ عَلى سَيِّدِنا مُحَمَّد خاتَمِ النَّبِيّينَ وَعِتْرَتِهِ الطّاهِرينَ وَسَلَّمَ تَسْليماً كَثيراً ."}],"preview":"اَللّـهُمَّ بِحَقِّ هذَا الدُّعآءِ تَفَضَّلْ عَلى فُقَرآءِ الْمُؤْمِنينَ وَالْمُؤْمِناتِ بِالْغِنى وَالثَّرْوَةِ، وَعَلى مَرْضَى الْمُؤْمِنينَ وَالْمُؤْمِناتِ بِالشِّفآءِ وَالصِّحَ","hasTranslate":false},{"id":"mf_ar_59","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل السادس :","title":"وَقال الشّيخ ابن فهد: يستحبّ أن تقول بعد دعاء السّمات :","blocks":[{"type":"Text","content":"اَللّـهُمَّ اِنّى اَسْأَلُكَ بِحُرْمَةِ هذَا الدُّعآءِ وَبِمافاتَ مِنْهُ مِنَ الاَْسْمآءِ وَبِما يَشْتَمِلُ عَلَيْهِ مِنَ التَّفْسيرِ وَالتَّدْبيرِ الَّذى لايُحيطُ بِهِ اِلاّ اَنْتَ اَنْ تَفْعَلَ بى كَذا وَكَذا . وتذكُر حاجتك عوض كَذا وَكَذا ."},{"type":"Text","content":"دُعْاءُ المَشْلُول"},{"type":"Text","content":"الموسوم بدُعاء الشّاب المأخوذ بذَنْبه المروي في كتب الكفْعمي وَفي كتاب مهج الدّعوات، وهُو دُعـاء علّمه امير المؤمِنين (عليه السلام) شابّاً مأخوذاً بِذنبه مشلولاً نتيجة ما عمله من الظّلم والاثم في حقّ والده، فدَعى بهـذا الّدعاء واضطَجع فرأى النّبى (صلى الله عليه وآله وسلم) في مَنامه وقد مَسَح يَدَه عليه وقال: احتفظ بِاسم الله الاعظم فان عملك يكون بخَير ، فانتبه مَعافى وهُو هذا الدّعاء :"},{"type":"Text","content":"اَللّـهُمَّ اِنّى اَسْأَلُكَ بِاسْمِكَ بِسْمِ اللهِ الرَّحْمنِ الرَّحيمِ يا ذَا الْجَلالِ وَالاِْكرامِ يا حَىُّ يا قَيّوُمُ يا حَىُّ لا اِلـهَ اِلاّ اَنْتَ، يا هُوَ يا مَنْ لا يَعْلَمُ ما هُوَ وَلا كَيْفَ هُوَ وَلا حَيْثُ هُوَ اِلاّ هُوَ، يا ذَا المُلْكِ وَالْمَلَكوُتِ يا ذَا الْعِزَّةِ وَالْجَبَروُتِ، يا مَلِكُ يا قُدُّوسُ، يا سَلامُ يا مُؤْمِنُ يا مُهَيْمِنُ يا عَزيزُ يا جَبّارُ يا مُتَكَبِّرُ يا خالِقُ يا بارِئُ يا مصوّر يا مُفيدُ يا مُدَبِّرُ يا شَديدُ يا مُبْدِئُ يا مُعيدُ يا مُبيدُ يا وَدُودُ يا مَحْمُودُ يا مَعْبوُدُ يا بَعيدُ يا قَريبُ يا مجيب يا رقيب يا حَسيبُ يا بَديعُ يا رَفيعُ يا منيعٌ يا سَميعُ يا عَليمُ يا حَليمُ يا كَريمُ يا حَكيمُ يا قَديمُ يا عَلِىُّ يا عَظيمُ يا حَنّانُ يا مَنّانُ يا دَيّانُ يا مُسْتَعانُ يا جَليلُ يا جَميلُ يا وَكيلُ يا كفَيلُ يا مُقيلُ يا مُنيلُ يا نَبيلُ يا دَليلُ يا هادى يا بادى يا اَوَّلُ يا اخِرُ يا ظاهِرُ يا باطِنُ يا قآئِمُ يا دآئِمُ يا عالِمُ يا حاكِمُ يا قاضى يا عادِلُ يا فاصِلُ يا واصِلُ يا طاهِرُ يا مُطَهِّرُ يا قادِرُ يا مُقْتَدِرُ يا كَبيرُ يا مُتَكَبِّرُ يا واحِدُ يا اَحَدُ يا صَمَدُ يا مَنْ لَمْ يَلِدْ وَلَمْ يوُلَدْ وَلَمْ يَكُنْ لَهُ كُفُواً اَحَدٌ وَلَمْ يَكُنْ لَهُ صاحِبَةٌ وَلا كانَ مَعَهُ وَزيرٌ، وَلاَ اتَّخَذَ مَعَهُ مُشيراً، وَلاَ احْتاجَ اِلى ظَهير وَلا كانَ مَعَهُ مِنْ اِلـه غَيْرُهُ، لا اِلـهَ اِلاّ اَنْتَ فَتَعالَيْتَ عَمّا يَقُولُ الظّالِمُونَ عُلُوّاً كَبيراً، يا عَلِىُّ يا شامِخُ يا باذِخُ يا فَتّاحُ يا نَفّاحُ يا مُرْتاحُ يا مُفَرِّجُ يا ناصِرُ يا مُنْتَصِرُ يا مُدْرِكُ يا مُهْلِكُ يا مُنْتَقِمُ يا باعِثُ يا وارِثُ يا طالِبُ يا غالِبُ يا مَنْ لا يَفُوتُهُ هارِبٌ، يا تَوّابُ يا اَوّابُ يا وَهّابُ يا مُسَبِّبَ الاَْسْبابِ يا مُفَتِّحَ الاَْبْوابِ يا مَنْ حَيْثُ ما دُعِىَ اَجابَ، يا طَهُورُ يا شَكُورُ يا عَفُوُّ يا غَفُورُ يا نُورَ النُّورِ يا مُدَبِّرَ الاُْموُرِ يا لَطيفُ يا خَبيرُ يا مُجيرُ يا مُنيرُ يا بَصيرُ يا كَبيرُ يا وِتْرُ يا فَرْدُ يا اَبَدُ يا سَنَدُ يا صَمَدُ، يا كافى يا شافى يا وافى يا مُعافى يا مُحْسِنُ يا مُجْمِلُ يا مُنْعِمُ يا مُفْضِلُ يا مُتَكَرِّمُ يا مُتَفَرِّدُ، يا مَنْ عَلا فَقَهَرَ، يا مَنْ مَلَكَ فَقَدَرَ، يا مَنْ بَطَنَ فَخَبَرَ، يا مَنْ عُبِدَ فَشَكَرَ، يا مَنْ عُصِىَ فَغَفَرَ، يا مَنْ لا يَحْويهِ الْفِكَرُ وَلا يُدْرِكُهُ بَصَرٌ، وَلا يَخْفى عَلَيْهِ اَثَرٌ، يا رازِقَ الْبَشَرِ يا مُقَدِّرَ كُلِّ قَدَر، يا عالِىَ الْمَكانِ يا شَديدَ الاَْرْكانِ يا مُبَدِّلَ الزَّمانِ يا قابِلَ الْقُرْبانِ يا ذَا الْمَنِّ وَالاِْحْسانِ يا ذَا الْعِزَّةِ وَالسُّلْطانِ يا رَحيمُ يا مَنْ هُوَ كُلِّ يَوُم فى شَاْن يا مَنْ لا يَشْغَلُهُ شَاْنٌ عَنْ شَاْن، يا عَظيمَ الشَّأنِ يا مَنْ هُوَ بِكُلِّ مَكان، يا سامِعَ الاَْصْواتِ يا مُجيبَ الدَّعَواتِ يا مُنْجِحَ الطَّلِباتِ يا قاضِىَ الْحاجاتِ يا مُنْزِلَ الْبَرَكاتِ يا راحِمَ الْعَبَراتِ يا مُقيلَ الْعَثَراتِ يا كاشِفَ الْكُرُباتِ يا وَلِىَّ الْحَسَناتِ يا رافِعَ الدَّرَجاتِ يا مُؤْتِىَ السُّؤْلاتِ يا مُحْيِىَ الاَْمْواتِ يا جامِعَ الشَّتاتِ يا مُطَّلِعاً عَلَى النِّيّاتِ يا رادَّ ما قَدْ فاتَ يا مَنْ لا تَشْتَبِهُ عَلَيْهِ الاَْصْواتُ يا مَنْ لا تُضْجِرُهُ الْمَسْأَلاتُ وَلا تَغْشاهُ الظُّلُماتُ، يا نُورَ الاَْرْضِ والسِّماواتِ يا سابِغَ النِّعَمِ يا دافِعَ النِّقَمِ، يا بارِئَ النَّسَمِ يا جامِعَ الاُْمَمِ يا شافِىَ السَّقَمِ يا خالِقَ النُّورِ وَالظُّلَمِ يا ذَا الْجُودِ وَالْكَرَمِ يا مَنْ لا يَطَأُ عَرْشَهٌ قَدَمٌ، يا اَجْوَدَ الاَْجْوَدينَ يا اَكْرَمَ الاَْكْرَمينَ يا اَسْمَعَ السّامِعينَ يا اَبْصَرَ النّاظِرينَ يا جارَ الْمُسْتَجيرينَ يا اَمانَ الْخائِفينَ يا ظَهْرَ اللاّجينَ يا وَلِىَّ الْمُؤْمِنينَ يا غِياثَ الْمُسْتَغيثينَ يا غايَةَ الطّالِبينَ يا صاحِبَ كُلِّ غَريب يا مُؤنِسَ كُلِ وَحيد، يا مَلْجَاَ كُلِّ طَريد يا مَاْوى كُلِّ شَريد يا حافِظَ كُلِّ ضآلَّة، يا راحِمَ الشَّيْخِ الْكَبيرِ، يا رازِقَ الّطِفْلِ الصَّغيرِ يا جابِرَ الْعَظْمِ الْكَسيرِ يا فاكَّ كُلِّ اَسير، يا مُغْنِىَ الْبآئِسِ الْفَقيرِ، يا عِصْمَةَ الْخائِفِ الْمُسْتَجيرِ، يا مَنْ لَهُ التَّدْبيرُ وَالتَّقْديرُ يا مِنَ الْعَسيرُ عَلَيْهِ سَهْلٌ يَسيرٌ، يا مَنْ لا يَحْتاجُ اِلى تَفْسير، يا مَنْ هُوَ عَلى كُلِّ شْيء قَديرُ يا مَنْ هُوَ بِكُلِّ شَْيء خَبيرٌ يا مَنْ هُوَ بِكُلِّ شَْيء بَصيرٌ، يا مُرْسِلَ الرِّياحِ يا فالِقَ الاِْصْباحِ يا باعِثَ الاَْرْواحِ يا ذَا الْجُودِ وَالسَّماحِ يا مَنْ بِيَدِهِ كُلُّ مِفْتاح، يا سامِعَ كُلِّ صَوْت يا سابِقَ كُلِّ فَوْت يا مُحْيِىَ كُلِّ نَفْس بَعْدَ المَوْتِ، يا عُدَّتى فى شِدَّتى يا حافِظىِ فى غُرْبَتى يا مُؤنِسى فى وَحْدَتى يا وَلِيّى فى نِعْمَتى يا كَهْفى حينَ تُعْيينِى الْمَذاهِبُ وَتُسَلِّمُنىِ الاَْقارِبُ وَيَخْذُلُنى كُلُّ صاحِب، يا عِمادَ مَنْ لا عِمادَ لَهُ، يا سَنَدَ مَنْ لا سَنَدَ لَهُ، يا ذُخْرَ مَنْ لا ذُخْرَ لَهُ، يا حِرْزَ مَنْ لا حِرْزَ لَهُ، يا كَهْفَ مَنْ لا كَهْفَ لَهُ، يا كَنْزَ مَنْ لا كَنْزَ لَهُ، يا رُكُنَ مَنْ لا رُكْنَ لَهُ، يا غِياثَ مَنْ لا غِياثَ لَهُ، يا جارَ مَنْ لا جارَ لَهُ، يا جارِىَ اللَّصيقَ، يا رُكْنِىَ الَْوثيقَ، يا اِلـهى بِالتَّحْقيقِ، يا رَبَّ الْبَيْتِ الْعَتيقِ، يا شَفيقُ يا رَفيقُ فُكَّنى مِنْ حَلَقِ الْمَضيقِ، وَاصْرِفْ عَنّى كُلَّ هَمٍّ وَغَمٍّ وَ ضيق، وَاكْفِنى شَرَّ ما لا اُطيقُ، وَاَعِنّى عَلى ما اُطيقُ، يا رآدَّ يُوسُفَ عَلى يَعْقُوبَ، يا كاشِفَ ضُرِّ اَيُّوبَ، يا غافِرَ ذَنْبِ داوُدَ، يا رافِعَ عيسَى بْنِ مَرْيَمَ وَ مُنْجِيَهُ مِنْ اَيْدِى الْيَهوُدِ، يا مُجيبَ نِدآءِ يُونٌسَ فِى الظُّلُماتِ، يا مُصْطَفِىَ مُوسى بِالْكَلِماتِ، يا مَنْ غَفَرَ لاِدَمَ خَطيـئَتَهُ وَرَفَعَ اِدْريسَ مَكاناً عَلِيّاً بِرَحْمَتِهِ، يا مَنْ نَجّى نُوحاً مِنَ الْغَرَقِ، يا مَنْ اَهْلَكَ عاداً الاْوُلى وَثَمُودَ فَما اَبْقى وَقَوْمَ نوُح مِنْ قَبْلُ اِنَّهُمْ كانُوا هُمْ اَظْلَمَ وَاَطْغى، وَالْمُؤْتَفِكَةَ اَهْوى يا مَنْ دَمَّرَ عَلى قَوْمِ لوُط وَدَمْدَمَ عَلى قَوْمِ شُعَيْب، يا مَنِ اتَّخَذَ اِبْراهيمَ خَليلاً، يا مَنِ اتَّخَذَ مُوسى كَليماً وَاتَّخَذَ مُحَمَّداً صَلَّى اللهُ عَلَيْهِ وَآلِهِ وَعَلَيْهِمْ اَجْمَعينَ حَبيباً، يا مُؤْتِىَ لُقْمانَ الْحِكْمَةَ وَالْواهِبَ لِسُلَيْمانَ مُلْكاً لا يَنْبَغى لاَِحَد مِنْ بَعْدِهِ، يا مَنْ نَصَرَ ذَا الْقَرْنَيْنِ عَلَى الْمُلُوكِ الْجَبابِرَةِ، يا مَنْ اَعْطَى الْخِضْرَ الْحَيوةَ، وَرَدَّ لِيٌوشَعَ بْنِ نوُن الشَّمْسَ بَعْدَ غرُوُبِها يا مَنْ رَبَطَ عَلى قَلْبِ اُمِّ مُوسى وَاَحْصَنَ فَرْجَ مَرْيَمَ ابْنَتِ عِمْرانَ، يا مَنْ حَصَّنَ يَحْيَى بْنَ زَكَرِيّا مِنَ الذَّنْبِ وَسَكَّنَ عَنْ مُوسَى الْغَضَبَ، يا مَنْ بَشَّرَ زَكَرِيّا بِيَحْيى، يا مَنْ فَدا اِسْماعيلَ مِنَ الذَّبْحِ بِذِبْح عَظيم، يا مَنْ قَبِلَ قُرْبانَ هابيلَ وَجَعَلَ اللَّعْنَةَ عَلى قابيلَ، يا هازِمَ الاَْحْزابِ لُِمحَمَّد صَلَّى اللهُ عَلَيْهِ وَآلِهِ، صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّدِ وَ عَلى جَميعِ الْمُرْسَلينَ وَمَلائِكَتِكَ الْمُقَرَّبينَ وَاَهْلِ طاعَتِكَ اَجْمَعينَ، وَاَسْأَلُكَ بِكُلِّ مَسْأَلَة سَأَلَكَ بِها اَحَدٌ مِمَّنْ رَضيتَ عَنْهُ، فَحَتَمْتَ لَهُ عَلَى الاِْجابَةِ يا اَللهُ يا اَللهُ يا اَللهُ، يا رَحْمنُ يا رَحمنُ يا رَحْمنُ، يا رَحيمُ يا رَحيمُ يا رَحيمُ، يا ذَا الْجَلالِ وَالاِْكُرامِ يا ذَا الْجَلالِ وَ الاِْكْرامِ يا ذَا الْجَلالِ وَالاِْكْرامِ، بِهِ بِهِ بِهِ بِهِ بِهِ بِهِ بِهِ اَسْأَلُكَ بِكُلِّ اسْم سَمَّيْتَ بِهِ نَفْسَكَ اَوْ اَنْزَلْتَهُ فى شَْيء مِنْ كُتُبِكَ اَوِ اسْتَأثَرْتَ بِهِ فِى عِلْمِ الْغَيْبِ عِنْدَكَ، وَبِمَعاقِدِ الْعِزِّ مِنْ عَرْشِكَ، وَبِمُنْتَهَى الرَّحْمَةِ مِنْ كِتابِكَ، وَبِما لَوْ اَنَّ ما فِى الاَْرْضِ مِنْ شَجَرَة اَقْلامٌ وَالْبَحْرُ يَمُدُّهُ مِنْ بَعْدِهِ سَبْعَةُ اَبْحُر ما نَفِدَتْ كَلِماتُ اللهِ اِنَّ اللهَ عَزيزٌ حَكيمٌ وَ اَسْأَلُكَ بِاَسْمآئِكَ الْحُسْنَى الَّتى نَعَتَّها فى كِتابِكَ فَقُلْتَ وَللهِ الاَْسْمآءُ الْحُسْنى فَادْعوُهُ بِها، وَقُلْتَ اُدْعُونى اَسْتَجِبْ لَكُمْ،وَقُلْتَ وَاِذا سَأَلَكَ عِبادى عَنّى فَانّى قَريبٌ اُجيبُ دَعْوَةَ الدّاعِ اِذا دَعانِ، وَقُلْتَ يا عِبادِىَ الّذَينَ اَسْرَفوُا عَلى اَنْفُسِهِمْ لا تَقْظَوُا مِنْ رَحْمَةِ اللهِ اِنَّ اللهَ يَغْفِرُ الذُّنُوبَ جَميعاً اِنَّهُ هُوَ الْغَفُورُ الرَّحيمُ، وَاَنَا اَسْاَلُكَ يا اِلـهى وَاَدْعُوكَ يا رَبِّ وَاَرْجُوكَ يا سَيِّدى وَاَطْمَعُ فى اِجابَتى يا مَوْلاىَ كَما وَعَدْتَنى، وَقَدْ دَعَوْتُكَ كَما اَمَرْتَنى فَافْعَلْ بى ما اَنْتَ اَهْلُهُ يا كَريمُ، وَالْحَمْدُ للهِِ رَبِّ الْعالَمينَ وَصَلَّى اللهُ عَلى مُحَمَّد وَآلِهِ اَجْمَعينَ ."},{"type":"Text","content":"ثُمّ سَلْ حاجتك فَاِنَّها تُقضى ان شاء الله تعالى، وفي الرّواية المروية في مهج الدّعوات لا تدعو بهذا الدّعاء الاّ متطهّراً ."}],"preview":"اَللّـهُمَّ اِنّى اَسْأَلُكَ بِحُرْمَةِ هذَا الدُّعآءِ وَبِمافاتَ مِنْهُ مِنَ الاَْسْمآءِ وَبِما يَشْتَمِلُ عَلَيْهِ مِنَ التَّفْسيرِ وَالتَّدْبيرِ الَّذى لايُحيطُ بِهِ اِلاّ اَنْت","hasTranslate":false},{"id":"mf_ar_60","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل السادس :","title":"الدّعاء الْمَعرُوف بيَسْتشير","blocks":[{"type":"Text","content":"روَى السّيّدْ ابن طاوُس في كِتاب مهج الدّعوات عَنْ أمير المؤمنين (عليه السلام) أنه قال: عَلَّمني رَسوُلُ الله (صلى الله عليه وآله وسلم) هذا الدّعاء وَاَمَرني اَنْ اَدعُوَ به لِكلّ شِدّة وَرَخآء، وَاَنْ اعلّمه خليفتي مِنْ بَعْدي، وَاَمَرَني اَنْ لا اُفاِرق طوُل عُمري حَتّى القى الله عزوَجَلّ ، وَقالَ لي : قُل هذَا الدّعاء حين تُصبحِ وتُمسى فانّه مِنْ كنوز العَرش، فالتمس ابيّ بن كعب النّبيّ (صلى الله عليه وآله وسلم) أن يحدّث بفضل هذا الدّعاء، فاَخَبر النّبيّ (صلى الله عليه وآله وسلم) بِبَعْضِ ثَوابِهِ الجزيل، وَمَنْ اَراد الاطِّلاع عَلَيه فَليطلبه مِنْ كتاب مهج الدَّعوات ."},{"type":"Text","content":"اَلْحَمْدُ للهِ الَذى لا اِلـهَ اِلاّ هُوَ الْمَلِكُ الْحَقُّ الْمُبينُ الْمُدَبِرُّ بِلا وَزير وَلا خَلْق مِنْ عِبادِهِ يَسْتَشيرُ، الاَْوَّلُ غَيْرُ مَوْصُوف (مَصْرُوف)، وَالْباقى بَعْدَ فَنآءِ الْخَلْقِ، الْعَظيمُ الرُّبُوبِيَّةِ، نُورُ السَّماواتِ وَالاَْرَضينَ وَفاطِرُهُما وَمُبْتَدِعُهُما بِغَيْرِ عَمَد خَلَقَهُما وَفَتَقَهُما، فَتْقاً فَقامَتِ السَّماواتُ طآئِعات بِاَمْرِهِ وَاسْتَقَرَّتِ الاَْرضَوُنَ (الاَْرْضِ) بِاَوْتادِها فَوْقَ الْمآءِ، ثُمَّ عَلا رَبُّنا فِى السَماواتِ الْعُلى اَلَّرحْمنُ عَلَى الْعَرْشِ اسْتَوى، لَهُ ما فِى السَّماواتِ وَما فِى الاَْرْضِ وَما بَيْنَهُما وَما تَحْتَ الثَّرى، فَاَنَا اَشْهَدُ بِاَنَّكَ اَنْتَ اللهُ لا رافِعَ لِما وَضَعْتَ، وَلا واضِعَ لِما رَفَعْتَ، وَلا مُعِزَّ لِمَنْ اَذْلَلْتَ، وَلا مُذِلَّ لِمَنْ اَعْزَزْتَ، وَلا مانِعَ لِما اَعْطَيْتَ، وَلا مُعْطِىَ لِما مَنَعْتَ، وَاَنْتَ اللهُ لا اِلـهَ اِلاّ اَنْتَ كُنْتَ اِذْ لَمْ تَكُنْ سَمآءٌ مَبْنِيَّةٌ وَلا اَرْضٌ مَدْحِيَّةٌ وَلا شَمْسٌ مُضيـئَةٌ وَلا لَيْلٌ مُظْلِمٌ، وَلا نَهارٌ مُضيـىءٌ، وَلا بَحْرٌ لُجِّىٌّ وَلا جَبَلٌ راس، وَلا نَجْمٌ سار، وَلا قَمَرٌ مُنيرٌ، وَلا ريحٌ تَهُبُّ، وَلا سَحابٌ يَسْكُبُ، وَلا بَرْقٌ يَلْمَعُ، وَلا رَعْدٌ يُسَبِّحُ، وَلا رُوحٌ تَنَفَّسُ، وَلا طآئِرٌ يَطيرُ، وَلا نارٌ تَتَوَقَّدُ، وَلا مآءٌ يَطَّرِدُ كُنْتَ قَبْلَ كُلِّ شَْيء وَكَوَّنْتَ كُلَّ شَْيء وَقَدَرْتَ عَلى كُلِّ شَْيء وَابْتَدَعْتَ كُلَّ شَْيء وَاَغْنَيْتَ وَاَفْقَرْتَ وَ اَمَتَّ وَاَحْيَيْتَ وَاَضْحَكْتَ وَاَبْكَيْتَ وَعَلَى الْعَرشِ اسْتَوَيْتَ فَتَبارَكْتَ يا اَللهُ وَ تَعالَيْتَ، اَنْتَ اللهُ الَّذى لا اِلـهَ اِلاّ اَنْتَ الْخَلاّقُ الْمُعينُ (الْعَليمُ) اَمْرُكَ غالِبٌ وَعِلْمُكَ نافِذٌ، وَكَيْدُكَ غَريبٌ، وَوَعْدُكَ صادِقٌ، وَقَوْلُكَ حَقٌّ وَحُكْمُكَ عَدْلٌ، وَكَلامُكَ هُدىً، وَوَحْيُكَ نوُرٌ، وَرَحْمَتُكَ واسِعَةٌ، وَعَفْوُكَ عَظيمٌ، وَفَضْلُكَ كَثيرٌ، وَعَطاؤُكَ جَزيلٌ، وَحَبْلُكَ مَتينٌ، وَاِمْكانُكَ عَتيدٌ، وَجارُكَ عَزيزٌ، وَبَاْسُكَ شَديدٌ، وَمَكْرُكَ مَكيدٌ، اَنْتَ يا رَبِ مَوْضِعُ كُلِّ شَكْوى حاضِرُ كُلِّ مَلاَء وَشاهِدُ كُلِّ نَجْوى، مُنْتَهى كُلِّ حاجَة مُفَرِّجُ كُلِّ حُزْن (حَزين) غِنى كُلِّ مِسْكين حِصْنُ كُلِّ هارِب اَمانُ كُلِّ خآئِف، حْرِزُ الضُّعَفآءِ كَنْزُ الْفُقَرآءِ، مُفَرِّجُ الْغَمّآءِ مُعينُ الصّالِحينَ، ذلِكَ اللهُ رَبُّنا لا اِلـهَ اِلاّ هُوَ، تَكْفى مِنْ عِبادِكَ مَنْ تَوَكَّلَ عَلَيْكَ وَاَنْتَ جارُ مَنْ لاذَ بِكَ وَتَضَرَّعَ اِلَيْكَ عِصْمَةُ مَنِ اعْتَصَمَ بِكَ ناصِرُ، مَنِ انْتَصَرَ بِكَ تَغْفِرُ الذُّنُوبَ لِمَنِ اسْتَغْفَرَكَ، جَبّارُ الْجَبابِرَةِ، عَظيمُ الْعُظَمآءِ كَبيرُ الْكُبَرآءِ، سَيِّدُ السّاداتِ مُوْلَى الْمَوالى صَريخُ الْمُسْتَصْرِخينَ مُنَفِّسٌ عَنِ الْمَكْروُبينَ، مُجيبُ دَعْوَةِ الْمُضْطَرِّينَ اَسْمَعُ السّامِعينَ اَبْصَرُ النّاظِرينَ اَحْكَمُ الْحاكِمينَ اَسْرَعُ الْحاسِبينَ اَرْحَمُ الرّاحِمينَ خَيْرُ الغافِرينَ، قاضى حَوآئِج الْمُؤْمِنينَ مُغيثُ الصّالِحينَ اَنْتَ اللهُ لا اِلـهَ اِلاّ اَنْتَ رَبُّ الْعالَمينَ، اَنْتَ الْخالِقُ وَاَنَا الَْمخْلوُقُ وَاَنْتَ الْمالِكُ وَاَنَا الْمَمْلوُكُ وَاَنْتَ الرَّبُّ وَاَنَا الْعَبْدُ وَاَنْتَ الرّازِقُ وَاَنَا الْمَرْزُوقُ وَاَنْتَ الْمُعْطى وَاَنَا السّآئِلُ وَاَنْتَ الْجَوادُ وَاَنَا الْبَخيلُ، وَاَنْتَ الْقَوِىُّ وَاَنَا الضَّعيفُ وَاَنْتَ الْعَزيزُ وَاَنَا الذَّليلُ، وَاَنْتَ الْغَنِىُّ وَاَنَا الْفَقيرُ، وَاَنْتَ السَّيِّدُ وَاَنَا الْعَبْدُ، وَاَنْتَ الْغافِرُ وَاَنَا الْمُسـيئُ وَاَنْتَ الْعالِمُ وَاَنَا الْجاهِلُ، وَاَنْتَ الْحَليمُ وَاَنَا الْعَجُولُ، وَاَنْتَ الرَّحْمنُ وَاَنَا الْمَرْحُومُ، وَاَنْتَ الْمُعافى وَاَنَا الْمُبْتَلى، وَاَنْتَ الُْمجيبُ وَاَنَا الْمُضْطَرُّ، وَاَنَا اَشْهَدُ بِانَّكَ اَنْتَ اللهُ لا اِلـهَ اِلاّ اَنْتَ الْمُعْطى عِبادَكَ بِلا سُؤال، وَاَشْهَدُ بَاِنَّكَ اَنْتَ اللهُ الْواحِدُ الاَْحَدُ الْمُتَفَرِّدُ الصَّمَدُ الْفَرْدُ وَاِلَيْكَ الْمَصيرُ، وَصَلَّى اللهُ عَلى مُحَمَّد وَاَهْلِ بَيْتِهِ الطَّيِّبينَ الطّاهِرينَ وَاغْفِرْ لى ذُنُوبى وَاسْتُرْ عَلَىَّ عيُوُبى وَافْتَحْ لى مِنْ لَدُنْكَ رَحْمَةً وَرِزْقاً واسِعاً يا اَرْحَمَ الرّاحِمينَ وَالْحَمْدُ للهِ رَبِّ الْعالَمينَ وَحَسْبُنَا اللهُ وَنْعِمَ الْوَكيلُ وَلا حَوْلَ وَلا قُوَّةَ اِلاّ بِاللهِ الْعَلِىِّ الْعَظيمِ ."}],"preview":"روَى السّيّدْ ابن طاوُس في كِتاب مهج الدّعوات عَنْ أمير المؤمنين (عليه السلام) أنه قال: عَلَّمني رَسوُلُ الله (صلى الله عليه وآله وسلم) هذا الدّعاء وَاَمَرني اَنْ اَدعُوَ به لِكلّ","hasTranslate":false},{"id":"mf_ar_61","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل السادس :","title":"دُعاءُ المجير","blocks":[{"type":"Text","content":"وَهوَ دُعاء رَفيع الشّأن مَروِيّ عَنِ النّبي (صلى الله عليه وآله وسلم) نَزَل به جَبرئيل عَلَى الّنَبي (صلى الله عليه وآله وسلم) وَهْو يصلّي في مَقامِ ابراهيم (عليه السلام) . ذكر الكفعمي هذا الدّعاءِ في كِتابيه البَلد الامين وَالمِصباح واشارَ في الهامِش اِلى ما لهِ مِنَ الفَضْل، وَمِن جُملتها اِنّ مَنْ دعا به في الايّام البيض مِنْ شَهر رَمَضان غفرت ذنوبه وَلَوْ كانت عَدَد قطر المطر، وَوَرق الشجر، وَرَمل، البر وَيجدى في شِفاءِ المريض و قضآءِ الدّين وَالغنى عَنِ الفقر وَيفرّج الغَم ويكشف الكرب ، وهو هذا الدّعاء :"},{"type":"Text","content":"سُبْحانَكَ يا اَللهُ تَعالَيْتَ يا رَحْمنُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا رَحيمُ تَعالَيْتَ يا كَريمُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا مَلِكُ تَعالَيْتَ يا مالِكُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا قُدُّوسُ تَعالَيْتَ يا سَلامُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا مُؤْمِنُ تَعالَيْتَ يا مُهَيْمِنُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا عَزيزُ تَعالَيْتَ يا جَبّارُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا مُتَكَبِّرُ تَعالَيْتَ يا مُتَجَبِّرُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا خالِقُ تَعالَيْتَ يا بارِئُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا مُصَوِّرُ تَعالَيْتَ يا مُقَدِّرُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا هادى تَعالَيْتَ يا باقى اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا وَهّابُ تَعالَيْتَ يا تَوّابُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا فَتّاحُ تَعالَيْتَ يا مُرْتاحُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ ياسيِّدي تَعالَيْتَ يامولاي اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا قَريبُ تَعالَيْتَ يا رَقيبُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا مُبْدِئُ تَعالَيْتَ يا مُعيدُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا حَميدُ تَعالَيْتَ يا مَجيدُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا قَديمُ تَعالَيْتَ يا عَظيمُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا غَفُورُ تَعالَيْتَ يا شَكُورُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا شاهِدُ تَعالَيْتَ يا شَهيدُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا حَنّانُ تَعالَيْتَ يا مَنّانُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا باعِثُ تَعالَيْتَ يا وارِثُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا مُحْيى تَعالَيْتَ يا مُميتُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا شَفيقُ تَعالَيْتَ يا رَفيقُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا اَنيسُ تَعالَيْتَ يا موُنِسُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا جَليلُ تَعالَيْتَ يا جَميلُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا خَبيرُ تَعالَيْتَ يا بَصيرُ اَجِرْنا مِنَ النّارِ يا مَجيرُ،سُبْحانَكَ يا حَفِىُّ تَعالَيْتَ يا مَلِىُّ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا مَعْبُودُ تَعالَيْتَ يا مَوُجُودُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا غَفّارُ تَعالَيْتَ يا قَهّارُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا مَذْكُورُ تَعالَيْتَ يا مَشْكُورُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا جَوادُ تَعالَيْتَ يا مَعاذُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا جَمالُ تَعالَيْتَ يا جَلالُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا سابِقُ تَعالَيْتَ يا رازِقُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا صادِقُ تَعالَيْتَ يا فالِقُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا سَميعُ تَعالَيْتَ يا سَريعُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا رَفيعُ تَعالَيْتَ يا بديعُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا فَعّالُ تَعالَيْتَ يا مُتَعالُ اجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا قاضى تَعالَيْتَ يا راضى اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا قاهِرُ تَعالَيْتَ يا طاهِرُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا عالِمُ تَعالَيْتَ يا حكِمُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا دآئِمُ تَعالَيْتَ يا قآئِمُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا عاصِمُ تَعالَيْتَ يا قاسِمُ اِجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا غَنِىُّ تَعالَيْتَ يا مُغْنى اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا وَفِىُّ تَعالَيْتَ يا قَوِىُّ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا كافى تَعالَيْتَ يا شافى اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا مُقَدِّمُ تَعالَيْتَ يا مُؤَخِّرُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا اَوَّلُ تَعالَيْتَ يا آخِرُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا ظاهِرُ تَعالَيْتَ يا باطَنُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا رَجآءُ تَعالَيْتَ يا مُرْتَجى اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا ذَا الْمَنِّ تَعالَيْتَ يا ذَا الطَّوْلِ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا حَىُّ تَعالَيْتَ يا قَيّوُمُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا واحِدُ تَعالَيْتَ يا اَحَدُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا سَيِّدُ تَعالَيْتَ يا صَمَدُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا قَديرٌ تَعالَيْتَ يا كَبيْرٌ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا والى تَعالَيْتَ يا مُتَعالى اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا عَلِىُّ تَعالَيْتَ يا اَعْلى اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا وَلِىُّ تَعالَيْتَ يا مَوْلى اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا ذارِئُ تَعالَيْتَ يا بارِئُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا خافِضُ تَعالَيْتَ يا رافِعُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا مُقْسِطُ تَعالَيْتَ يا جامِعُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا مُعِزُّ تَعالَيْتَ يا مُذِلُّ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا حافِظُ تَعالَيْتَ يا حَفيظُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا قادِرُ تَعالَيْتَ يا مُقْتَدِرُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا عَليمُ تَعالَيْتَ يا حَليمُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا حَكَمُ تَعالَيْتَ يا حَكيمُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا مُعْطى تَعالَيْتَ يا مانِعُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا ضآرُّ تَعالَيْتَ يا نافِعُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا مُجيبُ تَعالَيْتَ يا حَسيبُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا عادِلُ تَعالَيْتَ يا فاصِلُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا لَطيفُ تَعالَيْتَ يا شَريفُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا رَبُّ تَعالَيْتَ يا حَقُّ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا ماجِدُ تَعالَيْتَ يا واحِدُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا عَفُوُّ تَعالَيْتَ يا مُنْتَقِمُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا واسِعُ تَعالَيْتَ يا مُوَسِّعُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا رَؤوُفُ تَعالَيْتَ يا عَطوُفُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا فَرْدُ تَعالَيْتَ يا وِتْرُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا مُقيتُ تَعالَيْتَ يا مُحيطُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا وَكيلُ تَعالَيْتَ يا عَدْلُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا مُبينُ تَعالَيْتَ يا مَتينُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا بَرُّ تَعالَيْتَ يا وَدُودُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا يارَشيدُ تَعالَيْتَ يا مُرْشِدُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا نُورُ تَعالَيْتَ يا مُنَوِّرُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا نَصيرُ تَعالَيْتَ يا ناصِرُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا صَبُورُ تَعالَيْتَ يا صابِرُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا مُحْصى تَعالَيْتَ يا مُنْشِئُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا سُبْحانُ تَعالَيْتَ يا دَيّانُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا مُغيثُ تَعالَيْتَ يا غِياثُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا فاطِرُ تَعالَيْتَ يا حاضِرُ اَجِرْنا مِنَ النّارِ يا مُجيرُ، سُبْحانَكَ يا ذَا الْعِزِّ والْجَمالِ تَبارَكْتَ يا ذَا الْجَبَرُوتِ وَالْجَلالِ، سُبْحانَكَ لا اِلـهِ اِلاّ اَنْتَ، سُبْحانَكَ اِنّى كُنْتُ مِنَ الظّالِمينَ فَاسْتَجَبْنا لَهُ وَنَجَّيْناهُ مِنَ الْغَمِّ وَكَذلِكَ نُنْجىِ الْمُؤمِنينَ، وَصَلَّى اللهُ عَلى سَيِّدِنا مُحَمَّد وَآلِهِ اَجْمَعينَ، وَالْحَمْدُ للهِ رَبِّ الْعالَمينَ وَحَسْبُنَا اللهُ وَنِعْمَ الْوَكيلُ وَلا حَوْلَ وَلا قُوَّةَ اِلاّ بِاللهِ الْعَليِّ العَظيمِ ."}],"preview":"وَهوَ دُعاء رَفيع الشّأن مَروِيّ عَنِ النّبي (صلى الله عليه وآله وسلم) نَزَل به جَبرئيل عَلَى الّنَبي (صلى الله عليه وآله وسلم) وَهْو يصلّي في مَقامِ ابراهيم (عليه السلام) . ذكر ال","hasTranslate":false},{"id":"mf_ar_62","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل السادس :","title":"دُعاءُ الْعَديلة","blocks":[{"type":"Text","content":"شَهِدَ اللهُ اَنَّهُ لا اِلـهَ اِلاّ هُوَ وَالْمَلائِكَةُ وَاُولُوا الْعِلْمِ قآئِماً بِالْقِسْطِ لا اِلـهَ اِلاّ هُوَ الْعَزيزُ الْحَكيمُ، اِنَّ الدّينَ عِنْدَ اللهِ الاِْسْلامُ، وَاَنَا الْعَبْدُ الضَّعيفٌ الْمُذْنِبُ الْعاصِىُ الُْمحْتاجُ الْحَقيرُ، اَشْهَدُ لِمُنْعِمى وَخالِقى وَرازِقى وَمُكْرِمى كَما شَهِدَ لِذاتِهِ وَشَهِدَتْ لَهُ الْمَلائِكَةُ وَاُولُو الْعِلْمِ مِنْ عِبادِهِ بِاَنَّهُ لا اِلـهَ اِلاّ هُوَ ذُو النِّعَمِ وَالاِْحْسانِ وَالْكَرَمِ وَالاِْمْتِنانِ، قادِرٌ اَزَلِىٌّ، عالِمٌ اَبَدِىٌّ، حَىٌّ اَحَدِىٌّ، مَوْجُودٌ سَرْمَدِىٌّ، سَميعٌ بَصيرٌ مُريدٌ كُارِهٌ مُدْرِكٌ صَمَدِىٌّ، يَسْتَحِقُّ هذِهِ الصِّفات وَهُوَ عَلى ما هُوَ عَلَيْهَ فى عِزِّ صِفاتِهِ، كانَ قَوِيّاً قَبْلَ وُجُودِ الْقُدْرَةِ وَالْقُوَّةَ، وَكانَ عَليماً قَبْلَ ايجادِ الْعِلْمِ وَالْعِلَّةِ، لَمْ يَزَلْ سُلْطاناً اِذْ لا مَمْلَكَةَ وَلا مالَ، وَلَمْ يَزَلْ سُبْحاناً عَلى جَميعِ الاَْحْوالِ وُجُودُهُ قَبْلَ الْقَبْلِ فى اَزَلِ الاْزالِ وَبَقآؤُهُ بَعْدَ الْبَعْدِ مِنْ غَيْرِ اِنْتِقال وَلا زَوال، غَنِىٌّ فِى الاَْوَّلِ وَالاْخِرِ، مُسْتَغْن فِى الْباطِنِ وَالظّاهِرِ، لا جَوْرَ فى قَضِيَّتِهِ وَلا مَيْلَ فى مَشِيَّتِهِ، وَلا ظُلْمَ فى تَقْديرِهِ وَلا مَهْرَبَ مِنْ حُكُومَتِهِ، وَلا مَلْجَاَ مِنْ سَطَواتِهِ وَلا مَنْجا مِنْ نَقِماتِهِ، سَبَقَتْ رَحْمَتُهُ غَضَبَهُ وَلا يَفُوتُهُ اَحَدٌ اِذا طَلَبَهُ، اَزاحَ الْعِلَلَ فِى التَّكْليفِ وَسَوَّى التَّوْفيقَ بَيْنَ الضَّعيفِ وَالشَّريفِ، مَكَّنَ اَدآءَ الْمَاْمُورِ وَسَهَّلَ سَبيلَ اجْتِنابِ الَْمحْظُورِ، لَمْ يُكَلِّفِ الطّاعَةَ اِلاّ دُوْنَ الْوُسْعِ والطّاقَةِ، سُبْحانَهُ ما اَبْيَنَ كَرَمَهُ وَاَعْلى شَأنَهُ، سُبْحانَهُ ما اَجَلَّ نَيْلَهُ وَاَعْظَمَ اِحْسانَهُ، بَعَثَ الاَْنْبِيآءَ لِيُبَيِّنَ عَدْلَهُ وَنَصَبَ الاَْوْصِيآءَ لِيُظْهِرَ طَوْلَهُ وَفَضْلَهُ، وَجَعَلَنا مِنْ اُمَّةِ سَيِّدِ الاَْنْبِيآءِ وَخَيْرِ الاَْوْلِيآءِ وَاَفْضَلِ الاَْصْفِيآءِ وَاَعْلَى الاَْزْكِيآءِ مُحَمَّد صلى الله عليه وآله وسلم، امَنّا ازلي وَبِما دَعانا اِلَيْهِ وَبِالْقُرْآنِ الَّذى اَنْزَلَهُ عَلَيْهِ وَبِوَصِيِّهِ الَّذى نَصَبَهُ يَوْمَ الْغَديرِ وَاَشارِ بِقَوْلِهِ هذا عَلِىٌّ اِلَيْهِ، وَاَشْهَدُ اَنَّ الاَْئِمَّةَ الاَْبْرارَ وَالْخُلَفآءَ الاَْخْيارَ بَعْدَ الرَّسُولِ الُْمخْتارِ، عَلِىٌّ قامِعُ الْكُفّارِ وَمِنْ بَعْدِهِ سَيِّدُ اَوْلادِهِ الْحَسَنُ بْنُ عَلِىٍّ ثُمَّ اَخُوُه السِّبْطُ التّابِعُ لِمَرْضاتِ اللهِ الْحُسَيْنُ، ثُمَّ الْعابِدُ عَلِىٌّ، ثُمَّ الْباقِرُ مُحَمَّدٌ، ثُمَّ الصّادِقُ جَعْفَرٌ، ثُمَّ الْكاظِمُ مُوسى، ثُمَّ الرِّضا عَلِىٌّ، ثُمَّ التَّقِىُّ مُحَمَّدٌ، ثُمَّ النَّقِىُّ عَلِىٌّ، ثُمَّ الزَّكِىُّ الْعَسْكَرِىُّ الْحَسَنُ، ثُمَّ الْحُجَّةُ الْخَلَفُ الْقآئِمُ الْمُنْتَظَرُ الْمَهْدِىُّ الْمُرجَى الَّذى بِبَقائِهِ بَقِيَتِ الدُّنْيا، وَبِيُمْنِهِ رُزِقَ الْوَرى، وَبِوُجُودِهِ ثَبتَتِ الاَْرْضُ وَالسَّمآءُ وَبِهِ يَمْلاَُ اللهُ الاَْرْضَ قِسْطاً وَعَدْلاً بَعْدَ ما مُلِئَتْ ظُلْماً وَجَوْراً، وَاَشْهَدُ اَنَّ اَقْوالَهُمْ حُجَّةٌ وَامْتِثالَهُمْ فَريْضَةٌ وَطاعَتَهُمْ مَفْرُوضَةٌ وَمَوَدَّتَهُمْ لازِمَةٌ مَقْضِيَّةٌ، وَالاِْقْتِدآءَ بِهِمْ مُنْجِيَةٌ، وَمُخالَفَتَهُمْ مُرْدِيَةٌ، وَهُمْ ساداتُ اَهْلِ الْجَنَّةِ اَجْمَعينَ، وَشُفَعآءُ يَوْمِ الدّينِ وَاَئِمَّةُ اَهْلِ الاَْرْضِ عَلَى الْيَقينِ، وَاَفْضَلُ الاَْوْصِيآءِ الْمَرْضِيّينَ، وَاَشْهَدُ اَنَّ الْمَوْتَ حَقٌّ وَمُسآءَلَةَ الْقَبْرِ حَقٌّ وَالْبَعْثَ حَقٌّ وَالنُّشُورَ حَقٌّ ز وَالصِّراطِ حَقٌّ، وَالْميزانَ حَقٌّ، وَالْحِسابَ حَقٌّ، وَالْكِتابَ حَقٌّ، وَالْجَنَّةَ حَقٌّ، وَالنّارَ حَقٌّ، وَاَنَّ السّاعَةَ اتِيَةٌ لا رَيْبَ فيها، وَاَنَّ اللهَ يَبْعَثُ مَنْ فِى الْقُبُورِ، اَللّـهُمَّ فَضْلُكَ رَجآئى وَكَرَمُكَ وَرَحْمَتُكَ اَمَلى لا عَمَلَ لى اَسْتَحِقُّ بِهِ الْجَنَّةَ، وَلا طاعَةَ لىْ اَسْتَوْجِبُ بِهَا الرِّضْوانَ اِلاّ اَنِّى اعْتَقَدْتُ تَوْحيدَكَ وَعَدْلَكَ، وَارْتَجَيْتُ اِحْسانَكَ وَفَضْلَكَ، وَتَشَفَّعْتُ اِلَيْكَ بِالنَّبِىِّ وَآلِهِ مَنْ اَحِبَّتِكَ وَاَنْتَ اَكْرَمُ الاَْكْرَمينَ وَاَرْحَمُ الرّاحِمينَ، وَصَلَّى اللهُ عَلى نَبِيِّنا مُحَمَّد وَآلِهِ اَجْمَعينَ الطَّيِّبينَ الطّاهِريْنَ وَسَلَّمَ تَسْليماً كَثيراً كَثيراً وَلا حَوْلَ وَلا قُوَّةَ اِلاّ بِاللهِ الْعَلِىِّ الْعَظيمِ اَللّـهُمَّ يا اَرْحَمَ الرّاحِمينَ اِنّى اَوْدَعْتُكَ يَقينى هذا وَثَباتَ دينى وَاَنْتَ خَيْرُ مُسْتَوْدَع وَقَدْ اَمَرْتَنا بِحِفْظِ الْوَدآئِعِ فَرُدَّهُ عَلَىَّ وَقْتَ حُضُورِ مَوْتى بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ ."},{"type":"AboutText","content":"أقول: قَد وَرَد في الادعية المأثورة اَللّـهُمَّ اِنِّى اَعُوذُ بِكَ مِنَ الْعَديلَةِ عِنْدَ الْمَوْتِ، وَمعنى العديلة عند المَوت هُو العُدول إلى الباطِل عن الحقّ وهُو بأن يحضر الشّيطان عند المحتضر ويوسوس في صَدره ويجعله يشكّ في دينه فيستل الايمان مِن فؤاده، ولهذا قد وَردت الاستعاذة منها في الدّعوات، وقال فخر المحقّقين (رحمه الله): مَن أراد أن يسلم من العديلة فليستحضر الايمان بأدلّتها والاصول الخمس ببراهينها القطعيّة بخلوص وصفاء وليودعها الله تعالى ليردّها اليه في ساعة الاحتضار بأن يقول بعد استحضار عقائده الحقّة :"},{"type":"Text","content":"اَللّـهُمَّ يا اَرْحَمَ الرّحِمينَ اِنّى قَدْ اَوْدَعْتُكَ يَقينى هذا وَثَباتَ دينى وَاَنْتَ خَيْرُ مُسْتَوْدَع وَقَدْ اَمَرْتَنا بِحِفْظِ الْوَدائِعِ فَرُدَّهُ عَلَىَّ وَقْتَ حُضُورِ مَوْتى،، فَعلى رأيه (قدس سره) قراءة هذا الدّعاء الشّريف « دُعاء العديلة » واستحضار مضمونه في البال تمنح المَرء اماناً من خطر العديلة عند الموت، وأمّا هذا الدّعاء فهل هو عن المعصوم (عليه السلام) أم هو انشاء من بعض العلماء ، يقول في ذلك خريت صناعة الحديث وجامع أخبار الائمة (عليهم السلام)العالم المتبحّر الخبير والمحدّث النّاقد البصير مولانا الحاج ميرزا حسين النّوري نوّر الله مرقده: وأمّا الدّعاء العديلة المعروفة فهو من مؤلّفات بعض أهل العلم ليس بمأثور ولا موجود في كتب حملة الاحاديث ونقّادها. واعلم انّه روى الطوسي عن محمّد بن سليمان الدّيلمي انّه قال للصّادق (عليه السلام): ان شيعتك تقول: انّ الايمان قسمين فمستقرّ ثابت ومستودع يزول، فعلّمني دعاءً يكمل به ايماني اذا دعوت به فلا يزول ، قال (عليه السلام): قل عقيب كلّ صلاة مكتوبة : رَضيتُ بِاللهِ رَبّاً وَبِمُحَمَّد صَلَّى اللهُ عَلَيْهِ وآلِهِ نَبِيّاً وَبِالاِسْلامِ ديناً وَبِالْقُرآنِ كِتاباً وَبِالْكَعْبَةِ قِبْلَةً وَبِعَلِىٍّ وَلِيّاً وَاِماماً وَبِالْحَسَنِ وَالْحُسَيْنِ وَعَلِىِّ بْنِ الْحُسَيْنِ وَمُحَمَّدَ بْنِ عَلِىٍّ وَجَعْفَرِ بْنَ مُحَمَّد وَمُوسى بْنِ جَعْفَر وَعَلِىِّ بْنِ مُوسى وَمُحَمَّدَ بْنِ عَلِىٍّ وَعَلِىِّ بْنِ مُحَمَّد وَالْحَسَنِ بْنِ عَلِيٍّ وَالْحُجَّةِ بْنِ الْحَسَنِ صَلَواتُ اللهِ عَلَيْهِمْ اَئمَّةً، اَللّـهُمَّ اِنّى رَضيتُ بِهِمْ اَئِمَّةً فَارْضَنى لَهُمْ اِنَّكَ عَلى كُلِّ شَيء قَديرٌ ."}],"preview":"شَهِدَ اللهُ اَنَّهُ لا اِلـهَ اِلاّ هُوَ وَالْمَلائِكَةُ وَاُولُوا الْعِلْمِ قآئِماً بِالْقِسْطِ لا اِلـهَ اِلاّ هُوَ الْعَزيزُ الْحَكيمُ، اِنَّ الدّينَ عِنْدَ اللهِ الاِْسْلامُ،","hasTranslate":false},{"id":"mf_ar_63","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل السادس :","title":"دُعاء الجَوشن الكبير","blocks":[{"type":"Text","content":"المذكور في كتابي البلد الامين والمِصباح للكفعمي وهُو مَرويّ عَنِ السّجاد عن أبيه عَنْ جدّه عن النبيّ صلّى الله علَيهِ وعَليْهم اجمعين، وَقد هبط به جبرئيل على النبيّ (صلى الله عليه وآله وسلم)وهُو في بعْضِ غزواته وَعَلَيْهِ جَوشن ثقيل المهُ، فقال: يا محمّد ربّك يقرئك السّلام ويقوُل لكَ: اخلع هذا الجوشَنْ واقرأ هذا الدّعآء فهو أمان لكَ ولامّتك، ثمّ أطال في ذكر فَضله بما لا يسعْه المقام ومِنْ جُملة فَضله انّ مَنْ كتبه على كفنه استحى الله أن يُعذّبه بالنّار ومَنْ دعا به بنيّة خالِصة في أوّل شهر رَمضان رزقه الله تعالى ليلة القدر، وَخلق له سَبعين ألف ملك يسبّحون الله وَيُقدّسونه وَجَعَلَ ثوابهم له، وَمَن دعا به في شهر رمضان ثلاث مرّات حرّم الله تعالى جَسده على النّار وأوجب له الجَنّة ووكّل الله تعالى به مَلَكين يحفظانه مِن المعاصي وَكانَ في أمان الله طول حَياته، وفي آخر الخبر انّه قال الحُسين (عليه السلام) : أوصاني أبي عليّ ابن أبي طالب (عليه السلام)بحفظ هذا الدّعاء وتعظيمه وأن أكتبه على كفنه وأن أعلّمه أهلي واحثّهم عليه، وهُو ألف اسْم وفيه الاسم الاعظم ."}],"preview":"المذكور في كتابي البلد الامين والمِصباح للكفعمي وهُو مَرويّ عَنِ السّجاد عن أبيه عَنْ جدّه عن النبيّ صلّى الله علَيهِ وعَليْهم اجمعين، وَقد هبط به جبرئيل على النبيّ (صلى الله عليه","hasTranslate":false},{"id":"mf_ar_64","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل السادس :","title":"أقول يستفاد من هذا الحديث أمران :","blocks":[{"type":"Text","content":"الاوّل : استحباب كتابة هذا الدّعاء على الاكفان كما أشار الى ذلك العلاّمة بحر العلوم عطّر الله مرقده في كتابِ الدُرّة ."},{"type":"Text","content":"وَسُنَّ اَنْ يُكْتَبَ بِالاَْكْفانِ شَهادَةُ الاسْلامِ والايمانِ"},{"type":"Text","content":"وَهكَذا كِتابَةُ الْقُرْآنِ وَالْجَوْشَنِ الْمَنْعُوتِ بِالاَْمانِ"},{"type":"Text","content":"الثاني : استحباب الدّعاء به في أوّل شهر رمضان، وأمّا الدّعاء به في خصُوص ليالي القدْر فلم يذكر في حديث ولكنّ العلاّمة المجلسي قدّس الله تعالى روحه قال في كتاب زاد المعاد في ضمن أعمال ليالي القدر: انّ في بعض الروايات انّه يدعى بدعاء الجوشن الكبير في كلّ من هذه الثّلاث ليالي، ويكفينا في المقام قوله الشّريف احلّه الله دار السّلام، وبالاجمال فهذا الدّعاء يحتوي على مائة فصل وكلّ فصل يحتوي على عشرة أسمآء مِن أسماء الله تعالى وتقول في آخر كلّ فصل : سُبْحانَكَ يا لا اِلـهَ إلاّ اَنْتَ الْغَوْثَ الْغَوْثَ خَلِّصْنا مِنَ النّارِ يا رَبِّ وقال في كتاب البلد الامين ابتدىء كلّ فصل بالبسملة واختمه بقول : سُبْحانَكَ يا لا اِلـهَ إلاّ اَنْتَ الْغَوْثَ الْغَوْثَ صَلِّ عَلى مُحَمَّد وَآلِهِ خَلِّصْنا مِنَ النّارِ يا رَبِّ يا ذَا الْجَلالِ وَالاِْكْرامِ يا أرْحَمَ الرّاحِمينَ ."},{"type":"Text","content":"وَهوَ هذَا الدُّعاء"},{"type":"Text","content":"اَللّـهُمَّ اِنّي اَسْأَلُكَ بِاسْمِكَ يا اَللهُ يا رَحْمنُ يا رَحيمُ يا كَريمُ يا مُقيمُ يا عَظيمُ يا قَديمُ يا عَليمُ يا حَليمُ يا حَكيمُ سُبْحانَكَ يا لا اِلـهَ إلاّ اَنْتَ الْغَوْثَ الْغَوْثَ خَلِّصْنا مِنَ النّارِ يا رَبِّ (2) يا سَيِّدَ السّاداتِ يا مُجيبَ الدَّعَواتِ يا رافِعَ الدَّرَجاتِ يا وَلِيَّ الْحَسَناتِ يا غافِرَ الْخَطيئاتِ يا مُعْطِيَ الْمَسْأَلاتِ يا قابِلَ التَّوْباتِ يا سامِعَ الاَْصْواتِ يا عالِمَ الْخَفِيّاتِ يا دافِعَ الْبَلِيّاتِ (3) يا خَيْرَ الْغافِرينَ يا خَيْرَ الْفاتِحينَ يا خَيْرَ النّاصِرينَ يا خَيْرَ الْحاكِمينَ يا خَيْرَ الرّازِقينَ يا خَيْرَ الْوارِثينَ يا خَيْرَ الْحامِدينَ يا خَيْرَ الذّاكِرينَ يا خَيْرَ الْمُنْزِلينَ يا خَيْرَ الُْمحْسِنينَ (4) يا مَنْ لَهُ الْعِزَّةُ وَالْجَمالُ يا مَنْ لَهُ الْقُدْرَةُ وَالْكَمالُ يا مَنْ لَهُ الْمُلْكُ وَالْجَلالُ يا مَنْ هُوَ الْكَبيرُ الْمُتَعالُ يا مُنْشِىءَ الْسَّحابِ الثِّقالِ يا مَنْ هُوَ شَديدُ الِْمحالِ يا مَنْ هُوَ سَريعُ الْحِسابِ يا مَنْ هُوَ شَديدُ الْعِقابِ يا مَنْ عِنْدَهُ حُسْنُ الثَّوابِ يا مَنْ عِنْدَهُ اُمُّ الْكِتابِ (5) اَللّـهُمَّ اِنّي اَسْأَلُكَ بِاسْمِكَ يا حَنّانُ يا مَنّانُ يا دَيّانُ يا بُرْهانُ يا سُلْطانُ يا رِضْوانُ يا غُفْرانُ يا سُبْحانُ يا مُسْتَعانُ يا ذَا الْمَنِّ وَالْبَيانِ (6) يا مَنْ تَواضَعَ كُلُّ شَيْء لِعَظَمَتِهِ يا مَنِ اسْتَسْلَمَ كُلُّ شَيْء لِقُدْرَتِهِ يا مَنْ ذَلَّ كُلُّ شَيْء لِعِزَّتِهِ يا مَنْ خَضَعَ كُلُّ شَيْء لِهَيْبَتِهِ يا مَنِ انْقادَ كُلُّ شَيْء مِنْ خَشْيَتِهِ يا مَنْ تَشَقَّقَتِ الْجِبالُ مِنْ مَخافَتِهِ يا مَنْ قامَتِ السَّماواتُ بِاَمْرِهِ يا مَنِ اسْتَقَرَّتِ الاَْرَضُونَ بِاِذْنِهِ يا مَنْ يُسَبِّحُ الرَّعْدُ بِحَمْدِهِ يا مَنْ لا يَعْتَدي عَلى اَهْلِ مَمْلَكَتِهِ (7) يا غافِرَ الْخَطايا يا كاشِفَ الْبَلايا يا مُنْتَهَي الرَّجايا يا مُجْزِلَ الْعَطايا يا واهِبَ الْهَدايا يا رازِقَ الْبَرايا يا قاضِيَ الْمَنايا يا سامِعَ الشَّكايا يا باعِثَ الْبَرايا يا مُطْلِقَ الاُْسارى (8) ياذَا الْحَمْدِ وَالثَّناءِ يا ذَا الْفَخْرِ وَاْلبَهاءِ يا ذَا الَْمجْدِ وَالسَّناءِ يا ذَا الْعَهْدِ وَالْوَفاءِ يا ذَا الْعَفْوِ وَالرِّضاءِ يا ذَا الْمَنِّ وَالْعَطاءِ يا ذَا الْفَضْلِ وَالْقَضاءِ يا ذَا الْعِزِّ وَالْبَقاءِ يا ذَا الْجُودِ وَالسَّخاءِ يا ذَا الاْلاءِ وَالنَّعْماءِ (9) اَللّـهُمَّ اِنّي اَسْأَلُكَ بِاسْمِكَ يا مانِعُ يا دافِعُ يا رافِعُ يا صانِعُ يا نافِعُ يا سامِعُ يا جامِعُ يا شافِعُ يا واسِعُ يا مُوسِعُ (10) يا صانِعَ كُلِّ مَصْنُوع يا خالِقَ كُلِّ مَخْلُوق يا رازِقَ كُلِّ مَرْزُوق يا مالِكَ كُلِّ مَمْلُوك يا كاشِفَ كُلِّ مَكْرُوب يا فارِجَ كُلِّ مَهْمُوم يا راحِمَ كُلِّ مَرْحُوم يا ناصِرَ كُلِّ مَخْذُول يا ساتِرَ كُلِّ مَعْيُوب يا مَلْجَأَ كُلِّ مَطْرُود (11)يا عُدَّتى عِنْدَ شِدَّتي يا رَجائي عِنْدَ مُصيبَتي يا مُونِسي عِنْدَ وَحْشَتي يا صاحِبي عِنْدَ غُرْبَتي يا وَلِيّي عِنْدَ نِعْمَتي يا غِياثى عِنْدَ كُرْبَتى يا دَليلي عِنْدَ حَيْرَتى يا غَنائى عِنْدَ افْتِقارى يا مَلجَئي عِنْدَ اضْطِرارى يا مُعينى عِنْدَ مَفْزَعى (12) يا عَلاّمَ الْغُيُوبِ يا غَفّارَ الذُّنُوبِ يا سَتّارَ الْعُيُوبِ يا كاشِفَ الْكُرُوبِ يا مُقَلِّبَ الْقُلُوبِ يا طَبيبَ الْقُلُوبِ يا مُنَوِّرَ الْقُلُوبِ يا اَنيسَ الْقُلُوبِ يا مُفَرِّجَ الْهُمُومِ يا مُنَفِّسَ الْغُمُومِ (13)اَللّـهُمَّ اِنّى اَسْأَلُكَ بِاْسمِكَ يا جَليلُ يا جَميلُ يا وَكيلُ يا كَفيلُ يا دَليلُ يا قَبيلُ يا مُديلُ يا مُنيلُ يا مُقيلُ يا مُحيلُ (14)يا دَليلَ الْمُتَحَيِّرينَ يا غِياثَ الْمُسْتَغيثينَ يا صَريخَ الْمُسْتَصْرِخينَ يا جارَ الْمُسْتَجيرينَ يا اَمانَ الْخائِفينَ يا عَوْنَ الْمُؤْمِنينَ يا راحِمَ الْمَساكينَ يا مَلْجَأَ الْعاصينَ يا غافِرَ الْمُذْنِبينَ يا مُجيبَ دَعْوَةِ الْمُضْطَرّينَ (15)يا ذَا الْجُودِ وَالاِْحْسانِ يا ذَا الْفَضْلِ وَالاِْمْتِنانِ يا ذَا الاَْمْنِ وَالاَْمانِ يا ذَا الْقُدْسِ وَالسُّبْحانِ يا ذَا الْحِكْمَةِ وَالْبَيانِ يا ذَا الرَّحْمَةِ وَالرِّضْوانِ يا ذَا الْحُجَّةِ وَالْبُرْهانِ يا ذَا الْعَظَمَةِ وَالسُّلْطانِ يا ذَا الرَّأْفَةِ وَالْمُسْتَعانِ يا ذَا العَفْوِ وَالْغُفْرانِ (16) يا مَنْ هُوَ رَبُّ كُلِّ شَيْء يا مَنْ هُوَ اِلـهُ كُلِّ شَيء يا مَنْ هُوَ خالِقُ كُلِّ شَيْء يا مَنْ هُوَ صانِعُ كُلِّ شَيْء يا مَنْ هُوَ قَبْلَ كُلِّ شَيْء يا مَنْ هُوَ بَعْدَ كُلِّ شَيْء يا مَنْ هُوَ فَوْقَ كُلِّ شَيْء يا مَنْ هُوَ عالِمٌ بِكُلِّ شَيْء يا مَنْ هُوَ قادِرٌ عَلى كُلِّ شَيْء يا مَنْ هُوَ يَبْقى وَيَفْنى كُلُّ شَيْء (17) اَللّـهُمَّ اِنّي اَسْأَلُكَ بِاسْمِكَ يا مُؤْمِنُ يا مُهَيْمِنُ يا مُكَوِّنُ يا مُلَقِّنُ يا مُبَيِّنُ يا مُهَوِّنُ يا مُمَكِّنُ يا مُزَيِّنُ يا مُعْلِنُ يا مُقَسِّمُ (18)يا مَنْ هُوَ فى مُلْكِهِ مُقيمٌ يا مَنْ هُوَ فى سُلْطانِهِ قَديمٌ يا مَنْ هُو فى جَلالِهِ عَظيمٌ يا مَنْ هُوَ عَلى عِبادِهِ رَحيمٌ يا مَنْ هُوَ بِكُلِّ شَيْء عَليمٌ يا مَنْ هُوَ بِمَنْ عَصاهُ حَليمٌ يا مَنْ هُوَ بِمَنْ رَجاهُ كَريمٌ يا مَنْ هُوَ فى صُنْعِهِ حَكيمٌ يا مَنْ هُوَ فى حِكْمَتِهِ لَطيفٌ يا مَنْ هُوَ فى لُطْفِهِ قَديمٌ (19) يا مَنْ لا يُرْجى إلاّ فَضْلُهُ يا مَنْ لا يُسْأَلُ إلاّ عَفْوُهُ يا مَنْ لا يُنْظَرُ إلاّ بِرُّهُ يا مَنْ لا يُخافُ إلاّ عَدْلُهُ يا مَنْ لا يَدُومُ إلاّ مُلْكُهُ يا مَنْ لا سُلْطانَ إلاّ سُلْطانُهُ يا مَنْ وَسِعَتْ كُلَّ شَيْء رَحْمَتُهُ يا مَنْ سَبَقَتْ رَحْمَتُهُ غَضَبَهُ يا مَنْ اَحاطَ بِكُلِّ شَيْء عِلْمُهُ يا مَنْ لَيْسَ اَحَدٌ مِثْلَهُ (20) يا فارِجَ الْهَمِّ يا كاشِفَ الْغَمِّ يا غافِرَ الذَّنْبِ يا قابِلَ التَّوْبِ يا خالِقَ الْخَلْقِ يا صادِقَ الْوَعْدِ يا مُوفِىَ الْعَهْدِ يا عالِمَ السِّرِّ يا فالِقَ الْحَبِّ يا رازِقَ الاَْنامِ (21) اَللّـهُمَّ اِنّي اَسْأَلُكَ بِاسْمِكَ يا عَلِيُّ يا وَفِيُّ يا غَنِيُّ يا مَلِيُّ يا حَفِيُّ يا رَضِيُّ يا زَكِيُّ يا بَدِيُّ يا قَوِيُّ يا وَلِيُّ (22) يا مَنْ اَظْهَرَ الْجَميلَ يا مَنْ سَتَرَ الْقَبيحَ يا مَنْ لَمْ يُؤاخِذْ بِالْجَريرَةِ يا مَنْ لَمْ يَهْتِكِ السِّتْرَ يا عَظيمَ الْعَفْوِ يا حَسَنَ التَّجاوُزِ يا واسِعَ الْمَغْفِرَةِ يا باسِطَ الْيَدَيْنِ بِالرَّحْمَةِ يا صاحِبَ كُلِّ نَجْوى يا مُنْتَهى كُلِّ شَكْوى (23) يا ذَا النِّعْمَةِ السّابِغَةِ يا ذَا الرَّحْمَةِ الْواسِعَةِ يا ذَا الْمِنَّةِ السّابِقَةِ يا ذَا الْحِكْمَةِ الْبالِغَةِ يا ذَا الْقُدْرَةِ الْكامِلَةِ يا ذَا الْحُجَّةِ الْقاطِعَةِ يا ذَا الْكَرامَةِ الظّاهِرَةِ يا ذَا الْعِزَّةِ الدّائِمَةِ يا ذَا الْقُوَّةِ الْمَتينَةِ يا ذَا الْعَظَمَةِ الْمَنيعَةِ (24) يا بَديعَ السَّماواتِ يا جاعِلَ الظُّلُماتِ يا راحِمَ الْعَبَراتِ يا مُقيلَ الْعَثَراتِ يا ساتِرَ الْعَوْراتِ يا مُحْيِيَ الاَْمْواتِ يا مُنْزِلَ الاياتِ يا مُضَعِّفَ الْحَسَناتِ يا ماحِيَ السَّيِّئاتِ يا شَديدَ النَّقِماتِ (25)اَللّـهُمَّ اِنّى اَسْأَلُكَ بِاسْمِكَ يا مُصَوِّرُ يا مُقَدِّرُ يا مُدَبِّرُ يا مُطَهِّرُ يا مُنَوِّرُ يا مُيَسِّرُ يا مُبَشِّرُ يا مُنْذِرُ يا مُقَدِّمُ يا مُؤَخِّرُ (26)يا رَبَّ الْبَيْتِ الْحَرامِ يا رَبَّ الشَّهْرِ الْحَرامِ يا رَبَّ الْبَلَدِ الْحَرامِ يا رَبَّ الرُّكْنِ وَالْمَقامِ يا رَبَّ الْمَشْعَرِ الْحَرامِ يا رَبَّ الْمَسْجِدِ الْحَرامِ يا رَبَّ الْحِلِّ وَالْحَرامِ يا رَبَّ النُّورِ وَالظَّلامِ يا رَبَّ التَّحِيَّةِ وَالسَّلامِ يا رَبَّ الْقُدْرَةِ فِي الاَْنامِ (27)يا اَحْكَمَ الْحاكِمينَ يا اَعْدَلَ الْعادِلينَ يا اَصْدَقَ الصّادِقينَ يا اَطْهَرَ الطّاهِرينَ يا اَحْسَنَ الْخالِقينَ يا اَسْرَعَ الْحاسِبينَ يا اَسْمَعَ السّامِعينَ يا اَبْصَرَالنّاظِرينَ يا اَشْفَعَ الشّافِعينَ يا اَكْرَمَ الاَْكْرَمينَ (28)يا عِمادَ مَنْ لا عِمادَ لَهُ يا سَنَدَ مَنْ لا سَنَدَ لَهُ يا ذُخْرَ مَنْ لا ذُخْرَ لَهُ يا حِرْزَ مَنْ لا حِرْزَ لَهُ يا غِياثَ مَنْ لا غِياثَ لَهُ يا فَخْرَ مَنْ لا فَخْرَ لَهُ يا عِزَّ مَنْ لا عِزَّ لَهُ يا مُعينَ مَنْ لا مُعينَ لَهُ يا اَنيسَ مَنْ لا اَنيسَ لَهُ يا اَمانَ مَنْ لا اَمانَ لَهُ (29)اَللّـهُمَّ اِنّى اَسْأَلُكَ بِاسْمِكَ يا عاصِمُ يا قائِمُ يا دائِمُ يا راحِمُ يا سالِمُ يا حاكِمُ يا عالِمُ يا قاسِمُ يا قابِضُ يا باسِطُ (30)يا عاصِمَ مَنِ اسْتَعْصَمَهُ يا راحِمَ مَنِ اسْتَرْحَمَهُ يا غافِرَ مَنِ اسْتَغْفَرَهُ يا ناصِرَ مَنِ اسْتَنْصَرَهُ يا حافِظَ مَنِ اسْتَحْفَظَهُ يا مُكْرِمَ مَنِ اسْتَكْرَمَهُ يا مُرْشِدَ مَنِ اسْتَرْشَدَهُ يا صَريخَ مَنِ اسْتَصْرَخَهُ يا مُعينَ مَنِ اسْتَعانَهُ يا مُغيثَ مَنِ اسْتَغاثَهُ (31) يا عَزيزاً لا يُضامٌ يا لَطيفاً لا يُرامُ يا قَيُّوماً لا يَنامُ يا دائِماً لا يَفُوتُ يا حَيّاً لا يَمُوتُ يا مَلِكاً لا يَزُولُ يا باقِياً لا يَفْنى يا عالِماً لا يَجْهَلُ يا صَمَداً لا يُطْعَمُ يا قَوِيّاً لا يَضْعُفُ (32)اَللّـهُمَّ اِنّى اَسْأَلُكَ بِاسْمِكَ يا اَحَدُ يا واحِدُ يا شاهِدُ يا ماجِدُ يا حامِدُ يا راشِدُ يا باعِثُ يا وارِثُ يا ضارُّ يا نافِعُ (33)يا اَعْظَمَ مِنْ كُلِّ عَظيم يا اَكْرَمَ مِنْ كُلِّ كَريم يا اَرْحَمَ مِنْ كُلِّ رَحيم يا اَعْلَمَ مِنْ كُلِّ عَليم يا اَحْكَمَ مِنْ كُلِّ حَكيم يا اَقْدَمَ مِنْ كُلِّ قَديم يا اَكْبَرَ مِنْ كُلِّ كَبير يا اَلْطَفَ مِنْ كُلِّ لَطيف يا اَجَلَّ مِن كُلِّ جَليل يا اَعَزَّ مِنْ كُلِّ عَزيز (34) يا كَريمَ الصَّفْحِ يا عَظيمَ الْمَنِّ يا كَثيرَ الْخَيْرِ يا قَديمَ الْفَضْلِ يا دائِمَ اللُّطْفِ يا لَطيفَ الصُّنْعِ يا مُنَفِّسَ الْكَرْبِ يا كاشِفَ الضُّرِّ يا مالِكَ الْمُلْكِ يا قاضِيَ الْحَقِّ (35) يا مَنْ هُوَ فى عَهْدِهِ وَفِيٌّ يا مَنْ هُوَ في وَفائِهِ قَوِيٌّ يا مَنْ هُوَ في قُوَّتِهِ عَلِيٌّ يا مَنْ هُوَ في عُلُوِّهِ قَريبٌ يا مَنْ هُوَ فى قُرْبِهِ لَطيفٌ يا مَنْ هُوَ فى لُطْفِهِ شَريفٌ يا مَنْ هُوَ فى شَرَفِهِ عَزيزٌ يا مَنْ هُوَ فى عِزِّهِ عَظيمٌ يا مَنْ هُوَ فى عَظَمَتِهِ مَجيدٌ يا مَنْ هُوَ فى مَجْدِهِ حَميدٌ (36) اَللّـهُمَّ اِنّي اَسْأَلُكَ بِاسْمِكَ يا كافى يا شافى يا وافى يا مُعافى يا هادى يا داعى يا قاضى يا راضى يا عالي يا باقي (37) يا مَنْ كُلُّ شَيْء خاضِعٌ لَهُ يا مَنْ كُلُّ شَيْء خاشِعٌ لَهُ يا مَنْ كُلُّ شَيْء كائِنٌ لَهُ يا مَنْ كُلُّ شَيْء مَوْجُودٌ بِهِ يا مَنْ كُلُّ شَيْء مُنيبٌ اِلَيْهِ يا مَنْ كُلُّ شَيْء خائِفٌ مِنْهُ يا مَنْ كُلُّ شَيْء قائِمٌ بِهِ يا مَنْ كُلُّ شَيْء صائِرٌ اِلَيْهِ يا مَنْ كُلُّ شَيْء يُسَبِّحُ بِحَمْدِهِ يا مَنْ كُلُّ شَيْء هالِكٌ إلاّ وَجْهَهُ (38) يا مَنْ لا مَفَرَّ إلاّ اِلَيْهِ يا مَنْ لا مَفْزَعَ إلاّ اِلَيْهِ يا مَنْ لا مَقْصَدَ إلاّ اِلَيْهِ يا مَنْ لا مَنْجا مِنْهُ إلاّ اِلَيْهِ يا مَنْ لا يُرْغَبُ إلاّ اِلَيْهِ يا مَنْ لا حَوْلَ وَلا قُوَّةَ إلاّ بِهِ يا مَنْ لا يُسْتَعانُ إلاّ بِهِ يا مَنْ لا يُتَوَكَّلُ إلاّ عَلَيْهِ يا مَنْ لا يُرْجى إلاّ هُوَ يا مَنْ لا يُعْبَدُ إلاّ هو (39) يا خَيْرَ الْمَرْهُوبينَ يا خَيْرَ الْمَرْغُوبينَ يا خَيْرَ الْمَطْلُوبينَ يا خَيْرَ الْمَسْؤولينَ يا خَيْرَ الْمَقْصُودينَ يا خَيْرَ الْمَذْكُورينَ يا خَيْرَ الْمَشْكُورينَ يا خَيْرَ الَْمحْبُوبينَ يا خَيْرَ الْمَدْعُوّينَ يا خَيْرَ الْمُسْتَأْنِسينَ (40) اَللّـهُمَّ اِنّي اَسْأَلُكَ بِاسْمِكَ يا غافِرُ يا ساتِرُ يا قادِرُ يا قاهِرُ يا فاطِرُ يا كاسِرُ يا جابِرُ يا ذاكِرُ يا ناظِرُ يا ناصِرُ (41) يا مَنْ خَلَقَ فَسَوّى يا مَنْ قَدَّرَ فَهَدى يا مَنْ يَكْشِفُ الْبَلْوى يا مَنْ يَسْمَعُ النَّجْوى يا مَنْ يُنْقِذُ الْغَرْقى يا مَنْ يُنْجِي الْهَلْكى يا مَنْ يَشْفِي الْمَرْضى يا مَنْ اَضْحَكَ وَاَبْكى يا مَنْ اَماتَ وَاَحْيى يا مَنْ خَلَقَ الزَّوْجَيْنِ الذَّكَرَ وَالاُْنْثى (42) يا مَنْ فيِ الْبَرِّ وَالْبَحْرِ سَبيلُهُ يا مَنْ فِي الاْفاقِ اياتُهُ يا مَنْ فِى الاْياتِ بُرْهانُهُ يا مَنْ فِي الْمَماتِ قُدْرَتُهُ يا مَنْ فِي الْقُبُورِ عِبْرَتُهُ يا مَنْ فِي الْقِيامَةِ مُلْكُهُ يا مَنْ فِي الْحِسابِ هَيْبَتُهُ يا مَنْ فِي الْميزانِ قَضاؤُهُ يا مَنْ فِي الْجَنَّةِ ثَوابُهُ يا مَنْ فِي النّارِ عِقابُهُ (43) يا مَنْ اِلَيْهِ يَهْرَبُ الْخائِفُونَ يا مَنْ اِلَيْهِ يَفْزَعُ الْمُذْنِبُونَ يا مَنْ اِلَيْهِ يَقْصِدُ الْمُنيبُونَ يا مَنْ اِلَيْهِ يَرْغَبُ الزّاهِدُونَ يا مَنْ اِلَيْهِ يَلْجَأُ الْمُتَحَيِّرُونَ يا مَنْ بِهِ يَسْتَأْنِسُ الْمُريدُونَ يا مَنْ بِه يَفْتَخِرُ الُْمحِبُّونَ يا مَنْ فى عَفْوِهِ يَطْمَعُ الْخاطِئُونَ يا مَنْ اِلَيْهِ يَسْكُنُ الْمُوقِنُونَ يا مَنْ عَلَيْهِ يَتَوَكَّلُ الْمُتَوَكِّلُونَ (44) اَللّـهُمَّ اِنّى اَسْأَلُكَ بِاسْمِكَ يا حَبيبُ يا طَبيبُ يا قَريبُ يا رَقيبُ يا حَسيبُ يا مُهيبُ يا مُثيبُ يا مُجيبُ يا خَبيرُ يا بَصيرُ (45) يا اَقَرَبَ مِنْ كُلِّ قَريب يا اَحَبَّ مِنْ كُلِّ حَبيب يا اَبْصَرَ مِنْ كُلِّ بَصير يا اَخْبَرَ مِنْ كُلِّ خَبير يا اَشْرَفَ مِنْ كُلِّ شَريف يا اَرْفَعَ مِنْ كُلِّ رَفيع يا اَقْوى مِنْ كُلِّ قَوِيٍّ يا اَغْنى مِنْ كُلِّ غَنِيٍّ يا اَجْوَدَ مِنْ كُلِّ جَواد يا اَرْاَفَ مِنْ كُلِّ رَؤوُف (46) يا غالِباً غَيْرَ مَغْلُوب يا صانِعاً غَيْرَ مَصْنُوع يا خالِقاً غَيْرَ مَخْلُوق يا مالِكاً غَيْرَ مَمْلُوك يا قاهِراً غَيْرَ مَقْهُور يا رافِعاً غَيْرَ مَرْفُوع يا حافِظاً غَيْرَ مَحْفُوظ يا ناصِراً غَيْرَ مَنْصُور يا شاهِداً غَيْرَ غائِب يا قَريباً غَيْرَ بَعيد (47) يا نُورَ النُّورِ يا مُنَوِّرَ النُّورِ يا خالِقَ النُّورِ يا مُدَبِّرَ النُّورِ يا مُقَدِّرَ النُّورِ يا نُورَ كُلِّ نُور يا نُوراً قَبْلَ كُلِّ نُور يا نُوراً بَعْدَ كُلِّ نُور يا نُوراً فَوْقَ كُلِّ نُور يا نُوراً لَيْسَ كَمِثْلِهِ نُورٌ (48) يا مَنْ عَطاؤُهُ شَريفٌ يا مَنْ فِعْلُهُ لَطيفٌ يا مَنْ لُطْفُهُ مُقيمٌ يا مَنْ اِحْسانُهُ قَديمٌ يا مَنْ قَوْلُهُ حَقٌّ يا مَنْ وَعْدُهُ صِدْقٌ يا مَنْ عَفْوُهُ فَضْلٌ يا مَنْ عَذابُهُ عَدْلٌ يا مَنْ ذِكْرُهُ حُلْوٌ يا مَنْ فَضْلُهُ عَميمٌ (49) اَللّـهُمَّ اِنّي اَسْأَلُكَ بِاسْمِكَ يا مُسَهِّلُ يا مُفَصِّلُ يا مُبَدِّلُ يا مُذَلِّلُ يا مُنَزِّلُ يا مُنَوِّلُ يا مُفْضِلُ يا مُجْزِلُ يا مُمْهِلُ يا مُجْمِلُ (50) يا مَنْ يَرى وَلا يُرى يا مَنْ يَخْلُقُ وَلا يُخْلَقُ يا مَنْ يَهْدى وَلا يُهْدى يا مَنْ يُحْيي وَلا يُحْيا يا مَنْ يَسْأَلُ وَلا يُسْأَلُ يا مَنْ يُطْعِمُ وَلا يُطْعَمُ يا مَنْ يُجيرُ وَلا يُجارُ عَلَيْهِ يا مَنْ يَقْضى وَلا يُقْضى عَلَيْهِ يا مَنْ يَحْكُمُ وَلا يُحْكَمُ عَلَيْهِ يا مَنْ لَمْ يَلِدْ وَلَمْ يُولَدْ وَلَمْ يَكُنْ لَهُ كُفُواً اَحَدٌ (51) يا نِعْمَ الْحَسيبُ يا نِعْمَ الطَّبيبُ يا نِعْمَ الرَّقيبُ يا نِعْمَ الْقَريبُ يا نِعْمَ الْمـٌجيبُ يا نِعْمَ الْحَبيبُ يا نِعْمَ الْكَفيلُ يا نِعْمَ الَوْكيلُ يا نِعْمَ الْمَوْلى يا نِعْمَ النَّصيرُ (52) يا سُرُورَ الْعارِفينَ يا مُنَى الُْمحِبّينَ يا اَنيسَ الْمُريدينَ يا حَبيبَ التَّوّابينَ يا رازِقَ الْمُقِلّينَ يا رَجاءَ الْمُذْنِبينَ يا قُرَّةَ عَيْنِ الْعابِدينَ يا مُنَفِّسُ عَنِ الْمَكْرُوبينَ يا مُفَرِّجُ عَنِ الْمَغْمُومينَ يا اِلـهَ الاَْوَّلينَ وَالاخِرينَ (53) اَللّـهُمَّ اِنّي اَسْأَلُكَ بِاسْمِكَ يا رَبَّنا يا اِلهَنا يا سَيِّدَنا يا مَوْلانا يا ناصِرَنا يا حافِظَنا يا دَليلَنا يا مُعينَنا يا حَبيبَنا يا طَبيبَنا (54) يا رَبَّ النَّبيّينَ وَالاَْبْرارِ يا رَبَّ الصِّدّيقينَ وَالاَْخْيارِ يا رَبَّ الْجَنَّةِ وَالنّارِ يا رَبَّ الصِّغارِ وَالْكِبارِ يا رَبَّ الْحُبُوبِ وَالِّثمارِ يا رَبَّ الاَْنْهارِ وَالاَْشْجارِ يا رَبَّ الصَّحارى وَالْقِفارِ يا رَبَّ الْبَراري وَالْبِحارِ يا رَبَّ اللَّيْلِ وَالنَّهارِ يا رَبَّ الاِْعْلانِ وَالاِْسْرارِ (55) يا مَنْ نَفَذَ في كُلِّ شَيْء اَمْرُهُ يا مَنْ لَحِقَ بِكُلِّ شَيْء عِلْمُهُ يا مَنْ بَلَغَتْ اِلى كُلِّ شَيْء قُدْرَتُهُ يا مَنْ لا تُحْصِى الْعِبادُ نِعَمَهُ يا مَنْ لا تَبْلُغُ الْخَلائِقُ شُكْرَهُ يا مَنْ لا تُدْرِكُ الاَْفْهامُ جَلالَهُ يا مَنْ لا تَنالُ الاَْوْهامُ كُنْهَهُ يا مَنِ الْعَظَمَةُ وَالْكِبْرِياءُ رِداؤُهُ يا مَنْ لا تَرُدُّ الْعِبادُ قَضاءَهُ يا مَنْ لا مُلْكَ إلاّ مُلْكُهُ يا مَنْ لا عَطاءَ إلاّ عَطاؤُهُ (56) يا مَنْ لَهُ الْمَثَلُ الاَْعْلى يا مَنْ لَهُ الصِّفاتُ الْعُلْيا يا مَنْ لَهُ الاْخِرَةُ وَالاُْولى يا مَنْ لَهُ الْجَنَّةُ الْمَاْوى يا مَنْ لَهُ الاياتُ الْكُبْرى يا مَنْ لَهُ الاَْسْماءُ الْحُسْنى يا مَنْ لَهُ الْحُكْمُ وَالْقَضاءُ يا مَنْ لَهُ الْهَواءُ وَالْفَضاءُ يا مَنْ لَهُ الْعَرْشُ وَالثَّرى يا مَنْ لَهُ السَّماواتُ الْعُلى (57) اَللّـهُمَّ اِنّي اَسْأَلُكَ بِاسْمِكَ يا عَفُوُّ يا غَفُورُ يا صَبُورُ يا شَكُورُ يا رَؤوفُ يا عَطُوفُ يا مَسْؤولُ يا وَدُودُ يا سُبُّوحُ يا قُدُّوسُ (58) يا مَنْ فِي السَّماءِ عَظَمَتُهُ يا مَنْ فِي الاَْرْضِ آياتُهُ يا مَنْ في كُلِّ شَيْء دَلائِلُهُ يا مَنْ فِي الْبِحارِ عَجائِبُهُ يا مَنْ فِي الْجِبالِ خَزائِنُهُ يا مَنْ يَبْدَأُ الْخَلْقَ ثُمَّ يُعيدُهُ يا مَنْ اِلَيْهِ يَرْجِـعُ الاَْمْرُ كُلُّهُ يا مَنْ اَظْهَرَ فى كُلِّ شَيْء لُطْفَهُ يا مَنْ اَحْسَنَ كُلَّ شَيْء خَلْقَهُ يا مَنْ تَصَرَّفَ فِي الْخَلائِقِ قُدْرَتُهُ (59) يا حَبيبَ مَنْ لا حَبيبَ لَهُ يا طَبيبَ مَنْ لا طَبيبَ لَهُ يا مُجيبَ مَنْ لا مُجيبَ لَهُ يا شَفيقَ مَنْ لا شَفيقَ لَهُ يا رَفيقَ مَنْ لا رَفيقَ لَهُ يا مُغيثَ مَن لا مُغيثَ لَهُ يا دَليلَ مَنْ لا دَليلَ لَهُ يا اَنيسَ مَنْ لا اَنيسَ لَهُ يا راحِمَ مَنْ لا راحِمَ لَهُ يا صاحِبَ مَنْ لا صاحِبَ لَهُ (60) يا كافِيَ مَنِ اسْتَكْفاهُ يا هادِيَ مَنِ اسْتَهْداهُ يا كالِىءَ مَنِ اسْتَكْلاهُ يا راعِيَ مَنِ اسْتَرْعاهُ يا شافِيَ مَنِ اسْتَشْفاهُ يا قاضِيَ مَنِ اسْتَقْضاهُ يا مُغْنِيَ مَنِ اسْتَغْناهُ يا مُوفِيَ مَنِ اسْتَوْفاهُ يا مُقَوِّيَ مَنِ اسْتَقْواهُ يا وَلِيَّ مَنِ اسْتَوْلاهُ (61) اَللّـهُمَّ اِنّي اَسْأَلُكَ بِاسْمِكَ يا خالِقُ يا رازِقُ يا ناطِقُ يا صادِقُ يا فالِقُ يا فارِقُ يا فاتِقُ يا راتِقُ يا سابِقُ يا سامِقُ (62) يا مَنْ يُقَلِّبُ اللَّيْلَ وَالنَّهارَ يا مَنْ جَعَلَ الظُّلُماتِ وَالاَْنْوارَ يا مَنْ خَلَقَ الظِّلَّ وَالْحَرُورَ يا مَنْ سَخَّرَ الشَّمْسَ وَالْقَمَرَ يا مَنْ قَدَّرَ الْخَيْرَ وَالشَّرَّ يا مَنْ خَلَقَ الْمَوْتَ وَالْحَياةَ يا مَنْ لَهُ الْخَلْقُ وَالاَْمْرُ يا مَنْ لَمْ يَتَّخِذْ صاحِبَةً وَلا وَلَداً يا مَنْ لَيْسَ لَهُ شَريكٌ فِى الْمُلْكِ يا مَنْ لَمْ يَكُنْ لَهُ وَلِيٌّ مِنَ الذُّلِّ (63) يا مَنْ يَعْلَمُ مُرادَ الْمُريدينَ يا مَنْ يَعْلَمُ ضَميرَ الصّامِتينَ يا مَنْ يَسْمَعُ اَنينَ الْواهِنينَ يا مَنْ يَرى بُكاءَ الْخائِفينَ يا مَنْ يَمْلِكُ حَوائِجَ السّائِلينَ يا مَنْ يَقْبَلُ عُذْرَ التّائِبينَ يا مَنْ لا يُصْلِحُ عَمَلَ الْمُفْسِدينَ يا مَنْ لا يُضيعُ اَجْرَ الْمـٌحْسِنينَ يا مَنْ لا يَبْعُدُ عَنْ قُلُوبِ الْعارِفينَ يا اَجْوَدَ الاَْجْودينَ (64) يا دائِمَ الْبَقاءِ يا سامِعَ الدُّعاءِ يا واسِعَ الْعَطاءِ يا غافِرَ الْخَطاءِ يا بَديعَ السَّماءِ يا حَسَنَ الْبَلاءِ يا جَميلَ الثَّناءِ يا قَديمَ السَّناءِ يا كَثيرَ الْوَفاءِ يا شَريفَ الْجَزاءِ (65) اَللّـهُمَّ اِنّي اَسْأَلُكَ بِاسْمِكَ يا سَتّارُ يا غَفّارُ يا قَهّارُ يا جَبّارُ يا صَبّارُ يا بارُّ يا مُخْتارُ يا فَتّاحُ يا نَفّاحُ يا مُرْتاحُ (66) يا مَنْ خَلَقَنى وَسَوّاني يا مَنْ رَزَقَني وَرَبّاني يا مَنْ اَطْعَمَنى وَسَقانى يا مَنْ قَرَّبَنى وَ اَدْنانى يا مَنْ عَصَمَنى وَكَفانى يا مَنْ حَفِظَني وَكَلانى يا مَنْ اَعَزَّنى وَاَغْنانى يا مَنْ وَفَّقَنى وَهَدانى يا مَنْ آنَسَنى وَآوَانى يا مَنْ اَماتَنى وَاَحْيانى (67) يا مَنْ يُحِقُّ الْحَقَّ بِكَلِماتِهِ يا مَنْ يَقْبَلُ التَّوْبَةَ عَنْ عِبادِهِ يا مَنْ يَحُولُ بَيْنَ الْمَرْءِ وَقَلْبِهِ يا مَنْ لا تَنْفَعُ الشَّفاعَةُ إلاّ بِاِذْنِهِ يا مَنْ هُوَ اَعْلَمُ بِمَنْ ضَلَّ عَنْ سَبيلِهِ يا مَنْ لا مُعَقِّبَ لِحُكْمِهِ يا مَنْ لا رادَّ لِقَضائِهِ يا مَنِ انْقادَ كُلُّ شَيْء لاَِمْرِهِ يا مَنِ السَّماواتُ مَطْوِيّاتٌ بِيَمينِهِ يا مَنْ يُرْسِلُ الرِّياحَ بُشْراً بَيْنَ يَدَيْ رَحْمَتِهِ (68) يا مَنْ جَعَلَ الاَْرْضَ مِهاداً يا مَنْ جَعَلَ الْجِبالَ اَوْتاداً يا مَنْ جَعَلَ الشَّمْسَ سِراجاً يا مَنْ جَعَلَ الْقَمَرَ نُوراً يا مَنْ جَعَلَ اللَّيْلَ لِباساً يا مَنْ جَعَلَ النَّهارَ مَعاشاً يا مَنْ جَعَلَ النَّوْمَ سُباتاً يا مَنْ جَعَلَ السَّمآءَ بِناءً يا مَنْ جَعَلَ الاَْشْياءَ اَزْواجاً يا مَنْ جَعَلَ النّارَ مِرْصاداً (69) اَللّـهُمَّ اِنّي اَسْأَلُكَ بِاسْمِكَ يا سَميعُ يا شَفيعُ يا رَفيعُ يا مَنيعُ يا سَريعُ يا بَديعُ يا كَبيرُ يا قَديرُ يا خَبيرُ يا مُجيرُ (70) يا حَيّاً قَبْلَ كُلِّ حَيٍّ يا حَيّاً بَعْدَ كُلِّ حَيٍّ يا حَيُّ الَّذي لَيْسَ كَمِثْلِهِ حَيٌّ يا حَيُّ الَّذي لا يُشارِكُهُ حَيٌّ يا حَيُّ الَّذى لا يَحْتاجُ اِلى حَيٍّ يا حَيُّ الَّذى يُميتُ كُلَّ حَيٍّ يا حَيُّ الَّذى يَرْزُقُ كُلَّ حَيٍّ يا حَيّاً لَمْ يَرِثِ الْحَياةَ مِنْ حَيٍّ يا حَيُّ الَّذى يُحْيِي الْمَوْتى يا حَيُّ يا قَيُّومُ لا تَأخُذُهُ سِنَةٌ وَلا نَوْمٌ (71) يا مَنْ لَهُ ذِكْرٌ لا يُنْسى يا مَنْ لَهُ نُورٌ لا يُطْفى يا مَنْ لَهُ نِعَمٌ لا تُعَدُّ يا مَنْ لَهُ مُلْكٌ لا يَزُولُ يا مَنْ لَهُ ثَناءٌ لا يُحْصى يا مَنْ لَهُ جَلالٌ لا يُكَيَّفُ يا مَنْ لَهُ كَمالٌ لا يُدْرَكُ يا مَنْ لَهُ قَضاءٌ لا يُرَدُّ يا مَنْ لَهُ صِفاتٌ لا تُبَدَّلُ يا مَنْ لَهُ نُعُوتٌ لا تُغَيَّرُ (72)يا رَبَّ الْعالَمينَ يا مالِكَ يَوْمِ الدّينِ يا غايَةَ الطّالِبينَ يا ظَهْرَ اللاّجينَ يا مُدْرِكَ الْهارِبينَ يا مَنْ يُحِبُّ الصّابِرينَ يا مَنْ يُحِبُّ التَّوّابينَ يا مَنْ يُحِبُّ الْمُتَطَهِّرينَ يا مَنْ يُحِبُّ الُْمحْسِنينَ يا مَنْ هُوَ اَعْلَمُ بِالْمُهْتَدينَ (73)اَللّـهُمَّ اِنّى اَسْأَلُكَ بِاسْمِكَ يا شَفيقُ يا رَفيقُ يا حَفيظُ يا مُحيطُ يا مُقيتُ يا مُغيثُ يا مُعِزُّ يا مُذِلُّ يا مُبْدِئُ يا مُعيدُ (74)يا مَنْ هُوَ اَحَدٌ بِلا ضِدٍّ يا مَنْ هُوَ فَرْدٌ بِلا نِدٍّ يا مَنْ هُوَ صَمَدٌ بِلا عَيْب يا مَنْ هُوَ وِتْرٌ بِلا كَيْف يا مَنْ هُوَ قاض بِلا حَيْف يا مَنْ هُوَ رَبٌّ بِلا وَزير يا مَنْ هُوَ عَزيزٌ بِلا ذُلٍّ يا مَنْ هُوَ غَنِيٌّ بِلا فَقْر يا مَنْ هُوَ مَلِكٌ بِلا عَزْل يا مَنْ هُوَ مَوْصُوفٌ بِلا شَبيه (75) يا مَنْ ذِكْرُهُ شَرَفٌ لِلذّاكِرينَ يا مَنْ شُكْرُهُ فَوْزٌ لِلشّاكِرينَ يا مَنْ حَمْدُهُ عِزٌّ لِلْحامِدينَ يا مَنْ طاعَتُهُ نَجاةٌ لِلْمُطيعينَ يا مَنْ بابُهُ مَفْتُوحٌ لِلطّالِبينَ يا مَنْ سَبيلُهُ واضِحٌ لِلْمُنيبينَ يا مَنْ آياتُهُ بُرْهانٌ لِلنّاظِرينَ يا مَنْ كِتابُهُ تَذْكِرَةٌ لِلْمُتَّقينَ يا مَنْ رِزْقُهُ عُمُومٌ لِلطّائِعينَ وَالْعاصينَ يا مَنْ رَحْمَتُهُ قَريبٌ مِنَ الْمحْسِنينَ (76) يا مَنْ تَبارَكَ اسْمُهُ يا مَنْ تَعالى جَدُّهُ يا مَنْ لا اِلـهَ غَيْرُهُ يا مَنْ جَلَّ ثَناؤُهُ يا مَنْ تَقَدَّسَتَ اَسْماؤُهُ يا مَنْ يَدُومُ بَقاؤُهُ يا مَنِ الْعَظَمَةُ بَهاؤُهُ يا مَنِ الْكِبْرِياءُ رِداؤُهُ يا مَنْ لا تُحْصى الاؤُهُ يا مَنْ لا تُعَدُّ نَعْماؤُهُ (77) اَللّـهُمَّ اِنّي اَسْأَلُكَ بِاسْمِكَ يا مُعينُ يا اَمينُ يا مُبينُ يا مَتينُ يا مَكينُ يا رَشيدُ يا حَميدُ يا مَجيدُ يا شَديدُ يا شَهيدُ (78) يا ذَا الْعَرْشِ الَْمجيدِ يا ذَا الْقَوْلِ السَّديدِ يا ذَا الْفِعْلِ الرَّشيدِ يا ذَا الْبَطْشِ الشَّديدِ يا ذَا الْوَعْدِ وَالْوَعيدِ يا مَنْ هُوَ الْوَلِيُّ الْحَميدُ يا مَنْ هُوَ فَعّالٌ لِما يُريدُ يا مَنْ هُوَ قَريبٌ غَيْرُ بَعيد يا مَنْ هُوَ عَلى كُلِّ شَيْء شَهيدٌ يا مَنْ هُوَ لَيْسَ بِظَلاّم لِلْعَبيدِ (79) يا مَنْ لا شَريكَ لَهُ وَلا وَزيرَ يا مَنْ لا شَبيهَ لَهُ وَلا نَظيرَ يا خالِقَ الشَّمْسِ وَالْقَمَرِ الْمُنيرِ يا مُغْنِيَ الْبائِسِ الْفَقيرِ يا رازِقَ الْطِّفْلِ الصَّغيرِ يا راحِمَ الشَّيْخِ الْكَبيرِ يا جابِرَ الْعَظْمِ الْكَسيرِ يا عِصْمَةَ الْخآئِفِ الْمُسْتَجيرِ يا مَنْ هُوَ بِعِبادِهِ خَبيرٌ بَصيرٌ يا مَنْ هُوَ عَلى كُلِّ شَيْء قَديرٌ (80) يا ذَا الْجُودِ وَالنِّعَمِ يا ذَا الْفَضْلِ وَالْكَرَمِ يا خالِقَ اللَّوْحِ وَالْقَلَمِ يا بارِئَ الذَّرِّ وَالنَّسَمِ يا ذَا الْبَأْسِ وَالنِّقَمِ يا مُلْهِمَ الْعَرَبِ وَالْعَجَمِ يا كاشِفَ الضُّرِّ وَالاَْلَمِ يا عالِمَ السِّرِّ وَالْهِمَمِ يا رَبَّ الْبَيْتِ وَالْحَرَمِ يا مَنْ خَلَقَ الاَْشياءَ مِنَ الْعَدَمِ (81) اَللّـهُمَّ اِنّي اَسْأَلُكَ بِاسْمِكَ يا فاعِلُ يا جاعِلُ يا قابِلُ يا كامِلُ يا فاصِلُ يا واصِلُ يا عادِلُ يا غالِبُ يا طالِبُ يا واهِبُ (82) يا مَنْ اَنْعَمَ بِطَوْلِهِ يا مَنْ اَكْرَمَ بِجُودِهِ يا مَنْ جادَ بِلُطْفِهِ يا مَنْ تَعَزَّزَ بِقُدْرَتِهِ يا مَنْ قَدَّرَ بِحِكْمَتِهِ يا مَنْ حَكَمَ بِتَدْبيرِهِ يا مَنْ دَبَّرَ بِعِلْمِهِ يا مَنْ تَجاوَزَ بِحِلْمِهِ يا مَنْ دَنا في عُلُوِّهِ يا مَنْ عَلا في دُنُوِّهِ (83) يا مَنْ يَخْلُقُ ما يَشاءُ يا مَنْ يَفْعَلُ ما يَشاءُ يا مَنْ يَهْدي مَنْ يَشاءُ يا مَنْ يُضِلُّ مَنْ يَشاءُ يا مَنْ يُعَذِّبُ مَنْ يَشاءُ يا مَنْ يَغْفِرُ لِمَنْ يَشآءُ يا مَنْ يُعِزُّ مَنْ يَشاءِ يا مَنْ يُذِلُّ مَنْ يَشاءُ يا مَنْ يُصَوِّرُ فِي الاَْرْحامِ ما يَشاءُ يا مَنْ يَخْتَصُّ بِرَحْمَتِهِ مَنْ يَشاءُ (84) يا مَنْ لَمْ يَتَّخِذْ صاحِبَةً وَلا وَلَداً يا مَنْ جَعَلَ لِكُلِّ شَيْء قَدْراً يا مَنْ لا يُشْرِكُ في حُكْمِهِ اَحَداً يا مَنْ جَعَلَ الْمَلائِكَةَ رُسُلاً يا مَنْ جَعَلَ فِي السَّماءِ بُرُوجاً يا مَنْ جَعَلَ الاَْرْضَ قَراراً يا مَنْ خَلَقَ مِنَ الْماءِ بَشَراً يا مَنْ جَعَلَ لِكُلِّ شَيْء اَمَداً يا مَنْ اَحاطَ بِكُلِّ شَيْء عِلْماً يا مَنْ اَحْصى كُلَّ شَيْء عَدَداً (85) اَللّـهُمَّ اِنّي اَسْأَلُكَ بِاسْمِكَ يا اَوَّلُ يا اخِرُ يا ظاهِرُ يا باطِنُ يا بَرُّ يا حَقُّ يا فَرْدُ يا وِتْرُ يا صَمَدُ يا سَرْمَدُ (86) يا خَيْرَ مَعْرُوف عُرِفَ يا اَفْضَلَ مَعْبُود عُبِدَ يا اَجَلَّ مَشْكُور شُكِرَ يا اَعَزَّ مَذْكُور ذُكِرَ يا اَعْلى مَحْمُود حُمِدَ يا اَقْدَمَ مَوْجُود طُلِبَ يا اَرْفَعَ مَوْصُوف وُصِفَ يا اَكْبَرَ مَقْصُود قُصِدَ يا اَكْرَمَ مَسْؤول سُئِلَ يا اَشْرَفَ مَحْبُوب عُلِمَ (87) يا حَبيبَ الْباكينَ يا سَيِّدَ الْمُتَوَكِّلينَ يا هادِيَ الْمُضِلّينَ يا وَلِيَّ الْمُؤْمِنينَ يا اَنيسَ الذّاكِرينَ يا مَفْزَعَ الْمَلْهُوفينَ يا مُنْجِيَ الصّادِقينَ يا اَقْدَرَ الْقادِرينَ يا اَعْلَمَ الْعالِمينَ يا اِلـهَ الْخَلْقِ اَجْمَعينَ (88) يا مَنْ عَلا فَقَهَرَ يا مَنْ مَلَكَ فَقَدَرَ يا مَنْ بَطَنَ فَخَبَرَ يا مَنْ عُبِدَ فَشَكَرَ يا مَنْ عُصِيَ فَغَفَرَ يا مَنْ لا تَحْويهِ الْفِكَرُ يا مَنْ لا يُدْرِكُهُ بَصَرٌ يا مَنْ لا يَخْفى عَلَيْهِ اَثَرٌ يا رازِقَ الْبَشَرِ يا مُقَدِّرَ كُلِّ قَدَر (89) اَللّـهُمَّ اِنّي اَسْأَلُكَ بِاسْمِكَ يا حافِظُ يا بارِئُ يا ذارِئُ يا باذِخُ يا فارِجُ يا فاتِحُ يا كاشِفُ يا ضامِنُ يا امِرُ يا ناهي (90) يا مَنْ لا يَعْلَمُ الْغَيْبَ إلاّ هُوَ يا مَنْ لا يَصْرِفُ السُّوءَ إلاّ هُوَ يا مَنْ لا يَخْلُقُ الْخَلْقَ إلاّ هُوَ يا مَنْ لا يَغْفِرُ الذَّنْبَ إلاّ هُوَ يا مَنْ لا يُتِمُّ النِّعْمَةَ إلاّ هُوَ يا مَنْ لا يُقَلِّبُ الْقُلُوبَ إلاّ هُوَ يا مَنْ لا يُدَبِّرُ الاَْمْرَ إلاّ هُوَ يا مَنْ لا يُنَزِّلُ الْغَيْثَ إلاّ هُوَ يا مَنْ لا يَبْسُطُ الرِّزْقَ إلاّ هُوَ يا مَنْ لا يُحْيِي الْمَوْتى إلاّ هُوَ (91) يا مُعينَ الْضُعَفاءِ يا صاحِبَ الْغُرَباءِ يا ناصِرَ الاَْوْلِياءِ يا قاهِرَ الاَْعْداءِ يا رافِعَ السَّماءِ يا اَنيسَ الاَْصْفِياءِ يا حَبيبَ الاَْتْقِياءِ يا كَنْزَ الْفُقَراءِ يا اِلـهَ الاَْغْنِياءِ يا اَكْرَمَ الْكُرَماءِ (92) يا كافِياً مِنْ كُلِّ شَيْء يا قائِماً عَلى كُلِّ شَيْء يا مَنْ لا يُشْبِهُهُ شَيْءٌ يا مَنْ لا يَزيدُ في مُلْكِهِ شَيْءٌ يا مَنْ لا يَخْفى عَلَيْهِ شَيْءٌ يا مَنْ لا يَنْقُصُ مِنْ خَزائِنِهِ شَيْءٌ يا مَنْ لَيْسَ كَمِثْلِهِ شَيْءٌ يا مَنْ لا يَعْزُبُ عَنْ عِلْمِهِ شَيءٌ يا مَنْ هُوَ خَبيرٌ بِكُلِّ شَيْء يا مَنْ وَسِعَتْ رَحْمَتُهُ كُلَّ شَيْء (93) اَللّـهُمَّ اِنّي اَسْئَلُكَ بِاسْمِكَ يا مُكْرِمُ يا مُطْعِمُ يا مُنْعِمُ يا مُعْطى يا مُغْني يا مُقْني يا مُفْني يا مُحْيي يا مُرْضي يا مُنْجي (94) يا اَوَّلَ كُلِّ شَيْء وَآخِرَهُ يا اِلـهَ كُلِّ شَيْء وَمَليكَهُ يا رَبَّ كُلِّ شَيْء وَصانِعَهُ يا بارِئَ كُلِّ شَيْء وَخالِقَهُ يا قابِضَ كُلِّ شَيْء وَباسِطَهُ يا مُبْدِئَ كُلِّ شَيْء وَمُعيدَهُ يا مُنْشِئَ كُلِّ شَيْء وَمُقَدِّرَهُ يا مُكَوِّنَ كُلِّ شَيْء وَمُحَوِّلَهُ يا مُحْيِيَ كُلِّ شَيْء وَمُميتَهُ يا خالِقَ كُلِّ شَيْء وَوارِثَهُ (95) يا خَيْرَ ذاكِر وَمَذْكُور يا خَيْرَ شاكِر وَمَشْكُور يا خَيْرَ حامِد وَمَحْمُود يا خَيْرَ شاهِد وَمَشْهُود يا خَيْرَ داع وَمَدْعُوٍّ يا خَيْرَ مُجيب وَمُجاب يا خَيْرَ مُؤنِس وَاَنيس يا خَيْرَ صاحِب وَجَليس يا خَيْرَ مَقْصُود وَمَطْلُوب يا خَيْرَ حَبيب وَمَحْبُوب (96) يا مَنْ هُوَ لِمَنْ دَعاهُ مُجيبٌ يا مَنْ هُوَ لِمَنْ اَطاعَهُ حَبيبٌ يا مَنْ هُوَ اِلى مَنْ اَحَبَّهُ قَريبٌ يا مَنْ هُوَ بِمَنِ اسْتَحْفَظَهُ رَقيبٌ يا مَنْ هُوَ بِمَنْ رَجاهُ كَريمٌ يا مَنْ هُوَ بِمَنْ عَصاهُ حَليمٌ يا مَنْ هُوَ في عَظَمَتِهِ رَحيمٌ يا مَنْ هُوَ في حِكْمَتِهِ عَظيمٌ يا مَنْ هُوَ في اِحْسانِهِ قَديمٌ يا مَنْ هُوَ بِمَنْ اَرادَهُ عَليمٌ (97) اَللّـهُمَّ اِنّي اَسْأَلُكَ بِاسْمِكَ يا مُسَبِّبُ يا مُرَغِّبُ يا مُقَلِّبُ يا مُعَقِّبُ يا مُرَتِّبُ يا مُخَوِّفُ يا مُحَذِّرُ يا مُذَكِّرُ يا مُسَخِّرُ يا مُغَيِّرُ (98) يا مَنْ عِلْمُهُ سابِقٌ يا مَنْ وَعْدُهُ صادِقٌ يا مَنْ لُطْفُهُ ظاهِرٌ يا مَنْ اَمْرُهُ غالِبٌ يا مَنْ كِتابُهُ مُحْكَمٌ يا مَنْ قَضاؤُهُ كأئِنٌ يا مَنْ قُرْانُهُ مَجيدٌ يا مَنْ مُلْكُهُ قَديمٌ يا مَنْ فَضْلُهُ عَميمٌ يا مَنْ عَرْشُهُ عَظيمٌ (99) يا مَنْ لا يَشْغَلُهُ سَمْعٌ عَنْ سَمْع يا مَنْ لا يَمْنَعُهُ فِعْلٌ عَنْ فِعْل يا مَنْ لا يُلْهيهِ قَوْلٌ عَنْ قَوْل يا مَنْ لا يُغَلِّطُهُ سُؤالٌ عَنْ سُؤال يا مَنْ لا يَحْجُبُهُ شَيْءٌ عَنْ شَيْء يا مَنْ لا يُبْرِمُهُ اِلْحاحُ الْمُلِحّينَ يا مَنْ هُوَ غايَةُ مُرادِ الْمُريدينَ يا مَنْ هُوَ مُنْتَهى هِمَمِ الْعارِفينَ يا مَنْ هُوَ مُنْتَهى طَلَبِ الطّالِبينَ يا مَنْ لا يَخْفى عَلَيْهِ ذَرَّةٌ فِي الْعالَمينَ (100) يا حَليماً لا يَعْجَلُ يا جَواداً لا يَبْخَلُ يا صادِقاً لا يُخْلِفُ يا وَهّاباً لا يَمَلُّ يا قاهِراً لا يُغْلَبُ يا عَظيماً لا يُوصَفُ يا عَدْلاً لا يَحيفُ يا غَنِيّاً لا يَفْتَقِرُ يا كَبيراً لا يَصْغُرُ يا حافِظاً لا يَغْفُلُ سُبْحانَكَ يا لا اِلـهَ إلاّ اَنْتَ الْغَوْثَ الْغَوْثَ خَلِّصْنا مِنَ النّارِ يا رَبِّ ."},{"type":"Text","content":"دُعـاءُ الجْوشَنِّ الّصَغيـر"},{"type":"Text","content":"وَقد ذكر لهـذا الدّعـاء في الكتب المُعتبرة شرح اطولُ وفضل أكثر مِمّا ذكر لدعـاءِ الجوشن الكبير، وقالَ الكفعمي في هـامش كتاب البلد الامين : هذا دُعاء رفيع الشّأن عظيم المنزلة دعا به الكاظم (عليه السلام) وقد همّ موسى الهـادي العبّاسي بقتله فَرَأى (عليه السلام) جدّه النّبي (صلى الله عليه وآله وسلم) في المنـام فأخبره بأنّ الله تعالى سَيقضى على عَدوّه، وأورد السّيّد ابن طاووس هذا الدّعاء في كتاب مهَج الدّعوات وتختلف نسختا الدّعاءِ عَن بعضَهما ونحنُ نأتي به طبقاً لكتاب البَلَد الامين للكفعمي(قدس سره) وهوُ هـذا الدّعاء :"},{"type":"Text","content":"اِلـهي كُمْ مِنْ عَدُو انْتَضى عَلَيَّ سَيفَ عَداوَتِهِ وَشَحَذَ لي ظُبَةَ مُدْيَتِهِ، وَاَرْهَفَ لي شَبا حَدِّهِ، وَدافَ لى قَواتِلَ سمُوُمِهِ، وَسَدَّدَ اِلَيَّ (نَحْوي) صَوائِبَ سِهامِهِ وَلَمْ تَنَمْ عَنّي عَيْنُ حِراسَتِهِ، وَاَضْمَرَ اَنْ يَسوْمَنيَ الْمَكْرٌوْهَ وَيُجَرِّعَني ذُعافَ مَرارَتِهِ نَظَرْتَ (فَنَظَرْتَ) اِلى ضَعْفى عَنِ احتِمالِ الْفَوادِحِ وَعَجْزي عَنِ الاْنْتِصارِ مِمَّنْ قَصَدني بِمُحارَبَتِهِ وَوَحْدَتي في كَثير مِمَّنْ ناوانى واَرْصَدَ لى فيـما لَمْ اُعْمِلْ فِكْري في الاْرْصادِ لَهُمْ بِمِثْلِهِ، فَاَيَّدْتَنى بِقُوَّتِكَ وَشَدَدْتَ اَزْري بِنُصْرَتِكَ وفَلَلْتَ لي حَدَّهُ (شَبا حَدِّهِ) وَخَذَلْتَهُ بَعْدَ جَمْعِ عَديدِهِ وَحَشْدِهِ واَعْلَيْتَ كَعْبى عَلَيْهِ وَوَجَّهْتَ ما سَدَّدَ اِلَيَّ مِنْ مَكائِدِهِ اِلَيْهِ، وَرَدَدْتَهُ عَلَيْهِ وَلَمْ يَشْفِ غَليلَهُ وَلَمْ تَبْرُدْ حَزازاتُ غَيْظِهِ وَقَدْ عَضَّ عَلَيَّ اَنامِلِهِ وَاَدْبَرَ مُوَلِّياً قَدْ اَخْفَقَتْ سَراياهُ، فَلَكَ الْحَمْدُ يا رَبِّ مِنْ مُقْتَدِر لا يُغْلَبُ وَذي اَناة لا يَعْجَلُ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاجْعَلْني لِنَعْمائِكَ مِنَ الشّاكِرينَ وَلالائِكَ مِنَ الذّاكِرينَ، اِلهِي وَكَمْ مِنْ باغ بَغاني بِمَكائِدِهِ وَنَصَبَ لي اَشْراكَ مَصايِدِهِ وَوَكَّلَ بى تَفَقُّدَ رِعايَتِهِ، واَضبَأَ اِلَيَّ اِضْباءَ السَّبُعِ لِطَريدَتِهِ انْتِظاراً لاِنْتِهازِ فُرْصَتِهِ وَهُوَ يُظْهِرُ بَشاشَةَ الْمَلَقِ، وَيَبْسُطُ (لى) وَجْهاً غَيْرَ طَلِق، فَلَمّا رَاَيْتَ دَغَلَ سَريرَتِهِ وَقُبْحَ مَا انْطَوى عَلَيْهِ لِشَريكِهِ فى مِلّتِهِ واَصْبَحَ مُجْلِباً لي (اِلَيَّ) في بَغْيِهِ اَرْكَسْتَهُ لاُمِّ رَأسِهِ واَتَيْتَ بُنْيانَهُ مِنْ اَساسِهِ فَصَرَعْتَهُ فى زُبْيَتِهِ وَرَدَّيْتَهُ (اَرْدَيْتَهُ) فى مَهْوى حُفْرَتِهِ وَجَعَلْتَ خَدَّهُ طَبَقاً لِتُرابِ رِجْلِهِ وَشَغَلْتَهُ فى بَدَنِهِ وَرِزْقِهِ وَرَمَيْتَهُ بِحَجَرِهِ وَخَنَقْتَهُ بِوَتَرِهِ وَذَكَّيْتَهُ بِمَشاقِصِهِ وَكَبَبْتَهُ لِمَنْخَرِهِ وَرَدَدْتَ كَيْدَهُ في نَحْرِهِ وَرَبَقْتَهُ (وَوَثَقْتَهُ) بِنَدامَتِهِ وَفَسَأتَهُ (اَفْنَيْتَهُ) بِحَسْرَتِهِ فَاسْتَخْذَأ وَتَضآءَلَ بَعْدَ نَخْوَتِهِ وانْقَمَعَ بَعْدَ اْستِطالَتِهِ ذَليلاً مَأسُوراً في رِبْقِ حِبالَتِهِ (حَبائِلِهِ) الَّتي كانَ يُؤَمِّلُ اَنْ يَرانى فيها يَوْمَ سَطْوَتِهِ، وَقَدْ كِدْتُ يا رَبِّ لَوْلا رَحْمَتُكَ اَنْ يَحُلَّ بي ما حَلَّ بِساحَتِهِ فَلَكَ الْحَمْدُ يا رَبِّ مِنْ مُقْتَدِر لا يُغْلَبُ وَذى اَناة لا يَعْجَلُ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاجْعَلنى لِنَعْمآئِكَ مِنَ الشّاكِرينَ ولاِلائِكَ مِنَ الذّاكِرينَ، اِلـهى وَكَمْ مِنْ حاسِد شَرِقَ بِحَسْرَتِهِ (بِحَسَدِهِ) وَعَدُوٍّ شَجِىَ بِغَيْظِهِ وَسَلَقَنى بِحَدِّ لِسانِهِ، وَوَخَزَنى بِمُوقِ عَيْنِهِ وَجَعَلَنى (وَجَعَلَ) غَرَضاً لِمراميهِ، وَقَلَّدَنى خِلالاً لَمْ تَزَلْ فِيهِ، نادَيْتُكَ (فَنادَيْتُ) يا رَبِّ مُسْتَجيراً بِكَ واثِقاً بِسُرْعَةِ اِجابَتِكَ مُتَوَكِّلاً عَلى ما لَمْ اَزَلْ اَتَعرَّفُهُ مِنْ حُسْنِ دِفاعِكَ عالِماً اَنَّهُ لا يُضْطَهَدُ مَنْ اَوى اِلى ظِلِّ كَنَفِكَ وَلَنْ تَقْرَعَ الْحَوادِثُ (الْفَوادِحُ) مَنْ لَجَاَ اِلى مَعْقِلِ الاِْنْتِصارِ بِكَ فَحَصَّنْتَنى مَنْ بأسِهِ بِقُدْرَتِكَ فَلَكَ الْحْمدُ يـا رَبِّ مِنْ مُقْتَدِر لا يُغْلَبُ وَذي اَناة لا يَعْجَلُ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد واجْعَلْني لِنَعْمـائِكَ مِنَ الشّاكِرينَ وَلاِلائِكَ مِنَ الذّاكِرينَ، اِلـهى وَكَمْ مِنْ سَحائِبِ مَكْروه جَلَّيْتَها وسَمـاءِ نِعْمَة مَطَرْتَها (اَمْطَرْتَها) وَجَداوِلِ كَرامَة اَجْرَيْتَها واَعْيُنِ اَحْداث طَمَسْتَها وناشِئَةِ رَحْمَة نَشَرْتَهَا وَجُنَّةِ عافِيَة اَلْبَسْتَها وَغَوامِرِ كُرُبات كَشَفْتَها واُمُور جارِيَة قَدَّرْتَها، لَمْ تُعْجِزْكَ اِذْ طَلَبْتَها وَلَمْ تَمْتَنِعْ مِنْكَ اِذْ اَرَدْتَهَا، فَلَكَ الْحَمْدُ يـا رَبِّ مِنْ مُقْتَدِر لا يُغْلَبُ وَذي اَناة لا تَعْجَلُ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاْجَعْلنى لِنَعْمآئِكَ مِنَ الشّاكِرينَ وَلاِلائِكَ مِنَ الذّاكِرينَ اِلـهي وكَمْ مِنْ ظَنٍّ حَسَن حَقَّقْتَ وَمِنْ كَسْرِ اِمْلاق جَبَرْتَ وَمِنْ مَسْكَنَة فادِحَة حَوَّلْتَ وَمِنْ صَرْعَة مُهْلِكَة نَعَشْتَ (اَنْعَشْتَ) وَمِنْ مَشَقَّة اَرَحْتَ، لا تُسْأَلُ (يا سَيِّدي) عَمّا تَفْعَلُ وَهُمْ يُسْأَلُونَ وَلا يَنْقُصُكَ ما اَنْفَقْتَ وَلَقَدْ سُئِلْتَ فَاَعْطَيْتَ وَلَمْ تُسْأَلْ فاَبْتَدَأتَ وَاسْتُميحَ بابُ فَضْلِكَ فَما اَكْدَيْتَ، اَبَيْتَ إلاّ اِنْعاماً وَاْمِتناناً وإلاّ تَطَوُّلاً يا رَبِّ وَاِحْساناً، واَبَيْتُ (يا رَبِّ) إلاّ اْنتِهاكاً لِحُرُماتِكَ وَاْجْتِراءً عَلى مَعاصِيكَ وَتَعَدِّياً لِحُدُودِكَ وَغَفْلَةً عَنْ وَعيدِكَ وَطاعَةً لِعَدُوّى وَعَدُوِّكَ، لَمْ يَمْنَعْكَ يا اِلـهي وناصِري اِخْلالي بِالشُّكْرِ عَنْ اِتْمامِ اِحْسانِكَ وَلاَ حَجَزَنى ذلِكَ عَنِ ارْتِكابِ مَساخِطِكَ، اَللّـهُمَّ وَهذا (فَهذا) مَقامُ عَبْد ذَليل اعْتَرَفَ لَكَ بِالتَّوْحيدِ وَاَقَرَّ عَلى نَفْسِهِ بِالتَّقْصيرِ فى اَداءِ حَقِّكَ وَشَهِدَ لَكَ بِسُبُوغِ نِعْمَتِكَ عَلَيْهِ وَجَميلِ عادَتِكَ عِنْدَهُ واِحْسانِكَ اِلَيْهِ فَهَبْ لي يا اِلـهي وَسَيِّدِي مِنْ فَضْلِكَ ما اُريدُهُ (سَبَباً) اِلى رَحْمَتِكَ واَتَّخِذُهُ سُلَّماً اَعْرُجُ فيهِ اِلى مَرْضاتِكَ وَآمَنُ بِهِ مِنْ سَخَطِكَ بِعِزَّتِكَ وَطَوْلِكَ وَبِحَقِّ نَبِيِّكَ مَحَمَّد صَلى الله عليه وآله فلك الحمد يا ربِّ مِنْ مقتدر يغلبُ وذي أناة يعجل صلّ على محمد وآل محمد وَاجْعَلْني لِنَعْمائِكَ مِنَ الشّاكِرينَ وَلالائِكَ مِنَ الذّاكِرينَ، اِلـهي وَكَمْ مِنْ عَبْد اَمْسى وَاَصْبَحَ في كَرْبِ الْمَوْتِ وَحَشْرَجَةِ الصَّدْرِ وَالنَّظَرِ اِلى ما تَقْشَعِرُّ مِنْهُ الجُلُودُ وَتَفْزَعُ لَهُ القُلُوبُ واَنَا في عافِيَة مِنْ ذلِكَ كُلِّهِ فَلَكَ الْحَمْدُ يا رَبِّ مِنْ مُقْتَدِر لا يُغْلَبُ وَذي اَناة لا يَجْعَلُ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاجْعَلْني لِنَعمائِكَ مِنَ الشّاكِرينَ وَلالائِكَ مِنَ الذّاكِرينَ، اِلـهي وَكَمْ مِنْ عَبْد اَمْسى وَاَصْبَحَ سَقِيماً مُوْجِعاً في اَنَّة وَعَويل يَتَقَلَّبُ في غَمِّهِ لا يَجِدُ مَحيصاً وَلا يُسيغُ طَعاماً وَلا شَراباً وَاَنَا في صِحَّة مِنَ الْبَدَنِ وَسَلامَة مِنَ الْعَيْشِ كُلُّ ذلِكَ مِنْكَ فَلَكَ الْحَمْدُ يا رَبِّ مِنْ مُقْتَدِر لا يُغْلَبُ وَذي اَناة لا يَعْجَلُ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد واجْعَلْني لِنَعْمائِكَ مِنٌ الشّاكِرينَ وَلالائِكَ مِنَ الذّاكِرينَ، اِلـهي وَكَمْ مِنْ عَبْد أَمْسى وَأصْبَحَ خائِفاً مَرْعُوباً مُشْفِقاً وَجِلاً هارِباً طَريداً مُنْجَحِراً في مَضيق وَمَخْبَأة مِنَ الَْمخابِي قَدْ ضاقَتْ عَلَيْهِ الاْرْضُ بِرَحْبِها لا يَجِدُ حيلَةً وَلا مَنْجىً وَلا مَأوىً وَاَنَا في اَمْن وَطُمَأنينة وَعافِيَة مِنْ ذلِكَ كُلِّهِ فَلَكَ الْحَمْدُ يا رَبِّ مِنْ مُقْتَدر لا يُغْلَبُ وَذى اَناة لا يَعْجَلُ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاْجعَلْنى لِنَعْمائِكَ مِنَ الشّاكِرينَ وَلالائِكَ مِنَ الذّاكِرينَ اِلـهي وَسَيِّدي وَكَمْ مِنْ عَبْد اَمْسى وَاَصْبَحَ مَغْلُولاً مُكَبَّلاً فِي الْحَديدِ بِاَيْدي الْعَداةِ لا يَرْحَمُونَهُ، فَقيداً مِنْ اَهْلِهِ وَوَلَدِهِ مُنْقَطِعاً عَنْ اِخْوانِهِ وَبَلَدهِ، يَتَوَقَّعُ كُلَّ ساعَة بِاَيِّ قِتْلَة يُقْتَلُ وَبِاَيِّ مُثْلَة يُمَثَّلُ بِهِ وَاَنَا في عافِيَة مِنْ ذلِكَ كُلِّهِ فَلَكَ الْحَمْدُ يا رَبِّ مِنْ مُقْتَدر لا يُغْلَبُ وَذى اَناة لا يَعْجَلُ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاجْعَلْني لِنَعْمائِكَ مِنَ الشّاكِرينَ وَلالائِكَ مِنَ الذّاكِرينَ، اِلـهي وَكَمْ مِنْ عَبْد اَمْسى وَاَصْبَحَ يُقاسِي الْحَرْبَ وَمُباشَرَةَ الْقِتالِ بِنَفْسِهِ قَدْ غَشِيَتْهُ الاْعْداءُ مِنْ كُلِّ جانِب بِالسُّيُوفِ وَالرِّماحِ وَآلَةِ الْحْربِ يَتَقَعْقَعُ فِي الْحَديدِ قَدْ بَلَغَ مَجْهُودَهُ لا يَعْرِفُ حيلَةً وَلا يَجِدُ مَهْرَباً قَدْ اُدْنِفَ بِالْجِراحاتِ اَوْ مُتَشَحِّطاً بِدَمِهِ تَحْتَ السَّنابِكِ وَالاَْرْجُلِ يَتَمَنّى شَرْبَةً مِنْ ماء اَوْ نَظْرَةً اِلى اَهْلِهِ وَوَلَدِهِ لا يَقْدِرُ عَلَيْها وَاَنَا في عافِيَة مِنْ ذلِكَ كُلِّهِ فَلَكَ الْحَمْدُ يا رَبِّ مِنْ مُقْتَدِر لا يُغْلَبُ وَذي اَناة لا يَعْجَلُ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاْجَعَلْني لِنَعْمائِكَ مِنَ الشّاكِرينَ وَلالائِكَ مِنَ الذّاكِرينَ، اِلـهي وكم مِنْ عَبْد اَمْسى وَاَصْبَحَ في ظُلُماتِ الْبِحارِ وَعَواصِفِ الرِّياحِ وَالاَْهْوالِ وَالاْمْواجِ يَتَوقَّعُ الغَرَقَ وَالْهَلاكَ لا يَقْدِرُ عَلى حيلَة اَوْ مُبْتَلىً بِصاعِقَة اَوْ هَدْم اَوْ حَرْق اَوْ شَرْق اَوْ خَسْف اَوْ مَسْخ اَوْ قَذْف وَاَنَا فى عافِيَة مِنْ ذلِكَ كُلِّهِ فَلَكَ الْحَمْدُ يا رَبِّ مِنْ مُقْتَدِر لا يُغْلَبُ وَذي اَناة لا يَعْجَلُ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاجْعَلني لِنَعْمائِكَ مِنَ الشّاكِرينَ وَلالائِكَ مِنَ الذّاكِرينَ، اِلـهي وكَمْ مِنْ عَبْد اَمْسى واَصْبَحَ مُسافِراً شاخِصاً عَنْ اَهْلِهِ وَوَلَدِهِ مُتَحَيِّراً فِي الْمَفاوِزِ تائِهاً مَعَ الْوُحُوشِ وَالْبَهائِمِ وَالْهَوامِّ وَحِيداً فَريداً لا يَعْرِفُ حيلَةً وَلا يَهْتَدي سَبيلاً، اَوْ مُتَاَذِّياً بِبَرْد اَوْ حَرٍّ اَوْ جُوع اَوْ عُرْي اَوْ غَيْرِهِ مِنَ الشَّدائِدِ مِمَّا اَنَا مِنْهُ خِلْوٌ في عافِيَة مِنْ ذلِكَ كُلِّهِ فَلَكَ الْحَمْدُ يا رَبِّ مِنْ مُقْتَدِر لا يُغْلَبُ وَذي اَناة لا يَعْجَلُ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد واجْعَلْني لِنعمائِكَ مِنَ الشّاكِرينَ ولالائِكَ مِنَ الذّاكِرينَ، اِلـهي وَسَيِّدي وكَمْ مِنْ عَبْد اَمْسى وَاَصْبَحَ فَقيراً عائِلاً عارِياً مُمْلِقاً مُخْفِقاً مَهْجُوراً (خائِفاً) جائِعاً ظَمآنَ يَنْتَظِرُ مَنْ يَعُودُ عَلَيْهِ بِفَضْل، اَوْ عَبْد وَجيه عِنْدَكَ هُوَ اَوْجَهُ مِنّي عِنْدَكَ وَاَشدُّ عِبادَةً لَكَ مَغْلُولاً مَقْهُوراً قَدْ حُمِّلَ ثِقْلاً مِنْ تَعَبِ الْعَناء وَشِدَّةِ الْعُبُودِيَّةِ وَكُلْفَةِ الرِّقِّ وَثِقْلِ الضَّريبَةِ اَوْ مُبْتلىً بِبَلاء شَديد لا قِبَلَ لَهُ (بِهِ) إلاّ بِمَنَّكَ عَلَيْهِ واَنَا الَْمخْدُومُ الْمُنَعَّمُ الْمُعافَي الْمَكَرَّمُ فى عافِيَة مِمّا هُوَ فيهِ فَلَكَ الْحَمْدُ عَلى ذلِكَ كُلِّهِ مِنْ مُقْتَدر لا يُغْلَبُ وَذي اَناة لا يَجْعَلُ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاْجَعْلني لِنَعْمائِكَ مِنَ الشّاكِرينَ وَلالائِكَ مِنَ الذّاكِرينَ، } اِلـهي وَسَيِّدي وَكَمْ مِنْ عَبْد اَمْسى واَصْبَحَ شَريداً طَريداً حَيرانَ مُتَحَيِّراً جائِعاً خائِفاً خاسِراً فِي الصَّحاري وَالْبَراري قَدْ اَحْرَقَهُ الْحَرُّ وَالْبَرْدُ وَهُوَ فى ضرٍّ مِنَ الْعَيْشِ وَضَنْك مِنَ الْحَياةِ وَذُلٍّ مِنَ المَقامِ يَنْظُرُ اِلى نَفْسِهِ حَسْرَةً لا يَقْدِرُ لَها عَلى ضَرٍّ وَلا نَفْع وَاَنَا خِلْوٌ مِنْ ذلِكَ بِجُودِكَ وَكَرَمِكَ فَلا اِلـهَ إلاّ اَنْتَ سُبْحانَكَ مِنْ مُقْتَدر لا يُغْلَبُ وَذى اَناة لا يَعْجَلُ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد واْجعَلْني لاَنْعُمِكَ مِنَ الشّاكِرينَ ولالائِكَ مِنَ الذّاكِرينَ واَرْحَمْني بِرَحْمَتِكَ يا اَرْحَمَ الرَّاحِمينَ ـ نسخة المجلسي { اِلـهي وَسَيِّدي وكَم مِنْ عَبْد اَمْسى وَاَصْبَحَ عَليلاً مَريضاً سَقيماً مُدْنِفاً عَلى فُرُشِ العِلَّةِ وَفى لِباسِها يَتَقَلَّبُ يَميناً وشِمالاً لا يَعْرِفُ شَيْئاً مِنْ لَذَّةِ الطَّعامِ وَلا لَذَّةِ الشَّرابِ يَنْظُرُ اِلى نَفْسِهِ حَسْرةً لا يَسْتَطيعُ لَها ضَرّاً وَلا نَفْعاً وَاَنَا خِلْوٌ مِنْ ذلِكَ كُلِّهِ بِجُودِكَ وَكَرَمِكَ فَلا اِلـهَ إلاّ اَنْتَ سُبْحانَكَ مِنْ مُقْتَدر لا يُغْلَبُ وَذي اَناة لا يَعْجَلُ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد واْجعَلْنى لَكَ مِنَ الْعابِدينَ وَلِنعَمائِكَ مِنَ الشّاكِرينَ وَلالائِكَ مِنَ الذّاكِرينَ وَارْحَمْني بِرحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ، مَوْلاي وَسَيِّدي وَكَمْ مِنْ عَبْد اَمْسى وَاَصْبَحَ وَقَدْ دَنا يَْومَهُ مِنْ حَتْفِهِ واَحْدَقَ بِهِ مَلَكُ الْمَوْتِ في اَعْوانِهِ يُعالِجُ سَكَراتِ الْمَوْتِ وَحِياضَهُ تَدُورُ عَيْناهُ يَميناً وَشِمالاً يَنْظُرُ اِلى اَحِبّائِهِ وَاَوِدّائِهِ واَخِلاّئِهِ، قَدْ مُنِعَ مِنَ الكَلامِ وَحُجِبَ عَنِ الخِطابِ يَنْظُرُ اِلى نَفْسِهِ حَسْرَةً لا يَسْتَطيعُ لَها ضَرّاً وَلا نَفْعاً وَاَنَا خِلْوٌ مِنْ ذلِكَ كُلِّهِ بِجُودِكَ وَكَرمِكَ فَلا اِلـهَ إلاّ اَنْتَ سُبْحانَكَ مِنْ مُقْتَدِر لا يُغْلَبُ وَذي اَناة لا يَعْجَلُ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد واجْعَلْني لِنَعْمائِكَ مِنَ الشّاكِرينَ وَلالائِكَ مِنَ الذّاكِرينَ وَارْحَمْني بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ، مَوْلايَ وَسَيِّدي وكَم مِنْ عَبْد اَمْسى وَاَصْبَحَ في مَضَائِقِ الحُبُوسِ وَالسُّجُونِ وَكُرَبِها وَذُلِّها وَحَديدِها يَتَداوَلُهُ اَعْوانُها وَزَبانِيَتُها فَلا يَدْري اَيُّ حال يُفْعَلُ بِهِ وَاَيَّ مُثْلَة يُمَثَّلُ بِهِ فَهُوَ في ضُرٍّ مِنَ الْعَيْشِ وَضنْك مِنَ الْحَياةِ يَنْظُرُ اِلى نَفْسِهِ حَسْرَةً لا يَسْتَطيعُ لَها ضَرّاً وَلا نَفْعاً وَاَنَا خِلْوٌ مِنْ ذلِكَ كُلِّهِ بِجُودِكَ وَكَرَمِكَ فَلا اِلـهَ إلاّ اَنْتَ سُبْحانَكَ مِنْ مُقْتَدِر لا يُغْلَبُ وَذى اَناة لا يَعْجَلُ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد واْجعَلْني لَكَ مِنَ الْعابِدينَ ولِنَعْمائِكَ مِنَ الشّاكِرينَ وَلالائِكَ مِنَ الذّكِرينَ وَارْحَمْني بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ، سَيِّدِي وَمَوْلايَ وَكَمْ مِنْ عَبْد اَمْسى وَاَصْبَحَ قَدِ اسْتَمَرَّ عَلَيْهِ القَضاءُ وَاَحْدقَ بِهِ الْبَلاءُ وَفارَقَ اَوِدّاءَهٌ وَاَحِبّاءَهٌ وَاَخِلاّءَهٌ وَاَمْسى اَسيراً حَقيراً ذَليلاً في اَيْدِى الْكُفّارِ وَالاْعْداء يَتَداوَلُونَهُ يَميناً وَشِمالاً قَدْ حُصِرَ فِي الْمَطاميرِ وَثُقِّلَ بِالْحَديدِ لا يَرى شَيْئاً مِنْ ضِياءِ الدُّنْيا وَلا مِنْ رَوْحِها يَنْظُرُ اِلَى نَفْسِهِ حَسْرَةً لا يَسْتَطيعُ لَها ضَرّاً وَلا نَفْعاً وَاَنَا خِلْوٌ مِنْ ذلِكَ كُلِّهِ بِجُودِكَ وَكَرَمِكَ فَلا اِلـهَ إلاّ اَنْتَ سُبْحانَكَ مِنْ مُقْتَدِر لا يُغْلَبُ وَذي اَناة لا يَعْجَلُ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد واْجعَلْني لَكَ مِنَ الْعابِدينَ وَلِنَعْمائِكَ مِنَ الشّاكِرينَ وَلالائِكَ مِنَ الذّاكِرينَ وَارْحَمْني بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ } اِلـهي وَسَيِّدِي وَكَمْ مِنْ عَبْد اَمْسى وَاَصْبَحَ قَدِ اشتاقَ اِلَى الدُّنْيا للِرَّغْبَةِ فيها اِلى اَنْ خاطَرَ بِنَفْسِهِ وَمالِهِ حِرْصاً مِنْهُ عَلَيْها قَدْ رَكِبَ الْفُلْكَ وَكُسِرَتْ بِهِ وَهُوَ في آفاقِ الْبِحارِ وَظُلَمِها يَنْظِرُ اِلى نَفْسِهِ حَسْرَةً لا يَقْدِرُ لَها على ضَرٍّ وَلا نَفْع واَنَا خِلْوٌ مِنْ ذلِكَ كُلِّه بِجُوِدكَ وَكَرَمِكَ فَلا اِلـهَ إلاّ اَنْتَ سُبْحانَكَ مِنْ مُقْتَدِر لا يُغْلَبُ وَذى اَناة لا يَعْجَلُ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد واْجعَلْني لَكَ مِنَ الْعابِدينَ وَلِنَعْمائِكَ مِنَ الشّاكِرينَ وَلالائِكَ مِنَ الذّاكِرينَ وَارْحَمْني بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ، اِلـهي وَسَيِّدي وَكَمْ مِنْ عَبْد اَمْسى قَدِ اسْتَمَرَّ عَلَيْهِ الْقَضاءُ وَاَحْدَقَ بِهِ الْبَلاءُ والكُفّارُ والاْعْداءُ واَخَذَتْهُ الرِّماحُ وَالسُّيُوفُ وَالسِّهامُ وَجُدِّلَ صَريعاً وَقَدْ شَرِبَتِ الاْرْضُ مِنْ دَمِهِ واَكَلَتِ السِّباعُ وَالطِّيْرُ مِنْ لَحْمِهِ واَنَا خِلْوٌ مِنْ ذلِكَ كُلِّهِ بِجُودِكَ وَكَرَمِكَ لا بِاسْتِحْقاق مِنّي يا لا اِلـهَ إلاّ اَنْتَ سُبْحانَكَ مِنْ مُقْتَدِر لا يُغْلَبُ وَذي اَناة لا يَعْجَلُ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد واْجعَلْني لِنَعْمائِكَ مِنَ الشّاكِرينَ وَلالائِكَ مِنَ الذّاكِرينَ وَارْحَمْني بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ ـ نسخة المجلسي {، وَعِزَّتِكَ يا كَريمُ لاَطْلُبَنَّ مِمّا لَدَيْكَ، وَلاَُلِحَّنَّ عَلَيْكَ وَلاََمُدَّنَّ يَدى نَحْوَكَ مَعَ جُرْمِها اِلَيْكَ يا رَبِّ فَبِمَنْ اَعُوذُ وَبِمَنْ اَلُوذُ لا اَحَدَ لي اِلاّ اَنْتَ اَفَتَرُدَّني وَاَنْتَ مُعَوَّلي وَعَلَيْكَ مُتَّكَلي، اَسْأَلُكَ بِاسْمِكَ الَّذي وَضَعْتَهُ عَلَى السَّماءِ فَاْستَقَلَّتْ وَعَلَى الاْرْضِ فاَسْتَقَرَّتْ وَعَلى الْجِبالِ فَرَسَتْ وَعَلَى اللَّيْلِ فَاَظْلَمَ وَعَلَى النَّهارِ فَاسْتَنارَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمِّد وَاَنْ تَقْضِيَ لي حَوائِجي كُلَّها وَتَغْفِرَ لي ذُنُوبي كُلَّها صَغيرَها وَكَبيرَها، وَتُوَسِّعَ عَلَيَّ مِنَ الرِّزْقِ ما تُبَلِّغُني بِهِ شَرَفَ الدُّنْيا وَالاخِرَةِ يا اَرْحَمَ الَّراحِمينَ، مَوْلايَ بكَ اْستَعَنْتُ فَصَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد واَعِنّي، وَبِكَ اسْتَجَرْتُ فَاَجِرْنى واَغْنِنى بِطاعَتِكَ عَنْ طاعَةِ عِبادِكَ وَبِمَسْأَلَتِكَ عَنْ مَسْأَلَةِ خَلْقِكَ وَانْقُلْنى مِنْ ذُلِّ الْفَقْرِ اِلى عِزِّ الْغِنى وَمِنْ ذُلِّ الْمَعاصى اِلى عِزِّ الطّاعَةِ فَقَدْ فَضَّلْتَني عَلى كَثير مِنْ خَلْقِكَ جُوداً مِنْكَ وَكَرَماً لا بِاسْتِحْقاق مِنّي، اِلـهي فَلَكَ الْحَمْدُ عَلى ذلِكَ كُلِّهِ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد واْجعَلْنى لِنَعْمائِكَ مِنَ الشّاكِرينَ وَلالائِكَ مِنَ الذّاكِرينَ وَارْحَمْني بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ ثمّ اسجد وقل : سَجَدَ وَجْهِيَ الذَّليلُ لِوَجْهِكَ الْعَزيزِ الْجَليلِ، سَجَدَ وَجْهِيَ البالى الْفاني لِوَجْهِكَ الدّائِم الْباقي، سَجَدَ وَجْهِيَ الْفَقيرُ لِوَجْهِكَ الْغَنيِّ الْكَبيرِ، سَجَدَ وَجْهي وَسَمْعي وَبَصَري وَلَحْمي وَدَمي وَجِلْدى وَعَظْمي وَما اَقَلَّتِ الاْرْضُ مِنّي لله رَبِّ الْعالَمينَ، اَللّـهُمَّ عُدْ عَلى جَهْلي بِحِلْمِكَ، وَعَلى فَقْري بِغِناكَ، وَعَلى ذُلّي بِعِزِّكَ وَسُلْطانِكَ، وَعَلى ضَعْفي بِقُوَّتِكَ، وَعَلى خَوْفي بِاَمْنِكَ، وَعَلى ذُنُوبي وَخطايايَ بِعَفْوِكَ وَرَحْمَتِكَ يا رَحمن يا رَحيمُ اَللّـهُمَّ اِنّى اَدْرَأُ بِكَ في نَحْرِ فلان بن فلان واَعُوُذ بِكَ مِنْ شَرِّهِ فَاكْفِنيهِ بِما كَفَيْتَ بِهِ اَنْبِياءِكَ وَاَوْلِياءِكَ مِنْ خَلْقِكَ وَصالِحى عِبادِكَ مِنْ فَراعِنَةِ خَلْقِكَ وَطُغاةِ عُداتِكَ وَشَرِّ جَميعِ خَلْقِكَ بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ اِنَّكَ عَلى كُلِّ شَيْء قَديرٌ وَحَسْبُنَا اللهُ وَنِعْمَ الْوَكيلُ ."}],"preview":"الاوّل : استحباب كتابة هذا الدّعاء على الاكفان كما أشار الى ذلك العلاّمة بحر العلوم عطّر الله مرقده في كتابِ الدُرّة .","hasTranslate":false},{"id":"mf_ar_65","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفصل السادس :","title":"دُعاء السّيفي الصَّغير المعروف بِدُعاء القاموس","blocks":[{"type":"Text","content":"ذَكَره الشّيخ الاجلّ ثقة الاسلام النّوري عطّر الله مرقده في الصّحيفة الثّانية العلويّة، وقال: انّ لهذا الدّعاء في كلمات أرباب الطّلسمات والتسخيرات شرح غريب وقد ذكروا له آثاراً عجيبة، وَلَم أروِ ما ذكرُوه لعدم اعتمادي عليه ولكن اُورد أصل الدّعاء تسامحاً في أدلّة السّنن وتاسّياً، بالعلمآء الاعلام ، وهو هذا الدّعاء :"},{"type":"Text","content":"رَبِّ اَدْخِلْني في لُجَّةِ بَحْرِ اَحَدِيَّتِكَ، وَطَمْطامِ يَمِّ وَحْدانِيَّتِكَ، وَقَوِّنى بِقُوَّةِ سَطْوَةِ سُلْطانِ فَرْدانِيَّتِكَ، حَتّى اَخْرُجَ اِلى فَضاءِ سَعَةِ رَحْمَتِكَ وَفي وَجْهي لَمَعاتُ بَرْقِ الْقُرْبِ مِنْ آثارِ حِمايَتِكَ، مَهيباً بِهَيْبَتِكَ عَزيزاً بِعِنايَتِكَ مُتَجَلِّلاً مُكَرَّماً بِتَعْليمِكَ وَتَزْكِيَتِكَ، واَلْبِسْنى خِلَعَ الْعِزَّةِ وَالْقَبُولِ وَسَهِّلْ لى مَناهِجَ الْوُصْلَةِ والْوُصُولِ، وَتَوِّجْني بِتاجِ الْكَرامَةِ وَالْوَقارِ وَاَلِّفْ بَيْني وَبَيْنَ اَحِبّائِكَ فى دارِ الدُّنْيا وَدارِ الْقَرارِ، وارْزُقْنى مِنْ نُورِ اسْمِكَ هَيْبَةً وَسَطْوَةً تَنْقادُ لِيَ الْقُلُوبُ وَالاَْرْواحُ، وَتَخْضَعُ لَدَيَّ النُّفُوسُ وَالاْشْباحُ، يا مَنْ ذَلَّتْ لَهُ رِقابُ الْجَبابِرَةِ وَخَضَعَتْ لَدَيْهِ اَعْناقُ الاْكاسِرَةِ لا مَلْجَاَ وَلا مَنْجا مِنْكَ إلاّ اِلَيْكَ، وَلا اِعانَةَ إلاّ بِكَ وَلاَ اِتّكاءَ إلاّ عَلَيْكَ، ادْفَعْ عَنّي كَيْدَ الْحاسِدينَ وَظُلُماتِ شَرِّ المُعانِدينَ وارْحَمْني تَحْتَ سُرادِقاتِ عَرْشِكَ يا اَكْرَمَ الاَْكْرَمينَ اَيِّدْ ظاهِري في تَحْصيلِ مَراضيكَ وَنَوِّرْ قَلْبي وَسِرّي بالاِْطِّلاعِ عَلى مَناهِجِ مَساعيكَ، اِلـهي كَيْفَ اَصْدُرُ عَنْ بابِكَ بِخَيْبَة مِنْكَ وَقَدْ وَرَدْتُهُ عَلى ثِقَة بِكَ، وَكَيْفَ تُؤْيِسُني مِنْ عَطائِكَ وَقَدْ اَمَرْتَنى بِدُعائِكَ وَها اَنَا مُقْبِلٌ عَلَيْكَ مُلْتَجِيٌ اِلَيْكَ باعِدْ بَيْني وَبيْنَ اَعْدائي، كَما باعَدْتَ بَيْنَ اَعْدائي اِخْتَطِفْ اَبْصارَهُمْ عَنّي بِنُورِ قُدْسِكَ وَجَلالِ مَجْدِكَ اِنَّكَ اَنْتَ اللهُ المُعْطي جَلائِلَ النِّعَمِ الْمُكَرَّمَةِ لِمَنْ ناجاكَ بِلَطائِفِ رَحْمَتِكَ، يا حَيُّ يا قَيُّومُ يا ذَا الْجَلالِ وَالاِْكْرامِ، وَصَّلى اللهُ عَلى سَيِّدِنا وَنَبِيِّنا مُحَمَّد وَآلِهِ اَجْمَعينَ الطَّيِّبينَ الطّاهِرينَ ."}],"preview":"ذَكَره الشّيخ الاجلّ ثقة الاسلام النّوري عطّر الله مرقده في الصّحيفة الثّانية العلويّة، وقال: انّ لهذا الدّعاء في كلمات أرباب الطّلسمات والتسخيرات شرح غريب وقد ذكروا له آثاراً عجيب","hasTranslate":false},{"id":"mf_ar_66","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفَصلُ السّابِع :","title":"في ذكر نبذ مِن الدَّعوات النّافِعة المختصرة الّتي اقتطفتها من الكتب المعتبرة","blocks":[{"type":"Text","content":"الاوّل : قال السيّد الاجل السيّد عليخان الشيرازي رضوان الله عليه في كتاب الكلم الطيّب: انّ اسم الله الاعظم هو ما يفتتح بكلمة الله ويختتم بكلمة هو، وليس في حروفه حرف منقوط، ولا يتغيّر قراءته، اٌعرب أم لم يٌعرب، ونظفر بذلك في القرآن المجيد في خمس آيات من خمس سُور ، هي البقرة وآل عمران والنّساء وطه والتّغابن ، قال الشيخ المغربي: من اتّخذ هذه الايات الخمس ورداً وردّدها في كلّ يوم احدى عشرة مرّة تيسّر له ما أهمّه من الامور الكليّة والجزئية عاجلاً ان شاء الله تعالى، والايات الخمس هي :"},{"type":"Text","content":"(1) اَللهُ لا اِلـهَ إلاّ هُوَ الْحَيُّ القَيُّومُ إلى آخر آية الكرسي (2) اَللهُ لا اِلـهَ إلاّ هُوَ الحَيُّ القَيُّومُ نَزَّلَ عَلَيْكَ الْكِتَابَ بِالْحَقِّ مُصَدِّقاً لِما بَيْنَ يَدَيْهِ واَنْزَلَ التَّوْراةَ وَالاِْنْجيلَ مِنْ قَبْلُ هُدىً لِلنّاسِ وَاَنْزَلَ الْفُرْقانَ (3) اَللهُ لا اِلـهَ إلاّ هُوَ لَيَجْمَعَنَّكُمْ اِلى يَوْمِ الْقِيامَةِ لا رَيْبَ فيهِ وَمَنْ اَصْدَقُ مِنَ اللهِ حَديثاً (4) اَللهُ لا اِلـهَ إلاّ هُوَ لَهُ الاَْسْماءُ الْحُسْنى (5) اَللهُ لا اِلـهَ إلاّ هُوَ وَعَلَى اللهِ فَلْيَتَوَكَّلِ الْمُؤْمِنُونَ ."},{"type":"Text","content":"الثّاني : التّوسُّل، قال العلاّمة المجلسي (رحمه الله) عن بعض الكتب المعتبرة انّه: روى محمّد بن بابويه هذا التّوسّل عن الائمة (عليهم السلام) وقال: ما توسّلت لامر من الامور الاّ ووجدت أثر الاجابة سريعاً، وهو :"},{"type":"Text","content":"اَللّـهُمَّ اِنّي اَسْاَلُكَ وَاَتَوَجَّهُ اِلَيْكَ بِنَبِيِّكَ نَبِيِّ الرَّحْمَةِ مُحَمَّد صَلَّى اللهُ عَلَيْهِ وَآلِهِ، يا اَبَا الْقاسِمِ يا رَسُولَ اللهِ يا اِمامَ الرَّحْمَةِ يا سَيِّدَنا وَمَوْلانا اِنّا تَوَجَّهْنا وَاسْتَشْفَعْنا وَتَوَسَّلْنا بِكَ اِلَى اللهِ وَقَدَّمْناكَ بَيْنَ يَدَيْ حاجاتِنا يا وَجيهاً عِنْدَ اللهِ اِشْفَعْ لَنا عِنْدَ اللهِ، يا اَبَا الْحَسَنِ يا اَميرَ الْمُؤْمِنينَ يا عَلِيَّ بْنَ اَبي طالِب، يا حُجَّةَ اللهِ عَلى خَلْقِهِ يا سَيِّدَنا وَمَوْلانا اِنّا تَوَجَّهْنا وَاسْتَشْفَعْنا وَتَوَسَّلْنا بِكَ اِلَى اللهِ وَقَدَّمْناكَ بَيْنَ يَدَيْ حاجاتِنا، يا وَجيهاً عِنْدَ اللهِ اِشْفَعْ لَنا عِنْدَ اللهِ، يا فاطِمَةَ الزَّهْراءُ يا بِنْتَ مُحَمَّد يا قُرَّةَ عَيْنِ الرَّسُولِ، يا سَيِّدَتَنا اِنّا تَوَجَّهْنا وَاسْتَشْفَعْنا وَتَوَسَّلْنا بِكِ اِلَى اللهِ وَقَدَّمْناكِ بَيْنَ يَدَيْ حاجاتِنا، يا وَجيهَةً عِنْدَ اللهِ اِشْفَعي لَنا عِنْدَ اللهِ، يا اَبا مُحَمَّد يا حَسَنَ بْنَ عَلِيٍّ اَيُّهَا الُْمجْتَبى يَا بْنَ رَسُولِ اللهِ، يا حُجَّةَ اللهِ عَلى خَلْقِهِ يا سَيِّدَنا وَمَوْلانا اِنّا تَوَجَّهْنا وَاسْتَشْفَعْنا وَتَوَسَّلْنا بِكَ اِلَى اللهِ وَقَدَّمْناكَ بَيْنَ يَدَيْ حاجاتِنا يا وَجيهاً عِنْدَ اللهِ اِشْفَعْ لَنا عِنْدَ اللهِ، يا اَبا عَبْدِاللهِ يا حُسَيْنَ بْنَ عَلِيٍّ، اَيُّهَا الشَّهيدُ يَا بْنَ رَسُولِ اللهِ يا حُجَّةَ اللهِ عَلى خَلْقِهِ يا سَيِّدَنا وَمَوْلانا اِنّا تَوَجَّهْنا وَاسْتَشْفَعْنا وَتَوَسَّلْنا بِكَ اِلَى اللهِ وَقَدَّمْناكَ بَيْنَ يَدَيْ حاجاتِنا يا وَجيهاً عِنْدَ اللهِ اِشْفَعْ لَنا عِنْدَ اللهِ، يا اَبَا الْحَسَنِ يا عَلِيَّ بْنَ الْحُسَيْنِ، يا زَيْنَ الْعابِدينَ يَا بْنَ رَسُولِ اللهِ يا حُجَّةَ اللهِ عَلى خَلْقِهِ يا سَيِّدَنا وَمَوْلانا اِنّا تَوَجَّهْنا وَاسْتَشْفَعْنا وَتَوَسَّلْنا بِكَ اِلَى اللهِ، وَقَدَّمْناكَ بَيْنَ يَدَيْ حاجاتِنا، يا وَجيهاً عِنْدَ اللهِ اِشْفَعْ لَنا عِنْدَ اللهِ، يا اَبا جَعْفَر يا مُحَمَّدَ، بْنَ عَلِيٍّ اَيُّهَا الْباقِرُ يَا بْنَ رَسُولِ اللهِ يا حُجَّةَ اللهِ عَلى خَلْقِهِ يا سَيِّدَنا وَمَوْلانا اِنّا تَوَجَّهْنا وَاسْتَشْفَعْنا وَتَوَسَّلْنا بِكَ اِلَى اللهِ، وَقَدَّمْناكَ بَيْنَ يَدَيْ حاجاتِنا، يا وَجيهاً عِنْدَ اللهِ اِشْفَعْ لَنا عِنْدَ اللهِ، يا اَبا عَبْدِ اللهِ يا جَعْفَرَ بْنَ مُحَمَّد، اَيُّهَا الصّادِقُ يَا بْنَ رَسُولِ اللهِ يا حُجَّةَ اللهِ عَلى خَلْقِهِ يا سَيِّدَنا وَمَوْلانا اِنّا تَوَجَّهْنا وَاسْتَشْفَعْنا وَتَوَسَّلْنا بِكَ اِلَى اللهِ وَقَدَّمْناكَ بَيْنَ يَدَيْ حاجاتِنا، يا وَجيهاً عِنْدَ اللهِ اِشْفَعْ لَنا عِنْدَ اللهِ، يا اَبَا الْحَسَنِ يا مُوسَى بْنَ جَعْفَر، اَيُّهَا الْكاظِمُ يَا بْنَ رَسُولِ اللهِ يا حُجَّةَ اللهِ عَلى خَلْقِهِ يا سَيِّدَنا وَمَوْلانا اِنّا تَوَجَّهْنا وَاسْتَشْفَعْنا وَتَوَسَّلْنا بِكَ اِلَى اللهِ وَقَدَّمْناكَ بَيْنَ يَدَيْ حاجاتِنا، يا وَجيهاً عِنْدَ اللهِ اِشْفَعْ لَنا عِنْدَ اللهِ، يا اَبَا الْحَسَنِ يا عَلِيَّ بْنَ مُوسى اَيُّهَا الرِّضا يَا بْنَ رَسُولِ اللهِ يا حُجَّةَ اللهِ عَلى خَلْقِهِ يا سَيِّدَنا وَمَوْلانا اِنّا تَوَجَّهْنا وَاسْتشْفَعْنا وَتَوَسَّلْنا بِكَ اِلَى اللهِ وَقَدَّمْناكَ بَيْنَ يَدَيْ حاجاتِنا، يا وَجيهاً عِنْدَ اللهِ اِشْفَعْ لَنا عِنْدَ اللهِ، يا اَبا جَعْفَر يا مُحَمَّدَ بْنَ عَلِيٍّ اَيُّهَا التَّقِيُّ الْجَوادُ يَا بْنَ رَسُولِ اللهِ يا حُجَّةَ اللهِ عَلى خَلْقِهِ يا سَيِّدَنا وَمَوْلانا اِنّا تَوَجَّهْنا وَاسْتَشْفَعْنا وَتَوَسَّلْنا بِكَ اِلَى اللهِ وَقَدَّمْناكَ بَيْنَ يَدَيْ حاجاتِنا، يا وَجيهاً عِنْدَ اللهِ اِشْفَعْ لَنا عِنْدَ اللهِ، يا اَبَا الْحَسَنِ يا عَلِيَّ بْنَ مُحَمَّد اَيُّهَا الْهادِي النَّقِيُّ يَا بْنَ رَسُولِ اللهِ يا حُجَّةَ اللهِ عَلى خَلْقِهِ يا سَيِّدَنا وَمَوْلانا اِنّا تَوَجَّهْنا وَاسْتَشْفَعْنا وَتَوَسَّلْنا بِكَ اِلَى اللهِ وَقَدَّمْناكَ بَيْنَ يَدَيْ حاجاتِنا يا وَجيهاً عِنْدَ اللهِ اِشْفَعْ لَنا عِنْدَ اللهِ، يا اَبا مُحَمَّد يا حَسَنَ بْنَ عَلِيٍّ، اَيُّهَا الزَّكِيُّ الْعَسْكَرِيُّ يَا بْنَ رَسُولِ اللهِ يا حُجَّةَ اللهِ عَلى خَلْقِهِ يا سَيِّدَنا وَمَوْلانا اِنّا تَوَجَّهْنا وَاسْتشْفَعْنا وَتَوَسَّلْنا بِكَ اِلَى اللهِ وَقَدَّمْناكَ بَيْنَ يَدَيْ حاجاتِنا يا وَجيهاً عِنْدَ اللهِ اِشْفَعْ لَنا عِنْدَ اللهِ، يا وَصِيَّ الْحَسَنِ وَالْخَلَفَ الْحُجَّةَ اَيُّهَا الْقائِمُ الْمُنْتَظَرُ الْمَهْدِىُّ يَا بْنَ رَسُولِ اللهِ يا حُجَّةَ اللهِ عَلى خَلْقِهِ يا سَيِّدَنا وَمَوْلانا اِنّا تَوَجَّهْنا وَاسْتَشْفَعْنا وَتَوَسَّلْنا بِكَ اِلَى اللهِ وَقَدَّمْناكَ بَيْنَ يَدَيْ حاجاتِنا يا وَجيهاً عِنْدَ اللهِ اِشْفَعْ لَنا عِنْدَ اللهِ ."},{"type":"Text","content":"ثمّ سل حوائجك، فانّها تٌقضى ان شاء الله تعالى، وعلى رواية اُخرى قُل بعد ذلك :"},{"type":"Text","content":"يا سادَتي وَمَوالِيَّ اِنّي تَوَجَّهْتُ بِكُمْ اَئِمَّتي وَعُدَّتي لِيَوْمِ فَقْري وَحاجَتي اِلَى اللهِ، وَتَوَسَّلْتُ بِكُمْ اِلَى اللهِ، وَاسْتَشْفَعْتُ بِكُمْ اِلَى اللهِ، فَاشْفَعُوا لي عِنْدَ اللهِ، وَاسْتَنْقِذُوني مِنْ ذُنُوبي عِنْدَ اللهِ، فَاِنَّكُمْ وَسيلَتي اِلَى اللهِ وَبِحُبِّكُمْ وَبِقُرْبِكُمْ اَرْجُو نَجاةً مِنَ اللهِ، فَكُونُوا عِنْدَ اللهِ رَجائي يا سادَتي يا اَوْلِياءَ اللهِ، صَلَّى اللهُ عَلَيْهِمْ اَجْمَعينَ وَلَعَنَ اللهُ اَعْداءَ اللهِ ظالِميهِمْ مِنَ الاَْوَّلينَ وَالاْخِرينَ آمينَ رَبَّ الْعالَمينَ ."},{"type":"AboutText","content":"أقول: أورد الشّيخ الكفعمي في كتاب البلد الامين دعاء مبسُوطاً موسوماً بدعاء الفرج، وهو يحتوي في مطاويه على هذا التّوسّل واظنّ انّ التّوسّل بالائمة الاثنى عشر المنسوب إلى الخواجة نصير الدّين (دوازده امام خواجه نصير الدّين) هو تركيب من هذا التّوسّل ومن الصّلوة على الحجج الطّاهرين في خطبة بليغة أوردها الكفعمي في أواخر كتاب المصباح، والسيّد عليخان قد أورد في كتاب الكلم الطّيّب نقلاً عن قبس المصابيح للشّيخ الصهرشتي دعاء للتوسّل ذا شرح لا يسعه المقام، والدّعاء هُو :"},{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلى مُحَمِّد وَعَلى اِبْنَتِه وَعَلى ابْنَيْها، وَاَسْاَلُكَ بِهِمْ اَنْ تُعينَني عَلى طاعَتِكَ وَرِضْوانِكَ، واَنْ تُبَلِّغَني بِهِمْ اَفْضَلَ ما بَلَّغْتَ اَحَداً مِنْ اَوْلِيائِكَ اِنَّكَ جَوادٌ كَريمٌ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِحَقِّ اَميرِ الْمُؤْمِنينَ عَلِيِّ بْنِ أَبي طالِب عليه السلام إلاّ انْتَقَمْتَ بِهِ مِمَّنْ ظَلَمَني وَغَشَمَني وَآذاني واْنَطَوى عَلى ذلِكَ، وَكَفيْتَني بِهِ مَؤُنَةَ كُلِّ اَحَد يا اَرْحَمَ الرّاحِمينَ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِحَقِّ وَلِيِّكَ عَليِّ بْنِ الْحُسَيْنِ عليه السلام إلاّ كَفَيْتَني بِهِ مَؤُنَةَ كُلِّ شَيْطان مَريد وَسُلْطان عَنيد يَتَقَوّى عَلِيِّ بِبَطْشَهِ وَيَنْتَصِرُ عَليَّ بِجُنْدِهِ اِنَّكَ جَوادٌ كَريمٌ يا وَهّابُ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِحَقِّ وَلِيَّيْكَ مُحَمَّدِ بْنِ عَلىٍّ وَجَعْفَرِ بنِ مُحَمَّد عليهما السلام اِلاّ اَعَنْتَني بِهِما عَلى اَمْرِ آخِرَتي بِطاعَتِكَ وَرِضْوانِكَ وَبَلَّغْتنِي بِهِما ما يُرْضيكَ اِنَّكَ فَعّالٌ لِما تُريدُ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِحَقِّ وَلِيِّكَ مُوسَى بْنِ جَعْفَر عليه السلام اِلاّ عافَيْتَني بِهِ فِي جَميعِ جَوارِحي ما ظَهَرَ مِنْها وَما بَطَنَ يا جَوادُ يا كَرِيمُ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِحَقِّ وَلِيِّكَ الرِّضا عَلِىِّ بْنِ مُوسى عليه السلام إلاّ سَلَّمْتَني بِهِ فِي جَميعِ اَسْفارِي فِي الْبَراري وَالْبِحارِ وَالْجِبالِ والْقِفارِ والاَْوْدِيَةِ وَالْغِياضِ مِنْ جَميعِ ما اَخافُهُ وَاَحْذَرُهُ اِنَّكَ رَؤوفٌ رَحيمٌ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِحَقِّ وَلِيِّكَ مُحمَّد بْنِ عَلِىٍّ عليه السلام إلاّ جُدْتَ بِهِ عَلَيَّ مِنْ فَضْلِكَ وَتَفَضَّلْتَ بِهِ عَليَّ مِنْ وُسْعِكَ وَوَسَّعْتَ عَلَيَّ رِزْقَكَ وَاَغْنَيْتَني عَمَّنْ سِواكَ، وَجَعَلْتَ حاجَتي اِلَيْكَ وَقَضاها عَلَيْكَ اِنَّكَ لِما تَشاءُ قَديرٌ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِحَقِّ وَلِيِّكَ عَلىِّ بْنِ مُحَمَّد عليهما السلام اِلاّ اَعَنْتَني بِهِ عَلى تَأدِيَةِ فُرُوضِكَ وَبِرِّ اِخْوانِيَ الْمُؤْمِنينَ، وَسَهِّلْ ذلِكَ لي وَاقْرُنْهُ بِالْخَيْرِ وَاَعِنّي عَلى طاعَتِكَ بِفَضْلِكَ يا رَحيمُ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِحَقِّ وَلِيِّكَ الحَسَنِ بْنِ عَلِىٍّ عليهما السلام اِلاّ اَعَنْتَني بِهِ عَلى اَمْرِ آخِرَتي بِطاعَتِكَ وَرِضْوانِكَ، وَسَرَرْتَني فِي مُنْقَلَبي وَمَثْوايَ بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِحَقِّ وَلِيِّكَ وحُجَّتِكَ صاحِبَ الزَّمانِ عليه السلام إلا اَعَنْتَني بِهِ عَلى جَميعِ اُمُوري وَكَفَيْتَني بِهِ مَؤُنَةَ كُلِّ مُوْذ وَطاغ وَباغ، واَعَنْتَني بِهِ، فَقَدْ بَلَغَ مَجْهُودي وَكَفيْتَني بِهِ كُلَّ عَدُوٍّ وَهَمٍّ وَغَمٍّ وَدَيْن وَعَنّي وَعَنْ وُلْدي وَجَميعِ اَهْلِي وَاِخْوانِي وَمَنْ يَعْنيني اَمْرُهُ وَخاصَّتي، آمينَ رَبَّ الْعالَمينَ ."},{"type":"Text","content":"الثّالث : روى الشّيخ الكفعمي في البلد الامين دعاء عن أمير المؤمنين (عليه السلام)، ما دعا به ملهوف أو مكروب أو حزين أو مبتلي أو خائف الاّ وفرّج الله تعالى عنه، وهُو :"},{"type":"Text","content":"يا عِمادَ مَنْ لا عِمادَ لَهُ، ويا ذُخْرَ مَنْ لا ذُخْرَ لَهُ، وَيا سَنَدَ مَنْ لا سَنَدَ لَهُ، ويا حِرْزَ مَنْ لا حِرْزَ لَهُ، وَيا غِياثَ مَنْ لا غِياثَ لَهُ، وَيا كَنْزَ مَنْ لا كَنْزَ لَهُ، وَيا عِزَّ مَنْ لا عِزَّ لَهُ، يا كَريمَ الْعَفْوِ، يا حَسَنَ التَّجاوُزِ، يا عَوْنَ الضُّعَفاءِ، يا كَنْزَ الْفُقَراءِ، يا عَظيمَ الَّرجاءِ، يا مُنْقِذَ الْغَرْقى، يا مُنْجِيَ الْهَلْكى، يا مُحْسِنُ، يا مُجْمِلُ، يا مُنْعِمُ، يا مُفْضِلُ، اَنْتَ الَّذي سَجَدَ لَكَ سَوادُ اللّيْلِ وَنُورُ النَّهارِ وَضوْءُ الْقَمَرِ، وَشُعاعُ الشَّمْسِ، وَحَفيفُ الشَّجَرِ، وَدَوِىُّ الْماءِ، يا اَللهُ يا اَللهُ يا اَللهُ لا اِلـهَ إلاّ اَنْتَ وَحْدَكَ لا شَريكَ لَكَ، يا رَبّاهُ يا اَللهُ، صَلِّ عَلى مُحَمَّد وآلِ مُحَمَّد وَافْعَلْ بِنا ما اَنْتَ اَهْلُهُ . ثمّ سل حاجتك ."},{"type":"AboutText","content":"أقول: يجدى ايضاً للفرج ورفع الغموم والبلايا المواظبة على هذا الذّكر المروي عن الجواد (عليه السلام) : يَا مَنْ يَكْفي مِنْ كُلِّ شَيء وَلا يَكْفي مِنْهُ شَيءٌ، اِكْفِني ما اَهَمَّني ."},{"type":"Text","content":"الرّابع : الدّعاء للخلاص من السّجن ، قال السيّد ابن طاووس في مهج الدعوات: روي انّ رجلاً اعتقل في الشّام مدّة طويلة، فرأى الزّهراء (عليها السلام) في المنام تقول: اُدع بهذا الدعاء، وعلّمته ايّاه، فلمّا دعا به اطلق سراحه وعاد إلى بيته، وهُو هذا الدّعاء :"},{"type":"Text","content":"اللّـهُمَّ بِحَقِّ الْعَرْشِ وَمنْ عَلاهُ، وَبِحَقِّ الْوَحْي وَمَنْ اَوْحاهُ، وَبِحَقِّ النَّبِيِّ وَمَنْ نَبَّاَهُ، وَبِحَقِّ الْبَيْتِ وَمَنْ بَناهُ، يا سامِعَ كُلِّ صَوْت، يا جامِعَ كُلِّ فَوْت، يا بارِئَ النُّفُوسِ بَعْدَ الْمَوْتِ، صَلِّ عَلى مُحَمَّد واَهْلِ بَيْتِهِ، وآتِنا وَجَميعَ الْمُؤْمِنينَ وَالْمُؤْمِناتِ فِي مَشارِقِ الاَْرْضِ وَمَغارِبِها فَرَجاً مِنْ عِنْدِكَ عاجِلاً بِشَهادَةِ اَنْ لا اِلـهَ اِلاَّ اللهُ، واَنَّ مُحَمَّداً عَبْدُكَ وَرَسُولُكَ صَلّى اللهُ عَليْهِ وَآلِهِ وَعَلى ذُرِّيَّتِهِ الطَّيِّبينَ الطّاهِرِينَ وَسَلَّمَ تَسْليماً كَثيراً ."},{"type":"Text","content":"الخامس : روى السّيد ابن طاووس في مهج الدّعوات حديثاً عن سلمان، وقد ورد في آخر الحديث ما حاصله: انّ فاطمة (عليها السلام) علّمتني كلاماً كانت تعلّمته من رسول الله (صلى الله عليه وآله وسلم)، وكانت تقوله غدوة وعشيّة، وقالت: انّ سرّك أن لا يمسّك اذى الحمّى ما عشت في دار الدّنيا فواظب عليه، وهُوَ :"},{"type":"Text","content":"بِسْمِ اللهِ النُّورِ، بِسْمِ اللهِ نُورِ النُّورِ، بِسْمِ اللهِ نُورٌ عَلى نُور، بِسْمِ اللهِ الَّذي هُوَ مُدَبِّرُ الاُْمُورِ، بِسْمِ اللهِ الَّذي خَلَقَ النُّورَ مِنْ النُّورِ، الْحَمْدُ للهِِ الَّذي خَلَقَ النُّورَ مِنَ النُّورِ، وَاَنْزَلَ النُّورَ عَلى الطُّورِ، فِي كِتاب مَسْطُور، رِقٍّ مَنْشُور، بِقَدَر مَقْدُور، عَلى نَبِيٍّ مَحْبُور، الْحَمْدُ للهِِ الَّذي هُوَ بِالْعِزِّ مَذْكُورٌ، وَبِالْفَخْرِ مَشْهُورٌ، وَعَلَى السَّرّاءِ وَالضَّرّاءِ مَشْكُورٌ، وَصَلَىّ اللهُ عَلى مُحَمَّد وَآلِهِ الطّاهِرينَ ."},{"type":"AboutText","content":"قال سلمان: فتعلمتهنّ وعلّمتهنّ اكثر من ألف نفس من أهل المدينة ومكّة ممّن بهم الحمّى، فبرئوا من مَرضهم باذن الله تعالى ."},{"type":"Text","content":"السّادس : حِرز الامام زين العابدين (عليه السلام) ; روى السيّد في موضعين مِن كتاب المَهج هذا الحرز عن الامام زين العابدين (عليه السلام) :"},{"type":"Text","content":"يا اَسْمَعَ السّامِعِينَ، يا اَبْصَرَ النّاظِرينَ، يا اَسْرَعَ الحاسِبِينَ، يا اَحْكَمَ الْحاكِمِينَ، يا خالِقَ الَْمخْلُوقِينَ، يا رازِقَ الْمَرْزُوقينَ، يا ناصِرَ المَنْصُوريِنَ، يا اَرْحَمَ الرّاحِمينَ، يا دَليلَ الْمُتَحيِّرينَ، يا غِياثَ الْمُسْتَغيثينَ اَغِثْني، يا مالِكَ يَوْمِ الدّينِ، اِيّاكَ نَعْبُدُ وَاِيّاكَ نَسْتَعينُ، يا صَريخَ الْمَكْرُوبينَ، يا مُجيبَ دَعْوَةِ المُضْطَرِّينَ، اَنْتَ اللهُ رَبُّ الْعالَمينَ. اَنْتَ اللهُ لا اِلـهَ اِلاّ اَنْتَ الْمَلِكُ الْحَقُّ الْمُبِينُ، الْكِبْرِياءُ رِداؤُكَ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد الْمُصْطَفى وَعَلى عَلِيٍّ الْمُرْتَضى وَفاطِمَةَ الزَّهْراءِ وَخَدِيجَةَ الْكُبْرى وَالْحَسَنِ الُْمجْتَبى وَالْحُسَيْنِ الشَّهِيدِ بِكَرْبَلاءَ وَعَلِيِّ بْنِ الْحُسَيْنِ زَيْنِ الْعابِدينَ وَمُحَمَّدِ بْنِ عَليٍّ الْباقِرِ وَجَعْفَرِ بْنِ مُحَمِّد الصّادِقِ وَمُوسَى بْنِ جَعْفَر الْكاظِمِ وَعَليِّ بِْن مُوسَى الرِّضا وَمُحَمَّدِ بْنِ عَليٍّ التَّقِيِّ وَعَلِيِّ بْنِ مُحَمَّد النَّقِيِّ وَالْحَسَنِ بن عَليٍّ الْعَسْكَرِيِّ وَالْحُجَّةِ الْقائِمِ الْمَهْدِيِّ الاِْمامِ المُنْتَظَرِ، صَلَوتُ اللهِ عَلَيْهِمْ اَجَمَعينَ، اَللّـُهمَّ والِ مَنْ والاهُمْ، وَعادِ مَنْ عاداهُمْ، وانْصُرْ مَنْ نَصَرَهُمْ، واخْذُل مَنْ خَذَلَهُمْ، وَالْعَنْ مَنْ ظَلَمَهُمْ، وَعجِّلْ فَرَجَ آلِ مُحَمَّد، واْنصُرْ شيعَةَ آلِ مُحَمَّد، وَاَهْلِكْ اَعْداءَ آلِ مُحَمَّد، وَارْزُقْني رُؤْيَةَ قائِمِ آلِ مُحَمَّد، واجْعَلْني مِنْ اَتْباعِهِ واَشْياعِهِ وَالرّاضينَ بِفِعْلِهِ بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ ."},{"type":"Text","content":"السّابع : روى الشيخ الكفعمي في كتاب البلد الامين دعاء عن الامام زين العابدين (عليه السلام)، وقال: روى عنه (عليه السلام) هذا الدّعاء مقاتل بن سليمان، وقال: مَنْ دعا به مائة مرّة فلم يجب له فليلعن مقاتلاً، والدّعاء هو :"},{"type":"Text","content":"اِلـهي كَيْفَ اَدْعُوكَ واَنَا اَنَا وَكَيْفَ اَقْطَعُ رَجائي مِنْكَ واَنْتَ اَنْتَ، اِلـهي اِذا لَمْ اَسْاَلْكَ فَتُعْطيني فَمَنْ ذَا الَّذي اَسْأَلُهُ فَيُعْطيني، اِلـهي اِذا لَمْ اَدْعُكَ فَتَسْتَجيبَ لي فَمَنْ ذَا الَّذي اَدْعُوهُ فَيَسْتَجيبَ لي، اِلـهي اِذا لَمْ اَتَضرَّعْ اِلَيْكَ فَتَرْحَمْني فَمَنْ ذَا الَّذي اَتَضرَّعُ اِلَيْهِ فَيَرْحَمُني، اِلـهي فَكَما فَلَقْتَ الْبَحْرَ لِمُوسى عليه السلام وَنَجَّيْتَهُ اَسْاَلُكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِهِ واَنْ تُنَجِّيَني مِمّا اَنَا فيهِ وَتُفَرِّجَ عَنّي فَرَجاً عاجِلاً غَيْرَ آجِل بِفَضْلِكَ وَرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ ."},{"type":"Text","content":"الثّامن : روى السّيد ابن طاووس (رحمه الله) في المهج، عن الامام محمّد الباقر (عليه السلام)، قال: أتى جبرئيل النّبي (صلى الله عليه وآله وسلم) وقال : يا نبيّ الله اعلم انّي ما أحببت نبيّاً من الانبياء كحبّي لك فأكثر من قول :"},{"type":"Text","content":"اَللّـهُمَّ اِنَّكَ تَرى وَلا تُرى واَنْتَ بِالْمَنْظَرِ الاْعْلى، وَاَنَّ اِلَيْكَ الْمُنْتَهى وَالرُّجْعىْ واَنَّ لَكَ الاْخِرَةَ وَالاُْولى، واَنَّ لَكَ الْمَماتَ وَالَْمحْيا، وَرَبِّ اَعُوذُ بِكَ اَنْ اُذَلَّ اَوْ اُخْزى ."},{"type":"Text","content":"التّاسع : روى الكفعمي في البلد الامين دعاء عن الامام موسى الكاظم (عليه السلام) وقال: انّه دعاء عظيم الشّأن سريع الاجابة، وهُو :"},{"type":"Text","content":"اَللّـهُمَّ اِنّي اَطَعْتُكَ فِي اَحَبِّ الاَْشْياءِ إليْكَ وَهُوَ التَّوْحيدُ وَلَمْ اَعْصِكَ فِي اَبْغَضِ الاَْشْياءِ اِلَيْكَ وَهُوَ الْكُفْرُ فَاغْفِرْ لي ما بَيْنَهُما يا مَنْ اِلَيْهِ مَفَرّي آمِنّي مِمّا فَزِعْتُ مِنْه اِلَيْكَ، اَللّـهُمَّ اغْفِرْ لِيَ الْكَثيرَ مِنْ مَعاصيكَ واقْبَلْ مِنِّي الْيَسيرَ مِنْ طاعَتِكَ يا عُدَّتي دُونَ الْعُدَدِ، وَيا رَجائي وَالْمُعْتَمَدَ، وَيا كَهْفي وَالسَّنَدَ، وَيا واحِدُ يا اَحَدُ، يا قُلْ هُوَ اللهُ اَحَدٌ اَللهُ الصَّمَدُ لَمْ يَلِدْ وَلَمْ يُولَدْ وَلَمْ يَكُنْ لَهُ كُفُواً اَحَدٌ، اَسْاَلُكَ بِحَقِّ مَنِ اصْطَفَيْتَهُمْ مِنْ خَلْقِكَ وَلَمْ تَجْعَلْ خَلْقِكَ مِثْلَهُمْ اَحَداً اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِهِ وَتَفْعَلَ بي ما اَنْتَ اَهْلُهُ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِالْوَحْدانِيَّةِ الْكُبْرى وَالُْمحَمَّدَيَّةِ الْبَيْضاءِ وَالْعَلَوِيَّةِ الْعُلْيا وَبِجَميعِ مَا احْتَجَجْتَ بِهِ عَلى عِبادِكَ وَبِالاِْسْمِ الَّذِي حَجَبْتَهُ عَنْ خَلْقِكَ فَلَمْ يَخْرُجْ مِنْكَ اِلاّ اِلَيْكَ، صَلِّ عَلى مُحَمِّد وَآلِهِ وَاجْعَلْ لي مِنْ اَمْري فَرَجاً ومَخرَجاً وَارْزُقْني مِنْ حَيْثُ اَحْتَسِبُ وَمِنْ حَيْثُ لا اَحْتَسِبُ، اِنَّكَ تَرْزُقُ مَنْ تَشاءُ بِغَيْرِ حِساب . ثمّ سل حاجتك ."},{"type":"Text","content":"العاشِر : روى الكفعمي في المصباح دعاء وقال: قد أورد السّيد ابن طاووس هذا الدّعاء للامن من السّلطان والبلاء وظهور الاعداء، ولخوف الفقر وضيق الصّدر، وهو من أدعية الصحيفة السّجاديّة، فادع به إذا خفت أن يضرّك شيء ممّا ذكر، وهُو هذا الدّعاء :"},{"type":"Text","content":"يا مَنْ تُحَلُّ بِهِ عُقَدُ الْمَكارِهِ، وَيا مَنْ يُفْثَأُ بِهِ حَدُّ الشَّدائِدِ، وَيا مَنْ يُلْتَمَسُ مِنْهُ الَمخْرَجُ اِلى رَوْحِ الْفَرَجِ، ذَلَّتْ لِقُدْرَتِكَ الصِّعابُ، وَتَسَبَّبَتْ بِلُطْفِكَ الاَْسْبابُ، وَجَرى بِقُدْرَتِكَ الْقَضاءُ، وَمَضَتْ عَلى اِرادَتِكَ الاَْشْياءُ، فَهِيَ بِمَشِيَّتِكَ دُونَ قَوْلِكَ مُؤْتَمِرَةٌ، وَبِإِرادَتِكَ دُونَ نَهْيِكَ مُنْزَجِرَةٌ، اَنْتَ الْمَدْعُوُّ لِلْمُهِمّاتِ، واَنْتَ الْمَفْزَعُ المُلِمّاتِ، لا يَنْدَفِعُ مِنْها اِلاّ ما دَفَعْتَ، وَلا يَنْكَشِفُ مِنْها اِلاّ ما كَشَفْتَ، وَقَدْ نَزَلَ بي يا رَبِّ ما قَدْ تَكأَّدَني ثِقْلُهُ، وَاَلَمَّ بي ما قَدْ بَهَظَني حَمْلُهُ، وَبِقُدْرَتِكَ اَوْرَدْتَهُ عَلَيَّ، وَبِسُلْطانِكَ وَجَّهْتَهُ اِلَيَّ، فَلا مُصْدِرَ لِما اَوْرَدْتَ، وَلا صارِفَ لِما وَجَّهْتَ، وَلا فاتِحَ لِما اَغْلَقْتَ، وَلا مُغْلِقَ لِما فَتَحْتَ، وَلا مُيَسِّرَ لِما عَسَّرْتَ، وَلا ناصِرَ لِمَنْ خَذَلْتَ، فَصَلِّ عَلى مُحَمَّد وآلِهِ، وَاْفْتَحْ لي يا رَبِّ بابَ الْفَرَجِ بِطَولِكَ، وَاكْسِرْ عَنّي سُلْطانَ الْهَمِّ بِحَوْلِكَ، وَاَنِلْني حُسْنَ النَّظَرِ فيـما شَكَوْتُ، وَاَذِقْني حَلاوَةَ الصُّنْعِ فيـما سَاَلْتُ ، وَهَبْ لي مِنْ لَدُنْكَ رَحْمةً وَفَرجاً هَنيئاً، وَاجْعَلْ لي مِنْ عِنْدِكَ مَخْرَجاً وَحِيّاً، وَلا تَشْغَلْني بِالاِْهتِمامِ عَنْ تَعاهُدِ فُرُوضِكَ، وَاسْتِعْمالِ سُنَّتِكَ فَقَدْ ضِقْتُ لِما نَزَلَ بي يا رَبِّ ذَرْعاً، وامْتَلأتُ بِحَمْلِ ما حَدَثَ عَليَّ هَمّاً، واَنْتَ الْقادِرُ عَلى كَشْفِ ما مُنيتُ بِهِ، وَدَفْعِ ما وَقَعْتُ فيهِ، فاَفْعَلْ بي ذلِكَ وَاِنْ لَمْ اَسْتَوْجِبْهُ مِنْكَ، يا ذَا الْعَرْشِ الْعَظيمِ، وَذَا الْمَنِّ الْكَريمِ، فَاَنْتَ قادِرٌ يا اَرْحَمَ الرّاحِمينَ، آمينَ رَبَّ الْعالَمينَ ."},{"type":"Text","content":"الحادي عشر : قال الكفعمي في البلد الامين: هذا دعاء صاحِب الامر (عليه السلام) وقد علّمه سجيناً فأطلق سراحه :"},{"type":"Text","content":"اِلـهي عَظُمَ الْبَلاءُ، وَبَرِحَ الْخَفاءُ، وَانْكَشَفَ الْغِطاءُ، وَانْقَطَعَ الرَّجاءُ، وَضاقَتِ الاَْرْضُ، وَمُنِعَتِ السَّماءُ، واَنْتَ الْمُسْتَعانُ، وَاِلَيْكَ الْمُشْتَكى، وَعَلَيْكَ الْمُعَوَّلُ فِي الشِّدَّةِ والرَّخاءِ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، اُولِي الاَْمْرِ الَّذينَ فَرَضْتَ عَلَيْنا طاعَتَهُمْ، وَعَرَّفْتَنا بِذلِكَ مَنْزِلَتَهُمْ، فَفَرِّجْ عَنا بِحَقِّهِمْ فَرَجاً عاجِلاً قَريباً كَلَمْحِ الْبَصَرِ اَوْ هُوَ اَقْرَبُ، يا مُحَمَّدُ يا عَلِيُّ يا عَلِيُّ يا مُحَمَّدُ اِكْفِياني فَاِنَّكُما كافِيانِ، وَانْصُراني فَاِنَّكُما ناصِرانِ، يا مَوْلانا يا صاحِبَ الزَّمانِ، الْغَوْثَ الْغَوْثَ الْغَوْثَ، اَدْرِكْني اَدْرِكْني اَدْرِكْني، السّاعَةَ السّاعَةَ السّاعَةَ، الْعَجَلَ الْعَجَلَ الْعَجَل، يا اَرْحَمَ الرّاحِمينَ، بِحَقِّ مُحَمَّد وَآلِهِ الطّاهِرينَ ."}],"preview":"الاوّل : قال السيّد الاجل السيّد عليخان الشيرازي رضوان الله عليه في كتاب الكلم الطيّب: انّ اسم الله الاعظم هو ما يفتتح بكلمة الله ويختتم بكلمة هو، وليس في حروفه حرف منقوط، ولا يتغي","hasTranslate":false},{"id":"mf_ar_67","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفَصلُ السّابِع :","title":"الثّاني عشر : وقال الكفعمي أيضاً في المصباح: هذا دعاء المهدي صلواتُ الله عليهِ :","blocks":[{"type":"Text","content":"اَللّـهُمَّ ارْزُقْنا تَوْفيقَ الطّاعَةِ، وَبُعْدَ الْمَعْصِيَةِ، وَصِدْقَ النِّيَّةِ، وَعِرْفانَ الْحُرْمَةِ، وَاَكْرِمْنا بِالْهُدى وَالاِْسْتِقامَةِ، وَسَدِّدْ اَلْسِنَتَنا بِالصَّوابِ وَالْحِكْمَةِ، وَامْـلاَْ قُلُوبَنا بِالْعِلْمِ وَالْمَعْرِفَةِ، وَطَهِّرْ بُطُونَنا مِنَ الْحَرامِ وَالشُّبْهَةِ، وَاكْفُفْ اَيْدِيَنا عَنِ الظُّلْمِ وَالسَّرِقَةِ، وَاغْضُضْ اَبْصارَنا عَنِ الْفُجُورِ وَالْخِيانَةِ، وَاسْدُدْ اَسْماعَنا عَنِ اللَّغْوِ وَالْغِيبَةِ، وَتَفَضَّلْ عَلى عُلَمائِنا بِالزُّهْدِ وَالنَّصيحَةِ، وَعَلَى الْمُتَعَلِّمينَ بِالْجُهْدِ وَالرَّغْبَةِ، وَعَلَى الْمُسْتَمِعينَ بِالاِْتِّباعِ وَالْمَوْعِظَةِ، وَعَلى مَرْضَى الْمُسْلِمينَ بِالشِّفاءِ وَالرّاحَةِ، وَعَلى مَوْتاهُمْ بِالرَّأفَةِ وَالرَّحْمَةِ، وَعَلى مَشايِخِنا بِالْوَقارِ وَالسَّكينَةِ، وَعَلَى الشَّبابِ بِالاِْنابَةِ وَالتَّوْبَةِ، وَعَلَى النِّساءِ بِالْحَياءِ وَالْعِفَّةِ، وَعَلَى الاَْغْنِياءِ بِالتَّواضُعِ وَالسَّعَةِ، وَعَلَى الْفُقَراءِ بِالصَّبْرِ وَالْقَناعَةِ، وَعَلَى الْغُزاةِ بِالنَّصْرِ وَالْغَلَبَةِ، وَعَلَى الاُْسَراءِ بِالْخَلاصِ وَالرّاحَةِ، وَعَلَى الاُْمَراءِ بِالْعَدْلِ وَالشَّفَقَةِ، وَعَلَى الرَّعِيَّةِ بِالاِْنْصافِ وَحُسْنِ السّيرَةِ، وَبارِكْ لِلْحُجّاجِ وَالزُّوّارِ فِي الزّادِ وَالنَّفَقَةِ، وَاقْضِ ما اَوْجَبْتَ عَلَيْهِمْ مِنَ الْحَجِّ وَالْعُمْرَةِ، بِفَضْلِكَ وَرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ ."}],"preview":"اَللّـهُمَّ ارْزُقْنا تَوْفيقَ الطّاعَةِ، وَبُعْدَ الْمَعْصِيَةِ، وَصِدْقَ النِّيَّةِ، وَعِرْفانَ الْحُرْمَةِ، وَاَكْرِمْنا بِالْهُدى وَالاِْسْتِقامَةِ، وَسَدِّدْ اَلْسِنَتَنا بِال","hasTranslate":false},{"id":"mf_ar_68","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفَصلُ السّابِع :","title":"الثّالث عشر : في المهج: انّ هذا دعاء الحجّة (عليه السلام) :","blocks":[{"type":"Text","content":"اِلـهي بِحَقِّ مَنْ ناجاكَ وَبِحَقِّ مَنْ دَعاكَ فِي الْبَرِّ وَالْبَحْرِ صَلِّ عَلى مُحَمَّد وَآلِهِ تٌفَضَّلْ عَلى فُقَراءِ الْمُؤْمِنينَ وَالْمُؤْمِناتِ باِلْغَناءِ وَالثَّرْوَةِ، وَعَلى مَرْضَى الْمُؤْمِنينَ والْمُؤْمِناتِ بِالشِّفاءِ وَالصِّحَةِ، وَعَلى اَحْياءِ الْمُؤْمِنينَ وَالْمُؤْمِناتِ بِاللُّطْفِ وَالْكَرَمِ وَعَلى اَمْواتِ الْمُؤْمِنينَ وَالْمُؤْمِناتِ بِالْمَغْفِرَةِ وَالرَّحْمَةِ، وَعَلى غُرَباءِ الْمُؤْمِنينَ وَالْمُؤْمِناتِ بِالرَّدِّ اِلى اَوْطانِهِمْ سالِمينَ غانِمينَ بِمُحَمَّد وَآلِهِ اَجْمَعينَ ."},{"type":"Text","content":"الرّابع عشر : قال السّيد عليخان في الكلم الطّيّب: هذه استغاثة بالحجّة صاحب العصر صلوات الله عليه، صلّ أينما كنت ركعتين بالحمد وما شئت من السّور، ثمّ قف مستقبل القبلة تحت السماء وقل :"},{"type":"Text","content":"سَلامُ اللهِ الْكامِلُ التّامُّ الشّامِلُ الْعامُّ، وَصَلَواتُهُ الدّائِمَةُ وَبَرَكاتُهُ الْقائِمَةُ التّامَّةُ عَلى حُجَّةِ اللهِ وَوَلِيِّهِ في اَرْضِهِ وَبِلادِهِ، وَخَليفَتِهِ عَلى خَلْقِهِ وَعِبادِهِ، وَسُلالَةِ النُّبُوَّةِ وَبَقِيَّةِ الْعِتْرَةِ وَالصَّفْوَةِ، صاحِبِ الزَّمانِ وَمُظْهِرِ الاْيمانِ، وَمُلَقِّنِ اَحْكامِ الْقُرْآنِ، وَمُطَهِّرِ الاَْرْضِ وَناشِرِ الْعَدْلِ فِي الطُّولِ وَالْعَرْضِ، وَالْحُجِّةِ الْقائِمِ الْمَهْدِيِّ الاِْمامِ الْمُنْتَظَرِ الْمَرْضِيِّ، وَابْنِ الاَْئِمَّةِ الطّاهِرينَ الْوَصِيِّ ابْنِ الاَْوْصِياءِ الْمَرْضِيّينَ الْهادِي الْمَعْصُومِ ابْنِ الاَْئِمَّةِ الْهُداةِ الْمَعْصُومينَ، السَّلامُ عَلَيْكَ يا مُعِزَّ الْمُؤْمِنينَ الْمُسْتَضْعَفينَ، السَّلامُ عَلَيْكَ يا مُذِلَّ الْكافِرينَ الْمُتَكَبِّرينَ الظّالِمينَ، اَلسَّلامُ عَلَيْكَ يا مَوْلايَ يا صاحِبَ الزَّمانِ، السَّلامُ عَلَيْكَ يَا بْنَ رَسُولِ اللهِ، اَلسَّلامُ عَلَيْكَ يَا بْنَ اَميرِ الْمُؤْمِنينَ، اَلسَّلامُ عَلَيْكَ يَا بْنَ فاطِمَةَ الزَّهْراءِ سَيِّدَةِ نِساءِ الْعالَمينَ، اَلسَّلامُ عَلَيْكَ يَا بْنَ الاَْئِمَّةِ الْحُجَجِ الْمَعْصُومينَ وَالاِْمامِ عَلَى الْخَلْقِ اَجْمَعينَ، اَلسَّلامُ عَلَيْكَ يا مَوْلايَ سَلامَ مُخْلِص لَكَ فِي الْوِلايَةِ، اَشْهَدُ اَنَّكَ الاِْمامُ الْمَهْدِىُّ قَوْلاً وَفِعْلاً، وَاَنْتَ الَّذي تَمْلاَُ الاَْرْضَ قِسْطاً وَعَدْلاً بَعْدَ ما مُلِئَتْ ظُلْماً وَجَوْراً، فَعَجَّلَ اللهُ فَرَجَكَ وَسَهَّلَ مَخْرَجَكَ وَقَرَّبَ زَمانَكَ وَكَثَّرَ اَنْصارَكَ وَاَعْوانَكَ، وَاَنْجَزَ لَكَ ما وَعَدَكَ فَهُوَ اَصْدَقُ الْقائِلينَ «وَنُريدُ اَنْ نَمُنَّ عَلَى الَّذينَ اسْتُضْعِفُوا فِي الاَْرْضِ وَنَجْعَلَهُمْ اَئِمَّةً وَنَجْعَلَهُمُ الْوارِثينَ» يا مَوْلايَ يا صاحِبَ الزَّمانِ يَا بْنَ رَسُولِ اللهِ حاجَتي كَذا وَكَذا (وَاذكُر حاجَتك عوض كلمة كذا وكذا) فَاشْفَعْ لي في نَجاحِها فَقَدْ تَوَجَّهْتُ اِلَيْكَ بِحاجَتي لِعِلْمي اَنَّ لَكَ عِنْدَ اللهِ شَفاعَةً مَقْبُولَةً وَمَقاماً مَحْمُوداً، فَبِحَقِّ مَنِ اخْتَصَّكُمْ بِاَمْرِهِ وَارْتَضاكُمْ لِسِرِّهِ، وَبِالشَّأنِ الَّذي لَكُمْ عِنْدَ اللهِ بَيْنَكُمْ وَبَيْنَهُ، سَلِ اللهَ تَعالى في نُجْحِ طَلِبَتي وَاِجابَةِ دَعْوَتي وَكَشْفِ كُرْبَتي . وسل ما تريد فانّه، يقضى إن شاء الله ."},{"type":"AboutText","content":"أقول: الاحسن أن يقرأ بعد الحمد في الرّكعة الاُولى من هذه الصّلاة سُورة انّا فَتَحنا، وَفي الثانية اِذا جاء نَصر اللهِ وَالفَتْح ."}],"preview":"اِلـهي بِحَقِّ مَنْ ناجاكَ وَبِحَقِّ مَنْ دَعاكَ فِي الْبَرِّ وَالْبَحْرِ صَلِّ عَلى مُحَمَّد وَآلِهِ تٌفَضَّلْ عَلى فُقَراءِ الْمُؤْمِنينَ وَالْمُؤْمِناتِ باِلْغَناءِ وَالثَّرْوَة","hasTranslate":false},{"id":"mf_ar_69","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفَصلُ السّابِع :","title":"الفَصْلُ الثّامِن :","blocks":[{"type":"Text","content":"في المناجيات: الخمس عَشَرة لمولانا عليّ بن الحُسين (عليهما السلام)."},{"type":"AboutText","content":"قال العلامة المجلسي (رحمه الله) في البحار: وجدتها مرويّة عنه (عليه السلام) في كتب بعض الاصحاب رضوانُ الله عَلَيهم ."}],"preview":"في المناجيات: الخمس عَشَرة لمولانا عليّ بن الحُسين (عليهما السلام).","hasTranslate":false},{"id":"mf_ar_70","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفَصلُ السّابِع :","title":"المناجاة الاُولى : « مناجاة التّائِبينَ »","blocks":[{"type":"Text","content":"اِلـهي اَلْبَسَتْنِى الْخَطايا ثَوْبَ مَذَلَّتي، وَجَلَّلَنِى التَّباعُدُ مِنْكَ لِباسَ مَسْكَنَتي، وَاَماتَ قَلْبي عَظيمُ جِنايَتي، فَاَحْيِهِ بِتَوْبَة مِنْكَ يا اَمَلي وَبُغْيَتي وَيا سُؤْلي وَمُنْيَتي، فَوَ عِزَّتِكَ ما اَجِدُ لِذُنوُبي سِواكَ غافِراً، وَلا اَرى لِكَسْري غَيْرَكَ جابِراً، وَقَدْ خَصَعْتُ بِالاِْنابَةِ اِلَيْكَ، وَعَنَوْتُ بِالاِْسْتِكانَةِ لَدَيْكَ، فَاِنْ طَرَدْتَني مِنْ بابِكَ فَبِمَنْ اَلُوذُ، وَاِنْ رَدَدْتَني عَنْ جَنابِكَ فَبِمَنْ اَعُوذُ، فَوا اَسَفاهُ مِنْ خَجْلَتي وَافْتِضاحي، وَوا لَهْفاهُ مِنْ سُوءِ عَمَلي وَاجْتِراحي، اَسْاَلُكَ يا غافِرَ الذَّنْبِ الْكَبيرِ، وَيا جابِرَ الْعَظْمِ الْكَسيرِ، اَنْ تَهَبَ لي مُوبِقاتِ الْجَرائِرِ، وَتَسْتُرَ عَلَيَّ فاضِحاتِ السَّرائِرِ، وَلا تُخْلِني في مَشْهَدِ الْقِيامَةِ مِنْ بَرْدِ عَفْوِكَ، وَغَفْرِكَ وَلا تُعْرِني مِنْ جَميلِ صَفْحِكَ وَسَتْرِكَ، اِلـهي ظَلِّلْ عَلى ذُنُوبي غَمامَ رَحْمَتِكَ، وَاَرْسِلْ عَلى عُيُوبي سَحابَ رَأفَتِكَ اِلـهي هَلْ يَرْجِعُ الْعَبْدُ الاْبِقُ اِلاّ اِلى مَوْلاهُ، اَمْ هَلْ يُجيرُهُ مِنْ سَخَطِهِ اَحَدٌ سِواهُ، اِلـهي اِنْ كانَ النَّدَمُ عَلَى الذَّنْبِ تَوْبَةً فَاِنّي وَعِزَّتِكَ مِنَ النّادِمينَ، وَاِنْ كانَ الاِْسْتِغْفارُ مِنَ الْخَطيـئَةِ حِطَّةً فَاِنّي لَكَ مِنَ الْمُسْتَغْفِرينَ، لَكَ الْعُتْبى حَتّى تَرْضى، اِلـهي بِقُدْرَتِكَ عَلَيَّ، تُبْ عَلَيَّ وَبِحِلْمِكَ عَنّىِ، اعْفُ عَنّي وَبِعِلْمِكَ بي، اَرْفِقْ بي اِلـهي اَنْتَ الَّذي فَتَحْتَ لِعِبادِكَ باباً اِلى عَفْوِكَ سَمَّيْتَهُ التَّوْبَةَ، فَقُلْتَ «تُوبُوا اِلَى اللهِ تَوْبَةً نَصُوحاً»، فَما عُذْرُ مَنْ اَغْفَلَ دُخُولَ الْبابِ بَعْدَ فَتْحِهِ، اِلـهي اِنْ كانَ قَبُحَ الذَّنْبُ مِنْ عَبْدِكَ فَلْيَحْسُنِ الْعَفْوُ مِنْ عِنْدِكَ، اِلـهي ما اَنَا بِاَوَّلِ مَنْ عَصاكَ فَتُبْتَ عَلَيْهِ، وَتَعَرَّضَ لِمَعْرُوفِكَ فَجُدْتَ عَلَيْهِ، يا مُجيبَ الْمُضْطَرِّ، يا كاشِفَ، الضُّرِّ يا عَظيمَ الْبِرِّ، يا عَليماً بِما فِي السِّرِّ، يا جَميلَ السِّتْرِ، اِسْتَشْفَعْتُ بِجُودِكَ وَكَرَمِكَ اِلَيْكَ، وَتَوَسَّلْتُ بِجَنابِكَ وَتَرَحُّمِكَ لَدَيْكَ، فَاسْتَجِبْ دُعائي وَلا تُخَيِّبْ فيكَ رَجائي، وَتَقَبَّلْ تَوْبَتي وَكَفِّرْ خَطيـئَتي بِمَنِّكَ وَرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ ."}],"preview":"اِلـهي اَلْبَسَتْنِى الْخَطايا ثَوْبَ مَذَلَّتي، وَجَلَّلَنِى التَّباعُدُ مِنْكَ لِباسَ مَسْكَنَتي، وَاَماتَ قَلْبي عَظيمُ جِنايَتي، فَاَحْيِهِ بِتَوْبَة مِنْكَ يا اَمَلي وَبُغْيَت","hasTranslate":false},{"id":"mf_ar_71","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفَصلُ السّابِع :","title":"الثّانية : « مُناجاة الشّاكين »","blocks":[{"type":"Text","content":"اِلـهي اِلَيْكَ اَشْكُو نَفْساً بِالسُّوءِ اَمّارَةً، وَاِلَى الْخَطيئَةِ مُبادِرَةً، وَبِمَعاصيكَ مُولَعَةً، وَلِسَخَطِكَ مُتَعَرِّضَةً، تَسْلُكُ بي مَسالِكَ الْمَهالِكِ، وَتَجْعَلُني عِنْدَكَ اَهْوَنَ هالِك، كَثيرَةَ الْعِلَلِ، طَويلَةَ الاَْمَلِ، اِنْ مَسَّهَا الشَّرُّ تَجْزَعُ، وَاِنْ مَسَّهَا الْخَيْرُ تَمْنَعُ، مَيّالَةً اِلَى اللَّعِبِ وَالَلَّهْوِ مَمْلُؤةً بِالْغَفْلَةِ وَالسَّهْوِ، تُسْرِ عُ بي اِلَى الْحَوْبَةِ وَتُسَوِّفُني بِالتَّوْبَةِ، اِلـهي اَشْكُو اِلَيْكَ عَدُوّاً يُضِلُّني، وَشَيْطاناً يُغْويني، قَدْ مَلاََ بِالْوَسْواسِ صَدْري، وَاَحاطَتْ هَواجِسُهُ بِقَلْبي، يُعاضِدُ لِيَ الْهَوى، وَيُزَيِّنُ لي حُبَّ الدُّنْيا وَيَحُولُ بَيْني وَبَيْنَ الطّاعَةِ وَالزُّلْفى، اِلـهي اِلَيْكَ اَشْكُو قَلْباً قاسِياً مَعَ الْوَسْواسِ مُتَقَلِّباً، وَبِالرَّيْنِ وَالطَّبْعِ مُتَلَبِّساً، وَعَيْناً عَنِ الْبُكاءِ مِنْ خَوْفِكَ جامِدَةً، وِ اِلى ما يَسٌرُّها طامِحَةً، اِلـهي لا حَوْلَ لي وَلا قُوَّةَ اِلاّ بِقُدْرَتِكَ، وَلا نَجاةَ لي مِنْ مَكارِهِ الدُّنْيا اِلاّ بِعِصْمَتِكَ، فَاَسْألُكَ بِبَلاغَةِ حِكْمَتِكَ وَنَفاذِ مَشِيَّتِكَ، اَنْ لا تَجْعَلَني لِغَيْرِ جُوْدِكَ مُتَعَرِّضاً، وَلا تُصَيِّرَني لِلْفِتَنِ غَرَضاً، وَكُنْ لي عَلَى الاَْعْداءِ ناصِراً، وَعَلَى الَْمخازي وَالْعُيُوبِ ساتِراً، وَمِنَ الْبَلاءِ واقِياً، وَعَنِ الْمَعاصي عاصِماً بِرَأْفَتِكَ وَرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ ."}],"preview":"اِلـهي اِلَيْكَ اَشْكُو نَفْساً بِالسُّوءِ اَمّارَةً، وَاِلَى الْخَطيئَةِ مُبادِرَةً، وَبِمَعاصيكَ مُولَعَةً، وَلِسَخَطِكَ مُتَعَرِّضَةً، تَسْلُكُ بي مَسالِكَ الْمَهالِكِ، وَتَجْعَ","hasTranslate":false},{"id":"mf_ar_72","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفَصلُ السّابِع :","title":"الثّالِثة : « مُناجاة الخآئِفينَ »","blocks":[{"type":"Text","content":"اِلـهي اَتَراكَ بَعْدَ الاْيمانِ بِكَ تُعَذِّبُني، اَمْ بَعْدَ حُبّي اِيّاكَ تُبَعِّدُني، اَمْ مَعَ رَجائي لِرَحْمَتِكَ وَصَفْحِكَ تَحْرِمُني، اَمْ مَعَ اسْتِجارَتي بِعَفْوِكَ تُسْلِمُني، حاشا لِوَجْهِكَ الْكَريمِ اَنْ تُخَيِّبَني، لَيْتَ شِعْري اَلِلشَّقاءِ وَلَدَتْني اُمّي، اَمْ لِلْعَناءِ رَبَّتْني، فَلَيْتَها لَمْ تَلِدْني وَلَمْ تُرَبِّني، وَلَيْتَني عَلِمْتُ اَمِنْ اَهْلِ السَّعادَةِ جَعَلْتَني وَبِقُرْبِكَ وَجِوارِكَ خَصَصْتَني، فَتَقِرَّ بِذلِكَ عَيْني وَتَطْمَئِنَّ لَهُ نَفْسي، اِلـهي هَلْ تُسَوِّدُ وُجُوهاً خَرَّتْ ساجِدةً لِعَظَمَتِكَ، اَوْ تُخْرِسُ اَلْسِنَةً نَطَقَتْ بِالثَّناءِ عَلى مَجْدِكَ وَجَلالَتِكَ، اَوْ تَطْبَعُ عَلى قُلُوب انْطَوَتْ عَلى مَحَبَّتِكَ، اَوْ تُصِمُّ اَسْماعاً تَلَذَّذَتْ بِسَماعِ ذِكْرِكَ في اِرادَتِكَ، اَوْ تَغُلُّ اَكُفَّاً رَفَعَتْهَا الاْمالُ اِلَيْكَ رَجاءَ رَأفَتِكَ، اَوْ تُعاقِبُ اَبْداناً عَمِلَتْ بِطاعَتِكَ حَتّى نَحِلَتْ في مُجاهَدَتِكَ، اَوْ تُعَذِّبُ اَرْجُلاً سَعَتْ في عِبادَتِكَ، اِلـهي لا تُغْلِقْ عَلى مُوَحِّديكَ اَبْوابَ رَحْمَتِكَ، وَلا تَحْجُبْ مُشْتاقيكَ عَنِ النَّظَرِ اِلى جَميلِ رُؤْيَتِكَ، اِلـهي نَفْسٌ اَعْزَزْتَها بِتَوْحيدِكَ كَيْفَ تُذِلُّها بِمَهانَةِ هِجْرانِكَ، وَضَميرٌ انْعَقَدَ عَلى مَوَدَّتِكَ كَيْفَ تُحْرِقُهُ بِحَرارَةِ نيرانِكَ، اِلـهي اَجِرْني مِنْ أليمِ غَضَبِكَ وَعَظيمِ سَخَطِكَ يا حَنّانُ يا مَنّانُ، يا رَحيمُ يا رَحْمنُ، يا جَبّارُ يا قَهّارُ، يا غَفّارُ يا سَتّارُ، نَجِّني بِرَحْمَتِكَ مَنْ عَذابِ النّارِ وَفَضيحَةِ الْعارِ، اِذَا امْتازَ الاَْخْيارُ مِنَ الاَْشْرارِ، وَحالَتِ الاَْحْوالُ وَهالَتِ الاَْهْوالُ، وَقَرُبَ الُْمحْسِنُونَ وَبَعُدَ الْمُسيـئُونَ، وَوُفّيَتْ كُلُّ نَفْس ما كَسَبَتْ وَهُمْ لا يُظْلَمُونَ ."}],"preview":"اِلـهي اَتَراكَ بَعْدَ الاْيمانِ بِكَ تُعَذِّبُني، اَمْ بَعْدَ حُبّي اِيّاكَ تُبَعِّدُني، اَمْ مَعَ رَجائي لِرَحْمَتِكَ وَصَفْحِكَ تَحْرِمُني، اَمْ مَعَ اسْتِجارَتي بِعَفْوِكَ تُسْ","hasTranslate":false},{"id":"mf_ar_73","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفَصلُ السّابِع :","title":"الرّابِعَة : « مُناجاة الرّاجِين »","blocks":[{"type":"Text","content":"يا مَنْ اِذا سَأَلَهُ عَبْدٌ اَعْطاهُ، وَاِذا اَمَّلَ ما عِنْدَهُ بَلَّغَهُ مُناهُ، وَاِذا اَقْبَلَ عَلَيْهِ قَرَّبَهُ وَاَدْناهُ، وَاِذا جاهَرَهُ بِالْعِصْيانِ سَتَرَ عَلى ذَنْبِهِ وَغَطّاهُ، وَاِذا تَوَكَّلَ عَلَيْهِ اَحْسَبَهُ وَكَفاهُ، اِلـهي مَنِ الَّذي نَزَلَ بِكَ مُلْتَمِساً قِراكَ فَما قَرَيْتَهُ، وَمَنِ الَّذي اَناخَ بِبابِكَ مُرْتَجِياً نَداكَ فَما اَوْلَيْتَهُ، اَيَحْسُنُ اَنْ اَرْجِعَ عَنْ بابِكَ بِالْخَيْبَةِ مَصْرُوفاً وَلَسْتُ اَعْرِفُ سِواكَ مَوْلىً بِالاِْحْسانِ مَوْصُوفاً، كَيْفَ اَرْجُو غَيْرَكَ وَالْخَيْرُ كُلُّهُ بِيَدِكَ، وَكَيْفَ اُؤَمِّلُ سِواكَ وَالْخَلْقُ وَالاَْمْرُ لَكَ، أَاَقْطَعُ رَجائي مِنْكَ وَقَدْ اَوْلَيْتَني ما لَمْ اَسْأَلْهُ مِنْ فَضْلِكَ اَمْ تُفْقِرُني اِلى مِثْلي وَاَنـَا اَعْتَصِمُ بِحَبْلِكَ، يا مَنْ سَعِدَ بِرَحْمَتِهِ الْقاصِدُونَ، وَلَمْ يَشْقَ بِنِقْمَتِهِ الْمُسْتَغْفِرُونَ، كَيْفَ اَنْساكَ وَلَمْ تَزَلْ ذاكِري، وَكَيْفَ اَلْهُو عَنْكَ وَاَنْتَ مُراقِبي، اِلـهي بِذَيْلِ كَرَمِكَ اَعْلَقْتُ يَدي، وَلِنَيْلِ عَطاياكَ بَسَطْتُ اَمَلي، فَاَخْلِصْني بِخالِصَةِ تَوْحيدِكَ، وَاجْعَلْني مِنْ صَفْوَةِ عَبيدِكَ، يا مَنْ كُلُّ هارِب اِلَيْهِ يَلْتَجِئُ، وَكُلُّ طالِب اِيّاهُ يَرْتَجي، يا خَيْرَ مَرْجُوٍّ وَيا اَكْرَمَ مَدْعُوٍّ، وَيا مَنْ لا يَرُدُّ سائِلَهُ وَلا يُخَيِّبُ امِلَهُ، يا مَنْ بابُهُ مَفْتُوحٌ لِداعيهِ، وَحِجابُهُ مَرْفُوعٌ لِراجيهِ، اَسْاَلُكَ بِكَرَمِكَ اَنْ تَمُنَّ عَلَيَّ مِنْ عَطائِكَ بِما تَقِرُّ بِهِ عَيْني، وَمِنْ رَجائِكَ بِما تَطْمَئِنُّ بِهِ نَفْسي، وَمِنَ الْيَقينِ بِما تُهَوِّنُ بِهِ عَلَيَّ مُصيباتِ الدُّنْيا، وَتَجْلُو بِهِ عَنْ بَصيرَتي غَشَواتِ الْعَمى، بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ ."}],"preview":"يا مَنْ اِذا سَأَلَهُ عَبْدٌ اَعْطاهُ، وَاِذا اَمَّلَ ما عِنْدَهُ بَلَّغَهُ مُناهُ، وَاِذا اَقْبَلَ عَلَيْهِ قَرَّبَهُ وَاَدْناهُ، وَاِذا جاهَرَهُ بِالْعِصْيانِ سَتَرَ عَلى ذَنْبِه","hasTranslate":false},{"id":"mf_ar_74","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفَصلُ السّابِع :","title":"الخامِسة : « مُناجاة الرّاغِبين »","blocks":[{"type":"Text","content":"اِلـهي اِنْ كانَ قَلَّ زادي فِي الْمَسيرِ اِلَيْكَ فَلَقَدْ حَسُنَ ظَنّي بِالتَّوَكُّلِ عَلَيْكَ، وَاِنْ كانَ جُرْمي قَدْ اَخافَني مِنْ عُقُوبَتِكَ فَاِنَّ رَجائي قَدْ اَشْعَرَني بِالاْمْنِ مِنْ نِقْمَتِكَ، وَاِنْ كانَ ذَنْبي قَدْ عَرَضَني لِعِقابِكَ فَقَدْ اذَنَني حُسْنُ ثِقَتي بِثَوابِكَ، وَاِنْ اَنامَتْنِي الْغَفْلَةُ عَنِ الاِْسْتِعْدادِ لِلِقائِكَ فَقَدْ نَبَّهَتْنِى الْمَعْرِفَةُ بِكَرَمِكَ وَآلائِكَ، وَاِنْ اَوْحَشَ ما بَيْني وَبَيْنَكَ فَرْط الْعِصْيانِ وَالطُّغْيانِ فَقَدْ انَسَني بُشْرَى الْغُفْرانِ وَالرِّضْوانِ، اَسْاَلُكَ بِسُبُحاتِ وَجْهِكَ وَبِاَنْوارِ قُدْسِكَ، وَاَبْتَهِلُ اِلَيْكَ بِعَواطِفِ رَحْمَتِكَ وَلَطائِفِ بِرِّكَ اَنْ تُحَقِّقَ ظَنّي بِما اُؤَمِّلُهُ مِنْ جَزيلِ اِكْرامِكَ، وَجَميلِ اِنْعامِكَ فِي الْقُرْبى مِنْكَ وَالزُّلْفى لَدَيْكَ وَالَّتمَتُعِّ بِالنَّظَرِ اِلَيْكَ، وَها اَنـَا مُتَعَرِّضٌ لِنَفَحاتِ رَوْحِكَ وَعَطْفِكَ، وَمُنْتَجِعٌ غَيْثَ جُودِكَ وَلُطْفِكَ، فارٌّ مِنْ سَخَطِكَ اِلى رِضاكَ، هارِبٌ مِنْكَ اِلَيْكَ، راج اَحْسَنَ ما لَدَيْكَ، مُعَوِّلٌ عَلى مَواهِبِكَ، مُفْتَقِرٌ اِلى رِعايَتِكَ، اِلـهي ما بَدَاْتَ بِهِ مِنْ فَضْلِكَ فَتَمِّمْهُ، وَما وَهَبْتَ لي مِنْ كَرَمِكَ فَلا تَسْلُبْهُ، وَما سَتَرْتَهُ عَلَيَّ بِحِلْمِكَ فَلا تَهْتِكْهُ، وَما عَلِمْتَهُ مِنْ قَبيحِ فِعْلي فَاغْفِرْهُ، اِلـهي اِسْتَشْفَعْتُ بِكَ اِلَيْكَ، وَاسْتَجَرْتُ بِكَ مِنْكَ، اَتَيْتُكَ طامِعاً في اِحْسانِكَ، راغِباً فِي امْتِنانِكَ، مُسْتَسقِياً وابِلَ طَوْلِكَ، مُسْتَمْطِراً غَمامَ فَضْلِكَ، طالِباً مَرْضاتَكَ، قاصِداً جَنابَكَ، وارِداً شَريعَةَ رِفْدِكَ، مُلْتَمِساً سَنِيَّ الْخَيْراتِ مِنْ عِنْدِكَ، وافِداً اِلى حَضْرَةِ جَمالِكَ، مُريداً وَجْهَكَ، طارِقاً بابَكَ، مُسْتَكيناً لِعَظَمَتِكَ وَجَلالِكَ، فَافْعَلْ بي ما اَنْتَ اَهْلُهُ مِنَ الْمَغْفِرَةِ وَالرَّحْمَةِ وَلا تَفْعَلْ بي ما اَنَا اَهْلُهُ مِنْ الْعَذابِ وَالنَّقْمَةِ بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ ."}],"preview":"اِلـهي اِنْ كانَ قَلَّ زادي فِي الْمَسيرِ اِلَيْكَ فَلَقَدْ حَسُنَ ظَنّي بِالتَّوَكُّلِ عَلَيْكَ، وَاِنْ كانَ جُرْمي قَدْ اَخافَني مِنْ عُقُوبَتِكَ فَاِنَّ رَجائي قَدْ اَشْعَرَني ب","hasTranslate":false},{"id":"mf_ar_75","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفَصلُ السّابِع :","title":"السّادِسة : « مُناجاة الشّاكِرين »","blocks":[{"type":"Text","content":"اِلـهي اَذْهَلَني عَنْ اِقامَةِ شُكْرِكَ تَتابُعُ طَوْلِكَ، وَاَعْجَزَني عَنْ اِحْصاءِ ثَنائِكَ فَيْضُ فَضْلِكَ، وَشَغَلَني عَنْ ذِكْرِ مَحامِدِكَ تَرادُفُ عَوائِدِكَ، وَاَعْياني عَنْ نَشْرِ عَوارِفِكَ تَوالي اَياديكَ، وَهذا مَقامُ مَنِ اعْتَرَفَ بِسُبُوغِ النَّعْماءِ وَقابَلَها بِالتَّقْصيرِ، وَشَهِدَ عَلى نَفْسِهِ بِالاِْهْمالِ وَالتَّضْييعِ، وَاَنْتَ الرَّؤوفُ الرَّحيمُ الْبَّرُ الْكَريمُ، الَّذي لا يُخَيِّبُ قاصِديهِ وَلا يَطْرُدُ عَنْ فِنائِهِ امِليهِ، بِساحَتِكَ تَحُطُّ رِحالُ الرّاجينَ، وَبِعَرْصَتِكَ تَقِفُ امالُ الْمُسْتَرْفِدينَ، فَلا تُقابِلْ امالَنا بِالتَّخْييبِ وَالاِْياسِ، وَلا تُلْبِسْنا سِرْبالَ الْقُنُوطِ وَالاِْبْلاسِ، اِلـهي تَصاغَرَ عِنْدَ تَعاظُمِ الائِكَ شُكْري وَتَضاءَلَ في جَنْبِ اِكْرامِكَ اِيّايَ ثَنائي وَنَشْري، جَلَّلَتْني نِعَمُكَ مِنْ اَنْوارِ الاْيمانِ حُلَلاً، وَضَرَبَتْ عَلَيَّ لَطائِفُ بِرّكَ مِنَ الْعِزِّ كِلَلاً، وَقَلَّدَتْني مِنَنُكَ قَلائِدَ لا تُحَلُّ، وَطَوَّقَتْني اَطْواقاً لا تُفَلُّ فَآلاؤُكَ جَمَّةٌ ضَعُفَ لِساني عَنْ اِحْصائِها، وَنَعْماؤُكَ كَثيرَةٌ قَصُرَ فَهْمي عَنْ اِدْراكِها فَضْلاً عَنِ اسْتِقْصائِها، فَكَيْفَ لي بِتَحْصيلِ الشُّكْرِ وَشُكْري اِيّاكَ يَفْتَقِرُ اِلى شُكْر، فَكُلَّما قُلْتُ لَكَ الْحَمْدُ وَجَبَ لِذلِكَ اَنْ اَقُولَ لَكَ الْحَمْدُ، اِلـهي فَكَما غَذَّيْتَنا بِلُطْفِكَ وَرَبَّيْتَنا بِصُنْعِكَ فَتَمِّمْ عَلَيْنا سَوابِـغَ النِّعَمِ وَادْفَعْ عَنّا مَكارِهَ النِّقَمِ، وَآتِنا مِنْ حُظُوظِ الدّارَيْنِ اَرْفَعَها وَاَجَلَّها عاجِلاً وَآجِلاً، وَلَكَ الْحَمْدُ عَلى حُسْنِ بَلائِكَ وَسُبُوغِ نَعْمائِكَ حَمْداً يُوافِقُ رِضاكَ، وَيَمتَرِى الْعَظيمَ مِنْ بِرِّكَ وَنَداكَ، يا عَظيمُ يا كَريمُ بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ ."}],"preview":"اِلـهي اَذْهَلَني عَنْ اِقامَةِ شُكْرِكَ تَتابُعُ طَوْلِكَ، وَاَعْجَزَني عَنْ اِحْصاءِ ثَنائِكَ فَيْضُ فَضْلِكَ، وَشَغَلَني عَنْ ذِكْرِ مَحامِدِكَ تَرادُفُ عَوائِدِكَ، وَاَعْياني ع","hasTranslate":false},{"id":"mf_ar_76","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفَصلُ السّابِع :","title":"السّابعة : « مُناجاة المُطيعين للهِ »","blocks":[{"type":"Text","content":"اَلّلهُمَّ اَلْهِمْنا طاعَتَكَ، وَجَنِّبْنا مَعْصِيَتَكَ، وَيَسِّرْ لَنا بُلُوغَ ما نَتَمَنّى مِنِ ابْتِغاءِ رِضْوانِكَ، وَاَحْلِلْنا بُحْبُوحَةَ جِنانِكَ، وَاقْشَعْ عَنْ بَصائِرِنا سَحابَ الاْرْتِيابِ، وَاكْشِفْ عَنْ قُلُوبِنا اَغْشِيَةَ الْمِرْيَةِ وَالْحِجابِ، وَاَزْهَقِ الْباطِلَ عَنْ ضَمائِرِنا، وَاَثْبِتِ الْحَقَّ في سَرائِرِنا، فَاِنَّ الشُّكُوكَ وَالظُّنُونَ لَواقِحُ الْفِتَنِ، وَمُكَدِّرَةٌ لِصَفْوِ الْمَنايِـحِ وَالْمِنَنِ، اَلّلهُمَّ احْمِلْنا في سُفُنِ نَجاتِكَ وَمَتِّعْنا بِلَذيذِ مُناجاتِكَ، وَاَوْرِدْنا حِياضَ حُبِّكَ، وَاَذِقْنا حَلاوَةَ وُدِّكَ وَقُرْبِكَ، وَاجْعَلْ جِهادَنا فيكَ، و هَمَّنا في طاعَتِكَ، وَاَخْلِصْ نِيّاتِنا في مُعامَلَتِكَ، فَاِنّا بِكَ وَلَكَ وَلا وَسيلَةَ لَنا اِلَيْكَ اِلاّ اَنْتَ، اِلـهي اِجْعَلْني مِنَ الْمُصْطَفَيْنَ الاَْخْيارِ، وَاَلْحِقْني بِالصّالِحينَ الاَْبْرارِ، السّابِقينَ اِليَ الْمَكْرُماتِ الْمُسارِعينَ اِلَى الْخَيْراتِ، الْعامِلينَ لِلْباقِياتِ الصّالِحاتِ، السّاعينَ اِلى رَفيعِ الدَّرَجاتِ، اِنَّكَ عَلى كُلِّ شَيْء قَديرٌ، وَبِالاِْجابَةِ جَديرٌ بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ ."}],"preview":"اَلّلهُمَّ اَلْهِمْنا طاعَتَكَ، وَجَنِّبْنا مَعْصِيَتَكَ، وَيَسِّرْ لَنا بُلُوغَ ما نَتَمَنّى مِنِ ابْتِغاءِ رِضْوانِكَ، وَاَحْلِلْنا بُحْبُوحَةَ جِنانِكَ، وَاقْشَعْ عَنْ بَصائِرِن","hasTranslate":false},{"id":"mf_ar_77","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفَصلُ السّابِع :","title":"الثّامِنة : « مُناجاة المُريدين »","blocks":[{"type":"Text","content":"سُبْحانَكَ ما اَضْيَقَ الْطُّرُقَ عَلى مَنْ لَمْ تَكُنْ دَليلَهُ، وَما اَوْضَحَ الْحَقَّ عِنْدَ مَنْ هَدَيْتَهُ سَبيلَهُ، اِلـهي فَاسْلُكْ بِنا سُبُلَ الْوُصُولِ اِلَيْكَ، وَسَيِّرْنا في اَقْرَبِ الطُّرُقِ لِلْوُفُودِ عَلَيْكَ، قَرِّبْ عَلَيْنَا الْبَعيدَ وَسَهِّلْ عَلَيْنَا الْعَسيرَ الشَّديدَ، وَاَلْحِقْنا بِعِبادِكَ الَّذينَ هُمْ بِالْبِدارِ اِلَيْكَ يُسارِعُونَ، وَبابَكَ عَلَى الدَّوامِ يَطْرُقُونَ، وَاِيّاكَ فِي اللَّيْلِ وَالنَّهارِ يَعْبُدُونَ، وَهُمْ مِنْ هَيْبَتِكَ مُشْفِقُونَ، الَّذينَ صَفَّيْتَ لَهُمُ الْمَشارِبَ وَبَلَّغْتَهُمُ الرَّغائِبَ، وَاَنْجَحْتَ لَهُمُ الْمَطالِبَ، وَقَضَيْتَ لَهُمْ مِنْ فَضْلِكَ الْمَآرِبَ، وَمَلاَْتَ لَهُمْ ضَمائِرَهُمْ مِنْ حُبِّكَ، وَرَوَّيْتَهُمْ مِنْ صافي شِرْبِكَ، فَبِكَ اِلى لَذيذِ مُناجاتِكَ وَصَلُوا، وَمِنْكَ اَقْصى مَقاصِدِهِمْ حَصَّلُوا، فَيا مَنْ هُوَ عَلَى الْمُقْبِلينَ عَلَيْهِ مُقْبِلٌ، وَبِالْعَطْفِ عَلَيْهِمْ عائِدٌ مُفْضِلٌ، وَبِالْغافِلينَ عَنْ ذِكْرِهِ رَحيمٌ رَؤوفٌ وَبِجَذْبِهِمْ اِلى بابِهِ وَدُودٌ عَطُوفٌ، اَسْاَلُكَ اَنْ تَجْعَلَني مِنْ اَوْفَرِهِمْ مِنْكَ حَظّاً، وَاَعْلاهُمْ عِنْدَكَ مَنْزِلاً، وَاَجْزَلِهِمْ مِنْ وُدِّكَ قِسْماً، وَاَفْضَلِهِمْ في مَعْرِفَتِكَ نَصيباً، فَقَدِ انْقَطَعَتْ اِلَيْكَ هِمَّتي، وَانْصَرَفَتْ نَحْوَكَ رَغْبَتي، فَاَنْتَ لا غَيْرُكَ مُرادي، وَلَكَ لا لِسِواكَ سَهَري وَسُهادي، وَلِقاؤُكَ قُرَّةُ عَيْني، وَوَصْلُكَ مُنى نَفْسي، وَاِلَيْكَ شَوْقي، وَفي مَحَبَّتِكَ وَلَهي، وَاِلى هَواكَ صَبابَتي، وَرِضاكَ بُغْيَتي، وَرُؤْيَتَكَ حاجَتي وَجِوارُكَ طَلَبي، وَقُرْبُكَ غايَةُ سُؤْلي، وَفي مُناجاتِكَ رَوْحي وَراحَتي، وَعِنْدَكَ دَواءُ عِلَّتي وَشِفاءُ غُلَّتي، وَبَرْدُ لَوْعَتي، وَكَشْفُ كُرْبَتي، فَكُنْ اَنيسي في وَحْشَتي، وَمُقيلَ عَثْرَتي، وَغافِرَ زَلَّتي، وَقابِلَ تَوْبَتي، وَمُجيبَ دَعْوَتي، وَوَلِيَّ عِصْمَتي، وَمُغْنِيَ فاقَتي، وَلا تَقْطَعْني عَنْكَ، وَلا تُبْعِدْني مِنْكَ، يا نَعيمي وَجَنَّتي، وَيا دُنْيايَ وَآخِرَتي، يا اَرْحَمَ الرّاحِمينَ ."}],"preview":"سُبْحانَكَ ما اَضْيَقَ الْطُّرُقَ عَلى مَنْ لَمْ تَكُنْ دَليلَهُ، وَما اَوْضَحَ الْحَقَّ عِنْدَ مَنْ هَدَيْتَهُ سَبيلَهُ، اِلـهي فَاسْلُكْ بِنا سُبُلَ الْوُصُولِ اِلَيْكَ، وَسَيِّر","hasTranslate":false},{"id":"mf_ar_78","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفَصلُ السّابِع :","title":"التّاسعة : « مُناجاة الُمحبيّن »","blocks":[{"type":"Text","content":"اِلـهي مَنْ ذَا الَّذي ذاقَ حَلاوَةَ مَحَبَّتِكَ فَرامَ مِنْكَ بَدَلاً، وَمَنْ ذَا الَّذي اَنـِسَ بِقُرْبِكَ فَابْتَغى عَنْكَ حِوَلاً، اِلـهي فَاجْعَلْنا مِمَّنِ اصْطَفَيْتَهُ لِقُرْبِكَ وَوِلايَتِكَ، وَاَخْلَصْتَهُ لِوُدِّكَ وَمَحَبَّتِكَ، وَشَوَّقْتَهُ اِلى لِقائِكَ، وَرَضَّيْتَهُ بِقَضائِكَ، وَمَنَحْتَهُ بِالنَّظَرِ اِلى وَجْهِكَ، وَحَبَوْتَهُ بِرِضاكَ، وَاَعَذْتَهُ مِنْ هَجْرِكَ وَقِلاكَ، وَبَوَّأتَهُ مَقْعَدَ الصِّدْقِ في جِوارِكَ، وَخَصَصْتَهُ بِمَعْرِفَتِكَ، وَاَهَّلْتَهُ لِعِبادَتِكَ، وَهَيَّمْتَ قَلْبَهُ لاِِرادَتِكَ، وَاجْتَبَيْتَهُ لِمُشاهَدَتِكَ، وَاَخْلَيْتَ وَجْهَهُ لَكَ، وَفَرَّغْتَ فُؤادَهُ لِحُبِّكَ، وَرَغَّبْتَهُ فيـما عِنْدَكَ، وَاَلْهَمْتَهُ ذِكْرَكَ، وَاَوْزَعْتَهُ شُكْرَكَ، وَشَغَلْتَهُ بِطاعَتِكَ، وَصَيَّرْتَهُ مِنْ صالِحي بَرِيَّتِكَ، وَاخْتَرْتَهُ لِمُناجاتِكَ، وَقَطَعْتَ عَنْهُ كُلَّ شَيْء يَقْطَعُهُ عَنْكَ، اَلّلهُمَّ اجْعَلْنا مِمَّنْ دَأْبُـهـُمُ الاِْرْتِياحُ اِلَيْكَ وَالْحَنينُ، وَدَهْرُهُمُ الزَّفْرَةُ وَالاَْنينُ، جِباهُهُمْ ساجِدَةٌ لِعَظَمَتِكَ، وَعُيُونُهُمْ ساهِرَةٌ في خِدْمَتِكَ، وَدُمُوعُهُمْ سائِلَةٌ مِنْ خَشْيَتِكَ، وَقُلُوبُهُمْ مُتَعَلِّقَةٌ بِمَحَبَّتِكَ، وَاَفْئِدَتُهُمْ مُنْخَلِعَةٌ مِنْ مَهابَتِكَ، يا مَنْ اَنْوارُ قُدْسِهِ لاَِبْصارِ مُحِبّيهِ رائِقَةٌ، وَسُبُحاتُ وَجْهِهِ لِقُلُوبِ عارِفيهِ شائِقَةٌ، يا مُنى قُلُوبِ الْمُشْتاقينَ، وَيا غايَةَ آمالِ الُْمحِبّينَ، اَسْاَلُكَ حُبَّكَ وَحُبَّ مَنْ يُحِبُّكَ وَحُبَّ كُلِّ عَمَل يُوصِلُني اِلى قُرْبِكَ، وَاَنْ تَجْعَلَكَ اَحَبَّ اِلَيَّ مِمّا سِواكَ، وَاَنْ تَجْعَلَ حُبّي اِيّاكَ قائِداً اِلى رِضْوانِكَ، وَشَوْقي اِلَيْكَ ذائِداً عَنْ عِصْيانِكَ، وَامْنُنْ بِالنَّظَرِ اِلَيْكَ عَلَيَّ، وَانْظُرْ بِعَيْنِ الْوُدِّ وَالْعَطْفِ اِلَىّ، وَلا تَصْرِفْ عَنّي وَجْهَكَ، وَاجْعَلْني مِنْ اَهْلِ الاِْسْعادِ وَالْحَظْوَةِ عِنْدَكَ، يا مُجيبُ يا اَرْحَمَ الرّاحِمينَ ."}],"preview":"اِلـهي مَنْ ذَا الَّذي ذاقَ حَلاوَةَ مَحَبَّتِكَ فَرامَ مِنْكَ بَدَلاً، وَمَنْ ذَا الَّذي اَنـِسَ بِقُرْبِكَ فَابْتَغى عَنْكَ حِوَلاً، اِلـهي فَاجْعَلْنا مِمَّنِ اصْطَفَيْتَهُ لِقُ","hasTranslate":false},{"id":"mf_ar_79","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفَصلُ السّابِع :","title":"العاشِرَة : « مُناجاة المُتوَسِّلين »","blocks":[{"type":"Text","content":"اِلـهي لَيْسَ لي وَسيلَةٌ اِلَيْكَ اِلاّ عَواطِفُ رَأفَتِكَ، وَلا لي ذَريعَةٌ اِلَيْكَ اِلاّ عَوارِفُ رَحْمَتِكَ، وَشَفاعَةُ نَبِيِّكَ نَبِيِّ الرَّحْمَةِ، وَمُنْقِذِ الاُْمَّةِ مِنَ الْغُمَّةِ، فَاجْعَلْهُما لي سَبَباً اِلى نَيْلِ غُفْرانِكَ، وَصَيِّرْهُما لي وُصْلَةً اِليَ الْفَوْزِ بِرِضْوانِكَ، وَقَدْ حَلَّ رَجائي بِحَرَمِ كَرَمِكَ، وَحَطَّ طَمَعي بِفِناءِ جُودِكَ، فَحَقِّقْ فيكَ اَمَلي، وَاخْتِمْ بِالْخَيْرِ عَمَلي، وَاجْعَلْني مِنْ صَفْوَتِكَ الَّذينَ اَحْلَلْتَهُمْ بُحْبُوحَةَ جنَّتِكَ، وَبوَّأْتَهُمْ دارَ كَرامَتِكَ، وَاَقْرَرْتَ اَعْيُنَهُمْ بِالنَّظَرِ اِلَيْكَ يَوْمَ لِقائِكَ، وَاَوْرَثْتَهُمْ مَنازِلَ الصِّدْقِ في جِوارِكَ، يا مَنْ لا يَفِدُ الْوافِدُونَ عَلى اَكْرَمَ مِنْهُ، وَلا يَجِدُ الْقاصِدُونَ اَرْحَمَ مِنْهُ، يا خَيْرَ مَنْ خَلا بِهِ وَحيدٌ، وَيا اَعْطَفَ مَنْ اَوى اِلَيْهِ طَريدٌ، اِلى سَعَةِ عَفْوِكَ مَدَدْتُ يَدي، وَبِذَيْلِ كَرَمِكَ اَعْلَقْتُ كَفّي، فَلا تُولِنِي الْحِرْمانَ، وَلا تُبْلِني بِالْخَيْبَةِ وَالْخُسْرانِ، يا سَميعَ الدٌّعاءِ يا اَرْحَمَ الرّحِمينَ ."}],"preview":"اِلـهي لَيْسَ لي وَسيلَةٌ اِلَيْكَ اِلاّ عَواطِفُ رَأفَتِكَ، وَلا لي ذَريعَةٌ اِلَيْكَ اِلاّ عَوارِفُ رَحْمَتِكَ، وَشَفاعَةُ نَبِيِّكَ نَبِيِّ الرَّحْمَةِ، وَمُنْقِذِ الاُْمَّةِ مِ","hasTranslate":false},{"id":"mf_ar_80","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفَصلُ السّابِع :","title":"الحادِية عَشرَة : « مُناجاة المُفتقرينْ »","blocks":[{"type":"Text","content":"اِلـهي كَسْري لا يَجْبُرُهُ اِلاّ لُطْفُكَ وَحَنانُكَ، وَفَقْري لايُغْنيهِ اِلاّ عَطْفُكَ وَاِحْسانُكَ، وَرَوْعَتي لا يُسَكِّنُهااَمانُكَ، وَذِلَّتي لا يُعِزُّها اِلاّ سُلْطانُكَ، وَاُمْنِيَّتي لا يُبَلِّغُنيها اِلاّ فَضْلُكَ، وَخَلَّتي لا يَسُدُّها اِلاّ طَوْلُكَ، وَحاجَتي لا يَقْضيها غَيْرُكَ، وَكَرْبي لا يُفَرِّجُهُ سِوى رَحْمَتِكَ، وَضُرّي لا يَكْشِفُهُ غَيْرُ رَأفَتِكَ، وَغُلَّتي لا يُبَرِّدُها اِلاّ وَصْلُكَ، وَلَوْعَتي لا يُطْفيها اِلاّ لِقاؤُكَ، وَشَوْقي اِلَيْكَ لا يَبُلُّهُ إلاّ النَّظَرُ اِلى وَجْهِكَ، وَقَراري لا يَقِّرُّ دُونَ دُنُوّي مِنْكَ، وَلَهْفَتي لا يَرُدُّها اِلاّ رَوْحُكَ، وَسُقْمي لا يَشْفيهِ اِلاّ طِبُّكَ، وَغَمّي لا يُزيلُهُ اِلاّ قُرْبُكَ، وَجُرْحي لا يُبْرِئُهُ اِلاّ صَفْحُكَ، وَرَيْنُ قَلْبي لا يَجْلُوهُ اِلاّ عَفْوُكَ، وَوَسْواسُ صَدْري لا يُزيحُهُ اِلاّ اَمْرُكَ، فَيا مُنْتَهى اَمَلِ الاْمِلينَ، وَيا غايَةَ سُؤْلِ السّائِلينَ، وَيا اَقْصى طَلِبَةِ الطّالِبينَ، وَيا اَعْلى رَغْبَةِ الرّاغِبينَ، وَيا وَلِيَّ الصّالِحينَ، وَيا اَمانَ الْخائِفينَ، وَيا مُجيبَ دَعْوَةِ الْمُضْطَرّينَ، وَيا ذُخْرَ الْمُعْدِمينَ، وَيا كَنْزَ الْبائِسينَ، وَيا غِياثَ الْمُسْتَغيثينَ، وَيا قاضِيَ حَوائِجِ الْفُقَراءِ وَالْمَساكينَ، وَيا اَكرَمَ الاَْكْرَمينَ، وَيا اَرْحَمَ الرّاحِمينَ، لَكَ تَخَضُّعي وَسُؤالي، وَاِلَيْكَ تَضَرُّعي وَابْتِهالي، اَسْاَلُكَ اَنْ تُنيلَني مِنْ رَوْحِ رِضْوانِكَ، وَتُديمَ عَلَيَّ نِعَمَ امْتِنانِكَ، وَها اَنـَا بِبابِ كَرَمِكَ واقِفٌ، وَلِنَفَحاتِ بِرِّكَ مُتَعَرِّضٌ، وَبِحَبْلِكَ الشَّديدِ مُعْتَصِمٌ، وَبِعُرْوَتِكَ الْوُثْقى مُتَمَسِّكٌ، اِلـهي اِرْحَمْ عَبْدَكَ الذَّليلَ ذَا الّلِسانِ الْكَليلِ وَالْعَمَلِ الْقَليلِ، وَامْنُنْ عَلَيْهِ بِطَوْلِكَ الْجَزيلِ، وَاكْنُفْهُ تَحْتَ ظِلِّكَ الظَّليلِ، يا كَريمُ يا جَميلُ يا اَرْحَمَ الرّاحِمينَ ."}],"preview":"اِلـهي كَسْري لا يَجْبُرُهُ اِلاّ لُطْفُكَ وَحَنانُكَ، وَفَقْري لايُغْنيهِ اِلاّ عَطْفُكَ وَاِحْسانُكَ، وَرَوْعَتي لا يُسَكِّنُهااَمانُكَ، وَذِلَّتي لا يُعِزُّها اِلاّ سُلْطانُكَ،","hasTranslate":false},{"id":"mf_ar_81","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفَصلُ السّابِع :","title":"الثّانيَة عَشرة : « مُناجاة العارفين »","blocks":[{"type":"Text","content":"اِلـهي قَصُرَتِ الاَْلْسُنُ عَنْ بُلُوغِ ثَنائِكَ كَما يَليقُ بِجَلالِكَ، وَعَجَزَتِ الْعُقُولُ عَنْ اِدْراكِ كُنْهِ جَمالِكَ، وَانْحَسَرَتِ الاَْبْصارُ دُونَ النَّظَرِ اِلى سُبُحاتِ وَجْهِكَ، وَلَمْ تَجْعَلْ لِلْخَلْقِ طَريقاً اِلى مَعْرِفَتِكَ اِلاّ بِالْعَجْزِ عَنْ مَعْرِفَتِكَ، اِلـهي فَاجْعَلْنا مِنَ الَّذينَ تَرَسَّخَتْ اَشْجارُ الشَّوْقِ اِلَيْكَ في حَدائِقِ صُدُورِهِمْ، وَاَخَذَتْ لَوْعَةُ مَحَبَّتِكَ بِمَجامِعِ قُلُوبِهِمْ، فَهُمْ اِلى اَوْكارِ الاَْفْكارِ يَأْوُونَ، وَفي رِياضِ الْقُرْبِ وَالْمُكاشَفَةِ يَرْتَعُونَ، وَمِنْ حِياضِ الَْمحَبَّةِ بِكَاْسِ الْمُلاطَفَةِ يَكْرَعُونَ، وَشَرايِـعَ الْمُصافاتِ يَرِدُونَ، قَدْ كُشِفَ الْغِطاءُ عَنْ اَبْصارِهِمْ، وَانْجَلَتْ ظُلْمَةُ الرَّيْبِ عَنْ عَقائِدِهِمْ وَضَمائِرِهِمْ، وَانْتَفَتْ مُخالَجَةُ الشَّكِّ عَنْ قُلُوبِهِمْ وَسَرائِرِهِمْ، وَانْشَرَحَتْ بِتَحْقيقِ الْمَعْرِفَةِ صُدُورُهُمْ، وَعَلَتْ لِسَبْقِ السَّعادَةِ فِي الزَّهادَةِ هِمَمُهُمْ، وَعَذُبَ في مَعينِ الْمُعامَلَةِ شِرْبُهُمْ، وَطابَ في مَجْلِسِ الاُْنْسِ سِرُّهُمْ، وَاَمِنَ في مَوْطِنِ الَْمخافَةِ سِرْبُهُمْ، وَاطْمَأنَّتْ بِالرُّجُوعِ اِلى رَبِّ الاَْرْبابِ اَنْفُسُهُمْ، وَتَيَقَّنَتْ بِالْفَوْزِ وَالْفَلاحِ اَرْواحُهُمْ، وَقَرَّتْ بِالنَّظَرِ اِلى مَحْبُوبِهِمْ اَعْيُنُهُمْ، وَاسْتَقَرَّ بِإدْراكِ السُّؤْلِ وَنَيْلِ الْمَأْمُولِ قَرارُهُمْ، وَرَبِحَتْ في بَيْعِ الدُّنْيا بِالاْخِرَةِ تِجارَتُهُمْ، اِلـهي ما أَلَذَّ خَواطِرَ الاِْلْهامِ بِذِكْرِكَ عَلَى الْقُلُوبِ، وَما اَحْلَى الْمَسيرَ اِلَيْكَ بِالاَْوْهامِ في مَسالِكِ الْغُيُوبِ، وَما اَطْيَبَ طَعْمَ حُبِّكَ، وَما اَعْذَبَ شِرْبَ قُرْبِكَ، فَاَعِذْنا مِنْ طَرْدِكَ وَاِبْعادِكَ، وَاجْعَلْنا مِنْ اَخَصِّ عارِفيكَ، وَاَصْلَحِ عِبادِكَ، وَاَصْدَقِ طائِعيكَ، وَاَخْلَصِ عُبّادِكَ، يا عَظيمُ يا جَليلُ، يا كَريمُ يا مُنيلُ، بِرَحْمَتِكَ وَمَنِّكَ يا اَرْحَمَ الرّاحِمينَ ."}],"preview":"اِلـهي قَصُرَتِ الاَْلْسُنُ عَنْ بُلُوغِ ثَنائِكَ كَما يَليقُ بِجَلالِكَ، وَعَجَزَتِ الْعُقُولُ عَنْ اِدْراكِ كُنْهِ جَمالِكَ، وَانْحَسَرَتِ الاَْبْصارُ دُونَ النَّظَرِ اِلى سُبُحا","hasTranslate":false},{"id":"mf_ar_82","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفَصلُ السّابِع :","title":"الثّالثَة عَشرة : « مُناجاة الذّاكرينَ »","blocks":[{"type":"Text","content":"اِلـهي لَوْلاَ الْواجِبُ مِنْ قَبُولِ اَمْرِكَ لَنَزَّهْتُكَ مِنْ ذِكْري اِيّاكَ عَلى اَنَّ ذِكْري لَكَ بِقَدْري لا بِقَدْرِكَ، وَما عَسى اَنْ يَبْلُغَ مِقْداري حَتّى اُجْعَلَ مَحَلاًّ لِتَقْديسِكَ، وَمِنْ اَعْظَمِ النِّعَمِ عَلَيْنا جَرَيانُ ذِكْرِكَ عَلى اَلْسِنَتِنا، وَاِذْنُكَ لَنا بِدُعائِكَ وَتَنْزيهِكَ وَتَسْبيحِكَ، اِلـهي فَاَلْهِمْنا ذِكْرَكَ فِي الْخَلاءِ وَالْمَلاءِ وَاللَّيْلِوَالنَّهارِ، وَالاِْعْلانِ وَالاِْسْرارِ، وَفِي السَّرّاءِ وَالضَّرّاءِ، وَآنِسْنا بِالذِّكْرِ الْخَفِيِّ، وَاسْتَعْمِلْنا بِالْعَمَلِ الزَّكِيِّ، وَالسَّعْيِ الْمَرْضِيِّ، وَجازِنا بِالْميزانِ الْوَفِيِّ، اِلـهي بِكَ هامَتِ الْقُلُوبُ الْوالِهَةُ، وَعَلى مَعْرِفَتِكَ جُمِعَتِ الْعُقُولُ الْمُتَبايِنَةُ، فَلا تَطْمَئِنُّ الْقُلُوبُ اِلاّ بِذِكْراكَ، وَلا تَسْكُنُ النُّفُوسُ اِلاّ عِنْدَ رُؤْياكَ، اَنْتَ الْمُسَبَّحُ في كُلِّ مَكان، وَالْمَعْبُودُ في كُلِّ زَمان، وَالْمَوْجُودُ في كُلِّ اَوان، وَالْمَدْعُوُّ بِكُلِّ لِسان، وَالْمُعَظَّمُ في كُلِّ جَنان، وَاَسْتَغْفِرُكَ مِنْ كُلِّ لَذَّة بِغَيْرِ ذِكْرِكَ، وَمِنْ كُلِّ راحَة بِغَيْرِ اُنْسِكَ، وَمِنْ كُلِّ سُرُور بِغَيْرِ قُرْبِكَ، وَمِنْ كُلِّ شُغْل بِغَيْرِ طاعَتِكَ، اِلـهي اَنْتَ قُلْتَ وَقَوْلُكَ الْحَقُّ «يا اَيُّهَا الَّذينَ امَنُوا اذْكُرُوا اللهَ ذِكْراً كَثيراً وَسَبِّحُوهُ بُكْرَةً وَاَصيلاً» وَقُلْتَ وَقَوْلُكَ الْحَقُّ «فَاذْكُرُوني اَذْكُرْكُمْ» فَاَمَرْتَنا بِذِكْرِكَ، وَوَعَدْ تَنا عَلَيْهِ اَنْ تَذْكُرَنا تَشْريفاً لَنا وَتَفْخيماً وَاِعْظاماً، وَها نَحْنُ ذاكِرُوكَ كَما اَمَرْتَنا، فَاَنْجِزْ لَنا ما وَعَدْتَنا، يا ذاكِرَ الذّاكِرينَ وَيا اَرْحَمَ الرّحِمينَ ."}],"preview":"اِلـهي لَوْلاَ الْواجِبُ مِنْ قَبُولِ اَمْرِكَ لَنَزَّهْتُكَ مِنْ ذِكْري اِيّاكَ عَلى اَنَّ ذِكْري لَكَ بِقَدْري لا بِقَدْرِكَ، وَما عَسى اَنْ يَبْلُغَ مِقْداري حَتّى اُجْعَلَ مَحَ","hasTranslate":false},{"id":"mf_ar_83","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفَصلُ السّابِع :","title":"الرّابِعَة عَشَرة : « مُناجات المُعتَصِمين »","blocks":[{"type":"Text","content":"اَلّلهُمَّ يا مَلاذَ اللاّئِذينَ، وَيا مَعاذَ الْعائِذينَ، وَيا مُنْجِيَ الْهالِكينَ، وَيا عاصِمَ الْبائِسينَ، وَيا راحِمَ الْمَساكينِ، وَيا مُجيبَ الْمُضْطَرّينَ، وَياكَنْزَ الْمُفْتَقِرينَ، وَيا جابِرَ الْمُنْكَسِرينَ، وَيا مَأوَى الْمُنْقَطِعينَ، وَيا ناصِرَ الْمُسْتَضْعَفينَ، وَيا مُجيرَ الْخائِفينَ، وَيا مُغيثَ الْمَكْرُوبينَ، وَيا حِصْنَ اللاّجئينَ اِنْ لَمْ اَعُذْ بِعِزَّتِكَ فَبِمَنْ اَعُوذُ، وَاِنْ لَمْ اَلُذْ بِقُدْرَتِكَ فَبِمَنْ اَلُوذُ، وَقَدْ اَلْجَاَتْنِي الذُّنُوبُ اِلى التَّشَبُّثِ بِاَذْيالِ عَفْوِكَ، وَاَحْوَجَتْنِى الْخَطايا اِلَى اسْتِفْتاحِ اَبْوابِ صَفْحِكَ وَدَعَتْنِى الاِْساءَةُ اِلَى الاِْناخَةِ بِفِناءِ عِزِّكَ، وَحَمَلَتْنِى الَْمخافَةُ مِنْ نِقْمَتِكَ عَلَى الَّتمَسُّكِ بِعُرْوَةِ عَطْفِكَ، وَما حَقُّ مَنِ اعْتَصَمَ بِحَبْلِكَ اَنْ يُخْذَلَ، وَلا يَليقُ بِمَنِ اسْتَجارَ بِعِزِّكَ اَنْ يُسْلَمَ اَوْ يُهْمَلَ، اِلـهي فَلا تُخْلِنا مِنْ حِمايَتِكَ وَلا تُعْرِنا مِنْ رِعايَتِكَ، وَذُدْنا عَنْ مَوارِدِ الْهَلَكَةِ، فَاِنّا بِعَيْنِكَ وَفي كَنَفِكَ وَلَكَ، اَسْاَلُكَ بِاَهْلِ خاصَّتِكَ مِنْ مَلائِكَتِكَ وَالصّالِحينَ مِنْ بَرِيَّتِكَ اَنْ تَجْعَلَ عَلَيْنا واقِيَةً تُنْجينا مِنَ الْهَلَكاتِ، وَتُجَنِّبُنا مِنَ الاْفاتِ، وَتُكِنُّنا مِنْ دَواهِي الْمُصيباتِ، وَاَنْ تُنْزِلَ عَلَيْنا مِنْ سَكينَتِكَ، وَاَنْ تُغَشِّيَ وُجُوهَنا بِاَنْوارِ مَحَبَّتِكَ، وَاَنْ تُؤْوِيَنا اِلى شَديدِ رُكْنِكَ، وَاَنْ تَحْوِيَنا في اَكْنافِ عِصْمَتِكَ، بِرَأفَتِكَ وَرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ ."}],"preview":"اَلّلهُمَّ يا مَلاذَ اللاّئِذينَ، وَيا مَعاذَ الْعائِذينَ، وَيا مُنْجِيَ الْهالِكينَ، وَيا عاصِمَ الْبائِسينَ، وَيا راحِمَ الْمَساكينِ، وَيا مُجيبَ الْمُضْطَرّينَ، وَياكَنْزَ الْمُ","hasTranslate":false},{"id":"mf_ar_84","bookId":"الباب_الاو_ل_","book":"البابُ الاوَّلُ","section":"الفَصلُ السّابِع :","title":"الخامسَة عَشَرة : « مُناجاة الزّاهدين »","blocks":[{"type":"Text","content":"اِلـهي اَسْكَنْتَنا داراً حَفَرَتْ لَنا حُفَرَ مَكْرِها، وَعَلَّقَتْنا بِاَيْدِي الْمَنايا في حَبائِلِ غَدْرِها، فَاِلَيْكَ نَلْتَجِيءُ مِنْ مَكائِدِ خُدَعِها، وَبِكَ نَعْتَصِمُ مِنَ الاْغْتِرارِ بِزَخارِفِ زينَتِها، فَاِنَّهَا الْمُهْلِكَةُ طُلاّبَهَا، الْمُتْلِفَةُ حُلاّلَهَا، الَْمحْشُوَّةُ بِالاْفاتِ، الْمَشْحُونَةُ بِالنَّكَباتِ، اِلـهي فَزَهِّدْنا فيها، وَسَلِّمْنا مِنْها بِتَوْفيقِكَ وَعِصْمَتِكَ، وَانْزَعْ عَنّا جَلابيبَ مُخالَفَتِكَ، وَتَوَلَّ اُمُورَنا بِحُسْنِ كِفايَتِكَ، وَاَوْفِرْ مَزيدَنا مِنْ سَعَةِ رَحْمَتِكَ، وَاَجْمِلْ صِلاتِنا مِنْ فَيْضِ مَواهِبِكَ، وَاَغْرِسْ في اَفْئِدَتِنا اَشْجارَ مَحَبَّتِكَ، وَاَتْمِمْ لَنا اَنْوارَ مَعْرِفَتِكَ، وَاَذِقْنا حَلاوَةَ عَفْوِكَ، وَلَذَّةَ مَغْفِرَتِكَ، وَاَقْرِرْ اَعْيُنَنا يَوْمَ لِقائِكَ بِرُؤْيَتِكَ، وَاَخْرِجْ حُبَّ الدُّنْيا مِنْ قُلُوبِنا كَما فَعَلْتَ بِالصّالِحينَ مِنْ صَفْوَتِكَ، وَالاَْبْرارِ مِنْ خاصَّتِكَ، بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ وَيا اَكْرَمَ الاَْكْرَمينَ ."},{"type":"Text","content":"المُناجاة المَنظُومَة لامير المؤمِنين عليّ بن أبي طالِب عَلَيه الصَّلاة وَالسَّلام نقلاً عن الصّحيفة العَلَويّة"},{"type":"Text","content":"لَكَ الْحَمْدُ يا ذَا الْجُودِ وَالَْمجْدِ وَالْعُلى تَبارَكْتَ تُعْطي مَنْ تَشاءُ وَتَمْنَعُ اِلـهي وَخَلاّقي وَحِرْزي وَمَوْئِلي"},{"type":"Text","content":"اِلَيْكَ لَدى الاِْعْسارِ وَالْيُسْرِ اَفْزَعُ اِلـهي لَئِنْ جَلَّتْ وَجَمَّتْ خَطيئَتى"},{"type":"Text","content":"فَعَفْوُكَ عَنْ ذَنْبي اَجَلُّ وَاَوْسَعُ اِلـهي تَرى حالي وَفَقْري وَفاقَتي"},{"type":"Text","content":"وَاَنْتَ مُناجاتي الخَفِيَّةَ تَسْمَعُ اِلـهي فَلا تَقْطَعْ رَجائي وَلا تُزِغْ"},{"type":"Text","content":"فُؤادي فَلي في سَيْبِ جُودِكَ مَطْمَعٌ اِلـهي لَئِنْ خَيَّبْتَني اَوْ طَرَدْتَني"},{"type":"Text","content":"فَمَنْ ذَا اَّلذي اَرْجُو وَمَنْ ذا اُشَفِّعُ اِلـهي اَجِرْني مِنْ عَذابِكَ اِنَّني"},{"type":"Text","content":"اَسيرٌ ذَليلٌ خائِفٌ لَكَ اَخْضَعُ اِلـهي فَآنِسْني بِتَلْقِينِ حُجَّتي"},{"type":"Text","content":"اِذا كانَ لي في الْقَبْرِ مَثْوَىً وَمَضْجَعٌ اِلـهي لَئِنْ عَذَّبْتَني اَلْفَ حِجَّة"},{"type":"Text","content":"فَحَبْلُ رَجائي مِنْكَ لا يَتَقَطَّعُ اِلـهي اَذِقْني طَعْمَ عَفْوِكَ يَوْمَ لا"},{"type":"Text","content":"بَنُونَ وَلا مالٌ هُنا لِكَ يَنْفَعُ اِلـهي لَئِنْ لَمْ تَرْعَني كُنْتُ ضائِعاً"},{"type":"Text","content":"وَاِنْ كُنْتَ تَرْعاني فَلَسْتُ اُضَيَّعُ اِلـهي إذا لَمْ تَعْفُ عَنْ غَيْرِ مُحْسِن"},{"type":"Text","content":"فَمَنْ لِمُسيء بِالهَوى يَتَمَتَّعُ اِلـهي لَئِنْ فَرَّطْتُ فِي طَلَبِ التُّقى"},{"type":"Text","content":"فَها اَنَا اِثْرَ الْعَفْوِ اَقْفُو وَاَتْبَعُ اِلـهي لَئِنْ اَخْطاْتُ جَهْلاً فَطالَما"},{"type":"Text","content":"رَجَوْتُكَ حَتّى قيلَ ما هُوَ يَجْزَعُ اِلـهي ذُنُوبي بَذَّتِ الطَّوْدَ وَاْعتَلَتْ"},{"type":"Text","content":"وَصَفْحُكَ عَنْ ذَنْبي اَجَلُّ وَاَرْفَعُ اِلـهي يُنَحّي ذِكْرُ طَوْلِكَ لَوْعَتي"},{"type":"Text","content":"وَذِكْرُ الْخَطايَا الْعَيْنَ مِنّي يُدَمِّعُ اِلـهي اَقِلْني عَثْرَتي وَامْحُ حَوْبَتي"},{"type":"Text","content":"فَاِنّي مُقِرٌّ خائِفٌ مُتَضَرِّعٌ اِلـهي اَنِلْني مِنْك رَوْحاً وَراحَةً"},{"type":"Text","content":"فَلَسْتُ سِوى اَبْوابِ فَضْلِكَ اَقْرَعُ اِلـهي لَئِنْ اَقْصَيْتَني اَوْ اَهَنْتَني"},{"type":"Text","content":"فَما حيلَتي يا رَبِّ اَمْ كَيْفَ اَصْنَعُ اِلـهي حَليفُ الْحُبِّ في اللَّيْلِ ساهِرٌ"},{"type":"Text","content":"يُناجي وَيَدْعُو وَالْمُغَفَّلُ يَهْجَعُ اِلـهي وَهذَا الْخَلْقُ ما بَيْنَ نائِم"},{"type":"Text","content":"وَمُنْتَبه في لَيْلَهِ يَتَضَرَّعُ وكُلُّهُمْ يَرجُو نَوالَكَ راجِياً"},{"type":"Text","content":"لِرَحْمَتِكَ الْعُظْمى وَفِي الْخُلْدِ يَطْمَعُ اِلـهي يُمَنّيني رَجائِي سَلامَةً"},{"type":"Text","content":"وَقُبْحُ خَطيئاتِي عَلَيَّ يُشَنِّعُ اِلـهي فَاِنْ تَعْفُو فَعَفْوُكَ مُنْقِذي"},{"type":"Text","content":"وَاِلاّ فَبِالذَّنْبِ الْمُدَمِّرِ اُصْرَعُ اِلـهي بِحَقِّ الْهاشِميِّ مُحَمَّد"},{"type":"Text","content":"وَحُرْمَةِ اَطْْهار هُمُ لَكَ خُضَّعٌ اِلـهي بِحَقِّ الْمُصْطَفى وَابْنِ عَمِّهِ"},{"type":"Text","content":"وَحُرْمَةِ اَبْرار هُمُ لَكَ خُشَّعٌ اِلـهي فَاَنْشِرْني عَلى دينِ اَحْمَد"},{"type":"Text","content":"مُنيباً تَقِيّاً قانِتاً لَكَ اَخْضَعُ وَلا تَحْرِمْني يا اِلـهي وَسَيِّدي"},{"type":"Text","content":"شَفاعَتَهُ الْكُبْرى فَذاكَ الْمُشَفَّعُ وَصلِّ عَلَيْهِمْ ما دَعاكَ مُوَحِّدٌ"},{"type":"Text","content":"وَناجاكَ اَخْيارٌ بِبابِكَ رُكَّعٌ وقد روي في الصّحيفة أيضاً عنه (عليه السلام) مناجاة منظومة اُخرى أوّلها يا سامع الدّعاء وقد أعرضنا عن ذكره لما تحتويه من اللّغات الصّعبة الغريبة ولما نبغيه من الاختصار :"},{"type":"Text","content":"ثلاث كَلمات من مولانا عَليّ (عليه السلام) فِي المُناجاة"},{"type":"Text","content":"اِلـهي كَفى بي عِزّاً اَنْ اَكُونَ لَكَ عَبْداً، وَكَفى بي فَخْراً اَنْ تَكُونَ لي رَبّاً، اَنْتَ كَما اُحِبُّ فَاجْعَلْني كَما تُحِبُّ ."},{"type":"Text","content":"في أعمال أشهر السّنة العربيّة وَفضل يوم النّيروز وَأعماله وأعمال الاشهر الرّوميّة وفيه عدّة فصُول"}],"preview":"اِلـهي اَسْكَنْتَنا داراً حَفَرَتْ لَنا حُفَرَ مَكْرِها، وَعَلَّقَتْنا بِاَيْدِي الْمَنايا في حَبائِلِ غَدْرِها، فَاِلَيْكَ نَلْتَجِيءُ مِنْ مَكائِدِ خُدَعِها، وَبِكَ نَعْتَصِمُ مِ","hasTranslate":false},{"id":"mf_ar_85","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل الاوّلْ :","title":"في فضلِ شهر رَجَب وأعمالِه","blocks":[{"type":"AboutText","content":"اعلم انّ هذا الشّهر وشهر شعبان وشهر رمضان هي أشهر متناهية الشرف، والاحاديث في فضلها كثيرة، بل روي عن النّبي (صلى الله عليه وآله وسلم) انّه قال : انّ رجب شهر الله العظيم لا يقاربه شهر من الشّهور حرمةً وفضلاً، والقتال مع الكفّار فيه حرام ألا انّ رجل شهر الله، وشعبان شهري، ورمضان شهر اُمّتي، ألا فمن صام من رجب يوماً استوجب رضوان الله الاكبر، وابتعد عنه غضب الله، واغلق عنه باب من أبواب النّار، وعن موسى بن جعفر (عليهما السلام) قال : من صام يوماً من رجب تباعدت عنه النّار مسير سنة، ومن صام ثلاثة أيام وجبت له الجنّة ."},{"type":"Text","content":"وقال أيضاً: رجب نهر في الجنّة أشدّ بياضاً من اللّبن، وأحلى من العسل مَنْ صام يوماً من رجب سقاه الله عزوجل من ذلك النّهر، وعن الصّادق صلوات الله وسلامه عليه قال : قال رسول الله (صلى الله عليه وآله وسلم): رجب شهر الاستغفار لامّتي، فأكثروا فيه الاستغفار فانّه غفورٌ رحيم، ويسمّى الرجب الاصبّ لان الرّحمة على امّتي تصب صبّاً فيه، فاستكثروا من قول اَسْتَغْفِر اللهَ وَاَسْأَلُهُ التَّوْبَةَ"},{"type":"AboutText","content":"وروى ابن بابويه بسند معتبر عن سالم قال : دخلت على الصّادق (عليه السلام) في رجب وقد بقيت منه أيّام، فلمّا نظر اليّ قال لي: يا سالم هل صمت في هذا الشّهر شيئاً قلت: لا والله ياابن رسول الله، فقال لي: فقد فاتك من الثّواب ما لم يعلم مبلغه الّا الله عزوجل، انّ هذا شهر قد فضّله الله وعظّم حرمته وأوجب الصّائمين فيه كرامته ، قال : فقلت له : ياابن رسول الله فان صمت ممّا بقي منه شيئاً هل أنال فوزاً ببعض ثواب الصّائمين فيه، فقال : يا سالم من صام يوماً من آخر هذا الشهر كان ذلك أماناً من شدّة سكرات الموت وأماناً له من هول المطّلع وعذاب القبر، ومن صام يومين من آخر هذا الشّهر كان له بذلك جوازاً على الصّراط، ومن صام ثلاثة أيّام من آخر هذا الشّهر أمن يوم الفزع الاكبر من أهواله وشدائده واعطى براءة من النّار"},{"type":"AboutText","content":"واعلم انّه قد ورد لصوم شهر رجب فضل كثير وروى انّ من لم يقدر على ذلك يسبّح في كلّ يوم مائة مرّة بهذا التّسبيح لينال أجر الصّيام فيه: سُبْحانَ الاِْلهِ الْجَليلِ، سُبْحانَ مَنْ لا يَنْبَغي التَّسْبيحُ إِلاّ لَهُ، سُبْحانَ الاَْعَزِّ الاَْكْرَمِ، سُبْحانَ مَنْ لَبِسَ الْعِزَّ وَهُوَ لَهُ اَهْلٌ ."}],"preview":"اعلم انّ هذا الشّهر وشهر شعبان وشهر رمضان هي أشهر متناهية الشرف، والاحاديث في فضلها كثيرة، بل روي عن النّبي (صلى الله عليه وآله وسلم) انّه قال : انّ رجب شهر الله العظيم لا يقاربه ش","hasTranslate":false},{"id":"mf_ar_86","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل الاوّلْ :","title":"وَأمّا أعماله فقِسمان","blocks":[{"type":"Text","content":"الاوّل : أن يدعو في كلّ يوم من رجب بهذا الدّعاء الذي روى انّ الامام زين العابدين صلوات الله وسلامه عليه دعا به في الحجر في غرّة رجب :"},{"type":"Text","content":"يا مَنْ يَمْلِكُ حَوائِجَ السّائِلينَ، ويَعْلَمُ ضَميرَ الصّامِتينَ، لِكُلِّ مَسْأَلَة مِنْكَ سَمْعٌ حاضِرٌ وَجَوابٌ عَتيدٌ، اَللّـهُمَّ وَ مَوعيدُكَ، الصّادِقَةُ، واَيديكَ الفاضِلَةُ، ورَحْمَتُكَ الواسِعَةُ، فأسْألُكَ اَنْ تٌصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد واَنْ تَقْضِيَ حَوائِجي لِلدُّنْيا وَالاَْخِرَةِ، اِنَّكَ عَلى كُلِّ شَيْيء قَديرٌ ."},{"type":"Text","content":"الثّاني : أن يدعو بهذا الدّعاء الّذي كان يدعو به الصّادق (عليه السلام) في كلّ يوم من رجَبَ :"},{"type":"Text","content":"خابَ الوافِدُونَ عَلى غَيْرِكَ، وَخَسِرَ المُتَعَرِّضُونَ إِلاّ لَكَ، وَضاعَ المُلِّمُونَ إِلاّ بِكَ، وَاَجْدَبَ الْمُنْتَجِعُونَ إِلاّ مَنِ انْتَجَعَ فَضْلَكَ، بابُكَ مَفْتُوحٌ لِلرّاغِبينَ، وَخَيْرُكَ مَبْذُولٌ لِلطّالِبينَ وَفَضْلُكَ مُباحٌ لِلسّائِلينَ، وَنَيْلُكَ مُتاحٌ لِلامِلينَ، وَرِزْقُكَ مَبْسُوطٌ لِمَنْ عَصاكَ، وَحِلْمُكَ مُعْتَرِضٌ لِمَنْ ناواكَ، عادَتُكَ الاِْحْسانُ اِلَى الْمُسيئينَ، وَسَبيلُكَ الاِبْقاءُ عَلَى الْمُعْتَدينَ، ُاَللّـهُمَّ فَاهْدِني هُدَى الْمُهْتَدينَ، وَارْزُقْني اجْتِهادَ الُْمجْتَهِدينَ، وَلا تَجْعَلْني مِنَ الْغافِلينَ الْمُبْعَدينَ، واغْفِرْ لي يَوْمَ الدّينِ ."},{"type":"Text","content":"الثالث : قال الشّيخ في المصباح : روى المُعلّى بن خنيس عن الصادق (عليه السلام) انّه قال : قُل في رجب :"},{"type":"Text","content":"اَللّـهُمَّ اِنّي اَساَلُكَ صَبْرَ الشّاكِرينَ لَكَ، وَعَمَلَ الْخائِفينَ مِنْك، وَيَقينَ الْعابِدينَ لَكَ، اَللّـهُمَّ اَنْتَ الْعَلِيُّ الْعَظيمُ، وَاَنَا عَبْدُكَ الْبائِسُ الْفَقيرُ، اَنْتَ الْغَنِيُّ الْحَميدُ، وَاَنَا الْعَبْدُ الذَّليل، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِهِ وَاْمْنُنْ بِغِناكَ عَلى فَقْري، وَبِحِلْمِكَ عَلى جَهْلي، وَبِقُوَّتِكَ عَلى ضَعْفي، يا قَوِيُّ يا عَزيزُ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِهِ الاْوصياءِ الْمَرْضِيِّينَ، وَاكْفِني ما اَهَمَّني مِنْ اَمْرِ الدُّنْيا وَالاخِرَةِ يا اَرْحَمَ الرّاحِمينَ ."},{"type":"AboutText","content":"أقول : هذا دُعاء رواه السّيّد أيضاً في الاقبال، ويظهر من تِلك الرّواية انّ هذا الدعاء هو أجمع الدَّعوات ويصلح لان يدعى به في كل الاوقات ."}],"preview":"الاوّل : أن يدعو في كلّ يوم من رجب بهذا الدّعاء الذي روى انّ الامام زين العابدين صلوات الله وسلامه عليه دعا به في الحجر في غرّة رجب :","hasTranslate":false},{"id":"mf_ar_87","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القسم الاوّل : الاعمال العامّة التي تؤدّى في جميع الشّهر ولا تخصّ أيّاماً معيّنة منه وهي أمور :","title":"الرابع : قالَ الشيخ أيضاً: يستحبّ اَنْ يدعو بهذا الّدعاء في كلّ يَوْم :","blocks":[{"type":"Text","content":"اَللّـهُمَّ يا ذَا الْمِنَنِ السّابِغَةِ، وَالاْلاءِ الْوازِعَةِ، والرَّحْمَةِ الْواسِعَةِ، وَالْقُدْرَةِ الْجامِعَةِ، وَالنِّعَمِ الْجَسْيمَةِ، وَالْمَواهِبِ الْعَظيمَةِ، وَالاَْيادِي الْجَميلَةِ، والْعَطايَا الْجَزيلَةِ، يا مَنْ لا يُنْعَتُ بِتَمْثيل، وَلا يُمَثَّلُ بِنَظير، وَلا يُغْلَبُ بِظَهير، يا مَنْ خَلَقَ فَرَزَقَ وَأَلْهَمَ فَاَنْطَقَ، وَابْتَدَعَ فَشَرَعَ، وَعَلا فَارْتَفَعَ، وَقَدَّرَ فَاَحْسَنَ، وَصَوَّرَ فَاَتْقَنَ، وَاحْتَجَّ فَاَبْلَغَ، وَاَنْعَمَ فَاَسْبَغَ، وَاَعْطى فَاَجْزَلَ، وَمَنَحَ فَاَفْضَلَ، يا مَنْ سَما فِي الْعِزِّ فَفاتَ نَواظِرَ الاْبْصارِ، وَدَنا فِي الُّلطْفِ فَجازَ هَواجِسَ الاَْفْكارِ، يا مَنْ تَوَحَّدَ باِلْمُلكِ فَلا نِدَّ لَهُ في مَلَكُوتِ سُلْطانِهِ، وَتفَرَّدَ بِالاْلاء وَالْكِبرِياءِ فَلا ضِدَّ لَهُ في جَبَرُوتِ شَانِهِ، يا مَنْ حارَتْ في كِبْرِياءِ هَيْبَتِهِ دَقائِقُ لَطائِفِ الاَْوْهامِ، وَانْحَسَرَتْ دُونَ اِدْراكِ عَظَمَتِهِ خَطائِفُ اَبْصارِ الاَْنامِ، يا مَنْ عَنَتِ الْوُجُوهُ لِهَيْبَتِهِ، وَخَضَعَتِ الرِّقابُ لِعَظَمَتِهِ، وَوجِلَتِ الْقُلُوبُ مِنْ خيفَتِهِ، اَساَلُكَ بِهذِهِ الْمِدْحَةِ الَّتي لا تَنْبَغي إِلاّ لَكَ، وَبِما وَأَيْتَ بِهِ عَلى نَفْسِكَ لِداعيكَ مِنَ الْمُؤْمِنينَ، وَبِما ضَمِنْتَ الاِجابَةَ فيهِ عَلى نَفْسِكَ لِلدّاعينَ، يا اَسْمَعَ السّامِعينَ، وَابْصَرَ النّاظِرينَ، وَاَسْرَعَ الْحاسِبينَ، يا ذَا الْقُوَّةِ الْمتينُ، صَلِّ عَلى مُحَمَّد خاتَمِ النَّبِيّينَ، وَعَلى اَهْلِ بَيْتِهِ، وَاقْسِمْ لي في شَهْرِنا هذا خَيْرَ ما قَسَمْتَ، وَاحْتِمْ لي في قَضائِكَ خَيْرَ ما حَتَمْتَ، وَاخْتِمْ لي بِالسَّعادَةِ فيمَنْ خَتَمْتَ، وَاحْيِني ما اَحْيَيْتَني مَوْفُوراً، وَاَمِتْني مَسْرُوراً وَمَغْفُوراً، وَتوَلَّ اَنْتَ نَجاتي مِنْ مُساءَلَةِ الْبَرْزَخِ، وَادْرَأْ عَنّي مُنْكَراً وَنَكيراً، وَاَرِ عَيْني مُبَشِّراً وَبَشيراً، وَاجْعَلْ لي اِلى رِضْوانِكَ وَجِنانِكَ مَصيراً، وَعَيْشاً قَريراً، وَمُلْكاً كَبيْراً، وَصَلِّ عَلى مُحَمَّد وَآلِهِ كَثيراً ."}],"preview":"اَللّـهُمَّ يا ذَا الْمِنَنِ السّابِغَةِ، وَالاْلاءِ الْوازِعَةِ، والرَّحْمَةِ الْواسِعَةِ، وَالْقُدْرَةِ الْجامِعَةِ، وَالنِّعَمِ الْجَسْيمَةِ، وَالْمَواهِبِ الْعَظيمَةِ، وَالاَْي","hasTranslate":false},{"id":"mf_ar_88","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القسم الاوّل : الاعمال العامّة التي تؤدّى في جميع الشّهر ولا تخصّ أيّاماً معيّنة منه وهي أمور :","title":"أقول : هذا دعاء يدعى به في مسجد صعصعة أيضاً","blocks":[{"type":"Text","content":"الخامس : روى الشّيخ انّه خرج هذا التّوقيع الشّريف من النّاحية المقدّسة على يد الشّيخ الكبير أبي جعفر محمّد بن عثمان بن سعيد (رضي الله عنه) :"}],"preview":"الخامس : روى الشّيخ انّه خرج هذا التّوقيع الشّريف من النّاحية المقدّسة على يد الشّيخ الكبير أبي جعفر محمّد بن عثمان بن سعيد (رضي الله عنه) :","hasTranslate":false},{"id":"mf_ar_89","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القسم الاوّل : الاعمال العامّة التي تؤدّى في جميع الشّهر ولا تخصّ أيّاماً معيّنة منه وهي أمور :","title":"اُدع في كلّ يوم من أيّام رجب :","blocks":[{"type":"Text","content":"اَللّـهُمَّ اِنّي اَساَلُكَ بِمَعاني جَميعِ ما يَدْعُوكَ بِهِ وُلاةُ اَمْرِكَ، الْمَاْمُونُونَ عَلى سِرِّكَ، الْمُسْتَبْشِرُونَ بِاَمْرِكَ، الْواصِفُونَ لِقُدْرَتِكَ الْمُعلِنُونَ لِعَظَمَتِكَ، اَساَلُكَ بِما نَطَقَ فيهِمْ مِنْ مَشِيَّتِكَ، فَجَعَلْتَهُمْ مَعادِنَ لِكَلِماتِكَ، وَاَرْكاناً لِتَوْحيدِكَ، وَآياتِكَ وَمَقاماتِكَ الَّتي لا تَعْطيلَ لَها في كُلِّ مَكان، يَعْرِفُكَ بِها مَنْ عَرَفَكَ، لا فَرْقَ بَيْنَكَ وَبَيْنَها إِلاّ اَنَّهُمْ عِبادُكَ وَخَلْقُكَ، فَتْقُها وَرَتْقُها بِيَدِكَ، بَدْؤُها مِنْكَ وَعَوْدُها اِلَيكَ اَعْضادٌ واَشْهادٌ ومُناةٌ واَذْوادٌ وَحَفَظَةٌ وَرُوّادٌ، فَبِهمْ مَلاْتَ سَمائكَ وَاَرْضَكَ حَتّى ظَهَرَ اَنْ لا اِلـهَ إلاّ اَنْتَ، فَبِذلِكَ اَساَلُكَ، وَبِمَواقِعِ الْعِزِّ مِنْ رَحْمَتِكَ، وَبِمَقاماتِكَ وَعَلاماتِكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِهِ، واَنْ تَزيدَني إيماناً وَتَثْبيتاً، يا باطِناً في ظُهُورِهِ وَظاهراً في بُطُونِهِ وَمَكْنُونِهِ، يا مُفَرِّقاً بَيْنَ النُّورِ وَالدَّيْجُورِ، يا مَوْصُوفاً بِغَيْرِ كُنْه، وَمَعْرُوفاً بِغَيْرِ شِبْه، حادَّ، كُلِّ مَحْدُود، وَشاهِدَ كُلِّ مَشْهُود، وَمُوجِدَ كُلِّ مَوْجُود، وَمُحْصِيَ كُلِّ مَعْدُود، وَفاقِدَ كُلِّ مَفْقُود، لَيْسَ دُونَكَ مِنْ مَعْبُود، اَهْلَ الْكِبْرِياءِ وَالْجُودِ، يا مَنْ لا يُكَيَّفُ بِكَيْف، وَلا يُؤَيَّنُ بِاَيْن، يا مُحْتَجِباً عَنْ كُلِّ عَيْن، يا دَيْمُومُ يا قَيُّومُ وَعالِمَ كُلِّ مَعْلُوم، صَلِّ عَلى مُحَمَّد وَآلِهِ، وَعَلى عِبادِكَ الْمُنْتَجَبينَ، وَبَشَرِكَ الُْمحْتَجِبينَ، وَمَلائِكَتِكَ الْمُقَرَّبينَ، وَالْبُهْمِ الصّافّينَ الْحافّينَ، وَبارِكَ لَنا في شَهْرِنا هذَا الْمُرَجَّبِ الْمُكَرَّم وَما بَعْدَهُ مِنَ الاَْشْهُرِ الْحُرُمِ، وَاَسْبِغْ عَلَيْنا فيهِ النِّعَمَ، وَاَجْزِلْ لَنا فيهِ الْقِسَمَ، وَاَبْرِزْ لَنا فيهِ الْقَسَمَ بِاسْمِكَ الاَْعْظَمِ الاَْجَلِّ الاَْكْرَمِ الَّذي وَضَعْتَهُ عَليَ النَّهارِ فَاَضاءَ، وَعَلى اللَّيْلِ فَاَظْلَمَ، وَاْغفِرْ لَنا ما تَعْلَمُ مِنّا وَما لا نَعْلَمُ، وَاعْصِمْنا مِنَ الذُّنُوبِ خَيْرَ الْعِصَمِ، وَاكْفِنا كَوافِيَ قَدَرِكَ، واْمنُنْ عَلْيْنا بِحُسْنِ نَظَرِكَ، وَلا تَكِلْنا اِلى غَيْرِكَ، وَلا تَمْنَعْنا مِنْ خَيْركَ وَبارِكَ لَنا فيما كَتَبْتَهُ لَنا مِنْ اَعْمارِنا، واَصْلحْ لنا خَبيئَةَ اَسْررِنا، واَعْطِنا مِنْكَ الاَْمانَ، وَاْستَعْمِلْنا بِحُسْنِ الاِْيْمانِ وَبَلِّغْنا شَهْرَ الصِّيامِ وَما بَعْدَهُ مِنَ الاَْيّامِ وَالاَْعْوامِ يا ذَا الْجَلالِ والاِكْرامِ ."},{"type":"Text","content":"السّادس : وروى الشّيخ انّه خرج من النّاحية المقدّسة على يد الشّيخ أبي القاسم (رضي الله عنه) هذا الدّعاء في أيّام رجب :"},{"type":"Text","content":"اَللّـهُمَّ اِنّي اَساَلُكَ بِالْمَوْلُودَيْنِ في رَجَب مُحَمَّد بْنِ عَليٍّ الثاني وَابْنِهِ عَلِيِّ بْنِ مُحَمَّد الْمُنْتَجَبِ، وَاَتَقَرَّبُ بِهِما اِلَيْكَ خَيْرَ الْقُرْبِ، يا مَنْ اِلَيْهِ الْمَعْرُوفُ طُلِبَ، وَفيـما لَدَيْهِ رُغِبَ، اَساَلُكَ سُؤالَ مُقْتَرِف مُذْنِب قَدْ اَوْبَقَتْهُ ذُنُوبُهُ، وَاَوْثَقَتْهُ عُيُوبُهُ، فَطالَ عَلَى الْخَطايا دُؤُوبُهُ، وَمِنَ الرَّزايا خُطُوبُهُ، يَسْأَلُكَ التَّوْبَةَ وَحُسْنَ الاَْوْبَةِ والنُّزْوعَ عَنِ الْحَوْبَةِ، وَمِنَ النّارِ فَكاكَ رَقَبَتِهِ، وَالْعَفْوَ عَمّا في رِبْقَتِهِ، فَاَنْتَ مَوْلايَ اَعْظَمُ اَمَلِهِ وَثِقَتِهِ، اَللّـهُمَّ واَساَلُكَ بِمَسائِلِكَ الشَّريفَةِ، وَوَسائِلَك الْمُنيفَةِ اَنْ تَتَغَمَّدَني في هذَا الشَّهْرِ بِرَحْمَة مِنْكَ واسِعَة، وَنِعْمَة وازِعَة، وَنَفْس بِما رَزَقْتَها قانِعَة، اِلى نُزُولِ الحافِرَةِ وَمَحلِّ الاْخِرَةِ وَما هِيَ اِلَيْهِ صائِرَةٌ ."},{"type":"Text","content":"السّابع : وروى الشّيخ أيضاً عن أبي القاسم حسين بن روح (رضي الله عنه) النّائب الخاصّ للحجّة (عليه السلام) انّه قال زر أيّ المشاهد كنت بحضرتها في رجب تقول :"},{"type":"Text","content":"الْحَمْدُ للهِ الَّذي اَشْهَدَنا مَشْهَدَ اَوْلِيائِهِ في رَجَب، وَاَوْجَبَ عَلَيْنا مِنْ حَقِّهِمْ ما قَدْ وَجَبَ، وَصَلَّى اللهُ عَلى مُحَمَّد الْمُنْتَجَبِ، وَعَلى اَوْصِيائِهِ الْحُجُبِ، اَللّـهُمَّ فَكَما اَشْهَدْتَنا مَشْهَدَهُمْ فَاَنْجِزْ لَنا مَوْعِدَهُمْ، وَاَوْرِدْنا مَوْرِدَهُمْ، غَيْرَ مُحَلَّئينَ عَنْ وِرْد في دارِ الْمُقامَةِ والْخُلْدِ، وَالسَّلامُ عَلَيْكُمْ اِنّي قَصَدْتُكُمْ وَاعْتَمَدْتُكُمْ بِمَسْأَلَتي وَحاجَتي وَهِيَ فَكاكُ رَقَبَتي مِنَ النّارِ، وَالْمَقَرُّ مَعَكُمْ في دارِ الْقَرارِ مَعَ شيعَتِكُمُ الاَْبْرارِ، وَالسَّلامُ عَلَيْكُمْ بِما صَبَرْتُمْ فَنِعْمَ عُقْبَى الدّارِ، اَنَا سائِلُكُمْ وَآمِلُكُمْ فيـما اِلَيْكُمُ التَّفْويضُ، وَعَلَيْكُمْ التَّعْويضُ فَبِكُمْ يُجْبَرُ الْمَهيضُ وَيُشْفَى الْمَريضُ، وَما تَزْدادُ الاَْرْحامُ وَما تَغيضُ، اِنّي بِسِرِّكُمْ مُؤْمِنٌ، وَلِقَوْلِكُمْ مُسَلِّمٌ، وَعَلَى اللهِ بِكُمْ مُقْسِمٌ في رَجْعي بِحَوائِجي وَقَضائِها وَاِمْضائِها وَاِنْجاحِها وَاِبْراحِها، وَبِشُؤوني لَدَيْكُمْ وَصَلاحِها، وَالسَّلامُ عَلَيْكُمْ سَلامَ مُوَدِّع، وَلَكُمْ حَوائِجَهُ مُودِعٌ يَسْأَلُ اللهَ اِلَيْكُمْ الْمَرْجِعَ وَسَعْيُهُ اِلَيْكُمْ غَيْرُ مُنْقَطِع، وَاَنْ يَرْجِعَني مِنْ حَضْرَتِكُمْ خَيْرَ مَرْجِع اِلى جَناب مُمْرِع، وَخَفْضِ مُوَسَّع، وَدَعَة وَمَهَل اِلى حينِ الاَْجَلِ، وَخَيْرِ مَصير وَمَحلٍّ، في النَّعيمِ الاَْزَلِ، وَالْعَيْشِ الْمُقْتَبَلِ وَدَوامِ الاُْكُلِ، وَشُرْبِ الرَّحيقِ وَالسَّلْسَلِ، وَعَلٍّ وَنَهَل، لا سَأمَ مِنْهُ وَلا مَلَلَ، وَرَحْمَةُ اللهِ وَبَرَكاتُهُ وَتَحِيّاتُهُ عَلَيْكُمْ حَتّيَ الْعَوْدِ اِلى حَضْرَتِكُمْ، والْفَوزِ في كَرَّتِكُمْ، وَالْحَشْرِ في زُمْرَتِكُمْ، وَرَحْمَةُ اللهِ وَبَرَكاتُهُ عَلَيْكُمْ وَصَلَواتُهُ وَتَحِيّاتُهُ، وَهُوَ حَسْبُنا وَنِعْمَ الْوَكيلُ ."},{"type":"Text","content":"الثّامن : روى السيّد ابن طاووس عن محمّد بن ذكوان المعروف بالسّجاد لانّه كان يكثر من السّجود والبكاء فيه حتّى ذهب بصره قال : قلت للصّادق (عليه السلام) : جعلت فداك هذا رجب علّمني فيه دعاءاً ينفعني الله به، قال (عليه السلام) : اكتب بِسْمِ اللهِ الرَّحْمنِ الرَّحيمِ قل في كلّ يوم من رجب صباحاً ومساءاً وفي أعقاب صلواتك في يومك وليلتك يا مَنْ اَرْجُوهُ لِكُلِّ خَيْر، وَآمَنَ سَخَطَهُ عِنْدَ كُلِّ شَرٍّ، يا مَنْ يُعْطِي الْكَثيرَ بِالْقَليلِ، يا مَنْ يُعْطي مَنْ سَأَلَهُ يا مَنْ يُعْطي مَنْ لَمْ يَسْأَلْهُ وَمَنْ لَمْ يَعْرِفْهُ تَحَنُّناً مِنْهُ وَرَحْمَةً، اَعْطِني بِمَسْأَلَتي اِيّاكَ جَميعَ خَيْرِ الدُّنْيا وَجَميعَ خَيْرِ الاْخِرَةِ، وَاصْرِفْ عَنّي بِمَسْأَلَتي اِيّاكَ جَميعَ شَرِّ الدُّنْيا وَشَرِّ الاْخِرَةِ، فَاِنَّهُ غَيْرُ مَنْقُوص ما اَعْطَيْتَ، وَزِدْني مِنْ فَضْلِكَ يا كَريمُ ."},{"type":"AboutText","content":"قال الراوي : ثمّ مدّ (عليه السلام) يده اليسرى فقبض على لحيته ودعا بهذا الدّعاء وهو يلوذ بسبّابته اليمنى، ثمّ قال بعد ذلك : يا ذَا الْجَلالِ وَالاِْكْرامِ، يا ذَا النَّعْماءِ وَالْجُودِ، يا ذَا الْمَنِّ وَالطَّوْلِ، حَرِّمْ شَيْبَتي عَلَى النّارِ ."},{"type":"Text","content":"التّاسِع : عن النّبي (صلى الله عليه وآله وسلم) انّه قال من قال: في رجب: اَسْتَغْفِرُ اللهَ لا اِلـهَ إِلاّ هُوَ وَحْدَهُ لا شَريكَ لَهُ وَاَتُوبُ اِلَيْهِ مائة مرّة وختمها بالصّدقة ختم الله له بالرّحمة والمغفرة، ومن قالها أربعمائة مرّة كتب الله له أجر مائة شهيد ."},{"type":"Text","content":"العاشر : وعنه (صلى الله عليه وآله وسلم) قال : من قال في رجب: (لا اِلـهَ إلاَّ اللهُ) ألف مرّة، كتب الله له مائة ألف حسنة وبنى الله له مائة مدينة في الجنّة ."},{"type":"Text","content":"الحادي عشر : في الحديث : من استغفر الله في رجب سبعين مرّة بالغداة وسبعين مرّة بالعشيّ يقول: اَسْتَغْفِرُ اللهَ وَاَتُوبُ اِلَيْهِ، فاذا بلغ تمام سبعين مرّة رفع يديه وقال: اَللّـهُمَّ اغْفِرْ لي وَتُبْ عَلَيَّ، فان مات في رجب مات مرضيّاً عنه ولا تمسّه النّار ببركة رجب ."},{"type":"Text","content":"الثّاني عشر : أن يستغفر في هذا الشهر ألف مرّة قائلاً: اَسْتَغْفِرُ اللهَ ذَا الْجَلالِ وَالاِْكْرامِ مِنْ جَميعِ الذُّنُوبِ وَالاثامِ، ليغفر له الله الرّحيم ."},{"type":"Text","content":"الثّالث عشر : روى السّيد في الاقبال فضلاً كثيراً لقراءة قل هو الله احد عشرة آلاف مرّة أو ألف مرّة أو مائة مرّة في شهر رجب، وروى ايضاً انّ من قرأ قُل هو الله أحدٌ مائة مرّة في يوم الجمعة من شهر رجب كان له يوم القيامة نور يجذبه الى الجنّة ."},{"type":"Text","content":"الرّابع عشر : روى السيّد انّ من صام يوماً من رجب وصلّى أربع ركعات يقرأ في الاُولى آية الكرسي مائة مرّة، وفي الثّانية قل هو الله أحد مائتين مرّة، لم يمت الّا وقد شاهد مكانه في الجنّة أو شوهد له ."},{"type":"Text","content":"الخامس عشر : روى السيّد ايضاً عن النّبي (صلى الله عليه وآله وسلم) انّ من صلّى يوم الجمعة من رجب أربع ركعات ما بين صلاة الظّهر وصلاة العصر يقرأ في كلّ ركعة الحمد مرّة وآية الكرسي سبع مرّات وقُلْ هُوَ اللهُ أحَدٌ خمس مرّات، ثمّ يقول عشراً اَسْتَغْفِرُ اللهَ الَّذي لا اِلـهَ إِلاّ هُوَ وَاَسْأَلُهُ التَّوْبَةَ، كتب الله له من اليوم الذي صلّى فيه هذه الصّلاة الى اليوم الذي يموت فيه بكلّ يوم ألف حسنة، وأعطاه بكلّ آية تلاها مدينة في الجنّة من الياقوت الاحمر، وبكلّ حرف قصراً في الجنّة من الدّرّ الابيض، وزوّجه حور العين ورضي عنه بغير سخط، وكتب من العابدين، وختم له بالسّعادة والمغفرة الخبر."},{"type":"Text","content":"السّادس عشر : أن يصوم ثلاثة أيّام من هذا الشّهر هي أيّام الخميس والجمعة والسّبت، فقد روى انّ من صامها في شهر من الاشهر الحرم كتب الله له عبادة تسعمائة عام ."},{"type":"Text","content":"السّابع عشر : يصلّى في هذا الشهر ستّين ركعة، يُصلّى منها في كلّ ليلة ركعتين يقرأ في كلّ ركعة الحمد مرّة و (قُل يا أيّها الكافِرُونَ) ثلاث مرّات و(قُلْ هُوَ اللهُ أحَدٌ) مرّة واحدة، فاذا سلم رفع يديه الى السّماء وقال : لا اِلـهَ إلاَّ اللهُ وَحْدَهُ لا شَريكَ لَهُ، لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ، يُحْيي وَيُميتُ، وَهُوَ حَيٌّ لا يَمُوتُ، بِيَدِهِ الْخَيْرُ وَهُوَ عَلى كُلِّ شَيْيء قَديرٌ، وَاِلَيْهِ الْمَصيرُ، وَلا حَوْلَ وَلا قُوَّةَ إِلاّ بِاللهِ الْعَلِيِّ الْعَظيمِ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد النَّبِيِّ الاُْمِّيِّ وَآلِهِ، ويمرر يده على وجهه، وعن النّبي (صلى الله عليه وآله وسلم) انّ من فعل ذلك استجاب الله دعاءه واعطاه أجر ستّين حجّة وعُمرة ."},{"type":"Text","content":"الثّامن عشر : روى عن النّبي (صلى الله عليه وآله وسلم) انّ من قرأ في ليلة من ليالي رجب مائة مرّة قُلْ هُوَ اللهُ أحَدٌ في ركعتين فكأنّما قد صام مائة سنة في سبيل الله ورزقه الله في الجنّة مائة قصر كلّ قصر في جوار نبيّ من الانبياء (عليهم السلام) ."},{"type":"Text","content":"التّاسع عشر : وعنه (صلى الله عليه وآله وسلم) ايضاً انّ من صلّى في ليلة من ليالي رجب عشر ركعات يقرأ في كلّ ركعة الحَمْد وقُل يا أيّها الكافِرُونَ مرّة، والتّوحيد ثلاث مرّات غفر الله له ما اقترفه من الامم الخبر."},{"type":"Text","content":"العشرون : قال العلاّمة المجلسي في زاد المعاد: روي عن أمير المؤمنين (عليه السلام) انّه قال : قال رسول الله (صلى الله عليه وآله وسلم)من قرأ في كلّ يوم من أيّام رجب وشعبان ورمضان وفي كلّ ليلة منها كلّاً من الحمد وآية الكرسي و(قُل يا أيّها الكافِرُونَ) و (قُلْ هُوَ اللهُ أحَدٌ) و (قُلْ اَعُوذُ بِرَبِّ الفَلَق) و (قُلْ اَعُوذُ بِرَبِّ النّاسِ) ثلاث مرّات، وقال: سُبْحانَ اللهِ وَالْحَمْدُ للهِ وَلا اِلـهَ إلاَّ اللهُ وَاللهُ اَكْبَرُ، وَلا حَوْلَ وَلا قُوَّةَ إِلاّ بِاللهِ الْعَلِيِّ الْعَظيمِ، وثلاثاً اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وثلاثاً اَللّـهُمَّ اغْفِرْ لِلْمُؤمِنينَ وَالْمُؤمِناتِ، وأربعمائة مرّة اَسْتَغْفِرُ اللهَ وَاَتُوبُ اِلَيْهِ، غفر الله له ذنوبه وإن كانت عدد قطر الامطار وَورق الاشجار وزبد البحارالخبر."},{"type":"Text","content":"الحادي والعشرون : وقال العلامة المجلسي (رحمه الله) ايضاً من المأثور قول لا اِلـهَ إلاَّ اللهُ في كلّ ليلة من هذا الشّهر ألف مرّة."},{"type":"AboutText","content":"واعلم انّ أوّل ليلة من ليالي الجمعة من رجب تسمّى ليلة الرّغائب وفيها عمل مأثور عن النّبي (صلى الله عليه وآله وسلم)ذو فضل كثير ورواه السّيد في الاقبال والعلامة المجلسي رحمه الله في اجازة بني زهرة، ومن فضله أن يغفر لمن صلّاها ذنوب كثيرة، وانّه اذا كان أوّل ليلة نزوله الى قبره بعَث الله اليه ثواب هذه الصّلاة في أحسن صورة بوجه طلق ولسان ذلق، فيقول: يا حبيبي أبشر فقد نجوت مِن كلّ شدّة، فيقول : مَنْ أنت فما رأيت أحسن وجهاً منك، ولا سمعت كلاماً أحلى من كلامك، ولا شمت رائحة أطيب من رائحتك؟ فيقول : يا حبيبي أنا ثواب تلك الصّلاة التي صلّيتها ليلة كذا في بلدة كذا في شهر كذا في سنة كذا، جئت اللّيلة لاقضي حقّك، وأنس وحدتك، وارفع عنك وحشتك، فاذا نفخ في الصّور ظلّلت في عرصة القيامة على رأسِك، فافرح فانّك لن تعدم الخير أبداً ."},{"type":"Text","content":"وَصِفَة هـذه الصّلاة"},{"type":"Text","content":"أن يصوم أوّل خميس من رجب ثمّ يصلّي بين صلاتي المغرب والعشاء اثنتي عشرة ركعة يفصل بين كلّ ركعتين بتسليمة يقرأ في كلّ ركعة فاتحة الكتاب مرّة وَ (انّا أَنْزَلْناهُ) ثلاث مرّات و (قُلْ هُوَ اللهُ أحَدٌ) اثنتي عشرة مرّة، فاذا فرغ من صَلاته قال سبعين مرّة: اَللّـهُمَّ صَلِّ عَلى مُحَمَّد النَّبِيِّ الاُْمِّيِّ وَعَلى آلِهِ، ثمّ يسجد ويقول في سجوده سبعين مرّة: سُبُّوحٌ قُدُّوسٌ رَبُّ الْمَلائِكَةِ وَالرُّوحِ ثمّ يسأل حاجته فانّها تقضى ان شاء الله، واعلم ايضاً انّ من المندوب في شهر رجب زيارة الامام الرّضا (عليه السلام) ولها في هذا الشّهر مزيّة كما انّ للعمرة ايضاً في هذا الشّهر فضل وروي انّها تالية الحجّ في الثّواب وروى انّ عليّ بن الحسين (عليه السلام) كان قد اعتمر في رجب فكان يُصلّي عند الكعبة ويسجد ليله ونهاره وكان يسمع منه وهُو في السّجود : عَظُمَ الذَّنْبُ مِنْ عَبْدِكَ فَلْيَحْسُنِ الْعَفْوُ مِنْ عِنْدِكَ ."}],"preview":"اَللّـهُمَّ اِنّي اَساَلُكَ بِمَعاني جَميعِ ما يَدْعُوكَ بِهِ وُلاةُ اَمْرِكَ، الْمَاْمُونُونَ عَلى سِرِّكَ، الْمُسْتَبْشِرُونَ بِاَمْرِكَ، الْواصِفُونَ لِقُدْرَتِكَ الْمُعلِنُونَ","hasTranslate":false},{"id":"mf_ar_90","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القسم الاوّل : الاعمال العامّة التي تؤدّى في جميع الشّهر ولا تخصّ أيّاماً معيّنة منه وهي أمور :","title":"الليلة الاُولى: هي ليلة شريفة وقد ورد فيها أعمال :","blocks":[{"type":"Text","content":"الاوّل : أن يقول اذا رأى الهلال: اَللّـهُمَّ اَهِلَّهُ عَلَيْنا بِالاَْمْنِ وَالاْيمانِ وَالسَّلامَةِ وَالاِْسْلامِ رَبّي وَرَبُّكَ اللهُ عَزَّوَجَلَّ وروي عن النّبي (صلى الله عليه وآله وسلم)انّه كان اذا رأى هلال رجب قال :"},{"type":"Text","content":"اَللّـهُمَّ بارِكْ لَنا في رَجَب وَشَعْبانَ، وبَلِّغْنا شَهْرَ رَمَضانَ، واَعِنّا عَلَى الصِّيامِ وَالْقِيامِ وَحِفْظِ اللِّسانِ، وَغَضِّ الْبَصَرِ، وَلا تَجْعَلْ حَظَّنا مِنْهُ الْجُوعَ وَالْعَطَشَ ."},{"type":"Text","content":"الثّاني : أن يغتسل، فمن بعض العلماء عن النّبي (صلى الله عليه وآله وسلم) انّه قال : من أدرك شهر رجب فاغتسل في أوّله وأوسطه وآخره خرج مِن ذنوبه كيوم ولدته اُمّه ."},{"type":"Text","content":"الثّالث : أن يزور الحسين (عليه السلام) ."},{"type":"Text","content":"الرّابع : أن يُصلّي بعد صلاة المغرب عشرين ركعة يقرأ في كلّ ركعة فاتحة الكتاب وقُل هو الله احد مرّة ويسلم بين كلّ ركعتين ليحفظ في أهله وماله ووَلده، ويجار مِن عذاب القبر، ويجوز على الصّراط كالبرق الخاطف من غير حساب ."},{"type":"Text","content":"الخامس : أن يصلّي ركعتين بعد العشاء يقرأ في أوّل ركعة منها فاتحة الكتاب وألم نشرح مرّة، وقل هو الله احدٌ ثلاث مرّات، وفي الرّكعة الثّانية فاتحة الكتاب وألم نشرح وقُلْ هُوَ اللهُ احدٌ والمعوّذتين، فاذا سلّم قال: لا اِلـهَ إلاَّ اللهُ ثلاثين مرّة، وصلّى على النّبي (صلى الله عليه وآله وسلم) ثلاثين مرّة ليغفر الله له ذنوبه ويخرج منها كيوم ولدته اُمّه ."},{"type":"Text","content":"السّادس : أن يصلّي ثلاثين ركعة يقرأ في كلّ ركعة فاتحة الكتاب وقُلْ يا أيّها الكافِرُونَ مرّة، وسورة التوحيد ثلاث مرّات ."},{"type":"Text","content":"السّابع : أن يأتي بما ذكره الشّيخ في المصباح حيث قال : العمل في أوّل ليلة من رجب : روى ابو البختري وهب بن وهب عن الصّادق (عليه السلام): عن أبيه، عن جدّه، عن عليّ (عليه السلام) قال : كان يعجبه أن يفرغ نفسه أربع ليال في السّنة، وهي أوّل ليلة من رجب، وليلة النّصف من شعبان، وليلة الفطر، وليلة النّحر ."},{"type":"AboutText","content":"وروى عن أبي جعفر الثّاني (عليه السلام) انّه قال : يستحبّ أن يدعو بهذا الدّعاء أوّل ليلة من رجب بعد العشاء الاخرة :"},{"type":"Text","content":"اَللّـهُمَّ اِنّي اَساَلُكَ بِاَنَّكَ مَلِكٌ، واَنَّكَ عَلى كُلِّ شَيْيء مُقْتَدِرٌ، وَاَنَّكَ ما تَشاءُ مِنْ أَمْر يَكُونُ، اَللّـهُمَّ اِنّي اَتَوجَّهُ اِلَيْكَ بِنَبِيِّكَ مُحَمَّد نَبِيِّ الرَّحْمَةِ صَلَّى اللهُ عَلَيْهِ وَآلِهِ، يا مُحَمَّدُ يا رَسُولَ اللهِ، اِنّي اَتَوجَّهُ بِكَ اِلَى اللهِ رَبِّكَ وَرَبِّي لِيُنْجِحَ لي بِكَ طَلِبَتي، اَللّـهُمَّ بِنَبِيِّكَ مُحَمَّد وَالاَْئِمَّةِ مِنْ اَهْلِ بَيْتِهِ صَلَّى اللهُ عَلَيْهِ وَعَلَيْهِمْ اَنْجِحْ طَلِبَتي . ثمّ تسأل حاجتك ."},{"type":"AboutText","content":"وروى عليّ بن حديد قال : كان موسى بن جعفر (عليه السلام) يقول وهو ساجد بعد فراغه من صلاة اللّيل :"},{"type":"Text","content":"لَكَ الَْمحْمِدَةُ أنْ اَطَعْتُكَ، وَلَكَ الْحُجَّةُ أنْ عَصَيْتُكَ، لا صُنْعَ لي وَلا لِغَيْري في اِحْسان إِلاّ بِكَ، ياكائِن (كائناً) قَبْلَ كُلِّ شَيْيء ، وَيا مُكَوِّنَ كُلِّ شَيْيء ، اِنَّكَ عَلى كُلِّ شَيْيء قَديرٌ، اَللّـهُمَّ اِنّي اَعُوذُ بِكَ مِنَ الْعَديلَةِ عِنْدَ الْمَوْتِ، وَمِنْ شَرِّ الْمَرْجِعِ فِي الْقُبُورِ، وَمِنَ النَّدامَةِ يَوْمَ الاْزِفَةِ، فَاَسْاَلُكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد، واَنْ تَجْعَلَ عَيْشي عَيْشَةً نَقِيَّةً وَميتَتي ميتَةً سَوِيَّةً، وَمُنْقَلَبي مُنْقَلَباً كَريماً، غَيْرَ مُخْز وَلا فاضِح، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِهِ الاَْئِمَّةَ، يَنابيعِ الْحِكْمَةِ وَاُولِى النِّعْمَةِ وَمَعادِنِ الْعِصْمَةِ، وَاْعصِمْني بِهِمْ مِنْ كُلِّ سُوء، وَلا تَأخُذْني عَلى غِرَّة، وَلا عَلى غَفْلَة، وَلا تَجْعَلْ عَواقِبَ اَعْمالي حَسْرةً، وَارْضَ عَنّي فَاِنَّ مَغْفِرَتَكَ لِلظّالِمينَ، وَاَنَا مِنَ الظّالِمينَ اَللّـهُمَّ اغْفِرْ لي ما لا يَضُرُّكَ، واَعْطِني ما لا يَنْقُصُكَ، فَاِنَّكَ الْوسيعُ رَحْمَتُهُ، الْبدَيعُ حِكْمَتُهُ، وَاَعْطِني السَّعَةَ وَالدِّعَةَ، والاَْمْنَ وَالصِّحَّةَ، وَالْبُخُوعَ وَالْقُنُوعَ، وَالشُّكْرَ وَالْمُعافاةَ، والتَّقْوى وَالصَّبْرَ، وَالصِّدْقَ عَلَيْكَ وَعَلى اَوْلِيائِكَ، وَالْيُسْرَ وَالشُّكْرَ، وَاَعْمِمْ بِذلِكَ يا رَبِّ اَهْلي وَوَلَدي وَاِخْواني فيكَ وَمَنْ اَحْبَبْتُ وَاَحَبَّني، وَوَلَدْتُ وَوَلَدَني مِنَ الْمُسْلِمينَ وَالْمُؤْمِنينَ يا رَبَّ الْعالَمينَ ."},{"type":"AboutText","content":"قال ابن أشيم: هذا الدّعاء يعقب الثّماني ركعات صلاة اللّيل قبل صلاة الوتر، ثمّ تصلي الثلاث ركعات صلاة الوتر فاذا سلّمت قلت وأنت جالِس :"},{"type":"Text","content":"اَلْحَمْدُ للهِ الَّذي لا تَنْفَدُ خَزائِنُهُ، وَلا يَخافُ آمِنُهُ، رَبِّ اِنِ ارْتَكَبْتُ الْمَعاصِيَ فَذلِكَ ثِقَةٌ مِنّي بِكَرَمِكَ اِنَّكَ تَقْبَلُ التَّوْبَةَ عَنْ عِبادِكَ، وَتَعْفُو عَنْ سَيِّئاتِهِمْ، وَتَغْفِرُ الزَّلَلَ، وَاِنَّكَ مُجيبٌ لِداعيكَ وَمِنْهُ قَريبٌ، وَاَنَا تائِبٌ اِلَيْكَ مِنَ الْخَطايا، وَراغِبٌ اِلَيْكَ في تَوْفيرِ حَظّي مِنَ الْعَطايا، يا خالِقَ الْبَرايا، يا مُنْقِذي مِنْ كُلِّ شَديدَة، يا مُجيري مِنْ كُلِّ مَحْذُور، وَفِّرْ عَلَيَّ السُّرُورَ، وَاكْفِني شَرَّ عَواقِبِ الاْمُورِ، فَاَنْتَ اللهُ عَلى نَعْمائِكَ وَجَزيلِ عَطائِكَ مَشْكُورٌ وَلِكُلِّ خَيْر مَذْخُورٌ ."},{"type":"AboutText","content":"واعلم انّ لكلّ ليلة من ليالي هذا الشّهر الشّريف صلاة خاصّة ذكرها علماؤنا ولا يسمح لنا المقام نقلها ."},{"type":"Text","content":"اليوْم الاوّل مِنْ رَجَب"}],"preview":"الاوّل : أن يقول اذا رأى الهلال: اَللّـهُمَّ اَهِلَّهُ عَلَيْنا بِالاَْمْنِ وَالاْيمانِ وَالسَّلامَةِ وَالاِْسْلامِ رَبّي وَرَبُّكَ اللهُ عَزَّوَجَلَّ وروي عن النّبي (صلى الله عليه","hasTranslate":false},{"id":"mf_ar_91","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القسم الاوّل : الاعمال العامّة التي تؤدّى في جميع الشّهر ولا تخصّ أيّاماً معيّنة منه وهي أمور :","title":"وهو يوم شريف وفيه أعمال :","blocks":[{"type":"Text","content":"الاوّل : الصّيام وقد روي انّ نوحاً (عليه السلام)كان قد ركب سفينته في هذا اليوم فأمر مَنْ معهُ أن يصوموه ومن صام هذا اليوم تباعدت عنه النّار مسير سنة ."}],"preview":"الاوّل : الصّيام وقد روي انّ نوحاً (عليه السلام)كان قد ركب سفينته في هذا اليوم فأمر مَنْ معهُ أن يصوموه ومن صام هذا اليوم تباعدت عنه النّار مسير سنة .","hasTranslate":false},{"id":"mf_ar_92","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القسم الاوّل : الاعمال العامّة التي تؤدّى في جميع الشّهر ولا تخصّ أيّاماً معيّنة منه وهي أمور :","title":"الثّاني : الغُسل","blocks":[{"type":"Text","content":"الثّالث : زيارة الحُسين (عليه السلام) . روى الشيخ عن بشير الدّهان عن الصّادق (عليه السلام) قال : من زار الحسين بن علي (عليهما السلام) أوّل يوم من رجب غفر الله له البتّة ."}],"preview":"الثّالث : زيارة الحُسين (عليه السلام) . روى الشيخ عن بشير الدّهان عن الصّادق (عليه السلام) قال : من زار الحسين بن علي (عليهما السلام) أوّل يوم من رجب غفر الله له البتّة .","hasTranslate":false},{"id":"mf_ar_93","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القسم الاوّل : الاعمال العامّة التي تؤدّى في جميع الشّهر ولا تخصّ أيّاماً معيّنة منه وهي أمور :","title":"الرّابع : أن يدعو بالدّعاء الطّويل المروي في كتاب الاقبال","blocks":[{"type":"Text","content":"الخامس : أن يبتديء صلاة سلمان (رضي الله عنه)، وهي ثلاثون ركعة يصلّي منها في هذا اليوم عشر ركعات، يسلّم بعد كلّ ركعتين، ويقرأ في كلّ ركعة فاتحة الكتاب مرّة، وقُل هُوَ اللهُ اَحَدٌ ثلاث مرّات، وقُل يا أيّها الكافِرُونَ ثلاث مرّات، فاذا سلّم رفع يديه وقال :"},{"type":"Text","content":"لا اِلـهَ إلاَّ اللهُ وَحْدَهُ لا شَريكَ لَهُ، لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ يُحْيي وَيُميتُ، وَهُوَ حَيٌّ لا يَمُوتُ بِيَدِهِ الْخَيْرُ وَهُوَ عَلى كُلِّ شَيْيء قَديرٌ، ثمّ يقول : اَللّـهُمَّ لا مانِعَ لِما اَعْطَيْتَ، وَلا مُعْطِيَ لِما مَنَعْتَ، وَلا يَنْفَعُ ذَا الْجَدِّ مِنْكَ الْجَدُّ، ثمّ يمسح بهما وجهه ويصلّي عشراً بهذه الصّفة في يوم النّصف من رجب ولكن يقول بعد (عَلى كُلِّ شَيْيء قَديرٌ) وَصَلَّى اللهُ عَلى مُحَمَّد وَآلِهِ الطّاهِرينَ وَلا حَوْلَ وَلا قُوَّةَ إِلاّ بِاللهِ الاعَلِيِّ ْلْعَظيمِ، ثمّ يمسح وجهه بيديه، ويسأل حاجته وهذه صلاة ذات فوائد جمّة لا ينبغي التّغاضى عنها، ولسلمان (رحمه الله) أيضاً صلاة اُخرى في هذا اليوم وهي عشر ركعات يقرأ في كلّ ركعة الفاتحة مرّة والتّوحيد ثلاث مرّات وهي صلاة ذات فضل عظيم، فانّها توجب غفران الذّنوب، والوقاية مِن فتنة القبر ومن عذاب يوم القيامة، ويصرف عن من صلّاها الجذام والبرص وذات الجنب ."},{"type":"AboutText","content":"وروى السيّد في الاقبال صلاة اُخرى لهذا اليوم ايضاً فراجعه إن شئت، وفي مثل هذا اليوم من سنة سبع وخمسين كان على بعض الاقوال ولادة الامام الباقر (عليه السلام)، وامّا مختاري فيها فهو اليوم الثّالث من شهر صفر ."},{"type":"Text","content":"وفي اليوم الثالث من هذا الشّهر على بعض الرّوايات كانت ولادة الامام عليّ النّقي (عليه السلام) وكان وفاته في الثّالث من هذا الشّهر سنة مائتين وأربع وخمسين في سرّ من رأى ."}],"preview":"الخامس : أن يبتديء صلاة سلمان (رضي الله عنه)، وهي ثلاثون ركعة يصلّي منها في هذا اليوم عشر ركعات، يسلّم بعد كلّ ركعتين، ويقرأ في كلّ ركعة فاتحة الكتاب مرّة، وقُل هُوَ اللهُ اَحَدٌ ث","hasTranslate":false},{"id":"mf_ar_94","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القسم الاوّل : الاعمال العامّة التي تؤدّى في جميع الشّهر ولا تخصّ أيّاماً معيّنة منه وهي أمور :","title":"اليوم العاشر : كان فيه على قول ابن عيّاش ولادة الامام محمّد التّقي (عليه السلام)","blocks":[{"type":"Text","content":"اللّيْلة الثّالِثة عشرة"},{"type":"AboutText","content":"اعلم انّه يستحبّ أن يصلّي في كلّ ليلة من اللّيالي البيض من هذه الاشهر الثّلاثة رجب وشعبان ورمضان اللّيلة الثالثة عشرة منها ركعتين، يقرء في كلّ ركعة فاتحة الكتاب مرّة، وسورة يس وتبارك الملك والتّوحيد، ويصلّي مثلها أربع ركعات بسلامين في الليلة الرّابعة عشرة، ويأتي ستّ ركعات مثلها يسلّم بين كلّ ركعتين منها في الليلة الخامسة عشرة، فعن الصّادق (عليه السلام) انّه من فعل ذلك حاز فضل هـذه الاشهر الثّلاثة، وغفر له كلّ ذنب سوى شرك ."},{"type":"Text","content":"اليَومُ الثّالث عشر"},{"type":"Text","content":"هو أوّل الايّام البيض، وقد ورد لِلصيام في هذا اليوم واليومين بعده أجر جزيل، ومَن أراد أن يدعو بدعاء أمّ داود فليبدأ بصيام هذا اليوم، وكان في هذا اليوم على المشهور ولادة أمير المؤمنين صلوات الله وسلامه عليه في الكعبة بعد ثلاثين سنة من عام الفيل ."}],"preview":"اللّيْلة الثّالِثة عشرة","hasTranslate":false},{"id":"mf_ar_95","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القسم الاوّل : الاعمال العامّة التي تؤدّى في جميع الشّهر ولا تخصّ أيّاماً معيّنة منه وهي أمور :","title":"الاوّل : الغُسل","blocks":[{"type":"Text","content":"الثّاني : احياؤها بالعبـادة كما قال العلاّمة المجلسي ."}],"preview":"الثّاني : احياؤها بالعبـادة كما قال العلاّمة المجلسي .","hasTranslate":false},{"id":"mf_ar_96","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القسم الاوّل : الاعمال العامّة التي تؤدّى في جميع الشّهر ولا تخصّ أيّاماً معيّنة منه وهي أمور :","title":"الرّابع : الصّلاة ستّ ركعات التّي قد مرّت عند ذكر الليلة الثّالثة عشرة","blocks":[{"type":"Text","content":"الخامس : الصّلاة ثلاثون ركعة، يقرأ في كلّ ركعة الفاتحة مرّة، والتّوحيد عشر مرّات، وقد روى السّيد هذه الصّلاة عن النّبي (صلى الله عليه وآله وسلم)وروى لهـا فضلاً كثيراً ."},{"type":"Text","content":"السّادس : الصّلاة اثنتا عشرة ركعة، تسلم بين كلّ ركعتين، تقرأ في كلّ ركعة كلّاً من سور الفاتحة والتّوحيد والفلق والنّاس وآية الكرسي وسورة (انّا أنزلناهُ) أربع مرّات، ثمّ تسلّم وتقول بعد الفراغ أربع مرّات: اَللهُ اَللهُ رَبّي لا اُشْرِكُ بِهِ شَيْئاً، وَلاَ اَتَّخِذُ مِنْ دُونِه وَلِيّاً، ثمّ تدعو بما أحببت، وقد روى السّيد هذه الصّلاة عن الصّادق (عليه السلام)بهذه الصّفة ولكن الشّيخ قال في المصباح : روى داوُد بن سرحان عن الصّادق (عليه السلام) قال : تصلّي ليلة النّصف من رجب اثنتي عشرة ركعة تقرأ في كلّ ركعة الحمد وسورة، فاذا فرغت من الصّلاة قرأت بعد ذلك الحمد والمعوّذتين وسورة الاخلاص وآية الكرسي أربع مرّات، وتقول بعد ذلك : سُبْحانَ اللهِ وَالْحَمْدُ للهِ وَلا اِلـهَ إلاَّ اللهُ وَاللهُ اَكْبَرُ أربع مرّات، ثمّ تقول : اَللهُ اَللهُ رَبّي لا اُشْرِكُ بِهِ شَيْئاً، وَما شاءَ اللهُ لا قُوَّةَ إِلاّ بِاللهِ الْعَلِيِّ الْعَظيمِ، وتقول في ليلة سبع وعشرين مثلها ."},{"type":"Text","content":"يَومُ النّصف مِن رجب"}],"preview":"الخامس : الصّلاة ثلاثون ركعة، يقرأ في كلّ ركعة الفاتحة مرّة، والتّوحيد عشر مرّات، وقد روى السّيد هذه الصّلاة عن النّبي (صلى الله عليه وآله وسلم)وروى لهـا فضلاً كثيراً .","hasTranslate":false},{"id":"mf_ar_98","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القسم الاوّل : الاعمال العامّة التي تؤدّى في جميع الشّهر ولا تخصّ أيّاماً معيّنة منه وهي أمور :","title":"الثّالث : صلاة سلمان على نحو ما مرّ في اليوم الاوّل","blocks":[{"type":"Text","content":"الرّابع : أن يصلّي أربع ركعات فاذا سلّم بسط يده وقال :"},{"type":"Text","content":"اَللّـهُمَّ يا مُذِلَّ كُلِّ جَبّار، وَيا مُعِزَّ الْمُؤْمِنينَ، اَنْتَ كَهْفي حينَ تُعْيينِى الْمَذاهِبُ، وَاَنْتَ بارِئُ خَلْقي رَحْمَةً بي وَقَدْ كُنْتَ عَنْ خَلْقي غَنِيّاً، وَلَوْلا رَحْمَتُكَ لَكُنْتُ مِنَ الْهالِكينَ، وَاَنْتَ مُؤَيِّدي بِالنَّصْرِ عَلى اَعْدائي وَلَوْلا نَصْرُكَ اِيّايَ لَكُنْتُ مِنَ الْمَفْضُوحينَ، يا مُرْسِلَ الرَّحْمَةِ مِنْ مَعادِنِها، وَمُنْشِىءَ الْبَرَكَةِ مِنْ مَواضِعِها، يا مَنْ خَصَّ نَفْسَهُ بِالشُّمُوخِ وَالرِّفْعَةِ، فَاَوْلِياؤُهُ بِعِزِّهِ يَتَعَزَّزُونَ، وَيا مَنْ وَضَعَتْ لَهُ الْمُلُوكِ نيرَ الْمَذَلَّةِ عَلى اَعْناقِهِمْ، فَهُمْ مِنْ سَطَواتِهِ خائِفُونَ، اَساَلُكَ بِكَيْنُونِيَّتِكَ الَّتِي اشْتَقَقْتَها مِنْ كِبْرِيائِكَ، وَاَساَلُكَ بِكِبْرِيائِكَ الَّتِى اشْتَقَقْتَها مِنْ عِزَّتِكَ، وَاَساَلُكَ بِعِزَّتِكَ الَّتِي اسْتَوَيْتَ بِها عَلى عَرْشِكَ فَخَلَقْتَ بِها جَميعَ خَلْقِكَ فَهُمْ لَكَ مُذْعِنُونَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَاَهْلِ بَيْتِهِ ."}],"preview":"الرّابع : أن يصلّي أربع ركعات فاذا سلّم بسط يده وقال :","hasTranslate":false},{"id":"mf_ar_99","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القسم الاوّل : الاعمال العامّة التي تؤدّى في جميع الشّهر ولا تخصّ أيّاماً معيّنة منه وهي أمور :","title":"وفي الحديث ما دعا بهذا الدّعاء مكروب الّا نفّس الله كُربته","blocks":[{"type":"Text","content":"الخامس : دعاء أمّ داوُد وهو اهمّ أعمال هذا اليوم ومن آثاره قضاء الحوائج وكشف الكروب ودفع ظُلم الظالمين، وصفته على ما أورده الشّيخ في المصباح هي انّ من أراد ذلك فليصم اليوم الثّالث عشر والرّابع عشر والخامس عشر : فاذا كان عند الزّوال من اليوم الخامس عشر اغتسل، فاذا زالت الشّمس صلّى الظّهر والعصر يحسن ركوعهما وسجُودهما، وليكن في موضع خال لا يشغله شاغل، ولا يكلّمه انسان، فاذا فرغ من الصّلاة استقبل القبلة وقرأ الحمد مائة مرّة، والاخلاص مائة مرّة، وآية الكرسي عشر مرّات، ثمّ يقرأ بعد ذلك سُورة الانعام، وبني اسرائيل، والكهف، ولقمان، ويس، والصّافات، وحم، السّجدة وحم، عسق وحم، الدّخان، والفتح، والواقعة، والملك، ون، و (اذا السّماء انشقّت)، وما بعدها الى آخر القرآن، فاذا فرغ من ذلك قال وهو مستقبل القبلة :"},{"type":"Text","content":"صَدَقَ اللهُ الْعَظيمُ الَّذي لا اِلـهَ إِلاّ هُوَ الْحَيُّ الْقَيُّومُ، ذُو الْجَلالِ وَالاِْكْرامِ، الرَّحْمنُ الرَّحيمُ، الْحَليمُ الْكَريمُ، الَّذي لَيْسَ كَمِثْلِهِ شَيْءٌ وَهُوَ السَّميعُ الْعَليمُ الْبَصيرُ الْخَبيرُ، شَهِدَ اللهُ اَنَّهُ لا اِلـهَ إِلاّ هُوَ وَالْمَلائِكَةُ وَاُولُو الْعِلْمِ قائِماً بِالْقِسْطِ لا اِلـهَ إِلاّ هُوَ الْعَزيزُ الْحَكيمُ، وَبَلَّغَتْ رُسُلُهُ الْكِرامُ وَاَنَا عَلى ذلِكَ مِنَ الشّاهِدينَ، اَللّـهُمَّ لَكَ الْحَمْدُ، وَلَكَ الَْمجْدُ، وَلَكَ الْعِزُّ، وَلَكَ الْفَخْرُ، وَلَكَ الْقَهْرُ، وَلَكَ النِّعْمَةُ، وَلَكَ الْعَظَمَةُ، وَلَكَ الرَّحْمَةُ، وَلَكَ الْمَهابَةُ، وَلَكَ السُّلْطانُ، وَلَكَ الْبَهاءُ، وَلَكَ الاِْمْتِنانُ، وَلَكَ التَّسْبيحُ، وَلَكَ التَّقْديسُ، وَلَكَ التَّهْليلُ، وَلَكَ التَّكْبيرُ، وَلَكَ ما يُرى، وَلَكَ ما لا يُرى، وَلَكَ ما فَوْقَ السَّمواتِ الْعُلى، وَ لَكَ ما تَحْتَ الثَّرى، وَلَكَ الاَْرَضُونَ السُّفْلى، وَلَكَ الاْخِرَةُ وَالاُْولى، وَلَكَ ما تَرْضى بِهِ مِنَ الثَّناءِ وَالْحَمْدِ وَالشُّكرِ وَ النَّعْماءِ، اَللّـهُمَّ صَلِّ عَلى جَبْرَئيلَ اَمينِكَ عَلى وَحْيِكَ، وَالْقَوِيِّ عَلى اَمْرِكَ، وَالْمُطاعِ في سَمواتِكَ، وَمَحالِّ كَراماتِكَ الْمُتَحَمِّلِ لِكَلِماتِكَ النّاصِرِ لاَِنْبِيائِكَ الْمُدَمِّرِ لاَِعْدائِكَ، اَللّـهُمَّ صَلِّ عَلى ميكائيلَ مَلَكِ رَحْمَتِكَ، وَالَْمخْلُوقِ لِرَأْفَتِكَ، وَالْمُسْتَغْفِرِ الْمُعينِ لاَِهْلِ طاعَتِكَ، اَللّـهُمَّ صَلِّ عَلى اِسْرافيلَ حامِلِ عَرْشِكَ، وَصاحِبِ الصُّورِ الْمُنْتَظِرِ لاَِمْرِكَ، الْوَجِلِ الْمُشْفِقِ مِنْ خيفَتِكَ، اَللّـهُمَّ صَلِّ عَلى حَمَلَةِ الْعَرْشِ الطّاهِرينَ، وَعَلى السَّفَرَةِ الْكِرامِ الْبَرَرَةِ الطَّيِّبينَ، وَعَلى مَلائِكَتِكَ الْكِرامِ الْكاتِبينَ، وَ عَلى مَلائِكَةِ الْجِنانِ، وَخَزَنَةِ النّيرانِ، وَمَلَكِ الْمَوْتِ وَالاَْعْوانِ، يا ذَا الْجَلالِ وَالاِْكْرامِ، اَللّـهُمَّ صَلِّ عَلى اَبينا آدَمَ بَديعِ فِطْرَتِكَ الَّذي كَرَّمْتَهُ بِسُجُودِ مَلائِكَتِكَ، وَاَبَحْتَهُ جَنَّتَكَ، اَللّـهُمَّ صَلِّ عَلى اُمِّنا حَوّاءَ الْمُطَهَّرَةِ مِنَ الرِّجْسِ، الْمُصَفّاةِ مِنَ الدَّنَسِ، الْمُفَضَّلَةِ مِنَ الاِْنْسِ، الْمُتَرَدِّدَةِ بَيْنَ مَحالِّ الْقُدْسِ، اَللّـهُمَّ صَلِّ عَلى هابيلَ وَشَيْث وَاِدْريسَ وَنُوح وَهُود وَصالِح وَ اِبْراهيمَ وَاِسْماعيلَ وَاِسْحاقَ وَيَعْقُوبَ وَيُوسُفَ وَالاَْسْباطِ وَلُوط وَشُعَيْب وَاَيُّوبَ وَمُوسى وَهارُونَ وَيُوشَعَ وَميشا وَالْخِضْرِ وَذِى الْقَرْنَيْنِ وَيُونُسَ وَاِلْياسَ وَالْيَسَعَ وَذِي الْكِفْلِ وَطالُوتَ وَداوُدَ وَسُلَيْمانَ وَزَكَرِيّا وَشَعْيا وَيَحْيى وَتُورَخَ وَمَتّى وَاِرْمِيا وَحَيْقُوقَ وَدانِيالَ وَعُزَيْر وَعيسى وَشَمْعُونَ وَجِرْجيسَ وَالْحَوارِيّينَ وَالاَْتْباعِ وَخالِد وَحَنْظَلَةَ وَلُقْمانَ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَارْحَمْ مُحَمَّداً وَآلَ مُحَمَّد، وَبارِكْ عَلى مُحَمَّد وَآلِ مُحَمَّد، كَما صَلَّيْتَ وَرَحِمْتَ وَبارَكْتَ عَلى اِبْرهيمَ وَآلِ اِبْرهيمَ اِنَّكَ حَميدٌ مَجيدٌ، اَللّـهُمَّ صَلِّ عَلَى الاَْوْصِياءِ وَالسُّعَداءِ وَالشُّهَداءِ وَاَئِمَّةِ الْهُدى، اَللّـهُمَّ صَلِّ عَلَى الاَْبْدالِ وَالاَْوْتادِ وَالسُّيّاحِ وَالْعُبّادِ وَالُْمخْلِصينَ وَالزُّهّادِ وَاَهْلِ الجِدِّ وَالاِْجْتِهادِ، وَاخْصُصْ مُحَمَّداً وَاَهْلَ بَيْتِهِ بِاَفْضَلِ صَلَواتِكَ وَاَجْزَلِ كَراماتِكَ، وَبَلِّغْ رُوحَهُ وَ جَسَدَهُ مِنّي تَحِيَّةً وَسَلاماً، وَزِدْهُ فَضْلاً وَشَرَفاً وَكَرَماً، حَتّى تُبَلِّغَهُ اَعْلى دَرَجاتِ اَهْلِ الشَّرَفِ مِنَ النَّبِيّينَ وَالْمُرْسَلينَ وَالاَْفاضِلِ الْمُقَرَّبينَ، اَللّـهُمَّ وَصَلِّ عَلى مَنْ سَمَّيْتُ وَمَنْ لَمْ اُسَمِّ مِنْ مَلائِكَتِكَ وَاَنْبِيائِكَ وَرُسُلِكَ وَاَهْلِ طاعَتِكَ، وَاَوْصِلْ صَلَواتي اِلَيْهِمْ وَاِلى اَرْواحِهِمْ، وَاجْعَلْهُمْ اِخْواني فيكَ وَاَعْواني عَلى دُعائِكَ، اَللّـهُمَّ اِنّي اَسْتَشْفِعُ بِكَ اِلَيْكَ، وَبِكَرَمِكَ اِلى كَرَمِكَ، وَبِجُودِكَ اِلى جُودِكَ، وَبِرَحْمَتِكَ اِلى رَحْمَتِكَ، وَبِاَهْلِ طاعَتِكَ اِلَيْكَ، وَاَساَلُكَ الّلهُمَّ بِكُلِّ ما سَأَلَكَ بِهِ اَحَدٌ مِنْهُمْ مِنْ مَسْأَلَة شَريفَة غَيْرِ مَرْدُودَة، وَبِما دَعَوْكَ بِهِ مِنْ دَعْوَة مُجابَة غَيْرِ مُخَيَّبَة، يااَللهُ يارَحْمنُ يا رَحيمُ يا كَريمُ يا عَظيمُ يا جَليلُ يا مُنيلُ يا جَميلُ يا كَفيلُ يا وَكيلُ يا مُقيلُ يا مُجيرُ يا خَبيرُ يا مُنيرُ يا مُبيرُ يا مَنيعُ يا مُديلُ يا مُحيلُ يا كَبيرُ يا قَديرُ يا بَصيرُ يا شَكُورُ يا بَرُّ يا طُهْرُ يا طاهِرُ يا قاهِرُ يا ظاهِرُ يا باطِنُ يا ساتِرُ يا مُحيطُ يا مُقْتَدِرُ يا حَفيظُ يا مُتَجَبِّرُ يا قَريبُ يا وَدُودُ يا حَميدُ يا مَجيدُ يا مُبْدِئُ يا مُعيدُ يا شَهيدُ يا مُحْسِنُ يا مُجْمِلُ يا مُنْعِمُ يا مُفْضِلُ يا قابِضُ يا باسِطُ يا هادي يا مُرْسِلُ يا مُرْشِدُ يا مُسَدِّدُ يا مُعْطي يا مانِعُ يا دافِعُ يا رافِعُ يا باقي يا واقي يا خَلاّقُ يا وَهّابُ يا تَوّابُ يا فَتّاحُ يا نَفّاحُ يا مُرْتاحُ يا مَنْ بِيَدِهِ كُلُّ مِفْتاح، يا نَفّاعُ يا رَؤوفُ يا عَطُوفُ يا كافي يا شافي يا مُعافي يا مُكافي يا وَفِيُّ يا مُهَيْمِنُ يا عَزيزُ يا جَبّارُ يا مُتَكَبِّرُ يا سَلامُ يا مُؤْمِنُ يا اَحَدُ يا صَمَدُ يا نُورُ يا مُدَبِّرُ يا فَرْدُ يا وِتْرُ يا قُدُّوسُ يا ناصِرُ يا مُؤنِسُ يا باعِثُ يا وارِثُ يا عالِمُ يا حاكِمُ يا بادي يا مُتَعالي يا مُصَوِّرُ يا مُسَلِّمُ يا مُتَحَّبِّبُ يا قائِمُ يا دائِمُ يا عَليمُ يا حَكيمُ يا جَوادُ يا بارِىءُ يا بارُّ يا سارُّ يا عَدْلُ يا فاصِلُ يا دَيّانُ يا حَنّانُ يا مَنّانُ يا سَميعُ يا بَديعُ يا خَفيرُ يا مُعينُ يا ناشِرُ يا غافِرُ يا قَديمُ يا مُسَهِّلُ يا مُيَسِّرُ يا مُميتُ يا مُحْيي يا نافِعُ يا رازِقُ يا مُقْتَدِرُ يا مُسَبِّبُ يا مُغيثُ يا مُغْني يا مُقْني يا خالِقُ يا راصِدُ يا واحِدُ يا حاضِرُ يا جابِرُ يا حافِظُ يا شَديدُ يا غِياثُ يا عائِدُ يا قابِضُ، يا مَنْ عَلا فَاسْتَعْلى فَكانَ بِالْمَنْظَرِ الاَْعْلى، يا مَنْ قَرُبَ فَدَنا وَبَعُدَ فَنَأى، وَعَلِمَ السِّرَّ وَاَخْفى، يا مَنْ اِلَيْهِ التَّدْبيرُ وَلَهُ الْمَقاديرُ، وَيا مَنِ الْعَسيرُ عَلَيْهِ سَهْلٌ يَسيرٌ، يا مَنْ هُوَ عَلى ما يَشاءُ قَديرٌ، يا مُرْسِلَ الرِّياحِ، يا فالِقَ الاِْصْباحِ، يا باعِثَ الاَْرْواحِ، يا ذَا الْجُودِ وَالسَّماحِ، يا رادَّ ما قَدْ فاتَ، يا ناشِرَ الاَْمْواتِ، يا جامِعَ الشَّتاتِ، يا رازِقَ مَنْ يَشاءُ بِغَيْرِ حِساب، وَيا فاعِلَ ما يَشاءُ، كَيْفَ يَشاءُ وَيا ذَا الْجَلالِ وَالاِْكْرامِ، يا حَيُّ يا قَيُّومُ، يا حَيّاً حينَ لا حَيَّ، يا حَيُّ يا مُحْيِيَ الْمَوْتى يا حَيُّ لا اِلـهَ إِلاّ اَنْتَ بَديعُ السَّماواتِ وَالاَْرْضِ، يا اِلهي وَسَيِّدي صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَارْحَمْ مُحَمَّداً وَآلَ مُحَمَّد، وَبارِكْ عَلى مُحَمَّد وَآلِ مُحَمَّد، كَما صَلَّيْتَ وَبارَكْتَ وَرَحِمْتَ عَلى اِبْرهيمَ وَآلِ اِبْرهيمَ اِنَّكَ حَميدٌ مَجيدٌ، وَارْحَمْ ذُلىّ وَ فاقَتي وَفَقْري وَانْفِرادي وَوَحْدَتي وَخُضُوعي بَيْنَ يَدَيْكَ وَاعْتِـمادي عَلَيْكَ، وَتَضَرُّعي اِلَيْكَ، اَدْعُوكَ دُعاءَ الْخاضِعِ الذَّليلِ الْخاشِعِ، الْخائِفِ الْمُشْفِقِ الْبائِسِ، الْمَهينِ الْحَقيرِ، الْجائِعِ الْفَقيرِ، الْعائِذِ الْمُسْتَجيرِ، الْمُقِرِّ بِذَنْبِهِ الْمُسْتَغْفِرِ مِنْهُ، الْمُسْتَكينِ لِرَبِّهِ، دُعاءَ مَنْ اَسْلَمْتَهُ ثَقِتُهُ، وَرَفَضَتْهُ اَحِبَتُّهُ، وَعَظُمَتْ فَجيعَتُهُ، دُعاءَ حَرِق حَزين، ضَعيف مَهين، بائِس مُسْتَكين بِكَ مُسْتَجير، اَللّـهُمَّ وَاَساَلُكَ بِاَنَّكَ مَليكٌ، وَاَنَّكَ ما تَشاءُ مِنْ اَمْر يَكُونُ، وَاَنَّكَ عَلى ما تَشاءُ قَديرٌ، وَاَساَلُكَ بِحُرْمَةِ هذَا الشَّهْرِ الْحَرامِ، وَالْبَيْتِ الْحَرامِ، وَالْبَلَدِ الْحَرامِ، وَالرُّكْنِ وَالْمَقامِ، وَالْمَشاعِرِ الْعِظامِ، وَبِحَقِّ نَبِيِّكَ مُحَمَّد عَلَيْهِ وَآلِهِ السَّلامُ، يا مَنْ وَهَبَ لاِدَمَ شِيْثاً، وَلاِِبْراهيمَ اِسْماعيلَ وَاِسْحاقَ، وَيا مَنْ رَدَّ يُوسُفَ عَلى يَعْقُوبَ، وَيا مَنْ كَشَفَ بَعْدَ الْبَلاءِ ضُرَّ اَيُّوبَ، يا رادَّ مُوسى عَلى اُمِّهِ، وَ زائِدَ الْخِضْرِ في عِلْمِهِ، وَيا مَنْ وَهَبَ لِداوُدَ سُلَيْمانَ، وَلِزَكَرِيّا يَحْيى، وَلِمَرْيَمَ عيسى، يا حافِظَ بِنْتِ شُعَيْب، وَيا كافِلَ وَلَدِ اُمِّ مُوسى، اَساَلُكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَنْ تَغْفِرَ لِي ذُنُوبي كُلَّها، وَتُجيرَني مِنْ عَذابِكَ، وَتُوجِبَ لي رِضْوانَكَ وَاَمانَكَ وَاِحْسانَكَ وَغُفْرانَكَ وَجِنانَكَ، وَاَساَلُكَ اَنْ تَفُكَّ عَنّي كُلَّ حَلْقَة بَيْني وَبَيْنَ مَنْ يُؤْذيني، وَتَفْتَحَ لي كُلَّ باب، وَتُلَيِّنَ لي كُلَّ صَعْب، وَتُسَهِّلَ لي كُلَّ عَسَير، وَتُخْرِسَ عَنّي كُلَّ ناطِق بِشَرٍّ، وَتَكُفَّ عَنّي كُلَّ باغ، وَتَكْبِتَ عَنّي كُلَّ عَدُوٍّ لي وَحاسِد، وَتَمْنَعَ مِنّي كُلَّ ظالِم، وَتَكْفِيَني كُلَّ عائِق يَحُولُ بَيْني وَبَيْنَ حاجَتي، وَيُحاوِلُ اَنْ يُفَرِّقَ بَيْني وَبَيْنَ طاعَتِكَ، وَيُثَبِّطَني عَنْ عِبادَتِكَ، يا مَنْ اَلْجَمَ الْجِنَّ الْمُتَمَرِّدينَ، وَقَهَرَ عُتاةَ الشَّياطينِ، وَاَذَلَّ رِقابَ الْمُتَجَبِّرينَ، وَرَدَّ كَيْدَ الْمُتَسَلِّطين عَنِ الْمُسْتَضْعَفينَ، اَساَلُكَ بِقُدْرَتِكَ عَلى ما تَشاءُ، وَتَسْهيلِكَ لِما تَشاءُ كَيْفَ تَشاءُ اَنْ تَجْعَلَ قَضاءَ حاجَتي فيما تَشاءُ ."},{"type":"Text","content":"ثمّ اسجد على الارض وعفّر خدّيك وقل :"},{"type":"Text","content":"اَللّـهُمَّ لَكَ سَجَدْتُ، وَبِكَ امَنْتُ، فَارْحَمْ ذُلّي وَفاقَتي، وَاجْتِهادي وَتَضَرُّعي، وَمَسْكَنَتي وَفَقْرى اِلَيْكَ يا رَبِّ ."},{"type":"Text","content":"واجتهد أن تسح عيناك ولو بقدر رأس الذّبابة دُموعاً فانّ ذلك علامة الاجابة ."},{"type":"Text","content":"اليَومُ الخامس والعشرون"},{"type":"Text","content":"في هذا اليوم من سنة مائة وثلاث وثمانين كانت وفاة الامام موسى بن جعفر (عليهما السلام) في بغداد وله من العُمر خمس وخمسون سنة، وهو يوم يتجدّد فيه احزان آل محمّد (عليهم السلام) وشيعتهم ."}],"preview":"الخامس : دعاء أمّ داوُد وهو اهمّ أعمال هذا اليوم ومن آثاره قضاء الحوائج وكشف الكروب ودفع ظُلم الظالمين، وصفته على ما أورده الشّيخ في المصباح هي انّ من أراد ذلك فليصم اليوم الثّالث","hasTranslate":false},{"id":"mf_ar_100","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القسم الاوّل : الاعمال العامّة التي تؤدّى في جميع الشّهر ولا تخصّ أيّاماً معيّنة منه وهي أمور :","title":"هي ليلة المبعث وهي من اللّيالي المتبرّكة وفيها اعمال :","blocks":[{"type":"Text","content":"الاوّل : قال الشّيخ في المصباح: روى عن أبي جعفر الجواد (عليه السلام)قال: انّ في رجب ليلة هي خير للنّاس ممّا طلعت عليه الشّمس، وهي ليلة السّابع والعشرين منه بُنيّ رسول الله (صلى الله عليه وآله وسلم) في صبيحتها، وانّ للعامل فيها من شيعتنا مثل أجر عمل ستّين سنة . قيل وما العمل فيها ؟ قال : اذا صلّيت العشاء ثمّ أخذت مضجعك ثمّ استيقظت أيّ ساعة من ساعات اللّيل كانت قبل منتصفه صلّيت اثنتي عشرة ركعة، تقرأ في كلّ ركعة الحمد وسورة خفيفة من المفصّل، والمفصّل سورة محمّد (صلى الله عليه وآله وسلم) الى آخر القرآن، وتسلّم بين كلّ ركعتين، فاذا فرغت من الصّلوات جلست بعد السّلام وقرأت الحمد سبعاً، والمعوذّتين سبعاً، و (قُلْ هُوَ اللهُ أحَدٌ) و (قُل يا أيّها الكافِرُونَ) كلاً منهما سبعاً، وانّا أنزلناه وآية الكُرسي كلاً منهما سبعاً، وتقول بعد ذلك كلّه :"},{"type":"Text","content":"اَلْحَمْدُ للهِ الَّذي لَمْ يَتَّخِذْ وَلَداً وَلَمْ يَكُنْ لَهُ شَريكٌ في الْمُلْكِ، وَلَمْ يَكُنْ لَهُ وَلِيٌّ مِنَ الذُّلِّ وَكَبِّرْهُ تَكْبيراً اَللّـهُمَّ اِنّي اَساَلُكَ بِمَعاقِدِ عِزِّكَ عَلَىَّ، اَرْكانِ عَرْشِكَ، وَمُنْتَهَى الرَّحْمَةِ مِنْ كِتابِكَ، وَبِاسْمِكَ الاَْعْظَمِ الاَْعْظَمِ الاَْعْظَمِ، وَذِكْرِكَ الاَْعْلَى الاَْعْلَى الاَْعْلَى، وَبِكَلِماتِكَ التّامّاتِ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِهِ، وَاَنْ تَفْعَلَ بي ما اَنْتَ اَهْلُهُ . ثمّ ادع بما شئت، ويستحبّ الغُسل في هذه اللّيلة وقد مرّت عند ذكر ليلة النّصف من رجب (ص143) صلاة تصلّى ايضاً في هذه اللّيلة ."},{"type":"Text","content":"الثّاني : زيارة أمير المؤمنين (عليه السلام)، وهي أفضل أعمال هذه اللّيلة، وله (عليه السلام) في هذه اللّيلة زيارات ثلاث سنشير اليها في باب الزيارات ان شاء الله، واعلم انّ أبا عبد الله محمّد بن بطوطة الذي هو من علماء أهل السّنة وقد عاش قبل ستّة قرون قد أتى بذكر المرقد الطّاهر لمولانا امير المؤمنين (عليه السلام) في رحلته المعروفة باسمه (رحلة ابن بطُوطة) عندما ذكر دخوله مدينة النّجف الاشرف في عودته من مكّة المُعظّمة، فقال: وأهل هذه المدينة كُلّهم رافضيّة وهذه الرّوضة ظهرت لها كرامات، منها انّ في ليلة السّابع والعشرين من رجب وتسمّى عندهم ليلة المحيى يؤتى الى تلك الرّوضة بكلّ مفعد، من العراقين وخراسان وبلاد فارس والرّوم، فيجتمع منهم الثّلاثون والاربعُون ونحو ذلك، فاذا كان بعد العشاء الاخرة جعلوا فوق الضّريح المقدّس والنّاس ينتظرون قيامهم وهم ما بين مصلّ وذاكر وتال ومشاهد الرّوضة، فاذا مضى من اللّيل نصفه أو ثلثاه أو نحو ذلك قام الجميع أصحّاء من غير سوء، وهم يقولون: لا اِلـهَ إلاَّ اللهُ مُحَمَّدٌ رَسُولُ اللهِ عَلَيٌّ وَليُّ اللهِ، وهذا أمر مستفيض عندهم سمعته من الثّقات ولم أحضر تلك اللّيلة، لكنّي رأيت بمدرسة الضيّاف ثلاثة من الرّجال، أحدهم من أرض الرّوم، والثّاني من اصفهان، والثّالث من خراسان، وهم مقعدون فاستخبرتهم عن شأنهم فأخبروني انّهم لم يدركوا الليلة المحيى، وانّهم منتظرون أوانها من عام آخر، وهذه اللّيلة يجتمع لها النّاس من البلاد خلق كثير، ويقيمون سوقاً عظيمة مدّة عشرة أيّام ."},{"type":"AboutText","content":"أقول : لا تستبعد هذا الحديث فانّ ما برز من هذه الرّوضات الشّريفة من الكرامات الثّابتة لنا عن طريق التّواتر تفوق حدّ الاحصاء، وهذا شهر شوّال من السّنة الماضية سنة ألف وثلاثمائة وأربعين قد شاهد الملا فيه معجزة باهرة غير قابلة للافكار ومن المرقد الطّاهر لامامنا ثامِن الائمة الهداة، وضامن الامة العُصاة مولانا أبي الحسن عليّ بن موسى الرّضا صلوات الله وسلامه عليه، فثلاث نسوة مقعدة مصابة بالفالج أو نظائره قد توسّلن بهذا المرقد الشّريف والاطبّاء ودكاترة الطب كانت قد أبدت عجزها عن علاجهنّ، فبان ما رزقن من الشّفاء للملا ناصعاً كالشّمس في السماء الصّاحية، وكمعجزة انفتاح باب مدينة النّجف على أعراب البادية، وقد تجلّت هذه الحقيقة للجميع فآمن بها على ما حكى حتى دكاترة الطّب الواقفين على أماكن مصابة به من الاسقام، فأبدوا تصديقهم لها مع شدّة تبيّنهم للامر ورقّتهم فيه، وقد سجّل بعضهم كتاباً يشهد فيه على ما رزقن من الشّفاء، ولو لا ملاحظة الاختصار ومناسبة المقام لاثبتّ القصة كاملة ولقد أجاد شيخنا الحرّ العاملي في اُرجوزته :"},{"type":"Text","content":"وَما بَدا مِنْ بَرَكاتِ مَشْهَدهِ في كُلِّ يَوْم اَمْسُهُ مِثْلُ غَدِهِ"},{"type":"Text","content":"وَكَشِفَا الْعمى وَالمَرْضى بِهِ اِجابَةُ الدُّعاءِ في اَعْتابِهِ"}],"preview":"الاوّل : قال الشّيخ في المصباح: روى عن أبي جعفر الجواد (عليه السلام)قال: انّ في رجب ليلة هي خير للنّاس ممّا طلعت عليه الشّمس، وهي ليلة السّابع والعشرين منه بُنيّ رسول الله (صلى الل","hasTranslate":false},{"id":"mf_ar_101","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القسم الاوّل : الاعمال العامّة التي تؤدّى في جميع الشّهر ولا تخصّ أيّاماً معيّنة منه وهي أمور :","title":"الثّالث : قال الكفعمي في كتاب البلد الامين: اُدع في ليلة المبعث بهذا الدّعاء :","blocks":[{"type":"Text","content":"اَللّـهُمَّ اِنّي اَساَلُكَ بِالتَّجَلِي الاَْعْظَمِ في هذِهِ اللَّيْلَةِ مِنَ الشَّهْرِ الْمُعَظَّمِ وَالْمُرْسَلِ الْمُكَرَّمِ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِهِ، وَاَنْ تَغْفِرَ لَنا ما اَنْتَ بِهِ مِنّا اَعْلَمُ، يا مَنْ يَعْلَمُ وَلا نَعْلَمُ، اَللّـهُمَّ بارِكْ لَنا في لَيْلَتِنا هذِهِ الَّتي بِشَرَفِ الرِّسالَةِ فَضَّلْتَها، وَبِكَرامَتِكَ اَجْلَلْتَها، وَبِالَْمحَلِّ الشَّريفِ اَحْلَلْتَها، اَللّـهُمَّ فَاِنّا نَسْأَلُكَ بِالْمَبْعَثِ الشَّريفِ، وَالسَّيِّدِ اللَّطيفِ، وَالْعُنْصُرِ الْعَفيفِ، اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِهِ، وَ اَنْ تَجْعَلَ اَعْمالَنا في هذِهِ اللَّيْلَةِ وَفي سايِرِ اللَّيالي مَقْبُولَةً، وَذُنُوبَنا مَغْفُورَةً، وَحَسَناتِنا مَشْكُورَةً، وَسَيِّئاتِنا مَسْتُورَةً، وَقُلُوبَنا بِحُسْنِ الْقَوْلِ مَسْرُورَةً، وَاَرْزاقَنا مِنْ لَدُنْكَ بِالْيُسْرِ مَدْرُورَةً، اَللّـهُمَّ اِنَّكَ تَرى وَلا تُرى، وَاَنْتَ بِالْمَنْظَرِ الاَْعْلى، وَاِنَّ اِلَيْكَ الرُّجْعى وَالْمُنْتَهى، وَاِنَّ لَكَ الْمَماتَ وَالَْمحْيا، وَاِنَّ لَكَ الاْخِرَةَ وَالاُْولى، اَللّـهُمَّ اِنّا نَعُوذُ بِكَ اَنْ نَذِلَّ وَنَخْزى، وَاَنْ نَأتِيَ ما عَنْهُ تَنْهى اَللّـهُمَّ اِنّا نَسْأَلُكَ الْجَنَّةَ بِرَحْمَتِكَ، وَنَسْتَعيذُ بِكَ مِنَ النّارِ فَاَعِذْنا مِنْها بِقُدْرَتِكَ وَنَسْأَلُكَ مِنَ الْحُورِ الْعينِ فَارْزُقْنا بِعِزَّتِكَ، وَاجْعَلْ اَوْسَعَ اَرْزاقِنا عِنْدَ كِبَرِ سِنِّنا، وَاَحْسَنَ اَعْمالِنا عِنْدَ اقْتِرابِ آجالِنا، وَاَطِلْ في طاعَتِكَ وَما يُقَرِّبُ اِلَيْكَ وَيُحْظي عِنْدَكَ وَيُزْلِفُ لَدَيْكَ اَعْمارَنا، وَاَحْسِنْ في جَميعِ اَحْوالِنا وَاُمُورِنا مَعْرِفَتَنا، وَلا تَكِلْنا اِلى اَحَد مِنْ خَلْقِكَ فَيَمُنَّ عَلَيْنا، وَتَفَضَّلْ عَلَيْنا بجَميعِ حَوائِجِنا لِلدُّنْيا وَالاْخِرَةِ، وَابْدَأ بِابائِنا وَاَبْنائِنا وَجَميعِ اِخْوانِنَا الْمُؤْمِنينَ في جَميعِ ما سَأَلْناكَ لاَِنْفُسِنا يا اَرْحَمَ الرّاحِمينَ، اَللّـهُمَّ اِنّا نَسْأَلُكَ بِاسْمِكَ الْعَظيمِ، وَمُلْكِكَ الْقَديمِ، اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَنْ تَغْفِرَ لَنَا الذَّنْبَ الْعَظيمَ اِنَّهُ لا يَغْفِرُ الْعَظيمَ الْعَظيمُ، اَللّـهُمَّ وَهذا رَجَبٌ الْمُكَرَّمُ الَّذي اَكْرَمْتَنا بِهِ، اَوَّلُ اَشْهُرِ الْحُرُمِ، اَكْرَمْتَنا بِهِ مِنْ بَيْنِ الاُْمَمِ، فَلَكَ الْحَمْدُ يا ذَا الْجُودِ وَالْكَرَمِ، فَاَسْأَلُكَ بِهِ وَبِاسْمِكَ الاَْعْظَمِ الاَْعْظَمِ الاَْعْظَمِ الاَْجَلِّ الاَْكْرَمِ، الَّذي خَلَقْتَهُ فَاسْتَقَرَّ في ظِلِّكَ فَلا يَخْرُجُ مِنْكَ اِلى غَيْرِكَ، اَنْ تُصَلِّيَ عَلى مُحَمَّد وَاَهْلِ بَيْتِهِ الطّاهِرينَ، وَاَنْ تَجْعَلَنا مِنَ الْعامِلينَ فيهِ بِطاعَتِكَ، وَالاْمِلينَ فيهِ لِشَفاعَتِكَ، اَللّـهُمَّ اهْدِنا اِلى سَواءِ السَّبيلِ، وَاجْعَلْ مَقيلَنا عِنْدَكَ خَيْرَ مَقيل، في ظِلٍّ ظَليل، وَمُلك جَزيل، فَاِنَّكَ حَسْبُنا وَنِعْمَ الْوَكيلُ، اَللّـهُمَّ اقْلِبْنا مُفْلِحينَ مُنْجِحينَ غَيْرَ مَغْضُوب عَلَيْنا وَلا ضالّينَ، بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ، اَللّـهُمَّ اِنّي اَساَلُكَ بِعَزائِمِ مَغْفِرَتِكَ، وَبِواجِبِ رَحْمَتِكَ، السَّلامَةَ مِنْ كُلِّ اِثْم، وَالْغَنيمَةَ مِنْ كُلِّ بِرٍّ، وَالْفَوْزَ بِالْجَنَّةِ وَالنَّجاةَ مِنَ النّارِ، اَللّـهُمَّ دَعاكَ الدّاعُونَ وَدَعَوْتُكَ، وَسَأَلَكَ السّائِلُونَ وَسَأَلْتُكَ وَطَلَبَ اِلَيْكَ الطّالِبُونَ وَطَلَبْتُ اِلَيْكَ، اَللّـهُمَّ اَنْتَ الثِّقَةُ وَالرَّجاءُ، وَاِلَيْكَ مُنْتَهَى الرَّغْبَةِ فِي الدُّعاءِ، اَللّـهُمَّ فَصَلِّ عَلى مُحَمَّد وَآلِهِ، وَاجْعَلِ الْيَقينَ في قَلْبي، وَالنُّورَ في بَصَري، وَالنَّصيحَةَ في صَدْري، وَذِكْرَكَ بِاللَّيْلِ وَالنَّهارِ عَلى لِساني، وَرِزْقاً واسِعاً غَيْرَ مَمْنُون وَلا مَحْظُور فَارْزُقْني، وَبارِكْ لي فيما رَزَقْتَني، وَاجْعَلْ غِنايَ في نَفْسي، وَرَغْبَتي فيما عِنْدَكَ بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ، ثمّ اسجد وقُلْ : اَلْحَمْدُ للهِِ الَّذي هَدانا لِمَعْرِفَتِهِ، وَخَصَّنا بِوِلايَتِهِ، وَوَفَّقَنا لِطاعَتِهِ، شُكْراً شُكْراً مائة مرّة، ثمّ ارفع رأسك من السّجود وقُل : اَللّـهُمَّ اِنّي قَصَدْتُكَ بِحاجَتي، وَاعْتَمَدْتُ عَلَيْكَ بِمَسْأَلَتي، وَتَوَجَّهْتُ اِلَيْكَ بِاَئِمَّتي وَسادَتي، اَللّـهُمَّ انْفَعْنا بِحُبِّهِم، وَاَوْرِدْنا مَوْرِدَهُمْ، وَارْزُقْنا مُرافَقَتَهُمْ، وَاَدْخِلْنَا الْجَنَّةَ في زُمْرَتِهِمْ، بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ ."}],"preview":"اَللّـهُمَّ اِنّي اَساَلُكَ بِالتَّجَلِي الاَْعْظَمِ في هذِهِ اللَّيْلَةِ مِنَ الشَّهْرِ الْمُعَظَّمِ وَالْمُرْسَلِ الْمُكَرَّمِ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِهِ، وَاَنْ تَغْفِ","hasTranslate":false},{"id":"mf_ar_102","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القسم الاوّل : الاعمال العامّة التي تؤدّى في جميع الشّهر ولا تخصّ أيّاماً معيّنة منه وهي أمور :","title":"وقد ذكر السّيد هذا الدّعاء لِيوم المبعث","blocks":[{"type":"Text","content":"اليَومُ السّابع والعشرُون"},{"type":"Text","content":"وهو عيد من الاعياد العظيمة وفيه كان بعثة النّبي (صلى الله عليه وآله وسلم) وهبوط جبرئيل عليه (صلى الله عليه وآله وسلم) بالرّسالة، ومن الاعمال الواردة فيه :"}],"preview":"اليَومُ السّابع والعشرُون","hasTranslate":false},{"id":"mf_ar_104","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القسم الاوّل : الاعمال العامّة التي تؤدّى في جميع الشّهر ولا تخصّ أيّاماً معيّنة منه وهي أمور :","title":"الرّابع : زيارة النّبي وزيارة أمير المؤمنين عليهما وآلهما السّلام","blocks":[{"type":"Text","content":"الخامس : قال الشّيخ في المصباح : روى الريّان بن الصّلت ، قال : صام الجواد(عليه السلام) لما كان ببغداد يوم النّصف من رجب ويوم سبع وعشرين منه وصام جميع حشمه، وأمرنا أن نصلّي الصّلاة الّتي هي اثنتا عشرة ركعة، تقرأ في كلّ ركعة الحمد وسورة فاذا فرغت قرأت الحمد أربعاً و (قل هو الله أحد) أربعاً والمعوّذتين أربعاً وقلت أربعاً : لا اِلـهَ إِلاّ اللهُ واللهُ اَكْبَرُ، وَسُبْحانَ اللهِ وَالْحَمْدُ للهِ، وَلا حَوْلَ وَلا قُوَّةَ إِلاّ بِاللهِ الْعَلِيِّ الْعَظيم، وأربعاً : اللهُ اللهُ رَبِّي لا اُشْرِكُ بِهِ شَيْئاً، وأربعاً : لا اُشْرِكُ بِرَبِّي اَحَداً ."},{"type":"Text","content":"السّادس : وروى الشّيخ ايضاً عن أبي القاسم حسين بن روح (رحمه الله)قال : تصلّى في هذا اليوم اثنتي عشرة ركعة نقراء في كلّ ركعة فاتحة الكتاب وما تيسّر من السّور، وتتشهّد وتسلّم وتجلس وتقول بين كلّ ركعتين : اَلْحَمْدُ للهِ الَّذي لَمْ يَتَّخِذْ وَلَداً، وَلَمْ يَكُنْ لَهُ شَريكٌ في الْمُلْكِ، وَلَمْ يَكُنْ لَهُ وَلِيٌّ مِنَ الذُّلِّ وَكَبِّرْهُ تَكْبيراً، يا عُدَّتي في مُدَّتي، يا صاحِبي في شِدَّتي، يا وَليّي في نِعْمَتي، يا غِياثي في رَغْبَتي، يا نَجاحي في حاجَتي، يا حافِظي في غَيْبَتي، يا كافيَّ في وَحْدَتي، يا اُنْسي في وَحْشَتي، اَنْتَ السّاتِرُ عَوْرَتي فَلَكَ الْحَمْدُ، واَنْتَ الْمُقيلُ عَثْرَتي فَلَكَ الْحَمْدُ، وَاَنْتَ الْمُنْعِشُ صَرْعَتي فَلَكَ الْحَمْدُ، صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاسْتُرْ عَوْرَتي، وَآمِنْ رَوْعَتي، وَاَقِلْني عَثْرَتي، وَاصْفَحْ عَنْ جُرْمي، وَتَجاوَزْ عَنْ سَيِّئاتي في اَصْحابِ الْجَنَّةِ وَعْدَ الصِّدْقِ الَّذي كانُوا يُوَعَدُونَ ."},{"type":"Text","content":"فاذا فرغت من الصّلاة والدّعاء قرأت الحمد والاخلاص والمعوّذتين و(قل يا أيّها الكافرون) و (انّا أنزلناه) وآية الكرسي سبع مرّات، ثمّ تقول : لا اِلـهَ إلاَّ اللهُ واللهُ اَكْبَرُ وَسُبْحانَ اللهِ وَلا حَوْلَ وَلا قُوَّةَ إِلاّ بِاللهِ سبع مرّات، ثمّ تقول سبع مرّات : اللهُ اللهُ رَبِّي لا اُشْرِكُ بِهِ شَيْئاً، وتدعو بما أحببت ."}],"preview":"الخامس : قال الشّيخ في المصباح : روى الريّان بن الصّلت ، قال : صام الجواد(عليه السلام) لما كان ببغداد يوم النّصف من رجب ويوم سبع وعشرين منه وصام جميع حشمه، وأمرنا أن نصلّي الصّلاة","hasTranslate":false},{"id":"mf_ar_105","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القسم الاوّل : الاعمال العامّة التي تؤدّى في جميع الشّهر ولا تخصّ أيّاماً معيّنة منه وهي أمور :","title":"السّابع : في الاقبال وفي بعض نسخ المصباح انّه يستحبّ الدّعاء في هذا اليوم بهذا الدّعاء :","blocks":[{"type":"Text","content":"يا مَنْ اَمَرَ بِالْعَفْوِ وَالتَّجاوُزِ، وَضَمَّنَ نَفْسَهُ الْعَفْوَ وَالتَّجاوُزَ، يا مَنْ عَفا وَتَجاوَزَ، اُعْفُ عَنّي وَتَجاوَزْ يا كَريمُ اَللّـهُمَّ وَقَدْ اَكْدَى الطَّلَبُ، وَاَعْيَتِ الْحيلَةُ وَالْمَذْهَبُ، وَدَرَسَتِ الاْمالُ، وَانْقَطَعَ الرَّجاءُ اِلاّ مِنْكَ وَحْدَكَ لا شَريكَ لَكَ، اَللّـهُمَّ اِنّي اَجِدُ سُبُلَ الْمَطالِبِ اِلَيْكَ مُشْرَعَةً، وَمناهِلَ الرَّجاءِ لَدَيْكَ مُتْرَعَةً، واَبْوابَ الدُّعاءِ لِمَنْ دَعاكَ مُفتَّحَةً، وَالاِسْتِعانَةَ لِمَنِ اسْتَعانَ بِكَ مُباحَةً، وَاَعْلَمُ اَنَّكَ لِداعيكَ بِمَوْضِعِ اِجابَة، وَللصّارِخِ اِلَيْكَ بِمَرْصَدِ اِغاثَة، وَاَنَّ فِي اللَّهْفِ اِلى جُودِكَ وَالظَّمانِ بِعِدَتِكَ عِوَضاً مِنْ مَنْعِ الْباخِلينَ، وَمَنْدُوحَةً عَمّا في اَيْدِى الْمُسْتَأثِرينَ، وَاَنَّكَ لا تَحْتَجِبُ عَنْ خَلْقِكَ إِلاّ اَنْ تَحْجُبُهُمُ الاَْعْمالُ دُونَكَ، وَقَدْ عَلِمْتُ اَنَّ اَفْضَلَ زادِ الرّاحِلِ اِلَيْكَ عَزْمُ اِرادَة يَخْتارُكَ بِها، وَقَدْ ناجاكَ بِعَزْمِ الاِرادَةِ قَلْبي، وَاَساَلُكَ بِكُلِّ دَعْوَة دَعاكَ بِها راج بَلَّغْتَهُ اَمَلَهُ، اَوْ صارِخ اِلَيْكَ اَغَثْتَ صَرْخَتَهُ، اَوْ مَلْهُوف مَكْرُوب فَرَّجْتَ كَرْبَهُ، اَوْ مُذْنِب خاطِئ غَفَرْتَ لَهُ اَوْ مُعافىً اَتْمَمْتَ نِعْمَتَكَ عَلَيْهِ، اَوْ فَقير اَهْدَيْتَ غِناكَ اِلَيْهِ، وَلِتِلْكَ الَّدعْوَةِ عَلَيْكَ حَقٌّ وَعِنْدَكَ مَنْزِلَةٌ، إِلاّ صَلَّيْتَ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَقَضَيْتَ حَوائِجي حَوائِجَ الدُّنْيا وَالاْخِرَةِ، وَهـذا رَجَبٌ الْمُرَجَّبُ الْمُكَرَّمُ الَّذي اَكْرَمْتَنا بِهِ اَوَّلُ اَشْهُرِ الْحُرُمِ، اَكْرَمْتَنا بِهِ مِنْ بَيْنِ الاُْمَمِ، يا ذَا الْجُودِ وَالْكَرَمِ، فَنَسْأَلُكَ بِهِ وَبِاسْمِكَ الاَْعْظَمِ الاَْعْظَمِ الاَْعْظَمِ الاَْجَلِّ الاَْكْرَمِ، الَّذي َخَلَقْتَهُ فَاسْتَقَرَّ في ظِلِّكَ فَلا يَخْرُجُ مِنْكَ اِلى غَيْرِكَ، اَنْ تُصَلِّيَ عَلى مُحَمَّد وَاَهْلِ بَيْتِهِ الطّاهِرينَ، وَتَجْعَلَنا مِنَ الْعامِلينَ فيهِ بِطاعَتِكَ، وَالاْمِلينَ فيهِ بِشَفاعَتِكَ، اَللّـهُمَّ وَاهْدِنا اِلى سَواءِ السِّبيلِ، وَاجْعَلْ مَقيلَنا عِنْدَكَ خَيْرَ مَقيل، في ظِلٍّ ظَليل، فَاِنَّكَ حَسْبُنا وَنِعْمَ الوَكيلُ، وَالسَّلامُ عَلى عِبادِهِ المُصْطَفِيْنَ، وَصَلَواتُهُ عَلَيْهِمْ اَجْمَعينَ، اَللّـهُمَّ وَبارِكَ لَنا في يَوْمِنا هَذَا الَّذي فَضَّلْتَهُ، وَبِكَرامَتِكَ جَلَّلْتَهُ، وَبِالْمَنْزِلِ الْعظيمِ الاَْعْلى اَنْزَلْتَهُ، صَلِّ عَلى مَنْ فيهِ اِلى عِبادِكَ اَرْسَلْتَهُ، وَبالَْمحَلِّ الْكَريمِ اَحْلَلْتَهُ، اَللّـهُمَّ صَلِّ عَلَيْهِ صَلاةً دائِمَةً تَكُونُ لَكَ شُكْراً وَلنا ذُخراً، وَاجْعَلْ لَنا مِنْ اَمْرِنا يُسراً، وَاخْتِمْ لَنا بِالسَّعادَةِ اِلى مُنْتَهى آجالِنا، وَقَدْ قَبِلْتَ الْيسيرَ مِنْ اَعْمالِنا، وَبَلَّغْتَنا بِرَحْمَتِكَ اَفْضَلَ آمالِنا، اِنَّكَ عَلى كُلِّ شَيء قَديرٌ، وَصَلَّى اللهُ عَلى مُحَمَّد وَآلِهِ وَسَلَّم ."},{"type":"AboutText","content":"أقول : هذا دعاء الامام موسى بن جعفر (عليه السلام) وكان قد دعا به يوم انطلقوا به نحو بغداد وهو اليوم السّابع والعشرون من رجب وهو دعاء مذخور من أدعية رجب ."},{"type":"Text","content":"الثّامن : قال في الاقبال قل: اَللّـهُمَّ اِنِّي اَساَلُكَ بِالنَّجْلِ الاَْعْظَمِ، الدّعاء وقد مرّ هذا الدّعاء على رواية الكفعمي في دعوات الليلة السّابعة والعشرين ."},{"type":"Text","content":"اليَومُ الاخير من الشّهر"},{"type":"Text","content":"ورد فيه الغُسل وصيامه يُوجب غفران الذّنوب ما تقدّم منها وما تأخّر، ويصلّي فيه صلاة سلمان التّي مرّت في اليوم الاوّل ."}],"preview":"يا مَنْ اَمَرَ بِالْعَفْوِ وَالتَّجاوُزِ، وَضَمَّنَ نَفْسَهُ الْعَفْوَ وَالتَّجاوُزَ، يا مَنْ عَفا وَتَجاوَزَ، اُعْفُ عَنّي وَتَجاوَزْ يا كَريمُ اَللّـهُمَّ وَقَدْ اَكْدَى الطَّلَب","hasTranslate":false},{"id":"mf_ar_106","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل الثّاني :","title":"في فضلِ شهر شعبان والاعمال الواردة فيه","blocks":[{"type":"AboutText","content":"اعلم انّ شهر شعبان شهر شريف وهو منسوب الى رسول الله (صلى الله عليه وآله وسلم) وكان (صلى الله عليه وآله وسلم) يصوم هذا الشّهر ويوصل صيامه بشهر رمضان، وكان (صلى الله عليه وآله وسلم) يقول : شعبان شهري من صامَ يوماً من شهري وجبت له الجنّة ، وروى عن الصّادق (عليه السلام) انّه قال : كان السّجاد (عليه السلام) اذا دخل شعبان جمع أصحابه وقال (عليه السلام): يا أصحابي أتدرون ما هذا الشّهر، هذا شهر شعبان وكان النّبي (صلى الله عليه وآله وسلم) يقول : شعبان شهري، فصوموا هذا الشّهر حُبّاً لنبيّكم وتقرّباً الى ربّكم، أقسم بمن نفسي بيده لقد سمعت أبي الحسين (عليه السلام) يقول : سمعت أمير المؤمنين (عليه السلام) يقول : من صام شعبان حُبّاً لرسول الله (صلى الله عليه وآله وسلم) وتقرّباً الى الله أحبّه الله وقرّبه الى كرامته يوم القيامة وأوجب له الجنّة ."},{"type":"AboutText","content":"وروى الشّيخ عن صفوان الجمّال قال : قال لي الصّادق (عليه السلام) حُثّ من في ناحيتك على صوم شعبان، فقلت : جعلت فداك ترى فيه شيئاً ، فقال : نعم انّ رسول الله (صلى الله عليه وآله وسلم) كان اذا رأى هلال شعبان أمر منادياً ينادي في المدينة : يا أهل يثرب انّي رسول رسول الله (صلى الله عليه وآله وسلم)اليكم ألا انّ شعبان شهري فرحم الله من أعانني على شهري . ثمّ قال انّ أمير المؤمنين (عليه السلام) كان يقول : ما فاتني صوم شعبان منذ سمعت منادي رسول الله (عليه السلام) ينادي في شعبان، ولن يفوتني أيّام حياتي صوم شعبان ان شاء الله تعالى ، ثمّ كان (عليه السلام) يقول : صوم شهرين متتابعين توبة من الله ."},{"type":"AboutText","content":"وروى اسماعيل بن عبد الخالق قال : كنت عند الصّادق (عليه السلام)فجرى ذكر صوم شعبان فقال الصّادق (عليه السلام): انّ في فضل صوم شعبان كذا وكذا حتّى انّ الرّجل ليرتكب الدّم الحرام فيغفر له، واعلم انّ ما ورد في هذا الشّهر الشّريف من الاعمال نوعان : أعمال عامّة تؤتى في جميع الشّهر، وأعمال خاصّة تخصّ أيّاماً أو ليالي خاصّة منه، والاعمال العامّة هي ما يلي :"}],"preview":"اعلم انّ شهر شعبان شهر شريف وهو منسوب الى رسول الله (صلى الله عليه وآله وسلم) وكان (صلى الله عليه وآله وسلم) يصوم هذا الشّهر ويوصل صيامه بشهر رمضان، وكان (صلى الله عليه وآله وسلم)","hasTranslate":false},{"id":"mf_ar_107","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل الثّاني :","title":"الاوّل : أن يقول في كلّ يوم سبعين مرّة: اَسْتَغْفِر اللهَ وَاَسْأَلُهُ التَّوْبَةَ","blocks":[{"type":"Text","content":"الثّاني : أن يستغفر كلّ يوم سبعين مرّة قائلاً: اَسْتَغْفِر اللهَ الّذي لا اِلـهَ اِلاَّ هُوَ الرَّحْمنُ الرَّحيمُ الْحَيُّ الْقَيُّومُ وَاَتُوبُ اِلَيْهِ ووردت كلمة (الحي القيّوم) في بعض الرّوايات قبل كلمة (الرَّحْمنُ الرَّحيمُ) وبأيّ الروايتين عمل فقد أحسن الاستغفار، كما يستفاد من الرّوايات أفضل الادعية والاذكار في هذا الشّهر، ومن استغفر في كلّ يوم من هذا الشّهر سبعين مرّة كان كمن استغفر الله سبعين ألف مرّة في سائر الشّهور ."},{"type":"Text","content":"الثّالث : أن يتصدّق في هذا الشّهر ولو بنصف تمرة ليحرم الله تعالى جسده على النّار، وعن الصّادق (عليه السلام) انّه سئل عن صوم رجب ، فقال : أين أنتم عن صوم شعبان ، فقال له الراوي : ياابن رسول الله (صلى الله عليه وآله وسلم) ما ثواب من صام يوماً من شعبان ؟ فقال : الجنّة والله ، فقال الراوي : ما أفضل ما يفعل فيه ، قال: الصّدقة والاستغفار، ومن تصدّق بصدقة في شعبان رباها الله تعالى كما يربى أحدكم فصيله حتّى يوافى يوم القيامة وقد صار مثل أُحد ."},{"type":"Text","content":"الرّابع : أن يقول في شعبان ألف مرّة: لا اِلـهَ إلاَّ اللهُ وَلا نَعْبُدُ إِلاّ اِيّاهُ مُخلِصينَ لَهُ الدّينَ وَلَوْ كَرِهَ الْمُشْرِكُونَ ولهذا العمل الشّريف أجر عظيم، ويكتب لمن أتى به عبادة ألف سنة ."},{"type":"Text","content":"الخامس : أن يصلّي في كلّ خميس من شعبان ركعتين يقرء في كلّ ركعة فاتحة الكتاب مرّة وقل هو الله احد مائة مرّة فاذا سلّم صلّى على النّبي وآله مائة مرّة، ليقضي الله له كلّ حاجة من أمور دينه ودنياه، ويستحبّ صيامه ايضاً ففي الحديث تتزيّن السّماوات في كلّ خميس من شعبان فتقول الملائكة : الهنا اغفر لصائمه وأجب دعاءه . وفي النبوي : من صام يوم الاثنين والخميس من شعبان قضى الله له عشرين حاجة من حوائج الدّنيا وعشرين حاجة من حوائج الاخرة ."},{"type":"Text","content":"السّادس : الاكثار في هذا الشّهر من الصّلاة على محمّد وآله ."},{"type":"Text","content":"السّابع : أن يصلّي عند كلّ زوال من ايّام شعبان وفي ليلة النّصف منه بهذه الصّلوات المرويّة عن السّجاد (عليه السلام) :"},{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، شَجَرَةِ النُّبُوَّةِ، وَمَوْضِعِ الرِّسالَةِ، وَمُخْتَلَفِ الْمَلائِكَةِ، وَمَعْدِنِ الْعِلْمِ، وَاَهْلِ بَيْتِ الْوَحْىِ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد الْفُلْكِ الْجارِيَةِ فِي اللُّجَجِ الْغامِرَةِ، يَأْمَنُ مَنْ رَكِبَها، وَيَغْرَقُ مَنْ تَرَكَهَا، الْمُتَقَدِّمُ لَهُمْ مارِقٌ، وَالْمُتَاَخِّرُ عَنْهُمْ زاهِقٌ، وَاللاّزِمُ لَهُمْ لاحِقٌ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، الْكَهْفِ الْحَصينِ، وَغِياثِ الْمُضْطَرِّ الْمُسْتَكينِ، وَمَلْجَأِ الْهارِبينَ، وَعِصْمَةِ الْمُعْتَصِمينَ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد صَلاةً كَثيرَةً، تَكُونُ لَهُمْ رِضاً وَلِحَقِّ مُحَمَّد وَآلِ مُحَمَّد اَداءً وَقَضاءً، بِحَوْل مِنْكَ وَقُوَّة يا رَبَّ الْعالَمينَ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، الطَّيِّبينَ الاَْبْرارِ الاَْخْيارِ، الَّذينَ اَوْجَبْتَ حُقُوقَهُمْ، وَفَرَضْتَ طاعَتَهُمْ وَوِلايَتَهُمْ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاعْمُرْ قَلْبي بِطاعَتِكَ، وَلا تُخْزِني بِمَعْصِيَتِكَ، وَارْزُقْني مُواساةَ مَنْ قَتَّرْتَ عَلَيْهِ مِنْ رِزْقِكَ بِما وَسَّعْتَ عَلَيَّ مِنْ فَضْلِكَ، وَنَشَرْتَ عَلَيَّ مِنْ عَدْلِكَ، وَاَحْيَيْتَني تَحْتَ ظِلِّكَ، وَهذا شَهْرُ نَبِيِّكَ سَيِّدِ رُسُلِكَ، شَعْبانُ الَّذي حَفَفْتَهُ مِنْكَ بِالرَّحْمَةِ وَالرِّضْوانِ، الَّذي كانَ رَسُولُ اللهِ صلى الله عليه وآله وسلم يَدْاَبُ في صِيامِه وَقِيامِه في لَياليهِ وَاَيّامِه بُخُوعاً لَكَ في اِكْرامِه وَاِعْظامِه اِلى مَحَلِّ حِمامِهِ، اَللّـهُمَّ فَاَعِنّا عَلَى الاْسْتِنانِ بِسُنَّتِه فيهِ، وَنَيْلِ الشَّفاعَةِ لَدَيْهِ، اَللّـهُمَّ وَاجْعَلْهُ لي شَفيعاً مُشَفَّعاً وَطَريقاً اِلَيْكَ مَهيعاً، وَاجْعَلْني لَهُ مُتَّبِعاً حَتّى اَلْقاكَ يَوْمَ الْقِيامَةِ عَنّي راضِياً، وَ عَنْ ذُنُوبي غاضِياً، قَدْ اَوْجَبْتَ لي مِنْكَ الرَّحْمَةَ وَالرِّضْوانَ، وَاَنْزَلْتَني دارَ الْقَرارِ وَمَحَلَّ الاَْخْيارِ ."},{"type":"Text","content":"الثّامن : أن يقرأ هذه المناجاة التي رواها ابن خالويه وقال انّها مناجاة أمير المؤمنين والائمة من ولده (عليهم السلام) كانوا يدعون بها في شهر شعبان :"},{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاسْمَعْ دُعائي اِذا دَعَوْتُكَ، وَاْسمَعْ نِدائي اِذا نادَيْتُكَ، وَاَقْبِلْ عَليَّ اِذا ناجَيْتُكَ، فَقَدْ هَرَبْتُ اِلَيْكَ، وَوَقَفْتُ بَيْنَ يَدَيكَ مُسْتَكيناً، لَكَ مُتَضرِّعاً اِلَيْكَ، راجِياً لِما لَدَيْكَ ثَوابي، وَتَعْلَمُ ما في نَفْسي، وَتَخْبُرُ حاجَتي، وَتَعْرِفُ ضَميري، وَلا يَخْفى عَلَيْكَ اَمْرُ مُنْقَلَبي وَمَثْوايَ، وَما اُريدُ اَنْ اُبْدِيَ بِهِ مِنْ مَنْطِقي، واَتَفَوَّهُ بِهِ مِنْ طَلِبَتي، وَاَرْجُوهُ لِعاقِبَتي، وَقَدْ جَرَتْ مَقاديرُكَ عَليَّ يا سَيِّدي فيما يَكُونُ مِنّي اِلى آخِرِ عُمْري مِنْ سَريرَتي وَعَلانِيَتي، وَبِيَدِكَ لا بِيَدِ غَيْرِكَ زِيادَتي وَنَقْصي وَنَفْعي وَضرّي، اِلـهي اِنْ حَرَمْتَني فَمَنْ ذَا الَّذي يَرْزُقُني، وَاِنْ خَذَلْتَني فَمَنْ ذَا الَّذي يَنْصُرُني، اِلـهي اَعُوذُ بِكَ مِنَ غَضَبِكَ وَحُلُولِ سَخَطِكَ، اِلـهي اِنْ كُنْتُ غَيْرَ مُسْتاْهِل لِرَحْمَتِكَ فَاَنْتَ اَهْلٌ اَنْ تَجُودَ عَليَّ بِفَضْلِ سَعَتِكَ، اِلـهي كَأَنّي بِنَفْسي واقِفَةٌ بَيْنَ يَدَيْكَ وَقَدْ اَظَلَّها حُسْنُ تَوَكُّلي عَلَيْكَ، فَقُلْتَ ما اَنْتَ اَهْلُهُ وَتَغَمَّدْتَني بِعَفْوِكَ، اِلـهي اِنْ عَفَوْتَ فَمَنْ اَوْلى مِنْكَ بِذلِكَ، وَاِنْ كانَ قَدْ دَنا اَجَلي وَلَمْ يُدْنِني مِنْكَ عَمَلي فَقَدْ جَعَلْتُ الاِقْرارَ بِالذَّنْبِ اِلَيْكَ وَسيلَتي، اِلـهي قَدْ جُرْتُ عَلى نَفْسي في النَّظَرِ لَها، فَلَها الْوَيْلُ اِنْ لَمْ تَغْفِرْ لَها، اِلـهي لَمْ يَزَلْ بِرُّكَ عَلَيَّ اَيّامَ حَياتي فَلا تَقْطَعْ بِرَّكَ عَنّي في مَماتي، اِلـهي كَيْفَ آيَسُ مِنْ حُسْنِ نَظَرِكَ لي بَعْدَ مَماتي، وَاَنْتَ لَمْ تُوَلِّني إلاّ الْجَميلَ في حَياتي، اِلـهي تَوَلَّ مِنْ اَمْري ما اَنْتَ اَهْلُهُ، وَعُدْ عَلَيَّ بِفَضْلِكَ عَلى مُذْنِب قَدْ غَمَرَهُ جَهْلُهُ، اِلـهي قَدْ سَتَرْتَ عَلَيَّ ذُنُوباً في الدُّنْيا وَاَنَا اَحْوَجُ اِلى سَتْرِها عَلَيَّ مِنْكَ في الاُْخْرى، اِذْ لَمْ تُظْهِرْها لاَِحَد مِنْ عِبادِكَ الصّالِحينَ، فَلاتَفْضَحْني يَوْمَ الْقِيامَةِ عَلى رُؤُوسِ الاَْشْهادِ، اِلـهي جُودُكَ بَسَطَ اَمَلي، وَعفْوُكَ اَفْضَلُ مِنْ عَمَلي، اِلـهي فَسُرَّني بِلِقائِكَ يَوْمَ تَقْضي فيهِ بَيْنَ عِبادِكَ، اِلـهىِ اعْتِذاري اِلَيْكَ اعْتِذارُ مَنْ لَمْ يَسْتَغْنِ عَنْ قَبُولِ عُذْرِهِ، فَاقْبَلْ عُذْري يا اَكْرَمَ مَنِ اعْتَذَرَ اِلَيْهِ الْمُسيئُونَ، اِلـهي لا َتَرُدَّ حاجَتي، وَلا تُخَيِّبْ طَمَعي، وَلا تَقْطَعْ مِنْكَ رَجائي وَاَمَلي، اِلـهي لَوْ اَرَدْتَ هَواني لَمْ تَهْدِني، وَلَوْ اَرَدْتَ فَضيحَتي لَمْ تُعافِني، اِلـهي ما اَظُنُّكَ تَرُدُّني في حاجَة قَدْ اَفْنَيْتُ عُمْري في طَلَبَها مِنْكَ، اِلـهي فَلَكَ الْحَمْدُ اَبَداً اَبَداً دائِماً سَرْمَداً، يَزيدُ وَلا يَبيدُ كَما تُحِبُّ وَتَرْضى، اِلـهي اِنْ اَخَذْتَني بِجُرْمي اَخَذْتُكَ بِعَفْوِكَ، وَاِنْ اَخَذْتَني بِذُنُوبي اَخَذْتُكَ بِمَغْفِرَتِكَ، وَاِنْ اَدْخَلْتَني النّارَ اَعْلَمْتُ اَهْلَها اَنّي اُحِبُّكَ، اِلـهي اِنْ كانَ صَغُرَ في جَنْبِ طاعَتِكَ عَمَلي فَقَدْ كَبُرَ في جَنْبِ رَجائِكَ اَمَلي، اِلـهي كيف اَنْقَلِبُ مِنْ عِنْدِكَ بِالَخْيبَةِ مَحْروماً، وَقَدْ كانَ حُسْنُ ظَنّي بِجُودِكَ اَنْ تَقْلِبَني بِالنَّجاةِ مَرْحُوماً، اِلـهي وَقَدْ اَفْنَيْتُ عُمْري في شِرَّةِ السَّهْوِ عَنْكَ، وَاَبْلَيْتُ شَبابي في سَكْرَةِ التَّباعُدِ مِنْكَ، اِلـهي فلَمْ اَسْتَيْقِظْ اَيّامَ اغْتِراري بِكَ وَرُكُوني اِلى سَبيلِ سَخَطِكَ، اِلـهي وَاَنَا عَبْدُكَ وَابْنُ عَبْدِكَ قائِمٌ بَيْنَ يَدَيْكَ، مُتَوَسِّلٌ بِكَرَمِكَ اِلَيْكَ، اِلـهي اَنَا عَبْدٌ اَتَنَصَّلُ اِلَيْكَ، مِمَّا كُنْتُ اُواجِهُكَ بِهِ مِنْ قِلَّةِ اسْتِحْيائي مِنْ نَظَرِكَ، وَاَطْلُبُ الْعَفْوَ مِنْكَ اِذِ الْعَفْوُ نَعْتٌ لِكَرَمِكَ، اِلـهي لَمْ يَكُنْ لي حَوْلٌ فَانْتَقِلَ بِهِ عَنْ مَعْصِيَتِكَ إِلاّ في وَقْت اَيْقَظْتَني لَِمحَبَّتِكَ، وَكَما اَرَدْتَ اَنْ اَكُونَ كُنْتُ، فَشَكَرْتُكَ بِاِدْخالي في كَرَمِكَ، وَلِتَطْهيرِ قَلْبي مِنْ اَوْساخِ الْغَفْلَةِ عَنْكَ، اِلـهي اُنْظُرْ اِلَيَّ نَظَرَ مَنْ نادَيْتَهُ فَاَجابَكَ، وَاْستَعْمَلتُهُ بِمَعونَتِكَ فَاَطاعَكَ، يا قَريباً لا يَبْعُدُ عَنِ المُغْتَرِّ بِهِ، وَيا جَواداً لايَبْخَلُ عَمَّنْ رَجا ثَوابَهُ، اِلـهي هَبْ لي قَلْباً يُدْنيهِ مِنْكَ شَوْقُهُ وَلِساناً يُرْفَعُ اِلَيْكَ صِدْقُهُ، وَنَظَراً يُقَرِّبُهُ مِنْكَ حَقُّهُ، اِلـهي إنَّ مَنْ تَعَرَّفَ بِكَ غَيْرُ مَجْهُول وَمَنْ لاذَ بِكَ غَيْرُ مَخْذُول، وَمَنْ اَقْبَلْتَ عَلَيْهِ غَيْرُ مَمْلُول، اِلـهي اِنَّ مَن انْتَهَجَ بِكَ لَمُسْتَنيرٌ وِاِنَّ مَنِ اعْتَصَمَ بِكَ لَمُسْتَجيرٌ، وَقَدْ لُذْتُ بِكَ يا اِلـهي فَلا تُخَيِّبْ ظَنّي مِنْ رَحْمَتِكَ، وَلا تَحْجُبْني عَنْ رَأفَتِكَ، اِلـهي اَقِمْني في اَهْلِ وِلايَتِكَ مُقامَ مَنْ رَجَا الزِّيادَةَ مِنْ مَحَبَّتِكَ، اِلـهي وَاَلْهِمْني وَلَهاً بِذِكْرِكَ اِلى ذِكْرِكَ وَهَمَّتي في رَوْحِ نَجاحِ اَسْمائِكَ وَمَحَلِّ قُدْسِكَ، اِلـهي بِكَ عَلَيْكَ إلاّ اَلْحَقْتَني بِمَحَلِّ اَهْلِ طاعَتِكَ وَالْمَثْوىَ الصّالِحِ مِنْ مَرْضاتِكَ، فَاِنّي لا اَقْدِرُ لِنَفْسي دَفْعاً، وَلا اَمْلِكُ لَها نَفْعاً، اِلـهي اَنَا عَبْدُكَ الضَّعيفُ الْمُذْنِبُ، وَمَمْلُوكُكَ الْمُنيبُ، فَلا تَجْعَلْني مِمَّنْ صَرَفتَ عَنْهُ وَجْهَكَ، وَحَجَبَهُ سَهْوُهُ عَنْ عَفْوِكَ، اِلـهي هَبْ لي كَمالَ الانْقِطاعِ اِلَيْكَ، وَاَنِرْ اَبْصارَ قُلُوبِنا بِضِياءِ نَظَرِها اِلَيْكَ، حَتّى تَخْرِقَ اَبْصارُ الْقُلُوبِ حُجُبَ النُّورِ فَتَصِلَ اِلى مَعْدِنِ الْعَظَمَةِ، وَتَصيرَ اَرْواحُنا مُعَلَّقَةً بِعِزِّ قُدْسِكَ، اِلـهي وَاْجَعَلْني مِمَّنْ نادَيْتَهُ فَاَجابَكَ، وَلاحَظْتَهُ فَصَعِقَ لِجَلالِكَ، فَناجَيْتَهُ سِرّاً وَعَمِلَ لَكَ جَهْراً، اِلـهي لَمْ اُسَلِّطْ عَلى حُسْنِ ظَنّي قُنُوطَ الاِْياسِ، وَلاَ انْقَطَعَ رَجائي مِنْ جَميلِ كَرَمِكَ، اِلـهي اِنْ كانَتِ الْخَطايا قَدْ اَسْقَطَتْني لَدَيْكَ، فَاصْفَحْ عَنّي بِحُسْنِ تَوَكُّلي عَلَيْكَ، اِلـهي اِنْ حَطَّتْني الذُّنوبُ مِنْ مَكارِمِ لُطْفِكَ، فَقَدْ نَبَّهَني الْيَقينُ اِلى كَرَمِ عَطْفِكَ، اِلـهي اِنْ اَنَامَتْنِى الْغَفْلَةُ عَنِ الاسْتْعِدادِ لِلِقائِكَ، فَقَدْ نَبَّهَني، الْمَعْرِفَةُ بِكَرَمِ آلائِكَ، اِلـهي اِنْ دَعاني اِلى النّارِ عَظيْمُ عِقابِكَ، فَقَدْ دَعاني اِلَى الْجَنَّةِ جَزيلُ ثَوابِكَ اِلـهي فَلَكَ اَسْأَلُ وَاِلَيْكَ اَبْتَهِلُ وَاَرْغَبُ، وَاَساَلُكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَنْ تَجْعَلَني مِمَّنْ يُديمُ ذِكَرَكَ، وَلا يَنْقُضُ عَهْدَكَ، وَلايَغْفُلُ عَنْ شُكْرِكَ، وَلا يَسْتَخِفُّ بِاَمْرِكَ، اِلـهي وَاَلْحِقْني بِنُورِ عِزِّكَ الاَْبْهَجِ، فَاَكُونَ لَكَ عارِفاً، وَعَنْ سِواكَ مُنْحَرِفاً، وَمِنْكَ خائِفاً مُراقِباً، يا ذَالْجَلالِ وَالاِكْرامِ، وَصَلَّى اللهُ عَلى مُحَمَّد رَسُولِهِ وَآلِهِ الطّاهِرينَ وَسَلَّمَ تَسْليماً كَثيراً ."},{"type":"Text","content":"وهذه مناجاة جليلة القدر مَنسُوبة الى أئمتنا (عليهم السلام) مشتملة على مضامين عالية ويحسن أن يدعى بها عند حضور القلب متى ما كان ."}],"preview":"الثّاني : أن يستغفر كلّ يوم سبعين مرّة قائلاً: اَسْتَغْفِر اللهَ الّذي لا اِلـهَ اِلاَّ هُوَ الرَّحْمنُ الرَّحيمُ الْحَيُّ الْقَيُّومُ وَاَتُوبُ اِلَيْهِ ووردت كلمة (الحي القيّوم)","hasTranslate":false},{"id":"mf_ar_108","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل الثّاني :","title":"اعمال شَعْبـان الخاصّة","blocks":[{"type":"Text","content":"اللّيلة الاُولى"},{"type":"Text","content":"قد وردت فيها صَلوات كثيرة مذكورة في الاقبال ومن تلك الصّلوات اثنتا عشرة ركعة يقرأ في كلّ ركعة الحمد مرّة والتّوحيد احدى عشرة مرّة ."},{"type":"Text","content":"اليَومُ الاوّل"},{"type":"Text","content":"ويفضل صيامه فضلاً كثيراً وقد روى عن الصّادق (عليه السلام) انّ من صام اوّل يوم من شعبان وجبت له الجنّة البتّة، وقد روى السّيد ابن طاووس عن النّبي (صلى الله عليه وآله وسلم) اجراً جزيلاً لمن صام ثلاثة أيّام من هذا الشّهر يصلّي في لياليها ركعتين يقرأ في كلّ ركعة الحمد مرّة وسورة التّوحيد احدى عشرة مرّة، واعلم انّه قد ورد في تفسير الامام (عليه السلام) رواية في فضل شعبان وفضل اليوم الاوّل منه تشتمل على فوائد جمّة، وشيخنا ثقة الاسلام النّوري نوّر الله مرقده قد أورد ترجمتها في نهاية كتابه الفارسي (كلمه طيّبه) والرّواية مبسوطة لا يسعها المقام، وملخّصها انّ امير المؤمنين (عليه السلام) قد مرّ على قوم من أخلاط المسلمين وهُم قعود في بعض المساجد في أوّل يوم من شعبان، وهُم يخوضون في أمر القدر وغيره، قد ارتفعت أصواتهم واشتدّ فيه محكمهم وجدالهم، فوقف عليهم وسلّم فردّوا عليه وأوسعوا له وقاموا اليه يسألونه القعود عليهم، فلم يحفل بهم ثمّ قال لهم وناداهم : يا معاشر المتكلّمين فيما لا يعنيهم ولا يردّ عليهم، ألم تعلموا انّ لله عباداً قد أسكتهم خشية من غير عيّ ولا بكم، ولكنّهم اذا ذكروا عظمة الله انكسرت ألسنتهم وانقطعت أفئدتهم وطاشت عقولهم، وحامت حلومهم اعزازاً لله واعظاماً واجلالاً، فاذا أفاقوا من ذلك استبقوا الى الله بالاعمال الزّاكية، يعدّون أنفسهم مع الظّالمين والخاطئين وانّهم براء من المقصّرين ومن المفرطين، ألا انّهم لا يرضُون لله بالقليل، ولا يستكثرون لله الكثير، فهم يدأبون له في الاعمال، فهم اذا رأيتهم قائمون للعبادة مروعون خائفون مشفقون وجلون، فأين أنتم منهم يا معشر المبتدعين، أما علمتهم انّ أعلم النّاس بالقدر أسكتهم عنه، وانّ أجهلهم به اكثرهم كلاماً فيه، يا معشر المبتدعين هذا يوم غرّة شعبان الكريم سمّاه ربّنا شعبان لتشعّب الخيرات فيه، قد فتح ربّكم فيه أبواب جنانه، وعرض عليكم قصورها وخيراتها بأرخص الاثمان، وأسهل الامور ، فاشتروها، وعرض لكم ابليس اللّعين شعب شروره وبلاياه، فأنتم دائباً تتيهون في الغيّ والطّغيان، تمسكون بشعب ابليس وتحيدون عن شعب الخير المفتوح لكم أبوابه، هذه غرّة شعبان وشعب خيراته الصّلاة والزّكاة والامر بالمعروف والنّهي عن المنكر وبرّ الوالدين والقرابات والجيران واصلاح ذات البين والصّدقة على الفقراء والمساكين، تتكلّفون ما قد وُضِعَ عنكم (أي أمر القدر) وما قد نهيتم عن الخوض فيه من كشف سراير الله التي من فتش عنها كان من الهالكين، أما انّكم لو وقفتم على ما قد أعدّ ربّنا عزّوجل للمطيعين من عباده في هذا اليوم لقصّرتم عمّا أنتم فيه، وشرعتم فيما أمرتم به."},{"type":"AboutText","content":"قالوا : يا أمير المؤمنين وما الذي أعدّه الله في هذا اليوم للمطيعين له ؟ فروى (عليه السلام) ما كان من أمر الجيش الذي بعثه رسول الله (صلى الله عليه وآله وسلم) الى الكفّار فوثب الكفّار عليه ليلاً وكانت ليلة ظلماء دامسة والمسلمون نيام ولم يك فيهم يقظان سوى زيد بن حارثة وعبد الله بن رواحة وقتادة بن نعمان وقيس بن عاصم المنقري وكلّ منهم يقظان في جانب من جوانب العسكر يصلّي الصّلاة أو يتلو القرآن، وكاد المسلمون أن يهلكوا لانّهم في الظّلام لا يبصرون أعداءهم ليتّقوهم، واذا بأضواء تسطع من أفواه هؤلاء النّفر الاربعة تضيء معسكر المسلمين فتورثهم القوّة والشّجاعة فوضعوا السّيوف على الكفّار فصاروا بين قتيل أو جريح أو أسير، فلمّا رجعوا قصّوا على النّبي (صلى الله عليه وآله وسلم) ما كان ، فقال (صلى الله عليه وآله وسلم) : انّ هذه الانوار قد كانت لما عمله اخوانكم هؤلاء من الاعمال في غرّة شعبان، ثمّ حدّثهم بتلك الاعمال واحداً فواحداً الى أن قال : انّ ابليس اذا كان اوّل يوم من شعبان يبث جنودُه في أقطار الارض وآفاقها يقول لهم اجتهدوا في اجتذاب بعض عباد الله اليكم في هذا اليوم، وانّ الله عزوجل يبث ملائكته في أقطار الارض وآفاقها ، يقول لهم : سدّدوا عبادي وارشدوهم وكلّهم يسعد الّا من أبى وطغى فانّه يصير في حزب ابليس وجنوده، وانّ الله عزوجل اذا كان اوّل يوم من شعبان يأمر باب الجنّة فتفتح، ويأمر شجرة طوبى فتدني أغصانها من هذه الدّنيا، فتعلّقوا بها لترفعكم الى الجنّة، وهذه أغصان شجرة الزّقوم فأيّاكم وايّاها لا تؤديكم الى الجحيم."},{"type":"AboutText","content":"قال : فو الذي بعثني بالحقّ نبيّاً انّ من تعاطى باباً من الخير في هذا اليوم فقد تعلّق بغصن من أغصان شجرة طوبى فهو مؤدّيه الى الجنّة، وانّ من تعاطى باباً من الشرّ في هذا اليوم فقد تعلّق بغصن من أغصان شجرة الزّقّوم ، فهو مؤديّه الى النّار ، ثمّ قال رسول الله (صلى الله عليه وآله وسلم): فمن تطوّع لله بصلاة في هذا اليوم فقد تعلّق منه بغصن، ومن صام في هذا اليوم تعلّق منه بغصن، ومن أصلح بين المرء وزوجه، والوالد وولده، والقريب وقريبه، والجار وجاره، والاجنبيّ والاجنبيّ، فقد تعلّق بغصن منه، ومن خفّف عن معسر من دَينه، أو حطّ عنه فقد تعلّق منه بغصن، ومن نظر في حسابه فرأى دَيناً عتيقاً قد أيس منه صاحبه فأدّاه فقد تعلّق منه بغصن، ومن كفل يتيماً فقد تعلّق منه بغصن، ومن كفّ سقيماً عن عِرض مؤمن فقد تعلّق منه بغصن، ومن تلا القُرآن أو شيئاً منه فقد تعلّق منه بغصن، ومن قعد يذكر الله ونعماءه ليشكره فقد تعلّق منه بغصن، ومن عاد مريضاً فقد تعلّق منه بغصن، ومن برّ فيه والديه أو أحدهما في هذا اليوم فقد تعلّق منه بغصن، ومن كان أسخطهما قبل هذا اليوم فأرضاهما في هذا اليوم فقد تعلّق منه بغُصن، وكذلك من فعل شيئاً من سائر أبواب الخير في هذا اليوم فقد تعلّق منه بغصن ، ثمّ قال رسول الله (صلى الله عليه وآله وسلم)والذي بعثني بالحقّ نبيّاً وانّ من تعاطى باباً من الشرّ والعصيان في هذا اليوم فقد تعلّق بغصن من أغصان الزّقوم فهو مؤدّيه الى النّار ."},{"type":"Text","content":"ثمّ قال رسول الله (صلى الله عليه وآله وسلم) والّذي بعثني بالحقّ نبيّاً فمن قصّر في الصّلاة المفروضة وضيّعها فقد تعلّق بغصن منه ومن جاءه في هذا اليوم فقير ضعيف يعرف سوء حاله فهو يقدر على تغيير حاله من غير ضرر يلحقه وليس هناك من ينوب عنه ويقوم مقامه، فتركه يضيع ويعطب، ولم يأخذ بيده فقد تعلّق بغصن منه، ومن اعتذر اليه مسيء فلم يعذره ثمّ لم يقتصر به على قدر عقوبة اساءته بل زاد عليه فقد تعلّق بغصن منه، ومن ضرب بين المرء وزوجه، أو الوالد وولده، أو الاخ وأخيه، أو القريب وقريبه، أو بين جارين، أو خليطين، أو اُختين فقد تعلّق بغصن منه، ومن شدّد على معسر وهو يعلم اعسـاره فزاد غيظاً وبلاءاً فقد تعلّق بغصن منه، ومن كان عليه دَين فأنكره على صاحبه وتعدّى عليه حتّى أبطل دينه فقد تعلّق بغصن منه، ومن جفا يتيماً وآذاه وهزم ماله فقد تعلّق بغصن منه، ومن وقع في عِرض أخيه المؤمن وحمل النّاس على ذلك فقد تعلّق بغصن منه، ومن تغنى بغناء يبعث فيه على المعاصي فقد تعلّق بغصن منه، ومن قعد يعدّد قبائح أفعاله في الحروب وأنواع ظُلمه لعباد الله فيفتخر بها فقد تعلّق بغصن منه، ومن كان جاره مريضاً فترك عيادته استخفافاً بحقّه فقد تعلّق بغصن منه، ومَن مات جاره فترك تشييع جنازته تهاوناً فقد تعلّق بغصن منه، ومن عقّ والديه أو احدهما فقد تعلّق بغصن منه، ومن كان قبل ذلك عاقاً لهما فلم يرضهما في هذا اليوم يقدر على ذلك فقد تعلّق بغصن منه، وكذا من فعل شيئاً من سائر أبواب الشرّ فقد تعلّق بغصن منه، والذي بعثني بالحقّ نبيّاً انّ المتعلّقين بأغصان شجرة طوبى ترفعهم تلك الاغصان الى الجنّة، ثمّ رفع رسول الله (صلى الله عليه وآله وسلم) طرفه الى السّماء مليّاً وجعل يضحك ويستبشر، ثمّ خفض طرفه الى الارض فجعل يقطب ويعبس، ثمّ أقبل على أصحابه فقال : والذي بعث محمّداً بالحقّ نبيّاً لقد رأيت شجرة طوبى ترفع أغصانها وترفع المتعلّقين بها الى الجنّة، ورأيت منهم من تعلّق منها بغصن ومنهم من تعلّق بغصنين أو بأغصان على حسب اشتمالهم على الطّاعات، وانّي لارى زيد بن حارثة فقد تعلّق بعامة أغصانها فهي ترفعه الى أعلى اعلاها فبذلك ضحكت واستبشرت ثمّ نظرت الى الارض فو الذي بعثني بالحقّ نبيّاً لقد رأيت شجرة الزقّوم تنخفض أغصانها وتخفض المتعلّقين بها الى الجحيم، ورأيت منهم من تعلّق بغصن ومنهم من تعلّق بغصنين أو بأغصان على حسب اشتمالهم على القبائح، وانّي لارى بعض المنافقين قد تعلّق بعامة أغصانها وهي تخفضه الى أسفل دركاتها، فلذلك عبست وقطبت ."},{"type":"Text","content":"اليَومُ الثّالث"},{"type":"Text","content":"هو يوم مبارك ، قال الشّيخ في المصباح : في هذا اليوم ولد الحسين بن علي (عليه السلام)وخرج الى أبي القاسم بن علاء الهمداني وكيل الامام العسكري انّ مولانا الحسين (عليه السلام) ولد يوم الخميس لثلاث خلون من شعبان فصُمه وادع فيه بهذا الدّعاء :"},{"type":"Text","content":"اَللّـهُمَّ اِنّي اَساَلُكَ بِحَقِّ الْمَوْلُودِ في هذَا الْيَوْمِ، الْمَوْعُودِ بِشَهادَتِهِ قَبْلَ اْستِهْلالِهِ وَوِلادَتِهِ. بَكَتْهُ السَّماءُوَمَنْ فيها، وَالاَْرْضُ وَمَنْ عَلَيْها، وَلَمّا يَطَأْ لابَتَيْها قَتيل الْعَبْرَةِ، وَسَيِّدِ الاُْسْرَةِ، الْمَمْدُودِ بِالنُّصْرَةِ يَوْمَ الْكَرَّةِ، الْمُعَوَّضِ مِنْ قَتْلِهِ اَنَّ الاَْئِمَّةَ مِنْ نَسْلِهِ، وَالشِّفاءَ في تُرْبَتِهِ، والْفَوْزَ مَعَهُ في اَوْبَتِهِ، والاَْصِياءِ مِنْ عِتْرَتِهِ بَعْدَ قائِمِهِمْ وَغَيْبَتِهِ حَتّى يُدْرِكُوا الاَْوْتارَ، وَيَثْأَرُوا الثّارَ، وَيُرْضُوا الْجَبّارَ، وَيَكُونُوا خَيْرَ اَنْصار، صَلَّى اللهُ عَلَيْهِمْ مَعَ اْختِلافِ اللَّيلِ وَالنَّهارِ، اَللّـهُمَّ فَبِحَقِّهِمْ اِلَيْكَ اَتَوَسَّلُ وَاَسْأَلُ سُؤالَ مُقْتَرف مُعْتَرف مُسيئ اِلى نَفْسِهِ، مِمَّا فَرَّطَ في يَوْمِهِ وَاَمْسِهِ يَسْأَلُكَ الْعِصْمَةَ اِلى مَحَلِّ رَمْسِهِ، اَللّـهُمَّ فَصَلِّ عَلى مُحَمَّد وَعِتْرَتِهِ، وَاحْشُرْنا في زُمْرَتِهِ، وَبَوِّئْنا مَعَهُ دارَ الْكَرامَةِ، وَمَحَلَّ الاِقامَةِ، اَللّـهُمَّ وَكَما اَكْرَمْتَنا بِمَعْرِفَتِهِ فَاَكْرِمْنا بِزُلْفَتِهِ، وَارْزُقْنا مُرافَقَتَهُ وَسابِقَتَهُ، وَاجْعَلْنا مِمَّنْ يُسَلِّمُ لاَْمْرِهِ وَيُكْثِرُ الصَّلاةَ عَلَيْهِ عِنْدَ ذِكْرِهِ، وَعَلى جَميعِ اَوْصِيائِهِ وَاَهْلِ اَصْفِيائِهِ الْمَمْدُوديِنَ مِنْكَ بِالْعَدَدِ، الاَْثْنَىْ عَشَرَ، النّجُومِ الزُّهرِ، وَالْحُجَجِ عَلى جَميعِ الْبَشَرِ، اَللّـهُمَّ وَهَبْ لَنا في هذَا الْيَوْمِ خَيْرَ مَوْهِبَة، وَاَنْجِحْ لَنا فيهِ كُلَّ طَلِبَته كَما وَهَبْتَ الْحُسَيْنِ لُِمحَمَّد جَدِّهِ وَعاذَ فُطْرُسُ بِمَهْدِهِ، فَنَحْنُ عائِذُونَ بِقَبْرِهِ مِنْ بَعْدِهِ، نَشْهَدُ تُرْبَتَهُ، وَننْظُر اَوْبَتَهُ، آمينَ رَبَّ الْعالَمينَ ."},{"type":"Text","content":"ثمّ تدعو بعد ذلك بدعاء الحسين (عليه السلام)وهو آخر دعائه (عليه السلام) يوم كثرت عليه أعداؤه وهو يوم عاشوراء :"},{"type":"Text","content":"اَللّـهُمَّ اَنْتَ مُتَعالِي الْمَكانِ، عَظيمُ الْجَبَرُوتِ، شَديدُ الِمحالِ، غَنِيٌّ َعنِ الْخَلايِقِ، عَريضُ الْكِبْرِياءِ، قادِرٌ عَلى ما تَشاءُ، قَريبُ الرَّحْمَةِ، صادِقُ الْوَعْدِ، سابِغُ النِّعْمَةِ، حَسَنُ الْبَلاءِ، قَريبٌ إذا دُعيتَ، مُحيطٌ بِما خَلَقْتَ، قابِلُ التُّوبَةِ لَمَنْ تابَ اِلَيْكَ، قادِرٌ عَلى ما اَرَدْتَ، وَمُدْرِكُ ما طَلَبْتَ، وَشَكُورٌ اِذا شُكِرْتَ، وَذَكُورٌ اِذا ذُكِرْتَ، اَدْعُوكَ مُحْتاجاً، وَاَرْغَبُ اِلَيْكَ فَقيراً، وَاَفْزَعُ اِلَيْكَ خائِفاً، واَبْكي اِلَيْكَ مَكْرُوباً، وَاَسْتَعينُ بِكَ ضَعيفاً، وَاَتوَكَّلُ عَلَيْكَ كافِياً، اُحْكُمْ بَيْنَنا وَبَيْنَ قَوْمِنا فَاِنَّهُمْ غَرُّونا وَخَدَعُونا وَغَدَروا بِنا وَقَتَلُونا، ونَحْنُ عِتْرَةُ نَبِيِّكَ، وَوَلَدُ حَبيبِكَ مُحَمَّدِ بْنِ عَبْدِاللهِ، الَّذي اصطَفَيْتَهُ بِالرِّسالَةِ، وَائْتَمَنْتَهُ عَلى وَحْيِكَ، فَاجْعَلْ لَنا مِنْ اَمْرِنا فَرَجاً وَمَخْرجاً بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ ."},{"type":"AboutText","content":"قال ابن عيّاش : سمعت الحسين بن علي بن سفيان البزوفري يقول : سمعت الصّادق (عليه السلام) يدعو به في هذا اليوم وقال هو من أدعية اليوم الثّالث من شعبان وهو ميلاد الحسين (عليه السلام) ."},{"type":"Text","content":"اللّيلة الثّالِثة عشرة"},{"type":"Text","content":"وهي أوّل اللّيالي البيض وقد مرّ ما يصلّى في هذه اللّيلة واللّيلتين بعدها في أعمال شهر رجب"}],"preview":"اللّيلة الاُولى","hasTranslate":false},{"id":"mf_ar_109","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل الثّاني :","title":"ليلة النّصف من شعبان","blocks":[{"type":"Text","content":"وهي ليلة بالغة الشّرف وقد روى عن الصّادق (عليه السلام) قال : سُئل الباقر (عليه السلام) عن فضل ليلة النّصف من شعبان ، فقال (عليه السلام) : هي أفضل اللّيالي بعد ليلة القدر، فيها يمنح الله العباد فضله ويغفر لهم بمنّه، فاجتهدوا في القربة الى الله تعالى فيها فانّها ليلة آلى الله عزوجل على نفسه أن لا يردّ سائلاً فيها ما لم يسأل الله المعصية، وانّها اللّيلة التي جعلها الله لنا أهل البيت بازاء ما جعل ليلة القدر لنبيّنا (عليه السلام)، فاجتهدوا في دعاء الله تعالى والثّناء عليه، الخبر ومن عظيم بركات هذه اللّيلة المباركة انّها ميلاد سلطان العصر وامام الزّمان أرواحنا له الفداء، ولد عند السّحر سنة خمس وخمسين ومائتين في سرّ مَن رأى، وهذا ما يزيد هذه اللّيلة شرفاً وفضلاً وقد ورد فيها أعمال :"},{"type":"Text","content":"أوّلها : الغسل ، فانّه يوجب تخفيف الذّنوب ."},{"type":"Text","content":"الثّاني : احياؤها بالصّلاة والدّعاء والاستغفار كما كان يصنع الامام زين العابدين (عليه السلام)، وفي الحديث من أحيا هذه اللّيلة لم يمت قلبه يوم تموت فيه القلوب ."},{"type":"Text","content":"الثّالث : زيارة الحسين (عليه السلام) وهي أفضل أعمال هذه اللّيلة، وتوجب غفران الذّنوب، ومن أراد أن يصافحه أرواح مائة وأربعة وعشرين ألف نبيّ فليزره (عليه السلام) في هذه اللّيلة، وأقلّ ما يزار به (عليه السلام) أن يصعد الزائر سطحاً مرتفعاً فينظر يمنة ويسرة ثمّ يرفع رأسه الى السّماء فيزوره (عليه السلام) بهذه الكلمات :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا اَبا عَبْدِ اللهِ، السَّلامُ عَلَيْكَ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، ويرجى لمن زار الحسين (عليه السلام)حيثما كان بهذه الزيارة أن يكتب له أجر حجّة وعمرة، ونحن سنذكر في باب الزّيارات ما يختصّ بهذه اللّيلة منها ان شاء الله تعالى."},{"type":"Text","content":"الرّابع : أن يدعو بهذا الدّعاء الذي رواه الشّيخ والسّيد وهو بمثابة زيارة للامام الغائب صلوات الله عليه :"},{"type":"Text","content":"اَللّـهُمَّ بِحَقِّ لَيْلَتِنا وَمَوْلُودِها، وَحُجَّتِكَ وَمَوْعُودِها، الَّتي قَرَنْتَ اِلى فَضْلِها، فَضْلاً فَتَمَّتْ كَلِمَتُكَ صِدْقاً وَعَدْلاً لا مُبَدِّلَ لِكَلِماتِكَ، وَلا مُعَقِّبَ لاِياتِكَ، نُورُكَ الْمُتَاَلِّقُ، وَضِياؤُكَ الْمُشْرِقُ، وَالْعَلَمُ النُّورُ في طَخْياءِ الدَّيْجُورِ، الْغائِبُ الْمَسْتُورُ، جَلَّ مَوْلِدُهُ وَكَرمَ مَحْتِدُهُ، وَالْمَلائِكَةُ شُهَّدُهُ، وَاللهُ ناصِرُهُ وَمُؤَيِّدُهُ، اِذا آن ميعادُهُ، وَالْمَلائِكَةُ اَمْدادُهُ، سَيْفُ الله الَّذي لا يَنْبُو، وَنُورُهُ الَّذي لا يَخْبُو، وَذُو الْحِلْمِ الَّذي لا يَصْبُو، مَدارُ الَّدهْرِ، وَنَواميسُ الْعَصْرِ، وَوُلاةُ الاَْمْرِ، وَالْمُنَزَّلُ عَلَيْهِمْ ما يَتَنَزَّلُ في لَيْلَةِ الْقَدْرِ، وَاَصْحابُ الْحَشْرِ وَالنَّشْرِ، تَراجِمَةَ وَحْيِهِ، وَوُلاةُ اَمْرِهِ وَنَهْيِهِ، اَللّـهُمَّ فَصَلِّ عَلى خاتِمِهم وَقائِمِهِمْ الْمَسْتُورِ عَوالِمِهِمْ، اَللّـهُمَّ وَاَدْرِكَ بِنا أَيّامَهُ وَظُهُورَهُ وَقِيامَهُ، وَاجْعَلْنا مِنْ اَنْصارِهِ، وَاقْرِنْ ثارَنا بِثارِهِ، وَاكْتُبْنا في اَعْوانِهِ وَخُلَصائِهِ، وَاَحْيِنا في دَوْلَتِهِ ناعِمينَ، وَبِصُحْبَتِهِ غانِمينَ وَبِحَقِّهِ قائِمينَ، وَمِنَ السُّوءِ سالِمينَ، يا اَرْحَمَ الرّاحِمينَ، وَالْحَمْدُ للهِ رَبِّ الْعالَمينَ وَصَلَواتُهُ عَلى سَيِّدِنا مُحَمَّد خاتَمِ النَّبِيّينَ وَالْمُرْسَلينَ، وَعَلى اَهْلِ بَيْتِهِ الصّادِقينَ وَعِتْرَتِهَ النّاطِقينَ، وَالْعَنْ جَميعَ الظّالِمينَ، واحْكُمْ بَيْنَنا وَبَيْنَهُمْ يا اَحْكَمَ الْحاكِمينَ ."},{"type":"Text","content":"الخامس : روى الشّيخ عن اسماعيل بن فضل الهاشمي قال : علّمني الصّادق (عليه السلام)هذا الدّعاء لادعو به ليلة النّصف من شعبان :"},{"type":"Text","content":"اَللّـهُمَّ اَنْتَ الْحَيُّ الْقَيُّومُ، الْعَلِيُّ الْعَظيمُ، الْخالِقُ الرّازِقُ، الُْمحْيِي الْمُميتُ، الْبَديءُ الْبَديعُ، لَكَ الْجَلالُ، وَلَكَ الْفَضْلُ، وَلكَ الْحَمْدُ، وَلَكَ الْمَنُّ، وَلَكَ الْجُودُ، وَلَكَ الْكَرَمُ، وَلَكَ الاَْمْرُ، وَلَكَ الَمجْدُ، وَلَكَ الْشُّكْرُ، وَحْدَكَ لا شَريكَ لَكَ، يا واحِدُ يا اَحَدُ، يا صَمَدُ، يا مَنْ لَمْ يَلِدْ وَلَمْ يُولَدْ وَلَمْ يَكُنْ لَهُ كُفُواً اَحَدٌ، صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاْغفِرْ لي وَارْحَمْني، وَاكْفِني ما اَهَمَّني، وَاقْضِ دَيْني، وَوَسِّعْ عَليَّ في رِزْقي، فَاِنَّكَ في هذِهِ اللَّيْلَةِ كُلَّ اَمْر حَكيم تَفْرُقُ، وَمَنْ تَشاءُ مِنْ خلْقِكَ تَرْزُقُ، فَارْزُقْني وَاَنْتَ خَيْرُ الرّازِقينَ، فَاِنَّكَ قُلْتَ وَاَنْتَ خَيْرُ الْقائِلينَ النّاطِقينَ واسْأَلُو اللهَ مِنْ فَضْلِهِ، فَمِنْ فَضْلِكَ أسْأَلُ، وَاِيّاكَ قَصَدْتُ، وابْنَ نَبِيِّكَ اعْتَمَدْتُ، وَلَكَ رَجَوْتُ، فَارْحَمْني يا اَرْحَمَ الرّاحِمينَ ."},{"type":"Text","content":"السّادس : اُدع بهذا الدّعاء الذي كان يدعو به النّبي (صلى الله عليه وآله وسلم) في هذه الليلة :"},{"type":"Text","content":"اَللّـهُمَّ اقْسِمْ مِنْ خَشْيَتِكَ ما يَحُولُ بَيْنَنا وَبَيْنَ مَعْصِيَتِكَ، وَمِنْ طْاعَتِكَ ما تُبَلِّغُنا بِهِ رِضْوانَكَ، وَمِنَ الْيَقينِ ما يَهُونُ عَلَيْنا بِهِ مُصيباتُ الدُّنْيا، اَللّـهُمَّ اَمْتِعْنا بِاَسْماعِنا وَاَبْصارِنا وَقُوَّتِنا ما اَحْيَيْتَنا، وَاجْعَلْهُ الْوارِثَ مِنّا، واجْعَلْ ثأرَنا عَلى مَنْ ظَلَمَنا، وَانْصُرنا عَلى مَنْ عادانا، وَلا تَجْعَلْ مُصيبَتَنا في دينِنا، وَلا تَجْعَلِ الدُّنْيا اَكْبَرَ هَمِّنا، وَلا مَبْلَغَ عِلْمِنا، وَلا تُسَلِّطْ عَلَيْنا مَنْ لا يَرْحَمُنا، بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ ."},{"type":"Text","content":"وهذه من الدّعوات الجامعات الكاملات ويغتنم الدّعاء به في سائر الاوقات، وفي كتاب عوالي اللئالي انّ النّبي (صلى الله عليه وآله وسلم) كان يدعو بهذا الدّعاء في كافّة الاوقات ."}],"preview":"وهي ليلة بالغة الشّرف وقد روى عن الصّادق (عليه السلام) قال : سُئل الباقر (عليه السلام) عن فضل ليلة النّصف من شعبان ، فقال (عليه السلام) : هي أفضل اللّيالي بعد ليلة القدر، فيها يمنح","hasTranslate":false},{"id":"mf_ar_110","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل الثّاني :","title":"السّابع : أن يقرأ الصّلوات التي يدعى بها عند الزّوال في كلّ يوم","blocks":[{"type":"Text","content":"الثّامن : أن يدعو بدعاء كميل الذي اثبتناه في الباب الاوّل من الكتاب، وهو وارد في هذه الليلة ."},{"type":"Text","content":"التّاسع : أن يذكر الله بكلّ من هذه الاذكار مائة مرّة، سُبْحانَ اللهِ وَالْحَمْدُ للهِ وَلا اِلـهَ إلاَّ اللهُ واللهُ اَكْبَرُ ليغفر الله له ما سلف من معاصيه، ويقضي له حوائج الدّنيا والاخرة ."},{"type":"Text","content":"العاشر : روى الشّيخ في المصباح عن أبي يحيى في حديث في فضل ليلة النّصف من شعبان انّه قال : قلت لمولاي الصّادق (عليه السلام) : ما هو أفضل الادعية في هذه اللّيلة، فقال : اذا صلّيت العشاء فصلّ ركعتين تقرأ في الاُولى الحمد وسورة الجحد وهي سورة «قل يا أيّها الكافرون»، وفي الثّانية الحمد وسورة التّوحيد وهي سورة «قُلْ هُوَ اللهُ أحَدٌ»، فاذا سلّمت قلت: «سُبْحانَ اللهِ» ثلاثاً وثلاثين مرّة، و«الْحَمْدُ للهِ» ثلاثاً وثلاثين مرّة، و «اللهُ اَكْبَرُ» أربعاً وثلاثين مرّة، ثمّ قل :"},{"type":"Text","content":"يا مَنْ اِلَيْهِ مَلْجَأُ الْعِبادِ في الْمُهِمّاتِ، وَاِلَيْهَ يَفْزَعُ الْخَلْقُ فىِ الْمُلِمّاتِ، يا عالِمَ الْجَهْرِ وَالْخَفِيّاتِ، يا مَنْ لا تَخْفى عَلَيْهِ خَواطِرُ الاَْوْهامِ وَتَصَرُّفُ الْخَطَراتِ، يا رَبَّ الْخَلايِقِ وَالْبَرِيّاتِ، يا مَنْ بِيَدِهِ مَلَكُوتُ الاَْرَضينَ وَالسَّماواتِ، اَنْتَ اللهُ لا اِلـهَ إِلاّ اَنْتَ، اَمُتُّ اِلَيْكَ بِلا اِلـهَ إِلاّ اَنْتَ، فَيا لا اِلـهَ اِلاّ اَنْتَ اجْعَلْني في هِذِهِ اللَّيْلَةِ مِمَّنْ نَظَرْتَ اِلَيْهِ فَرَحِمْتَهُ وَسَمِعْتَ دُعاءَهُ فَاَجَبْتَهُ، وَعَلِمْتَ اسْتِقالَتَهُ فَاَقَلْتَهُ، وَتَجاوَزْتَ عَنْ سالِفِ خَطيئَتِهِ وَعَظيمِ جَريرَتِهِ، فَقَدِ اسْتَجَرْتُ بِكَ مِنْ ذُنُوبي، وَلَجَأتُ اِلَيْكَ في سَتْرِ عُيُوبي، اَللّـهُمَّ فَجُدْ عَلَيَّ بِكَرَمِكَ وَفَضْلِكَ، وَاحْطُطْ خَطايايَ بِحِلْمِكَ وَعَفْوِكَ، وَتَغَمَّدْني في هذِهِ اللَّيْلَةِ بِسابِغِ كَرامَتِكَ، وَاجْعَلْني فيها مِنْ اَوْلِيائِكَ الَّذينَ اجْتَبَيْتَهُمْ لِطاعَتِكَ، واخْتَرْتَهُمْ لِعِبادَتِكَ، وَجَعَلْتَهُمْ خالِصَتَكَ وَصِفْوَتَكَ، اَللّـهُمَّ اجْعَلْني مِمَّنْ سَعَدَ جَدُّهُ، وَتَوَفَّرَ مِنَ الْخَيْراتِ حَظُّهُ، وَاجْعَلْني مِمَّنْ سَلِمَ فَنَعِمَ، وَفازَ فَغَنِمَ، وَاكْفِني شَرَّ ما اَسْلَفْتُ، وَاعْصِمْني مِنَ الاْزدِيادِ في مَعْصِيَتِكَ، وَحَبِّبْ اِلَيَّ طاعَتَكَ وَما يُقَرِّبُني مِنْكَ وَيُزْلِفُني عِنْدَكَ، سَيِّدي اِلَيْكَ يَلْجَأُ الْهارِبُ، وَمِنْكَ يَلْتَمِسُ الطّالِبُ، وَعَلى كَرَمِكَ يُعَوِّلُ الْمُسْتَقْيِلُ التّائِبُ، اَدَّبْتَ عِبادَكَ بالتَّكَرُّمِ، وَاَنْتَ اَكْرَمُ الاَْكْرَمينَ، وَاَمَرْتَ بِالْعَفْوِ عِبادَكَ وَاَنْتَ الْغَفُورُ الَّرحيمُ، اَللّـهُمَّ فَلاتَحْرِمْني ما رَجَوْتُ مِنْ كَرَمِكَ، وَلا تُؤْيِسْني مِنْ سابِغِ نِعَمِكَ، وَلا تُخَيِّبْني مِنْ جَزيلِ قِسْمِكَ في هذِهِ اللَّيْلَةِ لاَِهْلِ طاعَتِكَ، وَاجْعَلْني في جُنَّة مِنْ شِرارِ بَرِيَّتِكَ، رَبِّ اِنْ لَمْ اَكُنْ مِنْ اَهْلِ ذلِكَ فَاَنْتَ اَهْلُ الْكَرَمِ وَالْعَفْوِ وَالْمَغْفِرَةِ، وَجُدْ عَلَيَّ بِما اَنْتَ اَهْلُهُ لا بِما اَسْتَحِقُّهُ، فَقَدْ حَسُنَ ظَنّي بِكَ، وَتَحَقَّقَ رَجائي لَكَ، وَعَلِقَتْ نَفْسي بِكَرَمِكَ، فَاَنْتَ اَرْحَمُ الرّاحِمينَ وَاَكْرَمُ الاَْكْرَمينَ، اَللّـهُمَّ واخْصُصْني مِنْ كَرمِكَ بِجَزيلِ قِسْمِكَ، وَاَعُوذُ بِعَفْوِكَ مِنْ عُقُوبَتِكَ، وَاغْفِر لِيَ الَّذنْبَ الَّذي يَحْبِسُ عَلَيَّ الْخُلُقَ، وَيُضَيِّقُ عَليَّ الرِّزْقَ، حَتى اَقُومَ بِصالِحِ رِضاكَ، وَاَنْعَمَ بِجَزيلِ عَطائِكَ، وَاَسْعَدَ بِسابِغِ نَعْمائِكَ، فَقَدْ لُذْتُ بِحَرَمِكَ، وَتَعَرَّضْتُ لِكَرَمِكَ، واَسْتَعَذْتُ بِعَفْوِكَ مِنْ عُقُوبَتِكَ، وَبِحِلْمِكَ مِنْ غَضَبِكَ، فَجُدْ بِما سَأَلْتُكَ وَاَنِلْ مَا الَْتمَسْتُ مِنْكَ، اَساَلُكَ بِكَ لا بِشَيء هُوَ اَعْظَمُ مِنْكَ ."},{"type":"Text","content":"ثمّ تسجد وتقول : «يا رَبُّ» عشرين مرّة، «يا اَللهُ» سبع مرّات، «لا حَوْلَ وَلا قُوَّةَ إِلاّ بِاللهِ» سبع مرّات، «مآ شاءَ اللهُ» عشر مرّات، «لا قُوّةَ إِلاّ بِاللهِ» عشر مرّات، ثمّ تصلّي على النّبي (صلى الله عليه وآله وسلم) وآله وتسأل حاجتك فو الله لو سألت بها بعدد القطر لبلّغك الله عزوجل ايّاها بكرمه وفضله ."},{"type":"Text","content":"الحادي عشر : قال الطّوسي والكفعمي: يقال في هذه اللّيلة :"},{"type":"Text","content":"اِلـهي تَعَرَّضَ لَكَ في هذَ اللَّيْلِ الْمُتَعَرِّضُونَ، وَقَصَدَكَ الْقاصِدُونَ، وَاَمَّلَ فَضْلَكَ وَمَعْرُوفَكَ الطّالِبُونَ، وَلَكَ في هذَا اللّيْلِ نَفَحاتٌ وَجَوائِزُ وَعَطايا وَمَواهِبُ تَمُنُّ بِها عَلى مَنْ تَشاءُ مِنْ عِبادِكَ، وَتَمْنَعُها مَنْ لَمْ تَسْبِقْ لَهُ الْعِنايَةُ مِنْكَ، وَها اَنَا ذا عُبَيْدُكَ الْفَقيرُ اِلَيْكَ، الْمُؤَمِّلُ فَضْلَكَ وَمَعْرُوفَكَ، فَاِنْ كُنْتَ يا مَولايَ تَفَضَّلْتَ في هذِهِ اللَّيْلَةِ عَلى اَحَد مِنْ خَلْقِكَ، وَعُدْتَ عَلَيْهِ بِعائِدَة مِنْ عَطْفِكَ، فَصَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد الطَّيِّبينَ الطّاهِرينَ، الْخَيِّرينَ الْفاضِلينَ، وَجُدْ عَلَيَّ بِطَولِكَ وَمَعْرُوفِكَ يا رَبَّ الْعالَمينَ، وَصَلَّى اللهُ عَلى مُحَمَّد خاتَمِ النَّبيّينَ وَآلِهِ الطّاهِرينَ وَسَلَّمَ تَسْليماً، اِنَّ اللهَ حَميدٌ مَجيدٌ، اَللّـهُمَّ اِنّي اَدْعُوكَ كَما اَمَرْتَ فَاسْتَجِبْ لي كَما وَعَدْتَ اِنَّكَ لا تُخْلِف الْميعادَ ."}],"preview":"الثّامن : أن يدعو بدعاء كميل الذي اثبتناه في الباب الاوّل من الكتاب، وهو وارد في هذه الليلة .","hasTranslate":false},{"id":"mf_ar_111","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل الثّاني :","title":"وهذا دعاء يدعى به في الاسحار عقيب صلاة الشّفع","blocks":[{"type":"Text","content":"الثّاني عشر : أن يدعو بعد كلّ ركعتين من صلاة اللّيل وبعد الشّفع والوتر بما رواه الشّيخ والسّيد ."},{"type":"Text","content":"الثّالث عشر :أن يسجد السّجدات ويدعو بالدّعوات المأثورة عن النّبي (صلى الله عليه وآله وسلم)منها رواه الشّيخ، عن حماد بن عيسى، عن أبان بن تغلب قال : قال الصّادق صلوات الله وسلامه عليه : كان ليلة النّصف من شعبان وكان رسول الله (صلى الله عليه وآله وسلم)عند عايشة، فلمّا انتصف اللّيل قام رسول الله (صلى الله عليه وآله وسلم) عن فراشه، فلمّا انتبهت وجدت رسول الله (صلى الله عليه وآله وسلم)قد قام عن فراشها فداخلها ما يدخل النّساء أي الغيرة، وظنّت انّه قد قام الى بعض نسائه، فقامت وتلفّفت بشملتها وايم الله ما كانت قزّاً ولا كتاناً ولا قطناً ولكن سداه شعراً ولحمته أوبار الابل، فقامت تطلب رسول الله (صلى الله عليه وآله وسلم) في حجر نسائه حجرة حجرة فبينا هي كذلك اذ نظرت الى رسول الله (صلى الله عليه وآله وسلم) ساجداً كثوب متلبّد بوجه الارض فدنت منه قريباً فسمعته يقول في سجوده :"},{"type":"Text","content":"سَجَدَ لَكَ سَوادي وَخَيالي، وَآمَنَ بِكَ فؤادي، هذِهِ يَدايَ وَماجَنَيْتُهُ عَلى نَفْسي، يا عَظيمُ تُرْجى لِكُلِّ عَظيم، اِغْفِرْ لِيَ الْعَظيمَ فَاِنَّهُ لايَغْفِرُ الذَّنْبَ الْعَظيمَ إِلاّ الرَّبُّ الْعَظيم . ثمّ رفع رأسه وأهوى ثانياً الى السّجود وسمعته عايشة يقول :"},{"type":"Text","content":"اَعُوذُ بُنُورِ وَجْهِكَ الَّذي اَضاءَتْ لَهُ السَّماواتُ وَالاَْرَضُونَ، وانْكَشَفَتْ لَهُ الظُّلُماتُ، وَصَلَحَ عَلْيْهِ اَمرُ الاَْوَّلينَ وَالاْخِرينَ، مِنْ فُجْأَةِ نِقْمَتِكَ، وَمِنْ تَحْويلِ عافِيَتِكَ، وَمِنْ زَوالِ نِعْمَتِكَ، اَللّـهُمَّ ارْزُقْني قَلْباً تَقِيّاً نَقِيّاً، وَمِنَ الشِّرْكِ بَرياً لا كافِراً وَلا شَقِياً . ثمّ عفّر خدّيه في التّراب وقال : عَفَّرْتُ وَجْهي فِي التُرابِ وَحُقَّ لي اَنْ اَسْجُدَ لَكَ، فلمّا همّ رسول الله (صلى الله عليه وآله وسلم) بالانصراف هرولت الى فراشها وأتى النبي (صلى الله عليه وآله وسلم) الى الفراش وسمعها تتنفّس أنفاساً عالية، فقال لها رسول الله (صلى الله عليه وآله وسلم): ما هذا النّفس العال تعلمين أي ليلة هذه، ليلة النّصف من شعبان، فيها تقسم الارزاق، وفيها تكتب الاجال، وفيها يكتب وفد الحاج، وانّ الله تعالى ليغفر في هذه اللّيلة من خلقه اكثر من شعر معزي قبيلة كلب، وينزل الله ملائكة من السّماء الى الارض بمكّة ."}],"preview":"الثّاني عشر : أن يدعو بعد كلّ ركعتين من صلاة اللّيل وبعد الشّفع والوتر بما رواه الشّيخ والسّيد .","hasTranslate":false},{"id":"mf_ar_112","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل الثّاني :","title":"الرّابع عشر : أن يصلّي صلاة جعفر كما رواه الشّيخ عن الرّضا صلوات الله عليه","blocks":[{"type":"Text","content":"الخامس عشر : أن يأتي بما ورد في هذه اللّيلة من الصّلوات وهي كثيرة منها ما رواها أبو يحيى الصّنعاني عن الباقر والصّادق (عليهما السلام) ورواها عنهما ايضاً ثلاثون نفر ممّن يوثق بهم ويعتمد عليهم قالوا : قالا (عليهما السلام) : اذا كانت ليلة النّصف من شعبان فصلّ أربع ركعات تقرأ في كلّ ركعة الحمد وقُلْ هُوَ اللهُ أحَدٌ مرّة فاذا فرغت فقُل :"},{"type":"Text","content":"اَللّـهُمَّ اِنّي اِلَيْكَ فَقيرٌ، وَمِنْ عَذاِبكَ خائِفٌ مُسْتَجيرٌ، اَللّـهُمَّ لا تُبَدِّلِ اسمي، وَلا تُغَيِّرْ جِسْمي، وَلاتَجْهَدْ بَلائي، وَلاتُشْمِتْ بي اَعْدائي، اَعُوذُ بِعَفْوِكَ مِنْ عِقابِكَ، وَاَعُوذُ بِرَحْمَتِكَ مِنْ عَذابِكَ، وَاَعُوذُ بِرِضاكَ مِنْ سَخَطِكَ، وَاعُوذُ بِكَ مِنْكَ، جَلَّ ثَناؤُكَ، اَنْتَ كَما اَثْنَيْتَ عَلى نَفْسِكَ وَفَوْقَ مايَقُولُ الْقائِلُونَ ."},{"type":"AboutText","content":"واعلم انّه قد ورد في الحديث فضل كثير لصلاة مائة ركعة في هذه اللّيلة تقرأ في كلّ ركعة الحمد مرّة والتّوحيد عشر مرّات وقد مرّ في أعمال شهر رجب صفة الصّلاة ستّ ركعات في هذه اللّيلة يقرأ فيها سورة الحمد ويس وتبارك والتّوحيد ."}],"preview":"الخامس عشر : أن يأتي بما ورد في هذه اللّيلة من الصّلوات وهي كثيرة منها ما رواها أبو يحيى الصّنعاني عن الباقر والصّادق (عليهما السلام) ورواها عنهما ايضاً ثلاثون نفر ممّن يوثق بهم وي","hasTranslate":false},{"id":"mf_ar_113","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل الثّاني :","title":"يوم النّصف من شعبان","blocks":[{"type":"Text","content":"وهو عيد الميلاد قد ولد فيه الامام الثّاني عشر امامنا المهديّ الحجّة بن الحسن صاحب الزّمان صلوات الله عليه وعلى آبائه ويستحبّ زيارته (عليه السلام) في كلّ زمان ومكان والدّعاء بتعجيلِ الفرَج عند زيارته وتتأكّد زيارته في السّرداب بسرّ من رأى وهو المتيقّنُ ظهوره وتملّكُهُ وانّه يملا الارض قسطاً وعدلاً كما ملئت ظلماً وجوراً ."}],"preview":"وهو عيد الميلاد قد ولد فيه الامام الثّاني عشر امامنا المهديّ الحجّة بن الحسن صاحب الزّمان صلوات الله عليه وعلى آبائه ويستحبّ زيارته (عليه السلام) في كلّ زمان ومكان والدّعاء بتعجيلِ","hasTranslate":false},{"id":"mf_ar_114","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل الثّاني :","title":"أعمال ما بقي من هذا الشّهر","blocks":[{"type":"Text","content":"عن الرّضا صلوات الله وسلامه عليه قال : من صام ثلاثة أيّام من آخر شعبان ووصلها بشهر رمضان كتب الله تعالى له صيام شهرين متتابعين، وعن أبي الصّلت الهروي قال : دخلت على الامام الرّضا (عليه السلام)في آخر جمعة من شعبان فقال لي: يا أبا الصّلت انّ شعبان قد مضى اكثره وهذا آخر جمعة فيه فتدارك فيما بقى تقصيرك فيما مضى منه وعليك بالاقبال على ما يعنيك، واكثر من الدّعاء والاستغفار وتلاوة القرآن وتب الى الله من ذنوبك ليقبل شهر رمضان اليك وأنت مخلص لله عزّوجل، ولا تدعنّ امانة في عنقك الّا أدّيتها ولا في قلبك حقداً على مؤمن الّا نزعته، ولا ذنباً انت مرتكبه إلاّ أقلعت عنه، واتقّ الله وتوكّل عليه في سرائرك وعلانيتك(وَمَنْ يَتَوكَّلْ عَلَى اللهِ فَهُوَ حَسْبُهُ اِنَّ اللهَ بالِغُ اَمْرِهِ قَدْ جَعَلَ اللهُ لِكُلِّ شَىء قَدْراً) واكثر من أن تقول في ما بقى من هذا الشّهر : اَللّـهُمَّ اِنْ لَمْ تَكُنْ غَفَرْتَ لَنا فيما مَضى مِنْ شَعْبانَ فَاغْفِرْ لَنا فيما بَقِيَ مِنْهُ، فانّ الله تبارك وتعالى يعتق في هذا الشّهر رقاباً من النّار لحرمة هذا الشّهر، وروى الشّيخ عن حارث بن مغيرة النّضري قال : كان الصّادق صلوات الله وسلامه عليه يدعو في آخر ليلة من شعبان وأوّل ليلة من رمضان :"},{"type":"Text","content":"اَللّـهُمَّ اِنَّ هذَا الشَّهْرَ الْمُبارَكَ الَّذي اُنْزِلَ فيهِ الْقُرآنُ وَجُعِلَ هُدىً لِلنّاسِ وَبَيِّناتِ مِنَ الْهُدى وَالْفُرْقانِ قَدْ حَضَرَ فَسَلِّمْنا فيهِ وَسَلَّمْهُ لَنا وَتَسَلِّمْهُ مِنّا في يُسْر مِنْكَ وعافِيَة، يا مَنْ اَخَذَ الْقَليلَ، وَشَكَرَ الْكَثيرَ، اِقْبَل مِنِّى الْيَسيرَ، اَللّـهُمَّ اِنّي اَساَلُكَ اَنْ تَجْعَلَ لي اِلى كُلِّ خَيْر سَبيلاً، وَمِنْ كُلِّ ما لا تُحِبُّ مانِعاً، يا اَرْحَمَ الرّاحِمينَ، يا مَنْ عَفا عَنّي وَعَمّا خَلَوْتُ بِهِ مِنَ السَّيِّئاتِ، يا مَنْ لَمْ يُؤاخِذْني بِارْتِكابِ الْمَعاصي، عَفْوَكَ عَفْوَكَ عَفْوَكَ ياكَريمُ، اِلـهي وَعَظتَني فَلَمْ اَتَّعِظْ، وَزَجَرْتَني عَنْ مَحارِمِكَ فلَمْ اَنْزَجِرْ، فَما عُذْري، فَاعْفُ عَنّي يا كَريمُ، عَفْوَكَ عَفْوَكَ، اَللّـهُمَّ اِنّي اَساَلُكَ الرّاحَةَ عًنْدَ الْمَوْتِ، وَالْعَفْوَ عِنْدَ الْحِسابِ، عَظُمَ الذَّنْبُ مِنْ عَبدِكَ فَلْيَحْسُنِ التَّجاوُزُ مِنْ عِنْدِكَ، يا اَهْلَ التَّقْوى وَيا اَهْلَ الْمَغْفِرَةِ، عَفْوَكَ عَفْوَكَ، اَللّـهُمَّ اِنّي عَبْدُكَ ابْنُ عَبْدِكَ وابنُ اَمَتِكَ، ضَعيْفٌ فَقيرٌ اِلى رَحْمَتِكَ وَاَنْتَ مُنْزِلُ الْغِنى والْبَرَكَةِ عَلَى الْعِبادِ قاهِرٌ مُقْتَدِرٌ اَحْصَيْتَ اَعمالَهُمْ، وَقَسَمْتَ اَرْزاقَهُمْ، وَجَعَلْتَهُمْ مُخْتَلِفَةً اَلْسِنَتُهُمْ وَاَلْوانُهُمْ خَلْقاً مِنْ بَعْدِ خَلْق، وَلايَعْلَمُ الْعِبادُ عِلْمَكَ، وَلا يَقْدِرُ الْعِبادُ قَدْرَكَ، وَكُلُّنا فَقيرٌ اِلى رَحْمَتِكَ، فَلا تَصْرِفْ عَنّي وَجْهَكَ، واجْعَلْني مِنْ صالِحِي خَلْقِكَ الْعَمَلِ وَالاْمَلِ وَالْقَضاءِ وَالْقَدَرِ، اَللّـهُمَّ اَبْقِني خَيْرَ الْبَقاءِ، وَاَفِنني خَيْرَ الْفَناءِ عَلى مُوالاةِ اَوْلِيائِكَ وَمُعادةِ اَعْدائِكَ، والرَّغْبَةِ اِلَيْكَ، والرَّهْبَةِ مِنْكَ وَالْخُشُوعِ وَالْوَفاء وَالتَّسْليمِ لَكَ وَالتَّصْديقِ بِكِتابِكَ وَاتّباعِ سُنَّةِ رَسُولِكَ، اَللّـهُمَّ ما كانَ في قَلْبي مِنْ شَكٍّ اَوْ رَيْبَة اَوْ جُحُود اَوْ قُنُوط اَوْ فَرَح اَوْ بَذَخ اَوْ بَطَر اَوْ خُيَلاءِ اَوْ رِياء اَوْ سُمْعَة اَوْ شِقاق اَوْ نِفاق اَوْ كُفْر اَوْ فُسُوق اَوْ عِصْيان اَوْ عَظَمَة اَوْ شَيء لا تُحِبُّ فَاَسْأَلُكَ يا رَبِّ أنْ تُبَدِّلَني مَكانَهُ ايماناً بِوَعْدِكَ، وَوَفاءً بِعَهْدِكَ، وَرِضاً بِقَضائِكَ، وَزُهْداً فِي الدُّنْيا، وَرَغْبَةً فيما عِنْدَكَ، وَاَثَرَةً وَطُمَأنينَةً وَتَوْبَةً نَصُوحاً اَساَلُكَ ذلِكَ يا رَبَّ الْعالَمينَ، اِلـهي اَنْتَ مِنْ حِلْمِكَ تُعْصى، وَمِنْ كَرَمِكَ وَجُودِكَ تُطاعُ، فَكَانَّكَ لَمْ تُعْصَ وَاَنَا وَمَنْ لَمْ يَعْصِكَ سُكّانُ اَرْضِكَ، فَكُنْ عَلَيْنابِالْفَضْلِ جَواداً، وَبِالْخَيْرِ عَوّاداً يا اَرْحَمَ الرّاحِمينَ، وَصَلَّى اللهُ عَلى مُحَمَّد وَآلِهِ صَلاةً دائِمَةً لا تُحْصى وَلا تُعَدُّ وَلا يَقْدِرُ قَدْرَها غَيْرُكَ يا اَرْحَمَ الرّاحِمينَ ."}],"preview":"عن الرّضا صلوات الله وسلامه عليه قال : من صام ثلاثة أيّام من آخر شعبان ووصلها بشهر رمضان كتب الله تعالى له صيام شهرين متتابعين، وعن أبي الصّلت الهروي قال : دخلت على الامام الرّضا (","hasTranslate":false},{"id":"mf_ar_115","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل الثّالِثْ :","title":"في فضلِ شهر رَمضان وأعمالِه","blocks":[{"type":"Text","content":"روى الصّدوق بسند مُعتبر عن الرّضا (عليه السلام)، عن آبائه، عن أمير المؤمنين عليه وعلى أولاده السّلام قال : إنّ رسول الله (صلى الله عليه وآله وسلم) خطبنا ذات يوم فقال : أيّها النّاس أنّه قد أقبل إليكم شهر الله بالبركة والرّحمة والمغفرة، شهر هو عند الله أفضل الشّهور، وأيّامه أفضل الأيّام، ولياليه أفضل اللّيالي، وساعاته أفضل السّاعات، هو شهر دعيتم فيه الى ضيافة الله، وجعلتم فيه من أهل كرامة الله، أنفاسكم فيه تسبيح، ونومكم فيه عبادة، وعملكم فيه مقبول، ودعاؤكم فيه مستجاب، فسلوا الله ربّكم بنيّات صادقة، وقلُوب طاهرة أن يوفّقكم لصيامه، وتلاوة كتابه، فإنّ الشّقي من حرم غفران الله في هذا الشّهر العظيم، واذكروا بجوعكم وعطشكم فيه جوع يوم القيامة وعطشه، وتصدّقوا على فقرائكم ومساكينكم، ووقرّوا كباركم، وارحموا صغاركم، وصلوا أرحامكم، واحفظوا ألسنتكم، وغضّوا عمّا لا يحلّ النّظر إليه أبصاركم، وعمّا لا يحلّ الاستماع إليه اسماعكم و تحننوا على أيتام الناس يتحنّن على أيتامكم وتوبوا إليه من ذنوبكم، وارفعوا إليه أيديكم بالدّعاء في أوقات صلواتكم فانّها أفضل السّاعات ينظر الله عزوجل فيها بالرّحمة الى عباده يجيبهم إذا ناجوه، ويلبّيهم إذا نادوه، ويستجيب لهم اذا دعوه ."},{"type":"Text","content":"أيّها الناس إنّ أنفسكم مرهونة بأعمالكم ففكّوها باستغفاركم، وظهوركم ثقيلة من أوزاركم فخفّفوا عنها بطول سجودكم، واعلموا أنّ الله تعالى ذكره أقسمَ بعزّته أن لا يعذّب المصلّين والسّاجدين، وأن لا يروعهم بالنّار يوم يقوم النّاس لربّ العالمين ، أيّها النّاس من فطّر منكم صائماً مؤمناً في هذا الشّهر كان له بذلك عند الله عتق رقبة، ومغفرة لما مضى من ذنوبه ، قيل : يا رسول الله (صلى الله عليه وآله وسلم) وليس كّلنا يقدر على ذلك ، فقال (صلى الله عليه وآله وسلم) : اتّقوا النّار ولو بشقّ تمرة اتقّوا النّار ولو بشربة من ماء، فإنّ الله تعالى يهب ذلك الأجر لمن عمل هذا اليسير إذا لم يقدر على أكثر منه ، يا أيّها النّاس من حسّن منكم في هذا الشّهر خُلقه كان له جواز على الصّراط يوم تزلّ فيه الاقدام، ومن خفّف في هذا الشّهر عمّا ملكت يمنيه خفّف الله عليه حسابه، ومن كفّ فيه شرّه كفّ الله عنه غضبه يوم يلقاه، ومن أكرم فيه يتيماً أكرمه الله يوم يلقاه، ومن وصل فيه رحمه وصله الله برحمته يوم يلقاه، ومن قطع فيه رحمه قطع الله عنه رحمته يوم يلقاه، ومن تطوّع فيه بصلاة كتب الله له براءة من النّار، ومن أدّى فيه فرضاً كان له ثواب مَن أدّى سبعين فريضة فيما سواه من الشّهور، من أكثر فيه من الصّلاة عليّ ثقل الله ميزانه يوم تخفّ الموازين، ومن تلا فيه آية من القرآن كان له مثل أجر من ختم القرآن في غيره من الشّهور ، أيّها النّاس إنّ أبواب الجنان في هذا الشّهر مفتحة فسلوا ربّكم أن لا يغلقها عليكم، وأبواب النّيران مغلقة فسلوا ربّكم أن لا يفتحها عليكم، والشّياطين مغلولة فسلوا ربّكم أن لا يسلّطها عليكم ، إلخ ."},{"type":"AboutText","content":"وروى الصّدوق (رحمه الله) إنّ النّبي (صلى الله عليه وآله وسلم) كان إذا دخل شهر رمضان فكّ كلّ أسير وأعطى كلّ سائل ."},{"type":"AboutText","content":"أقول : شهر رمضان هو شهر الله ربّ العالمين وهو أشرف الشّهور شهر يفتح فيه أبواب السّماء وأبواب الجنان وأبواب الرّحمة ويغلق فيه أبواب جهنّم، وفي هذا الشّهر ليلة تكون عبادة الله فيها خيراً من عبادته في ألف شهر فانتبه فيه لنفسك وتبصّر كيف تقضى فيه ليلك ونهارك وكيف تصون جوارحك وأعضائك عن معاصي ربّك، وايّاك وأن تكون في ليلتك من النّائمين وفي نهارك من الغافلين عن ذكر ربّك، ففي الحديث انّ الله عزوجلّ يعتق في آخر كلّ يوم من أيّام شهر رمضان عند الافطار ألف ألف رقبة من النّار فاذا كانت ليلة الجمعة ونهارها اعتق الله من النّار في كلّ ساعة ألف ألف رقبة ممّن قد استوجب العذاب ويعتق في اللّيلة ا لاخيرة من الشّهر ونهارها بعدد جميع من أعتق في الشّهر كلّه، فايّاك يا أيّها العزيز وأن ينقضي عنك شهر رمضان وقد بقى عليك ذنب من الذّنوب وايّاك أن تعد من المُذنبين المحرومين من الاستغفار والدّعاء ، فَعَنِ الصّادق (عليه السلام) انّه : « مَنْ لَم يُغفَر لَه في شَهر رَمَضان لَم يُغفَر لَهُ الى قابِل اِلاّ أن يَشهَدَ عَرَفَةَ » وصن نفسك ممّا قد حرّمه الله ومن أن تفطر بمحرّم عليك، واعمل بما أوصى به مولانا الصّادق صلوات الله وسلامه عليه ، فقال : اذا أصبحت صائماً فليصم سمعك وبصرك وشعرك وجلدك وجميع جوارحك ، أي عن المحرّمات بل المكروهات أيضاً، وقال (عليه السلام) : لا يكن يوم صومك كيوم افطارك ، وقال (عليه السلام) : انّ الصّيام ليس من الطّعام والشّراب وحدهما فاذا صمتم فاحفظوا ألسنتكم عن الكذب، وغضّوا أبصاركم عمّا حرّم الله، ولا تنازعوا ولا تحاسدوا ولا تغتابوا ولا تمارُوا ولا تخالفوا (كذباً بل ولا صدقاً) ولا تسابوا ولا تشاتموا ولا تظلموا ولا تسافهوا ولا تضاجروا ولا تغفلوا عن ذكر الله وعن الصّلاة وألزموا الصّمت والسّكوت والصّبر والصدّق ومجانبة أهل الشّر، واجتنبوا قول الزّور والكذب والفرى والخصومة وظنّ السّوء والغيبة والنّميمة وكونوا مشرفين على الاخرة منتظرين لايّامكم (ظهور القائم (عليه السلام) من آل محمّد (صلى الله عليه وآله وسلم)) منتظرين لما وعدكم الله متزوّدين للقاء الله، وعليكم السّكينة والوقار والخشوع والخضوع وذلّ العبيد الخيّف من مولاها خائفين راجين، ولتكن أنت أيّها الصّائم قد طهر قلبك من العيوب وتقدّست سريرتك من الخبث ونظف جسمك من القاذورات وتبرّأت الى الله ممّن عداه وأخلصت الولاية له وصمتّ ممّا قد نهاك الله عنه في السّر والعلانية وخشيت الله حقّ خشيته في سرّك وعلانيك، ووهبت نفسك الله في أيّام صومك وفرغت قلبك له ونصبت نفسك له فيما أمرك ودعاك اليه ، فاذا فعلت ذلك كلّه فأنت صائم لله بحقيقة صومه صانع له ما أمرك، وكلّمأ انقصت منها شيئاً فيما بيّنت لك فقد نقص من صومك بمقدار ذلك، وانّ أبي (عليه السلام) قال : سمع رسول الله (صلى الله عليه وآله وسلم)امرأة تساب جارية لها وهي صائمة فدعا رسول الله (صلى الله عليه وآله وسلم) بطعام فقال لها : كُلي ، فقالت : أنا صائمة يا رسول الله (صلى الله عليه وآله وسلم) ، فقال : كيف تكونين صائمة وقد سببت جاريتك انّ الصّوم ليس من الطّعام والشّراب وانّما جعل الله ذلك حجاباً عن سواهما من الفواحش من الفعل والقول، ما أقلّ الصّوم وأكثر الجّوع، وقال أمير المؤمنين صلوات الله وسلامه عليه : كم من صائم ليس له من صيامه الّا الظّماء، وكم من قائم ليس له من قيامه الّا العناء، حبّذا نوم الاكياس وافطارهم، وعن جابر بن يزيد عن الباقر (عليه السلام)قال : قال النّبي (صلى الله عليه وآله وسلم) لجابر بن عبد الله : يا جابر هذا شهر رمضان مَن صام نهاره وقام ورداً من ليلته وصان بطنه وفرجه وحفظ لسانه لخرج من الذّنوب كما يخرج من الشّهر ، قال جابر : يا رسول الله (صلى الله عليه وآله وسلم) ما أحسنه من حديث ، فقال رسول الله (صلى الله عليه وآله وسلم) : وما أصعبها من شروط ."}],"preview":"روى الصّدوق بسند مُعتبر عن الرّضا (عليه السلام)، عن آبائه، عن أمير المؤمنين عليه وعلى أولاده السّلام قال : إنّ رسول الله (صلى الله عليه وآله وسلم) خطبنا ذات يوم فقال : أيّها النّاس","hasTranslate":false},{"id":"mf_ar_116","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل الثّالِثْ :","title":"وأمّا أعمال هذا الشّهر فسنعرضها في مطلبين وخاتمة :","blocks":[{"type":"Text","content":"وهِيَ أربعة أقسام"},{"type":"Text","content":"روى السّيد ابن طاووس (رحمه الله) عن الصّادق والكاظم (عليهما السلام) قالا : تقول في شهر رمضان من أوّله الى آخره بعد كلّ فريضة:"},{"type":"Text","content":"اَللّـهُمَّ ارْزُقْني حَجَّ بَيْتِكَ الْحَرامِ فِي عامي هذا وَفي كُلِّ عام ما اَبْقَيْتَني في يُسْر مِنْكَ وَعافِيَة، وَسَعَةِ رِزْق، وَلا تُخْلِني مِنْ تِلْكَ الْمواقِفِ الْكَريمَةِ، وَالْمَشاهِدِ الشَّريفَةِ، وَزِيارَةِ قَبْرِ نَبِيِّكَ صَلَواتُكَ عَلَيْهِ وَآلِهِ، وَفي جَميعِ حَوائِجِ الدُّنْيا وَالاْخِرَةِ فَكُنْ لي، اَللّـهُمَّ اِنّي اَساَلُكَ فيـما تَقْضي وَتُقَدِّرُ مِنَ الاَمْرِ الَْمحْتُومِ في لَيْلَةِ الْقَدْرِ، مِنَ الْقَضاءِ الَّذي لا يُرَدُّ وَلا يُبَدَّلُ، اَنْ تَكْتُبَني مِنْ حُجّاجِ بَيْتِكَ الْحَرامِ، الْمَبْرُورِ حَجُّهُمْ، الْمَشْكُورِ سَعْيُهُمْ، الْمَغْفُورِ ذُنُوبُهُمْ، الْمُكَفَّرِ عَنْهُمْ سَيِّئاتُهُمْ، واجْعَلْ فيـما تَقْضي وَتُقَدِّرُ، اَنْ تُطيلَ عُمْري، وَتُوَسِّعَ عَلَيَّ رِزْقي، وَتُؤدِّى عَنّي اَمانَتي وَدَيْني آمينَ رَبَّ الْعالَمين."}],"preview":"وهِيَ أربعة أقسام","hasTranslate":false},{"id":"mf_ar_117","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القِسمُ الاوّل : ما يعمّ اللّيالي والايّام :","title":"وتَدْعُو عقيب كلّ فريضة فتقول :","blocks":[{"type":"Text","content":"يا عَلِيُّ يا عَظيمُ، يا غَفُورُ يا رَحيمُ، اَنْتَ الرَّبُّ الْعَظيمُ الَّذي لَيْسَ كَمِثْلِهِ شَيءٌ وَهُوَ السَّميعُ الْبَصيرُ، وَهذا شَهْرٌ عَظَّمْتَهُ وَكَرَّمْتَهْ، وَشَرَّفْتَهُ وَفَضَّلْتَهُ عَلَى الشُّهُورِ، وَهُوَ الشَّهْرُ الَّذي فَرَضْتَ صِيامَهُ عَلَيَّ، وَهُوَ شَهْرُ رَمَضانَ، الَّذي اَنْزَلْتَ فيهِ الْقُرْآنَ، هُدىً لِلنّاسِ وَبَيِّنات مِنَ الْهُدى وَالْفُرْقانَ، وَجَعَلْتَ فيهِ لَيْلَةَ الْقَدْرِ، وَجَعَلْتَها خَيْراً مِنْ اَلْفِ شَهْر، فَيا ذَا الْمَنِّ وَلا يُمَنُّ عَلَيْكَ، مُنَّ عَلَيَّ بِفَكاكِ رَقَبَتي مِنَ النّارِ فيمَنْ تَمُنَّ عَلَيْهِ، وَاَدْخِلْنِى الْجَنَّةَ بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ ."},{"type":"AboutText","content":"وروى الكفعمي في المصباح وفي البلد الامين كما روى الشّيخ الشّهيد في مجموعته عن النّبي (صلى الله عليه وآله وسلم) انّه قال : من دعا بهذا الدّعاء في رمضان بعد كلّ فريضة غفر الله له ذنوبه الى يوم القيامة :"},{"type":"Text","content":"اَللّـهُمَّ اَدْخِلْ عَلى اَهْلِ الْقُبُورِ السُّرُورَ اَللّـهُمَّ اَغْنِ كُلَّ فَقير، اَللّـهُمَّ اَشْبِعْ كُلَّ جائِع، اَللّـهُمَّ اكْسُ كُلَّ عُرْيان، اَللّـهُمَّ اقْضِ دَيْنَ كُلِّ مَدين، اَللّـهُمَّ فَرِّجْ عَنْ كُلِّ مَكْرُوب، اَللّـهُمَّ رُدَّ كُلَّ غَريب، اَللّـهُمَّ فُكَّ كُلَّ اَسير، اَللّـهُمَّ اَصْلِحْ كُلَّ فاسِد مِنْ اُمُورِ الْمُسْلِمينَ، اَللّـهُمَّ اشْفِ كُلَّ مَريض، اللّهُمَّ سُدَّ فَقْرَنا بِغِناكَ، اَللّـهُمَّ غَيِّر سُوءَ حالِنا بِحُسْنِ حالِكَ، اَللّـهُمَّ اقْضِ عَنَّا الدَّيْنَ وَاَغْنِنا مِنَ الْفَقْرِ، اِنَّكَ عَلى كُلِّ شَيء قَديرٌ ."},{"type":"AboutText","content":"وروى الكليني في الكافي عن أبي بصير قال : كان الصّادق (عليه السلام) يدعو بهذا الدّعاء في شهر رمضان :"},{"type":"Text","content":"اَللّـهُمَّ اِنّي بِكَ وَمِنْكَ اَطْلُبُ حاجَتي، وَمَنْ طَلَبَ حاجَةً اِليَ النّاسِ فَاِنّي لا اَطْلُبُ حاجَتي إلاّ مِنْكَ وَحْدَكَ لا شَريكَ لَكَ، وَاَساَلُكَ بِفَضْلِكَ وَرِضْوانِكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وأهْلِ بَيْتِهِ، وَاَنْ تَجْعَلَ لي في عامي هذ اِلى بَيْتِكَ الْحَرامِ سَبيلاً حِجَّةً مَبْرُورَةً مُتَقبَّلَةً زاكِيَةً خالِصَةً، لَكَ تَقَرُّ بِها عَيْني، وَتَرْفَعُ بِها دَرَجَتي، وَتَرْزُقَني اَنْ اَغُضَّ بَصَري، وَاَنْ اَحْفَظَ فرْجي، وَاَنْ اَكُفَّ بِها عَنْ جَميعِ مَحارِمَكَ، حَتّى لايَكُونَ شَيءٌ آثَرَ عِنْدي مِنْ طاعَتِكَ وَخَشْيَتِكَ، وَالْعَمَلِ بِما اَحْبَبْتَ، وَالتَّرْكِ لِما كَرِهْتَ وَنَهَيْتَ عَنْهُ، وَاجْعَلْ ذلِكَ في يُسْر ويسار عافِيَة وَما اَنْعَمْتَ بِهِ عَلَيَّ، وَاَساَلُكَ اَنْ تَجْعَلَ وَفاتي قَتْلاً في سَبيلِكَ، تَحْتَ رايَةِ نَبِيِّكَ مَعَ اَوْلِيائِكَ، وَاَسْاَلُكَ اَنْ تَقْتُلَ بي اَعْداءَكَ وَاَعْداءَ رَسُولِكَ، وَاَسْاَلُكَ اَنْ تُكْرِمَني بِهَوانِ مَنْ شِئْتَ مِنْ خَلْقِكَ، وَلا تُهِنّي بِكَرامَةِ اَحَد مِنْ اَوْلِياءِكَ اَللّـهُمَّ اجْعَلْ لي مَعَ الرَّسُولِ سَبيلاً، حَسْبِيَ اللهُ ما شاءَ اللهُ ."},{"type":"AboutText","content":"أقول : هذا الدّعاء يسمّى دعاء الحجّ وقد رواه السّيد في الاقبال عن الصّادق (عليه السلام) لليالي شهر رمضان بعد المغرب، وقال الكفعمي في البلد الامين: يستحبّ الدّعاء به في كلّ يوم من رمضان وفي أوّل ليلة منه، وأورده المفيد في المقنعة في خصوص اللّيلة الاُولى بعد صلاة المغرب."},{"type":"AboutText","content":"واعلم انّ أفضل الاعمال في ليالي شهر رمضان وأيّامه هو تلاوة القرآن الكريم وينبغي الاكثار من تلاوته في هذا الشّهر ففيه كان نزول القرآن وفي الحديث انّ لكلّ شيء ربيعاً وربيع القرآن هو شهر رمضان، ويستحبّ في سائر الايّام ختم القرآن ختمة واحدة في كلّ شهر وأقلّ ما روى في ذلك هو ختمة في كلّ ستّة أيّام، وامّا شهر رمضان فالمسنون فيه ختمه في كلّ ثلاثة أيّام، ويحسن إن تيسّر له أن يختمه ختمة في كلّ يوم، وروى العلامة المجلسي (رحمه الله) انّ بعض الائمة الاطهار (عليهم السلام) كانوا يختمون القرآن في هذا الشّهر أربعين ختمة واكثر من ذلك، ويضاعف ثواب الختمات ان أهديت الى أرواح المعصومين الاربعة عشر يخصّ كلّ منهم بختمة، ويظهر من بعض الرّوايات انّ أجر مهديها أن يكون معهم في يوم القيامة، وليكثر المرء في هذا الشّهر من الدّعاء والصّلاة والاستغفار ومن قول لا اِلـه إلاّ اللهُ وقد روي انّ زين العابدين (عليه السلام) كان اذا دخل شهر رمضان لا يتكلّم إلاّ بالدّعاء والتّسبيح والاستغفار والتّكبير، وليهتم اهتماماً بالغاً بالمأثور من ا لعبادات ونوافل اللّيالي والايّام ."},{"type":"Text","content":"وهي اُمور : الاوّل : الافطار ويستحبّ تأخيره عن صلاة العشاء الّا اذا غلب عليه الضّعف أو كان له قوم ينتظرونه ."},{"type":"Text","content":"الثّاني : أن يفطر بالحلال الخالي من الشّبهات سيّما التّمر ليضاعف أجر صلاته أربعمائة ضعف ويحسن الافطار أيضاً بأيّ من التّمر والرّطب والحلواء والنّبات ـ النّبات كلمة فارسيّة تعنى بلّورات خاصة من السّكر ـ والماء الحار ."},{"type":"Text","content":"الثّالث : أن يدعو عند الافطار بدعوات الافطار المأثورة، منها أن يقول: اَللّـهُمَّ لَكَ صُمْتُ، وَعَلى رِزْقِكَ اَفْطَرْتُ، وَعَلَيْكَ تَوَكَّلْتُ، ليهب الله له مثل أجر كلّ من صام ذلك اليوم ولدعاء اَللّـهُمَّ رَبَّ النّورِ الْعَظيم الذي رواه السّيد والكفعمي فضل كبير، وروي انّ امير المؤمنين (عليه السلام) كان اذا أراد أن يفطر يقول : بِسْمِ اللهِ اَللّـهُمَّ لَكَ صُمْنا وَعَلى رِزْقِكَ اَفْطَرْنا فَتَقَبَّلْ مِنّا اِنَّكَ اَنْتَ السَّميعُ الْعَليمُ ."},{"type":"Text","content":"الرّابع : أن يقول عند أوّل لقمة يأخذها: بِسْمِ اللهِ الرَّحْمـنِ الرّحَيـمِ، يا واسِعَ الْمَغْفِرَةُ اِغْفِرْ لي، لِيَغفِرَ اللهُ لهُ وفي الحديث انّ الله تعالى يعتق في آخر ساعة من نهار كلّ يوم من شهر رمضان ألف ألف رقبة فسل الله تعالى أن يجعلك منهم ."},{"type":"Text","content":"الخامس : أن يتلو سورة القدر عند الافطار ."},{"type":"Text","content":"السّادس : أن يتصدّق عند الافطار ويفطّر الصّائمين ولو بعدد من التّمر أو بشربة من الماء ، وعن النّبي (صلى الله عليه وآله وسلم) : انّ من فطّر صائماً فله أجر مثله من دون أن ينقص من أجره شيء وكان له مثل أجر ما عمله من الخير بقوّة ذلك الطّعام ."},{"type":"AboutText","content":"وروى آية الله العلاّمة الحلّي في الرّسالة السّعديّة عن الصّادق (عليه السلام) : انّ أيّما مؤمن أطعم مؤمناً لقمة في شهر رمضان كتب الله له أجر من أعتق ثلاثين رقبة مؤمنة وكان له عند الله تعالى دعوة مستجابة ."}],"preview":"يا عَلِيُّ يا عَظيمُ، يا غَفُورُ يا رَحيمُ، اَنْتَ الرَّبُّ الْعَظيمُ الَّذي لَيْسَ كَمِثْلِهِ شَيءٌ وَهُوَ السَّميعُ الْبَصيرُ، وَهذا شَهْرٌ عَظَّمْتَهُ وَكَرَّمْتَهْ، وَشَرَّفْتَ","hasTranslate":false},{"id":"mf_ar_118","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القِسمُ الثّاني : ما يستحبّ إيتانه في ليالي شهر رمضان","title":"الثّامن : أن يتلو سورة حم الدخّان في كلّ ليلة مائة مرّة إن تيسّرت","blocks":[{"type":"Text","content":"التّاسع : روى السّيد انّ من قال هذا الدّعاء في كلّ ليلة من شهر رمضان غفرت له ذنوب أربعين سنة :"},{"type":"Text","content":"اَللّـهُمَّ رَبَّ شَهْرِ رَمَضانَ الَّذي اَنْزَلْتَ فيهِ الْقُرْآنَ، وَافْتَرَضْتَ على عِبادِكَ فيهِ الصِّيامَ، صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَارْزُقْني حَجَّ بَيْتِكَ الْحَرامِ في عامي هذا وَفي كُلِّ عام، وَاغْفِرْ لي تِلْكَ الذُّنُوبَ الْعِظامَ، فَاِنَّهُ لا يَغْفِرُها غَيْرُكَ يا رَحْمنُ يا عَلاّمُ ."}],"preview":"التّاسع : روى السّيد انّ من قال هذا الدّعاء في كلّ ليلة من شهر رمضان غفرت له ذنوب أربعين سنة :","hasTranslate":false},{"id":"mf_ar_119","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القِسمُ الثّاني : ما يستحبّ إيتانه في ليالي شهر رمضان","title":"الحادي عشر : أن يدعو في كلّ ليلة من رمضان بهذا الدّعاء :","blocks":[{"type":"Text","content":"اَللّـهُمَّ اِنّي اَفْتَتِحُ الثَّناءَ بِحَمْدِكَ، وَاَنْتَ مُسَدِّدٌ لِلصَّوابِ بِمَّنِكَ، وَاَيْقَنْتُ اَنَّكَ اَنْتَ اَرْحَمُ الرّاحِمينَ في مَوْضِعِ الْعَفْوِ وَالرَّحْمَةِ، وَاَشَدُّ الْمُعاقِبينَ في مَوْضِعِ النَّكالِ وَالنَّقِمَةِ، وَاَعْظَمُ الْمُتَجَبِّرِينَ في مَوْضِعِ الْكِبْرياءِ وَالْعَظَمَةِ، اَللّـهُمَّ اَذِنْتَ لي في دُعائِكَ وَمَسْأَلَتِكَ فَاسْمَعْ يا سَميعُ مِدْحَتي، وَاَجِبْ يا رَحيمُ دَعْوَتي، وَاَقِلْ يا غَفُورُ عَثْرَتي، فَكَمْ يا اِلهي مِنْ كُرْبَة قَدْ فَرَّجْتَها وَهُمُوم قَدْ كَشَفْتَها، وَعَثْرَة قَدْ اَقَلْتَها، وَرَحْمَة قَدْ نَشَرْتَها، وَحَلْقَةِ بَلاء قَدْ فَكَكْتَها، اَلْحَمْدُ للهِ الَّذي لَمْ يَتَّخِذْ صاحِبَةً وَلا وَلَداً، وَلَمْ يَكُنْ لَهُ شَريكٌ في الْمُلْكِ، وَلَمْ يَكُنْ لَهُ وَلِىٌّ مِنَ الذُّلِّ وَكَبِّرْهُ تَكْبيراً، اَلْحَمْدُ للهِ بِجَميعِ مَحامِدِهِ كُلِّهَا، عَلى جَميعِ نِعَمِهِ كُلِّها اَلْحَمْدُ للهِ الَّذي لا مُضادَّ لَهُ في مُلْكِهِ، وَلا مُنازِعَ لَهُ في اَمْرِهِ، اَلْحَمْدُ للهِ الَّذي لا شَريكَ لَهُ في خَلْقِهِ، وَلا شَبيهَ لَهُ في عَظَمَتِهِ، اَلْحَمْدُ للهِ الْفاشي في الْخَلْقِ اَمْرُهُ وَحَمْدُهُ، الظّاهِرِ بِالْكَرَمِ مَجْدُهُ، الْباسِطِ بِالْجُودِ يَدَهُ، الَّذي لا تَنْقُصُ خَزائِنُهُ، وَلا تَزيدُهُ كَثْرَةُ الْعَطاءِ إلاّ جُوداً وَكَرَماً، اِنَّهُ هُوَ الْعَزيزُ الْوَهّابُ، اَللّـهُمَّ اِنّي اَسْاَلُكَ قَليلاً مِنْ كَثير، مَعَ حاجَة بي اِلَيْهِ عَظيمَة وَغِناكَ عَنْهُ قَديمٌ، وَهُوَ عِنْدي كَثيرٌ، وَهُوَ عَلَيْكَ سَهْلٌ يَسيرٌ، اَللّـهُمَّ اِنَّ عَفْوَكَ عَنْ ذَنْبي، وَتَجاوُزَكَ عَنْ خَطيـئَتي، وَصَفْحَكَ عَنْ ظُلْمي وَسِتْرَكَ عَنْ قَبيحِ عَمَلي، وَحِلْمَكَ عَنْ كَثيرِ جُرْمي، عِنْدَ ما كانَ مِنْ خَطئي وَعَمْدي، اَطْمَعَني في اَنْ اَسْأَلَكَ ما لا اَسْتَوْجِبُهُ مِنْكَ، الَّذي رَزَقْتَني مِنْ رَحْمَتِكَ، وَاَرَيْتَني مَنْ قُدْرَتِكَ، وَعَرَّفْتَني مِنْ اِجابَتِكَ، فَصِرْتُ اَدْعُوكَ آمِناً، وَاَسْاَلُكَ مُسْتَأنِساً، لا خائِفاً وَلا وَجِلاً، مُدِلاًّ عَلَيْكَ فيـما قَصَدْتُ فيهِ اِلَيْكَ، فَاِنْ اَبْطأَ عَنّي عَتَبْتُ بِجَهْلي عَلَيْكَ، وَلَعَلَّ الَّذي اَبْطأَ عَنّي هُوَ خَيْرٌ لي لِعِلْمِكَ بِعاقِبَةِ الاُْمُورِ، فَلَمْ اَرَ مَوْلاً كَريماً اَصْبَرَ عَلى عَبْد لَئيم مِنْكَ عَلَيَّ يا رَبِّ، اِنَّكَ تَدْعُوني فَاُوَلّي عَنْكَ، وَتَتَحَبَّبُ اِلَيَّ فَاَتَبَغَّضُ اِلَيْكَ، وَتَتَوَدَّدُ اِلَىَّ فَلا اَقْبَلُ مِنْكَ، كَاَنَّ لِيَ التَّطَوُّلَ عَلَيْكَ، فَلَمْ يَمْنَعْكَ ذلِكَ مِنَ الرَّحْمَةِ لي، وَالاِْحْسانِ اِلَىَّ، وَالتَّفَضُّلِ عَلَيَّ بِجُودِكَ وَكَرَمِكَ، فَارْحَمْ عَبْدَكَ الْجاهِلَ وَجُدْ عَلَيْهِ بِفَضْلِ اِحْسانِكَ اِنَّكَ جَوادٌ كَريمٌ، اَلْحَمْدُ للهِ مالِكِ الْمُلْكِ، مُجْرِي الْفُلْكِ، مُسَخِّرِ الرِّياحِ، فالِقِ الاِْصْباحِ، دَيّانِ الدّينِ، رَبِّ الْعَالَمينَ، اَلْحَمْدُ للهِ عَلى حِلْمِهِ بَعْدَ عِلمِهِ، وَالْحَمْدُ للهِ عَلى عَفْوِهِ بَعْدَ قُدْرَتِهِ، وَالْحَمْدُ للهِ عَلى طُولِ اَناتِهِ في غَضَبِهِ، وَهُوَ قادِرٌ عَلى ما يُريدُ، اَلْحَمْدُ للهِ خالِقِ الْخَلْقِ، باسِطِ الرِّزْقِ، فاِلقِ اَلاِْصْباحِ ذِي الْجَلالِ وَالاِْكْرامِ وَالْفَضْلِ وَالاِْنْعامِ، الَّذي بَعُدَ فَلا يُرى، وَقَرُبَ فَشَهِدَ النَّجْوى تَبارَكَ وَتَعالى، اَلْحَمْدُ للهِ الَّذي لَيْسَ لَهُ مُنازِعٌ يُعادِلُهُ، وَلا شَبيهٌ يُشاكِلُهُ، وَلا ظَهيرٌ يُعاضِدُهُ قَهَرَ بِعِزَّتِهِ الاَْعِزّاءَ، وَتَواضَعَ لِعَظَمَتِهِ الْعُظَماءُ، فَبَلَغَ بِقُدْرَتِهِ ما يَشاءُ، اَلْحَمْدُ للهِ الَّذي يُجيبُني حينَ اُناديهِ، وَيَسْتُرُ عَلَيَّ كُلَّ عَورَة وَاَنَا اَعْصيهِ، وَيُعَظِّمُ الْنِّعْمَةَ عَلَىَّ فَلا اُجازيهِ، فَكَمْ مِنْ مَوْهِبَة هَنيئَة قَدْ اَعْطاني، وَعَظيمَة مَخُوفَة قَدْ كَفاني، وَبَهْجَة مُونِقَة قَدْ اَراني، فَاُثْني عَلَيْهِ حامِداً، وَاَذْكُرُهُ مُسَبِّحاً، اَلْحَمْدُ للهِ الَّذي لا يُهْتَكُ حِجابُهُ، وَلا يُغْلَقُ بابُهُ، وَلا يُرَدُّ سائِلُهُ، وَلا يُخَيَّبُ آمِلُهُ، اَلْحَمْدُ للهِ الَّذي يُؤْمِنُ الْخائِفينَ، وَيُنَجِّى الصّالِحينَ، وَيَرْفَعُ الْمُسْتَضْعَفينَ، وَيَضَعُ الْمُسْتَكْبِرينَ،يُهْلِكُ مُلُوكاً وَيَسْتَخْلِفُ آخَرينِ، وَالْحَمْدُ للهِ قاِصمِ الجَّبارينَ، مُبيرِ الظّالِمينَ، مُدْرِكِ الْهارِبينَ، نَكالِ الظّالِمينَ صَريخِ الْمُسْتَصْرِخينَ، مَوْضِعِ حاجاتِ الطّالِبينَ، مُعْتَمَدِ الْمُؤْمِنينَ، اَلْحَمْدُ للهِ الَّذي مِنْ خَشْيَتِهِ تَرْعَدُ السَّماءُ وَسُكّانُها، وَتَرْجُفُ الاَْرْضُ وَعُمّارُها، وَتَمُوجُ الْبِحارُ وَمَنْ يَسْبَحُ في غَمَراتِها، اَلْحَمْدُ للهِ الَّذي هَدانا لِهذا وَما كُنّا لِنَهْتَدِيَ لَوْلا اَنْ هَدانَا اللّهُ، اَلْحَمْدُ للهِ الَّذي يَخْلُقُ، وَلَمْ يُخْلَقْ وَيَرْزُقُ، وَلا يُرْزَقُ وَيُطْعِمُ، وَلا يُطْعَمُ وَيُميتُ الاَْحياءَ وَيُحْيِي الْمَوْتى وَهُوَ حَيٌّ لا يَمُوتُ، بِيَدِهِ الْخَيْرُ وَهُوَ عَلى كُلِّ شَيْء قَديرٌ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد عَبْدِكَ وَرَسُولِكَ، وَاَمينِكَ، وَصَفِيِّكَ، وَحَبيبِكَ، وَخِيَرَتِكَ مَنْ خَلْقِكَ، وَحافِظِ سِرِّكَ، وَمُبَلِّغِ رِسالاتِكَ، اَفْضَلَ وَاَحْسَنَ، وَاَجْمَلَ وَاَكْمَلَ، وَاَزْكى وَاَنْمى، وَاَطْيَبَ وَاَطْهَرَ، وَاَسْنى وَاَكْثَرَ ما صَلَّيْتَ وَبارَكْتَ وَتَرَحَّمْتَ، وَتَحَنَّنْتَ وَسَلَّمْتَ عَلى اَحَد مِن عِبادِكَ وَاَنْبِيائِكَ وَرُسُلِكَ، وَصِفْوَتِكَ وَاَهْلِ الْكَرامَةِ عَلَيْكَ مِن خَلْقِكَ، اَللّـهُمَّ وَصَلِّ عَلى عَليٍّ اَميرِ الْمُؤْمِنينَ، وَوَصِيِّ رَسُولِ رَبِّ الْعالَمينَ، عَبْدِكَ وَوَليِّكَ، وَاَخي رَسُولِكَ، وَحُجَّتِكَ عَلى خَلْقِكَ، وَآيَتِكَ الْكُبْرى، وَالنَّبأِ الْعَظيمِ، وَصَلِّ عَلَى الصِّدّيقَةِ الطّاهِرَةِ فاطِمَةَ سَيِّدَةِ نِساءِ الْعالَمينَ، وَصَلِّ عَلى سِبْطَيِ الرَّحْمَةِ وَاِمامَيِ الْهُدى، الْحَسَنِ وَالْحُسَيْنِ سَيِّدَيْ شَبابِ اَهْلِ الْجَّنَةِ، وَصَلِّ عَلى اَئِمَّةِ الْمُسْلِمينَ، عَلِيِّ بْنِ الْحُسَيْنِ، وَمُحَمَّدِ ابْنِ عَلِيٍّ، وَجَعْفَرِ بْنِ مُحَمَّد، وَمُوسَى بْنِ جَعْفَر، وَعَلِيِّ بْنِ مُوسى، وَمُحَمَّدِ بْنِ عَلِيٍّ، وَعَلِيِّ بْنِ مُحَمَّد، وَالْحَسَنِ بْنِ عَلِىٍّ، وَالْخَلَفِ الْهادي الْمَهْدِيِّ، حُجَجِكَ عَلى عِبادِكَ، وَاُمَنائِكَ في بِلادِكَ صَلَاةً كَثيرَةً دائِمَةً اَللّـهُمَّ وَصَلِّ عَلى وَلِىِّ اَمْرِكَ الْقائِمِ الْمُؤَمَّلِ، وَالْعَدْلِ الْمُنْتَظَرِ، وَحُفَّهُ بِمَلائِكَتِكَ الْمُقَرَّبينَ، وَاَيِّدْهُ بِرُوحِ الْقُدُسِ يا رَبَّ الْعالَمينَ، اَللّـهُمَّ اجْعَلْهُ الدّاعِيَ اِلى كِتابِكَ، وَالْقائِمَ بِدينِكَ، اِسْتَخْلِفْهُ في الاَْرْضِ كَما اسْتَخْلَفْتَ الَّذينَ مِنْ قَبْلِهِ، مَكِّنْ لَهُ دينَهُ الَّذي ارْتَضَيْتَهُ لَهُ، اَبْدِلْهُ مِنْ بَعْدِ خَوْفِهِ اَمْناً يَعْبُدُكَ لا يُشْرِكُ بِكَ شَيْئاً، اَللّـهُمَّ اَعِزَّهُ وَاَعْزِزْ بِهِ، وَانْصُرْهُ وَانْتَصِرْ بِهِ، وَانْصُرْهُ نَصْراً عَزيزاً، وَاْفتَحْ لَهُ فَتْحاً يَسيراً، وَاجْعَلْ لَهُ مِنْ لَدُنْكَ سُلْطاناً نَصيراً، اَللّـهُمَّ اَظْهِرْ بِهِ دينَكَ، وَسُنَّةَ نَبِيِّكَ، حَتّى لا يَسْتَخْفِيَ بِشَىْء مِنَ الْحَقِّ، مَخافَةَ اَحَد مِنَ الْخَلْقِ اَللّـهُمَّ اِنّا نَرْغَبُ اِلَيْكَ في دَوْلَة كَريمَة تُعِزُّ بِهَا الاِْسْلامَ وَاَهْلَهُ، وَتُذِلُّ بِهَا النِّفاقَ وَاَهْلَهُ، وَتَجْعَلُنا فيها مِنَ الدُّعاةِ اِلى طاعَتِكَ، وَالْقادَةِ اِلى سَبيلِكَ، وَتَرْزُقُنا بِها كَرامَةَ الدُّنْيا وَالاْخِرَةِ، اَللّـهُمَّ ما عَرَّفْتَنا مِن الْحَقِّ فَحَمِّلْناهُ، وَما قَصُرْنا عَنْهُ فَبَلِّغْناهُ، اَللّـهُمَّ الْمُمْ بِهِ شَعَثَنا، وَاشْعَبْ بِهِ صَدْعَنا، وَارْتُقْ بِهِ فَتْقَنا، وَكَثِّرْبِهِ قِلَّتَنا، وَاَعْزِزْ بِهِ ذِلَّتَنا، وَاَغْنِ بِهِ عائِلَنا، وَاَقْضِ بِهِ عَنْ مَغْرَمِنا، وَاجْبُرْبِهِ فَقْرَنا، وَسُدَّ بِهِ خَلَّتَنا، وَيَسِّرْ بِهِ عُسْرَنا، وَبَيِّضْ بِهِ وُجُوهَنا، وَفُكَّ بِهِ اَسْرَنا، وَاَنْجِحْ بِهِ طَلِبَتَنا، وَاَنْجِزْ بِهِ مَواعيدَنا، وَاسْتَجِبْ بِهِ دَعْوَتَنا، وَاَعْطِنا بِهِ سُؤْلَنا، وَبَلِّغْنا بِهِ مِنَ الدُّنْيا وَالاْخِرَةِ آمالَنا، وَاَعْطِنا بِهِ فَوْقَ رَغْبَتِنا، يا خَيْرَ الْمَسْؤولينَ وَاَوْسَعَ الْمُعْطينَ، اِشْفِ بِهِ صُدُورَنا، وَاَذْهِبْ بِهِ غَيْظَ قُلُوبِنا، وَاهْدِنا بِهِ لِمَا اخْتُلِفَ فيهِ مِنَ الْحَقِّ بِاِذْنِكَ، اِنَّكَ تَهْدي مَنْ تَشاءُ اِلى صِراط مُسْتَقيم، وَانْصُرْنا بِهِ عَلى عَدُوِّكَ وَعَدُوِّنا اِلـهَ الْحَقِّ آمينَ، اَللّـهُمَّ اِنّا نَشْكُو اِلَيْكَ فَقْدَ نَبِيِّنا صَلَواتُكَ عَلَيْهِ وَآلِهِ، وَغَيْبَةَ وَلِيِّنا، وَكَثْرَةَ عَدُوِّنا، وَقِلَّةَ عَدَدِنا، وَشِدّةَ الْفِتَنِ بِنا، وَتَظاهُرَ الزَّمانِ عَلَيْنا، فَصَلِّ عَلى مُحَمَّد وَآلِهِ، وَاَعِنّا عَلى ذلِكَ بِفَتْح مِنْكَ تُعَجِّلُهُ، وَبِضُرٍّ تَكْشِفُهُ، وَنَصْر تُعِزُّهُ وَسُلْطانِ حَقٍّ تُظْهِرُهُ، وَرَحْمَة مِنْكَ تَجَلِّلُناها وَعافِيَة مِنْكَ تُلْبِسُناها، بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ ."}],"preview":"اَللّـهُمَّ اِنّي اَفْتَتِحُ الثَّناءَ بِحَمْدِكَ، وَاَنْتَ مُسَدِّدٌ لِلصَّوابِ بِمَّنِكَ، وَاَيْقَنْتُ اَنَّكَ اَنْتَ اَرْحَمُ الرّاحِمينَ في مَوْضِعِ الْعَفْوِ وَالرَّحْمَةِ، وَ","hasTranslate":false},{"id":"mf_ar_120","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القِسمُ الثّاني : ما يستحبّ إيتانه في ليالي شهر رمضان","title":"الثّاني عشر : أن يقول في كلّ ليلة :","blocks":[{"type":"Text","content":"اَللّـهُمَّ بِرَحْمَتِكَ فِي الصّالِحينَ فَاَدْخِلْنا، وَفي عِلِّيّينَ فَارْفَعْنا، وِبَكَأس مِنْ مَعين مِنْ عَيْن سَلْسَبيل فاسْقِنا، وَمِنَ الْحُورِ الْعينِ بِرَحْمَتِكَ فَزَوِّجْنا، وَمِنَ الْوِلْدانِ الُْمخَلَّدينَ كَاَنَّهُمْ لُؤْلُؤٌ مَكْنُونٌ فَاَخْدِمْنا، وَمِنْ ثِمارِ الْجَنَّةِ وَلُحُومِ الطَّيْرِ فَاَطْعِمْنا، وِمِنْ ثِيابِ السُّنْدُسِ وَالْحَريرِ وَالاِسْتَبْرَقِ فَاَلْبِسْنا، وَلَيْلَةَ الْقَدْرِ وَحَجَّ بَيْتِكَ الْحرامِ، وَقَتْلاً في سَبيلِكَ فَوفِّقْ لَنا، وَصالِحَ الدُّعاءِ وَالْمَسْأَلةِ فاسْتَجِبْ لَنا، وَاِذا جَمَعْتَ الاَوَّلينَ وَالاخِرينَ يَوْمَ الْقِيامَةِ فاَرْحَمْنا وَبَراءَةً مِنَ النّارِ فَاكْتُبْ لَنا، وَفي جَهَنَّمَ فَلا تَغُلَّنا، وَفي عَذابِكَ وَهَوانِكَ فَلا تَبْتَلِنا، وَمِنَ الزَّقُّومِ وَالضَّريعِ فَلا تُطْعِمْنا، وَمَعَ الشَّياطينِ فَلا تَجْعَلْنَا، وَفِي النّارِ عَلى وُجُوهِنا فَلا تَكْبُبْنا، وَمِنْ ثِيابِ النّارِ وَسَرابيلِ الْقَطِرانِ فَلا تُلْبِسْنا، وَمِنْ كُلِّ سُوء يا لا اَله إلاّ اَنْتَ بِحَقِّ لا اِلـهَ إلاّ اَنْتَ فَنَجِّنا ."}],"preview":"اَللّـهُمَّ بِرَحْمَتِكَ فِي الصّالِحينَ فَاَدْخِلْنا، وَفي عِلِّيّينَ فَارْفَعْنا، وِبَكَأس مِنْ مَعين مِنْ عَيْن سَلْسَبيل فاسْقِنا، وَمِنَ الْحُورِ الْعينِ بِرَحْمَتِكَ فَزَوِّج","hasTranslate":false},{"id":"mf_ar_121","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القِسمُ الثّاني : ما يستحبّ إيتانه في ليالي شهر رمضان","title":"الثّالث عشر : عن الصّادق (عليه السلام) قال : تقول في كلّ ليلة من شهر رمضان :","blocks":[{"type":"Text","content":"اَللّـهُمَّ اِنّي اَسْاَلُكَ اَنْ تَجْعَلَ فيـما تَقْضي وَتُقَدِّرُ مِنَ الاَمْرِ الَْمحْتُومِ فِى الاَمْرِ الْحَكيمِ، مِنَ الْقَضاءِ الَّذي لا يُرَدُّ وَلا يُبَدَّلُ اَنْ تَكْتُبَني مِنْ حُجّاجِ بَيْتِكَ الْحَرامِ، الْمَبْرُورِ حَجُّهُمْ، الْمَشْكُورِ سَعْيُهُمْ ،الْمَغْفُورِ ذُنُوبُهُمْ، اَلْمُكَفَّرِ عَنْ سَيِّئاتِهِمْ، وَأنْ تَجْعَلَ فيـما تَقْضي وَتُقَدِّرُ، اَنْ تُطيلَ عُمْري في خَيْر وَعافِيَة، وَتُوَسِّعَ في رِزْقي، َوَتَجْعَلَني مِمَّنْ تَنْتصِرُ بِهِ لِدينِكَ وَلا تَسْتَبْدِلْ بي غَيْري ."}],"preview":"اَللّـهُمَّ اِنّي اَسْاَلُكَ اَنْ تَجْعَلَ فيـما تَقْضي وَتُقَدِّرُ مِنَ الاَمْرِ الَْمحْتُومِ فِى الاَمْرِ الْحَكيمِ، مِنَ الْقَضاءِ الَّذي لا يُرَدُّ وَلا يُبَدَّلُ اَنْ تَكْتُبَ","hasTranslate":false},{"id":"mf_ar_122","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القِسمُ الثّاني : ما يستحبّ إيتانه في ليالي شهر رمضان","title":"الرّابع عشر : في كتاب أنيس الصّالحين اُدع في كلّ ليلة من ليالي شهر رمضان قائلاً :","blocks":[{"type":"Text","content":"اَعُوذُ بِجَلالِ وَجْهِكَ الْكَريمِ اَنْ يَنْقَضِيَ عَنّي شَهْرُ رَمَضانَ، اَوْ يَطْلُعَ الْفَجْرُ مِنْ لَيْلَتي هذِهِ، وَلَكَ قِبَلي تَبِعَةٌ اَوْ ذَنْبٌ تُعَذِّبُني عَلَيْهِ ."},{"type":"Text","content":"الخامس عشر : روى الكفعمي في هامش كتابه البلد الامين عن السّيد ابن باقي قال : يستحبّ في كلّ ليلة من ليالي شهر رمضان صلاة ركعتين تقرأ في كلّ ركعة الحمد والتّوحيد ثلاث مرّات فاذا سلّمت تقول : سُبْحانَ مَنْ هُوَ حَفيظٌ لا يَغْفُل، سُبحانَ مَنْ هُوَ رَحيمٌ لا يَعْجَلُ، سُبْحانَ مَنْ هُوَ قا ئِمٌ لا يَسْهُو، سُبْحانَ مَنْ هُوَ دائِمٌ لا يَلْهُو، ثمّ تسبّح بالتّسبيحات الاربع سبع مرّات ثمّ تقول : سُبْحانَكَ سُبْحانَكَ سُبْحانَكَ، يا عَظيمُ اغْفِرْ لِيَ الذَّنْبَ الْعَظيمَ . ثمّ تصلّي على النّبي وآله عشر مرّات ."},{"type":"Text","content":"من صلّى هذه الصّلاة غفر الله له سبعين ألف سيّئة ... الخ ."},{"type":"Text","content":"السّادس عشر : في الحديث انّ من قرأ في كلّ ليلة من شهر رمضان سورة انّا فتَحنا في صلاة مسنونة كان مصُوناً في ذلك العام ، واعلم انّ من أعمال ليالي شهر رمضان الصّلاة ألف ركعة وقد أشار اليها المشايخ والاعاظم في كتبهم في الفقه وفي العبادة، وأمّا كيفيّة هذه الصّلاة فقد اختلفت فيها الرّوايات وهي على ما رواها ابن أبي قرة عن الجواد (عليه السلام)واختارها المفيد في كتاب الغرية والاشراف بل واختارها المشهور هي أن يصلّي منها في كلّ ليلة من ليالي العشر الاُولى والثّانية عشرين ركعة يسلّم بين كلّ ركعتين، فيصلّي منها ثمان ركعات بعد صلاة المغرب والباقية وهي اثنتا عشرة ركعة تؤخّر عن صلاة العشاء وفي العشرة، الاخيرة يصلّي منها كلّ ليلة ثلاثين ركعة يؤتي ثمان منها بعد صلاة المغرب أيضاً ويؤخّر الباقية عن العشاء، فالمجموع يكون سبعمائة ركعة وهي تنقص عن الالف ركعة ثلاثمائة ركعة، وهي تؤدّى في ليالي القدر وهي اللّيلة التّاسعة عشرة والحادية والعشرون والثّالثة، والعشرون فيخصّ كلّ من هذه اللّيالي بمائة ركعة منها، فتتمّ الالف ركعة وقد وزّع هذه الصّلاة على الشّهر بنحو آخر وتفصيل ذلك في مقام اخر ولا يسعنا هنا بسط الكلام ."},{"type":"AboutText","content":"روي انّك تقول بعد كلّ ركعتين من نوافل شهر رمضان :"},{"type":"Text","content":"اَللّـهُمَّ اجْعَلْ فيـما تَقْضي وَتُقَدِّرُ مِنَ الامْرِ الَْمحْتُومِ، وَفيـما تَفْرُقُ مِنَ الاَمْرِ الْحَكيمِ، في لَيْلَةِ الْقَدْرِ، اَنْ تَجْعَلَني مِنْ حُجّاجِ بَيْتِكَ الْحَرامِ، الْمَبْرُورِ حَجُّهُمُ الْمَشْكُورِ سَعْيُهُمْ، الْمَغْفُورِ ذُنُوبُهُمُ، وَاَسْاَلُكَ اَنْ تُطيلَ عُمْري في طاعَتِكَ، وَتُوَسِّعَ لي في رِزْقي، يا اَرْحَمَ الرّاحِمينَ ."},{"type":"Text","content":"وهي عديدة : الاوّل : أن يتسحّر فلا يدع السّحُور ولو على حشفة تمر أو جرعة من الماء، وأفضل السّحور السّويق والتّمر وفي الحديث انّ الله وملائكته يصلّون على المستغفرين والمستسحرين بالاسحار ."},{"type":"Text","content":"الثّاني : أن يقرأ عند السّحور سورة انّا أنزلناه، ففي الحديث ما من مؤمن صام فقرأ «انّا أنْزَلناهُ في ليلة القدر» عند سحوره وعند افطاره الّا كان فيما بينهما كالمتشحّط بدمه في سبيل الله ."},{"type":"Text","content":"الثّالث : أن يدعو بهذا الدّعاء العظيم الشّأن الذي روي عن الرّضا صلوات الله وسلامه عليه انّه قال : هو دعاء الباقر (عليه السلام) في أسحار شهر رمضان :"},{"type":"Text","content":"اَللّـهُمَّ اِنّي اَسْاَلُكَ مِنْ بَهائِكَ بِاَبْهاهُ وَكُلُّ بَهائِكَ بَهِىٌّ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِبَهائِكَ كُلِّهِ، اَللّـهُمَّ اِنّي اَسْاَلُكَ مِنْ جَمالِكَ بِاَجْمَلِهِ وَكُلُّ جَمالِكَ جَميلٌ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِجَمالِكَ كُلِّهِ، اَللّـهُمَّ اِنّي اَسْاَلُكَ مِنْ جَلالِكَ بِاَجَلِّهِ وَكُلُّ جَلالِكَ جَليلٌ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِجَلالِكَ كُلِّهِ، اَللّـهُمَّ اِنّي اَسْاَلُكَ مِنْ عَظَمَتِكَ بِاَعْظَمِها وَكُلُّ عَظَمَتِكَ عَظَيمَةٌ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِعَظَمَتِكَ كُلِّها، اَللّـهُمَّ اِنّي اَسَأَلُكَ مِنْ نُورِكَ بِاَنْوَرِهِ وَكُلُّ نُورِكَ نَيِّرٌ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِنُورِكَ كُلِّهِ، اَللّـهُمَّ اِنّي اَسْاَلُكَ مِنْ رَحْمَتِكَ بِاَوْسَعِها وَكُلُّ رَحْمَتِكَ واسِعَةٌ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِرَحْمَتِكَ كُلِّها، اَللّـهُمَّ اِنّي اَسْاَلُكَ مِنْ كَلِماتِكَ بِاَتَمِّها وَكُلُّ كَلِماتِكَ تامَّةٌ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِكَلِماتِكَ كُلِّهَا، اَللّـهُمَّ اِنّي اَسْاَلُكَ مِنْ كَمالِكَ بِاَكْمَلِهِ وَكُلُّ كَمالِكَ كامِلٌ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِكَمالِكَ كُلِّهِ، اَللّـهُمَّ اِنّي اَسْاَلُكَ مِنْ اَسمائِكَ بِاَكْبَرِها وَكُلُّ اَسْمائِكَ كَبيرَةٌ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِاَسْمائِكَ كُلِّها، اَللّـهُمَّ اِنّي اَسْاَلُكَ مِنْ عِزَّتِكَ باَعَزِّها وَكُلُّ عِزَّتِكَ عَزيزَةٌ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِعِزَّتِكَ كُلِّها، اَللّـهُمَّ اِنّي اَسْاَلُكَ مِنْ مَشِيَّتِكَ بِاَمْضاها وَكُلُّ مَشِيَّتِكَ ماضِيَةٌ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِمَشِيَّتِكَ كُلِّها، اَللّـهُمَّ اِنّي اَسْاَلُكَ مِنْ قُدْرَتِكَ بِالْقُدْرَةِ الَّتي اسْتَطَلْتَ بِها عَلى كُلِّ شَيْء وَكُلُّ قُدْرَتِكَ مُسْتَطيلَةٌ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِقُدْرَتِكَ كُلِّها، اَللّـهُمَّ اِنّي اَسْاَلُكَ مِنْ عِلْمِكَ بِاَنْفَذِهِ وَكُلُّ عِلْمِكَ نافِذٌ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِعِلْمِكَ كُلِّهِ، اَللّـهُمَّ اِنّي اَسْاَلُكَ مِنْ قَوْلِكَ بِاَرْضاهُ وَكُلُّ قَوْلِكَ رَضِيٌّ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِقَوْلِكَ كُلِّهِ، اَللّـهُمَّ اِنّي اَسْاَلُكَ مِنْ مَسائِلِكَ بِاَحَبِّها اِلَيْكَ وَكُلُّ مَسائِلِكَ اِلَيْكَ حَبيبَةٌ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِمَسائِلِكَ كُلِّها، اَللّـهُمَّ اِنّي اَسْاَلُكَ مِنْ شَرَفِكَ بِاَشْرَفِهِ وَكُلُّ شَرَفِكَ شَريفٌ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِشَرَفِكَ كُلِّهِ، اَللّـهُمَّ اِنّي اَسْاَلُكَ مِنْ سُلْطانِكَ بِاَدْوَمِهِ وَكُلُّ سُلطانِكَ دائِمٌ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِسُلْطانِكَ كُلِّهِ، اَللّـهُمَّ اِنّي اَسْاَلُكَ مِنْ مُلْكِكَ بِاَفْخَرِهِ وَكُلُّ مُلْكِكَ فاخِرٌ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِمُلْكِكَ كُلِّهِ، اَللّـهُمَّ اِنّي اَسْاَلُكَ مِنْ عُلُوِّكَ بِاَعْلاهُ وَكُلُّ عُلُوِّكَ عال، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِعُلُوِّكَ كُلِّهِ، اَللّـهُمَّ اِنّي اَسْاَلُكَ مِنْ مَنِّكَ بِاَقْدَمِهِ وَكُلُّ مَنِّكَ قَديمٌ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِمَنِّكَ كُلِّهِ، اَللّـهُمَّ اِنّي اَسْاَلُكَ مِنْ اياتِكَ بِاَكْرَمِها وَكُلُّ آياتِكَ كَريمَةٌ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِآياتِكَ كُلِّها، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِما اَنْتَ فيهِ مِنَ الشَّأنِ وَالْجَبَرُوتِ، وَاَسْاَلُكَ بِكُلِّ شَأْن وَحْدَهُ جَبَرُوت وَحْدَها، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِما تُجيبُني بِهِ حينَ اَسْاَلُكَ فَاَجِبْني يا اَللهُ ."},{"type":"Text","content":"ثمّ سل حاجتك فانّها تقضى البتّة ."}],"preview":"اَعُوذُ بِجَلالِ وَجْهِكَ الْكَريمِ اَنْ يَنْقَضِيَ عَنّي شَهْرُ رَمَضانَ، اَوْ يَطْلُعَ الْفَجْرُ مِنْ لَيْلَتي هذِهِ، وَلَكَ قِبَلي تَبِعَةٌ اَوْ ذَنْبٌ تُعَذِّبُني عَلَيْهِ .","hasTranslate":false},{"id":"mf_ar_123","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القِسمُ الثّالثُ : في أعمال أسحار شهر رمضان المبارك","title":"دعاء أبي حمزة الثّمالي:","blocks":[{"type":"Text","content":"الرّابع : في المصباح عن أبي حمزة الثّمالي (رحمه الله) قال : كان زين العابدين (عليه السلام) يصلّي عامّة اللّيل في شهر رمضان فاذا كان في السّحر دعا بهذا الدّعاء :"},{"type":"Text","content":"اِلهي لا تُؤَدِّبْني بِعُقُوبَتِكَ، وَلا تَمْكُرْ بي في حيلَتِكَ، مِنْ اَيْنَ لِيَ الْخَيْرُ يا رَبِّ وَلا يُوجَدُ إلاّ مِنْ عِنْدِكَ، وَمِنْ اَيْنَ لِيَ النَّجاةُ وَلا تُسْتَطاعُ إلاّ بِكَ، لاَ الَّذي اَحْسَنَ اسْتَغْنى عَنْ عَوْنِكَ وَرَحْمَتِكَ، وَلاَ الَّذي اَساءَ وَاجْتَرَأَ عَلَيْكَ وَلَمْ يُرْضِكَ خَرَجَ عَنْ قُدْرَتِكَ، يا رَبِّ يا رَبِّ يا رَبِّ حتّى ينقطع النّفس."},{"type":"Text","content":"بِكَ عَرَفْتُكَ وَاَنْتَ دَلَلْتَني عَلَيْكَ وَدَعَوْتَني اِلَيْكَ، وَلَوْلا اَنْتَ لَمْ اَدْرِ ما اَنْتَ، اَلْحَمْدُ للهِ الَّذي اَدْعوُهُ فَيُجيبُني وَاِنْ كُنْتَ بَطيـئاً حينَ يَدْعوُني، وَاَلْحَمْدُ للهِ الَّذي اَسْأَلُهُ فَيُعْطيني وَاِنْ كُنْتُ بَخيلاً حينَ يَسْتَقْرِضُني، وَالْحَمْدُ للهِ الَّذي اُناديهِ كُلَّما شِئْتُ لِحاجَتي، وَاَخْلُو بِهِ حَيْثُ شِئْتُ، لِسِرِّي بِغَيْرِ شَفيع فَيَقْضى لي حاجَتي، اَلْحَمْدُ للهِ الَّذي لا اَدْعُو غَيْرَهُ وَلَوْ دَعَوْتُ غَيْرَهُ لَمْ يَسْتَجِبْ لي دُعائي، وَالْحَمْدُ للهِ الَّذي لا اَرْجُو غَيْرَهُ وَلَوْ رَجَوْتُ غَيْرَهُ لاََخْلَفَ رَجائي، وَالْحَمْدُ للهِ الَّذي وَكَلَني اِلَيْهِ فَاَكْرَمَني وَلَمْ يَكِلْني اِلَى النّاسِ فَيُهينُوني، وَالْحَمْدُ للهِ الَّذي تَحَبَّبَ اِلَىَّ وَهُوَ غَنِيٌّ عَنّي، وَالْحَمْدُ للهِ الَّذي يَحْلُمُ عَنّي حَتّى كَاَنّي لا ذَنْبَ لي، فَرَبّي اَحْمَدُ شَيْيء عِنْدي، وَاَحَقُّ بِحَمْدي، اَللّـهُمَّ اِنّي اَجِدُ سُبُلَ الْمَطالِبِ اِلَيْكَ مُشْرَعَةً، وَمَناهِلَ الرَّجاءِ اِلَيْكَ مُتْرَعَةً، وَالاِْسْتِعانَةَ بِفَضْلِكَ لِمَنْ اَمَّلَكَ مُباحَةً، وَاَبْوابَ الدُّعاءِ اِلَيْكَ لِلصّارِخينَ مَفْتُوحَةً، وَاَعْلَمُ اَنَّكَ لِلرّاجي بِمَوْضِعِ اِجابَة، وَلِلْمَلْهُوفينَ بِمَرْصَدِ اِغاثَة، وَاَنَّ فِي اللَّهْفِ اِلى جُودِكَ وَالرِّضا بِقَضائِكَ عِوَضاً مِنْ مَنْعِ اْلباِخلينَ، وَمَنْدُوحَةً عَمّا في اَيْدي الْمُسْتَأثِرينَ، وَاَنَّ الِراحِلَ اِلَيْكَ قَريبُ الْمَسافَةِ، وَاَنَّكَ لا تَحْتَجِبُ عَنْ خَلْقِكَ إلاّ اَنْ تَحْجُبَهُمُ الاَْعمالُ دُونَكَ، وَقَدْ قَصَدْتُ اِلَيْكَ بِطَلِبَتي،"},{"type":"Text","content":"وَتَوَجَّهْتُ اِلَيْكَ بِحاجَتي، وَجَعَلْتُ بِكَ اسْتِغاثَتي، وَبِدُعائِكَ تَوَسُّلي مِنْ غَيْرِ اِسْتِحْقاق لاِسْتِماعِكَ مِنّي، وَلاَ اسْتيجاب لِعَفْوِكَ عَنّي، بَلْ لِثِقَتي بِكَرَمِكَ، وَسُكُوني اِلى صِدْقِ وَعْدِكَ، وَلَجَائي اِلَى الاْيمانِ بِتَوْحيدِكَ، وَيَقيني بِمَعْرِفَتِكَ مِنّي اَنْ لا رَبَّ لي غَيْرُكَ، وَلا اِلـهَ إلاّ اَنْتَ وَحْدَكَ لا شَريكَ لَكَ، اَللّـهُمَّ اَنْتَ الْقائِلُ وَقَوْلُكَ حَقٌّ، وَوَعْدُكَ صِدْقٌ (وَاسْأَلاوُ اللهَ مِنْ فَضْلِهِ اِنَ اللهَ كانَ بِكُمْ رَحيماً)، وَلَيْسَ مِنْ صِفاتِكَ يا سَيّدي اِنْ تَأمُرَ بِالسُّؤالِ وَتَمْنَعَ الْعَطِيَّةَ، وَاَنْتَ الْمَنّانُ بِالْعَطِيّاتِ عَلى اَهْلِ مَمْلَكَتِكَ، وَالْعائِدُ عَلَيْهِمْ بِتَحَنُّنِ رَأفَتِكَ، اِلهي رَبَّيْتَني في نِعَمِكَ وَاِحْسانِكَ صَغيراً، وَنَوَّهْتَ بِاِسْمي كَبيراً، فَيا مَنْ رَبّاني فِي الدُّنْيا بِاِحْسانِهِ وَتَفَضُّلِهِ وَنِعَمِهِ، وَاَشارَ لي فِي الاْخِرَةِ اِلى عَفْوِهِ وَكَرَمِهِ، مَعْرِفَتي يا مَوْلايَ دَليلي عَلَيْكَ، وَحُبّي لَكَ شَفيعي اِلَيْكَ، وَاَنَا واثِقٌ مِنْ دَليلي بِدَلالَتِكَ، وَساكِنٌ مِنْ شَفيعي اِلى شَفاعَتِكَ، اَدْعُوكَ يا سَيِّدي بِلِسان قَدْ اَخْرَسَهُ ذَنْبُهُ، رَبِّ اُناجيكَ بِقَلْب قَدْ اَوْبَقَهُ جُرْمُهُ، اَدْعوُكَ يا رَبِّ راهِباً راعِباً، راجِياً خائِفاً، اِذا رَاَيْتُ مَوْلايَ ذُنُوبي فَزِعْتُ، وَاِذا رَاَيْتُ كَرَمَكَ طَمِعْتُ، فَاِنْ عَفَوْتَ فَخَيْرُ راحِم، وَاِنْ عَذَّبْتَ فَغَيْرُ ظالِم، حُجَّتي يا اَللهُ في جُرْأَتي عَلى مَسْأَلَتِكَ، مَعَ اِتْياني ما تَكْرَهُ، جُودُكَ وَكَرَمُكَ، وَعُدَّتي في شِدَّتي مَعَ قِلَّةِ حَيائي رَأفَتُكَ وَرَحْمَتُكَ، وَقَدْ رَجَوْتُ اَنْ لا تَخيبَ بَيْنَ ذَيْنِ وَذَيْنِ مُنْيَتي، فَحَقِّقْ رَجائي، وَاَسْمِعْ دُعائي يا خَيْرَ مَنْ دَعاهُ داع، وَاَفْضَلَ مَنْ رَجاهُ راج، عَظُمَ يا سَيِّدي اَمَلي، وَساءَ عَمَلي، فَاَعْطِني مِنْ عَفْوِكَ بِمِقْدارِ اَمَلي، وَلا تُؤاخِذْني بِأَسْوَءِ عَمَلي، فَاِنَّ كَرَمَكَ يَجِلُّ عَنْ مُجازاةِ الْمُذْنِبينَ، وَحِلْمَكَ يَكْبُرُ عَنْ مُكافاةِ الْمُقَصِّرينَ، وَاَنَا يا سَيِّدي عائِذٌ بِفَضْلِكَ، هارِبٌ مِنْكَ اِلَيْكَ، مُتَنَجِّزٌ ما وَعَدْتَ مِنَ الصَّفْحِ عَمَّنْ اَحْسَنَ بِكَ ظَنّاً، وَما اَنَا يا رَبِّ وَما خَطَري، هَبْني بِفَضْلِكَ، وَتَصَدَّقْ عَلَيَّ بِعَفْوِكَ اَيْ رَبِّ جَلِّلْني بِسَتْرِكَ، وَاعْفُ عَنْ تَوْبيخي بِكَرَمِ وَجْهِكَ، فَلَوِ اطَّلَعَ الْيَوْمَ عَلى ذَنْبي غَيْرُكَ ما فَعَلْتُهُ، وَلَوْ خِفْتُ تَعْجيلَ الْعُقُوبَةِ لاَجْتَنَبْتُهُ، لا لاَِنَّكَ اَهْوَنُ النّاظِرينَ وَاَخَفُّ الْمُطَّلِعينَ، بَلْ لاَِنَّكَ يا رَبِّ خَيْرُ السّاتِرينَ، وَاَحْكَمُ الْحاكِمينَ، وَاَكْرَمُ الاَْكْرَمينَ، سَتّارُ الْعُيُوبِ، غَفّارُ الذُّنُوبِ، عَلاّمُ الْغُيُوبِ، تَسْتُرُ الذَّنْبِ بِكَرَمِكَ، وَتُؤَخِّرُ الْعُقُوبَةَ بِحِلْمِكَ، فَلَكَ الْحَمْدُ عَلى حِلْمِكَ بَعْدَ عِلْمِكَ، وَعَلى عَفْوِكَ بَعْدَ قُدْرَتِكَ، وَيَحْمِلُني وَيُجَرَّئُني عَلى مَعْصِيَتِكَ حِلْمُكَ عَنّي، وَيَدْعُوني اِلى قِلَّةِ الْحَياءِ سِتْرُكَ عَلَيَّ، وَيُسْرِعُني اِلَى التَّوَثُّبِ عَلى مَحارِمِكَ مَعْرِفَتي بِسِعَةِ رَحْمَتِكَ، وَعَظيمِ عَفْوِكَ، يا حَليمُ يا كَريمُ، يا حَيُّ يا قَيُّومُ، يا غافِرَ الذَّنْبِ، يا قابِلَ التَّوْبِ، يا عَظيمَ الْمَنِّ، يا قَديمَ الاِْحسانِ، اَيْنَ سَِتْرُكَ الْجَميلُ، اَيْنَ عَفْوُكَ الْجَليلُ، اَيْنَ فَرَجُكَ الْقَريبُ، اَيْنَ غِياثُكَ السَّريعُ، اَيْنَ رَحْمَتِكَ الْواسِعَةِ، اَيْنَ عَطاياكَ الْفاضِلَةُ، اَيْنَ مَواهِبُكَ الْهَنيئَةُ، اَيْنَ صَنائِعُكَ السَّنِيَّةُ، اَيْنَ فَضْلُكَ الْعَظيمُ، اَيْنَ مَنُّكَ الْجَسيمُ، اَيْنَ اِحْسانُكَ الْقَديمُ، اَيْنَ كَرَمُكَ يا كَريمُ، بِهِ فَاسْتَنْقِذْني، وَبِرَحْمَتِكَ فَخَلِّصْني، يا مُحْسِنُ يا مُجْمِلُ، يا مُنْعِمُ يا مُفْضِلُ، لَسْتُ اَتَّكِلُ فِي النَّجاةِ مِنْ عِقابِكَ عَلى اَعْمالِنا، بَلْ بِفَضْلِكَ عَلَيْنا، لاَِنَّكَ اَهْلَ التَّقْوى وَاَهْلَ الْمَغْفِرَةِ تُبْدِئُ بِالاِْحْسانِ نِعَماً، وَتَعْفُو عَنِ الذَّنْبِ كَرَماً، فَما نَدْري ما نَشْكُرُ، اَجَميلَ ما تَنْشُرُ، اَمْ قَبيحَ ما تَسْتُرُ، اَمْ عَظيمَ ما اَبْلَيْتَ وَاَوْلَيْتَ، اَمْ كَثيرَ ما مِنْهُ نَجَّيْتَ وَعافَيْتَ، يا حَبيبَ مَنْ تَحَبَّبَ اِلَيْكَ، وَيا قُرَّةَ عَيْنِ مَنْ لاذَ بِكَ وَانْقَطَعَ اِلَيْكَ، اَنْتَ الُْمحْسِنُ وَنَحْنُ الْمُسيؤنَ فَتَجاوَزْ يا رَبِّ عَنْ قَبيحِ ما عِنْدَنا بِجَميلِ ما عِنْدَكَ، وَاَيُّ جَهْل يا رَبِّ لا يَسَعُهُ جُودُكَ، اَوْ اَيُّ زَمان اَطْوَلُ مِنْ اَناتِكَ، وَما قَدْرُ اَعْمالِنا في جَنْبِ نِعَمِكَ، وَكَيْفَ نَسْتَكْثِرُ اَعْمالاً نُقابِلُ بِها كَرَمَكَ، بَلْ كَيْفَ يَضيقُ عَلَى الْمُذْنِبينَ ما وَسِعَهُمْ مِنْ رَحْمَتِكَ، يا واسِعَ الْمَغْفِرَةِ، يا باسِطَ الْيَدَيْنِ بِالرَّحْمَةِ، فَوَ عِزَّتِكَ يا سَيِّدي، لَوْ نَهَرْتَني ما بَرِحْتُ مِنْ بابِكَ، وَلا كَفَفْتُ عَنْ تَمَلُّقِكَ، لِمَا انْتَهى اِلَىَّ مِنَ الْمَعْرِفَةِ بِجُودِكَ وَكَرِمَك، وَاَنْتَ الْفاعِلُ لِما تَشاءُ تُعَذِّبُ مَنْ تَشاءُ بِما تَشاءُ كَيْفَ تَشاءُ، وَتَرْحَمُ مَنْ تَشاءُ بِما تَشاءُ كَيْفَ تَشاءُ، لا تُسْأَلُ عَنْ فِعْلِكَ، وَلا تُنازِعُ في مُلْكِكَ، وَلا تُشارَكُ في اَمْرِكَ، وَلا تُضادُّ في حُكْمِكَ، وَلا يَعْتَرِضُ عَلَيْكَ اَحَدٌ في تَدْبيرِكَ، لَكَ الْخَلْقُ وَالاَْمْرُ، تَبارَكَ اللهُ رَبُّ الْعالَمينَ، يا رَبِّ هذا مَقامُ مَنْ لاذَ بِكَ، وَاسْتَجارَ بِكَرَمِكَ، وَاَلِفَ اِحْسانَكَ وَنِعَمَكَ وَاَنْتَ الْجَوادُ الَّذي لا يَضيقُ عَفُْوكَ، وَلا يَنْقُصُ فَضْلُكَ، وَلا تَقِلُّ رَحْمَتُكَ، وَقَدْ تَوَثَّقْنا مِنْكَ بِالصَّفْحِ الْقَديمِ، وَالْفَضْلِ الْعَظيمِ، وَالرَّحْمَةِ الْواسِعَةِ، اَفَتَراكَ يا رَبِّ تُخْلِفُ ظُنُونَنا، اَوْ تُخَيِّبْ آمالَنا، كَلاّ يا كَريمُ، فَلَيْسَ هذا ظَنُّنا بِكَ، وَلا هذا فيكَ طَمَعُنا يا رَبِّ اِنَّ لَنا فيكَ اَمَلاً طَويلاً كَثيراً، اِنَّ لَنا فيكَ رَجاءً عَظيماً، عَصَيْناكَ وَنَحْنُ نَرْجُو اَنْ تَسْتُرَ عَلَيْنا، وَدَعَوْناكَ وَنَحْنُ نَرْجُو اَنْ تَسْتَجيبَ لَنا، فَحَقِّقْ رَجاءَنا مَوْلانا، فَقَدْ عَلِمْنا ما نَسْتَوْجِبُ بِاَعْمالِنا، وَلكِنْ عِلْمُكَ فينا وَعِلْمُنا بِاَنَّكَ لا تَصْرِفُنا عَنْكَ وَاِنْ كُنّا غَيْرَ مُسْتَوْجِبينَ لِرَحْمَتِكَ، فَاَنْتَ اَهْلٌ اَنْ تَجُودَ عَلَيْنا وَعَلَى الْمُذْنِبينَ بِفَضْلِ سَعَتِكَ، فَامْنُنْ عَلَيْنا بِما اَنْتَ اَهْلُهُ، وَجُدْ عَلَيْنا فَاِنّا مُحْتاجُونَ اِلى نَيْلِكَ، يا غَفّارُ بِنُورِكَ اهْتَدَيْنا، وَبِفَضْلِكَ اسْتَغْنَيْنا، وَبِنِعْمَتِكَ اَصْبَحْنا وَاَمْسَيْنا، ذُنُوبَنا بَيْنَ يَدَيْكَ نَسْتَغْفِرُكَ الّلهُمَّ مِنْها وَنَتُوبُ اِلَيْكَ، تَتَحَبَّبُ اِلَيْنا بِالنِّعَمِ وَنُعارِضُكَ بِالذُّنُوبِ، خَيْرُكَ اِلَيْنا نازِلٌ، وَشُّرنا اِلَيْكَ صاعِدٌ، وَلَمْ يَزَلْ وَلا يَزالُ مَلَكٌ كَريمٌ يَأتيكَ عَنّا بِعَمَل قَبيح، فَلا يَمْنَعُكَ ذلِكَ مِنْ اَنْ تَحُوطَنا بِنِعَمِكَ، وَتَتَفَضَّلَ عَلَيْنا بِآلائِكَ، فَسُبْحانَكَ ما اَحْلَمَكَ وَاَعْظَمَكَ وَاَكْرَمَكَ مُبْدِئاً وَمُعيداً، تَقَدَّسَتْ اَسْماؤكَ وَجَلَّ ثَناؤُكَ، وَكَرُمَ صَنائِعُكَ وَفِعالُكَ، اَنْتَ اِلهي اَوْسَعُ فَضْلاً، وَاَعْظَمُ حِلْماً مِنْ اَنْ تُقايِسَني بِفِعْلي وَخَطيـئَتي، فَالْعَفْوَ الْعَفْوَ الْعَفْوَ، سَيِّدي سَيِّدي سَيِّدي، اَللّـهُمَّ اشْغَلْنا بِذِكْرِكَ، وَاَعِذْنا مِنْ سَخَطِكَ، وَاَجِرْنا مِنْ عَذابِكَ، وَارْزُقْنا مِنْ مَواهِبِكَ، وَاَنْعِمْ عَلَيْنا مِنْ فَضْلِكَ، وَارْزُقْنا حَجَّ بَيْتِكَ، وَزِيارَةَ قَبْرِ نَبِيِّكَ صَلَواتُكَ وَرَحْمَتُكَ وَمَغْفِرَتُكَ وَرِضْوانُكَ عَلَيْهِ وَعَلى اَهْلِ بَيْتِهِ اِنَّكَ قَريبٌ مُجيبٌ، وَارْزُقْنا عَمَلاً بِطاعَتِكَ، وَتَوَفَّنا عَلى مِلَّتِكَ، وَسُنَّةِ نَبِيِّكَ صَلَّى اللهُ عَلَيْهِ وَآلِهِ، اَللّـهُمَّ اغْفِرْ لي وَلِوالِدَيَّ وَارْحَمْهُما كَما رَبَّياني صَغيراً، اِجْزِهما بِالاِْحسانِ اِحْساناً وَبِالسَّيِّئاتِ غُفْراناً، اَللّـهُمَّ اغْفِرْ لِلْمُؤْمِنينَ وَالْمُؤْمِناتِ الاَْحياءِ مِنْهُمْ وَالاَْمواِت، وَتابِعْ بَيْنَنا وَبَيْنَهُمْ بِالْخَيْراتِ اَللّـهُمَّ اغْفِرْ لِحَيِّنا وَمَيِّتِنا، وَشاهِدِنا وَغائِبِنا، ذَكَرِنا وَاُنْثانا، صَغيرِنا وَكَبيرِنا، حُرِّنا وَمَمْلُوكِنا، كَذَبَ الْعادِلُونَ بِاللهِ وَضَلُّوا ضَلالاً بَعيداً، وَخَسِرُوا خُسْراناً مُبيناً، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاخْتِمْ لي بِخَيْر، وَاكْفِني ما اَهَمَّني مِنْ اَمْرِ دُنْيايَ وَآخِرَتي وَلا تُسَلِّطْ عَلَيَّ مَنْ لا يَرْحَمُني، وَاجْعَلْ عَلَيَّ مِنْكَ واقِيَةً باقِيَةً، وَلا تَسْلُبْني صالِحَ ما اَنْعَمْتَ بِهِ عَلَيَّ، وَارْزُقْني مِنْ فَضْلِكَ رِزْقاً واسِعاً حَلالاً طَيِّباً، اَللّـهُمَّ احْرُسْني بِحَراسَتِكَ، وَاحْفَظْني بِحِفْظِكَ، وَاكْلاَني بِكِلائَتِكَ، وَارْزُقْني حَجَّ بَيْتِكَ الْحَرامِ في عامِنا هذا وَفي كُلِّ عام، وَزِيارَةَ قَبْرِ نَبِيِّكَ وَالاَْئِمَّةِ عليهم السلام، وَلا تُخْلِني يا رَبِّ مِنْ تِلْكَ الْمَشاهِدِ الشَّريفَةِ، وَالْمَواقِفِ الْكَريمَةِ، اَللّـهُمَّ تُبْ عَلَيَّ حَتّى لا اَعْصِيَكَ، وَاَلْهِمْنِيَ الْخَيْرَ وَالْعَمَلَ بِهِ، وَخَشْيَتَكَ بِاللَّيْلِ وَالنَّهارِ ما اَبْقَيْتَني يا رَبَّ الْعالَمينَ، اَللّـهُمَّ اِنّي كُلَّما قُلْتُ قَدْ تَهَيَّأتُ وَتَعَبَّأتُ وَقُمْتُ لِلصَّلاةِ بَيْنَ يَدَيْكَ وَناجَيْتُكَ اَلْقَيْتَ عَلَيَّ نُعاساً اِذا اَنَا صَلَّيْتُ، وَسَلَبْتَني مُناجاتِكَ اِذا اَنَا ناجَيْتُ، مالي كُلَّما قُلْتُ قَدْ صَلَحَتْ سَريرَتي، وَقَرُبَ مِنْ مَجالِسِ التَّوّابينَ مَجْلِسي، عَرَضَتْ لي بَلِيَّةٌ اَزالَتْ قَدَمي، وَحالَتْ بَيْني وَبَيْنَ خِدْمَتِكَ سَيِّدي لَعَلَّكَ عَنْ بابِكَ طَرَدْتَني، وَعَنْ خِدْمَتِكَ نَحَّيْتَني اَوْ لَعَلَّكَ رَاَيْتَني مُسْتَخِفّاً بِحَقِّكَ فَاَقْصَيْتَني، اَوْ لَعَلَّكَ رَاَيْتَني مُعْرِضاً عَنْكَ فَقَلَيْتَني، اَوْ لَعَلَّكَ وَجَدْتَني في مَقامِ الْكاذِبينَ فَرَفَضْتَني، اَوْ لَعَلَّكَ رَاَيْتَني غَيْرَ شاكِر لِنَعْمائِكَ فَحَرَمْتَني، اَوْ لَعَلَّكَ فَقَدْتَني مِنْ مَجالِسِ الْعُلَماءِ فَخَذَلْتَني، اَوْ لَعَلَّكَ رَاَيْتَني فِى الْغافِلينَ فَمِنْ رَحْمَتِكَ آيَسْتَني، اَوْ لَعَلَّكَ رَاَيْتَني آلفَ مَجالِسِ الْبَطّالينَ فَبَيْني وَبَيْنَهُمْ خَلَّيْتَني، اَوْ لَعَلَّكَ لَمْ تُحِبَّ اَنْ تَسْمَعَ دُعائي فَباعَدْتَني، اَوْ لَعَلَّكَ بِجُرْمي وَجَريرَتي كافَيْتَني، اَوْ لَعَلَّكَ بِقِلَّةِ حَيائي مِنْكَ جازَيْتَني، فَاِنْ عَفَوْتَ يا رَبِّ فَطالما عَفَوْتَ عَنِ الْمُذْنِبينَ قَبْلي، لاَِنَّ كَرَمَكَ اَيْ رَبِّ يَجِلُّ عَنْ مُكافاتِ الْمُقَصِّرينَ، وَاَنَا عائِذٌ بِفَضْلِكَ، هارِبٌ مِنْكَ اِلَيْكَ، مُتَنَجِّزٌ ما وَعَدْتَ مِنَ الصَّفْحِ عَمَّنْ اَحْسَنَ بِكَ ظَنّاً، اِلهي اَنْتَ اَوْسَعُ فَضْلاً، وَاَعْظَمُ حِلْماً مِنْ اَنْ تُقايِسَني بِعَمَلي اَوْ اَنْ تَسْتَزِلَّني بِخَطيئَتي، وَما اَنَا يا سَيِّدي وَما خَطَري، هَبْني بِفَضْلِكَ سَيِّدي، وَتَصَدَّقْ عَلَيَّ بِعَفْوِكَ، وَجَلِّلْني بِسَتْرِكَ، وَاعْفُ عَنْ تَوْبيخي بِكَرَمِ وَجْهِكَ، سَيِّدي اَنَا الصَّغيرُ الَّذي رَبَّيْتَهُ، وَاَنَا الْجاهِلُ الَّذي عَلَّمْتَهُ، وَاَنَا الضّالُّ الَّذي هَدَيْتَهُ، وَاَنَا الْوَضيعُ الَّذي رَفَعْتَهُ، وَاَنَا الْخائِفُ الَّذي آمَنْتَهُ، وَالْجايِعُ الَّذي اَشْبَعْتَهُ، وَالْعَطْشانُ الَّذي اَرْوَيْتَهُ، وَالْعاري الَّذي كَسَوْتَهُ، وَالْفَقيرُ الَّذي اَغْنَيْتَهُ، وَالضَّعيفُ الَّذي قَوَّيْتَهُ، وَالذَّليلُ الَّذي اَعْزَزْتَهُ، وَالسَّقيمُ الَّذي شَفَيْتَهُ، وَالسّائِلُ الَّذي اَعْطَيْتَهُ، وَالْمُذْنِبُ الَّذي سَتَرْتَهُ، وَالْخاطِئُ الَّذي اَقَلْتَهُ، وَاَنَا الْقَليلُ الَّذي كَثَّرْتَهُ، وَالْمُسْتَضْعَفُ الَّذي نَصَرْتَهُ، وَاَنَا الطَّريدُ الَّذي آوَيْتَهُ، اَنَا يا رَبِّ الَّذي لَمْ اَسْتَحْيِكَ فِى الْخَلاءِ، وَلَمْ اُراقِبْكَ فِى الْمَلاءِ، اَنَا صاحِبُ الدَّواهِي الْعُظْمى، اَنَا الَّذي عَلى سَيِّدِهِ اجْتَرى، اَنَا الَّذي عَصَيْتُ جَبّارَ السَّماءِ، اَنَا الَّذي اَعْطَيْتُ عَلى مَعاصِى الْجَليلِ الرُّشا، اَنَا الَّذي حينَ بُشِّرْتُ بِها خَرَجْتُ اِلَيْها اَسْعى، اَنَا الَّذي اَمْهَلْتَني فَما ارْعَوَيْتُ، وَسَتَرْتَ عَلَيَّ فَمَا اسْتَحْيَيْتُ، وَعَمِلْتُ بِالْمَعاصي فَتَعَدَّيْتُ، وَاَسْقَطْتَني مِنْ عَيْنِكَ فَما بالَيْتُ، فَبِحِلْمِكَ اَمْهَلْتَني وَبِسِتْرِكَ سَتَرْتَني حَتّى كَاَنَّكَ اَغْفَلْتَني، وَمِنْ عُقُوباتِ الْمَعاصي جَنَّبْتَني حَتّى كَاَنَّكَ اسْتَحْيَيْتَني، اِلهي لَمْ اَعْصِكَ حينَ عَصَيْتُكَ وَاَنَا بِرُبُوبِيَّتِكَ جاحِدٌ، وَلا بِاَمْرِكَ مُسْتَخِفٌّ، وَلا لِعُقُوبَتِكَ مُتَعَرِّضٌّ، وَلا لِوَعيدِكَ مُتَهاوِنٌ، لكِنْ خَطيئَةٌ عَرَضَتْ وَسَوَّلَتْ لي نَفْسي، وَغَلَبَني هَوايَ، وَاَعانَني عَلَيْها شِقْوَتي، وَغَرَّني سِتْرُكَ الْمُرْخى عَلَىَّ، فَقَدْ عَصَيْتُكَ وَخالَفْتُكَ بِجَهْدي، فَالاْنَ مِنْ عَذابِكَ مَنْ يَسْتَنْقِذُني، وَمِنْ اَيْدي الْخُصَماءِ غَداً مِنْ يُخَلِّصُني، وَبِحَبْلِ مَنْ اَتَّصِلُ اِنْ اَنْتَ قَطَعْتَ حَبْلَكَ عَنّي، فَواسَوْاَتا عَلى ما اَحْصى كِتابُكَ مِنْ عَمَلِيَ الَّذي لَوْلا ما اَرْجُو مِنْ كَرَمِكَ وَسَعَةِ رَحْمَتِكَ وَنَهْيِكَ اِيّايَ عَنِ الْقُنُوطِ لَقَنَطْتُ عِنْدَما اَتَذَكَّرُها، يا خَيْرَ مَنْ دَعاهُ داع، وَاَفْضَلَ مَنْ رَجاهُ راج، اَللّـهُمَّ بِذِمَّةِ الاِْسْلامِ اَتَوَسَّلُ اِلَيْكَ، وَبِحُرْمَةِ الْقُرْآنِ اَعْتَمِدُ اِلَيْكَ، وَبِحُبِّيَ النَّبِيَّ الاُْمِّيَّ الْقُرَشِيَّ الْهاشِمِيَّ الْعَرَبِيَّ التِّهامِيَّ الْمَكِّيَّ الْمَدَنِيَّ اَرْجُو الزُّلْفَةَ لَدَيْكَ، فَلا تُوحِشِ اسْتيناسَ ايماني، وَلا تَجْعَلْ ثَوابي ثَوابَ مَنْ عَبَدَ سِواكَ، فَاِنَّ قَوْماً آمَنُوا بِاَلْسِنَتِهِمْ لِيَحْقِنُوا بِهِ دِماءَهُمْ فَاَدْرَكُوا ما اَمَّلُوا، َوَإنّا آَمّنا بِكَ بِاَلْسِنَتِنا وَقُلُوبِنا لِتَعْفُوَ عَنّا، فَاَدْرِكْنا ما اَمَّلْنا، وَثَبِّتْ رَجاءَكَ في صُدُورِنا، وَلا تُزِغْ قُلُوبَنا بَعْدَ اِذْ هَدَيْتَنا، وَهَبْ لَنا مِنْ لَدُنْكَ رَحْمَةً اِنَّكَ اَنْتَ الْوَهّابُ، فَوَعِزَّتِكَ لَوِ انْتَهَرْتَني ما بَرِحْتُ مِنْ بابِكَ، وَلا كَفَفْتُ عَنْ تَمَلُّقِكَ لِما اُلْهِمَ قَلْبي مِنَ الْمَعْرِفَةِ بِكَرَمِكَ وَسَعَةِ رَحْمَتِكَ، اِلى مَنْ يَذْهَبُ الْعَبْدُ إلاّ اِلى مَوْلاهُ، وَاِلى مَنْ يَلْتَجِئُ الَْمخْلُوقُ إلاّ اِلى خالِقِهِ، اِلهي لَوْ قَرَنْتَني بِالاَْصْفادِ، وَمَنَعْتَني سَيْبَكَ مِنْ بَيْنِ الاَْشْهادِ، وَدَلَلْتَ عَلى فَضايِحي عُيُونَ الْعِبادِ، وَاَمَرْتَ بي اِلَى النّارِ، وَحُلْتَ بَيْني وَبَيْنَ الاَْبْرارِ، ما قَطَعْتُ رَجائي مِنْكَ وَما صَرَفْتُ تَأميلي لِلْعَفْوِ عَنْكَ، وَلا خَرَجَ حُبُّكَ مِنْ قَلْبي، اَنَا لا اَنْسى اَيادِيَكَ عِنْدي، وَسِتْرَكَ عَلَيَّ في دارِ الدُّنْيا، سَيِّدي اَخْرِجْ حُبَّ الدُّنْيا مِنْ قَلْبي، وَاجْمَعْ بَيْني وَبَيْنَ الْمُصْطَفى وَآلِهِ خِيَرَتِكَ مِنْ خَلْقِكَ وَخاتَمِ النَّبِيّينَ مُحَمَّد صَلَّى اللهُ عَلَيْهِ وَآلِهِ، وَانْقُلْني اِلى دَرَجَةِ الَّتوْبَةِ اِلَيْكَ، وَاَعِنّي بِالْبُكاءِ عَلى نَفْسي، فَقَدْ اَفْنَيْتُ بِالتَّسْويفِ وَالاْمالِ عُمْري، وَقَدْ نَزَلْتُ مَنْزِلَةَ الاْيِسينَ مِنْ خَيْري، فَمَنْ يَكُونُ اَسْوَأ حالاً مِنّي إنْ اَنَا نُقِلْتُ عَلى مِثْلِ حالي اِلى قَبْري، لَمْ اُمَهِّدْهُ لِرَقْدَتي، وَلَمْ اَفْرُشْهُ بِالْعَمَلِ الصّالِحِ لِضَجْعَتي، وَمالي لا اَبْكي وَلا اَدْري اِلى ما يَكُونُ مَصيري، وَاَرى نَفْسي تُخادِعُني، وَاَيّامي تُخاتِلُني، وَقَدْ خَفَقَتْ عِنْدَ رَأسي اَجْنِحَةُ الْمَوْتِ، فَمالي لا اَبْكي اَبْكي، لِخُُروجِ نَفْسي، اَبْكي لِظُلْمَةِ قَبْري، اَبْكي لِضيقِ لَحَدي، اَبْكي لِسُؤالِ مُنْكَر وَنَكير اِيّايَ، اَبْكي لِخُرُوجي مِنْ قَبْري عُرْياناً ذَليلاً حامِلاً ثِقْلي عَلى ظَهْري، اَنْظُرُ مَرَّةً عَنْ يَميني وَاُخْرى عَنْ شِمالي، اِذِ الْخَلائِقِ في شَأن غَيْرِ شَأني (لِكُلِّ امْرِئ مِنْهُمْ يَوْمَئِذ شَأنٌ يُغْنيهِ * وُجوُهٌ يَوْمَئِذ مُسْفِرَةٌ * ضاحِكَةٌ مُسْتَبْشِرَةٌ * وَوُجوُهٌ يَوْمَئِذ عَلَيْها غَبَرَةٌ * تَرْهَقُها قَتَرَةٌ) وَذِلَّةٌ، سَيِّدي عَلَيْكَ مُعَوَّلي وَمُعْتَمَدي وَرَجائي وَتَوَكُّلي، وَبِرَحْمَتِكَ تَعَلُّقي، تُصيبُ بِرَحْمَتِكَ مَنْ تَشاءُ وَتَهْدي بِكَرامَتِكَ مَنْ تُحِبُّ، فَلَكَ الْحَمْدُ عَلى ما نَقَّيْتَ مِنَ الشِّرْكِ قَلْبي، وَلَكَ الْحَمْدُ عَلى بَسْطِ لِساني، اَفَبِلِساني هذَا الْكالِّ اَشْكُرُكَ، اَمْ بِغايَةِ جُهْدي في عَمَلي اُرْضيكَ، وَما قَدْرُ لِساني يا رَبِّ في جَنْبِ شُكْرِكَ، وَما قَدْرُ عَمَلي في جَنْبِ نِعَمِكَ وَاِحْسانِكَ، اِلهي اِنَّ جُودَكَ بَسَطَ اَمَلي، وَشُكْرَكَ قَبِلَ عَمَلي، سَيِّدي اِلَيْكَ رَغْبَتي، وَاِلَيْكَ رَهْبَتي، وَاِلَيْكَ تَأميلي، وَقَدْ ساقَني اِلَيْكَ اَمَلي، وَعَلَيْكَ يا واحِدي عَكَفَتْ هِمَّتي، وَفيـما عِنْدَكَ انْبَسَطَتْ رَغْبَتي، وَلَكَ خالِصُ رَجائي وَخَوْفي، وَبِكَ أَنِسَتْ مَحَبَّتي، وَاِلَيْكَ اَلْقَيْتُ بِيَدي، وَبِحَبْلِ طاعَتِكَ مَدَدْتُ رَهْبَتي، يا مَوْلايَ بِذِكْرِكَ عاشَ قَلْبي، وَبِمُناجاتِكَ بَرَّدْتُ اَلَمَ الْخَوْفِ عَنّي، فَيا مَوْلايَ وَيا مُؤَمَّلي وَيا مُنْتَهى سُؤْلي فَرِّقْ بَيْني وَبَيْنَ ذَنْبِيَ الْمانِعِ لي مِنْ لُزُومِ طاعَتِكَ، فَاِنَّما اَسْاَلُكَ لِقَديمِ الرَّجاءِ فيكَ، وَعَظيمِ الطَّمَعِ مِنْكَ، الَّذي اَوْجَبْتَهُ عَلى نَفْسِكَ مِنَ الرَّأفَةِ وَالرَّحْمَةِ، فَالاَْمْرُ لَكَ، وَحْدَكَ لا شَريكَ لَكَ وَالْخَلْقُ كُلُّهُمْ عِيالُكَ وَفي قَبْضَتِكَ، وَكُلُّ شَيْي خاضِعٌ لَكَ تَبارَكْتَ يا رَبَّ الْعالَمينَ، اِلهي ارْحَمْني اِذَا انْقَطَعَتْ حُجَّتي وَكَلَّ عَنْ جَوابِكَ لِساني، وَطاشَ عِنْدَ سُؤالِكَ اِيّايَ لُبّي، فَيا عَظيمَ رَجائي لا تُخَيِّبْني اِذَا اشْتَدَّتْ فاقَتي، وَلا تَرُدَّني لِجَهْلي، وَلا تَمْنَعْني لِقِلَّةِ صَبْري، اَعْطِني لِفَقْري وَارْحَمْني لِضَعْفي، سَيِّدي عَلَيْكَ مُعْتَمَدي وَمُعَوَّلي وَرَجائي وَتَوَكُّلي، وَبِرَحْمَتِكَ تَعَلُّقي، وَبِفَنائِكَ اَحُطُّ رَحْلي، وَبِجُودِكَ اَقْصِدُ طَلِبَتي، وَبِكَرَمِكَ اَيْ رَبِّ اسْتَفْتِحُ دُعائي، وَلَدَيْكَ اَرْجُو فاقَتي، وَبِغِناكَ اَجْبُرُ عَيْلَتي، وَتَحْتَ ظِلِّ عَفْوِكَ قِيامي، وَاِلى جُودِكَ وَكَرَمِكَ اَرْفَعُ بَصَري، وَاِلى مَعْرُوفِكَ اُديمُ نَظَري، فَلا تُحْرِقْني بِالنّارِ وَاَنْتَ مَوْضِعُ اَمَلي، وَلا تُسْكِنِّىِ الْهاوِيَةَ فَاِنَّكَ قُرَّةُ عَيْني، يا سَيِّدي لا تُكَذِّبْ ظَنّي بِاِحْسانِكَ وَمَعْرُوفِكَ فَاِنَّكَ ثِقَتي، وَلا تَحْرِمْني ثَوابَكَ فَاِنَّكَ الْعارِفُ بِفَقْري، اِلهي اِنْ كانَ قَدْ دَنا اَجَلي وَلَمْ يُقَرِّبْني مِنْكَ عَمَلي فَقَدْ جَعَلْتُ الاْعْتِرافَ اِلَيْكَ بِذَنْبي وَسائِلَ عِلَلي، اِلهي اِنْ عَفَوْتَ فَمَنْ اَوْلى مِنْكَ بِالْعَفْوِ، وَاِنْ عَذَّبْتَ فَمَنْ اَعْدَلُ مِنْكَ فِي الْحُكْمِ، ارْحَمْ في هذِهِ الدُّنْيا غُرْبَتي، وَعِنْدَ الْمَوْتِ كُرْبَتي، وَفِي الْقَبْرِ وَحْدَتي، وَفِي اللَّحْدِ وَحْشَتي، وَاِذا نُشِرْتُ لِلْحِسابِ بَيْنَ يَدَيْكَ ذُلَّ مَوْقِفي، وَاغْفِرْ لي ما خَفِيَ عَلَى الاْدَمِيّينَ مِنْ عَمَلي، وَاَدِمْ لي ما بِهِ سَتَرْتَني، وَارْحَمْني صَريعاً عَلَى الْفِراشِ تُقَلِّبُني اَيْدي اَحِبَّتي، وَتَفَضَّلْ عَلَيَّ مَمْدُوداً عَلَى الْمُغْتَسَلِ يُقَلِّبُني صالِحُ جيرَتي، وَتَحَنَّنْ عَلَيَّ مَحْموُلاً قَدْ تَناوَلَ الاَْقْرِباءُ اَطْرافَ جَِنازَتي، وَجُدْ عَلَيَّ مَنْقُولاً قَدْ نَزَلْتُ بِكَ وَحيداً في حُفْرَتي، وَارْحَمْ في ذلِكَ الْبَيْتِ الْجَديدِ غُرْبَتي، حَتّى لا اَسْتَاْنِسَ بِغَيْرِكَ، يا سَيِّدي اِنْ وَكَلْتَني اِلى نَفْسي هَلَكْتُ، سَيِّدي فَبِمَنْ اَسْتَغيثُ اِنْ لَمْ تُقِلْني عَثَرْتي، فَاِلى مَنْ اَفْزَعُ اِنْ فَقَدْتُ عِنايَتَكَ في ضَجْعَتي، وَاِلى مَنْ اَلْتَجِئُ اِنْ لَمْ تُنَفِّسْ كُرْبَتي سَيِّدي مَنْ لي وَمَنْ يَرْحَمُني اِنْ لَمْ تَرْحَمْني، وَفَضْلَ مَنْ اُؤَمِّلُ اِنْ عَدِمْتُ فَضْلَكَ يَوْمَ فاقَتي، وَاِلى مَنِ الْفِرارُ مِنَ الذُّنُوبِ اِذَا انْقَضى اَجَلي، سَيِّدي لا تُعَذِّبْني وَاَنَا اَرْجُوكَ، اِلهي حَقِّقْ رَجائي، وَآمِنْ خَوْفي، فَاِنَّ كَثْرَةَ ذُنُوبي لا اَرْجُو فيها إلاّ عَفْوُكَ، سَيِّدي اَنَا اَسْاَلُكَ ما لا اَسْتَحِقُّ وَاَنْتَ اَهْلُ التَّقْوى وَاَهْلُ الْمَغْفِرَةِ، فَاغْفِرْ لي وَاَلْبِسْني مِنْ نَظَرِكَ ثَوْباً يُغَطّي عَلَيَّ التَّبِعاتِ، وَتَغْفِرُها لي وَلا اُطالَبُ بِها، اِنَّكَ ذُو مَنٍّ قَديم، وَصَفْح عَظيم، وَتَجاوُز كَريم، اِلهي اَنْتَ الَّذي تُفيضُ سَيْبَكَ عَلى مَنْ لا يَسْأَلُكَ وَعَلَى الْجاحِدينَ بِرُبُوبِيَّتِكَ، فَكَيْفَ سَيِّدي بِمَنْ سَأَلَكَ وَاَيْقَنَ اَنَّ الْخَلْقَ لَكَ، وَالاَْمْرَ اِلَيْكَ، تَبارَكْتَ وَتَعالَيْتَ يا رَبَّ الْعالَمينَ، سَيِّدي عَبْدُكَ بِبابِكَ أقامَتْهُ الْخَصاصَةُ بَيْنَ يَدَيْكَ يَقْرَعُ بابَ اِحْسانِكَ بِدُعائِهِ، فَلا تُعْرِضْ بِوَجْهِكَ الْكَريمِ عَنّي، وَاَقْبَلْ مِنّي ما اَقُولُ، فَقَدْ دَعَوْتُ بِهذَا الدُّعاءِ وَاَنا اَرْجُو اَنْ لا تَرُدَّني، مَعْرِفَةً مِنّي بِرَأفَتِكَ وَرَحْمَتِكَ، اِلهي اَنْتَ الَّذي لا يُحْفيكَ سائِلٌ، وَلا يَنْقُصُكَ نائِلٌ، اَنْتَ كَما تَقُولُ وَفَوْقَ ما نَقُولُ، اَللّـهُمَّ اِنّي اَسْاَلُكَ صَبْراً جَميلاً، وَفَرَجاً قَريباً، وَقَولاً صادِقاً، وَاَجْراً عَظيماً، اَسْاَلُكَ يا رَبِّ مِنَ الْخَيْرِ كُلِّهِ ما عَلِمْتُ مِنْهُ وَما لَمْ اَعْلَمْ، اَسْاَلُكَ اللّهُمَّ مِنْ خَيْرِ ما سَأَلَكَ مِنْهُ عِبادُكَ الصّالِحُونَ، يا خَيْرَ مَنْ سُئِلَ، وَاَجْوَدَ مَنْ اَعْطى، اَعْطِني سُؤْلي في نَفْسي وَاَهْلي وَوالِديَّ وَوَلَدي وَاَهْلِ حُزانَتي وَاِخْواني فيكَ، وَاَرْغِدْ عَيْشي، وَاَظْهِرْ مُرُوَّتي، وَاَصْلِحْ جَميعَ اَحْوالي، وَاجْعَلْني مِمَّنْ اَطَلْتَ عُمْرَهُ، وَحَسَّنْتَ عَمَلَهُ، وَاَتْمَمْتَ عَلَيْهِ نِعْمَتَكَ، وَرَضيتَ عَنْهُ وَاَحْيَيْتَهُ حَياةً طَيِّبَةً في اَدْوَمِ السُّرُورِ، وَاَسْبَغِ الْكَرامَةِ، وَاَتَمِّ الْعَيْشِ، اِنَّكَ تَفْعَلُ ما تَشاءُ وَلا تَفْعَلُ ما يَشاءُ غَيْرُكَ، اَللّـهُمَّ خُصَّني مِنْكَ بِخاصَّةِ ذِكْرِكَ، وَلا تَجْعَلْ شَيْئاً مِمّا اَتَقَرَّبُ بِهِ في آناءِ اللَّيْلِ وَاَطْرافِ النَّهارِ رِياءً وَلا سُمْعَةً وَلا اَشَراً وَلا بَطَراً، وَاجْعَلْني لَكَ مِنَ الْخاشِعينَ، اَللّـهُمَّ أعْطِنِى السِّعَةَ فِي الرِّزْقِ، وَالاَْمْنَ فِي الْوَطَنِ، وَقُرَّةَ الْعَيْنِ فِي الاَْهْلِ وَالْمالِ وَالْوَلَدِ، وَالْمُقامَ في نِعَمِكَ عِنْدي، وَالصِّحَّةَ فِى الْجِسْمِ، وَالْقُوَّةَ فِي الْبَدَنِ، وَالسَّلامَةَ فِى الدّينِ، وَاسْتَعْمِلْني بِطاعَتِكَ وَطاعَةِ رَسُولِكَ مُحَمَّد صَلَّى اللهُ عَلَيْهِ وَآلِهِ اَبَداً مَا اسْتَعْمَرَتْني، وَاجْعَلْني مِنْ اَوْفَرِ عِبادِكَ عِنْدَكَ نَصيباً في كُلِّ خَيْر اَنْزَلْتَهُ وَتُنْزِلُهُ في شَهْرِ رَمَضانَ في لَيْلَةِ الْقَدْرِ، وَما اَنْتَ مُنْزِلُهُ في كُلِّ سَنَة مِنْ رَحْمَة تَنْشُرُها، وَعافِيَة تُلْبِسُها، وَبَلِيَّة تَدْفَعُها، وَحَسَنات تَتَقَبَّلُها، وَسَيِّئات تَتَجاوَزُ عَنْها، وَارْزُقْني حَجَّ بَيْتِكَ الْحَرامِ في عامِنا هذا وَفي كُلِّ عام، وَارْزُقْني رِزْقاً واسِعاً مِنْ فَضْلِكَ الْواسِعِ، وَاصْرِفْ عَنّي يا سَيِّدي الاَْسْواءَ، وَاقْضِ عَنِّيَ الدَّيْنَ وَالظُّلاماتِ، حَتّى لا اَتَاَذّى بِشَي مِنْهُ، وَخُذْ عَنّي بِاَسْماعِ وَاَبْصارِ اَعْدائي وَحُسّادي وَالْباغينَ عَلَيَّ، وَانْصُرْني عَلَيْهِمْ، وَاَقِرَّ عَيْني وَفَرِّحْ قَلْبي، وَاجْعَلْ لي مِنْ هَمّي وَكَرْبي فَرَجاً وَمَخْرَجاً، وَاجْعَلْ مَنْ اَرادَني بِسُوء مِنْ جَميعِ خَلْقِكَ تَحْتَ قَدَمَيَّ، وَاكْفِني شَرَّ الشَّيْطانِ، وَشَرَّ السُّلْطانِ، وَسَيِّئاتِ عَمَلي، وَطَهِّرْني مِنَ الذُّنُوبِ كُلِّها، وَاَجِرْني مِنَ النّارِ بِعَفْوِكَ، وَاَدْخِلْنِى الْجَنَّةَ بِرَحْمَتِكَ، وَزَوِّجْني مِنَ الْحُورِ الْعينِ بِفَضْلِكَ، وَاَلْحِقْني بِاَوْلِيائِكَ الصّالِحينَ مُحَمَّد وَآلِهِ الاَْبْرارِ الطَّيِّبينَ الطّاهِرينَ الاَْخْيارِ صَلَواتُكَ عَلَيْهِمْ وَعَلى اَجْسادِهِمْ وَاَرْواحِهِمْ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ."},{"type":"Text","content":"اِلهي وَسَيِّدي وَعِزَّتِكَ وَجَلالِكَ لَئِنْ طالَبَتْني بِذُنُوبي لاَُطالِبَنَّكَ بِعَفْوِكَ، وَلَئِنْ طالَبَتْني بِلُؤْمي لاَُطالِبَنَّكَ بِكَرَمِكَ، وَلَئِنْ اَدْخَلْتَنِى النّارَ لاَُخْبِرَنَّ اَهْلَ النّارِ بِحُبّي لَكَ، اِلهي وَسَيِّدي اِنْ كُنْتَ لا تَغْفِرُ إلاّ لاَِوْلِيائِكَ وَاَهْلِ طاعَتِكَ فَاِلى مَنْ يَفْزَعُ الْمُذْنِبُونَ، وَاِنْ كُنْتَ لا تُكْرِمُ إلاّ اَهْلَ الْوَفاءِ بِكَ فَبِمَنْ يَسْتَغيثُ الْمُسْيؤُنَ اِلهي اِنْ اَدْخَلْتَنِى النّارَ فَفي ذلِكَ سُرُورُ عَدُوِّكَ، وَاِنْ اَدْخَلْتَنِى الْجَنَّةَ فَفي ذلِكَ سُرُورُ نَبِيِّكَ، وَاَنَا وَاللهِ اَعْلَمُ اَنَّ سُرُورَ نَبِيِّكَ اَحَبُّ اِلَيْكَ مِنْ سُرُورِ عَدُوِّكَ، اَللّـهُمَّ اِنّي اَسْاَلُكَ اَنْ تَمْلاََ قَلْبي حُبّاً لَكَ، وَخَشْيَةً مِنْكَ، وَتَصْديقاً بِكِتابِكَ، وَايماناً بِكَ، وَفَرَقاً مِنْكَ، وَشَوْقاً اِلَيْكَ، يا ذَا الْجَلالِ وَالاِْكْرامِ حَبِّبْ اِلَىَّ لِقاءِكَ وَاَحْبِبْ لِقائي، وَاجْعَلْ لي في لِقائِكَ الرّاحَةَ وَالْفَرَجَ وَالْكَرامَةَ، اَللّـهُمَّ اَلْحِقْني بِصالِحِ مِنْ مَضى، وَاجْعَلْني مِنْ صالِحِ مَنْ بَقي وَخُذْ بي سَبيلَ الصّالِحينَ، وَاَعِنّي عَلى نَفْسي بِما تُعينُ بِهِ الصّالِحينَ عَلى اَنْفُسِهِمْ، وَاخْتِمْ عَمَلي بِاَحْسَنِهِ، وَاجْعَلْ ثَوابي مِنْهُ الْجَنَّةَ بِرَحْمَتِكَ، وَاَعِنّي عَلى صالِحِ ما اَعْطَيْتَني، وَثَبِّتْني يا رَبِّ، وَلا تَرُدَّني في سُوء اسْتَنْقَذْتَني مِنْهُ يا رَبِّ الْعالَمينَ، اَللّـهُمَّ اِنّي اَسْاَلُكَ ايماناً لا اَجَلَ لَهُ دُونَ لِقائِكَ، اَحْيِني ما اَحْيَيْتَني عَلَيْهِ وَتَوَفَّني اِذا تَوَفَّيْتَني عَلَيْهِ، وَابْعَثْني اِذا بَعَثْتَني عَلَيْهِ وَاَبْرِىءْ قَلْبي مِنَ الرِّياءِ وَالشَّكِّ وَالسُّمْعَةِ في دينِكَ، حَتّى يَكُونَ عَمَلي خالِصاً لَكَ، اَللّـهُمَّ اَعْطِني بَصيرَةً في دينِكَ، وَفَهْماً في حُكْمِكَ، وَفِقْهاً في عِلْمِكَ، وَكِفْلَيْنِ مِنْ رَحْمَتِكَ، وَوَرَعاً يَحْجُزُني عَنْ مَعاصيكَ، وَبَيِّضْ وَجْهي بِنُورِكَ، وَاجْعَلْ رَغْبَتي فيـما عِنْدَكَ، وَتَوَفَّني في سَبيلِكَ، وَعَلى مِلَّةَ رَسُولِكَ صَلَّى اللهُ عَلَيْهِ وَآلِهِ، اَللّـهُمَّ اِنّي اَعُوذُ بِكَ مِنَ الْكَسَلِ وَالْفَشَلِ وَالْهَمِّ وَالْجُبْنِ وَالْبُخْلِ وَالْغَفْلَةِ وَالْقَسْوَةِ وَالْمَسْكَنَةِ وَالْفَقْرِ وَالْفاقَةِ وَكُلِّ بَلِيَّة، وَالْفَواحِشِ ما ظَهَرَ مِنْها وَما بَطَنَ، وَاَعُوذُ بِكَ مِنْ نَفْس لا تَقْنَعُ، وَبَطْن لا يَشْبَعُ، وَقَلْب لا يَخْشَعُ، وَدُعاء لا يُسْمَعُ وَعَمَل لا يَنْفَعُ، وَاَعُوذُ بِكَ يا رَبِّ عَلى نَفْسي وَديني وَمالي وَعَلى جَميعِ ما رَزَقْتَني مِنَ الشَّيْطانِ الرَّجيمَ اِنَّكَ اَنْتَ السَّميعُ الْعَليمُ، اَللّـهُمَّ اِنَّهُ لا يُجيرُني مِنْكَ اَحَدٌ وَلا اَجِدُ مِنْ دُونِكَ مُلْتَحَداً، فَلا تَجْعَلْ نَفْسي في شَي مِنْ عَذابِكَ، وَلا تَرُدَّني بِهَلَكَة وَلا تَرُدَّني بِعَذاب اَليم، اَللّـهُمَّ تَقَبَّلْ مِنّي وَاَعْلِ ذِكْري، وَارْفَعْ دَرَجَتي، وَحُطَّ وِزْري، وَلا تَذْكُرْني بِخَطيئَتي، وَاجْعَلْ ثَوابَ مَجْلِسي وَثَوابَ مَنْطِقي وَثَوابَ دُعائي رِضاكَ وَالْجَنَّةَ، وَاَعْطِني يا رَبِّ جَميعَ ما سَاَلْتُكَ، وَزِدْني مِنْ فَضْلِكَ، اِنّي اِلَيْكَ راغِبٌ يا رَبَّ الْعالَمينَ، اَللّـهُمَّ اِنَّكَ اَنْزَلْتَ في كِتابِكَ اَنْ نَعْفُوَ عَمَّنْ ظَلَمْنا، وَقَدْ ظَلَمَنا اَنْفُسَنا فَاعْفُ عَنّا فَاِنَّكَ اَوْلى بِذلِكَ مِنّا، وَاَمَرْتَنا اَنْ لا نَرُدَّ سائِلاً عَنْ اَبْوابِنا وَقَدْ جِئْتُكَ سائِلاً فَلا تَرُدَّني إلاّ بِقَضاءِ حاجَتي، وَاَمَرْتَنا بِالاِْحْسانِ اِلى ما مَلَكَتْ اَيْمانُنا وَنَحْنُ اَرِقّاؤكَ فَاَعْتِقْ رِقابَنا مِنَ النّارِ، يا مَفْزَعي عِنْدَ كُرْبَتي، وَيا غَوْثي عِنْدَ شِدَّتي، اِلَيْكَ فَزِعْتُ وَبِكَ اسْتَغَثْتُ وَلُذْتُ، لا اَلُوذُ بِسِواكَ وَلا اَطْلُبُ الْفَرَجَ إلاّ مِنْكَ، فَاَغِثْني وَفَرِّجْ عَنّيك يا مَنْ يَفُكُّ الاَْسيرَ، وَيَعْفُو عَنِ الْكَثيرِ اِقْبَلْ مِنِّى الْيَسيرَ وَاعْفُ عَنِّى الْكَثيرَ اِنَّكَ اَنْتَ الرَّحيمُ الْغَفُورُ، اَللّـهُمَّ اِنّي اَسْاَلُكَ ايماناً تُباشِرُ بِهِ قَلْبي وَيَقيناً حَتّى اَعْلَمُ اَنَّهُ لَنْ يُصيبَني ما كَتَبْتَ لي وَرَضِّني مِنَ الْعَيْشِ بِما قَسَمْتَ لي يا اَرْحَمَ الرّاحِمينَ ."}],"preview":"الرّابع : في المصباح عن أبي حمزة الثّمالي (رحمه الله) قال : كان زين العابدين (عليه السلام) يصلّي عامّة اللّيل في شهر رمضان فاذا كان في السّحر دعا بهذا الدّعاء :","hasTranslate":false},{"id":"mf_ar_124","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القِسمُ الثّالثُ : في أعمال أسحار شهر رمضان المبارك","title":"الخامس : قال الشّيخ أيضاً تدعو في السّحر بهذا الدّعاء :","blocks":[{"type":"Text","content":"يا عُدَّتي في كُرْبَتي، وَيا صاحِبي في شِدَّتي، وَيا وَلِيّي في نِعْمَتي، وَيا غايَتي في رَغْبَتـي، اَنْتَ السّاتِرُ عَوْرَتي، وَالْمُؤْمِنُ رَوْعَتي، وَالْمُقيلُ عَثْرَتي، فَاغْفِرْ لي خَطيئَتي، اَللّـهُمَّ اِنّي اَسْاَلُكَ خُشُوعَ الايمانِ قَبْلَ خُشُوعِ الذّلِّ فِي النّارِ، يا واحِدُ يا اَحَدُ يا صَمَدُ يا مَنْ لَمْ يَلِدْ وَلَمْ يُولَدْ وَلَمْ يَكُنْ لَهُ كُفواً اَحَدٌ، يا مَنْ يُعْطي مَنْ سَأَلَهُ تَحَنُّناً مِنْهُ وَرَحْمَةً، وَيَبْتَدِئُ بِالْخَيْرِ مَنْ لَمْ يَسْأَلْهُ تَفَضُّلاً مِنْهُ وَكَرَماً، بِكَرَمِكَ الّدائِمِ صَلِّ عَلى مُحَمَّد وَآلِِ مُحَمَّد، وَهَبْ لي رَحْمَةً واسِعَةً جامِعَةً اَبْلُغُ بِها خَيْرَ الدُّنْيا وَالاَْخِرَةِ، اَللّـهُمَّ اِنّي اَسْتَغْفِرُكَ لِما تُبْتُ اِلَيْكَ مِنْهُ ثُمَّ عُدْتُ فيهِ، وَاَسْتَغْفِرُكَ لِكُلِّ خَيْر اَرَدْتُ بِهِ وَجْهَكَ فَخالَطَني فيهِ ما لَيْسَ لَكَ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِِ مُحَمَّد وَاعْفُ عَنْ ظُلْمي وَجُرْمي بِحِلْمِكَ وَجُودِكَ يا كَريمُ، يا مَنْ لا يَخيبُ سائِلُهُ، وَلا يَنْفَدُ نائِلُهُ، يا مَنْ عَلا فَلا شَيْءَ فَوْقَهُ، وَدَنا فَلا شَيءَ دُونَهُ، صَلِّ عَلى مُحَمَّد وآلِ مُحَمَّد وَارْحَمْني، يا فالِقَ الْبَحْرِ لِمُوسى، اللَّيلَةَ اللَّيْلَةَ اللَّيْلَةَ، السّاعَةَ السّاعَةَ السّاعَةَ، اَللّـهُمَّ طَهِّرْ قَلْبي مِنَ النِّفاقِ، وَعَمَلي مِنَ الرِّياءِ، وَلِساني مِنَ الْكَذِبِ، وَعَيْني مِنَ الْخِيانَةِ، فَاِنَّكَ تَعْلَمُ خائِنَةَ الاَْعْيُنِ وَما تُخْفِي الصُّدورِ يا رَبِّ هذا مَقامُ الْعائِذِ بِكَ مِنَ النّارِ، هذا مَقامُ الْمُسْتَجيرِ بِكَ مِنَ النَّارِ، هذا مَقامُ الْمُسْتَغيثِ بِكَ مِنَ النّارِ، هذا مَقامُ الْهارِبِ اِلَيْكَ مِنَ النّارِ، هذا مَقامُ مَنْ يَبُوءُ لَكَ بِخَطيئَتِهِ وَيَعْتَرِفُ بِذَنْبِهِ وَيَتُوبُ اِلى رَبِّهِ، هذا مَقامُ الْبائِسِ الْفَقيرِ، هذا مَقامُ الْخائِفِ الْمُسْتَجيرِ، هذا مَقامُ الَْمحْزُونِ الْمَكْرُوبِ، هذا مَقامُ الْمَغْمُومِ الْمَهْمُومِ، هذا مَقامُ الْغَريبِ الْغَريقِ، هذا مَقامُ الْمُسْتَوْحِشِ الْفَرِقِ، هذا مَقامُ مَنْ لا يَجِدُ لِذَنْبِهِ غافِراً غَيْرَكَ، وَلا لِضَعْفِهِ مُقَوِّياً اِلاّا اَنْتَ، وَلا لِهَمِّهِ مُفَرِّجاً سِواكَ، يا اللهُ يا كَريمُ، لا تُحْرِقْ وَجْهي بِالنّارِ بَعْدَ سُجُودي لَكَ وَتَعْفيري بِغَيْرِ مَنٍّ مِنّي عَلَيْكَ، بَلْ لَكَ الْحَمْدُ وَالْمَنُّ وَالتَّفَضُّلُ عَليَّ ارْحَمْ اَيْ رَبِّ اَيْ رَبِّ (حتّى ينقطع النفس) ضَعْفي وَقِلَّةَ حيلَتي وَرِقَّةَ جِلْدي وَتَبَدُّدَ اَوْصالي وَتَناثُرَ لَحْمي وَجِسْمي وَجَسَدي، وَوَحْدَتي وَوَحْشَتي في قَبْري، وَجَزَعي مِنْ صَغيرِ الْبَلاءِ، اَسْاَلُكَ يا رَبِّ قُرَّةَ الْعَيْنِ، وَالاِغْتِباطَ يَومَ الْحَسْرَةِ وَالنَّدامَةِ، بَيِّضْ وَجْهِي يا رَبِّ يَوْمَ تَسْوَدُّ الْوُجُوهُ، آمِنّي مِنَ الْفَزَعِ الاَْكْبَرِ، اَسْاَلُكَ الْبُشْرى يَوْمَ تُقَلَّبُ الْقُلُوبُ وَالاَْبْصارُ، وَالْبُشْرى عِنْدَ فِراقِ الدُّنْيا، اَلْحَمْدُ للهِ الَّذي اَرْجُوهُ عَوْناً في حَياتي، وَاُعِدُّهُ ذُخْراً لِيَوْمِ فاقَتي، اَلْحَمْدُ لله الَّذي اَدْعُوهُ وَلا اَدْعُو غَيْرَهُ وَلوْ دَعَوْتُ غَيْرَهُ لَخَيَّبَ دُعائي، اَلْحَمْدُ للهِ الَّذي اَرْجُوهُ وَلا اَرْجُو غَيْرَهُ وَلَوْ رَجَوْتُ غَيْرَهُ لاََخْلَفَ رَجائي، اَلْحَمْدُ للهِ الْمُنْعِمِ الُْمحْسِنِ الُمجْمِلِ الْمُفْضِلِ ذِي الْجَلالِ والاِكْرامِ وَلِيُّ كُلِّ نِعْمَة، وَصاحِبُ كُلِّ حَسَنَة، وَمُنْتَهى كُلِّ رَغْبَة، وَقاضي كُلِّ حاجَة، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَارْزُقْني الْيَقينَ وُحسْنَ الظَّنِّ بِكَ، وَاَثْبِتْ رَجاءِكَ في قَلْبي، وَاقْطَعْ رَجائي عَمَّنْ سِواكَ، حَتّى لا اَرْجُو غَيْرَكَ وَلا اَثِقَ اِلاّ بِكَ يا لَطيفاً لِما تَشاءُ اْلُطُفْ لي في جَميعِ اَحْوالي بِما تُحِبُّ وَتَرْضى، يا رَبِّ اِنّي ضَعيفٌ عَلَى النّارِ فَلا تُعَذِّبْني بالنّارِ، يا رَبِّ ارْحَمْ دُعائي وَتَضرُّعي وَخَوْفي وَذُلّي وَمْسكَنَتي وَتَعْويذي وَتَلْويِذي، يا رَبِّ اِنّي ضَعيفٌ عَنْ طَلَبِ الدُّنْيا وَاَنْتَ واسِعٌ كَريمٌ، اَسْأَلُكُ يا رَبِّ بِقُوَّتِكَ عَلى ذلِكَ وَقُدْرَتِكَ عَلَيْهِ وَغِناكَ عَنْهُ وَحاجَتي اِلَيْهِ اَنْ تَرْزُقَني في عامي هذا وَشَهْري هذا وَيَوْمي هذا وَساعَتي هذِهِ رِزْقاً تُغْنيني بِهِ عَنْ تَكَلُّفُ ما في اَيْدي النّاسِ مِنْ رِزْقِكَ الْحَلالِ الطَّيِّبِ، اَيْ رَبِّ مِنْكَ اَطْلُبُ وَاِلَيْكَ اَرْغَبُ وِايّاكَ اَرْجُو وَاَنْتَ اَهْل ذلِكَ، لا اَرْجُو غَيْرَكَ وَلا اَثِقُ إلاّ بِكَ يا اَرْحَمَ الرّاحِمينَ، اَيْ رَبِّ ظَلَمْتُ نَفْسي فَاْغفِرْ لي وَارْحَمْني وَعافِني، يا سامِعَ كُلِّ صَوْت، وَيا جامِعَ كُلِّ فَوْت، وَيا بارِئَ النُّفُوسِ بَعْدَ الْمَوْتِ، يا مَنْ لا تَغْشاهُ الظُّلُماتُ، وَلا تَشْتَبِهُ عَلَيْهِ الاَْصْواتُ، وَلا يَشْغَلُهُ شَيءٌ عَنْ شَيء، اَعْطِ مُحَمَّداً صَلَّى اللهُ عَلَيْهِ وآلِهِ اَفْضَلَ ما سَأَلَكَ وَاَفْضَلَ ما سُئِلْتَ لَهُ، وَاَفْضَلَ ما اَنْتَ مَسْؤُولٌ لَهُ اِلى يَوْمِ الْقِيامَةِ، وَهَبْ لِيَ الْعافِيَةَ حَتّى تُهَنِّئَني الْمَعيشَةَ، وَاخْتِمْ لي بِخَيْر حَتّى لا تَضُرَّنيِ الذُّنُوبُ، اَللّـهُمَّ رَضِّني بِما قَسَمْتَ لي حَتّى لا اَسْأَلَ اَحَداً شَيْئاً، اَللّـهُمَّ صَلّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَافْتَحْ لي خَزائِنَ رَحْمَتِكَ، وَارْحَمْني رَحْمَةً لا تُعَذِّبُني بَعْدَها اَبَداً فِي الدُّنْيا وَالاخِرَةِ، وَارْزُقْني مِنْ فَضْلِكَ الْواسِعِ رِزْقاً حَلالاً طَيِّباً لا تُفْقِرُني اِلى اَحَد بَعْدَهُ سِواكَ، تَزيدُني بِذلِكَ شُكْراً وَاِلَيْكَ فاقَةً وَفَقْراً، وَبِكَ عَمَّنْ سِواكَ غِناً وَتَعفُّفاً، يا مُحْسِنُ يا مُجْمِلُ، يا مُنْعِمُ يا مُفْضِلُ، يا مَليكُ يا مُقْتَدِرُ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاكْفِني الْمُهِمَّ كُلَّهُ، وَاقْضِ لي بِالْحُسْنى، وَبارِكْ لي في جَميعِ اُمُوري، وَاقْضِ لي جَميعَ حَوائِجي، اَللّـهُمَّ يَسِّرْ لي ما اَخافُ تَعْسيرَهُ، فَاِنَّ تَيْسيرَ ما اَخافُ تَعْسيرَهُ عَلَيْكَ سَهْلٌ يَسيرٌ، وَسَهِّلْ لي ما اَخافُ حُزونَتَهُ، وَنَفِّسْ عَنّي ما اَخافُ ضيقَهُ، وَكُفَّ عَنّي ما اَخافُ هَمَّهُ، وَاصْرِفْ عَنّي ما اَخافُ بَلِيَّتَهُ، يا اَرْحَمَ الرَّاحِمينَ، اَللّـهُمَّ امْلاَ قَلْبي حُبّاً لَكَ، وخَشْيَةً مِنْكَ، وَتَصْديقاً لَكَ، وَايماناً بِكَ، وفَرَقاً مِنْكَ، وَشَوْقاً اِلَيْكَ يا ذَا الْجَلالِ وَالاِكْرامِ، اَللّـهُمَّ اِنَّ لَكَ حُقُوقاً فَتَصَدَّقْ بِها عَلَيَّ، وَلِلنّاسِ قِبَلي تَبِعاتٌ فَتَحمَّلْها عَنّي، وَقَدْ اَوْجَبْتَ لِكُلِّ ضَيْف قِرىً، وَاَنَا ضَيْفُكَ، فَاْجعَلْ قِرايَ اللَّيْلَةَ الْجَنَّةَ، يا وَهّابَ الْجَنَّةِ يا وَهّابَ الْمَغْفِرَةِ، وَلا حَوْلَ وَلا قُوَّةَ إلاّ بِكَ ."},{"type":"Text","content":"السّادس : تدعو بدعاء ادريس الذي رواه الشّيخ والسّيد فليطلب من كتاب المصباح أو كتاب الاقبال ."}],"preview":"يا عُدَّتي في كُرْبَتي، وَيا صاحِبي في شِدَّتي، وَيا وَلِيّي في نِعْمَتي، وَيا غايَتي في رَغْبَتـي، اَنْتَ السّاتِرُ عَوْرَتي، وَالْمُؤْمِنُ رَوْعَتي، وَالْمُقيلُ عَثْرَتي، فَاغْفِ","hasTranslate":false},{"id":"mf_ar_125","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القِسمُ الثّالثُ : في أعمال أسحار شهر رمضان المبارك","title":"السّابع : أن تدعو بهذا الدعاء الذي هو أخصر أدعية السحّر وهو مروي في الاقبال :","blocks":[{"type":"Text","content":"يا مَفْزَعي عِنْدَ كُرْبَتي، وَيا غَوْثي عِنْدَ شِدَّتي اِلَيْكَ فَزِعْتُ، وَبِكَ اسْتَغَثْتُ، وَبِكَ لُذْتُ لا اَلُوذُ بِسِواكَ وَلا اَطْلُبُ الْفَرَجَ إلاّ مِنْكَ، فَاَغِثْني وَفَرِّجْ عَنّي، يا مَنْ يَقْبَلُ الْيَسيرَ، وَيَعْفُو عَنِ الْكَثيرِ، اِقْبَلْ مِنِّي الْيَسيرَ وَاعْفُ عَنِّي الْكَثيرَ، اِنَّكَ اَنْتَ الْغَفُورُ الرَّحيمُ، اَللّـهُمَّ اِنّي اَسْاَلُكَ ايماناً تُباشِرُبِهِ قَلْبي، وَيَقيناً حَتّى اَعْلَمَ اَنَّهُ لَنْ يُصيَبني إلاّ ما كَتَبْتَ لي، وَرَضِّني مِنَ الْعَيْشِ بِما قَسَمْتَ لي يا اَرْحَمَ الرّاحِمينَ، يا عُدَّتي في كُرْبَتي، وَيا صاحِبي في شِدَّتي، وَيا وَليّي في نِعْمَتي، وَيا غايَتي في رَغْبَتي، اَنْتَ السّاتِرُ عَوْرَتي، وَالاْمِنُ رَوْعَتي، وَالْمُقيلُ عَثْرَتي، فَاغْفِرْ لي خَطيئَتي يا اَرْحَمَ الرّاحِمينَ ."},{"type":"Text","content":"الثّامن : وتسبّح أيضاً بهذه التّسبيحات المرويّة في الاقبال :"},{"type":"Text","content":"سُبْحـانَ مَنْ يَعْلَمُ جَوارِحَ الْقُلُوبِ، سُبْحـانَ مَنْ يُحْصي عَدَدَ الذُّنُوبِ، سُبْحـانَ مَنْ لا يَخْفى عَلَيْهِ خافِيَةٌ فِي السَّماواتِ وَالاَْرَضينَ، سُبْحـانَ الرَّبِّ الْوَدُودِ، سُبْحـانَ الْفَرْدِ الْوِتْرِ، سُبْحـانَ الْعَظيمِ الاَْعْظَمِ، سُبْحـانَ مَنْ لا يَعْتَدي عَلى اَهْلِ مَمْلَكَتِهِ، سُبْحـانَ مَنْ لا يُؤاخِذُ اَهْلَ الاَْرْضِ بِاَلْوانِ الْعَذابِ، سُبْحـانَ الْحَنّانِ الْمَنّانِ، سُبْحـانَ الرَّؤُوفِ الرَّحيمِ، سُبْحـانَ الْجَبّارِ الْجَوادِ، سُبْحـانَ الْكَريمِ الْحَليمِ، سُبْحـانَ الْبَصيرِ الْعَليمِ، سُبْحـانَ الْبَصيرِ الْواسِعِ، سُبْحـانَ اللهِ عَلى اِقْبالِ النَّهارِ، سُبْحـانَ اللهِ عَلى اِدْبارِ النَّهارِ، سُبْحـانَ اللهِ عَلى اِدْبارِ اللَّيْلِ واِقْبالِ النَّهارِ، وَلَهُ الْحَمْدُ وَالَْمجْدُ وَالْعَظَمةُ وَالْكِبرِياءُ مَعَ كُلِّ نَفَس، وَكُلِّ طَرْفَةِ عَيْن، وَكُلِّ لَْمحَة سَبَقَ في عِلْمِهِ سُبْحانَكَ، مِلاَ ما اَحْصى كِتابُكَ، سُبْحانَكَ زِنَةَ عَرْشِكَ، سُبْحانَكَ سُبْحانَكَ سُبْحانَكَ ."},{"type":"AboutText","content":"واعلم انّ نيّة الصّوم على ما ذكره العلماء يحسن أن تكون عقيب ما تسحر، ومن الجائز أن ينوي الصّوم في أي وقت كان من اللّيل ويكفي في النيّة انّه يعلم ويقصد أن يصوم نهار الغد لله تعالى، وأن يمسك فيه عن المفطّرات وينبغي أن لا يدع صلاة اللّيل في الاسحار وأن لا يترك التهجّد فيها ."},{"type":"Text","content":"وهي اُمور : أوّلها : أن يدعو كلّ يوم بهذا الدّعاء الذي رواه الشّيخ ، كما رواه السّيد :"},{"type":"Text","content":"اَللّـهُمَّ هذا شَهْرُ رَمَضانَ الَّذي اَنْزَلْتَ فيهِ الْقُرآنَ هُدىً لِلنَّاسِ وَبَيِّنات مِنَ الْهُدى وَالْفْرقانِ، وهذا شَهْرُ الصِّيامِ، وَهذا شَهْرُ الْقِيامِ، وَهذا شَهْرُ الاِنابَةِ، وَهذا شَهْرُ التَّوْبَةِ، وَهذا شَهْرُ الْمَغْفِرَةِ وَالرَّحْمَةِ، وَهذا شَهْرُ الْعِتْقِ مِنَ النّارِ وَالْفَوْزِ بِالْجَنَّةِ، وَهذا شَهْرٌ فيهِ لَيْلَةُ الْقَدْرِ الَّتي هِيَ خَيْرٌ مِنْ اَلْفِ شَهْر، اَللّـهُمَّ فَصَلِّ عَلى مُحَمَّد وآلِ مُحَمَّد، وَاَعِّني عَلى صِيامِهِ وَقِيامِهِ، وَسلِّمْهُ لي وَسَلِّمْني فيهِ، وَاَعِنّي عَلَيْهِ بِاَفْضَلِ عَوْنِكَ، وَوَفِّقْني فيهِ لِطاعَتِكَ وَطاعَةِ رَسُولِكَ واَوْليائِكَ صَلَّى اللهُ عَلَيْهِمْ، وَفَرِّغْني فيهِ لِعِبادَتِكَ وَدُعائِكَ وَتِلاوَةِ كِتابِكَ، وَاَعْظِمْ لي فيهِ الْبَرَكَةَ، وَاَحْسِنْ لي فيهِ الْعافِيَةَ، وَاَصِحَّ فيهِ بَدَني، وَاَوْسِعْ لي فيهِ رِزْقي، وَاكْفِني فيهِ ما أهَمَّي وَاسْتَجِبْ فيهِ دُعائي، وَبَلِّغْني رَجائي، اَللّـهُمَّ صَلّ عَلى مُحَمَّد وَآلِ مُحَمَّد، واَذْهِبْ عَنّي فيهِ النُّعاسَ وَالْكَسَلَ وَالسَّامَةَ وَالْفَتْرَةَ وَالْقَسْوَةَ وَالْغَفْلَةَ وَالْغِرَّةَ، وَجَنِّبْني فيهِ الْعِلَلَ وَالاَسْقامَ وَالْهُمُومَ وَالاَحْزانَ وَالاَعْراضَ وَالاَمْراضَ وَالْخَطايا وَالذُّنُوبَ، وَاصْرِفْ عَنّي فيهِ السُّوءَ وَالْفَحشاءَ وَالْجَهْدَ وَالْبَلاء وَالتَّعَبَ وَالْعِناءَ اِنَّكَ سَميعُ الدُّعاءِ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَعِذْني فيهِ مِنَ الشَّيْطانِ الرَّجيمِ وَهَمْزِهِ وَلَمْزِهِ وَنُفْثِهِ وَنُفْخِهِ وَوَسْوَسَتِهِ وَتَثْبيطِهِ وَبَطْشِه وَكَيْدِهِ وَمَكْرِهِ وَحبائِلِهِ وَخُدَعِهِ وَاَمانِيِّهِ وَغُرُورِهِ وَفِتْنَتِهِ وَشَرَكِهِ وَاَحْزَابِهِ وَاَتْباعِهِ واَشْياعِهِ وَاَوْلِيائِهِ وَشُرَكائِهِ وَجَميعِ مَكائِدِهِ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَارْزُقْنا قِيامَهُ وَصِيامَهُ وَبُلُوغَ الاَمَلِ فيهِ وَفي قِيامِهِ، وَاسْتِكْمالَ ما يُرْضيكَ عَنّي صَبْراً وَاْحتِساباً وَايماناً وَيَقيناً، ثُمَّ تَقَبَّلْ ذلِكَ مِنّي بِالاَضْعافِ الْكَثيرَةِ، والاَجْرِ الْعَظيمِ يا رَبَّ الْعالَمينَ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَارْزُقْني الْحَجَّ وَالْعُمْرَةَ والجدّ وَالاجْتِهادَ وَالْقُوَّةَ والنَّشاطَ والاِنابَةَ والتَّوْبَةَ ولِلتوفيْق والْقُرْبَةَ والْخَيْرَ الْمَقْبُولَ وَالرَّغْبَةَ والرَّهْبَةَ وَالتَّضَرُّعَ والْخُشُوعَ وَالرِّقَّةَ، والنِّيَّةَ الصّادِقَهَ، وَصِدْقَ اللِّسانِ، وَالْوَجَلَ مِنْكَ، وَالرَّجاءَ لَكَ، وَالتَّوَكُّلَ عَلَيْكَ، وَالثِّقَةَ بِكَ، وَالْوَرَعَ عَنْ مَحارِمِكَ، مَعَ صالِحِ الْقَوْلِ، وَمَقْبُولِ السَّعْي، وَمَرْفُوعِ الْعَمَلِ، وَمُسْتَجابِ الدَّعْوَةِ، وَلا تَحُلْ بَيْني وَبَيْنَ شيء مِنْ ذلِكَ بَعَرَض وَلا مَرَض وَلا هَمٍّ وَلا غَمٍّ وَلا سُقْم وَلا غَفْلَة وَلانِسْيان، بَلْ بِالتَّعاهُدِ والتَّحَفُّظِ لَكَ وَفيكَ، وَالرِّعايَةِ لِحَقِّكَ، وَالْوَفاءِ بَعَهْدِكَ وَوَعْدِكَ بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ، اَللّـهُمَّ صَلّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاقْسِمْ لي فيهِ اَفْضَلَ ما تَقْسِمُهُ لِعبادِكَ الصّالِحينَ، وَاَعْطِني فيهِ اَفْضَلَ ما تُعْطي اَوْلِياءَكَ الْمُقَرَّبينَ، مِنَ الرَّحْمَةِ وَالْمَغْفِرَةِ والتَّحَنُّنِ وَالاِجابَةِ وَالْعَفْوِ وَالْمَغْفِرَةِ الدّائِمَةِ، وَالْعافِيَةِ وَالْمُعافاةِ، وَالْعِتْقِ مِنَ النّارِ، وَالْفَوْزِ بِالْجَنَّةِ، وَخَيْرِ الدُّنْيا وَالاْخِرَةِ، اَللّـهُمَّ صَلّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاجْعَلْ دُعائي فيهِ اِلَيْكَ واصِلاً، وَرَحْمَتَكَ وَخَيْرَكَ اِلَىَّ فيه نازِلاً، وَعَمَلي فيهِ مَقْبُولاً، وَسَعْيي فيهِ مَشْكُوراً، وَذَنْبي فيهِ مَغْفُوراً، حَتّى يَكُونَ نَصيبي فيهِ الاَكْثَرَ، وَحَظّي فيهِ الاَوْفَرَ، اَللّـهُمَّ صَلّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَوَفِّقْني فيهِ لِلَيْلَةِ الْقَدْرِ عَلى اَفْضَلِ حال تُحِبُّ اَنْ يَكُونَ عَلَيْها اَحَدٌ مِنْ اَوْلِيائِكَ، وَاَرْضاها لَكَ، ثُمَّ اجْعَلْها لي خَيْراً مِنْ اَلْفِ شَهْر، وَارْزُقْني فيها اَفْضَلَ ما رَزَقْتَ اَحَداً مِمَّنْ بَلَّغْتَهُ اِيّاها وَاَكْرَمْتَهُ بِها، وَاْجعَلْني فيها مِنْ عُتَقائِكَ مِنْ جَهَنَّمَ، وطُلَقائِكَ مِنَ النّارِ، وَسُعَداءِ خَلْقِكَ بِمَغْفِرَتِكَ وَرِضْوانِكَ يا اَرْحَمَ الرّاحِمينَ، اَللّـهُمَّ صَلّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَارْزُقْنا في شَهْرِنا هذَا الْجِدَّ وَالاجْتِهادَ، والْقُوَّةَ وَالنَّشاطَ، وَما تُحِبُّ وَتَرْضى، اَللّـهُمَّ رَبَّ الْفَجْرِ وَلَيال عَشْر، وَالشَّفْعِ وَالْوَتْرِ، وَربَّ شَهْرِ رَمَضانَ، وَما اَنْزَلْتَ فيهِ مِنَ الْقُرآنِ، وَرَبَّ جَبْرَئيلَ وَميكائيلَ واِسْرافيلَ وَعِزْرائيلَ وَجَميعِ الْمَلائِكَةِ الْمُقَرَّبينَ، وَربَّ اِبْراهيمَ وَاِسْماعيلَ وَاِسْحـاقَ وَيَعْقُوبَ، وَربَّ مُوسى وَعيسىوَجميعِ النَّبِيّينَ وَالْمُرْسَلينَ، وَربَّ مُحَمَّد خاتَمِ النَّبِيِّينَ صَلَواتُكَ عَلَيْهِ وَعَلَيْهِمْ اَجْمَعينَ، وَاَسْاَلُكَ بِحَقِّكَ عَلَيْهِمْ وَبِحَقِّهِمْ عَلَيْكَ، وَبِحَقِّكَ الْعَظيمِ لَمّا صَلَّيْتَ عَلَيْهِ وَآلِهِ وَعَلَيْهِمْ اَجْمَعينَ، وَنَظَرْتَ اِلَيَّ نَظْرَةً رَحيمَةً تَرْضى بِها عَنّي رِضىً لا سَخَطَ عَلَيَّ بَعْدَهُ اَبَداً، وَاَعْطَيْتَني جَميعَ سُؤْلي وَرَغْبَتي وَاُمْنِيَّتي وَاِرادَتي، وَصَرَفْتَ عَنّي ما اَكْرَهُ وَاَحْذَرُ وَاَخافُ عَلى نَفْسي وَما لا اَخافُ، وَعَنْ اَهْلي وَمالي وَاِخْواني وَذُرِّيَّتي، اَللّـهُمَّ اِلَيْكَ فَرَرْنا مِنْ ذُنُوبِنا فَـاوِنا تائِبينَ وَتُبْ عَلَيْنا مُسْتَغْفِرينَ، وَاغْفِرْ لَنا مُتَعوِّذينَ، وَاَعِذْنا مُسْتَجيرينَ، وَاَجِرْنا مُسْتَسْلِمينَ، وَلا تَخْذُلْنا راهِبينَ، وآمِنّا راغِبينَ، وَشَفِّعْنا سائِلينَ، وَاَعْطِنا اِنَّكَ سَميعُ الدُّعاءِ قَريبٌ مُجيبٌ، اَللّـهُمَّ اَنْتَ رَبِّي وَاَنَا عَبْدُكَ وَاَحَقُّ منْ سَأَلَ الْعَبْدُ رَبَّهُ وَلَمْ يَسْأَلِ الْعْبادُ مِثْلَكَ كَرَماً وَجُوداً، يا مَوْضِعَ شَكْويَ السّائِلينَ، وَيا مُنْتَهى حاجَةِ الرّاغِبينَ، وَيا غِياثَ الْمُسْتَغيثينَ، وَيا مُجيبَ دَعْوَةِ الْمُضْطَرِّينَ، وَيا مَلْجَاَ الْهارِبينَ، وَيا صَريخَ الْمُسْتَصْرِخينَ، وَيا رَبَّ الْمُسْتَضْعَفينَ، وَيا كاشِفَ كَرْبِ الْمَكْرُوبينَ، وَيا فارِجَ هَمِّ الْمَهْمُومينَ، وَيا كاشِفَ الْكَرْبِ الْعَظيمِ يا اَللهُ يا رَحْمنُ يا رَحيمُ يا اَرْحَمَ الرّاحِمينَ (وَيا اَللهُ المَكْنُون مِنْ كُلِّ عَيْنِ، الْمُرْتَدي بِالْكِبْرِياءِ) صَلّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاغْفِرْ لي ذُنُوبي وَعُيُوبي وَاِساءَتي وَظُلْمي وَجُرْمي وَاِسْرافي عَلى نَفْسي، وَارْزُقْني مِنْ فَضْلِكَ وَرَحْمَتِكَ فَاِنَّهُ لا يَمْلِكُها غَيْرُكَ، وَاعْفُ عَنّي وَاغْفِرْ لي كُلَّ ما سَلَفَ مِنْ ذُنُوبي، وَاعْصِمْني فيـما بَقِيَ مِنْ عُمْري، وَاسْتُرْ عَلَيَّ وَعَلى والِديَّ وَوَلَدي وَقرابَتي وَاَهْلِ حُزانَتي وَمَنْ كانَ مِنّي بِسَبيْل مِنَ الْمُؤْمِنينَ وَالْمُؤْمِناتِ في الدُّنْيا وَالاْخِرَةِ فَاِنَّ ذلِكَ كُلَّهُ بِيَدِكَ وَاَنْتَ واسِعُ الْمَغْفِرَةِ، فَلا تُخَيِّبْني يا سَيِّدي، وَلا تَرُدَّ دُعائي وَلا يَدي اِلى نَحْري حَتّى تَفْعَلَ ذلِكَ بي، وَتَسْتَجيبَ لي جَميعَ ما سَأَلْتُكَ، وَتَزيدَني مِنْ فَضْلِكَ فَاِنَّكَ عَلى كُلِّ شَيء قَديرٌ، وَنَحْنُ اِلَيْكَ راغِبُونَ، اَللّـهُمَّ لَكَ الاَسْماءُ الْحُسْنى، وَالاَمْثالُ الْعُلْيا، وَالْكِبْرِياءُ وَالالاءُ، اَسْاَلُكَ بِاسْمِكَ بِسْمِ الله الرَّحْمـنِ الرَّحيمِ اِنْ كُنْتَ قَضَيْتَ في هذِهِ اللَّيْلَةِ تَنَزُّلَ الْمَلائِكَةِ وَالرُّوحِ فيها اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَنْ تَجْعَلَ اسْمي فِي السُّعَداءِ، وَرُوحي مَعَ الشُّهَداءِ، وَاِحْساني في عِلِّيّينَ، وَاِساءَتي مَغْفُورَةً وَاَنْ تَهَبَ لي يَقيناً تُباشِرُ بِهِ قَلْبي، وَايماناً لا يَشُوبُهُ شَكٌّ، وَرِضىً بِما قَسَمْتَ لي، وَآتِني في الدُّنْيا حَسَنَةً وَفِى حَسَنَةً وَقِنى عَذابَ النّارِ، وَاِنْ لَمْ تَكُنْ قَضَيْتَ في هذِهِ اللَّيْلَةِ تَنَزُّلَ الْمَلـائِكَةِ وَالرُّوحِ فيها فَاَخِّرْني اِلى ذلِكَ، وَارْزُقْني فيها ذِكْرَكَ وَشُكْرَكَ وَطاعَتَكَ وَحُسْنَ عِبادَتِكَ وصَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّدبِاَفْضَلِ صَلَواتِكَ يا اَرْحَمَ الرّاحِمينَ يا اَحَدٌ يا صَمَدٌ، يا رَبَّ مُحَمَّد، اغْضَبِ الْيَوْمَ لُِمحَمَّد وَلاَِبْرارِ عِتْرَتِهِ واقْتُلْ اَعْداءَهُمْ بَدَداً، وَاَحْصِهِمْ عَدَداً، وَلا تَدَعْ عَلى ظَهْرِ الاَرْضِ مِنْهُمْ اَحَداً، وَلا تَغْفِرْ لَهُمْ اَبَداً، يا حَسَنَ الصُّحْبَةِ يا خَليفَةَ النَّبِيّينَ اَنْتَ اَرْحَمُ الرّاحِمينَ الْبَديءُ الْبَديعُ الَّذي لَيْسَ كَمِثْلِكَ شَيءٌ، وَالدّائِمُ غَيْرُ الْغافِلِ، وَالْحَيُّ الَّذي لا يَمُوتُ، اَنْتَ كُلَّ يَوْم في شَأن، اَنْتَ خَليفَةَ، مُحَمَّد، وَناصِرُ مُحَمَّد، وَمُفَضِّلُ مُحَمَّد، اَسْاَلُكَ اَنْ تَنْصُرَ وَصِيَّ مُحَمَّد، وَخَليفَةَ مُحَمَّد، وَالْقائِمَ بِالْقِسْطِ مِنْ أَوْصِياءِمُحَمَّد صَلَواتُكَ عَلَيْهِ وَعَلَيْهِمْ، اِعْطِفْ عَلَيْهِمْ نَصْرَكَ يا لا اِلـهَ إلاّ اَنْتَ، بِحَقِّ لا اِلـهَ إلاّ اَنْتَ، صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاجْعَلْني مَعَهُمْ في الدُّنْيا وَالاخِرَةِ، وَاجْعَلْ عاقِبَةَ اَمْري اِلى غُفْرانِكَ وَرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ، وَكَذلِكَ نَسَبْتَ نَفْسَكَ يا سَيِّدي بِاللَّطيفِ، بَلى اِنَّكَ لَطيفٌ، فَصَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَالْطُفْ بي لِما تَشاءُ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَارْزُقْنِى الْحَجَّ وَالْعُمْرَةَ في عامِنا هذا، وَتَطَوَّلْ عَلَيَّ بِجَميعِ حَوائِجي لِلاْخِرَةِ وَالدُّنْيا (ثُمَّ تَقُول ثلاثاً) اَسْتَغْفِرُ اللهَ رَبِّي وَاَتُوبُ اِلَيْهِ اِنَّ رَبِّي قَريبٌ مُجيبٌ، اَسْتَغْفِرُ اللهَ رَبِّي وَاَتُوبُ اِلَيْهِ اِنَّ رَبّي رَحيمٌ وَدُودٌ، اَسْتَغْفِرُ اللهَ رَبِّي وَاَتُوبُ اِلَيْهِ اِنَّهُ كانَ غَفّاراً اَللّـهُمَّ اغْفِرْ لي اِنَّكَ اَرْحَمُ الرّاحِمينَ، رَبِّ اِنّي عَمِلْتُ سُوءاً وَظَلَمْتُ نَفْسي فَاغْفِرْ لي اِنَّهُ لا يَغْفِرُ الذُّنُوبَ إلاّ اَنْتَ، اَسْتَغْفِرُ اللهَ الَّذي لا اِلـهَ إلاّ هُوَ الْحَيُّ، الْقَيُّومُ الْحَليمُ الْعَظيمُ الْكَريمُ، الْغَفّارُ لِلذَّنْبِ الْعَظيمِ وَاَتُوبُ اِلَيْهِ، اَسْتَغْفِرُ اللهَ اِنَّ اللهَ كانَ غَفُوراً رَحيماً (ثُم تقولُ :) اَللّـهُمَّ إنّي اَسْألُكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَنْ تَجْعَلَ فيـما تَقْضي وَتُقَدِّرُ مِنَ الاَمْرِ الْعَظيمِ الَْمحْتُومِ في لَيْلَةِ الْقَدْرِ مِنَ الْقَضاءِ الَّذي لا يُرَدُّ وَلا يُبَدَّلُ، اَنْ تَكْتُبَني مِنْ حُجّاجِ بَيْتِكَ الْحَرامِ، الْمَبْرُورِ حَجُّهُمْ، الْمَشْكُورِ سَعْيُهُمْ، الْمَغْفُورِ ذُنُوبُهُمْ، الْمُكَفَّرِ عَنْهُمْ سَيِّئاتُهُمْ، وَاَنْ تَجْعَلَ فيـما تَقْضي وَتُقَدِّرُ اَنْ، تُطيلَ عُمْري وَتُوَسِّعَ رِزْقي، وَتُؤَدِّي عَنّي اَمانَتي وَدَيْني، آمينَ رَبَّ الْعالَمينَ، اَللّـهُمَّ اجْعَلْ لي مِنْ اَمْري فَرَجاً وَمَخْرَجاً، وَارْزُقْني مِنْ حَيْثُ اَحْتَسِبُ وَمِنْ حَيْثُ لا اَحْتَسِبُ، وَاحْرُسْني مِنْ حَيْثُ اَحْتَرِسُ، وَمِنْ حَيْثُ لا اَحْتَرِسُ وَصَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَسَلِّمْ كَثيراً ."},{"type":"Text","content":"الثّاني : وقال أيضاً تسبّح كلّ يوم من شهر رمضان الى آخره بهذه التّسبيحات وهي عشرة أجزاء كلّ جزء يحتوي على عشرة تسبيحات :"},{"type":"Text","content":"(1) سُبْحـانَ اللهِ بارِئِ النَّسَمِ، سُبْحـانَ اللهِ المُصَوِّرِ، سُبْحـانَ اللهِ خالِقِ الاَزْواجِ كُلِّها، سُبْحـانَ اللهِ جاعِلِ الظُّلُماتِ وَالنُّورِ، سُبْحـانَ اللهِ فالِقِ الْحَبِّ وَالنَّوى، سُبْحـانَ اللهِ خالِقِ كُلِّ شَيء، سُبْحـانَ اللهِ خالِقِ ما يُرى، وَما لا يُرى سُبْحـانَ اللهِ مِدادَ كَلِماتِهِ، سُبْحـانَ اللهِ رَبِّ الْعالَمينَ، سُبْحـانَ اللهِ السَّميعِ الَّذي لَيْسَ شَيءٌ اَسْمَعَ مِنْهُ، يَسْمَعُ مِنْ فَوْقِ عَرْشِهِ ما تَحْتَ سَبْعِ اَرَضينَ، وَيَسْمَعُ ما في ظُلُماتِ الْبَرِّ وَالْبَحْرِ، وَيَسْمَعُ الاَنينَ وَالشَّكْوى وَيَسْمَعُ السِّرَّ وَاَخْفى، وَيَسْمَعُ وَساوِسَ الصُّدُورِ (وَيَعْلَمُ خائِنَةَ الاَعْيُنِ وَما تُخْفِي الصُّدُورِ) وَلا يُصِمُّ سَمْعَهُ صَوْتٌ (2) سُبْحـانَ اللهِ بارِئِ النَّسَمِ، سُبْحـانَ اللهِ الُمصَوِّرِ، سُبْحـانَ اللهِ خالِقِ الاَزْواجِ كُلِّها، سُبْحـانَ اللهِ جاعِلِ الظُّلُماتِ وَالنُّورِ، سُبْحـانَ اللهِ فالِقِ الْحَبِّ وَالنَّوى، سُبْحـانَ اللهِ خالِقِ كُلِّ شَيء، سُبْحـانَ اللهِ خالِقِ ما يُرى وَما لا يُرى، سُبْحـانَ اللهِ مِدادَ كَلِماتِهِ، سُبْحـانَ اللهِ رَبِّ الْعالَمينَ، سُبْحـانَ اللهِ الْبَصيرِ الَّذي لَيْسَ شَيءٌ اَبْصَرَ مِنْهُ، يُبْصِرُ مِنْ فَوْقِ عَرْشِهِ ما تَحْتَ سَبْعِ اَرَضينَ، وَيُبْصِرُ ما في ظُلُماتِ الْبَرِّ وَالْبَحْر، لا تُدْرِكُهُ الابْصارُ وَهُوَ يُدْرِكُ الاَبْصارَ وَهُوَ اللَّطيفُ الْخَبيرُ، لا تَغْشَى بَصَرَهُ الظُّلْمَةُ، وَلا يُسْتَتَرُ مِنْهِ بِسِتْر، وَلا يُواري مِنْهُ جِدارٌ، وَلا يَغيبُ عَنْهُ بَرٌّ وَلا بَحْرٌ، وَلا يَكُنُّ مِنْهُ جَبَلٌ ما في اَصْلِهِ، وَلا قَلْبٌ ما فيهِ، وَلا جَنْبٌ ما في قَلْبِهِ، وَلا يَسْتَتِرُ مِنْهُ صَغيرٌ وَلا كَبيرٌ، وَلا يَسْتَخْفي مِنْهُ صَغيرٌ لِصِغَرِهِ، وَلا يَخْفى عَلَيْهِ شَيءٌ فِي الاَرْضِ وَلا فِي السَّماءِ، هُوَ الَّذي يُصَوِّرُكُمْ فِي الاَرْحامِ كَيْفَ يَشاءُ، لا اِلـهَ إلاّ هُوَ الْعَزيزُ الْحَكيمُ (3) سُبْحـانَ اللهِ بارِئِ النَّسَمِ، سُبْحـانَ اللهِ الُمصَوِّرِ، سُبْحـانَ اللهِ خالِقِ الاَزْواجِ كُلِّها، سُبْحـانَ اللهِ جاعِلِ الظُّلُماتِ وَالنُّورِ، سُبْحـانَ اللهِ فالِقِ الْحَبِّ وَالنَّوى، سُبْحـانَ اللهِ خالِقِ كُلِّ شَيء، سُبْحـانَ اللهِ خالِقِ ما يُرى، وَما لا يُرى سُبْحـانَ اللهِ مِدادَ كَلِماتِهِ، سُبْحـانَ اللهِ رَبِّ الْعالَمينَ، سُبْحـانَ اللهِ الَّذي يُنْشِئُ السَّحابَ الثِّقالَ، وَيُسَبِّحُ الرَّعْدُ بِحَمْدِهِ، وَالْمَلائِكَةُ مِنْ خِيفَتِهِ، وَيُرْسِلُ الصَّواعِقَ فَيُصيبُ بِها مَنْ يَشاءُ، وَيُرْسِلُ الرِّياحَ بُشْراً بَيْنَ يَدَي رَحْمَتِهِ، وَيُنَزِّلُ الْماءَ مِنَ السَّماءِ بِكَلِمَتِهِ وَيُنْبِتُ النَّباتَ بِقُدْرَتِهِ، وَيَسْقُطُ الْوَرَقُ بِعِلْمِهِ، سُبْحـانَ اللهِ الَّذي لا يَعْزُبُ عَنْهُ مِثْقالُ ذَرَّة فِي الاَرْضِ وَلا فِي السَّماءِ، وَلا اَصْغَرُ مِنْ ذلِكَ وَلا اَكْبَرُ إلاّ في كِتاب مُبين (4) سُبْحـانَ اللهِ بارِئِ النَّسَمِ، سُبْحـانَ اللهِ الُمصَوِّرِ، سُبْحـانَ اللهِ خالِقِ الاَزْواجِ كُلِّها، سُبْحـانَ اللهِ جاعِلِ الظُّلُماتِ وَالنُّورِ، سُبْحـانَ اللهِ فالِقِ الْحَبِّ وَالنَّوى، سُبْحـانَ اللهِ خالِقِ كُلِّ شَيء، سُبْحـانَ اللهِ خالِقِ ما يُرى، وَما لا يُرى سُبْحـانَ اللهِ مِدادَ كَلِماتِهِ، سُبْحـانَ اللهِ رَبِّ الْعالَمينَ، سُبْحـانَ اللهِ الَّذي يَعْلَمُ ما تَحْمِلُ كُلُّ اُنْثى وَما تَغيْضُ الاَرْحامُ وَما تَزْدادُ وَكُلُّ شَيْء عِنْدَهُ بِمِقْدار، عالِمُ الْغَيْبِ وَالشَّهادَةِ الْكَبيْرُ الْمُتَعالِ، سَواءٌ مِنْكُمْ مَنْ اَسَرَّ الْقَوْلَ وَمَنْ جَهَرَ بِهِ، وَمَنْ هُوَ مُسْتَخْف بِاللَّيْلِ وَسارِبٌ بِالنَّهارِ، لَهُ مُعَقِّباتٌ مِنْ بَيْنِ يَدَيْهِ وَمِنْ خَلْفِهِ يَحْفَظُونَهُ مِنَ اَمْرِ اللهِ، سُبْحانَ اللهِ الَّذي يُميتُ الاَحْياءَ، وَيُحْيِى الْمَوْتى، وَيَعْلَمُ ما تَنْقُصُ الاَرْضُ مِنْهُمْ، وَيُقِرُّ فِي الاَرْحامِ ما يَشاءُ اِلى اَجَل مُسَمّىً (5) سُبْحـانَ اللهِ بارِئِ النَّسَمِ، سُبْحـانَ اللهِ الُمصَوِّرِ، سُبْحـانَ اللهِ خالِقِ الاَزْواجِ كُلِّها، سُبْحـانَ اللهِ جاعِلِ الظُّلُماتِ وَالنُّورِ، سُبْحـانَ اللهِ فالِقِ الْحَبِّ وَالنَّوى، سُبْحـانَ اللهِ خالِقِ كُلِّ شَيء، سُبْحـانَ اللهِ خالِقِ ما يُرى وَما لا يُرى، سُبْحـانَ اللهِ مِدادَ كَلِماتِهِ، سُبْحـانَ اللهِ رَبِّ الْعالَمينَ، سُبْحـانَ اللهِ مالِكِ الْمُلْكِ تُؤْتِى الْمُلْكَ مَنْ تَشاءُ، وَتَنْزِعُ الْمُلْكَ مِمَّنْ تَشاءُ، وَتُعِزُّ مَنْ تَشاءُ، وَتُذِلُّ مَنْ تَشاءُ، بِيَدِكَ الْخَيْرُ اِنَّكَ عَلى كُلِّ شَيء قَديرٌ، تُولِجُ اللَّيْلَ فِي النَّهارِ، وَتُولِجُ النَّهارَ فِي اللَّيْلِ، تُخْرِجُ الْحَىَّ مِنَ الْمَيِّتِ، وَتُخْرِجُ الْمَيِّتَ مِنَ الْحَيِّ، وَتَرْزُقُ مَنْ تَشاءُ بِغَيْرِ حِسابِ (6) سُبْحـانَ اللهِ بارِئِ النَّسَمِ، سُبْحـانَ اللهِ الُمصَوِّرِ، سُبْحـانَ اللهِ خالِقِ الاَزْواجِ كُلِّها، سُبْحـانَ اللهِ جاعِلِ الظُّلُماتِ وَالنُّورِ، سُبْحـانَ اللهِ فالِقِ الْحَبِّ وَالنَّوى، سُبْحـانَ اللهِ خالِقِ كُلِّ شَيء، سُبْحـانَ اللهِ خالِقِ ما يُرى وَما لا يُرى، سُبْحـانَ اللهِ مِدادَ كَلِماتِهِ، سُبْحـانَ اللهِ رَبِّ الْعالَمينَ، سُبْحـانَ اللهِ الَّذي عِنْدَهُ مُفاتِحُ الْغَيْبِ لا يَعْلَمُها إلاّ هُوَ وَيَعْلَمُ ما فِي الْبَرِّ وَالْبَحْرِ، وَما تَسْقُطُ مِنْ وَرَقَة إلاَّ يَعْلَمُها، وَلا حَبَّة في ظُلُماتِ الاَرْضِ وَلا رَطْب وَلا يابِس إلاّ في كِتاب مُبين (7) سُبْحـانَ اللهِ بارِئِ النَّسَمِ، سُبْحـانَ اللهِ الُمصَوِّرِ، سُبْحـانَ اللهِ خالِقِ الاَزْواجِ كُلِّها، سُبْحـانَ اللهِ جاعِلِ الظُّلُماتِ وَالنُّورِ، سُبْحـانَ اللهِ فالِقِ الْحَبِّ وَالنَّوى، سُبْحـانَ اللهِ خالِقِ كُلِّ شَيء، سُبْحـانَ اللهِ خالِقِ ما يُرى وَما لا يُرى، سُبْحـانَ اللهِ مِدادَ كَلِماتِهِ، سُبْحـانَ اللهِ رَبِّ الْعالَمينَ، سُبْحـانَ اللهِ الَّذي لا يُحْصي مِدْحَتَهُ الْقائِلُونَ، وَلا يَجْزي بِـآلائِهِ الشّاكِرُونَ الْعابِدُونَ، وَهُوَ كَما قالَ وَفَوْقَ ما نَقُولُ، وَاللهُ سُبْحانَهُ كَما اَثْنى عَلى نَفْسِهِ وَلا يُحيطونَ بِشَئ مِنْ عِلْمِهِ اِلاّا بِما شاءَوَسِعَ كُرْسِيُّهُ السَّماواتِ وَالاَرْضَ وَلا يَؤُدُهُ حِفْظُهُما وَهُوَ الْعَلِيُّ الْعَظيمُ (8) سُبْحـانَ اللهِ بارِئِ النَّسَمِ، سُبْحـانَ اللهِ الُمصَوِّرِ، سُبْحـانَ اللهِ خالِقِ الاَزْواجِ كُلِّها، سُبْحـانَ اللهِ جاعِلِ الظُّلُماتِ وَالنُّورِ، سُبْحـانَ اللهِ فالِقِ الْحَبِّ وَالنَّوى، سُبْحـانَ اللهِ خالِقِ كُلِّ شَيء، سُبْحـانَ اللهِ خالِقِ ما يُرى وَما لا يُرى، سُبْحـانَ اللهِ مِدادَ كَلِماتِهِ، سُبْحـانَ اللهِ رَبِّ الْعالَمينَ، سُبْحـانَ اللهِ الَّذي يَعْلَمُ ما يَلِجُ فِى الاَرْضِ وَما يَخْرُجُ مِنْها وَما يَنْزِلُ مِنَ السَّماءِ وَما يَعْرُجُ فيها، وَلا يَشْغَلُهُ ما يَلِجُ فِى الاَرْضِ وَمايَخْرُجُ مِنْها عَمّا يَنْزِلُ مِنَ السَّماءِ وَما يَعْرُجُ فيها، وَلا يَشْغَلُهُ ما يَنْزِلُ مِنَ السَّماءِ وَما يَعْرُجُ فيها عَمّا يَلِجُ فِى الاَرْضِ وَما يَخْرُجُ مِنْها، وَلا يَشْغَلُهُ عِلْمُ شَىْء عَنْ عِلْمِ شَىْء وَلا يَشْغَلُهُ خَلْقُ شَىْء عَنْ خَلْقِ شَيْء، وَلا حِفْظُ شَيْء، عَنْ حِفْظِ شَيْء وَلا يُساويهِ شَيْءٌ وَلا يَعْدِلُهُ شَيْءٌ لَيْسَ كَمِثْلِهِ شَيْءٌ وَهُوَ السَّميعُ الْبَصيرُ (9) سُبْحـانَ اللهِ بارِئِ النَّسَمِ، سُبْحـانَ اللهِ الُمصَوِّرِ، سُبْحـانَ اللهِ خالِقِ الاَزْواجِ كُلِّها، سُبْحـانَ اللهِ جاعِلِ الظُّلُماتِ وَالنُّورِ، سُبْحـانَ اللهِ فالِقِ الْحَبِّ وَالنَّوى، سُبْحـانَ اللهِ خالِقِ كُلِّ شَيء، سُبْحـانَ اللهِ خالِقِ ما يُرى وَما لا يُرى، سُبْحـانَ اللهِ مِدادَ كَلِماتِهِ، سُبْحـانَ اللهِ رَبِّ الْعالَمينَ، سُبْحـانَ اللهِ فاطِرِ السَّماواتِ وَالاَرْضِ، جاعِلِ الْمَلائِكَةِ رُسُلاً اُولي اَجْنِحَة، مَثْنى وَثُلاثَ وَرُباعَ، يَزيدُ فِى الْخَلْقِ ما يَشاءُ اِنَّ اللهَ عَلى كُلِّ شَيْء قَديرٌ، ما يَفْتَحِ اللهُ لِلنّاسِ مِنْ رَحْمَة فَلا مُمْسِكَ لَها، وَما يُمْسِكُ فَلا مُرْسِلَ لَهُ مِنْ بَعْدِهِ وَهُوَ الْعَزيزُ الْحَكيمُ (10) سُبْحـانَ اللهِ بارِىءِ النَّسَمِ، سُبْحـانَ اللهِ الُمصَوِّرِ، سُبْحـانَ اللهِ خالِقِ الاَزْواجِ كُلِّها، سُبْحـانَ اللهِ جاعِلِ الظُّلُماتِ وَالنُّورِ، سُبْحـانَ اللهِ فالِقِ الْحَبِّ وَالنَّوى، سُبْحـانَ اللهِ خالِقِ كُلِّ شَيء، سُبْحـانَ اللهِ خالِقِ ما يُرى وَما لا يُرى، سُبْحـانَ اللهِ مِدادَ كَلِماتِهِ، سُبْحـانَ اللهِ رَبِّ الْعالَمينَ، سُبْحـانَ اللهِ الَّذي يَعْلَمُ ما فِى السَّماواتِ وَما فِى الاَرْضِ، ما يَكُونُ مِنْ نَجْوى ثَلاثَة إلاّ هوَ رابِعُهُمْ، وَلا خَمْسَة اِلاّا هُوَ سادِسُهُمْ، وَلا اَدْنى مِنْ ذلِكَ وَلا اَكْثَرَ إلاّ هُوَ مَعَهُمْ اَيْنَما كانُوا، ثُمَّ يُنَبِّئُهُمْ بِما عَمِلُوا يَوْمَ الْقِيامَةِ اِنَّ اللهَ بِكُلِّ شَيْء عَليمٌ ."}],"preview":"يا مَفْزَعي عِنْدَ كُرْبَتي، وَيا غَوْثي عِنْدَ شِدَّتي اِلَيْكَ فَزِعْتُ، وَبِكَ اسْتَغَثْتُ، وَبِكَ لُذْتُ لا اَلُوذُ بِسِواكَ وَلا اَطْلُبُ الْفَرَجَ إلاّ مِنْكَ، فَاَغِثْني وَف","hasTranslate":false},{"id":"mf_ar_126","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القِسمُ الرّابعُ : في أعمال أيّام شهر رمضان","title":"الثّالث : وقالا أيضاً: تصلّي في كلّ يوم من رمضان على النّبي تقول :","blocks":[{"type":"Text","content":"اِنَّ اللهَ وَمَلائِكَتَةُ يُصَلُّونَ عَلَى النَّبِيِّ يا اَيُّهَا الَّذينَ آمَنُوا صَلُّوا عَلَيْهِ وَسَلِّمُوا تَسْليما، لَبَّيْكَ يا رَبِّ وَسَعْدَيْكَ وَسُبْحانَكَ، اَللّـهُمَّ صَلّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَبارِكَ عَلى مُحَمَّد وَآلِ مُحَمَّد، كَما صَلَّيْتَ وَبارَكْتَ عَلى اِبْراهيمَ وَآلِ اِبْراهيمَ اِنَّكَ حَميدٌ مَجيدٌ، اَللّـهُمَّ ارْحَمْ مُحَمَّداً وَآلِ مُحَمَّد كَما رَحِمْتَ اِبْراهيمَ وآلَ اِبْراهيمَ اِنَّكَ حَميدٌ مَجيدٌ، اَللّـهُمَّ سَلِّمْ عَلى مُحَمَّد وَآلِ مُحَمَّد كَما سَلَّمْتَ عَلى نُوح فِى الْعالَمينَ، اَللّـهُمَّ امْنُنْ عَلى مُحَمَّد وَآلِ مُحَمَّد كَما مَنَنْتَ عَلى مُوسى وَهارُونَ، اَللّـهُمَّ صَلّ عَلى مُحَمَّد وَآلِ مُحَمَّد كَما شَرَّفْتَنا بِهِ اَللّهُمَّ صَلّ عَلى مُحَمَّد وَآلِ مُحَمَّد كَما هَدَيْتَنا بِهِ، اَللّـهُمَّ صَلّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَابْعَثْهُ مَقاماً مَحْمُوداً يَغْبِطُهُ بِهِ الاَوَّلُونَ وَالاخِرُونَ، عَلى مُحَمَّد وَآلِهِ السَّلامُ كُلَّما طَلَعَتْ شَمْسٌ اَوْ غَرَبَتْ، عَلى مُحَمَّد وآلِهِ السَّلامُ كُلَّما طَرَفَتْ عَيْنٌ اَوْ بَرَقَتْ، عَلى مُحَمَّد وَآلِهِ السَّلامُ كُلَّما ذُكِرَ السَّلامُ، عَلى مُحَمَّد وَآلِهِ السَّلامُ كُلَّما سَبَّحَ اللهَ مَلَكٌ اَوْ قَدَّسَهُ، السَّلامُ عَلى مُحَمَّد وَآلِهِ فِى الاَوَّلينَ، والسَّلامُ عَلى مُحَمَّد وَآلِهِ فِى الاخِرِينَ، وَالسَّلامُ عَلى مُحَمَّد وَآلِهِ فِي الدُّنْيا وَالاخِرَةِ، اَللّـهُمَّ رَبَّ الْبَلَدِ الْحرامِ وَرَبَّ الرُّكْنِ وَالْمَقامِ، وَرَبَّ الْحِلِّ وَالْحَرامِ، اَبْلِغْ مُحَمَّداً نَبيَّكَ عَنَّا السَّلامَ، اَللّـهُمَّ اَعْطِ مُحَمَّداً مِنَ الْبَهاءِ وَالنَّضْرَةِ وَالسُّرُورِ وَالْكَرامَةِ وَالْغِبْطَةِ وَالْوَسيلَةِ وَالْمَنْزِلَةِ وَالْمَقامِ وَالشَّرَفِ وَالرِّفْعَةِ وَالشَّفاعَةِ عِنْدَكَ يَوْمَ الْقِيامَةِ اَفْضَلَ ما تُعْطي اَحَداً مِنْ خَلْقِكَ، وَاَعْطِ مُحَمَّداً فَوْقَ ما تُعْطِي الْخَلائِقَ مِنَ الْخَيْرِ اَضْعافاً كَثيرَةً لا يُحْصيها غَيْرُكَ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد اَطْيَبَ وَاَطْهَرَ وَأزْكى وَاَنْمى وَاَفْضَلَ ما صَلَّيْتَ عَلى اَحَد مِنَ الاَوَّلينَ وَالاخِرينَ، وَعَلى اَحَد مِنْ خَلْقِكَ يا اَرْحَمَ الرّاحِمينَ، اَللّـهُمَّ صَلِّ عَلى عَليٍّ اَميرِ الْمُؤْمِنينَ وَوالِ مَنْ والاهُ وَعادِ مَنْ عاداهُ وَضاعِفِ الْعَذابَ عَلى مَنْ شَرِكَ في دَمِهِ، اَللّـهُمَّ صَلِّ عَلى فاطِمَةَ بِنْتِ نَبيِّكَ مُحَمَّد عَلَيْهِ وَآلِهِ السَّلامُ وَالْعَنْ مَنْ آذى نَبِيَّكَ فيهاوَوال مَنْ والاها وعاد مَنْ عاداها وضا عِفِ العَذاب عَلى مَن ظَلَمَها واَلعَنْ مَنْ اذى نَبيِّك فيْها اَللّـهُمَّ صَلِّ عَلَى الْحَسَنِ وَالْحُسَيْنِ اِمامَىِ الْمُسْلِمينَ، وَوالِ مَنْ والاهُماوَعادِ مَنْ عاداهُما، وَضاعِفِ الْعَذابَ عَلى مَنْ شَرِكَ في دِمائِهِما، اَللّـهُمَّ صَلِّ عَلى عَلِيِّ بْنِ الْحُسَيْنِ اِمامِ الْمُسْلِمينَ وَوالِ مَنْ والاهُ وَعادِ مَنْ عاداهُ وَضاعِفِ الْعَذابَ عَلى مَنْ ظَلَمَهُ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد بنِ عَلِيٍّ اِمامِ الْمُسْلِمينَ وَوالِ مَنْ والاهُ وَعادِ مَنْ عاداهُ وَضاعِفِ الْعَذابَ عَلى مَنْ ظَلَمَهُ، اَللّـهُمَّ صَلِّ عَلى جَعْفَرِ بْنِ مُحَمَّد اِمامِ الْمُسْلِمينَ وَوالِ مَنْ والاهُ وَعادِ مَنْ عاداهُ وَضاعِفِ الْعَذابَ عَلى مَنْ ظَلَمَهُ، اَللّـهُمَّ صَلِّ عَلى مُوسَى بْنِ جَعْفَر اِمامِ الْمُسْلِمينَ وَوالِ مَنْ والاهُ وَعادِ مَنْ عاداهُ وَضاعِفِ الْعَذابَ عَلى مَنْ شَرِكَ في دَمِهِ، اَللّـهُمَّ صَلِّ عَلى عَلِيِّ بْنِ مُوسى اِمامِ الْمُسْلِمينَ وَوالِ مَنْ والاهُ وَعادِ مَنْ عاداهُ وَضاعِفِ الْعَذابَ عَلى مَنْ شَرِكَ في دَمِهِ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد بْنِ عَلِيٍّ اِمامِ الْمُسْلِمينَ وَوالِ مَنْ والاهُ وَعادِ مَنْ عاداهُ وَضاعِفِ الْعَذابَ عَلى مَنْ ظَلَمَهُ، اَللّـهُمَّ صَلِّ عَلى عَلِي بْنِ مُحَمَّد اِمامِ الْمُسْلِمينَ وَوالِ مَنْ والاهُ وَعادِ مَنْ عاداهُ وَضاعِفِ الْعَذابَ عَلى مَنْ ظَلَمَهُ، اَللّـهُمَّ صَلِّ عَلَى الْحَسَنِ بْنِ عَلِيٍّ اِمامِ الْمُسْلِمينَ وَوالِ مَنْ والاهُ وَعادِ مَنْ عاداهُ وَضاعِفِ الْعَذابَ عَلى مَنْ ظَلَمَهُ، اَللّـهُمَّ صَلِّ عَلَى الْخَلَفِ مِنْ بَعْدِهِ اِمامِ الْمُسْلِمينَ وَوالِ مَنْ والاهُ وَعادِ مَنْ عاداهُ وَعَجِّلْ فَرَجَهُ، اَللّـهُمَّ صَلِّ عَلَى الْقاسِمِ وَالطّاهِرِ اِبْنَي نَبِيِّكَ، اَللّـهُمَّ صَلِّ عَلَى رُقَيَّةَ بِنْتِ نَبِيِّكَ وَالْعَنْ مَنْ آذى نَبِيَّكَ فيها، اَللّـهُمَّ صَلِّ عَلَى اُمِّ كُلْثُومَ بِنْتِ نَبِيِّكَ وَالْعَنْ مَنْ آذى نَبِيَّكَ فيها، اَللّـهُمَّ صَلِّ عَلَى ذُرِّيَّةِ نَبِيِّكَ، اَللّـهُمَّ اخْلُفْ نَبِيَّكَ في اَهْلِ بَيْتِهِ، اَللّـهُمَّ مَكِّنْ لَهُمْ فِى الاَرْضِ، اَللّـهُمَّ اجْعَلْنا مِنْ عَدَدِهِمْ وَمَدَدِهِمْ وَاَنْصارِهِمْ عَلَى الْحَقِّ فِى السِّرِّ وَالْعَلانَيَةِ، اَللّـهُمَّ اطْلُبْ بِذِحْلِهِمْ وَوِتْرِهِمْ وَدِمائِهِمْ وَكُفَّ عَنّا وَعَنْهُمْ وَعَنْ كُلِّ مُؤْمِن وَمُؤْمِنَة بَأسَ كُلِّ باغ وَطاغ وَكُلِّ دابَّة اَنْتَ آخِذٌ بِناصِيَتِها اِنَّكَ اَشَدُّ بَأساً وَاَشَدُّ تَنْكيلاً."},{"type":"Text","content":"وقال السّيّد ابن طاووس وتقول : يا عُدَّتي في كُرْبَتي، وَيا صاحِبي في شِدَّتي، وَيا وَلِيّي في نِعْمَتي، وَيا غايَتي في رَغْبَتي، اَنْتَ السّاتِرُ عَوْرَتي، وَالْمُؤْمِنُ رَوْعَتي، وَالْمُقيلُ عَثْرَتي، فَاغْفِرْ لي خَطيئَتي يا اَرْحَمَ الرّاحِمينَ وتقول : اَللّـهُمَّ اِنّي اَدْعُوكَ لِهَمٍّ لا يُفَرِّجُهُ غَيْرُكَ، وَلِرَحْمَة لا تُنالُ إلاّ بِكَ، وَلِكَرْب لا يَكْشِفُهُ إلاّ اَنْتَ، وَلِرَغْبَة لا تُبْلَغُ إلاّ بِكَ، وَلِحاجَة لا يَقْضيها إلاّ اَنْتَ، اَللّـهُمَّ فَكَما كانَ مِنْ شَأنِكَ ما اَذِنْتَ لي بِهِ مِنْ مَسْأَلَتِكَ وَرَحِمْتَني بِهِ مِنْ ذِكْرِكَ، فَلْيَكُنْ مِنْ شَأنِكَ سَيِّدي الاِجابَةُ لي فيـما دَعْوَتُكَ، وَعَوائِدُ الاِفْضالِ فيـما رَجَوْتُكَ، وَالنَّجاهُ مِمّا فَزِعْتُ اِلَيْكَ فيهِ، فَاِنْ لَمْ اَكُنْ اَهْلاً اَنْ اَبْلُغَ رَحْمَتَكَ فَاِنَّ رَحْمَتَكَ اَهْلٌ اَنْ تَبْلُغَني وَتَسَعَني، وَاِنْ لَمْ اَكُنْ لِلاِْجابَةِ اَهْلاً فَاَنْتَ اَهْلُ الْفَضْلِ، وَرَحْمَتُكَ وَسِعَتْ كُلَّ شَيْء، فَلْتَسَعْني رَحْمَتُكَ، يا اِلـهي يا كَريمُ اَسْاَلُكَ بِوَجْهِكَ الْكَريمِ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَاَهْلِ بَيْتِهِ، وَاَنْ تُفَرِّجَ هَمّي، وَتَكْشِفَ كَرْبي وَغَمّي، وَترْحَمَني بِرَحْمَتِكَ، وَتَرْزُقَني مِنْ فَضْلِكَ اِنَّكَ سَميعُ الدُّعاءِ قَريبٌ مُجيبٌ ."}],"preview":"اِنَّ اللهَ وَمَلائِكَتَةُ يُصَلُّونَ عَلَى النَّبِيِّ يا اَيُّهَا الَّذينَ آمَنُوا صَلُّوا عَلَيْهِ وَسَلِّمُوا تَسْليما، لَبَّيْكَ يا رَبِّ وَسَعْدَيْكَ وَسُبْحانَكَ، اَللّـهُمَّ","hasTranslate":false},{"id":"mf_ar_127","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"القِسمُ الرّابعُ : في أعمال أيّام شهر رمضان","title":"الرّابع : وقال الشّيخ والسّيد أيضاً : قل في كلّ يوم :","blocks":[{"type":"Text","content":"اَللّـهُمَّ اِنّي اَسْاَلُكَ مِنْ فَضْلِكَ بِاَفْضَلِهِ وَكُلُّ فَضْلِكَ فاضِلٌ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِفَضْلِكَ كُلِّه، اَللّـهُمَّ اِنّي اَسْاَلُكَ مِنْ رِزْقِكَ بِاَعَمِّهِ وَكُلُّ رِزْقِكَ عامٌّ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِرِزْقِكَ كُلِّهِ، اَللّـهُمَّ اِنّي اَسْاَلُكَ مِنْ عَطائِكَ بِأَهْنَئِهِ وَكُلُّ عَطائكَ هَنيءٌ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِعَطائِكَ كُلِّه، اَللّـهُمَّ اِنّي اَسْاَلُكَ مِنْ خَيْرِكَ بِاَعْجَلِهِ وَكُلُّ خَيْرِكَ عاجِلٌ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِخَيْرِكَ كُلِّهِ اَللّـهُمَّ اِنّي اَسْاَلُكَ مِنْ اِحْسانِكَ بِاَحْسَنِهِ وَكُلُّ اِحْسانِكَ حَسَنٌ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِاِحْسانِكَ كُلِّهِ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِما تُجيبُني بِهِ حينَ اَسْاَلُكَ فَاَجِبْني يا اَللهُ، وَصَلِّ عَلى مُحَمَّد وآلِ مُحَمَّد عَبْدِكَ الْمُرْتَضى، وَرسُولِكَ الْمُصْطَفى، وَاَمينِكَ وَنَجِيِّكَ دُونَ خَلْقِكَ وَنَجيبِكَ مِنْ عِبادِكَ، وَنَبِيِّكَ بِالصِّدْقِ، وَحَبيبِكَ، وَصَلِّ عَلى رَسُولِكَ وَخِيَرَتِكَ مِنَ الْعالَمينَ، الْبَشيرِ الَّنذيرِ السِّراجِ الْمُنيرِ، وَعلى اَهْلِ بَيْتِهِ الاَبْرارِ الطّاهِرينَ، وَعَلى مَلائِكَتِكَ الَّذينَ اسْتَخْلَصْتَهُمْ لِنَفْسِكَ، وَحَجَبْتَهُمْ عَنْ خَلْقِكَ، وَعَلى اَنْبِيائِكَ الَّذينَ يُنبِئُونَ عَنْكَ بِالصِّدْقِ، وَعَلى رُسُلِكَ الَّذينَ خَصَصْتَهُمْ بِوَحْيِكَ، وَفَضَّلْتَهُمْ عَلَى الْعالَمينَ بِرِسالاتِكَ، وَعَلى عِبادِكَ الصّالِحينَ الَّذينَ اَدْخَلْتَهُمْ في رَحْمَتِكَ، الاَئِمَّةِ الْمُهْتَدينَ الرّاشِدينَ، وَاَوْلِيائِكَ الْمُطَهَّرينَ، وَعَلى جَبْرَئيلَ وَميكائيلَ وَاِسْرافيلَ وَمَلَكِ الْمَوْتِ، وَعَلى رِضْوانَ خازِنِ الْجِنانِ، وَعَلى مالِك خازِنِ النّارِ، وَرُوحِ الْقُدُسِ وَالرُّوحِ الاَمينِ، وَحَمَلَةِ عَرْشِكَ الْمُقَرَّبينَ، وَعَلى الْمَلَكَيْنِ الْحافِظَيْنِ عَلَيَّ بِالصَّلاةِ الَّتي تُحِبُّ اَنْ يُصَلِّيَ بِها عَلَيْهِمْ اَهْلُ السَّماواتِ وَاَهْلُ الاَرَضينَ صَلاةً طَيِّبَةً كَثيرةً مُبارَكَةً زاكِيَةً نامِيَةً ظاهِرَةً باطِنَةً شَريفَةً فاظِلَةً، تُبَيِّنُ بِها فَضْلَهُمْ عَلَى الاَوَّلينَ وَالاخِرِينَ، اَللّـهُمَّ اعْطِ مُحَمَّداً الْوَسيلَةَ وَالشَّرَفَ وَالْفَضيلَةَ واجْزِهِ خَيْرَ ما جَزَيْتَ نَبِيّاً عَنْ اُمَّتِهِ، اَللّـهُمَّ وَاَعْطِ مُحَمَّداً صَلَّى اللهُ عَلَيْهِ وَآلِهِ مَعَ كُلِّ زُلْفَة زُلْفَةً، وَمَعَ كُلِّ وَسيلَة وَسيلَةً، وَمَعَ كُلِّ فَضيلَة فَضيلَةً، وَمَعَ كُلِّ شَرَف شَرَفَاً تُعْطي اَللّـهُمَّ أعْطِ مُحَمَّداً وَآلَهُ يَوْمَ الْقِيامَةِ اَفْضَلَ ما اَعْطَيْتَ اَحَداً مِنَ الاَوَّلينَ والاخِرِينَ، اَللّـهُمَّ وَاجْعَلْ مُحَمَّداً صَلَّى اللهُ عَلَيْهِ وآلِهِ اَدْنَى الْمُرْسَلينَ مِنْكَ مَجْلِساً، وَأفْسَحَهُمْ فِى الْجَنَّةِ عِنْدَكَ مَنْزِلاً، وَاَقْرَبَهُمْ اِلَيْكَ وَسيلَةً، وَاْجْعَلْهُ اَوَّلَ شافِع، وَاَوَّلَ مُشَفَّع، وَاَوَّلَ قائِل، وَاَنْجَحَ سائِل، وَابْعَثْهُ الْمَقامَ الَْمحْمُودَ الَّذي يَغْبِطُهُ بِهِ الاَوَّلُونَ والاخِرُونَ يا اَرْحَمَ الرّاحِمينَ، وَاَسْاَلُكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاَنْ تَسْمَعَ صَوْتي وَتُجيبَ دَعْوَتي، وَتَجاوَزَ عَنْ خَطيئَتي، وَتَصْفَحَ عَنْ ظُلْمي، وَتُنْجِحَ طَلِبَتي، وَتَقْضِيَ حاجَتي، وَتُنْجِزَ لي ما وَعَدْتَني، وَتُقيلَ عَثْرَتي، وَتَغْفِرَ ذُنُوبي، وَتَعْفُوَ عَنْ جُرْمي، وَتُقْبِلَ عَلَيَّ وَلاتُعْرِضَ عَنّي، وَتَرْحَمَني وَلا تُعَذِّبَني وَتُعافِيَني وَلا تَبْتَلِيَني، وَتْرزُقَني مِنَ الرِّزْقِ اَطْيَبَهُ وَاَوْسَعَهُ وَلا تَحْرِمْني يا رَبِّ وَاقْضِ عَنّي دَيْني، وَضَعْ عَنّي وِزْري، وَلا تُحَمِّلْني ما لا طاقَةَ لي بِهِ، يامَوْلايَ اَدْخِلْني في كُلِّ خَيْر اَدْخَلْتَ فيهِ مُحَمَّداً وآلَ مُحَمَّد، وَاَخْرِجْني مِنْ كُلِّ سُوء اَخْرَجْتَ مِنْهُ مُحَمَّداً وَآلَ مُحَمَّد، صَلَواتُكَ عَلَيْهِ وَعَلَيْهِمْ، وَالسَّلامُ عَلَيْهِ وَعَلَيْهِمْ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ ."},{"type":"Text","content":"ثمّ قل ثلاثاً : اَللّـهُمَّ اِنّي اَدْعُوكَ كَما اَمَرْتَني فَاسْتَجِبْ لي كَما وَعَدْتَني (ثمّ قل) اَللّـهُمَّ اِنّي اَسْاَلُكَ قَليلاً مِنْ كَثير مَعَ حاجَة بي اِلَيْهِ عَظيمَة، وَغِناكَ عَنْهُ قَديمٌ، وَهُوَ عِنْدي كَثيرٌ، وَهُوَ عَلَيْكَ سَهْلٌ يَسيرٌ، فَامْنُنْ عَلَيَّ بِهِ اِنَّكَ عَلى كُلِّ شَيء قَديْرٌ، آمينَ رَبَّ الْعالَمينَ ."},{"type":"Text","content":"الخامس : أن يدعو بهذا الدّعاء اَللّـهُمَّ اِنِّي اَدْعُوكَ كَما اَمَرْتَني فَاسْتَجِبْ لي كَما وَعَدْتَني وقد تركناه لطوله فليطلب من كتاب الاقبال أو من زاد المعاد ."},{"type":"Text","content":"السّادس : روى المفيد في المقنعة عن الثّقة الجليل عليّ بن مهزيار عن الامام محمّد التّقي (عليه السلام) انّه يستحبّ أن تكثر في شهر رمضان في ليله ونهاره من أوّله الى آخره :"},{"type":"Text","content":"يا ذَا الَّذي كانَ قَبْلَ كُلِّ شَيء، ثُمَّ خَلَقَ كُلَّ شَيء، ثُمَّ يَبْقى وَيَفْنى كُلُّ شَيء، يا ذَا الَّذي لَيْسَ كَمِثْلِهِ شيءٌ، وَيا ذَا الَّذي لَيْسَ فِي السَّماواتِ الْعُلى، وَلا فِى الاَرَضينَ السُفْلى، وَلا فَوقَهُنَّ وَلا تَحْتَهُنَّ، وَلا بَيْنَهُنَّ اِلـهٌ يُعْبَدُ غَيْرُهُ لَكَ الْحَمْدُ حَمْداً لا يَقْوى عَلى اِحْصائِهِ إلاّ اَنْتَ، فَصَلِّ عَلى مُحَمَّد وَآلِ مُحَمِّد صَلاةً لا يَقْوى عَلى اِحْصائِها إلاّ اَنْتَ ."},{"type":"Text","content":"السّابع : روى الكفعمي في البلد الامين وفي المصباح عن كتاب اختيار السّيد ابن باقي انّ من قرأ هذا الدّعاء في كلّ يوم من رمضان غفر الله له ذنوب أربعين سنة اَللّـهُمَّ رَبَّ شَهْرِ رَمَضانَ الَّذي اَنْزَلْتَ فيهِ الْقُرْآنَ، وَافْتَرَضْتَ عَلى عِبادِكَ فيهِ الصِّيامَ، ارْزُقْني حَجَّ بَيْتِكَ الْحَرامِ في هذَا الْعامِ وَفي كُلِّ عام، وَاغْفِرْ لِيَ الذُّنُوبَ الْعِظامَ فَاِنَّهُ لا يَغْفِرُها غَيْرُكَ يا ذَا الْجَلالِ وَالاِْكْرامِ ."},{"type":"Text","content":"الثّامن : أن يذكر الله تعالى في كلّ يوم مائة مرّة بهذه الاذكار التي أوردها المحدّث الفيض في كتاب خلاصة الاذكار سُبْحانَ الضّارِّ النّافِعِ، سُبْحانَ الْقاضي بالْحَقِّ، سُبْحانَ الْعَلِيِّ الاعْلى، سُبْحانَهُ وَبِحَمْدِهِ، سُبْحانَهُ وَتَعالى ."},{"type":"Text","content":"التّاسع : قال المفيد في المقنعة: انّ من سُنن شهر رمضان الصّلاة على النّبي (صلى الله عليه وآله وسلم) في كلّ يوم مائة مرّة، والافضل أن يزيد عليها ."},{"type":"Text","content":"اللّيلة الاُولى"}],"preview":"اَللّـهُمَّ اِنّي اَسْاَلُكَ مِنْ فَضْلِكَ بِاَفْضَلِهِ وَكُلُّ فَضْلِكَ فاضِلٌ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِفَضْلِكَ كُلِّه، اَللّـهُمَّ اِنّي اَسْاَلُكَ مِنْ رِزْقِكَ بِاَعَمّ","hasTranslate":false},{"id":"mf_ar_128","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"وفيها أعمال :","blocks":[{"type":"Text","content":"الاوّل : الاستهلال وقد أوجبه بعض العلماء ."},{"type":"Text","content":"الثّاني : اذا رأيت هلال شهر رمضان فلا تشر اليه ولكن استقبل القبلة وارفع يديك الى السّماء وخاطب الهلال تقول :"},{"type":"Text","content":"رَبّي وَرَبُّكَ اللهُ رَبُّ الْعالَمينَ، اَللّـهُمَّ اَهِلَّهُ عَلَيْنا بِالاَْمْنِ وَالاِيمانِ، وَالسَّلامَةِ وَالاِسْلامِ، وَالْمُسارَعَةِ اِلى ما تُحِبُّ وَتَرْضى، اَللّـهُمَّ بارِكْ لَنا في شَهْرِنا هذا، وَارْزُقْنا خَيْرَهُ وَعَوْنَهُ، وَاصْرِفْ عَنّا ضُرَّهُ وَشَرَّهُ وَبلاءَهُ وَفِتْنَتَهُ ."},{"type":"Text","content":"وروي انّ رسول الله (صلى الله عليه وآله وسلم) كان اذا استهلّ هلال شهر رمضان استقبل القبلة بوجهه وقال :"},{"type":"Text","content":"اَللّـهُمَّ اَهِلَّهُ عَلَيْنا بِالاَْمْنِ والاِيمانِ، وَالسَّلامَةِ وَالاِسْلامِ، وَالْعافِيَةِ الُْمجَلَّلَةِ وَدِفاعِ الاَسْقامِ، وَالْعَوْنِ َعَلَى الصَّلاةِ وَالصِّيامِ وَالْقِيامِ وَتِلاوَةِ الْقُرآنِ، اَللّـهُمَّ سَلَّمْنا لِشَهْرِ رَمَضانَ وَتَسَلِّمْهُ مِّنا، وَسَلِّمْنا فيهِ حَتّى يَنْقَضِيَ عَنّا شَهْرُ رَمَضانَ وَقَدْ عَفَوْتَ عَنّا وَغَفَرْتَ لَنا وَرَحِمْتَنا ."},{"type":"AboutText","content":"وعن الصّادق (عليه السلام) قال : اذا رأيت الهلال فقل :"},{"type":"Text","content":"اَللّـهُمَّ قَدْ حَضَرَ شَهْرُ رَمَضانَ، وَقَدِ افْتَرَضْتَ عَلَيْنا صِيامَهُ، وَاَنْزَلْتَ فيهِ الْقُرآنَ هُدىً لِلنّاسِ وَبَيِّنات مِنَ الْهُدى وَالْفُرْقانِ، اَللّـهُمَّ اَعِنّا عَلى صِيامِهِ وَتَقَبَّلْهُ مِنّا، وَسَلِّمْنا فيهِ، وَسَلِّمْنا مِنْهُ وَسَلَّْمُهَ لَنا في يُسْر مِنَكَ وَعافِيَة اِنَّكَ عَلى كُلِّ شَيْء قَديرٌ، يا رَحْمنُ يا رَحيمُ ."},{"type":"Text","content":"الثّالث : أن يدعو اذا شاهد الهلال بالدّعاء الثّالث والاربعين من دعوات الصحيفة الكاملة ، روى السيّد ابن طاووس انّ عليّ بن الحسين (عليه السلام) مرّ في طريقه يوماً فنظر الى هلال شهر رمضان فوقف فقال :"},{"type":"Text","content":"اَيُّهَا الْخَلْقُ الْمُطيعُ الدّائِبُ السَّريعُ، الْمُتَرَدِّدُ في مَنازِلِ التَّقْديرِ، الْمُتَصَرِّفُ في فَلَكِ التَّدْبيرِ، آمَنْتُ بِمَنْ نَوَّرَ بِكَ الظُّلَمَ، وَاَوْضَحَ بِكَ الْبُهَمَ، وجَعَلَكَ آيَةً مِنْ آياتِ مُلْكِهِ، وَعَلامَةً مِنْ عَلاماتِ سُلْطانِهِ، فَحَدَّ بِكَ الزَّمانَ، وامْتَهَنَكَ بِالْكَمالِ وَالنُّقْصانِ، وَالطُّلُوعِ والاُفُولِ، وَالاِنارَةِ والْكُسُوفِ، في كُلِّ ذلِكَ اَنْتَ لَهُ مُطيعٌ، وَاِلَى اِرادَتِهِ سَريعٌ، سُبْحانَهُ ما اَعْجَبَ ما دَبَّرَ مِنْ اَمْرِكَ، وَاَلْطَفَ ما صَنَعَ في شَأنِكَ، جَعَلَك مِفْتاحَ شَهْر حادِث لاَمْر حادِث، فَاَسأَلُ اللهَ رَبِّي وَرَبَّكَ، وَخالِقي وَخالِقَكَ، وَمُقَدِّري وَمُقَدِّرَكَ، وَمُصَوِّري وَمُصَوِّرَكَ اَنْ يُصَلِّيَ عَلى مُحَمَّد وآلِ مُحَمَّد، وَاَنْ يَجْعَاَلك هِلالَ بَرَكة لا تَمْحَقُها الاَيامُ، وَطَهارَة لا تُدَنِّسُهَا الاثامُ، هِلالَ اَمْن مِنَ الافاتِ، وَسَلامَة مِنَ السَّيِّئاتِ، هِلالَ سَعْد لا نَحْسَ فيهِ يُمْن لا نَكَدَ مَعَهُ، وَيُسْر لا يُمازِجُهُ عُسْرٌ، وَخَيْر لا يَشُوبُهُ شَرٌّ، هِلالَ اَمْن وَايمان وَنِعْمَة وَاِحْسان وَسَلامَة وَاِسْلام، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاجْعَلْنا مِنْ اَرْضى مَنْ طَلَعَ عَلَيْهِ، وَاَزْكى مَنْ نَظَرَ اِلَيْهِ، وَاَسْعَدَ مَنْ تَعَبَّدَ لَكَ فيهِ، وَوَفِّقْنَا اَللّـهُمَّ فيهِ لِلطّاعَةِ وَالتَّوْبَةِ، وَاعْصِمْنا فيهِ مِنَ الاثامِ وَالْحَوبَةِ، وَاَوْزِعْنا فيهِ شُكْرَ النِّعْمَةِ، واَلْبِسْنا فيهِ جُنَنَ الْعافِيَةِ، وَاَتْمِمْ عَلَيْنا بِاسْتِكْمالِ طاعَتِكَ فيهِ الْمِنَّةَ، اِنَّكَ اَنْتَ الْمَنّانُ الْحَميدُ، وَصَلَّى اللهُ عَلى مُحَمَّد وآلِهِ الطَيِّبينَ، وَاجْعَلْ لَنا فيهِ عَوناً مِنْكَ عَلى ما نَدَبْتَنا اِلَيْهِ مِنْ مُفْتَرَضِ طاعَتِكَ، وَتَقَبَّلْها اِنَّكَ الاَكْرَمُ مِنْ كُلِّ كَريم، وَالاَرْحَمُ مِنْ كُلِّ رَحيم، آمينَ آمينَ رَبَّ الْعالَمينَ ."},{"type":"Text","content":"الرّابع : يستحبّ أن يأتي أهله وهذا ممّا خصّ به هذا الشّهر ويكره ذلك في أوائل سائر الشّهور ."},{"type":"Text","content":"الخامس : الغُسل ، ففي الحديث انّ من اغتسل اوّل ليلة منه لم يصبه الحكّة الى شهر رمضان القابل ."},{"type":"Text","content":"السّادس : أن يغتسل في نهر جار ويصبّ على رأسه ثلاثين كفّاً من الماء ليكون على طهر معنوي الى شهر رمضان القابل ."},{"type":"Text","content":"السّابع : أن يزور قبر الحسين (عليه السلام) لتذهب عنه ذنوبه ويكون له ثواب الحجّاج والمعتمرين في تلك السّنة ."},{"type":"Text","content":"الثّامن : أن يبدأ في الصّلاة ألف ركعة الواردة في هذا الشّهر التي مرّت في أواخر القسم الثّاني من أعمال هذا الشّهر ."},{"type":"Text","content":"التّاسع : أن يصلّي ركعتين في هذه اللّيلة يقرأ في كلّ ركعة الحمد وسورة الانعام ويسأل الله تعالى أن يكفيه ويقيه المخاوف والاسقام ."},{"type":"Text","content":"العاشر : أن يدعُو بدعاء اَللّـهُمَّ اِنَّ هذَا الشَّهْرَ الْمُبارَكَ الذي ذكرناه في آخر ليلة من شعبان ."},{"type":"Text","content":"الحادي عشر : أن يرفع يديه اذا فرغ من صلاة المغرب ويدعو بهذا الدّعاء المرويّ في الاقبال عن الامام الجواد (عليه السلام) :"},{"type":"Text","content":"اَللّـهُمَّ يا مَنْ يَمْلِكُ التَّدْبيرَ وَهُوَ عَلى كُلِّ شَيء قَديرٌ، يا مَنْ يَعْلَمُ خائِنَةَ الاَعْيُنِ وَما تُخْفِي الصُّدُورِ وَتُجِنُّ الضَّميرُ وَهُوَ اللَّطيفُ الْخَبيرُ، اَللّـهُمَّ اجْعَلْنا مِمَّنْ نَوى فَعَمِلَ، وَلا تَجْعَلْنا مِمَّنْ شَقِيَ فَكَسِلَ، وَلا مِمَّنْ هُوَ عَلى غَيْرِ عَمَل يَتَّكِلُ، اَللّـهُمَّ صَحِّحْ اَبْدانَنا مِنَ الْعِلَلِ، وَاَعِنّا عَلى ما افْتَرَضْتَ عَلَيْنا مِنَ الْعَمَلِ، حَتّى يَنْقَضِيَ عَنّا شَهْرُكَ هذا وَقَدْ اَدَّيْنا مَفْرُوضَكَ فيهِ عَلَيْنا، اَللّـهُمَّ اَعِنّا عَلى صِيامِهِ، وَوَفِّقْنا لِقِيامِهِ، وَنَشِّطْنا فيهِ لِلصَّلاةِ، وَلا تَحْجُبْنا مِنَ الْقِراءَةِ، وَسَهِّلْ لَنا فيهِ ايتاءَ الزَّكاةِ، اَللّـهُمَّ لا تُسَلِّطْ عَلَيْنا وَصَباً وَلا تَعَباً وَلا سَقَماً وَلا عَطَباً، اَللّـهُمَّ ارْزُقْنا الاِفْطارَ مِنْ رِزْقِكَ الْحلالِ، اَللّـهُمَّ سَهِّلْ لَنا فيهِ ما قَسَمْتَهُ مِنْ رِزْقِكَ، وَيَسِّرْ ما قَدَّرْتَهُ مِنْ اَمْرِكَ، وَاجْعَلْهُ حَلالاً طَيِّباً نَقِيّاً مِنَ الاثامِ خالِصاً مِنَ الاصارِ وَالاَجْرامِ، اَللّـهُمَّ لا تُطْعِمْنا اِلاّ طَيِّباً غَيْرَ خَبيث وَلا حَرام، وَاجْعَلْ رِزْقَكَ لَنا حَلالاً لا يَشُوبُهُ دَنَسٌ وَلا اَسْقامٌ يا مَنْ عِلْمُهُ بِالسِّرِّ كَعِلْمِهِ باِلاِعْلانِ، يا مُتَفَضِّلاً عَلى عِبادِهِ بِالاِحْسانِ، يا مَنْ هُوَ عَلى كُلِّ شَيء قَديرٌ وَبِكُلِّ شَيء عَليمٌ خَبيرٌ اَلْهِمْنا ذِكْرَكَ وَجَنِّبْنا عُسْرَكَ، وَاَنِلْنا يُسْرَكَ، وَاَهْدِنا لِلرَّشادِ، وَوَفِّقْنا لِلسَّدادِ، وَاعْصِمْنا مِنَ الْبَلايا، وَصُنّا مِنَ الاَوْزارِ وَالْخَطايا، يا مَنْ لا يَغْفِرُ عَظيمَ الذُّنُوبِ غَيْرُهُ، وَلا يَكْشِفُ السُّوءَ إلاّ هُوَ، يا اَرْحَمَ الرّاحِمينَ، وَاَكْرَمَ الاَكْرَمينَ، صَلِّ عَلى مُحَمَّد وَاَهْلِ بَيْتِهِ الطَّيِّبينَ، وَاجْعَلْ صِيامَنا مَقْبُولاً، وَبِالْبِرِّ وَالتَّقْوى مَوْصُولاً، وَكَذلِكَ فَاجْعَلْ سَعْيَنا مَشْكُوراً وَقِيامَنا مَبْرُوراً، وَقُرْآنَنا مَرْفُوعاً، وَدُعاءَنا مَسْمُوعاً، وَاهْدِنا لِلْحُسْنى، وَجَنِّبْنَا الْعُسْرى، وَيَسِّرْنا لِلْيُسْرى، وَاَعِلْ لَنَا الدَّرَجاتِ، وَضاعِفْ لَنا الْحَسَناتِ، وَاقْبَلْ مِنَّا الصَّوْمَ وَالصَّلاةَ، واسْمَعْ مِنَّا الدَّعَواتِ، وَاغْفِرْ لَنَا الْخَطيئاتِ، وَتَجاوَزْ عَنَّا السَّيِّئاتِ، وَاجْعَلْنا مِنَ الْعامِلينَ الْفائِزينَ، وَلا تَجْعَلْنا مِنَ الْمَغْضُوبِ عَلَيْهِمْ وَلاَ الضّالّينَ، حَتّى يَنْقَضِيَ شَهْرُ رَمَضانَ عَنّا وَقَدْ قَبِلْتَ فيهِ صِيامَنا وَقِيامَنا، وَزَكَّيْتَ فيهِ اَعْمالَنا، وَغَفَرْتَ فيهِ ذُنوبَنا، وَاَجْزَلْتَ فيهِ مِنْ كُلِّ خَيْر نَصيبَنا، فَاِنَّكَ الاِْلـهُ الُْمجيبُ، وَالرَّبُّ الْقَريبُ، وَاَنْتَ بِكُلِّ شَيْء مُحيطٌ ."},{"type":"Text","content":"الثّاني عشر : أن يدعو بهذا الدّعاء المأثور عن الصّادق (عليه السلام) المروي في كتاب الاقبال :"},{"type":"Text","content":"اَللّـهُمَّ رَبَّ شَهْرِ رَمَضانَ، مُنَزِّلَ الْقُرْآنِ، هذا شَهْرُ رَمَضانَ الَّذي اَنْزَلْتَ فيهِ الْقُرْآنَ، وَاَنْزَلْتَ فيهِ آيات بَيِّنات مِنَ الْهُدى وَالْفُرْقانِ، اَللّـهُمَّ ارْزُقْنا صِيامَهُ، وَاَعِنّا عَلى قِيامِهِ، اَللّـهُمَّ سَلِّمْهُ لَنا وَسَلِّمْنا فيهِ وَتَسَلَّمْهُ مِنّا في يُسْر مِنَكَ وَمُعافاة، وَاجْعَلْ فيـما تَقْضي وَتُقَدِّرُ مِنَ الاَمْرِ الَْمحْتُومِ وَفيـما تَفْرُقُ مِنَ الاَمْرِ الْحَكيمِ في لَيْلَةِ الْقَدْرِ مِنَ الْقَضاءِ الَّذي لا يُرَدُّ وَلا يُبَدَّلُ، اَنْ تَكْتُبَني مِنْ حُجّاجِ بَيْتِكَ الْحَرامِ الْمَبْرُورِ حَجُّهُمُ، الْمَشْكُورِ سَعْيُهُمُ، الْمَغْفُورِ ذُنُوبُهُمُ، الْمُكَفَّرِ عَنْهُمْ سَيِّئاتُهُمْ، وَاجْعَلْ فيـما تَقْضي وَتُقَدِّرُ اَنْ تُطيلَ عُمْري وَتُوَسِّعَ عَليَّ مِنَ الرِّزْقِ الْحَلالِ ."}],"preview":"الاوّل : الاستهلال وقد أوجبه بعض العلماء .","hasTranslate":false},{"id":"mf_ar_129","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"الثّالث عشر : أن يدعو بالدّعاء الرابع والاربعين من أدعية الصّحيفة الكاملة","blocks":[{"type":"Text","content":"الرّابع عشر : أن يدعو بالدّعاء الطّويل اَللّـهُمَّ اِنَّه قَد دَخَلَ شَهْرُ رَمَضانَ ... الخ ، الذي رواه السيّد في الاقبال ."},{"type":"Text","content":"الخامس عشر : يقول : اَللّـهُمَّ اِنَّ هذا شَهْرُ رَمَضانَ اَللّـهُمَّ رَبَّ شَهْرِ رَمَضانَ، الَّذي اَنزَلْتَ فيهِ الْقُرْآنَ، وَجَعَلْتَهُ بَيِّنات مِنَ الْهُدى وَالْفُرْقانِ، اَللّـهُمَّ فَبارِكْ لَنا في شَهْرِ رَمَضانَ، وَاَعِنّا عَلى صِيامِهِ وَصَلَواتِهِ وَتَقَبَّلْهُ مِنّا، ففي الحديث انّ النّبي (صلى الله عليه وآله وسلم)كان اذا دخل شهر رمضان دعا بهذا الدّعاء ."},{"type":"Text","content":"السّادس عشر : عن النّبي (صلى الله عليه وآله وسلم) ايضاً انّه كان يدعو في أوّل ليلة من شهر رمضان فيقول :"},{"type":"Text","content":"اَلْحَمْد للهِ الَّذي اَكْرَمَنا بِكَ اَيُّهَا الشَّهرُ الْمُبارَكُ، اَللّـهُمَّ فَقَوِّنا عَلى صِيامِنا وَقِيامِنا، وَثبِّتْ اَقْدامَنا وَانْصُرْنا عَلَى الْقَوْمِ الْكافِرينَ، اَللّـهُمَّ اَنْتَ الْواحِدُ فَلا وَلَدَ لَكَ، واَنْتَ الصَّمَدُ فلا شِبْهَ لَكَ، واَنْتَ الْعَزيزُ فَلا يُعِزُّكَ شَيْءٌ، وَاَنْتَ الْغَنِيُّ وَاَنَا الْفَقير، وَاَنْتَ الْمَوْلى وَاَنا الْعَبْدُ، واَنْتَ الْغُفورُ وَاَنا الْمُذْنِبُ، وَاَنْتَ الرَّحيمُ وَاَنَا الُْمخْطِئُ، وَاَنْتَ الْخالِقُ وَاَنَا الَْمخْلُوقُ، وَاَنْتَ الْحَيُّ وَاَنَا الْمَيِّتُ، اَسْاَلُكَ بِرَحْمَتِكَ اَنْ تَغْفِرَ لي وَتَرْحَمَني، وَتَجاوَزَ عَنّي اِنَّكَ عَلى كُلِّ شَيْء قَديرٌ ."},{"type":"Text","content":"السّابع عشر : قد مرّ في الباب الاوّل من الكتاب استحباب أن يدعو بدعاء الجوشن الكبير في أوّل ليلة من رمضان ."}],"preview":"الرّابع عشر : أن يدعو بالدّعاء الطّويل اَللّـهُمَّ اِنَّه قَد دَخَلَ شَهْرُ رَمَضانَ ... الخ ، الذي رواه السيّد في الاقبال .","hasTranslate":false},{"id":"mf_ar_130","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"الثّامن عشر : أن يدعو بدعاء الحجّ الذي مرّ في أوّل الشّهر","blocks":[{"type":"Text","content":"التّاسع عشر : ينبغي الاكثار من تلاوة القرآن اذا دخل شهر رمضان، وروي انّ الصّادق (عليه السلام) كان يقول قبلما يتلو القرآن :"},{"type":"Text","content":"اَللّـهُمَّ اِنّي اَشْهَدُ اَنَّ هذا كِتابُكَ الْمُنْزَلُ مِنْ عِنْدِكَ عَلى رَسُولِكَ مُحَمَّدِ بْنِ عَبْدِاللهِ صَلَّى اللهُ عَلَيْهِ وآلِهِ، وَكَلامُكَ النّاطِقُ عَلى لِسانِ نَبِيِّكَ، جَعَلْتَهُ هادِياً مِنْكَ اِلى خَلْقِكَ، وَحَبْلاً مُتَّصِلاً فيـما بَيْنَكَ وَبَيْنَ عِبادِكَ، اَللّـهُمَّ اِنّي نَشَرْتُ عَهْدَكَ وَكِتابَكَ، اَللّـهُمَّ فَاجْعَلْ نَظَري فيهِ عِبادَةً، وَقِراءَتي فيهِ فِكْراً، وَفِكْري فيهِ اعْتِباراً، وَاجْعَلْني مِمَّنْ اتَّعَظَ بِبَيانِ مَواعِظِكَ فيهِ، وَاجْتَنَبَ مَعاصيكَ، وَلا تَطْبَعْ عِنْدَ قِراءَتي عَلى سَمْعي، وَلا تَجْعَلْ عَلى بَصَري غِشاوَةً، وَلا تَجْعَلْ قِراءَتي قِراءَةً لا تَدَبُّرَ فيها، بَلِ اجْعَلْني اَتَدَبَّرُ آياتِهِ وَاَحْكامَهُ، آخِذاً بِشَرايِعِ دينِكَ، وَلا تَجْعَلْ نَظَري فيهِ غَفْلَةً، وَلا قِراءَتي هَذَراً، اِنَّكَ اَنْتَ الرَّؤوفُ الرَّحيمُ ."}],"preview":"التّاسع عشر : ينبغي الاكثار من تلاوة القرآن اذا دخل شهر رمضان، وروي انّ الصّادق (عليه السلام) كان يقول قبلما يتلو القرآن :","hasTranslate":false},{"id":"mf_ar_131","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"ويقول بعدما فرغ من تلاوته :","blocks":[{"type":"Text","content":"اَللّـهُمَّ اِنّي قَدْ قَرَأتُ ما قَضَيْتَ مِنْ كِتابِكَ الَّذي اَنْزَلْتَهُ عَلى نَبِيِّكَ الصّادِقِ صَلَّى اللهُ عَلَيْهِ وَآلِهِ، فَلَكَ الْحَمْدُ رَبَّنا، اَللّـهُمَّ اجْعَلْني مِمَّنْ يُحِلُّ حَلالَهُ، وَيُحَرِّمُ حَرامَهُ، وَيُؤْمِنُ بِمُحْكَمِهِ وَمُتَشابِهِه، وَاجْعَلْهُ لي اُنْساً في قَبْري، وَاُنْساً في حَشْري، وَاجْعَلْني مِمَّنْ تُرْقيهِ بِكُلِّ آيَة قَرَأها دَرَجَةً في اَعْلا عِلِّيّينَ، آمينَ رَبَّ الْعالَمينَ ."},{"type":"Text","content":"اليَوْمُ الاوّل"}],"preview":"اَللّـهُمَّ اِنّي قَدْ قَرَأتُ ما قَضَيْتَ مِنْ كِتابِكَ الَّذي اَنْزَلْتَهُ عَلى نَبِيِّكَ الصّادِقِ صَلَّى اللهُ عَلَيْهِ وَآلِهِ، فَلَكَ الْحَمْدُ رَبَّنا، اَللّـهُمَّ اجْعَلْني","hasTranslate":false},{"id":"mf_ar_132","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"وفيه أعمال :","blocks":[{"type":"Text","content":"الاوّل : أن يغتسل في ماء جار ويصبّ على رأسه ثلاثين كفّاً من الماء، فانّ ذلك يورث الامن من جميع الالام والاسقام في تلك السّنة ."},{"type":"Text","content":"الثّاني : أن يغسل وجهه بكفّ من ماء الورد لينجو من المذلّة والفقر وأن يصب شيئاً منه على رأسه ليأمن من السِرسام ."}],"preview":"الاوّل : أن يغتسل في ماء جار ويصبّ على رأسه ثلاثين كفّاً من الماء، فانّ ذلك يورث الامن من جميع الالام والاسقام في تلك السّنة .","hasTranslate":false},{"id":"mf_ar_133","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"الثّالث : أن يؤدي ركعتي صلاة اوّل الشّهور والصّدقة بعدهما","blocks":[{"type":"Text","content":"الرّابع : أن يصلّي ركعتين يقرأ في الاُولى الحمد وسورة انّا فتحنا، وفي الثّانية الحمد وما شاء من السّور ليدرأ الله عنه كلّ سوء ويكون في حفظ الله الى العام القادم ."},{"type":"Text","content":"الخامس : أن يقول اذا طلع الفجر :"},{"type":"Text","content":"اَللّـهُمَّ قَدْ حَضَرَ شَهْرُ رَمَضانَ، وَقَدِ افْتَرَضْتَ عَلَيْنا صِيامَهُ، وَاَنْزَلْتَ فيهِ الْقُرآنَ هُدىً لِلنّاسِ وَبَيِّنات مِنَ الْهُدى وَالْفُرْقانِ، اَللّـهُمَّ اَعِنّا عَلى صِيامِهِ، وَتَقَبَّلْهُ مِنّا وَتَسَلَّمْهُ مِنّا وَسَلِّمْهُ لَنا في يُسْر مِنَكَ وَعافِيَة اِنَّكَ عَلى كُلِّ شَيْء قَديرٌ ."},{"type":"Text","content":"السّادس : أن يدعو بالدّعاء الرّابع والاربعين من أدهية الصّحيفة الكاملة إن لم يدع به ليلاً ."},{"type":"Text","content":"السّابع : قال العلاّمة المجلسي في كتاب زاد المعاد : روى الكليني والطّوسي وغيرهما بسند صحيح عن الامام موسى الكاظم (عليه السلام) قال : ادع بهذا الدّعاء في شهر رمضان في اوّل السّنة، أي اليوم الاوّل من الشّهر على ما فهمه العلماء وقال (عليه السلام) : من دعا الله تعالى خلواً من شوائب الاغراض الفاسدة والرّياء لم تصبه في ذلك العام فتنة ولا ضلالة ولا آفة يضرّ دينه أو بدنه، وصانه الله تعالى من شرّ ما يحدث في ذلك العام من البلايا، وهو هذا الدّعاء :"},{"type":"Text","content":"اَللّـهُمَّ اِنّي اَسْاَلُكَ بِإسْمِكَ الَّذي دانَ لَهُ كُلُّ شَيْء، وَبِرَحْمَتِكَ الَّتي وَسِعَتْ كُلَّ شَيْء، وَبِعَظَمَتِكَ الَّتي تَواضَعَ لَها كُلُّ شَيْء، وَبِعِزَّتِكَ الَّتي قَهَرَتْ كُلَّ شَيْء، وَبِقُوَّتِكَ الَّتي خَضَعَ لَها كُلُّ شَيْء، وَبِجَبَرُوتِكَ الَّتي غَلَبَتْ كُلَّ شَىْء، وَبِعِلْمِكَ الَّذي اَحاطَ بِكُلِّ شَيْء، يا نُورُ يا قُدُّوسُ، يا اَوَّلَ قبْلَ كُلِّ شَيْء، وَيا باقِياً بَعْدَ كُلِّ شَيْء، يا اَللهُ يا رَحْمنُ، صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاغْفِرْ لِيَ الذُّنُوبَ الَّتي تُغَيِّرُ النِّعَمَ، وَاغْفِرْ لِيَ الذُّنُوبَ الَّتي تُنْزِلُ النِّقَمَ، وَاغْفِرْ لِيَ الذُّنُوبَ الَّتي تَقْطَعُ الرَّجاءَ، وَاغْفِرْ لايَ ِلذُّنُوبَ الَّتي تُديلُ الاَعْداءَ، وَاغْفِرْ لِيَ الذُّنُوبَ الَّتى تَرُدُّ الدُّعاءَ، وَاغْفِرْ لِيَ الذُّنُوبَ الَّتي يُسْتَحَقُّ بِها نُزُولُ الْبَلاءِ وَاغْفِرْ لِيَ الذُّنُوبَ الَّتي تَحْبِسُ غَيْثَ السَّماءِ، وَاغْفِرْ لِيَ الذُّنُوبَ الَّتي تَكْشِفُ الْغِطاءَ، وَاغْفِرْ لِيَ الذُّنُوبَ الَّتي تُعَجِّلُ الْفَناءَ، وَاغْفِرْ لِيَ الذُّنُوبَ الَّتي تُورِثُ النَّدَمَ، وَاغْفِرْ لِيَ الذُّنُوبَ الَّتي تَهْتِكُ الْعِصَمَ، وَاَلْبِسْني دِرْعَكَ الْحَصينَةَ الَّتي لا تُرامُ، وَعافِني مِنْ شَرِّ ما اُحاذِرُ بِاللَّيْلِ وَالنَّهارِ في مُسْتَقْبِلِ سَنَتي هذِهِ، اَللّـهُمَّ رَبَّ السَّماواتِ السَّبْعِ، وَرَبَّ الاَرَضينَ السَّبْعِ وَما فيهِنَّ وَما بَيْنَهُنَّ، وَرَبَّ الْعَرْشِ الْعَظيمِ، وَرَبَّ السْبْعِ الْمَثاني، وَالْقُرْآنِ الْعَظيمِ، وَرَبَّ اِسْرافيلَ وَميكائيلَ وَجَبْرائيلَ، وَرَبَّ مُحَمَّد صَلَّى اللهُ عَلَيْهِ وَآلِهِ سَيِّدِ الْمُرْسَلينَ وَخاتَمِ النَّبِيّينَ، اَسْاَلُكَ بكَ وَبِما سَمَّيْتَ بهِ نَفْسَكَ يا عَظيمُ، اَنْتَ الَّذي تَمُنَّ بِالْعَظيمِ، وَتَدْفَعُ كُلَّ مَحْذُور، وَتُعْطي كُلَّ جَزِيل، وَتُضاعِفُ الْحَسَناتِ بِالْقَليلِ وَبِالْكَثيرِ، وَتَفْعَلُ ما تَشاءُ يا قَديرُ يا اَللهُ يا رَحْمن، صَلِّ عَلى مُحَمَّد وَاَهْلِ بَيْتِهِ، وَاَلْبِسْني في مُسْتَقْبَلِ سَنَتي هذِهِ سِتْرَكَ، وَنَضِّرْ وَجْهي بِنُورِكَ، وَاَحِبَّني بِمَحبَّتِكَ، وَبَلِّغْني رِضْوانَكَ، وَشَريفَ كَرامَتِكَ، وَجَسيمَ عَطِيَّتِكَ، وَاَعْطِني مِنْ خَيْرِ ما عِنْدَكَ وَمِنْ خَيْرِ ما اَنْتَ مُعْطيهِ اَحَداً مِنْ خَلْقِكَ، وَاَلْبِسْني مَعَ ذلِكَ عافِيَتَكَ يا مَوْضِعَ كُلِّ شَكْوى، وَيا شاهِدَ كُلِّ نَجْوى، وَيا عالِمَ كُلِّ خَفِيَّة، وَيا دافِعَ ما تَشاءُ مِنْ بَلِيَّة، يا كَريمَ الْعَفْوِ، يا حَسَنَ التَّجاوُزِ، تَوَفَّني عَلى مِلَّةِ اِبْراهيمَ وَفِطْرَتِهِ، وَعَلى دينِ مُحَمَّد صَلَّى اللهُ عَلَيْهِ وآلِهِ وَسُنَّتِهِ، وَعَلى خَيْرِ الْوَفاةِ، فَتَوَفَّني مُوالِياً لاَِولِيائِكَ، وَمُعادِياً لاَِعْدائِكَ، اَللّـهُمَّ وَجَنِّبْني في هذِهِ السَّنَةِ كُلَّ عَمَل اَوْ قَوْل اَوْ فِعْل يُباعِدُني مِنْكَ، وَاَجْلِبْني اِلَى كُلِّ عَمَل اَوْ قَوْل اَوْ فِعْل يُقَرِّبُني مِنْكَ في هذِهِ السَّنَةِ يا اَرْحَمَ الرّاحِمينَ، وَامْنَعْني مِنْ كُلِّ عَمَل اَوْ قَوْل اَوْ فِعْل يَكُونُ مِنّي اَخافُ ضَرَرَ عاقِبَتهِ، وَاَخافُ مَقْتَكَ اِيّايَ عَلَيْهِ حِذارَ اَنْ تَصْرِفَ وَجْهَكَ الْكَريمَ عَنّي فَاَستَوجِبَ بِهِ نَقْصاً مِنْ حَظٍّ لي عِنْدَكَ يا رَؤوفُ يا رَحيمُ، اَللّـهُمَّ اجْعَلْني في مُسْتَقْبَلِ سَنَتي هذِهِ في حِفْظِكَ َوفي جِوارِكَ وَفي كَنَفِكَ، وَجَلِّلْني سِتْرَ عافِيَتِكَ، وَهَبْ لي كَرامَتَكَ، عَزَّ جارُكَ وَجَلَّ ثَناؤُكَ وَلا اِلـهَ غَيْرُكَ، اَللّـهُمَّ اجْعَلني تابِعاً لِصالِحي مَنْ مَضى مِنْ اَوْلِيائِكَ، وَاَلْحِقْني بِهِمْ وَاَجْعَلْني مُسْلِماً لِمَنْ قالَ بِالصِّدْقِ عَلَيْكَ مِنْهُمْ، وَاَعُوذُ بِكَ اَللّـهُمَّ اَنْ تُحيطَ بي خَطيئَتي وَظُلْمي وَاِسْرافي عَلى نَفْسي، وَاتِّباعي لِهَوايَ، واشْتِغالي بِشَهَواتي، فَيَحُولُ ذلِكَ بَيْني وَبَيْنَ رَحْمَتِكَ وَرِضْوانِكَ فَاَكُونُ مَنْسِيّاً عِنْدَكَ، مُتَعَرِّضاً لِسَخَطِكَ وَنِقْمَتِكَ، اَللّـهُمَّ وَفِّقْني لِكُلِّ عَمَل صالِح تَرْضى بِهِ عَنّي، وَقَرِّبْني اِلَيْكَ زُلْفى، اَللّـهُمَّ كَما كَفَيْتَ نَبيَّكَ مُحَمَّداً صَلَّى اللهُ عَلَيْهِ وآلِهِ هَوْلَ عَدُوِّهِ، وَفَرَّجْتَ هَمَّهُ، وَكَشَفْتَ غَمَّهُ، وَصَدَقْتَهُ، وَعْدَكَ، وَاْنجَزْتَ لَهُ عَهْدَكَ، اَللّـهُمَّ فَبِذلِكَ فَاكْفِني هَوْلَ هذهِ السَّنَةِ وَآفاتِها وَاَسقامَها وَفِتْنَتَها وَشُرُورَها وَاَحزانَها وَضيقَ الْمَعاشِ فيها، وَبَلِّغْني بِرَحْمَتِكَ كَمالَ الْعافِيَةِ بِتَمامِ دَوامِ النِّعْمَةِ عِنْدي اِلى مُنْتَهى اَجَلَي، اَسْاَلُكَ سُؤالَ مَنْ اَساءَ وَظَلَمَ وَاسْتَكانَ وَاعْتَرَفَ، وَاَسْأَلفكَ اَنْ تَغْفِرَ لي ما مَضى مِنَ الذُّنُوبِ الَّتي حَصْرَتَها حَفَظَتُكَ وَاَحْصَتْها كِرامُ مَلائِكَتِكَ عَلَيَّ، وَاَنْ تَعْصِمَني يا اِلـهي مِنَ الذُّنُوبِ فيـما بَقِيَ مِنْ عمْري اِلى مُنْتَهى اَجَلي، يا اَللهُ يا رَحْمنُ يا رَحيمُ، صَلِّ عَلَى مُحمَّد وَاَهْلِ بَيْتِ مُحَمَّد، وَآتِني كُلَّ ما سَاَلْتُكَ وَرَغِبْتُ اِلَيْكَ فيهِ، فَاِنكَ اَمَرْتَني بِالدُّعاءِ وَتَكَفَّلْتَ لي بِالاِجابَةِ يا اَرْحَمَ الرّاحِمينَ ."}],"preview":"الرّابع : أن يصلّي ركعتين يقرأ في الاُولى الحمد وسورة انّا فتحنا، وفي الثّانية الحمد وما شاء من السّور ليدرأ الله عنه كلّ سوء ويكون في حفظ الله الى العام القادم .","hasTranslate":false},{"id":"mf_ar_134","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"أقول : قد أورد السّيد هذا الدّعاء في اللّيلة الاُولى من هذا الشّهر","blocks":[{"type":"Text","content":"اليَومُ السّادس"},{"type":"Text","content":"في مثل هذا اليوم من سنة مائتين وواحدة بويع الامام الرّضا (عليه السلام)، وذكر السّيد انّه يصلّي فيها شكراً ركعتين يقرأ في كلّ ركعة بعد الحمد سورة الاخلاص خمساً وعشرين مرّة ."},{"type":"Text","content":"اللّيلة الثّالثة عشر"}],"preview":"اليَومُ السّادس","hasTranslate":false},{"id":"mf_ar_135","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"الاوّل : الغسل","blocks":[{"type":"Text","content":"الثّاني : الصّلاة أربع ركعات في كلّ ركعة الحمد مرّة والتّوحيد خمساً وعشرين مرّة ."},{"type":"Text","content":"الثّالث : صلاة ركعتين قد مرّ مثلها في اللّيلة الثّالثة عشرة من شهري رجب وشعبان تقرأ في كلّ ركعة منها بعد الفاتحة سورة يس وتبارك الملك والتّوحيد ."},{"type":"Text","content":"اللّيلة الرّابعة عشرة"},{"type":"Text","content":"وفي اللّيلة الرّابعة عشرة تصلّي مثل ذلك أربع ركعات بسلامين وقد قدّمنا عند ذكر دعاء المجير انّ من دعا به في الايّام البيض من شهر رمضان غفر له ذنوبه وإن كانت عدد قطر المطر وورق الشّجر ورمل البرّ ."},{"type":"Text","content":"اللّيلة الخامِسة عشرة"}],"preview":"الثّاني : الصّلاة أربع ركعات في كلّ ركعة الحمد مرّة والتّوحيد خمساً وعشرين مرّة .","hasTranslate":false},{"id":"mf_ar_136","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"الثّاني : زيارة الحسين (عليه السلام)","blocks":[{"type":"Text","content":"الثّالث : الصّلاة ستّ ركعات بالفاتحة ويس وتبارك والتّوحيد ."},{"type":"Text","content":"الرّابع : الصّلاة مائة ركعة يقرأ في كلّ ركعة بعد الفاتحة التّوحيد عشر مرّات ."},{"type":"Text","content":"روى الشّيخ المفيد في المقنعة عن أمير المؤمنين (عليه السلام) : انّ من أتى بها أرسل الله تعالى اليه عشرة املاك يدفعون عنه اعداءه من الجنّ والانس، ويرسل اليه ثلاثين ملكاً عند الموت يؤمّنونه من النّار ."},{"type":"Text","content":"الخامس : عن الصّادق (عليه السلام) انّه قيل له: ما ترى لمن حضر قبر الحسين (عليه السلام) ليلة النّصف من شهر رمضان ؟ فقال : بخّ بخّ من صلّى عند قبره ليلة النّصف من شهر رمضان عشر ركعات من بعد العشاء من غير صلاة اللّيل يقرأ في كلّ ركعة فاتحة الكتاب وقُلْ هُوَ اللهُ اَحَدٌ عشر مرّات واستجار بالله من النّار كتبه الله عتيقاً من النّار ولم يمت حتّى يرى في منامه ملائكة يبشّرونه بالجنّة وملائكة يؤمّنونه من النّار ."}],"preview":"الثّالث : الصّلاة ستّ ركعات بالفاتحة ويس وتبارك والتّوحيد .","hasTranslate":false},{"id":"mf_ar_137","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"يومُ النّصف من شهر رمضان","blocks":[{"type":"Text","content":"فيه كانت في السّنة الثّانية من الهجرة ولادة الامام الحسن المجتبى (عليه السلام) وقال المفيد فيه أيضاً في سنة مائة وخمس وتسعين كانت ولادة الامام محمّد التّقي (عليه السلام)، ولكن المشهور خلاف ذلك وعلى أيّ حال فانّ هذا اليوم يوم شريف جدّاً وللصّدقة والبرّ فيه فضل كثير ."},{"type":"Text","content":"اللّيلة السّابِعَة عشرة"},{"type":"Text","content":"ليلة مباركة جدّاً وفيها تقابل الجيشان في بدر ، جيش رسول الله (صلى الله عليه وآله وسلم) وجيش كفّار قريش، وفي يومها كانت غزوة بدر ونصر الله جيش رسول الله (صلى الله عليه وآله وسلم) على المشركين وكان ذلك أعظم فتوح الاسلام ولذلك قال علماؤنا يستحبّ الاكثار من الصّدقة والشّكر في هذا اليوم وللغسل والعبادة في ليله أيضاً فضل عظيم ."},{"type":"AboutText","content":"أقول : في روايات عديدة انّ النّبي (صلى الله عليه وآله وسلم) قال لاصحابه ليلة بدر من منكم يمضي في هذه اللّيلة الى البئر فيستقي لنا؟ فصمتوا ولم يقدم منهم أحد على ذلك، فأخذ امير المؤمنين (عليه السلام) قربة وانطلق يبغي الماء، وكانت ليلة ظلمآء باردة ذات رياح حتّى ورد البئر وكان عميقاً مظلماً، فلم يجد دلواً يستقي به فنزل في البئر وملا القربة، فارتقى وأخذ في الرّجوع، فعصفت عليه عاصفة جلس على الارض لشدّتها حتّى سكنت، فنهض واستأنف المسير واذا بعاصفة كالاولى تعترض طريقه فتجلسه على الارض، فلمّا هدأت العاصفة قام يواصل مسيره واذا بعاصفة ثالثة تعصف عليه فجلس على الارض، فلمّا زالت عنه قام وسلك طريقه حتّى بلغ النّبي (صلى الله عليه وآله وسلم) فسأله النّبي (صلى الله عليه وآله وسلم) فقال : يا أبا الحسن لماذا أبطأت ؟ فقال : عصفت عليّ عواصف ثلاث زعزعتني فمكثت لكي تزول ، فقال (صلى الله عليه وآله وسلم) : وهل علمت ما هي تلك العواصف يا علي ؟ فقال (عليه السلام) : لا ، فقال (صلى الله عليه وآله وسلم) : كانت العاصفة الاولى جبرئيل ومعه ألف ملك سلّم عليك وسلّموا، والثّانية كانت ميكائيل ومعه ألف ملك سلّم عليك وسلّموا، والثّالثة قد كانت اسرافيل ومعه ألف ملك سلّم عليك وسلّموا، وكلّهم قد هبطوا مدداً لنا ."},{"type":"AboutText","content":"أقول : الى هذا قد أشار من قال انّها كانت لامير المؤمنين (عليه السلام) ثلاثة آلاف منقبة في ليلة واحدة ويشير اليه السّيد الحميري في مدحه له (عليه السلام) في الشّعر :"},{"type":"Text","content":"اُقسِمُ بِاللهِ وَآلائِهِ وَالْمَرْءُ عَمّا قالَ مَسْؤُولُ"},{"type":"Text","content":"اِنَّ عَلِىَّ بنَ اَبى طالِب عَلَى التُّقى وَالْبِرِّ مَجْبُولُ"},{"type":"Text","content":"كانَ اِذَا الْحَربُ مَرَتْهَا الْقَنا وَاَحَجَمَتْ عَنْهَا البَهاليلُ"},{"type":"Text","content":"يَمْشي اِلَى الْقِرْنِ وَفي كَفِّهِ اَبْيَضُ ماضِي الْحَدِّ مَصْقُولٌ"},{"type":"Text","content":"مَشْيَ الْعَفَرْنا بَيْنَ اَشْبالِهِ اَبْرَزَهُ لِلْقَنَصِ الْغيلُ"},{"type":"Text","content":"ذاكَ الَّذي سَلَّمَ في لَيْلَة عَلَيْهِ ميكالٌ وَجِبْريلُ"},{"type":"Text","content":"ميكالُ في اَلْف وَجِبْريلُ في اَلْفِ وَيَتْلُوهُمْ سَرافيلُ"},{"type":"Text","content":"لَيْلَةَ بَدْر مَدَداً اُنْزِلُوا كَاَنَّهُمْ طَيْرٌ اَبابيلُ"},{"type":"Text","content":"اللّيلة التّاسِعَة عَشرة"},{"type":"Text","content":"وهي اوّل ليلة من ليالي القدر، وليلة القدر هي ليلة لا يضاهيها في الفضل سواها من اللّيالي والعمل فيها خير من عمل ألف شهر، وفيها يقدّر شؤون السّنة وفيها تنزّل الملائكة والرّوح الاعظم باذن الله، فتمضي الى امام العصر (عليه السلام)وتتشرّف بالحضور لديه، فتعرض عليه ما قدر لكلّ احد من المقدّرات، وأعمال ليالي القدر نوعان : فقسم منها عام يؤدّى في كلّ ليلة من اللّيالي الثلاثة، وقسم خاص يؤتى فيما خصّ به من هذه اللّيالي ، والقسم الاوّل عدّة أعمال :"},{"type":"Text","content":"الاوّل : الغُسل ، قال العلامة المجلسي (رحمه الله) : الافضل أن يغتسل عند غروب الشّمس ليكون على غسل لصلاة العشاء ."},{"type":"Text","content":"الثّاني : الصّلاة ركعتان يقرأ في كلّ ركعة بعد الحمد التّوحيد سبع مرّات ويقول بعد الفراغ سبعين مرّة اَسْتَغْفِرُ اللهَ واَتُوبُ اِلَيْهِ وفي النّبوي : من فعل ذلك لا يقوم من مقامه حتّى يغفر الله له ولابويه الخبر"},{"type":"Text","content":"الثّالث : تأخذ المصحف فتنشره وتضعه بين يديك وتقول :"},{"type":"Text","content":"اَللّـهُمَّ اِنّي اَسْاَلُكَ بِكِتابِكَ وَما فيهِ وَفيهِ اسْمُكَ الاَكْبَرُ وَاَسْماؤُكَ الْحُسْنى، وَما يُخافُ وَيُرْجى اَنْ تَجْعَلَني مِنْ عُتَقائِكَ مِنَ النّارِ وتدعو بما بدالك من حاجة ."},{"type":"Text","content":"الرّابع : خذ المُصحف فدعه على رأسك وقُل :"},{"type":"Text","content":"اَللّـهُمَّ بِحَقِّ هذَا الْقُرْآنِ، وَبِحَقِّ مَنْ اَرْسَلْتَهُ بِهِ، وَبِحَقِّ كُلِّ مُؤْمِن مَدَحْتَهُ فيهِ، وَبِحَقِّكَ عَلَيْهِمْ، فَلا اَحَدَ اَعْرَفُ بِحَقِّكَ مِنْكَ ثمَّ قُل عَشر مرّات بِكَ يااَللهُ وعَشر مرّات بِمُحَمَّد وعَشر مرّات بِعَليٍّ وعَشر مرّات بِفاطِمَةَ وعَشر مرّات بِالْحَسَنِ وعَشر مرّات بِالْحُسَيْنِ وعَشر مرّات بِعَلِي بْنِ الْحُسَيْنِ وعَشر مرّات بُمَحَمَّدِ بْنِ عَلِيٍّ وعَشر مرّات بِجَعْفَرِ بْنِ مُحَمَّد وعَشر مرّات بِمُوسَى بْنِ جَعْفَر وعَشر مرّات بِعَلِيِّ بْنِ مُوسى وعَشر مرّات بِمُحَمَّدِ بْنِ عَلِيٍّ وعَشر مرّات بِعَلِيِّ بْنِ مُحَمَّد وعَشر مرّات بِالْحَسَنِ بْنِ عَلِيٍّ وعَشر مرّات بِالْحُجَّةِ وتسأل حاجتك ."},{"type":"Text","content":"الخامس : زيارة الحسين (عليه السلام) في الحديث انّه اذا كان ليلة القدر نادى مناد من السّماء السّابعة من بطنان العرش انّ الله قد غفر لمن زار قبر الحسين (عليه السلام) ."},{"type":"Text","content":"السّادس : احياء هذه اللّيالي الثّلاثة ففي الحديث : مَنْ احيا ليلة القدر غفرت له ذنوبه ولو كانت ذنوبه عدد نجوم السّماء ومثاقيل الجبال ومكائيل البحار ."},{"type":"Text","content":"السّابع : الصّلاة مائة ركعة فانّها ذات فضل كثير، والافضل أن يقرأ في كلّ ركعة بعد الحمد التّوحيد عشر مرّات ."}],"preview":"فيه كانت في السّنة الثّانية من الهجرة ولادة الامام الحسن المجتبى (عليه السلام) وقال المفيد فيه أيضاً في سنة مائة وخمس وتسعين كانت ولادة الامام محمّد التّقي (عليه السلام)، ولكن المش","hasTranslate":false},{"id":"mf_ar_138","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"الثّامن : تقول :","blocks":[{"type":"Text","content":"اَللّـهُمَّ اِنّي اَمْسَيْتُ لَكَ عَبْداً داخِراً لا اَمْلِكُ لِنَفْسي نَفْعاً وَلا ضَرّاً، وَلا اَصْرِفُ عَنْها سُوءاً، اَشْهَدُ بِذلِكَ عَلى نَفْسي، وَاَعْتَرِفُ لَكَ بِضَعْفِ قُوَّتي، وَقِلَّةِ حيلَتي، فَصَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَنْجِزْ لي ما وَعَدْتَني وَجَميعَ الْمُؤْمِنينَ وَالْمُؤْمِناتِ مِنَ الْمَغْفِرَةِ في هذِهِ اللَّيْلَةِ، وَاَتْمِمْ عَلَيَّ ما آتَيْتَني فَاِنّي عَبْدُكَ الْمِسْكينُ الْمُسْتَكينُ الضَّعيفُ الْفَقيرُ الْمَهينُ، اَللّـهُمَّ لا تَجْعَلْني ناسِياً لِذِكْرِكَ فيـما اَوْلَيْتَني، وَلا لاِِحْسانِكَ فيـما اَعْطَيْتَني، وَلا آيِساً مِنْ اِجابَتِكَ وَاِنْ اَبْطَأَتَ عَنّي، في سَرّاءَ اَوْ ضَرّاءَ، اَوْ شِدَّة اَوْ رَخاء، اَوْ عافِيَة اَوْ بَلاء، اَوْ بُؤْس اَوْ نَعْماءَ اِنَّكَ سَميعُ الدُّعاءِ ."},{"type":"Text","content":"وقد روى الكفعمي هذا الدّعاء عن الامام زين العابدين (عليه السلام) كان يدعو به في هذه اللّيالي قائماً وقاعداً وراكعاً وساجداً، وقال العلاّمة المجلسي (رحمه الله) : انّ أفضل الاعمال في هذه اللّيالي هو الاستغفار والدّعاء لمطالب الدّنيا والاخرة للنّفس وللوالدين والاقارب وللاخوان المؤمنين الاحياء منهم والاموات والذّكر والصّلاة على محمّد وآل محمّد ما تيسّر، وقد ورد في بعض الاحاديث استحباب قراءة دعاء الجوشن الكبير في هذه اللّيالي الثّلاث ."},{"type":"AboutText","content":"أقول : قد أوردنا الدّعاء فيما مضى وقد روي انّ النّبي (صلى الله عليه وآله وسلم) قيل له : ماذا أسأل الله تعالى اذا أدركت ليلة القدر ؟ قال : العافية ."}],"preview":"اَللّـهُمَّ اِنّي اَمْسَيْتُ لَكَ عَبْداً داخِراً لا اَمْلِكُ لِنَفْسي نَفْعاً وَلا ضَرّاً، وَلا اَصْرِفُ عَنْها سُوءاً، اَشْهَدُ بِذلِكَ عَلى نَفْسي، وَاَعْتَرِفُ لَكَ بِضَعْفِ قُ","hasTranslate":false},{"id":"mf_ar_139","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"أعمال اللّيلة التّاسِعة عشرة","blocks":[{"type":"Text","content":"الاوّل : أن يقول مائة مرّة اَسْتَغْفِرُ اللهَ واَتُوبُ اِلَيْهِ ."},{"type":"Text","content":"الثّاني : مائة مرّة اَللّـهُمَّ الْعَنْ قَتَلَةَ اَميرِ الْمُؤمِنينَ ."}],"preview":"الاوّل : أن يقول مائة مرّة اَسْتَغْفِرُ اللهَ واَتُوبُ اِلَيْهِ .","hasTranslate":false},{"id":"mf_ar_140","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"الرّابع : يقول :","blocks":[{"type":"Text","content":"اَللّـهُمَّ اْجْعَلْ فيـما تَقْضي وَتُقَدِّرُ مِنَ الاَمْرِ الَْمحْتُومِ، وَفيـما تَفْرُقُ مِنَ الاَمْرِ الحَكيمِ في لَيْلَةِ الْقَدْرِ، وَفِي الْقَضاءِ الَّذي لا يُرَدُّ وَلا يُبَدَّلْ، اَنْ تَكْتُبَني مِنْ حُجّاجِ بَيْتِكَ الْحَرامِ، الْمَبْرُورِ حَجُّهُمُ، الْمَشْكُورِ سَعْيُهُمُ، الْمَغْفُورِ ذُنُوبُهُمُ الْمُكَفَّرِ عَنْهُمْ سَيِّئاتُهُمْ وَاجْعَلْ فيـما تَقْضي وَتُقَدِّرُ اَنْ تُطيلَ عُمْري وَتُوَسِّعَ عَلَيَّ في رِزْقي، وَتَفْعَلَ بي كَذا وَكَذا ويسأل حاجته عوض هذه الكلمة ."},{"type":"Text","content":"اللّيلة الواحدة والعِشرون"},{"type":"Text","content":"وفضلها أعظم من اللّيلة التّاسعة عشرة وينبغي أن يؤدّى فيها الاعمال العامّة لليالي القدر من الغسل والاحياء والزّيارة والصّلاة ذات التّوحيد سبع مرّات ووضع المصحف على الرّأس ودعاء الجوشن الكبير وغير ذلك وقد أكّدت الاحاديث استحباب الغُسل والاحياء والجدّ في العبادة في هذه اللّيلة واللّيلة الثّالثة والعشرين وانّ ليلة القدر هي احدهما ، وقد سُئل المعصوم (عليه السلام) في عدّة أحاديث عن ليلة القدر أي اللّيلتين هي ؟ فلم يعيّن ، بل قال : « ما أيسَر ليلتين فيما تطلبُ » أو قال : « ما عَليْكَ اَنْ تَفعَلَ خيراً في لَيلَتَيْنِ » ونحو ذلك، وقال شيخنا الصّدوق فيما أملى على المشايخ في مجلس واحد من مذهب الاماميّة: ومن أحيى هاتين اللّيلتين بمذاكرة العلم فهو أفضل، وليبدأ من هذه اللّيلة في دعوات العشر الاواخر من الشّهر، منها هذا الدّعاء وقد رواه الكليني في الكافي عن الصّادق (عليه السلام) قال : تقول في العشر الاواخر من شهر رمضان كلّ ليلة :"},{"type":"Text","content":"اَعُوذُ بِجَلالِ وَجْهِكَ الْكَريمِ أنْ يَنْقِضيَ عَنّي شَهْرُ رَمَضانَ اَوْ يَطْلُعَ الْفَجْرُ مِنْ لَيْلَتي هذِهِ وَلَكَ قِبَلي ذَنْبٌ اَوْ تَبِعَةٌ تُعَذِّبُني عَلَيْهِ ."},{"type":"AboutText","content":"وروى الكفعمي في هامش كتاب البلد الامين انّ الصّادق (عليه السلام) كان يقول في كلّ ليلة من العشر الاواخر بعد الفرائض والنّوافل :"},{"type":"Text","content":"اَللّـهُمَّ اَدِّ عَنّا حَقَّ ما مَضى مِنْ شَهْرِ رَمَضانَ، وَاغْفِرْ لَنا تَقْصيرَنا فيهِ، وَتَسَلَّمْهُ مِنّا مَقْبُولاً وَلا تُؤاخِذْنا بِاِسْرافِنا عَلى اَنْفُسِنا، وَاجْعَلْنا مِنَ الْمَرْحُومينَ وَلا تَجْعَلْنا مِنَ الَْمحْرُومينَ ."},{"type":"Text","content":"وقال : من قاله غفر الله له ما صدر عنه فيما سلف من هذا الشّهر وعصمه من المعاصي فيما بقى منه ."},{"type":"Text","content":"ومنها ما رواه السّيد ابن طاووس في الاقبال عن ابن أبي عمير، عن مرازم قال : كان الصّادق (عليه السلام) يقول في كلّ ليلة من العشر الاواخر :"},{"type":"Text","content":"اَللّـهُمَّ اِنَّكَ قُلْتَ في كِتابِكَ الْمُنْزَلِ:(شَهْرُ رَمَضانَ الَّذي اُنْزِلَ فيهِ الْقُرْآنُ هُدىً لِلنّاسِ وَبَيِّنات مِنَ الْهُدى وَالْفُرْقانِ) فَعظَّمْتَ حُرْمَةَ شَهْرِ رَمَضانَ بما اَنْزَلْتَ فيهِ مِنَ الْقُرآنِ، وَخَصَصْتَهُ بِلَيْلَةِ الْقَدْرِ وَجَعَلْتَها خَيْراً مِنْ اَلْفِ شَهْر، اَللّـهُمَّ وَهذِهِ اَيّامُ شَهْرِ رَمَضانَ قَدِ انْقَضَتْ، وَلَياليهِ قَدْ تَصَرَّمَتْ، وَقَدْ صِرْتُ يا اِلـهي مِنْهُ اِلى ما اَنْتَ اَعْلَمُ بِهِ مِنّي وَاَحْصى لِعَدَدِهِ مِنَ الْخَلْقِ اَجْمَعينَ، فَاَسْأَلُكَ بِما سَأَلكَ بِهِ مَلائِكَتُكَ الْمُقَرَّبُونَ وَاَنْبِياؤُكَ الْمُرْسَلُونَ، وَعِبادُكَ الصّالِحُونَ، اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد وَأنَ تَفُكَّ رَقَبَتي مِنَ النّارِ، وَتُدْخِلَنِى الْجَنَّةَ بِرَحْمَتِكَ، وَاَنْ تَتَفَضَّلَ عَليَّ بِعَفْوِكَ وَكَرَمُكَ و تَتَقبَّل تَقَربي وَ تَسْتَجيْبَ دُعائي وتَمُنَّ عَليّ بالامن يوم الخوف مِنْ كُلِّ هَوْل اَعْدَدْتَهُ لِيَومِ الْقِيامَةِ، اِلـهي وَاَعُوذُ بِوَجْهِكَ الْكَريمِ، وَبِجَلالِكَ الْعَظيمِ اَنْ يَنْقَضِيَ اَيّامُ شهْرِ رَمَضانَ وَلَياليهِ وَلكَ قِبَلي تَبِعَةٌ اَوْ ذَنْبٌ تُؤاخِذُني بِهِ اَوْ خَطيئَةٌ تُريدُ اَنْ تَقْتَصَّهَا مِنّي لَمْ َتَغْفِرْها لي سَيِّدي سَيِّدي سَيِّدي أسألُك يا لا اِلـهَ إلاّ اَنْتَ اِذْ لا اِلـهَ إلاّ اَنْتَ اِنْ كُنْتَ رَضَيْتَ عَني في هذَا الشَّهْرِ فَاْزدَدْ عَنّي رِضاً، وَاِنْ لَمْ تَكُن رَضَيْتَ عنِّي فَمِنَ الانَ فَارْضَ عَنّي يا اَرْحَمَ الرّاحِمينَ، يا اَللهُ يا اَحَدُ يا صَمَدُ يا مَنْ لَمْ يَلِدْ وَلمْ يُولَدْ وَلَمْ يَكُنْ لَهُ كُفُواً اَحَدٌ (وأكثر من قول ) يا مُلَيِّنَ الْحَديدِ لِداوُدَ عليه السلام يا كاشِفَ الضَرّ والكُرَبِ العِظام عَن ايّوب (عليه السلام) اَي مُفَرِّجَ هَمِّ يَعْقُوبَ عليه السلام، اَيْ مُنَفِّسَ غَمِّ يُوسُفَ عليه السلام صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد كَما اَنْتَ أَهْلهُ اَنْ تُصَلِّيَ عَلَيْهِمْ اَجْمَعينَ وَافْعَلْ بي ما اَنْتَ اَهْلُهُ وَلا تَفْعَلْ بي ما اَنَا اَهْلُهُ ."},{"type":"Text","content":"ومنها ما رواه في الكافي مسنداً وفي المقنعة والمصباح مرسلاً، تقول أوّل ليلة منه أي في اللّيلة الحادية والعشرين :"},{"type":"Text","content":"يا مُولِجَ اللَّيْلِ فِي النَّهارِ، وَمُولِجَ النَّهارِ فِي اللَّيْلِ، وَمُخْرِجَ الْحَيِّ مِنَ الْمَيِّتِ، وَمُخْرِجَ الْمَيِّتِ مِنْ الْحَيِّ، يا رازِقَ مَنْ يَشاءُ بِغَيْرِ حِساب، يا اَللهُ يا رَحْمـنُ، يا اَللهُ يا رَحيمُ، يا اَللهُ يا اَللهُ يا اَللهُ لَكَ الاَسْماءُ الْحُسْنى، وَالاَمْثالُ الْعُلْيا، وَالْكِبْرِياءُ وَالالاءُ، اَسْاَلُكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَنْ تَجْعَلَ اسْمي في هذِهِ اللَّيْلَةِ فِي السُّعَداءِ، وَرُوحي مَعَ الشُّهَداءِ، وَاِحْساني في عِلِّيّينَ، وَاِساءَتي مَغْفُورَةً، وَاَنْ تَهَبَ لي يَقينَاً تُباشِرُ بِهِ قَلْبي، وَاِيماناً يُذْهِبُ الشَّكَّ عَنّي، وَتُرْضِيَني بِما قَسَمْتَ لي، وَآتِنا فِي الدُّنْيا حَسَنَةً وَفِي الاخِرَةِ حَسَنَةً، وَقِنا عَذابَ النّارِ الْحَريقِ، وَارْزُقْني فيها ذِكْرَكَ وَشُكْرَكَ، وَالرَّغْبَةَ اِلَيْكَ وَالاِنابَهَ وَالتَّوْفيقَ لِما وَفَّقْتَ لَهُ مُحَمَّداً وآلَ مُحَمَّداً عَلَيْهِ وَعليهم السلام ."}],"preview":"اَللّـهُمَّ اْجْعَلْ فيـما تَقْضي وَتُقَدِّرُ مِنَ الاَمْرِ الَْمحْتُومِ، وَفيـما تَفْرُقُ مِنَ الاَمْرِ الحَكيمِ في لَيْلَةِ الْقَدْرِ، وَفِي الْقَضاءِ الَّذي لا يُرَدُّ وَلا يُبَ","hasTranslate":false},{"id":"mf_ar_141","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"دُعاء اللّيلة الثّانية وَالْعِشْرينَ","blocks":[{"type":"Text","content":"يا سالِخَ النَّهارِ مِنَ اللَّيْلِ فَاِذا نَحْنُ مُظْلِموُنَ وَمُجْرِي الشَّمْسِ لِمُسْتَقَرِّها بِتَقْديرِكَ، يا عَزيزُ يا عَليمُ، وَمُقَدِّرَ الْقَمَرِ مَنازِلَ حَتّى عادَ كَالْعُرْجُونِ الْقَديمِ، يا نُورَ كُلِّ نُور، وَمُنْتَهى كُلِّ رَغْبَة، وَوَلِيَّ كُلِّ نِعْمَة، يا اَللهُ يا رَحْمـنُ، يا اَللهُ يا قُدُّوسُ، يا اَحَدُ يا واحِدُ، يا فَرْدُ يا اَللهُ يا اَللهُ يا اَللهُ، لَكَ الاَسْماءُ الْحُسْنى، وَالاَمْثالُ الْعُلْيا، وَالْكِبْرِياءُ وَالالاءِ، اَسْأَلكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَاَهْلِ بَيْتِهِ، وَاَنْ تَجْعَلَ اسْمي في هذِهِ اللَّيْلَةِ فِي السُّعَداءِ،وَرُوحي مَعَ الشُّهَداءِ، وَاِحْساني في عِلِّيّينَ، وَاِساءَتي مَغْفُورَةً، وَاَنْ تَهَبَ لي يَقيناً تُباشِرُ بِهِ قَلْبي، وَايماناً يُذْهِبُ الشَّكَّ عَنّي، وَتُرْضِيَني بِما قَسَمْتَ لي، وَآتِنا فِي الدُّنْيا حَسَنةً وَفِى الاخِرَةِ حَسَنَةً وَقِنا عَذابَ النّارِ الْحَريقِ، وَارْزُقْني فيها ذِكْرَكَ وَشُكْرَكَ وَالرَّغَبَةَ اِلَيْكَ وَالاِنابَةَ وَالتَّوفيقَ لِما وَفَّقْتَ لَهُ مُحَمَّداً وآلَ مُحَمَّد عليهم السلام ."}],"preview":"يا سالِخَ النَّهارِ مِنَ اللَّيْلِ فَاِذا نَحْنُ مُظْلِموُنَ وَمُجْرِي الشَّمْسِ لِمُسْتَقَرِّها بِتَقْديرِكَ، يا عَزيزُ يا عَليمُ، وَمُقَدِّرَ الْقَمَرِ مَنازِلَ حَتّى عادَ كَالْع","hasTranslate":false},{"id":"mf_ar_142","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"دُعاء اللّيلة الثّالِثة وَالْعِشْرينَ","blocks":[{"type":"Text","content":"يا رَبَّ لَيْلَةِ الْقَدْر وَجاعِلَها خَيْراً مِنْ اَلْفِ شَهْر، وَرَبَّ اللَّيْلِ والنَّهارِ، وَالْجِبالِ والْبِحارِ، والظُّلَمِ والاَْنْوارِ، وَالاَْرْضِ وَالسَّماءِ، يا بارِئُ يا مُصَوِّرُ، يا حَنّانُ يا مَنّانُ، يا اَللهُ يا رَحْمنُ، يا اَللهُ يا بَديعُ، يا اَللهُ يا اَللهُ يا اَللهُ، لَكَ الاَْسْماءُ الْحُسْنى، وَالاَْمْثالُ الْعُلْيا، وَالْكِبْرِياءُ وَالالاءُ، اَسْاَلُكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَنْ تَجْعَلَ اسْمي في هذِهِ اللَّيْلَةِ فِى السُّعَداءِ، وَرُوحي مَعَ الشُّهَداءِ وَاِحْساني في عِلِّيّينَ، وَاِساءَتي مَغْفُورَةً، وَاَنْ تَهَبَ لي يَقيناً تُباشِرُ بِهِ قَلْبي وَايماناً يُذهِبُ الشَّكَّ عَنّي، وَتُرْضِيَني بِما قَسَمْتَ لي، وَآتِنا فِي الدُّنْيا حَسَنَةً وَفِي الاخِرَةِ حَسَنَةً، وَقِنا عَذابَ النّارِ الْحَريقِ، وَارْزُقْني فيها ذِكْرَكَ وَشُكْرَكَ وَالرَّغْبَةَ اِلَيْكَ وَالانابَةَ والتَّوبَةَ والتَّوْفيقَ لِما وَفَّقْتَ لَهُ مُحَمَّداً وَآلَ مُحَمَّد عليهم السلام ."},{"type":"AboutText","content":"وروى محمّد بن عيسى بسنده عن الصّالحين (عليهم السلام) قالوا : كرّر في اللّيلة الثّالثة والعشرين من شهر رمضان هذا الدّعاء ساجداً وقائماً وقاعداً وعلى كلّ حال وفي الشّهر كلّه وكيف أمكنك ومتى حضرك من دهرك تقول بعد تمجيده تعالى والصّلاة على نبيّه (صلى الله عليه وآله وسلم) :"},{"type":"Text","content":"اَللّـهُمَّ كُنْ لِوَلِيِّكَ فلان بن فلان وتقول عوض فلان بن فلان الْحُجَّةِ بْنِ الْحَسَنِ صَلَواتُكَ عَلَيْهِ وَعَلى آبائِه في هذِهِ السَّاعَةِ وَفي كُلِّ ساعَة وَلِيّاً وَحافِظاً وَقائِداً وَناصِراً وَدَليلاً وَعَيْنا حَتّى تُسْكِنَهُ اَرْضَكَ طَوْعاً وَتُمَتِّعَهُ فيها طَويلاً (وتقول أيضاً) يا مُدَبِّرَ الاُمُورِ، يا باعِثَ مَنْ فِى الْقُبُورِ، يا مُجْرِيَ الْبُحُورِ، يا مُلَيِّنَ الْحَديدِ لِداوُدَ صَلِّ عَلى مُحَمَّد وَآل مُحَمد وافْعَلْ بي كَذ وَكَذا (وتسْأل حأجتك) اللَّيْلَةَ اللَّيْلَةَ ."},{"type":"Text","content":"وارفع يديك الى السّماء أي عند قولك يا مُدَبِّرَ الاُمُورِ الى آخر الدّعاء وادع بهذا الدّعاء راكعاً وساجداً وقائماً وقاعداً وكرّره وادع به في اللّيلة الاخيرة ايضاً ."}],"preview":"يا رَبَّ لَيْلَةِ الْقَدْر وَجاعِلَها خَيْراً مِنْ اَلْفِ شَهْر، وَرَبَّ اللَّيْلِ والنَّهارِ، وَالْجِبالِ والْبِحارِ، والظُّلَمِ والاَْنْوارِ، وَالاَْرْضِ وَالسَّماءِ، يا بارِئُ ي","hasTranslate":false},{"id":"mf_ar_143","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"دُعاءُ اللَّيلَةِ الرّابعةِ وَالْعِشْرين","blocks":[{"type":"Text","content":"يا فالِقَ الاِْصْباحِ، وَجاعِلَ اللَّيْلِ سَكَناً، وَالشَّمْسِ وَالْقَمَرِ حُسْباناً، يا عَزيزُ يا عَليمُ، يا ذَا المَنِّ وَالطَّوْلِ، وَالْقُوَّةِ وَالْحَوْلِ، وَالْفَضْلِ والاِْنْعامِ، وَالْجَلالِ وَالاِْكْرامِ، يا اَللهُ يا رَحْمـنُ، يا اَللهُ يا فَرْدُ يا وِتْرُ، يا اَللهُ يا ظاهِرُ يا باطِنُ، يا حَيُّ لا اِلـهَ إلاّ اَنْتَ، لَكَ الاَْسْماءُ الْحُسْنى، وَالاَْمْثالُ الْعُلْيا، وَالْكِبْرِياءُ وَالالاءُ، اَسْاَلُكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَنْ تَجْعَلَ اسْمي في هذِهِ اللَّيْلَةِ فِي السُّعَداءِ، وَرُوحي مَعَ الشُّهَداءِ، وَاِحْساني في عِلِّيّينَ، وَاِساءَتي مَغْفُورَةً، وَاَنْ تَهَبَ لي يَقيناً تُباشِرُ بِهِ قَلْبي، وَايماناً يَذْهَبُ بِالشَّكِّ عَنّي، وَرِضىً بِما قَسَمْتَ لي، وَآتِنا فِي الدُّنْيا حَسَنَةً وَفِي الاخِرَةِ حَسَنَهً، وَقِنا عَذابَ النّارِ الْحَريقِ، وَارْزُقْني فيها ذِكْرَكَ وَشُكْرَكَ وَالرَّغْبَةَ اِلَيْكَ، وَالانابَةَ وَالتَّوْبَهَ وَالتَّوْفيقَ لِما وَفَّقْتَ لَهُ مُحَمَّداً وَآلَ مُحَمَّد صَلَواتُكَ عَلَيْهِ وَعَلَيْهِمْ ."}],"preview":"يا فالِقَ الاِْصْباحِ، وَجاعِلَ اللَّيْلِ سَكَناً، وَالشَّمْسِ وَالْقَمَرِ حُسْباناً، يا عَزيزُ يا عَليمُ، يا ذَا المَنِّ وَالطَّوْلِ، وَالْقُوَّةِ وَالْحَوْلِ، وَالْفَضْلِ والاِْن","hasTranslate":false},{"id":"mf_ar_144","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"دُعاء اللّيْلَةِ الخامِسَةِ وَالْعِشْرينَ","blocks":[{"type":"Text","content":"يا جاعِلَ اللَّيْلِ لِباساً، وَالنَّهارِ مَعاشاً، وَالاَْرْضِ مِهاداً، وَالْجِبالِ اَوْتاداً، يا اَللهُ يا قاهِرُ، يا اَللهُ يا جَبّارُ، يا اَللهُ يا سَميعُ، يا اَللهُ يا قَريبُ، يا اَللهُ يا مُجيبُ، يا اَللهُ يا اَللهُ يا اَللهُ، لَكَ الاَْسْماءُ الْحُسْنى، وَالاَْمْثالُ الْعُلْيا، وَالْكِبْرِياءُ وَالالاءُ، اَسْاَلُكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَنْ تَجْعَلَ اسْمي في هذِهِ اللَّيْلَةِ فِي السُّعَداءِ، وَرُوحي مَعَ الشُّهَداءِ، وَاِحْساني في عِلِّيّينَ، وَاِساءَتي مَغْفُورةً، وَاَنْ تَهَبَ لي يَقيناً تُباشِرُ بِهِ قَلْبي، وَايماناً يُذْهِبُ الشَّكَّ عَنّي، وَرِضىً بِما قَسَمْتَ لي، وَآتِنا فِي الدُّنْيا حَسَنَةً وَفِي الاخِرَةِ، حَسَنَةً وَقِنا عَذابَ النّارِ الْحَريقِ، وَارْزُقْني فيها ذِكْرَكَ وَشُكْرَكَ وَالرَّغْبَةَ اِلَيْكَ وَالاِْنابَةَ وَالتَّوْبَةَ والتَّوْفيقَ لِما وَفَّقْتَ لَهُ مَحَمَّداً وَآلَ مُحَمَّد عليهم السلام ."}],"preview":"يا جاعِلَ اللَّيْلِ لِباساً، وَالنَّهارِ مَعاشاً، وَالاَْرْضِ مِهاداً، وَالْجِبالِ اَوْتاداً، يا اَللهُ يا قاهِرُ، يا اَللهُ يا جَبّارُ، يا اَللهُ يا سَميعُ، يا اَللهُ يا قَريبُ، ي","hasTranslate":false},{"id":"mf_ar_145","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"دُعاءِ اللَّيلة السّادِسَة وَالْعِشْرينَ","blocks":[{"type":"Text","content":"يا جاعِلَ اللَّيْلِ وَالنَّهارِ آيتَيْنِ، يا مَنْ مَحا آيَةَ اللَّيْلِ وَجَعَلَ آيَةَ النَّهارِ مُبْصِرَةً لِتَبْتَغُوا فَضْلاً مِنْهُ وَرِضْواناً، يا مُفَصِّلَ كُلِّ شَيْء تَفْصيلاً، يا ماجِدُ يا وَهّابُ، يا اَللهُ يا جَوادُ، يا اَللهُ يا اَللهُ يا اَللهُ، لَكَ الاَْسْماءُ الْحُسْنى، وَالاَْمْثالُ الْعُلْيا، وَالْكِبْرِياءُ وَالالاءُ، اَسْاَلُكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمد، وَاَنْ تَجْعَلَ اسْمي في هذِهِ اللَّيْلَةِ فِي السُّعَدآءِ، وَرُوحي مَعَ الشُّهَداءِ وَاِحْساني في عِلِّيّينَ، وَاِساءَتي مَغْفُورَةً، وَاَنْ تَهَبَ لي يَقيناً تُباشِرُ بِهِ قَلْبي، وَايماناً يُذْهبُ الشَّكَّ عَنّي، وَتُرضِيَني بِما قَسَمْتَ لي، وَآتِنا فِي الدُّنْيا حَسَنَةً وَفِي الاخِرَةِ حَسَنةً، وَقِنا عَذابَ النَّارِ الْحَريقِ، وَارْزُقْني فيها ذِكْرَكَ وَشُكْرَكَ وَالرَّغْبَةَ اِلَيْكَ وَالاِْنابَةَ وَالتَّوْبَةَ وَالتَّوْفيقَ لِما وَفَّقْتَ لَهُ مُحَمَّداً وَآلَ مُحَمَّد صَلَّى اللهُ عَلَيْهِ وَعَلَيْهِمْ ."}],"preview":"يا جاعِلَ اللَّيْلِ وَالنَّهارِ آيتَيْنِ، يا مَنْ مَحا آيَةَ اللَّيْلِ وَجَعَلَ آيَةَ النَّهارِ مُبْصِرَةً لِتَبْتَغُوا فَضْلاً مِنْهُ وَرِضْواناً، يا مُفَصِّلَ كُلِّ شَيْء تَفْصيل","hasTranslate":false},{"id":"mf_ar_146","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"دعاء اللّيْلَةِ السّابِعَة وَالْعِشْرينَ","blocks":[{"type":"Text","content":"يا مادَّ الظِّلِّ وَلَوْ شِئْتَ لَجَعَلْتَهُ ساكِناً، وَجَعَلْتَ الشَّمْسَ عَلَيْهِ دَليلاً ثُمَّ قَبَضْتَهُ اِليْكَ قَبْضاً يَسيراً، يا ذَالْجُودِ وَالطَّوْلِ وَالْكِبْرِياءِ وَالالاءِ، لا اِلـهَ إلاّ اَنْتَ عالِمُ الْغَيْبِ وَالشَّهادَةِ الرَّحْمنُ الرَّحيمُ، لا إلهَ إلاّ اَنْتَ يا قُدُّوسُ يا سَلامُ يا مُؤْمِنُ يامُهَيْمِنُ يا عَزيزُ ياجَبّارُ يا مُتَكبِّرُ يا اَللهُ يا خالِقُ يا بارِئُ يا مُصَوِّرُ، يا اَللهُ يا اَللهُ يا اَللهُ، لَكَ الاَْسْماءُ الْحُسْنى، وَالاَْمْثالُ الْعُلْيا، وَالْكِبْرِياءُ وَالالاءُ، اَسْاَلُكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَنْ تَجْعَلَ اسْمي في هذِهِ اللَّيْلَةِ فِي السُّعَداءِ، وَرُوحي مَعَ الشُّهَداءِ، وَاِحْساني في عِلِّيّينَ، وَاِساءَتي مَغْفُورةً، وَاَنْ تَهَبَ لي يَقيناً تُباشِرُ بِهِ قَلْبي، وَايماناً يُذْهِبُ الشَّكَّ عَنّي، وَتُرِْضيَني بِما قَسَمْتَ لي، وَآتِنا فِي الدُّنْيا حَسَنَةً وَفِي الاخِرَةِ حَسَنَةً وَقِنا عَذابَ النّارِ الْحَريقِ، وَارْزُقْني فيها ذِكْرَكَ وَشُكْرَكَ وَالرَّغْبَةَ اِلَيْكَ وَالاِْنابَةَ وَالتَّوْبَةَ والتَّوْفيقَ لِما وَفَّقْتَ لَهُ مَحَمَّداً وَآلَ مُحَمَّد صَلّى اللهُ عَلَيْهِ وَعَلَيْهِمْ ."}],"preview":"يا مادَّ الظِّلِّ وَلَوْ شِئْتَ لَجَعَلْتَهُ ساكِناً، وَجَعَلْتَ الشَّمْسَ عَلَيْهِ دَليلاً ثُمَّ قَبَضْتَهُ اِليْكَ قَبْضاً يَسيراً، يا ذَالْجُودِ وَالطَّوْلِ وَالْكِبْرِياءِ وَال","hasTranslate":false},{"id":"mf_ar_147","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"دُعاء اللَّيْلَةِ الثّامِنة وَالْعِشْرينَ","blocks":[{"type":"Text","content":"يا خازِنَ اللَّيْلِ فِى الْهَواءِ، وَخازِنَ النُّورِ فِى السَّماءِ، وَمانِعَ السَّماءِ أَنْ تَقَعَ عَلَى الاَْرْضِ إلاّ بِاِذْنِهِ وَحابِسَهُما اَنْ تَزُولا، يا عَليمُ يا عَظيمُ، يا غَفُورُ يا دائِمُ، يا اَللهُ يا وارِثُ، يا باعِثَ مَنْ فِي الْقُبُورِ، يا اَللهُ يا اَللهُ يا اَللهُ، لَكَ الاَْسْماءُ الْحُسْنى، وَالاَْمْثالُ الْعُلْيا، وَالْكِبْرِياءُ وَالالاءُ، اَسْاَلُكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَنْ تَجْعَلَ اسْمي في هذِهِ اللَّيْلَةِ فِي السُّعَداءِ، وَرُوحي مَعَ الشُّهَداءِ، وَاِحْساني في عِلِّيّينَ، وَاِساءَتي مَغْفُورةً، وَاَنْ تَهَبَ لي يَقيناً تُباشِرُ بِهِ قَلْبي وَايماناً يُذْهِبُ الشَّكَّ عَنّي، وَتُرِْضيَني بِما قَسَمْتَ لي، وَآتِنا فِي الدُّنْيا حَسَنَةً وَفِي الاخِرَةِ حَسَنَةً وَقِنا عَذابَ النّارِ الْحَريقِ، وَارْزُقْني فيها ذِكْرَكَ وَشُكْرَكَ وَالرَّغْبَةَ اِلَيْكَ وَالاِْنابَةَ وَالتَّوْبَةَ والتَّوْفيقَ لِما وَفَّقْتَ لَهُ مَحَمَّداً وَآلَ مُحَمَّد صَلّى اللهُ عَلَيْهِ وَعَلَيْهِمْ ."}],"preview":"يا خازِنَ اللَّيْلِ فِى الْهَواءِ، وَخازِنَ النُّورِ فِى السَّماءِ، وَمانِعَ السَّماءِ أَنْ تَقَعَ عَلَى الاَْرْضِ إلاّ بِاِذْنِهِ وَحابِسَهُما اَنْ تَزُولا، يا عَليمُ يا عَظيمُ، ي","hasTranslate":false},{"id":"mf_ar_148","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"دُعاء اللّيلةِ التّاسِعَة وَالْعِشْرينَ","blocks":[{"type":"Text","content":"يا مُكَوِّرَ اللَّيْلِ عَلَى النَّهارِ، وَمُكَوِّرَ النَّهارِ عَلَى اللَّيْلِ، يا عَليمُ يا حَكيمُ يا رَبَّ الاَرْبابِ وَسَيِّدَ الساداتِ، لا اِلهَ إلاّ اَنْتَ يا اَقْرَبَ اِلَيَّ مِنْ حَبْلِ الْوَريدِ، يا اَللهُ يا اَللهُ يا اَللهُ، لَكَ الاَْسْماءُ الْحُسْنى، وَالاَْمْثالُ الْعُلْيا، وَالْكِبْرِياءُ وَالالاءُ اَسْاَلُكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَنْ تَجْعَلَ اسْمي في هذِهِ اللَّيْلَةِ فِي السُّعَداءِ، وَرُوحي مَعَ الشُّهَداءِ، وَاِحْساني في عِلِّيّينَ، وَاِساءَتي مَغْفُورةً، وَاَنْ تَهَبَ لي يَقيناً تُباشِرُ بِهِ قَلْبي، وَايماناً يُذْهِبُ الشَّكَّ عَنّي، وَتُرِْضيَني بِما قَسَمْتَ لي، وَآتِنا فِي الدُّنْيا حَسَنَةً وَفِي الاخِرَةِ حَسَنَةً، وَقِنا عَذابَ النّارِ الْحَريقِ، وَارْزُقْني فيها ذِكْرَكَ وَشُكْرَكَ وَالرَّغْبَةَ اِلَيْكَ وَالاِْنابَةَ وَالتَّوْبَةَ والتَّوْفيقَ لِما وَفَّقْتَ لَهُ مَحَمَّداً وَآلَ مُحَمَّد صَلّى اللهُ عَلَيْهِ وَعَلَيْهِمْ ."}],"preview":"يا مُكَوِّرَ اللَّيْلِ عَلَى النَّهارِ، وَمُكَوِّرَ النَّهارِ عَلَى اللَّيْلِ، يا عَليمُ يا حَكيمُ يا رَبَّ الاَرْبابِ وَسَيِّدَ الساداتِ، لا اِلهَ إلاّ اَنْتَ يا اَقْرَبَ اِلَيَّ","hasTranslate":false},{"id":"mf_ar_149","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"دُعاء اللّيلةِ الثّلاثينَ","blocks":[{"type":"Text","content":"الْحَمْدُ للهِ لا شَريكَ لَهُ، الْحَمْدُ للهِ كَما يَنْبَغي لِكَرَمِ وَجْهِهِ وَعِزِّ جَلالِهِ وَكَما هُوَ اَهْلُهُ، يا قُدُّوسُ يا نُورُ يا نُورَ الْقُدْسِ، يا سُبُّوحُ يا مُنْتَهى التَّسْبيحِ، يا رَحْمـنُ يا فاعِلَ الرَّحْمَةِ، يا اللهُ يا عَليمُ يا كَبيرُ، يا اَللهُ يا لَطيفُ يا جَليلُ، يا اَللهُ يا سَميعُ يا بَصيرُ، يا اَللهُ يا اَللهُ يا اَللهُ، لَكَ الاَْسْماءُ الْحُسْنى، وَالاَْمْثالُ الْعُلْيا، وَالْكِبْرِياءُ وَالالاءُ، اَسْاَلُكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاَهْلِ بَيْتِهِ، وَاَنْ تَجْعَلَ اسْمي في هذِهِ اللَّيْلَةِ فِي السُّعَداءِ، وَرُوحي مَعَ الشُّهَداءِ، وَاِحْساني في عِلِّيّينَ، وَاِساءَتي مَغْفُورةً، وَاَنْ تَهَبَ لي يَقيناً تُباشِرُ بِهِ قَلْبي، وَايماناً يُذْهِبُ الشَّكَّ عَنّي، وَتُرِْضيَني بِما قَسَمْتَ لي، وَآتِنا فِي الدُّنْيا حَسَنَةً وَفِى الاخِرَةِ حَسَنَةً، وَقِنا عَذابَ النّارِ الْحَريقِ، وَارْزُقْني فيها ذِكْرَكَ وَشُكْرَكَ وَالرَّغْبَةَ اِلَيْكَ وَالاِْنابَةَ وَالتَّوْبَةَ والتَّوْفيقَ لِما وَفَّقْتَ لَهُ مَحَمَّداً وَآلَ مُحَمَّد صَلّى اللهُ عَلَيْهِ وَعَلَيْهِمْ ."}],"preview":"الْحَمْدُ للهِ لا شَريكَ لَهُ، الْحَمْدُ للهِ كَما يَنْبَغي لِكَرَمِ وَجْهِهِ وَعِزِّ جَلالِهِ وَكَما هُوَ اَهْلُهُ، يا قُدُّوسُ يا نُورُ يا نُورَ الْقُدْسِ، يا سُبُّوحُ يا مُنْتَه","hasTranslate":false},{"id":"mf_ar_150","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"تتمّة أعمال اللّيلة الحادِيةَ وَالْعِشْرينَ","blocks":[{"type":"Text","content":"روى الكفعمي عن السّيّد ابن باقي : تقول في اللّيلةِ الحادية والعشرين :"},{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلى مُحَمَّد، وَآلِ مُحَمَّد وَاقْسِمْ لي حِلْماً يَسُدُّ عَنّي بابَ الْجَهْلِ، وَهُدىً تَمُنُّ بِهِ عَلَيَّ مِنْ كُلِّ ضَلالَة، وَغِنىً تَسُدُّ بِهِ عَنّي بابَ كُلِّ فَقْر، وَقُوَّةً تَرُدُّ بِها عَنّي كُلَّ ضَعْف، وَعِزّاً تُكْرِمُني بِهِ عَنْ كُلِّ ذُلٍّ، وَرِفْعَةً تَرْفَعُني بِها عَنْ كُلِّ ضَعَة، وَاَمْناً تَرُدُّ بِهِ عَنّي كُلَّ خَوْف، وَعافِيَةً تَسْتُرُني بِها عَنْ كُلِّ بَلاء، وَعِلْماً تَفْتَحُ لي بِهِ كُلَّ يَقين، وَيَقيناً تُذْهِبُ بِهِ عَنّي كُلَّ شَكٍّ، وَدُعاءً تَبْسُطُ لي بِهِ الاِجابَةَ في هذِهِ اللَّيْلَةِ، وَفي هذِهِ السّاعَةِ، السّاعَةَ السّاعَةَ السّاعَةَ يا كَريمُ، وَخَوْفاً تَنْشُرُ لي بِهِ كُلَّ رَحْمَة، وَعِصْمَةً تَحُولُ بِها بَيْني وَبَيْنَ الذُّنُوبِ، حَتّى اُفْلِحَ بِها عِنْدَ الْمَعْصُومُينَ عِنْدَكَ، بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ ."},{"type":"Text","content":"وروي عن حماد بن عثمان قال : دخلت على الصّادق (عليه السلام) ليلة احدى وعشرين من شهر رمضان فقال لي : يا حماد اغتسلت ، فقلت : نعم جعلت فداك، فدعا بحصير ثمّ قال : اليّ لزقي فصلّ فلم يزل يصلّي وأنا اُصلّي الى لزقه حتّى فرغنا من جميع صلواتنا، ثمّ أخذ يدعو وأنا اُءَمِّن على دعائه الى أن اعترض الفجر، فأذّن وأقام ودعا بعض غلمانه فقمنا خلفه، فتقدّم فصلّى بنا الغداة، فقرأ بفاتحة الكتابِ وَاِنّا اَنْزَلناهُ في لَيلَةِ الْقَدْرِ في الاُولى، وفي الرّكعة الثّانية بفاتحة الكتاب وقُل هُوَ اللهُ اَحَدٌ، فلمّا فرغنا من التّسبيح والتّحميد والتّقديس والثّناء على الله تعالى والصّلاة على رسول الله (صلى الله عليه وآله وسلم) والدّعاء لجميع المؤمنين والمؤمنات والمسلمين والمسلمات خرّ ساجداً لا أسمع منه الّا النّفس ساعة طويلة، ثمّ سمعته يقول لا اِلـهَ إلاّ اَنْتَ مُقَلِّبَ الْقُلُوبِ وَالاَبْصارِ، الى آخر الدّعاء المروي في الاقبال."},{"type":"AboutText","content":"وروى الكليني انّه كان الباقر (عليه السلام)اذا كانت ليلة احدى وعشرين وثلاث وعشرين أخذ في الدّعاء حتّى يزول اللّيل (ينتصف) فاذا زال اللّيل صلّى . وروى انّ النّبي (صلى الله عليه وآله وسلم) كان يغتسل في كلّ ليلة من هذا العشر، ويستحبّ الاعتكاف في هذا العشر وله فضل كثير وهو أفضل الاوقات للاعتكاف، وروي انّه يعدل حجّتين وعمرتين، وكان رسول الله (صلى الله عليه وآله وسلم) اذا كان العشر الاواخر اعتكف في المسجد وضُرِبت له قُبّة من شعر وشمّر المئزَر وطَوى فِراشه واعلم انّ هذه ليلة تتجدّد فيها أحزان آل محمّد وأشياعهم ففيها في سنة أربعين من الهجرة كانت شهادة مولانا أمير المؤمنين صلوات الله عليه ."},{"type":"AboutText","content":"وروى انّه ما رفع حجر عن حجر في تلك اللّيلة الّا وكان تحته دماً عبيطاً كما كان ليلة شهادة الحسين (عليه السلام) ، وقال المفيد (رحمه الله): ينبغي الاكثار في هذه اللّيلة من الصّلاة على محمّد وآل محمّد والجدّ في اللّعن على ظالمي آل محمّد (عليهم السلام)واللّعن على قاتل امير المؤمنين (عليه السلام) ."},{"type":"Text","content":"الْيَومُ الحادي وَالعِشرون"},{"type":"Text","content":"يوم شهادة أمير المؤمنين (عليه السلام) ومن المناسب أن يزار (عليه السلام) في هذا اليوم، والكلمات التي نطق بها خضر (عليه السلام) في هذا اليوم وهي كزيارة له (عليه السلام) فيه قد أودعناها كتابنا هديّة الزّائر ."},{"type":"Text","content":"اللّيلة الثّالِثة وَالعِشرُون"},{"type":"Text","content":"وهي أفضل من اللّيلتين السّابقتين ويستفاد من أحاديث كثيرة انّها هي ليلة القدر وفيها يقدّر كلّ أمر حكيم، ولهذه اللّيلة عدّة أعمال خاصّة سوى الاعمال العامّة التي تشارك فيها اللّيلتين الماضيتين ."},{"type":"Text","content":"الاوّل : قراءة سورتي العنكبوت والرّوم، وقال الصّادق (عليه السلام) : انّ من قرأ هاتين السّورتين في هذه اللّيلة كان من أهل الجنّة ."}],"preview":"روى الكفعمي عن السّيّد ابن باقي : تقول في اللّيلةِ الحادية والعشرين :","hasTranslate":false},{"id":"mf_ar_151","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"الثّاني : قراءة سورة حم دُخّان","blocks":[{"type":"Text","content":"الثّالث : قراءة سورة القدر ألف مرّة ."},{"type":"Text","content":"الرّابع : أن يكرّر في هذه اللّيلة بل في جميع الاوقات هذا الدّعاء اَللّـهُمَّ كُنْ لِوَلِيِّكَ الخ ، وقد ذكرناه في خلال أدعية العشر الاواخر بعد دعاء اللّيلة الثّالثة والعشرين."}],"preview":"الثّالث : قراءة سورة القدر ألف مرّة .","hasTranslate":false},{"id":"mf_ar_152","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"الخامس : يقول :","blocks":[{"type":"Text","content":"اَللّـهُمَّ امْدُدْ لي في عُمْري، وَاَوْسِعْ لي في رِزْقي، وَاَصِحَّ لي جِسْمي، وَبَلِّغْني اَمَلي، وَاِنْ كُنْتُ مِنَ الاَْشْقِياءِ فَاْمُحني مِنَ الاَْشْقِياءِ، وَاْكتُبْني مِنَ السُّعَداءِ، فَاِنَّكَ قُلْتَ في كِتابِكَ الْمُنْزَلِ عَلى نَبِيِّكَ الْمُرْسَلِ صَلَوتُكَ عَلَيْهِ وَآلِهِ:(يَمْحُو اللهُ ما يَشاءُ وَيُثْبِتُ وَعِنْدَهُ اُمُّ الْكِتابِ)."}],"preview":"اَللّـهُمَّ امْدُدْ لي في عُمْري، وَاَوْسِعْ لي في رِزْقي، وَاَصِحَّ لي جِسْمي، وَبَلِّغْني اَمَلي، وَاِنْ كُنْتُ مِنَ الاَْشْقِياءِ فَاْمُحني مِنَ الاَْشْقِياءِ، وَاْكتُبْني مِنَ","hasTranslate":false},{"id":"mf_ar_153","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"السّادس : يقول :","blocks":[{"type":"Text","content":"اَللّـهُمَّ اجْعَلْ فيـما تَقْضي وَفيـما تُقَدِّرُ مِنَ الاَْمْرِ الَْمحْتُومِ، وَفيـما تَفْرُقُ مِنَ الاَْمْرِ الْحَكيمِ في لَيْلَةِ الْقَدْرِ، مِنَ الْقَضاءِ الَّذي لا يُردُّ وَلا يُبَدَّلُ اَنْ تَكْتُبَني مِنْ حُجّاجِ بَيْتِكَ الْحَرامِ في عامي هذا الْمَبْرُورِ حَجُّهُمْ الْمَشْكُورِ سَعْيُهُمُ، الْمَغْفُورِ ذُنُوبُهُمُ، الْمُكَفَّرِ عَنْهُمْ سَيِّئاتُهُمْ، وَاجْعَلْ فيـما تَقْضي وَتُقَدِّرُ اَنْ تُطيلَ عُمْري وَتُوَسِّعَ لي في رِزْقي ."}],"preview":"اَللّـهُمَّ اجْعَلْ فيـما تَقْضي وَفيـما تُقَدِّرُ مِنَ الاَْمْرِ الَْمحْتُومِ، وَفيـما تَفْرُقُ مِنَ الاَْمْرِ الْحَكيمِ في لَيْلَةِ الْقَدْرِ، مِنَ الْقَضاءِ الَّذي لا يُردُّ وَل","hasTranslate":false},{"id":"mf_ar_154","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"السّابع : يدعو بهذا الدّعاء المروي في الاقبال :","blocks":[{"type":"Text","content":"يا باطِناً في ظُهُورِهِ، وَيا ظاهِراً في بُطُونِهِ وَيا باطِناً لَيْسَ يَخْفى، وَيا ظاهِراً لَيْسَ يُرى، يا مَوْصُوفاً لا يَبْلُغُ بِكَيْنُونَيِةِ مَوْصُوفٌ وَلا حَدٌّ مَحْدُودٌ، وَيا غائِباً غَيْرَ مَفْقُود، وَيا شاهِداً غَيْرَ مَشْهُود، يُطْلَبُ فَيُصابُ، وَلَمْ يَخْلُ مِنْهُ السَّماواتُ وَالاَْرْضِ وَمابَيْنَهُما طَرْفَةَ عَيْن، لا يُدْرِكُ بِكَيْف وَلا يُؤَيَّنُ بِاَيْن وَلا بِحَيْث، اَنْتَ نُورُ النُّورِ وَرَبَّ الاَْرْبابِ، اَحَطْتَ بِجَميعِ الاُمُورِ، سُبْحانَ مَنْ لَيْسَ كَمِثْلِهِ شَيْءٌ وَهُوَ السَّميعُ الْبَصيرُ سُبْحانَ مَنْ هُوَ هكَذا وَلا هكَذا غَيْرُهُ . ثمّ تدعو بما تشاء ."},{"type":"Text","content":"الثّامن : أن يأتي غسلاً آخر في آخر اللّيل سوى ما يغتسله في أوّله واعلم انّ للغسل في هذه اللّيلة واحياؤها وزيارة الحسين (عليه السلام) فيها والصّلاة مائة ركعة فضل كثير وقد أكّدتها الاحاديث ."},{"type":"Text","content":"روى الشّيخ في التهذيب عن أبي بصير قال : قال لي الصّادق (عليه السلام) : صلّ في اللّيلة التي يرجى أن تكون ليلة القدر مائة ركعة تقرأ في كلّ ركعة قُل هُوَ اللهُ اَحَدٌ عشر مرّات قال : قلت : جعلت فداك فإن لم أقو عليها قائماً قال : صلّها جالساً ، قلت : فإن لم أقو ، قال : ادّها وأنت مستلق في فراشك ."},{"type":"AboutText","content":"وعن كتاب دعائم الاسلام انّ رسول الله (صلى الله عليه وآله وسلم) كان يطوي فراشه ويشدّ مئزره للعبادة في العشر الاواخر من شهر رمضان، وكان يوقظ أهله ليلة ثلاث وعشرين، وكان يرشّ وجوه النّيام بالماء في تلك اللّيلة وكانت فاطمة صلوات الله عليها لا تدع أهلها ينامون في تلك اللّيلة وتعالجهم بقلّة الطّعام وتتأهّب لها من النّهار، أي كانت تأمرهم بالنّوم نهاراً لئلاّ يغلب عليهم النّعاس ليلاً، وتقول: محروم من حرم خيرها ."},{"type":"Text","content":"وروي انّ الصّادق (عليه السلام) كان مدنفاً فأمر فأخرج الى المسجد فكان فيه حتّى أصبح ليلة ثلاث وعشرين من شهر رمضان ."},{"type":"AboutText","content":"قال العلامة المجلسي (رحمه الله): عليك في هذه اللّيلة أن تقرأ من القرآن ما تيسّر لك، وأن تدعو بدعوات الصّحيفة الكاملة لا سيّما دعاء مكارم الاخلاق ودعاء التّوبة، وينبغي أن يراعى حرمة أيّام ليالي القدر والاشتغال فيها بالعبادة وتلاوة القرآن المجيد والدّعاء، فقد روي باسناد معتبرة انّ يوم القدر مثل ليلته ."},{"type":"Text","content":"اللّيلة السّابِعَة وَالعِشرُون"},{"type":"Text","content":"ورد فيها الغسل وروي انّ الامام زين العابدين (عليه السلام) كان يقول فيها من اوّل اللّيلة الى آخرها: اَللّـهُمَّ ارْزُقْني التَّجافِيَ عَنْ دارِ الغُرُورِ، وَالاِنابَةَ اِلى دارِ الْخُلُودِ، وَالاسْتِعْدادَ لِلْمَوْتِ قَبْلَ حُلُولِ الْفَوْتِ."}],"preview":"يا باطِناً في ظُهُورِهِ، وَيا ظاهِراً في بُطُونِهِ وَيا باطِناً لَيْسَ يَخْفى، وَيا ظاهِراً لَيْسَ يُرى، يا مَوْصُوفاً لا يَبْلُغُ بِكَيْنُونَيِةِ مَوْصُوفٌ وَلا حَدٌّ مَحْدُودٌ، و","hasTranslate":false},{"id":"mf_ar_156","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"الرّابع : أن يدعو بهذا الدّعاء الذي رواه الكليني عن الصّادق (عليه السلام) :","blocks":[{"type":"Text","content":"اَللّـهُمَّ هذا شَهْرُ رَمَضانَ الَّذي اَنْزَلْتَ فيهِ الْقُرْآنَ، وَقَدْ تَصَرَّمَ وَاَعُوذُ بِوَجْهِكَ الْكَريمِ يا رَبِّ أنْ يَطْلُعَ الْفَجْرُ مِنْ لَيْلَتي هذِهِ، اَوْ يَتَصَرَّمَ شَهْرُ رَمَضانَ وَلَكَ قِبَلي تَبِعَةٌ اَوْ ذَنْبٌ تُريدُ اَنْ تُعَذِّبَني بِهِ يَوْمَ اَلْقاكَ ."},{"type":"Text","content":"الخامس : أن يدعو بالدّعاء يا مُدَبِّرَ الاُمُورِ الخ الذي مضى في أعمال اللّيلة الثّالثة والعشرين."},{"type":"Text","content":"السّادس : أن يودّع شهر رمضان بدعوات الوداع التي رواها الكليني والصّدوق والمفيد والطّوسي والسّيد ابن طاووس رضوان الله عليهم ولعلّ احسنها هو الدّعاء الخامس والاربعون من الصّحيفة الكاملة ، وروى السّيد ابن طاووس عن الصّادق (عليه السلام) قال : مَن ودّع شهر رمضان، في آخر ليلة منه وقال : اَللّـهُمَّ لا تَجْعَلْهُ آخرَ الْعَهْدِ مِنْ صِيامي لِشَهْرِ رَمَضانَ وَاَعُوذُ بِكَ اَنْ يَطْلُعَ فَجرُ هذِهِ اللَّيْلَةِ إلاّ وَقَد غَفَرْتَ لي غفر الله تعالى له قبل أن يصبح ورزقه الانابة اليه وروى السّيد والشّيخ الصّدوق عن جابر بن عبد الله الانصاري قال : دخلت على رسول الله (صلى الله عليه وآله وسلم) في آخر جمعة من شهر رمضان فلمّا أبصر بي قال لي : يا جابر هذا آخر جُمعة من شهر رمضان فودّعه وقل : اَللّـهُمَّ لا تَجْعَلْهُ اخرَ الْعَهْدِ مِنْ صِيامِنا اِيّاهُ فَاِنْ جَعَلْتَهُ فَاجْعَلْني مَرْحُوماً وَلا تَجْعَلني مَحْرُوماً، فانّه من قال ذلك ظفر باحدى الحسنيين امّا ببلوغ شهر رمضان من قابل، وأمّا بغفران الله ورحمته ."},{"type":"AboutText","content":"وروى السّيد ابن طاووس والكفعمي عن النّبي (صلى الله عليه وآله وسلم) قال : من صلّى آخر ليلة من شهر رمضان عشر ركعات يقرأ في كلّ ركعة فاتحة الكتاب مرّة واحدة وقُلْ هُوَ اللهُ اَحَدٌ عشر مرّات ويقول في ركوعه وسجوده عشر مرّات سُبْحانَ اللهِ وَالْحَمْدُ للهِ وَلا اِلـهَ اِلاَّ اللهُ وَاللهُ اَكْبَرُ، ويتشهّد في كلّ ركعتين ثمّ يسلّم فاذا فرغ من آخر عشر ركعات وسلّم استغفر الله ألف مرّة، فاذا فرغ من الاستغفار سجد ويقول في سجوده : يا حِيُّ يا قَيُّومُ، يا ذَا الْجَلالِ وَالاِكْرام، يا رِحْمنَ الدُّنْيا وَالاخِرَةِ وَرَحيمَهُما، يا اَرْحَمَ الرّاحِمينَ، يا اِلـهَ الاَوَّلينَ وَالاخِرينَ، اِغْفِرْ لَنا ذُنُوبَنا، وَتَقَبَّلْ مِنّا صَلاتَنا وَصِيامَنا وَقِيامَنا ."},{"type":"AboutText","content":"قال النّبي (صلى الله عليه وآله وسلم) : والذي بعثني بالحقّ نبيّاً انّ جبرئيل أخبرني عن اسرافيل عن ربّه تبارك وتعالى انّه لا يرفع رأسه من السّجود حتّى يغفر الله له ويتقبّل منه شهر رمضان ويتجاوز عن ذنوبه الخبر، وقد روّيت هذه الصّلاة في ليلة عيد الفطر أيضاً ولكن في تلك الرّواية انّه يسبّح بالتسبيحات الاربع في الرّكوع والسّجود ."},{"type":"Text","content":"وورد في دعاء السّجود بعد الصّلاة عوض اِغْفِرْ لَنا ذُنُوبَنا الى آخر الدّعاء اِغْفِرْ لي ذُنُوبي وَتَقَبَّلْ صَوْمي وَصَلاتي وَقِيامي ."},{"type":"Text","content":"اليَوْمُ الثّلاثُون"},{"type":"Text","content":"روى السّيد لليوم الاخير من الشّهر دعاءاً أوّله اَللّـهُمَّ اِنَّكَ اَرْحَمَ، الرّاحِمينَ ويختم القرآن غالباً في هذا اليوم، فينبغي أن يدعى عند الختم بالدّعاء الثّاني والاربعين من الصّحيفة الكاملة ولمن شاء أن يدعو بهذا الدّعاء الوجيز الذي رواه الشّيخ عن أمير المؤمنين صلوات الله وسلامه عليه: اَللّـهُمَّ اشْرَحْ بِالْقُرْآنِ صَدْري وَاسْتَعْمِلْ بِالْقُرآنِ بَدَني، وَنَوِّرْ بِالْقُرآنِ بَصَري، وَاَطْلِقْ بِالْقُرآنِ لِساني، وَاَعَنّي عَلَيْهِ ما اَبْقَيْتَني، فَاِنَّهُ لا حَوْلَ وَلا قُوَّةَ إلاّ بِكَ، ويدعو أيضاً بهذا الدّعاء المروي عن أمير المؤمنين (عليه السلام) :"},{"type":"Text","content":"اَللّـهُمَّ اِنِّي اَسْاَلُكَ اِخْباتَ الُْمخْبِتينَ، وَاِخْلاصَ الْمُوقِنينَ، وَمُرافَقَةَ الاَْبْرارِ، وَاسْتِحْقاقَ حَقائِقِ الاِيمانِ، وَالْغَنيمَةَ مِنْ كُلِّ بِرٍّ، وَالسَّلامَةَ مِنْ كُلِّ اِثْم، وَوُجُوبَ رَحْمَتِكَ، وَعَزآئِمَ مَغْفِرَتِكَ، وَالْفَوْزَ بِالْجَنَّةِ وَالنَّجاةَ مِنَ النّارِ ."},{"type":"Text","content":"خاتمة في صلوات اللّيالي ودعوات الايّام المشهورة، وقد ذكرها العلاّمة المجلسي (رحمه الله) في كتاب زاد المعاد في الفصل الاخير من أعمال شهر رمضان، وانّني اقتصر هُنا على ما ذكر هُناك ، قال :"}],"preview":"اَللّـهُمَّ هذا شَهْرُ رَمَضانَ الَّذي اَنْزَلْتَ فيهِ الْقُرْآنَ، وَقَدْ تَصَرَّمَ وَاَعُوذُ بِوَجْهِكَ الْكَريمِ يا رَبِّ أنْ يَطْلُعَ الْفَجْرُ مِنْ لَيْلَتي هذِهِ، اَوْ يَتَصَر","hasTranslate":false},{"id":"mf_ar_157","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"المطلب الثّاني في أعمالِ شهر رَمضان الخاصّة","title":"صلاة اللّيلة الاُولى اربع ركعات في كلّ ركعة بعد الحمد التّوحيد خمس عشرة مرّة","blocks":[{"type":"Text","content":"اللّيلة الثّانية أربع ركعات في كلّ ركعة بعد الحمد عشرون مرّة انّا اَنْزَلناهُ ."},{"type":"Text","content":"الثّالثة عشر ركعات في كلّ ركعة الحمد والتّوحيد خمسون مرّة."},{"type":"Text","content":"الرّابعة ثمان ركعات في كلّ ركعة الحمد وانّا اَنْزَلناهُ عشرون مرّة."},{"type":"Text","content":"الخامسة ركعتان في كلّ منهما الحمد والتّوحيد خمسون مرّة ويقول بعد الفراغ مائة مرّة اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد ."},{"type":"Text","content":"السّادسة أربع ركعات في كلّ منها الحمد وسورة تَبارَكَ الّذي بِيَدِهِ المُلْكُ ."},{"type":"Text","content":"السّابعة أربع ركعات في كلّ منها الحمد وثلاث عشرة مرّة انّا اَنْزَلناهُ."},{"type":"Text","content":"الثّامنة ركعتان في كلّ منهما الحمد والتّوحيد عشر مرّات ويقول بعد السّلام ألف مرّة سُبْحانَ اللهِ ."},{"type":"Text","content":"التّاسِعة ستّ ركعات بين المغرب والعشاء في كلّ منها الحمد وآية الكرسي سبع مرّات ويقول بعد الفراغ خمسين مرّة اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد ."},{"type":"Text","content":"العاشرة عشرون ركعة في كلّ ركعة الحمد والتّوحيد ثلاثون مرّة."},{"type":"Text","content":"الحادية عشرة ركعتان في كلّ منهما الحمد وعشرون مرّة اِنّا اَعْطَيْناكَ الْكَوثَرَ ."},{"type":"Text","content":"الثّانية عشرة ثمان ركعات في كلّ منها الحمد وثلاثون مرّة انّا اَنْزَلناهُ ."},{"type":"Text","content":"الثّالثة عشرة أربع ركعات في كلّ منها الحمد والتّوحيد خمساً وعشرون مرّة ."},{"type":"Text","content":"الرّابعة عشرة ستّ ركعات في كلّ ركعة الحمد وثلاثون مرّة سورة اِذا زُلزِلَت ."},{"type":"Text","content":"الخامسة عشرة أربع ركعات في الاوّليين يقرأ بعد الحمد التّوحيد مائة مرّة، وفي الاخريين يقرؤها خمسون مرّة."},{"type":"Text","content":"السّادسة عشرة اثنتا عشرة ركعة في كلّ ركعة الحمد واثنتا عشرة مرّة سورة اَلْهيكُمُ التَّكاثُرُ ."},{"type":"Text","content":"السّابعة عشرة ركعتان في الاولى يقرأ بعد الحمد ما شاء من السّور وفي الثّانية يقرأ بعدها التّوحيد مائة مرّة. ويقول بعد السّلام مائة مرّة لا اِلـهَ إلاّ اللهُ"},{"type":"Text","content":"الثّامنة عشرة أربع ركعات في كلّ ركعة الحمد وخمس وعشرون مرّة سورة اِنّا اَعْطَيْناكَ الْكَوثَرَ ."},{"type":"Text","content":"التّاسعة عشرة خمسون ركعة بالحمد وخمسين مرّة سورة اِذا زُلْزِلَت والظاهر انّ المراد أن تقرأ السّورة في كلّ ركعة مرّة واحدة فانّ من الصّعب أن يقرأ سورة اذا زلزلت في ليلة واحدة الفين وخمسمائة مرّة ."},{"type":"Text","content":"صلاة اللّيلة العشرين والحادية والعشرين والثّانية والعشرين والثّالثة والعشرين والرّابعة والعشرين في كلّ من هذه اللّيالي يصلّي ثمان ركعات بما تيسّر من السّور."},{"type":"Text","content":"الخامسة والعشرين ثمان ركعات في كلّ منها الحمد والتّوحيد عشر مرّات."},{"type":"Text","content":"السّادسة والعشرين ثمان ركعات في كلّ منها الحمد والتّوحيد مائة مرّة."},{"type":"Text","content":"السّابعة والعشرين أربع ركعات في كلّ منها الحمد وسورة تَبارَكَ الّذي بِيَدِهِ المُلْكُ فان لم يتمكّن قرأ التّوحيد خمساً وعشرين مرّة."},{"type":"Text","content":"الثّامنة والعشرين ستّ ركعات في كلّ منها الحمد وآية الكرسي مائة مرّة، والتّوحيد مائة مرّة، وسورة الكوثر مائة مرّة، وبعد الصّلاة يصلّي على النّبي وآله مائة مرّة ."},{"type":"AboutText","content":"أقول : صلاة اللّيلة الثّامنة والعشرين على ما وجدتها في الاحاديث ستّ ركعات بفاتحة الكتاب وآية الكرسي عشر مرّات والكوثر عشراً وقُلْ هُوَ اللهُ اَحَدٌ عشراً ويُصلّي على النّبي وآله مائة مرّة."},{"type":"Text","content":"التّاسعة والعشرين ركعتان في كلّ منهما الحمد والتّوحيد عشرون مرّة."},{"type":"Text","content":"الثّلاثين اثنتا عشرة ركعة في كلّ ركعة الحمد والتّوحيد عشرون مرّة ويصلّي بعد الفراغ على محمّد وآل محمّد مائة مرّة وهذه الصّلوات كلّها يفصل بين كلّ ركعتين منها بالسّلام كما ذكر ."},{"type":"Text","content":"وأمّا دَعَواتِ الايّام"},{"type":"Text","content":"فقد روي عن ابن عبّاس عن النّبي (صلى الله عليه وآله وسلم) فضلاً كثيراً لصيام كلّ يوم من شهر رمضان وذكر لكلّ يوم منه دعاءاً يخصّه ذا فضل كثير وأجر جزيل ونحن نقتصر على ايراد الدّعوات ."},{"type":"Text","content":"دعاء اليوم الاوّل : اَللّـهُمَّ اجْعَلْ صِيامي فيهِ صِيامَ الصّائِمينَ، وَقِيامي فيهِ قيامَ الْقائِمينَ، وَنَبِّهْني فيهِ عَنْ نَوْمَةِ الْغافِلينَ، وَهَبْ لى جُرْمي فيهِ يا اِلـهَ الْعالَمينَ، وَاعْفُ عَنّي يا عافِياً عَنْ الُْمجْرِمينَ ."},{"type":"Text","content":"اليوم الثّاني : اَللّـهُمَّ قَرِّبْني فيهِ اِلى مَرْضاتِكَ، وَجَنِّبْني فيهِ مِنْ سَخَطِكَ وَنَقِماتِكَ، وَوَفِّقْني فيهِ لِقِرآءَةِ ايـاتِكَ بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ ."},{"type":"Text","content":"اليوم الثّالث : اَللّـهُمَّ ارْزُقْني فيهِ الذِّهْنَ وَالتَّنْبيهَ، وَباعِدْني فيهِ مِنَ السَّفاهَةِ وَالَّتمْويهِ، وَاجْعَلْ لى نَصيباً مِنْ كُلِّ خَيْر تُنْزِلُ فيهِ، بِجُودِكَ يا اَجْوَدَ الاَْجْوَدينَ ."},{"type":"Text","content":"اليوم الرّابع : اَللّـهُمَّ قَوِّني فيهِ عَلى اِقامَةِ اَمْرِكَ، وَاَذِقْني فيهِ حَلاوَةَ ذِكْرِكَ، وَاَوْزِعْني فيهِ لاَِداءِ شُكْرِكَ بِكَرَمِكَ، وَاحْفَظْني فيهِ بِحِفْظِكَ وَسَتْرِكَ، يا اَبْصَرَ النّاظِرينَ ."},{"type":"Text","content":"اليوم الخامس : اَللّـهُمَّ اجْعَلْني فيهِ مِنْ الْمُسْتَغْفِرينَ، وَاجْعَلْني فيهِ مِنْ عِبادِكَ الصّالِحينَ اْلقانِتينَ، وَاجْعَلني فيهِ مِنْ اَوْلِيائِكَ الْمُقَرَّبينَ، بِرَأْفَتِكَ يا اَرْحَمَ الرّاحِمينَ ."},{"type":"Text","content":"اليوم السّادس : اَللّـهُمَّ لا تَخْذُلْني فيهِ لِتَعَرُّضِ مَعْصِيَتِكَ، وَلاتَضْرِبْني بِسِياطِ نَقِمَتِكَ، وَزَحْزِحْني فيهِ مِنْ مُوجِباتِ سَخَطِكَ، بِمَنِّكَ وَاَياديكَ يا مُنْتَهى رَغْبَةِ الرّاغِبينَ ."},{"type":"Text","content":"اليوم السّابع : اَللّـهُمَّ اَعِنّي فِيهِ عَلى صِيامِهِ وَقِيامِهِ، وَجَنِّبْني فيهِ مِنْ هَفَواتِهِ وَآثامِهِ، وَارْزُقْني فيهِ ذِكْرَكَ بِدَوامِهِ، بِتَوْفيقِكَ يا هادِيَ الْمُضِلّينَ ."},{"type":"Text","content":"اليوم الثّامن : اَللّـهُمَّ ارْزُقْني فيهِ رَحْمَةَ الاَْيْتامِ، وَاِطْعامَ اَلطَّعامِ، وَاِفْشاءَ السَّلامِ، وَصُحْبَةَ الْكِرامِ، بِطَولِكَ يا مَلْجَاَ الاْمِلينَ ."},{"type":"Text","content":"اليوم التّاسع : اَللّـهُمَّ اجْعَلْ لي فيهِ نَصيباً مِنْ رَحْمَتِكَ الْواسِعَةِ، وَاهْدِني فيهِ لِبَراهينِكَ السّاطِعَةِ، وَخُذْ بِناصِيَتي اِلى مَرْضاتِكَ الْجامِعَةِ، بِمَحَبَّتِكَ يا اَمَلَ الْمُشْتاقينَ ."},{"type":"Text","content":"اليوم العاشر : اَللّـهُمَّ اجْعَلْني فيهِ مِنَ الْمُتَوَكِّلينَ عَلَيْكَ، وَاجْعَلْني فيهِ مِنَ الْفائِزينَ لَدَيْكَ، وَاجْعَلْني فيهِ مِنَ الْمُقَرَّبينَ اِلَيْكَ، بِاِحْسانِكَ يا غايَةَ الطّالِبينَ ."},{"type":"Text","content":"اليوم الحادي عشر : اَللّـهُمَّ حَبِّبْ اِلَيَّ فيهِ الاِْحْسانَ، وَكَرِّهْ اِلَيَّ فيهِ الْفُسُوقَ وَالْعِصْيانَ، وَحَرِّمْ عَلَيَّ فيهِ السَّخَطَ وَالنّيرانَ بِعَوْنِكَ يا غِياثَ الْمُسْتَغيثينَ ."},{"type":"Text","content":"اليوم الثّاني عشر : اَللّـهُمَّ زَيِّنّي فيهِ بِالسِّتْرِ وَالْعَفافِ، وَاسْتُرْني فيهِ بِلِباسِ الْقُنُوعِ وَالْكَفافِ، وَاحْمِلْني فيهِ عَلَى الْعَدْلِ وَالاِْنْصافِ، وَآمِنّي فيهِ مِنْ كُلِّ ما اَخافُ، بِعِصْمَتِكَ يا عِصْمَةَ الْخائِفينَ ."},{"type":"Text","content":"اليوم الثّالث عشر : اَللّـهُمَّ طَهِّرْني فيهِ مِنَ الدَّنَسِ وَالاَْقْذارِ، وَصَبِّرْني فيهِ عَلى كائِناتِ الاَْقْدارِ، وَوَفِّقْني فيهِ لِلتُّقى وَصُحْبَةِ الاَْبْرارِ، بِعَوْنِكَ يا قُرَّةَ عَيْنِ الْمَساكينَ ."},{"type":"Text","content":"اليوم الرّابع عشر : اَللّـهُمَّ لا تُؤاخِذْني فيهِ بِالْعَثَراتِ، وَاَقِلْني فيهِ مِنَ الْخَطايا وَالْهَفَواتِ، وَلا تَجْعَلْني فيهِ غَرَضاً لِلْبَلايا وَالاْفاتِ، بِعِزَّتِكَ يا عِزَّ الْمُسْلِمينَ ."},{"type":"Text","content":"اليوم الخامس عشر : اَللّـهُمَّ ارْزُقْني فيهِ طاعَةَ الْخاشِعينَ، وَاشْرَحْ فيهِ صَدْري بِاِنابَةِ الُْمخْبِتينَ، بِاَمانِكَ يا اَمانَ الْخائِفينَ ."},{"type":"Text","content":"اليوم السّادس عشر : اَللّـهُمَّ وَفِّقْني فيهِ لِمُوافَقَةِ الاَْبْرارِ، وَجَنِّبْني فيهِ مُرافَقَةَ الاَْشْرارِ، وَآوِني فيهِ بِرَحْمَتِكَ اِلى دارِ الْقَـرارِ، بِاِلهِيَّتِكَ يا اِلـهَ الْعالَمينَ ."},{"type":"Text","content":"اليوم السّابع عشر : اَللّـهُمَّ اهْدِني فيهِ لِصالِحِ الاَْعْمالِ، وَاقْضِ لي فيهِ الْحَوائِجَ وَالاْمالَ، يا مَنْ لا يَحْتاجُ اِلَى التَّفْسيرِ وَالسُّؤالِ، يا عالِماً بِما في صُدُورِ الْعالَمينَ، صَلِّ عَلى مُحَمَّد وَآلِهِ الطّاهِرينَ ."},{"type":"Text","content":"اليوم الثّامن عشر : اَللّـهُمَّ نَبِّهْني فيهِ لِبَرَكاتِ اَسْحارِهِ، وَنَوِّرْ فيهِ قَلْبي بِضياءِ اَنْوارِهِ، وَخُذْ بِكُلِّ اَعْضائي اِلَى اتِّباعِ آثارِهِ، بِنُورِكَ يا مُنَوِّرَ قُلُوبِ الْعارِفينَ ."},{"type":"Text","content":"اليوم التّاسع عشر : اَللّـهُمَّ وَفِّرْ فيهِ حَظّي مِنْ بَرَكاتِهِ، وَسَهِّلْ سَبيلي اِلى خَيْراتِهِ، وَلا تَحْرِمْني قَبُولَ حَسَناتِهِ، يا هادِياً اِلَى الْحَقِّ الْمُبينِ ."},{"type":"Text","content":"اليوم العشرين : اَللّـهُمَّ افْتَحْ لي فيهِ اَبْوابَ الْجِنانِ، وَاَغْلِقْ عَنّي فيهِ اَبْوابَ النّيرانِ، وَوَفِّقْني فيهِ لِتِلاوَةِ الْقُرْآنِ، يا مُنْزِلَ السَّكينَةِ فى قُلُوبِ الْمُؤْمِنينَ ."},{"type":"Text","content":"اليوم الحادي والعشرين : اَللّـهُمَّ اجْعَلْ لى فيهِ اِلى مَرْضاتِكَ دَليلاً، وَلا تَجْعَلْ لِلشَّيْطانِ فيهِ عَلَيَّ سَبيلاً، وَاجْعَلِ الْجَنَّةَ لى مَنْزِلاً وَمَقيلاً، يا قاضِيَ حَوائِجِ الطّالِبينَ ."},{"type":"Text","content":"اليوم الثّاني والعشرين : اَللّـهُمَّ افْتَحْ لى فيهِ اَبْوابَ فَضْلِكَ، وَاَنْزِلْ عَلَيَّ فيهِ بَرَكاتِكَ، وَوَفِّقْني فيهِ لِمُوجِباتِ مَرْضاتِكَ، وَاَسْكِنّي فيهِ بُحْبُوحاتِ جَنّاتِكَ، يا مُجيبَ دَعْوَةِ الْمُضْطَرّينَ ."},{"type":"Text","content":"اليوم الثّالث والعشرين : اَللّـهُمَّ اغْسِلْني فيهِ مِنَ الذُّنُوبِ، وَطَهِّرْني فيهِ مِنَ الْعُيُوبِ، وَامْتَحِنْ قَلْبي فيهِ بِتَقْوَى الْقُلُوبِ، يا مُقيلَ عَثَراتِ الْمُذْنِبينَ ."},{"type":"Text","content":"اليوم الرّابع والعشرين : اَللّـهُمَّ اِنّي اَسْأَلُكَ فيهِ ما يُرْضيكَ، وَاَعُوذُبِكَ مِمّا يُؤْذيكَ، وَاَسْأَلُكَ التَّوْفيقَ فيهِ لاَِنْ اُطيعَكَ وَلا اَعْصيْكَ، يا جَوادَ السّائِلينَ ."},{"type":"Text","content":"اليوم الخامس والعشرين : اَللّـهُمَّ اجْعَلْني فيهِ مُحِبَّاً لاَِوْلِيائِكَ، وَمُعادِياً لاَِعْدائِكَ، مُسْتَنّاً بِسُنَّةِ خاتَمِ اَنْبِيائِكَ، يا عاصِمَ قُلُوبِ النَّبِيّينَ ."},{"type":"Text","content":"اليوم السّادس والعشرين : اَللّـهُمَّ اجْعَلْ سَعْيي فيهِ مَشْكُوراً، وَذَنْبي فيهِ مَغْفُوراً وَعَمَلي فيهِ مَقْبُولاً، وَعَيْبي فيهِ مَسْتُوراً، يا اَسْمَعَ السّامِعينَ ."},{"type":"Text","content":"اليوم السّابع والعشرين : اَللّـهُمَّ ارْزُقْني فيهِ فَضْلَ لَيْلَةِ الْقَدْرِ، وَصَيِّرْ اُمُوري فيهِ مِنَ الْعُسْرِ اِلَى الْيُسْرِ، وَاقْبَلْ مَعاذيري، وَحُطَّ عَنّيِ الذَّنْبَ وَالْوِزْرَ، يا رَؤوفاً بِعِبادِهِ الصّالِحينَ ."},{"type":"Text","content":"اليوم الثّامن والعشرين : اَللّـهُمَّ وَفِّرْ حَظّي فيهِ مِنَ النَّوافِلِ، وَاَكْرِمْني فيهِ بِاِحْضارِ الْمَسائِلِ، وَقَرِّبْ فيهِ وَسيلَتى اِلَيْكَ مِنْ بَيْنِ الْوَسائِلِ، يا مَنْ لا يَشْغَلُهُ اِلْحـاحُ الْمُلِحّينَ ."},{"type":"Text","content":"اليوم التّاسع والعشرين : اَللّـهُمَّ غَشِّني فيهِ بِالرَّحْمَةِ، وَارْزُقْني فيهِ التَّوْفيقَ وَالْعِصْمَةَ، وَطَهِّرْ قَلْبي مِنْ غَياهِبِ التُّهْمَةِ، يا رَحيماً بِعِبادِهِ الْمُؤْمِنينَ ."},{"type":"Text","content":"اليوم الثّلاثين : اَللّـهُمَّ اجْعَلْ صِيامى فيهِ بِالشُّكْرِ وَالْقَبُولِ عَلى ما تَرْضاهُ وَيَرْضاهُ الرَّسُولُ، مُحْكَمَةً فُرُوعُهُ بِالاُْصُولِ، بِحَقِّ سَيِّدِنا مُحَمَّد وَآلِهِ الطّاهِرينَ، وَالْحَمْدُ للهِ رَبِّ الْعالَمينَ ."},{"type":"AboutText","content":"أقول : اختلفت كتب الدّعوات في تقديم بعض الدّعوات والعبادات على بعض، والرّواية في ذلك غير معتبرة عندي لذلك لم أتعرّض لشيء منه، وقد ذكر الكفعمي دعاء اليوم السّابع والعشرين لليوم التّاسع والعشرين ولا يبعد أن يكون الانسب على مذهب الشّيعة الدّعاء به في اليوم الثّالث والعشرين ، انتهى ."}],"preview":"اللّيلة الثّانية أربع ركعات في كلّ ركعة بعد الحمد عشرون مرّة انّا اَنْزَلناهُ .","hasTranslate":false},{"id":"mf_ar_158","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل الرّابِعُ :","title":"في أعمالِ شهرِ شَوّال","blocks":[{"type":"Text","content":"اللّيلة الاولى"},{"type":"Text","content":"هي من اللّيالي الشّريفة وقد وردت في فضل العبادة فيها واحيائها احاديث كثيرة ، وروي انّها لا تقل عن ليلة القدر ولها عدّة أعمال :"}],"preview":"اللّيلة الاولى","hasTranslate":false},{"id":"mf_ar_159","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل الرّابِعُ :","title":"الثّاني : احياؤها بالصّلاة والدّعاء والاستغفار والبيتوتة في المسجد","blocks":[{"type":"Text","content":"الثّالث : أن يقول في أعقاب صلوات المغرب والعشاء وعقيب صلاة العيد اللهُ اَكْبَرُ اللهُ اَكْبَرُ لا اِلـهَ إلاّ اللهُ وَاللهُ اَكْبَرُ، اللهُ اَكْبَرُ وَللهِ الْحَمْدُ، الْحَمْدُ للهِ عَلى ما هَدانا وَلَهُ الشُّكْرُ على ما اَوْلانا ."},{"type":"Text","content":"الرّابع : أن يرفع يديه الى السّماء اذا فرغ من فريضة المغرب ونافلته ويقول : يا ذَا الْمَنِّ وَالطَّوْلِ ا يا ذَا الْجُودِ، يا مُصْطَفِيَ مُحَمَّد وَناصِرَهُ، صَلِّ عَلى مُحَمَّد وَآل مُحَمَّد، وَاغْفِرْ لي كُلَّ ذَنْب اَحْصَيْتَهُ ا وَهُوَ عِنْدَكَ في كِتاب مُبين ثمّ يسجد ويقول في سجوده مائة مرّة اَتُوبُ اِلَى اللهِ ."},{"type":"Text","content":"الخامس : زيارة الحسين (عليه السلام) فانّ لها فضلاً عظيماً وسيأتي في باب الزّيارات ما يخصّ هذه اللّيلة من الزّيارة ."}],"preview":"الثّالث : أن يقول في أعقاب صلوات المغرب والعشاء وعقيب صلاة العيد اللهُ اَكْبَرُ اللهُ اَكْبَرُ لا اِلـهَ إلاّ اللهُ وَاللهُ اَكْبَرُ، اللهُ اَكْبَرُ وَللهِ الْحَمْدُ، الْحَمْدُ لله","hasTranslate":false},{"id":"mf_ar_160","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل الرّابِعُ :","title":"السّابع : أن يصلّي عشر ركعات التي مضت في أعمال اللّيلة الاخيرة من شهر رمضان (ص232)","blocks":[{"type":"Text","content":"الثّامن : يصلّي ركعتين يقرأ في الاُولى بعد الحمد التّوحيد ألف مرّة ويقرأها في الثّانية مرّة واحدة ويسجد بعد السّلام فيقول : اَتُوبُ اِلَى اللهِ (ثمّ يقول) يا ذَا الْمَنِّ وَالطَّوْلِ، يا مُصْطَفِيَ مُحَمَّد صَلّى اللهُ عَلَيْهِ وَآلِهِ، صَلِّ عَلى مُحَمَّد وَآلِهِ وَافْعَلْ بي كَذا وَكَذا ويسأل حاجته ."},{"type":"Text","content":"وروي انّ امير المؤمنين (عليه السلام) كان يصلّيها كما ذكر فاذا رفع رأسه يقول: والذي نفسي بيده لا يفعلها احد يسأل الله تعالى شيئاً الّا أعطاه ولو أتاه من الذّنوب عدد رمل الصّحراء غفر الله له ، ووردت التّوحيد في رواية اخرى مائة مرّة عوض الالف مرّة ولكن على هذه الرّواية يصلّي هذه الصّلاة بعد فريضة المغرب ونافلته ."}],"preview":"الثّامن : يصلّي ركعتين يقرأ في الاُولى بعد الحمد التّوحيد ألف مرّة ويقرأها في الثّانية مرّة واحدة ويسجد بعد السّلام فيقول : اَتُوبُ اِلَى اللهِ (ثمّ يقول) يا ذَا الْمَنِّ وَالطَّوْ","hasTranslate":false},{"id":"mf_ar_161","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل الرّابِعُ :","title":"وقد روى الشّيخ والسّيد بعد هذه الصّلاة هذا الدّعاء :","blocks":[{"type":"Text","content":"يا اَللهُ يا اَللهُ يا اَللهُ، يا رَحْمنُ يا اَللهُ، يا رَحيمُ يا اَللهُ، يا مَلِكُ يا اَللهُ، يا قُدُّوسُ يا اَللهُ، يا سَلامُ يا اَللهُ، يا مؤْمِنُ يا اَللهُ يا مُهَيْمِنُ يا اَللهُ، يا عَزيزُ يا اَللهُ، يا جَبّارُ يا اَللهُ، يا مُتَكَبِّرُ يا اَللهُ، يا خالِقُ يا اَللهُ، يا بارِئُ يا اَللهُ، يا مُصَوِّرُ يا اَللهُ، يا عالِمُ يا اَللهُ، يا عَظيمُ يا اَللهُ، يا عَليمُ يا اَللهُ، يا كَريمُ يا اَللهُ، يا حَليمُ يا اَللهُ، يا حَكيمُ يا اَللهُ، يا سَميعُ يا اَللهُ، يا بَصيرُ يا اَللهُ، يا قَريبُ يا اَللهُ، يا مُجيبُ يا اَللهُ، يا جَوادُ يا اَللهُ، يا ماجِدُ يا اَللهُ، يا مِليُّ يا اَللهُ، يا وَفِيُّ يا اَللهُ، يا مَوْلى يا اَللهُ، يا قاضي يا اَللهُ، يا سَريعُ يا اَللهُ، يا شَديدُ يا اَللهُ، يا رَؤوفُ يا اَللهُ، يا رَقيبُ يا اَللهُ، يا مَجيدُ يا اَللهُ، يا حَفيظُ يا اَللهُ، يا مُحيطُ يا اَللهُ، يا سَيِّدَ السّاداتِ يا اَللهُ، يا اَوَّلُ يا اَللهُ، يا اخِرُ يا اَللهُ يا ظاهِرُ يا اَللهُ، يا باطِنُ يا اَللهُ، يا فاخِرُ يا اَللهُ، يا قاهِرُ يا اَللهُ، يا رَبّاهُ يا اَللهُ يا رَبّاهُ يا اَللهُ يا رَبّاهُ يا اَللهُ، يا وَدُودُ يا اَللهُ، يا نُورُ يا اَللهُ، يا رافِعُ يا اَللهُ، يا مانِعُ يا اَللهُ، يا دافِعُ يا اَللهُ، يا فاتِحُ يا اَللهُ، يا نَفّاحُ يا اَللهُ، يا جَليلُ يا اَللهُ، يا جَميلُ يا اَللهُ، يا شَهيدُ يا اَللهُ، يا شاهِدُ يا اَللهُ، يا مُغيثُ يا اَللهُ، يا حَبيبُ يا اَللهُ، يا فاطِرُ يا اَللهُ، يا مُطَهِّرُ يا اَللهُ، يا مَلِكُ يا اَللهُ، يا مُقْتَدِرُ يا اَللهُ، يا قابِضُ يا اَللهُ، يا باسِطُ يا اَللهُ، يا مِحيي يا اَللهُ، يا مُميتُ يا اَللهُ يا باعِثُ يا اَللهُ، يا وارِثُ يا اَللهُ، يا مُعطي يا اَللهُ، يا مُفْضِلُ يا اَللهُ، يا مُنْعِمُ يا اَللهُ، يا حَقُّ يا اَللهُ، يا مُبينُ يا اَللهُ، يا طَيِّبُ يا اَللهُ، يا مُحْسِنُ يا اَللهُ، يا مُجْمِلُ يا اَللهُ، يا مُبْدِئُ يا اَللهُ، يا مُعيدُ يا اَللهُ، يا بارِئُ يا اَللهُ، يا بَديعُ يا اَللهُ، يا هادي يا اَللهُ، يا كافي يا اَللهُ، يا شافي يا اَللهُ، يا عَلِىُّ يا اَللهُ، يا عَظيمُ يا اَللهُ، يا حَنّانُ يا اَللهُ، يا مَنّانُ يا اَللهُ، يا ذَا الْطَّوْلِ يا اَللهُ، يا مُتَعالي يا اَللهُ، يا عَدْلُ يا اَللهُ، يا ذَا الْمَعارِجِ يا اَللهُ، يا صادِقُ يا اَللهُ، يا صَدُوقُ يا اَللهُ، يا دَيّانُ يا اَللهُ، يا باقي يا اَللهُ، يا واقي يا اَللهُ، يا ذَا الْجَلالِ يا اَللهُ، يا ذَا الاِكْرامِ يا اَللهُ، يا مَحْمُودُ يا اَللهُ، يا مَعْبُودُ يا اَللهُ، يا صانِعُ يا اَللهُ، يا مُعينُ يا اَللهُ، يا مُكَوِّنُ يا اَللهُ، يا فَعّالُ يا اَللهُ، يا لَطيفُ يا اَللهُ، يا غَفُورُ يا اَللهُ، يا شَكُورُ يا اَللهُ، يا نُورُ يا اَللهُ، يا قَديرُ يا اَللهُ، يا رَبّاهُ يا اَللهُ يا رَبّاهُ يا اَللهُ يا رَبّاهُ يا اَللهُ يا رَبّاهُ يا اَللهُ يا رَبّاهُ يا اَللهُ يا رَبّاهُ يا اَللهُ يا رَبّاهُ يا اَللهُ يا رَبّاهُ يا اَللهُ يا رَبّاهُ يا اَللهُ يا رَبّاهُ اَسْاَلُكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَتَمُنَّ عَلَيَّ بِرِضاكَ، وَتَعْفُوَ عَنّي بِحِلْمِكَ، وَتُوَسِّعَ عَلَيَّ مِنْ رِزْقِكَ الْحَلالِ الطَّيِّبِ، وَمِنْ حَيْثُ اَحْتَسِبُ وَمِنْ حَيْثُ لا اَحْتَسِبُ، فَاِنّي عَبْدُكَ لَيْسَ لي اَحَدٌ سِواكَ، وَلا اَحَدٌ اَسْأَلُهُ غَيْرُكَ يا اَرْحَمَ الرّاحِمينَ، ما شاءَ اللهُ لا قُوَّةَ إلاّ بِاللهِ الْعَلِيِّ الْعَظيمِ (ثم تسجد وتقول) يا اَللهُ يا اَللهُ يا اَللهُ، يا رَبُّ رَبُّ رَبُّ يا مُنْزِلَ الْبَرَكاتِ بِكَ تُنْزَلُ كُلُّ حاجَة، اَسْاَلُكَ بِكُلِّ اسْم في مَخْزُونِ الْغَيْبِ عِنْدَكَ، وَالاَْسْماءِ الْمَشْهُورةِ عِنْدَكَ، الْمَكْتُوبَةِ عَلى سُرادِقِ عَرْشِكَ، اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَنْ تَقْبَلَ مِنّي شَهْرَ رَمَضانَ، وَتَكْتُبَني مِنَ الْوافِدينَ اِلى بَيْتِكَ الْحَرامِ، وَتَصْفَحَ لي عَنِ الذُّنُوبِ الْعِظامِ، وَتَسْتَخْرِجَ لي يا رَبِّ كُنُوزَكَ يا رَحْمـنُ ."},{"type":"Text","content":"التّاسع : يصلّي أربع عشرة ركعة يقرأ في كلّ ركعة الحمد وآية الكرسي وثلاث مرّات سورة قُل هو اللهُ احدٌ ليكون له بكلّ ركعة عبادة أربعين سنة وعبادة كلّ من صام وصلّى في هذا الشّهر ."},{"type":"Text","content":"العاشر : قال الشّيخ في المصباح: اغتسل في آخر اللّيل واجلس في مصلاّك الى طلوع الفجر ."}],"preview":"يا اَللهُ يا اَللهُ يا اَللهُ، يا رَحْمنُ يا اَللهُ، يا رَحيمُ يا اَللهُ، يا مَلِكُ يا اَللهُ، يا قُدُّوسُ يا اَللهُ، يا سَلامُ يا اَللهُ، يا مؤْمِنُ يا اَللهُ يا مُهَيْمِنُ يا اَل","hasTranslate":false},{"id":"mf_ar_162","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل الرّابِعُ :","title":"اعمال يوم عيد الفطر","blocks":[{"type":"Text","content":"اليَوم الاوّل"}],"preview":"اليَوم الاوّل","hasTranslate":false},{"id":"mf_ar_163","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل الرّابِعُ :","title":"يوم عيد الفطر وأعماله عديدة :","blocks":[{"type":"Text","content":"الاوّل : أن تكبّر بعد صلاة الصّبح وبعد صلاة العيد بما مرّ من التكبيرات في ليلة العيد بعد الفريضة ."},{"type":"Text","content":"الثّاني : أن تدعو بعد فريضة الصّبح بما رواه السّيد (رحمه الله) من دعاء اَللّـهُمَّ اِنّي تَوَجَّهْتُ اِلَيْكَ بِمُحَمَّد اَمامي الخ وقد أورد الشّيخ هذا الدّعاء بعد صلاة العيد ."},{"type":"Text","content":"الثّالث : اخراج زكاة الفطرة صاعاً عن كلّ نسمة قبل صلاة العيد على التّفصيل المبين في الكتب الفقهيّة، واعلم انّ زكاة الفطر من الواجبات المؤكّدة، وهي شرط في قبول صوم شهر رمضان، وهي أمان عن الموت الى السّنة القابلة، وقد قدّم الله تعالى ذكرها على الصّلاة في الاية الكريمة « قَدْ اَفْلَحَ » ."},{"type":"Text","content":"الرّابع : الغسل والاحسن أن يغتسل من النّهر اذا تمكّن ووقت الغسل من الفجر الى حين أداء صلاة العيد، كما قال الشّيخ، وفي الحديث ليكن غسلك تحت الظّلال أو تحت حائط فاذا هممت بذلك فقل: اَللّـهُمَّ اِيماناً بِكَ وَتَصْديقاً بِكِتابِكَ، وَاتّباعَ سُنَّةِ نَبيِّكَ مُحَمَّد صَلّى اللهُ عَلَيْهِ وَآلِهِ، ثمّ سمّ بِسم اللهِ واغتسل، فاذا فرغت من الغسل فقل : اَللّـهُمَّ اجْعَلْهُ كَفّارَةً لِذُنُوبي وَطَهِّرْ ديني، اَللّـهُمَّ اَذْهِبْ عَنِّي الدَّنَسَ ."},{"type":"Text","content":"الخامس : تحسين الثّياب واستعمال الطّيب والاصحار في غير مكّة للصّلاة تحت السّماء ."},{"type":"Text","content":"السّادس : الافطار اوّل النّهار قبل صلاة العيد، والافضل أن يفطر على التّمر أو على شيء من الحلوى وقال الشّيخ المفيد: يستحبّ أن يبتلع شيئاً من تُربة الحسين (عليه السلام) فانّها شفاء من كلّ داء ."},{"type":"Text","content":"السّابع : أن لا تخرج لصلاة العيد الّا بعد طلوع الشّمس، وأن تدعو بما رواه السّيد في الاقبال من الدّعوات، منها ما رواه عن أبي حمزة الثّمالي، عن الباقر (عليه السلام) قال : ادع في العيدين والجمعة اذا تهيّأت للخروج بهذا الدّعاء :"},{"type":"Text","content":"اَللّـهُمَّ مَنْ تَهَيَّأَ في هذَا الْيَوْمِ اَوْ تَعَبَّأَ اَوْ اَعَدَّ وَاسْتَعَدَّ لِوِفادَة اِلى مَخْلُوق رَجاءَ رِفْدِهِ وَنَوافِلِهِ وَفَواضِلِهِ وَعَطاياهُ، فَاِنَّ اِلَيْكَ يا سَيِّدي تَهْيِئَتي وَتَعْبِئَتي وَاِعْدادي وَاسْتِعْدادي رَجاءَ رِفْدِكَ وَجَوائِزِكَ وَنَوافِلِكَ وَفَواضِلِكَ وَفَضائِلِكَ وَعَطاياكَ، وَقَدْ غَدَوْتُ اِلى عيد مِنْ اَعْيادِ اُمَّةِ نَبيِّكَ مُحَمَّد صَلَواتُ اللهِ عَلَيْهِ وَعَلى آلِهِ، وَلَمْ اَفِدْ اِلَيْكَ الْيَوْمَ بِعَمَل صالِح اَثِقُ بِهِ قَدَّمْتُهُ، وَلا تَوَجَّهْتُ بِمَخْلُوق اَمَّلْتُهُ، وَلكِنْ اَتَيْتُكَ خاضِعاً مُقِرّاً بِذُنُوبي وَاِساءَتي اِلى نَفْسي، فَيا عَظيمُ يا عَظيمُ يا عَظيمُ اِغْفِرْ لِيَ الْعَظيمَ مِنْ ذُنُوبي، فَاِنَّهُ لا يَغْفِرُ الذُّنُوبَ الْعِظامَ إلاّ اَنْتَ يا لا اِلـهَ إلاّ اَنْتَ، يا اَرْحَمَ الرّاحِمينَ ."},{"type":"Text","content":"الثّامن : صلاة العيد وهي ركعتان يقرأ في الاُولى الحمد وسورة الاعلى، ويكبّر بعد القراءة خمس تكبيرات وتقنت بعد كلّ تكبيرة فتقول :"},{"type":"Text","content":"اَللّـهُمَّ اَهْلَ الْكِبْرِياءِ وَالْعَظَمَةِ، وَاَهْلَ الْجُودِ وَالْجَبَرُوتِ، وَاَهْلَ الْعَفْوِ وَالرَّحْمَةِ، وَاَهْلَ التَّقْوى وَالْمَغْفِرَةِ، اَسْاَلُكَ بِحَقِّ هذَا الْيَومِ الَّذي جَعَلْتَهُ لِلْمُسْلِمينَ عيداً، وَلُِمحَمَّد صَلَّى اللهُ عَلَيْهِ وَآلِهِ ذُخْراً وَشَرَفاً وَمَزيْداً، اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَنْ تُدْخِلَني في كُلِّ خَيْر اَدْخَلْتَ فيهِ مُحَمَّداً وَآلَ مُحَمَّد، وَاَنْ تُخْرِجَني مِنْ كُلِّ سُوء اَخْرَجْتَ مِنْهُ مُحَمَّداً وَآلَ مُحَمَّد صَلَواتُكَ عَلَيْهِ وَعَلَيْهِمْ، اَللّـهُمَّ اِنّي اَسْاَلُكَ خَيْرَ ما سَأَلَكَ مِنْهُ عِبادُكَ الصّالِحُونَ، وَاَعُوذُ بِكَ مِمَّا اسْتعاذَ مِنْهُ عِبادُكَ الْصّالِحُونَ ."},{"type":"Text","content":"ثمّ تكبّر السّادسة وتركع وتسجد، ثمّ تنهض للركعة الثّانية، فتقرأ فيها بعد الحمد سورة والشّمس، ثمّ تكبرّ أربع تكبيرات تقنت بعد كلّ تكبيرة وتقرأ في القنوت ما مرّ، فاذا فرغت كبّرت الخامسة فركعت وأتممت الصّلاة وسبّحت بعد الصّلاة تسبيح الزّهراء (عليها السلام)، وقد وردت دعوات كثيرة بعد صلاة العيد ولعلّ أحسنها هو الدّعاء السّادس والاربعون من الصّحيفة الكاملة، ويستحبّ أن يبرز في صلاة العيد تحت السّماء، وأن يصلّي على الارض من دون بساط ولا بارية، وأن يرجع عن المصلّى من غير الطّريق الذي ذهب منه، وأن يدعو لاخوانه المؤمنين بقبول أعمالهم ."},{"type":"Text","content":"التّاسع : أن يزور الحسين (عليه السلام) ."},{"type":"Text","content":"العاشر : قراءة دعاء النّدبة، وسيأتي إن شاء الله تعالى، وقال السّيد ابن طاووس (رحمه الله): اسجد اذا فرغت من الدّعاء فقُل : اَعُوذُ بِكَ مِنْ نار حَرُّها لا يَطْفى، وَجَديدُها لا يَبْلى، وَعَطْشانُها لا يُرْوى، (ثمّ ضع خدّك الايمن على الارض وقل ) اِلهي لا تُقَلِّبْ وَجْهي في النّارِ بَعْدَ سُجُودي وَتَعْفيري لَكَ بِغَيْرِ مَنٍّ مِنّي عَلَيْكَ بَلْ لَكَ الْمَنُّ عَلَيَّ (ثمّ ضع خدّك الايسر على الارض وقل) اِرْحَمْ مَنْ اَساءَ وَاقْتَرَفَ وَاسْتَكانَ وَاعْتَرَفَ (ثمّ عد الى السّجود وقل) اِنْ كُنْتُ بِئْسَ الْعَبْدُ فَاَنْتَ نِعْمَ الرَّبُّ، عَظُمَ الذَّنْبُ مِنْ عَبْدِكَ فَلْيَحْسُنِ الْعَفْوُ مِنْ عِنْدِكَ يا كَريمُ (ثمّ قل) الْعَفْوَ الْعَفْوَ مائة مرّة ثمّ قال السّيد : ولا تقطع يومك هذا باللّعب والاهمال وأنت لا تعلم اَمَردودٌ أم مقبول الاعمال، فاِن رجوت القبول فقابل ذلك بالشّكر الجميل واِن خفت الرّدَّ فكُن أسير الحزن الطويل."},{"type":"Text","content":"اليوم الخامس والعشرون فيه على بعض الاقوال توفّي الامام جعفر بن محمّد الصّادق (عليه السلام) في سنة مائة وثماني وأربعين وقد ارتأى البعض انّ وفاته كانت في النّصف من رجب، وكان سبب وفاته سمّاً دسّ له في العِنب، وروي انّه (عليه السلام)حينما حضرته الوفاة فتح عينيه وقال : اجمعوا لي الاقارب، فلمّا اجتمعوا كلّهم نظر اليهم وقال : لا يبلغ شفاعتنا من استخفّ بصلاته ولم يهتمّ بها ."}],"preview":"الاوّل : أن تكبّر بعد صلاة الصّبح وبعد صلاة العيد بما مرّ من التكبيرات في ليلة العيد بعد الفريضة .","hasTranslate":false},{"id":"mf_ar_164","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل الخامِسُ :","title":"في أعمالِ شهرِ ذِي القعدة","blocks":[{"type":"AboutText","content":"اعلم انّ هذا الشّهر هو اوّل الاشهر الحرم التي ذكرها الله في كتابه المجيد، وروى السّيد ابن طاووس في حديث انّ شهر ذي القعدة موقع اجابة الدّعاء عند الشّدة، وروي عن رسول الله (صلى الله عليه وآله وسلم) صلاة في اليوم الاحّد من هذا الشّهر ذات فضل كثير، وفضلها مُلخّصاً انّ من صلّاها قبلت توبته، وغفرت ذنوبه، ورضى عنه خصماؤه يوم القيامة ومات على الايمان وما سلب منه الدّين، ويفسح في قبره، وينوّر فيه، ويرضى عنه أبواهُ، ويغفر لابويهِ ولذرّيّته، ويوسّع في رزقه، ويرفق به ملك الموت عند موته، ويخرج الرّوح من جسده بُسير وسهولة، وصفتها أن يغتسل في اليوم الاحّد ويتوضّأ ويصلّي أربع ركعات يقرأ في كلّ منها الحمد مرّة وقُلْ هُوَ اللهُ اَحَدٌ ثلاث مرّات والمعوّذتين مرّة ثمّ يستغفر سبعين مرّة ثمّ يختم بكلمة لا حَوْلَ وَلا قُوَّةَ إلاّ بِاللهِ الْعَليِّ الْعَظيمِ ثمّ يقول : يا عَزيزُ يا غَفّارُ اغْفِرْ لي ذُنُوبي وَذُنُوبَ جَميعِ المؤمِنينَ وَالْمُؤمِناتِ فَاِنَّهُ لا يَغْفِرُ الذُّنُوبَ إلاّ اَنْتَ ."},{"type":"AboutText","content":"أقول : الظّاهر انّ هذا الاستغفار والدّعاء الّذي ورد بعده يؤدّى بعد الصّلاة، واعلم انّ في الحديث انّ من صام من شهر حرام ثلاثة ايّام ; الخميس والجُمعة والسّبت كتب له عِبادة تسعمائة سنة، وقال الشّيخ الاجلّ عليّ بن ابراهيم القمّي: انّ السيّئات تضاعف في الاشهر الحرم وكذلك الحسنات ."},{"type":"Text","content":"اليوم الحادي عشر : كان فيه في سنة مائة وثماني وأربعين ولادة الامام الرّضا (عليه السلام) ."},{"type":"Text","content":"اللّيلة الخامسة عشرة : ليلة مُباركة ينظر الله تعالى فيها الى عباده المؤمنين بالرّحمة وأجر العامل فيها بطاعة الله أجر مائة سائح (أي الصّائم المُلازم للمسجد) لم يعص الله طرفة عين كما في النّبوي، فاغتنمّ هذه اللّيلة واشتغل فيها بالعبادة والطّاعة والصّلاة وطلب الحاجات من الله تعالى ، فقد روي انّه من سأل الله تعالى فيها حاجة اعطاه ما سأل ."},{"type":"Text","content":"اليوم الثّالِثُ والعِشرون : من سنة مائتين توفّي فيه الامام الرّضا صلوات الله وسلامه عليه على بعض الاقوال ومن المسنون فيه زيارة الرّضا (عليه السلام) من قرب أو بعد ."},{"type":"AboutText","content":"قال السّيد بن طاووس (رحمه الله) في الاقبال : ورأيت في بعض تصانيف أصحابنا العجم رضوان الله عليهم انّه يستحبّ أن يزار مولانا الرّضا (عليه السلام) يوم ثالث وعشرين من ذي القعدة من قرب أو بعد ببعض زياراته المعروفة أو بما يكون كالزّيارة من الرّواية بذلك ."},{"type":"Text","content":"اللّيلة الخامسة والعشرون : ليلة دحو الارض (انبساط الارض من تحت الكعبة على الماء) ، وهي ليلة شريفة تنزل فيها رحمة الله تعالى، وللقيام بالعبادة فيها أجر جزيل، وروي عن الحسن بن عليّ الوشّاء قال : كنت مع أبي وأنا غلام فتعشّينا عند الرّضا (عليه السلام) ليلة خمسة وعشرين من ذي القعدة ، فقال له: ليلة خمس وعشرين من ذي القعدة ولد فيها ابراهيم (عليه السلام)، وولد فيها عيسى بن مريم (عليه السلام)، وفيها دحيت الارض من تحت الكعبة، فمن صام ذلك اليوم كان كمن صام ستّين شهراً، وقال على رواية اخرى: ألا انّ فيه يقوم القائم (عليه السلام) ."},{"type":"Text","content":"اليوم الخامس والعشرون : يوم دحو الارض ، وهو أحد الايّام الاربعة التي خصّت بالصّيام بين أيّام السّنة، وروي انّ صيامه يعدل صيام سبعين سنة، وهو كفّارة لذنوب سبعين سنة على رواية أخرى، ومن صام هذا اليوم وقام ليلته فله عبادة مائة سنة، ويستغفر لمن صامه كلّ شيء بين السّماء والارض، وهو يوم انتشرت فيه رحمة الله تعالى، وللعبادة والاجتماع لذكر الله تعالى فيه أجر جزيل . وقد ورد لهذا اليوم سوى الصّيام والعبادة وذكر الله تعالى والغُسل عملان :"},{"type":"Text","content":"الاوّل : صلاة مرويّة في كتب الشّيعة القميّين، وهي ركعتان تصلّى عند الضحى بالحمد مرّة والشّمس خمس مرّات ويقول بعد التّسليم : لا حَوْلَ وَلا قُوَّةَ إلاّ بِاللهِ الْعَلىِّ الْعَظيمِ ثمّ يدعو ويقول : يا مُقيلَ العَثَراتِ اَقِلْني عَثْرَتي، يا مُجيبَ الدَّعَواتِ اَجِبْ دَعْوَتي، يا سامِعَ الاَْصْواتِ اِسْمَعْ صَوْتي وَارْحَمْني وَتَجاوَزْ عَنْ سَيِّئاتي وَما عِنْدي يا ذَا الْجَلالِ وَالاكْرامِ ."}],"preview":"اعلم انّ هذا الشّهر هو اوّل الاشهر الحرم التي ذكرها الله في كتابه المجيد، وروى السّيد ابن طاووس في حديث انّ شهر ذي القعدة موقع اجابة الدّعاء عند الشّدة، وروي عن رسول الله (صلى الله","hasTranslate":false},{"id":"mf_ar_165","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل الخامِسُ :","title":"الثّاني : هذا الدّعاء الذي قال الشّيخ في المصباح انّه يستحبّ الدّعاء به :","blocks":[{"type":"Text","content":"اَللّـهُمَّ داحِيَ الْكَعْبَةِ، وَفالِقَ الْحَبَّةِ، وَصارِفَ اللَّزْبَةِ، وَكاشِفَ كُلِّ كُرْبَة، اَسْاَلُكَ في هذَا الْيَوْمِ مِنْ اَيّامِكَ الَّتي اَعْظَمْتَ حَقَّها، وَاَقْدَمْتَ سَبْقَها، وَجَعَلْتَها عِنْدَ الْمُؤْمِنينَ وَديعَةً، وَاِلَيْكَ ذَريعَةً، وَبِرَحْمَتِكَ الْوَسيعَةِ اَنْ تُصَلِّيَ عَلى مُحَمَّد عَبْدِكَ الْمُنْتَجَبِ فِى الْميثاقِ الْقَريبِ يَوْمَ التَّلاقِ، فاتِقِ كُلِّ رَتْق، وَداع اِلى كُلِّ حَقِّ، وَعَلى اَهْلِ بَيْتِهِ الاَْطْهارِ الْهُداةِ الْمَنارِ دَعائِمِ الْجَبّارِ، وَوُلاةِ الْجَنَّةِ وَالنّارِ، وَاَعْطِنا في يَوْمِنا هذا مِنْ عَطائِكَ الَْمخْزوُنِ غَيْرَ مَقْطوُع وَلا مَمْنوُع، تَجْمَعُ لَنا بِهِ التَّوْبَةَ وَحُسْنَ الاَْوْبَةِ، يا خَيْرَ مَدْعُوٍّ، وَاَكْرَمُ مَرْجُوٍّ، يا كَفِيُّ يا وَفِيُّ يا مَنْ لُطْفُهُ خَفِيٌّ اُلْطُفْ لي بِلُطْفِكَ، وَاَسْعِدْني بِعَفْوِكَ، وَاَيِّدْني بِنَصْرِكَ، وَلا تُنْسِني كَريمَ ذِكْرِكَ بِوُلاةِ اَمْرِكَ، وَحَفَظَةِ سِرِّكَ، وَاحْفَظْني مِنْ شَوائِبِ الدَّهْرِ اِلى يَوْمِ الْحَشْرِ وَالنَّشْرِ، وَاَشْهِدْني اَوْلِياءِكَ عِنْدَ خُرُوجِ نَفْسي، وَحُلُولِ رَمْسي، وَانْقِطاعِ عَمَلي، وَانْقِضاءِ اَجَلي، اَللّـهُمَّ وَاذْكُرْني عَلى طُولِ الْبِلى اِذا حَلَلْتُ بَيْنَ اَطْباقِ الثَّرى، وَنَسِيَنِى النّاسُونَ مِنَ الْوَرى، وَاحْلِلْني دارَ الْمُقامَةِ، وَبَوِّئْني مَنْزِلَ الْكَرامَةِ، وَاجْعَلْني مِنْ مُرافِقي اَوْلِيائِكَ وَاَهْلِ اجْتِبائِكَ وَاصْطَفائِكَ، وَباركْ لي في لِقائِكَ، وَارْزُقْني حُسْنَ الْعَمَلِ قَبْلَ حُلُولِ الاَْجَلِ، بَريئاً مِنَ الزَّلَلِ وَسوُءِ الْخَطَلِ، اَللّـهُمَّ وَاَوْرِدْني حَوْضَ نَبِيِّكَ مُحَمَّد صَلَّى اللهُ عَلَيْهِ وَآلِهِ، وَاسْقِني مِنْهُ مَشْرَباً رَوِيّاً سائِغاً هَنيئاً لا اَظْمَأُ بَعْدَهُ وَلا اُحَلاَُّ وِرْدَهُ وَلا عَنْهُ اُذادُ، وَاجْعَلْهُ لي خَيْرَ زاد، وَاَوْفى ميعاد يَوْمَ يَقُومُ الاَْشْهادُ، اَللّـهُمَّ وَالْعَنْ جَبابِرَةَ الاَْوَّلينَ وَالاْخِرينَ، وَبِحُقُوقِ اَوْلِيائِكَ الْمُسْتَأثِرِينَ اَللّـهُمَّ وَاقْصِمْ دَعائِمَهُمْ وَاَهْلِكْ اَشْياعَهُمْ وَعامِلَهُمْ، وَعَجِّلْ مَهالِكَهُمْ، وَاسْلُبْهُمْ مَمالِكَهُمْ، وَضَيِّقْ عَلَيْهِمْ مَسالِكَهُمْ، وَالْعَنْ مُساهِمَهُمْ وَمُشارِكَهُمْ، اَللّـهُمَّ وَعَجِّلْ فَرَجَ اَوْلِيائِكَ، وَارْدُدْ عَلَيْهِمْ مَظالِمَهُمْ، وَاَظْهِرْ بِالْحَقِّ قائِمَهُمْ، وَاجْعَلْهُ لِدينِكَ مُنْتَصِراً، وَبِاَمْرِكَ في اَعْدائِكَ مُؤْتَمِراً اَللّـهُمَّ احْفُفْهُ بِمَلائِكَةِ النَّصْرِ وَبِما اَلْقَيْتَ اِلَيْهِ مِنَ الاَْمْرِ في لَيْلَةِ الْقَدْرِ، مُنْتَقِماً لَكَ حَتّى تَرْضى وَيَعوُدَ دينُكَ بِهِ وَعَلى يَدَيْهِ جَديداً غَضّاً، وَيَمْحَضَ الْحَقَّ مَحْضاً، وَيَرْفُضَ الْباطِلَ رَفْضاً، اَللّـهُمَّ صَلِّ عَلَيْهِ وَعَلى جَميعِ آبائِهِ، وَاجْعَلْنا مِنْ صَحْبِهِ وَاُسْرَتِهِ، وَابْعَثْنا في كَرَّتِهِ حَتّى نَكُونَ في زَمانِهِ مِنْ اَعْوانِهِ، اَللّـهُمَّ اَدْرِكْ بِنا قِيامَهُ، وَاَشْهِدْنا اَيّامَهُ، وَصَلِّ عَلَيْهِ وَارْدُدْ اِلَيْنا سَلامَهُ، وَالسَّلامُ عَلَيْهِ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ ."},{"type":"AboutText","content":"اعلم انّ السّيد الدّاماد (رحمه الله) قال في رسالته المسمّاة الاربعة ايّام في خلال أعمال يوم دحوّ الارض انّ زيارة الرّضا (عليه السلام) في هذا اليوم هي أكد آدابه المسنونة كذلك، ويتأكّد استحباب زيارته (عليه السلام) في اليوم الاوّل من شهر رجب الفرد، وقد حثّ عليها حثّاً بالغاً ."},{"type":"Text","content":"اليوم الاخير من الشّهر : في هذا اليوم من سنة مائتين وعشرين على المشهور استشهد الامام محمّد بن عليّ التّقي (عليهما السلام) في بغداد، وقد سمّه المعتصم بالله العبّاسي، وكان شهادته بعد سنتين ونصف من وفاة المأمون، كما كان الامام نفسه يتنبّأ بذلك فيقول : « الفَرَجَ بَعْدَ المأمُون بِثَلاثينَ شَهراً » تشعر هذه الكلمة بما كان يعانيه من الاذى والمحن من سوء معاشرة المأمون له حتّى اعتبر الموت فرجه الذي يترقّبه كما عانى من المحن ما عاناه أبوه العظيم الامام الرّضا (عليه السلام)حينما ولّي العهد، وكان كلّما رجع من الجامع يوم الجمعة رفع يديه الى السّماء وهو عرقان مغبراً فقال : « اِلهي اِنْ كانَ فَرَجي في مَوتي فَعَجِّلْ وَفاتي لِساعَتي »، وكان دائم الكآبة والغمّ حتّى قضى نحبه، وقد توفّى الامام محمّد بن عليّ التّقيّ (عليهما السلام)وله من العمر خمساً وعشرون سنة وبضعة أشهر، ويقع قبره الشّريف خلف قبر جدّه العظيم الامام موسى الكاظم (عليه السلام)في الكاظميّة ."}],"preview":"اَللّـهُمَّ داحِيَ الْكَعْبَةِ، وَفالِقَ الْحَبَّةِ، وَصارِفَ اللَّزْبَةِ، وَكاشِفَ كُلِّ كُرْبَة، اَسْاَلُكَ في هذَا الْيَوْمِ مِنْ اَيّامِكَ الَّتي اَعْظَمْتَ حَقَّها، وَاَقْدَمْ","hasTranslate":false},{"id":"mf_ar_166","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل السّادِسُ :","title":"في أعمالِ شهرِ ذِي الحُجّة","blocks":[{"type":"Text","content":"وهو شهر شريف وكان صلحاء الصّحابة والتّابعين يهتمّون بالعبادة فيه اهتماماً بالغاً، والعشر الاوائل من ايّامه هي الايّام المعلومات المذكورة في القرآن الكريم وهي أيّام فاضلة غاية الفضل، وقد روي عن النّبي (صلى الله عليه وآله وسلم) ما من أيّام العمل فيها أحبّ الى الله عزّوجلّ من أيّام هذه العشر ولهذه العشر، أعمال :"},{"type":"Text","content":"الاوّل : صيام الايّام التسّعة الاوُل منها فانّه يعدل صيام العمر كلّه ."},{"type":"Text","content":"الثّاني : أن يصلّي بين فريضتي المغرب والعشاء في كلّ ليلة من لياليها ركعتين يقرأ في كلّ ركعة فاتحة الكتاب والتّوحيد مرّة واحدة، وهذه الاية وَواعَدْنا مُوسى ثَلاثينَ لَيْلَةً وَاَتْمَمْناها بِعَشْر فَتَمَّ ميقاتُ رَبِّهِ اَرْبَعينَ لَيْلَةً وَقالَ مُوسى لاَِخيهِ هارُونَ اخْلُفنى فى قَوْمى وَاَصْلِحْ وَلا تَتَّبِعْ سَبيلَ الْمُفْسِدينَ ليشارك الحاج في ثوابهم ."},{"type":"Text","content":"الثّالث : أن يدعو بهذا الدّعاء من أوّل يوم من عشر ذي الحجّة الى عشيّة عرفة في دبر صلاة الصّبح وقبل المغرب، وقد رواه الشّيخ والسّيد عن الصّادق (عليه السلام) :"},{"type":"Text","content":"اَللّـهُمَّ هذِهِ الاَْيّامُ الَّتى فَضَّلْتَها عَلَى الاَْيّامِ وَشَرَّفْتَها قَدْ بَلَّغْتَنيها بِمَنِّكَ وَرَحْمَتِكَ، فَاَنْزِلْ عَلَيْنا مِنْ بَرَكاتِكَ، وَاَوْسِعْ عَلَيْنا فيها مِنْ نَعْمآئِكَ، اَللّـهُمَّ اِنّى اَسْاَلُكَ اَنْ تُصَلِّىَ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاَنْ تَهْدِيَنا فيها لِسَبيلِ الْهُدى وَالْعِفافِ وِالْغِنى وَالْعَمَلِ فيها بِما تُحِبُّ وَتَرْضى، اَللّـهُمَّ اِنّى اَسْاَلُكَ يا مَوْضِعَ كُلِّ شَكْوى، وَيا سامِعَ كُلِّ نَجْوى، وَيا شاهِدَ كُلِّ مَلاَء، وَيا عالِمَ كُلِّ خَفِيَّةً اَنْ تُصَلِّىَ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَنْ تَكْشِفَ عَنّا فيهَا الْبَلاءَ، وَتَسْتَجيبَ لَنا فيهَا الدُّعآءَ، وَتُقَوِّيَنا فيها وَتُعينَنا وَتُوَفِّقَنا فيها لِما تُحِبُّ رَبَّنا وَتَرْضى وَعَلى مَا افْتَرَضْتَ عَلَيْنا مِنْ طاعَتِكَ وَطاعَةِ رَسوُلِكَ وَاَهْلِ وَلايَتِكَ، اَللّـهُمَّ اِنّى اَسْاَلُكَ يا اَرْحَمَ الرّاحِمينَ اَنْ تُصَلِّىَ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَنْ تَهَبَ لَنا فيهَا الرِّضا اِنَّكَ سَميعُ الدُّعآءِ، وَلا تَحْرِمْنا خَيْرَ ما تُنْزِلُ فيها مِنَ السَّمآءِ، وَطَهَّرْنا مِنَ الذُّنوُبِ يا عَلاّمَ الْغُيوُبِ، وَاَوْجِبْ لَنا فيها دارَ الْخُلوُدِ، اَللّهمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَلا تَتْرُكْ لَنا فيها ذَنْباً اِلاّ غَفَرْتَهُ، وَلا هَمّاً اِلاّ فَرَّجْتَهُ، وَلا دَيْناً اِلاّ قَضَيْتَهُ، وَلا غائِباً اِلاّ اَدَّيْتَهُ، وَلا حاجَةً مِنْ حَوائِجِ الدُّنْيا وَالاْخِرَةِ اِلاّ سَهَّلْتَها وَيَسَّرْتَها اِنَّكَ عَلى كُلِّ شَىْء قَديرٌ، اَللّـهُمَّ يا عالِمَ الْخَفِيّاتِ، يا راحِمَ الْعَبَراتِ، يا مُجيبَ الدَّعَواتِ، يا رَبَّ الاَْرَضينَ وَالسَّماواتِ، يا مَنْ لا تَتَشابَهُ عَلَيْهِ الاَْصْواتِ، صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاجْعَلْنا فيها مِنْ عُتَقآئِكَ وَطُلَقآئِكَ مِنَ النّارِ، وَالْفائِزينَ بِجَنَّتِكَ وَالنّاجينَ بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ، وَصَلَّى اللهُ عَلَيْهِ سَيِّدِنا مُحَمَّد وَآلِهِ اَجْمَعينَ ."},{"type":"Text","content":"الرّابع : أن يدعو في كلّ يوم من أيّام العشر بهذه الدّعوات الخمس وقد جاء بها جبرئيل الى عيسى بن مريم هديّة من الله تعالى ليدعو بها في أيّام العشر، وهذه هي الدّعوات الخمس :"},{"type":"Text","content":"(1) اَشْهَدُ اَنْ لا اِلـهَ اِلاَّ اللهُ وَحْدَهُ لا شَريكَ لَهُ، لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ، بِيَدِهِ الْخَيْرُ وَهُوَ عَلى كُلِّ شَىْء قَديرٌ (2) اَشْهَدُ اَنْ لا اِلـهَ اِلاَّ اللهُ وَحْدَهُ لا شَريكَ لَهُ، اَحَداً صَمَداً لَمْ يَتَّخِذْ صاحِبَةً وَلا وَلَداً (3) اَشْهَدُ اَنْ لا اِلـهَ اِلاَّ اللهُ وَحْدَهُ لا شَريكَ لَهُ اَحَداً صَمَداً لَمْ يَلِدْ وَلَمْ يُولَدْ وَلَمْ يَكُنْ لَهُ كُفُواً اَحَدٌ (4) اَشْهَدُ اَنْ لا اِلـهَ اِلاَّ اللهُ وَحْدَهُ لا شَريكَ لَهُ، لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ يُحْيى وَيُميتُ وَهُوَ حَىٌّ لا يَمُوتُ، بِيَدِهِ الْخَيْرُ وَهُوَ عَلى كُلِّ شَىْء قَديرٌ (5) حَسْبِىَ اللهُ وَكَفى سَمِعَ اللهُ لِمَنْ دَعا، لَيْسَ وَرآءَ اللهِ مُنْتَهى، اَشْهَدُ للهِ بِما دَعا وَاَنَّهُ بَرىءٌ مِمَّنْ تَبَرَأَ وَاَنَّ لِلّهِ الاْخِرَةَ وَالاُْولى ."},{"type":"Text","content":"ثمّ ذكر عيسى (عليه السلام) اجراً جزيلاً للدّعاء بكلّ من هذه الدّعوات الخمس مائة مرّة، ولا يبعد أن يكون الدّاعى لله بكلّ من هذه الدّعوات في كلّ يوم عشر مرّات ممتثلاً لما ورد في الحديث، كما احتمله العلاّمة المجلسي (رحمه الله) والافضل أن يدعى بكُلّ منها في كلّ يوم مائة مرّة ."},{"type":"Text","content":"الخامس : أن يهلّل في كلّ يوم من العشر بهذا التّهليل المروي عن أمير المؤمنين (عليه السلام) بأجره الجزيل، والافضل التهليل به في كلّ يوم عشر مرّات :"},{"type":"Text","content":"لا اِلـهَ اِلاَّ اللهُ عَدَدَ الّلَيالى وَالدُّهُورِ، لا اِلـهَ اِلاَّ اللهُ عَدَدَ اَمْواجِ الْبُحُورِ، لا اِلـهَ اِلاَّ اللهُ و رَحْمَتُهُ خَيْرٌ مِما يَجْمَعُونَ، لا اِلـهَ اِلاَّ اللهُ عَدَدَ الشَّوْكِ الشَّجَرِ، لا اِلـهَ اِلاَّ اللهُ عَدَدَ الشَّعْرِ وَالْوَبَرِ، لا اِلـهَ اِلاَّ اللهُ عَدَدَ الْحَجَرِ وَالْمَدَرِ، لا اِلـهَ اِلاَّ اللهُ عَدَدَ لَمْحِ الْعُيُونِ، لا اِلـهَ اِلاَّ اللهُ فِى الّلَيْلِ اِذا عَسْعَسَ وَالصُّبْحِ اِذا تَنَفَّسَ، لا اِلـهَ اِلاَّ اللهُ عَدَدَ الرِّياحِ فِى الْبَرارى وَالصُّخُورِ، لا اِلـهَ اِلاَّ اللهُ مِنَ الْيَوْمِ اِلى يَوْمِ يُنْفَخُ فِى الصُّورِ ."}],"preview":"وهو شهر شريف وكان صلحاء الصّحابة والتّابعين يهتمّون بالعبادة فيه اهتماماً بالغاً، والعشر الاوائل من ايّامه هي الايّام المعلومات المذكورة في القرآن الكريم وهي أيّام فاضلة غاية الفضل","hasTranslate":false},{"id":"mf_ar_167","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل السّادِسُ :","title":"يوم شريف جدّاً وقد ورد فيه عدّة أعمال :","blocks":[{"type":"Text","content":"الاوّل : الصّيام فانّه يعدَل صوم ثمانين شهراً ."},{"type":"Text","content":"الثّاني : صلاة فاطمة (عليها السلام) ، قال الشّيخ : روي انّها أربع ركعات بسلامين وهي كصلاة أمير المؤمنين (عليه السلام)يقرأ في كلّ ركعة الحمد مرّة والتّوحيد خمسين مرّة ويسبّح بعد السّلام تسبيحها (عليها السلام) ويقول :"},{"type":"Text","content":"سُبْحانَ ذِى الْعِزِّ الشّامِخِ الْمُنيفِ، سُبْحانَ ذِى الْجَلالِ الْباذِخِ الْعَظيمِ، سُبْحانَ ذِى الْمُلكِ الْفاخِرِ الْقَديمِ، سُبْحانَ مَنْ يَرى اَثَرَ الَّنمْلَةِ فِى الصَّفا، سُبْحانَ مَنْ يَرى وَقْعَ الطَّيْرِ فِى الْهَوآءِ، سُبْحانَ مَنْ هُوَ هَكَذا وَلا هُكَذا غَيْرُهُ ."},{"type":"Text","content":"الثّالث : الصّلاة ركعتان قبل الزّوال بنِصف ساعة، يقرأ في كلّ ركعة الحمد مرّة وكلاً من التّوحيد وآية الكرسي والقدر عشر مرّات ."},{"type":"Text","content":"الرّابع : من خاف ظالماً فقال في هذا اليوم : حَسْبى حَسْبى حَسْبى مِنْ سُؤالى عِلْمُكَ بِحالى كفاه الله شرّه، واعلم انّ في هذا اليوم ولد ابراهيم الخليل (عليه السلام) وعلى رواية الشّيخين كان فيه أيضاً تزويج فاطمة من أمير المؤمنين (عليهما السلام) ."}],"preview":"الاوّل : الصّيام فانّه يعدَل صوم ثمانين شهراً .","hasTranslate":false},{"id":"mf_ar_168","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل السّادِسُ :","title":"اليوم السّابع","blocks":[{"type":"Text","content":"يوم حُزن الشّيعة كان فيه في سنة مائة وأربع عشرة وفاة الامام محمّد بن عليّ الباقر (عليه السلام) في المدينة ."}],"preview":"يوم حُزن الشّيعة كان فيه في سنة مائة وأربع عشرة وفاة الامام محمّد بن عليّ الباقر (عليه السلام) في المدينة .","hasTranslate":false},{"id":"mf_ar_169","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل السّادِسُ :","title":"اليوم الثّامن","blocks":[{"type":"Text","content":"يوم التّروية وللصّيام فيه فضل كثير وروي انّه كفّارة لذنوب ستّين سنة وقال الشّيخ الشّهيد (رحمه الله) : انّه يستحبّ فيه الغسل ."},{"type":"Text","content":"اللّيلة التّاسعة"},{"type":"Text","content":"ليلة مباركة وهي ليلة مناجاة قاضي الحاجات، والتّوبة فيها مقبولة، والدّعاء فيها مستجاب، وللعامل فيها بطاعة الله أجر سبعين ومائة سنة، وفيها عدّة أعمال :"},{"type":"Text","content":"الاوّل : أن يدعو بهذا الدّعاء الذي روى انّ من دعا به في ليلة عرفة أو ليالي الجُمع غفر الله له :"},{"type":"Text","content":"اَللّـهُمَّ يا شاهِدَ كُلِّ نَجْوى، وَمَوْضِعَ كُلِّ شَكْوى، وَعالِمَ كُلِّ خَفِيَّة، وَمُنْتَهى كُلِّ حاجَة، يا مُبْتَدِئاً بِالنِّعَمِ عَلَى الْعِبادِ، يا كَريمَ الْعَفْوِ، يا حَسَنَ التَّجاوُزِ، يا جَوادُ يا مَنْ لا يُواري مِنْهُ لَيْلٌ داج، وَلا بَحْرٌ عَجّاجٌ، وَلا سَمآءٌ ذاتُ اَبْراج، وَلا ظُلَمٌ ذاتُ ارْتِتاج، يا مَنِ الظُّلْمَةُ عِنْدَهُ ضِيآءٌ، اَسْاَلُكَ بِنوُرِ وَجْهِكَ الْكَريمِ الَّذى تَجَلَّيْتَ بِهِ لِلْجَبَلِ فَجَعَلْتَهُ دَكَّاً وَخَرَّ موُسى صَعِقاً، وَبِاِسْمِكَ الَّذى رَفَعْتَ بِهِ السَّماواتِ بِلا عَمَد، وَسَطَحْتَ بِهِ الاَْرْضَ عَلى وَجْهِ ماء جَمَد، وَبِاِسْمِكَ الَْمخْزوُنِ الْمَكْنوُنِ الْمَكْتوُبِ الطّاهِرِ الَّذى اِذا دُعيتَ بِهِ اَجَبْتَ، وَاِذا سُئِلْتَ بِهِ اعَطْيَتْ، وَبِاِسْمِكَ السُّبوُحِ الْقُدُّوسِ الْبُرْهانِ الَّذى هُوَ نوُرٌ عَلى كُلِّ نُور وَنوُرٌ مِنْ نوُر يُضيىُ مِنْهُ كُلُّ نوُر، اِذا بَلَغَ الاَْرْضَ انْشَقَّتْ، وَاِذا بَلَغَ السَّماواتِ فُتِحَتْ، وَاِذا بَلَغَ الْعَرْشَ اهْتَزَّ، وَبِاِسْمِكَ الَّذى تَرْتَعِدُ مِنْهُ فَرائِصُ مَلائِكَتِكَ، وَاَسْاَلُكَ بِحَقِّ جَبْرَئيلَ وَميكائيلَ وَاِسْرافيلَ، وَبِحَقِّ مُحَمَّد الْمُصْطَفى صَلَّى اللهُ عَلَيْهِ وَآلِهِ وَعَلى جَميعِ الاَْنْبِيآءِ وَجَميعِ الْمَلائِكَةِ، وَبِالاِْسْمِ الَّذى مَشى بِهِ الْخِضْرُ عَلى قُلَلِ الْمآءِ كَما مَشى بِهِ عَلى جَدَدِ الاَْرْضِ، وَبِاِسْمِكَ الَّذى فَلَقْتَ بِهِ الْبَحْرَ لِموُسى، وَاَغْرَقْتَ فِرْعَوْنَ وَقَوْمَهُ وَاَنْجَيْتَ بِهِ موُسَى بْنَ عِمْرانَ وَمَنْ مَعَهُ، وَبِاِسْمِكَ الَّذى دَعاكَ بِهِ موُسَى بْنُ عِمْران مِنْ جانِبِ الطُّورِ الاَْيْمَنِ فَاسْتَجَبْتَ لَهُ وَاَلْقَيْتَ عَلَيْهِ مَحَبَّةً مِنْكَ، وَبِاِسْمِكَ الَّذى بِهِ اَحْيى عيسَى بْنُ مَرْيَمَ الْمَوْتى، وَتَكَلَّمَ فِى الْمَهْدِ صَبِيّاً وَاَبْرَأَ الاَْكْمَهَ وَالاَْبْرَصَ بِاِذْنِكَ، وَبِاِسْمِكَ الَّذى دَعاكَ بِهِ حَمَلَةُ عَرْشِكَ وَجَبْرَئيلُ وَميكآئيلُ وَاِسْرافيلُ وَحَبيبِكَ مُحَمَّدٌ صَلَّى اللهُ عَلَيْهِ وَآلِهِ وَمَلائِكَتِكَ الْمُقَرَّبوُنَ وَاَنْبِيآؤُكَ الْمُرْسَلوُنَ وَعِبادُكَ الصّالِحوُنَ مِنْ اَهْلِ السَّماواتِ وَالاَْرَضينَ، وَبِاِسْمِكَ الَّذى دَعاكَ بِهِ ذوُ النُّونِ اِذْ ذَهَبَ مُغاضِباً فَظَنَّ اَنْ لَنْ نَقْدِرَ عَلَيْهِ فَنادى فِى الظُّلُماتِ اَنْ لا اِلـهَ اِلاّ اَنْتَ سُبْحانَك اِنّى كُنْتُ مِنَ الظّالِمينَ فَاسْتَجَبْتَ لَهُ وَنَجَّيْتَهُ مِنَ الْغَمِّ وَكَذلِكَ نُنْجِى الْمُؤْمِنينَ، وَبِاِسْمِكَ الْعَظيمِ الَّذى دَعاكَ بِهِ داوُدُ وَخَرَّ لَكَ ساجِداً فَغَفَرْتَ لَهُ ذَنْبَهُ، وَبِاِسْمِكَ الَّذى دَعَتْكَ بِهِ آسِيَةُ امْرَأَةُ فِرْعَوْنَ اِذْ قالَتْ رَبِّ ابْنِ لى عِنْدَكَ بَيْتاً فِى الْجَنَّةِ وَنَجِّنى مِنْ فِرْعَوْنَ وَعَمَلِهِ، وَنَجِّنى مِنَ الْقَوْمِ الظّالِمينَ، فَاسْتَجَبْتَ لَها دُعآءَها وَبِاِسْمِكَ الَّذى دَعاكَ بِهِ اَيُّوبُ اِذْ حَلَّ بِهِ الْبَلاءُ فَعافَيْتَهُ وَآتَيْتَهُ اَهْلَهُ وَمِثْلَهُمْ مَعَهُمْ رَحْمَةً مِنْ عِنْدَكَ وَذِكْرى لِلْعابِدينَ، وَبِاِسْمِكَ الَّذى دَعاكَ بِهِ يَعْقوُبُ فَرَدَدْتَ عَلَيْهِ بَصَرَهُ وَقُرَّةَ عَيْنِهِ يوُسُفَ وَجَمَعْتَ شَمْلَهُ، وَبِاِسْمِكَ الَّذى دَعاكَ بِهِ سُلَيْمانُ فَوَهَبْتَ لَهُ مُلْكاً لا يَنْبَغى لاَِحَد مِنْ بَعْدِهِ اِنَّكَ اَنْتَ الْوَهّابُ، وَبِاِسْمِكَ الَّذى سَخَّرْتَ بِهِ الْبُراقَ لُِمحَمَّد صلى الله عليه وآله وسلم اِذْ قالَ تَعالى: سُبْحانَ الَّذى اَسْرى بِعَبْدِهِ لَيْلاً مِنَ الْمَسْجِدِ الْحرامِ اِلَى الْمَسْجِدِ الاَْقْصى، وَقَوْلُهُ: سُبْحانَ الَّذى سَخَّرَ لَنا هذا وَما كُنّا لَهُ مُقْرِنينَ وَاِنّا اِلى رَبِّنا لَمُنْقَلِبوُنَ، وَبِاِسْمِكَ الَّذى تَنَزَّلَ بِهِ جَبْرَئيلُ عَلى مُحَمَّد صَلَّى اللهُ عَلَيْهِ وَآلِهِ، وَبِاِسْمِكَ الَّذى دَعاكَ بِهِ آدَمُ فَغَفَرْتَ لَهُ ذَنْبَهُ وَاَسْكَنْتَهُ جَنَّتَكَ، وَاَسْاَلُكَ بِحَقِّ الْقُرْآنِ الْعَظيمِ، وَبِحَقِّ مُحَمَّد خاتِمَ النَّبِيّينَ، وَبِحَقِّ اِبْرهيمَ، وَبِحَقِّ فَصْلِكَ يَوْمَ الْقَضآءِ، وَبِحَقِّ الْمَوازينَ اِذا نُصِبَتْ، وَالصُّحُفِ اِذا نُشِرَتْ، وَبِحَقِّ الْقَلَمِ وَما جَرى، وَاللَّوْحِ وَما اَحْصى، وَبِحَقِّ الاِْسْمِ الَّذى كَتَبْتَهُ عَلى سُرادِقِ الْعَرْشِ قَبْلَ خَلْقِكَ الْخَلْقَ وَالدُّنْيا وَالشَّمْسَ وَالْقَمَرَ بِاَلْفَىْ عام، وَاَشْهَدُ اَنْ لا اِلـهَ اِلاَّ اللهُ وَحْدَهُ لا شَريكَ لَهُ، وَاَنَّ مُحَمَّداً عَبْدُهُ وَرَسوُلُهُ، وَاَسْاَلُكَ بِاِسْمِكَ الَْمخْزُونِ فى خَزآئِنِكَ الَّذى اسْتَأثَرْتَ بِهِ فى عِلْمِ الْغَيْبِ عِنْدَكَ لَمْ يَظْهَرْ عَلَيْهِ اَحَدٌ مِنْ خَلْقِكَ لا مَلَكٌ مُقَرَّبٌ وَلا نَبِىٌّ مُرْسَلٌ وَلا عَبْدٌ مُصْطَفىً، وَاَسْاَلُكَ بِاِسْمِكَ الَّذى شَقَقْتَ بِهِ الْبِحارَ، وَقامَتْ بِهِ الْجِبالُ، وَاخْتَلَفَ بِهِ اللَّيْلُ وَالنَّهارُ، وَبِحَقِّ السَّبْعِ الْمَثانى، وَالْقُرْآنِ الْعَظيمِ، وَبِحَقِّ الْكِرامَ الْكاتِبينَ، وَبِحَقِّ طه وَيس وَكهيعص وَحمعسق، وَبِحَقِّ تَوْراةِ موُسى وَاِنْجيلِ عيسى وَزَبوُرِ داوُدَ وَفُرْقانِ مُحَمَّد صَلَّى اللهُ عَلَيْهِ وَآلِهِ وَعَلى جَميعِ الرُّسُلِ وَِباهِيّاً شَراهِيّاً، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِحَقِّ تِلْكَ الْمُناجاةِ الَّتى كانَتْ بَيْنَكَ وَبَيْنَ موُسَى بْنِ عَمْرانَ فَوْقَ جَبَلِ طوُرِ سَيْنآءَ، وَاَسْاَلُكَ بِاِسْمِكَ الَّذى عَلَّمْتَهُ مَلَكَ الْمَوْتِ لِقَبْضِ الاَْرْواحِ، وَاَسْاَلُكَ بِاِسْمِكَ الَّذى كُتِبَ عَلى وَرَقِ الزَّيْتوُنِ فَخَضَعَتِ النّيرانُ لِتِلْكَ الْوَرَقَةِ فَقُلْتُ يا نارُ كوُنى بَرْداً وَسَلاماً، وَاَسْاَلُكَ بِاِسْمِكَ الَّذى كَتَبْتَهُ عَلى سُرادِقِ الَْمجْدِ وَالْكَرامَةِ يا مَنْ لا يُحْفيهِ سآئِلٌ، وَلا يَنْقُصُهُ نآئِلٌ، يا مَنْ بِهِ يُسْتَغاثُ، وَاِلَيْهِ يُلْجَأُ، اَسْاَلُكَ بِمَعاقِدِ الْعِزِّ مِنْ عَرْشِكَ وَمُنْتَهَى الرَّحْمَةِ مِنْ كِتابِكَ، وَبِاِسْمِكَ الاَْعْظَمِ وَجَدِّكَ الاَْعْلى وَكَلِماتِكَ التّآمّاتِ الْعُلى، اَللّـهُمَّ رَبَّ الرِّياحِ وَما ذَرَتْ، وَالسَّمآءِ وَما اَظَلَّتْ، وَالاَْرْضِ وَما اَقَلَّتْ، وَالشَّياطينِ وَما اَضَلَّتْ، وَالْبِحارِ وَما جَرَتْ، وَبِحَقِّ كُلِّ حَقٍّ هُوَ عَلَيْكَ حَقٌّ، وَبِحَقِّ الْمَلائِكَةِ الْمُقَرَّبينَ وَالرَّوحانِيّينَ وَالْكَروُبِيّينَ وَالْمُسَبِّحينَ لَكَ بِاللَّيْلِ وَالنَّهارِ لا يَفْتَروُنَ، وَبِحَقِّ اِبْرهيمَ خَليلِكَ، وَبِحَقِّ كُلِّ وَلِىٍّ يُناديكَ بَيْنَ الصَّفا وَالْمَرْوَةِ وَتَسْتَجيبُ لَهُ دُعآءَهُ يا مُجيبُ اَسْاَلُكَ بِحَقِّ هذِهِ الاَْسْماءِ وَبِهذِهِ الدَّعَواتِ اَنْ تَغْفِرَ لَنا ما قَدَّمْنا وَما اَخَّرْنا وَما اَسْرَرْنا وَما اَعْلَنّا وَما اَبْدَيْنا وَما اَخْفَيْنا وَما اَنْتَ اَعْلَمُ بِهِ مِنّا اِنَّكَ عَلى كُلِّ شَىْء قَديرٌ بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ، يا حافِظَ كُلِّ غَريب، يا موُنِسَ كُلِّ وَحيد، يا قُوَّةَ كُلِّ ضَعيف، يا ناصِرَ كُلِّ مَظْلوُم يا رازِقَ كُلِّ مَحْروُم، يا موُنِسَ كُلِّ مُسْتَوْحِش، يا صاحِبَ كُلِّ مُسافِر، يا عِمادَ كُلِّ حاضِر، يا غافِرَ كُلِّ ذَنْب وَخَطيئَة، يا غِياثَ الْمُسْتَغيثينَ، يا صَريخَ الْمُسْتَصْرِخينَ، يا كاشِفَ كُرَبِ الْمَكْروُبينَ، يا فارِجَ هَمِّ الْمَهْموُمينَ، يا بَديعَ السَّماواتِ وَالاَْرَضينَ، يا مُنْتَهى غايَةَ الطّالِبينَ، يا مُجيبَ دَعْوَةِ الْمُضْطَرّينَ، يا اَرْحَمَ الرّاحِمينَ، يا رَبَّ الْعالَمين، يا دَيّانِ يَوْمِ الدّينِ، يا اَجْوَدَ الاَْجْوَدينَ، يا اَكْرَمَ الاَْكْرَمِينَ، يا اَسْمَعَ السّامِعينَ، يا اَبْصَرَ النّاظِرينَ، يا اَقْدَرَ الْقادِرينَ، اِغْفِرْ لِىَ الذُّنوُبَ الَّتى تُغَيِّرُ النِّعَمَ، وَاغْفِرْ لِىَ الذُّنوُبَ الَّتى توُرِثُ النَّدَمَ، وَاغْفِرْ لِىَ الذُّنوُبَ الَّتى توُرَثُ السَّقَمَ، وَاغْفِرْ لِىَ الذُّنوُبَ الَّتى تَهْتِكُ الْعِصَمَ، وَاغْفِرْ لِىَ الذُّنوُبَ الَّتى تَرُدُّ الدُّعآءَ، وَاغْفِرْ لِىَ الذُّنوُبَ الَّتى تَحْبِسُ قَطْرَ السَّمآءِ، وَاغْفِرْ لِىَ الذُّنوُبَ الَّتى تُعَجِّلُ الْفَنآءَ، وَاغْفِرْ لِىَ الذُّنوُبَ الَّتى تَجْلِبُ الشَّقآءَ، وَاغْفِرْ لِىَ الذُّنوُبَ الَّتى تُظْلِمُ الْهَوآءَ، وَاغْفِرْ لِىَ الذُّنوُبَ الَّتى تَكْشِفُ الْغِطآءَ، وَاغْفِرْ لِىَ الذُّنوُبَ الَّتى لا يَغْفِرُها غَيْرُكَ يا اَللهُ، وَاحْمِلْ عَنّى كُلَّ تَبِعَة لاَِحَد مِنْ خَلْقِكَ، وَاجْعَلْ لى مِنْ اَمْرى فَرَجاً وَمَخْرَجاً وَيُسْراً، وَاَنْزِلْ يَقينَكَ فى صَدْرى، وَرَجآءَكَ فى قَلْبى حَتّى لا اَرْجُوَ غَيْرَكَ، اَللّـهُمَّ احْفَظْنى وَعافِنى فى مَقامى وَاصْحَبْنى فى لَيْلى وَنَهارى وَمِنْ بَيْنِ يَدَىَّ وَمِنْ خَلْفى وَعَنْ يَمينى وَعَنْ شِمالى وَمِنْ فَوْقى وَمِنْ تَحْتى، وَيَسِّرْ لِىَ السَّبيلَ، وَاَحْسِنْ لِىَ التَّيْسِيرَ، وَلا تَخْذُلْنى فِى الْعَسيرِ، وَاهْدِنى يا خَيْرَ دَليل، وَلا تَكِلْنى اِلى نَفْسى فِى الاُْموُرِ، وَلَقِّنى كُلَّ سُروُر، وَاقْلِبْنى اِلى اَهْلى بِالْفَلاحِ وَالنَّجاحِ مَحْبوُراً فِى الْعاجِلِ وَالاَْجَلِ اِنَّكَ عَلى كُلِّ شَىْء قَديرٌ، وَارْزُقْنى مِنْ فَضْلِكَ، وَاَوْسِعْ عَلَىَّ مِنْ طَيِّباتِ رِزْقِكَ، وَاسْتَعْمِلْنى فى طاعَتِكَ، وَاَجِرْنى مِنْ عَذابِكَ وَنارِكَ، وَاقْلِبْنى اِذا تَوَفَّيْتَنى اِلى جَنَّتِكَ بِرَحْمَتِكَ، اَللّـهُمَّ اِنّى اَعوُذُ بِكَ مِنْ زَوالِ نِعْمَتِكَ، وَمِنْ تَحْويلِ عافِيَتِكَ، وَمِنْ حُلوُلِ نَقِمَتِكَ وَمِنْ نُزوُلِ عَذابِكَ، وَاَعوُذُ بِكَ مِنْ جَهْدِ الْبَلاءِ، وَدَرَكِ الشِّقآءِ، وَمِنْ سُوءِ الْقَضآءِ، وَشَماتَةِ الاَْعْدآءِ، وَمِنْ شَرِّ ما يَنْزِلُ مِنَ السَّمآءِ، وَمِنْ شَرِّ ما فِى الْكِتابِ الْمُنْزَلِ، اَللّـهُمَّ لا تَجْعَلْنى مِنَ الاَْشْرارِ، وَلا مِنْ اَصْحابِ النّارِ، وَلا تَحْرِمْنى صُحْبَةَ الاَْخْيارِ، وَاَحْيِنى حَياةً طَيِّبَةً وَتَوَفَّنى وَفاةً طَيِّبَةً تُلْحِقْنى بِالاَبْرارِ، وَارْزُقْنى مُرافَقَةِ الاَنْبِيآءِ فى مَقْعَدِ صِدْق عِنْدَ مَليك مُقْتَدِر، اَللّـهُمَّ لَكَ الْحَمْدُ عَلى حُسْنِ بَلائِكَ وَصُنْعِكَ، وَلَكَ الْحَمْدُ عَلَى الاِْسْلامِ وَاتِّباعِ السُّنَةِ يا رَبِّ كَما هَدَيْتَهُمْ لِدينِكَ وَعَلَّمْتَهُمْ كِتابَكَ فَاهْدِنا وَعَلِّمْنا، وَلَكَ الْحَمْدُ عَلى حُسْنِ بَلائِكَ وَصُنْعِكَ عِنْدى خآصَّةً كَما خَلَقْتَنى فَاَحْسَنْتَ خَلْقى، وَعَلَّمْتَنى فَاَحْسَنْتَ تَعْليمى، وَهَدَيْتَنى فَاَحْسَنْتَ هِدايَتى، فَلَكَ الْحَمْدُ عَلى اِنْعامِكَ عَلَىَّ قَديماً وَحَديثاً، فَكَمْ مِنْ كَرْب يا سَيِّدى قَدْ فَرَّجْتَهُ، وَكَمْ مِنْ غَمٍّ يا سَيِّدى قَدْ نَفَّسْتَهُ، وَ كَمْ مِنْ هَمّ يا سيِّدى قَد كَشَفتَه، وَكَم مَنْ بَلاء يا سيِّدى قَد صَرفَتَه وَكَمْ مِنْ عَيْب يا سَيِّدى قَدْ سَتَرْتَهُ، فَلَكَ الْحَمْدُ عَلى كُلِّ حال فى كُلِّ مَثْوىً وَزَمان وَمُنْقَلَب وَمَقام، وَعَلى هذِهِ الْحالِ وَكُلِّ حال اَللّـهُمَّ اجْعَلْنى مِنْ اَفْضَلِ عِبادِكَ نَصيباً فى هذَا الْيَوْمِ مِنْ خَيْر تَقْسِمُهُ اَوْ ضُرٍّ تَكْشِفُهُ اَوْ سُوء تَصْرِفُهُ اَوْ بَلاء تَدْفَعُهُ اَوْ خَيْر تَسوُقُهُ اَوْ رَحْمَة تَنْشُرُها اَوْ عافِيَة تُلْبِسُها، فَاِنَّكَ عَلى كُلِّ شَىْء قَديرٌ وَبِيَدِكَ خَزآئِنُ السَّماواتِ وَالاَْرْضِ، وَاَنْتَ الْواحِدُ الْكَريمُ الْمُعْطِى الَّذى لا يُرَدَّ سآئِلُهُ، وَلا يُخَيَّبُ آمِلُهُ، وَلا يَنْقُصُ نآئِلُهُ، وَلا يَنْفَدُ ما عِنْدَهُ بَلْ يَزْدادُ كَثْرَةً وَطَيِّباً وَعَطآءً وَجوُداً، وَارْزُقْنى مِنْ خَزآئِنِكَ الَّتى لا تَفْنى، وَمِنْ رَحْمَتِكَ الْواسِعَةِ اِنَّ عَطآءَكَ لَمْ يَكُنْ مَحْظوُراً، وَاَنْتَ عَلى كُلِّ شَىْء قَديرٌ بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ ."},{"type":"Text","content":"الثّاني : أن يسبّح ألف مرّة بالتّسبيحات العشر الّتي رواها السّيد وستأتي في أعمال يوم عرفة ."},{"type":"Text","content":"الثّالث : أن يقرأ الدّعاء اَللّـهُمَّ مَنْ تَعَبَّأَ وَتَهَيَّأَ المسنون قراءته في يوم عرفة وليلة الجمعة ونهارها، وقد مرّ في خلال أعمال ليلة الجمعة."},{"type":"Text","content":"الرّابع : أن يزور الحسين (عليه السلام) وأرض كربلاء ويقيم بها حتّى يعيّد، ليقيه الله شرّ سنته ."}],"preview":"يوم التّروية وللصّيام فيه فضل كثير وروي انّه كفّارة لذنوب ستّين سنة وقال الشّيخ الشّهيد (رحمه الله) : انّه يستحبّ فيه الغسل .","hasTranslate":false},{"id":"mf_ar_170","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل السّادِسُ :","title":"اليوم التّاسع","blocks":[{"type":"Text","content":"هو يوم عرفة وهو عيد من الاعياد العظيمة وإن لم يسمّ عيداً، وهو يوم دعا الله عباده فيه الى طاعته وعبادته وبسط لهم موائد احسانه وجوده، والشّيطان فيه ذليل حقير طريد غضبان أكثر من أيّ وقت سواه ، وروي انّ الامام زين العابدين صلوات الله وسلامه عليه سمع في يوم عرفة سائلاً يسأل النّاس فقال له : ويلك أتسأل غير الله في هذا اليوم وهو يوم يرجى فيه للاجنّة في الارحام أن تعمّها فضل الله تعالى فتسعد، ولهذا اليوم عدّة أعمال :"}],"preview":"هو يوم عرفة وهو عيد من الاعياد العظيمة وإن لم يسمّ عيداً، وهو يوم دعا الله عباده فيه الى طاعته وعبادته وبسط لهم موائد احسانه وجوده، والشّيطان فيه ذليل حقير طريد غضبان أكثر من أيّ و","hasTranslate":false},{"id":"mf_ar_171","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل السّادِسُ :","title":"الاوّل : الغُسل","blocks":[{"type":"Text","content":"الثّاني : زيارة الحسين صلوات الله عليه، فانّها تعدل ألف حجّة وألف عمرة وألف جهاد بل تفوقها، والاحاديث في كثرة فضل زيارته (عليه السلام) في هذا اليوم متواترة، ومن وفّق فيه لزيارته (عليه السلام) والحضور تحت قبّته المقدّسة فهو لا يقلّ أجراً عمّن حضَرَ عَرفات ، بل يفوقه وستأتي صفة زيارته (عليه السلام) في هذا اليوم في باب الزّيارات ان شاء الله تعالى ."},{"type":"Text","content":"الثّالث : أن يصلّي بعد فريضة العصر قبل أن يبدأ في دعوات عرفة ركعتين تحت السّماء ويقرّ لله تعالى بذنوبه ليفوز بثواب عرفات ويغفر ذنُوبه ثمّ يشرع في أعمال عرفة ودعواته المأثورة عن الحجج الطّاهرة صلوات الله عليهم، وهي اكثر من أن تذكر في هذه الوجيزة ونحن نقتصر منها بما يسعه الكتاب ."},{"type":"AboutText","content":"قال الكفعمي في المصباح : يستحبّ صوم يوم عرفة لمن لا يضعف عن الدّعاء والاغتسال قبل الزّوال وزيارة الحُسين صلوات الله عليه فيه وفي ليلته، فاذا زالت الشّمس فأبرز تحت السّماء وصلّ الظّهرين تحسن ركوعهما وسجودهما، فاذا فرغت فصلّ ركعتين في الاولى بعد الحمد التّوحيد وفي الثّانية بعد الحمد سورة قُلْ يا أيُّها الْكافِرُونَ ثمّ صلّ أربعاً اخرى في كلّ ركعة الحمد والتّوحيد خمسون مرّة ."},{"type":"AboutText","content":"أقول : هذه الصّلاة هي صلاة أمير المؤمنين (عليه السلام) التي مضت في أعمال يوم الجُمعة ، ثمّ قل: ما ذكره ابن طاووس في كتاب الاقبال مرويّاً عن النّبي (صلى الله عليه وآله وسلم) وهو :"},{"type":"Text","content":"سُبْحانَ الَّذى فِى السَّمآءِ عَرْشُهُ، سُبْحانَ الَّذى فِى الاَْرْضِ حُكْمُهُ، سُبْحانَ الَّذى فِى الْقُبوُرِ قَضآؤُهُ، سُبْحانَ الَّذى فِى الْبَحْرِ سَبيلُهُ، سُبْحانَ الَّذى فِى النّارِ سُلْطانُهُ، سُبْحانَ الَّذى فِى الْجَنَّةِ رَحْمَتُهُ، سُبْحانَ الَّذى فِى الْقِيامَةِ عَدْلُهُ، سُبْحانَ الَّذى رَفَعَ السَّمآءِ، سُبْحانَ الَّذى بَسَطَ الاَرْضَ، سُبْحانَ الَّذى لا مَلْجَاَ وَلا مَنْجا مِنْهُ اِلاّ اِلَيْهِ . ثّم قل : سُبْحانَ اللهِ وَالْحَمْدُ للهِ وَلا اِلـهَ اِلاَّ اللهُ وَاللهُ اَكْبَرُ مائة مرّة ، واقرأ التّوحيد مائة مرّة وآية الكرسي مائة مرّة وصلّ على محمد وآله مائة مرّة وقل : لا اِلـهَ اِلاَّ اللهُ وَحْدَهُ لا شَريكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ يُحْيى وَيُميتُ وَيُميتُ وَيُحْيى وَهُوَ حَىٌّ لا يَموُتُ بِيَدِهِ الْخَيْرُ وَهُوَ عَلى كُلِّ شَىْء قَديرٌ (عشراً) اَسْتَغْفِرُ اللهَ الَّذى لا اِلـهَ اِلاّ هُوَ الْحَىُّ الْقَيُّومُ وَاَتوُبُ اِلَيْهِ (عشراً) يا اَللهُ (عشراً) يا رَحْمنُ (عشراً) يا رَحيمُ (عشراً) يا بَديعُ السَّماواتِ وَالاَْرْضِ يا ذَا الْجَلالِ وَالاِكْرامِ (عشراً) يا حَىُّ يا قَيُّومُ (عشراً) يا حَنّانُ يا مَنّانُ (عشراً) يا لا اِلـهَ اِلاّ اَنْتَ (عشراً) آمينَ (عشراً) ثمّ قل : اَللّـهُمَّ اِنّى اَسْاَلُكَ يا مَنْ هُوَ اَقْرَبُ اِلَىَّ مِنْ حَبْلِ الْوَريدِ، يا مَنْ يَحوُلُ بَيْنَ الْمَرْءِ وَقَلْبِهِ، يا مَنْ هُوَ بِالْمَنْظَرِ الاَْعْلى وَبِالاُْفُقِ الْمُبينِ، يا مَنْ هُوَ الرَّحْمنُ عَلَى الْعَرْشِ اسْتَوى، يا مَنْ لَيْسَ كَمِثْلِهِ شَىْءٌ وَهُوَ السَّميعُ الْبَصيرُ، اَسْاَلُكَ اَنْ تُصَلِّىَ عَلى مُحَمَّد وَآلِ مُحَمَّد . وسل حاجتك تُقضى ان شاء الله تعالى ."},{"type":"Text","content":"ثمّ ادع بهذه الصّلوات التي روى عن الّصادق (عليه السلام) : انّ من أراد أن يسرّ محمّداً وآل محمّد (عليهم السلام) فليقل في صلاته عليهم :"},{"type":"Text","content":"اَللّـهُمَّ يا اَجْوَدَ مَنْ اَعْطى، وَيا خَيْرَ مَنْ سُئِلَ، وَيا اَرْحَمَ مَنِ اسْتُرْحِمَ اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِهِ فِى الاَْوَّلينَ، وَصَلِّ عَلى مُحَمَّد وَآلِهِ فِى الاْخِرينَ، وَصَلِّ عَلى مُحَمَّد وَآلِهِ فِى الْمَلاَءِ الاَْعْلى، وَصَلِّ عَلى مُحَمَّد وَآلِهِ فِى الْمُرْسَلينَ، اَللّـهُمَّ اَعْطِ مُحَمَّداً وَآلَهِ الْوَسيلَةَ وَالْفَضيلَةَ وَالشَّرَفَ وَالرَّفْعَةَ وَالدَّرَجَةَ الْكَبيرَةَ، اَللّـهُمَّ اِنّى آمَنْتُ بِمُحَمَّد صَلَّى اللهُ عَلَيْهِ وَآلِهِ وَلَمْ اَرَهُ فَلا تَحْرِمْنى فِى الْقِيامَةِ رُؤْيَتَهُ، وَارْزُقْنى صُحْبَتَهُ وَتَوَفَّنى عَلى مِلَّتِهِ، وَاسْقِنى مِنْ حَوْضِهِ مَشْرَباً رَوِيّاً سآئِغاً هَنيئاً لا اَظْمَأُ بَعْدَهُ اَبَداً اِنَّكَ عَلى كُلِّ شَىْء قَديرٌ، اَللّـهُمَّ اِنّى آمَنْتُ بِمُحَمَّد صَلَّى اللهُ عَلَيْهِ وَآلِهِ وَلَمْ اَرَهُ فَعَرَِّفْنى فِى الْجِنانِ وَجْهَهُ، اَللّـهُمَّ بَلِّغْ مُحَمَّداً صَلَّى اللهُ عَلَيْهِ وَآلِهِ مِنّى تَحِيَّةً كَثيرَةً وَسَلاماً ."},{"type":"Text","content":"ثمّ ادعُ بدعاء اُمّ داوُد وقد مرّ ذكره في أعمال رجب ثمّ سبّح بهذا التّسبيح وثوابه لا يحصى كثرة تركناه اختصاراً وهو :"},{"type":"Text","content":"سُبْحانَ اللهَ قَبْلَ كُلِّ اَحَد، وَسُبْحانَ اللهِ بَعْدَ كُلِّ اَحَد، وَسُبْحانَ اللهَ مَعَ كُلِّ اَحَد، وَسُبْحانَ اللهَ يَبْقى رَبُّنا ويَفْنى كُلُّ وأحَد، وَسُبْحانَ اللهِ تَسْبيحاً يَفْضُلُ تَسْبيحَ الْمُسَبِّحينَ فَضْلاً كَثيراً قَبْلَ كُلِّ اَحَد، وَسُبْحانَ اللهِ تَسْبيحاً يَفْضُلُ تَسْبيحَ الْمُسَبِّحينَ فَضْلاً كَثيراً بَعْدَ كُلِّ اَحَد، وَسُبْحانَ اللهِ تَسْبيحاً يَفْضُلُ تَسْبيحَ الْمُسَبِّحينَ فَضْلاً كَثيراً مَعَ كُلِّ اَحَد، وَسُبْحانَ اللهِ تَسْبيحاً يَفْضُلُ تَسْبيحَ الْمُسَبِّحينَ فَضْلاً كَثيراً لِرَبِّنَا الْباقى وَيَفْنى كُلِّ اَحَد، وَسُبْحانَ اللهِ تَسْبيحاً لا يُحْصى وَلا يُدْرى وَلا يُنْسى وَلا يَبْلى وَلا يَفْنى وَلَيْسَ لَهُ مُنْتَهى، وَسُبْحانَ اللهِ تَسْبيحاً يَدوُمُ بِدَوامِهِ وَيَبْقى بِبَقآئِهِ فى سِنِى الْعالَمينَ وَشُهوُرِ الدُّهوُرِ وَاَيّامِ الدُّنْيا وَساعاتِ اللَّيْلِ وَالنَّهارِ، وَسُبْحانَ اللهِ اَبَدَ الاَْبَدِ وَمَعَ الاَْبَدِ مِمّا لا يُحْصيهِ الْعَدَدُ وَلا يُفْنيهِ الاَْمَدُ وَلا يَقْطَعُهُ الاَْبَدُ، وَتَبارَكَ اللهُ اَحْسَنُ الْخالِقينَ . ثمّ قل : وَالْحَمْدُ للهِ قَبْلَ كُلِّ اَحَد وَالْحَمْدُ للهِ بَعْدَ كُلِّ اَحَد ."},{"type":"Text","content":"الى آخر ما مرّ في التّسبيح غير انّك تقول عوض (سُبْحانَ اللهَ) (الْحَمْدُ للهِ)، فاذا انتهيت الى اَحْسَنُ الْخالِقينَ تعود فتقول : لا اِلـهَ اِلاَّ اللهُ قَبْلَ كُلِّ اَحَد الى آخره تستبدل بـ (سُبْحانَ اللهَ) كلمة (لا اِلـهَ اِلاَّ اللهُ) ثمّ تقول : وَاللهُ اَكْبَرُ قَبْلَ كُلِّ اَحَد الى آخره تستبدل بـ (سُبْحانَ اللهَ) (اللهُ اَكْبَرُ) ثمّ تدعو بالدّعاء اَللّـهُمَّ مَنْ تَعَبَّأَ وَتَهَيَّأَ وقد مرّ في أعمال ليلة الجمعة ثمّ ادع بما ذكره الشّيخ ."},{"type":"AboutText","content":"أقول : هذا دعاء يدعى به في الموقف في عرفات وهو دعاء طويل وقد أعرضنا عن ذكره، وادعُ ايضاً في هذا اليوم وأنت خاشِع بالدّعاء السّابع والاربعين من الصّحيفة الكاملة وهو يحتوي على جميع مطالب الدّنيا والاخرة صلوات الله على منشئها، ومن دعوات هذا اليوم المشهورات دعاء سيّد الشّهداء (عليه السلام) ."},{"type":"Text","content":"روى بشر وبشير ابنا غالب الاسدي قالا : كنّا مع الحسين بن علي (عليهما السلام) عشيّة عرفة، فخرج (عليه السلام) من فُسطاطه متذلّلاً خاشاً فجعل يمشي هوناً هوناً حتّى وقف هو وجماعة من أهل بيته وولده ومواليه في ميسرة الجبل مستقبل البيت، ثمّ رفع يديه تلقاء وجهه كاستطعام المسكين، ثمّ قال :"},{"type":"Text","content":"اَلْحَمْدُ للهِ الَّذى لَيْسَ لِقَضآئِهِ دافِعٌ، وَلا لِعَطائِهِ مانِعٌ، وَلا كَصُنْعِهِ صُنْعُ صانِع، وَهُوَ الْجَوادُ الْواسِعُ، فَطَرَ اَجْناسَ الْبَدائِعِ، واَتْقَنَ بِحِكْمَتِهِ الصَّنائِعَ، لا تَخْفى عَلَيْهِ الطَّلائِعُ، وَلا تَضيعُ عِنْدَهُ الْوَدائِعُ، جازى كُلِّ صانِع، وَرائِشُ كُلِّ قانع، وَراحِمُ كُلِّ ضارِع، وَمُنْزِلُ الْمَنافِعِ وَالْكِتابِ الْجامِعِ، بِالنُّورِ السّاطِعِ، وَهُوَ لِلدَّعَواتِ سامِعٌ، وَلِلْكُرُباتِ دافِعٌ، وَلِلدَّرَجاتِ رافِعٌ، وَلِلْجَبابِرَةِ قامِعٌ، فَلا اِلهَ غَيْرُهُ، وَلا شَىءَ يَعْدِلُهُ، وَلَيْسَ كَمِثْلِهِ شَىءٌ، وَهُوَ السَّميعُ الْبَصيرُ، اللَّطيفُ الْخَبيرُ، وَهُوَ عَلى كُلِّ شَىء قَديرٌ، اَللّهُمَّ اِنّى اَرْغَبُ إِلَيْكَ، وَاَشْهَدُ بِالرُّبُوبِيَّةِ لَكَ، مُقِرّاً بِاَنَّكَ رَبّى، اِلَيْكَ مَرَدّى، اِبْتَدَأتَنى بِنِعْمَتِكَ قَبْلَ اَنْ اَكُونَ شَيْئاًمَذكوراً، وَخَلَقْتَنى مِنَ التُّرابِ، ثُمَّ اَسْكَنْتَنِى الاَْصْلابَ، آمِناً لِرَيْبِ الْمَنُونِ، وَاخْتِلافِ الدُّهُورِ والسِّنينَ، فَلَمْ اَزَلْ ظاعِناً مِنْ صُلْب اِلى رَحِم، فى تَقادُم مِنَ الاَْيّامِ الْماضِيَةِ، وَالْقُرُونِ الْخالِيَةِ، لَمْ تُخْرِجْنى لِرَأفَتِكَ بى، وَلُطْفِكَ لى، وَاِحْسانِكَ اِلَىَّ، فى دَوْلَةِ اَئِمَّةِ الْكُفْرِ الَّذينَ نَقَضُوا عَهْدَكَ، وَكَذَّبُوا رُسُلَكَ، لكِنَّكَ اَخْرَجْتَنى للَّذى سَبَقَ لى مِنَ الْهُدى، الَّذى لَهُ يَسَّرْتَنى، وَفيهِ اَنْشَأْتَنى، وَمِنْ قَبْلِ رَؤُفْتَ بى بِجَميلِ صُنْعِكَ، وَسَوابِغِ نِعَمِكَ، فابْتَدَعْتَ خَلْقى مِنْ مَنِىّ يُمْنى، وَاَسْكَنْتَنى فى ظُلُمات ثَلاث، بَيْنَ لَحْم وَدَم وَجِلْد، لَمْ تُشْهِدْنى خَلْقى، وَلَمْ تَجْعَلْ اِلَىَّ شَيْئاً مِنْ اَمْرى، ثُمَّ اَخْرَجْتَنى لِلَّذى سَبَقَ لى مِنَ الْهُدى اِلَى الدُّنْيا تآمّاً سَوِيّاً، وَحَفِظْتَنى فِى الْمَهْدِ طِفْلاً صَبِيّاً، وَرَزَقْتَنى مِنَ الْغِذآءِ لَبَناً مَرِيّاً، وَعَطَفْتَ عَلَىَّ قُلُوبَ الْحَواضِنِ، وَكَفَّلْتَنِى الاُْمَّهاتِ الرَّواحِمَ، وَكَلاْتَنى مِنْ طَوارِقِ الْجآنِّ، وَسَلَّمْتَنى مِنَ الزِّيادَةِ وَالنُّقْصانِ، فَتَعالَيْتَ يا رَحيمُ يا رَحْمنُ، حتّى اِذَا اسْتَهْلَلْتُ ناطِقاً بِالْكَلامِ، اَتْمَمْتَ عَلَىَّ سَوابِغَ الانْعامِ، وَرَبَّيْتَنى آيِداً فى كُلِّ عام، حَتّى إذَا اكْتَمَلَتْ فِطْرَتى، وَاعْتَدَلَتْ مِرَّتى، اَوْجَبْتَ عَلَىَّ حُجَتَّكَ، بِاَنْ اَلْهَمْتَنى مَعْرِفَتَكَ، وَرَوَّعْتَنى بِعَجايِبِ حِكْمَتِكَ، وَاَيْقَظْتَنى لِما ذَرَأتَ فى سَمآئِكَ وَاَرْضِكَ مِنْ بَدائِعِ خَلْقِكَ، وَنَبَّهْتَنى لِشُكْرِكَ، وَذِكْرِكَ، وَاَوجَبْتَ عَلَىَّ طاعَتَكَ وَعِبادَتَكَ، وَفَهَّمْتَنى ما جاءَتْ بِهِ رُسُلُكَ، وَيَسَّرْتَ لى تَقَبُّلَ مَرْضاتِكَ، وَمَنَنْتَ عَلَىَّ فى جَميعِ ذلِكَ بِعَونِكَ وَلُطْفِكَ، ثُمَّ اِذْ خَلَقْتَنى مِنْ خَيْرِ الثَّرى، لَمْ تَرْضَ لى يا اِلهى نِعْمَةً دُونَ اُخرى، وَرَزَقْتَنى مِنْ اَنواعِ الْمَعاشِ، وَصُنُوفِ الرِّياشِ بِمَنِّكَ الْعَظيمِ الاَْعْظَمِ عَلَىَّ، وَاِحْسانِكَ الْقَديمِ اِلَىَّ، حَتّى اِذا اَتْمَمْتَ عَلَىَّ جَميعَ النِّعَمِ، وَصَرَفْتَ عَنّى كُلَّ النِّقَمِ، لَمْ يَمْنَعْكَ جَهْلى وَجُرْأَتى عَلَيْكَ اَنْ دَلَلْتَنى اِلى ما يُقَرِّبُنى اِلَيْكَ، وَوفَّقْتَنى لِما يُزْلِفُنى لَدَيْكَ، فَاِنْ دَعْوَتُكَ اَجَبْتَنى، وَاِنْ سَأَلْتُكَ اَعْطَيْتَنى، وَاِنْ اَطَعْتُكَ شَكَرْتَنى، وَاِنْ شَكَرْتُكَ زِدْتَنى، كُلُّ ذلِكَ اِكْمالٌ لاَِنْعُمِكَ عَلَىَّ، وَاِحْسانِكَ اِلَىَّ، فَسُبْحانَكَ سُبْحانَكَ، مِنْ مُبْدِئ مُعيد، حَميد مجيد، تَقَدَّسَتْ اَسْمآؤُكَ، وَعَظُمَتْ آلاؤُكَ، فَأَىُّ نِعَمِكَ يا اِلهى اُحْصى عَدَداً وَذِكْراً، أَمْ اَىُّ عَطاياكَ أَقُومُ بِها شُكْراً، وَهِىَ يا رَبِّ اَكْثرُ مِنْ اَنْ يُحْصِيَهَا الْعآدّوُنَ، أَوْ يَبْلُغَ عِلْماً بِهَا الْحافِظُونَ، ثُمَّ ما صَرَفْتَ وَدَرَأْتَ عَنّى اَللّهُمَّ مِنَ الضُرِّ وَالضَّرّآءِ، أَكْثَرَ مِمّا ظَهَرَ لى مِنَ الْعافِيَةِ وَالسَّرّآءِ، وَاَنَا اَشْهَدُ يا اِلهى بِحَقيقَةِ ايمانى، وَعَقْدِ عَزَماتِ يَقينى، وَخالِصِ صَريحِ تَوْحيدى، وَباطِنِ مَكْنُونِ ضَميرى، وَعَلائِقِ مَجارى نُورِ بَصَرى، وَاَساريرِ صَفْحَةِ جَبينى، وَخُرْقِ مَسارِبِ نَفْسى، وَخَذاريفِ مارِنِ عِرْنَينى، وَمَسارِبِ سِماخِ سَمْعى، وَما ضُمَّتْ وَاَطبَقَتْ عَلَيْهِ شَفَتاىَ، وَحرِكاتِ لَفظِ لِسانى، وَمَغْرَزِ حَنَكِ فَمى وَفَكّى، وَمَنابِتِ اَضْراسى، وَمَساغِ مَطْعَمى وَمَشْرَبى، وَحِمالَةِ اُمِّ رَأْسى، وَبُلُوغِ فارِغِ حبائِلِ عُنُقى، وَمَا اشْتَمَلَ عَليْهِ تامُورُ صَدرى، وَحمائِلِ حَبْلِ وَتينى، وَنِياطِ حِجابِ قَلْبى، وَأَفْلاذِ حَواشى كَبِدى، وَما حَوَتْهُ شَراسيفُ اَضْلاعى، وَحِقاقُ مَفاصِلى، وَقَبضُ عَوامِلى، وَاَطرافُ اَنامِلى وَلَحْمى وَدَمى، وَشَعْرى وَبَشَرى، وَعَصَبى وَقَصَبى، وَعِظامى وَمُخّى وَعُرُوقى، وَجَميعُ جَوارِحى، وَمَا انْتَسَجَ عَلى ذلِكَ اَيّامَ رَِضاعى، وَما اَقلَّتِ الاَْرْضُ مِنّى، وَنَوْمى وَيقَظَتى وَسُكُونى وَحرَكاتِ رُكُوعى وَسُجُودى، اَنْ لَوْ حاوَلْتُ وَاجْتَهَدْتُ مَدَى الاَْعصارِ وَالاَْحْقابِ لَوْ عُمِّرْتُها اَنْ أُؤَدِّىَ شُكْرَ واحِدَة مِنْ أَنْعُمِكَ مَا اسْتَطَعْتُ ذلِكَ اِلاّ بِمَنِّكَ الْمُوجَبِ عَلَىَّ بِهِ شُكْرَكَ اَبَداً جَديداً، وَثَنآءً طارِفاً عَتيداً، اَجَلْ وَلوْ حَرَصْتُ اَنَا وَالْعآدُّونَ مِنْ اَنامِكَ، أَنْ نُحْصِىَ مَدى اِنْعامِكَ، سالِفِهِ وَآنِفِهِ ما حَصَرْناهُ عَدَداً، وَلا اَحْصَيناهُ اَمَداً، هَيْهاتَ أنّى ذلِكَ وَاَنْتَ الُْمخْبِرُ فى كِتابِكَ النّاطِقِ، وَالنَّبَأِ الصّادِقِ، وَاِنْ تَعُدُّوا نِعْمَةَ اللهِ لا تُحْصُوها، صَدَقَ كِتابُكَ اَللّهُمَّ وَاِنْبآؤُكَ، وَبَلَّغَتْ اَنْبِيآؤُكَ وَرُسُلُكَ، ما اَنْزَلْتَ عَلَيْهِمْ مِنْ وَحْيِكَ، وَشَرَعْتَ لَهُمْ وَبِهِمْ مِنْ دينِكَ، غَيْرَ أَنّى يا اِلهى اَشْهَدُ بِجَُهْدى وَجِدّى، وَمَبْلَغِ طاعَتى وَوُسْعى، وَأَقُولُ مُؤْمِناً مُوقِناً، اَلْحَمْدُ للهِ الَّذى لَمْ يَتَّخِذْ وَلَداً فَيَكُونَُ مَوْرُوثاً، وَلَمْ يَكُنْ لَهُ شَريكٌ فى مُلْكِهِ فَيُضآدَُّهُ فيَما ابْتَدَعَ، وَلا وَلِىٌّ مِنَ الذُّلِّ فَيُرْفِدَهُ فيما صَنَعَ، فَسُبْحانَهُ سُبْحانَهُ، لَوْ كانَ فيهِما آلِهَةٌ اِلاَّ الله لَفَسَدَتا وَتَفَطَّرَتا، سُبْحانَ اللهِ الْواحِدِ الاَْحَدِ الصَّمَدِ الَّذى لَمْ يَلِدْ وَلَمْ يُولَدْ، وَلَمْ يَكُنْ لَهُ كُفُواً اَحَدٌ، اَلْحَمْدُ للهِ حَمْداً يُعادِلُ حَمْدَ مَلائِكَتِهِ الْمُقَرَّبينَ، وَاَنْبِيآئِهِ الْمُرْسَلينَ، وَصَلَّى اللهُ عَلى خِيَرَتِهِ مُحَمَّد خاتَمِ النَّبِيّينَ، وَآلِهِ الطَّيِبينَ الطّاهِرينَ الُْمخلَصينَ وَسَلَّمَ ."},{"type":"Text","content":"ثمّ اندفع في المسألة واجتهد في الدّعاء ، وقال وعيناه سالتا دموعاً :"},{"type":"Text","content":"اَللّهُمَّ اجْعَلْنى اَخْشاكَ كَاُنّى اَراكَ، وَاَسْعِدْنى بِتَقوايكَ، وَلا تُشْقِنى بِمَعْصِيَتِكَ، وَخِرْلى فى قَضآئِكَ، وَبارِكْ لى فى قَدَرِكَ، حَتّى لا أُحِبَّ تَعْجيلَ ما اَخَّرْتَ وَلا تَأخيرَ ما عَجَّلْتَ، اَللّهُمَّ اجْعَلْ غِناىَ فى نَفْسى، وَالْيَقينَ فى قَلْبى، وَالاِْخْلاصَ فى عَمَلى، وَالنُّورَ فى بَصَرى، وَالْبَصيرَةَ فى دينى، وَمَتِّعْنى بِجَوارِحى، وَاجْعَلْ سَمْعى وَبَصَرىَ الْوارِثَيْنِ مِنّى، وَانْصُرْنى عَلى مَنْ ظَلَمَنى، وَاَرِنى فيهِ ثَاْرى وَمَآرِبى، وَاَقِرَّ بِذلِكَ عَيْنى، اَللَّهُمَّ اكْشِفْ كُرْبَتى، وَاسْتُرْ عَوْرَتى، وَاغْفِرْ لى خَطيئَتى، وَاخْسَأْ شَيْطانى، وَفُكَّ رِهانى، وَاْجَعْلْ لى يا اِلهى الدَّرَجَةَ الْعُلْيا فِى الاْخِرَةِ وَالاُْوْلى، اَللّهُمَّ لَكَ الْحَمْدُ كَما خَلَقْتَنى فَجَعَلْتَنى سَميعاً بَصيراً، وَلَكَ الْحَمْدُ كَما خَلَقْتَنى فَجَعَلْتَنى خَلْقاً سَوِيّاً رَحْمَةً بى، وَقَدْ كُنْتَ عَنْ خَلْقى غَنِيّاً، رَبِّ بِما بَرَأْتَنْى فَعَدَّلْتَ فِطْرَتى، رَبِّ بِما اَنَشَأْتَنى فَاَحْسَنْتَ صُورَتى، رَبِّ بِما اَحْسَنْتَ اِلَىَّ وَفى نَفْسى عافَيْتَنى، رَبِّ بِما كَلاَتَنى وَوَفَّقْتَنى، رَبِّ بِما اَنَعْمَتَ عَلَىَّ فَهَدَيْتَنى، رَبِّ بِما اَوْلَيْتَنى وَمِنْ كُلِّ خَيْر اَعْطَيْتَنى، رَبِّ بِما اَطْعَمْتَنى وَسَقَيْتَنى، رَبِّ بِما اَغْنَيْتَنى وَاَقْنَيْتَنى، رَبِّ بِما اَعَنْتَنى وَاَعْزَزْتَنى، رَبِّ بِما اَلْبَسْتَنى مِنْ سِتْرِكَ الصّافى، وَيَسَّرْتَ لى مِنْ صُنْعِكَ الْكافى، صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَعِنّى عَلى بَوائِقِ الدُّهُورِ، وَصُرُوفِ اللَّيالى وَالاَْيّامِ، وَنَجِّنى مِنْ اَهْوالِ الدُّنْيا وَكُرُباتِ الاْخِرَةِ، وَاكْفِنى شَرَّ ما يَعْمَلُ الظّالِمُونَ فِى الاَْرْضِ، اَللّهُمَّ ما اَخافُ فَاكْفِنى، وَما اَحْذَرُ فَقِنى، وَفى نَفْسى وَدينى فَاحْرُسْنى، وَفى سَفَرى فَاحْفَظْنى، وَفى اَهْلى وَمالى فَاخْلُفْنى، وَفى ما رَزَقْتَنى فَبارِكْ لى، وَفى نَفْسى فَذلِّلْنى، وَفى اَعْيُنِ النّاسِ فَعَظِّمْنى، وَمِنْ شَرِّ الْجِنِّ وَالاِْنْسِ فَسَلِّمْنى، وَبِذُنُوبى فَلا تَفْضَحْنى وَبِسَريرَتى فَلا تُخْزِنى، وَبِعَمَلى فَلا تَبْتَِلْنى، وَنِعَمَكَ فَلا تَسْلُبْنى، وَاِلى غَيْرِكَ فَلا تَكِلْنى، اِلهى اِلى مَنْ تَكِلُنى اِلى قَريب فَيَقطَعُنى، اَمْ اِلى بَعيد فَيَتَجَهَّمُنى، اَمْ اِلَى الْمُسْتَضْعَفينَ لى، وَاَنْتَ رَبّى وَمَليكُ اَمْرى، اَشْكُو اِلَيْكَ غُرْبَتى وَبُعْدَ دارى، وَهَوانى عَلى مَنْ مَلَّكْتَهُ اَمْرى، اِلهى فَلا تُحْلِلْ عَلَىَّ غَضَبَكَ، فَاِنْ لَمْ تَكُنْ غَضِبْتَ عَلَىَّ فَلا اُبالى سُبْحانَكَ غَيْرَ اَنَّ عافِيَتَكَ اَوْسَعُ لى، فَأَسْأَلُكَ يا رَبِّ بِنُورِ وَجْهِكَ الَّذى اَشْرَقَتْ لَهُ الاَْرْضُ وَالسَّماواتُ، وَكُشِفَتْ بِهِ الظُّلُماتُ، وَصَلُحَ بِهِ اَمْرُ الاَْوَّلينَ وَالاْخِرِينَ، اَنْ لا تُميتَنى عَلى غَضَبِكَ، وَلا تُنْزِلْ بى سَخَطَكَ، لَكَ الْعُتْبى لَكَ الْعُتْبى حَتّى تَرْضى قَبْلَ ذلِك، لا اِلهَ اِلاّ اَنْتَ، رَبَّ الْبَلَدِ الْحَرامِ وَالْمَشْعَرِ الْحَرامِ، وَالْبَيْتِ الْعَتيقِ الَّذى اَحْلَلْتَهُ الْبَرَكَةَ، وَجَعَلْتَهُ لِلنّاسِ اَمْنَاً، يا مَنْ عَفا عَنْ عَظيمِ الذُّنُوبِ بِحِلْمِهِ، يا مَنْ اَسْبَغَ النَّعْمآءَ بِفَضْلِهِ، يا مَنْ اَعْطَى الْجَزيلَ بِكَرَمِهِ، يا عُدَّتى فى شِدَّتى، يا صاحِبى فى وَحْدَتى، يا غِياثى فى كُرْبَتى، يا وَلِيّى فى نِعْمَتى، يا اِلهى وَاِلهَ آبائى اِبْراهيمَ وَاِسْماعيلَ وَاِسْحاقَ وَيَعْقُوبَ، وَرَبَّ جَبْرَئيلَ وَميكائيلَ وَاِسْرافيلَ، وَربَّ مُحَمَّد خاتَمِ النَّبِيّيينَ وَآلِهِ الْمُنْتَجَبينَ، مُنْزِلَ التَّوراةِ وَالاِْنْجيلَ، وَالزَّبُورِ وَالْفُرْقانِ، وَمُنَزِّلَ كهيعص، وَطه وَيس، وَالْقُرآنِ الْحَكيمِ، اَنْتَ كَهْفى حينَ تُعيينِى الْمَذاهِبُ فى سَعَتِها، وَتَضيقُ بِىَ الاَْرْضُ بِرُحْبِها، وَلَوْلا رَحْمَتُكَ لَكُنْتُ مِنَ الْهالِكينَ، وَاَنْتَ مُقيلُ عَثْرَتى، وَلَوْلا سَتْرُكَ اِيّاىَ لَكُنْتُ مِنَ الْمَفْضُوحِينَ، وَاَنْتَ مُؤَيِّدى بِالنَّصْرِ عَلى اَعْدآئى، وَلَوْلا نَصْرُكَ اِيّاىَ لَكُنْتُ مِنَ الْمَغْلُوبينَ، يا مَنْ خَصَّ نَفْسَهُ بِالْسُّمُوِّ وَالرِّفْعَةِ، فَاَوْلِيآؤهُ بِعِزِّهِ يَعْتَزُّونَ، يا مَنْ جَعَلَتْ لَهُ الْمُلُوكُ نَيرَ الْمَذَلَّةِ عَلى اَعْناقِهِمْ، فَهُمْ مِنْ سَطَواتِهِ خائِفُونَ، يَعْلَمُ خائِنَةَ الاَْعْيُنِ وَما تُخْفِى الصُّدُورُ، وَغَيْبَ ما تَأتِى بِهِ الاَْزْمِنَةُ وَالدُّهُورُ، يا مَنْ لا يَعْلَمُ كَيْفَ هُوَ اِلاّ هُوَ، يا مَنْ لا يَعْلَمُ ما هُوَ اِلاّ هُوَ، يا مَنْ لا يَعْلَم يَعْلَمُهُ، اِلاّ هُوَ يا مَنْ كَبَسَ الاَْرْضَ عَلَى الْمآءِ، وَسَدَّ الْهَوآءَ بِالسَّمآءِ، يا مَنْ لَهُ اَكْرَمُ الاَْسْمآءِ، يا ذَا الْمَعْرُوفِ الَّذى لا يَنْقَطِعُ اَبَداً، يا مُقَيِّضَ الرَّكْبِ لِيُوسُفَ فِى الْبَلَدِ الْقَفْرِ، وَمُخْرِجَهُ مِنَ الْجُبِّ وَجاعِلَهُ بَعْدَ الْعُبودِيَّةِ مَلِكاً، يا رآدَّهُ عَلى يَعْقُوبَ بَعْدَ اَنِ ابْيَضَّتْ عَيْناهُ مِنَ الْحُزْنِ فَهُوَ كَظيمٌ، يا كاشِفَ الضُّرِّ وَالْبَلْوى عَنْ اَيُّوبَ، وَمُمْسِكَ يَدَىْ اِبْرهيمَ عَنْ ذَبْحِ ابْنِهِ بَعْدَ كِبَرِ سِنِّهِ، وَفَنآءِ عُمُرِهِ، يا مَنِ اسْتَجابَ لِزَكَرِيّا فَوَهَبَ لَهُ يَحْيى، وَلَمْ يَدَعْهُ فَرْداً وَحيداً، يا مَنْ اَخْرَجَ يُونُسَ مِنْ بَطْنِ الْحُوتِ، يا مَنْ فَلَقَ الْبَحْرَ لِبَنى اِسْرآئيلَ فَاَنْجاهُمْ، وَجَعَلَ فِرْعَوْنَ وَجُنُودَهُ مِنَ الْمُغْرَقينَ، يا مَنْ اَرْسَلَ الرِّياحَ مُبَشِّرات بَيْنَ يَدَىْ رَحْمَتِهِ، يا مَنْ لَمْ يَعْجَلْ عَلى مَنْ عَصاهُ مِنْ خَلْقِهِ، يا مَنِ اسْتَنْقَذَ السَّحَرَةَ مِنْ بَعْدِ طُولِ الْجُحُودِ، وَقَدْ غَدَوْا فى نِعْمَتِهِ يَأكُلُونَ رِزْقَهُ، وَيَعْبُدُونَ غَيْرَهُ، وَقَدْ حادُّوهُ وَنادُّوهُ وَكَذَّبُوا رُسُلَهُ، يا اَللهُ يا اَللهُ، يا بَدىُ يا بَديعُ، لا نِدَّلَكَ، يا دآئِماً لا نَفَادَ لَكَ، يا حَيّاً حينَ لا حَىَّ، يا مُحْيِىَ الْمَوْتى، يا مَنْ هُوَ قآئِمٌ عَلى كُلِّ نَفْس بِما كَسَبَتْ، يا مَنْ قَلَّ لَهُ شُكْرى فَلَمْ يَحْرِمْنى، وَعَظُمَتْ خَطيئَتى فَلَمْ يَفْضَحْنى، وَرَآنى عَلَى الْمَعاصى فَلَمْ يَشْهَرْنى، يا مَنْ حَفِظَنى فى صِغَرى، يا مَنْ رَزَقَنى فى كِبَرى، يا مَنْ اَياديهِ عِنْدى لا تُحْصى، وَنِعَمُهُ لا تُجازى، يا مَنْ عارَضَنى بِالْخَيْرِ والاِْحْسانِ، وَعارَضْتُهُ بِالاِْساءَةِ وَالْعِصْيانِ، يا مَنْ هَدانى لِلاْيمانِ مِنْ قَبْلِ اَنْ اَعْرِفَ شُكْرَ الاِْمْتِنانِ، يا مَنْ دَعَوْتُهُ مَريضاً فَشَفانى، وَعُرْياناً فَكَسانى، وَجائِعاً فَاَشْبَعَنى، وَعَطْشاناً فَاَرْوانى، وَذَليلاً فَاَعَزَّنى، وَجاهِلاً فَعَرَّفَنى، وَوَحيداً فَكَثَّرَنى، وَغائِباً فَرَدَّنى، وَمُقِلاًّ فَاَغْنانى، وَمُنْتَصِراً فَنَصَرَنى، وَغَنِيّاً فَلَمْ يَسْلُبْنى، وَاَمْسَكْتُ عَنْ جَميعِ ذلِكَ فَابْتَدَاَنى، فَلَكَ الْحَمْدُ وَالشُّكْرُ، يا مَنْ اَقالَ عَثْرَتى، وَنَفَّسَ كُرْبَتى، وَاَجابَ دَعْوَتى، وَسَتَرَ عَوْرَتى، وَغَفَرَ ذُنُوبى، وَبَلَّغَنى طَلِبَتى، وَنَصَرَنى عَلى عَدُوّى، وَاِنْ اَعُدَّ نِعَمَكَ وَمِنَنَكَ وَكَرائِمَ مِنَحِكَ لا اُحْصيها، يا مَوْلاىَ اَنْتَ الَّذى مَنْنْتَ، اَنْتَ الَّذى اَنْعَمْتَ، اَنْتَ الَّذى اَحْسَنْتَ، اَنْتَ الَّذى اَجْمَلْتَ، اَنْتَ الَّذى اَفْضَلْتَ، اَنْتَ الَّذى اَكْمَلْتَ، اَنْتَ الَّذى رَزَقْتَ، اَنْتَ الَّذى وَفَّقْتَ، اَنْتَ الَّذى اَعْطَيْتَ، اَنْتَ الَّذى اَغْنَيْتَ، اَنْتَ الَّذى اَقْنَيْتَ، اَنْتَ الَّذى آوَيْتَ، اَنْتَ الَّذى كَفَيْتَ، اَنْتَ الَّذى هَدَيْتَ، اَنْتَ الَّذى عَصَمْتَ، اَنْتَ الَّذى سَتَرْتَ، اَنْتَ الَّذى غَفَرْتَ، اَنْتَ الَّذى اَقَلْتَ، اَنْتَ الَّذى مَكَّنْتَ، اَنْتَ الَّذى اَعْزَزْتَ، اَنْتَ الَّذى اَعَنْتَ، اَنْتَ الَّذى عَضَدْتَ، اَنْتَ الَّذى اَيَّدْتَ، اَنْتَ الَّذى نَصَرْتَ، اَنْتَ الَّذى شَفَيْتَ، اَنْتَ الَّذى عافَيْتَ، اَنْتَ الَّذى اَكْرَمْتَ، تَبارَكْتَ وَتَعالَيْتَ، فَلَكَ الْحَمْدُ دآئِماً، وَلَكَ الشُّكْرُ واصِباً اَبَداً، ثُمَّ اَنَا يا اِلهَى الْمُعَتَرِفُ بِذُنُوبى فَاغْفِرْها لى، اَنَا الَّذى اَسَأتُ، اَنَا الَّذى اَخْطَأتُ، اَنَا الَّذى هَمَمْتُ، اَنَا الَّذى جَهِلْتُ، اَنَا الَّذى غَفِلْتُ، اَنَا الَّذى سَهَوْتُ، اَنَا الَّذِى اعْتَمَدْتُ، اَنَا الَّذى تَعَمَّدْتُ، اَنَا الَّذى وَعَدْتُ، وَاَنَا الَّذى اَخْلَفْتُ، اَنَا الَّذى نَكَثْتُ، اَنَا الَّذى اَقْرَرْتُ، اَنَا الَّذِى اعْتَرَفْتُ بِنِعْمَتِكَ عَلَىَّ وَعِنْدى، وَاَبُوءُ بِذُنُوبى فَاغْفِرْها لى، يا مَنْ لا تَضُرُّهُ ذُنُوبُ عِبادِهِ، وهُوَ الَغَنِىُّ عَنْ طاعَتِهِمْ، وَالْمُوَفِّقُ مَنْ عَمِلَ صالِحاً مِنْهُمْ بِمَعُونَتِهِ وَرَحْمَتِه، فَلَكَ الْحَمْدُ اِلهى وَسيِّدى، اِلهى اَمَرْتَنى فَعَصَيْتُكَ، وَنَهَيْتَنى فَارْتَكَبْتُ نَهْيَكَ، فَاَصْبَحْتُ لا ذا بَرآءَة لى فَاَعْتَذِرُ، وَلاذا قُوَّة فَاَنْتَصِرَُ، فَبِأَىِّ شَىء اَسْتَقْبِلُكَ يا مَوْلاىَ، اَبِسَمْعى اَمْ بِبَصَرى، َاْم بِلِسانى، اَمْ بِيَدى اَمْ بِرِجْلى، اَلَيْسَ كُلُّها نِعَمَكَ عِندى، وَبِكُلِّها عَصَيْتُكَ يا مَوْلاىَ، فَلَكَ الْحُجَّةُ وَالسَّبيلُ عَلىَّ، يا مَنْ سَتَرَنى مِنَ الاْباءِ وَالاُْمَّهاتِ اَنْ يَزجُرُونى، وَمِنَ الْعَشائِرِ وَالاِْخْوانِ اَنْ يُعَيِّرُونى، وَمِنَ السَّلاطينِ اَنْ يُعاقِبُونى، وَلَوِ اطَّلَعُوا يا مَوْلاىَ عَلى مَا اطَّلَعْتَ عَلَيْهِ مِنّى اِذاً ما اَنْظَرُونى، وَلَرَفَضُونى وَقَطَعُونى، فَها اَنَا ذا يا اِلهى بَيْنَ يَدَيْكَ يا سَيِّدى خاضِعٌ ذَليلٌ، حَصيرٌ حَقيرٌ، لا ذُو بَرآءَة فَاَعْتَذِرَ، وَلا ذُو قُوَّة فَاَنْتَصِرَُ، وَلا حُجَّة فَاَحْتَجُّ، بِها، وَلا قائِلٌ لَمْ اَجْتَرِحْ، وَلَمْ اَعْمَلْ سُواً، وَما عَسَى الْجُحُودُ وَلَوْ جَحَدْتُ يا مَوْلاىَ يَنْفَعُنى، كَيْفَ وَاَنّى ذلِكَ وَجَوارِحى كُلُّها شاهِدَةٌ عَلَىَّ بِما قَدْ عَمِلْتُ، وَعَلِمْتُ يَقيناً غَيْرَ ذى شَكٍّ اَنَّكَ سآئِلى مِنْ عَظائِمِ الاُْمُورِ، وَاَنَّكَ الْحَكَمُ الْعَدْلُ الَّذى لا تَجُورُ، وَعَدْلُكَ مُهْلِكى، وَمِنْ كُلِّ عَدْلِكَ مَهْرَبى، فَاِنْ تُعَذِّبْنى يا اِلهى فَبِذُنُوبى بَعْدَ حُجَّتِكَ عَلَىَّ، وَاِنْ تَعْفُ عَنّى فَبِحِلْمِكَ وَجُودِكَ وَكَرَمِكَ، لا اِلهَ اِلاّ اَنْتَ سُبْحانَكَ اِنّى كُنْتُ مِنَ الظّالِمينَ، لا اِلهَ اِلاّ اَنْتَ سُبْحانَكَ اِنّى كُنْتُ مِنَ الْمُسْتَغْفِرينَ، لا اِلهَ اِلاّ اَنْتَ سُبْحانَكَ اِنّى كُنْتُ مِنَ الْمُوَحِّدينَ، لا اِلهَ اِلاّ اَنْتَ سُبْحانَكَ اِنّى كُنْتُ مِنَ الْخائِفينَ، لا اِلهَ اِلاّ اَنْتَ سُبْحانَكَ اِنّى كُنْتُ مِنَ الْوَجِلينَ، لا اِلهَ اِلاّ اَنْتَ سُبْحانَكَ اِنّى كُنْتُ مِنَ الَّراجينَ، لا اِلهَ اِلاّ اَنْتَ سُبْحانَكَ اِنّى كُنْتُ مِنَ الرّاغِبينَ، لا اِلهَ اِلاّ اَنْتَ سُبْحانَكَ اِنّى كُنْتُ مِنَ الْمُهَلِّلينَ، لا اِلهَ اِلاّ اَنْتَ سُبْحانَكَ اِنّى كُنْتُ مِنَ السّائِلينَ، لا اِلهَ اِلاّ اَنْتَ سُبْحانَكَ اِنّى كُنْتُ مِنَ الْمُسَبِّحينَ، لا اِلهَ اِلاّ اَنْتَ سُبْحانَكَ اِنّى كُنْتُ مِنَ الْمُكَبِّرينَ، لا اِلهَ اِلاّ اَنْتَ سُبْحانَكَ رَبّى وَرَبُّ آبائِىَ الاَْوَّلينَ، اَللّهُمَّ هذا ثَنائى عَلَيْكَ مُمَجِّداً، وَاِخْلاصى بِذِكْرِكَ مُوَحِّداً، وَاِقْرارى بِآلائكَ مَعَدِّداً، وَاِنْ كُنْتُ مُقِرّاً اَنّى لَمْ اُحْصِها لِكَثْرَتِها وَسُبوغِها، وَتَظاهُرِها وَتَقادُمِها اِلى حادِث، ما لَمْ تَزَلْ تَتَعَهَّدُنى بِهِ مَعَها مُنْذُ خَلَقْتَنى وَبَرَأتَنى مِنْ اَوَّلِ الْعُمْرِ، مِنَ الاِْغْنآءِ مِنَ الْفَقْرِ، وَكَشْفِ الضُّرِّ، وَتَسْبِيبِ الْيُسْرِ، وَدَفْعِ الْعُسْرِ، وَتَفريجِ الْكَرْبِ، وَالْعافِيَةِ فِى الْبَدَنِ، وَالسَّلامَةِ فِى الدّينِ، وَلَوْ رَفَدَنى عَلى قَدْرِ ذِكْرِ نِعْمَتِكَ جَميعُ الْعالَمينَ مِنَ الاَْوَّلينَ وَالاْخِرينَ،، ما قَدَرْتُ وَلاهُمْ عَلى ذلِكَ، تَقَدَّسْتَ وَتَعالَيْتَ مِنْ رَبٍّ كَريم، عَظيم رَحيم، لا تُحْصى آلاؤُكَ، وَلا يُبْلَغُ ثَنآؤُكَ، وَلا تُكافى نَعْمآؤُكَ، فَصَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَتْمِمْ عَلَيْنا نِعَمَكَ، وَاَسْعِدْنا بِطاعَتِكَ، سُبْحانَكَ لا اِلهَ اِلاّ اَنْتَ، اَللَّهُمَّ اِنَّكَ تُجيبُ الْمُضْطَرَّ، وَتَكْشِفُ السُّوءَ، وَتُغيثُ الْمَكْرُوبَ، وَتَشْفِى السَّقيمَ، وَتُغْنِى الْفَقيرَ، وَتَجْبُرُ الْكَسيرَ، وَتَرْحَمُ الصَّغيرَ، وَتُعينُ الْكَبيرَ، وَلَيْسَ دُونَكَ ظَهيرٌ، وَلا فَوْقَكَ قَديرٌ، وَانْتَ الْعَلِىُّ الْكَبيرُ، يا مُطْلِقَ الْمُكَبِّلِ الاَْسيرِ، يا رازِقَ الطِّفْلِ الصَّغيرِ، يا عِصْمَةَ الْخآئِفِ الْمُسْتَجيرِ، يا مَنْ لا شَريكَ لَهُ وَلا وَزيرَ، صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَعْطِنى فى هذِهِ الْعَشِيَّةِ، اَفْضَلَ ما اَعْطَيْتَ وَاَنَلْتَ اَحَداً مِنْ عِبادِكَ، مِنْ نِعْمَة تُوليها، وَآلاء تُجَدِّدُها، وَبَلِيَّة تَصْرِفُها، وَكُرْبَة تَكْشِفُها، وَدَعْوَة تَسْمَعُها، وَحَسَنَة تَتَقَبَّلُها، وَسَيِّئَة تَتَغَمَّدُها، اِنَّكَ لَطيفٌ بِما تَشاءُ خَبيرٌ، وَعَلى كُل"},{"type":"Text","content":"ومِن خطبة أمير المؤمنين (عليه السلام) في يَوم الغَدير"},{"type":"Text","content":"ومن فطّر مؤمناً في ليلته فكأنّما فطّر فئاماً وفئاماً يعدها بيده عشراً، فنهض ناهِض فقال : يا أمير المؤمنين وما الفئام ؟ قال : مائتا ألف نبيّ وصدّيق وشهيد، فكيف بمن يكفل عدداً من المؤمنين والمؤمنات فأنا ضمينه على الله تعالى الامان من الكفر والفقر الخ ."},{"type":"Text","content":"والخلاصة : انّ فضل هذا اليوم الشريف اكثر من أن يذكر، وهو يوم قبول أعمال الشّيعة، ويوم كشف غمُومهم، وهو اليوم الذي انتصر فيه موسى على السّحرة، وجعل الله تعالى النّار فيه على ابراهيم الخليل برداً وسلاماً، ونصب فيه موسى (عليه السلام) وصيّه يوشع بن نون، وجعل فيه عيسى (عليه السلام) شمعون الصّفا وَصيّاً له، واشهد فيهِ سليمان (عليه السلام) قومه على استخلاف آصف بن برخيا، وآخى فيه رسول الله (صلى الله عليه وآله وسلم) بين أصحابه، ولذلك ينبغي فيه أن يواخي المؤمن أخاه وهي على ما رواه شيخنا في مستدرك الوسائل عن كتاب زاد الفردوس بأن يضع يده اليمنى على اليد اليمنى لاخيه المؤمِن ويقول :"},{"type":"Text","content":"وَآخَيْتُكَ فِى اللهِ، وَصافَيْتُكَ فِى اللهِ، وَصافَحْتُكَ فِى اللهِ، وَعاهَدْتُ اللهَ وَمَلائِكَتَهُ وَكُتُبَهُ وَرُسُلَهُ وَاَنْبِيآءَهُ وَالاَْئِمَّةَ الْمَعْصُومينَ عليهم السلام عَلى اَنّى اِنْ كُنْتُ مِنْ اَهْلِ الْجَنَّةِ وَالشَّفاعَةِ وَاُذِنَ لى بِاَنْ اَدْخُلَ الْجَنَّةَ لا اَدْخُلُها اِلاّ وَاَنْتَ مَعى ."},{"type":"Text","content":"ثمّ يقول أخوهُ المؤمن : قَبِلْتُ (ثمّ يقُول) : اَسْقَطْتُ عَنْكَ جَميعَ حُقُوقِ الاُخُوَّةِ ما خَلاَ الشَّفاعَةَ وَالدُّعآءَ وَالزِّيارَةَ، والمحدّث الفيض ايضاً قد أورد ايجاب عقد المواخاة في كتاب خلاصة الاذكار بما يقرب ممّا ذكرناه ثمّ قال : ثمّ يقبل الطرف الاخر لنفسه أو لموكّله باللّفظ الدّال على القبول ، ثمّ يسقط كلّ منهما عن صاحبه جميع حقوق الاخوّة ما سوى الدّعاء والزّيارة ."}],"preview":"الثّاني : زيارة الحسين صلوات الله عليه، فانّها تعدل ألف حجّة وألف عمرة وألف جهاد بل تفوقها، والاحاديث في كثرة فضل زيارته (عليه السلام) في هذا اليوم متواترة، ومن وفّق فيه لزيارته (ع","hasTranslate":false},{"id":"mf_ar_172","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل السّادِسُ :","title":"اليوم الرّابع والعِشرون","blocks":[{"type":"Text","content":"هُو يوم المباهلة على الاشهر، باهل فيه رسول الله (صلى الله عليه وآله وسلم) نصارى نجران وقد اكتسى بعبائه، وأدخل معه تحت الكساء عليّاً وفاطمة والحسن والحسين (عليهم السلام) وقال : « اللهمّ انّه قد كان لكلّ نبيّ من الانبياء أهل بيت هم أخصّ الخلق اليه، اللهمّ وهؤلاءِ أهل بيتي فأذهب عنهم الرِّجس وَطهّرهم تطهيراً » فهبط جبرئيل بآية التّطهير في شأنهم، ثمّ خرج النّبيّ (صلى الله عليه وآله وسلم)بهم (عليهم السلام) للمباهلة، فلمّا بصر بهم النّصارى ورأوا منهم الصّدق وشاهدوا امارات العذاب، لم يجرؤا على المباهلة، فطلبوا المصالحة وقبلوا الجزية عليهم، وفي هذا اليوم أيضاً تصدّق أمير المؤمنين (عليه السلام) بخاتمه على الفقير وهو راكع، فنزل فيه الاية انّما وَليُّكُمُ اللهُ وَرَسُولُهُ ."}],"preview":"هُو يوم المباهلة على الاشهر، باهل فيه رسول الله (صلى الله عليه وآله وسلم) نصارى نجران وقد اكتسى بعبائه، وأدخل معه تحت الكساء عليّاً وفاطمة والحسن والحسين (عليهم السلام) وقال : « ال","hasTranslate":false},{"id":"mf_ar_173","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل السّادِسُ :","title":"الثّاني : الصّيام","blocks":[{"type":"Text","content":"الثّالث : الصّلاة ركعتان كصلاة عيد الغدير وقتاً وصفة وأجراً، ولكن فيها تقرأ آية الكرسي الى هُمْ فيها خالِدُونَ ."},{"type":"Text","content":"الرّابع : أن يدعو بدعاء المباهِلة وهو يشابه دعاء أسحار شهر رمضان وفي هذا الدّعاء يختلف نسخة الشّيخ عن نسخة السّيد اختلافاً كثيراً وانّي أختار منهما رواية الشّيخ في المصباح ، قال : دعاء يوم المباهلة مرويّاً عن الصّادق صلوات الله وسلامه عليه بما له من الفضل، تقول :"},{"type":"Text","content":"اَللّـهُمَّ اِنّى اَسْاَلُكَ مِنْ بَهآئِكَ بِاَبْهاهُ وَكُلُّ بَهآئِكَ بَهِىٌّ، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِبَهآئِكَ كُلِّهِ، اَللّـهُمَّ اِنّى اَسْاَلُكَ مِنْ جَلالِكَ بِاَجَلِّهِ وَكُلُّ جَلالِكَ جَليلٌ، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِجَلالِكَ كُلِّهِ، اَللّـهُمَّ اِنّى اَسْاَلُكَ مِنْ جَمالِكَ بِاَجْمَلِهِ وَكُلُّ جَمالِكَ جَميلٌ، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِجَمالِكَ كُلِّهِ، اَللّـهُمَّ اِنّى اَدْعُوكَ كَما اَمَرْتَنى فَاسْتَجِبْ لى كَما وَعَدْتَنى، اَللّـهُمَّ اِنّى اَسْاَلُكَ مِنْ عَظَمَتِكَ بِاَعْظَمِها وَكُلُّ عَظَمَتِكَ عَظَيمَةٌ، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِعَظَمَتِكَ كُلِّها، اَللّـهُمَّ اِنّى اَسَأَلُكَ مِنْ نُورِكَ بِاَنْوَرِهِ وَكُلُّ نُورِكَ نَيِّرٌ، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِنُورِكَ كُلِّهِ، اَللّـهُمَّ اِنّى اَسْاَلُكَ مِنْ رَحْمَتِكَ بِاَوْسَعِها وَكُلُّ رَحْمَتِكَ واسِعَةٌ، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِرَحْمَتِكَ كُلِّها، اَللّـهُمَّ اِنّى اَدْعُوكَ كَما اَمَرْتَنى فَاسْتَجِبْ لى كَما وَعَدْتَنى، اَللّـهُمَّ اِنّى اَسْاَلُكَ مِنْ كَمالِكَ بِاَكْمَلِهِ وَكُلُّ كَمالِكَ كامِلٌ اَللّـهُمَّ اِنّى اَسْاَلُكَ بِكَمالِكَ كُلِّهِ، اَللّـهُمَّ اِنّى اَسْاَلُكَ مِنْ كَلِماتِكَ بِاَتَمِّها وَكُلُّ كَلِماتِكَ تآمَّةٌ، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِكَلِماتِكَ كُلِّهَا، اَللّـهُمَّ اِنّى اَسْاَلُكَ مِنْ اَسمآئِكَ بِاَكْبَرِها وَكُلُّ اَسْمآئِكَ كَبيرَةٌ، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِاَسْمآئِكَ كُلِّها، اَللّـهُمَّ اِنّى اَدْعُوكَ كَما اَمَرْتَنى فَاسْتَجِبْ لى كَما وَعَدْتَنى، اَللّـهُمَّ اِنّى اَسْاَلُكَ مِنْ عِزَّتِكَ باَعَزِّها وَكُلُّ عِزَّتِكَ عَزيزَةٌ، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِعِزَّتِكَ كُلِّها، اَللّـهُمَّ اِنّى اَسْاَلُكَ مِنْ مَشِيَّتِكَ بِاَمْضاها وَكُلُّ مَشِيَّتِكَ ماضِيَةٌ، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِمَشِيَّتِكَ كُلِّها، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِقُدْرَتِكَ الَّتى اسْتَطَلْتَ بِها عَلى كُلِّ شَىْء وَكُلُّ قُدْرَتِكَ مُسْتَطيلَةٌ، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِقُدْرَتِكَ كُلِّها، اَللّـهُمَّ اِنّى اَدْعُوكَ كَما اَمَرْتَنى فَاسْتَجِبْ لى كَما وَعَدْتَنى، اَللّـهُمَّ اِنّى اَسْاَلُكَ مِنْ عِلْمِكَ بِاَنْفَذِهِ وَكُلُّ عِلْمِكَ نافِذٌ، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِعِلْمِكَ كُلِّهِ، اَللّـهُمَّ اِنّى اَسْاَلُكَ مِنْ قَوْلِكَ بِاَرْضاهُ وَكُلُّ قَوْلِكَ رَضِىٌّ، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِقَوْلِكَ كُلِّهِ، اَللّـهُمَّ اِنّى اَسْاَلُكَ مِنْ مَسآئِلِكَ بِاَحَبِّهآ وَكُلُّها اِلَيْكَ حَبيبةٌ، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِمَسآئِلِكَ كُلِّها، اَللّـهُمَّ اِنّى اَدْعُوكَ كَما اَمَرْتَنى فَاسْتَجِبْ لى كَما وَعَدْتَنى، اَللّـهُمَّ اِنّى اَسْاَلُكَ مِنْ شَرَفِكَ بِاَشْرَفِهِ وَكُلُّ شَرَفِكَ شَريفٌ، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِشَرَفِكَ كُلِّهِ، اَللّـهُمَّ اِنّى اَسْاَلُكَ مِنْ سُلْطانِكَ بِاَدْوَمِهِ وَكُلُّ سُلطانِكَ دآئِمٌ، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِسُلْطانِكَ كُلِّهِ، اَللّـهُمَّ اِنّى اَسْاَلُكَ مِنْ مُلْكِكَ بِاَفْخَرِهِ وَكُلُّ مُلْكِكَ فاخِرٌ، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِمُلْكِكَ كُلِّهِ، اَللّـهُمَّ اِنّى اَدْعُوكَ كَما اَمَرْتَنى فَاسْتَجِبْ لى كَما وَعَدْتَنى، اَللّـهُمَّ اِنّى اَسْاَلُكَ مِنْ عَلائِكَ بِاَعْلاهُ وَكُلُّ عَلائِكَ عال، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِعَلائِكَ كُلِّهِ، اَللّـهُمَّ اِنّى اَسْاَلُكَ مِنْ آياتِكَ بِاَعْجَبِها وَكُلُّ آياتِكَ عَجيبَةٌ، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِاياتِكَ كُلِّها، اَللّـهُمَّ اِنّى اَسْاَلُكَ مِنْ مَنِّكَ بِاَقْدَمِهِ وَكُلُّ مَنِّكَ قَديمٌ، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِمَنِّكَ كُلِّهِ، اَللّـهُمَّ اِنّى اَدْعُوكَ كَما اَمَرْتَنى فَاسْتَجِبْ لى كَما وَعَدْتَنى، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِما اَنْتَ فيهِ مِنَ الشُّؤُنِ وَالْجَبَرُوتِ، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِكُلِّ شَأْن وَكُلِّ جَبَرُوت، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِما تُجيبُنى بِهِ حينَ اَسْاَلُكَ، يا اَللهُ يا لا اِلـهَ اِلاّ اَنْتَ، اَسْاَلُكَ بِبَهآءِ لا اِلـهَ اِلاّ اَنْتَ، يا لا اِلـهَ اِلاّ اَنْتَ اَسْاَلُكَ بِجَلالِ لا اِلـهَ اِلاّ اَنْتَ، يا لا اِلـهَ اِلاّ اَنْتَ اَسْاَلُكَ بِلا اِلـهَ اِلاّ اَنْتَ، اَللّـهُمَّ اِنّى اَدْعُوكَ كَما اَمَرْتَنى فَاسْتَجِبْ لى كَما وَعَدْتَنى، اَللّـهُمَّ اِنّى اَسْاَلُكَ مِنْ رِزْقِكَ باَعَمِّهِ وَكُلُّ رِزْقِكَ عآمُّ، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِرِزْقِكَ كُلِّهِ، اَللّـهُمَّ اِنّى اَسْاَلُكَ مِنْ عَطآئِكَ بِاَهْنَإِهِ وَكُلُّ عَطآئِكَ هَنيئٌ، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِعَطآئِكَ كُلِّهِ، اَللّـهُمَّ اِنّى اَسْاَلُكَ مِنْ خَيْرِكَ باَعْجَلِهِ وَكُلُّ خَيْرِكَ عاجِلُ، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِخَيْرِكَ كُلِّهِ، اَللّـهُمَّ اِنّى اَسْاَلُكَ مِنْ فَضْلِكَ بِاَفْضَلِهِ وَكُلُّ فَضْلِكَ فاضِلُ، اَللّـهُمَّ اِنّى اَسْاَلُكَ بِفَضْلِكَ كُلِّهِ، اَللّـهُمَّ اِنّى اَدْعُوكَ كَما اَمَرْتَنى فَاسْتَجِبْ لى كَما وَعَدْتَنى، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَابْعَثْنى عَلَى الاِْيمانِ بِكَ، وَالتَّصْديقِ بِرَسُولِكَ عَلَيْهِ وَآلِهِ السَّلامُ، وَالْوِلايَةِ لِعَلِىِّ بْنِ اَبيطالِب، وَالْبَرآءَةِ مِنْ عَدُوِّهِ وَالاْيتِمامِ بِالاَْئِمَّةِ مِنْ آلِ مُحَمَّد عليهم السلام فَإِنّى قَدْ رَضيتُ بِذلِكَ يا رَبِّ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد عَبْدِكَ وَرَسُولِكَ فِى الاَْوَّلينَ، وَصَلِّ عَلى مُحَمَّد فِى الاَْخِرِينَ، وَصَلِّ عَلى مُحَمَّد فِى الْمَلاِ الاَْعْلى، وَصَلِّ عَلى مُحَمَّد فِى الْمُرْسَلينَ، اَللّـهُمَّ اَعْطِ مُحَمَّدًا الْوَسيلَةَ وَالشَّرَفَ وَالْفَضيلَةَ وَالدَّرَجَةَ الْكَبيرَةَ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَقَنِّعْنى بِما رَزَقْتَنى، وَبارِكْ لى فيـما آتَيْتَنى، وَاحْفَظْنى فى غَيْبَتى وَكُلِّ غائِب هُوَ لى، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَابْعَثْنى عَلَى الاِْيمانِ بِكَ، وَالتَّصْديقِ بِرَسُولِكَ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاَسْاَلُكَ خَيْرَ الْخَيْرِ رِضْوانَكَ وَالْجَنَّةَ، وَاَعُوذُ بِكَ مِنْ شَرِّ الشَرِّ سَخَطِكَ وَالنّارِ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاحْفَظْنى مِنْ كُلِّ مُصيبَة، وَمِنْ كُلِّ بَلِيَّة، وَمِنْ كُلِّ عُقُوبَة، وَمِنْ كُلِّ فِتْنَة وَمِنْ كُلِّ بَلاء، وَمِنْ كُلِّ شَرّ، وَمِنْ كُلِّ مَكْرُوه، وَمِنْ كُلِّ مُصيبَة، وَمِنْ كُلِّ آفَة، نَزَلَتْ اَوْ تَنْزِلُ مِنَ السَّمآءِ اِلَى الاَْرْضِ فى هذِهِ السّاعَةِ، وَفى هذِهِ اللّيْلَةِ، وَفى هذَا الْيَومِ، وَفى هذَا الشَّهْرِ، وَفى هذِهِ السَّنَةِ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاقْسِمْ لى مِنْ كُلِّ سُرُور، وَمِنْ كُلِّ بَهْجَة، وَمِنْ كُلِّ اسْتِقامَة، وَمِنْ كُلِّ فَرَج، وَمِنْ كُلِّ عافِيَة، وَمِنْ كُلِّ سَلامَة، وَمِنْ كُلِّ كَرامَة، وَمِنْ كُلِّ رِزْق واسِع حَلال طَيِّب، وَمِنْ كُلِّ نِعْمَة وِمَنْ كُلِّ سَعَة نَزَلَتُ اَوْ تَنْزِلُ مِنَ السَّمآءِ اِلَى الاَْرْضِ فى هذِهِ السّاعَةِ وَفى هذِهِ اللّيْلَةِ وَفى هذَا الْيَوْمِ وَفى هذَا الشَّهْرِ وَفى هذِهِ السَّنَةِ، اَللّـهُمَّ اِنْ كانَتْ ذُنُوبى قَدْ اَخْلَقَتْ وَجْهى عِنْدَكَ، وَحالَتْ بَيْنى وَبَيْنَكَ، وَغَيَّرَتْ حالى عِنْدَكَ فَاِنّى اَسْاَلُكَ بِنُورِ وَجْهِكَ الَّذى لا يُطْفَأْ وَبِوَجْهِ مُحَمَّد حَبيبِكَ الْمُصْطَفى، وَبِوَجْهِ وَلِيِّكَ عَلِىّ الْمُرْتَضى، وَبِحَقِّ اَوْلِيآئِكَ الَّذينَ انْتَجَبْتَهُمْ اَنْ تُصَلِّىَ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَنْ تَغْفِرَ لى ما مَضى مِنْ ذُنُوبى، وَاَنْ تَعْصِمَنى فيـما بَقِىَ مِنْ عُمْرى، وَاَعُوذُ بِكَ اَللّـهُمَّ اَنْ اَعُودَ فى شَىْء مِنْ مَعاصيكَ اَبَداً ما اَبْقَيْتَنى حَتّى تَتَوَفّانى، وَاَنَا لَكَ مُطيعٌ وَاَنْتَ عَنّى راض، وَاَنْ تَخْتِمَ لى عَمَلى بِاَحْسَنِهِ، وَتَجْعَلَ لى ثَوابَهُ الْجَنَّةَ، وَاَنْ تَفْعَلَ بى ما اَنْتَ اَهْلُهُ يا اَهْلَ التَّقْوى وَيا اَهْلَ الْمَغْفِرَةِ، صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَارْحِمْنى بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ ."},{"type":"Text","content":"الخامس : أن يدعو بما رواه الشّيخ والسّيد بعد الصّلاة ركعتين والاستغفار سبعين مرّة ومفتتح الدّعاء اَلْحَمْدُ للهِ رَبِّ الْعالَمينَ، وينبغي التّصدّق في هذا اليوم على الفقراء تأسّياً بمولى كلّ مؤمن ومؤمنة أمير المؤمنين (عليه السلام) وينبغي أيضاً زيارته (عليه السلام) والانسب قراءة الزّيارة الجامِعة ."}],"preview":"الثّالث : الصّلاة ركعتان كصلاة عيد الغدير وقتاً وصفة وأجراً، ولكن فيها تقرأ آية الكرسي الى هُمْ فيها خالِدُونَ .","hasTranslate":false},{"id":"mf_ar_174","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل السّادِسُ :","title":"اليوم الخامس والعشرون","blocks":[{"type":"Text","content":"يوم شريف وهو اليوم الذي نزل فيه سُورة هَل اَتى في شأن أهل البيت (عليهم السلام) لانّهم كانوا قد صامُوا ثلاثة أيّام واعطوا فطورهم مِسكيناً ويتيماً وأسيراً وأفطروا على الماء وينبغي على شيعة أهل البيت (عليهم السلام) في هذه الايّام ولا سيّما في اللّيلة الخامسة والعشرين أن يتأسّوا بمولاهم في التّصدّق على المساكين والايتام وأن يجتهدوا في اطعامهم وأن يصوموا هذا اليوم وعند بعض العلماء انّ هذا اليوم هو يوم المباهلة فمن المناسب أن يقرأ فيه أيضاً زيارة الجامعة ودعاء المباهلة ."}],"preview":"يوم شريف وهو اليوم الذي نزل فيه سُورة هَل اَتى في شأن أهل البيت (عليهم السلام) لانّهم كانوا قد صامُوا ثلاثة أيّام واعطوا فطورهم مِسكيناً ويتيماً وأسيراً وأفطروا على الماء وينبغي عل","hasTranslate":false},{"id":"mf_ar_175","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل السّادِسُ :","title":"اليوم الاخير مِن ذي الحجّة","blocks":[{"type":"Text","content":"يوم الختام للسّنة العربيّة . ذكر السّيد في الاقبال طِبقاً لبعض الرّوايات انّه يُصلّي فيه ركعتان بفاتحة الكتاب وعشر مرّات سورة قُلْ هُوَ اللهُ اَحَدٌ وعشر مرّات آية الكرسي ثمّ يدعى بعد الصّلاة بهذا الدّعاء :"},{"type":"Text","content":"اَللّـهُمَّ ما اَللّـهُمَّ ما عَمِلْتُ فى هذِهِ السَّنَةِ مِنْ عَمَل نَهَيْتَنى عَنْهُ وَلَمْ تَرْضَهُ وَنَسيتَهُ وَلَمْ تَنْسَهُ وَدَعَوْتَنى اِلَى التَّوْبَةِ بَعْدَ اجْتِرائى عَلَيْكَ اَللّـهُمَّ فَاِنّى اَسْتَغْفِرُكَ مِنْهُ فَاغْفِر لى وَما عَمِلْتُ مِنْ عَمَل يُقَرِّبُنى اِلَيْكَ فَاقْبَلْهُ مِنّى وَلا تَقْطَعْ رَجآئى مِنْكَ يا كَريمُ ."},{"type":"Text","content":"فاذا قلت هذا قال الشّيطان يا ويلي ما تعبت فيه هذه السّنة هدمه أجمع بهذه الكلمات وشهدت له السّنة الماضية انّه قد ختمها بخيْر ."}],"preview":"يوم الختام للسّنة العربيّة . ذكر السّيد في الاقبال طِبقاً لبعض الرّوايات انّه يُصلّي فيه ركعتان بفاتحة الكتاب وعشر مرّات سورة قُلْ هُوَ اللهُ اَحَدٌ وعشر مرّات آية الكرسي ثمّ يدعى","hasTranslate":false},{"id":"mf_ar_176","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل السّابِعُ :","title":"في أعمالِ شهرِ مُحَرَّمْ","blocks":[{"type":"AboutText","content":"اعلم انّ هذا الشّهر هو شهر حُزن أهل البيت (عليهم السلام) وشيعتهم وعن الرّضا (عليه السلام) قال : كان أبي صلوات الله عليه اذ دخل شهر المحرّم لم ير ضاحكاً وكانت كابته تغلب عليه حتّى يمضي منه عشرة أيّام فاذا كان اليوم العاشِر كان ذلك اليوم يوم مصيبته وحُزنه وبكائه ويقول هذا اليوم الذي قتل فيه الحسين (عليه السلام) ."},{"type":"Text","content":"اللّيلة الاولى"},{"type":"Text","content":"روى لها السّيد في الاقبال عدّة صلوات :"},{"type":"Text","content":"الاولى : مائة ركعة يقرأ في كلّ ركعة الحمد والتّوحيد ."},{"type":"Text","content":"الثّانية : ركعتان في الاولى منها الحمد وسورة الانعام وفي الثّانية الحمد وسورة يس ."},{"type":"Text","content":"الثّالث : ركعتان في كلّ منهما الحمد واحدى عشرة مرّة قُلْ هُوَ اللهُ اَحَدٌ ."},{"type":"Text","content":"في الحديث عن النّبي (صلى الله عليه وآله وسلم) قال : من أدّى هذه الصّلاة في هذه اللّيلة وصام صبيحتها وهو أوّل يوم من السّنة فهو كمن يدوم على الخير سنة ولا يزال محفوظاً من السّنة الى قابل فاِن ماتَ قبل ذلك صار الى الجنّة وأورد السيّد أيضاً دعاء مبسُوطاً يدعى به عند رؤية الهلال في هذه اللّيلة ."}],"preview":"اعلم انّ هذا الشّهر هو شهر حُزن أهل البيت (عليهم السلام) وشيعتهم وعن الرّضا (عليه السلام) قال : كان أبي صلوات الله عليه اذ دخل شهر المحرّم لم ير ضاحكاً وكانت كابته تغلب عليه حتّى ي","hasTranslate":false},{"id":"mf_ar_177","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل السّابِعُ :","title":"اليوم الاوّل","blocks":[{"type":"AboutText","content":"اعلم انّ غرّة محرّم هو اوّل السّنة وفيه عملان :"},{"type":"Text","content":"الاوّل : الصّيام ، وفي رواية ريّان بن شبيب عن الرّضا صلوات الله وسلامه عليه انّه قال : من صام هذا اليوم ودعا الله استجاب الله دعاءه كما استجاب لزكريّا ."},{"type":"Text","content":"الثّاني : عن الرّضا (عليه السلام) انّه كان النّبي (صلى الله عليه وآله وسلم) يصلّي اوّل يوم من محرّم ركعتين فاذا فرغ رفع يديه ودعا بهذا الدّعاء ثلاث مرّات :"},{"type":"Text","content":"اَللّـهُمَّ اَنْتَ الاِْلهُ الْقَديمُ وَهذِهِ سَنَةُ جَديدَةُ فَاَسْئَلُكَ فيهَا الْعِصْمَةَ مِنَ الشَّيْطانِ وَالْقُوَّةَ عَلى هذِهِ النَّفْسِ الاَْمّارَةِ بِالسّوءِ وَالاِْشْتِغالَ بِما يُقَرِّبُنى اِلَيْكَ يا كَريمُ يا ذَا الْجَلالِ وَالاِْكْرامِ يا عِمادَ مَنْ لا عِمادَ لَهُ يا ذَخيرَةَ مَنْ لا ذَخيرَةَ لَهُ يا حِرْزَ مَنْ لا حِرْزَ لَهُ يا غِياثَ مَنْ لا غِياثَ لَهُ يا سَنَدَ مَنْ لا سَنَدَ لَهُ يا كَنْزَ مَنْ لا كَنْزَ لَهُ يا حَسَنَ الْبَلاءِ يا عَظيمِ الرَّجاءِ يا عِزَّ الضُّعَفآءِ يا مُنْقِذَ الْغَرْقى يا مُنْجِىَ الْهَلْكى يا مُنْعِمُ يا مُجْمِلُ يا مُفْضِلُ يا مُحْسِنُ اَنْتَ الَّذى سَجَدَ لَكَ سَوادُ اللَّيْلِ وَنُورُ النَّهارِ وَضَوْءُ الْقَمَرِ وَشُعاعُ الشَّمْسِ وَدَوِىُّ الْمآءِ وَحَفيفُ الشَّجَرِ يا اَللهُ لا شَريكَ لَكَ اَللّـهُمَّ اجْعَلْنا خَيْراً مِمّا يَظُنُّونَ وَاغْفِرْ لَنا ما لا يَعْمَلُونَ وَلا تُؤاخِذْنا بِما يَقُولُونَ حِسْبِىَ اللهُ لا اِلـهَ اِلاّ هُوَ عَلَيْهِ تَوَكَّلْتُ وَهُوَ رَبُّ الْعَرْشِ الْعَظيمِ آمَنّا بِهِ كلٌّ مِنْ عِنْدِ رَبِّنا وَما يَذَّكَّرُ اِلاّ اُولُوا الاَْلْبابِ رَبَّنا لا تُزِغْ قُلُوبَنا بَعْدَ اِذْ هَدَيْتَنا وَهَبْ لَنا مِنْ لَدُنْكَ رَحْمَةً اِنَّكَ اَنْتَ الْوَهّابُ ."},{"type":"AboutText","content":"قال الشّيخ الطّوسي : يستحبّ صيام الايّام المتسعة من اوّل محرّم وفي اليوم العاشر يمسك عن الطّعام والشّراب الى بعد العصر ثمّ يفطر من تربة الحسين (عليه السلام) وروى السّيد فضلاً لصوم شهر المحرّم كلّه وانّه يعصم سائمه من كلّ سيّئة ."}],"preview":"اعلم انّ غرّة محرّم هو اوّل السّنة وفيه عملان :","hasTranslate":false},{"id":"mf_ar_178","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل السّابِعُ :","title":"اليوم الثّالث","blocks":[{"type":"Text","content":"فيه كان خلاص يُوسف (عليه السلام) من السِّجن فمن صامه يسّر الله له الصّعب وفرّج عنه الكرب وفي الحديث النبوي (صلى الله عليه وآله وسلم)انّه استجيب دعوته ."}],"preview":"فيه كان خلاص يُوسف (عليه السلام) من السِّجن فمن صامه يسّر الله له الصّعب وفرّج عنه الكرب وفي الحديث النبوي (صلى الله عليه وآله وسلم)انّه استجيب دعوته .","hasTranslate":false},{"id":"mf_ar_179","bookId":"الباب_ال_ث_اني","book":"البابُ الْثّاني","section":"الفَصل السّابِعُ :","title":"اليوم التّاسع","blocks":[{"type":"Text","content":"يوم التّاسوعاء . عن الصّادق (عليه السلام) قال : تاسُوعا يوم حُوصر فيه الحسين (عليه السلام) وأصحابه بكربلاء واجتمع عليه خيل أهل الشّام وأناخوا عليه وفرح ابن مرجانة وعمر بن سعد بتوافر الخيل وكثرتها واستضعفوا فيهِ الحسين (عليه السلام) وأصحابه وأيقَنوا انّه لا يأتي الحسين (عليه السلام) ناصر ولا يمدّه أهل العراق ثمّ قال بأبي المستضعف الغريب ."},{"type":"Text","content":"اللّيلة العاشرة"},{"type":"Text","content":"ليلة العاشُوراء ، وقد أورد السّيد في الاقبال لهذه اللّيلة أدعية وصلوات كثيرة بما لها من وافر الفضل منها الصّلاة مائة ركعة كلّ ركعة بالحمد وقُلْ هُوَ اللهُ اَحَدٌ ثلاث مرّات ويقول بعد الفراغ من الجميع سُبْحانَ اللهِ وَالْحَمْدُ للهِ وَلا اِلـهَ اِلاَّ اللهُ وَاللهُ اَكْبَرُ وَلا حَوْلَ وَلا قُوَّةَ اِلاّ بِاللهِ الْعَلىِّ الْعَظيمِ سبعين مرّة وقد ورد الاستغفار ايضاً بعد كلمة (الْعَلىِّ الْعَظيمِ) في رواية أخرى ومنها الصّلاة أربع ركعات في آخر اللّيل يقرأ في كلّ ركعة بعد الحمد كلاً من آية الكرسي والتّوحيد والفلق والنّاس عشر مرّات ويقرأ التّوحيد بعد السّلام مائة مرّة ومنها الصّلاة أربع ركعات يقرأ في كلّ ركعة الحمد والتّوحيد خمسين مرّة وهذه الصّلاة تطابق صلاة أمير المؤمنين صلوات الله وسلامه عليه ذات الفضل العظيم ."},{"type":"Text","content":"وقال السّيد بعد ذكر هذه الصّلاة : فاذا سلّمت من الرّابعة فأكثر ذكر الله تعالى والصّلاة على رسوله واللّعن على اعدائهم ما استطعت وروي في فضل احياء هذه اللّيلة انّ من أحياها فكأنّما عبد الله عبادة جميع الملائكة وأجر العامل فيها يعدل سبعين سنة ومن وفّق في هذه اللّيلة لزيارة الحُسين (عليه السلام) بكربلاء والمبيت عنده حتى يصبح حشره الله يوم القيامة ملطّخاً بدم الحسين (عليه السلام) في جملة الشّهداء معه (عليه السلام) ."},{"type":"Text","content":"في الزّيارات وَتحتوي عَلى مُقدّمة وَفُصول وَخاتمة"},{"type":"Text","content":"المقدّمة في آداب السَّفر : اذا أردت الخروج الى السّفر فينبغي لك أن تصوم الاربعاء والخميس والجمعة وأن تختار من أيّام الاسبوع يوم السّبت أو يوم الثّلاثاء أو يوم الخميس واجتنب السّفر في يوم الاثنين والاربعاء وقبل الظّهر من يوم الجُمعة واجتنب السّفر في اليوم الثّالث من الشّهر والخامس منه والثّالث عشر والسّادس عشر والحادي والعشرين والرّابع والعشرين، والخامس والعِشرين وقد نظمت هذه الايّام في بيتين بالفارسيّة :"},{"type":"AboutText","content":"خلاصة البيتين بالفارسية: الأيام المنحوسة المذكورة هنا هي اليوم الثالث والخامس والثالث عشر والسادس عشر والحادي والعشرون والرابع والعشرون والخامس والعشرون من الشهر."},{"type":"Text","content":"ولا تسافر في محاق الشّهر ولا اذا كان القمر في برج العقرب وإن دعت ضرُورة الى الخروج في هذه الاحوال والاوقات فليدع المُسافر بدعوات السّفر ويتصدّق ويخرج متى شاء، وروي انّ رجلاً من أصحاب الباقر (عليه السلام) أراد السّفر فأتاه ليودّعه فقال له : انّ أبي عليّ بن الحسين (عليهما السلام) كان اذا أراد الخروج الى بعض أمواله اشترى السّلامة من الله عزوجل بما تيسّر أي بالصّدقة بما تيسّر له ويكون ذلك اذا وضع رجله في الرّكاب، واذا سلّمه الله وعاد مِن سفره حمد الله وشكره أيضاً بما تيسّر له، فودّعه الرّجل ومضى ولم يعمل بما وصّاه الباقر (عليه السلام) فهلك في الطّريق، فأتى الخبر الباقر (عليه السلام) فقال : قد نُصح الرّجل لو كان قَبِلَ، وينبغي أن تغتسل قبل التوجّه ثمّ تجمع أهلك بين يديك وتصلّي ركعتين وتسأل الله الخيرة وتقرأ آية الكرسي وتحمد الله وتثني عليه وتصلّي على النّبي وآله صلوات الله عليهم وتقول :"},{"type":"Text","content":"اَللّـهُمَّ اِنّي اَسْتَوْدِعُكَ الْيَوْمَ نَفْسِيوَاَهْلي وَمالي وَوُلْدي وَمَنْ كانَ مِنّي بِسَبيل، الشّاهِدَ مِنْهُمْ وَالْغائِبَ، اَللّـهُمَّ احْفَظْنا بِحِفْظِ الاِْيْمانِ وَاحْفَظْ عَلَيْنا، اَللّـهُمَّ اجْعَلْنا في رَحْمَتِكَ وَلا تَسْلُبْنا فَضْلَكَ اِنّا اِلَيْكَ راغِبُونَ، اَللّـهُمَّ اِنّا نَعُوذُ بِكَ مِنْ وَعْثاءِ السَّفَرِ، وَكابَةِ الْمُنْقَلَبِ، وَسُوءِ الْمَنْظَرِ فِي الاَْهْلِ وَالْمالِ وَالْوَلَدِ فِي الدُّنْيا وَالاْخِرَةِ، اَللّـهُمَّ اِنّي اَتَوَجَّهُ اِلَيْكَ هذَا التَّوَجُّهَ طَلَباً لِمَرْضاتِكَ وَتَقَرُّباً اِلَيْكَ، اَللّـهُمَّ فَبَلِّغْني ما اُؤَمِّلُهُ وَاَرْجُوهُ فيكَ وَفي اَوْلِيائِكَ يا اَرْحَمَ الرّاحِمينَ ."},{"type":"Text","content":"ثمّ ودّع أهلك وانهض وَقف بالباب فسبّح الله بتسبيح الزّهراء (عليها السلام) واقرأ سورة الحمد أمامك وعن يمينك وعن شمالك وكذلك آية الكرسي وقُل :"},{"type":"Text","content":"اَللّـهُمَّ اِلَيْكَ وَجَّهْتُ وَجْهي، وَعَلَيْكَ خَلَّفْتُ اَهْلي وَمالي وَما خَوَّلْتَني، وَقَدْ وَثِقْتُ بِكَ فَلا تُخَيِّبْني يا مَنْ لا يُخَيِّبُ مَنْ اَرادَهُ، وَلا يُضَيِّعُ مَنْ حَفِظَهُ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِهِ وَاحْفَظْني فيـما غِبْتُ عَنْهُ، وَلا تَكِلْني اِلى نَفْسي يا اَرْحَمَ الرّاحِمينَ ... الدّعاء ."},{"type":"Text","content":"ثمّ اقرأ سورة قُلْ هُوَ اللهُ احدى عشرة مرّة وسورة اِنّا اَنزَلْناهُ وآية الكرسي وسورة قُلْ اَعوذُ بِرَبِّ النّاسِ وقُلْ اَعوذُ بِرَبِّ الْفَلَقِ ثمّ أمرر بيدك على جميع جسدك وتصدّق بما تيسّر وقُل :"},{"type":"Text","content":"اَللّـهُمَّ اِنّي اشْتَرَيْتُ بِهذِهِ الصَّدَقَةِ سَلامَتي وَسَلامَةَ سَفَرِي وَما مَعي، اَللّـهُمَّ احْفَظْني وَاحْفَظْ ما مَعِيَ وَسَلِّمْني وَسَلِّمْ ما مَعِيَ، وَبَلِّغْني وَبَلِّغْ ما مَعِيَ بِبَلاغِكَ الْحَسَنِ الْجَميلِ ."},{"type":"Text","content":"وتأخذ معك عصى مِن شجر اللّوز المرّ فقد رُوي عن النّبي (صلى الله عليه وآله وسلم) انّه قال : من خرج الى السّفر ومعه عصى لوز مرّ وتلا قوله تعالى (وَلَمّا تَوَجَّهَ تِلْقاءَ مَدْيَنَ اِلى وَاللهُ عَلى ما نَقُولُ وَكيلٌ) وهو في سورة القصص أمّنه الله تعالى مِن كلّ سبع ضار، ومن كلّ لُصّ عاد، ومن كلّ ذات حمة حتّى يرجع الى منزله وكان (معه سَبع وسبعون من المعقّبات الملائكة) يستغفرون له حتّى يرجع ويضعها، ويستحبّ أن يخرج معتماً متحنّكاً لكي لا يصيبه السّرق ولا الغرق ولا الحرق، وتأخذ معك شيئاً من تربة الحسين (عليه السلام) وقُل اذا أخذتها :"},{"type":"Text","content":"اَللّـهُمَّ هذِهِ طينَةُ قَبْرِ الْحُسَيْنِ عليه السلام وَلِيِّكَ وَابْنِ وَلِيِّكَ اتَّخَذْتُها حِرْزاً لِما اَخافُ وَما لا اَخافُ وخذ معك خاتم العقيق والفيروزج، والاحسن أن يكون العقيق أصفر منقوشاً على أحد وجهيه ما شاءَ اللهُ لا قُوَّةَ إلاّ بِاللهِ اَسْتَغْفِرُ اللهَ وعلى الوجه الثّاني محمّد وعليّ ."},{"type":"Text","content":"روى السّيد ابن طاووس في أمان الاخطار عن أبي مُحمّد قاسم بن علاء عن الصّافي خادم الامام عليّ النّقي (عليه السلام)قال : استأذنته في الزّيارة الى طوس فقال لي : يكون معك خاتم فصّه عقيق اصفَر عليه ما شاءَ اللهُ لا قُوَّةَ إلاّ بِاللهِ اَسْتَغْفِرُ اللهَ، وعلى الجانب الاخر محمّد وعليّ، فانّه أمانٌ من القطع، وأتمّ للسّلامة، وأصون لدينك ، قال : فخرجت وأخذت خاتماً على الصّفة التي أمرني بها، ثمّ رجعت اليه لوداعه فودّعته وانصرفت، فلمّا بعدت أمر بردّي فرجعت اليه فقال : يا صافي ، قلت : لبّيْكَ يا سَيِّدي قال : ليكن معك خاتم آخر من فيروزج فانّه يلقاك في طريقك أسد بين طوس ونيشابور فيمنع القافلة من المسير، فتقدّم اليه وأره الخاتم وقل له: مَولاي يقول لك تنحّ عن الطّريق، ثمّ قال : ليكن نقشه (اَللهُ المَلكُ) وعلى الجانب الاخر (اَلْمُلْكُ للهِ الْواحِدِ الْقَهّارِ) فانّه خاتم امير المؤمنين (عليه السلام) كان عليه اَللهُ المَلكُ فلمّا ولّى الخلافة نقش على خاتمه اَلْمُلْكُ للهِ الْواحِدِ الْقَهّارِ، وكان فصّه فيرُوزج، وهو أمان من السّباع خاصّة وظفر في الحرب ."},{"type":"AboutText","content":"قال الخادم : فخرجت في سفري ذلك فلقيني والله السّبع ففعلت ما أمرت به فلمّا رجعت حدّثته ، فقال لي : بقيت عليك خصلة لم تحدّثني بها إن شئت حدّثتك بها، فقلت: ياسيّدي اذكر علىّ لعلّي نسيتها ، فقال : نعم ، بتّ ليلة بطوس عند القبر فصار الى القبر قوم من الجن لزيارته فنظروا الى الفص في يدك وقرأوا نقشه فأخذوه عن يدك وصاروا به الى عليل لهم وغسلوا الخاتم بالماء وسقوه ذلك الماء فبرأ، وردّوا الخاتم اليك وكان في يدك اليمنى فصيّروه في يدك اليسرى، فكثر تعجّبك من ذلك ولم تعرف السّبب فيه، ووجدت عند رأسك حجراً ياقوتاً فأخذته وهو معك، فاحمله الى السّوق فانّك ستبيعه بثمانين ديناراً وهو هديّة القوم اليك، فحملته الى السّوق فبعته بثمانين ديناراً كما قال سيّدي (عليه السلام)، وعن الصّادق (عليه السلام) قال : من قرأ آية الكرسي في السّفر في كلّ ليلة سلم وسلم ما معهُ ويقول : اَللّـهُمَّ اجْعَلْ مَسيري عِبَراً وَصَمْتي تَفَكُّراً وَكَلامي ذِكْراً وعن الامام زين العابدين (عليه السلام) قال : لا اُبالي اذا قلت هذه الكلمات ان لو اجتمع عليّ الجنّ والانس :"},{"type":"Text","content":"بِسْمِ اللهِ وَبِاللهِ وَمِنَ اللهِ وَاِلَى اللهِ وَفي سَبِيلِ اللهِ، اَللّـهُمَّ اِلَيْكَ اَسْلَمْتُ نَفْسِيوَاِلَيْكَ وَجَّهْتُ وَجْهي، وَاِلَيْكَ فَوَّضْتُ اَمْرِى، فَاحْفَظْني بِحِفْظِ الاِْيْمانِ مِنْ بَيْنِ يَدَىَّ وَمِنْ خَلْفي، وَعَنْ يَميني وَعَنْ شِمالِي، وَمِنْ فَوْقي وَمِنْ تَحْتي وَادْفَعْ عَنّي بِحَوْلِكَ وَقُوَّتِكَ لا حَوْلَ وَلا قُوَّةَ إلاّ بِاللهَ الْعَلِيِّ الْعَظيمِ ."}],"preview":"يوم التّاسوعاء . عن الصّادق (عليه السلام) قال : تاسُوعا يوم حُوصر فيه الحسين (عليه السلام) وأصحابه بكربلاء واجتمع عليه خيل أهل الشّام وأناخوا عليه وفرح ابن مرجانة وعمر بن سعد بتواف","hasTranslate":false},{"id":"mf_ar_180","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الفَصل السّابِعُ :","title":"أقول : دَعواتُ السّفر وآدابُه كثيرة ونحن هنا نقتصر بذكر عدّة آداب :","blocks":[{"type":"Text","content":"الاوّل : ينبغي للمرء أن لا يترك التسمية عند الرّكوب ."},{"type":"Text","content":"الثّاني : أن يحفظ نفقته في موضِع مصُون ، فقد روي انّ من فقه المُسافر حفظ نفقته ."},{"type":"Text","content":"الثّالث : أن يُساعد اصحابه في السّفر ولا يحجم عن السّعي في حوائجهم كي ينفس الله عنه ثلاثاً وسبعين كربة، ويجيره في الدّنيا من الهمّ والغم، وينفس كربه العظيم يوم القيامة ، وروي انّ الامام زين العابدين (عليه السلام) كان لا يسافر الّا مع رفقة لا يَعرفُونه ليخدمهم في الطّريق فانّهم لو عرفوه منعُوه عن ذلك، ومن الاخلاق الكريمة للنّبي (صلى الله عليه وآله وسلم)انّه كان مع صحابته في بعض الاسفار فارادوا ذبح شاة تاتون بها ، فقال أحدهم : عليّ ذبحها ، وقال آخر : عليّ سلخ جلدها ، وقال الاخر : عليّ طبخها ، فقال (صلى الله عليه وآله وسلم) : عليّ الاحتطاب ، فقالوا : يا رسول الله نحن نعمل ذلك فلا تتكلّفه أنت، فأجاب أنا أعلم انّكم تعملونه ولكن لا يسرّني أن أمتاز عنكم فانّ الله يكره أن يرى عبده قد فضّل نفسه على أصحابه ، واعلم انّ أثقل الخلق على الاصحاب في السّفر من تكاسل في الاعمال وهو في سلامة من اعضائه وجوارحه فهو لا يؤدّي شيئاً من وظائفه ، مرتقباً رفقته يقضُون له حوائجه ."},{"type":"Text","content":"الرّابع : أن يصاحِب الرجل من يماثله في الانفاق ."},{"type":"Text","content":"الخامس : أن لا يشرب من ماء أي منزل يرده الّا بعد أن يمزجه بماء المنزل الذي سبقه، ومن اللاّزم أن يتزوّد المُسافر من تربة بلده وطينته الّتي ربّي عليها، وكلّما ورد منزلاً طرح في الاناء الّذي يشرب منه الماء شيئاً من الطّين الّذي تزوّده من بلده ويشرب الماء والطّين في الانية بالتّحريك ويؤخّر شربه حتّى يصفو ."},{"type":"Text","content":"السّادس : أن يحسن أخلاقه ويتزيّن بالحلم، وسيأتي في آداب زيارة الحسين (عليه السلام) ما يناسب المقام ."},{"type":"Text","content":"السّابع : أن يتزوّد لسفره، ومن شرف المرء أن يطيّب زاده لا سيّما في طريق مكّة ، نعم لا يستحسن في سفر زيارة الحسين (عليه السلام) أن يتّخذ زاداً لذيذاً كاللّحم المشوي والحلويّات وغير ذلك كما سيأتي في آداب زيارته (عليه السلام)، وقال ابن الاعسم :"},{"type":"Text","content":"مِنْ شَرَفِ الاِْنْسانِ فِي الاَْسْفارِ تَطييبُهُ الزّادَ مَعَ الاَْكْثارِ"},{"type":"Text","content":"وَلْيُحْسِنِ الاِْنْسانُ فِي حالِ السَّفَرْ اَخْلاقَهُ زِيادَةً عَلَى الْحَضَرْ"},{"type":"Text","content":"وَلْيَدْعُ عِنْدَ الْوَضْعِ لِلْخِوانِ مَنْ كانَ حاضِراً مِنَ الاِْخْوانِ"},{"type":"Text","content":"وَلْيُكْثِرِ الْمَزْحَ مَعَ الصَّحْبِ اِذا لَمْ يُسْخِطِ اللهَ وَلَمْ يَجْلِبْ اَذى"},{"type":"Text","content":"مَنْ جاءَ بَلْدَةً فَذا ضَيْفٌ عَلى اِخْوانِهِ فيها اِلى اَنْ يَرْحَلا"},{"type":"Text","content":"يُبَرُّ لَيْلَتَيْنِ ثُمَّ لْيَأكُلِ مِنْ اَكْلِ اَهْلِ الْبَيْتِ في الْمُسْتَقْبِلِ"},{"type":"Text","content":"الثّامن : من أهمّ الاشياء في السّفر المحافظة على الفرائض بشرائطها وحدودها واداؤها في بدء أوقاتها، فما أكثر ما يشاهد الحجّاج والزّوار في الاسفار يضيعون الفرائض بتأخيرها عن أوقاتها أو بأدائها راكبين أو في المحامل أو متيمّمين بلا وضوء أو مع نجاسة البدن أو الثّياب وغيرها من اشباهها، فهذه كلّها تنشأ عن استخفافهم بشأن الصّلاة وعدم مُبالاتهم، بها هذا وقد روي في الحديث عن الصّادق (عليه السلام)قال : صلاة الفريضة أفضل من عشرين حجّة، وحجّة واحدة أفضل من دار ملئت ذهباً يتصدّق به حتّى تفرغ، ولا تدع بعد الصّلاة المقصُورة أن تقول ثلاثين مرّة سُبْحانَ اللهِ وَالْحَمْدُ للهِ وَلا اِلـهَ اِلاَّ اللهُ وَاللهُ اَكْبَرُ فهو من السُنن المؤكّدة ."},{"type":"Text","content":"في آدابِ الزِّيارَة"}],"preview":"الاوّل : ينبغي للمرء أن لا يترك التسمية عند الرّكوب .","hasTranslate":false},{"id":"mf_ar_181","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الفَصلُ الاوَّلْ :","title":"وهي عديدة نقتصر منها على امور :","blocks":[{"type":"Text","content":"الاوّل : الغُسل قبل الخروج لسفر الزّيارة ."},{"type":"Text","content":"الثّاني : أن يتجنّب في الطّريق التكلّم باللّغو والخصام والجدال ."},{"type":"Text","content":"الثّالث : أن يغتسل لزيارة الائمة (عليهم السلام) وأن يدعو بالمأثورة من دعواته، وستذكر في أوّل زيارة الوارث ."},{"type":"Text","content":"الرّابع : الطّهارة من الحدث الاكبر والاصغر ."},{"type":"Text","content":"الخامس : أن يلبس ثياباً طاهرة نظيفة جديدة ويحسن أن تكون بيضاء ."},{"type":"Text","content":"السّادس : أن يقصر خطاه اذا خرج الى الرّوضة المقدّسة، وان يسير وعليه السّكينة والوقار، وأن يكون خاضعاً خاشعاً، وأن يطأطِيء رأسه فلا يلتفت الى الاعلى ولا الى جوانبه ."}],"preview":"الاوّل : الغُسل قبل الخروج لسفر الزّيارة .","hasTranslate":false},{"id":"mf_ar_182","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الفَصلُ الاوَّلْ :","title":"السّابع : أن يتطيّب بشيء من الطّيب فيما عدا زيارة الحسين (عليه السلام)","blocks":[{"type":"Text","content":"الثّامن : أن يشتغل لسانه وهو يمضي الى الحرم المطهّر بالتكبير والتّسبيح والتّهليل والتّمجيد، ويعطّر فاه بالصّلاة على محمّد وآله (عليهم السلام) ."},{"type":"Text","content":"التّاسع : أن يقف على باب الحرم الشّريف ويستأذن ويجتهد لتحصيل الرّقّة والخضوع والانكسار والتفكير في عظمة صاحب ذلك المرقد المنوّر وجلاله، وانّه يرى مقامه ويسمع كلامه ويردّ سلامه كما يشهد على ذلك كلّه عندما يقرأ الاستئذان، والتّدبّر في لطفهم وحُبّهم لشيعتهم وزائريهم، والتّأمّل في فساد حال نفسه وفي جفائه عليهم برفضه ما لا يحصى من تعاليمهم، وفيما صدر عنه نفسه من الاذى لهم أو لخاصّتهم وأحبابهم وهو في المال اذىً راجع اليهم (عليهم السلام) فلو التفت الى نفسه التفات تفكير وتدقيق لتوقّفت قدماه عن المسير وخشع قلبه ودمعت عينه، وهذا هو لُبّ آداب الزّيارة كلّها، وينبغي لنا هُنا أن نورد أبيات السّخاوي والحديث الّذي رواه العلاّمة المجلسي (رحمه الله) في البحار نقلاً عن كتاب عيون المعجزات، امّا أبيات السّخاوي وهي ما ينبغي أن يتمثّل به في تلك الحالة فهي :"},{"type":"AboutText","content":"قالُوا غَدًا نَأْتي دِيارَ الْحِمى وَيَنْزِلُ الرَّكْبُ بِمَغْناهُمُ"},{"type":"Text","content":"فَكُلُّ مَنْ كانَ مُطيعاً لَهُمْ اَصْبَحَ مَسْرُوراً بِلُقْياهُمُ"},{"type":"Text","content":"قُلْتُ فَلي ذَنْبٌ فَما حيلَتي بَاَيّ وَجْه اَتَلَقّاهُمُ"},{"type":"AboutText","content":"قالُوا اَلَيْسَ الْعَفْوُ مِنْ شَاْنِهِمْ لا سِيَّما عَمَّنْ تَرَجّاهُمُ"},{"type":"Text","content":"فَجِئْتُهُم اَسْعى اِلى بابِهِمْ اَرْجُوهُمُ طَوْراً وَاَخْشاهُمُ"},{"type":"Text","content":"وأمّا الرّواية الشريفة فهي انّه استأذن ابراهيم الجمّال وكان من الشّيعة على عليّ بن يقطين وهو وزير هارون الرّشيد، فحجبه لانّه جمّال، فحجّ عليّ بن يقطين في تلك السّنة فاستأذن بالمدينة على موسى بن جعفر (عليه السلام) فحجبه فرآه ثاني يومه خارج الدّار ، فقال عليّ بن يقطين : يا سيّدي ما ذنبي ؟ فقال : حجبتك لانّك حجبت أخاك ابراهيم الجمّال وقد أبى الله أن يشكر سعيك أو يغفر لك ابراهيم الجمّال ، قال عليّ : فقلت يا سيّدي ومولاي من لي بابراهيم الجمّال في هذا الوقت وأنا بالمدينة وهو بالكوفة ؟ فقال : اذا كان الليل فامض الى البقيع وحدك من غير أن يعلم بك أحد من أصحابك وغلمانك، وتجد نجيباً هناك مسرّجاً فاركبه وامض الى الكوفة ، فوافى البقيع وركب النّجيب ولم يلبث أن أناخه على باب ابراهيم الجمّال بالكوفة (في مدّة قصيرة) فقرع الباب وقال : أنا عليّ بن يقطين ، فقال ابراهيم الجمّال من داخل الدّار : وما يعمل عليّ بن يقطين الوزير ببابي ، فقال عليّ بن يقطين : ما هذا انّ أمري عظيم وآلى عليه أن يأذن له، فلمّا دخل قال : يا ابراهيم انّ المولى (عليه السلام) أبى أن يقبلني أو تغفر لي ، فقال : يغفر الله لك، فآلى عليّ بن يقطين على ابراهيم الجمّال أن يطأ خدّه، فامتنع ابراهيم من ذلك، فآلى عليه ثانياً ففعل فلم يزل ابراهيم يطأ خدّه وعليّ بن يقطين يقول : اَللّـهُمَّ اشْهَدْ، ثمّ انصرف وركب النّجيب ورجع الى المدينة من ليلته وأناخه بباب المولى موسى بن جعفر (عليه السلام) فأذن له ودخل عليه فقبله ."},{"type":"Text","content":"من هذا الحديث يعرف مبلغ حقوق الاخوان ."},{"type":"Text","content":"العاشر : تقبيل العتبة العالية المباركة ، قال الشّيخ الشّهيد (رحمه الله): ولو سجد الزّائر ونوى بالسّجدة الشكر لله تعالى على بلوغه تلك البقعة كان أولى ."},{"type":"Text","content":"الحادي عشر : أن يقدّم للدّخول رجله اليمنى ويقدّم للخروج رجله اليُسرى كما يصنع عند دخُول المساجد والخروج منها ."},{"type":"Text","content":"الثّاني عشر : أن يقف على الضّريح بحيث يمكنه الالتصاق به، وتوهّم انّ البعد أدب وهم، فقد نص على الاتّكاء على الضّريح وتقبيله ."},{"type":"Text","content":"الثّالث عشر : أن يقف للزّيارة مستقبلاً القبر مُستدبِراً القبلة وهذا الادب ممّا يخصّ زيارة المعصوم على الظّاهر، فاذا فرغ من الزّيارة فليضع خدّه الايمن على الضّريح ويدعو الله بتضرّع ثمّ ليضع الخدّ الايسر ويدعو الله بحقّ صاحب القبر أن يجعله من أهل شفاعته ويبالغ في الدّعاء والالحاح ثمّ يمضي الى جانب الرّأس فيقف مُستقبل القبلة فيدعو الله تعالى ."},{"type":"Text","content":"الرّابع عشر : أن يزُور وهُو قائم على قَدَميه الّا اذا كان له عُذر منْ ضعف أو وجع في الظّهر أو في الرّجل أو غير ذلك من الاعذار ."},{"type":"Text","content":"الخامس عشر : أن يكبّر اذا شاهد القبر المطهّر قبل الشّروع في الزّيارة، وفي رواية انّ من كبّر امام الامام (عليه السلام) وقال : لا اِلـهَ اِلاَّ اللهُ وَحْدَهُ لا شَريكَ لَهُ كتب له رضوان الله الاكبر ."},{"type":"Text","content":"السّادس عشر : أن يزُور بالزّيارات المأثورة المرويّة عن سادات الانام (عليهم السلام) ويترك الزّيارات المخترعة التي لفقها بعض الاغبياء من عوام النّاس الى بعض الزّيارات فأشغل بها الجهّال ."},{"type":"Text","content":"روى الكليني (رحمه الله) عن عبد الرّحيم القصير ، قال : دخلت على الصّادق (عليه السلام) فقلت : جعلت فداك قد اخترعت دعاءاً من نفسي ، فقال (عليه السلام) : دعني عن اختراعك اذا عرضتك حاجة فلذ برسول الله (صلى الله عليه وآله وسلم) وصلّ ركعتين واهدهما اليه الخ ."},{"type":"Text","content":"السّابع عشر : أن يصلّي صلاة الزّيارة وأقلّها ركعتان ، قال الشّيخ الشّهيد : فان كان الزّيارة للنّبي (صلى الله عليه وآله وسلم)فليصلّ الصّلاة في الرّوضة، وإن كانت لاحد الائمة فعند الرّأس، ولو صلاها بمسجد المكان أي مسجد الحرم جاز، وقال العلامة المجلسي (رحمه الله) : انّ صلاة الزّيارة وغيرها فيما أرى يفضل أن تؤتى خلف القبر أو عند الرّأس الشّريف، وقال أيضاً العلامة بحر العلوم في الدرّة :"},{"type":"Text","content":"وَمِنْ حَديثِ كَرْبَلا وَالْكَعْبَةْ لِكَرْبَلا بانَ عُلُوُّ الرُّتْبَةْ"},{"type":"Text","content":"وَغَيْرُها مِنْ سائِرِ الْمَشاهِدِ اَمْثالُها بِالنَّقْلِ ذِي الشّواهِدِ"},{"type":"Text","content":"وَراعِ فيهِنَّ اقْتِرابَ الرَّمْسِ وَآثِرِ الصَّلاةَ عِنْدَ الرَّأسِ"},{"type":"Text","content":"وَصَلِّ خَلْفَ الْقَبْرِ فَالصَّحيحُ كَغَيْرِهِ في نَدْبِها صَريحُ"},{"type":"Text","content":"وَالْفَرْقُ بَيْنَ هذِهِ الْقُبُورِ وَغَيْرِها كَالنُّورِ فَوْقَ الطُّورِ"},{"type":"Text","content":"فَالسَّعْيُ لِلصَّلاةِ عِنْدَها نُدِبْ وَقُرْبُها بَلِ اللُّصُوقُ قَدْ طُلِبْ"},{"type":"Text","content":"الثّامن عشر : تلاوة سورة يس في الرّكعة الاولى وسورة الرّحمن في الثّانية ان لم تكن صلاة الزّيارة التي يصلّيها مأثورة على صفة خاصّة، وان يدعو بعدها بالمأثور أو بما سنح له في امور دينه ودُنياه، وليعمّم الدّعاء فانّه أقرب الى الاجابة ."},{"type":"Text","content":"التّاسع عشر : قال الشّهيد (رحمه الله) : ومن دخل المشهد والامام يصلّي بدأ بالصّلاة قبل الزّيارة وكذلك لو كان قد حضر وقتها والّا فالبدء بالزّيارة أولى لانّها غاية مقصده، ولو أقيمت الصّلاة استحبّ للزّائرين قطع الزّيارة والاقبال على الصّلاة ويكره تركه، وعلى ناظر الحرم أمرهم بذلك ."},{"type":"Text","content":"العشرون : عدّ الشّهيد (رحمه الله) من آداب الزّيارة تلاوة شيء من القرآن عند الضّريح واهداؤه الى المزور والمنتفع بذلك الزّائر وفيه تعظيم للمزور ."},{"type":"Text","content":"الحادي والعشرون : ترك اللّغو وما لا ينبغي من الكلام وترك الاشتغال بالتكلّم في امور الدّنيا فهو مذموم قبيح في كلّ زمان ومكان، وهو مانع للرّزق ومجلبة للقساوة لا سيّما في هذه البقاع الطّاهرة والقُباب السّامية التي أخبر الله تعالى بجلالها وعظمتها في سورة نور (في بُيُوت اَذِنَ اللهُ اَنْ تُرْفَعَ) الاية ."},{"type":"Text","content":"الثّاني والعشرون : أن لا يرفع صوته بما يزور به كما نبّهت عليه في كتاب هديّة الزّائر ."},{"type":"Text","content":"الثّالث والعشرون : أن يودّع الامام (عليه السلام) بالمأثور أو بغيره اذا أراد الخروج من البلد ."},{"type":"Text","content":"الرّابع والعشرون : أن يتوب الى الله ويستغفر من ذنوبه، وأن يجعل أعماله وأقواله بعد الزّيارة خيراً منها قبلها ."},{"type":"Text","content":"الخامس والعشرون : الانفاق على سدنة المشهد الشّريف، وينبغي لهؤلاء أن يكونوا من أهل الخير والصّلاح والدّين والمروّة، وأن يحتملوا ما يصدر من الزّوار فلا يصبوا سخطهم عليهم ولا يحتدموا عليهم، قائمين بحوائج المحتاجين، مُرشدين للغُرباء اذا ضلّوا، وبالاجمال فالخدم ينبغي أن يكونوا خداماً قائمين بما لزم من تنظيف البُقعة الشّريفة وحراستها ومُحافظة الزّائرين وغير ذلك من الخدمات ."},{"type":"Text","content":"السّادس والعشرون : الانفاق على المجاورين لتلك البُقعة من الفقراء والمساكين المتعفّفين والاحسان اليهم لا سيّما السّادة وأهل العلم المنقطعين الذين يعيشُون في غُربة وضيق وهم يرفعون لواء ا لتّعظيم لشعائر الله وقد اجتمعت فيهم جهات عديدة تكفي احداها لفرض اعانتهم ورعايتهم ."},{"type":"Text","content":"السّابع والعشرون : قال الشّهيد: انّ من جُملة الاداب تعجيل الخُروج عند قضاء الوطر من الزّيارة لتعظم الحُرمة وليشتد الشّوق، وقال أيضاً: والنّساء اذا زُرن فليكنّ منفردات عن الرّجال والاولى أن يزرن ليلاً وليكنّ متنكّرات أي يبدلن الثّياب النّفيسة بالدّانية الرّخيصة لكي لا يعرفن وليبرزن متخفّيات متستّرات ولو زرن بين الرّجال جاز وإن كره ."},{"type":"AboutText","content":"أقول : من هذه الكلمة تُعرف مبلغ القُبح والشّناعة في ما دأبت عَليه النّسوة في زماننا من أن يتبرّجن للزّيارة فيبرزن بنفايس الثّياب فيزاحمن الاجانب من الرّجال في الحرم الطّاهر ويضاغطنهم بأبدانهنّ مقتربات من الضّرائح الطّاهرة أو يجلسن في قبلة المُصلّين من الرّجال ليقرأن الزّيارة فيلفتن الخواطر ويصدّن القائمين بالعبادة في تلك البُقعة الشّريفة من المصلّين والمتضرّعين والباكين عن عبادتهم، فيكنّ بذلك من الصّادات عن سبيل الله الى غير ذلك من التّبعات وأمثال هذه الزّيارات ينبغي حقّاً أن تعدّ من منكرات الشّرع لا من العبادات، وتحصى من المُوبقات لا القربات ، وقد روي عن الصّادق (عليه السلام) انّ أمير المؤمنين (عليه السلام) قال لاهل العراق : يا أهل العراق نُبّئتُ انّ نِساءكُم يوافينَ الرّجال في الطّريق أما تستحيون؟ وقال : لعن الله من لا يغار ."},{"type":"Text","content":"وفي الفقيه روى الاصبغ بن نباتة عن امير المؤمنين (عليه السلام) قال : سمعته يقول : يظهر في آخر الزّمان واقتراب السّاعة وهو شرّ الازمنة نسوة كاشِفات عاريات متبرّجات، من الدّين خارجات، داخلات في الفِتن، مائلات الى الشّهوات، مسرعات الى اللّذات، مستحلاّت المحرّمات، في جهنّم خالدات ."},{"type":"Text","content":"الثّامن والعشرون : ينبغي عند ازدحام الزّائرين للسّابقين الى الضّريح أن يخفّفوا زيارتهم وينصرفوا ليفُوز غيرهم بالدّنوّ من الضّريح الطّاهر كما كانوا هم من الفائزين ."}],"preview":"الثّامن : أن يشتغل لسانه وهو يمضي الى الحرم المطهّر بالتكبير والتّسبيح والتّهليل والتّمجيد، ويعطّر فاه بالصّلاة على محمّد وآله (عليهم السلام) .","hasTranslate":false},{"id":"mf_ar_183","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الفَصلُ الاوَّلْ :","title":"أقول لزيارة الحسين صلوات الله عليه آداب خاصّة سنذكرها في مقام ذكر زيارته (عليه السلام)","blocks":[{"type":"Text","content":"في ذِكر الاِسْتِئذانِ لِلدُّخولِ في كُلٍّ منَ الرَّوضاتِ الشَّريفة ."}],"preview":"في ذِكر الاِسْتِئذانِ لِلدُّخولِ في كُلٍّ منَ الرَّوضاتِ الشَّريفة .","hasTranslate":false},{"id":"mf_ar_184","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الفَصلُ الّثاني :","title":"وهُنا نثبت استئذانين :","blocks":[{"type":"Text","content":"الاوّل : اذا أردت دخول مسجد النّبي (صلى الله عليه وآله وسلم) أو أحد المشاهد الشّريفة لاحد الائمة (عليهم السلام) فقل :"},{"type":"Text","content":"اَللّـهُمَّ اِنّي وَقَفْتُ عَلى باب مِنْ اَبْوابِ بُيُوتِ نَبِيِّكَ صَلَواتُكَ عَلَيْهِ وَآلِهِ، وَقَدْ مَنَعْتَ النّاسَ اَنْ يَدْخُلُوا إلاّ بِاِذْنِهِ، فَقُلْتَ يا اَيُّها الَّذينَ آمَنُوا لا تَدْخُلُوا بُيُوتَ النَّبيِّ إلاّ اَنْ يُؤْذَنَ لَكُمْ، اَللّـهُمَّ اِنّي اَعْتَقِدُ حُرْمَةَ صاحِبِ هذَا الْمَشْهَدِ الشَّريفِ في غَيْبَتِهِ كَما اَعْتَقِدُها في حَضْرَتِهِ، وَاَعْلَمُ اَنَّ رَسُولَكَ وَخُلَفاءَكَ عليهم السلام اَحْياءٌ عِنْدَكَ يُرْزَقُونَ، يَرَوْنَ مَقامي، وَيَسْمَعُوَن كَلامي، وَيَرُدُّونَ سَلامي، وَاَنِّكَ حَجَبْتَ عَنْ سَمْعي كَلامَهُمْ، وَفَتَحْتَ بابَ فَهْمي بِلَذيذِ مُناجاتِهِمْ، وَاِنّي اَسْتَأذِنُكَ يا رَبِّ اوَّلاً وَاَسْتَأذِنُ رَسُولَكَ صَلَّى اللهُ عَلَيْهِ وَآلِهِ ثانِياً، وَاَسْتَأذِنُ خَليفَتَكَ الاِْمامَ الْمَفْرُوضَ عَلَيَّ طاعَتُهُ (فُلانَ بْنَ فُلان) (واذكر اسم الامام الذي تزُوره واسم أبيه ، فقل في زيارة الحسين (عليه السلام) مثلاً : الْحُسَيْنَ بْنَ عَلِيٍّ عليه السلام وفي زيارة الامام الرّضا (عليه السلام) عَلِيِّ بْنَ مُوسَى الرِّضا عليه السلام وهكذا ثمّ قل :) وَالْمَلائِكَةَ الْمُوَكَّلينَ بِهذِهِ الْبُقْعَةِ الْمُبارَكَةِ ثالِثاً، أَاَدْخُلُ يا رَسُولَ اللهِ، أَاَدْخُلُ يا حُجَّةَ اللهِ أَاَدْخُلُ يا مَلائِكَةَ اللهِ الْمُقَرَّبينَ الْمُقيمينَ في هذَا الْمَشْهَدِ، فَأذَنْ لي يا مَوْلايَ في الدُّخُولِ اَفْضَلَ ما اَذِنْتَ لاَِحَد مِنْ اَوْلِيائِكَ، فَاِنْ لَمْ اَكُنْ اَهْلاً لِذلِكَ فَاَنْتَ اَهْل ٌ لِذلِكَ ."},{"type":"Text","content":"ثمّ قبّل العتبة الشّريفة وادخل وقُلْ : بِسْمِ اللهِ وَبِاللهِ وَفي سَبيلِ اللهِ وَعَلى مِلَّةِ رَسُولِ اللهِ صَلَّى اللهُ عَلَيْهِ وَآلِهِ اَللّـهُمَّ اغْفِرْ لي وَارْحَمْني وَتُبْ عَلَيَّ اِنَّكَ اَنْتَ التَّوّابُ الرَّحيمُ ."},{"type":"Text","content":"الثّاني : الاستئذان الّذي رواه المجلسي (قدس سره) عن نسخة قديمة من مؤلّفات الاصحاب للدّخول في السّرداب المقدّس وفي البقاع المنوّرة للائمة (عليهم السلام) وهو هذا، تقول :"},{"type":"Text","content":"اَللّـهُمَّ اِنَّ هذِهِ بُقْعَةٌ طَهَّرْتَها، وَعَقْوَةٌ شَرَّفْتَها، وَمَعالِمُ زَكَّيْتَها، حَيْثُ اَظْهَرْتَ فيها اَدِلَّةَ التَّوْحيدِ، وَاَشْباحَ الْعَرْشِ الَْمجيدِ، الَّذينَ اصْطَفَيْتَهُمْ مُلُوكاً لِحِفْظِ النِّظامِ، وَاخْتَرْتَهُمْ رُؤَساءَ لِجَميعِ الاَْنامِ، وَبَعَثْتَهُمْ لِقِيامِ الْقِسْطِ فِي ابْتِدآءِ الْوُجُودِ اِلى يَوْمِ الْقِيامَةِ ثُمَّ مَنَنْتَ عَلَيْهِمْ بِاسْتِنابَةِ اَنْبِيائِكَ لِحِفْظِ شَرايِعِكَ وَاَحْكامِكَ، فَاَكْمَلْتَ بِاسْتِخْلافِهِمْ رِسالَةَ الْمُنْذِرينَ، كَما اَوْجَبْتَ رِياسَتَهُمْ في فِطَرِ الْمُكَلَّفينَ، فَسُبْحانَكَ مِنْ اِلـه ما اَرْاَفَكَ، وَلا اِلـهَ إلاّ اَنْتَ مِنْ مَلِك ما اَعْدَلَكَ، حَيْثُ طابَقَ صُنْعُكَ ما فَطَرْتَ عَلَيْهِ الْعُقُولَ، وَوافَقَ حُكْمُكَ ما قَرَّرْتَهُ فِي الْمَعْقُولِ وَالْمَنْقُولِ، فَلَكَ الْحَمْدُ عَلى تَقْديرِكَ الْحَسَنِ الْجَميلِ، وَلَكَ الشُّكْرُ عَلى قَضائِكَ الْمُعَلَّلِ بِاَكْمَلِ التَّعْليلِ، فَسُبْحانَ مَنْ لا يُسْأَلُ عَنْ فِعْلِهِ، وَلا يُنازِعُ في اَمْرِهِ، وَسُبْحانَ مَنْ كَتَبَ عَلى نَفْسِهِ الرَّحْمَةَ قَبْلَ ابْتِداءِ خَلْقِهِ، وَالْحَمْدُللهِ الَّذي مَنَّ عَلَيْنا بِحُكّام يَقُومُونَ مَقامَهُ لَوْ كانَ حاضِراً فِي الْمَكانِ، وَلا اِلـه اِلاَّ اللهُ الَّذي شَرَّفَنا بِاَوْصِياءَ يَحْفَظُونَ الشَّرايِعَ في كُلِّ الاَْزْمانِ، وَاللهُ اَكْبَرُ الَّذي اَظْهَرَهُمْ لَنا بِمُعْجِزات يَعْجَزُ عَنْهَا الثَّقَلانِ، لا حَوْلَ وَلا قُوَّةَ إلاّ بِاللهِ الْعَلِىِّ الْعَظيمِ، الَّذي اَجْرانا عَلى عَوائِدِهِ الْجَميلَةِ فِي الاُْمَمِ السّالِفينَ، اَللّـهُمَّ فَلَكَ الْحَمْدُ وَالثَّناءُ الْعَلِىُّ كَما وَجَبَ لِوَجْهِكَ الْبَقاءُ السَّرْمَدِىُّ، وَكَما جَعَلْتَ نَبِيَّنا خَيْرَ النَّبِيّينَ، وَمُلُوكَنا اَفْضَلَ الَْمخْلُوقينَ، وَاخْتَرْتَهُمْ عَلى عِلْم عَلَى الْعالَمينَ، وَفِّقْنا للِسَّعْىِ اِلى اَبْوابِهِمُ الْعامِرَةِ اِلى يَوْمِ الدّينِ، وَاجْعَلْ اَرْواحَنا تَحِنُّ إلَى مَوْطِئ اَقْدامِهِمْ، وَنُفُوسَنا تَهْوِى النَّظَرَ اِلى مَجالِسِهِمْ وَعَرصاتِهِمْ، حَتّى كَاَنَّنا نُخاطِبُهُمْ في حُضُورِ اَشْخاصِهِمْ، فَصَلَّى اللهُ عَلَيْهِمْ مِنْ سادَة غائِبينَ، وَمِنْ سُلالَة طاهِرينَ، وَمِنْ اَئمَّة مَعْصُومينَ، اَللّـهُمَّ فَأذَنْ لَنا بِدُخُولِ هذِهِ الْعَرَصاتِ الَّتي اسْتَعْبَدْتَ بِزِيارَتِها اَهْلَ الاَْرَضينَ وَالسَّماواتِ، وَاَرْسِلْ دُمُوعَنا بِخُشُوعِ الْمَهابَةِ، وَذَلِّلْ جَوارِحَنا بِذُلِّ الْعُبُودِيِّةِ وَفَرْضِ الطّاعَةِ، حَتّى نُقِرَّ بِما يَجِبُ لَهُمْ مِنَ الاَْوْصافِ، وَنَعْتَرِفُ بِاَنَّهُمْ شُفَعاءَ الْخَلايِقِ اِذا نُصِبَتِ الْمَوازينُ في يَوْمِ الاَْعْرافِ، وَالْحَمْدُ للهِ وَسَلامٌ عَلى عِبادِهِ الَّذينَ اصْطَفى مُحَمَّد وَآلِهِ الطّاهِرينَ ."},{"type":"Text","content":"ثمّ قبّل العتبة وادخل وأنت خاشِع باك فذلك اذن منهم صلوات الله عليهم أجمعين في الدُّخول ."},{"type":"Text","content":"في زِيارَة النّبيّ والزّهراء والائمّة بالبقيع صلوات الله عليهم أجمعين في المدينة الطيّبة ."},{"type":"AboutText","content":"اعلم انّه يستحبّ أكيداً لكافة النّاس ولا سيّما للحجّاج أن يتشرّفوا بزيارة الرّوضة الطّاهرة والعتبة المنوّرة لمفخرة الدّهر مولانا سيّد المرسلين محمّد بن عبد الله صلوات الله وسلامُه عليه، وترك زيارته جفاء في حقّه يوم القيامة ."},{"type":"Text","content":"وقال الشّهيد (رحمه الله) : فإن ترك النّاس زيارته فعلى الامام أن يجبرهم عليها، فان ترك زيارته جفاء محرّم، روى الصّدوق عن الصّادق (عليه السلام) : اذا حجّ أحدكم فليختم حجّه بزيارتنا لانّ ذلك من تمام الحجّ، وروي ايضاً عن امير المؤمنين (عليه السلام)قال : اتمّوا بزيارة رسول الله (صلى الله عليه وآله وسلم) حجّكم فانّ تركه بعد الحجّ جفاء وبذلك أمرتم واتمّوه بالقبُور التي ألزمكم الله عزوجل حقّها وزيارتها واطلبوا الرّزق عندها ."},{"type":"Text","content":"وروي أيضاً عن أبي الصّلت الهروي قال : قلت للرّضا (عليه السلام) : ياابن رسول الله ما تقول في الحديث الّذي يرويه أهل الحديث انّ المؤمنين يزورون ربّهم من منازلهم في الجنّة ـ ويعني الرّاوي بسؤاله انّ الرّواية إن صحّت ما معناها وهي بظاهرها تحتوي على ما لا يستقيم مع الاعتقاد الحقّ ـ فأجابه (عليه السلام) فقال : يا أبا الصّلت انّ الله تبارك وتعالى فضّل نبيّه محمّد (صلى الله عليه وآله وسلم) على جميع خلقه من النّبيّين والملائكة، وجعل طاعته طاعته ومبايعته مُبايعته وزيارته زيارته ، فقال الله عزوجل : « مِنْ يُطِعِ الرَّسُولَ فَقَدْ اَطاعَ اللهَ » وَقالَ : « اِنَّ الَّذينَ يُبايِعُونَكَ اِنَّما يُبايِعُونَ اللهَ يَدُ اللهِ فَوْقَ اَيْديهِمْ » ، وقال النّبي (صلى الله عليه وآله وسلم) : مَن زارني في حياتي أو بعد مماتي فقد زار الله تعالى الخ ."},{"type":"AboutText","content":"وروى الحميري في قُرب الاسناد عن الصّادق (عليه السلام) عن النّبي (صلى الله عليه وآله وسلم) قال : من زارني حيّاً أو ميّتاً كنت له شفيعاً يوم القيامة ."},{"type":"Text","content":"وفي الحديث انّه شهد الصّادق (عليه السلام) عيداً بالمدينة فانصرف فدخل على النّبي (صلى الله عليه وآله وسلم) فسلّم عليه ثمّ قال لِمن حضره امّا لقد فضّلنا على أهل البلدان كلّهم مكّة فمن دُونها لسلامنا على رسول الله (صلى الله عليه وآله وسلم) ."},{"type":"AboutText","content":"وروى الطّوسي (رحمه الله) في التّهذيب عن يزيد بن عبد الملك عن أبيه عَن جدّه انّه قال : دخلت على فاطمة (عليها السلام) فبدأتني بالسّلام ثمّ قالت : ما غدا بِكَ ، قلت : طلب البركة ، قالت : اخبرني أبي وهُو ذا هُو انّه من سلّم عليه وعليّ ثلاثة أيّام أوجب الله له الجنّة ، قلت لها : في حياته وحياتك ؟ قالت : نعم وبعد موتنا ."},{"type":"AboutText","content":"قال العلامة المجلسي (رحمه الله) : روي في حديث مُعتبر عن عبد الله بن عبّاس عن رسول الله (صلى الله عليه وآله وسلم) قال : مَنْ زار الحسن (عليه السلام) بالبقيع ثبت قدمه على الصّراط يوم تزُول فيه الاقدام ، وفي المقنعة عن الصّادق (عليه السلام) : من زارني غفرت ذنُوبه ولم يصب بالفقر والفاقة . وروى الطّوسي في التّهذيب عن الامام الحسن العسكري (عليه السلام) قال : من زار جعفر الصّادق وأباه لم يشكُ عينه ولم يصبه سقم ولم يمت مبتلى . وروى ابن قولويه في الكامل في حديث طويل عن هشام بن سالم عن الصّادق (عليه السلام) انّه أتاه رجل فقال : هل يزار والدك ؟ فقال : نعم ، قال : فما لمن زاره ؟ قال : الجنّة إن كان يأتمّ به ، قال : فما لمن تركه رغبة عنه ، قال : الحسرة يوم الحسرة الخ، والاحاديث في ذلك كثيرة حَسبنا منها ما ذكرناه ."}],"preview":"الاوّل : اذا أردت دخول مسجد النّبي (صلى الله عليه وآله وسلم) أو أحد المشاهد الشّريفة لاحد الائمة (عليهم السلام) فقل :","hasTranslate":false},{"id":"mf_ar_185","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الفَصلُ الثّالِثُ :","title":"وأمّا كيفيّة زيارة النّبي (صلى الله عليه وآله وسلم) فهي كما يلي :","blocks":[{"type":"Text","content":"اذا وردت ان شاء الله تعالى مدينة النّبي (صلى الله عليه وآله وسلم) فاغتسل للزّيارة فاذا أردت دخول مسجده (صلى الله عليه وآله وسلم) فقف على الباب واستأذن بالاستئذان الاوّل ممّا ذكرناه وادخل من باب جبرئيل وقدّم رجلك اليُمنى عند الدّخول ثمّ قل : اَللهُ اَكْبَرُ مائة مرّة، ثمّ صلّ ركعتين تحيّة المسجد، ثمّ امض الى الحجرة الشّريفة فاذا بلغتها فاستلمها بيدك وقبّلها وقُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا رَسُولَ اللهِ، اَلسَّلامُ عَلَيْكَ يا نَبِيَّ اللهِ، اَلسَّلامُ عَلَيْكَ يا مُحَمَّدَ بْنَ عَبْدِ اللهِ، اَلسَّلامُ عَلَيْكَ يا خاتَمَ النَّبِيّينَ، اَشْهَدُ اَنَّكَ قَدْ بَلَّغْتَ الرِّسالَةَ، وَاَقَمْتَ الصَّلاةَ، وَآتَيْتَ الزَّكاةَ، وَاَمَرْتَ بِالْمَعْرُوفِ، وَنَهَيْتَ عَنِ الْمُنَكَرِ، وَعَبَدْتَ اللهَ مُخْلِصاً حَتّى اَتاكَ الْيَقينُ، فَصَلَواتُ اللهِ عَلَيْكَ وَرَحْمَتُهُ وَعَلى اَهْلِ بَيْتِكَ الطّاهِرينَ، ثمّ قف عند الاُسطوانة المقدّمة من جانب القبر الايمن مُستقبل القبلة ومنكبك الايسر الى جانب القبر ومنكبك الايمن ممّا يلي المنبر فانّه موضِعُ رأس النّبي (صلى الله عليه وآله وسلم) وقل :"},{"type":"Text","content":"اَشْهَدُ اَنْ لا اِلـهَ اِلاَّ اللهُ وَحْدَهُ لا شَريكَ لَهُ، وَاَشْهَدُ اَنَّ مُحَمَّداً عَبْدُهُ وَرَسُولُهُ، وَاَشْهَدُ اَنَّكَ رَسُولُ اللهِ، وَاَنَّكَ مُحَمَّدُ بْنُ عَبْدِ اللهِ، وَاَشْهَدُ اَنَّكَ قَدْ بَلَّغْتَ رِسالاتِ رَبِّكَ، وَنَصَحْتَ لاُِمَّتِكَ، وَجاهَدْتَ في سَبيلِ اللهِ، وَعَبَدْتَ اللهَ حَتّى اَتاكَ الْيَقينُ بِالْحِكْمَةِ وَالْمَوْعِظَةِ الْحَسَنَةِ، وَاَدَّيْتَ الَّذي عَلَيْكَ مِنَ الْحَقِّ، وَاَنَّكَ قَدْ رَؤُفْتَ بِالْمُؤْمِنينَ، وَغَلُظْتَ عَلَى الْكافِرينَ، فَبَلَّغَ اللهُ بِكَ اَفْضَلَ شَرَفِ مَحَلِّ الْمُكَرَّمينَ، اَلْحَمْدُ للهِ الَّذي اِسْتَنْقَذَنا بِكَ مِنَ الشِّرْكِ وَالضَّلالَةِ، اَللّـهُمَّ فَاجْعَلْ صَلَواتِكَ، وَصَلَواتِ مَلائِكَتِكَ الْمُقَرَّبينَ، وَاَنْبِيائِكَ الْمُرْسَلينَ، وَعِبادِكَ الصّالِحينَ، وَاَهْلِ السَّماواتِ وَالاَْرَضينَ، وَمَنْ سَبَّحَ لَكَ يا رَبَّ الْعالَمينَ مِنَ الاَْوَّلينَ وَالاْخِرينَ عَلى مُحَمَّد عَبْدِكَ وَرَسُوِلِكَ وَنَبِيِّكَ وَاَمينِكَ وَنَجِيِّكَ وَحَبيبِكَ وَصَفِيِّكَ وَخاصَّتِكَ وَ صَفْوَتِكَ وَخِيَرَتِكَ مِنْ خَلْقِكَ، اَللّـهُمَّ اَعْطِهِ الدَّرَجَةَ الرَّفيعَةَ، وَآتِهِ الْوَسيلَةَ مِنَ الْجَّنَةِ، وَابْعَثْهُ مَقاماً مَحْمُوداً يَغْبِطُهُ بِهِ الاَْوَّلُونَ وَالاْخِرُونَ، اَللّـهُمَّ اِنَّكَ قُلْتَ: (وَلَوْ اَنَّهُمْ اِذْ ظَلَمُوا اَنْفُسَهُمْ جاؤُكَ فَاسْتَغْفَرُوا اللهَ وَاسْتَغْفَرَ لَهُمُ الرَّسُولُ لَوَجَدُوا اللهَ تَوّاباً رَحيماً) وَاِنّي اَتَيْتُكَ مُسْتَغْفِرًا تائِباً مِنْ ذُنُوبي، وَاِنّي اَتَوَجَّهُ بِكَ اِلَى اللهِ رَبّي وَرَبِّكَ لِيَغْفِرَ لي ذُنُوبي ."},{"type":"Text","content":"فإن كانت لك حاجة فانّه احرى أن تقضى ان شاء الله تعالى ."},{"type":"AboutText","content":"وروى ابن قولويه بسند معتبر عن محمّد بن مسعود قال : رأيت الصّادق (عليه السلام) انتهى الى قبر النّبي (صلى الله عليه وآله وسلم)فوضع يده عليه وقال : اَسْاَلُ اللهَ الَّذي اجْتَباكَ وَاخْتارَكَ وَهَداكَ وَهَدى بِكَ اَنْ يُصَلِّيَ عَلَيْكَ ثمّ قال : اِنَّ اللهَ وَمَلائِكَتَهُ يُصَلُّونَ عَلَى النَّبِىِّ يا اَيُّها الَّذينَ آمَنُوا صَلُّوا عَلَيْهِ وَسَلِّمُوا تَسْليماً، وقال الشّيخ في المصباح : فاذا فرغت من الدّعاء عند القبر فأت المنبر وامسحه بيدك وخُذ برمانتيه وهُما السُفلاوان وامسح وجهك وعَينيك به فانّ فيه شفاءاً للعين وقُم عنده واحمد الله واثنُ عليه وسل حاجتك فانّ رسول الله (صلى الله عليه وآله وسلم) قال : ما بين قبري ومنبري روضة من رياض الجنّة ومنبري على باب من أبواب الجنّة . ثمّ تأتي مقام النّبي (صلى الله عليه وآله وسلم)فتصلّي فيه ما بدا لك واكثر من الصّلاة في مسجد النّبي (صلى الله عليه وآله وسلم) فانّ الصّلاة فيه بألف صلاة، واذا دخلت المسجد أو خرجت منه فَصَلّ على النّبي (صلى الله عليه وآله وسلم) وصلّ في بيت فاطمة (عليها السلام) وأت مقام جبرئيل (عليه السلام) وهو تحت الميزاب فانّه كان مقامه اذا استأذن على رسول الله (صلى الله عليه وآله وسلم) وقل : اَسْاَلُكَ اَىْ جَواد اَىْ كَريمُ اَىْ قَريبُ اَىْ بَعيدُ اَنْ تَرُدَّ عَلَيَّ نِعْمَتَكَ، ثمّ زر فاطمة (عليها السلام) مِن عند الرّوضة، واختلف في موضع قبرها ، فقال قوم : هي مدفونة في الرّوضة أي ما بين القبر والمنبر ، وقال آخرون : في بيتها ، وقالت فرقة ثالثة : انّها مدفونة بالبقيع والذي عليه اكثر أصحابنا انّها تزار مِن عِند الرّوضة ومَن زارَها في هذه الثّلاثة مواضِع كان أفضل واذا وقفت عليها للزّيارة فقل :"},{"type":"Text","content":"يا مُمْتَحَنَةُ امْتَحَنَكِ اللهُ الَّذي خَلَقَكِ قَبْلَ اَنْ يَخْلُقَكِ، فَوَجَدَكِ لِمَا امْتَحَنَكِ صابِرَةً، وَزَعَمْنا اَنّا لَكِ اَوْلِياءُ وَمُصَدِّقُونَ وَصابِرُونَ لِكُلِّ ما اَتانا بِهِ اَبُوكِ صَلَّى اللهُ عَلَيْهِ وَآلِهِ وَاَتى بِهِ وَصِيُّهُ، فَاِنّا نَسْأَلُكِ اِنْ كُنّا صَدَّقْناكِ إلاّ اَلْحَقْتِنا بِتَصْديقِنا لَهُما لِنُبَشِّرَ اَنْفُسَنا بِاَنّا قَدْ طَهُرْنا بِوَلايَتِكِ ."},{"type":"Text","content":"ويستحبّ أيضاً أن تقول : اَلسَّلامُ عَلَيْكِ يا بِنْتَ رَسُولِ اللهِ، اَلسَّلامُ عَلَيْكِ يا بِنْتَ نَبِىِّ اللهِ، اَلسَّلامُ عَلَيْكِ يا بِنْتَ حَبيبِ اللهِ، اَلسَّلامُ عَلَيْكِ يا بِنْتَ خَليلِ اللهِ، اَلسَّلامُ عَلَيْكِ يا بِنْتَ صَفىِّ اللهِ، اَلسَّلامُ عَلَيْكِ يا بِنْتَ اَمينِ اللهِ، اَلسَّلامُ عَلَيْكِ يا بِنْتَ خَيْرِ خَلْقِ اللهِ، اَلسَّلامُ عَلَيْكِ يا بِنْتَ اَفْضَلِ اَنْبِياءِ اللهِ وَرُسُلِهِ وَمَلائِكَتِهِ، اَلسَّلامُ عَلَيْكِ يا بِنْتَ خَيْرِ الْبَرِّيَةِ، اَلسَّلامُ عَلَيْكِ يا سِيِّدَةَ نِساءِ الْعالَمينَ مِنَ الاَْوَّلينَ وَالاْخِرينَ، اَلسَّلامُ عَلَيْكِ يا زَوْجَةَ وَلِيِّ اللهِ وَخَيْرِ الْخَلْقِ بَعْدَ رَسُولِ اللهِ، اَلسَّلامُ عَلَيْكِ يا اُمَّ الْحَسَنِ وَالْحُسَيْنِ سَيِّدَىْ شَبابِ اَهْلِ الْجَنَّةِ، اَلسَّلامُ عَلَيْكِ اَيَّتُهَا الصِّدّيقَةُ الشَّهيدَةُ، اَلسَّلامُ عَلَيْكِ اَيَّتُهَا الرَّضِيَّةُ الْمَرْضِيَّةُ، اَلسـَّلامُ عـَلَيْكِ اَيَّتـُهَا الْفاضِلـَةُ الزَّكِيـَّةُ، اَلسـَّلامُ عـَلَيْكِ اَيَّتـُهَا الْحَوْراءُ الاِْنْسِيَّةُ، اَلسـَّلامُ عَلَيْكِ اَيَّتُهَا التَّقِيَّةُ النَّقِيَّةُ، اَلسَّلامُ عَلَيْكِ اَيَّتُهَا الُْمحَدَّثَةُ الْعَليمَةُ، اَلسَّلامُ عَلَيْكِ اَيَّتُهَا الْمَظْلُومَةُ الْمَغْصُوبَةُ، اَلسَّلامُ عَلَيْكِ اَيَّتُهَا الْمُضْطَهَدَةُ الْمَقْهُورَةُ، اَلسَّلامُ عَلَيْكِ يا فاطِمَةُ بِنْتَ رَسُولِ اللهِ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، صَلَّى اللهُ عَلَيْكِ وَعَلى رُوحِكِ وَبَدَنِكِ، اَشْهَدُ اَنَّكِ مَضَيْتِ عَلى بَيِّنَة مِنْ رَبِّكِ، وَاَنَّ مَنْ سَرَّكِ فَقَدْ سَرَّ رَسُولَ اللهِ صَلَّى اللهُ عَلَيْهِ وَآلِهِ، وَمَنْ جَفاكِ فَقَدْ جَفا رَسُولَ اللهِ صَلَّى اللهُ عَلَيْهِ وَآلِهِ، وَمَنْ آذاكِ فَقَدْ آذى رَسُولَ اللهِ صَلَّى اللهُ عَلَيْهِ وَآلِهِ، وَمَنْ وَصَلَكِ فَقَدْ وَصَلَ رَسُولَ اللهِ صَلَّى اللهُ عَلَيْهِ وَآلِهِ، وَمَنْ قَطَعَكِ فَقَدْ قَطَعَ رَسُولَ اللهِ صَلَّى اللهُ عَلَيْهِ وَآلِهِ، لاَِنَّكِ بِضْعَةٌ مِنْهُ وَرُوحُهُ الَّذي بَيْنَ جَنْبَيْهِ، اُشْهِدُ اللهَ وَرُسُلَهُ وَمَلائِكَتَهُ اَنّي راض عَمَّنْ رَضَيتِ عَنْهُ، ساخِطٌ عَلى مَنْ سَخِطْتِ عَلَيْهِ مُتَبَرِّىءٌ مِمَّنْ تَبَرَّأْتِ مِنْهُ، مُوال لِمَنْ والَيْتِ، مُعاد لِمَنْ عادِيْتِ، مُبْغِضٌ لِمَنْ اَبْغَضْتِ، مُحِبٌّ لِمَنْ اَحْبَبْتِ، وَكَفى بِاللهِ شَهيداً وَحَسيباً وَجازِياً وَمُثيباً ."},{"type":"Text","content":"ثمّ تصلّي على النّبي والائمة الاطهار (عليهم السلام) ."},{"type":"AboutText","content":"أقول : قد ذكرنا في اليوم الثّالث من شهر جمادى الاخرة زيارة اخرى لها صلوات الله عليها، وقد أورد العلماء لها صلوات الله عليها زيارة مبسوطة تتّفق في ألفاظها مع هذه الزّيارة التي نقلناها عن الشّيخ من أوّلها وهي : اَلسَّلامُ عَلَيْكِ يا بِنْتَ رَسُولِ اللهِ الى اُشْهِدُ اللهَ وَرُسُلَهُ وَمَلائِكَتَهُ، وتختلف عنها هُنا فتكُون : اُشْهِدُ اللهَ وَمَلائِكَتَهُ اَنّي وَلِيُّ لِمَنْ والاكِ، وَعَدُوٌّ لِمَنْ عاداكِ، وَحَرْبٌ لِمَنْ حارَبَكِ، اَنَا يا مَوْلاتي بِكِ وَبِاَبيكِ وَبَعْلِكِ وَالاَْئِمَّةِ مِنْ وُلْدِكِ مُوقِنٌ، وَبِوِلايَتِهِمْ مُؤْمِنٌ، وَلِطاعَتِهِمْ مُلْتَزِمٌ، اَشْهَدُ اَنَّ الدّينَ دينُهُمْ، وَالْحُكْمَ حُكْمُهُمْ، وَهُمْ قَد بَلَّغُوا عَنِ اللهِ عَزَّوَجَلَّ، وَدَعَوْا اِلى سَبيلِ اللهِ بِالْحِكْمَةِ وَالْمَوْعِظَةِ الْحَسَنَةِ لا تَأخُذُهُمْ فِي اللهِ لَوْمَةُ لائِم، وَصَلَواتُ اللهِ عَلَيْكِ وَعَلى اَبيكِ وَبَعْلِكِ وَذُرِّيَّتِكِ الاَْئِمَّةِ الطّاهِرينَ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَاَهْلِ بَيْتِهِ، وَصَلِّ عَلَى الْبَتُولِ الطّاهِرَةِ الصِّديقَةِ الْمَعْصُومَةِ التَّقِيَّةِ النَّقِيَّةِ الرَّضِيَّةِ الْمَرْضِيَّةِ الزَّكِيَّةِ الرَّشيدَةِ الْمَظْلُومَةِ الْمَقْهُورَةِ الْمَغْصُوبَةِ حَقَّهَا، الْمَمْنُوعَةِ اِرْثَهَا، الْمَكْسُورَةِ ضِلْعَهَا، الْمَظْلُومِ بَعْلُهَا، الْمَقْتُولِ وَلَدُها فاطِمَةَ بِنْتِ رَسُولِكَ، وَبِضْعَةِ لَحْمِهِ، وَصَميمِ قَلْبِهِ، وَفِلْذَةِ كَبِدِهِ، وَالنُّخْبَةِ مِنْكَ لَهُ وَالتُّحْفَةِ، خَصَصْتَ بِها وَصِيَّهُ، وَحَبيبَةِ الْمُصْطَفى، وَقَرينَةِ الْمُرْتَضى، وَسَيِّدَةِ النِّساءِ، وَمُبَشِّرَةِ الاَْوْلِياءِ، حَليفَةِ الْوَرَعِ وَالزُّهْدِ، وَتُفّاحَةِ الفِرْدَوْسِ وَالْخُلْدِ، الَّتي شَرَّفْتَ مَوْلِدَها بِنِساءِ الْجَنَّةِ، وَسَلَلْتَ مِنْها اَنْوارَ الاَْئِمَّةِ، وَاَرْخَيْتَ دُونَها حِجابَ النُّبُوَّةِ، اَللّـهُمَّ صَلِّ عَلَيْها صَلاةً تَزيدُ في مَحَلِّها عِنْدَك وَشَرَفِها لَدَيْكَ، وَمَنْزِلَتِها مِنْ رِضاكَ، وَبَلِّغْها مِنّا تَحِيَّةً وَسَلاماً، وَآتِنا مِنْ لَدُنْكَ في حُبِّها فَضْلاً وَاِحْساناً وَرَحْمَةً وَغُفْراناً، اِنَّكَ ذُو الْعَفْوِ الْكَريمِ ."},{"type":"AboutText","content":"أقول : قال الشّيخ في التّهذيب: انّ ما روي في فضل زيارَتها صلوات الله عليها أكثر من أن يحصى، وروى العلامة المجلسي عن كتاب مصباح الانوار عن الزّهراء صلوات الله عليها قالت : قال لي أبي : من صلّى عليك غفر الله عزّوجل له وألحقه بي حيثما كنت من الجنّة ."},{"type":"Text","content":"زِيارَة النَّبي صَلّى اللهُ عَلَيْه وَآلِهِ مِنَ الْبُعد"},{"type":"AboutText","content":"قال العلامة المجلسي (رحمه الله) في زاد المعاد في أعمال عيد الميلاد وهو اليوم السّابع عشر من ربيع الاوّل : قال الشّيخ المفيد والشّهيد والسّيد ابن طاووس (رحمهم الله) : اذا أردت زيارة النّبي (صلى الله عليه وآله وسلم) في ما عدا المدينة الطيّبة من البِلاد فاغتسل ومثّل بين يديك شبه القبر واكتب عليه اسمه الشّريف ثمّ قف وتوجّه بقلبك اليه وقُل : اَشْهَدُ اَنْ لا اِلـهَ اِلاَّ اللهُ وَحْدَهُ لا شَريكَ لَهُ، وَاَشْهَدُ اَنَّ مُحَمَّداً عَبْدُهُ وَرَسُولُهُ، وَاَشْهَدُ اَنَّهُ سَيِّدُ الاَْوَّلينَ وَالاْخِرينَ، وَاَنَّهُ سَيِّدُ الاَْنْبِياءِ وَالْمُرْسَلينَ، اَللّـهُمَّ صَلِّ عَلَيْهِ وَعَلى اَهْلِ بَيْتِهِ الاَئِمَّةِ الطَّيِّبينَ، ثمّ قل : اَلسَّلامُ عَلَيْكَ يا رَسُولَ اللهِ، اَلسَّلامُ عَلَيْكَ يا خَليلَ اللهِ، اَلسَّلامُ عَلَيْكَ يا نَبِيَّ اللهِ، اَلسَّلامُ عَلَيْكَ يا صَفِيَّ اللهِ، اَلسَّلامُ عَلَيْكَ يا رَحْمَةَ اللهِ، اَلسَّلامُ عَلَيْكَ يا خِيَرَةَ اللهِ، اَلسَّلامُ عَلَيْكَ يا حَبيبَ اللهِ، اَلسَّلامُ عَلَيْكَ يا نَجيبَ اللهِ، اَلسَّلامُ عَلَيْكَ يا خاتَمَ النَّبِيّينَ، اَلسَّلامُ عَلَيْكَ يا سَيِّدَ الْمُرْسَلينَ، اَلسَّلامُ عَلَيْكَ يا قائِماً بِالْقِسْطِ، اَلسَّلامُ عَلَيْكَ يا فاتِحَ الْخَيْرِ، اَلسَّلامُ عَلَيْكَ يا مَعْدِنَ الْوَحْيِ وَالتَّنْزيلِ، اَلسَّلامُ عَلَيْكَ يا مُبَلِّغاً عَنِ اللهِ، اَلسَّلامُ عَلَيْكَ اَيُّهَا السِّراجُ الْمُنيرُ، اَلسَّلامُ عَلَيْكَ يا مُبَشِّرُ، اَلسَّلامُ عَلَيْكَ يا نَذيرُ، اَلسَّلامُ عَلَيْكَ يا مُنْذِرُ، اَلسَّلامُ عَلَيْكَ يا نُورَ اللهِ الَّذي يُسْتَضاءُ بِهِ، اَلسَّلامُ عَلَيْكَ وَعَلى اَهْلِ بَيْتِكَ الطَّيِّبينَ الطّاهِرينَ الْهادينَ الْمَهْدِيّينَ، اَلسَّلامُ عَلَيْكَ وَعَلى جَدِّكَ عَبْدِ المُطَّلِبِ، وَعَلى اَبيكَ عِبْدِ اللهِ، اَلسَّلامُ عَلى اُمِّكَ آمِنَةَ بِنْتِ وَهَب، اَلسَّلامُ عَلى عَمِّكَ حَمْزَةَ سَيِّدِ الشُّهَداءِ، اَلسَّلاُمُ عَلى عَمِّكَ الْعَبّاسِ بْنِ عَبْدِ المُطَّلِبِ، اَلسَّلامُ عَلى عَمِّكَ وَكَفيلِكَ أبي طالِب، اَلسَّلامُ عَلى ابْنِ عَمِّكَ جَعْفَر الطَّيّارِ في جِنانِ الْخُلْدِ، اَلسَّلامُ عَلَيْكَ يا مُحَمَّدُ اَلسَّلامُ عَلَيْكَ يا اَحْمَدُ اَلسَّلامُ عَلَيْكَ يا حُجَّةَ اللهِ عَلَى الاَْوَّلينَ وَالاْخَرينَ وَالسّابِقُ اِلى طاعَةِ رَبِّ الْعالَمينَ، وَالْمُهَيْمِنُ عَلى رُسُلِهِ، وَالْخاتَمُ لاَِنْبِيائِهِ، وَالشّاهِدُ عَلى خَلْقِهِ، وَالشَّفِيعُ اِلَيْهِ، وَالْمَكينُ لَدَيْهِ، وَالْمُطاعُ في مَلَكُوتِهِ، الاَْحْمَدُ مِنَ الاَْوْصافِ، الُْمحَمَّدُ لِسائِرِ الاَْشْرافِ، الْكَريمُ عِنْدَ الرَّبِّ، وَالْمُكَلَّمُ مِنْ وَراءِ الْحُجُبِ، الْفائِزُ بِالسِّباقِ، وَالْفائِتُ عَنِ اللِّحاقِ، تَسْليمَ عارِف بِحَقِّكَ مُعْتَرِف بِالتَّقْصيرِ في قِيامِهِ بِواجِبِكَ، غَيْرَ مُنْكَر مَا انْتَهى اِلَيْهِ مِنْ فَضْلِكَ، مُوقِن بِالْمَزيداتِ مِنْ رَبِّكَ، مُؤْمِن بِالْكِتابِ الْمُنْزَلِ عَلَيْكَ، مُحَلِّل حَلالَكَ، مُحَرَّم حَرامَكَ، اَشْهَدُ يا رَسُولَ اللهِ مَعَ كُلِّ شاهِد، وَاَتَحَمَّلُها عَنْ كُلِّ جاحِد، اَنَّكَ قَدْ بَلَّغْتَ رِسالاتِ رَبِّكَ، وَنَصَحْتَ لاُِمَّتِكَ، وَجاهَدْتَ في سَبيلِ رَبِّكَ، وصَدَعْتَ بِاَمْرِهِ، وَاحْتَمَلْتَ الاَْذى في جَنْبِهِ، وَدَعَوْتَ اِلى سَبيلِهِ بِالْحِكْمَةِ وَالْمَوْعِظَةِ الْحَسَنَةِ الْجَميلَةِ، وَاَدَّيْتَ الْحَقَّ الَّذي كانَ عَلَيْكَ، وَاَنَّكَ قَدْ رَؤُفْتَ بِالْمُؤْمِنينَ، وَغَلُظْتَ عَلَى الْكافِرينَ، وَعَبَدْتَ اللهَ مُخْلِصاً حَتّى اَتاكَ الْيَقينُ، فَبَلَغَ اللهُ بِكَ اَشْرَفَ مَحَلِّ الْمُكَرَّمينَ، وَاَعْلى مَنازِلِ الْمُقَرَّبينَ، وَاَرْفَعَ دَرَجاتِ الْمُرْسَلينَ، حَيْثُ لا يَلْحَقُكَ لاحِقٌ، وَلا يَفُوقُكَ فائِقٌ، وَلا يَسْبِقُكَ سابِقٌ، وَلا يَطْمَعُ في اِدْراكِكَ طامِعٌ، اَلْحَمْدُ للهِ الَّذي اسْتَنْقَذَنا بِكَ مِنَ الْهَلَكَةِ، وَهَدانا بِكَ مِنَ الضَّلالَةِ، وَنوَّرَنا بِكَ مِنَ الظُّلْمَةِ، فَجَزاكَ اللهُ يا رَسُولَ اللهِ مِنْ مَبْعُوث اَفْضَلَ ما جازى نَبِيَّاً عَنْ اُمَّتِهِ، وَرَسُولاً عَمَّنْ اُرْسِلَ اِلَيْهِ، بَاَبي اَنْتَ وَاُمّي يا رَسُولَ اللهِ، زُرْتُكَ عارِفاً بِحَقِّكَ، مُقِرّاً بِفَضْلِكَ، مُسْتَبْصِراً بِضَلالَةِ مَنْ خالَفَكَ وَخالَفَ اَهْلَ بَيْتِكَ، عارِفاً بِالْهُدَى الَّذي اَنْتَ عَلَيْهِ، بِاَبي اَنْتَ وَاُمّي وَنَفْسي وَاَهْلي وَمالي وَوَلَدي، اَنَا اُصَلّي عَلَيْكَ كَما صَلَّى اللهُ عَلَيْكَ، وَصَلّى عَلَيْكَ مَلائِكَتُهُ وَاَنْبِياؤُهُ وَرُسُلُهُ، صَلاةً مُتَتابِعَةً وافِرَةً مُتَواصِلَةً لاَ انْقِطاعَ لَها وَلا اَمَدَ وَلا اَجَلَ، صَلَّى اللهُ عَلَيْكَ وَعَلى اَهْلِ بَيْتِكَ الطَّيِّبينَ الطّاهِرينَ كَما اَنْتُمْ اَهْلُهُ ."},{"type":"Text","content":"ثمّ ابسط كفّيك وقل : اَللّـهُمَّ اجْعَلْ جَوامِعَ صَلَواتِكَ، وَنَوامِيَ بَرَكاتِكَ، وَفَواضِلَ خَيْراتِكَ، وَشَرائِفَ تَحِيّاتِكَ وَتَسْليماتِكَ وَكَراماتِكَ وَرَحَماتِكَ وَصَلَواتِ مَلائِكَتِكَ الْمُقَرَّبينَ، وَاَنْبِيائِكَ الْمُرْسَلينَ، وَاَئِمَّتِكَ الْمُنْتَجَبينَ، وَعِبادِكَ الصّالِحينَ، وَاَهْلِ السَّماواتِ وَالاَْرَضينَ، وَمَنْ سَبَّحَ لَكَ يا رَبَّ الْعالَمينَ مِنَ الاَْوَّلينَ وَالاْخِرينَ، عَلى مُحَمَّد عَبْدِكَ وَرَسُولِكَ وَشاهِدِكَ وَنَبِيِّكَ وَنَذيرِكَ وَاَمينِكَ وَمَكينِكَ وَنَجِيِّكَ وَنَجيبِكَ وَحَبيبِكَ وَخَليلِكَ وَصَفيِّكَ وَصَفْوَتِكَ وَخاصَّتِكَ وَخالِصَتِكَ وَرَحْمَتِكَ وَخَيْرِ خِيَرَتِكَ مِنْ خَلْقِكَ، نَبِيِّ الرَّحْمَةِ، وَخازِنِ الْمَغْفِرَةِ، وَقائِدِ الْخَيْرِ وَالْبَرَكَةِ، وَمُنْقِذِ الْعِبادِ مِنَ الْهَلَكَةِ بِاِذْنِكَ، وَداعيهِمْ اِلى دينِكَ الْقَيِّمِ بِاَمْرِكَ، اَوَّلِ النَّبيّينَ ميثاقاً، وَآخِرِهِمْ مَبْعَثاً، الَّذي غَمَسْتَهُ في بَحْرِ الْفَضيلَةِ وَالْمَنْزِلَةِ الْجَليلَةِ، وَالدَّرَجَةِ الرَّفيعَهِ، وَالْمَرْتَبَةِ الْخَطيرَهِ، وَاَوْدَعْتَهُ الاَْصْلابَ الطّاهِرَةَ، وَنَقَلْتَهُ مِنْها اِلَى الاَْرْحامِ الْمُطَهَّرَةِ، لُطْفاً مِنْكَ لَهُ وَتَحَنُّناً مِنْكَ عَلَيْهِ، اِذْ وَكَّلْتَ لِصَوْنِهِ وَحِراسَتِهِ وَحِفْظِهِ وَحِياطَتِهِ مِنْ قُدْرَتِكَ عَيْناً عاصِمَةً، حَجَبْتَ بِها عَنْهُ مَدانِسَ الْعُهْرِ، وَمَعائِبَ السِّفاحِ، حَتّى رَفَعْتَ بِهِ نَواظِرَ الْعِبادِ، وَاَحْيَيْتَ بِهِ مَيْتَ الْبِلادِ، بِاَنْ كَشَفْتَ عَنْ نُورِ وِلادَتِهِ ظُلَمَ الاَْسْتارِ، وَاَلْبَسْتَ حَرَمَكَ بِهِ حُلَلَ الاَْنْوارِ، اَللّـهُمَّ فَكَما خَصَصْتَهُ بِشَرَفِ هذِهِ الْمَرْتَبَةِ الْكَريمَةِ وَذُخْرِ هذِهِ الْمَنْقَبَةِ العَظِيْمَة، صَلِّ عَلَيْهِ كَما وَفي بِعَهْدِكَ، وَبَلَّغَ رِسالاتِكَ، وَقاتَلَ اَهْلَ الْجُحُودِ عَلى تَوْحيدِكَ، وَقَطَعَ رَحِمَ الْكُفْرِ في اِعْزازِ دينِكَ، وَلَبِسَ ثَوْبَ الْبَلْوى في مُجاهَدَةِ اَعْدآئِكَ، وَاَوْجَبْتَ لَهُ بِكُلِّ اَذَىً مَسَّهُ اَوْ كَيْد اَحَسَّ بِهِ مِنَ الْفِئَةِ الَّتي حاوَلَتْ قَتْلَهُ فَضيلَةً تَفُوقُ الْفَضائِلَ، وَيَمْلِكُ بِهَا الْجَزيلَ مِنْ نَوالِكَ، وَقَدْ اَسَرَّ الْحَسْرَةَ، وَاَخْفَى الزَّفْرَةَ، وَتَجَرَّعَ الْغُصَّةَ، وَلَمْ يَتَخَطَّ ما مَثَّلَ لَهُ وَحْيُكَ، اَللّـهُمَّ صَلِّ عَلَيْهِ وَعَلى اَهْلِ بَيْتِهِ صَلاةً تَرْضاها لَهُمْ، وَبَلِّغْهُمْ مِنّا تَحِيَّةً كَثيرَةً وَسَلاماً، وَآتِنا مِنْ لَدُنْكَ في مُوالاتِهِمْ فَضْلاً وَاِحْساناً وَرَحْمَةً وَغُفْراناً، اِنَّكَ ذُو الْفَضْلِ الْعَظيمِ ."},{"type":"Text","content":"ثمّ صلّ أربع ركعات صلاة الزّيارة بسلامين واقرأ فيها ما شئت مِن السّور، فاذا فرغت فسبّح تسبيح الزّهراء (عليها السلام)وقُل :"},{"type":"Text","content":"اَللّـهُمَّ اِنَّكَ قُلْتَ لِنَبِيِّكَ مُحَمَّد صَلّى اللهُ عَلَيْه وَآلِهِ: (وَلَوْ اَنَّهُمْ اِذْ ظَلَمُوا اَنْفُسَهُمْ جاءُوكَ فَاسْتَغْفَرُوا اللهَ وَاسْتَغْفَرَ لَهُمُ الرَّسُولُ لَوَجَدُوا اللهَ تَوّاباً رَحيماً) وَلَمْ اَحْضُرْ زَمانَ رَسُولِكَ عَلَيْهِ وَآلِهِ السَّلامُ، اَللّـهُمَّ وَقَدْ زُرْتُهُ راغِباً تائِباً مِنْ سَيِّئِ عَمَلي، وَمُسْتَغْفِراً لَكَ مِنْ ذُنُوبي ومُقِرّاً لَكَ بِها وَاَنْتَ اَعْلَمُ بِها مِنّي، وَمُتَوَجِّهاً اِلَيْكَ بِنَبِيِّكَ نَبِيِّ الرَّحْمَةِ صَلَواتُكَ عَلَيْهِ وَآلِهِ، فَاجْعَلْني اَللّـهُمَّ بِمُحَمَّد وَاَهْلِ بَيْتِهِ عِنْدَكَ وَجيهاً فِي الدُّنْيا وَالاْخِرَةِ وَمِنَ الْمُقَرَّبينَ، يا مُحَمَّدُ يا رَسُولَ اللهِ، بِاَبي اَنْتَ وَاُمّي يا نَبِيَّ اللهِ يا سَيِّدَ خَلْقِ اللهِ، اِنّي اَتَوَجَّهُ بِكَ اِليَ اللهِ رَبِّكَ وَرَبّي لِيَغْفِرَ لي ذُنُوبي، وَيَتَقَبَّلَ مِنّي عَمَلي، وَيَقْضِيَ لي حَوائِجي، فَكُنْ لي شَفيعاً عِنْدَ رَبِّكَ وَرَبّي، فَنِعْمَ الْمَسْؤُولُ الْمَوْلى رَبّي، وَنِعْمَ الشَّفيعُ اَنْتَ يا مُحَمَّدُ، عَلَيْكَ وَعَلى اَهْلِ بَيْتِكَ السَّلامُ، اَللّـهُمَّ وَاَوْجِبْ لي مِنْكَ الْمَغْفِرَةَ وَالرَّحْمَةَ وَالرِّزْقَ الْواسِعَ الطَّيِّبَ النّافِعَ، كَما اَوْجَبْتَ لِمَنْ اَتى نَبِيَّكَ مُحَمَّداً صَلَواتُكَ عَلَيْهِ وَآلِهِ وَهُوَ حَيُّ، فَاَقَرَّ لَهُ بِذُنُوبِهِ وَاسْتَغْفَرَ لَهُ رَسُولُكَ عَلَيْهِ وَآلِهِ السَّلامُ، فَغَفَرْتَ لَهُ بِرَحْمَتِكَ يا اَرْحَمْ الرّاحِمينَ، اَللّـهُمَّ وَقَدْ اَمَّلْتُكَ وَرَجَوْتُكَ وَقُمْتُ بَيْنَ يَدَيْكَ، وَرَغِبْتُ اِلَيْكَ عَمَّنْ سِواكَ، وَقَدْ اَمَّلْتُ جَزيلَ ثَوابِكَ، وَاِنّي لَمُقِرٌّ غَيْرُ مُنْكِر، وَتائِبُ اِلَيْكَ مِمَّا اقْتَرَفْتُ، وَعائِذٌ بِكَ في هذَا الْمَقامِ مِمّا قَدَّمْتُ مِنَ الاَْعْمالِ التَّي تَقَدَّمْتَ اِلَيَّ فيها وَنَهَيْتَني عَنْها، وَاَوْعَدْتَ عَلَيْهَا الْعِقابَ، وَاَعُوذُ بِكَرَمِ وَجْهِكَ اَنْ تُقيمَني مَقامَ الْخِزْىِ وَالذُّلِّ يَوْمَ تُهْتَكُ فيهِ الاَْسْتارُ، وَتَبْدُو فيهِ الاَْسْرار وَالْفَضائِحُ، وَتَرْعَدُ فيهِ الْفَرائِصُ، يَوْمَ الْحَسْرَةِ وَالنَّدامَةِ، يَوْمَ الاْفِكَةِ، يَوْمَ الاْزِفَةِ، يَوْمَ التَّغابُنِ، يَوْمَ الْفَصْلِ، يَوْمَ الْجَزاءِ، يَوْماً كانَ مِقْدارُهُ خَمْسينَ اَلْفَ سَنَة، يَوْمَ النَّفْخَةِ، يَوْمَ تَرْجُفُ الرّاجِفَةُ تَتْبَعُهَا الرّادِفَهُ، يَوْمَ النَّشْرِ، يَوْمَ الْعَرَضْ، يَوْمَ يَقُومُ النّاسُ لِرَبِّ الْعالَمينَ، يَوْمَ يَفِرُّ الْمَرْءُ مِنْ اَخيهِ وَاُمِّهِ وَاَبيهِ وَصاحِبَتِهِ وَبَنيهِ، يَوْمَ تَشَقَّقُ الاَْرْضُ وَاَكْنافُ السَّماءِ، يَوْمَ تَأتي كُلُّ نَفْس تُجادِلُ عَنْ نَفْسِها، يَوْمِ يُرَدُّونَ اِلَى اللهِ فَيُنَبِّئُهُمْ بِما عَمِلُوا، يَوْمَ لا يُغْني مَوْلىً عَنْ مَوْلىً شَيْئاً وَلا هُمْ يُنْصَرُونَ إلاّ مَنْ رَحِمَ اللهُ اِنَّهُ هُوَ الْعَزيزُ الرَّحيمُ، يَوْمَ يُرَدُّونَ اِلى عالِمِ الْغَيْبِ وَالشَّهادَةِ، يَوْمَ يُرَدُّونَ اِلَى اللهِ مَوْلاهُمُ الْحَقُّ يَوْمَ يَخْرُجُونَ مِنَ الاَْجْداثِ سِراعاً كَاَنَّهُمْ اِلى نُصُب يُوفِضُونَ، وَكَاَنَّهُمْ جَرادٌ مُنْتَشِرٌ مُهْطِعينَ اِلَى الدّاعِ اِلَى اللهِ، يَوْمَ الْواقِعَةِ، يَوْمَ تَرُجُّ الاَْرْضُ رَجّاً، يَوْمَ تَكُونُ السَّماءُ كَالْمُهْلِ، وَتَكُونُ الْجِبالُ كَالْعِهْنِ، وَلا يُسْأَلُ حَميمٌ حَميماً، يَوْمَ الشّاهِدِ وَالْمَشْهُودِ، يَوْمَ تَكُونُ الْمَلائِكَةُ صَفّاً صَفّاً، اَللّـهُمَّ ارْحَمْ مَوْقِفي في ذلِكَ الْيَوْمِ بِمَوْقِفي في هذَا الْيَوْمِ، وَلا تُخْزِني في ذلِكَ الْمَوْقِفِ بِما جَنَيْتُ عَلى نَفْسي، وَاجْعَلْ يا رَبِّ في ذلِكَ الْيَوْمِ مَعَ اَوْلِيائِكَ مُنْطَلَقي، وَفي زُمْرَةِ مُحَمَّد وَاَهْلِ بَيْتِهِ عليهم السلام مَحْشَري، وَاجْعَلْ حَوْضَهُ مَوْرِدي، وَفِي الْغُرِّ الْكِرامِ مَصْدَري، وَاَعْطِني كِتابِي بِيَميني حَتّى اَفُوزَ بِحَسَناتي، وَتُبَيِّضَ بِهِ وَجْهي، وَتُيَسِّرَ بِهِ حِسابِي، وَتُرَجِّحَ بِهِ ميزاني، وَاَمْضِيَ مَعَ الْفائِزينَ مِنْ عِبادِكَ الصّالِحينَ اِلى رِضْوانِكَ وَجِنانِكَ اِلـهَ الْعالَمينَ، اَللّـهُمَّ اِنّي اَعُوذُ بِكَ مِنْ اَنْ تَفْضَحَني في ذلِكَ الْيَوْمِ بَيْنَ يَدَيِ الْخَلايِقِ بِجَريرَتي، اَوْ اَنْ اَلْقَى الْخِزْيَ وَالنَّدامَةَ بِخَطيئَتي، اَوْ اَنْ تُظْهِرَ فيهِ سَيِّئاتِي عَلى حَسَناتي، اَوْ اَنْ تُنَوِّهَ بَيْنَ الْخَلائِقِ بِاسْمي، يا كَريمُ يا كَريمُ، الْعَفْوَ الْعَفْوَ، السَّتْرَ السَّتْرَ، اَللّـهُمَّ وَاَعُوذُ بِكَ مِنْ اَنْ يَكُونَ في ذلِكَ الْيَوْمِ في مَواقِفِ الاَْشْرارِ مَوْقِفي، اَوْ في مَقامِ الاَْشْقياءِ مَقامي، وَاِذا مَيَّزْتَ بَيْنَ خَلْقِكَ فَسُقْتَ كُلاًّ بِاَعْمالِهِمْ زُمَرَاً اِلى مَنازِلِهِمْ فَسُقْني بِرَحْمَتِكَ في عِبادِكَ الصّالِحينَ، وَفي زُمْرَةِ اَوْلِيائِكَ الْمُتَّقينَ اِلى جَنّاتِكَ يا رَبَّ الْعالَمينَ ."},{"type":"Text","content":"ثمّ ودّعه وقل : اَلسَّلامُ عَلَيْكَ يا رَسُولَ اللهِ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الْبَشيرُ النَّذيرُ، اَلسَّلامُ عَلَيْكَ اَيُّهَا السِّراجُ الْمُنيرُ، اَلسَّلامُ عَلَيْكَ اَيُّهَا السَّفيرُ بَيْنَ اللهِ وَبَيْنَ خَلْقِهِ، اَشْهَدُ يا رَسُولَ اللهِ اَنَّكَ كُنْتَ نُوراً فِي الاَْصْلابِ الشّامِخَةِ، وَالاَْرْحامِ الْمُطَهَّرَةِ، لَمْ تُنَجِّسْكَ الْجاهِلِيَّةُ بِاَنْجاسِها، وَلَمْ تُلْبِسْكَ مِنْ مُدْلَهَمّاتِ ثِيابِها، واَشْهَدُ يا رَسُولَ اللهِ اَنّي مُؤْمِنٌ بِكَ وَبِالاَْئِمَّةِ مِنْ اَهْلِ بَيْتِكَ مُوقِنٌ بِجَميعِ ما اَتَيْتَ بِهِ راض مُؤْمِنٌ، وَاَشْهَدُ اَنَّ الاَْئِمَّةَ مِنْ اَهْلِ بَيْتِكَ اَعْلامُ الْهُدى، وَالْعُرْوَةُ الْوُثقى، وَالْحُجَّةُ عَلى اَهْلِ الدُّنْيا، اَللّـهُمَّ لا تَجْعَلْهُ آخِرَ الْعَهْدِ مِنْ زِيارَةِ نَبِيِّكَ عَلَيْهِ وَآلِهِ السَّلامُ، وَاِنْ تَوَفَّيْتَني فَاِنّي اَشْهَدُ في مَماتي عَلى ما اَشْهَدُ عَلَيْهِ في حَياتي اَنَّكَ اَنْتَ اللهُ لا اِلـهَ إلاّ اَنْتَ وَحْدَكَ لا شَريكَ لَكَ، وَاَنَّ مُحَمَّداً عَبْدُكَ وَرَسُولُكَ، وَاَنَّ الاَْئِمَّةَ مِنْ اَهْلِ بَيْتِهِ اَوْلِياؤُكَ وَاَنْصارُكَ وَحُجَجُكَ عَلى خَلْقِكَ، وَخُلَفاؤُكَ في عِبادِكَ، وَاَعْلامُكَ في بِلادِكَ، وَخُزّانُ عِلْمِكَ، وَحَفَظَةُ سِرِّكَ، وَتَراجِمَةُ وحْيِكَ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَبَلِّغْ رُوحَ نَبِيِّكَ مُحَمَّد وَآلِهِ في ساعَتي هذِهِ وَفي كُلِّ ساعَة تَحِيَّةً مِنّي وَسَلاماً، وَالسَّلامُ عَلَيْكَ يا رَسُولَ اللهِ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، لا جَعَلَهُ اللهُ آخِرُ تَسْليمي عَلَيْكَ ."},{"type":"AboutText","content":"قال الشّيخ في المِصباح والسّيد في جمال الاسبوع في ضمن أعمال يوم الجمعة : اعلم يستحبّ في يوم الجُمعة زيارة النّبي (صلى الله عليه وآله وسلم) والائمة (عليهم السلام)، ورويا عن الصّادق (عليه السلام) : انّ من أراد أن يزور قبر رسُول الله وقبر امير المؤمنين وفاطمة والحسن والحسين وقبور الحجج (عليهم السلام) وهو في بلدة فليغتسل في يوم الجمعة وليلبس ثوبين نظيفين وليخرج الى فلاة من الارض، وعلى رواية أخرى وليصعد سطحاً، ثمّ يصلّي أربع ركعات يقرأ فيهنّ ما تيسّر من السّور فاذا تشهّد وسلّم فليقم مستقبل القبلة وليقل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ اَيُّهَا النَّبِىُّ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَلسَّلامُ عَلَيْكَ اَيُّهَا النَّبِىُّ الْمُرْسَلُ، وَالْوَصِىُّ الْمُرْتَضى، وَالسَّيِّدَةُ الْكُبْرى، وَالسَّيِّدَةُ الزَّهْراءُ، وَالسِّبْطانِ الْمُنْتَجَبانِ، وَالاَْوْلادُ الاَْعْلامُ، وَالاُْمَناءُ الْمُنْتَجَبُونَ، جِئْتُ اِنْقِطاعاً اِلَيْكُمْ وَاِلى آبائِكُمْ وَوَلَدِكُمُ الْخَلَفِ، عَلى بَرَكَةِ الْحَقِّ، فَقَلْبي لَكُمْ مُسَلِّمٌ وَنُصْرَتي لَكُمْ مُعَدَّةٌ، حَتّى يَحْكُمَ اللهُ بِدينِهِ، فَمَعَكُمْ مَعَكُمْ لا مَعَ عَدُوِّكُمْ، اِنّي لَمِنَ الْقائِلينَ بِفَضْلِكُمْ، مُقِرٌّ بِرَجْعَتِكُمْ، لا اُنْكِرُ للهِ قُدْرَةً وَلا اَزْعُمُ إلاّ ماشاءَ اللهُ سُبْحانَ اللهِ ذِي الْمُلْكِ وَالْمَلَكُوتِ، يُسَبِّحُ اللهَ بِاَسْمائِهِ جَميعُ خَلْقِهِ، وَالسَّلامُ عَلى اَرْواحِكُمْ وَاَجْسادِكُمْ، وَالسَّلامُ عَلَيْكُمْ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ ."},{"type":"AboutText","content":"أقول : في روايات عديدة انّ النّبي (صلى الله عليه وآله وسلم) يبلغه سلام المُسلمين عليه، وصلوات المُصلّين عليه حيثما كانوا، وفي الحديث انّ ملكاً من الملائكة قد وكلّ على أن يرد على من قال من المؤمنين صَلَّى اللهُ عَلى مُحَمَّد وَآلِهِ وَسَلَّمَ فيقُول في جوابه : وعليك ، ثمّ يقول الملك : يا رسول الله انّ فلاناً يقرؤك السّلام، فيقول رسُول الله (صلى الله عليه وآله وسلم) : وعليه السلام ."},{"type":"AboutText","content":"وفي رواية معتبرة انّ النّبي (صلى الله عليه وآله وسلم) قال : مَن زار قبري بعد وفاتي كان كمن هاجر اليّ في حياتي، فإن لم تستطيعوا أن تزوروا قبري فابعثوا اليّ السّلام فانّه يبلغني، وقد وردت لهذا المعنى اخبار جمّة ونحن قد اثبتنا له صلوات الله عليه زيارتين اثنتين في يومِ الاثنين عند ذكر زيارات الحُجج الطّاهرة في أيّام الاسبُوع فراجعها إن شئت وفُز بفضل الزّيارة بهما، وينبغي أن يصلّي عليه بما صلّى به أمير المؤمنين (عليه السلام)في بعض خُطبه في يومِ الجُمعة ، كما في كتاب الرّوضة من الكافي :"},{"type":"Text","content":"اِنَّ اللهَ وَمَلائِكَتَهُ يُصَلُّونَ عَلَى النَّبِيِّ يا اَيُّها الَّذينَ آمَنُوا صَلُّوا عَلَيْهِ وَسَلِّمُوا تَسْليماً، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَبارِكْ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَتَحَنَّنْ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَسَلِّمْ عَلى مُحَمَّد وَآلِ مُحَمَّد، كَاَفْضَلَ ما صَلَّيْتَ وَبارَكْتَ وَتَرَحَّمْتَ وَتَحَنَّنْتَ وَسَلَّمْتَ عَلى اِبْراهيمَ وَآلِ اِبْراهيمَ اِنَّكَ حَميدٌ مَجيدٌ اَللّـهُمَّ اَعْطِ مُحَمَّدًا الْوَسيلَةَ وَالشَّرَفَ وَالْفَضيلَةَ وَالْمَنْزِلَةَ الْكَريمَةَ، اَللّـهُمَّ اجْعَلْ مُحَمَّداً وَآلَ مُحَمَّد اَعْظَمَ الْخَلائِقِ كُلِّهِمْ شَرَفاً يَوْمَ الْقِيامَةِ، وَاَقْرَبَهُمْ مِنْكَ مَقْعَداً، وَاَوْجَهَهُمْ عِنْدَكَ يَوْمَ الْقِيامَةِ جاهاً وَاَفْضَلَهُمْ عِنْدَكَ مَنْزِلَةً وَنَصيباً، اَللّـهُمَّ اَعْطِ مُحَمَّداً اَشْرَفَ الْمَقامِ، وَحِباءَ السَّلامِ، وَشَفاعَةَ الاِْسْلامِ، اَللّـهُمَّ وَاَلْحِقْنا بِهِ غَيْرَ خَزايا وَلا ناكِثينَ وَلا نادِمينَ وَلا مُبَدِّلينَ، اِلـهَ الْحَقِّ آمينَ ."}],"preview":"اذا وردت ان شاء الله تعالى مدينة النّبي (صلى الله عليه وآله وسلم) فاغتسل للزّيارة فاذا أردت دخول مسجده (صلى الله عليه وآله وسلم) فقف على الباب واستأذن بالاستئذان الاوّل ممّا ذكرناه","hasTranslate":false},{"id":"mf_ar_186","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الفَصلُ الثّالِثُ :","title":"وستأتي في آخر باب الزّيارات صلاة يصلّي بها عليه وعلى آله (عليهم السلام)","blocks":[{"type":"Text","content":"زِيارَة اَئمَّة البَقيع عليهم السلام"},{"type":"Text","content":"أي الامام الحسن المجتبى، والامام زين العابدين، والامام محمّد الباقر، والامام جعفر الصّادق (عليهم السلام) ."},{"type":"Text","content":"اذا أردت زيارتهم فاعمل بما سبق من آداب الزّيارة من الغسل والكون على الطّهارة ولبس الثّياب الطّاهرة النّظيفة والتّطيّب والاستئذان للدّخول ونحو ذلك وقُل أيضاً :"},{"type":"Text","content":"يا مَوالِيَّ يا اَبْناءَ رَسُولِ اللهِ، عَبْدُكُمْ وَابْنُ اَمَتِكُمُ الذَّليلُ بَيْنَ اَيْديكُمْ، وَالْمُضْعِفُ في عُلُوِّ قَدْرِكُمْ، وَالْمُعْتَرِفُ بِحَقِّكُمْ، جاءَكُمْ مُسْتَجيراً بِكُمْ، قاصِداً اِلى حَرَمِكُمْ، مُتَقَرِّباً اِلى مَقامِكُمْ، مُتَوَسِّلاً اِلَى اللهِ تَعالى بِكُمْ، أَدْخُلُ يا مَوالِيَّ، أَدْخُلُ يا اَوْلِياءَ اللهِ، أَدْخُلُ يا مَلائِكَةَ اللهِ الُْمحْدِقينَ بِهذَا الْحَرَمِ الْمُقيمينَ بِهذَا الْمَشْهَدِ ."},{"type":"Text","content":"وادخل بعد الخشُوع والخضُوع ورقّة القلب وقدّم رجلك اليمنى وقُل :"},{"type":"Text","content":"اَللهُ اَكْبَرُ كَبيراً، وَالْحَمْدُ للهِ كَثيراً، وَسُبْحانَ اللهِ بُكْرَةً وَاَصيلاً، وَالْحَمْدُ للهِ الْفَرْدِ الصَّمَدِ الْماجِدِ الاَْحَدِ الْمُتَفَضِّلِ الْمَنّانِ، الْمُتَطَوِّلِ الْحَنّانِ الَّذي مَنَّ بِطَوْلِهِ، وَسَهَّلَ زِيارَةَ ساداتي بِاِحْسانِهِ، وَلَمْ يَجْعَلْني عَنْ زِيارَتِهِمْ مَمْنُوعاً بَلْ تَطَوَّلَ وَمَنَحَ ."},{"type":"Text","content":"ثمّ اقترب من قبُورهم المقدّسة واستقبلها واستدبر القبلة وَقُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكُمْ اَئِمَّةَ الْهُدى، اَلسَّلامُ عَلَيْكُمْ اَهْلَ التَّقْوى، اَلسَّلامُ عَلَيْكُمْ اَيُّهَا الْحُجَجُ على اَهْلِ الدُّنْيا، اَلسَّلامُ عَلَيْكُمْ اَيُّهَا الْقُوّامُ في الْبَرِيَّةِ بِالْقِسْطِ، اَلسَّلامُ عَلَيْكُمْ اَهْلَ الصَّفْوَةِ، اَلسَّلامُ عَلَيْكُمْ آلَ رَسُولِ اللهِ، اَلسَّلامُ عَلَيْكُمْ اَهْلَ النَّجْوى، اَشْهَدُ اَنَّكُمْ قَدْ بَلَّغْتُمْ وَنَصَحْتُمْ وَصَبَرْتُمْ في ذاتِ اللهِ، وَكُذِّبْتُمْ وَاُسيءَ اِلَيْكُمْ فَغَفَرْتُمْ، وَاَشْهَدُ اَنَّكُمُ الاَْئِمَّةُ الرّاشِدُونَ الْمُهْتَدُونَ، وَاَنَّ طاعَتَكُمْ مَفْرُوضَةٌ، وَاَنَّ قَوْلَكُمُ الصِّدْقُ، وَاَنَّكُمْ دَعْوَتُمْ فَلَمْ تُجابُوا، وَاَمَرْتُمْ فَلَمْ تُطاعُوا، وَاَنَّكُمْ دَعائِمُ الدّينِ وَاَرْكانُ الاَْرْضِ، لَمْ تَزالُوا بِعَيْنِ اللهِ يَنْسَخُكُمْ مِنْ اَصْلابِ كُلِّ مُطَّهَر، وَيَنْقُلُكُمْ مِنْ اَرْحامِ الْمُطَهَّراتِ، لَمْ تُدَنِّسْكُمُ الْجاهِلِيَّةُ الْجَهْلاءُ، وَلَمْ تَشْرَكْ فيكُمْ فِتَنُ الاَْهْواءِ، طِبْتُمْ وَطابَ مَنْبَتُكُمْ، مَنَّ بِكُمْ عَلَيْنا دَيّانُ الدّينِ، فَجَعَلَكُمْ في بُيُوت اَذِنَ اللهُ اَنْ تُرْفَعَ وَيُذْكَرَ فيهَا اسْمُهُ، وَجَعَلَ صَلَاتَنا عَلَيْكُمْ رَحْمَةً لَنا وَكَفّارَةً لِذُنُوبِنا، اِذِ اخْتارَكُمُ اللهُ لَنا، وَطَيَّبَ خَلْقَنا بِما مَنَّ عَلَيْنا مِنْ وِلايَتِكُمْ، وَكُنّا عِنْدَهُ مُسَمِّينَ بِعِلْمِكُمْ، مُعْتَرِفينَ بِتَصْديقِنا اِيّاكُمْ، وَهذا مَقامُ مَنْ اَسْرَفَ وَاَخْطَاَ وَاسْتَكانَ وَاَقَرَّ بِما جَنى وَرَجا بِمَقامِهِ الْخَلاصَ، وَاَنْ يَسْتَنْقِذَهُ بِكُمْ مُسْتَنْقِذُ الْهَلْكى مِنَ الرَّدى، فَكُونُوا لي شُفَعاءَ، فَقَدْ وَفَدْتُ اِلَيْكُمْ اِذْ رَغِبَ عَنْكُمْ اَهْلُ الدُّنْيا، وَاتَّخَذُوا آياتِ اللهِ هُزُواً وَاسْتَكْبَرُوا عَنْها (ثم ارفع رأسك الى السماء وقل:) يا مَنْ هُوَ قائِمٌ لا يَسْهُو، وَدائِمٌ لا يَلْهُو، وَمُحيطٌ بِكُلِّ شَىْء لَكَ الْمَنُّ بِما وَفَّقْتَني وَعَرَّفْتَني بِما اَقَمْتَني عَلَيْهِ، اِذْ صَدَّ عَنْهُ عِبادُكَ، وَجَهِلُوا مَعْرِفَتَهُ، وَاسْتَخَفُّوا بِحَقِّهِ، وَمالُوا اِلى سِواهُ، فَكانَتِ الْمِنَّةُ مِنْكَ عَلَيَّ مَعَ اَقْوام خَصَصْتَهُمْ بِما خَصَصْتَني بِهِ، فَلَكَ الْحَمْدُ اِذْ كُنْتُ عِنْدَكَ في مَقامي هذا مَذْكُوراً مَكْتُوباً، فَلا تَحْرِمْني ما رَجَوْتُ، وَلا تُخَيِّبْني فيـما دَعَوْتُ، بِحُرْمَةِ مُحَمَّد وَآلِهِ الطّاهِرينَ، وَصَلَّى اللهُ عَلى مُحَمَّد وَآلِ مُحَمَّد ."},{"type":"Text","content":"ثمّ ادعُ لنفسك بما تُريد ، وقال الطّوسي (رحمه الله) في التّهذيب: ثمّ صلّ صلاة الزّيارة ثمان ركعات أي صلّ لكلّ امام ركعتين ."},{"type":"Text","content":"وقال الشّيخ الطّوسي والسّيد ابن طاووس : اذا أردت أن تودّعهم (عليهم السلام) فقُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكُمْ اَئِمَّةَ الْهُدى وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَسْتَوْدِعُكُمُ اللهَ وَاَقْرَأُ عَلَيْكُمُ السَّلامَ، آمَنّا بِاِللهِ وَبِالرَّسُولِ، وَبِما جِئْتُمْ بِهِ وَدَلَلْتُمْ عَلَيْهِ، اَللّـهُمَّ فَاكْتُبْنا مَعَ الشّاهِدينَ ."},{"type":"Text","content":"ثمّ اكثر من الدّعاء وسل الله العود وأن لا تكون هذه آخر عهدك من زيارتهم، والعلامة المجلسي (رحمه الله) قد أورد في البحار زيارة مبسُوطة لهم (عليهم السلام)، ونحن هُنا قد اقتصرنا على ما مضى من زيارتهم فانّ أفضل الزّيارات لهم (عليهم السلام) هي الزّيارة الجامعة الاتية على ما صرّح به المجلسي وغيره، وفي الباب الاوّل من الكتاب عند ذكر زيارات الحجج الطّاهرة موزعة على أيّام الاسبُوع قد اثبتنا زيارة للحسن (عليه السلام) وزيارة اخرى للائمة الثّلاثة الاخرون بالبقيع فلا تغفل عنها، واعلم انّا نورد لكلّ من الحجج الطّاهرين عند ذكر زيارته كيفيّة الصّلاة عليه سوى ائمة البقيع حيث اقتصرنا في الصلاة عليهم بما سيذكر في آخر باب الزّيارات فلاحظها هُناك وثقّل ميزان حسناتك بالصّلاة عليهم، واعلم ايضاً انّ شدّة شوقي أنا المهجور الكسير الى تلك المشاهد الشريفة تبعثني على أن اشغل خاطرى بايراد عدّة ابيات تناسب المقام من القصيدة الهائية للفاضل الاوحد مادح آل احمد حضرة الشّيخ الاُزري رضوان الله عليه، وكان شيخ الفقهاء العظام خاتم المجتهدين الفخام الشّيخ محمّد حسن صاحب الجواهر يتمنّى على ما يروى عنه أن تكتب له القصيدة في ديوان أعماله، ويسجّل كتاب الجواهر في ديوان اعمال الاُزري قال (رحمه الله) :"},{"type":"Text","content":"اِنَّ تِلْكَ الْقُلُوبَ اَقْلَقَها الْوَجْدُ وَاَدْمى تِلْكَ الْعُيُونَ بُكاها"},{"type":"Text","content":"كانَ اَنْكَى الْخُطُوبِ لَمْ يُبْكِ مِنّي مُقْلَةً لكِنِ الْهَوى اَبْكاها"},{"type":"Text","content":"كُلَّ يَوْم لِلْحادِثاتِ عَواد لَيْسَ يَقْوى رَضْوى عَلى مُلْتَقاها"},{"type":"Text","content":"كَيْفَ يُرْجَى الْخَلاصُ مِنْهُنَّ إلاّ بِذِمام مِنْ سَيِّدِ الرُّسْلِ طه"},{"type":"Text","content":"مَعْقِلُ الْخائِفِينَ مِنْ كُلِّ خَوْف اَوْفَرُ الْعُرْبِ ذِمَّةً اَوْفاها"},{"type":"Text","content":"مَصْدَرُ الْعِلْمِ لَيْسَ إلاّ لَدَيْهِ خَبَرُ الْكائِناتِ مِنْ مُبْتَداها"},{"type":"Text","content":"فاضَ لِلْخَلْقِ مِنْهُ عِلْمٌ وَحِلْمٌ اَخَذَتْ مِنْهُمَا الْعُقُولُ نُهاها"},{"type":"Text","content":"نَوَّهَتْ بِاسْمِهِ السَّماواتُ وَالاَْرْ ضُ كَما نَوَّهَتْ بِصُبْح ذُكاها"},{"type":"Text","content":"وَغَدَتْ تَنْشُرُ الْفَضائِلَ عَنْهُ كُلُّ قَوْم عَلَى اخْتِلافِ لُغاها"},{"type":"Text","content":"طَرِبَتْ لاِسْمِهِ الثَّرى فَاسْتَطالَتْ فَوْقَ عُلْوِيَّةِ السَّما سُفْلاها"},{"type":"Text","content":"جازَ مِنْ جَوْهَرِ التَّقَدُّسِ ذاتاً تاهَتِ الاَْنْبِياءُ في مَعْناها"},{"type":"Text","content":"لا تُجِلْ في صِفاتِ اَحْمَدَ فِكْراً فَهِيَ الصُّورَةُ الَّتي لَنْ تَراها"},{"type":"Text","content":"اَىُّ خَلْق للهِ اَعْظَمُ مِنْهُ وَهُوَ الْغايَةُ الَّتِي اسْتَقْصاها"},{"type":"Text","content":"قَلَّبَ الْخافِقَيْنِ ظَهْراً لِبَطْن فَرَآى ذاتَ اَحْمَد فَاجْتَباها"},{"type":"Text","content":"لَسْتُ اَنْسى لَهُ مَنازِلَ قُدْس قَدْ بَناها التُّقى فَاَعْلا بِناها"},{"type":"Text","content":"وَرِجالاً اَعِزَّةً في بُيُوت اَذِنَ اللهُ اَنْ يُعَزَّ حِماها"},{"type":"Text","content":"سادَةٌ لا تُريدُ إلاّ رِضَى اللهِ كَما لا يُريدُ إلاّ رِضاها"},{"type":"Text","content":"خَصَّها مِنْ كَمالِهِ بِالْمَعاني وَبِاَعْلى اَسْمائِهِ سَمّاها"},{"type":"Text","content":"لَمْ يَكُونُوا لِلْعَرْشِ إلاّ كُنُوزاً خافِيات سُبْحانَ مَنْ اَبْداها"},{"type":"Text","content":"كَمْ لَهُمْ أَلْسُنٌ عَنِ اللهِ تُنْبي هِيَ اَقْلامُ حِكْمَة قَدْ بَراها"},{"type":"Text","content":"وَهُمُ الاَْعْيُنُ الصَّحيحاتُ تَهْدي كُلَّ عَيْن مَكْفُوفَة عَيْناها"},{"type":"Text","content":"عُلَماءٌ اَئِمَّةٌ حُكَماءٌ يَهْتَدِى النَّجْمُ بِاِتِّباعِ هُداها"},{"type":"Text","content":"قادَةٌ عِلْمُهُم وَرَأىُ حِجاهُم مَسْمَعا كُلِّ حِكْمَة مَنْظَراها"},{"type":"Text","content":"ما اُبالي وَلَوْ اُهيلَتْ عَلَى الاَْرْ ضِ السَّماواتُ بَعْدَ نَيْلِ وِلاها"},{"type":"Text","content":"ذِكر سائر الزّيارات في المَدينة الطّيّبة نَقلاً عن مِصباحُ الزّائر وغَيره"}],"preview":"زِيارَة اَئمَّة البَقيع عليهم السلام","hasTranslate":false},{"id":"mf_ar_187","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الفَصلُ الثّالِثُ :","title":"زيارة ابراهيم ابن رسول الله (صلى الله عليه وآله وسلم) : تقف عند القبر وتقول :","blocks":[{"type":"Text","content":"اَلسَّلامُ عَلى رَسُولِ اللهِ، اَلسَّلامُ عَلى نَبِيِّ اللهِ، اَلسَّلامُ عَلى حَبيبِ اللهِ، اَلسَّلامُ عَلى صَفِىِّ اللهِ، اَلسَّلامُ عَلى نَجِيِّ اللهِ، اَلسَّلامُ عَلى مُحَمَّدِ بْنِ عَبْدِ اللهِ سَيِّدِ الاَْنْبِياءِ، وَخاتَمِ الْمُرْسَلينَ، وَخِيَرَةِ اللهِ مِنْ خَلْقِهِ في اَرْضِهِ وَسَمائِهِ، اَلسَّلامُ عَلى جَميعِ اَنْبِيائِهِ وَرُسُلِهِ، اَلسَّلامُ عَلَى الشُّهَداءِ وَالسُّعَداءِ وَالصّالِحينَ، اَلسَّلامُ عَلَيْنا وَعَلى عِبادِ اللهِ الصّالِحينَ، اَلسَّلامُ عَلَيْكَ اَيَّتُهَا الرُّوحُ الزّاكِيَةُ، اَلسَّلامُ عَلَيْكَ اَيَّتُهَا النَّفْسُ الشَّريفَةُ، اَلسَّلامُ عَلَيْكَ اَيَّتُهَا السُّلالَةُ الطّاهِرَةُ، اَلسَّلامُ عَلَيْكَ اَيَّتُهَا النَّسَمَةُ الزّاكِيَةُ، اَلسَّلامُ عَلَيْكَ يَابْنَ خَيْرِ الْوَرى، اَلسَّلامُ عَلَيْكَ يَابْنَ النَبِيِّ الُْمجْتَبى، اَلسَّلامُ عَلَيْكَ يَابْنَ الْمَبْعُوثِ اِلى كافَّةِ الْوَرى، اَلسَّلامُ عَلَيْكَ يَابْنَ الْبَشيرِ النَّذيرِ، اَلسَّلامُ عَلَيْكَ يَابْنَ السِّراجِ الْمُنير، اَلسَّلامُ عَلَيْكَ يَابْنَ الْمُؤَيَّدِ بِالْقُرآنِ، اَلسَّلامُ عَلَيْكَ يَابْنَ الْمُرْسَلِ اِلَى الاِنْسِ وَالْجانِّ، اَلسَّلامُ عَلَيْكَ يَابْنَ صاحِبِ الرّايَةِ وَالْعَلامَةِ، اَلسَّلامُ عَلَيْكَ يَابْنَ الشَّفيعِ يَوْمَ الْقِيامَةِ، اَلسَّلامُ عَلَيْكَ يَابْنَ مَنْ حَباهُ اللهُ بِالْكَرامَةِ، اَلسَّلامُ عَلَيْكَ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَشْهَدُ اَنَّكَ قَدِ اخْتارَ اللهُ لَكَ دارَ اِنْعامِهِ قَبْلَ اَنْ يَكْتُبَ عَلَيْكَ اَحْكامَهُ اَوْ يُكَلِّفَكَ حَلالَهُ وَحَرامَهُ، فَنَقَلَكَ اِلَيْهِ طَيِّباً زاكِياً مَرْضِيِّاً طاهِراً مِنْ كُلِّ نَجَس، مُقَدَّساً مِنْ كُلِّ دَنَس، وَبَوَّأَكَ جَنَّةَ الْمَأوى، وَرَفَعَكَ اِلَى الدَّرَجاتِ الْعُلى، وَصَلَّى اللهُ عَلَيْكَ صَلاةً تَقَرُّ بِها عَيْنُ رَسُولِهِ، وَتُبَلِّغُهُ اَكْبَرَ مَأمُولِهِ، اَللّـهُمَّ اجْعَلْ اَفْضَلَ صَلَواتِكَ وَاَزْكاها، وَاَنْمى بَرَكاتِكَ وَاَوْفاها، عَلى رَسُولِكَ وَنَبِيِّكَ وَخِيَرَتِكَ مِنْ خَلْقِكَ مُحَمَّد خاتَمِ النَّبِيّينَ، وَعَلى مَنْ نَسَلَ مِنْ اَوْلادِهِ الطَّيِّبينَ، وَعَلى مَنْ خَلَّفَ مِنْ عِتْرَتِهِ الطّاهِرينَ، بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِحَقِّ مُحَمَّد صَفِيِّكَ، وَاِبْراهِيمَ نَجْلِ نَبِيِّكَ، اَنْ تَجْعَلَ سَعْيي بِهِمْ مَشْكوراً وَذَنْبي بَهم مَغفوراً وحياتي بهم سعيدة وعاقبتي بهم حميدة وحوائجي بهم مَقْضِيَّةً، وَاَفْعالِي بِهِمْ مَرْضِيَّةً، وَاُمُوري بِهِمْ مَسْعُودَةً، وَشُؤُوني بِهِمْ مَحْمُودَةً، اَللّـهُمَّ وَاَحسِنْ لِيَ التَّوْفيقَ، وَنَفِّسْ عَنِّي كُلَّ هَمّ وَضيق، اَللّـهُمَّ جَنِّبْني عِقابَكَ، وَامْنَحْني ثَوابَكَ، وَاَسْكِنِّي جِنانَكَ، وَارْزُقْني رِضْوانَكَ وَاَمانَكَ، وَاَشْرِكْ لي في صالِح دُعائي والِدَىَّ وَوَلَدي وَجَميعَ الْمُؤمِنينَ وَالمُؤْمِناتِ، الاَْحْياءَ مِنْهُمْ وَالاَْمْواتَ اِنَّكَ وَلِيُّ الْباقِياتِ الصّالِحاتِ، آمينَ رَبَّ الْعالَمينَ ."},{"type":"Text","content":"ثمّ تسأل حوائجك وتُصلّي ركعتين ."}],"preview":"اَلسَّلامُ عَلى رَسُولِ اللهِ، اَلسَّلامُ عَلى نَبِيِّ اللهِ، اَلسَّلامُ عَلى حَبيبِ اللهِ، اَلسَّلامُ عَلى صَفِىِّ اللهِ، اَلسَّلامُ عَلى نَجِيِّ اللهِ، اَلسَّلامُ عَلى مُحَمَّدِ","hasTranslate":false},{"id":"mf_ar_188","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الفَصلُ الثّالِثُ :","title":"تقف عند قبرها وتقول :","blocks":[{"type":"Text","content":"اَلسَّلامُ عَلى نَبِيِّ اللهِ، اَلسَّلامُ عَلى رَسُولِ اللهِ، اَلسَّلامُ عَلى مُحَمَّد سَيِّدِ الْمُرْسَلينَ، اَلسَّلامُ عَلى مُحَمَّد سَيِّدِ الاَْوَّلينَ، اَلسَّلامُ عَلى مُحَمَّد سَيِّدِ الاْخِرينَ، اَلسَّلامُ عَلى مَنْ بَعَثَهُ اللهُ رَحْمَةً لِلْعالَمينَ، اَلسَّلامُ عَلَيْكَ اَيُّهَا النَّبِيُّ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَلسَّلامُ عَلى فاطِمَةَ بِنْتِ اَسَد الْهاشِمِيَّةِ، اَلسَّلامُ عَلَيْكِ اَيَّتُهَا الصِّدّيقَةُ الْمَرْضِيَّةُ، اَلسَّلامُ عَلَيْكِ اَيَّتُهَا التَّقِيَّةُ النَّقِيَّةُ، اَلسَّلامُ عَلَيْكِ اَيَّتُهَا الْكَريمَةُ الرَّضِيَّةُ، اَلسَّلامُ عَلَيْكِ يا كافِلَةَ مُحَمَّد خاتَمِ النَّبِيّينَ، اَلسَّلامُ عَلَيْكِ يا والِدَةَ سَيِّدِ الْوَصِيّينَ، اَلسَّلامُ عَلَيْكِ يا مَنْ ظَهَرَتْ شَفَقَتُها عَلى رَسُولِ اللهِ خاتَمِ النَّبيّينَ، اَلسَّلامُ عَلَيْكِ يا مَنْ تَرْبِيَتُها لِوَلِىِّ اللهِ الاَْمينِ، اَلسَّلامُ عَلَيْكِ وَعَلى رُوحِكِ وَبَدَنِكِ الطّاهِرِ، اَلسَّلامُ عَلَيْكِ وَعَلى وَلَدِكِ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَشْهَدُ اَنَّكِ اَحْسَنْتِ الْكِفالَةَ، وَاَدَّيْتِ الاَْمانَةَ، وَاجْتَهَدْتِ في مَرْضاتِ اللهِ، وَبالَغْتِ في حِفْظِ رَسُولِ اللهِ، عارِفَةً بِحَقِّهِ، مُؤْمِنَةً بِصِدْقِهِ، مُعْتَرِفَةً بِنُبُوَّتِهِ، مُسْتَبْصِرَةً بِنِعْمَتِهِ، كافِلَةً بِتَرْبِيَتِهِ، مُشْفِقَةً عَلى نَفْسِهِ، واقِفَةً عَلى خِدْمَتِهِ، مُخْتارَةً رِضاهُ، وَاَشْهَدُ اَنَّكِ مَضَيْتِ عَلَى الاِْيْمانِ وَالَّتمَسُّكِ بِاَشْرَفِ الاَْدْيانِ، راضِيَةً مَرْضِيَّةً طاهِرَةً زَكِيَّةً تَقِيَّةً نَقِيَّةً، فَرَضِيَ اللهُ عَنْكِ وَاَرْضاكِ، وَجَعَلَ الْجَنَّةَ مَنْزِلَكِ وَمَأواكِ اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَانْفَعْني بِزِيارَتِها، وَثَبِّتْني عَلى مَحَبَّتِها، وَلا تَحْرِمْني شَفاعَتَها، وَشَفاعَةَ الاَْئِمَّةِ مِنْ ذُرِّيَّتِها، وَارْزُقْني مُرافَقَتَها، وَاحْشُرْني مَعَها وَمَعَ اَوْلادِهَا الطّاهِرينَ، اَللّـهُمَّ لا تَجْعَلْهُ آخِرَ الْعَهْدِ مِنْ زِيارَتي اِيّاها، وَارْزُقْنِي الْعَوْدَ اِلَيْها اَبَداً ما اَبْقَيْتَني، وَاِذا تَوَفَّيْتَني فَاحْشُرْني في زُمْرَتِها، وَاَدْخِلْني في شَفاعَتِها، بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمِينَ، اَللّـهُمَّ بِحَقِّها عِنْدَكَ وَمَنْزِلَتَها لَدَيْكَ، اِغْفِرْ لي وَلِوالِدَىَّ وَلِجَمِيعِ الْمُؤْمِنينَ وَالْمُؤْمِناتِ، وَآتِنا فِي الدُّنْيا حَسَنَةً وَفِي الاْخِرَةِ حَسَنَةً وَقِنا بِرَحْمَتِكَ عَذابَ النّارِ ."},{"type":"Text","content":"ثمّ تصلّي ركعتين للزّيارة وتدعُو بما تشاء وتنصرف :"}],"preview":"اَلسَّلامُ عَلى نَبِيِّ اللهِ، اَلسَّلامُ عَلى رَسُولِ اللهِ، اَلسَّلامُ عَلى مُحَمَّد سَيِّدِ الْمُرْسَلينَ، اَلسَّلامُ عَلى مُحَمَّد سَيِّدِ الاَْوَّلينَ، اَلسَّلامُ عَلى مُحَمَّ","hasTranslate":false},{"id":"mf_ar_189","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الفَصلُ الثّالِثُ :","title":"تقول عند قبره اذا مضيت لزيارَته :","blocks":[{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا عَمَّ رَسُولِ اللهِ صَلَّى اللهُ عَلَيْهِ وَآلِه، اَلسَّلامُ عَلَيْكَ يا خَيْرَ الشُّهَداءِ، اَلسَّلامُ عَلَيْكَ يا اَسَدَ اللهِ وَاَسَدَ رَسُولِهِ، اَشْهَدُ اَنَّكَ قَدْ جاهَدْتَ فِي اللهِ عَزَّوَجَلَّ، وَجُدْتَ بِنَفْسِكَ، وَنَصَحْتَ رَسُولَ اللهِ صَلَّى اللهُ عَلَيْهِ وَآلِهِ، وَكُنْتَ فيـما عِنْدَ اللهِ سُبْحانَهُ راغِباً، بَاِبي اَنْتَ وَاُمّي اَتَيْتُكَ مُتَقَرِّباً اِلى رَسُولِ اللهِ صَلَّى اللهُ عَلَيْهِ وَآلِهِ بِذلِكَ راغِباً اِلَيْكِ فِي الشَّفاعَةِ، اَبْتَغي بِزِيارَتِكَ خَلاصَ نَفْسي، مُتَعَوِّذاً بِكَ مِنْ نار اسْتَحَقَّها مِثْلي بِما جَنَيْتُ عَلى نَفْسي، هارِباً مِنْ ذُنُوبِيَ الَّتي احْتَطَبْتُها عَلى ظَهْري، فَزِعاً اِلَيْكَ رَجاءَ رَحْمَةِ رَبّي، اَتَيْتُكَ مِنْ شُقَّة بَعيدَة طالِباً فَكاكَ رَقَبَتي مِنَ النّارِ، وَقَدْ اَوْقَرَتْ ظَهْري ذُنُوبي، وَاَتَيْتُ ما اَسْخَطَ رَبّي، وَلَمْ اَجِدْ اَحَدًا اَفْزَعُ اِلَيْهِ خَيْراً لي مِنْكُمْ اَهْلَ بَيْتِ الرَّحْمَةِ، فَكُنْ لي شَفيعاً يَوْمَ فَقْري وَحاجَتي، فَقَدْ سِرْتُ اِلَيْكَ مَحْزُوناً، وَاَتَيْتُكَ مَكْرُوباً، وَسَكَبْتُ عَبْرَتي عِنْدَكَ باكِياً، وَصِرْتُ اِلَيْكَ مُفْرَداً، وَاَنْتَ مِمَّنْ اَمَرَنِي اللهُ بِصِلَتِهِ، وَحَثَّني عَلى بِرِّهِ، وَدَلَّني عَلى فَضْلِهِ، وَهَداني لِحُبِّهِ، وَرَغَّبَني فِي الْوِفادَةِ اِلَيْهِ، وَاَلْهَمَني طَلَبَ الْحَوائِجِ عِنْدَهُ، اَنْتُمْ اَهْلُ بَيْت لا يَشْقى مَنْ تَوَلاّكُمْ، وَلا يَخيبُ مَنْ اَتاكُمْ، وَلا يَخْسَرُ مَنْ يَهْواكُمْ وَلا يَسْعَدُ مَنْ عاداكُمْ ."},{"type":"Text","content":"ثمّ تستقبل القبلة وتصلّي ركعتين للزّيارة وبعد الفراغ تنكبّ على القبر وتقول :"},{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، اَللّـهُمَّ اِنّي تَعَرَّضْتُ لِرَحْمَتِكَ بِلُزُومي لِقَبْرِ عَمِّ نَبِيِّكَ صَلَّى اللهُ عَلَيْهِ وَآلِهِ لِيُجيرَني مِنْ نِقْمَتِكَ وَسَخَطِكَ وَمَقْتِكَ في يَوْم تَكْثُرُ فيهِ الاَْصْواتُ، وَتَشْغَلُ كُلُّ نَفْس بِما قَدَّمَتْ، وَتُجادِلُ عَنْ نَفْسِها، فَاِنْ تَرْحَمْنِي الْيَوْمَ فَلا خَوْفٌ عَلَيَّ وَلا حُزْنٌ، وَاِنْ تُعاقِبْ فَمَوْلىً لَهُ الْقُدْرَةُ عَلى عَبْدِهِ، وَلا تُخَيِّبْني بَعْدَ الْيَوْمِ، وَلا تَصْرِفْني بِغَيْرِ حاجَتي، فَقَدْ لَصِقْتُ بِقَبْرِ عَمِّ نَبِيِّكَ، وَتَقَرَّبْتُ بِهِ اِلَيْكَ ابْتِغاءَ مَرْضاتِكَ، وَرَجاءَ رَحْمَتِكَ، فَتَقَبَّلْ مِنّي، وَعُدْ بِحِلْمِكَ عَلى جَهْلي، وَبِرَأفَتِكَ عَلى جِنايَةِ نفْسي، فَقَدْ عَظُمَ جُرْمي، وَما اَخافُ اَنْ تَظْلِمَني وَلكِنْ اَخافُ سُوءَ الْحِسابِ، فَانْظُرِ الْيَوْمَ تَقَلُّبىِ عَلى قَبْرِ عَمِّ نَبِيِّكَ، فَبِهِما فُكَّني مِنَ النّارِ وَلا تُخَيِّبْ سَعْيي، وَلا يَهُونَنَّ عَلَيْكَ ابْتِهالي، وَلا تَحْجُبَنَّ عَنْكَ صَوْتي، وَلا تَقْلِبْني بِغَيْرِ حَوائِجي، يا غِياثَ كُلِّ مَكْرُوب وَمَحْزُون، وَيا مُفَرِّجاً عَنِ الْمَلْهُوفِ الْحَيْرانِ الْغَريقِ الْمُشْرِفِ عَلَى الْهَلَكَةِ، فَصَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَانْظُرْ اِلَيَّ نَظْرَةً لا اَشْقى بَعْدَها اَبَداً، وَارْحَمْ تَضَرُّعي وَعَبْرَتي وَانْفِرادي، فَقَدْ رَجَوْتُ رِضاكَ، وَتَحَرَّيْتُ الْخَيْرَ الَّذي لا يُعْطيهِ اَحَدٌ سِواكَ، فَلا تَرُدَّ اَمَلي، اَللّـهُمَّ اِنْ تُعاقِبْ فَمَوْلىً لَهُ الْقُدْرَةُ عَلى عَبْدِهِ، وَجَزائُهِ بِسُوءِ فِعْلِهِ، فَلا اَخيبَنَّ الْيَوْمَ، وَلا تَصْرِفْني بِغَيْرِ حاجَتي، وَلا تُخَيِّبَنَّ شُخُوصي وَوِفادَتي، فَقَدْ اَنْفَدْتُ نَفَقَتي، وَاَتْعَبْتُ بَدَني، وَقَطَعْتُ الْمَفازاتِ، وَخَلَّفْتُ الاَْهْلَ وَالْمالَ وَما خَوَّلْتَني، وَآثَرْتُ ما عِنْدَكَ عَلى نَفْسي، وَلُذْتُ بِقَبْرِ عَمِّ نَبِيِّكَ صَلَّى اللهُ عَلَيْهِ وَآلِهِ، وَتَقَرَّبْتُ بِهِ ابْتِغاءَ مَرْضاتِكَ، فَعُدْ بِحِلْمِكَ عَلى جَهْلي، وَبِرَأفَتِكَ عَلى ذَنْبي، فَقَدْ عَظُمَ جُرْمي بِرَحْمَتِكَ يا كَريمُ يا كَريمُ ."},{"type":"AboutText","content":"أقول : فضائل حمزة سلام الله عليه وفضل زيارته اكثر من أن يذكر وقال فخر المحقّقين (رحمه الله) في الرّسالة الفخريّة يستحبّ زيارة حمزة (رضي الله عنه) وباقي الشّهداء باُحد لما روي عن النّبي (صلى الله عليه وآله وسلم) انّه قال : من زارني ولم يزر عمّي حمزة فقد جفاني ."},{"type":"Text","content":"وأقول : انّي قد ذكرت في كتاب بيت الاحزان في مصائب سيّدة النّسوان انّ فاطمة صلوات الله عليها كانت تخرج يومي الاثنين والخميس من كلّ اسبوع بعد وفاة أبيها الى زيارة حمزة وباقي شُهداء اُحد، فتصلّي هناك وتدعو الى أن توفّيت، وقال محمُود بن لبيد: انّها كانت تأتي قبر حمزة وتبكي هناك، فلمّا كان في بعض الايّام أتيت قبر حمزة فوجدتها تبكي هناك فأمهلتها حتّى سكنت فأتيتها وسلّمت عليها وقلت : يا سيّدة النّسوان قد والله قطّعت أنياط قلبي من بُكائكِ ، فقالت : يا أبا عمرو ويحقّ لي البكاء فلقد أصبت بخير الاباء رسول الله (صلى الله عليه وآله وسلم) ثمّ قالت : واشوقاه الى رسُول الله ثمّ أنشدت تقول :"},{"type":"Text","content":"اِذا ماتَ يَوْماً مَيِّتٌ قَلَّ ذِكرُهُ وَذِكْرُ اَبي مُذْ ماتَ وَاللهِ اَكْثَرُ"},{"type":"Text","content":"وقال الشّيخ المفيد : وكان رسول الله (صلى الله عليه وآله وسلم) أمر في حياته بزيارة قبر حمزة (عليه السلام) وكان يلمّ به وبالشّهداء ولم تزل فاطمة (عليها السلام) بعد وفاته (صلى الله عليه وآله وسلم) تغدو الى قبره وتَرُوح والمسلمُون يَنتابُونَ على زيارتِهِ ومُلازَمَةِ قَبره ."}],"preview":"اَلسَّلامُ عَلَيْكَ يا عَمَّ رَسُولِ اللهِ صَلَّى اللهُ عَلَيْهِ وَآلِه، اَلسَّلامُ عَلَيْكَ يا خَيْرَ الشُّهَداءِ، اَلسَّلامُ عَلَيْكَ يا اَسَدَ اللهِ وَاَسَدَ رَسُولِهِ، اَشْهَدُ","hasTranslate":false},{"id":"mf_ar_190","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الفَصلُ الثّالِثُ :","title":"تقول في زيارتهم :","blocks":[{"type":"Text","content":"اَلسَّلامُ عَلى رَسُول اللهِ، اَلسَّلامُ عَلى نَبِيِّ اللهِ، اَلسَّلامُ عَلى مُحَمَّد بنِ عَبْدِاللهِ، اَلسَّلامُ عَلى اَهْلِ بَيْتِهِ الطّاهِرينَ، اَلسَّلامُ عَلَيْكُمْ اَيُّهَا الشُّهَداءُ الْمُؤْمِنُونَ، اَلسَّلامُ عَلَيْكُمْ يا اَهْلَ بَيْتِ الاْيمانِ وَالتَّوْحيدِ، اَلسَّلامُ عَلَيْكُمْ يا اَنْصارَ دينِ اللهِ وَاَنْصارَ رَسُولِهِ عَلَيْهِ وَآلِهِ السَّلامُ، سَلامٌ عَلَيْكُمْ بِما صَبَرْتُمْ فَنِعْمَ عُقْبَى الدّارِ، اَشْهَدُ اَنَّ اللهَ اخْتارَكُمْ لِدينِهِ، وَاصْطَفاكُمْ لِرَسُولِهِ، وَاَشْهَدُ اَنَّكُمْ قَدْ جاهَدْتُمْ فِي اللهِ حَقَّ جِهادِهِ، وَذَبَبْتُمْ عَنْ دينِ اللهِ وَعَنْ نَبِيِّهِ، وَجُدْتُمْ بِاَنْفُسِكُمْ دُونَهُ، وَاَشْهَدُ اَنَّكُم قُتِلْتُمْ عَلى مِنْهاجِ رَسُولِ اللهِ، فَجَزاكُمُ اللهُ عَنْ نَبِيِّهِ وَعَنِ الاِْسْلامِ وَاَهْلِهِ اَفْضَلَ الْجَزاءِ، وَعَرَّفَنا وُجُوهَكُمْ في مَحَلِّ رِضْوانِهِ، وَمَوْضِعِ اِكْرامِهِ، مَعَ النَّبِيّينَ وَالصِّدّيقينَ وَالشُّهَداءِ وَالصّالِحينَ وَحَسُنَ اُولئِكَ رَفيقاً، اَشْهَدُ اَنَّكُمْ حِزْبُ اللهِ، وَاَنَّ مَنْ حارَبَكُمْ فَقَدْ حارَبَ اللهَ، وَاَنَّكُمْ لِمَنَ الْمُقَرَّبينَ الْفائِزينَ الَّذينَ هُمْ اَحْياءٌ عِنْدَ رَبِّهِمْ يُرْزَقُونَ، فَعَلى مَنْ قَتَلَكُمْ لَعْنَةُ اللهِ وَالْمَلائِكَةِ وَالنّاسِ اَجْمَعينَ، اَتَيْتُكُمْ يا اَهْلَ التَّوْحيدِ زائِراً، وَبِحَقِّكُمْ عارِفاً، وِبِزِيارَتِكُمْ اِلَى اللهِ مُتَقَرِّباً، وَبِما سَبَقَ مِنْ شَريفِ الاَْعْمالِ وَمَرْضِيِّ الاَْفْعالِ عالِماً، فَعَلَيْكُمْ سَلامُ اللهِ وَرَحْمَتُهُ وَبَرَكاتُهُ، وَعَلى مَنْ قَتَلَكُمْ لَعْنَةُ اللهِ وَغَضَبُهُ وَسَخَطُهُ، اَللّـهُمَّ انْفَعْني بِزِيارَتِهِمْ، وَثَبِّتْني عَلى قَصْدِهِمْ، وَتَوَفَّني عَلى ما تَوَفَّيْتَهُمْ عَلَيْهِ، وَاجْمَعْ بَيْني وَبَيْنَهُم في مُسْتَقَرِّ دارِ رَحْمَتِكَ، اَشْهَدُ اَنَّكُمْ لَنا فَرَطٌ وَنَحْنُ بِكُمْ لاحِقُونَ ."},{"type":"Text","content":"وتكرّر سورة اِنّا اَنْزَلْناهُ في لَيلَةِ الْقَدرِ ما تمكّنت، وقال البعض: تصلّي عند كلّ مزور ركعتين وترجع ان شاء الله تعالى ."},{"type":"Text","content":"ذِكرُ المَساجد المُعظّمة بالمدينَة المنوّرة"},{"type":"Text","content":"منها مسجد قبا الّذي اسّس على التّقوى من اوّل يوم، وروي انّ من ذهب اليه فصلّى فيه ركعتين رجع بثواب العمرة فأمض اليه وَصلّ فيه ركعتين للتحيّة وسبّح تسبيح الزّهراء (عليها السلام) ثمّ زر بالزّيارة الجامعة الّتي تفتح بالسّلام على أولياء الله، وقد جعلناها أولى الزّيارة الجامعة وستأتي في أواخر الباب ان شاء الله، ثمّ ادع الله وقل : يا كائِناً قَبْلَ كُلَّ شَىْء وهو دعاء طويل وايرادُه هنا ينافي ما نبغيه من الاختصار فليطلبه من شاء من مزار البحار، وتصلّي في مشربة امّ ابراهيم أي غرفة امّ ابراهيم ابن رسُول الله (صلى الله عليه وآله وسلم) وقد كانت هناك مسكن رسُول الله (صلى الله عليه وآله وسلم) ومصلاّه، وكذلك في مسجد الفضيخ وهُو قريب من مسجد قبا ويُسمّى ايضاً مسجد ردّ الشّمس، وفي مسجد الفتح أيضاً وتسمّى أيضاً بمسجد الاحزاب . وقُل اذا فرغت من الصّلاة في مسجد الفتح : يا صَريخَ الْمَكْرُوبينَ، وَيا مُجيبَ دَعْوَةِ الْمُضْطَرّينَ، وَيا مُغيثَ الْمَهْمُومينَ، اكْشِفْ عَنّي ضُرّي وَهَمّي وَكَرْبي وَغَمّي كَما كَشَفْتَ عَنْ نَبِيِّكَ صَلَّى اللهُ عَلَيْهِ وَآلِهِ هَمَّهُ، وَكَفَيْتَهُ هَوْلَ عَدُوِّهِ، وَاكْفِني ما اَهَمَّني مِنَ أَمْرِ الدُّنْيا وَالاْخِرَةِ، يا اَرْحَمَ الرّاحِمينَ ."},{"type":"Text","content":"وتصّلّي ما استطعت في دار الامام زين العابدين ودار الامام جعفر الصّادق (عليهما السلام) وفي مسجد سلمان ومسجد أمير المؤمنين (عليه السلام) المحاذي قبر حمزة ومسجد المباهلة وتدعُو بما تشاء ان شاء الله تعالى ."},{"type":"Text","content":"الوَداع"},{"type":"Text","content":"اذا أردت أن تخرج من المدينة فاغتسل وامض الى قبر النّبي (صلى الله عليه وآله وسلم) واعمل ما كنت تعمله مِن قبل ثمّ ودّعه وقُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا رَسُولَ اللهِ، اَسْتَوْدِعُكَ اللهَ وَاَسْتَرْعيكَ وَاَقْرَأُ عَلَيْكَ السَّلامُ، آمَنْتُ بِاللهِ وَبِما جِئْتَ بِهِ وَدَلَلْتَ عَلَيْهِ، اَللّـهُمَّ لا تَجْعَلْهُ آخِرَ الْعَهْدِ مِنّي لِزِيارَةِ قَبْرِ نَبِيِّكَ، فَاِنْ تَوَفَّيْتَني قَبْلَ ذلِكَ فَاِنّي اَشْهَدُ في مَماتي عَلى ما شَهِدْتُ عَلَيْهِ في حَياتي اَنْ لا اِلهَ إلاّ اَنْتَ وَاَنَّ مُحَمَّداً عَبْدُكَ وَرَسُولُكَ صَلَّى اللهُ عَلَيْهِ وَآلِهِ ."},{"type":"Text","content":"وقال الصّادق (عليه السلام) ليونس بن يعقوب : قُل في وداع النّبي (صلى الله عليه وآله وسلم) صَلَّى اللهُ عَلَيْكَ، السَّلامُ عَلَيْكَ لا جَعَلَهُ اللهُ آخِرَ تَسْليمي عَلَيْكَ ."},{"type":"AboutText","content":"أقول : قد قلنا في كتاب هديّة الزّائرين عند بيان ما ينبغي أن يصنع زوّار المدينة الطيّبة انّ مِن مهام الامور أن يغتنموا الفرصة ما أقاموا في المدينة المعظّمة، فيكثروا من الصّلاة في مسجد النّبي (صلى الله عليه وآله وسلم) فانّ الصّلاة فيه تعدل عشرة آلاف صلاة في غيره من المواضِع، وأفضل الاماكن فيه مسجد الرّوضة وهو بين القبر والمنبر، واعلم انّه قال شيخنا في التحيّة : انّ موضع جسد نبيّنا والائمة صلوات الله عليهم أجمعين في الارض أشرف من الكعبة المعظّمة باتّفاق جميع الفقهاء كما صرّح به الشّهيد في القواعد، وفي حديث حسن عن الحضرمي قال : أمرني الصّادق (عليه السلام) : أن أكثر من الصّلاة في مسجد النّبي (صلى الله عليه وآله وسلم) ما امكنتني الصّلاة وقال : انّه لا يتيسّر لك دائماً الحضُور في هذه البُقعة الشّريفة الخ ."},{"type":"AboutText","content":"وروى الشّيخ الطّوسي (رحمه الله) في التّهذيب بسند معتبر عن مرازم عن الصّادق صلوات الله وسلامه عليه قال : الصّيام بالمدينة والقيام عند الاساطين ليس بمفروض ولكن من شآء فليصم فانّه خير له انّما المفروض الصّلوات الخمس وصيام شهر رمضان، فاكثروا الصّلاة في هذا المسجد ما استطعتم فانّه خير لكم، واعلموا انّ الرّجل قد يكون كيّساً في أمر الدّنيا فيقال : ما أكيس فلاناً فكيف من كاس في أمر آخرته، وكرّر ما امكنتك في كلّ يوم زيارة النّبي (صلى الله عليه وآله وسلم) وكذلك زيارة أئمة البقيع (عليهم السلام) وسلّم على النّبي (صلى الله عليه وآله وسلم) مهما وقع بصرك على حجرته، وراقب نفسك ما دمت في المدينة، وصُن نفسك من المعاصي والمظالم، وتدبّر في شرف تلك المدينة ولا سيّما مسجدها مسجد النّبي (صلى الله عليه وآله وسلم)، فتلك البقاع هي مواضع أقدام النّبي (صلى الله عليه وآله وسلم)وقد تردّد النّبي (صلى الله عليه وآله وسلم) في مسالك هذه المدينة وأسواقها وصلّى في مسجدها، وهناك موضع الوحي والتّنزيل، وكان يهبط فيها جبرئيل والملائكة المقرّبون، ولنعم ما قيل :"},{"type":"Text","content":"اَرْضٌ مَشى جِبْريلُ في عَرَصاتِها وَاللهُ شَرَّفَ اَرْضَها وَسَماءَها"},{"type":"Text","content":"وتصدّق ما استطعت في المدينة ولا سيّما في المسجد وخاصّة على السّادة وذريّة الرّسول (صلى الله عليه وآله وسلم) فانّ لها ثواباً جزيلاً وأجراً عظيماً، وقال العلامة المجلسي (رحمه الله): في رواية معتبرة انّ درهماً يتصدّق بها فيها يعدل عشرة آلاف درهم في غيرها، وجاور المدينة الطّيّبة ان أمكنتك فانّها مستحبّة، وقد ورد في فضلها أحاديث مستفيضة ."},{"type":"Text","content":"سَقَى اللهُ قَبْراً بِالْمَدينَةِ غَيْثَهُ فَقَدْ حَلَّ فيهِ الاَْمْنُ بِالْبَرَكاتِ"},{"type":"Text","content":"نَبِيُّ الْهُدى صَلّى عَلَيْهِ مَليكُهُ وَبَلَّغَ عَنّا رُوحَهُ التُّحَفاتِ"},{"type":"Text","content":"وَصَلّى عَلَيْهِ اللهُ ما ذَرَّ شارِقٌ وَلاحَتْ نُجُومُ اللَّيْلِ مُبْتَدِراتِ"}],"preview":"اَلسَّلامُ عَلى رَسُول اللهِ، اَلسَّلامُ عَلى نَبِيِّ اللهِ، اَلسَّلامُ عَلى مُحَمَّد بنِ عَبْدِاللهِ، اَلسَّلامُ عَلى اَهْلِ بَيْتِهِ الطّاهِرينَ، اَلسَّلامُ عَلَيْكُمْ اَيُّهَا ا","hasTranslate":false},{"id":"mf_ar_191","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الفَصلُ الرّابِعْ :","title":"في فَضلِ زِيارة مَولانا أميرُ المؤمِنين (عليه السلام) وَكيفيّتها وفيه عدّة مطالب :","blocks":[{"type":"Text","content":"روى الشّيخ الطّوسي (رحمه الله) بسند صحيح عن محمّد بن مُسلم عن الصّادق صلوات الله وسلامه عليه قال : ما خلق الله خلقاً اكثر من الملائكة، وانّه لينزل كلّ يوم سبعون ألف ملك فيأتون البيت المعمُور، فيطوفون به فاذا هم طافوا به طافوا بالكعبة، فاذا طافوا بها أتوا قبر النّبي (صلى الله عليه وآله وسلم) فسلّموا عليه، ثمّ أتوا قبر أمير المؤمنين (عليه السلام) فسلّموا عليه، ثمّ أتوا قبر الحسين (عليه السلام) فسلّموا عليه، ثمّ عرجُوا وينزل مثلهم أبداً الى يوم القيامة، ثمّ قال : مَن زار امير المؤمنين (عليه السلام) عارفاً بحقّه أي وهو يعترف بامامته وَوجوب طاعته وانّه الخليفة للنّبي (صلى الله عليه وآله وسلم) حقّاً غير متجبّر ولا متكبّر، كتب الله له أجر مائة ألف شهيد، وغفر الله له ما تقدّم من ذنبه وما تأخّر، وبعث من الامنين، وهوّن عليه الحساب، واستقبله الملائكة، فاذا انصرف الى منزله فان مرض عادُوه، وإن مات تبعوه بالاستغفار الى قبره ."},{"type":"AboutText","content":"وروى السّيد عبد الكريم بن طاووس (رحمه الله) في فرحة الغرّي عنه (عليه السلام) قال : مَن زار امير المؤمنين صلوات الله وسلامه عليه ماشياً كتب الله له بكلّ خطوة حجّة وعمرة، فإن رجع ماشياً كتب الله له بكلّ خطوة حجّتين وعمرتين ."},{"type":"Text","content":"وروي عنه (عليه السلام) ايضاً انّه قال لابن مارد : يا ابن مارد مَن زار جدّي عارفاً بحقّه كتب الله له بكلّ خطوة حجّة مقبُولة وعمرة مبرورة ، يا ابن مارد والله ما يطعم الله النّار قدماً غبرت في زيارة امير المؤمنين (عليه السلام)ماشياً كان أو راكباً، يا ابن مارد اكتب هذا الحديث بماء الذّهب ."},{"type":"Text","content":"وروي ايضاً عنه (عليه السلام) قال : نحن نقول بظهر الكوفة قبر لا يلُوذ به ذو عاهة الّا شفاه الله ."},{"type":"AboutText","content":"أقول : يظهر من أحاديث معتبرة انّ الله تعالى قد جعل قبور امير المؤمنين (عليه السلام) وأولاده الطّاهرين صلوات الله عليهم اجمعين معاقل الخائفين، وملاجيء المضطرّين، واماناً لاهل الارض، ما زارها مغموم الّا وفرّج الله عنه، وما تمسح بها سقيم الّا وشفى، وما التجأ اليها أحد الّا أمن ."},{"type":"Text","content":"روى السّيد عبد الكريم بن طاووس عن محمّد بن عليّ الشيباني قال : خرجت أنا وأبي وعمّي حسين ليلاً متخفين الى الغريّ لزيارة امير المؤمنين صلوات الله وسلامه عليه، وكان ذلك سنة مائتين وبضع وستّين وكنت طفلاً صغيراً، فلمّا وصلنا الى القبر الشّريف وكان يومئذ قبراً حوله حجارة سود ولا بناء عنده، فبينا نحن عنده بعضنا يقرأ وبعضنا يصلّي وبعضنا يزور، واذا نحن بأسد مقبل نحونا، فلمّا قرب منّا قدر رمح تباعدنا عن القبر الشّريف، فجاء الاسد فجَعل يمرّغ ذراعَيه على القبر، فمضى رجل منّا فشاهده فعاد فاعلمنا فزال الرّعب عنّا، فجئناه جميعاً فشاهدناه يمرّغ ذراعه على القبر وفيهِ جراح فلم يزل يمرّغه ساعة ثمّ انزاح عن القبر ومضى، فعدنا الى ما كنّا عليه لاتمام الزّيارة والصّلاة وقراءة القرآن ."},{"type":"Text","content":"وحكى الشّيخ المفيد قال : خرج الرّشيد يوماً من الكوفة للصّيد فصار الى ناحية الغريّين والثويّة، فرأى هُناك ظباءً فأمر بارسال الصّقور والكلاب المُعلّمة عليها، فحاولتها ساعة ثمّ لجأت الظِّباء الى أكمة، فتراجعت الصّقور والكلاب عنها، فتعجّب الرّشيد من ذلك، ثمّ انّ الظِّباء هبطت من الاكمة فسقطت الطّيُور والكلاب عليها، فرجعت الظِّباء الى الاكمة فراجعت الصّقور والكلاب عنها مرّة ثانية، ثمّ فعلت ذلك مرّة اخرى، فقال الرّشيد: اركضوا الى الكوفة فأتوا بأكبرها سنّاً، فأتّي بشيخ من بني أسد، فقال الرّشيد: أخبرني ما هذه الاكمة؟ فقال : وهل أنا آمن اذا أجبت السّؤال ؟ فقال الرّشيد : عاهدت الله على أن لا اُوذيك، فقال : حدّثني أبي عن آبائه انّهم كانوا يقولون انّ هذه الاكمة قبر عليّ بن أبي طالب صلوات الله وسلامه عليهما، جعله الله حرماً آمناً يأمن مَن لجأ اليه ."},{"type":"AboutText","content":"أقول : من أمثال العرب السّائرة (اَحْمى مِن مُجيرِ الجَرادِ) وقصّة المثال انّ رجلاً من اهلِ البادية من قبيلة طي يسمّى مُدلج بن سُويد كان ذات يوم في خيمته فاذا هُو بقوم من طي ومعهم أوعيتهم ، فقال : ما خطبكم ؟ قالوا : جراد وقع في فنائك فجئنا لنأخذه، فلمّا سمع مدلج ذلك ركب فرسه وأخذ رمحهُ وقال : اَيَكُونُ الْجَرادُ في جَواري ثُمَّ تُريدُونَ اَخْذَهُ لا يَكونُ ذلك، فما زال يحرسه حتّى حميت الشّمس عليهِ وطار ، فقال : شأنكم الان فقد تحوّل عن جواري ."},{"type":"Text","content":"وقال صاحب القاموس : انّ ذا الاعواد لقب رجل شريف جدّاً من العرب قيل هو جدّ أكثم بن الصّيفي كانت قبيلة مضر تجبي اليه الخراج، فلمّا هرم وبلغ الكِبر كان يحمل على سرير فيطاف به بين قبائل العرب ومياهها فيجبى له، وكان شريفاً مكرّماً ما لجأالى سريره خائف الّا أمن، وما دنا من سريره ذليل الّا عزّ، وما أتاه جائع الّا أشبع ، انتهى ."},{"type":"Text","content":"فاذا كان سرير رجل من العرب يبلع من العزّة والرّفعة هذا المبلَغ فلا غرو اذا جعل الله تعالى قبر وليّه الّذي كان حملة سريره هم جبرئيل وميكائيل (عليهما السلام) والامام الحسن (عليه السلام) والامام الحسين (عليه السلام) معقلاً للخائفين وملجأ للهاربين وغوثاً للمضطرّين، وشفاء للمرضى، فاجتهد أينما كنت لبلوغ قبره الشّريف والتصق به ما امكنك ذلك والحّ في الدّعاء كي يغيثك (عليه السلام) وينجّيك من الهلاك في الدّنيا والاخرة ."},{"type":"Text","content":"لُذْ اِلى جُودِهِ تَجِدْهُ زَعيماً بِنَجاةِ الْعُصاةِ يَوْمَ لِقاها"},{"type":"Text","content":"عائِذٌ لِلْمُؤَمِّلينَ مُجيبٌ سامِعٌ ما تُسِرُّ مِنْ نَجْواها"},{"type":"Text","content":"وحُكي في كتاب دار السّلام عن الشّيخ الديلمي انّه روى جمع من صُلحاء النّجف الاشرف انّ رجلاً شاهد في المنام القبّة الشريفة لحبل الله المتين امير المؤمنين صلوات الله عليه وقد امتدّت اليها واتّصلت بها خيوط خارجة من القبور التي في داخل ذلك المشهد الشّريف وفي خارجه، فأنشد الرّجل :"},{"type":"Text","content":"اِذا مُتُّ فَادْفِنِّي اِلى جَنْبِ حَيْدَر اَبي شَبَّر اَكْرِمْ بِهِ وَشُبَيْرِ"},{"type":"Text","content":"فَلَسْتُ اَخافُ النّارَ عِنْدَ جِوارِهِ وَلا اَتَّقي مِنْ مُنْكَر وَنَكيرِ"},{"type":"Text","content":"فَعارٌ عَلى حامي الْحِمى وَهُوَ فِى الْحِمى اِذا ضَلَّ فِى الْبَيْداء عِقالُ بَعيرِ"},{"type":"AboutText","content":"اعلم انّ زياراته (عليه السلام) نوعان، فزيارات مُطلقة لا تخصّ زماناً خاصّاً، وزيارات مخصوصة يزار بها في أوقات معيّنة، ونذكر الزّيارات في مقصدين :"},{"type":"Text","content":"المقصد الاوّل : في الزّيارات المُطلقة وهي كثيرة نقتصر هُنا على عدّة منها :"},{"type":"Text","content":"الاُولى : ما رواها الشّيخ المفيد والشّهيد والسّيد ابن طاووس وغيرهم، وصفتها انّك اذا أردت زيارته (عليه السلام) فاغتسل والبس ثوبين طاهرين ونل شيئاً من الطّيب وإنْ لم تنل اجزأك، فاذا خرجت مِن منزلك فقُل :"},{"type":"Text","content":"اَللّـهُمَّ اِنّي خَرَجْتُ مِنْ مَنْزِلي اَبْغي فَضْلَكَ، وَاَزُورُ وَصِيَّ نَبِيِّكَ صَلَواتُكَ عَلَيْهِما، اَللّـهُمَّ فَيَسِّرْ ذلِكَ لي، وَسَبِّبِ الْمَزارَ لَهُ، وَاخْلُفْني في عاقِبَتي وَحُزانَتي بِاَحْسَنِ الْخِلافَةِ يا اَرْحَمَ الرّاحِمينَ. فسر وانت تلهج بهذه الاذكار: اَلْحَمْدُ للهِ وَسُبْحانَ اللهِ وَلا اِلـهَ اِلاَّ اللهُ . واذا بلغت خندق الكوفة فقف عنده وقل : اَللهُ اَكْبَرُ اَللهُ اَكْبَرُ، اَهْلَ الْكِبْرِياءِ وَالَْمجْدِ وَالْعَظَمَةِ، اَللهُ اَكْبَرُ اَهْلَ التَّكْبير وَالتَّقدْيسِ وَالتَّسْبيحِ وَالاْلاءِ، اَللهُ اَكْبَرُ مِمّا اَخافُ وَاَحْذَرُ، اَللهُ اَكْبَرُ عِمادي وَعَلَيْهِ اَتَوَكَّلُ، اَللهُ اَكْبَرُ رَجائي وَاِلَيْهِ اُنيبُ، اَللّـهُمَّ اَنْتَ وَلِىُّ نِعْمَتي، وَالْقادِرُ عَلى طَلِبَتي، تَعْلَمُ حاجَتي وَما تُضْمِرُهُ هَواجِسُ الصُّدُورِ، وَخَواطِرُ النُّفُوسِ، فَاَسْأَلُكَ بِمُحَمَّد الْمُصْطَفَى الَّذي قَطَعْتَ بِهِ حُجَجَ الُْمحْتَجّينَ، وَعُذْرَ الْمُعْتَذِرينَ، وَجَعَلْتَهُ رَحْمَةً لِلْعالَمينَ، اَنْ لا تَحْرِمْني ثَوابَ زِيارَةِ وَلِيِّكَ وَأخي نَبِيِّكَ اَميرِ الْمؤْمِنينَ وَقَصْدَهُ، وَتَجْعَلَني مِنْ وَفْدِهِ الصّالِحينَ وَشِيعَتِهِ الْمُتَّقينَ، بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ . فاذا تراءت لك القبّة الشريفة فقل : اَلْحَمْدُ للهِ عَلى مَا اخْتَصَّني بِهِ مِنْ طيبِ الْمَوْلِدِ، وَاسْتَخْلَصَني اِكْراماً بِهِ مِنْ مُوالاةِ الاَْبْرارِ السَّفَرَةِ الاَْطْهارِ، وَالْخَيَرَةِ الاَْعْلامِ، اَللّـهُمَّ فَتَقَبَّلْ سَعْيي اِلَيْكَ، وَتَضَرُّعي بَيْنَ يَدَيْكَ، وَاغْفِرْ لِيَ الذُّنُوبَ الَّتي لا تَخْفى عَلَيْكَ، اِنَّكَ اَنْتَ اللهُ الْمَلِكُ الْغَفّارُ ."},{"type":"AboutText","content":"أقول : يعرض للزّائر اذا وقع نظره على قبّته المنيرة النّشاط والانبساط، ويثور في فؤاده العشق والولاء فيحاول أن يتوجّه اليه (عليه السلام) بمجامع قلبه، وأن يمدحه ويثنى عليه بكلّ لسان وبيان، ولا سيّما اذا كان الزّائر من أهل العلم والكمال فانّه يرغب في شِعر بليغ يتمثّل به في ذلك الحال، لذلك خطر لي أن أثبت هُنا هذه الابيات المناسبة للمقام مِن القصيدة الهائية الازريّة والرّجاء الواثق أن يسلّم الزّائر عنّي سلاماً على صاحب تلك القبّة البيضاء، وأن لا ينساني من الدّعاء وهذه هي الابيات :"},{"type":"Text","content":"اَيُّهاً الرّاكِبُ الُْمجِدُّ رُوَيْداً بِقُلُوب تَقَلَّبَتْ في جَواها"},{"type":"Text","content":"اِنْ تَراءَتْ اَرْضُ الْغَرِيَّينِ فَاخْضَعْ وَاخْلَعِ النَّعْلَ دُونَ وادي طُواها"},{"type":"Text","content":"وَاِذا شِمْتَ قُبَّةَ الْعالَمِ الاَْ عْلى وَاَنْوارُ رَبِّها تَغْشاها"},{"type":"Text","content":"فَتَواضَعْ فَثَمَّ دارَةُ قُدْس تَتَمَنَّى الاَْفْلاكُ لَثْمَ ثَراها"},{"type":"Text","content":"قُلْ لَهُ وَالدُّمُوعُ سَفْحُ عَقيق وَالْحَشا تَصْطَلي بِنارِ غَضاها"},{"type":"Text","content":"يَابْنَ عَمِّ النَّبيِّ اَنْتَ يَدُ اللهِ الَّتي عَمَّ كُلَّ شَيْء نَداها"},{"type":"Text","content":"اَنْتَ قُرْآْنُهُ الْقَدِيمُ وَاَوَصا فُـكَ آياتُهُ الَّتي اَوْحاها"},{"type":"Text","content":"خَصَّكَ اللهُ في مَآثِرَ شَتّى هِيَ مِثْلُ الاَْعْدادِ لا تَتَناهى"},{"type":"Text","content":"لَيْتَ عَيْناً بِغَيْرِ رَوْضِكَ تَرْعى قَذِيَتْ وَاسْتَمَرَّ فيها قَذاها"},{"type":"Text","content":"اَنْتَ بَعْدَ النَّبِيِّ خَيْرُ الْبَرايا وَالسَّما خَيْرُ ما بِها قَمَراها"},{"type":"Text","content":"لَكَ ذاتٌ كَذاتِهِ حَيْثُ لَوْلا اَنَّها مِثْلُها لَما آخاها"},{"type":"Text","content":"قَدْ تَراضَعْتُما بِثَدْي وِصال كانَ مِنْ جَوْهَرِ التَّجَلّي غِذاها"},{"type":"Text","content":"يا اَخَا الْمُصْطَفى لَدَيَّ ذُنُوبٌ هِيَ عَيْنُ الْقَذا وَاَنْتَ جَلاها"},{"type":"Text","content":"لَكَ في مُرْتَقَى الْعُلى وَالْمَعالي دَرَجاتٌ لا يُرْتَقى اَدْناها"},{"type":"Text","content":"لَكَ نَفْسٌ مِنْ مَعْدَنِ اللُّطْفِ صيغَتْ جَعَلَ اللهُ كُلَّ نَفْس فِداها"}],"preview":"روى الشّيخ الطّوسي (رحمه الله) بسند صحيح عن محمّد بن مُسلم عن الصّادق صلوات الله وسلامه عليه قال : ما خلق الله خلقاً اكثر من الملائكة، وانّه لينزل كلّ يوم سبعون ألف ملك فيأتون البي","hasTranslate":false},{"id":"mf_ar_192","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلب الثّاني : في كيفيّة زيارَته (عليه السلام) :","title":"فاذا بلغت باب حصن النّجف فقُل :","blocks":[{"type":"Text","content":"اَلْحَمْدُ للهِ الَّذي هَدانا لِهذا وَما كُنّا لِنَهْتَدِيَ لَوْلا اَنْ هَدانَا اللهُ، اَلْحَمْدُ للهِ الَّذي سَيَّرَني في بِلادِهِ، وَحَمَلَني عَلى دَوابِّهِ، وَطَوى لِيَ الْبَعيدَ، وَصَرَفَ عَنِّي الَْمحْذوُرَ، وَدَفَعَ عَنِّي الْمَكْرُوهَ، حَتّى اَقْدَمَني حَرَمَ اَخي رَسُولِهِ صَلَّى اللهُ عَلَيْهِ وَآلِهِ ."},{"type":"Text","content":"ثمّ ادخل وقل : اَلْحَمْدُ للهِ الَّذي اَدْخَلَني هذِهِ الْبُقْعَةَ الْمُبارَكَةَ الَّتي بارَكَ اللهُ فيها، وَاخْتارَها لِوَصِيِّ نَبِيِّهِ، اَللّـهُمَّ فَاجْعَلْها شاهِدَةً لي ."}],"preview":"اَلْحَمْدُ للهِ الَّذي هَدانا لِهذا وَما كُنّا لِنَهْتَدِيَ لَوْلا اَنْ هَدانَا اللهُ، اَلْحَمْدُ للهِ الَّذي سَيَّرَني في بِلادِهِ، وَحَمَلَني عَلى دَوابِّهِ، وَطَوى لِيَ الْبَعيد","hasTranslate":false},{"id":"mf_ar_193","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلب الثّاني : في كيفيّة زيارَته (عليه السلام) :","title":"فاذا بلغت العتبة الاُولى فقل :","blocks":[{"type":"Text","content":"اَللّـهُمَّ بِبابِكَ وَقَفْتُ، وَبِفَنائِكَ نَزَلْتُ، وَبِحَبْلِكَ اعْتَصَمْتُ، وِلِرَحْمَتِكَ تَعَرَّضْتُ، وَبِوَلِيِّكَ صَلَواتُكَ عَلَيْهِ تَوَسَّلْتُ، فَاجْعَلها زِيارَةً مَقْبُولَةً، وَدُعاءً مُسْتَجاباً ."}],"preview":"اَللّـهُمَّ بِبابِكَ وَقَفْتُ، وَبِفَنائِكَ نَزَلْتُ، وَبِحَبْلِكَ اعْتَصَمْتُ، وِلِرَحْمَتِكَ تَعَرَّضْتُ، وَبِوَلِيِّكَ صَلَواتُكَ عَلَيْهِ تَوَسَّلْتُ، فَاجْعَلها زِيارَةً مَقْب","hasTranslate":false},{"id":"mf_ar_194","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلب الثّاني : في كيفيّة زيارَته (عليه السلام) :","title":"ثم قف على باب الصّحن وقل :","blocks":[{"type":"Text","content":"اَللّـهُمَّ اِنَّ هذَا الْحَرَمَ حَرَمُكَ، وَالْمَقامَ مَقامُكَ وَاَنَا"}],"preview":"اَللّـهُمَّ اِنَّ هذَا الْحَرَمَ حَرَمُكَ، وَالْمَقامَ مَقامُكَ وَاَنَا","hasTranslate":false},{"id":"mf_ar_195","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلب الثّاني : في كيفيّة زيارَته (عليه السلام) :","title":"وَداعُ الاَمير (عليه السلام)","blocks":[{"type":"Text","content":"فاذا شئت وداعه فودّعهُ بهذا الوداع الّذي أورده العلماء تلو ما ذكروها مِنَ الزّيارة الخامِسة :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَسْتَوْدِعُكَ اللهَ وَأسْتَرْعيكَ وَاَقْرَأ عَلَيْكَ السَّلامَ، آمَنّا بِاللهِ وَبِالرُّسُلِ وَبِما جاءَتْ بِهِ وَدَعَتْ اِلَيْهِ وَدَلَّتْ عَلَيْهِ فَاكْتُبْنا مَعَ الشّاهِدينَ، اَللّـهُمَّ لا تَجْعَلْهُ آخِرَ الْعَهْدِ مِنْ زِيارَتي اِيّاهُ، فَاِنْ تَوَفَّيْتَني قَبْلَ ذلِكَ فَاِنّي اَشْهَدُ في مَماتي عَلى ما شَهِدْتُ عَلَيْهِ في حَياتي، اَشْهَدُ اَنَّ اَميرَ الْمُؤْمِنينَ عَلِيّاً وَالْحَسَنَ، وَالْحُسَيْنَ، وَعَلِيَّ بْنَ الْحُسَيْنِ، وَمُحَمَّدَ بْنَ عَلِيٍّ، وَجَعْفَرَ بْنَ مُحَمَّد، وَموُسَى بْنَ جَعْفَر، وَعَلِيَّ بْنَ مُوسى، وَمُحَمَّدَ بْنَ عَلِيٍّ، وَعَلِيَّ بْنَ مُحَمَّد، وَالْحَسَنَ بْنَ عَلِيٍّ وَالْحُجَّةَ بْنَ الْحَسَنِ صَلَواتُكَ عَلَيْهِمْ اَجْمَعينَ اَئِمَّتي، وَاَشْهَدُ اَنَّ مَنْ قَتَلَهُمْ وَحارَبَهُمْ مُشْرِكُونَ، وَمَنْ رَدَّ عَلَيْهِمْ في اَسْفَلِ دَرَْك مِنَ الْجَحيمِ، وَاَشْهَدُ اَنَّ مَنْ حارَبَهُمْ لَنا اَعْداءٌ وَنَحْنُ مِنْهُمْ بُرَءاءُ، وَاَنَّهُمْ حِزْبُ الشَّيْطانِ، وَعَلى مَنْ قَتَلَهُمْ لَعْنَةُ اللهِ وَالْمَلائِكَةِ وَالنّاسِ اَجْمَعينَ، وَمَنْ شَرِكَ فيهِمْ وَمَنْ سَرَّهُ قَتْلَهُمُ اَللّـهُمَّ اِنّي اَسْاَلُكَ بَعْدَ الصَّلاةِ وَالتَّسْليمِ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَعَليٍّ وَفاطِمَةَ وَالْحَسَنِ وَالْحُسَيْنِ وَعَلِيٍّ وَمُحَمَّد وَجَعْفَر وَمُوسى وَعَلِيٍّ وَمُحَمَّد وَعَلِيٍّ وَالْحَسَنِ وَالْحُجَّةِ، وَلا تَجْعَلْهُ آخِرَ الْعَهْدِ مِنْ زِيارَتِهِ فَاِنْ جَعَلْتَهُ فَاحْشُرْني مَعَ هؤُلاءِ الْمُسَمَّيْنَ الاَْئِمَّةِ، اَللّـهُمَّ وَذَلِّلْ قُلُوبَنا لَهُمْ بِالطّاعَةِ وَالْمُناصَحَةِ وَالَْمحَبَّةِ وَحُسْنِ الْمُوازَرَةِ وَالتَّسْليمِ ."}],"preview":"فاذا شئت وداعه فودّعهُ بهذا الوداع الّذي أورده العلماء تلو ما ذكروها مِنَ الزّيارة الخامِسة :","hasTranslate":false},{"id":"mf_ar_196","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلب الثّاني : في كيفيّة زيارَته (عليه السلام) :","title":"المَقْصَدُ الثّاني : في زيارات الامير (عليه السلام) المخصُوصة :","blocks":[{"type":"Text","content":"وهي عديدة أولاها زيارة يومِ الغدير، وقد رُوي عن الرّضا (عليه السلام) انّه قال لابن أبي نصر : يا ابن أبي نصر أينما كنت فاحضر يوم الغدير عند أمير المؤمنين (عليه السلام) فانّ الله تعالى يغفر لكلّ مؤمن ومؤمنة ومُسلم ومُسلمة ذنُوب ستّين سنة، ويعتق مِنَ النّار ضعف ما اعتق في شهر رمضان وفي ليلة القدر وفي ليلة الفطر ... الخبر ."}],"preview":"وهي عديدة أولاها زيارة يومِ الغدير، وقد رُوي عن الرّضا (عليه السلام) انّه قال لابن أبي نصر : يا ابن أبي نصر أينما كنت فاحضر يوم الغدير عند أمير المؤمنين (عليه السلام) فانّ الله تعا","hasTranslate":false},{"id":"mf_ar_197","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلب الثّاني : في كيفيّة زيارَته (عليه السلام) :","title":"الاُولى : زيارة أمين الله وقد جعلناها الثّانية من الزّيارة المُطلقة وهي قد سلفت","blocks":[{"type":"Text","content":"الثّانية : زيارة مرويّة باسناد معتبرة عن الامام عليّ بن محمّد النّقي (عليهما السلام) قد زار (عليه السلام) بها الامير (عليه السلام) يوم الغدير في السّنة التي أشخصه المعتصم، وصفتها كما يلي : اذا أردت ذلك فقف على باب القُبّة المنوّرة واستأذن، وقال الشّيخ الشّهيد : تغتسل وتلبس أنظف ثيابك وتستأذن وتقول : اَللّـهُمَّ اِنّي وَقَفْتُ عَلى باب وهذا هوَ الاستيذان الاوّل الذي اثبتناه في الباب الاوّل ثمّ ادخل مقدماً رجلك اليمنى على اليسرى وامش حتّى تقف على الضّريح واستقبله واجعل القِبلة بين كتفيك وقُل :"},{"type":"Text","content":"اَلسَّلامُ عَلى مُحَمَّد رَسُولِ اللهِ خاتَمِ النَّبِيّينَ وَسَيِّدِ الْمُرْسَلينَ، وَصَفْوَةِ رَبِّ الْعالَمينَ، اَمينِ اللهِ عَلى وَحْيِهِ وَعَزائِمِ اَمْرِهِ، وَالْخاتِمِ لِما سَبَقَ، وَالْفاتِحِ لِمَا اسْتُقْبِلَ، وَالْمُهَيْمِنِ عَلى ذلِكَ كُلِّهِ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ وَصَلَواتُهُ وَتَحِيّاتُهُ، اَلسَّلامُ عَلى اَنْبِياءِ اللهِ وَرُسُلِهِ وَمَلائِكَتِهِ الْمُقَرَّبينَ وَعِبادِهِ الصّالِحينَ، اَلسَّلامُ عَلَيْكَ يا اَميرَ الْمُؤْمِنينَ، وَسَيِّدَ الْوَصِيّينَ، وَوارِثَ عِلْمِ النَّبِيّينَ، وَوَلِيَّ رَبِّ الْعالَمينَ، وَمَوْلايَ وَمَوْلَى الْمُؤْمِنينَ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَلسَّلامُ عَلَيْكَ يا مَوْلايَ يا اَميرَ الْمُؤْمِنينَ ،يا اَمينَ اللهِ في اَرْضِهِ، وَسَفيرَهُ في خَلْقِهِ، وَحُجَّتَهُ الْبالِغَةَ عَلى عِبادِهِ، اَلسَّلامُ عَلَيْكَ يا دينَ اللهِ الْقَويمَ، وَصِراطَهُ الْمُسْتَقيمَ، اَلسَّلامُ عَلَيْكَ اَيُّهَا النَّبَأُ الْعَظيمُ الَّذي هُمْ فيهِ مُخْتَلِفُونَ وَعَنْهُ يَسْأَلُونَ، اَلسَّلامُ عَلَيْكَ يا اَميرَ الْمُؤْمِنينَ، آمَنْتَ بِاللهِ وَهُمْ مُشْرِكُونَ، وَصَدَّقْتَ بِالْحَقِّ وَهُمْ مُكَذِّبُونَ، وَجاهَدْتَ وَهُمْ مُحْجمُونَ، وَعَبَدْتَ اللهَ مُخْلِصاً لَهُ الدّينَ صابِراً مُحْتَسِباً حَتّى أَتاكَ الْيَقينُ، اَلا لَعْنَةُ اللهِ عَلَى الظّالِمينَ، اَلسَّلامُ عَلَيْكَ يا سَيِّدَ الْمُسْلِمينَ، وَيَعْسُوبَ الْمُؤْمِنينَُ وَاِمامَ الْمُتَّقينَ، وَقآئِدَ الْغُرِّ الُْمحَجَّلينَ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَشْهَدُ اَنَّكَ اَخُو رَسُولِ اللهِ وَوَصِيُّهُ، وَوارِثُ عِلْمِهِ وَاَمينُهُ عَلى شَرْعِهِ وَخَليفَتُهُ في اُمَّتِهِ، وَاَوَّلُ مَنْ آمَنَ بِاللهِ، وَصَدَّقَ بِما اُنْزِلَ عَلى نَبِيِّهِ، وَاَشْهَدُ اَنَّهُ قَدْ بَلَّغَ عَنِ اللهِ ما اَنْزَلَهُ فيكَ، فَصَدَعَ بِاَمْرِهِ، وَاَوْجَبَ عَلى اُمَّتِهِ فَرْضَ طاعَتِكَ وَوِلايَتِكَ، وَعَقَدَ عَلَيْهِمُ الْبَيْعَةَ لَكَ، وَجَعَلَكَ اَوْلى بِالْمُؤْمِنينَ مِنْ اَنْفُسِهِمْ كَما جَعَلَهُ اللهُ كَذلِكَ، ثُمَّ اَشْهَدَ اللهَ تَعالى عَلَيْهِمْ فَقالَ: اَلَسْتُ قَدْ بَلَّغْتُ، فَقالُوا: اَللّـهُمَّ بَلى، فَقالَ: اَللّـهُمَّ اشْهَدْ وَكَفى بِكَ شَهيداً وَحاكِماً بَيْنَ الْعِبادِ، فَلَعَنَ اللهُ جاحِدَ وِلايَتِكَ بَعْدَ الاِْقْرارِ، وَناكِثَ عَهْدِكَ بَعْدَ الْميثاقِ، وَاَشْهَدُ اَنَّكَ وَفَيْتَ بِعَهْدِ اللهِ تَعالى، وَاَنَّ اللهَ تَعالى مُوف لَكَ بِعَهْدِهِ، ( وَمَنْ اَوْفى بِما عاهَدَ عَلَيْهُ اللهَ فَسَيُؤْتيهِ اَجْراً عَظيماً )، وَاَشْهَدُ اَنَّكَ اَميرُ الْمُؤْمِنينَ الْحَقُّ الَّذي نَطَقَ بِوِلايَتِكَ التَّنْزيلُ، وَاَخَذَ لَكَ الْعَهْدَ عَلَى الاُْمَّةِ بِذلِكَ الرَّسُولُ، وَاَشْهَدُ اَنَّكَ وَعَمَّكَ وَاَخاكَ الَّذينَ تاجَرْتُمُ اللهَ بِنُفوُسِكُمْ فَاَنْزَلَ اللهُ فيكُمْ ( اِنَّ اللهَ اشْتَرى مِنَ الْمُؤْمِنينَ اَنْفُسَهُمْ وَاَمْوالَهُمْ بِاَنَّ لَهُمُ الْجَنَّةَ يُقاتِلُونَ في سَبيلِ اللهِ فَيَقْتُلُونَ وَيُقْتَلُونَ وَعْداً عَلَيْهِ حَقّاً فِي التَّوْراةِ وَالاِْنْجيلِ وَالْقُرْآنِ وَمَنْ اَوْفى بِعَهْدِهِ مِنَ اللهِ فَاسْتَبْشِروُا بِبِيْعِكُمُ الَّذي بايَعْتُمْ بِهِ وَذلِكَ هُوَ الْفَوْزُ الْعَظيمُ ) ( التّائِبُونَ الْعابِدُونَ الْحامِدُونَ السّائِحُونَ الرّاكِعُونَ السّاجِدُونَ الاْمِرُونَ بِالْمَعْرُوفِ، وَالنّاهُونَ عَنِ الْمُنْكَرِ، وَالْحافِظُونَ لِحُدُودِ اللهِ وَبَشِّرِ الْمُؤْمِنينَ )، اَشْهَدُ يا اَميرَ الْمُؤْمِنينَ اَنَّ الشّآكَّ فيكَ ما آمَنَ بِالرَّسُولِ الاَْمينِ، وَاَنَّ الْعادِلَ بِكَ غَيْرَكَ عانِدٌ عَنِ الدّينِ الْقَويمِ الَّذِي ارْتَضاهُ لَنا رَبُّ الْعالَمينَ، وَاَكْمَلَهُ بِوِلايَتِكَ يَوْمَ الْغَديرِ، وَاَشْهَدُ اَنَّكَ الْمَعْني بِقَوْلِ الْعَزيزِ الرَّحيمِ: ( وَاَنَّ هذا صِراطي مُسْتَقيماً فَاتَّبِعُوهُ وَلا تَتَّبِعُوا السُّبُلَ فَتَفَّرَقَ بِكُمْ عَنْ سَبيلِهِ، ضَلَّ وَاللهِ وَاَضَلَّ مَنِ اتَّبَعَ سِواكَ، وَعَنَدَ عَنِ الْحَقِّ مَنْ عاداكَ، اَللّـهُمَّ سَمِعْنا لاَِمْرِكَ وَاَطَعْنا وَاتَّبَعْنا صِراطِكَ الْمُسْتَقيمَ فَاهْدِنا رَبَّنا وَلا تُزِغْ قُلُوبَنا بَعْدَ اِذْ هَدَيْتَنا اِلى طاعَتِكَ، وَاجْعَلْنا مِنَ الشّاكِرينَ لاَِنْعُمِكَ، وَاَشْهَدُ اَنَّكَ لَمْ تَزَلْ لِلْهَوى مُخالِفاً، وَللِتُّقى مُحالِفاً، وَعَلى كَظْمِ الْغَيْظِ قادِراً، وَعَنِ النّاسِ عافِياً غافِراً، وَاِذا عُصِيَ اللهُ ساخِطاً، وَاِذا اُطيعَ اللهُ راضياً، وَبِما عَهِدَ اِلَيْكَ عامِلاً، راعِياً لِمَا اسْتُحْفِظْتَ، حافِظاً لِمَا اسْتوُدِعْتَ، مُبَلِّغاً ما حُمِّلْتَ، مُنْتَظِراً ما وُعِدْتَ، وَاَشْهَدُ اَنَّكَ مَا اتَّقَيْتَ ضارِعاً، وَلا اَمْسَكْتَ عَنْ حَقِّكَ جازِعاً، وَلا أحْجَمتَ عَنْ مُجاهَدَةِ غاصِبيكَ ناكِلاً، وَلا اَظْهَرْتَ الرِّضا بِخِلافِ ما يُرْضِي اللهَ مُداهِناً، وَلا وَهَنْتَ لِما اَصابَكَ في سَبيلِ اللهِ، وَلا ضَعُفْتَ وَلاَ اسْتَكَنْتَ عَنْ طَلَبِ حَقِّكَ مُراقِباً، مَعاذَ اللهِ اَنْ تَكُونَ كَذلِكَ بَلْ اِذْ ظُلِمْتَ احْتَسَبْتَ رَبَّكَ، وَفَوَّضْتَ اِلَيْهِ اَمْرَكَ، وَذَكَّرْتَهُمْ فَمَا ادَّكَرُوا وَوَعَظْتَهُمْ فَمَا اتَّعَظُوا، وَخَوَّفْتَهُمُ اللهَ فَما تَخَوَّفُوا، وَاَشْهَدُ اَنَّكَ يا اَميرَ الْمُؤْمِنينَ جاهَدْتَ فِي اللهِ حَقَّ جِهادِهِ حَتّى دَعاكَ اللهُ اِلى جِوارِهِ، وَقَبَضَكَ اِلَيْهِ بِاخْتِيارِهِ، وَاَلْزَمَ اَعْداءَكَ الْحُجَّةَ بِقَتْلِهِمْ اِيّاكَ لِتَكُونَ الْحُجَّةُ لَكَ عَلَيْهِمْ مَعَ ما لَكَ مِنَ الْحُجَجِ الْبالِغَةِ، عَلى جَميعِ خَلْقِهِ، اَلسَّلامُ عَلَيْكَ يا اَميرَ الْمُؤْمِنينَ، عَبَدْتَ اللهَ مُخْلِصاً، وَجاهَدْتَ فِي اللهِ صابِراً، وَجُدْتَ بِنَفْسِكَ مُحْتَسِباً، وَعَمِلْتَ بِكِتابِهِ، وَاتَّبَعْتَ سُنَّةَ نَبِيِّهِ، وَاَقَمْتَ الصَّلاةَ، وَآتَيْتَ الزَّكاةَ وَاَمَرْتَ بِالْمَعْرُوفِ، وَنَهَيْتَ عَنِ الْمُنْكَرِ مَا اسْتَطَعْتَ، مُبْتَغِياً ما عِنْدَ اللهِ، را"},{"type":"Text","content":"الثّالِثة مِنَ الزّيارات المخصُوصة"}],"preview":"الثّانية : زيارة مرويّة باسناد معتبرة عن الامام عليّ بن محمّد النّقي (عليهما السلام) قد زار (عليه السلام) بها الامير (عليه السلام) يوم الغدير في السّنة التي أشخصه المعتصم، وصفتها ك","hasTranslate":false},{"id":"mf_ar_198","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلب الثّاني : في كيفيّة زيارَته (عليه السلام) :","title":"زيارة ليلة المبعث وهو اليوم السّابع والعشرون من رجب وقد وردت فيه ثلاث زيارات :","blocks":[{"type":"Text","content":"الاُولى : الزّيارة الرّجبيّة اَلْحَمْدُ للهِ الَّذي أشَهَدَنا مَشْهَدَ اَوْلِيائِهِ، وقد سلفت في أعمال رجب وهي زيارة يزار بها كلّ من المشاهد المشرّفة في شهر رجب، وقد عدّها صاحب كتاب المزار القديم والشّيخ محمّد ابن المشهدي من زيارات ليلة المبعث المخصوصة وقالا : صلّ بعدها للزّيارة ركعتين ثمّ ادعُ بما شِئت ."},{"type":"Text","content":"الثّانية : زيارة اَلسَّلامُ عَلى اَبِي الاَْئِمَّةِ وَمَعْدِنِ النُّبُوَّة، التي قد جعلها العلامة المجلسي الزّيارة السّابعة من الزّيارات المطلقة في كتاب التحفة ."},{"type":"AboutText","content":"قال صاحب المزار القديم : انّها تخصّ اللّيلة السّابعة والعشرين من رجب، ونحن أيضاً قد جرينا على ذلك في كتاب هديّة الزّائر ."},{"type":"Text","content":"الثّالثة : زيارة أوردها الشّيخ المفيد والسّيد والشّهيد بهذه الكيفيّة، اذا أردت زيارة الامير (عليه السلام) في ليلة المبعث أو يَومه فقف على باب القُبّة الشّريفة مُقابل قبره (عليه السلام) وقل :"},{"type":"Text","content":"اَشْهَدُ اَنْ لا اِلـهَ اِلاَّ اللهُ وَحْدَهُ لا شَريكَ لَهُ،وَاَشْهَدُ اَنَّ مُحَمَّداً عَبْدُهُ وَرَسُولُهُ، وَاَنَّ عَلِيَّ بْنَ اَبي طالِب اَميرَ الْمُؤمِنينَ عَبْدُ اللهِ، وَاَخُو رَسُولِهِ، وَاَنَّ الاَْئِمَّةَ الطّاهِرينَ مِنْ وُلْدِهِ حُجَجُ اللهِ عَلى خَلْقِهِ، ثمّ ادخل وقِف عند القبر مستقبلاً القبر والقبلة بين كتفيك وكبّر الله مائة مرّة وقُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا وارِثَ آدَمَ خَليفَةِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ نُوح صَفْوَةِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ اِبْراهيمَ خَليلِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ مُوسى كَليمِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ عيسى رُوحِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ مُحَمَّد سَيِّدِ رُسُلِ اللهِ، اَلسَّلامُ عَلَيْكَ يا اَميرَ الْمُؤْمِنينَ، اَلسَّلامُ عَلَيْكَ يا اِمامَ المُتَّقينَ، اَلسَّلامُ عَلَيْكَ يا سَيِّدَ الْوَصِيّينَ، اَلسَّلامُ عَلَيْكَ يا وَصِيَّ رَسُولِ رَبِّ الْعالَمينَ، اَلسَّلامُ عَلَيْكَ يا وارِثَ عِلْمِ الاَْوَّلينَ وَالاْخِرينَ، اَلسَّلامُ عَلَيْكَ اَيُّهَا النَّبَأُ الْعَظيمُ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الصِّراطُ الْمُسْتَقيمُ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الْمُهَذَّبُ الْكَريمُ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الْوَصِيُّ التَّقِيُّ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الرَّضِيُّ الزَّكِيُّ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الْبَدْرُ الْمُضيءُ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الصِّديقُ الاَْكْبَرُ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الْفارُوقُ الاَْعْظَمُ، اَلسَّلامُ عَلَيْكَ اَيُّهَا السِّراجُ الْمُنيرُ، اَلسَّلامُ عَلَيْكَ يا اِمامَ الْهُدى، اَلسَّلامُ عَلَيْكَ يا عَلَمَ التُّقى، اَلسَّلامُ عَلَيْكَ يا حُجَّةَ اللهِ الْكُبْرى، اَلسَّلامُ عَلَيْكَ يا خاصَّةَ اللهِ وَخالِصَتَهُ، وَاَمينَ اللهِ وَصَفْوَتَهُ، وَبابَ اللهِ وَحُجَّتَهُ، وَمَعْدِنَ حُكْمِ اللهِ وَسِرِّهِ، وَعَيْبَةَ عِلْمِ اللهِ وَخازِنَهُ، وَسَفيرَ اللهِ في خَلْقِهِ، اَشْهَدُ اَنَّكَ اَقَمْتَ الصَّلاةَ، وَآتَيْتَ الزَّكاةَ، وَاَمَرْتَ بِالْمَعْرُوفِ، وَنَهَيْتَ عَنِ الْمُنْكَرِ، وَاتَّبَعْتَ الرَّسُولَ، وَتَلَوْتَ الْكِتابَ حَقَّ تِلاوَتِهِ، وَبَلَّغْتَ عَنِ اللهِ، وَوَفَيْتَ بِعَهْدِ اللهِ، وَتَمَّتْ بِكَ كَلِماتُ اللهِ، وَجاهَدْتَ فِي اللهِ حَقَّ جِهادِهِ، وَنَصَحْتَ للهِ وَلِرَسُولِهِ صَلَّى اللهُ عَلَيْهِ وَآلِهِ، وَجُدْتَ بِنَفْسِكَ صابِراً مُحْتَسِباً مُجاهِداً عَنْ دينِ اللهِ، مُوَقِّياً لِرَسُولِ اللهِ صلَّى اللهُ عَلَيْهِ وَآلِهِ، طالِباً ما عِنْدَ اللهِ، راغِباً فيـما وَعَدَ اللهُ، وَمَضَيْتَ لِلَّذي كُنْتَ عَلَيْهِ شَهيداً وَشاهِداً وَمَشْهُوداً، فَجَزاكَ اللهُ عَنْ رَسُولِهِ وَعَنِ الاِْسْلامِ وَاَهْلِهِ مِنْ صِدّيق اَفْضَلَ الْجَزاءِ، اَشْهَدُ اَنَّكَ كُنْتَ اَوَّلَ الْقَوْمِ اِسْلاماً، وَاَخْلَصَهُمْ ايماناً، وَاَشَدَّهُمْ يَقيناً، وَاَخْوَفَهُمْ للهِ وَاَعْظَمَهُمْ عَناءً، وَاَحْوَطَهُمْ عَلى رَسُولِ اللهِ صَلَّى اللهُ عَلَيْهِ وَآلِهِ، وَاَفْضَلَهُمْ مَناقِبَ، وَاَكْثَرَهُمْ سَوابِقَ، وَاَرْفَعَهُمْ دَرَجَةً، وَاَشْرَفَهُمْ مَنِزْلَةً، وَاَكْرَمَهُمْ عَلَيْهِ، فَقَوِيْتَ حينَ وَهَنوُا، وَلَزِمْتَ مِنْهاجَ رَسُولِ اللهِ صَلَّى اللهُ عَلَيْهِ وَآلِهِ، وَاَشْهَدُ اَنَّكَ كُنْتَ خَليفَتَهُ حَقّاً لَمْ تُنازَعْ بِرَغْمِ الْمُنافِقينَ، وَغَيْظِ الْكافِرينَ، وَضِغْنِ الْفاسِقينَ، وَقُمْتَ بِالاَْمْرِ حينَ فَشِلُوا، وَنَطَقْتَ حينَ تَتَعْتَعُوا، وَمَضَيْتَ بِنُورِ اللهِ اِذْ وَقَفُوا، فَمَنِ اتَّبَعَكَ فَقَدِ اهْتَدى، كُنْتَ اَوَّلَهُمْ كَلاماً، وَاَشَدَّهُمْ خِصاماً، وَاَصْوَبَهُمْ مَنْطِقاً، وَاَسَدَّهُمْ رَأياً، وَاَشْجَعَهُمْ قَلْباً، وَاَكْثَرَهُمْ يَقيناً، وَاَحْسَنَهُمْ عَمَلاً، وَاَعْرَفَهُمْ بِالاُْمُورِ، كُنْتَ لِلْمُؤْمِنينَ اَباً رَحيماً اِذْ صارُوا عَلَيْكَ عِيالاً، فَحَمَلْتَ اَثْقالَ ما عَنْهُ ضَعُفُوا، وَحَفِظْتَ ما اَضاعُوا، وَرَعَيْتَ ما اَهْمَلُوا، وَشَمَّرْتَ اِذْ جَبَنُوا، وَعَلَوْتَ اِذْ هَلِعُوا، وَصَبَرْتَ اِذْ جَزِعُوا، كُنْتَ عَلَى الْكافِرينَ عَذاباً صَبّاً وَغِلْظَةً وَغَيْظاً، وَلِلْمُؤْمِنينَ غَيْثاً وَخِصْباً وَعِلْماً، لَمْ تُفْلَلْ حُجَّتُكَ، وَلَمْ يَزِغْ قَلْبُكَ، وَلَمْ تَضْعُفْ بَصيرَتُكَ، وَلَمْ تَجْبُنْ نَفْسُكَ، كُنْتَ كَالْجَبَلِ لا تُحَرِّكُهُ الْعَواصِفُ، وَلا تَزيلُهُ الْقَواصِفُ، كُنْتَ كَما قالَ رَسُولُ اللهِ صَلَّى اللهُ عَلَيْهِ وَآلِهِ : قَوِيّاً في بَدَنِكَ، مُتَواضِعاً في نَفْسِكَ، عَظيماً عِنْدَ اللهِ، كَبيراً فِي الاَْرْضِ، جَليلاً فِي السَّماءِ، لَمْ يَكُنْ لاَِحَد فيكَ مَهْمَزٌ، وَلا لِقائِل فيكَ مَغْمَزٌ، وَلا لِخَلْق فيكَ مَطْمَعٌ، وَلا لاَِحَد"}],"preview":"الاُولى : الزّيارة الرّجبيّة اَلْحَمْدُ للهِ الَّذي أشَهَدَنا مَشْهَدَ اَوْلِيائِهِ، وقد سلفت في أعمال رجب وهي زيارة يزار بها كلّ من المشاهد المشرّفة في شهر رجب، وقد عدّها صاحب كتا","hasTranslate":false},{"id":"mf_ar_199","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلب الثّاني : في كيفيّة زيارَته (عليه السلام) :","title":"زِيارة مُسلِم بنَ عَقيل (قَدَّسَ اللهُ رُوحَهُ وَنَوَّرَ ضَريحَهُ)","blocks":[{"type":"Text","content":"فاذا فرغت من أعمال جامع الكوفة فامض الى قبر مسلم بن عقيل رضوان الله عليه وقِف عنده وقُل :"},{"type":"Text","content":"اَلْحَمْدُ للهِ الْمَلِكِ الْحَقِّ الْمُبينِ، الْمُتَصاغِرِ لِعَظَمَتِهِ جَبابِرَةُ الطّاغينَ، الْمُعْتَرِفِ بِرُبُوبِيَّتِهِ جَميعُ اَهْلِ السَّماواتِ وَالاَْرَضينَ، الْمُقِرِّ بِتَوْحيدِهِ سائِرُ الْخَلْقِ اَجْمَعينَ، وَصَلَّى اللهُ عَلى سَيِّدِ الاَْنامِ وَاَهْلِ بَيْتِهِ الْكِرامِ، صَلاةً تَقَرُّ بِها اَعْيُنُهُمْ، وَيَرْغَمُ بِها اَنْفُ شانِئِهِمْ مِنَ الْجِنِّ وَالاِْنْسِ اَجْمَعينَ، سَلامُ اللهِ الْعِليِّ الْعَظيمِ وَسَلامُ مَلائِكَتِهِ الْمُقَرَّبينَ وَاَنْبِيائِهِ الْمُرْسَلينَ وَاَئِمَّتِهِ الْمُنْتَجَبينَ وَعِبادِهِ الصّالِحينَ وَجَميعِ الشُّهَداءِ وَالصِّدّيقينَ، وَالزّاكِياتُ الطَّيِّباتُ فيـما تَغْتَدي وَتَرُوحُ عَلَيْكَ يا مُسْلِمَ بْنَ عَقيلِ بْنِ أبي طالِب وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَشْهَدُ اَنَّكَ اَقَمْتَ الصَّلاةَ، وَآتَيْتَ الزَّكاةَ، وَاَمَرْتَ بِالْمَعْرُوفِ، وَنَهَيْتَ عَنْ الْمُنْكَرِ، وَجاهَدْتَ فِي اللهِ حَقَّ جِهادِهِ، وَقُتِلْتَ عَلى مِنْهاجِ الُْمجاهِدينَ في سَبيلِهِ حَتّى لَقِيْتَ اللهَ عَزَّوَجَلَّ وَهُوَ عَنْكَ راض، وَاَشْهَدُ اَنَّكَ وَفَيْتَ بِعَهْدِ اللهِ، وَبَذَلْتَ نَفْسَكَ في نُصْرَةِ حُجَّةِ اللهِ وَابْنِ حُجَّتِهِ حَتّى اَتاكَ الْيَقينُ، اَشْهَدُ لَكَ بِالتَّسْليمِ وَالْوَفاءِ وَالنَّصيحَةِ لِخَلَفِ النَّبِيِّ الْمُرْسَلِ، وَالسِّبْطِ الْمُنْتَجَبِ، وَالدَّليلِ الْعالِمِ وَالْوَصِيِّ الْمُبَلِّغِ، وَالْمَظْلُومِ الْمُهْتَضَمِ، فَجَزاكَ اللهُ عَنْ رَسُولِهِ وَعَنْ اَميرِ الْمُؤْمِنينَ وَعَنِ الْحَسَنِ وَالْحُسَيْنِ اَفْضَلَ الْجَزاءَ بِما صَبَرْتَ وَاحْتَسَبْتَ وَاَعَنْتَ فَنِعْمَ عُقْبَى الدّارِ، لَعَنَ اللهُ مَنْ قَتَلَكَ، وَلَعَنَ اللهُ مَنْ اَمَرَ بِقَتْلِكَ، وَلَعَنَ اللهُ مَنْ ظَلَمَكَ، وَلَعَنَ اللهُ مَنِ افْتَرى عَلَيْكَ، وَلَعَنَ اللهُ مَنْ جَهِلَ حَقَّكَ وَاسْتَخَفَّ بِحُرْمَتِكَ، وَلَعَنَ اللهُ مَنْ بايَعَكَ وَغَشَّكَ وَخَذَلَكَ وَاَسْلَمَكَ، وَمَنْ اَلَبَّ عَلَيْكَ وَمَنْ لَمْ يُعِنْكَ، اَلْحَمْدُ للهِ الَّذي جَعَلَ النّارَ مَثْواهُمْ وَبِئْسَ الْوِرْدُ الْمَوْرُودُ، اَشْهَدُ اَنَّكَ قُتِلْتَ مَظْلُوماً، وَاَنَّ اللهَ مُنْجِزٌ لَكُمْ ما وَعَدَكُمْ جِئْتُكَ زائِراً عارِفاً بِحَقِّكُمْ مُسَلِّماً لَكُمْ تابِعاً لِسُنَّتِكُمْ، وَنُصْرَتي لَكُمْ مُعَدَّةٌ حَتّى يَحْكُمَ اللهُ وَهُوَ خَيْرُ الْحاكِمينَ، فَمَعَكُمْ مَعَكُمْ لا مَعَ عَدُوِّكُمْ، صَلَواتُ اللهِ عَلَيْكُمْ وَعَلى اَرْواحِكُمْ وَاَجْسادِكُمْ وَشاهِدِكُمْ وَغائِبِكُمْ، وَالسَّلامُ عَلَيْكُمْ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، قَتَلَ اللهُ اُمَّةً قَتَلَتْكُمْ بِالاَْيْدي وَالاَْلْسُنِ ."},{"type":"Text","content":"وجَعَلَ هذه الكلمات في المزار الكبير بمنزلة الاستئذان، وقال : بعد ذِكرِها : ثمّ ادخل وادنُ من القبر وعلى الرّواية السّابقة أشِر الى الضّريح ثمّ قُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ اَيُّهَا الْعَبْدُ الصّالِحُ الْمُطيعُ للهِ وَلِرَسُولِهِ وَلاَِميرِالْمُؤْمِنينَ وَالْحَسَنِ وَالْحُسَيْنِ عليهم السلام، الْحَمْدُ لله وَسَلامٌ عَلى عِبادِهِ الَّذينَ اصْطَفى مُحَمَّد وَآلِهِ، وَالسَّلامُ عَلَيْكُمْ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ وَمَغْفِرَتُهُ وَعَلى رُوحِكَ وَبَدَنِكَ، اَشْهَدُ اَنَّكَ مَضَيْتَ عَلى مامَضى عَلَيْهِ الْبَدْرِيُّونَ الُْمجاهِدُونَ في سَبيلِ اللهِ، الْمُبالِغُونَ في جِهادِ اَعْدائِهِ وَنُصْرَةِ اَوْلِيائِهِ، فَجَزاكَ اللهُ اَفْضَلَ الْجَزاءِ، وَاَكْثَرَ الْجَزاءِ، وَاَوْفَرَ جَزاءِ اَحَد مِمَّنْ وَفى بِبَيْعَتِهِ، وَاسْتَجابَ لَهُ دَعْوَتَهُ، وَاَطاعَ وُلاةَ اَمْرِهِ ،اَشْهَدُ اَنَّكَ قَدْ بالَغْتَ فِي النَّصيحَةِ وَاَعْطَيْتَ غايَةَ الَْمجْهُودِ حَتّى بَعَثَكَ اللهُ فِي الشُّهَداءِ، وَجَعَلَ رُوحَكَ مَعَ اَرْواحِ السُّعَداءِ، وَاَعْطاكَ مِنْ جِنانِهِ اَفْسَحَها مَنْزِلاً، وَاَفْضَلَها غُرَفاً، وَرَفَعَ ذِكْرَكَ فِي الْعِليّينَ، وَحَشَرَكَ مَعَ النَّبيّينَ وَالصِّدّيقينَ وَالشُّهَداءِ وَالصّالِحينَ وَحَسُنَ اوُلئِكَ رَفيقاً، اَشْهَدُ اَنَّكَ لَمْ تَهِنْ وَلَمْ تَنْكُلْ، وَاَنَّكَ قَدْ مَضَيْتَ عَلى بَصيرَة مِنْ اَمْرِكَ مُقْتَدِياً بِالْصّالِحينَ وَمُتَّبِعاً لِلنَّبيّينَ، فَجَمَعَ اللهُ بَيْنَنا وَبَيْنَكَ وَبَيْنَ رَسُولِهِ وَاَوْلِيائِهِ في مَنازِلِ الُْمخْبِتينَ فَاِنَّهُ اَرْحَمُ الرّاحِمينَ ."},{"type":"Text","content":"ثمّ صلّ ركعتين في جانب الرّأس واهدها الى جنابه ثمّ قل : اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَلا تَدَعْ لى ذَنْباً وهذا هو الدّعاء الّذي يدعى به في مرقد العبّاس وسيأتي ذكره فاذا شئت أن تودعه فودّعه بالوداع الّذي سيذكر في ذيل زيارة العبّاس ."},{"type":"Text","content":"زِيارَة هاني بنَ عروَة (رَحمة الله وَرضوانه عَليه)"},{"type":"Text","content":"تقف عند قبره وتسلّم على رسول الله (صلى الله عليه وآله وسلم) وتقول :"},{"type":"Text","content":"سَلامُ اللهِ الْعَظيمِ وَصَلَواتُهُ عَلَيْكَ يا هانِيَ بْنَ عُرْوَةَ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الْعَبْدُ الصّالِحُ النّاصِحُ للهِ وَلِرَسُولِهِ وَلاَِميرِ الْمُؤْمِنينَ وَالْحَسَنِ وَالْحُسَيْنِ عليهم السلام، اَشْهَدُ اَنَّكَ قُتِلْتَ مَظْلُوماً، فَلَعَنَ اللهُ مَنْ قَتَلَكَ وَاسْتَحَلَّ دَمَكَ، وَحَشى قُبُورَهُمْ ناراً، اَشْهَدُ اَنَّكَ لَقِيْتَ اللهَ وَهُوَ راض عَنْكَ بِما فَعَلْتَ وَنَصَحْتَ، وَاَشْهَدُ اَنَّكَ قَدْ بَلَغْتَ دَرَجَةَ الشُّهَداءِ وَجَعَلَ رُوحَكَ مَعَ اَرْواحِ السُّعَداءِ بِما نَصَحْتَ للهِ وَلِرَسُولِهِ مُجْتَهِداً، وَبَذَلْتَ نَفْسَكَ في ذاتِ اللهِ وَمَرْضاتِهِ، فَرَحِمَكَ اللهُ وَرَضِيَ عَنْكَ وَحَشَرَكَ مَعَ مُحَمَّد وَآلِهِ الطّاهِرينَ، وَجَمَعَنا وَاِيّاكُمْ مَعَهُمْ في دارِ النَّعيمِ، وَسَلامٌ عَلَيْكَ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ ."},{"type":"Text","content":"ثمّ صلّ ركعتين واهدها الى هاني وادعُ لنفسك بما شئت وودّعه بما تودّع به مسلم ."}],"preview":"فاذا فرغت من أعمال جامع الكوفة فامض الى قبر مسلم بن عقيل رضوان الله عليه وقِف عنده وقُل :","hasTranslate":false},{"id":"mf_ar_200","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلب الثّاني : في كيفيّة زيارَته (عليه السلام) :","title":"الفَصْلُ السادِسُ :","blocks":[{"type":"Text","content":"في فَضل مَسجد السّهلة وأعماله، وأعمال مسجد زيد، ومسجد صعصعة :"},{"type":"AboutText","content":"اعلم انّه ليس في تلك البقاع مسجد يضاهي مسجد السّهلة فضلاً وشرفاً بعد مسجد الكوفة وهو بيت ادريس (عليه السلام)وابراهيم (عليه السلام) ومنزل خضر (عليه السلام) ومسكنه، وعن أبي بصير عن الصّادق صلوات الله وسلامه عليه قال : قال لي : يا أبا محمّد كأنّي أرى نزول القائم صلوات الله عليه في مسجد السّهلة بأهله وعياله ويكون منزله، وما بعث الله نبيّاً الاّ وقد صلّى فيه والمقيم فيه كالمقيم في فُسطاط رسول الله (صلى الله عليه وآله وسلم)، وما من مؤمن ولا مؤمنة الاّ وقلبه يحنّ اليه وفيه صخرة فيها صورة كلّ نبيّ، وما صلّى فيه أحد فدعا الله بنيّه صادقة الاّ صرفه الله بقضاء حاجته، وما مِن أحد استجاره الاّ أجاره الله ممّا يخاف منه، قلت : هذا لهو الفضل ، قال : نزيدك ؟ قلت : نعم ، قال : هو من البقاع التّي أحبّ الله أن يدعى فيها وما من يوم ولا ليلة الاّ والملائكة تزُور هذا المسجد يعبدون الله فيه، أما انّي لو كنت بالقرب منكم ما صلّيت صلاة الاّ فيه، يا أبا محمّد ما لم أصف اكثر ، قلت : جعلت فداك لا يزال القائم (عليه السلام) فيه أبداً ؟ قال : نعم .. الخ ."}],"preview":"في فَضل مَسجد السّهلة وأعماله، وأعمال مسجد زيد، ومسجد صعصعة :","hasTranslate":false},{"id":"mf_ar_201","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلب الثّاني : في كيفيّة زيارَته (عليه السلام) :","title":"وأمّا أعمال مَسجد السَّهلة","blocks":[{"type":"Text","content":"فمن المسنون فيه الصّلاة ركعتين بين العشاءين، عن الصّادق (عليه السلام) ما صلاها مكروب ودعا الله الاّ فرّج الله كربته، وعن بعض كتب الزّيارة انّه اذا أردت أن تدخل المسجد فقف على الباب وقُل :"},{"type":"Text","content":"بِسْمِ اللهِ وَبِاللهِ وَمِنَ اللهِ وَاِلَى اللهِ وَما شاءَ اللهُ وَخَيْرُ الاَْسْماءِ للهِ، وَتَوَكَّلْتُ عَلَى اللهِ وَلا حَوْلَ و لا قُوَّةَ اِلاّ بِاللهِ الْعَلِيِّ الْعَظيمِ، اَللّـهُمَّ اجْعَلْني مِنْ عُمّارِ مَساجِدِكَ وَبُيُوتِكَ، اَللّـهُمَّ اِنّي اَتَوَجَّهُ اِلَيْكَ بِمُحَمَّد وَآلِ مُحَمَّد وَاُقَدِّمُهُمْ بَيْنَ يَدَيْ حَوائِجي، فَاجْعَلْنِي اَللّـهُمَّ بِهِمْ عِنْدَكَ وَجيهاً فِي الدُّنْيا وَالاْخِرةِ وَمِنَ الْمُقَرَّبينَ، اَللّـهُمَّ اجْعَلْ صَلاتي بِهِمْ مَقْبُولَهً، وَذَنْبي بِهِمْ مَغْفُوراً، وَرِزْقي بِهِمْ مَبْسُوطاً، وَدُعائي بِهِمْ مُسْتَجاباً، وَحَوائِجي بِهِمْ مَقْضِيَّةً، وَانْظُرْ اِلَيَّ بِوَجْهِكَ الْكَريمِ نَظَرْةً رَحيمَةً اَسْتَوْجِبُ بِها الْكَرامَةَ عِنْدَكَ، ثُمَّ لا تَصْرِفْهُ عَنّي اَبَداً بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ، يا مُقَلِّبَ الْقُلُوبِ وَالاَْبْصارِ ثَبِّتْ قَلْبي عَلى دينِكَ وَدينِ نَبِيِّكَ وَوَلِيِّكَ، وَلا تُزِغْ قَلْبي بَعْدَ اِذْ هَدَيْتَني، وَهَبْ لي مِنْ لَدُنْكَ رَحْمَةً اِنَّكَ اَنْتَ الْوَهّابُ، اَللّـهُمَّ اِلَيْكَ تَوَجَّهْتُ وَمَرْضاتَكَ طَلَبْتُ وَثَوابَكَ ابْتَغَيْتُ، وَبِكَ آمَنْتُ وَعَلَيْكَ تَوَكَّلْتُ، اَللّـهُمَّ فَاَقْبِلْ بِوَجْهِكَ ِالَيِّ، وَاَقْبِلْ بِوَجْهي اِلَيْكَ ثمّ اقرأ آية الكرسي والمعوّذتين وسبّح الله سبع مرّات واحمده سبعاً وهلّل سبعاً وكبّر سبعاً أي كرّر كلّ جملة مِن سُبْحانَ اللهِ وَالْحَمْدُ للهِ وَلا اِلـهَ اِلاّ اللهُ و اللهُ اَكْبَرُ سبع مرّات ثمّ قل : اَللّـهُمَّ لَكَ الْحَمْدُ عَلَى ما هَدَيْتَني، وَلَكَ الْحَمْدُ عَلى ما فَضَّلْتَني، وَلَكَ الْحَمْدُ عَلى ما شَرَّفْتَني، وَلَكَ الْحَمْدُ عَلى كُلِّ بَلاء حَسَن ابْتَلَيْتَني، اَللّـهُمَّ تَقَبَّلْ صَلاتي وَدُعائي، وَطَهِّرْ قَلْبي، وَاشْرَحْ لي صَدْري، وَتُبْ عَلَيَّ اِنَّكَ اَنْتَ التَّوّابُ الرَّحيمُ ."},{"type":"Text","content":"وقال السّيد ابن طاووس اذا أردت أن تمضي الى السّهلة فاجعل ذلك بين المغرب والعشاء الاخرة من ليلة الاربعاء وهو أفضل من غيره من الاوقات فاذا اتيته فصلّ المغرب ونافلتها ثمّ قم فصلّ ركعتين تحيّة المسجد قربةً الى الله تعالى، فاذا فرغت فارفع يدك الى السّماء وقُل : اَنْتَ اللهُ لا اِلـهَ اِلاّ اَنْتَ مُبْدِئُ الْخَلْقِ وَمُعيدُهُمْ، وَاَنْتَ اللهُ لا اِلـهَ اِلاّ اَنْتَ خالِقُ الْخَلْقِ وَرازِقُهُمْ، وَاَنْتَ اللهُ لا اِلـهَ اِلاّ اَنْتَ الْقابِضُ الْباسِطُ، وَاَنْتَ اللهُ لا اِلـهَ اِلاّ اَنْتَ مُدَبِّرُ الاُْمُورِ وَباعِثُ مَنْ فِي الْقُبُورِ، اَنْتَ وارِثُ الاَْرْضِ وَمَنْ عَلَيْها، اَسْاَلُكَ بِاسْمِكَ الَمخْزُنِ الْمَكْنُونِ الْحَيِّ الْقَيُّومِ وَاَنْتَ اللهُ لا اِلـهَ اِلاّ اَنْتَ عالِمُ الِسِّر وَاَخْفى، اَسْاَلُكَ بِاسْمِكَ الَّذي اِذا دُعيتَ بِهِ اَجَبْتَ، وَاِذا ِسُئِلْتَ بِهِ اَعْطَيْتَ، وَاَسْاَلُكَ بِحَقِّكَ عَلى مُحَمَّد وَاَهْلِ بَيْتِهِ وَبِحَقِّهِمُ الَّذي اَوْجَبْتَهُ عَلى نَفْسِكَ اَنْ تُصَلِّىَ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَنْ تَقْضِيَ لي حاجَتي السّاعَةَ السّاعَةَ، يا سامِعَ الدُّعاءِ، يا سَيِّداهُ يا مَوْلاهُ يا غِياثاهُ، اَسْاَلُكَ بِكُلِّ اسْم سَمَّيْتَ بِهِ نَفْسَكَ اَوْ اسْتَأثَرْتَ بِهِ في عِلْمِ الْغَيْبِ عِنْدَكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَنْ تُعَجِّلَ فَرَجَنا السّاعَةَ، يا مُقَلِّبَ الْقُلُوبِ وَالاَْبْصارِ، يا سَميعَ الدُّعاءِ ."},{"type":"Text","content":"ثمّ اسجد واخشع وادعُ الله بما تريد ثمّ صلّ في الزّاوية الغربيّة الشّماليّة ركعتين وهي موضع دار ابراهيم الخليل (عليه السلام) حيث كان يذهب منها الى قتال العمالقة، فاذا فرغت من الصّلاة فسبّح ثمّ قُل بعد ذلك : اَللّـهُمَّ بِحَقِّ هذِهِ الْبُقْعَةِ الشَّريفَةِ، وَبِحَقِّ مِنْ تَعَبَّدَ لَكَ فيها، قَدْ عَلِمْتَ حَوائِجي، فَصَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاقْضِها، وَقَدْ اَحْصَيْتَ ذُنُوبي فَصَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاغْفِرْها، اَللّـهُمَّ اَحْيِني ما كاَنَتِ الْحَياةُ خَيْراً لي، وَاَمِتْني اِذا كانَتِ الْوَفاةُ خَيْراً لي عَلى مُوالاةِ اَوْلِيائِكَ وَمُعاداةِ اَعْدائِكَ، وَافْعَلْ بي ما اَنْتَ اَهْلُهُ يا اَرْحَمَ الرّاحِمينَ، ثمّ تصلّي ركعتين في الزّاوية الغربية الاخرى التي هي في سمت القبلة، ثمّ ترفع يديك وتقول : اَللّـهُمَّ اِنّي صَلَّيْتُ هذِهِ الصَّلاةَ ابْتِغاءَ مَرْضاتِكَ، وَطَلَبَ نائِلِكَ، وَرَجاءَ رِفْدِكَ وَجَوائِزِكَ، فَصَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَتَقَبَّلْها مِنّي بِاَحْسَنِ قَبُول، وَبَلِّغْني بِرَحْمَتِكَ الْمَأْمُولَ، وَافْعَلْ بي ما اَنْتَ اَهْلُهُ يا اَرْحَمَ الرّاحِمينَ، ثمّ اهو الى السّجود وضع خدّيك على التّراب ثمّ امض الى الزّاوية الشّرقيّة فصلّ ركعتين وابسط يديك وقُل : اَللّـهُمَّ اِنْ كانَتْ الذُّنُوبُ وَالْخَطايا قَدْ اَخْلَقَتْ وَجْهي عِنْدَكَ فَلَمْ تَرْفَعْ لي اِلَيْكَ صَوْتاً وَلَمْ تَسْتَجِبْ لي دَعْوَةً فَاِنّي اَسْاَلُكَ بِكَ يا اللهُ فاَنَّهُ لَيْسَ مِثْلَكَ اَحَدٌ، وَاَتَوَسِّلُ اِلَيْكَ بِمُحَمَّد وَآلِهِ وَاَسْاَلُكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاَنْ تُقْبِلَ اِلَيَّ بِوَجْهِكَ الْكَريمِ وَتُقْبِلَ بِوَجْهي اِلَيْكَ وَلا تُخَيِّبْني حَيْنَ اَدْعُوكَ، وَلا تَحْرِمْني حَيْنَ اَرْجُوكَ يا اَرْحَمَ الرّاحِمينَ ."},{"type":"AboutText","content":"أقول : نقل عن كتاب غير معروف من كتب الزّيارات انّه ثمّ تمضى الى الزّاوية الشّرقيّة الاخرى وتصلّي هناك ركعتين وتقول : اَللّـهُمَّ اِنّي اَسْاَلُكَ بِاِسْمِكَ يا اللهُ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَنْ تَجْعَلَ خَيْرَ عُمْري آخِرَهُ، وَخَيْرَ اَعْمالي خَواتِيمَها وَخَيْرَ اَيّامي يَوْمَ اَلْقاكَ فيهِ اِنَّكَ عَلى كُلِّ شَيْء قَديرٌ، اَللّـهُمَّ تَقَبَّلْ دُعائي وَاسْمَعْ نَجْوايَ يا عَلِيُّ يا عَظيمُ يا قادِرُ يا قاهِرُ يا حَيّاً لا يَمُوتُ، صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاغْفِرْ لِيَ الذُّنُوبَ الَّتي بَيْني وَبَيْنَكَ، وَلا تَفْضَحْني عَلى رُؤوسِ الاَْشْهادِ، وَاحْرُسْني بِعينِكَ الَّتي لا تَنامُ وَارْحَمَني بِقُدْرَتِكَ عَلَيَّ يا اَرْحَمَ الرّاحِمينَ، وَصَلَّىَ اللهُ عَلى سَيِّدِنا مُحَمَّد وَآلِهِ الطّاهِرينَ يا رَبَّ الْعالَمينَ ."},{"type":"Text","content":"ثمّ تصلّي في البيت الذي في وسط المسجد ركعتين وتقول : يا مَنْ هُوَ اَقْرَبُ اِلَيَّ مِنْ حَبْلِ الْوَريدِ، يا فَعّالاً لِما يُريدُ، يا مَنْ يَحُولُ بَيْنَ الْمَرْءِ وَقَلْبِهِ صَلِّ عَلى مُحَمَّد وَآلِهِ، وَحُلْ بَيْنَنا وَبَيْنَ مَنْ يُؤْذينا بِحَوْلِكَ وَقُوَّتِكَ يا كافي مِنْ كُلِّ شَيْء وَلا يَكْفي مِنْهُ شَيْءٌ، اِكْفِنا الْمُهِمَّ مِنْ اَمْرِ الدُّنْيا وَالاْخِرَةِ يا اَرْحَمَ الرّاحِمينَ، ثمّ ضع جانبي وجهك على التّراب ."},{"type":"AboutText","content":"أقول : هذه البُقعة الشّريفة تعرف في العصر الحاضر بمقام الامام زين العابدين (عليه السلام) وقال في كتاب المزار القديم انّه يدعى فيها بعد الصّلاة ركعتين بدعاء اَللّـهُمَّ اِنّي اَسْاَلُكَ يا مَنْ لا تَراهُ الْعُيُونَ، الخ والدّعاء قد سلف في أعمال دكّة باب امير المؤمنين (عليه السلام) في مسجد الكوفة فراجعه هناك ويقرب من هذه البُقعة موضِع يعرف بمقام المهدي (عليه السلام) ومن المناسب فيه زيارته (عليه السلام)، ونقل عن بعض كتب الزّيارات انّه ينبغي أن يزوره الزّائر هنا قائماً على قدميه بهذه الزّيارة سَلامُ اللهِ الكامِلُ التّآمُّ الشّامِلُ الخ وهذه هي الاستغاثة السّالفة في الفصل السّابع من الباب الاوّل من الكتاب نقلاً عن كتاب الكلم الطّيب فلا نعيدها وقد عدّها السيّد ابن طاووس من الزّيارات التي يزار بها في السّرداب المقدّس بعد الصّلاة ركعتين ."}],"preview":"فمن المسنون فيه الصّلاة ركعتين بين العشاءين، عن الصّادق (عليه السلام) ما صلاها مكروب ودعا الله الاّ فرّج الله كربته، وعن بعض كتب الزّيارة انّه اذا أردت أن تدخل المسجد فقف على الباب","hasTranslate":false},{"id":"mf_ar_202","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلب الثّاني : في كيفيّة زيارَته (عليه السلام) :","title":"الصَّلاة وَالدُّعاء في مسجد زيد (رَحِمَهُ الله)","blocks":[{"type":"Text","content":"ثمّ تمضي الى مسجد زيد القريب من مسجد السّهلة فتصلّي فيه ركعتين وتبسط يديك وتقول :"},{"type":"Text","content":"اِلهي قَدْ مَدَّ اِلَيْكَ الْخاطِىءُ الْمُذْنِبُ يَدَيْهِ بِحُسْنِ ظَنِّهِ بِكَ، اِلهي قَدْ جَلَسَ الُمسيءُ بَيْنَ يَدَيْكَ مُقِرّاً لَكَ بِسُوءِ عَمَلِهِ وَراجِياً مِنْكَ الصَّفْحَ عَنْ زَلَلِهِ، اِلهي قَدْ رَفَعَ اِلَيْكَ الظّالِمُ كَفَّيْهِ راجِياً لِما لَدَيْكَ فَلا تُخَيِّبْهُ بِرَحْمَتِكَ مِنْ فَضْلِكَ، اِلهي قَدْ جَثَا الْعائِدُ اِلى الْمَعاصي بَيْنَ يَدَيْكَ خائِفاً مِنْ يَوْم تَجْثُو فيهِ الْخَلائِقُ بَيْنَ يَدَيْكَ، اِلهي جاءَكَ الْعَبْدُ الْخاطِىءُ فَزِعاً مُشْفِقاً وَرَفَعَ اِلَيْكَ طَرْفَهُ حَذِراً راجِياً، وَفاضَتْ عَبْرَتُهُ مُسْتَغْفِراً نادِماً، وَعِزَّتِكَ وَجَلالِكَ ما اَرَدْتُ بِمَعْصِيَتي مُخالَفَتَكَ، وَما عَصَيْتُكَ اِذْ عَصَيْتُكَ وَاَنَا بِكَ جاهِلٌ، وَلا لِعُقُوبَتِكَ مُتَعَرِّضٌ، وَلا لِنَظَرِكَ مُسْتَخِفٌّ، وَلكِنْ سَوَّلَتْ لي نَفْسي، وَاَعانَتْني عَلى ذلِكَ شَقْوَتي، وَغَرَّني سِتْرُكَ المْرُخْى عَلَيَّ، فَمِنَ الاْنَ مِنْ عَذابِكَ مَنْ يَسْتَنْقِذُني، وَبَحَبْلِ مَنْ اَعْتَصِمُ اِنْ قَطَعْتَ حَبْلَكَ عَنّي، فَيا سَوْاَتاهُ غَداً مِنَ الْوُقُوفِ بَيْنَ يَدَيْكَ اِذا قيلَ لِلْمُخِفّينَ جُوزُوا ولِلْمُثْقِلينَ حُطُّوا، اَفَمَعَ الُْمخِفّينَ اَجُوزُ اَمْ مَعَ الْمُثْقِلينَ اَحُطُّ، وَيْلي كُلَّما كَبُرَ سِنّي كَثُرَتْ ذُنُوبي، وَيْلي كُلَّما طالَ عُمْري كَثُرَتْ مَعاصِيّي، فَكَمْ اَتُوبُ وَكَمْ اَعُودُ اَما آنَ لي اَنْ اَسَتَحْيِيَ مِنْ رَبّي، اَللّـهُمَ فَبِحَِقِّ مُحَمَّد وَآلِ مُحَمَّد اِغْفِرَ لي وَارْحَمَني يا اَرْحَمَ الرّاحِمينَ وَخَيْرَ الْغافِرينَ ."},{"type":"Text","content":"ثمّ ابك وضَع وجهك على التّراب وقُل : اِرْحَمْ مَنْ اَساءَ وَاَقْتَرَفَ وَاسْتَكانَ وَاَعْتَرَفَ، ثمّ ضع خدّك الايمن وقُل : اِنْ كُنْتُ بِئْسَ الْعَبْدُ فَاَنْتَ نِعْمَ الرَّبُّ، ثمّ ضع خدّك الايسر وقُل : عَظُمَ الذَّنْبُ مِنْ عَبْدِكَ فَلْيَحْسُنِ الْعَفُْ مِنْ عِنْدِكَ يا كَريمُ، ثمّ عُد الى السّجود وقُل اَلْعَفْوَ اَلْعَفْوَ مائة مرّة ."},{"type":"AboutText","content":"أقول : هذا المسجد من المساجد الشّريفة في الكوفة وينتسب الى زيد بن صوحان وهو من كبار أصحاب امير المؤمنين (عليه السلام) ويعدّ من الابدال، وقد استشهد في ركابه (عليه السلام) في واقعة الجمل، والدّعاء السّالف هو دعاؤه الذي كان يدعو به في نافلة اللّيل، وبجوار مسجده هذا مسجد أخيه صعصعة بن صوحان وهو ايضاً من أصحاب امير المؤمنين (عليه السلام) ومن العارفين بحقّه ومن أكابر المؤمنين وقد بلغ في الفصاحة والبلاغة حيث لقّبه امير المؤمنين (عليه السلام) بالخطيب الشحشح، وأثنى عليه بالفصاحة وجودة الخطب كما مدحه بقلّة المؤنة وكثرة المعُونة، وقد حضر صعصعة تشييع جثمانه الشّريف ليلاً من الكوفة الى النّجف ولما لحدّ امير المؤمنين (عليه السلام) وقف صعصعة على القبر وأخذ كفّاً من التّراب فأهاله على رأسه وقال : بأبي أنت وأمّي يا أمير المؤمنين (عليه السلام) هنيئاً لك يا أبا الحسن (عليه السلام) فلقد طاب مولدك، وقوى صبرك، وعظم جهادك، وبلغت ما أمّلت، وربحت تجارتك، ومضيت الى ربّك، ونطق بكثير مثلها وبكى بكاء شديداً وأبكى كلّ من كان معه، وبذلك فقد انعقد في جوف اللّيل مأتم يخطب فيه صعصعة ويحضره الامامان الحسنان (عليهما السلام)ومحمّد بن الحنفيّة وأبو الفضل العبّاس وغيرهم من أبنائه واقاربه، ولما انتهى صعصعة من خطبته عدل الحاضرون الى الامامين الحسن والحسين (عليهما السلام) وغيرهما من أبنائه فعزّوهم في أبيهم (عليه السلام) فعادوا طرّاً الى الكوفة، والخلاصة انّ مسجد صعصعة من المساجد الشّريفة في الكوفة وقد شُوهد فيه الامام الغائب صاحب العصر صلوات الله عليه، شاهده فيه جمع من الاصحاب في شهر رجب يصلّي ركعتين ويدعو بالدّعاء اَللّـهُمَّ يا ذَا الْمِنَنِ السّابِغَةِ وَالاْلاءِ الْوازِعَةِ الدّعاء، وظاهر عمله الشّريف اختصاص الدّعاء بهذا المسجد الشّريف كأدعية مسجد السّهلة ومسجد زيد، ولكن العمل قد كان في شهر رجب وهذا ما أورث احتمال اختصاص الدّعاء بالشّهر لا بالمسجد ولذلك نجد الدّعاء في كتب العلماء مذكوراً أيضاً في خلال أعمال شهر رجب، ونحن أيضاً قد أوردناه هناك فلا نعيده ."}],"preview":"ثمّ تمضي الى مسجد زيد القريب من مسجد السّهلة فتصلّي فيه ركعتين وتبسط يديك وتقول :","hasTranslate":false},{"id":"mf_ar_203","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلب الثّاني : في كيفيّة زيارَته (عليه السلام) :","title":"في فَضل زيارة أبي عبد الله الحسين (عليه السلام)","blocks":[{"type":"Text","content":"والاداب الّتي ينبغي للزّائر رعايتها في طريقه الى زيارته"},{"type":"Text","content":"وفي حرمه الطّاهر وفي كيفيّة زيارته )عليه السلام)"}],"preview":"والاداب الّتي ينبغي للزّائر رعايتها في طريقه الى زيارته","hasTranslate":false},{"id":"mf_ar_204","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلب الثّاني : في كيفيّة زيارَته (عليه السلام) :","title":"في فضلِ زيارَته (عليه السلام) :","blocks":[{"type":"AboutText","content":"اعلم انّ فضل زيارة الحسين (عليه السلام) ممّا لا يبلغه البيان وفي روايات كثيرة انّها تعدل الحجّ والعمرة والجهاد بل هي أفضل بدرجات، تـُورث المغفرة وتخفيف الحساب وارتفاع الدّرجات واجابة الدعوات وتورث طول العمر والانحفاظ في النفس والمال وزيادة الرزق وقضاء الحوائج ورفع الهموم والكربات، وتركها يوجب نقصاً في الدّين وهو ترك حقّ عظيم من حقوق النّبي (صلى الله عليه وآله وسلم)، وأقلّ ما يوجر به زائره هو أن يغفر ذنوبه وأن يصون الله تعالى نفسه وماله حتّى يرجع الى أهله، فاذا كان يوم القيامة كان الله له أحفظ من الدّنيا، وفي روايات كثيرة انّ زيارته تزيل الغمّ وتهون سكرات الموت وتذهب بهول القبر، وانّ ما يصرف في زيارته (عليه السلام)يكتب بكلّ درهم منه الف درهم، بل عشرة آلاف دِرهم وانّ الزّائر اذا توجّه الى قبره (عليه السلام)استقبله اربعة آلاف ملك فاذا رجع منه شايعته، وانّ الانبياء والاوصياء والائمة المعصومين والملائكة سلام الله عليهم اجمعين يزورون الحسين (عليه السلام)ويدعون لزوّاره ويبشّرونهُم بالبشائر، وانّ الله تعالى ينظر الى زوّار الحسين صلوات الله وسلامه عليه قبل نظره الى من حضر عرفات، وانّه اذا كان يوم القيامة تمنّى الخلق كلّهم أن كانوا من زوّاره (عليه السلام) لما يصدر منه (عليه السلام) من الكرامة والفضل في ذلك اليوم، والاحاديث في ذلك لا تحصى وسنشير الى جملة منها عند ذكر زياراته الخاصّة وحسبنا هنا رواية واحدة ."},{"type":"Text","content":"روى ابن قولويه والكليني والسّيد ابن طاوُس وغيرهم باسناد معتبرة عن الثّقة الجليل معاوية بن وهب البجليّ الكوفي قال : دخلت على الصادق صلوات الله وسلامه عليه وهو في مُصلاّه فجلست حتّى قضى صلاته فسمعته وهو يُناجي ربّه ويقول : يا من خصّنا بالكرامة ووعدنا الشفاعة وحملنا الرّسالة وجعلنا ورثة الانبياء وختم بنا الامم السّالفة وخصّنا بالوصيّة وأعطانا علم ما مضى وعلم ما بقى وجعل افئدة الناس تهوي الينا اغْفِرْ لي وَلاِِخْواني وَزُوّارِ قَبْرِ اَبي الْحُسَيْنِ بْنِ عَليّ صَلَواتُ اللهِ عَلَيْهِما الذين انفقوا اموالهم واشخصوا أبدانهم رغبة في برّنا ورجاء لما عندك في وصلتنا، وسروراً أدخلوه على نبيّك محمّد صلّى الله عليه وآله واجابة منهم لامرنا وغيظاً أدخلوه على عدوّنا وأرادُوا بذلك رضوانك فكافهم عنّا بالرّضوان واكلاهم بالليل والنّهار واخلف على اهاليهم واولادهم الذين خلّفوا بأحسن الخلف وأصحبهم واكفهم شرّ كلّ جبّار عنيد واعطهم افضل ما املوا منك في غربتهم عن أوطانهم وما آثرونا على ابنائهم وأهاليهم وقراباتهم اللّهُمَّ انّ اعداءنا عابوا عليهم خروجهم فلم ينههم ذلك عن النّهوض والشّخوص الينا خلافاً عليهم فَارْحَمْ تِلْكَ الْوُجُوهَ الَّتي غَيَّرَتْهَا الشَّمْسُ وَارْحَمْ تِلْكَ الْخُدُودَ الَّتي تُقَلَّبُ عَلى قَبْرِ أبي عَبْدِاللهِ عليه السلام وارحم تلك الاعين التي جرت دموعها رحمة لنا وارحم تلك القلوب التي جزعت واحترقت لنا، وارحم تلك الصّرخة التي كانت لنا اللهم انّي استودعك تلك الانفس وتلك الابدان حتى ترويهم من الحوض يوم العطش، فما زال صلوات الله عليه يدعو بهذا الدّعاء وهو ساجد فلمّا انصرف قلت له : جعلت فداك لو انّ هذا الَّذي سمعته منك كان لمن لا يعرف الله لظننت انّ النّار لا تطعم منه شيئاً ابداً والله لقد تمنّيت انّي كنت زرته ولم أحج، فقال لي : ما أقربك منه فما الَّذي يمنعك من زيارته يا معاوية لا تدع ذلك ، قلت : جعلت فداك فلم أدر انّ الامر يبلغ هذا كلّه ، فقال : يا معاوية ومن يدعو لزوّاره في السّماء اكثر ممّن يدعو لهم في الارض، لا تدعه لخوف من أحد فمن تركه لخوف رأى من الحسرة ما يتمنّى انّ قبره كان بيده (أي تمنّى أن يكون قد ظلّ عنده حتّى دفن هُناك) أما تُحبّ أن يرى الله شخصك وسوادك فيمن يدعو له رسول الله وعليّ وفاطمة والائمة المعصومون (عليهم السلام) امّا تحبّ أن تكون غداً ممّن تصافحه الملائكة ، امّا تحبّ أن تكون غداً فيمن يأتي وليس عليه ذنب فيتبع به ، أما تحب أن تكون ممّن يصافح رسول الله (صلى الله عليه وآله وسلم) ."}],"preview":"اعلم انّ فضل زيارة الحسين (عليه السلام) ممّا لا يبلغه البيان وفي روايات كثيرة انّها تعدل الحجّ والعمرة والجهاد بل هي أفضل بدرجات، تـُورث المغفرة وتخفيف الحساب وارتفاع الدّرجات واجا","hasTranslate":false},{"id":"mf_ar_205","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلب الثّاني : في كيفيّة زيارَته (عليه السلام) :","title":"المقصَد الثاني :","blocks":[{"type":"Text","content":"فيما على الزّائر مراعاته"},{"type":"Text","content":"من الاداب في طريقه الى الزّيارة وفي ذلك الحرم الطّاهر وهي عديدة :"},{"type":"Text","content":"الاوّل : أن يصوم ثلاثة أيّام متوالية قبل الخروج من بيته ويغتسل في اليوم الثّالث على ما أمر الصّادق صلوات الله وسلامه عليه صفوان، وستأتي الرّواية عند ذكر الزّيارة السّابعة وقال الشّيخ محمّد بن المشهدي في مقدّمات زيارة العيدين: اذا أردت زيارته (عليه السلام) فصُم ثلاثة أيّام واغتسل في اليوم الثّالث واجمع اليك أهلك وعيالك وقُل :"},{"type":"Text","content":"اَللّـهُمَّ اِنّي اَسْتَوْدِعُكَ الْيَوْمَ نَفْسي وَاَهْلي وَمالي وَوَلَدي وَكُلَّ مَنْ كانَ مِنّي بِسَبيل، الشّاهِدَ مِنْهُمْ وَالْغائِبَ، اَللّـهُمَّ احْفَظْنا بِحِفْظِكَ بِحِفْظِ الاِْيمانِ وَاحْفَظْ عَلَيْنا، اَللّـهُمَّ اجْعَلْنا في حِرْزِكَ وَلا تَسْلُبْنا نِعْمَتَكَ وَلا تُغَيِّرْ ما بِنا مِنْ نِعْمَة وَعافِيَة، وَزِدْنا مِنْ فَضْلِكَ اِنّا اِلَيْكَ راغِبُونَ ."},{"type":"Text","content":"ثمّ اخرج من منزلك خاشعاً واكثر من قول لا اِلـهَ اِلاَّ اللهُ وَاللهُ اَكْبَرُ وَالْحَمْدُ للهِ وَمِن تمجيد الله تعالى والصّلاة على النّبي وآله صلوات الله عليهم وامض وعليك السّكينة والوقار . وروي انّ الله يخلق من عرق زوّار قبر الحسين (عليه السلام)من كلّ عرقة سبعين ألف ملك يسبحون الله ويستغفرون له ولزوّار الحسين (عليه السلام) الى أن تقوم السّاعة ."},{"type":"Text","content":"الثّاني : عن الصّادق (عليه السلام) قال : اذا زرت أبا عبد الله (عليه السلام) فزره وأنت حزين مكروب شعث مغبر جائع عطشان فانّ الحسين عليه السلام قتل حزيناً مكروباً شعثاً مغبراً جائعاً عطشاناً واسأله الحوائج وانصرف عنه ولا تتّخذه وطناً ."},{"type":"Text","content":"الثّالث : أن لا يُتّخذ الزّاد في سفر زيارته (عليه السلام) ممّا لذّ وطاب من الغذاء كاللّحم المشوي والحلاوة بل يغتذى بالخبز واللّبن، عن الصّادق صلوات الله وسلامه عليه قال : بلغني انّ قوماً اذا زاروا الحسين (عليه السلام)حملوا معهم السّفرة فيها الجداء والاخبصة واشباهه، ولو زاروا قبور آبائهم واحبّائهم ما حملوا معهم هذا، وقال المفضّل بن عمر في حديث معتبر آخر: تزورُون خير من أن لا تزورون ولا تزورون خير من أن تزورون ، قال : قلت قطعت ظهري ، قال : تالله ان احدكم ليذهب الى قبر أبيه كئيباً حزيناً وتأتونه بالسُّفر، كلاّ حتى تأتونه شعثاً غبراً."},{"type":"AboutText","content":"أقول : ما أجدر للاثرياء والتّجار أن يراعوا هذا الامر في سفر زيارة الحسين صلوات الله وسلامه عليه فاذا دعاهم أخلاؤهم في المدن الواقعة على المسير الى المادب رفضوا الدّعوة فاذا عمدوا الى حقائبهم وسفرهم يملؤونها بما طاب من مطبوخ الزّاد كالدّجاج المشوي وغيره من الشّواء أبوا ذلك وصدّوا عنه قائلينْ انّنا راحلون الى كربلاء ولا يجدر بنا أن نتغذّى بمثل ذلك ."},{"type":"Text","content":"روى الكليني (رحمه الله) انّه لمّا قتل الحسين صلوات الله وسلامه عليه اقامت امرأة الكلبيّة عليه مأتماً وبكت وبكت النّساء والخدم حتّى جفّت دموعهم فأهدى اليها الجونىَ وهو القطا على ما فسّرَ لِيَقْتَتْنَ به فَيَقْوينَ على البكاء على الحسين، (عليه السلام)فلمّا رأته سألت عنه فقيل: هو هديّة أهداها فلان تستعنّ بها في مأتم الحسين (عليه السلام)، فقالت: لَسْنا في عُرْس فَما نَصْنَعُ بِها فأمرت باخراجه من الدّار ."},{"type":"Text","content":"الرّابع : ممّا ندب اليه في سفر زيارة الحسين (عليه السلام) هو التّواضع والتّذلّل والتّخاشع والمشي مشي العبد الذّليل فمن ركب من الزّائرين المراكب الحديثة التي تجري مسرعة بقوّة البخار وامثالها يجب عليه التّحفّظ والاحتراز عن الكبر والخيلاء والتّمالك عن التّبختُر على سائر الزّوار من عباد الله الّذين هم يقاسون الشّدائد والصّعاب في طريقهم الى كربلاء فلا ينظرون اليهم نظر التّحقير والازدراء ."},{"type":"Text","content":"روى العلماء في أصحاب الكهف انّهم كانوا من خاصّة دقيانوس ووزرائه فلمّا وسعتهم رحمة الله تعالى فاستقام فكرهم في معرفة الله عزّوجل وفي اصلاح شأنهم استقرّوا على الرّهبنة والانزواء عن الخلق والاواء الى كهف يعبدون الله تعالى فيه، فركبوا خيولهم وخرجوا من المدينة فلمّا ساروا ثلاثة اميال قال لهم تميلخا وكان هو أحدهم : يا اِخْوَتاهُ جاءَتْ مَسْكَنَةُ الاْخِرَةِ وَذَهَبَ مُلْكُ الدُّنْيا اِنْزِلُوا عَنْ خُيُولِكُمْ وَامْشُوا عَلى اَرْجُلِكُمْ (انزلوا عن الخيول وسيروا في سبيل اللهِ على ارجلكم لعلّ الله تعالى ينزّل عليكم عطفه ورحمته ويجعل لكم من امركم مخرجاً) فنزل اولئك العظماء الاجلاء عن خيولهم ومشوا على أرجلهم سبعة فراسخ في ذلك اليوم حتى تقاطرت ارجلهم دماً، فعلى زائر هذا القبر الشّريف أن يراعي هذا الامر وليعلم ايضاً انّ تواضعه في هذا الطريق لوجه الله تعالى انّما هو رفعة له واعتلاء ."},{"type":"Text","content":"وقد روي في آداب زيارته (عليه السلام) عن الصّادق (عليه السلام) قال : من أتى قبر الحسين صلوات الله وسلامه عليه ماشياً كتب الله له بكلّ خطوة الف حسنة، ومحا عنه ألف سيّئة، ورفع له الف درجة، فاذا أتيت الفرات فاغتسل وعلّق نعليك وامش حافياً وامش مشي العبد الذّليل ."},{"type":"Text","content":"الخامس : أن يجتهد ما وسعه الاجتهاد في اعانة الزّائر الرّاجل اذا شاهده وقد تعب واعيا عن المسير فيهتمّ بشأنه ويبلغه منزلاً يستريح فيه، وحذار من الاستخفاف به وعدم الاهتمام لشأنه ."},{"type":"Text","content":"روى الكليني بسند معتبر عن أبي هارون ، قال : كنت عند الصّادق (عليه السلام)يوماً فقال لمن حضره : ماذا بكم تستخفّون بنا ؟ فقام من بينهم رجل من أهل خراسان وقال : نعوذ بالله أن نستخفّ بكم أو بشيء من امركم ، فقال : نعم أنت ممّن استخفّ بي واهانني ، قال الرّجل : اعوذ بالله أن اكون كذلك ، قال (عليه السلام) : ويلك ألم تسمع فلاناً يناديك عندما كنّا بقرب جحفة ويقول اركبني ميلاً فوالله لقد تعبت انّك والله لم ترفع اليه رأسك واستخففت به، ومن اذلّ مؤمناً فقد اذلّنا واضاع حرمة الله تعالى ."},{"type":"AboutText","content":"أقول : راجع الادب التّاسع من آداب الزّيارات العامّة فقد أوردنا هناك كلاماً يناسب المقام، ورواية عن عليّ بن يقطين، وهذا الادب الَّذي ذكرناه هُنا لا يخصّ زيارة الحسين (عليه السلام)وانّما أوردناه هُنا في الاداب الخاصّة بزيارته (عليه السلام)لكثرة مصادفة موارده في هذه الزّيارة خاصّة ."},{"type":"Text","content":"السّادس : عن الثّقة الجليل محمّد بن مُسلم عن الامام محمّد الباقر (عليه السلام)قال : قلت له: اذا خرجنا الى أبيك أفلسنا في حجّ ، قال : بلى ، قلت : فيلزمنا ما يلزم الحاج ، قال : يلزمك حُسن الصحبة لمن يصحبك، ويلزمك قلّة الكلام الاّ بخير، ويلزمك كثرة ذكر الله، ويلزمك نظافة الثّياب، ويلزمك الغسل قبل أن تأتي الحير، ويلزمك الخشوع وكثرة الصّلاة والصّلاة على محمّد وآل محمّد، ويلزمك التّحفّظ عمّا لا ينبغي لك، ويلزمك أن تغضى بصرك (من المحرّمات والمشتبهات)، ويلزمك أن تعود على أهل الحاجة من اخوانك اذا رأيت منقطعاً والمواساة (أن تناصفه نفقتك)، ويلزمك التّقيّة التي قوام دينك بها، والورع عمّا نهيت عنه، وترك الخصومة وكثرة الايمان والجدال الَّذي فيه الايمان، فاذا فعلت ذلك تمّ حجّك وعمرتك واستوجبت من الَّذي طلبت ما عنده بنفقتك واغترابك عن أهلك ورغبتك فيما رغبت أن تنصرف بالمغفرة والرحمة والرّضوان ."},{"type":"Text","content":"السّابع : في حديث أبي حمزة الثّمالي عن الصّادق صلوات الله عليه في زيارة الحسين (عليه السلام) انّه قال : اذا بلغت نينوى فحطّ رحلك هُناك ولا تدهن ولا تكتحل ولا تأكل اللحم ما أقمت فيه ."},{"type":"Text","content":"الثّامن : أن يغتسل بماء الفُرات ، فالروايات في فضله كثيرة، وفي رواية عن الصّادق صلوات الله وسلامه عليه قال : من اغتسل بماء الفُرات وزار قبر الحسين (عليه السلام) كان كيوم ولدته امّه صفراً من الذّنوب ولو اقترفها كبائر ."},{"type":"Text","content":"وروي انّه قيل له (عليه السلام) : ربّما أتينا قبر الحسين بن عليّ (عليهما السلام)فيصعب علينا الغُسل للزّيارة من البرد أو غيره ، فقال (عليه السلام): من اغتسل في الفرات وزار الحسين (عليه السلام) كُتب له من الفضل ما لا يحصى . وعن بشير الدّهان عن الصّادق (عليه السلام) قال : من أتى قبر الحسين بن عليّ (عليهما السلام) فتوضّأ واغتسل في الفرات لم يرفع قدماً ولم يضع قدماً الاّ كتب الله له حجّة وعُمرة، وفي بعض الرّوايات إئت الفرات واغتسل بحيال قبره، وكما يستفاد من بعض الرّوايات يحسن اذا بلغ الفرات أن يقول مائة مرّة اَللهُ اَكْبَرُ ومائة مرّة لا اِلـهَ اِلاَّ اللهُ ويصلّي على محمّد وآله مائة مرّة ."},{"type":"Text","content":"التّاسع : أن يدخل الحائر المقدّس من الباب الشّرقي على ما أمر الصّادق صلوات الله وسلامه عليه يوسف الكناسي ."},{"type":"Text","content":"العاشر : عن ابن قولويه عن الصّادق (عليه السلام) انّه قال للمفضّل بن عمر : يا مفضّل اذا بلغت قبر الحُسين صلوات الله وسلامه عليه فقف على باب الرّوضة وقل هذه الكلمات، فانّ لك بكلّ كلمة منها نصيباً من رحمة الله تعالى :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا وارِثَ آدَمَ صَفْوَةِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ نُوح نَبِيِّ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ اِبْراهيمَ خَليلِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ مُوسى كَليمِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ عيسى رُوحِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ مُحَمَّد حَبيبِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ عَلِيِّ وَصِيِّ رَسُولِ اللهِ، اَلسّلامُ عَلَيْكَ يا وارِثَ الحَسَنِ الرَّضِّي، اَلسَّلامُ عَلَيكَ يا وارِثَ فاطِمَةَ بِنْتَ رَسُولِ اللهِ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الشَّهيدُ الصِّدّيقُ اَلسَّلامُ عَلَيْكَ اَيُّهَا الْوَصِيُّ الْبارُّ الْتَّقِيُّ، اَلسَّلامُ عَلَى الاَْرْواحِ الَّتي حَلَّتْ بِفِنائِكَ وَاَناخَتْ بِرَحْلِكَ، اَلسَّلامُ عَلى مَلائِكَةِ اللهِ الُْمحْدِقينَ بِكَ، اَشْهَدُ اَنَّكَ قَدْ اَقَمْتَ الصَّلاةَ وَآتَيْتَ الزَّكاةَ وَاَمَرْتَ بِالْمَعْرُوفِ وَنَهَيْتَ عَنِ الْمُنْكَرِ وَعَبَدْتَ اللهَ مُخْلِصاً حَتّى اَتاكَ الْيَقينُ، اَلسَّلامُ عَلَيْكَ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ ثمّ تمضي الى القبر ولك بكلِّ خطوة تخطوها أجر المتشحّط بدمه في سبيل الله فاذا اقتربت من القبر فامسحه بيدك وقُل : اَلسَّلامُ عَلَيْكَ يا حُجَّةَ اللهِ في اَرْضِهِ وَسَمائِهِ ثمّ تمضي الى صلاتِك ولك بكلّ ركعة ركعتها عنده كثواب من حجّ ألف حجّة واعتمر الف عمرة واعتق في سبيل الله الف رقبة وكأنّما وقف في سبيل الله الف مرّة مع نبيّ مرسل . الخبر"},{"type":"Text","content":"الحادي عشر : روى عن أبي سعيد المدائني قال : أتيت الصّادق (عليه السلام)فسألته ءأذهب الى زيارة قبر الحسين (عليه السلام)فأجاب بلى اذهب الى زيارة قبر الحسين (عليه السلام) ابن رسول الله (صلى الله عليه وآله وسلم)أطيب الطيّبين واطهر الطّاهرين وأحسن المحسنين، فاذا زرته فسبّح عند رأسه بتسبيح امير المؤمنين (عليه السلام) ألف مرّة، وسبّح عند رجليه بتسبيح الزّهراء (عليها السلام) ألف مرّة، ثمّ صلّ عنده ركعتين تقرأ فيهما سورة يس والرّحمن، فاذا فعلت ذلك كان لك أجر عظيم ، قلت : جعلت فداك علّمني تسبيح عليّ وفاطمة (عليهما السلام) ، قال : بلى يا أبا سعيد تسبيح علي صلوات الله عليه هو :"},{"type":"Text","content":"سُبْحانَ الَّذي لا تَنْفَدُ خَزائِنُهُ، سُبْحانَ الَّذي لا تَبيدُ مَعالِمُهُ، سُبْحانَ الَّذي لا يَفْنى ما عِنْدَهُ، سُبْحانَ الَّذي لا يُشْرِكُ اَحَداً في حُكْمِهِ، سُبْحانَ الَّذي لاَ اضْمِحْلالَ لِفَخْرِهِ، سُبْحانَ الَّذي لاَ انْقِطاعَ لِمُدَّتِهِ، سُبْحانَ الَّذي لا اِلـهَ غَيْرُهُ ."}],"preview":"فيما على الزّائر مراعاته","hasTranslate":false},{"id":"mf_ar_206","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلب الثّاني : في كيفيّة زيارَته (عليه السلام) :","title":"وتسبيح فاطمة (عليها السلام) هو :","blocks":[{"type":"Text","content":"سُبْحانَ ذِي الْجَلالِ الْباذِخِ الْعَظيمِ، سُبْحانَ ذِي الْعِزِّ الشّامِخِ الْمُنيفِ سُبْحانَ ذِي الْمُلْكِ الْفاخِرِ الْقَديمِ، سُبْحانَ ذِي الْبَهْجَةِ وَالْجَمالِ، سُبْحانَ مَنْ تَرَدّى بِالنُّورِ وَالْوِقارِ، سُبْحانَ مَنْ يَرى اَثَرَ الَّنمْلِ فِي الصَّفا وَوَقَعَ الطَّيْرِ فِي الْهَواءِ ."},{"type":"Text","content":"الثّاني عشر : أن يصلّي الفرائض والنّوافل عند قبر الحسين (عليه السلام) فانّ الصّلاة عنده مقبُولة، وقال السّيد ابن طاوُس (رحمه الله):اجتهد في أن تؤدّي صلاتك كلّها فريضة كانت أو نافلة في الحائر فقد روي انّ الفريضة عنده تعدل الحجّ، والنّافلة تعدل العمرة ."},{"type":"AboutText","content":"أقول : قد مضى في حديث مفضّل فضل كثير للصّلاة في الحائر الشّريف، وفي رواية معتبرة عن الصّادق (عليه السلام) قال : من صلّى عنده ركعتين أو أربع ركعات كتبت له حجّة وعُمرة . والَّذي يبدو من الاخبار انّ صلاة الزّيارة أو غيرها من الصّلوات يحسن أداؤها خلف القبر كما يحسن أن تؤدّى ممّا يلي الرّأس الشّريف، وليتأخّر المُصلّي قليلاً اذا وقف ممّا يلي الرّأس حتى لا يكونُ محاذياً للقبر الشّريف، وورد في رواية أبي حمزة الثّمالي عن الصّادق (عليه السلام) انّه قال : صلّ عند رأسه ركعتين تقرأ في الاولى الحمد ويس وفي الثّانية الحمد والرّحمن وان شئت صلّيت خلف القبر وعند رأسه أفضل فاذا فرغت فصلّ ما أحببت الاّ انّ الركعتين ركعتي الزّيارة لابدّ منهما عند كلّ قبر . وروى ابن قولويه عن الباقر (عليه السلام)انّه قال لرجل : يا فلان ماذا يمنعك اذا عرضتك حاجة أن تمضي الى قبر الحسين صلوات الله عليه وتصلّي عنده أربع ركعات ثمّ تسأل حاجتك، انّ الفريضة عنده تعدل الحجّ، والنّافلة تعدل العُمرة ."},{"type":"Text","content":"الثّالث عشر : اعلم انّ أهمّ الاعمال في الرّوضة الطّاهرة للحسين (عليه السلام)هو الدّعاء فانّ اجابة الدّعاء تحت قبّته السّامية هي ممّا خوله الله الحسين (عليه السلام)عوضاً عن الشّهادة، فعلى الزّائر أن يغتنم ذلك ولا يتوانى في التّضرّع الى الله والانابة والتّوبة وعرض الحوائج عليه وقد وردت في خلال زياراته عليه السلام أدعية كثيرة ذات مضامين عالية لم يسمح لنا الاختصار بايرادها هنا والافضل أن يدعو بدعوات الصّحيفة الكاملة ما وسعه الدّعاء فانّها أفضل الادعية، ونحن سنذكر دعاء يدعى به في جميع الرّوضات المقدّسة في أواخر هذا الباب بعد ذكر الزّيارات الجامعة وسنذكر دعاءً هو أجمع الادعية التي تقرأ في روضات الائمة عليه السلام، واحترازاً عن خلوّ المقام نثبت هنا دعاء وجيزاً ورد في خلال بعض الزّيارات، وهو انّه تقول في ذلك الحرم الشّريف رافعاً يديك الى السّماء :"},{"type":"Text","content":"اَللّـهُمَّ قَدْ تَرى مَكاني، وَتَسْمَعُ كَلامي، وَتَرى مَقامي وَتَضَرُّعي وَمَلاذي بِقَبْرِ حُجَّتِكَ وَابْنِ نَبِيِّكَ، وَقَدْ عَلِمْتُ يا سَيِّدي حَوائِجي وَلا يَخْفى عَلَيْكَ حالي، وَقَدْ تَوَجَّهْتُ اِلَيْكَ بِابْنِ رَسُولِكَ وَحُجَّتِكَ وَاَمينِكَ وَقَدْ اَتَيْتُكَ مُتَقَرِّباً بِهِ اِلَيْكَ وَاِلى رَسُولِكَ فَاجْعَلْني بِهِ عِنْدَكَ وَجيهاً فِي الدُّنْيا وَالاْخِرَةِ وَمِنَ الْمُقَرَّبينَ وَاَعْطِني بِزِيارَتي اَمَلي وَهَبْ لي مُناىَ وَتَفَضَّلْ عَلَيَّ بِشَهْوَتي وَرَغْبَتي وَاقْضِ لي حَوائِجي وَلا تَرُدَّني خائِباً وَلا تَقْطَعْ رَجائي وَلا تُخَيِّبْ دُعائي وَعَرِّفْنِى الاِْجابَةِ في جَميعِ ما دَعَوْتُكَ مِنْ اَمْرِ الدّينِ وَالدُّنْيا وَالاْخِرَةِ وَاجْعَلْني مِنْ عِبادِكَ الَّذينَ صَرَفْتَ عَنْهُمُ الْبَلايا وَالاَْمْراضَ وَالْفِتَنَ وَالاَْعْراضَ مِنَ الدّينَ تُحْييهِمْ في عافِيَة وَتُميتُهُمْ في عافِيَة وَتُدْخِلُهُمُ الْجَنَّةَ في عافِيَة وَتُجيرُهُمْ مِنَ النّارِ في عافِيَة وَوَفِّقْ لي بِمَنْ مِنْكَ صَلاحَ ما اُؤَمِلَّ في نَفْسي وَاَهْلي وَوُلْدي وَاِخْواني وَمالي وَجَميعِ ما اَنْعَمْتَ بِهِ عَلَيَّ يا اَرْحَمَ الرّاحِمينَ ."},{"type":"Text","content":"الرابع عشر : من اعمال حرم الحسين (عليه السلام) الصّلاة عليه وروي انّك تقف خلف القبر عند كتفه الشّريف وتصلّي على النّبي (صلى الله عليه وآله وسلم) وعلى الحسين صلوات الله عليه، وقد أورد السّيد ابن طاوُس في مصباح الزّائر في خلال بعض الزّيارات هذه الصّلاة عليه :"},{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَصَلِّ عَلى الْحُسَيْنِ الْمَظْلُومِ الشَّهيدِ، قَتيلِ الْعَبَراتِ، وَاَسيرِ الْكُرُباتِ، صَلاةً نامِيَةً زاكِيَةً مُبارَكَةً يَصْعَدُ اَوَّلُها وَلا يَنْفَدُ آخِرُها اَفْضَلَ ما صَلَّيْتَ على اَحَد مِنْ اَوْلادِ الاَْنْبِياءِ وَالْمُرْسَلينَ يا رَبَّ الْعالِمينَ، اَللّـهُمَّ صَلِّ عَلَى الاِْمامِ الشَّهيدِ الْمَقْتُولِ الْمَظْلُومِ الَْمخْذُولِ، وَالسَّيِّدِ الْقائِدِ، وَالْعابِدِ الزّاهِدِ، والْوَصِيِّ الْخَليفَةِ الاِْمامِ الصِّدّيقِ الطُّهْرِ الطّاهِرِ الطَّيِّبِ الْمُبارَكِ، وَالرَّضِيِّ الْمَرْضِيِّ وَالتَّقِيِّ الْهادِي الْمَهْدِيِّ الزّاهِدِ الذّائِدِ الُْمجاهِدِ الْعالِمِ، اِمامِ الْهُدى سِبْطِ الرَّسُولِ، وَقُرَّةِ عَيْنِ الْبَتُولِ صلى الله عليه وآله وسلم، اَللّـهُمَّ صَلِّ عَلى سَيِّدي وَمَوْلايَ كَما عَمِلَ بِطاعَتِكَ وَنَهى عَنْ مَعْصِيَتِكَ وَبالَغَ في رِضْوانِكَ، وَاَقْبَلَ عَلى ايمانِكَ غَيْرَ قابِل فيكَ عُذْراً سِرّاً وَعَلانِيَةً يَدْعُو الْعِبادِ اِلَيْكَ، وَ يَدُلُّهُمْ عَلَيْكَ، وَقامَ بَيْنَ يَدَيْكَ يَهْدِمُ الْجَوْرَ بِالصَّوابِ، وَيُحْيِي السُّنَّةَ بِالْكِتابِ، فَعاشَ في رِضْوانِكَ مَكْدُوداً، وَمَضى عَلى طاعَتِكَ وَفي اَوْلِيآئِكَ مَكْدُوحاً، وَقَضى اِلَيْكَ مَفْقُوداً لَمْ يَعْصِكَ في لَيْلِ وَلا نَهار بَلْ جاهَدَ فيكَ الْمُنافِقينَ وَالْكُفّارَ، اَللّـهُمَّ فَاَجْزِهِ خَيْرَ جَزاءِ الصّادِقينَ الاَْبْرارِ، وَضاعِفْ عَلَيْهِمُ الْعَذابَ وَلِقاتِليهِ الْعِقابَ، فَقَدْ قاتَلَ كَريماً وَقُتِلَ مَظْلُوماً وَمَضى مَرْحُوماً، يَقُولُ اَنَا ابْنُ رَسُولِ اللهِ مُحَمَّد، وَابْنُ مَنْ زَكّى وَعَبَدَ، فَقَتَلُوهُ بِالْعَمْدِ الْمُعْتَمَدِ قَتَلُوهُ عَلَى الاْيمانِ وَ اَطاعُوا في قَتْلِهِ الشَّيْطانَ وَلَمْ يُراقِبُوا فيهِ الرَّحْمنَ، اَللّـهُمَّ فَصَلِّ عَلى سَيِّدي وَمَوْلايَ صَلاةً تَرْفَعُ بِها ذِكْرَه وَتُظْهِرُ بِها اَمْرَهُ، وَتُعَجِّلُ بِها نَصْرَهُ، وَاخْصُصْهُ بِاَفْضَلِ قِسَمِ الْفَضائِلِ يَوْمَ الْقِيامَةِ وَزِدْهُ شَرَفاً في اَعَلى عِلِّيِّينَ، وَبَلِّغْهُ اَعَلى شَرَفِ الْمُكَرَّمينَ وَاَرْفَعْهُ مِنْ شَرَفِ رَحْمَتِكَ في شَرَفِ الْمُقَرَّبينَ في الرَّفيعِ الاَْعَلى، وَبَلِّغْهُ الْوَسيلَةَ وَالْمَنْزِلَةَ الْجَليلَةَ وَالْفَضْلَ وَالْفَضيلَةَ وَالْكِرامَةَ الْجَزيلَةَ، اَللّـهُمَّ فَاَجْزِهِ عَنّا اَفْضَلَ ما جازَيْتَ اِماماً عَنْ رَعِيَّتِهِ، وَصَلِّ عَلى سَيِّدي و مَوْلايَ كُلَّما ذُكِرَ، وَكُلَّما لَمْ يُذْكَرْ يا سَيِّدي و مَوْلايَ أدْخِلْني في حِزْبِكَ وَزُمْرَتِكَ، وَاِسْتَوْهِبْني مِنْ رَبِّكَ وَرَبّي فَاِنَّ لَكَ عِنْدَ اللهِ جاهاً وَقَدْراً وَمَنْزِلَةً رَفيعَةً، اِنْ سَأَلْتَ اُعْطيتَ وَاِنْ شَفَعْتَ شُفِّعْتَ اللهَ اللهَ في عَبْدِكَ وَمَوْلاكَ لا تُخَلِّني عِنْدَ الشَّدائِدِ وَالاَْهْوالِ لِسُوءِ عَمَلي وَقَبيحِ فِعْلي وَعَظيمِ جُرْمي، فَاِنَّكَ اَمَلي وَرَجائي وَثِقَتي وَمُعْتَمَدي وَوَسيلَتي اِلَى اللهِ رَبّي وَرَبِّكَ لَمْ يَتَوَسَّلِ الْمُتَوَسِّلُونَ اِلَى اللهِ بِوَسيلَة هِىَ اَعْظَمُ حَقاً وَلا اَوْجَبُ حُرْمَةً وَلا اَجَّلُ قَدْراً عِنْدَهُ مِنْكُمْ اَهْلَ الْبَيْتِ لا خَلَّفَنِىَ اللهُ عَنْكُمْ بِذُنُوبي وَجَمَعَني وَاِيّاكُمْ في جَنَّةِ عَدْن الَّتي اَعَدَّها لَكُمْ وَلاَِوْلِيائِكُمْ اِنَّهُ خَيْرُ الْغافِرينَ وَ اَرْحَمَ الرّاحِمينَ، اَللّـهُمَّ اَبْلِغْ سَيِّدي وَمَوْلايَ تَحِيَّةً كَثيرَةً وَسَلاماً، وَارْدُدْ عَلَيْنا مِنْهُ السَّلامِ اِنَّكَ جَوادٌ كَريمٌ، وَصَلِّ عَلَيْهِ كُلَّما ذُكِرَ السَّلامُ وَكُلَّما لَمْ يُذْكَرْ يا رَبَّ الْعالَمينَ."},{"type":"AboutText","content":"أقول : قد أوردنا تلك الزّيارة في خلال اعمال يوم عاشوراء وسنذكر في أواخر الباب صلاة يصلّى بها على الحجج الطّاهرين (عليهم السلام)تتضمّن صلاة وجيزة على الحسين (عليه السلام) فلا تدع قراءتها ."},{"type":"Text","content":"الخامس عشر : من أعمال هذه الرّوضة المنوّرة دعاء المظلوم على الظّالم أي ينبغي لمن بغى عليه باغ أن يدعو بهذا الدّعاء في ذلك الحرم الشّريف، وهو ما أورده شيخ الطّايفة (رحمه الله) في مصباح المتهجّد في أعمال الجمعة ، قال : ويستحبّ أن يدعو بدعاء المظلوم عند قبر ابي عبدالله وهو : اَللّـهُمَّ اِنّي اَعْتَزُّ بِدينِكَ وَاكْرُمُ بِهِدايَتِكَ وَفُلانٌ يُذِلُّني بِشَرِّهِ وَيُهينُني بِاَذِيَّتِهِ، وَيُعيبُني بِوَلاءِ اَوْلِيائِكَ، وَيَبْهَتُني بِدَعْواهُ، وَقَدْ جِئْتُ اِلى مَوْضِعِ الدُّعاءِ وَضَمانِكَ الاِْجابَةَ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاَعْدني عَلَيْهِ السّاعَةَ السّاعَةَ، ثمّ تنكبّ على القبر وتقول : مَوْلايَ اِمامي مَظْلُومٌ اسْتَعْدي عَلى ظالِمِهِ النَّصْرَ النَّصْرَ حتّى ينقطع النّفس ."},{"type":"Text","content":"السّادس عشر : من اعمال ذلك الحرم الشّريف الدّعاء الَّذي رواه ابن فهد (رحمه الله)في عدّة الدّاعي عن الصّادق (عليه السلام)قال : من كان له الى الله تعالى حاجة فليقف عند رأس الحسين (عليه السلام) ويقول : يا اَبا عَبْدِاللهِ، اَشْهَدُ اَنَّكَ تَشْهَدُ مَقامي وَتَسْمَعُ كَلامي وَاَنَّكَ حَيٌّ عِنْدَ رَبِّكَ تُرْزَقُ فَاسْأَلْ رَبَّكَ وَرَبِّي في قَضاءِ حَوائِجي، فأنّه يقضى حاجته ان شاء الله تعالى ."},{"type":"Text","content":"السّابع عشر : من جملة الاعمال في ذلك الحرم الشّريف الصّلاة عند الرّأس المقدّس ركعتان بسورة الرّحمن وسورة تبارك ."},{"type":"Text","content":"روى السّيد ابن طاوُس (رحمه الله) انّ من صلاها كتب الله له خمساً وعشرين حجّة مقبولة مبرورة مع رسول الله (صلى الله عليه وآله وسلم) ."},{"type":"Text","content":"الثّامن عشر : من الاعمال تحت تلك القبّة السّامية الاستخارة، وصفتها على ما أوردها العلاّمة المجلسي (رحمه الله)ومصدر الرّواية كتاب قُرب الاسناد للحميري ، قال بسند صحيح عند الصّادق (عليه السلام) قال : ما استخار الله عزّوجلّ عبد في أمر قط مائة مرّة يقف عند رأس الحُسين صلوات الله عليه ويقول : اَلْحَمْدُ للهِِ وَلا اِلـهَ اِلاَّ اللهُ وَسُبْحانَ اللهِ فيحمد الله ويهلّله ويسبّحه ويمجّده ويثنى عليه بما هو أهله ويستخيره مائة مرّة الاّ رماه اللهُ تبارك وتعالى بأخير الامرين . وعلى رواية اخرى يستخير الله مائة مرّة قائلاً : اَسْتَخيرُ اللهَ بِرَحْمَتِهِ خِيَرَةً فِي عافِيَة ."},{"type":"Text","content":"التّاسع عشر : روى الشّيخ الاجل الكامل أبو القاسم جعفر بن قولويه القمّي (رحمه الله)عن الصّادق صلوات الله عليه انّه قال : اذا زرتم أبا عبد الله الحسين (عليه السلام) فألزموا الصّمت الاّ عن الخير، وانّ ملائكة اللّيل والنّهار من الحفظة يحضرون عند الملائكة الّذين هم في الحاير، ويصافحونهم فلا يجيبهم ملائكة الحائر من شدّة البكاء وهم ابداً يبكون ويندبون لا يفترون الاّ عند الزّوال وعند طلوع الفجر فالحفظة ينتظرون حين يحين الظّهر أو يطلع الفجر فيكالمونهم ويسألونهم عن امور من السّماء وهم لا يمسكون عن الدّعاء والبكاء فيما بين هاتين الفترتين ."},{"type":"Text","content":"وروي ايضاً عنه (عليه السلام) انّ الله تعالى قد وكّل على قبر الحسين صلوات الله عليه أربعة آلاف من الملائكة شعث غبر على هيئة اصحاب العزاء يبكون عليه من طلوع الفجر الى الزّوال فاذا زالت الشّمس عرجوا وهبط مثلهم يبكون الى طلوع الفجر، والاحاديث في ذلك كثيرة ويبدو من هذه الاحاديث استحباب البكاء عليه في ذلك الحرم الطّاهر بل الجدير أن يعد البكاء عليه والرّثاء له من اعمال تلك البُقعة المباركة الّتي هي بيت الاحزان للشّيعة الموالين، ويستفاد من حديث صفوان عن الصّادق (عليه السلام) انّه لا يهنأ للمرء أكله وشربه لو اطّلع على تضرّع الملائكة الى الله تعالى في اللّعن على قتلة امير المؤمنين والحسين (عليهما السلام) ، ونياح الجنّ عليهما وبكاء الملائكة الّذين هم حول ضريح الحسين (عليه السلام) وشدّة حزنهم . وفي حديث عبد الله بن حماد البصري عن الصّادق صلوات الله وسلامه عليه انّه قال : بلغني انّ قوماً يأتون من نواحي الكوفة وناساً من غيرهم ونساء يندبنه فمن بين قاريء يقرأ وقاص يقصّ أي يذكر المصائب ونادب يندب وقائل يقول المراثي ، فقلت له : نعم جعلت فداك قد شهدت بعض ما تصف ، فقال : الحمد لله الَّذي جعل في النّاس من يفد الينا ويمدحنا ويرثي لنا، وجعل عدوّنا من يطعن عليهم من قرابتنا أو غيرهم يهدون بهم ويقبّحون ما يصنعون ."},{"type":"Text","content":"وقد ورد في أوائل هذا الحديث انّه يبكيه من زاره ويحزن له من لم يزره، ويحترق له من لم يشهده، ويرحمه من نظر الى قبر ابنه عند رجليه في ارض فلاة ولا حميم قربة، ولا قريب، ثمّ منع الحقّ وتوازر عليه أهل الرّدة حتّى قتلوه وضيّعوه وعرضوه للسّباع، ومنعوه شرب ماء الفرات الَّذي يشربه الكلاب وضيّعوا حقّ رسُول الله (صلى الله عليه وآله وسلم) ووصيّته به وبأهل بيته ."},{"type":"AboutText","content":"وروى ايضاً ابن قولويه عن حارث الاعور عن امير المؤمنين صلوات الله عليه انّه قال : بأبي واُمّي الحسين الشّهيد خلف الكوفة، والله كأنّي أرى وحُوش الصّحراء من كلّ نوع قد مدّت اعناقها على قبره تبكي عليه ليلها حتّى الصّباح فاذا كان كذلك فايّاكم والجفاء، والاخبار في ذلك كثيرة ."},{"type":"Text","content":"العشرون : قال السّيد ابن طاوُس (رحمه الله) يستحبّ للمرء اذا فرغ من زيارته (عليه السلام)وأراد الخروج من الرّوضة المقدّسة أن ينكبّ على الضّريح ويُقبّله ويقول : اَلسَّلامُ عَلَيْكَ يا مَوْلايَ، اَلسَّلامُ عَلَيْكَ يا حُجَّةَ اللهِ، اَلسَّلامُ عَلَيْكَ يا صِفْوَةَ، اللهِ اَلسَّلامُ عَلَيْكَ يا خالِصَةَ اللهِ، اَلسَّلامُ عَلَيْكَ يا قَتيلَ الظَّماءِ، اَلسَّلامُ عَلَيْكَ يا غَريبَ الْغُرَباءِ، اَلسَّلامُ عَلَيْكَ سَلامَ مُوَدِّع لا سَئِم وَلا قال، فَاِنْ اَمْضِ فَلا عَنْ مَلالَة، وَاِنْ اُقِمْ فَلا عَنْ سُوءِ ظَن بِما وَعَدَ اللهُ الصّابِرينَ، لا جَعَلَهُ اللهُ آخِرَ الْعَهْدِ مِنّي لِزِيارَتِكَ، وَرَزَقَنِيَ اللهُ الْعَوْدَ اِلى مَشْهَدِكَ وَالْمَقامَ بِفَنائِكَ وَالْقِيامَ فِي حَرَمِكَ وَاِيّاهُ اَسْألُ اَنْ يُسْعِدَني بِكُمْ وَيَجْعَلَني مَعَكُمْ فِي الدُّنْيا وَالاْخِرَةِ ."}],"preview":"سُبْحانَ ذِي الْجَلالِ الْباذِخِ الْعَظيمِ، سُبْحانَ ذِي الْعِزِّ الشّامِخِ الْمُنيفِ سُبْحانَ ذِي الْمُلْكِ الْفاخِرِ الْقَديمِ، سُبْحانَ ذِي الْبَهْجَةِ وَالْجَمالِ، سُبْحانَ مَن","hasTranslate":false},{"id":"mf_ar_207","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلب الثّاني : في كيفيّة زيارَته (عليه السلام) :","title":"قدّس الله رُوحه :","blocks":[{"type":"AboutText","content":"اعلم انّ الزّيارات المرويّة للحسين (عليه السلام) نوعان فزيارات مُطلقة غير مقيّدة بزمان معيّن وزيارات مخصوصة تخصّ مواقيت خاصّة وسنذكر هذه الزّيارات في ضمن مطالب ثلاثة ."},{"type":"Text","content":"في الزّيارات المطلقة للحسين (عليه السلام) وهِيَ كثيرة وَنحنُ نكتفي بِعِدّة مِنها :"},{"type":"Text","content":"الزّيارَةُ الاُولى"},{"type":"Text","content":"روى الكليني في الكافي بسنده عن الحسين بن ثُوير قال : كنتُ أنا ويُونس بن ظبيان والمفضّل بن عمر وأبو سلمة السّراج جلوساً عند أبي عبد الله جعفر بن محمّد (عليه السلام) وكانَ المتكلّم يُونس وكان اكبرنا سنّاً، فقال له : جعلت فداك انّي أحضر مجالِس هؤلاء القوم يعني ولد عبّاس فما أقول ؟ قال : اذا حضرتهم وذكرتنا فقُل : اَللّـهُمَّ اَرِنَا الرَّخاءَ وَالسُّرُورَ، لتبلغ ما تريد من الثّواب أو الرّجوع عند الرّجعة ، فقلت : جعلت فداك انّي كثيراً ما أذكر الحسين (عليه السلام) فأيّ شيء أقول ؟ قال : تقول وتعيدُ ذلك ثلاثاً : صَلَّى اللهُ عَلَيْكَ يا اَبا عَبْدِاللهِ، فانّ السّلام يصل اليه من قريب وبعيد. ثمّ قال : انّ أبا عبد الله (عليه السلام) لمّا مضى بكت عليه السّماوات السّبع والارضُون السّبع وما فيهنّ وما بينهنّ ومن يتقلّب في الجنّة والنّار من خلق ربّنا وما يُرى وما لا يُرى بكاءً على أبيعبد الله (عليه السلام) الاّ ثلاثة أشياء لم تبك عليه ، قلت : جُعلت فداك ما هذه الثلاثة الاشياء ؟ قال : لم تبك عليه البصرة ولا الدّمشق ولا آل عثمان ، قال : قلت: جعلت فداك انّي أريد أن أزوره فكيف أقول وكيف أصنع ؟ قال : اذا أتيت أبا عبد الله (عليه السلام)فاغتسل على شاطيء الفرات ثمّ البس ثيابك الطّاهرة ثمّ امش حافياً فانّك في حرم من حرم الله ورسُوله بالتّكبير والتّهليل والتّمجيد والتّعظيم لله كثيراً والصّلاة على محمّد وأهل بيته حتّى تصير الى باب الحائر ثمّ قُل : اَلسَّلامُ عَلَيْكَ يا حُجَّةَ اللهِ وَابْنَ حُجَّتِهِ، اَلسَّلامُ عَلَيْكُمْ يا مَلائِكَةَ اللهِ وَزُوّارَ قَبْرِ ابْنِ نَبِيِّ اللهِ، ثمّ قِف فكبّر ثلاثين تكبيرة ثمّ امش الى القبر من قبل وجهه واستقبل وجهك بوجهه واجعل القبلة بين كتفيك ثمّ تقول :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا حُجَّةَ اللهِ وَابْنَ حُجَّتِهِ، اَلسَّلامُ عَلَيْكَ يا قَتيلَ اللهِ وَابْنَ قَتيلِهِ، اَلسَّلامُ عَلَيْكَ يا ثارَ اللهِ وَابْنَ ثارِهِ، اَلسَّلامُ عَلَيْكَ يا وِتْرَ اللهِ الْمَوْتُورَ فِي السَّماواتِ وَالاَْرْضِ، اَشْهَدُ اَنَّ دَمَكَ سَكَنَ فِي الْخُلْدِ وَاقْشَعَرَّتْ لَهُ اَظِلَّةُ الْعَرْشِ، وَبَكى لَهُ جَميعُ الْخَلائِقِ وَبَكَتْ لَهُ السَّماواتُ السَّبْعُ وَالاَْرَضُونَ السَّبْعُ وَما فيهِنَّ وَما بَيْنَهُنَّ وَمَنْ يَتَقَلَّبُ فِي الْجَنَّةِ وَالنّارِ مِنْ خَلْقِ رَبِّنا وَما يُرى وَما لا يُرى، اَشْهَدُ اَنَّكَ حُجَّةُ اللهِ وَابْنُ حُجَّتِهِ، وَاَشْهَدُ أنَّكَ قَتيلُ اللهِ وابنُ قَتيلِهِ واَشْهَدُ أنَّكَ ثارُ اللهِ وابْنَ ثارِهِ، وَاَشْهَدُ اَنَّك وِتْرُ اللهِ الْمَوْتورُ فِي السَّماواتِ وَالاَْرْضِ، وَاَشْهَدُ اَنَّكَ قَدْ بَلَّغْتَ وَنَصَحْتَ وَوَفَيْتَ وَاَوْفَيْتَ وَجاهَدْتَ فِي سَبيلِ اللهِ وَمَضَيْتُ لِلَّذي كُنْتَ عَلَيْهِ شهَيداً وَمُسْتَشْهِداً وَشاهِداً وَمَشْهُوداً، اَنَا عَبْدُاللهِ وَمَوْلاكَ وَفِي طاعَتِكَ وَالْوافِدُ اِلَيْكَ اَلَْتمِسُ كَمالَ الْمَنْزِلَةِ عِنْدَ اللهِ وَثَباتَ الْقَدَمِ فِي الْهِجْرَةِ اِلَيْكَ، وَالسَّبيلَ الَّذي لا يَخْتَلِجُ دوُنَكَ مِنَ الدُّخُولِ فِي كِفالَتِكَ الَّتي اَمَرْتَ بِها، مَنْ اَرادَ اللهَ بَدَأَ بِكُمْ، بِكُمْ يُبَيِّنُ اللهُ الْكَذِبَ، وَبِكُمْ يُباعِدُ اللهُ الزَّمانَ الْكَلِبَ، وَبِكُمْ فَتَحَ اللهُ وَبِكُمْ يَخْتِمُ اللهُ، وَبِكُمْ يَمْحُو ما يَشاءُ وَيُثْبِتُ، وبِكُمْ يَفُكُّ الذُّلَّ مِنْ رِقابِنا، وَبِكُمْ يُدْرِكُ اللهُ وِتْرَةَ كُلِّ مُؤْمِن يَطْلَبُ بِها، وَبِكُمْ تَنْبِتُ الاَْرْضُ اَشْجارَها، وَبِكُمْ تُخْرِجُ الاَْرْضُ ثِمارَها، وَبِكُمْ تُنْزِلُ السَّماءُ قَطْرَها وَرِزْقَها، وَبِكُمْ يَكْشِفُ اللهُ الْكَرْبَ، وَبِكُمْ يُنَزِّلُ اللهُ الْغَيْثَ، وَبِكُمْ تُسَبِّحُ الاَْرْضُ الَّتي تَحْمِلْ اَبْدانَكُمْ وَتَسْتَقِرُّ جِبالُها عَنْ مَراسيها اِرادَةُ الرَّبِّ في مَقاديرِ اُمُورِهِ تَهْبِطُ اِلَيْكُمْ وَتَصْدُرُ مِنْ بُيُوتِكُمْ وَالصّادِرُ عَمّا فُصِّلَ مِنْ اَحْكامِ الْعِبادِ، لُعِنَتْ اُمَّةٌ قَتَلَتْكُمْ، وَاُمَّةٌ خالَفَتْكُمْ، وَاُمَّةٌ جَحَدَتْ وَلايَتَكُمْ، وَاُمَّةٌ ظاهَرَتْ عَلَيْكُمْ، وَاُمَّةٌ شَهِدَتْ وَلَمْ تُسْتَشْهَدْ، اَلْحَمْدُ للهِ الَّذي جَعَلَ النّارَ مَأواهُمْ وَبِئْسَ وِرْدُ الْوارِدينَ، وَبِئْسَ الْوِرْدُ الْمَوْرُودُ، وَالْحَمْدُ للهِ رَبِّ الْعالَمينَ."},{"type":"Text","content":"فقل ثلاث مرات : وَصَلَّى اللهُ عَلَيْكَ يا اَبا عَبْدِاللهِ وقُل ثلاث مرّة : اَنَا اِلَى اللهِ مِمَّنْ خالَفَكَ بَريءٌ ثمّ تقوم فتأتي ابنه عليّاً وهو عند رجله فتقُول : اَلسَّلامُ عَلَيْكَ يا ابْنَ رَسُولِ اللهِ، اَلسَّلامُ عَلَيْكَ يا ابْنَ اَميرِ الْمُؤْمِنينَ، اَلسَّلامُ عَلَيْكَ يا ابْنَ الْحَسَنِ وَالْحُسَيْنِ، اَلسَّلامُ عَلَيْكَ يا ابْنَ خَديجَةَ وَفاطِمَةَ صَلَّى اللهُ عَلَيْكَ صَلّى اللهُ عَلَيْكَ صَلّى اللهُ عَلَيْكَ، لَعَنَ اللهُ مَنْ قَتَلَكَ تقول ذلك ثلاثاً، وثلاثاً: انا اِلَى اللهِ مِنْهُمْ بَريءٌ، ثمّ تقوم فتومىء بيدك الى الشّهداء رضي الله عنهم وتقُولُ : اَلسَّلامُ عَلَيْكُمْ اَلسَّلامُ عَلَيْكُمْ اَلسَّلامُ عَلَيْكُمْ، فُزْتُمْ وَاللهِ فُزْتُمْ وَاللهِ فُزْتُمْ وَاللهِ، فَلَيْتَ اَنّي مَعَكُمْ فَاَفُوزَ فَوْزاً عَظيماً، ثمّ تدور فتجعل قبر أبي عبد الله (عليه السلام)بين يَديك أي تقف خلف القبر المُطهّر فتصلّي ستّ ركعات وقد تمّت زيارتك فإنْ شئت فانصَرف ."},{"type":"AboutText","content":"أقول : قد روى ايضاً هذه الزّيارة الشّيخ الطّوسي في التّهذيب، والصّدوق في كتاب من لا يحضره الفقيه ، وقال الصّدوق: انّي قد ذكرت في كتابي المزار والمقتل أنواعاً من الزّيارات وانتخبت هذه الزّيارة لهذا الكتاب فانّها أصَحّ الزّيارات عندي رواية، وهي تكفينا وتفي بالمقصود ، انتهى ."},{"type":"Text","content":"الزّيارَةُ الثّانِيةُ"},{"type":"Text","content":"روى الشّيخ الكليني عن الامام علي النّقي (عليه السلام) قال : تقول عند الحسين (عليه السلام) :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا اَبا عَبْدِاللهِ، اَلسَّلامُ عَلَيْكَ يا حُجَّةَ اللهِ فِي اَرْضِهِ وَشاهِدَهُ عَلى خَلْقِهِ، اَلسَّلامُ عَلَيْكَ يا بْنَ رَسُولِ اللهِ، اَلسَّلامُ عَلَيْكَ يا بْنَ عَليِّ الْمُرْتَضى، اَلسَّلامُ عَلَيْكَ يا بْنَ فاطِمَةَ الزَّهْراءِ، اَشْهَدُ اَنَّكَ قَدْ اَقَمْتَ الصَّلاةَ وَآتَيْتَ الزَّكاةَ، وَاَمَرْتَ بِالْمَعْرُوفِ وَنَهَيْتَ عَنِ الْمُنْكَرِ، وَجاهَدْتَ فِي سَبيلِ اللهِ حَتّى اَتاكَ الْيَقينُ، فَصَلّى اللهُ عَلَيْكَ حَيّاً وَميّتاً، ثمّ تضع خدّك الايمن على القبر وتقول : اَشْهَدُ اَنَّكَ عَلى بَيِّنَة مِنْ رَبِّكَ، جِئْتُ مُقِرّاً بِالذُّنُوبِ لِتَشْفَعَ لي عِنْدَ رَبِّكَ يَا بْنَ رَسُولِ اللهِ، ثم سمّ الائمة (عليهم السلام) بأسمائهم واحداً بعد واحد وقُل : اَشْهَدُ اَنَّكُمْ حُجَجُ اللهِ (ثمّ قُل) : اُكْتُبْ لي عِنْدَكَ ميثاقاً وَعَهْداً اِنّي اَتَيْتُكَ مُجَدِّداً الْميثاقَ فَاشْهَدْ لي عِنْدَ رَبِّكَ اِنَّكَ اَنْتَ الشّاهِدُ ."},{"type":"Text","content":"الزّيارَةُ الثّالِثَةُ"},{"type":"Text","content":"هيَ ما رواها ابن طاوُس في المزار وروى لها فضلاً كثيراً ، قال بحذف الاسناد عن جابر الجُعفي ، قال : قال الصّادق (عليه السلام) لجابر : كَم بَيْنك وبين قبر الحسين (عليه السلام) ؟ قال : قلت: بأبي أنت وأمّي يوم وبعض يوم آخر ، قال : فتزُوره ؟ فقال : نعم ، قال : فقال : اَلا اُبشرك اَلا افرحك ببعض ثوابه ؟ قلت : بلى جعلتُ فداك ، قال : فقال لي: انّ الرّجُل منكم ليأخذ في جهازه ويتهيّأ لزيارته فيتباشر به أهل السّماء، فاذا خرج من باب منزله راكباً أو ماشياً وكّل الله به أربعة آلاف ملك من الملائكة يصلّون عليه حتّى يوافي الحسين (عليه السلام) ، يا مفضّل إنْ أتيت قبر الحسين بن علي (عليهما السلام) فقف بالباب وقُل هذه الكلمات فانّ لك بكلّ كلمة كفلاً من رحمة الله ، فقلت : ما هي جعلت فداك ؟ قال : تقول :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا وارِثَ آدَمَ صَفْوَةِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ نُوح نَبِيِّ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ اِبْراهيمَ خَليلِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ مُوسى كَليمِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ عيسى رُوحِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ مُحَمَّد سَيِّدِ رُسُلِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ عَليِّ اَميرِ الْمُؤْمِنينَ وَخَيْرِ الْوَصِيّينَ، اَلسَّلامُ عَلَيْكَ يا وارِثَ الْحَسَنِ الرَّضِيِّ الطّاهِرِ الرّاضِى الْمَرْضِيِّ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الْوَصِيُّ الْبَرُّ التَّقِيُّ، اَلسَّلامُ عَلَيْكَ وَعَلى الاَْرْواحِ الَّتي حَلَّتْ بِفِنائِكَ وَاَناخَتْ بِرَحْلِكَ، اَلسَّلامُ عَلَيْكَ وَعَلَى الْمَلائِكَةِ الْحافّينَ بِكَ، اَشْهَدُ اَنَّكَ قَدْ اَقَمْتَ الصَّلاةَ وَآتَيْتَ الزَّكاةَ وَاَمَرْتَ بِالْمَعْرُوفِ وَنَهَيْتَ عَنِ الْمُنْكَرِ وَجاهَدْتَ الْمُلْحِدينَ وَعَبَدْتَ اللهَ حَتّى اَتاكَ الْيَقينُ، اَلسَّلامُ عَلَيْكَ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ ."},{"type":"Text","content":"ثمّ تسعى الى القبر فَلَكَ بكلّ قدم رفعتها أو وضعتها كثواب المتشحّط بدمه في سبيل اللهِ، فاذا وصلت الى القبر ووقفت عنده فامرر عليه يدك وقُل : اَلسَّلامُ عَلَيْكَ يا حُجَّةَ اللهِ فِي اَرْضِهِ، ثمّ تمضي الى صلاتِك ولك بكلّ ركعة ركعتها عنده كثواب مَنْ حجّ ألف حجّة واعتمر ألف عُمرة واعتق ألف رقبة، وكأنّما وقف في سبيل الله ألف مرّة مع نبيّ مُرسل ... الخبر ."},{"type":"Text","content":"وقد مرّت هذه الرّواية مع اختلاف يسير في آداب زيارة الحسين (عليه السلام)على رواية مفضّل بن عمر ."},{"type":"Text","content":"الزّيارَةُ الرّابِعَةُ"},{"type":"Text","content":"عَن معاوية بن عمّار قال : قلت لابي عبد الله (عليه السلام) : ما أقول اذا أتيت قبر الحسين (عليه السلام) ؟ قال قُل : اَلسَّلامُ عَلَيْكَ يا اَبا عَبْدِاللهِ صَلَّى اللهُ عَلَيْكَ يا اَبا عَبْدِاللهِ، رَحِمَكَ اللهُ يا اَبا عَبْدِاللهِ، لَعَنَ اللهُ مَنْ قَتَلَكَ، وَلَعَنَ اللهُ مَنْ شَرِكَ فِي دَمِكَ، وَلَعَنَ اللهُ مَنْ بَلَغَهُ ذلِكَ فَرَضِيَ بِهِ اَنَا اِلَى اللهِ مَنْ ذلِكَ بَريءٌ ."},{"type":"Text","content":"الزّيارَةُ الخامِسَةُ"},{"type":"Text","content":"بسند مُعتبر عن الكاظم (عليه السلام) انّه قال لابراهيم بن أبي البلاد : ماذا تقول اذا زرت الحسين (عليه السلام) ؟ فأجاب : أقول : اَلسَّلامُ عَلَيْكَ يا اَبا عَبْدِاللهِ، اَلسَّلامُ عَلَيْكَ يا بْنَ رَسُولِ اللهِ، اَشْهَدُ اَنَّكَ قَدْ اَقَمْتَ الصَّلاةَ، وَآتَيْتَ الزَّكاةَ، وَاَمَرْتَ بِالْمَعْرُوفِ، وَنَهَيْتَ عَنِ المُنْكَرِ، وَدَعَوْتَ اِلى سَبيلِ رَبِّكَ بِالْحِكْمَةِ وَالْمَوْعِظَةِ الْحَسَنَةِ، وَاَشْهَدُ اَنَّ الَّذينَ سَفَكُوا دَمَكَ وَاسْتَحَلُّوا حُرْمَتَكَ مَلْعُونُونَ مُعَذَّبُونَ عَلى لِسانِ داوُدَ وَعيسَى بْنِ مَرْيَمَ، ذلِكَ بِما عَصَوْا وَكانُوا يَعْتَدُونَ، فقال (عليه السلام): بلى ."},{"type":"Text","content":"الزّيارَةُ السّادِسَةُ"},{"type":"Text","content":"عن عمّار عن الصّادق (عليه السلام) قال : تقول اذا انتهيت الى قبره (عليه السلام) :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا بْنَ رَسُولِ اللهِ، اَلسَّلامُ عَلَيْكَ يا بْنَ اَميرِ الْمُؤْمِنينَ، اَلسَّلامُ عَلَيْكَ يا اَبا عَبْدِاللهِ، اَلسَّلامُ عَلَيْكَ يا سَيِّدَ شَبابِ اَهْلِ الْجَنَّةِ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَلسَّلامُ عَلَيْكَ يا مَنْ رِضاهُ مِنْ رِضَا الرَّحْمنِ وَسَخَطُهُ مِنْ سَخَطِ الرَّحْمنِ، اَلسَّلامُ عَلَيْكَ يا اَمينَ اللهِ وَحُجَّةَ اللهِ وَبابَ اللهِ وَالدَّليلَ عَلَى اللهِ وَالدّاعي اِلَى اللهِ ،اَشْهَدُ اَنَّكَ قَدْ حَلَّلْتَ حَلالَ اللهِ، وَحَرَّمْتَ حَرامَ اللهِ، وَاَقَمْتَ الصَّلاةَ، وَآتَيْتَ الزَّكاةَ، وَاَمَرْتَ بِالمَعْروُفِ، وَنَهَيْتَ عَنِ الْمُنْكَرِ، وَدَعَوْتَ اِلى سَبيلِ رَبِّكَ بِالْحِكْمَةِ وَالْمَوْعِظَةِ الْحَسَنَةِ، وَاَشْهَدُ اَنَّكَ وَمَنْ قُتِلَ مَعَكَ شُهَداءٌ، اَحْياءٌ عِنْدَ رَبِّكُمْ تُرْزَقُونَ، وَاَشْهَدُ اَنَّ قاتِلَكَ فِي النّارِ اَدينُ اللهَ بِالْبَراءَةِ مِمَّنْ قَتَلَكَ وَمِمَّنْ قاتَلَكَ وَشايَعَ عَلَيْكَ، وَمِمَّنْ جَمَعَ عَلَيْكَ وَمِمَّنْ سَمِعَ صَوْتَكَ وَلَمْ يُعِنْكَ، يا لَيْتَني كُنْتُ مَعَكُمْ فَاَفُوزَ فَوْزاً عَظيماً ."},{"type":"Text","content":"الزّيارَةُ السّابِعَةُ"},{"type":"Text","content":"روى الشّيخ في المصباح عن صفوان (أقول: هذه الزّيارات الثّلاث مرويّة عن كتاب المزار لابن قولويه) قال : استأذنت الصّادق (عليه السلام) لزيارة مولاي الحُسين (عليه السلام)وسألته أن يعرفني ما أعمل عليه ، فقال : يا صفوان صم ثلاثة ايّام قبل خروجك واغتسل في اليوم الثّالث ، ثمّ اجمع اليك أهلك ، ثمّ قُل : اَللّـهُمَّ اِنّي اسْتَوْدِعُكَ، الدُّعاءَ ثمّ علّمه دعاء يدعو به اذا أتى الفرات، ثمّ قال: ثمّ اغتسل من الفرات فانّ أبي حدّثني عن آبائه (عليهم السلام) قال: قال رسول الله(صلى الله عليه وآله وسلم): انّ ابني هذا الحسين (عليه السلام) يُقتل بعدي على شاطيء الفرات ومن اغتسل من الفرات تساقطت خطاياه كهيئة يوم ولدته امّه، فاذا اغتسلت فقُل في غُسلكَ : بِسْمِ اللهِ وَبِاللهِ، اَللّـهُمَّ اجْعَلْهُ نُوراً وَطَهُوراً وَحِرْزاً وَشِفاءً مِنْ كُلِّ داء وَسُقْم وَآفَة وَعاهَة، اَللّـهُمَّ طَهِّرْ بِهِ قَلْبي وَاشْرَحْ بِهِ صَدْري وَسَهِّلْ لي بِهِ اَمْري، فاذا فرغت من غُسلك فالبس ثوبين وصلّ ركعتين خارج المشرعة وهو المكان الَّذي قال الله تعالى : (وَفِي الاَْرْضِ قِطَعٌ مُتَجاوِراتٌ وَجَنّاتٌ مِنْ اَعْناب وَزَرْعٌ وَنَخيلٌ صِنْوانٌ وَغَيْرَ صِنْوان يُسْقى بِماء واحِد وَنُفَضِّلُ بَعْضَها عَلى بَعْض فِي الاَْكْلِ) فاذا فرغت من صلاتك فتوجّه نحو الحائر وعليك السّكينة والوقار وقصّر خطاك فانّ الله تعالى يكتب لك بكُلّ خطوة حجّة وعُمرة، وصر خاشِعاً قلبك باكية عينك واكثر من التّكبير والتّهليل والثّناء على الله عزّوجل والصّلاة على نبيّه (صلى الله عليه وآله وسلم)والصّلاة على الحسين (عليه السلام) خاصّة ولعن من قتله والبراءة ممّن أسّس ذلك عليه فاذا أتيت باب الحائر فقف وقُل : اَللهُ اَكْبَرُ كَبيراً، وَالْحَمْدُ للهِِ كَثيراً، وَسُبْحانَ اللهِ بُكْرَةً وَاَصيلاً، اَلْحَمْدُ للهِ الَّذي هَدانا لِهذا وَما كُنّا لِنَهْتَدِيَ لَوْ لا اَنْ هَدانَا اللهُ، لَقَدْ جاءَتْ رُسُلُ رَبِّنا بِالْحَقِّ ثمّ قُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا رَسُولَ اللهِ، اَلسَّلامُ عَلَيْكَ يا نَبِيَّ اللهِ، اَلسَّلامُ عَلَيْكَ يا خاتَمَ النَّبِيّينَ، اَلسَّلامُ عَلَيْكَ يا سَيِّدَ الْمُرْسَلينَ، اَلسَّلامُ عَلَيْكَ يا حَبيبَ اللهِ، اَلسَّلامُ عَلَيْكَ يا اَميرَ الْمُؤْمِنينَ، اَلسَّلامُ عَلَيْكَ يا سَيِّدَ الْوَصِيّينَ، اَلسَّلامُ عَلَيْكَ يا قائِدَ الْغُرِّ الُْمحَجَّلينَ، اَلسَّلامُ عَلَيْكَ يَا بْنَ فاطِمَةَ سَيِّدَةِ نِساءِ الْعالَمينَ، اَلسَّلامُ عَلَيْكَ وَعَلَى الاَْئِمَّةَ مِنْ وُلْدِكَ، اَلسَّلامُ عَلَيْكَ يا وَصِيَّ اَميرِ الْمُؤْمِنينَ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الصِّديقُ الشَّهيدُ، اَلسَّلامُ عَلَيْكَم يا مَلائِكَةَ اللهِ المُقيمينَ فِي هذَا المَقامِ الشَّريفِ، اَلسَّلامُ عَلَيْكُمْ يا مَلائِكَةَ رَبِّي الُْمحْدِقينَ بِقَبْرِ الْحُسَيْنِ عليه السلام، اَلسَّلامُ عَلَيْكُمْ مِنّي اَبَداً ما بَقيتُ وَبَقِيَ اللَّيْلُ وَالنَّهارُ ."}],"preview":"اعلم انّ الزّيارات المرويّة للحسين (عليه السلام) نوعان فزيارات مُطلقة غير مقيّدة بزمان معيّن وزيارات مخصوصة تخصّ مواقيت خاصّة وسنذكر هذه الزّيارات في ضمن مطالب ثلاثة .","hasTranslate":false},{"id":"mf_ar_208","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلب الاوّل :","title":"ثمّ تقول :","blocks":[{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا اَبا عَبْدِاللهِ، اَلسَّلامُ عَلَيْكَ يَا بْنَ رَسُولِ الله، اَلسَّلامُ عَلَيْكَ يَا بْنَ اَميرِ الْمُؤْمِنينَ عَبْدُكَ وَابْنُ عَبْدِكَ وَابْنُ اَمَتِكَ الْمُقِرُّ بِالرِّقِّ وَالتّارِكُ لِلْخِلافِ عَلَيْكُمْ وَالْمُوالي لِوَلِيِّكُمْ وَالْمُعادي لِعَدُوِّكُمْ، قَصَدَ حَرَمَكَ وَاسْتَجارَ بِمَشْهَدِكَ، وَتَقَرَّبَ اِلَيْكَ بِقَصْدِكَ، أَاَدْخُلُ يا رَسُولَ اللهِ، أَاَدْخُلُ يا نَبِيَّ اللهِ ءَاَدْخُلُ يا اَميرَ الْمُؤْمِنينَ، أَاَدْخُلُ يا سَيِّدَ الْوَصِيّينَ، أَاَدْخُلُ يا فاطِمَةَ سَيِّدَةَ نِساءِ الْعالَمينَ، أَاَدْخُلُ يا مَوْلايَ يا اَبا عَبْدِاللهِ، أَاَدْخُلُ يا مَوْلايَ يَا بْنَ رَسُولِ اللهِ ."},{"type":"Text","content":"فإنْ خشع قلبكَ ودمعت عينك فهو علامة الاذن ثمّ ادخل وقُل : اَلْحَمْدُ للهِ الْواحِدِ الاَْحَدِ الْفَرْدِ الصَّمَدِ الَّذي هَداني لِوِلايَتِكَ، وَخَصَّني بِزِيارَتِكَ، وَسَهَّلَ لي قَصْدَكَ، ثمّ ائت باب القُبّة وقِف مِن حيث يلي الرّأس وقُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا وارِثَ آدَمَ صَفْوَةِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ نُوح نَبِيِّ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ اِبْراهيمَ خَليلِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ مُوسى كَليمِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ عيسى رُوحِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ مُحَمَّد حَبيبِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ اَميرِ الْمُؤْمِنينَ عليه السلام، اَلسَّلامُ عَلَيْكَ يَا بْنَ مُحَمَّد الْمُصْطَفى، اَلسَّلامُ عَلَيْكَ يَا بْنَ عَلِيِّ الْمُرْتَضى، اَلسَّلامُ عَلَيْكَ يَا بْنَ فاطِمَةَ الزَّهْراءِ، اَلسَّلامُ عَلَيْكَ يَا بْنَ خَديجَةَ الْكُبْرى، اَلسَّلامُ عَلَيْكَ يا ثارَ اللهِ وَابْنَ ثارِهِ وَالْوِتْرَ الْمَوْتُورَ، اَشْهَدُ اَنَّكَ قَدْ اَقَمْتَ الصَّلاةَ وَآتَيْتَ الزَّكاةَ، وَاَمَرْتَ بِالْمَعْرُوفِ وَنَهَيْتَ عَنْ الْمُنْكَرِ، وَاَطَعْتَ اللهَ وَرَسُولَهُ حَتّى اَتاكَ الْيَقينُ، فَلَعَنَ اللهُ اُمَّةً قَتَلَتْكَ، وَلَعَنَ اللهُ اُمَّةً ظَلَمَتْكَ، وَلَعَنَ اللهُ اُمَّةً سَمِعَتْ بِذلِكَ فَرَضِيَتْ بِهِ، يا مَوْلايَ يا اَبا عَبْدِاللهِ، اَشْهَدُ اَنَّكَ كُنْتَ نُوراً فِي الاَْصْلابِ الشّامِخَةِ، وَالاَْرْحامِ الْمُطَهَّرَةِ، لَمْ تُنَجِّسْكَ الْجاهِلِيَّةُ بِاَنْجاسِها، وَلَمْ تُلْبِسْكَ مِنْ مُدْلَهِمّاتِ ثِيابِها، وَاَشْهَدُ اَنَّكَ مِنْ دَعائِمِ الدّينِ، وَاَرْكانِ الْمُؤْمِنينَ، وَاَشْهَدُ اَنَّكَ الاِْمامُ الْبَرُّ التَّقِيُّ الرَّضِيُّ الزَّكِيُّ الْهادِي الْمَهْدِىُّ وَاَشْهَدُ اَنَّ الاَْئِّمَةَ مِنْ وُلْدِكَ كَلِمَةُ التَّقْوى، وَاَعْلامُ الْهُدى، وَالْعُروَةُ الْوُثْقى، وَالْحُجَّةُ عَلى اَهْلِ الدُّنْيا، وَاُشْهِدُ اللهَ وَمَلائِكَتَهُ وَاَنْبِياءَهُ وَرُسُلَهُ اَنّي بِكُمْ مُؤْمِنٌ وَبِاِيابِكُمْ، مُوقِنٌ بِشَرايـِعِ ديني وَخَواتيمِ عَمَلي، وَقَلْبي لِقَلْبِكُمْ سِلْمٌ وَاَمْري لاَِمْرِكُمْ مُتَّبِـعٌ، صَلَواتُ اللهِ عَلَيْكُمْ وَعَلى اَرْواحِكُمْ وَعَلى اَجْسادِكُمْ وَعَلى اَجْسامِكُمْ وَ عَلى شاهِدِكُمْ وَعَلى غائِبِكُمْ وَعَلى ظاهِرِكُمْ وَعَلى باطِنِكُمْ ."}],"preview":"اَلسَّلامُ عَلَيْكَ يا اَبا عَبْدِاللهِ، اَلسَّلامُ عَلَيْكَ يَا بْنَ رَسُولِ الله، اَلسَّلامُ عَلَيْكَ يَا بْنَ اَميرِ الْمُؤْمِنينَ عَبْدُكَ وَابْنُ عَبْدِكَ وَابْنُ اَمَتِكَ الْ","hasTranslate":false},{"id":"mf_ar_209","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلب الاوّل :","title":"ثمّ انكبّ على القبر وقبّله وقُل :","blocks":[{"type":"Text","content":"بِاَبي اَنْتَ وَاُمّي يَا بْنَ رَسُولِ اللهِ، بِاَبي اَنْتَ وَاُمّي يا اَبا عَبْدِاللهِ، لَقَدْ عَظُمَتِ الرَّزِيَّةُ وَجَلَّتِ الْمُصيبَةُ بِكَ عَلَيْنا وَعَلى جَميعِ اَهْلِ السَّماواتِ وَالاَْرْضِ، فَلَعَنَ اللهُ اُمَّةً اَسْرَجَتْ وَاَلْجَمَتْ وَتَهَيَّأَتْ لِقِتالِكَ، يا مَوْلايَ يا اَبا عَبْدِاللهِ، قَصَدْتُ حَرَمَكَ، وَاَتَيْتُ اِلى مَشْهَدِكَ، اَسْألُ اللهَ بِالشَّأنِ الَّذي لَكَ عِنْدَهُ وَبِالَْمحَلِّ الَّذي لَكَ لَدَيْهِ اَنْ يُصَلِيَّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَنْ يَجْعَلَني مَعَكُمْ فِي الدُّنْيا وَالاْخِرَةِ ."},{"type":"Text","content":"ثمّ قُم فَصَلِّ ركعتين عند الرّأس اقرأ فيها ما أحببت فاذا فرغت من صلاتك فقُل :"},{"type":"Text","content":"اَللّـهُمَّ اِنّي صَلَّيْتُ وَرَكَعْتُ وَسَجَدْتُ لَكَ وَحْدَكَ لا شَريكَ لَكَ، لاَِنَّ الصَّلاةَ وَالرُّكُوعَ وَالسُّجُودَ لا تَكُونُ اِلاّ لَكَ لاَِنَّكَ اَنْتَ اللهُ لا اِلـهَ الاّ اَنْتَ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاَبْلِغْهُمْ عَنّي اَفْضَلَ السَّلامِ وَالتَّحِيَّةِ، وَارْدُدْ عَلَيَّ مِنْهُمُ السَّلامَ، اَللّـهُمَّ وَهاتانِ الرَّكْعَتانِ هَدِيَّةٌ مِنّي اِلى مَوْلايَ الْحُسَيْنِ بْنِ عَلِيِّ عليهما السلام، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَعَلَيْهِ، وَتَقَبَّلْ مِنّي وَأجُرْني عَلى ذلِكَ بِاَفْضَلِ اَمَلي وَرَجائي فيكَ وَفِي وَلِيِّكَ يا وَلِيَّ الْمُؤْمِنينَ."},{"type":"Text","content":"ثمّ قُم وصِر الى عند رجلي القبر وقِف عند رأس عليّ بن الحسين (عليه السلام)وقُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يَا بْنَ رَسُولِ اللهِ، اَلسَّلامُ عَلَيْكَ يَا بْنَ نَبِيِّ اللهِ، اَلسَّلامُ عَلَيْكَ يَا بْنَ اَميرِ الْمُؤْمِنينَ، اَلسَّلامُ عَلَيْكَ يَا بْنَ الْحُسَيْنِ الشَّهيدِ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الشَّهيدُ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الْمَظْلُومُ وَابْنُ الْمَظْلُومِ، لَعَنَ اللهُ اُمَّةً قَتَلَتْكَ، وَلَعَنَ اللهُ اُمَّةً ظَلَمَتْكَ، وَلَعَنَ اللهُ اُمَّةً سَمِعَتْ بِذلِكَ فَرَضَيِتْ بِهِ ."}],"preview":"بِاَبي اَنْتَ وَاُمّي يَا بْنَ رَسُولِ اللهِ، بِاَبي اَنْتَ وَاُمّي يا اَبا عَبْدِاللهِ، لَقَدْ عَظُمَتِ الرَّزِيَّةُ وَجَلَّتِ الْمُصيبَةُ بِكَ عَلَيْنا وَعَلى جَميعِ اَهْلِ السَّ","hasTranslate":false},{"id":"mf_ar_211","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّاني :","title":"ثمّ ادخل فانكبّ على القبر وقُل :","blocks":[{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ اَيُّهَا الْعَبْدُ الصّالِحُ الْمُطيعُ للهِ وَلِرَسُولِهِ وَلاَِميرِالْمُؤْمِنينَ وَالْحَسَنِ والْحُسَيْنِ صَلَّى اللهُ عَلَيْهِمْ وَسَلَّمَ، اَلسَّلامُ عَلَيْكَ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ وَمَغْفِرَتُهُ وَرِضْوانُهُ وَعَلى رُوحِكَ وَبَدَنِكَ، اَشْهَدُ و اُشْهِدُ اللهَ اَنَّكَ مَضَيْتَ عَلى ما مَضى بِهِ الْبَدْرِيُّونَ وَالُْمجاهِدُونَ فِي سَبيلِ اللهِ الْمُناصِحُونَ لَهُ فِي جِهادِ اَعْدائِهِ الْمُبالِغُونَ فِي نُصْرَةِ اَوْلِيائِهِ الذّابُّونَ عَنْ اَحِبّائِهِ فَجَزاكَ اللهُ اَفْضَلَ الْجَزاءِ، وَاَكْثَرَ الْجَزاءِ، وَاَوْفَرَ الْجَزاءِ، وَاَوْفى جَزاءِ اَحَد مِمَّنْ وَفى بِبَيْعَتِهِ وَاسْتَجابَ لَهُ دَعْوَتَهُ وَاَطاعَ وُلاةَ، اَمْرِهِ اَشْهَدُ اَنَّكَ قَدْ بالَغْتَ فِي النَّصيحَةِ، وَاَعْطَيْتَ غايَةَ اْلَْمجْهُودِ، فَبَعَثَكَ اللهُ فِي الشُّهَداءِ، وَجَعَلَ رُوحَكَ مَعَ اَرْواحِ السُّعَداءِ، وَاَعْطاكَ مِنْ جِنانِهِ اَفْسَحَها مَنْزِلاً وَاَفْضَلَها غُرَفاً، وَرَفَعَ ذِكْرَكَ فِي عِلِّيّينَ، وَحَشَرَكَ مَعَ النَّبِيّينَ وَالصِّدّيقينَ وَالشُّهَداءِ وَالصّالِحينَ وَحَسُنَ اُولئِكَ رَفيقاً، اَشْهَدُ اَنَّكَ لَمْ تَهِنْ وَلَمْ تَنْكُلْ، وَاَنَّكَ مَضَيْتَ عَلى بَصيرَة مِنْ اَمْرِكَ مُقْتَدِياً بِالصّالِحينَ، وَمُتَّبِعاً لِلنَّبِيّينَ، فَجَمَعَ اللهُ بَيْنَنا وَبَيْنَكَ وَبَيْنَ رَسُولِهِ وَاَوْلِيائِهِ فِي مَنازِلِ الُْمخْبِتينَ، فَاِنَّهُ اَرْحَمُ الرّاحِمينَ."},{"type":"AboutText","content":"أقول : مِن المستحسن أن يُزار بهذه الزّيارة خلف القبر مستقبل القبلة كما قال الشّيخ في التّهذيب ، ثمّ ادخل فانكبّ على القبر وقُل وأنت مستقبل القبلة : اَلسَّلامُ عَلَيْكَ اَيُّهَا الْعَبْدُ الصّالِحُ، واعلم ايضاً انّ الى هُنا تنتهي زيارة العبّاس على الرّواية السّالفة ولكن السّيد ابن طاوُس والشّيخ المفيد وغيرهما ذيلوها قائلين: ثمّ انحرف الى عند الرّأس فصلّ ركعتين ثمّ صلّ بعدهما ما بدا لك وادعُ الله كثيراً وقُل عقيب الرّكعات :"},{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَلا تَدَعْ لي فِي هذَا الْمَكانِ الْمُكَرَّمِ وَالْمَشْهَدِ الْمُعَظَّمِ ذَنْباً اِلاّ غَفَرْتَهُ، وَلا هَمّاً اِلاّ فَرَّجَتَهُ، وَلا مَرَضاً اِلاّ شَفَيْتَهُ، وَلا عَيْباً اِلاّ سَتَرْتَهُ، وَلا رِزْقاً اِلاّ بَسَطْتَهُ، وَلا خَوْفاً الاّ آمَنْتَهُ، وَلا شَمْلاً اِلاّ جَمَعْتَهُ، وَلا غائِباً اِلاّ حَفَظْتَهُ وَاَدْنَيْتَهُ، وَلا حاجَةً مِنْ حَوائِجِ الدُّنْيا وَالاْخِرَةِ لَكَ فيها رِضىً وَلِيَ فيها صَلاحٌ اِلاّ قَضَيْتَها يا اَرْحَمَ الرّاحِمينَ."},{"type":"Text","content":"ثمّ عُد الى الضّريح فقف عند الرّجلين وقُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا اَبَا الْفَضْلِ الْعَبّاسَ ابْنَ اَميرِ الْمُؤْمِنينَ، اَلسَّلامُ عَلَيْكَ يَا بْنَ سَيِّدِ الْوَصِيّينَ، اَلسَّلامُ عَلَيْكَ يَا بْنَ اَوَّلِ الْقَوْمِ اِسْلاماً وَاَقْدَمِهِمْ ايماناً وَاَقْوَمِهِمْ بِدينِ اللهِ، وَاَحْوَطِهِمْ عَلَى الاِْسْلامِ، اَشْهَدُ لَقَدْ نَصَحْتَ للهِ وَلِرَسُولِهِ وَلاَِخيكَ فَنِعْمَ الاَْخُ الْمُواسي، فَلَعَنَ اللهُ اُمَّةً قَتَلَتْكَ، وَلَعَنَ اللهُ اُمَّةً ظَلَمَتْكَ، وَلَعَنَ اللهُ اُمَّةً اسْتَحَلَّتْ مِنْكَ الَْمحارِمَ، وَانْتَهَكَتْ حُرْمَةَ الاِْسْلامِ، فَنِعْمَ الصّابِرُ الُْمجاهِدُ الُْمحامِي النّاصِرُ وَالاَْخُ الدّافِعُ عَنْ اَخيهِ، الُْمجيبُ اِلى طاعَةِ رَبِّهِ، الرّاغِبُ فيـما زَهِدَ فيهِ غَيْرُهُ مِنَ الثَّوابِ الْجَزيلِ وَالثَّناءِ الْجَميلِ، وَاَلْحَقَكَ اللهُ بِدَرَجَةِ آبائِكَ فِي جَنّاتِ النَّعيمِ، اَللّـهُمَّ اِنّي تَعَرَّضْتُ لِزِيارَةِ اَوْلِيائِكَ رَغْبَةً فِي ثَوابِكَ وَرَجاءً لِمَغْفِرَتِكَ وَجَزيلِ اِحْسانِكَ، فَاَسْاَلُكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِهِ الطّاهِرينَ، وَاَنْ تَجْعَلَ رِزْقي بِهِمْ دارّاً وَعَيْشي بِهِمْ قارّاً، وَزِيارَتي بِهِمْ مَقْبُولَةً وَحَياتي بِهِمْ طَيِّبَةً، وَاَدْرِجْني اِدْراجَ الْمُكْرَمينَ، وَاجْعَلْني مِمَّنْ يَنْقَلِبُ مِنْ زِيارَةِ مَشاهِدِ اَحِبّائِكَ مُفْلِحاً مُنْجِحاً، قَدِ اسْتَوْجَبَ غُفْرانَ الذُّنُوبِ وَسَتْرَ الْعُيُوبِ وَكَشْفَ الْكُرُوبِ، اِنَّكَ اَهْلُ التَّقْوى وَاَهْلُ الْمَغْفِرَةِ ."},{"type":"Text","content":"فاذا أردت وداعه فادنُ من القبر الشّريف وودّعه بما وَرد في رواية أبي حمزة الثّمالي وذكره العلماء أيضاً :"},{"type":"Text","content":"اَسْتَوْدِعُكَ اللهَ وَاَسْتَرْعيكَ وَاَقْرَأُ عَلَيْكَ اَلسَّلامَ، آمَنّا بِاللهِ وَبِرَسُولِهِ وَبِكِتابِهِ وَبِما جاءَ بِهِ مِنْ عِنْدِ اللهِ، اَللّـهُمَّ فَاكْتُبْنا مَعَ الشّاهِدينَ، اَللّـهُمَّ لا تَجْعَلْهُ آخِرَ الْعَهْدِ مِنْ زِيارَتي قَبْرَ ابْنِ اَخي رَسُولِكَ صَلَّى اللهُ عَلَيْهِ وَآلِهِ، وَارْزُقْني زِيارَتَهُ اَبَداً ما اَبْقَيْتَني وَاحْشُرْني مَعَهُ وَمَعَ آبائِهِ فِي الجِنانِ، وَعَرِّفْ بَيْني وَبَيْنَهُ وَبَيْنَ رَسُولِكَ وَاَوْلِيائِكَ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَتَوَفَّني عَلَى الاْيمانِ بِكَ وَالتَّصْديقِ بِرَسُولِكَ وَالْوِلايَةِ لِعَليِّ بْنِ اَبي طالِب وَالاَْئِمَّةِ مِنْ وُلْدِهِ عليهم السلام وَالْبَراءَةِ مِنْ عَدُوِّهِمْ، فَاِنّي قَدْ رَضيتُ يا رَبِّي بِذلِكَ، وَصَلَّى اللهُ عَلى مُحَمَّد وَآلِ مُحَمَّد."}],"preview":"اَلسَّلامُ عَلَيْكَ اَيُّهَا الْعَبْدُ الصّالِحُ الْمُطيعُ للهِ وَلِرَسُولِهِ وَلاَِميرِالْمُؤْمِنينَ وَالْحَسَنِ والْحُسَيْنِ صَلَّى اللهُ عَلَيْهِمْ وَسَلَّمَ، اَلسَّلامُ عَلَيْك","hasTranslate":false},{"id":"mf_ar_212","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّاني :","title":"ثمّ ادعُ لنفسك ولابويك وللمؤمنين والمسلمين واختر من الدّعاء ما شئت","blocks":[{"type":"AboutText","content":"أقول : في رواية عن السّجاد صلوات الله وسلامه عليه قال : رحم الله العبّاس فلقد آثر وفدى أخاه بنفسه حتّى قطعت يداهُ فأبدله الله عزّوجل بهما جناحين يطير بهما مع الملائكة في الجنّة كما جعل لجعفر بن أبي طالب (عليهما السلام) وانّ للعبّاس (عليه السلام)عند الله تبارك وتعالى منزلة يغبطه بها جميع الشّهداء يوم القيامة ."},{"type":"AboutText","content":"وروى انّ العبّاس (عليه السلام) استشهد وله من العُمر أربع وثلاثون سنة وانّ اُمّه امّ البنين كانت تخرج لرثاء العبّاس (عليه السلام)واخوته الى البقيع فتبكي وتندب، فتُبكي كلّ من يمرّ بها ولا يستغرب البكاء من الموالي فقد كانت امّ البنين تُبكي مروان بن الحكم اذا مرّ بها وشاهد شجُوها وهو أكبر المعادين لال بيت الرّسول (صلى الله عليه وآله وسلم)، ومن قول امّ البنين في رثاء أبي الفضل العبّاس وسائر ابنائها :"},{"type":"Text","content":"يا مَنْ رَاَى الْعَبّاسَ كَرَّ عَلى جَماهيرِ النَّقَدْ وَوَراهُ مِنْ اَبْناءِ حَيْدَرَ كُلّ لَيْث ذي لَبَدْ"},{"type":"Text","content":"اُنْبِئْتُ اَنَّ ابْني اُصيبَ بِرَأسِهِ مَقْطُوعَ يَدْ وَيْلي عَلى شِبْلي اَمالَ بِرَأسِهِ ضَرْبُ الْعَمَدْ"},{"type":"Text","content":"لَوْ كانَ سَيْفُكَ فِي يَدَيْكَ لَما دَنا مِنْهُ اَحَدْ"}],"preview":"أقول : في رواية عن السّجاد صلوات الله وسلامه عليه قال : رحم الله العبّاس فلقد آثر وفدى أخاه بنفسه حتّى قطعت يداهُ فأبدله الله عزّوجل بهما جناحين يطير بهما مع الملائكة في الجنّة كما","hasTranslate":false},{"id":"mf_ar_213","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّاني :","title":"ولها ايضاً :","blocks":[{"type":"Text","content":"لا تَدْعُوَنّي وَيْكِ اُمَّ الْبَنينْ تُذَكِّريني بِلُيُوثِ الْعَرينْ"},{"type":"Text","content":"كانَتْ بَنُونَ لِيَ اُدْعى بِهِمْ وَالْيَوْمَ اَصْبَحْتُ وَلا مِنْ بَنينْ"},{"type":"Text","content":"اَرْبَعَةٌ مِثْلُ نُسُورِ الرُّبى قَدْ واصَلُوا الْمَوْتَ بِقَطْعِ الْوَتينْ"},{"type":"Text","content":"تَنازَعَ الْخِرْصانُ اَشْلاءَهُمْ فَكُلُّهُمْ اَمْسى صَريعاً طَعينْ"},{"type":"Text","content":"يا لَيْتَ شِعْري اَكَما اَخْبَرُوا بِاَنَّ عَبّاساً قَطيعُ الَْيمينْ"}],"preview":"لا تَدْعُوَنّي وَيْكِ اُمَّ الْبَنينْ تُذَكِّريني بِلُيُوثِ الْعَرينْ","hasTranslate":false},{"id":"mf_ar_214","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّالِثُ :","title":"الاُولى :","blocks":[{"type":"Text","content":"ما يُزار بها (عليه السلام) في اوّل رجب وفي النّصف منه ومن شعبان ."},{"type":"Text","content":"عن الصّادق (عليه السلام) قال : مَن زار الحسين صلوات الله عليه في اوّل يوم من رجب غفر الله له البتّة، وعن ابن ابي نصر قال : سألت الرّضا (عليه السلام) : أيّ الاوقات أفضل أن تزُور فيه الحسين (عليه السلام) ؟ قال : النّصف من رجب والنّصف من شعبان . وهذه الزّيارة التي سنذكرها هي على رأي الشّيخ المفيد والسّيد ابن طاوُس تخصّ اليوم الاوّل من رجب وليلة النّصف من شعبان ولكن الشّهيد اضاف اليها اوّل ليلة من رجب وليلة النّصف منه ونهاره، ويوم النّصف من شعبان فعلى رأيه الشّريف يُزار (عليه السلام) بهذه الزّيارة في ستّة أوقات ."},{"type":"Text","content":"وأمّا صفة هذه الزّيارة فهي كما يلي : اذا أردت زيارته (عليه السلام) في الاوقات المذكورة فاغتسل والبس أطهر ثيابك وقِف على باب قبّته مستقبل القبلة وسلّم على سيّدنا رسول الله وعليّ امير المؤمنين وفاطمة والحسن والحسين والائمة صلوات الله عليهم اجمعين، وسيأتي في الاستيذان لزيارة عرفة كيفيّة السّلام عليهم (عليهم السلام) ثمّ ادخل وقِف عند الضّريح المقدّس وقُل مائة مرّة : اَللهُ اَكْبَرُ ثمّ قُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يَا بْنَ رَسُولِ اللهِ، اَلسَّلامُ عَلَيْكَ يا بْنَ خاتَمِ النَّبِيّينَ، اَلسَّلامُ عَلَيْكَ يا بْنَ سَيِّدِ الْمُرْسَلينَ، اَلسَّلامُ عَلَيْكَ يا بْنَ سَيِّدِ الْوَصِيّينَ، اَلسَّلامُ عَلَيْكَ يا اَبا عَبْدِاللهِ، اَلسَّلامُ عَلَيْكَ يَا حُسَيْنَ بْنَ عَلِيِّ، اَلسَّلامُ عَلَيْكَ يَا بْنَ فاطِمَةَ سَيِّدَةِ نِساءِ الْعالَمينَ، اَلسَّلامُ عَلَيْكَ يَا وَلِيَّ اللهِ وَابْنَ وَلِيِّهِ، اَلسَّلامُ عَلَيْكَ يَا صَفِيَّ اللهِ وَابْنَ صَفِيِّهِ، اَلسَّلامُ عَلَيْكَ يَا حُجَّةَ اللهِ وَابْنَ حُجَّتِهِ، اَلسَّلامُ عَلَيْكَ يَا حَبيبَ اللهِ وابْنَ حَبيبِهِ، اَلسَّلامُ عَلَيْكَ يَا سَفيرَ اللهِ وَابْنَ سَفيرِهِ، اَلسَّلامُ عَلَيْكَ يَا خازِنَ الْكِتابَ الْمَسْطُورِ، اَلسَّلامُ عَلَيْكَ يَا وارِثَ التَّوْراةِ وَالاِْنْجيلِ وَالزَّبُورِ، اَلسَّلامُ عَلَيْكَ يَا اَمينَ الرَّحْمنِ، اَلسَّلامُ عَلَيْكَ يَا شَريكَ الْقُرْآنِ، السَّلامُ عَلَيْكَ يا عَمُودَ الدِّينِ، اَلسَّلامُ عَلَيْكَ يَا بابَ حِكْمَةِ رَبِّ الْعالَمينَ، اَلسَّلامُ عَلَيْكَ يَا بابَ حِطَّة الَّذي مَنْ دَخَلَهُ كانَ مِنَ الاْمِنينَ، اَلسَّلامُ عَلَيْكَ يَا عَيْبَةَ عِلْمِ اللهِ، اَلسَّلامُ عَلَيْكَ يَا مَوْضِعَ سِرِّ اللهِ، اَلسَّلامُ عَلَيْكَ يَا ثارَ اللهِ وَابْنَ ثارِهِ وَالْوِتْرَ الْمَوْتُورَ، اَلسَّلامُ عَلَيْكَ وَعَلى الاَْرْواحِ الّتي حَلَّتْ بِفِنائِكَ وَاَناخَتْ بِرَحْلِكَ، بِاَبي اَنْتَ وَاُمّي وَنَفْسي يا اَبا عَبْدِاللهِ لَقَدْ عَظُمَتِ الْمُصيبَةُ وَجَلَّتِ الرَّزِيَّةُ بِكَ عَلَيْنا وَعَلى جَميعِ اَهْلِ الاِْسْلامِ، فَلَعَنَ اللهُ اُمَّةً اَسَّسَتْ اَساسَ الظُّلْمِ وَالْجَوْرِ عَلَيْكُمْ اَهْلَ الْبَيْتِ، وَلَعَنَ اللهُ اُمَّةً دَفَعَتْكُمْ عَنْ مَقامِكُمْ وَاَزالَتْكُمْ عَنْ مَراتِبِكُمْ الَّتي رَتَّبَكُمُ اللهُ فيها، بِاَبي اَنْتَ وَاُمّي وَنَفْسي يا اَبا عَبْدِاللهِ اَشْهَدُ لَقَدِ اقْشَعَرَّتْ لِدِمائِكُمْ اَظِلَّةَ الْعَرْشِ مَعَ اَظِلَّةُ الْخَلائِقِ، وَبَكَتْكُمُ السَّماءُ وَالاَْرْضُ وَسُكّانُ الْجِنانِ وَالْبَرِّ وَالْبَحْرِ، صَلَّى اللهُ عَلَيْهِ عَدَدَ ما فِي عِلْمِ اللهِ، لَبَّيْكَ داعِيَ اللهِ اِنْ كانَ لَمْ يُجِبْكَ بَدَني عِنْدَ اسْتِغاثَتِكَ وَلِساني عِنْدَ اسْتِنْصارِكَ، فَقَدْ اَجابَكَ قَلْبي وَسَمْعي وَبَصَرَي، سُبْحانَ رَبِّنا اِنْ كانَ وَعْدُ رَبِّنا لَمَفْعُولاً، اَشْهَدُ اَنَّكَ طُهْرٌ طاهِرٌ مُطَهَّرٌ مِنْ طُهْر طاهِر مُطَهَّر، طَهُرْتَ وَطَهُرَتْ بِكَ الْبِلادُ وَطَهُرَتْ اَرْضٌ اَنْتَ بِها وَطَهُرَ حَرَمُكَ، اَشْهَدُ اَنَّكَ قَدْ اَمَرْتَ بِالْقِسْطِ وَالْعَدْلِ وَدَعَوْتَ اِلَيْهِما، وَاَنَّكَ صادِقٌ صِدّيقٌ صَدَقْتَ فيـما دَعَوْتَ اِلَيْهِ، وَاَنَّكَ ثارُ اللهِ فِي الاَْرْضِ، وَاَشْهَدُ اَنَّكَ قَدْ بَلَّغْتَ عَنِ اللهِ وَعَنْ جَدِّكَ رَسُولِ اللهِ وَعَنْ اَبيكَ اَميرِ الْمُؤْمِنينَ وَعَنْ اَخيكَ الْحَسَنِ، وَنَصَحْتَ وَجاهَدْتَ فِي سَبيلِ اللهِ وَعَبَدْتَهُ مُخْلِصاً حَتّى اَتيكَ الْيَقينُ، فَجَزاكَ اللهُ خَيْرَ جَزاءِ السّابِقينَ، وَصَلَّى اللهُ عَلَيْكَ وَسَلَّمَ تَسْليماً، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَصَلِّ عَلَى الْحُسَيْنِ الْمَظْلُومِ الشَّهيدِ الرَّشيدِ قَتيلِ الْعَبَراتِ وَاَسيرِ الْكُرُباتِ، صَلاةً نامِيَةً زاكِيَةً مُبارَكَةً يَصْعَدُ اَوَّلُها وَلا يَنْفَدُ آخِرُها، اَفْضَلَ ما صَلَّيْتَ عَلى اَحَد مِنْ اَوْلادِ اَنْبِيائِكَ الْمُرْسَلينَ يا اِلـهَ الْعالَمينَ ."},{"type":"Text","content":"ثمّ قبّل الضّريح وضع خدّك الايمن عليه ثمّ الايسر ثمّ طف حول الضّريح وقبّله من جوانبه الاربعة وقال المفيد (رحمه الله) : ثمّ امض الى ضريح عليّ بن الحسين (عليه السلام) وقِف عليه وقُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ اَيُّهَا الصِّدّيقُ الطَّيِّبُ الزَّكِيُّ الْحَبيبُ الْمُقَرَّبُ وَابْنَ رَيْحانَةِ رَسُولِ اللهِ، اَلسَّلامُ عَلَيْكَ مِنْ شَهيد مُحْتَسِب وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، ما اَكْرَمَ مَقامَكَ وَاَشْرَفَ مُنْقَلَبَكَ، اَشْهَدُ لَقَدْ شَكَرَ اللهُ سَعْيَكَ وَاَجْزَلَ ثَوابَكَ، وَاَلْحَقَكَ بِالذِّرْوَةِ الْعالِيَةِ، حَيْثُ الشَّرَفُ كُلُّ الشَّرفِ وَفِي الْغُرَفِ السّامِيَةِ كَما مَنَّ عَلَيْكَ مِنْ قَبْلُ وَجَعَلَكَ مِنْ اَهْلِ الْبَيْتِ الَّذينَ اَذْهَبَ اللهُ عَنْهُمُ الرِّجْسَ وَطَهَّرَهُمْ تَطْهيراً، صَلَواتُ اللهِ عَلَيْكَ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ وَرِضْوانُهُ، فَاشْفَعْ اَيُّهَا السَّيِّدُ الطّاهِرُ اِلى رَبِّكَ فِي حَطِّ الاَْثْقالِ عَنْ ظَهْري وَتَخْفيفِها عَنّي وَارْحَمْ ذُلّي وَخُضُوعي لَكَ وَلِلسَّيِّدِ اَبيكَ صَلَّى اللهُ عَلَيْكُما."}],"preview":"ما يُزار بها (عليه السلام) في اوّل رجب وفي النّصف منه ومن شعبان .","hasTranslate":false},{"id":"mf_ar_215","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّالِثُ :","title":"ثمّ انكب على القبر وقل :","blocks":[{"type":"Text","content":"زادَ اللهُ فِي شَرَفِكُمْ فِي الاْخِرَةِ كَما شَرَّفَكُمْ فِي الدُّنْيا، وَاَسْعَدَكُمْ كَما اَسْعَدَ بِكُمْ، وَاَشْهَدُ اَنَّكُمْ اَعْلامُ الدّينِ وَنُجُومُ الْعالَمينَ، وَاَلسَّلامُ عَلَيْكُمْ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ ."}],"preview":"زادَ اللهُ فِي شَرَفِكُمْ فِي الاْخِرَةِ كَما شَرَّفَكُمْ فِي الدُّنْيا، وَاَسْعَدَكُمْ كَما اَسْعَدَ بِكُمْ، وَاَشْهَدُ اَنَّكُمْ اَعْلامُ الدّينِ وَنُجُومُ الْعالَمينَ، وَاَلسَّل","hasTranslate":false},{"id":"mf_ar_216","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّالِثُ :","title":"ثمّ توجّه الى الشّهداء وقل :","blocks":[{"type":"Text","content":"اَلسَّلامُ عَلَيْكُمْ يا اَنْصارَ اللهِ وَاَنْصارَ رَسُولِهِ وَاَنْصارَ عَلِيّ بْنِ اَبي طالِب وَاَنْصارَ فاطِمَةَ وَاَنْصارَ الْحَسَنِ وَالْحُسَيْنِ وَاَنْصارَ الاِْسْلامِ، اَشْهَدُ اَنَّكُمْ قَدْ نَصَحْتُمْ للهِ وَجاهَدْتُمْ فِي سَبيلِهِ فَجَزاكُمُ اللهُ عَنِ الاِْسْلامِ وَاَهْلِهِ اَفْضَلَ الْجَزاءِ، فُزْتُمْ وَاللهِ فَوْزاً عَظيماً، يا لَيْتَني كُنْتُ مَعَكُمْ فَاَفُوزَ فَوْزاً عَظيماً، اَشْهَدُ اَنَّكُمْ اَحْياءٌ عِنْدَ رَبِّكُمْ تُرْزَقُونَ، اَشْهَدُ اَنَّكُمُ الشُّهَداءُ وَالسُّعَداءُ وَاَنَّكُمُ الْفائِزوُنَ فِي دَرَجاتِ الْعُلى، واَلسَّلامُ عَلَيْكُمْ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ."},{"type":"Text","content":"ثمّ عُد الى عند الرّأس فَصَلِّ صلاة الزّيارة وادعُ لنفسك ولوالديك ولاخوانك المؤمنين، واعلم انّ السّيد ابن طاوُس(رحمه الله) قد أورد زيارة لعليّ الاكبر والشّهداء قدّس الله أرواحهم تشتمل على أسمائهم وقد أعرضنا عن ذكرها لطولها واشتهارها ."}],"preview":"اَلسَّلامُ عَلَيْكُمْ يا اَنْصارَ اللهِ وَاَنْصارَ رَسُولِهِ وَاَنْصارَ عَلِيّ بْنِ اَبي طالِب وَاَنْصارَ فاطِمَةَ وَاَنْصارَ الْحَسَنِ وَالْحُسَيْنِ وَاَنْصارَ الاِْسْلامِ، اَشْهَ","hasTranslate":false},{"id":"mf_ar_217","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّالِثُ :","title":"الثّانية : زيارة النّصف من رجب","blocks":[{"type":"Text","content":"وهي زيارة اُخرى غير ما مرّ ، أوردها المى(قدس سرهما)(رحمه الله) في المزار للنّصف من رجب خاصّة ويسمّى (أي النّصف من رجب) بالغفيلة لغفلة عامّة النّاس عن فضله، فاذا أردت ذلك وأتيت الصّحن فادخل أي ادخل الرّوضة وكبّر الله تعالى ثلاثاً وقِف على القبر وقُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكُمْ يا آلَ اللهِ، اَلسَّلامُ عَلَيْكُمْ يا صَفْوَةَ اللهِ، اَلسَّلامُ عَلَيْكُمْ يا خِيَرَةَ اللهِ مِنْ خَلْقِهِ، اَلسَّلامُ عَلَيْكُمْ يا سادَةَ السّاداتِ، اَلسَّلامُ عَلَيْكُمْ يا لُيُوثَ الْغاباتِ، اَلسَّلامُ عَلَيْكُمْ يا سُفُنَ النَّجاةِ، اَلسَّلامُ عَلَيْكَ يا اَبا عَبْدِاللهِ الْحُسَيْنِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ عِلْمِ الاَْنْبِياءِ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَلسَّلامُ عَلَيْكَ يا وارِثَ آدَمَ صَفْوَةِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ نُوح نَبِيِّ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ اِبْراهيمَ خَليلِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ اِسْماعيلَ ذَبيحِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ مُوسى كَليمِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ عيسى رُوحِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ مُحَمَّد حَبيبِ اللهِ، اَلسَّلامُ عَلَيْكَ يَا بْنَ مُحَمَّد الْمُصْطَفى، اَلسَّلامُ عَلَيْكَ يَا بْنَ عَلِيِّ الْمُرْتَضى، اَلسَّلامُ عَلَيْكَ يَا بْنَ فاطِمَةَ الزَّهْراءِ، اَلسَّلامُ عَلَيْكَ يَا بْنَ خَديجَةَ الكُبرى، اَلسَّلامُ عَلَيْكَ يا شَهيدُ ابْنَ الشَّهيدِ، اَلسَّلامُ عَلَيْكَ يا قَتيلُ ابْنَ الْقَتيلِ ،اَلسَّلامُ عَلَيْكَ يا وَلِيَّ اللهِ وَابْنَ وَلِيِّهِ، اَلسَّلامُ عَلَيْكَ يا حُجَّةَ اللهِ وَابْنَ حُجَّتِهِ عَلى خَلْقِهِ، اَشْهَدُ اَنَّكَ قَدْ اَقَمْتَ الصَّلاةَ وَآتَيْتَ الزَّكاةَ وَاَمَرْتَ بِالْمَعْرُوفِ وَنَهَيْتَ عَنْ الْمُنْكَرِ، وَرُزِئْتَ بِوالِديكَ وَجاهَدْتَ عَدُوَّكَ، وَاَشْهَدُ اَنَّكَ تَسْمَعُ الْكَلامَ وَتَرُدُّ الْجَوابَ، وَاَنَّكَ حَبيبُ اللهِ وَخَليلُهُ وَنَجيبُهُ وَصَفِيُّهُ وَابْنُ صَفِيِّهِ، يا مَوْلايَ وَابْنَ مَوْلايَ، زُرْتُكَ مُشْتاقاً فَكُنْ لي شَفيعاً اِلى اللهِ يا سَيِّدي وَاَسْتَشْفِعُ اِلَى اللهِ بِجَدِّكَ سَيِّدِ النَّبِيّينَ، وَبِأبيكَ سَيِّدِ الْوَصِيّينَ، وَبِاُمِّكَ فاطِمَةَ سَيِّدَةِ نِساءِ الْعالَمينَ، اَلا لَعَنَ اللهُ قاتِليكَ وَلَعَنَ اللهُ ظالِميكَ وَلَعَنَ اللهُ سالِبيكَ وَمُبْغِضيكَ مِنَ الاْوَّلينَ وَالاْخِرينَ، وَصَلَّى اللهُ عَلى سَيِّدِنا مُحَمِّد وَآلِهِ الطَّيِّبينَ الطّاهِرينَ."},{"type":"Text","content":"ثمّ قبّل القبر الطّاهر وتوجّه الى قبر عليّ بن الحسين (عليهما السلام) فزره وقُل:"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا مَوْلايَ وَابْنَ مَوْلايَ، لَعَنَ اللهُ قاتِليكَ وَلَعَنَ اللهُ ظالِميكَ، اِنّي اَتَقَرَّبُ اِلَى اللهِ بِزِيارَتِكُمْ وَبِمَحَبَّتِكُمْ وَاَبَرَأُ اِلَى اللهِ مِنْ اَعْدائِكُمْ، وَالسَّلامُ عَلَيْكَ يا مَوْلايَ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ."},{"type":"Text","content":"ثمّ امض الى قبُور الشّهداء رضوان الله عليهم، فاذا بلغتها فقف وقُل:"},{"type":"Text","content":"اَلسَّلامُ عَلَى الاَْرْواحِ المُنيخَةِ بِقَبْرِ اَبي عَبْدِاللهِ الْحُسَيْنِ عليه السلام، اَلسَّلامُ عَلَيْكُمْ يا طاهِرينَ مِنَ الدَّنَسِ، اَلسَّلامُ عَلَيْكُمْ يا مَهْدِيُّونَ، اَلسَّلامُ عَلَيْكُمْ يا اَبْرارَ اللهِ، اَلسَّلامُ عَلَيْكُمْ وَعَلَى الْمَلائِكَةِ الْحافِّينَ بِقُبُورِكُمْ اَجْمَعينَ، جَمَعَنَا اللهُ وَاِيّاكُمْ فِي مُسْتَقَرِّ رَحْمَتِهِ وَتَحْتَ عَرْشِهِ اِنَّهُ اَرْحَمُ الرَّاحِمينَ، وَاَلسَّلامُ عَلَيْكُمْ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ ."},{"type":"Text","content":"ثمّ امض الى حرم العبّاس بن امير المؤمنين (عليهما السلام) فاذا بلغته فقِف على باب قبّته وقُل : سَلامُ اللهِ وَسَلامُ مَلائِكَتِهِ الْمُقَرَّبينَ الى آخر ما سبق من زيارته."}],"preview":"وهي زيارة اُخرى غير ما مرّ ، أوردها المى(قدس سرهما)(رحمه الله) في المزار للنّصف من رجب خاصّة ويسمّى (أي النّصف من رجب) بالغفيلة لغفلة عامّة النّاس عن فضله، فاذا أردت ذلك وأتيت الصّ","hasTranslate":false},{"id":"mf_ar_218","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّالِثُ :","title":"الثّالثة : زيارة النّصف من شعبان","blocks":[{"type":"AboutText","content":"اعلم انّه قد وردت أحاديث كثيرة في فضل زيارته في النّصف من شعبان ويكفيها فضلاً انّها رويت بعدّة اسناد معتبرة عن الامام زين العابدين وعن الامام جعفر الصّادق (عليهما السلام) قالا : من أحبّ أن يصافحه مائة ألف نبيّ وأربعة وعشرون ألف نبيّ فليزر قبر أبي عبد الله الحسين بن علي (عليهما السلام) في النّصف من شعبان فانّ أرواح النّبيّين (عليهم السلام) يستأذنون الله في زيارته فيؤذن لهم، فطوبى لمن صافح هؤلاء وصافحوه ومنهم خمسة اولو العزم من الرّسل هم نوح وابراهيم ومُوسى وعيسى ومحمّد صلّى الله عليه وآله وعليهم اجمعين ."},{"type":"AboutText","content":"قال الرّاوي : قلنا له ما معنى اولي العزم؟ قال : بعثوا الى شرق الارض وغربها جنّها وانسها. وقد وردت فيه زيارتان ، فالاولى هي ما أوردناه لزيارته (عليه السلام) في أوّل يوم من رجب، والثّانية ما رواه الشّيخ الكفعمي في كتاب البلد الامين عن الصّادق (عليه السلام) وهي كما يلي : تقِف عند قبره وتقُول :"},{"type":"Text","content":"اَلْحَمْدُ للهِ الْعَلِيِّ الْعَظيمِ وَالسَّلامُ عَلَيْكَ اَيُّهَا الْعَبْدُ الصّالِحُ الزَّكيُّ اُودِعُكَ شَهادَةً مِنّي لَكَ تُقَرِّبُني اِلَيْكَ فِي يَوْمِ شَفاعَتِكَ، اَشْهَدُ اَنَّكَ قُتِلْتَ وَلَمْ تَمُتْ بَلْ بِرَجاءِ حَياتِكَ حَيِيَتْ قُلُوبُ شيعَتِكَ، وَبِضِياءِ نُورِكَ اهْتَدَى الطّالِبُونَ اِلَيْكَ، وَاَشْهَدُ اَنَّكَ نُورُ اللهِ الَّذي لَمْ يُطْفَأْ وَلا يُطْفَأُ اَبَداً، وَاَنَّكَ وَجْهُ اللهِ الَّذي لَمْ يَهْلِكْ وَلا يُهْلَكُ اَبَداً، وَاَشْهَدُ اَنَّ هذِهِ التُّرْبَةَ تُرْبَتُكَ، وَهذَا الْحَرَمَ حَرَمُكَ، وَهذَا الْمَصْرَعَ مَصْرَعُ بَدَنِكَ لا ذَليلَ وَاللهِ مُعِزُّكَ وَلا مَغْلُوبَ وَاللهِ ناصِرُكَ، هذِهِ شَهادَةٌ لي عِنْدَكَ اِلى يَوْمَ قَبْضِ روُحي بِحَضْرَتِكَ، وَالسَّلامُ عَلَيْكُمْ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ ."}],"preview":"اعلم انّه قد وردت أحاديث كثيرة في فضل زيارته في النّصف من شعبان ويكفيها فضلاً انّها رويت بعدّة اسناد معتبرة عن الامام زين العابدين وعن الامام جعفر الصّادق (عليهما السلام) قالا : من","hasTranslate":false},{"id":"mf_ar_219","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّالِثُ :","title":"الرّابِعةُ : زيارة ليالي القدر","blocks":[{"type":"AboutText","content":"اعلم انّ الاحاديث كثيرة في فضل زيارة الحسين (عليه السلام) في شهر رمضان ولا سيّما في أوّل ليلة منه وليلة النّصف منه وآخر ليلة منه وفي خُصوص ليلة القدر . وروي عن الامام محمّد التّقي (عليه السلام) قال : من زار الحسين (عليه السلام) ليلة ثلاث وعشرين من شهر رمضان وهي اللّيلة الّتي يرجى أن تكون ليلة القدر وفيها يُفرَقُ كُلُّ اَمْر حَكيم، صافحه رُوح أربعة وعشرين ألف نبيّ كلّهم يستأذن الله في زيارة الحسين (عليه السلام) في تلك اللّيلة، وفي حديث معتبر آخر عن الصّادق (عليه السلام) : اذا كان ليلة القدر ونادى مناد من السّماء السّابعة من بطنان العرش انّ الله عزّوجل قد غفر لمن أتى قبر الحسين (عليه السلام) . وفي رواية انّ من كان عند قبر الحسين (عليه السلام) ليلة القدر يصلّي عنده ركعتين أو ما تيسّر له وسأل الله الجنّة واستعاذ به من النّار أعطاه الله ما سأل واعاذه الله ممّا استعاذ منه ."},{"type":"AboutText","content":"وروى ابن قولويه عن الصّادق (عليه السلام) انّ من زار قبر الحسين بن علي (عليهما السلام) في شهر رمضان ومات في الطّريق لم يعرض ولم يحاسب وقيل له ادخل الجنّة آمناً، وامّا الالفاظ الّتي يُزار بها الحسين (عليه السلام) في ليلة القدر فهي زيارة أوردها الشّيخ والمفيد ومحمّد بن المشهدي وابن طاوُس والشّهيد (رحمهم الله) في كتب الزّيارة وخصّوها بهذه اللّيلة وبالعيدين أي عيد الفطر وعيد الاضحى ."},{"type":"AboutText","content":"وروى الشّيخ محمّد ابن المشهدي باسناده المعتبرة عن الصّادق (عليه السلام) قال : اذا أردت زيارته (عليه السلام) فأت مشهده المقدّس بعد أن تغتسل وتلبس أطهر ثيابك فاذا وقفت على قبره فاستقبله بوجهك واجعل القبلة بين كتفيك وقُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يَا بْنَ رَسُولِ اللهِ، اَلسَّلامُ عَلَيْكَ يَا بْنَ اَميرِ الْمُؤْمِنينَ، اَلسَّلامُ عَلَيْكَ يَا بْنَ الصِّديقَةِ الطّاهِرَةِ فاطِمَةَ سَيِّدَةِ نِساءِ الْعالَمينَ، اَلسَّلامُ عَلَيْكَ يا مَوْلايَ اَبا عَبْدِاللهِ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَشْهَدُ اَنَّكَ قَدْ اَقَمْتَ الصَّلاةَ وَآتَيْتَ الزَّكاةَ وَاَمَرْتَ بِالْمَعْرُوفِ وَنَهَيْتَ عَنِ الْمُنْكَرِ، وَتَلَوْتَ الْكِتابَ حَقَّ تِلاوَتِهِ وَجاهَدْتَ فِي اللهِ حَقَّ جِهادِهِ وَصَبَرْتَ عَلَى الاَْذى فِي جَنْبِهِ مُحْتَسِباً حَتّى اَتاكَ الْيَقينُ، اَشْهَدُ اَنَّ الَّذينَ خالَفُوكَ وَحارَبُوكَ وَالَّذينَ خَذَلُوكَ وَالَّذينَ قَتَلُوكَ مَلْعُونُونَ عَلى لِسانِ النَّبِيِّ الاُْمّي وَقَدْ خابَ مَنِ افْتَرى، لَعَنَ اللهُ الظّالِمينَ لَكُمْ مِنَ الاَْوَّلينَ وَالاْخِرينَ وَضاعَفَ عَلَيْهِمُ الْعَذابَ الاَْليمَ، اَتَيْتُكَ يا مَوْلايَ يَا بْنَ رَسُولِ اللهِ زائِراً عارِفاً بِحَقِّكَ مُوالِياً لاَِوْلِيائِكَ مُعادِياً لاَِعْدائِكَ، مُسْتَبْصِراً بِالْهُدَى الّذي أَنْتَ عَلَيْهِ، عارِفاً بِضَلالَةِ مَنْ خالَفَكَ، فَاشْفَعْ لي عِنْدَ رَبِّكَ."},{"type":"Text","content":"ثمّ انكبّ على القبر وقبّله وضع خدّك عليه ثمّ انحرف الى عند الرّأس وقل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا حُجَّةَ اللهِ فِي اَرْضِهِ وَسَمائِهِ، صَلَّى اللهُ عَلى رُوحِكَ الطَّيِّبِ وَجَسَدِكَ الطّاهِرِ، وَعَلَيْكَ السَّلامُ يا مَوْلايَ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ ."},{"type":"Text","content":"ثمّ انكبّ على القبر وقبّله وضع خدّك عليه ثمّ انحرف الى عند الرّأس فصلّ ركعتين للزّيارة وصلّ بعدهما ما تيسّر ثمّ تحول الى عند الرّجلين وزُر عليّ بن الحسين (عليهما السلام) وقُل : اَلسَّلامُ عَلَيْكَ يا مَوْلايَ وَابْنَ مَوْلايَ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، لَعَنَ اللهُ مَنْ ظَلَمَكَ، وَلَعَنَ اللهُ مَنْ قَتَلَكَ، وَضاعَفَ عَلَيْهِمُ الْعَذابَ الاَْليمَ، وادعُ بما تريد ثمّ زُر الشّهداء منحرفاً من عند الرّجلين الى القبلة فقُل : اَلسَّلامُ عَلَيْكُمْ اَيُّهَا الصِّدّيقُونَ، اَلسَّلامُ عَلَيْكُمْ اَيُّهَا الشُّهَداءُ الصّابِرُونَ، اَشْهَدُ اَنَّكُمْ جاهَدْتُمْ فِي سَبيلِ اللهِ وَصَبَرْتُمْ عَلَى الاَْذى فِي جَنْبِ اللهِ، وَنَصَحْتُمْ للهِ وَلِرَسُولِهِ حَتّى اَتاكُمُ الْيَقينُ، اَشْهَدُ اَنَّكُمْ اَحْياءٌ عِنْدَ رَبِّكُمْ تُرْزَقُونَ، فَجَزاكُمُ اللهُ عَنِ الاِْسْلامِ وَاَهْلِهِ اَفْضَلَ جَزاءِ الُْمحْسِنينَ، وَجَمَعَ بَيْنَنا وَبَيْنَكُمْ فِي مَحَلِّ النَّعيمِ ثمّ امض الى مشهد العبّاس بن امير المؤمنين 8 فاذا وقفت عليه فقُل : اَلسَّلامُ عَلَيْكَ يا بْنَ اَميرِ الْمُؤْمِنينَ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الْعَبْدُ الصّالِحُ الْمُطيعُ للهِ وَلِرَسُولِهِ، اَشْهَدُ اَنَّكَ قَدْ جاهَدْتَ وَنَصَحْتَ وَصَبَرْتَ حَتّى اَتاكَ الْيَقينُ، لَعَنَ اللهُ الظّالِمينَ لَكُمْ مِنَ الاَْوَّلينَ وَالاْخِرينَ وَاَلْحَقَهُمْ بِدَرْكِ الْجَحيمِ، ثمّ صلّ تطوّعاً في مسجده ما تشاء وانصرف ."}],"preview":"اعلم انّ الاحاديث كثيرة في فضل زيارة الحسين (عليه السلام) في شهر رمضان ولا سيّما في أوّل ليلة منه وليلة النّصف منه وآخر ليلة منه وفي خُصوص ليلة القدر . وروي عن الامام محمّد التّقي","hasTranslate":false},{"id":"mf_ar_220","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّالِثُ :","title":"الخامِسة : زيارة الحُسين (عليه السلام) في عيدي الفطر والاضحى","blocks":[{"type":"Text","content":"بسند معتبر عن الصّادق (عليه السلام) قال : من زار قبر الحسين (عليه السلام) ليلة من ثلاث ليالي غفر الله له ما تقدّم من ذنبه وما تأخّر ، ليلة الفطر وليلة الاضحى وليلة النّصف من شعبان، وفي رواية معتبرة عن موسى بن جعفر (عليهما السلام) قال : ثلاث ليال من زار فيها الحسين (عليه السلام) غفر له ما تقدّم من ذنبه وما تأخّر، ليلة النّصف من شعبان، واللّيلة الثّالثة والعشرون من رمضان، وليلة العيد أي ليلة عيد الفطر . وعن الصّادق (عليه السلام) قال : من زار الحسين بن علي (عليهما السلام) ليلة النّصف من شعبان وليلة الفطر وليلة عرفة في سنة واحدة كتب الله له ألف حجّة مبرورة وألف عمرة متقبّلة وقضيت له ألف حاجة من حوائج الدّنيا والاخرة ."},{"type":"AboutText","content":"وعن الباقر (عليه السلام) قال : من بات ليلة عرفة بأرض كربلاء وأقام بها حتّى يعيّد وينصرف وقاه الله شرّ سنته . واعلم انّ العلماء قد أوردوا لهذين العيدين الشّريفين زيارتين إحداهما ما مضت من الزّيارة في ليالي القدر، والثّانية هي ما يلي، والزّيارة السّابقة يُزار بها على ما يظهر من كلماتهم في يومي العيدين وهذه الزّيارة تخصّ ليلتهما ، قالوا: اذا أردت زيارته في اللّيلتين المذكورتين فقِف على باب القبّة الطّاهرة وارمِ بطرفك نحو القبر مستأذناً فقُل :"},{"type":"Text","content":"يا مَوْلايَ يا اَبا عَبْدِاللهِ يا بْنَ رَسُولِ اللهِ عَبْدُكَ وَابْنُ عَبْدِكَ وَابْنُ اَمَتِكَ الذَّليلُ بَيْنَ يَدَيْكَ، وَالْمُصَغَّرُ فِي عُلُوِّ قَدْرِكَ، وَالْمُعْتَرِفُ بِحَقِّكَ جاءَكَ مُسْتَجيراً بِكَ قاصِداً اِلى حَرَمِكَ، مُتَوَجِّهاً اِلى مَقامِكَ مُتَوَسِّلاً اِلَى اللهِ تَعالى بِكَ، أَاَدْخُلُ يا مَوْلايَ أَاَدْخُلُ يا وَلِيَّ اللهِ أَاَدْخُلُ يا مَلائِكَةَ اللهِ الُْمحْدِقينَ بِهـذَا الْحَرَمِ الْمُقيمينَ فِي هـذا الْمَشْهَدِ."},{"type":"Text","content":"فان خشع قلبك ودمعت عينك فادخل وقدمّ رجلك اليمنى على اليسرى وقُل : بِسْمِ اللهِ وَبِاللهِ وَفِي سَبيلِ اللهِ وَعَلى مِلَّةِ رَسُولِ اللهِ، اَللّـهُمَّ اَنْزِلْني مُنْزَلاً مُبارَكاً وَاَنْتَ خَيْرُ الْمُنْزِلينَ، (ثمّ قُل): اَللهُ اَكْبَرُ كَبيراً وَالْحَمْدُ للهِ كَثيراً وَسُبْحانَ اللهِ بُكْرَةً وَاَصيلاً، وَالْحَمْدُ للهِ الْفَرْدِ الصَّمَدِ الْماجِدِ الاَْحَدِ، الْمُتَفَضِّلِ الْمَنّانِ الْمُتَطَوِّلِ الحَنّانِ، الَّذي مِنْ تَطَوُّلِهِ سَهَّلَ لي زِيارَةَ مَوْلايَ بِاِحْسانِهِ، وَلَمْ يَجْعَلْني عَنْ زِيارَتِهِ مَمْنُوعاً وَلا عَنْ ذِمَّتِهِ مَدْفُوعاً، بَلْ تَطَوَّلَ وَمَنَحَ، ثمّ ادخل فاذا توسّطت فقم حذاء القبر بخضوع وبكاء وتضرّع وقُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا وارِثَ آدَمَ صَفْوَةِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ نُوح اَمينِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ اِبْراهيمَ خَليلِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ مُوسى كَليمِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ عيسى رُوحِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ مُحَمَّد صَلَّى اللهُ عَلَيْهِ وَآلِهِ حَبيبِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ عَلِيِّ حُجَّةِ اللهِ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الْوَصِيُّ الْبَرُّ الْتَّقِيُّ، اَلسَّلامُ عَلَيْكَ يَا ثارَ اللهِ وَابْنَ ثارِهِ وَالْوِتْرَ الْمَوْتُورَ، اَشْهَدُ اَنَّكَ قَدْ اَقَمْتَ الصَّلاةَ وَآتَيْتَ الزَّكاةَ وَاَمَرْتَ بِالْمَعْرُوفِ وَنَهَيْتَ عَنِ الْمُنْكَرِ، وَجاهَدْتَ فِي اللهِ حَقَّ جِهادِهِ حَتّى اسْتُبيحَ حَرَمُكَ وَقُتِلْتَ مَظْلُوماً ."},{"type":"Text","content":"ثمّ قم عند رأسه خاشعاً قلبك دامعة عينك ثمّ قل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا اَبا عَبْدِاللهِ، اَلسَّلامُ عَلَيْكَ يا بْنَ رَسُولِ اللهِ، اَلسَّلامُ عَلَيْكَ يا بْنَ سَيِّدِ الْوَصِيّينَ، اَلسَّلامُ عَلَيْكَ يَا بْنَ فاطِمَةَ الزَّهْراءِ سَيِّدَةِ نِساءِ الْعالَمينَ، اَلسَّلامُ عَلَيْكَ يا بَطَلَ الْمُسْلِمينَ، يا مَوْلايَ اَشْهَدُ اَنَّكَ كُنْتَ نُوراً فِي الاَْصْلابِ الشّامِخَةِ وَالاَْرْحامِ الْمُطَهَّرَةِ، لَمْ تُنَجِّسْكَ الْجاهِلِيَّةُ بِاَنْجاسِها وَلَمْ تُلْبِسْكَ مِنْ مُدْلَهِمّاتِ ثِيابِها، وَاَشْهَدُ اَنَّكَ مِنْ دَعائِمِ الدّينِ وَاَرْكانِ الْمُسْلِمينَ وَمَعْقِلِ الْمُؤْمِنينَ، وَاَشْهَدُ اَنَّكَ الاِْمامُ الْبَرُّ التَّقِيُّ الرَّضِيُّ الزَّكِيُّ الْهادي الْمَهْدِيُّ، وَاَشْهَدُ اَنَّ الاْئِمَّةَ مِنْ وُلْدِكَ كَلِمَةُ التَّقْوى وَاَعْلامُ الْهُدى، وَالْعُروَةُ الْوُثْقى وَالْحُجَّةُ عَلى اَهْلِ الدُّنْيا ."}],"preview":"بسند معتبر عن الصّادق (عليه السلام) قال : من زار قبر الحسين (عليه السلام) ليلة من ثلاث ليالي غفر الله له ما تقدّم من ذنبه وما تأخّر ، ليلة الفطر وليلة الاضحى وليلة النّصف من شعبان،","hasTranslate":false},{"id":"mf_ar_221","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّالِثُ :","title":"ثمّ انكبّ على القبر وقُل :","blocks":[{"type":"Text","content":"اِنّا للهِ وَاِنّا اِلَيْهِ راجِعُونَ، يا مَوْلايَ اَنَا مُوال لِوَلِيِّكُمْ وَمُعاد لِعَدُوِّكُمْ، وَاَنَا بِكُمْ مُؤْمِنٌ وَبِاِيابِكُمْ، مُوقِنٌ بِشَرايـِعِ ديني وَخَواتيمِ عَمَلي، وَقَلْبي لِقَلْبِكُمْ سِلْمٌ وَاَمْرى لاَِمْرِكُمْ مُتَّبِـعٌ، يا مَوْلايَ اَتَيْتُكَ خائِفاً فَآمِنّي، وَاَتَيْتُكَ مُسْتَجيراً فَاَجِرْني، وَاَتَيْتُكَ فَقيراً فَاَغْنِني سَيِّدي وَمَوْلايَ اَنْتَ مَوْلايَ حُجَّةُ اللهِ عَلَى الْخَلْقِ اَجْمَعينَ، آمَنْتُ بِسِرِّكُمْ وَعَلانِيَتِكُمْ وَبِظاهِرِكُمْ وَباطِنِكُمْ وَاَوَّلِكُمْ وَآخِرِكُمْ، وَاَشْهَدُ اَنَّكَ التّالي لِكِتابِ اللهِ وَاَمينُ اللهِ الدّاعي اِلَى اللهِ بِالْحِكْمَةِ وَالْمَوْعِظَةِ الْحَسَنَةِ، لَعَنَ اللهُ اُمَّةً ظَلَمَتْكَ، وَلَعَنَ اللهُ اُمَّةً سَمِعَتْ بِذلِكَ فَرَضِيَتْ بِهِ ."},{"type":"Text","content":"ثمّ صلّ عند الرّأس ركعتين فاذا سلّمت فقُل :"},{"type":"Text","content":"اَللّـهُمَّ اِنّي لَكَ صَلَّيْتُ وَلَكَ رَكَعْتُ وَلَكَ سَجَدْتُ وَحْدَكَ لا شَريكَ لَكَ، فَاِنَّهُ لا تَجُوزُ الصَّلاةُ وَالرُّكُوعُ وَالسُّجُودُ اِلاّ لَكَ لاَِنَّكَ اَنْتَ اللهُ لا اِلـهَ الاّ اَنْتَ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاَبْلِغْهُمْ عَنّي اَفْضَلَ السَّلامِ وَالتَّحِيَّةِ وَارْدُدْ عَلَيَّ مِنْهُمُ السَّلامَ، اَللّـهُمَّ وَهاتانِ الرَّكْعَتانِ هَدِيَّةٌ مِنّي اِلى سَيِّدِي الْحُسَيْنِ بْنِ عَلِيِّ عليهما السلام اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَعَلَيْهِ، وَتَقَبَّلْهُما مِنّي وَاجْرِني عَليْهِما اَفْضَلَ اَمَلي وَرَجائي فيكَ وَفِي وَلِيِّكَ يا وَلِيَّ الْمُؤْمِنينَ ."}],"preview":"اِنّا للهِ وَاِنّا اِلَيْهِ راجِعُونَ، يا مَوْلايَ اَنَا مُوال لِوَلِيِّكُمْ وَمُعاد لِعَدُوِّكُمْ، وَاَنَا بِكُمْ مُؤْمِنٌ وَبِاِيابِكُمْ، مُوقِنٌ بِشَرايـِعِ ديني وَخَواتيمِ عَمَ","hasTranslate":false},{"id":"mf_ar_222","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّالِثُ :","title":"ثمّ انكبّ على القبر وقبّله وقُل :","blocks":[{"type":"Text","content":"اَلسَّلامُ عَلَى الْحُسَيْنِ بْنِ عَلِيِّ اَلْمَظْلُومِ الشَّهيدِ، قَتيلِ الْعَبَراتِ وَاَسيرِ الْكُرُباتِ، اَللّـهُمَّ اِنّي اَشْهَدُ اَنَّهُ وَلِيُّكَ وَابْنُ وَلِيِّكَ وَصَفِيُّكَ الثّائِرُ بِحَقِّكَ، اَكْرَمْتَهُ بِكَرامَتِكَ وَخَتَمْتَ لَهُ بِالشَّهادَةِ، وَجَعَلْتَهُ سَيِّداً مِنَ السّادَةِ وَقائِداً مِنَ الْقادَةِ، وَاَكْرَمْتَهُ بِطيبِ الْوِلادَةِ وَاَعْطَيْتَهُ مَواريثَ الاَْنْبِياءِ، وَجَعَلْتَهُ حُجَّةً عَلى خَلْقِكَ مِنَ الاَْوْصِياءِ، فَاَعْذَرَ فِي الدُّعاءِ، وَمَنَحَ النَّصيحَةَ، وَبَذَلَ مُهْجَتَهُ فيكَ حَتَّى اسْتَنْقَذَ عِبادَكَ مِنَ الْجَهالَةِ وَحَيْرَةِ الضَّلالَةِ، وَقَدْ تَوازَرَ عَلَيْهِ مَنْ غَرَّتْهُ الدُّنْيا وَباعَ حَظَّهُ مِنَ الاْخِرَةِ بِالاَْدْنى، وَتَرَدّى فِي هَواهُ وَاَسْخَطَكَ وَاَسْخَطَ نَبِيَّكَ وَاَطاعَ مِنْ عِبادِكَ اُوْلي الشِّقاقِ وَالنِّفاقِ وَحَمَلَةَ الاَْوْزارِ الْمُسْتَوْجِبينَ النّارَ، فَجاهَدَهُمْ فيكَ صابِراً مُحْتَسِباً مُقْبِلاً غَيْرَ مُدْبِر لا تَأخُذُهُ فِي اللهِ لَوْمَةُ لائِم حَتّى سُفِكَ فِي طاعَتِكَ دَمُهُ وَاسْتُبيحَ حَريمُهُ، اَللّـهُمَّ الْعَنْهُمْ لَعْناً وَبيلاً وَعَذِّبْهُمْ عَذاباً اَليماً ."},{"type":"Text","content":"ثمّ اعطف على علي بن الحُسين (عليهما السلام) وهو عند رجل الحسين (عليه السلام) وقُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا وَلِيَّ اللهِ، اَلسَّلامُ عَلَيْكَ يا بْنَ رَسُولِ اللهِ، اَلسَّلامُ عَلَيْكَ يا بْنَ خاتَمِ النَّبِيّينَ، اَلسَّلامُ عَلَيْكَ يا ابْنَ فاطِمَةَ سَيِّدَةِ نِساءِ الْعالَمينَ، اَلسَّلامُ عَلَيْكَ يا بْنَ اَميرِ الْمُؤْمِنينَ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الْمَظْلُومُ الشَّهيدُ، بِاَبي اَنْتَ وَاُمّي عِشْتَ سَعيداً وَقُتِلْتَ مَظْلُوماً شَهيداً ."},{"type":"Text","content":"ثمّ انحرف الى قبور الشّهداء رضي الله عنهم وقُل : اَلسَّلامُ عَلَيْكُمْ اَيُّهَا الذّابُّونَ عَنْ تَوْحيدِ اللهِ، اَلسَّلامُ عَلَيْكُمْ بِما صَبَرْتُمْ فَنِعْمَ عُقْبَى الدّارِ، بِاَبي اَنْتُمْ وَاُمّي فُزْتُمْ فَوْزاً عَظيماً، ثمّ امضِ الى مشهد العبّاس بن عليّ (عليهما السلام)وقف على ضريحه الشّريف وقُل : اَلسَّلامُ عَلَيْكَ اَيُّهَا الْعَبْدُ الصّالِحُ وَالصِّدِّيقُ الْمُواسي، اَشْهَدُ اَنَّكَ آمَنْتَ بِاللهِ وَنَصَرْتَ ابْنَ رَسُولِ اللهِ، وَدَعَوْتَ اِلى سَبيلِ اللهِ وَواسَيْتَ بِنَفْسِكَ، فَعَلَيْكَ مِنَ اللهِ اَفْضَلُ التَّحِيَّةِ وَالسَّلامِ، ثمّ انكبّ على القبر وقُل : بِاَبي اَنْتَ وَاُمّي يا ناصِرَ دينِ اللهِ، اَلسَّلامُ عَلَيْكَ يا ناصِرَ الْحُسَيْنِ الصِّدّيقِ، اَلسَّلامُ عَلَيْكَ يا ناصِرَ الْحُسَيْنِ الشَّهيدِ، عَلَيْكَ مِنّي السَّلامُ ما بَقيتُ وَبَقِيَ اللَّيْلُ وَالنَّهارُ، ثمّ صلّ عند رأسه (عليه السلام) ركعتين وقُل ما قلت عند رأس الحسين (عليه السلام)أي ادعُ بدعاء اَللّـهُمَّ اِنّي صَلَّيْتُ ... الخ ثمّ ارجع الى مشهد الحسين (عليه السلام)واقم عنده ما أحببت الاّ انّه يستحبّ أن لا تجعله موضِع مبيتك، فاذا أردت وداعه فقُم عند الرّأس وأنت تبكي وتقُول :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا مَوْلايَ سَلامَ مُوَدِّع لا قال وَلا سَئِم، فَاِنْ اَنْصَرِفْ فَلا عَنْ مَلالَة، وَاِنْ اَقِمْ فَلا عَنْ سُوءِ ظَنٍّ بِما وَعَدَ اللهُ الصّابِرينَ، يا مَوْلايَ لا جَعَلَهُ اللهُ آخِرَ الْعَهْدِ مِنّي لِزِيارَتِكَ، وَرَزَقَنِيَ الْعَوْدَ اِلَيْكَ وَالْمَقامَ فِي حَرَمِكَ وَالْكَوْنَ فِي مَشْهَدِكَ آمينَ رَبَّ الْعالَمينَ، ثمّ قبّله وامر عليه جميع جسدك فانّه أمان وحِرز واخرج من عنده القهقرى ولا تولّه دبرك وقُل : اَلسَّلامُ عَلَيْكَ يا بابَ الْمَقامِ، اَلسَّلامُ عَلَيْكَ يا شَريكَ الْقُرْآنِ، اَلسَّلامُ عَلَيْكَ يا حُجَّةَ الْخِصامِ، اَلسَّلامُ عَلَيْكَ يا سَفينَةَ النَّجاةِ، اَلسَّلامُ عَلَيْكُمْ يا مَلائِكَةَ رَبِّي الْمُقيمينَ فِي هـذا الْحَرَمِ، اَلسَّلامُ عَلَيْكَ اَبَداً ما بَقيتُ وَبَقِيَ اللَّيْلُ وَالنَّهارُ (وقُل) اِنّا للهِ وَاِنّا اِلَيْهِ راجِعُونَ وَلا حَوْلَ وَلا قُوَّةَ اِلاّ بِاللهِ الْعَلِيِّ الْعَظيمِ، ثمّ انصرف. وقال السّيد ابن طاوُس ومحمّد بن المشهدي : فاذا فعلت ذلك كنت كمن زار الله في عرشه ."}],"preview":"اَلسَّلامُ عَلَى الْحُسَيْنِ بْنِ عَلِيِّ اَلْمَظْلُومِ الشَّهيدِ، قَتيلِ الْعَبَراتِ وَاَسيرِ الْكُرُباتِ، اَللّـهُمَّ اِنّي اَشْهَدُ اَنَّهُ وَلِيُّكَ وَابْنُ وَلِيِّكَ وَصَفِيُّ","hasTranslate":false},{"id":"mf_ar_223","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّالِثُ :","title":"السّادسةُ : زيارة الحُسين (عليه السلام) في يوم عَرَفة","blocks":[{"type":"AboutText","content":"اعلم انّ ما روي من أهل البيت الطّاهرين المعصومين صلوات الله عليهم اجمعين في زيارة عرفة ممّا لا يحصى فضلاً وعدداً ونحن تشويقاً للزّائرين نورد منها البعض اليسير ."},{"type":"Text","content":"بسند معتبر عن بشير الدّهان قال : قلت للصّادق صلوات الله وسلامه عليه : ربما فاتني الحجّ فأعرف عند قبر الحسين (عليه السلام)، قال : أحسنت يا بشير ايّما مؤمن أتى قبر الحسين صلوات الله عليه عارفاً بحقّه في غير يوم عيد كتب له عشرون حجّة وعشرون عمرة مبرورات متقبّلات وعشرون غزوة مع نبيّ مرسل أو امام عادل، ومن أتاه في يوم عرفة عارفاً بحقّه كتب له ألف حجّة وألف عمرة مبرورات متقبّلات وألف غزوة مَعَ نبيّ مرسل أو امام عادل . قال : فقلت له : وكيف لي بمثل الموقف ؟ قال : فنظر اليّ شبه المغضب ثمّ قال : يا بشير انّ المؤمن اذا أتى قبر الحُسين صلوات الله عليه يوم عرفة واغتسل بالفرات ثمّ توجّه اليه كتب الله عزّوجل له بكلّ خطوة حجّة بمناسكها ولا أعلمه الاّ قال وعمرة (وقيل غزوة(."},{"type":"Text","content":"وفي احاديث كثيرة معتبرة انّ الله تعالى ينظر الى زوّار قبر الحسين (عليه السلام)نظر الرّحمة في يوم عرفة قبل نظره الى أهل عرفات، وفي حديث معتبر عن رفاعة ، قال : قال لي الصّادق (عليه السلام) : يا رفاعة أحججت العام؟ قلت : جعلت فداك ما كان عندي ما أحجّ به ولكنّي عرفت عند قبر الحسين (عليه السلام) ، فقال لي : يا رفاعة ما قصّرت عمّا كان أهل منى فيه لو لا انّي أكره ان يدع النّاس الحجّ لحدّثتك بحديث لا تدع زيارة قبر الحسين صلوات الله عليه أبداً، ثمّ سكت طويلاً ثمّ قال : أخبرني أبي ، قال : من خرج الى قبر الحسين (عليه السلام)عارفاً بحقّه غير مستكبر صحبه ألف ملك عن يمينه وألف ملك عن شماله وكتب له ألف حجّة وألف عمرة مع نبيّ أو وصيّ نبيّ ."},{"type":"Text","content":"وأمّا كيفيّة زيارته (عليه السلام) فهي على ما أورده اجلّة العلماء وزعماء المذهب والدّين كما يلي : اذا أردت زيارته في هذا اليوم فاغتسل من الفرات ان امكنك والاّ فمن حيث امكنك والبس أطهر ثيابك واقصد حضرته الشّريفة وأنت على سكينة ووقار، فاذا بلغت باب الحائر فكبّر الله تعالى وقُل :"},{"type":"Text","content":"اَللهُ اَكْبَرُ وقل : اَللهُ اَكْبَرُ كَبيراً وَاَلْحَمْدُ للهِ كَثيراً وَسُبْحانَ اللهِ بُكْرَةً وَاَصيلاً، وَالْحَمْدُ للهِ الَّذي هَدانا لِهذا وَما كُنّا لِنَهْتَدِىَ لَوْلا اَنْ هَدانَا اللهُ، لَقَدْ جاءَتْ رُسُلُ رَبِّنا بِالْحَقِّ، اَلسَّلامُ عَلى رَسُولِ اللهِ صَلَّى اللهُ عَلَيْهِ وَآلِهِ، اَلسَّلامُ عَلى اَميرِ الْمُؤْمِنينَ، اَلسَّلامُ عَلى فاطِمَةَ الزَّهْراءِ سَيِّدَةِ نِساءِ الْعالَمينَ، اَلسَّلامُ عَلَى الْحَسَنِ وَالْحُسَيْنِ، اَلسَّلامُ عَلى عَلِيِّ بْنِ الْحُسَيْنِ، اَلسَّلامُ عَلى مُحَمَّدِ بْنِ عَليِّ، اَلسَّلامُ عَلى جَعْفَرِ بْنِ مُحَمَّد، اَلسَّلامُ عَلى مُوسَى بْنِ جَعْفَر، اَلسَّلامُ عَلى عَلِيِّ بْنِ مُوسى، اَلسَّلامُ عَلى مُحَمَّدِ بْنِ عَلِيِّ، اَلسَّلامُ عَلى عَلِيِّ بْنِ مُحَمَّد، اَلسَّلامُ عَلَى الْحَسَنِ بْنِ عَلِيِّ، اَلسَّلامُ عَلَى الْخَلَفِ الصّالِحِ الْمُنْتَظَرِ، اَلسَّلامُ عَلَيْكَ يا اَبا عَبْدِاللهِ، اَلسَّلامُ عَلَيْكَ يَا بْنَ رَسُولِ اللهِ، عَبْدُكَ وَابْنُ عَبْدِكَ وَابْنُ اَمَتِكَ الْمُوالي لِوَلِيِّكَ الْمُعادي لِعَدُوِّكَ اسْتَجارَ بِمَشْهَدِكَ وَتَقَرَّبَ اِلَى اللهِ بِقَصْدِكَ، اَلْحَمْدُ للهِ الَّذي هَداني لِوِلايَتِكَ وَخَصَّني بِزِيارَتِكَ وَسَهَّلَ لي قَصْدَكَ ."},{"type":"Text","content":"ثمّ ادخل فقف ممّا يلي الرّأس وقل : اَلسَّلامُ عَلَيْكَ يا وارِثَ آدَمَ صَفْوَةِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ نُوح نَبِيِّ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ اِبْراهيمَ خَليلِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ مُوسى كَليمِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ عيسى روُحِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ مُحَمَّد حَبيبِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ اَميرِ الْمُؤْمِنينَ، اَلسَّلامُ عَلَيْكَ يا وارِثَ فاطِمَةَ الزَّهْراءِ، السَّلامُ عَلَيكَ يا بنَ محَمَّد المُصطَفى ، السَّلامُ علَيْكَ يا بنَ عليِّ المُرتَضى، السَلامُ عَلَيكَ يا بنَ فاطِمَةَ الزَهْراءِ، السَّلامُ عَلَيْكَ يَا بْنَ خَديجَةَ الْكُبْرى، اَالسَّلامُ عَلَيْكَ يا ثارَ اللهِ وَابْنَ ثارِهِ وَالْوِتْرَ الْمَوْتُورَ، اَشْهَدُ اَنَّكَ قَدْ اَقَمْتَ الصَّلاةَ، وَآتَيْتَ الزَّكاةَ، وَاَمَرْتَ بِالْمَعْروُفِ، وَنَهَيْتَ عَنِ الْمُنْكَرِ، وَاَطَعْتَ اللهَ حَتّى اَتاكَ الْيَقينُ، فَلَعَنَ اللهُ اُمَّةً قَتَلَتْكَ، وَلَعَنَ اللهُ اُمَّةً ظَلَمَتْكَ، وَلَعَنَ اللهُ اُمَّةً سَمِعَتْ بِذلِكَ فَرَضِيَتْ بِهِ، يا مَوْلايَ يا اَبا عَبْدِاللهِ اُشْهِدُ اللهَ وَمَلائِكَتَهُ وَاَنْبِيائَهُ وَرُسُلَهُ اَنّي بِكُمْ مُؤْمِنٌ وَبِاِيابِكُمْ، مُوقِنٌ بِشَرايِعِ ديني وَخَواتيمِ عَمَلي وَمُنْقَلَبي اِلى رَبّي، فَصَلَواتُ اللهَ عَلَيْكُمْ وَعَلى اَرْواحِكُمْ وَعَلى اَجْسادِكُمْ وَعَلى شاهِدِكُمْ وَعَلى غائِبُكُمْ وَظاهِرِكُمْ وَباطِنِكُمْ، اَلسَّلامُ عَلَيْكَ يَا بْنَ خاتَمَ النَّبِيّينَ وَابْنَ سَيِّدِ الْوَصِيّينَ وَابْنَ اِمامِ الْمُتَّقينَ وَابْنَ قائِدِ الْغُرِّ الُْمحَجَّلينَ اِلى جَنّاتِ النَّعيمِ، وَكَيْفَ لا تَكُونُ كَذلِكَ وَاَنْتَ بابُ الْهُدى وَاِمامُ التُّقى وَالْعُرْوَةُ الْوُثْقى وَالْحُجَّةُ عَلى اَهْلِ الدُّنْيا وَخامِسُ اَصْحابِ الْكِساءِ غَذَّتْكَ يَدُ الرَّحْمَةِ، وَرَضَعْتَ مِنْ ثَدْىِ الاْيمانِ، وَرُبّيتَ فِي حِجْرِ الاِْسْلامِ، فَالنَّفْسُ غَيْرُ راضِيَة بِفِراقِكَ وَلا شاكَّة فِي حَياتِكَ صَلَواتُ اللهِ عَلَيْك وَعَلى آبائِكَ وَاَبْنائِكَ، اَلسَّلامُ عَلَيْكَ يا صَريعَ الْعَبْرَةِ السّاكِبَةِ، وَقَرينَ الْمُصيبَةِ الرّاتِبَةِ، لَعَنَ اللهُ اُمَّةً اسْتَحَلَّتْ مِنْكَ الَْمحارِمَ وانْتَهَكَتْ فِيكَ حُرمَةَ الاسلامِ، فَقُتِلْتَ صَلَّى اللهُ عَلَيْكَ مَقْهُوراً، وَاَصْبَحَ رَسُولُ اللهِ صَلَّى اللهُ عَلَيْهِ وَآلِهِ بِكَ مَوْتُوراً، وَاَصْبَحَ كِتابُ اللهِ بِفَقْدِكَ مَهْجُوراً، اَلسَّلامُ عَلَيْكَ وَعَلى جَدِّكَ وَاَبيكَ وَاُمِّكَ وَاَخيكَ وَعَلَى الاَْئِمَّةِ مِنْ بَنيكَ، وَعَلَى الْمُسْتَشْهَدينَ مَعَكَ وَعَلَى الْمَلائِكَةِ الْحافّينَ بِقَبْرِكَ وَالشّاهِدينَ لِزُوّارِكَ الْمُؤْمِنينَ بِالْقَبُولِ عَلى دُعاءِ شيعَتِكَ، وَاَلسَّلامُ عَلَيْكَ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ بِاَبي اَنْتَ وَاُمّي يَا بْنَ رَسُولِ اللهِ، بِاَبي اَنْتَ وَاُمّي يا اَبا عَبْدِاللهِ، لَقَدْ عَظُمَتِ الرِّزِيَّةُ وَجَلَّتِ الْمُصيبَةُ بِكَ عَلَيْنا وَعَلى جَميعِ اَهْلِ السَّماواتِ وَالاَْرْضِ، فَلَعَنَ اللهُ اُمَّةً اَسْرَجَتْ وَاَلْجَمَتْ وَتَهَيَّأَتْ لِقِتالِكَ، يا مَوْلايَ يا اَبا عَبْدِاللهِ قَصَدْتُ حَرَمَكَ وَاَتَيْتُ مَشْهَدَكَ اَسْألُ اللهَ بِالشَّأْنِ الَّذي لَكَ عِنْدَهُ وَبِالَْمحَلِّ الَّذي لَكَ لَدَيْهِ اَنْ يُصَلِّىَ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاَنْ يَجْعَلَني مَعَكُمْ فِي الدُّنْيا وَالاْخِرَةِ بِمَنِّهِ وَجُودِهِ وَكَرَمِهِ ."},{"type":"Text","content":"ثمّ قبّل الضّريح وصلّ عند الرّأس ركعتين تقرأ فيهما ما أحببت من السّور فاذا فرغت فقل :"},{"type":"Text","content":"اَللّـهُمَّ اِنّي صَلَّيْتُ وَرَكَعْتُ وَسَجَدْتُ لَكَ وَحْدَكَ لا شَريكَ لَكَ، لاَِنَّ الصَّلاةَ وَالرُّكُوعَ وَالسُّجُودَ لا تَكُونُ اِلاّ لَكَ لاَِنَّكَ اَنْتَ اللهُ لا اِلـهَ اِلاّ اَنْتَ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاَبْلِغْهُمْ عَنّي اَفْضَلَ التَّحِيَّةِ وَالسَّلامِ، وَارْدُدُ عَلَيَّ مِنْهُمُ التَّحِيَّةَ وَالسَّلامَ، اَللّـهُمَّ وَهاتانِ الرَّكْعَتانِ هَدِيَّةٌ مِنّي اِلى مَوْلايَ وَسَيِّدي وَاِمامي الْحُسَيْنِ ابْنِ عَلِيِّ عليهما السلام، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَتَقَبَّلْ ذلِكَ مِنّي، وَاجْزِني عَلى ذلِكَ اَفْضَلَ اَمَلي وَرَجائي فيكَ وَفِي وَلِيِّكَ يا اَرْحَمَ الرّاحِمينَ."},{"type":"Text","content":"ثمّ صر الى عند رجلي الحسين وزُر عليّ بن الحُسين (عليهما السلام) ورأسه عند رجلي أبي عبد الله (عليه السلام) وقُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يَا بْنَ رَسُولِ اللهِ، اَلسَّلامُ عَلَيْكَ يَا بْنَ نَبِيِّ اللهِ، اَلسَّلامُ عَلَيْكَ يَا بْنَ اَميرِ الْمُؤْمِنينَ، اَلسَّلامُ عَلَيْكَ يَا بْنَ الْحُسَيْنِ الشَّهيدِ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الشَّهيدُ ابْنُ الشَّهيدِ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الْمَظْلُومُ ابْنُ الْمَظْلُومِ، لَعَنَ اللهُ اُمَّةً قَتَلَتْكَ، وَلَعَنَ اللهُ اُمَّةً ظَلَمَتْكَ، وَلَعَنَ اللهُ اُمَّةً سَمِعَتْ بِذلِكَ فَرَضِيَتْ بِهِ، اَلسَّلامُ عَلَيْكَ يا مَوْلايَ، اَلسَّلامُ عَلَيْكَ يا وَلِيَّ اللهِ وَابْنَ وَلِيِّهِ، لَقَدْ عَظُمَتِ الْمُصيبَةُ وَجَلَّتِ الرَّزِيَّةُ بِكَ عَلَيْنا وَعَلى جَميعِ الْمُؤْمِنينَ، فَلَعَنَ اللهُ اُمَّةً قَتَلَتْكَ وَاَبْرَأُ اِلَى اللهِ وَاِلَيْكِ مِنْهُمْ فِي الدُّنْيا وَالاْخِرَةِ ."}],"preview":"اعلم انّ ما روي من أهل البيت الطّاهرين المعصومين صلوات الله عليهم اجمعين في زيارة عرفة ممّا لا يحصى فضلاً وعدداً ونحن تشويقاً للزّائرين نورد منها البعض اليسير .","hasTranslate":false},{"id":"mf_ar_224","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّالِثُ :","title":"ثمّ توجّه الى الشّهداء وزُرهم وقُل :","blocks":[{"type":"Text","content":"اَلسَّلامُ عَلَيْكُمْ يا اَوْلِياءَ اللهِ وَاَحِبّاءَهُ، اَلسَّلامُ عَلَيْكُمْ يا اَصْفِياءَ اللهِ وَاَوِدّاءَهُ اَلسَّلامُ عَلَيْكُمْ يا اَنْصارَ دينِ اللهِ وَاَنْصارَ نَبِيّهِ وَاَنْصارَ اَميرِ الْمُؤْمِنينَ وَاَنْصارَ فاطِمَةَ سَيِّدَةِ نِساءِ الْعالَمينَ، اَلسَّلامُ عَلَيْكُمْ يا اَنْصارَ اَبي مُحَمَّد الْحَسَنِ الْوَلِيِّ النّاصِحِ، اَلسَّلامُ عَلَيْكُمْ يا اَنْصارَ أبي عَبْدِاللهِ الْحُسَيْنِ الشَّهيدِ الْمَظْلُومِ صَلَواتُ اللهِ عَلَيْهِمْ اَجْمَعينَ، بِاَبي اَنْتُمْ وَاُمّي طِبْتُمْ وَطابَتِ الاَْرْضُ الَّتي فيها دُفِنْتُمْ، وَفُزْتُمْ وَاللهِ فَوْزاً عَظيماً، يا لَيْتَني كُنْتُ مَعَكُمْ فَاَفُوزُ مَعَكُمْ فِي الْجِنانِ مَعَ الشُّهَداءِ وَالصّالِحينَ وَحَسُنَ اُولئِكَ رَفيقاً، وَالسَّلامُ عَلَيْكُمْ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ ."},{"type":"Text","content":"ثمّ عُد الى عند رأس الحُسين صلوات الله وسلامه عليه واكثر من الدّعاء لنفسك ولاهلك ولاخوانك المؤمنين ."},{"type":"Text","content":"وقال السّيد ابن طاوُس والشّهيد : ثمّ امضِ الى مشهد العبّاس (رضي الله عنه) فاذا أتيته فقف على قبره وقُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا اَبَا الْفَضْلِ الْعِبّاسَ بْنَ اَميرَ الْمُؤْمِنينَ، اَلسَّلامُ عَلَيْكَ يَا بْنَ سَيِّدِ الْوَصِيّينَ، اَلسَّلامُ عَلَيْكَ يَا بْنَ اَوَّلِ الْقَوْمِ اِسْلاماً وَاَقْدَمِهِمْ ايماناً وَاَقْوَمِهِمْ بِدينِ اللهِ وَاَحْوَطِهِمْ عَلَى الاِْسْلامِ، اَشْهَدُ لَقَدْ نَصَحْتَ للهِ وَلِرَسُولِهِ وَلاَِخيكَ فَنِعْمَ الاَْخُ الْمُواسي، فَلَعَنَ اللهُ اُمَّةً قَتَلَتْكَ، وَلَعَنَ اللهُ اُمَّةٌ ظَلَمَتْكَ، وَلَعَنَ اللهُ اُمَّةً اسْتَحَلَّتْ مِنْكَ الَْمحارِمَ وَانْتَهَكَتْ فِي قَتْلِكَ حُرْمَةَ الاِْسْلامِ، فَنِعْمَ الاَْخُ الصّابِرُ الُْمجاهِدُ الُْمحامِي النّاصِرُ وَالاَْخُ الدّافِعُ عَنْ اَخيهِ الُْمجيبُ اِلى طاعَةِ رَبِّهِ، الرّاغِبُ فيـما زَهِدَ فيهِ غَيْرُهُ مِنَ الثَّوابِ الْجَزيلِ وَالثَّناءِ الْجَميلِ، وَاَلْحَقَكَ اللهُ بِدَرَجَةِ آبائِكَ فِي دارِ النَّعيمِ اِنَّهُ حَميدٌ مَجيدٌ ."}],"preview":"اَلسَّلامُ عَلَيْكُمْ يا اَوْلِياءَ اللهِ وَاَحِبّاءَهُ، اَلسَّلامُ عَلَيْكُمْ يا اَصْفِياءَ اللهِ وَاَوِدّاءَهُ اَلسَّلامُ عَلَيْكُمْ يا اَنْصارَ دينِ اللهِ وَاَنْصارَ نَبِيّهِ وَ","hasTranslate":false},{"id":"mf_ar_225","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّالِثُ :","title":"ثمّ انكبّ على القبر وقل :","blocks":[{"type":"Text","content":"اَللّـهُمَّ لَكَ تَعَرَّضْتُ وَلِزِيارَةِ اَوْلِيائِكَ قَصَدْتُ، رَغْبَةً فِي ثَوابِكَ وَرَجاءً لِمَغْفِرَتِكَ وَجَزيلِ اِحْسانِكَ، فَاَسْاَلُكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَنْ تَجْعَلَ رِزْقي بِهِمْ دارّاً، وَعَيْشي بِهِمْ قارّاً، وَزِيارَتي بِهِمْ مَقْبُولَةً، وَذَنْبي بِهِمْ مَغْفُوراً، وَاقْلِبْني بِهُمْ مُفْلِحاً مُنْجِحاً مُسْتَجاباً دُعائي بِاَفْضَلِ ما يَنْقَلِبُ بِهِ اَحَدٌ مِنْ زُوّارِهِ وَالْقاصِدينَ اِلَيْهِ بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ ."},{"type":"Text","content":"ثمّ قبّل الضّريح وصلّ عنده صلاة الزّيارة وما بدا لك ، فاذا أردت وداعه فقُل ما ذكرناه سابقاً في وداعه (عليه السلام(."}],"preview":"اَللّـهُمَّ لَكَ تَعَرَّضْتُ وَلِزِيارَةِ اَوْلِيائِكَ قَصَدْتُ، رَغْبَةً فِي ثَوابِكَ وَرَجاءً لِمَغْفِرَتِكَ وَجَزيلِ اِحْسانِكَ، فَاَسْاَلُكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ","hasTranslate":false},{"id":"mf_ar_226","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّالِثُ :","title":"السّابعةُ : زيارة عاشُوراء","blocks":[{"type":"AboutText","content":"اعلم انّ ما خصّ من الزّيارات بيوم عاشوراء عديدة ونحن للاختصار نقتصر منها على زيارتين وقد ذكرنا في أعمال يوم عاشوراء ايضاً من الزّيارة وغيرها ما يناسب المقام ."},{"type":"Text","content":"الزّيارة الاُولى"},{"type":"Text","content":"ممّا أردنا ايرداه هُنا هي زيارة عاشوراء المشهورة ويُزار بها من قرب ومن بُعد، وروايتها المشروحة كما رواها الشّيخ أبو جعفر الطّوسي في المصباح ما يلي : روى محمّد بن اسماعيل بن بزيع، عن صالح بن عقبة، عن أبيه، عن الباقر (عليه السلام)قال : من زار الحسين بن عليّ (عليهما السلام) في يوم عاشوراء من المحرّم يظل عنده باكياً لقى الله عزّوجل يوم يلقاه بثواب ألفي حجّة وألفي عُمرة وألفي غزوة كثواب من حجّ واعتمر وغزا مع رسُول الله (صلى الله عليه وآله وسلم) ومع الائمّة الرّاشدين ، قال : قلت : جعلت فداك فما لمن كان في بعيد البلاد وأقاصيها ولم يمكنه المسير اليه في ذلك اليوم ؟ قال : اذا كان كذلك برز الى الصّحراء أو صعد سطحاً مرتفعاً في داره وأومأ اليه بالسّلام واجتهد في الدّعاء على قاتليه وصلّى من بُعد ركعتين وليكن ذلك في صدر النّهار قبل أن تزُول الشّمس ثمّ ليندب الحسين (عليه السلام) ويبكيه ويأمر من في داره ممّن لا يتّقيه بالبكاء عليه ويقم في داره المُصيبة باظهار الجزع عليه وليعزّ فيها بعضهم بعضاً بمصابهم بالحسين (عليه السلام)وأنا الضّامن لهم اذا فعلوا ذلك جميع ذلك ، قلت : جعلت فداك أنت الضّامن ذلك لهم والزّعيم ؟ قال : أنا الضّامن وأنا الزّعيم لمن فعل ذلك . قلت : فكيف يعزّي بعضنا بعضاً ؟ قال : تقولون : اَعْظَمَ اللهُ اُجُورَنا بِمُصابِنا بِالْحُسَيْنِ عليه السلام وَجَعَلَنا وَاِيّاكُمْ مِنَ الطّالِبينَ بِثارِهِ مَعَ وَلِيِّهِ الاِْمامِ الْمَهْدِيِّ مِنْ آلِ مُحَمَّد عليهم السلام، وان استطعت أن لا تخرج في يومك في حاجة فافعل فانّه يوم نحس لا يقضي فيه حاجة مؤمن وان قضيت لم يبارك له فيما ادّخر ولم يبارك له في أهله، فاذا فعلوا ذلك كتب الله لهم ثواب ألف حجّة وألف عمرة وألف غزوة كلّها مع رسول الله (صلى الله عليه وآله وسلم)وكان له أجر وثواب مُصيبة كُلّ نبيّ ورسُول ووصيّ وصدّيق وشهيد مات أو قُتل منذ خلق الله الدّنيا الى أن تقُوم السّاعة ."},{"type":"AboutText","content":"قال صالح بن عقبة وسيف بن عميرة : قال علقمة بن محمّد الحضرمي : قلت للباقر صلوات الله وسلامه عليه : علّمني دعاءً أدعو به في ذلك اليوم اذا أنا زُرته من قُرب ودعاءاً أدعو به اذا لم أزره من قُرب وأومأت من بُعد البلاد ومن داري بالسّلامة اليه . فقال لي : يا علقمة اذا أنت صلّيت الرّكعتين بعد أن تؤمي اليه بالسّلام فقل بعد الايماء اليه من بعد التّكبير هذا القول (أي الزّيارة الاتية) فانّك اذا قُلت ذلك فقد دعوت بما يدعُو به زوّاره من الملائكة وكتب الله لك مائة ألف ألف درجة وكنت كمن استشهدوا معه تشاركهم في درجاتهم، وما عرفت الاّ في زُمرة الشّهداء الّذين استشهدوا معه وكتب لك ثواب زيارة كلّ نبيّ وكُلّ رسُول وزيارة كلّ من زار الحسين (عليه السلام)منذ يوم قُتل سلام الله عليه وعلى أهل بيته . تقول :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا اَبا عَبْدِاللهِ، اَلسَّلامُ عَلَيْكَ يَا بْنَ رَسُولِ اللهِ(السَّلامُ عَلَيكَ يا خِيَرَةِ اللهِ وابْنَ خَيرَتِهِ) اَلسَّلامُ عَلَيْكَ يَا بْنَ اَميرِ الْمُؤْمِنينَ وَابْنَ سَيِّدِ الْوَصِيّينَ، اَلسَّلامُ عَلَيْكَ يَا بْنَ فاطِمَةَ سَيِّدَةِ نِساءِ الْعالَمينَ، اَلسَّلامُ عَلَيْكَ يا ثارَ اللهِ وَابْنَ ثارِهِ وَالْوِتْرَ الْمَوْتُورَ، اَلسَّلامُ عَلَيْكَ وَعَلَى الاَْرْواحِ الَّتي حَلَّتْ بِفِنائِكَ عَلَيْكُمْ مِنّي جَميعاً سَلامُ اللهِ اَبَداً ما بَقيتُ وَبَقِىَ اللَّيْلُ وَالنَّهارُ، يا اَبا عَبْدِاللهِ لَقَدْ عَظُمَتِ الرَّزِيَّةُ وَجَلَّتْ وَعَظُمَتِ الْمُصيبَةُ بِكَ عَلَيْنا وَعَلى جَميعِ اَهْلِ الاِْسْلامِ وَجَلَّتْ وَعَظُمَتْ مُصيبَتُكَ فِي السَّماواتِ عَلى جَميعِ اَهْلِ السَّماواتِ، فَلَعَنَ اللهُ اُمَّةً اَسَّسَتْ اَساسَ الظُّلْمِ وَالْجَوْرِ عَلَيْكُمْ اَهْلَ الْبَيْتِ، وَلَعَنَ اللهُ اُمَّةً دَفَعَتْكُمْ عَنْ مَقامِكُمْ وَاَزالَتْكُمْ عَنْ مَراتِبِكُمُ الَّتي رَتَّبَكُمُ اللهُ فيها، وَلَعَنَ اللهُ اُمَّةً قَتَلَتْكُمْ وَلَعَنَ اللهُ الْمُمَهِّدينَ لَهُمْ بِالَّتمْكينِ مِنْ قِتالِكُمْ، بَرِئْتُ اِلَى اللهِ وَاِلَيْكُمْ مِنْهُمْ وَمِنْ اَشْياعِهِمْ وَاَتْباعِهِمْ وَاَوْلِيائِهِم، يا اَبا عَبْدِاللهِ اِنّي سِلْمٌ لِمَنْ سالَمَكُمْ وَحَرْبٌ لِمَنْ حارَبَكُمْ اِلى يَوْمِ الْقِيامَةِ، وَلَعَنَ اللهُ آلَ زِياد وَآلَ مَرْوانَ، وَلَعَنَ اللهُ بَني اُمَيَّةَ قاطِبَةً، وَلَعَنَ اللهُ ابْنَ مَرْجانَةَ، وَلَعَنَ اللهُ عُمَرَ بْنَ سَعْد، وَلَعَنَ اللهُ شِمْراً، وَلَعَنَ اللهُ اُمَّةً اَسْرَجَتْ وَاَلْجَمَتْ وَتَنَقَّبَتْ لِقِتالِكَ، بِاَبي اَنْتَ وَاُمّي لَقَدْ عَظُمَ مُصابي بِكَ فَاَسْأَلُ اللهَ الَّذي َكْرَمَ مَقامَكَ وَاَكْرَمَني اَنْ يَرْزُقَني طَلَبَ ثارِكَ مَعَ اِمام مَنْصُور مِنْ اَهْلِ بَيْتِ مُحَمَّد صَلَّى اللهُ عَلَيْهِ وَآلِهِ، اَللّـهُمَّ اجْعَلْني عِنْدَكَ وَجيهاً بِالْحُسَيْنِ عليه السلام فِي الدُّنْيا وَالاْخِرَةِ، يا اَبا عَبْدِاللهِ اِنّي اَتَقَرَّبُ اِلى اللهِ وَ اِلى رَسُولِهِ وَاِلى اَميرِ الْمُؤْمِنينَ وَاِلى فاطِمَةَ وَاِلَى الْحَسَنِ وَاِلَيْكَ بِمُوالاتِكَ وَبِالْبَراءَةِ (مِمَّنْ قاتَلَكَ وَنَصَبَ لَكَ الْحَرْبَ وَبِالْبَراءَةِ مِمَّنْ اَسَسَّ اَساسَ الظُّلْمِ وَالْجَوْرِ عَلَيْكُمْ وَاَبْرَأُ اِلَى اللهِ وَاِلى رَسُولِهِ) مِمَّنْ اَسَسَّ اَساسَ ذلِكَ وَبَنى عَلَيْهِ بُنْيانَهُ وَجَرى فِي ظُلْمِهِ وَجَوْرِهِ عَلَيْكُمْ وَعلى اَشْياعِكُمْ، بَرِئْتُ اِلَى اللهِ وَاِلَيْكُمْ مِنْهُمْ وَاَتَقَرَّبُ اِلَى اللهِ ثُمَّ اِلَيْكُمْ بِمُوالاتِكُمْ وَمُوالاةِ وَلِيِّكُمْ وَبِالْبَراءَةِ مِنْ اَعْدائِكُمْ وَالنّاصِبينَ لَكُمُ الْحَرْبَ وَبِالْبَراءَةِ مِنْ اَشْياعِهِمْ وَاَتْباعِهِمْ، اِنّي سِلْمٌ لِمَنْ سالَمَكُمْ وَحَرْبٌ لِمَنْ حارَبَكُمْ وَوَلِىٌّ لِمَنْ والاكُمْ وَعَدُوٌّ لِمَنْ عاداكُمْ فَاَسْأَلُ اللهَ الَّذي أكْرَمَني بِمَعْرِفَتِكُمْ وَمَعْرِفَةِ اَوْلِيائِكُمْ وَرَزَقَنِى الْبَراءَةَ مِنْ اَعْدائِكُمْ اَنْ يَجْعَلَني مَعَكُمْ فِي الدُّنْيا وَالاْخِرَةِ وَاَنْ يُثَبِّتَ لي عِنْدَكُمْ قَدَمَ صِدْق فِي الدُّنْيا وَالاْخِرَةِ وَاَسْأَلُهُ اَنْ يُبَلِّغَنِى الْمَقامَ الَْمحْمُودَ لَكُمْ عِنْدَ اللهِ وَاَنْ يَرْزُقَني طَلَبَ ثاري مَعَ اِمام هُدىً ظاهِر ناطِق بِالْحَقِّ مِنْكُمْ وَاَسْألُ اللهَ بِحَقِّكُمْ وَبِالشَّأنِ الَّذي لَكُمْ عِنْدَهُ اَنْ يُعْطِيَني بِمُصابي بِكُمْ اَفْضَلَ ما يُعْطي مُصاباً بِمُصيبَتِهِ مُصيبَةً ما اَعْظَمَها وَاَعْظَمَ رَزِيَّتَها فِي الاِْسْلامِ وَفِي جَميعِ السَّماواتِ وَالاْرْضِ اَللّـهُمَّ اجْعَلْني فِي مَقامي هذا مِمَّنْ تَنالُهُ مِنْكَ صَلَواتٌ وَرَحْمَةٌ وَمَغْفِرَةٌ، اَللّـهُمَّ اجْعَلْ مَحْياىَ مَحْيا مُحَمَّد وَآلِ مُحَمَّد وَمَماتي مَماتَ مُحَمَّد وَآلِ مُحَمَّد، اَللّـهُمَّ اِنَّ هذا يَوْمٌ تَبَرَّكَتْ بِهِ بَنُو اُمَيَّةَ وَابْنُ آكِلَةِ الاَْكبادِ اللَّعينُ ابْنُ اللَّعينِ عَلى لِسانِكَ وَلِسانِ نَبِيِّكَ صَلَّى اللهُ عَلَيْهِ وَآلِهِ فِي كُلِّ مَوْطِن وَمَوْقِف وَقَفَ فيهِ نَبِيُّكَ صَلَّى اللهُ عَلَيْهِ وَآلِهِ، اَللّـهُمَّ الْعَنْ اَبا سُفْيانَ وَمُعاوِيَةَ وَيَزيدَ ابْنَ مُعاوِيَةَ عَلَيْهِمْ مِنْكَ اللَّعْنَةُ اَبَدَ الاْبِدينَ، وَهذا يَوْمٌ فَرِحَتْ بِهِ آلُ زِياد وَآلُ مَرْوانَ بِقَتْلِهِمُ الْحُسَيْنَ صَلَواتُ اللهِ عَلَيْهِ، اَللّـهُمَّ فَضاعِفْ عَلَيْهِمُ اللَّعْنَ مِنْكَ وَالْعَذابَ (الاَْليمَ) اَللّـهُمَّ اِنّي اَتَقَرَّبُ اِلَيْكَ فِي هذَا الْيَوْمِ وَفِي مَوْقِفي هذا وَاَيّامِ حَياتي بِالْبَراءَةِ مِنْهُمْ وَاللَّعْنَةِ عَلَيْهِمْ وَبِالْمُوالاةِ لِنَبِيِّكَ وَآلِ نَبِيِّكَ عَلَيْهِ وَعليهم السلام ثمّ تقول مائة مرّة : اَللّـهُمَّ الْعَنْ اَوَّلَ ظالِم ظَلَمَ حَقَّ مُحَمَّد وَآلِ مُحَمَّد وَآخِرَ تابِع لَهُ عَلى ذلِكَ، اَللّـهُمَّ الْعَنِ الْعِصابَةَ الَّتي جاهَدَتِ الْحُسَيْنَ (عليه السلام) وَشايَعَتْ وَبايَعَتْ وَتابَعَتْ عَلى قَتْلِهِ، اَللّـهُمَّ الْعَنْهُمْ جَميعاً ثمّ تقول مائة مرّة : اَلسَّلامُ عَلَيْكَ يا اَبا عَبْدِاللهِ وَعَلَى الاَْرْواحِ الَّتي حَلَّتْ بِفِنائِكَ عَلَيْكَ مِنّي سَلامُ اللهِ اَبَداً ما بَقيتُ وَبَقِيَ اللَّيْلُ وَالنَّهارُ وَلا جَعَلَهُ اللهُ آخِرَ الْعَهْدِ مِنّي لِزِيارَتِكُمْ، اَلسَّلامُ عَلَى الْحُسَيْنِ وَعَلى عَلِيِّ بْنِ الْحُسَيْنِ وَعَلى اَوْلادِ الْحُسَيْنِ وَعَلى اَصْحابِ الْحُسَيْنِ، ثمّ تقول : اَللّـهُمَّ خُصَّ اَنْتَ اَوَّلَ ظالِم بِاللَّعْنِ مِنّي وَابْدَأْ بِهِ اَوَّلاً ثُمَّ (الْعَنِ) الثّانيَ وَالثّالِثَ وَالرّابِعَ اَللّـهُمَّ الْعَنْ يَزيدَ خامِساً وَالْعَنْ عُبَيْدَ اللهِ بْنَ زِياد وَابْنَ مَرْجانَةَ وَعُمَرَ بْنَ سَعْد وَشِمْراً وَآلَ اَبي سُفْيانَ وَآلَ زِياد وَآلَ مَرْوانَ اِلى يَوْمِ الْقِيامَةِ ثمّ تسجد وتقُول : اَللّـهُمَّ لَكَ الْحَمْدُ حَمْدَ الشّاكِرينَ لَكَ عَلى مُصابِهِمْ اَلْحَمْدُ للهِ عَلى عَظيمِ رَزِيَّتي اَللّـهُمَّ ارْزُقْني شَفاعَةَ الْحُسَيْنِ يَوْمَ الْوُرُودِ وَثَبِّتْ لي قَدَمَ صِدْق عِنْدَكَ مَعَ الْحُسَيْنِ وَاَصْحابِ الْحُسَيْنِ اَلَّذينَ بَذَلُوا مُهَجَهُمْ دُونَ الْحُسَيْنِ عليه السلام ."},{"type":"AboutText","content":"قال علقمة : قال الباقر (عليه السلام) : وان استطعت أن تزُوره في كُلّ يوم بهذه الزّيارة في دارك فافعل فلك ثواب جميع ذلك ."},{"type":"AboutText","content":"وروى محمّد بن خالد الطّيالسي عن سيف بن عميرة ، قال : خرجتُ مع صفوان بن مهران وجماعة من أصحابنا الى الغريّ بعدما خرج الصّادق (عليه السلام)فسرنا من الحيرة الى المدينة فلمّا فرغنا من الزّيارة أي زيارة امير المؤمنين (عليه السلام)صرف صفوان وجهه الى ناحية أبي عبد الله (عليه السلام) فقال لنا: تزورون الحُسين (عليه السلام) من هذا المكان من عند رأس امير المؤمنين (عليه السلام) من هاهُنا أومأ اليه الصّادق (عليه السلام) وأنا معه ، قال سيف بن عميرة : فدعا صفوان بالزّيارة الّتي رواها علقمة بن محمّد الحضرمي عن الباقر (عليه السلام) في يوم عاشوراء ثمّ صلّى ركعتين عند رأس امير المؤمنين (عليه السلام) وودّع في دبرهما امير المؤمنين (عليه السلام)وأومأ الى الحسين صلوات الله عليه بالسّلام منصرفاً وجهه نحوه وودّع وكان ممّا دعا دبرها :"},{"type":"Text","content":"يا اَللهُ يا اَللهُ يا اَللهُ، يا مُجيبَ دَعْوَةِ الْمُضْطَرِّينَ، يا كاشِفَ كُرَبِ الْمَكْرُوبينَ، يا غِياثَ الْمُسْتَغيثينَ، يا صَريخَ الْمُسْتَصْرِخينَ، وَيا مَنْ هُوَ اَقْرَبُ اِلَيَّ مِنْ حَبْلِ الْوَريدِ، وَيا مَنْ يَحُولُ بَيْنَ الْمَرْءِ وَقَلْبِهِ، وَيا مَنْ هُوَ بِالْمَنْظَرِ الاَْعْلى وَ بِالاُْفـُقِ الْمُبينِ، وَيا مَنْ هُوَ الرَّحْمنُ الرَّحيمُ عَلَى الْعَرْشِ اسْتَوى، وَيا مَنْ يَعْلَمُ خائِنَةَ الاَْعْيُنِ وَما تُخْفِي الصُّدُورُ، وَيا مَنْ لا تَخْفى عَلَيْهِ خافِيَهٌ، يا مَنْ لا تَشْتَبِهُ عَلَيْهِ الاَْصْواتُ، وَيا مَنْ لا تُغَلِّطُهُ الْحاجاتُ، وَيا مَنْ لا يُبْرِمُهُ اِلْحاحُ الْمُلِحّينَ، يا مُدْرِكَ كُلِّ فَوْت، وَيا جامِعَ كُلِّ شَمْل، وَيا بارِئَ النُّفُوسِ بَعْدَ الْمَوْتِ، يا مَنْ هُوَ كُلَّ يَوْم فِي شَأن، يا قاضِىَ الْحاجاتِ، يا مُنَفِّسَ الْكُرُباتِ، يا مُعْطِيَ السُّؤُلاتِ، يا وَلِيَّ الرَّغَباتِ، يا كافِىَ الْمُهِمّاتِ، يا مَنْ يَكْفي مِنْ كُلِّ شَىْء وَلا يَكْفي مِنْهُ شَيءٌ فِي السَّماواتِ وَالاَْرْضِ، اَسْاَلُكَ بِحَقِّ مُحَمَّد خاتَمِ النَّبِيّينَ وَعَلِيِّ اَميرِ الْمُؤْمِنينَ، وَبِحَقِّ فاطِمَةَ بِنْتِ نَبِيِّكَ، وَبِحَقِّ الْحَسَنِ وَالْحُسَيْنِ فَاِنّي بِهِمْ اَتَوَجَّهُ اِلَيْكَ فِي مَقامي هذا وَبِهِمْ اَتَوَسَّلُ وَبِهِمْ اَتَشَفَّعُ اِلَيْكَ، وَبِحَقِّهِمْ اَسْأَلُكَ وَاُقْسِمُ وَاَعْزِمُ عَلَيْكَ، وَبِالشَّأنِ الَّذي لَهُمْ عِنْدَكَ وَبِالْقَدْرِ الَّذي لَهُمْ عِنْدَكَ، وَبِالَّذي فَضَّلْتَهُمْ عَلَى الْعالَمينَ، وَبِاسْمِكَ الَّذي جَعَلْتَهُ عِنْدَهُمْ وَبِهِ خَصَصْتَهُمْ دُونَ الْعالَمينَ، وَبِهِ اَبَنْتَهُمْ وَاَبَنْتَ فَضْلَهُمْ مِنْ فَضْلِ الْعالَمينَ، حَتّى فاقَ فَضْلُهُمْ فَضْلَ الْعالَمينَ جَميعاً، اَسْاَلُكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاَنْ تَكْشِفَ عَنّي غَمّي وَهَمّي وَكَرْبي، وَتَكْفِيَنِى الْمُهِمَّ مِنْ اُمُوري، وَتَقْضِيَ عَنّي دَيْني وَ تُجيرَني مِنَ الْفَقْرِ وَتُجيرَني مِنَ الْفاقَةِ وَتُغْنِيَني عَنِ الْمَسْأَلَةِ اِلَى الَْمخْلُوقينَ، وَتَكْفِيَني هَمَّ مَنْ اَخافُ هَمَّهُ، وَعُسْرَ مَنْ اَخافُ عُسْرَهُ، وَحُزُونَةَ مَنْ اَخافُ حُزُونَتَهُ، وَشَرَّ مَنْ اَخافُ شَرَّهُ، وَمَكْرَ مَنْ اَخافُ مَكْرَهُ، وَبَغْيَ مَنْ اَخافُ بَغْيَهُ، وَ جَوْرَ مَنْ اَخافُ جَوْرَهُ، وَسُلْطانَ مَنْ اَخافُ سُلْطانَهُ، وَكَيْدَ مَنْ اَخافُ كَيْدَهُ، وَمَقْدُرَةَ مَنْ اَخافُ مَقْدُرَتَهُ عَلَيَّ، وَتَرُدَّ عَنّي كَيْدَ الْكَيَدَةِ وَمَكْرَ الْمَكَرَةِ، اَللّـهُمَّ مَنْ اَرادَني فَاَرِدْهُ، وَمَنْ كادَني فَكِدْهُ، وَاصْرِفْ عَنّي كَيْدَهُ وَمَكْرَهُ وَبَأسَهُ وَاَمانِيَّهُ، وَامْنَعْهُ عَنّي كَيْفَ شِئْتَ وَاَنّى شِئْتَ، اَللّـهُمَّ اشْغَلْهُ عَنّي بِفَقْر لا تَجْبُرُهُ، وَبِبَلاء لا تَسْتُرُهُ، وَبِفاقَة لا تَسُدّها، وَبِسُقْم لا تُعافيهِ، وَذُلٍّ لا تُعِزُّهُ، وَبِمَسْكَنَة لا تَجْبُرُها، اَللّـهُمَّ اضْرِبْ بِالذُّلِّ نَصْبَ عَيْنَيْهِ، وَاَدْخِلْ عَلَيْهِ الْفَقْرَ فِي مَنْزِلِهِ، وَالْعِلَّةَ وَالسُّقْمَ فِي بَدَنِهِ، حَتّى تَشْغَلَهُ عَنّي بِشُغْل شاغِل لا فَراغَ لَهُ، وَاَنْسِهِ ذِكْري كَما اَنْسَيْتَهُ ذِكْرَكَ، وَخُذْ عَنّي بِسَمْعِهِ وَبَصَرِهِ وَلِسانِهِ وَيَدِهِ وَرِجْلِهِ وَقَلْبِهِ وَجَميعِ جَوارِحِهِ، وَاَدْخِلْ عَلَيْهِ فِي جَميعِ ذلِكَ الْسُّقْمَ وَلا تَشْفِهِ حَتّى تَجْعَلَ ذلِكَ لَهُ شُغْلاً شاغِلاً بِهِ عَنّي وَعَنْ ذِكْري، وَاكْفِني يا كافِيَ مالا يَكْفي سِواكَ، فَاِنَّكَ الْكافِي لا كافِىَ سِواكَ، وَمُفَرِّجٌ لا مُفَرِّجَ سِواكَ، وَمُغيثٌ لا مُغيثَ سِواكَ، وَجارٌ لا جارَ سِواكَ، خابَ مَنْ كانَ جارُهُ سِواكَ، وَمُغيثُهُ سِواكَ، وَمَفْزَعُهُ اِلى سِواكَ، وَمَهْرَبُهُ اِلى سِواكَ، وَمَلْجَأُهُ اِلى غَيْرِكَ، وَمَنْجاهُ مِنْ مَخْلُوق غَيْرِكَ، فَاَنْتَ ثِقَتي وَرَجائي وَمَفْزَعي وَمَهْرَبي وَمَلْجَئي وَمَنْجاىَ فَبِكَ اَسْتَفْتِحُ وَبِكَ اَسْتَنْجِحُ، وَبِمُحَمَّد وَآلِ مُحَمَّد اَتَوَجَّهُ اِلَيْكَ وَاَتَوَسَّلُ وَاَتَشَفَّعُ، فَاَسْاَلُكَ يا اَللهُ يا اَللهُ يا اَللهُ، فَلَكَ الْحَمْدُ وَلَكَ الشُّكْرُ وَاِلَيْكَ الْمُشْتَكى وَاَنْتَ الْمُسْتَعانُ فَاَسْاَلُكَ يا اَللهُ يا اَللهُ يا اَللهُ بِحَقِّ مُحَمَّد وَآلِ مُحَمَّد اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَنْ تَكْشِفَ عَنّي غَمّي وَهَمّي وَكَرْبي فِي مَقامي هذا كَما كَشَفْتَ عَنْ نَبِيِّكَ هَمَّهُ وَغَمَّهُ وَ كَرْبَهُ وَكَفَيْتَهُ هَوْلَ عَدُوِّهِ، فَاكْشِفْ عَنّي كَما كَشَفْتَ عَنْهُ وَفَرِّجْ عَنّي كَما فَرَّجْتَ عَنْهُ وَاكْفِني كَما كَفَيْتَهُ، وَاصْرِفْ عَنّي هَوْلَ ما اَخافُ هَوْلَهُ، وَمَؤُنَةَ ما اَخافُ مَؤُنَتَهُ، وَهَمَّ ما اَخافُ هَمَّهُ بِلا مَؤُنَة عَلى نَفْسي مِنْ ذلِكَ، وَاصْرِفْني بِقَضاءِ حَوائِجي، وَكِفايَةِ ما اَهَمَّني هَمُّهُ مِنْ اَمْرِ آخِرَتي وَدُنْياىَ، يا اَميرَ الْمُؤْمِنينَ وَيا اَبا عَبْدِاللهِ، عَلَيْكُما مِنّي سَلامُ اللهِ اَبَداً ما بَقيتُ وَبَقِيَ اللَّيْلُ وَالنَّهارُ وَلا جَعَلَهُ اللهُ آخِرَ الْعَهْدِ مِنْ زِيارَتِكُما، وَلا فَرَّقَ اللهُ بَيْني وَبَيْنَكُما، اَللّـهُمَّ اَحْيِني حَياةَ مُحَمَّد وَذُرِّيَّتِهِ وَاَمِتْني مَماتَهُمْ وَتَوَفَّني عَلى مِلَّتِهِمْ، وَاحْشُرْني فِي زُمْرَتِهِمْ وَلا تُفَرِّقْ بَيْني وَبَيْنَهُمْ طَرْفَةَ عَيْن اَبَداً فِي الدُّنْيا وَالاْخِرَةِ، يا اَميرَ الْمُؤْمِنينَ وَيا اَبا عَبْدِاللهِ اَتَيْتُكُما زائِراً وَمُتَوَسِّلاً اِلَى اللهِ رَبّي وَرَبِّكُما، وَمُتَوَجِّهاً اِلَيْهِ بِكُما وَمُسْتَشْفِعاً بِكُما اِلَى اللهِ (تَعالى) فِي حاجَتي هذِهِ فَاشْفَعا لي فَاِنَّ لَكُما عِنْدَ اللهِ الْمَقامَ الَْمحْمُودَ، وَالْجاهَ الْوَجيهَ، وَالْمَنْزِلَ الرَّفيعَ وَالْوَسيلَةَ، اِنّي اَنْقَلِبُ عَنْكُما مُنْتَظِراً لِتَنَجُّزِ الْحاجَةِ وَقَضائِها وَنَجاحِها مِنَ اللهِ بِشَفاعَتِكُما لي اِلَى اللهِ فِي ذلِكَ، فَلا اَخيبُ وَلا يَكُونُ مُنْقَلَبي مُنْقَلَباً خائِباً خاسِراً، بَلْ يَكُونُ مُنْقَلَبي مُنْقَلَباً راجِحاً (راجِياً) مُفْلِحاً مُنْجِحاً مُسْتَجاباً بِقَضاءِ جَميعِ حَوائِجي وَتَشَفَّعا لي اِلَى اللهِ، انْقَلَبْتُ عَلى ما شاءَ اللهُ وَلا حَوْلَ وَلا قُوَّةَ اِلاّ بِاللهِ، مُفَوِّضاً اَمْري اِلَى اللهِ مُلْجِأً ظَهْري اِلَى اللهِ، مُتَوَكِّلاً عَلَى اللهِ وَاَقُولُ حَسْبِيَ اللهُ وَكَفى سَمِعَ اللهُ لِمَنْ دَعا لَيْسَ لي وَراءَ اللهِ وَوَراءَكُمْ يا سادَتي مُنْتَهى، ما شاءَ رَبّي كانَ وَمالَمْ يَشَأْ لَمْ يَكُنْ، وَلا حَوْلَ وَلا قُوَّةَ اِلاّ بِاللهِ، اَسْتَوْدِعُكُمَا اللهَ وَلا جَعَلَهُ اللهُ آخِرَ الْعَهْدِ مِنّي اِلَيْكُما، اِنْصَرَفْتُ يا سَيِّدي يا اَميرَ الْمُؤْمِنينَ وَمَوْلايَ وَاَنْتَ يا اَبا عَبْدِاللهِ يا سَيِّدي وَسَلامي عَلَيْكُما مُتَّصِلٌ مَا اتَّصَلَ اللَّيْلُ وَالنَّهارُ واصِلٌ ذلِكَ اِلَيْكُما غَيْرُ مَحْجُوب عَنْكُما سَلامي اِنْ شاءَ اللهُ، وَاَسْأَلُهُ بِحَقِّكُما اَنْ يَشاءَ ذلِكَ وَيَفْعَلَ فَاِنَّهُ حَميدٌ مَجيدٌ، اِنْقَلَبْتُ يا سَيِّدَىَّ عَنْكُما تائِباً حامِداً للهِ شاكِراً راجِياً لِلاِْجابَةِ غَيْرَ آيِس وَلا قانِط تائِباً عائِداً راجِعاً اِلى زِيارَتِكُما غَيْرَ راغِب عَنْكُما وَلا مِنْ زِيارَتِكُما بَلْ راجِعٌ عائِدٌ اِنْ شاءَ اللهُ وَلا حَوْلَ وَلا قُوَّةَ اِلاّ بِاللهِ، يا سادَتي رَغِبْتُ اِلَيْكُما وَاِلى زِيارَتِكُما بَعْدَ اَنْ زَهِدَ فيكُما وَفِي زِيارَتِكُما اَهْلُ الدُّنْيا فَلا خَيَّبَنِيَ اللهُ ما رَجَوْتُ وَما اَمَّلْتُ فِي زِيارَتِكُما اِنَّهُ قَريبٌ مُجيبٌ."},{"type":"AboutText","content":"قال سيف بن عميرة: فسألت صفواناً فقُلت له: انّ علقمة بن محمّد لم يأتنا بهذا عن الباقر (عليه السلام) انّما أتانا بدعاء الزّيارة ، فقال صفوان : وردت مع سيّدي الصّادق صلوات الله وسلامه عليه الى هذا المكان ففعل مثل الَّذي فعلناه في زيارتنا، ودعا بهذا الدّعاء عند الوداع بعد أن صلّى كما صلّينا وودّع كما ودّعنا ، ثمّ قال صفوان : قال الصّادق (عليه السلام) : تعاهد هذه الزّيارة وادعُ بهذا الدّعاء وزُر به فانّي ضامن على الله لكلّ من زار بهذه الزّيارة ودعا بهذا الدّعاء من قُرب أو بُعد انّ زيارته مقبولة وسعيه مشكور وسلامه واصل غير محجُوب وحاجته مقضيّة من الله تعالى بالغة ما بلغت ولا يخيبُه، يا صفوان وجدت هذه الزّيارة مضمُونة بهذا الضّمان عن أبي وأبي عن أبيه عليّ بن الحسين (عليهما السلام) مضموناً بهذا الضّمان عن الحسين (عليه السلام)والحسين (عليه السلام) عن أخيه الحسن (عليه السلام) مضمُوناً بهذا الضّمان، والحسن (عليه السلام) عن أبيه امير المؤمنين (عليه السلام)مضموناً بهذا الضّمان، وامير المؤمنين (عليه السلام) عن رسول الله (صلى الله عليه وآله وسلم) مضمُوناً بهذا الضّمان، ورسول الله (صلى الله عليه وآله وسلم)عن جبرئيل (عليه السلام) مضموناً بهذا الضّمان، وجبرئيل عن الله تعالى مضموناً بهذا الضّمان، وقد آلى الله على نفسه عزّوجل انّ من زار الحسين (عليه السلام)بهذه الزّيارة من قُرب أو بُعد ودعا بهذا الدّعاء قبلت منه زيارته وشفعته في مسألته بالغة ما بلغت واعطيته سؤله ثمّ لا ينقلِب عنّي خائباً واقلبه مسروراً قريراً عينه بقضاء حاجته والفوز بالجنّة والعتق من النّار، وشفعته في كلّ من شفع خلا ناصب لنا أهل البيت، آلى الله تعالى بذلك على نفسه وأشهدنا بما شهدت به ملائكة ملكوته، ثمّ قال جبرئيل : يا رسول الله أرسلني الله اليك سُروراً وبشرى لك ولعليّ وفاطمة والحسن والحسين والائمة من ولدك وشيعتكم الى يوم البعث لا زلت مسروراً ولا زال علي وفاطمة والحسن والحسين وشيعتكم مسرورين الى يوم البعث ، قال صفوان : قال لي الصّادق (عليه السلام): يا صفوان اذا حدث لك الى الله حاجة فزُر بهذه الزّيارة من حيث كنت وادعُ بهذا الدّعاء وسل ربّك حاجتك تأتك من الله، والله غير مخلف وعده رسوله بجوده وبمنّه والحمد لله ."},{"type":"AboutText","content":"أقول : ورد في كتاب النّجم الثّاقب قصّة تشرّف الحاج السّيد احمد الرّشتي بالحضُور عند امام العصر أرواحنا فداه في سفر الحجّ وقوله (عليه السلام) له : لماذا لا تقرأ زيارة عاشوراء، عاشوراء عاشوراء عاشوراء ونحن سنرويها بعد الزّيارة الجامعة الكبيرة ان شاء الله ."},{"type":"Text","content":"وقال شيخنا ثقة الاسلام النّوري (رحمه الله) : أمّا زيارة عاشوراء فكفاها فضلاً وشرفاً انّها لا تسانخ سائر الزّيارات الّتي هي من انشاء المعصوم واملائه في ظاهر الامر وان كان لا يبرز من قلوبهم الطّاهرة الاّ ما تبلغها من المبدأ الاعلى بل تسانخ الاحاديث القدسيّة التي أوحى الله جلّت عظمته بها الى جبرئيل بنصّها بما فيها من اللّعن والسّلام والدّعاء، فأبلغها جبرئيل الى خاتم النّبيين (صلى الله عليه وآله وسلم) وهي كما دلّت عليه التجارب فريدة في آثارها من قضاء الحوائج ونيل المقاصد ودفع الاعادي لو واضب عليها الزّائر أربعين يوماً أو أقلّ، ولكن أعظم ما انتجته من الفوائد ما في كتاب دار السّلام وملّخصه انّه حدث الثّقة الصّالح التّقي الحاج المولى حسن اليزدي المجاور للمشهد الغرويّ وهو من الّذين وفوا بحقّ المجاورة وأتعبوا أنفسهم في العبادة، عن الثّقة الامين الحاج محمّد عليّ اليزدي قال : كان في يزد رجل صالح فاضل مشتغل بنفسه ومواظب لعمارة رمسه يبيت في اللّيالي بمقبرة خارج بلدة يزد تُعرف بالمزار وفيها جملة من الصّلحاء، وكان له جار نشأ معه من صغر سنّه عند المُعلّم وغيره الى أن صار عشّاراً وكان كذلك الى أن مات ودفن في تلك المقبرة قريباً من المحلّ الَّذي كان يبيت في الرّجل الصّالح المذكور، فرآه بعد موته بأقلّ من شهر في المنام في زيّ حسن وعليه نضرة النّعيم، فتقدّم اليه وقال له : انّي عالم بمبدئك ومنتهاك وباطنك وظاهرك ولم تكن ممّن يحتمل في حقّه حسن الباطن ولم يكن عملك مقتضياً أنّ العذاب والنكال فبم نلت هذا المقام ، قال: نعم الامر كما قلت، كنت مقيماً في أشدّ العذاب من يوم وفاتي الى أمس وقد توفّيت فيه زوجة الاستاذ أشرف الحدّاد ودفنت في هذا المكان، وأشار الى طرف بينه وبينه قريب من مائة ذراع وفي ليلة دفنها زارها أبو عبد الله (عليه السلام) ثلاث مرّات وفي المرّة الثّالثة أمر برفع العذاب عن هذه المقبرة فصرت في نعمة وسعة وخفض عيش ودعة، فانتبه متحيّراً ولم تكن له معرفة بالحدّاد ومحلّه فطلبه في سُوق الحدّادين فوجده ، فقال له : ألك زوجة ؟ قال : نعم توفّيت بالامس ودفنتها في المكان الفلاني وذكر الموضع الَّذي أشار اليه ، قال : فهل زارت أبا عبد الله (عليه السلام) ؟ قال : لا ، قال : فهل كانت تذكر مصائبه ؟ قال : لا ، قال : فهل كان لها مجلس تذكر فيه مصائبه ؟ قال : لا ، فقال الرّجل : وما تريد من السّؤال ؟ فقصّ عليه رؤياه ، قال : كانت مواظبة على زيارة عاشوراء ."}],"preview":"اعلم انّ ما خصّ من الزّيارات بيوم عاشوراء عديدة ونحن للاختصار نقتصر منها على زيارتين وقد ذكرنا في أعمال يوم عاشوراء ايضاً من الزّيارة وغيرها ما يناسب المقام .","hasTranslate":false},{"id":"mf_ar_227","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّالِثُ :","title":"الثّانية زيارة عاشُوراء غَير المشهُورة","blocks":[{"type":"Text","content":"وهي تناظر الزّيارة المشهُورة المتداولة في الاجر والثّواب خلوّاً من عناء اللّعن والسّلام مائة مرّة، وهي فوز عظيم لمن يشغله عن تلك الزّيارة شاغل هام، وكيفيّتها على ما في كتاب المزار القديم من دون الشّرح كما يلي : من أحبّ أن يزوره (عليه السلام) من بُعد البلاد أو قُربها فليغتسل ويبرز الى الصّحراء أو يصعد سطح داره فيصلّي ركعتين يقرأ فيهما سورة قُلْ هُوَ اللهُ اَحَدٌ فاذا سلّم أومأ اليه بالسّلام وليتوجّه بالسّلام والايماء والنيّة الى جهة قبر أبي عبد الله الحسين (عليه السلام) ، ثمّ يقول بخشوع واستكانة :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يَا بْنَ رَسُولِ اللهِ، اَلسَّلامُ عَلَيْكَ يَا بْنَ الْبَشيرِ النَّذيرِ وَابْنَ سَيِّدِ الْوَصِيّينَ، اَلسَّلامُ عَلَيْكَ يَا بْنَ فاطِمَةَ سَيِّدَةِ نِساءِ الْعالَمينَ، اَلسَّلامُ عَلَيْكَ يا خِيَرَةِ اللهِ وَابْنَ خِيَرَتِهِ، اَلسَّلامُ عَلَيْكَ يا ثارَ اللهِ وَابْنَ ثارِهِ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الْوِتْرُ الْمَوْتُور، اَلسَّلامُ عَلَيْكَ اَيُّهَا الاِْمامُ الْهادِي الزَّكيُّ وَعَلى اَرْواح حَلَّتْ بِفَنائِكَ وَاَقامَتْ فِي جَوارِكَ وَوَفَدَتْ مَعَ زُوّارِكَ، اَلسَّلامُ عَلَيْكَ مِنّي ما بَقيتُ وَبَقِيَ اللَّيْلُ وَالنَّهارُ، فَلَقَدْ عَظُمَتْ بِكَ الرَّزِيَّةُ وَجَلَّتْ فِي الْمُؤْمِنينَ وَالْمُسْلِمينَ وَفِي اَهْلِ السَّماواتِ وَاَهْلِ الاَْرَضينَ اَجْمَعينَ، فَاِنّا للهِ وَاِنّا اِلَيْهِ راجِعُونَ صَلَواتُ اللهِ وَبَرَكاتُهُ وَتَحِيّاتُهُ عَلَيْكَ يا اَبا عَبْدِاللهِ الْحُسَيْنَ وَعَلى آبائِكَ الطَّيِّبينَ الْمُنْتَجَبينَ وَعَلى ذُرِّيّاتِكُمُ الْهُداةِ الْمَهْدِيّينَ، لَعَنَ اللهُ اُمَّةً خَذَلَتْكَ وَتَرَكَتْ نُصْرَتَكَ وَمَعُونَتَكَ، وَلَعَنَ اللهُ اُمَّةً اَسَّسَتْ اَساسَ الظُّلْمِ لَكُمْ وَمَهَّدَتِ الْجَوْرَ عَلَيْكُمْ، وَطَرَّقَتْ اِلى اَذِيَّتِكُمْ وَتَحَيُّفِكُمْ وَجارَتْ ذلِكَ فِي دِيارِكُمْ وَاَشْياعِكُمْ، بَرِئْتُ اِلَى اللهِ عَزَّوَجَلَّ وَاِلَيْكُمْ يا ساداتي وَمَوالِيَّ وَاَئِمَّتي مِنْهُمْ وَمِنْ اَشْياعِهِمْ وَاَتْباعِهِمْ وَاَسْألُ اللهَ الذي أَكْرَمَ يا مَوالِيَّ مَقامَكُمْ وَشَرَّفَ مَنْزِلَتَكُمْ وَشَأنَكُمْ اَنْ يُكْرِمَني بِوِلايَتِكُمْ وَمَحَبَّتِكُمْ وَالاْئتِمامِ بِكُمْ وَبِالْبَراءَةِ مِنْ اَعْدائِكُمْ وَاَسْألُ اللهَ الْبَرَّ الرَّحيمَ اَنْ يَرْزُقَني مَوَدَّتَكُمْ، وَاَنْ يُوَفِّقَني لِلطَّلَبِ بِثارِكُمْ مَعَ الاِْمامِ الْمُنْتَظَرِ الْهادي مِنْ آلِ مُحَمَّد، وَاَنْ يَجْعَلَني مَعَكُمْ فِي الدُّنْيا وَالاْخِرَةِ، وَاَنْ يُبَلِّغَنِي الْمَقامَ الَْمحْمُودَ لَكُمْ عِنْدَ اللهِ وَاَسْألُ اللهَ عَزَّوَجَلَّ بِحَقِّكُمْ وَبِالشَّأْنِ الَّذي جَعَلَ اللهُ لَكُمْ اَنْ يُعْطِيَني بِمُصابي بِكُمْ اَفْضَلَ ما اَعْطى مُصاباً بِمُصيبَة، اِنّا للهِ وَاِنّا اِلَيْهِ راجِعُونَ، يا لَها مِنْ مُصيبَة ما اَفْجَعَها وَاَنْكاها لِقُلُوبِ الْمُؤْمِنينَ وَالْمُسْلِمينَ، فَاِنّا للهِ وَاِنّا اِلَيْهِ راجِعُونَ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاجْعَلْني فِي مَقامي مِمَّنْ تَنالُهُ مِنْكَ صَلَواتٌ وَرَحْمَةٌ وَمَغْفِرَةٌ وَاجْعَلْني عِنْدَكَ وَجيهاً فِي الدُّنْيا وَالاْخِرَةِ وَمِنَ الْمُقَرَّبينَ، فَاِنّي اَتَقَرَّبُ اِلَيْكَ بِمُحَمَّد وَآلِ مُحَمَّد صَلَواتُكَ عَلَيْهِ وَعَلَيْهِمْ اَجْمَعينَ، اَللّـهُمَّ وَاِنّي اَتَوَسَّلُ وَاَتَوَجَّهُ بِصَفْوَتِكَ مِنْ خَلْقِكَ وَخِيَرَتِكَ مِنْ خَلْقِكَ مُحَمَّد وَعَلِيٍّ وَالطَّيّبينَ مِنْ ذُرّيَّتِهِما، اَللّـهُمَّ فَصَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاجْعَلْ مَحْياىَ مَحْياهُمْ وَمَماتي مَماتَهُمْ وَلا تُفَرِّقْ بَيْني وَبَيْنَهُمْ فِي الدُّنْيا وَالاْخِرَةِ اِنَّكَ سَميعُ الدُّعاءِ، اَللّـهُمَّ وَهذا يَوْمٌ تُجَدَّدُ فيهِ النِّقْمَةُ وَتُنَزَّلَ فيهِ اللَّعْنَةُ عَلَى اللَّعينِ يَزيدَ وَعَلى آلِ يَزيدَ وَعَلى آلِ زِياد وَعُمَرَ بْنِ سَعْد وَالشِّمْرِ، اَللّـهُمَّ الْعَنْهُمْ وَالْعَنْ مَنْ رَضِيَ بِقَوْلِهِمْ وَفِعْلِهِمْ مِنْ اَوَّل وَآخِر لَعْناً كَثيراً وَاَصْلِهِمْ حَرَّ نارِكَ، وَاَسْكِنْهُمْ جَهَنَّمَ وَساءَتْ مَصيراً وَاَوْجِبْ عَلَيْهِمْ وَعَلى كُلِّ مَنْ شايَعَهُمْ وَبايَعَهُمْ وَتابَعَهُمْ وَساعَدَهُمْ وَرَضِيَ بِفِعْلِهِمْ وَافْتَحْ لَهُمْ وَعَلَيْهِمْ وَعَلى كُلِّ مَنْ رَضِيَ بِذلِكَ لَعَناتِكَ الَّتي لَعَنْتَ بِها كُلَّ ظالِم وَكُلَّ غاصِب وَكُلَّ جاحِد وَكُلَّ كافِر وَكُلَّ مُشْرِك وَكُلَّ شَيْطان رَجيم وَكُلَّ جَبّار عَنيد، اَللّـهُمَّ الْعَنْ يَزيدَ وَآلَ يَزيدَ وَبَني مَرْوانَ جَميعاً، اَللّـهُمَّ وَضَعِّفْ غَضَبَكَ وَسَخَطَكَ وَعَذابَكَ وَنَقِمَتَكَ عَلى اَوَّلِ ظالِم ظَلَمَ اَهْلَ بَيْتِ نَبِيِّكَ، اَللّـهُمَّ وَالْعَنْ جَميعَ الظّالِمينَ لَهُمْ وَانْتَقِمْ مِنْهُمْ اِنَّكَ ذوُ نِقْمَة مِنَ الُْمجْرِمينَ، اَللّـهُمَّ وَالْعَنْ اَوَّلَ ظالِم ظَلَمَ آلَ بَيْتِ مُحَمَّد، وَالْعَنْ اَرْواحَهُمْ وَدِيارَهُمْ وَقُبُورَهُمْ، وَالْعَنِ اللّهُمَّ الْعِصابَةَ الَّتي نازَلَتِ الْحُسَيْنِ بْنِ بِنْتَ نَبِيِّكَ وَحارَبَتْهُ وَقَتَلَتْ اَصْحابَهُ وَاَنْصارَهُ وَاَعْوانَهُ وَاَوْلِيائَهُ وَشيعَتَهُ وَمُحِبّيهِ وَاَهْلَ بَيْتِهِ وَذُرِّيَتَهُ، وَالْعَنِ اَللّـهُمَّ الَّذينَ نَهَبُوا مالَهُ وَسَلَبُوا حَريمَهُ وَلَمْ يَسْمَعُوا كَلامَهُ وَلا مَقالَهُ، اللّهُمَّ وَالْعَنْ كُلَّ مَنْ بَلَغَهُ ذلِكَ فَرَضِيَ بِهِ مِنَ الاَْوَّلينَ وَالاْخِرينَ وَالْخَلائِقِ اَجْمَعينَ اِلى يَوْمِ الدّينِ، اَلسَّلامُ عَلَيْكَ يا اَبا عَبْدِاللهِ الْحُسَيْنَ وَعَلى مَنْ ساعَدَكَ وَعاوَنَكَ وَواساكَ بِنَفْسِهِ وَبَذَلَ مُهْجَتَهُ فِي الذَّبِّ عَنْكَ، السَّلامُ عَلَيْكَ يا مَوْلايَ وَعَلَيْهِمْ وَعَلى رُوحِكَ وَعَلى اَرْواحِهِمْ وَعَلى تُرْبَتِكَ وَعَلى تُرْبَتِهِمْ، اَللّـهُمَّ لَقِّهِمْ رَحْمَةً وَرِضْواناً وَروُحاً وَرَيْحانا، السَّلامُ عَلَيْكَ يا مَوْلايَ يا اَبا عَبْدِاللهِ يَا بْنَ خاتَمِ النَّبِيّينَ وَيَا بْنَ سَيِّدِ الْوَصِيّينَ، وَيَا بْنَ سَيِّدَةِ نِساءِ الْعالَمينَ، السَّلامُ عَلَيْكَ يا شَهيدُ يَا بْنَ الشَّهيدِ، اَللّـهُمَّ بَلّغْهُ عَنّي فِي هذِهِ السّاعَةِ وَفِي هذَا الْيَوْمِ وَفِي هذَا الْوَقْتِ وَكُلِّ وَقْت تَحِيَّةً وَسَلاماً، السَّلامُ عَلَيْكَ يَا بْنَ سَيِّدِ الْعالَمينَ وَعَلَى الْمُسْتَشْهَدينَ مَعَكَ سَلاماً مُتَّصِلاً مَا اتَّصَلَ اللَّيْلُ وَالنَّهارُ، السَّلامُ عَلَى الْحُسَيْنِ بْنِ عَلِىِّ الشَّهيدِ، السَّلامُ على عليِّ بنِ الحُسَينِ الشَهيد، السَّلامُ على العباسِ بنِ أميرِ المؤمِنينَ الشَهيدِ، السَّلامُ عَلَى الشُّهَداءِ مِنْ وُلْدِ اَميرِ الْمُؤْمِنينَ، السَّلامُ عَلَى الشُّهَداءِ مِنْ وُلْدِ جَعْفَر وَعَقيل، السَّلامُ عَلى كُلِّ مُسْتَشْهَد مِنَ الْمُؤْمِنينَ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَبَلِّغْهُمْ عَنّي تَحِيَّةً وَسَلاماً، السَّلامُ عَلَيْكَ يا رَسُولَ اللهِ وَعَلَيْكَ السَّلامُ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَحْسَنَ اللهُ لَكَ الْعَزاءَ فِي وَلَدِكَ الْحُسَيْنِ عليه السلام السَّلامُ عَلَيْكَ يا اَبَا الْحَسَنِ يا اَميرَ الْمُؤْمِنينَ وَعَلَيْكَ السَّلامُ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَحْسَنَ اللهُ لَكَ الْعَزاءَ فِي وَلَدِكَ الْحُسَيْنِ السَّلامُ عَلَيْكِ يا فاطِمَةُ يا بِنْتَ رَسُولِ رَبِّ الْعالَمينَ وَعَلَيْكِ السَّلامُ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَحْسَنَ اللهُ لَكِ الْعَزاءَ فِي وَلَدِكِ الْحُسَيْنِ، السَّلامُ عَلَيْكَ يا اَبا مُحَمَّد الْحَسَنَ وَعَلَيْكَ السَّلامُ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَحْسَنَ اللهُ لَكَ الْعَزاءَ فِي اَخيكَ الْحُسَيْنِ، السَّلامُ عَلى اَرْواحِ الْمُؤْمِنينَ وَالْمُؤْمِناتِ الاَْحْياءِ مِنْهُمْ وَالاَْمْواتِ وَعليهم السلام وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَحْسَنَ اللهُ لَهُمُ الْعَزاءَ فِي مَوْلاهُمُ الْحُسَيْنِ، اللّهُمَّ اجْعَلْنا مِنَ الطّالِبينَ بِثارِهِ مَعَ اِمام عَدْل تُعِزُّ بِهِ الاِْسْلامَ وَاَهْلَهُ يا رَبَّ الْعالَمينَ."}],"preview":"وهي تناظر الزّيارة المشهُورة المتداولة في الاجر والثّواب خلوّاً من عناء اللّعن والسّلام مائة مرّة، وهي فوز عظيم لمن يشغله عن تلك الزّيارة شاغل هام، وكيفيّتها على ما في كتاب المزار","hasTranslate":false},{"id":"mf_ar_228","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّالِثُ :","title":"ثمّ اسجد وقل :","blocks":[{"type":"Text","content":"اَللّـهُمَّ لَكَ الْحَمْدُ عَلى جَميعِ ما نابَ مِنْ خَطْب، وَلَكَ الْحَمْدُ عَلى كُلِّ اَمْر، وَإلَيْكَ الْمُشْتَكى فِي عَظيمِ الْمُهِمّاتِ بِخِيَرَتِكَ وَاَوْلِيائِكَ وَذلِكَ لِما اَوْجَبْتَ لَهُمْ مِنَ الْكَرامَةِ وَالْفَضْلِ الْكَثيرِ، اَللّـهُمَّ فَصَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَارْزُقْني شَفاعَةَ الْحُسَيْنِ عليه السلام يَوْمَ الْوُرُودِ وَالْمَقامِ الْمَشْهُودِ وَالْحَوْضِ الْمَوْرُودِ، وَاجْعَلْ لي قَدَمَ صِدْق عِنْدَكَ مَعَ الْحُسَيْنِ وَاَصْحابِ الْحُسَيْنِ عليه السلام الَّذينَ واسَوْهُ بِاَنْفُسِهِمْ وَبَذَلُو دُونَهُ مُهَجَهُمْ وَجاهَدوُا مَعَهُ اَعْداءَكَ ابْتِغاءَ مَرْضاتِكَ وَرَجاءَكَ وَتَصْديقاً بِوَعْدِكَ وَخَوْفاً مِنْ وَعيدِكَ اِنَّكَ لَطيفٌ لِما تَشاءُ يا اَرْحَمَ الرّاحِمينَ ."}],"preview":"اَللّـهُمَّ لَكَ الْحَمْدُ عَلى جَميعِ ما نابَ مِنْ خَطْب، وَلَكَ الْحَمْدُ عَلى كُلِّ اَمْر، وَإلَيْكَ الْمُشْتَكى فِي عَظيمِ الْمُهِمّاتِ بِخِيَرَتِكَ وَاَوْلِيائِكَ وَذلِكَ لِما","hasTranslate":false},{"id":"mf_ar_229","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّالِثُ :","title":"الثّامِنَةُ : زيارة الاربعين أي اليوم العشرين من صفر","blocks":[{"type":"Text","content":"روى الشّيخ في التّهذيب والمصباح عن الامام الحسن العسكري (عليه السلام)قال: علامات المؤمن خمس: صلاة احدى وخمسين أي الفرائض اليوميّة وهي سبع عشرة ركعة والنّوافل اليوميّة وهي أربع وثلاثون ركعة، وزيارة الاربعين، والتختّم باليمين وتعفير الجبين بالسّجود، والجهر بِبِسْمِ اللهِ الرَّحْمنِ الرَّحيمِ، وقد رويت زيارته في هذا اليوم على نحوين، أحدهما ما رواه الشّيخ في التّهذيب والمصباح عن صفوان الجمّال قال : قال لي مولاي الصّادق صلوات الله عليه في زيارة الاربعين: تزُور عند ارتفاع النّهار وتقول :"},{"type":"Text","content":"اَلسَّلامُ عَلى وَلِيِّ اللهِ وَحَبيبِهِ، اَلسَّلامُ عَلى خَليلِ اللهِ وَنَجيبِهِ، اَلسَّلامُ عَلى صَفِيِّ اللهِ وَابْنِ صَفِيِّهِ، اَلسَّلامُ عَلى الْحُسَيْنِ الْمَظْلُومِ الشَّهيدِ، اَلسَّلامُ على اَسيرِ الْكُرُباتِ وَقَتيلِ الْعَبَراتِ، اَللّـهُمَّ اِنّي اَشْهَدُ اَنَّهُ وَلِيُّكَ وَابْنُ وَلِيِّكَ وَصَفِيُّكَ وَابْنُ صَفِيِّكَ الْفائِزُ بِكَرامَتِكَ، اَكْرَمْتَهُ بِالشَّهادَةِ وَحَبَوْتَهُ بِالسَّعادَةِ، وَاَجْتَبَيْتَهُ بِطيبِ الْوِلادَةِ، وَجَعَلْتَهُ سَيِّداً مِنَ السادَةِ، وَقائِداً مِنَ الْقادَةِ، وَذائِداً مِنْ الْذادَةِ، وَاَعْطَيْتَهُ مَواريثَ الاَْنْبِياءِ، وَجَعَلْتَهُ حُجَّةً عَلى خَلْقِكَ مِنَ الاَْوْصِياءِ، فَاَعْذَرَ فىِ الدُّعاءِ وَمَنَحَ النُّصْحَ، وَبَذَلَ مُهْجَتَهُ فيكَ لِيَسْتَنْقِذَ عِبادَكَ مِنَ الْجَهالَةِ وَحَيْرَةِ الضَّلالَةِ، وَقَدْ تَوازَرَ عَلَيْهِ مَنْ غَرَّتْهُ الدُّنْيا، وَباعَ حَظَّهُ بِالاَْرْذَلِ الاَْدْنى، وَشَرى آخِرَتَهُ بِالَّثمَنِ الاَْوْكَسِ، وَتَغَطْرَسَ وَتَرَدّى فِي هَواهُ، وَاَسْخَطَكَ وَاَسْخَطَ نَبِيَّكَ، وَاَطاعَ مِنْ عِبادِكَ اَهْلَ الشِّقاقِ وَالنِّفاقِ وَحَمَلَةَ الاَْوْزارِ الْمُسْتَوْجِبينَ النّارَ، فَجاهَدَهُمْ فيكَ صابِراً مُحْتَسِباً حَتّى سُفِكَ فِي طاعَتِكَ دَمُهُ وَاسْتُبيحَ حَريمُهُ، اَللّـهُمَّ فَالْعَنْهُمْ لَعْناً وَبيلاً وَعَذِّبْهُمْ عَذاباً اَليماً، اَلسَّلامُ عَلَيْكَ يَا بْنَ رَسُولِ اللهِ، اَلسَّلامُ عَلَيْكَ يَا بْنَ سَيِّدِ الاَْوْصِياءِ، اَشْهَدُ اَنَّكَ اَمينُ اللهِ وَابْنُ اَمينِهِ، عِشْتَ سَعيداً وَمَضَيْتَ حَميداً وَمُتَّ فَقيداً مَظْلُوماً شَهيداً، وَاَشْهَدُ اَنَّ اللهَ مُنْجِزٌ ما وَعَدَكَ، وَمُهْلِكٌ مَنْ خَذَلَكَ، وَمُعَذِّبٌ مَنْ قَتَلَكَ، وَاَشْهَدُ اَنَّكَ وَفَيْتَ بِعَهْدِ اللهِ وَجاهَدْتَ فِي سَبيلِهِ حَتّى اَتياكَ الْيَقينُ، فَلَعَنَ اللهُ مَنْ قَتَلَكَ، وَلَعَنَ اللهُ مَنْ ظَلَمَكَ، وَلَعَنَ اللهُ اُمَّةً سَمِعَتْ بِذلِكَ فَرَضِيَتْ بِهِ، اَللّـهُمَّ اِنّي اُشْهِدُكَ اَنّي وَلِيٌّ لِمَنْ والاهُ وَعَدُوٌّ لِمَنْ عاداهُ بِاَبي اَنْتَ وَاُمّي يَا بْنَ رَسُولِ اللهِ، اَشْهَدُ اَنَّكَ كُنْتَ نُوراً فىِ الاَْصْلابِ الشّامِخَةِ وَالاَْرْحامِ الْمُطَهَّرَةِ، لَمْ تُنَجِّسْكَ الْجاهِلِيَّةُ بِاَنْجاسِها وَلَمْ تُلْبِسْكَ الْمُدْلَهِمّاتُ مِنْ ثِيابِها، وَاَشْهَدُ اَنَّكَ مِنْ دَعائِمِ الدّينِ وَاَرْكانِ الْمُسْلِمينَ وَمَعْقِلِ الْمُؤْمِنينَ، وَاَشْهَدُ اَنَّكَ الاِْمامُ الْبَرُّ التَّقِيُّ الرَّضِيُّ الزَّكِيُّ الْهادِي الْمَهْدِيُّ، وَاَشْهَدُ اَنَّ الاَْئِمَّةَ مِنْ وُلْدِكَ كَلِمَةُ التَّقْوى وَاَعْلامُ الْهُدى وَالْعُرْوَةُ الْوُثْقى، وَالْحُجَّةُ على اَهْلِ الدُّنْيا، وَاَشْهَدُ اَنّي بِكُمْ مُؤْمِنٌ وَبِاِيابِكُمْ، مُوقِنٌ بِشَرايِعِ ديني وَخَواتيمِ عَمَلي، وَقَلْبي لِقَلْبِكُمْ سِلْمٌ وَاَمْري لاَِمْرِكُمْ مُتَّبِعٌ وَنُصْرَتي لَكُمْ مُعَدَّةٌ حَتّى يَأذَنَ اللهُ لَكُمْ، فَمَعَكُمْ مَعَكُمْ لا مَعَ عَدُوِّكُمْ صَلَواتُ اللهِ عَلَيْكُمْ وَعلى اَرْواحِكُمْ وَاَجْسادِكُمْ وَشاهِدِكُمْ وَغائِبِكُمْ وَظاهِرِكُمْ وَباطِنِكُمْ آمينَ رَبَّ الْعالِمينَ ."},{"type":"Text","content":"ثمّ تصلّي ركعتين وتدعو بما أحببت وترجع ."},{"type":"Text","content":"الزّيارة الاُخرى هي ما يروى عن جابر"},{"type":"Text","content":"وهي انّه روي عن عطا قال : كُنت مع جابر بن عبد الله الانصاري يوم العشرين من صفر، فلمّا وصلنا الغاضريّة اغتسل في شريعتها ولبس قميصاً كان معه طاهراً ثمّ قال لي : أمعك شيء من الطّيب يا عطا ؟ قلت : سعد، فجعل منه على رأسه وساير جسده ثمّ مشى حافياً حتّى وقف عند رأس الحسين (عليه السلام) وكبّر ثلاثاً ثمّ خرّ مغشيّاً عليه، فلمّا أفاق سمعته يقول : اَلسَّلامُ عَلَيْكُمْ يا آلَ اللهِ .. الخبر، وهي بعينها ما ذكرناه من زيارة النّصف من رجب لم يفترق عنها في شيء سوى بضع كلمات ولعلّها من اختلاف النسخ كما احتمله الشّيخ (رحمه الله) ، فمن أرادها فليقرأ زيارة النّصف من رجب السّالفة."},{"type":"AboutText","content":"أقول : زيارة الحسين (عليه السلام) تزداد فضلاً في الاوقات الشّريفة واللّيالي والايّام المباركة ممّا لم يخصّ بالذّكر لا سيّما فيما انتسب اليه من تلك الاوقات كيوم المباهلة ويوم نزول سورة هَلْ أَتى ويوم ميلاده الشّريف وليالي الجمعة وغير ذلك من شريف الازمان، ويستفاد من بعض الرّوايات انّ الله تعالى ينظر الى الحسين (عليه السلام)في كلّ ليلة من ليالي الجُمعة بعين الكرامة فيبعث الى زيارته كلّ نبيّ أو وصيّ نبيّ . وروى ابن قولويه عن الصّادق (عليه السلام) : انّ من زار قبر الحسين في كلّ جمعة غفر الله له ولم يخرج من الدّنيا حسراً وكان في الجنة مع الحُسين (عليه السلام) . وفي حديث الاعمش انّه قال له بعض جيرانه : رأيت في المنام رقعاً تتساقط من السّماء فيها أمان لمن زار الحسين (عليه السلام) ليلة الجمعة، وسيأتي اشارة الى هذا في أعمال الكاظميّة عند ذكر قصّة الحاج عليّ البغدادي ."},{"type":"AboutText","content":"وروى انّ الصّادق (عليه السلام) سئل عن زيارة الحسين (عليه السلام) هل لها وقت أفضل من غيره ؟ قال : زوروه في كلّ زمان فانّ زيارته خير مقرّر، من أكثر منها كثر نصيبه من الخير ومن أقلّ منها قلّ نصيبه منه، واجتهدوا في زيارته في الاوقات الشّريفة ففيها يضاعف أجر الصّالحات وتنزل فيها الملائكة من السّماء لزيارته (عليه السلام) .. الخبر . ولم نعثر على زيارة خاصّة له (عليه السلام) تخصّ هذه الاوقات المذكورة ، نعم قد خرج من النّاحية المقدّسة في اليوم الثّالث من شعبان وهو يوم ميلاده (عليه السلام) دعاء ينبغي قراءته، وقد مضى في خلال أعمال شهر شعبان، واعلم ايضاً انّ لزيارته (عليه السلام) في غير كربلاء من البلاد البعيدة فضلاً كثيراً ايضاً ونحن نقتصر في ذلك على ذكر حديثين مرويين في الكافي والفقيه والتّهذيب ."},{"type":"Text","content":"الحديث الاوّل : روى ابن أبي عمير عن هشام عن الصّادق (عليه السلام) قال : اذا بعدت بأحدكم الشّقة ونأت به الدّار فليعل أعلى منزله فيصلّي ركعتين وليؤم بالسّلام الى قبورنا فانّ ذلك يصير الينا ."},{"type":"Text","content":"الحديث الثّاني : عن حنان بن سدير عن أبيه قال : قال لي الصّادق (عليه السلام) : يا سدير تزُور قبر الحسين (عليه السلام)في كلّ يوم؟ قلت : جعلت فداك لا ، قال : ما أجفاكم ، فتزوره في كلّ جمعة ؟ قلت : لا ، قال : فتزوره في كلّ شهر ؟ قلت : لا ، قال : فتزوره في كلّ سنة ؟ قلت : قد يكون ذلك ، قال : يا سدير ما اجفاكم بالحسين (عليه السلام)، أما علمتم انّ لله ألفين من الملائكة - وفي رواية التّهذيب والفقيه ألف ألف ملك - شعثاً غبراً يبكون ويزُورون لا يفترون، وما عليك يا سدير أن تزُور قبر الحسين (عليه السلام) في كلّ جمعة خمس مرّات وفي كلّ يوم مرّة؟ قلت : جعلت فداك انّ بيننا وبينه فراسخ كثيرة ، فقال : تصعد فوق سطحك ثمّ تلتفت يمنة ويسرة ثمّ ترفع رأسك الى السّماء ثمّ تتحوّل نحو قبر الحسين (عليه السلام) ثمّ تقول: اَلسَّلامُ عَلَيْكَ يا اَبا عَبْدِاللهِ السَّلامُ عَلَيكَ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ تُكتب لك زورة، والزّورة حجّة وعمرة ، قال سدير: فربّما فعلته في الشّهر اكثر من عشرين مرّة وقد مضى في أوّل الزّيارة المطلقة الاولى ما يناسب المقام ."},{"type":"Text","content":"تَذييلٌ في فضل تربة الحسين (عليه السلام) المقدّسة وآدابها :"},{"type":"AboutText","content":"اعلم انّ لنا روايات متظافرة تنطق بأنّ تربته (عليه السلام) شفاء من كلّ سقم وداء الاّ الموت وامان من كلّ بلاء، وهي تورث الامن من كلّ خوف، والاحاديث في هذا الباب متواترة وما برزت من تلك التّربة المقدّسة من المعجزات اكثر من أن تُذكر واني قد ذكرت في كتاب الفوائد الرّضويّة في تراجم العلماء الاماميّة عند ترجمة السّيد المحدّث المتبحّر نعمة الله الجزائري انّه كان ممّن جهد لتحصيل العلم جهداً وتحمّل في سبيله الشّدائد والصّعاب وكان في أبان طلبه العلم لا يسعه الاسراج فقراً فيستفيد للمطالعة ليلاً من ضوء القمر وقد أكثر من المطالعة في ضوء القمر ومن القراءة والكتابة حتّى ضعف بصره فكان يكتحل بتربة الحسين (عليه السلام)المقدّسة وبتراب المراقد الشّريفة للائمة في العراق (عليهم السلام) فيقوي بصره ببركتها، وانّي قد حذرت هُناك ايضاً أهالي عصرنا أن يعجبوا لهذه الحكاية اثر معاشرتهم الكفّار والملاحدة ، فقد قال الدّميري في حياة الحيوان : انّ الافعى اذا عاش مائة سنة عميت عينه فيلهمه الله تعالى أن يمسحها بالرازيانج الرّطب لكي يعُود اليها بصرها فيقبل من الصّحراء نحو البساتين ومنابت الرّازيانج وان طالب المسافة حتّى يهتدي الى ذلك النّبات فيمسح بها عينه فيرجع اليها بصرها، ويروي ذلك عن الزّمخشري وغيره أيضاً، فاذا كان الله تعالى قد جعل مثل هذه الفائدة في نبات رطب وتهتدي اليه حيّة عمياء فتأخذ نصيبها منه فأيّ استبعاد واستعجاب في أن يجعل في تربة ابن نبيّه صلوات الله عليه الاذي َّستشهد هو وعترته في سبيله شفاء من كلّ داء وغير ذلك من الفوائد والبركات لينتفع بها الشّيعة والاحباب، ونحن في المقام نقنع بذكر عدّة روايات ."},{"type":"Text","content":"الاُولى : روي انّ الحور العين اذا بصرن بواحد من الاملاك يهبط الى الارض لامر ما يستهدين منه السّبح والتّربة من طين قبر الحسين (عليه السلام(."},{"type":"Text","content":"الثّانية : روي بسند معتبر عن رجل قال : بعث اليّ الرّضا (عليه السلام) من خراسان رزم ثياب وكان بين ذلك طين فقلت للرّسول : ما هذا؟ قال : هذا طين قبر الحسين (عليه السلام) ما كاد يوجه شيئاً من الثّياب ولا غيره الاّ ويجعل فيه الطّين، فكان يقول: هو أمان باذن الله ."},{"type":"Text","content":"الثّالثة : عن عبد الله بن أبي يعفور قال : قلت للصّادق (عليه السلام) : يأخذ الانسان من طين قبر الحسين (عليه السلام)فينتفع به ويأخذ غيره فلا ينتفع به ؟ فقال : لا والله ما يأخذه أحد وهو يرى انّ الله ينفعه به الاّ نفعه الله به ."},{"type":"Text","content":"الرّابعة : عن أبي حمزة الثّمالي قال : قلت للصّادق (عليه السلام): انّي رأيت أصحابنا يأخذون من طين الحسين (عليه السلام)يستشفُون به هل في ذلك شيء ممّا يقولون من الشّفاء ؟ قال : يستشفي بما بينه وبين القبر على رأس أربعة أميال وكذا طين قبر جدّي رسول الله (صلى الله عليه وآله وسلم) وكذا طين قبر الحسن وعليّ ومحمّد، فخُذ منها فانّها شفاء من كلّ سقم وجنّة ممّا تخاف ولا يعدلها شيء من الاشياء الّتي يستشفي بها الاّ الدّعاء وانّما يفسدها ما يخالطها من أوعيتها وقلّة اليقين ممّن يعالج بها، فامّا مَن أيقن انّها له شفاء اذا يعالج بها كفته باذن الله تعالى من غيرها ممّا يتعالج به، ويفسدها الشّياطين والجنّ من أهل الكفر منهم يتمسّحون بها وما تمرّ بشيء الاّ شمّها، وامّا الشّياطين وكفّار الجنّ فانّهم يحسدون ابن آدم عليها فيمسحون بها فيذهب عامّة طيبها ولا يخرج الطّين من الحائر الاّ وقد استعدّ له ما لا يحصى منهم، والله انّها لفي يدي صاحبها وهم يتمسّحون بها ولا يقدرُون مع الملائكة أن يدخلوا الحائر ولو كان من التّربة شيء يسلم ما عولج به أحد الاّ اُبريء من ساعته، فاذا أخذتها فاكتمها واكثر عليها ذكر الله عزّوجل، وقد بلغني انّ بعض من يأخذ من التّربة شيئاً يستخفّ به حتّى انّ بعضهم ليطرحها في مخلاة الابل والبغل والحمار أو في وعاء الطّعام وما يمسح به الايدي من الطّعام والخرج والجوالق، فكيف يستشفي به من هذا حالها عنده، ولكن القلب الَّذي ليس فيه اليقين من المستخفّ بما فيه صلاحه يفسد عمله ."},{"type":"Text","content":"الخامسة : روي انّه اذا تناول التّربة أحدكم فليأخذ باطراف أصابعه وقدره مثل الحمّصة فليقبلها وليضعها على عينيه وليمرها على سائر جسده وليقُل : اَللّـهُمَّ بِحَقِّ هـذِهِ التُّرْبَةِ وَبِحَقِّ مَنْ حَلَّ بِها وَثَوى فيها وَبِحِقِّ جَدِّهِ وَاَبيهِ وَاُمِّهِ وَاَخيهِ وَالاَْئِمَّةِ مِنْ وُلْدِهِ وَبِحَقِّ الْمَلائِكَةِ الْحافّينَ بِهِ اِلاّ جَعَلْتَها شِفاءً مِنْ كُلِّ داء، وَبُرْءاً مِنْ كُلِّ مَرَض، وَنَجاةً مِنْ كُلِّ آفَة، وَحِرْزاً مِمّا اَخافُ وَاَحْذَرُ، ثمّ ليستعملها ."},{"type":"Text","content":"وروي انّ الختم على طين قبر الحسين (عليه السلام) أن يقرأ على سورة (اِنّا اَنْزَلْناهُ فِي لَيْلَةِ الْقَدْرِ)."},{"type":"Text","content":"وروي ايضاً انّك تقول اذا طعمت شيئاً من التّربة أو أطعمته أحداً : بِسْمِ اللهِ وَبِاللهِ، اَللّـهُمَّ اجْعَلْهُ رِزْقاً واسِعاً وَعِلْماً نافِعاً وَشِفاءً مِنْ كُلِّ داء اِنَّكَ عَلى كُلِّ شَىْء قَديرٌ ."},{"type":"AboutText","content":"أقول : لتربته الشّريفة فوائد جمّة : منها استحباب جعلها مع الميّت في اللّحد واستحباب كتابة الاكفان بها واستحباب السّجود عليها ، فقد روي انّ السّجود عليها يخرق الحجب السّبعة أي يورث قبول الصّلاة عند ارتقائها السّماوات، واستحباب ان يصنع منها السّبحة فتستعمل للذّكر أو تترك في اليد من دون ذكر فلذلك فضل عظيم، ومن ذلك الفضل ان السّبحة تسبّح في يد صاحبها من غير أن يسبّح، ومن المعلوم انّ هذا التّسبيح بمعنى خاص غير التّسبيح الَّذي يسبّحه كلّ شيء كما قال الله تعالى :(وَاِنْ مِنْ شَىْء اِلاّ يُسَبِّحُ بِحَمْدِهِ وَلكِنْ لا تَفْقَهُونَ تَسْبيحَهُمْ)وقال العارف الرّومي في معنى الاية :"},{"type":"AboutText","content":"ومعنى الأبيات الفارسية هنا: لو انكشف للإنسان بصر الغيب لسمع تسبيح الذرات والماء والطين وسائر الكائنات، فكل شيء يسبح بحمد الله وإن كان كثير من الناس لا يدركون ذلك."},{"type":"Text","content":"ما سميعيم وبصير وباهُشيم با شما نامحرمان ما خامشيم"},{"type":"Text","content":"از جمادى سوى جان جان شويد غلغل اجزاى عالم بشنويد"},{"type":"Text","content":"فاش تسبيح جمادات آيدت وسوسه تاوليها بزد آيدت"},{"type":"Text","content":"وبالاجمال فالتّسبيح الوارد في هذه الرّواية هو تسبيح خاصّ بتربة سيّد الشّهداء أرواحنا له الفداء ."},{"type":"Text","content":"السّادسة : عن الرّضا (عليه السلام) من أدار السّبحة من تربة الحسين (عليه السلام) فقال: سُبْحانَ اللهِ وَالْحَمْدُ للهِ وَلا اِلـهَ اِلاَّ اللهُ وَاللهُ اَكْبَرُ، مع كلّ حبّة منها كتب الله لهُ بها ستّة آلاف حسنة، ومحا عنه ستّة آلاف سيّئة، ورفع له ستّة آلاف درجة، واثبت له من الشّفاعة مثلها، وعن الصّادق (عليه السلام): انّ من أدار الحصيات الّتي تعمل من تربة الحسين (عليه السلام) أي السّبحة من الخزف فاستغفر بها مرّة واحدة كتب له سبعون مرّة وان أمسك سبحة في يده ولم يسبّح كتب له بكلّ حبّة سبعاً ."},{"type":"Text","content":"السّابعة : في الحديث المعتبر انّ الصّادق صلوات الله عليه لما قدم العراق أتاه قوم فسألوه: عرفنا انّ تربة الحسين (عليه السلام) شفاء من كلّ داء فهل هي أمان ايضاً من كلّ خوف ؟ قال : بلى من أراد أن تكون التّربة أماناً له من كلّ خوف فليأخذ السّبحة منها بيده ويقول ثلاثاً :"},{"type":"Text","content":"اَصْبَحْتُ اللّـهُمَّ مُعْتَصِماً بِذِمامِكَ وَجِوارِكَ الْمَنيعِ الَّذي لا يُطاوَلُ وَلا يُحاوَلُ، مِنْ شَرِّ كُلِّ غاشِم وَطارِق مِنْ سائِرِ مَنْ خَلَقْتَ وَما خَلَقْتَ مِنْ خَلْقِكَ الصّامِتِ وَالنّاطِقِ فِي جُنَّة مِنْ كُلِّ مَخُوف بِلِباس سابِغَة حَصينَة وَهِيَ وَلاءُ اَهْلِ بَيْتِ نَبِيِّكَ مُحَمَّد صَلَّى اللهُ عَلَيْهِ وَآلِهِ مُحْتَجِزاً مِنْ كُلِّ قاصِد لي اِلى اَذِيَّة بِجَدار حَصين الاِْخْلاصِ فِي الاِْعْتِرافِ بِحَقِّهِمْ وَالَّتمَسُّكِ بِحَبْلِهِمْ جَميعاً، مُوقِناً اَنَّ الْحَقَّ لَهُمْ وَمَعَهُمْ وَمِنْهُمْ وَفيهِمْ وَبِهِمْ اُوالي مَنْ والَوا وَاُعادي مَنْ عادَوا وَاُجانِبُ مَنْ جانَبُوا، فَصَلِّ عَلى مُحَمَّد وَآلِهِ وَاَعِذْنِي اللّـهُمَّ بِهِمْ مِنْ شَرِّ كُلِّ مَا اَتَّقيهِ، يا عَظيمُ حَجَزْتُ الاَْعادِىَ عَنّي بِبَديعِ السَّماواتِ وَالاَْرْضِ، اِنّا جَعَلْنا مِنْ بَيْنِ اَيْديهِمْ سَدّاً وَمِنْ خَلْفِهِمْ سَدّاً فَاَغْشَيْناهُمْ فَهُمْ لا يُبْصِرُونَ . ثم يقبل السبحة ويمسح بها عينه ويقول: الَّلهُمَّ انِّي أسأَلُكَ بِحَقِّ هذِهِ التُربَةِ المُبارَكَةِ، وَبِحَقِّ صاحِبِها وبِحَقِّ جَدِّهِ وَبِحَقِّ أبيهِ وبِحَقِّ أُمِّهِ وبِحَقِّ أخيهِ وَبِحَقِّ وُلدِهِ الطاهِرينَ، اجْعَلْها شِفاءً مِنْ كُلِّ داء، وأماناً مِنْ كُلِّ خَوف، وَحِفظاً مِنْ كُلِّ سُوء."},{"type":"Text","content":"ثمّ يجعلها على جبينه، فان عمل ذلك صباحاً كان في أمان الله تعالى حتّى يمسي وان عمله مساءً كان في أمان الله تعالى حتّى يصبح ."},{"type":"Text","content":"وروي في حديث آخر انّ من خاف من سلطان أو غيره فليصنع مثل ذلك حين يخرج من منزله ليكُون ذلك حرزاً له ."},{"type":"AboutText","content":"أقول : لا يجوز مطلقاً على المشهور بين العلماء أكل شيء من التّراب أو الطّين الاّ تربة الحسين (عليه السلام)المقدّسة استشفاء من دُون قصد الالتذاذ بها بقدر الحمّصة، والاحوط أن لا يزيد قدرها على العدسة، ويحسن أن يضع التّربة في فمه ثمّ يشرب جُرعة من الماء ويقول : اَللّـهُمَّ اجْعَلْهُ رِزْقاً واسِعاً وَعِلْماً نافِعاً وَشِفاءً مِنْ كُلِّ داء وَسُقْم ."},{"type":"AboutText","content":"قال العلامة المجلسي : الاحوط ترك التّبايع على السّبحة من التّربة أو ما يصنع منها للسّجدة بل تهدى اهداءً ولعلّه ممّا لا بأس به أن يتراضى عليها المتعاملان تراضياً من دون اشتراط سابق، ففي الحديث المعتبر عن الصّادق (عليه السلام) قال : من باع تراب قبر الحسين (عليه السلام) فكأنّما تبايع على لحمه (عليه السلام) ."},{"type":"AboutText","content":"أقول : حكى شيخنا المحدّث المتبحّر ثقة الاسلام النّوري (رحمه الله) في كتاب دار السّلام قال : دخل بعض اخواني على والدتي رحمها الله فرأت في جيبه الَّذي في أسفل قبائه (بالفارسيّة) تربة مولانا أبي عبد الله (عليه السلام) فزجرته وقالت : هذا من سوء الادب ولعلّها تقع تحت فخذك فتنكسر ، فقال : نعم انكسرت منها الى الان اثنان وعهد أن لا يضعها بعد ذلك فيه ولما مضى بعض الايّام رأى والد العلاّمة رفع الله مقامه في المنام ولم يكن له اطّلاع بذلك انّ مولانا أبا عبد الله (عليه السلام)دخل عليه زائراً وقعد في بيت كتبه الَّذي كان يقعد فيه غالباً فلاطفه كثيراً وقال : ادعُ بنيك يأتوا اليّ لاكرمهم فدعاهم وكانوا خمسة معي، فوقفوا قدامه (عليه السلام) عند الباب وكان بين يديه اشياء من الثّوب وغيره، فكان يدعو واحداً بعد واحد ويعطيه شيئاً منه فلمّا وصلت النّوبة الى الاخ المزبور سلّمه الله نظر الله شبه المغضب والتفت الى الوالد (قدس سره) وقال : ابنك هذا قد كسر تربتين من تراب قبري تحت فخذه ثمّ طرح اليه شيئاً ولم يدعه اليه، وببالي انّ ما أعطاه كان بيت المشط الَّذي يعمل من الثّوب الَّذي يقال له بالفارسيّة (تِرْمه) فانتبه وقصّ ما رآه على الوالدة رحمها الله، فأخبرته بما وقع فتعجّب من صدقه ، انتهى ."}],"preview":"روى الشّيخ في التّهذيب والمصباح عن الامام الحسن العسكري (عليه السلام)قال: علامات المؤمن خمس: صلاة احدى وخمسين أي الفرائض اليوميّة وهي سبع عشرة ركعة والنّوافل اليوميّة وهي أربع وثلا","hasTranslate":false},{"id":"mf_ar_230","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّالِثُ :","title":"في فضل زيارة الكاظمين","blocks":[{"type":"Text","content":"أي الامام موسى الكاظم والامام محمّد التّقي (عليهما السلام) وكيفيّة زيارتهما وفي ذكر مسجد براثا"}],"preview":"أي الامام موسى الكاظم والامام محمّد التّقي (عليهما السلام) وكيفيّة زيارتهما وفي ذكر مسجد براثا","hasTranslate":false},{"id":"mf_ar_231","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّالِثُ :","title":"وزيارة سلمان (رضي الله عنه)","blocks":[{"type":"Text","content":"ويحتوي على عدّة مطالب ."}],"preview":"ويحتوي على عدّة مطالب .","hasTranslate":false},{"id":"mf_ar_232","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّالِثُ :","title":"في فضل زيارة الكاظمين (عليهما السلام) وكيفيّتها :","blocks":[{"type":"AboutText","content":"اعلم انّه قد ورد لزيارة هـذين الامامين المعصومين فضل كثير وفي اخبار كثيرة انّ زيارة الامام مُوسى بن جعفر (عليهما السلام) هي كزيارة النّبي (صلى الله عليه وآله وسلم) ."},{"type":"AboutText","content":"وفي رواية : من زاره كان كما لو زار رسول الله (صلى الله عليه وآله وسلم) وامير المؤمنين ."}],"preview":"اعلم انّه قد ورد لزيارة هـذين الامامين المعصومين فضل كثير وفي اخبار كثيرة انّ زيارة الامام مُوسى بن جعفر (عليهما السلام) هي كزيارة النّبي (صلى الله عليه وآله وسلم) .","hasTranslate":false},{"id":"mf_ar_233","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّالِثُ :","title":"وفي حديث آخر : انّ زيارته مثل زيارة الحسين (عليه السلام)","blocks":[{"type":"Text","content":"وفي حديث آخر : من زاره كان له الجنّة ."},{"type":"AboutText","content":"وروى الشّيخ الجليل محمّد بن شهر آشوب في المناقب عن تاريخ بغداد للخطيب، باسناده عن عليّ بن خلال ، قال : ما اهمّني أمر فقصدت موسى بن جعفر (عليهما السلام) وتوسّلت به الاّ سهّل الله لي، وقال ايضاً : ورؤي في بغداد امرأة تهرول ، فقيل لها: الى أين ؟ قالت : الى موسى بن جعفر (عليه السلام) فانّه حُبس ابني ، فقال لها حنبلي مُستهزئاً: انّه قد مات في الحبس ، فقالت : بحقّ المقتول في الحبس أن تريني قدرتك، فاذا بابنها قد اطلق واخذ ابن المستهزيء بجنايته ."},{"type":"AboutText","content":"وروى الصّدوق عن ابراهيم بن عقبة قال : كتبت الى الامام عليّ النّقي (عليه السلام)عن زيارة الحسين (عليه السلام)وزيارة الامام مُوسى بن جعفر والامام محمّد التّقي (عليهما السلام) أي اسأله عن أيّهما أفضل . فكتب اليّ: أبو عبد الله (عليه السلام) المقدّم وزيارتهما اجمع واعظم أجراً ."},{"type":"Text","content":"وامّا في كيفيّة زيارتهما (عليهما السلام) فاعلم انّ الزّيارات الواردة في ذلك الحرم الشّريف بعضها مشترك بين هذين الامامين (عليهما السلام) وبعضها يخصّ احدهما ، امّا ما يخصّ الامام مُوسى (عليه السلام) فهي على ما رواه السّيد ابن طاوُس في المزار كما يلي : اذا أردت زيارته (عليه السلام) فينبغي أن تغتسل ثمّ تأتي المشهد المقدّس وعليك السّكينة والوقار ، فاذا أتيته فقِف على بابه وقُل :"},{"type":"Text","content":"اَللهُ اَكْبَرُ اَللهُ اَكْبَرُ لا اِلـهَ اِلاَّ اللهُ وَاللهُ اَكْبَرُ اَلْحَمْدُ للهِ عَلى هِدايَتِهِ لِدِينِهِ وَالتَّوْفيقِ لِما دَعا اِلَيْهِ مِنْ سَبيلِهِ، اَللّـهُمَّ اِنَّكَ اَكْرَمُ مَقْصُود، وَاَكْرَمُ مَأتِيٍّ وَقَدْ اَتَيْتُكَ مُتَقَرِّباً اِلَيْكَ بِابْنِ بِنْتِ نَبِيِّكَ صَلَواتُكَ عَلَيْهِ وَعَلى آبائِهِ الطّاهِرينَ وَاَبْنائِهِ الطَّيِّبينَ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَلا تُخَيِّبْ سَعْيي وَلا تَقْطَعْ رَجائي وَاجْعَلْني عِنْدَكَ وَجيهاً في الدُّنْيا وَالاْخِرَةِ وَمِنَ الْمُقَرَّبينَ ."}],"preview":"وفي حديث آخر : من زاره كان له الجنّة .","hasTranslate":false},{"id":"mf_ar_234","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّالِثُ :","title":"ثمّ ادخل وقدّم رجلك اليُمنى وقُل :","blocks":[{"type":"Text","content":"بِسْمِ اللهِ وَبِاللهِ وَفي سَبيلِ اللهِ وَعَلى مِلَّةِ رَسُولِ اللهِ صَلَّى اللهُ عَلَيْهِ وَآلِهِ، اَللّـهُمَّ اغْفِرْ لي وَلِوالِدَيَّ وَلِجَميعِ الْمُؤْمِنينَ وَالْمُؤْمِناتِ ."},{"type":"Text","content":"فاذا وصلت باب القُبّة فقِف عليه واستأذن ، تقول :"},{"type":"Text","content":"أاَدْخُلُ يا رَسُولَ اللهِ، أَاَدْخُلُ يا نَبِيَّ اللهِ، أَاَدْخُلُ يا مُحَمَّدَ بْنَ عَبْدِاللهِ، أَاَدْخُلُ يا اَميرَ الْمُؤْمِنينَ، أَاَدْخُلُ يا اَبا مُحَمَّد الْحَسَنَ، أَاَدْخُلُ يا اَبا عَبْدِ اللهِ الْحُسَيْنَ، أَاَدْخُلُ يا اَبا مُحَمَّد عَلِيَّ بْنَ الْحُسَيْنِ، أَاَدْخُلُ يا اَبا جَعْفَر مُحَمَّدَ بْنَ عَلِيٍّ، أَاَدْخُلُ يا اَبا عَبْدِ اللهِ جَعْفَرَ بْنَ مُحَمَّد، أَاَدْخُلُ يا مَوْلايَ يا اَبَا الْحَسَنِ مُوسَى بْنَ جَعْفَر، أَاَدْخُلُ يا مَوْلايَ يا اَبا جَعْفَر أَاَدْخُلُ يا مَوْلايَ مُحَمَّدَ بْنَ عَلِيٍّ ."},{"type":"Text","content":"وادخل وقُل أربعاً : اَللهُ اَكْبَرُ، ثمّ قِف مستقبل القبر واجعل القِبلة بين كتفيك وقُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا ولِيَّ اللهِ وَابْنَ وَلِيِّهِ، اَلسَّلامُ عَلَيْكَ يا حُجَّةَ اللهِ وَابْنَ حُجَّتِهِ، اَلسَّلامُ عَلَيْكَ يا صَفِيَّ اللهِ وَابْنَ صَفِيِّهِ، اَلسَّلامُ عَلَيْكَ يا اَمينَ اللهِ وَابْنَ اَمينِهِ، اَلسَّلامُ عَلَيْكَ يا نُورَ اللهِ في ظُلُماتِ الاَْرْضِ، اَلسَّلامُ عَلَيْكَ يا اِمامَ الْهُدى، اَلسَّلامُ عَلَيْكَ يا عَلَمَ الدّينِ وَالتُّقى، اَلسَّلامُ عَلَيْكَ يا خازِنَ عِلْمِ النَّبِيّينَ، اَلسَّلامُ عَلَيْكَ يا خازِنَ عِلْمِ الْمُرْسَلينَ، اَلسَّلامُ عَلَيْكَ يا نائِبَ الاَْوْصِياءِ السّابِقينَ، اَلسَّلامُ عَلَيْكَ يا مَعْدِنَ الْوَحْيِ الْمُبينِ، اَلسَّلامُ عَلَيْكَ يا صاحِبَ الْعِلْمِ الْيَقينِ، اَلسَّلامُ عَلَيْكَ يا عَيْبَةَ عِلْمِ الْمُرْسَلينَ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الاِْمامُ الصّالِحُ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الاِْمامُ الزّاهِدُ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الاِْمامُ الْعابِدُ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الاِْمامُ السَّيِّدُ الرَّشيدُ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الْمَقْتُولُ الشَّهيدُ، اَلسَّلامُ عَلَيْكَ يَا بْنَ رَسُولِ اللهِ وَابْنَ وَصِيِّهِ، اَلسَّلامُ عَلَيْكَ يا مَوْلايَ مُوسَى بْنَ جَعْفَر وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَشْهَدُ اَنَّكَ قَدْ بَلَّغْتَ عَنِ اللهِ ما حَمَّلَكَ وَحَفِظْتَ مَا اسْتَوْدَعَكَ، وَحَلَّلْتَ حَلالَ اللهِ وَحَرَّمْتَ حَرامَ اللهِ، وَاَقَمْتَ اَحْكامَ اللهِ، وَتَلَوْتَ كِتابَ اللهِ وَصَبَرْتَ عَلَى الاَْذى في جَنْبِ اللهِ، وَجاهَدْتَ في اللهِ حَقَّ جِهادِهِ حَتّى أتاكَ الْيَقينُ، وَاَشْهَدُ اَنَّكَ مَضَيْتَ عَلى ما مَضى عَلَيْهِ آباؤُكَ الطّاهِرُونَ وَاَجْدادُكَ الطَّيِّبُونَ الاَْوْصِياءُ الْهادُونَ الاَْئِمَّةُ الْمَهْدِيُّونَ، لَمْ تُؤْثِرْ عَمىً عَلى هُدىً، وَلَمْ تَمِلْ مِنْ حَقٍّ اِلى باطِل، وَاَشْهَدُ اَنَّكَ نَصَحْتَ للهِ وَلِرَسُولِهِ وَلاَِميرِ الْمُؤمِنينَ، وَاَنَّكَ اَدَّيْتَ الاَْمانَةَ، وَاجْتَنَبْتَ الْخِيانَةَ، وَاَقَمْتَ الصَّلاةَ، وَآتَيْتَ الزَّكاةَ، وَاَمَرْتَ بِالْمَعْرُوفِ، وَنَهَيْتَ عَنِ الْمُنْكَرِ، وَعَبَدْتَ اللهَ مُخْلِصاً مُجْتَهِداً مُحْتَسِباً حَتّى أتاكَ الْيَقينُ فَجَزاكَ اللهُ عَنِ الاِْسْلامِ وَاَهْلِهِ اَفْضَلَ الْجَزاءِ وَاَشْرَفَ الْجَزاءِ، اَتَيْتُكَ يَا بْنَ رَسُولِ اللهِ زائِراً، عارِفاً بِحَقِّكَ، مُقِرّاً بِفَضْلِكَ، مُحْتَمِلاً لِعِلْمِكَ، مُحْتَجِباً بِذِمَّتِكَ، عائِذاً بِقَبْرِكَ، لائِذاً بِضَريحِكَ، مُسْتَشْفِعاً بِكَ اِلَى اللهِ، مُوالِياً لاَِوْلِيائِكَ، مُعادِياً لاَِعْدائِكَ، مُسْتَبْصِراً بِشَأْنِكَ وَبِالْهُدَى الَّذي اَنْتَ عَلَيْهِ، عالِماً بِضَلالَةِ مَنْ خالَفَكَ وَبِالْعَمَى الَّذي هُمْ عَلَيْهِ، بِاَبي اَنْتَ وَاُمّي وَنَفْسي وَاَهْلي وَمالي وَوَلَدي يَا بْنَ رَسُولِ اللهِ، اَتَيْتُكَ مُتَقَرِّباً بِزِيارَتِكَ اِلَى اللهِ تَعالى، وَمُسْتَشْفِعاً بِكَ اِلَيْهِ فَاشْفَعْ لي عِنْدَ رِبِّكَ لِيَغْفِرَ لي ذُنُوبي، وَيَعْفُوَ عَنْ جُرْمي، وَيَتَجاوَزَ عَنْ سَيِّئاتي، وَيَمْحُوَ عَنّي خَطيئاتي وَيُدْخِلَنِي الْجَنَّةَ، وَيَتَفَضَّلَ عَلَيَّ بِما هُوَ اَهْلُهُ، وَيَغْفِرَ لي وَلاِبائي وَلاِِخْواني وَاَخَواتي وَلِجَميعِ الْمُؤْمِنينَ وَالْمُؤْمِناتِ في مَشارِقِ الاَْرْضِ وَمَغارِبِها بِفَضْلِهِ وَجُودِهِ وَمَنِّهِ."},{"type":"Text","content":"ثمّ تنكب على القبر وتقبّله وتعفّر خدّيك عليه وتدعو بما تريد ثمّ تتحوّل الى الرّأس وتقُول :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا مَوْلايَ يا مُوسَى بْنَ جَعْفَر وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَشْهَدُ اَنَّكَ الاِْمامُ الْهادِي وَالْوَلِيُّ الْمُرْشِدُ وَاَنَّكَ مَعْدِنُ التَّنْزيلِ وَصاحِبُ التَّأويلِ وَحامِلُ التَّوْراةِ وَالاِْنْجيلِ، وَالْعالِمُ الْعادِلُ وَالصّادِقُ الْعامِلُ، يا مَوْلايَ اَنَا اَبْرَأُ اِلَى اللهِ مِنْ اَعْدائِكَ وَاَتَقَرَّبُ اِلَى اللهِ بِمُوالاتِكَ، فَصَلَّى اللهُ عَلَيْكَ وَعَلى آبائِكَ وَاَجْدادِكَ وَاَبْنائِكَ وَشيعَتِكَ وَمُحِبّيكَ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ ."},{"type":"Text","content":"ثمّ تصلّي ركعتين للزّيارة تقرأ فيهما سورة يس والرّحمن أو ما تيسّر من القرآن ثمّ ادعُ بما تريد ."}],"preview":"بِسْمِ اللهِ وَبِاللهِ وَفي سَبيلِ اللهِ وَعَلى مِلَّةِ رَسُولِ اللهِ صَلَّى اللهُ عَلَيْهِ وَآلِهِ، اَللّـهُمَّ اغْفِرْ لي وَلِوالِدَيَّ وَلِجَميعِ الْمُؤْمِنينَ وَالْمُؤْمِناتِ .","hasTranslate":false},{"id":"mf_ar_235","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّالِثُ :","title":"زيارة اُخرى لمُوسى بن جعفر (عليهما السلام(","blocks":[{"type":"AboutText","content":"قال المفيد والشّهيد ومحمّد ابن المشهدي : اذا أردت زيارته ببغداد فاغتسل للزّيارة واقصد المشهد وقِف على الباب الشّريف واستأذن ثمّ ادخُل وأنت تقول :"},{"type":"Text","content":"بِسْمِ اللهِ وَبِاللهِ وَفي سَبيلِ اللهِ وَعَلى مِلَّةِ رَسُولِ اللهِ صَلَّى اللهُ عَلَيْهِ وَآلِهِ وَالسَّلامُ عَلى اَوْلِياءِ اللهِ، ثمّ امضِ حتّى تستقبل قبر موسى بن جعفر (عليهما السلام) فاذا وقفت عند قبره فقُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا نُورَ اللهِ في ظُلُماتِ الاَْرْضِ، اَلسَّلامُ عَلَيْكَ يا وَلِيَّ اللهِ، اَلسَّلامُ عَلَيْكَ يا حُجَّةَ اللهِ، اَلسَّلامُ عَلَيْكَ يا بابَ اللهِ، اَشْهَدُ اَنَّكَ اَقَمْتَ الصَّلاةَ، وَآتَيْتَ الزَّكاةَ، وَاَمَرْتَ بِالْمَعْرُوفِ وَنَهَيْتَ عَنِ الْمُنْكَرِ، وَتَلَوْتَ الْكِتابَ حَقَّ تِلاوَتِهِ، وَجاهَدْتَ في اللهِ حَقَّ جِهادِهِ، وَصَبَرْتَ عَلَى الاَْذى في جَنْبِهِ مُحْتَسِباً، وَعَبَدْتَهُ مُخْلِصاً حَتّى أتاكَ الْيَقينُ، اَشْهَدُ اَنَّكَ اَوْلى بِاللهِ وِبِرَسُولِهِ وَاَنَّكَ اِبْنُ رَسُولِ اللهِ حَقّاً اَبْرَأُ اِلَى اللهِ مِنْ اَعْدائِكَ، وَاَتَقَرَّبُ اِلَى اللهِ بِمُوالاتِكَ، اَتَيْتُكَ يا مَوْلايَ عارِفاً بِحَقِّكَ، مُوالِياً لاَِوْلِيائِكَ، مُعادِياً لاَِعْدائِكَ، فَاشْفَعْ لي عِنْدَ رَبِّكَ ."},{"type":"Text","content":"ثمّ انكبّ على القبر وقبّله وضَع خدّيك عليه وتحوّل الى عند الرّأس وقِف وقُل : اَلسَّلامُ عَلَيْكَ يا بْنَ رَسُولِ اللهِ، اَشْهَدُ اَنَّكَ صادِقٌ اَدَّيْتَ ناصِحاً وَقُلْتَ اَميناً وَمَضَيْتَ شَهيداً، لَمْ تُؤْثِرْ عَمىً عَلَى الْهُدى وَلَمْ تَمِلْ مِنْ حَقٍّ اِلى باطِل، صَلَّى اللهُ عَلَيْكَ وَعَلى آبائِكَ وَاَبْنائِكَ الطّاهِرينَ، ثمّ قبّل القبر وصلّ ركعتين وصلّ بعدهما ما أحببت واسجُد وقُل : اَللّـهُمَّ اِلَيْكَ اعْتَمَدْتُ وَاِلَيْكَ قَصَدْتُ وَبِفَضْلِكَ رَجَوْتُ، وَقَبْرَ اِمامِيَ الَّذي اَوْجَبْتَ عَلَيَّ طاعَتَهُ زُرْتُ، وَبِهِ اِلَيْكَ تَوَسَّلْتُ، فَبِحَقِّهِمُ الَّذي اَوْجَبْتَ عَلى نَفْسِكَ اغْفِرْ لي وَلِوالِدَيَّ وَلِلْمُؤْمِنينَ يا كَريمُ، ثمّ أقلب خدك الايمن وقل: الّلهمَّ قَدْ عَلِمتَ حَوائِجِي فَصَلِّ على مُحَمَّد وآلِ مُحَمَّد وَاقْضِها، ثُمَّ أقلب خدّك الايسر وقُل : اَللّـهُمَّ قَدْ اَحْصَيْتَ ذُنُوبي فَبِحَقِّ مُحَمَّد وَآلِ مُحَمَّد صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاغْفِرْها وَتَصَدَّقْ عَلَيَّ بِما اَنْتَ اَهْلُهُ، ثمّ عُد الى السّجود وقُل : شُكْراً شُكْراً مائة مرّة، ثمّ ارفع رأسك من السّجود وادعُ بما شئت لمن شئت وأحببت ."},{"type":"AboutText","content":"أقول : قد أورد الجليل السّيد عليّ بن طاوُس (رضي الله عنه) في كتاب مصباح الزّائر عند ذكر بعض زيارات الامام مُوسى بن جعفر (عليهما السلام) صلاة يصلّى بها عليه تحوي ذكر نبذ من فضائله ومناقبه وعباداته ومصائبه ينبغي للزّائر أن لا يفوته فضل الصّلاة بها عليه وهي :"},{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَاَهْلِ بَيْتِهِ، وَصَلِّ عَلى مُوسَى بْنِ جَعْفَر وَصِيِّ الاَْبْرارِ، وَاِمامِ الاَْخْيارِ، وَعَيْبَةِ الاَْنْوارِ، وَوارِثِ السَّكِينَةِ وَالْوَقارِ وَالْحِكَمِ وَالاْثارِ الَّذي كانَ يُحْيِي اللَّيْلَ بِالسَّهَرِ اِلَى السَّحَرِ بِمُواصَلَةِ الاْسْتِغْفارِ، حَليفِ السَّجْدَةِ الطَّويلَةِ، وَالدُّمُوعِ الْغَزيرَةِ، وَالْمُناجاةِ الْكَثيرَةِ، وَالضَّراعاتِ الْمُتَّصِلَةِ، وَمَقَرِّ النُّهى وَالْعَدْلِ وَالْخَيْرِ وَالْفَضْلِ وَالنَّدى وَالْبَذْلِ، وَمَألَفِ الْبَلْوى وَالصَّبْرِ، وَالْمُضْطَهَدِ بِالظُّلْمِ، وَالْمَقْبُورِ بِالْجَوْرِ، وَالْمُعَذَّبِ في قَعْرِ السُّجُونِ، وَظُلَمِ الْمَطاميرِ ذِي السّاقِ الْمَرْضُوضِ بِحَلَقِ الْقُيُودِ، وَالْجِنازَةِ الْمُنادى عَلَيْها بِذُلِّ الاِْسْتِخْفافِ، وَالْوارِدِ عَلى جَدِّهِ الْمُصْطَفى وَاَبيهِ الْمُرْتَضى وَاُمِّهِ سَيِّدَةِ النِّساءِ بِإرْث مَغْصُوب وَوَلاء مَسْلُوب وَاَمْر مَغْلُوب وَدَم مَطْلُوب وَسَمٍّ مَشْرُوب، اَللّـهُمَّ وَكَما صَبَرَ عَلى غَليظِ الِْمحَنِ وَتَجَرَّعَ غُصَصَ الْكُرَبِ، وَاسْتَسْلَمَ لِرِضاكَ وَاَخْلَصَ الطّاعَةَ لَكَ، وَمَحَضَ الْخُشُوعَ، وَاسْتَشْعَرَ الْخُضُوعَ، وَعادَى الْبِدْعَةَ وَاَهْلَها وَلَمْ يَلْحَقْهُ في شَيء مِنْ اَوامِرِكَ وَنَواهيكَ لَوْمَةُ لائِم، صَلِّ عَلَيْهِ صَلاةً نامِيَةً مُنْيفَةً زاكِيَةً تُوجِبُ لَهُ بِها شَفاعَةَ اُمَم مِنْ خَلْقِكَ، وَقُرُون مِنْ بَراياكَ، وَبَلِّغْهُ عَنّا تَحِيَّةً وَسَلاماً، وَآتِنا مِنْ لَدُنْكَ في مُوالاتِهِ فَضْلاً وَاِحْساناً وَمَغْفِرَةً وَرِضْواناً، اِنَّكَ ذُوا الْفَضْلِ الْعَميمِ، وَالتَّجاوُزِ الْعَظيمِ، بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ ."},{"type":"Text","content":"وأمّا الزّيارة الخاصّة بالامام محمّد التّقي (عليه السلام) فقد قال فيها الاجلاّء الثّلاثة ايضاً ثمّ توجّه نحو قبر أبي جعفر محمّد بن عليّ الجواد (عليهما السلام) وهو بظهر جدّه (عليه السلام) فاذا وقفت عليه فقُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا وَلِيَّ اللهِ، اَلسَّلامُ عَلَيْكَ يا حُجَّةَ اللهِ، اَلسَّلامُ عَلَيْكَ يا نُورَ اللهِ في ظُلُماتِ الاَْرْضِ، اَلسَّلامُ عَلَيْكَ يَا بْنَ رَسُولِ اللهِ، اَلسَّلامُ عَلَيْكَ وَعَلى آبائِكَ، اَلسَّلامُ عَلَيْكَ وَعَلى اَبْنائِكَ، اَلسَّلامُ عَلَيْكَ وَعَلى اَوْلِيائِكَ، اَشْهَدُ اَنَّكَ قَدْ اَقَمْتَ الصَّلاةَ، وَآتَيْتَ الزّكاةَ، وَاَمَرْتَ بِالْمَعْرُوفِ، وَنَهَيْتَ عَنِ الْمُنْكَرِ، وَتَلَوْتَ الْكِتابَ حَقَّ تِلاوَتِهِ، وَجاهَدْتَ في اللهِ حَقَّ جِهادِهِ، وَصَبَرْتَ عَلَى الاَْذى في جَنْبِهِ حَتّى أتاكَ الْيَقينُ، اَتَيْتُكَ زائِراً عارِفاً بِحَقِّكَ مُوالِياً لاَِوْلِيائِكَ مُعادِياً لاَِعْدائِكَ فَاشْفَعْ لي عِنْدَ رَبِّكَ ."},{"type":"Text","content":"ثمّ قبّل القبر وضَع خدّيك عليه، ثمّ صلّ ركعتين للزّيارة وصلّ بعدهما ما شئت ثمّ اسجد وقُل : اِرْحَمْ مَنْ اَساءَ وَاقْتَرَفَ وَاسْتَكانَ وَاعْتَرَفَ، ثمّ اقلب خدّك الايمن وقُل : اِنْ كُنْتُ بِئْسَ الْعَبْدُ فَاَنْتَ نِعْمَ الرَّبُّ ثمّ اقلب خدّك الايسر وقُل : عَظُمَ الذَّنْبُ مِنْ عَبْدِكَ فَلْيَحْسُنِ الْعَفْوُ مِنْ عِنْدِكَ يا كَريمُ، ثمّ عُد الى السّجود وقُل : شُكْراً شُكْراً مائة مرّة ثمّ انصرف ."}],"preview":"قال المفيد والشّهيد ومحمّد ابن المشهدي : اذا أردت زيارته ببغداد فاغتسل للزّيارة واقصد المشهد وقِف على الباب الشّريف واستأذن ثمّ ادخُل وأنت تقول :","hasTranslate":false},{"id":"mf_ar_236","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّالِثُ :","title":"زيارة اُخرى للامام محمّد بن عليّ التّقي (عليهما السلام)","blocks":[{"type":"AboutText","content":"قال السّيد ابن طاوُس في المزار: اذا زُرت الامام موسى الكاظم (عليه السلام) فقِف على قبر الجواد (عليه السلام) وقبّله وقُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا اَبا جَعْفَر مُحَمَّدَ بْنَ عَلِيٍّ الْبَرَّ التَّقِيَّ الاِْمامَ الْوَفِيَّ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الرَّضِيُّ الزَّكِيُّ، اَلسَّلامُ عَلَيْكَ يا وَلِيَّ اللهِ، اَلسَّلامُ عَلَيْكَ يا نَجِيَّ اللهِ، اَلسَّلامُ عَلَيْكَ يا سَفيرَ اللهِ، اَلسَّلامُ عَلَيْكَ يا سِرَّ اللهِ، اَلسَّلامُ عَلَيْكَ يا ضِياءَ اللهِ، اَلسَّلامُ عَلَيْكَ يا سَناءَ اللهِ، اَلسَّلامُ عَلَيْكَ يا كَلِمَةَ اللهِ، اَلسَّلامُ عَلَيْكَ يا رَحْمَةَ اللهِ، اَلسَّلامُ عَلَيْكَ اَيُّهَا النُّوُرُ السّاطِعُ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الْبَدْرُ الطّالِعُ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الطَّيِّبُ مِنَ الطَّيِّبينَ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الطّاهِرُ مِنَ الْمُطَهَّرينَ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الاْيَةُ الْعُظْمى، اَلسَّلامُ عَلَيْكَ اَيُّهَا الْحُجَّةُ الْكُبْرى، اَلسَّلامُ عَلَيْكَ اَيُّهَا الْمُطَهَّرُ مِنَ الزَّلاَّتِ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الْمُنَزَّهُ عَنِ الْمُعْضِلاتِ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الْعَلِىُّ عَنْ نَقْصِ الاَْوْصافِ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الرَّضِيُّ عِنْدَ الاَْشْرافِ، اَلسَّلامُ عَلَيْكَ يا عَمُودَ الدّينَ، اَشْهَدُ اَنَّكَ وَلِيَّ اللهِ وَحُجَّتُهُ في اَرْضِهِ وَأنَّكَ جَنْبُ اللهِ وَخيَرَةُ اللهِ وَمُسْتَوْدَعُ عِلْمِ اللهِ وَعِلْمِ الاَْنْبِياءِ، وَرُكْنُ الاْيمانِ وَتَرْجُمانُ الْقُرْآنِ، وَاَشْهَدُ اَنَّ مَنِ اتَّبَعَكَ عَلَى الْحَقِّ وَالْهُدى، وَاَنَّ مَنْ اَنْكَرَكَ وَنَصَبَ لَكَ الْعَداوَةَ عَلَى الضَّلالَةِ وَالرَّدى اَبْرَءُ اِلَى اللهِ وَاِلَيْكَ مِنْهُمْ في الدُّنْيا وَالاْخِرَةِ، وَاَلسَّلامُ عَلَيْكَ ما بَقيتُ وَبَقِيَ اللَّيْلُ وَالنَّهارُ."}],"preview":"قال السّيد ابن طاوُس في المزار: اذا زُرت الامام موسى الكاظم (عليه السلام) فقِف على قبر الجواد (عليه السلام) وقبّله وقُل :","hasTranslate":false},{"id":"mf_ar_237","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّالِثُ :","title":"وقل في الصّلاة عليه :","blocks":[{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَاَهْلِ بَيْتِهِ، وَصَلِّ عَلى مُحَمَّد بْنِ عَلِيِّ الزَّكِيِّ التَّقِيِّ وَالْبَرِّ الْوَفِيِّ وَالْمُهَذَّبِ التَّقِيِّ هادِى الاُْمَّةِ، وَوارِثِ الاَْئِمَّةِ، وَخازِنِ الرَّحْمَةِ، وَيَنْبُوعِ الْحِكْمَةِ، وَقائِدِ الْبَرَكَةِ، وَعَديلِ الْقُرْآنِ في الطّاعَةِ، وَواحِدِ الاَْوْصِياءِ في الاِْخْلاصِ وَالْعِبادَةِ، وَحُجَّتِكَ الْعُلْيا وَمَثَلِكَ الاَْعْلى، وَكَلِمَتِكَ الْحُسْنى الدّاعي اِلَيْكَ، وَالدّالِّ عَلَيْكَ، الَّذي نَصَبْتَهُ عَلَماً لِعِبادِكَ، وَمُتَرْجِماً لِكِتابِكَ، وَصادِعاً بِاَمْرِكَ، وَناصِراً لِدينِكَ، وَحُجَّةً عَلى خَلْقِكَ، وَنُوراً تَخْرُقُ بِهِ الظُّلَمَ، وَقُدْوَةً تُدْرَكُ بِهَا الْهِدايَةُ، وَشَفيعاً تُنالُ بِهِ الْجَنَّةُ، اَللّـهُمَّ وَكَما اَخَذَ في خُشُوعِهِ لَكَ حَظَّهُ، وَاسْتَوْفى مِنْ خَشْيَتِكَ نَصيبَهُ، فَصَلِّ عَلَيْهِ اَضْعافَ ما صَلَّيْتَ عَلى وَلِيٍّ ارْتَضَيْتَ طاعَتَهُ، وَقَبِلْتَ خِدْمَتَهُ، وَبَلِّغْهُ مِنّا تَحِيَّةً وَسَلاماً، وَآتِنا في مُوالاتِهِ مِنْ لَدُنْكَ فَضْلاً وَاِحْساناً وَمَغْفِرَةً وَرِضْواناً، اِنَّكَ ذُو الْمَنِّ الْقَديمِ وَالصَّفْحِ الْجَميلِ."},{"type":"Text","content":"ثمّ صلّ صلاة الزّيارة وقُل بعد السّلام : اَللّـهُمَّ اَنْتَ الرَّبُّ وَاَنَا الْمَرْبُوبُ .. الدعاء ."}],"preview":"اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَاَهْلِ بَيْتِهِ، وَصَلِّ عَلى مُحَمَّد بْنِ عَلِيِّ الزَّكِيِّ التَّقِيِّ وَالْبَرِّ الْوَفِيِّ وَالْمُهَذَّبِ التَّقِيِّ هادِى الاُْمَّةِ، وَوارِ","hasTranslate":false},{"id":"mf_ar_238","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"الْمَطْلَبُ الثّالِثُ :","title":"زيارة اُخرى مختصّة به (عليه السلام)","blocks":[{"type":"Text","content":"روى الصّدوق في الفقيه ، قال : اذا أردت زيارته فاغتسل وتنظف والبس ثوبين طاهرين وقُل في زيارته :"},{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلى مُحَمَّدِ بْنِ عَلِيِّ الاِْمامِ التَّقِيِّ النَّقِيِّ الرِّضِيِّ الْمَرْضِيِّ وَحُجَّتِكَ عَلى مَنْ فَوْقَ الاَْرْضِ وَمَنْ تَحْتَ الثَّرى، صَلاةً كَثيرَةً نامِيَةً زاكِيَةً مُبارَكَةً مُتَواصِلَةً مُتَرادِفَةً مُتَواتِرَةً، كَاَفْضَلِ ما صَلَّيْتَ عَلى اَحَد مِنْ اَوْلِيائِكَ، وَاَلسَّلامُ عَلَيْكَ يا وَلِيَّ اللهِ، اَلسَّلامُ عَلَيْكَ يا نُورَ اللهِ، اَلسَّلامُ عَلَيْكَ يا حُجَّةَ اللهِ، اَلسَّلامُ عَلَيْكَ يا اِمامَ الْمُؤْمِنينَ وَوارِثَ عِلْمِ النَّبِيّينَ وَسُلالَةَ الْوَصِيّينَ، اَلسَّلامُ عَلَيْكَ يا نُورَ اللهِ في ظُلُماتِ الاَْرْضِ، اَتَيْتُكَ زائِراً عارِفاً بِحَقِّكَ مُعادِياً لاَِعْدائِكَ مُوالِياً لاَِوْلِيائِكَ فَاشْفَعْ لي عِنْدَ رَبِّكَ ."},{"type":"Text","content":"ثمّ سل حاجتك ثمّ صلّ في القُبّة الّتي فيها قبر مُحمّد بن عليّ (عليهما السلام) عند رأسه اربع ركعات ، ركعتين لزيارة موسى الكاظم (عليه السلام) وركعتين لزيارة محمّد التّقي (عليهما السلام) ولا تصلّ عند رأس موسى الكاظم فانّه يقابل قبُور قريش ولا يجوز اتّخاذها قبلة ."},{"type":"AboutText","content":"أقول : يبدو من كلام الشّيخ الصّدوق انّ قبر الامام الكاظم (عليه السلام) كان مفرزاً عن قبر الامام الجواد (عليه السلام)،فكان ينفرد بقُبّة مستقلّة وباب خاصّ فالزّائر يخرج منها ليدخل تحت قُبّة الجواد (عليه السلام) الّتي كانت ذات بناء خاص وأمّا الزّيارات المشتركة بين هذين الامامين الهمامين فهي ايضاً نوعان :"},{"type":"Text","content":"الاوّل : ما يُزار به كلّ واحد منهُما (عليهما السلام) منفرداً ."},{"type":"Text","content":"روى الشّيخ الجليل جعفر بن محمّد بن قولويه القمّي في كتاب كامل الزّيارة عن الامام عليّ النّقي (عليه السلام) قال : قُل في زيارة كلّ من الامامين :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا وَلِيَّ اللهِ، اَلسَّلامُ عَلَيْكَ يا حُجَّةَ اللهِ، اَلسَّلامُ عَلَيْكَ يا نُورَ اللهِ في ظُلُماتِ الاَْرْضِ، اَلسَّلامُ عَلَيْكَ يا مَنْ بَدا للهِ في شَأنِهِ اَتَيْتُكَ زائِراً عارِفاً بِحَقِّكَ مُعادِياً لاَِعْدائِكَ مُوالِياً لاَِوْلِيائِكَ فَاشْفَعْ لي عِنْدَ رَبِّكَ يا مَوْلايَ ."},{"type":"Text","content":"وهذه الزّيارة معتبرة غاية الاعتبار وقد رواها ايضاً الصّدوق والكليني والطّوسي مع اختلاف يسير ."},{"type":"Text","content":"الثّاني : ما يُزار به كلا الامامين (عليهما السلام) معاً وهي كما يلي :"},{"type":"AboutText","content":"قال المفيد والشّهيد ومحمّد ابن المشهدي: تقول في زيارتهما(عليهما السلام) اذا وقفت عند الضّريح الطّاهر :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكُما يا وَلِيَّيِ اللهِ، اَلسَّلامُ عَلَيْكُما يا حُجَّتَيِ اللهِ، اَلسَّلامُ عَلَيْكُما يا نُورَيِ اللهِ في ظُلُماتِ الاَْرْضِ، اَشْهَدُ اَنَّكُما قَدْ بَلَّغْتُما عَنِ اللهِ ما حَمَّلَكُما، وَحَفِظْتُما مَا اسْتَودَعْتُما، وَحَلَّلْتُما حَلالَ اللهِ وَحَرَّمْتُما حَرامَ اللهِ، وَاَقَمْتُما حُدُودَ اللهِ، وَتَلَوْتُما كِتابَ اللهِ، وَصَبَرْتُما عَلَى الاَْذى في جَنْبِ اللهِ مُحْتَسبَيْنَ حَتّى اَتاكُمَا الْيَقينُ، اَبْرَأُ اِلَى اللهِ مِنْ اَعْدائِكُما، وَاَتَقَرَّبُ اِلَى اللهِ بِوِلايَتِكُما، اَتَيْتُكُما زائِراً عارِفاً بِحَقِّكُما، مُوالِياً لاَِوْلِيائِكُما، مُعادِياً لاَِعْدائِكُما مُسْتَبْصِراً بِالْهُدَى الَّذي اَنْتُما عَلَيْهِ، عارِفاً بِضَلالَةِ مَنْ خالَفَكُما، فَاشْفَعا لي عِنْدَ رَبِّكُما فَاِنَّ لَكُما عِنْدَ اللهِ جاهاً عَظيماً وَمَقاماً مَحْمُوداً."},{"type":"Text","content":"ثمّ قبّل التّربة الشّريفة وضع خدّك الايمن عليها ثمّ تحوّل الى جانب الرّأس المقدّس فقُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكُما يا حُجَّتَيِ اللهِ في اَرْضِهِ وَسَمائِهِ، عَبْدُكُما وَوَلِيُّكُما زائِرُكُما مُتَقَرِّباً اِلَى اللهِ بِزِيارَتِكُما، اَللّـهُمَّ اجْعَلْ لي لِسانَ صِدْق في اَوْلِيائِكَ الْمُصْطَفَيْنَ، وَحَبِّبْ اِلَيَّ مَشاهِدَهُمْ وَاجْعَلْني مَعَهُمْ في الدُّنْيا وَالاْخِرَةِ يا اَرْحَمَ الرّاحِمينَ، ثمّ صلّ ركعتين لزيارة كلّ امام وادعُ بما أحببت ."},{"type":"AboutText","content":"أقول : كان عصر صُدور هذه الزّيارات عصر التقيّة الشّديدة ولاجل ذلك كان المعصومون (عليهم السلام) يعلّمون الشّيعة زيارات قصيرة صيانة لهم عن طاغية الزّمان، فالزّائر إن طلب زيارة طويلة فليقرأ الزّيارات الجامعة الاتية وهي خير ما يُزاران بها ولا سيّما الزّيارة الاُولى منها حيث يظهر من روايتها انّ لها مزيد اختصاص بالامام الكاظم (عليه السلام)، واذا شاء الزّائر أن يخرج من بلدهما(عليهما السلام) فليودّعهما(عليهما السلام) بدعوات الوداع، ومن تلك الدّعوات ما رواه الطّوسي(رحمه الله)في التّهذيب قال : اذا أردت أن تودع الامام مُوسى (عليه السلام) فقِف عند القبر وقُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا مَوْلايَ يا اَبَا الْحَسَنِ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَسْتَوْدِعُكَ اللهَ وَاَقْرَأُ، عَلَيْكَ السَّلامَ آمَنّا بِاللهِ وَبِالرَّسُولِ وَبِما جِئْتَ بِهِ وَدَلَلْتَ عَلَيْهِ، اَللّـهُمَّ اَكْتُبْنا مَعَ الشّاهِدينَ. وتقول أيضاً في وداع الامام محمد التقي(عليه السلام): السَّلامُ عَلَيكَ يا مَولايَ يا ابْنَ رَسُولِ الله ورَحمَةُ اللهِ وَبَركاتُهُ أسْتَوْدِعُكَ اللهَ وأقْرأُ عَلَيْكَ السَّلامَ آمَنّا باللهِ وبِرَسُولِهِ وبِما جِئْتَ بِهِ وَلَلْتَ عَلَيْهِ، الَّلهُمَّ اُكْتُبْنا مَعَ الشّاهِدِينَ."},{"type":"Text","content":"وتقول ايضاً في وداع الامام محمّد التّقي (عليه السلام):"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا مَوْلايَ يا بْنَ رَسُولِ اللهِ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ اَسْتَوْدِعُكَ اللهَ وَاَقْرَءُ عَلَيْكَ السَّلامُ آمَنّا بِاللهِ وَبِالرَّسُولِ وَبِما جَئْتَ بِهِ وَدَلَلْتَ عَلَيْهِ اَللّـهُمَّ اَكْتُبْنا مَعَ الشّاهِدينَ ."},{"type":"Text","content":"ثمّ سل الله تعالى أن لا تكون هذه آخر عهدك من زيارتهم وأن توفّق للعود، وقبل القبر وضَع خدّيك عليه ."},{"type":"AboutText","content":"أقول : ممّا يناسب المقام قصّة السّعيد الصّالح الصّفيّ المتّقي الحاج عليّ البغدادي الّتي أوردها شيخنا في جنّة المأوى والنّجم الثّاقب، وقال في كتاب النّجم الثّاقب: انّه لو لم يكن في هذا الكتاب سوى هذه القصّة المتقنة الصّحيحة الحاوية على فوائد جمّة الحادثة في عصرنا لكفاه شرفاً ونفساً، ثمّ قال بعدما مهّده من المقدّمات : حكى الحاج علي أيّده ا لله قائلاً: تراكم في ذمّتي من سهم الامام (عليه السلام) من الخمس مبلغ ثمانين توماناً، فرحلت الى النّجف الاشرف ودفعت منها الى علم الهُدى والتّقي حضرة الشّيخ مرتضى أعلى الله مقامه عشرين توماناً، والى حضرة الشّيخ محمّد حسين المجتهد الكاظمي عشرين توماناً، والى حضرة الشّيخ محمّد الشّروقي عشرين توماناً، ولم يبق عليّ سوى عشرين توماناً كنت أروم أن اقدّمها اذا قفلت من النّجف الى الشّيخ محمّد حسن آل يس الكاظمي أيّده الله، ووددت لمّا وافيت بغداد أن أُبادر الى أداء ما استمرّ عليّ من السّهم، فتوجّهت الى الكاظميّة وكان اليوم يوم الخميس فزرت الامامين الهمامين الكاظمين (عليهما السلام)ثمّ وافيت حضرة الشّيخ سلّمه الله فنقدته شطراً من العشرين توماناً وأوعدته بانّ أؤدّي الباقي اذا بعت بعض البضائع بأن أبذله الى مستحقّه حسب ما يحيله عليّ بالتّدريج، ثمّ أزمعت على مغادرة الكاظميّة ورفضت ما الحّ فيه حضرة الشّيخ من البقاء معتذراً بأن عليّ أن أوفيّ عمّال معمل النّسيج أجورهم حسب ما قررت عليه من بذل أجر عمل الاسبوع في يوم الخميس عصراً، فأخذت أسلك طريقي الى بغداد، فلمّا قاربت ثلث الطّريق اذاً أنا بسيّد جليل من السّادة يعرّج عليّ في طريقه الى الكاظميّة فدنى منّي وسلّم عليّ وبسط يده للمصافحة والمعانقة ورحّب بي قائلاً: أهلاً وسهلاً وضمّني الى صدره وتلاثمنا، وكان قد تعمّم بعمامة خضراء زاهرة وفي وجهه الشّريف شامة كبيرة سوداء فتوقّف وقال: خير أيّها الحاج علي أين المقصد؟ فأجبته : قد زُرت الكاظمين (عليهما السلام)وأنا الان ماض الى بغداد ، فقال لي : عُد الى الكاظمين (عليه السلام)فهذه ليلة الجمعة ، قلت : لا يسعني العود ، فأجاب : ذلك في وسعك عُد كي اشهد لك بانّك من الموالين لجدّي امير المؤمنين (عليه السلام) ولنا ويشهد لك الشّيخ ، فقد قال تعالى : واستشهدوا شهيدين، وكان هذا تلميحاً الى ما كنت أتوخاه من التماس الشّيخ أن يمنحني رقعة أجعلها في كفني يشهد لي فيها بانّي من الموالين لاهل البيت (عليهم السلام)، فسألته من أين عرفتني وكيف تشهد لي . فأجاب : وكيف لا يعرف المرء من وافاه حقّه ، قلت : وأيّ حقّ هذا الّذي تعنيه ؟ فأجاب : ما بذلته لوكيلي ، قلت : ومن هو ، قال : الشّيخ محمّد حسن ، فقلت : أهو وكيلك ؟ أجاب : هو وكيلي وكذلك السّيد محمّد ، قال الحاج علي: ما كنت أعرف صاحبي هذا ولكنّه كان قد دعاني باسمي فاحتملت أن تكون بيننا معرفة سابقة وقلت أيضاً في نفسي: انّه يطالبني بشيء من الخمس ووددت أن أبذل له من سهم الامام (عليه السلام) فقُلت : يا أيّها السّيد انّه قد بقي في ذمّتي من حقّكم شيء (أي حقّ السّادة) وقد راجعت في ذلك حضرة الشّيخ محمّد حسن كي أؤدّيه اليكم باذنه، فتبسّم في وجهي قائلاً : نعم قد أبلغت شطراً من حقّنا الى وكلائنا في النّجف الاشرف ، فقلت : هل قُبل ما أدّيته ؟ قال : نعم ، ثمّ انتبهت الى انّ صاحبي هذا يعبّر عن اعاظم العلماء بكلمة وكلائي فاستكبرت ذلك ثمّ قلت في نفسي : العلماء وكلاء السّادة في قبض حقوقهم ثمّ اعترضتني الغفلة ، انتهى ."},{"type":"Text","content":"ثمّ قال لي : عُد الى زيارة جدّي فطاوعته وعُدت معه وكنت قابضاً على يده اليمنى بيدي اليسرى ، فلمّا استأنفنا المسير وجدت نهراً الى جانبنا الايمن يجري بماء زلال ووجدت اشجار اللّيمون والرّارنج والعنب والرّمان وغيرها تظلّنا من فوق رؤوسنا وكلّها مثمرة معاً في غير مواسمها، فسألته عن النّهر والاشجار ، فقال: انّها تصاحب كلّ مُوال من موالينا اذا زار جدّنا وزارنا، فقلت له : مسألة أريد سؤالها، قال : سل، قلت : انّ الشّيخ عبد الرّزاق (رحمه الله) كان ممّن يزاول التّدريس وقد وافيته يوماً فسمعته يقول : من دأب في حياته على صيام النّهار وقيام اللّيل وحجّ اربعين حجّة واعتمر أربعين عُمرة ثمّ وافته المنون وهو بين الصّفا والمروة ولم يكن هو من الموالين لامير المؤمنين (عليه السلام) ما كان له شيء من الاجر. فأجاب : نعم والله ما كان له شيء. ثمّ سألته عن بعض أقربائي هل هو من الموالين لامير المؤمنين (عليه السلام) ، فأجاب : نعم هو ومن يتّصل بك ، ثمّ قلت : سيّدنا مسألة، قال:سل ، قلت له : يقول خطباء مأتم الحسين (عليه السلام) انّ سليمان الاعمش أتى رجلاً يسأله عن زيارة سيّد الشّهداء (عليه السلام) فأجابه الرّجل انّها بدعة ثمّ رأى في المنام هودجاً بين السّماء والارض فسأل عن الهودج فأجيب بأنّ فيه فاطمة الزّهراء وخديجة الكبرى (عليهما السلام) فسأل أين تذهبان، فأجيب الى زيارة الحسين (عليه السلام) في هذه اللّيلة وهي ليلة الجمعة، وشاهد رقعاً تتساقط الى الارض من ذلك الهودج كتب فيها اَمانٌ مِنَ النّارِ لِزُوّارِ الْحُسَيْنِ عليه السلام في لَيْلَةِ الْجُمُعَةِ، اَمانٌ مِنِ النّارِ يَوْمَ الْقِيامَةِ، فهل صحيح هذا الحديث ؟ قال : نعم تامّ صحيح . قلت : سيّدنا أصحيح ما يُقال من انّ من زار الحسين (عليه السلام) ليلة الجمعة كان آمناً ؟ قال : نعم ، ودمعت عيناه وبكى ، قلت : سيّدنا مسألة ، قال : سل ، قلت : قد زُرنا الرّضا (عليه السلام) سنة ألف ومائتين وتسع وستّين فصادفنا في بلدة درود أحد الشّرُوقيّين (وهم قوم من العرب يسكنون البادية الشّرقيّة للنّجف الاشرف) فاضفناه وسألناه عن ولاية الرّضا(عليه السلام)، فقال: هي الجنّة، وقال : هذا هو الخامس عشر من ايّام اقتات فيها بطعام الرّضا(عليه السلام) فكيف يجرأ منكر ونكير أن يدنوا منّي في قبري انّه قد نبت لحمي وعظمي من طعام الرّضا(عليه السلام)في دار ضيافته، فهل صحيح انّ الرّضا(عليه السلام) يوافيه في قبره وينجيه من منكر ونكير؟ فأجاب : نعم والله انّ جدّي الضّامن ، قلت : سيّدنا مسألة قصيرة شئت أسألها ، قال : سل ، قلت : زيارتي للرّضا (عليه السلام) هل هي مقبُولة؟ أجاب : مقبولة ان شاء الله ، قلت : سيّدنا مسألة ، قال : سل بسم الله ، قلت : وهل قُبلت زيارة الحاج محمّد حسين البزّاز (بزّاز باشى) ابن المرحوم الحاج احمد البّزاز (بزّاز باشى) وقد رافقته في طريقي الى مشهد الرّضا (عليه السلام) فكنّا شريكين في النّفقة ؟ قال : زيارة العبد الصّالح مقبولة ، قلت : سيّدنا مسألة ، قال : سل بسم الله ، قلت : وهل قُبلت زيارة فلان من أهالي بغداد وكان معنا في طريقنا الى خراسان، فسكت ولم يجب ، قلت : سيّدنا مسألة ، قال : سل بسم الله ، قلت : هل سمعت مسألتي السّابقة؟ هل قُبلت زيارة الرّجل؟ فلم يجبني ، قال: الحاج عليّ انّ الرّجل كان هو واخلاّؤه في الطّريق من أهالي بغداد المترفين وكانوا في رحلتهم هذه يدأبون في اللّعب واللّهو وكان هو قاتل امّه ."},{"type":"Text","content":"ثمّ بلغنا متّسعاً من الطّريق يواجه مدينة الكاظمين (عليه السلام) محاطاً بالبساتين من الجانبين وكان شطر من هذه الجادة يقع على يمين القادم من بغداد ملكاً لبعض الايتام من السّادة وقد اغتصبته الحكومة فجعله جزءاً من الطّريق العام، فكان الورع التّقي من أهالي بغداد والكاظميّة يحذر المسير في هذا الشّطر من الجادة، فرأيت صاحبي هذا لا يأبى الجري عليه ، فقلت له : سيّدي هذا الموضع ملك لبعض الايتام من السّادة ولا ينبغي التّصرّف فيه ، فأجاب: هو لجدّي امير المؤمنين (عليه السلام) وذرّيّته وأولادنا ويحلّ التّصرف فيه لموالينا، وكان على الجانب الايمن قُرب هذا الموضِع بستان لرجل يدعى الحاج ميرزا هادي وكان ثرياً من أثرياء العجم المشهورين وكان يسكن بغداد ، فقلت : سيّدنا هل صحيح ما يقال انّ هذا البستان أرضه للامام موسى بن جعفر (عليهما السلام)؟ قال : ما شأنك وهذا، وأعرض عن الجواب ، ثمّ بلغنا ساقية مدّت من نهر دجلة لريّ المزارع والبساتين وهي تقاطع الجادة فتنشعب هُناك المسلك الى المدينة شعبتين هما الشّارع السّلطاني وشارع السّادة، فتوجّه صاحبي الى شارع السّادة فدعوته الى الشّارع السّلطاني فرفض وقال: لنسر في شارعنا هذا، فما خطونا خطوات الاّ ووجدنا أنفسنا في الصّحن المقدّس عند منزع الاحذية (الكيشوانيّة) من دون أن نمرّ بسوق أو زقاق، فدخلنا الايوان من جانب باب المراد شرقاً ممّا يلي الرّجل فلم يمكث صاحبي للاستئذان لدخول الرّواق الطّاهر وورد من دون الاستئذان، ثمّ وقف على باب الحرم الشّريف فخاطبني وقال : زُر ، قلت : انّي لا أعرف القراءة ، قال : فأقرأ لك الزّيارة ؟ قلت : نعم ، فقال : أَاَدْخُلُ يا اَللهُ، اَلسَّلامُ عَلَيْكَ يا رَسُولَ اللهِ، السَّلامُ عَلَيْكَ يا اَميرَ الْمُؤْمِنينَ، (وسلّم على الائمة واحداً فواحداً حتّى بلغ الامام العسكري (عليه السلام) فقال:( اَلسَّلامُ عَلَيْكَ يا اَبا مُحَمَّد الْحَسَنَ الْعَسْكَرِيَّ، ثمّ خاطبني قائلاً : أتعرف امام عصرك ؟ أجبت : وكيف لا أعرفه ، قال : فسلّم عليه، فقلت: اَلسَّلامُ عَلَيْكَ يا حُجَّةَ اللهِ يا صاحِبَ الزَّمانِ يا بْنَ الْحَسَنِ، فتبسّم وقال : عَلَيْكَ السَّلامُ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، فدخلنا الحرم الطّاهر وانكببنا على الضّريح المقدّس وقبّلناه ثمّ قال لي : زُر ، قلت : لا أعرف القراءة ، قال : فأقرأ لك الزّيارة؟ قلت: نعم ، قال : في أي الزّيارات ترغب؟ قلت : اقرأ عليَّ ما هو أفضل الزّيارات ، فقال : زيارة امين الله هي الفضلى، ثمّ أخذ يزُور بها قائلاً: اَلسَّلامُ عَلَيْكُما يا اَمينَيِ اللهِ في اَرْضِهِ وَحُجَّتَيْهِ عَلى عِبادِهِ .. الخ واُجّجت حينئذ مصابيح الحرم الشّريف فشاهدت الشّموع لا تؤثر ضياءً في تلك البُقعة الشّريفة فكأنّها مشرقة بنور الشّمس والشّموع تبدو كما لو اُجّجت في وضح النّهار هذا وأنا ذاهِل عن هذه الايات فلا أنتبه اليها، فلمّا انتهى من الزّيارة دار من سمت الرّجل الى خلف القبر الشّريف فوقف في الجانب الشّرقي وقال : هل تزُور جدّي الحسين (عليه السلام) ؟ قلت : نعم أزُوره (عليه السلام)فهذه ليلة الجُمعة، فزاره (عليه السلام)بزيارة وارث وانتهى المؤذّن حينئذ من أذان المغرب ، فقال لي صاحبي : صلّ والتحق بالجماعة فأتى المسجد الواقع خلف القبر الشّريف وقد أقيمت هُناك صلاة الجماعة ووقف هو منفرداً الى يمين الامام محاذياً له ، أمّا أنا فوجدت مكاناً في الصّف الاوّل ووقفت هُناك مصلّياً مع الجماعة فلمّا فرغت من الصّلاة لم أجد صاحبي فخرجت من المسجد وفتّشت عنه الحرم الشّريف فلم أجده وكنتُ أنوي أن أبذل له عدّة قرانات واستضيفه تلك اللّيلة واذا أنا أفيق من غفلتي وأنتبه، فأشخص السّيد الّذي صحبني فتتوالى في خاطري الايات والمعجزات التي مرّت بي فقد انقادت له نفسي فعدت معه الى الكاظمين (عليهما السلام) غير مبال بما كان يصدّني عن ذلك من الامر الهام في بغداد وقد دعاني باسمي ولم أكن قد رأيته من قبل وقد عبّر بكلمة الموالين لنا وقال ايضاً: أنا اشهد لك، وقد أبدى لي النّهر الجاري والاشجار المثمرة في غير مواسمها، فهذه الشّواهد الواضحة وغيرها ممّا شهدت تورث لي القطع واليقين بأنّه هو الامام المهدي (عليه السلام) ولا سيّما انّه سألني : هل تعرف امام زمانك ؟ قلت : نعم ، فقال : سلّم عليه ، فلمّا سلّمت تبسّم وردّ هو عليّ السّلام ثمّ أتيت حافظ الاحذية (الكيشوان) وسألته عن صاحبي ، فأجاب : قد خرج وسألني أكان هو صاحبك ؟ قلت : نعم ، ثمّ أويت الى البيت الّذي كنت أحلّ بها ضيفاً فبتّ فيه ليلتي فلمّا أصبح الصّباح توجّهت الى حضرة الشّيخ محمّد حسن وقصصت له قصّتي، فوضع يده على فيه ونهاني عن افشاء القصّة وقال لي : وفّقك الله فكنت أكتمها ولا اُنبىء بها أحداً، وبعد شهر من حدوثها شاهدت يوماً في الحرم الطّاهر سيّداً جليلاً يدنُو منّي ويسألني ماذا حدث لك ويلمح الى القصّة فأنكرتها قائلاً : لم يحدث لي شيء ، فأعاد عليَّ كلامه فاشتدّ انكاري لها ، ثمّ غاب عن بصري ولم أره بعد ، انتهى ."},{"type":"AboutText","content":"اعلم انّ جامع براثا من المساجد المعروفة المباركة وهو واقع على الطّريق بين الكاظميّة وبغداد على الطّريق الّذي يسلكه الوافدون لزيارة الاعتاب المقدّسة في العراق من دون مبالاة بالمسجد الّذي يمرّون عليه ، على ما روي له من الفضل والشّرف الرّفيع ."},{"type":"AboutText","content":"قال الحموي وهو من مورّخي سنة ستمائة في كتابه مُعجم البلدان : براثا محلّة كانت في طرف بغداد في قبلة الكرخ وجنوبي باب محول وكان لها جامع مفرد تصلّي فيه الشّيعة وقد خربت عن آخرهما وقال : كانت الشّيعة قبل الرّاضي بالله الخليفة العبّاسي يجتمع فيه قوم منهم يسبّون الصّحابة فكبسه الرّاضي بالله وأخذ مَنْ وجده فيه وحبسهم وهدمه حتّى سوّى به الارض، وأنهى الشّيعة خبره الى حكم الماكاني امير الامراء ببغداد، فأمر باعادة بنائه وتوسيعه واحكامه وكتب في صدره اسم الرّاضي، ولم تزل الصّلاة تقام فيه الى بعد الخمسين وأربعمائة، ثمّ تعطّلت الى الان وكانت براثا قبل بناء بغداد قرية يزعمون انّ عليّاً (عليه السلام) مرّ بها لما خرج لقتال الحروريّة بالنّهروان وصلّى في موضع من الجامِع المذكور، وانّه دخل حمّاماً كان في هذه القرية، وينسب الى براثا هذه أبو شعيب البراثي العابد كان أوّل من سكن براثا في كوخ يتعبّد فيه فمرّت بكوخه جارية من ابناء الكتاب الكبار وابناء الدّنيا كانت ربيت في القُصور، فنظرت الى أبي شعيب فاستحسنت حاله وما كان عليه فصارت كالاسير له، فجاءت الى أبي شعيب وقالت : أريد أن أكون لك خادمة ، فقال لها : إن أردتِ ذلك فتعرّي من هيئتك وتجرّدي عمّا أنت فيه حتّى تصلحي لما أردتِ، فتجرّدت (السّعيدة) عن كلّ ما تملكه ولبست لبسة النّساك وحضرته فتزوّجها، فلمّا دخلت الكوخ رأت قطعة خصاف كانت في مجلس أبي شعيب تقيه من النّدى ، فقالت : ما أنا بمقيمة عندك حتّى تخرج الخصاف لانّي سمعتك تقول : انّ الارض تقول : يَا ابْنَ آدَمَ تَجْعَلُ بَيْنِى وَبَيْنَكَ حِجاباً وَاَنْتَ غَداً في بَطْني ، فرماها أبو شعيب ومكثت عنده سنين يتعبّدان أحسن العبادة وتوفّيا على ذلك ."},{"type":"AboutText","content":"أقول : قد حدّثنا في كتاب هديّة الزّائر في فضل هذا المسجد الشّريف وقلنا هُناك انّ لهذا المسجد كما يبدو من مجموع هذه الاحاديث فضائل عديدة تكفي احداها لو حازها مسجد من المساجد أن تشدّ اليه الرّحال وتطوي المراحل ابتغاء رضوان الله بالصّلاة فيه والدّعاء :"},{"type":"Text","content":"الاُولى : انّ الله تعالى أقرّ أن لا ينزله بجيشه الاّ نبيّ أو وصيّ نبيّ ."}],"preview":"روى الصّدوق في الفقيه ، قال : اذا أردت زيارته فاغتسل وتنظف والبس ثوبين طاهرين وقُل في زيارته :","hasTranslate":false},{"id":"mf_ar_239","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"الثّانية : انّه بيت مريم","blocks":[{"type":"Text","content":"الثّالثة : انّه أرض عيسى (عليه السلام) ."},{"type":"Text","content":"الرّابعة : انّ فيه العين الّتي نبعت لمريم ."},{"type":"Text","content":"الخامسة : انّ أمير المؤمنين صلوات الله وسلامه عليه أبان تلك العين باعجازه ."},{"type":"Text","content":"السّادسة : انّ فيهِ صخرة بيضاء مباركة عليها وضعت مريم عيسى (عليه السلام)من عاتقها ."},{"type":"Text","content":"السّابعة : انّ أمير المؤمنين (عليه السلام) كشف باعجازه عن تلك الصّخرة فنصبها الى القبلة وصلّى اليها ."},{"type":"Text","content":"الثّامنة : صلاة أمير المؤمنين (عليه السلام) وابنيه الحسن المجتبى وسيّد الشّهداء (عليهم السلام) فيه ."},{"type":"Text","content":"التّاسعة : انّ امير المؤمنين (عليه السلام) أقام هناك أربعة أيّام ."},{"type":"Text","content":"العاشرة : انّه صلّى فيه الانبياء لا سيّما النّبي خليل الرّحمن (عليه السلام) ."},{"type":"Text","content":"الحادية عشرة : انّ هناك قبر نبيّ من الانبياء ولعلّه يوشع (عليه السلام) ، فقد قال الشّيخ رحمة الله عليه: انّ قبره في الفسحة المقابلة لمسجد براثا ."},{"type":"Text","content":"الثّانية عشرة : انّ فيه قد رُدّت الشّمس لامير المؤمنين (عليه السلام)، والغريب انّ المسجد بما له من الفضل والشّرف الرّفيع وبما بدا فيه من الايات الالهيّة والمعجزات الحيدريّة قد عفاه معظم الوافدين لزيارة الاعتاب المقدّسة في العراق وهو لم يكن في ناحية منعزلة وانّما هو واقع على طريقهم الّذي يجتازونه مراراً عديدة ، فلم يعهد أن يؤمّه فرد واحد من كلّ ألف من الزّوار وقد يتّفق انّ زائراً من الزّوار يتوجّه اليه متوخياً عظيم فضل الله فيه، فاذا وافاه والباب مغلق فاقتضى فتح الباب أن يبذل نزراً يسيراً من المال تماسك عنه وتضايق وأغمظ عن عظيم الاجر وهو لا يحجم عن بذل الجزيل لمشاهدة مدينة بغداد وصروح الجبابرة فيها ، فضلاً عن المبالغ الطّائلة الّتي ينفقها في فضول المعاش وفي التّعامل مع يهود بغداد على أمتعتهم النّحسة النّجسة الّتي صارت ابتياعها كالجزء المكمّل لزيارة معظم الزّائرين والله المستعان ."}],"preview":"الثّالثة : انّه أرض عيسى (عليه السلام) .","hasTranslate":false},{"id":"mf_ar_240","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"المَطلبُ الثّالِثُ : في زيارة النّواب الاربعة :","blocks":[{"type":"Text","content":"وهم أبو عمرو عثمان بن سعيد الاسدي ، وأبو جعفر محمّد بن عثمان ، والشّيخ أبو القاسم حسين بن روح النّوبختي ، والشّيخ الجليل أبو الحسن علي بن محمّد السّمري رضي الله عنهم ."},{"type":"AboutText","content":"اعلم انّ من وظائف الوافدين لزيارة الاعتاب المقدّسة في العراق أثناء اقامتهم في مدينة الكاظمين (عليهما السلام) الطّيّبة هو التّوجه الى بغداد لزيارة هؤلاء النّواب الاربعة الّذين نابُوا عن الحجّة المنتظر امام العصر صلوات الله عليه، وزيارة قبورهم لا يتطلّب من الزّائر بذل كثير من الجُهد فهي مجتمعة في بغداد غير بعيدة عن الوافدين من الزّوار، وهي لو كانت منتشرة في أقاصي البلاد لكان يحقّ أن يشّد اليها الرّحال ويطوى في سبيلها المسافات الشّاسعة ويتحمّل متاعب السّفر وشدائده لنيل ما في زيارة كلّ منها من الاجر العظيم والثّواب الجزيل، وهم قد فاقوا جميع اصحاب الائمّة (عليهم السلام)وخواصهم مرتبة وفضلاً وفازوا بالنّيابة عن الامام (عليه السلام) وسفارته والوساطة بينه وبين الرّعية خلال سبعين سنة، وقد جرى على أيديهم كرامات كثيرة وخوارق لا تحصى، ويعزى الى بعض العلماء القول بعصمتهم وغير خفيّ انّهم في مماتهم ايضاً وسائط، فمن اللاّزم أن يبلغ الامام (عليه السلام) ما تكتب في الحاجات والشّدائد من الرّقاع عن طريقهم وبوسيلتهم كما عُرف في محلّه، والخلاصة انّ عظيم فضلهم ومنزلتهم ممّا لا يحدّه البيان وحسبنا ما ذكرناه ترغيباً الى زيارتهم ."},{"type":"Text","content":"وامّا صفة زيارتهم فهي كما ذكرها الطّوسي (رحمه الله) في التّهذيب والسّيد ابن طاوُس (رحمه الله) في مصباح الزّائر مسنداً الى أبي القاسم حُسين بن روح (رحمه الله) حيث قال في صفة زيارتهم: يسلّم على رسول الله وعلى امير المؤمنين بعده وعلى خديجة الكبرى وعلى فاطمة الزّهراء وعلى الحسن والحسين وعلى الائمة (عليهم السلام)الى صاحب الزّمان صلوات الله عليه ثمّ تقول : اَلسَّلامُ عَلَيْكَ يا فُلانَ بْنَ فُلان وتذكر اسم صاحب القبر واسم أبيه وتقول :"},{"type":"Text","content":"اَشْهَدُ اَنَّكَ بابُ الْمَوْلى اَدَّيْتَ عَنْهُ وَاَدَّيْتَ اِلَيْهِ ما خالَفْتَهُ وَلا خالَفْتَ عَلَيْهِ، قُمْتَ خاصّاً وَانْصَرَفْتَ سابِقاً جِئْتُكَ عارِفاً بِالْحَقِّ الَّذي اَنْتَ عَلَيْهِ، واَنَّكَ ما خُنْتَ في التَّأدِيَةِ وَالسَّفارَةِ، اَلسَّلامُ عَلَيْكَ مِنْ باب ما اَوْسَعَكَ وَمِنْ سَفير ما آمَنَكَ وَمِنْ ثِقَة ما اَمْكَنَكَ، اَشْهَدُ اَنَّ اللهَ اخْتَصَّكَ بِنُورِهِ حَتّى عايَنْتَ الشَّخْصَ فَاَدَّيْتَ عَنْهُ وَاَدَّيْتَ اِلَيْهِ ."},{"type":"Text","content":"ثمّ ترجع فتبتدئ بالسّلام على رسول الله الى صاحِب الزّمان (عليهم السلام) ثمّ تقول :"},{"type":"Text","content":"جِئْتُكَ مُخْلِصاً بِتَوْحيدِ اللهِ وَمُوالاةِ اَوْلِيائِهِ وَالْبَراءَةِ مِنْ اَعْدآئِهِمْ وَمِنَ الّذينَ خالَفُوكَ يا حُجَّةَ الْمَوْلى وَبِكَ اِلَيْهِمْ تَوَجُّهي وَبِهِمْ اِلىَ اللهِ تَوَسُّلي . ثمّ تدعُو وتسأل الله ما تُحِبّ تجب ان شاء الله تعالى ."},{"type":"AboutText","content":"أقول : وينبغي ايضاً أن يُزار في بغداد الشّيخ الاجلّ الافخم ثقة الاسلام محمّد بن يعقوب الكليني عطّر الله مرقده، وقد كان زعيم الشّيعة وأوثقهم وأثبتهم في الحديث، وقد صنّف كتاب الكافي في خلال عشرين سنة وهو الكتاب القيّم الّذي تقرّ به عُيون الشّيعة، وهو منّة منّ بها على الشّيعة ولا سيّما رجال الّدين منهم، وقد عدّه ابن الاثير مجدّد مذهب الاماميّة في بدء القرن الثّالث بعدما عدّ مولانا ثامن الائمة صلوات الله عليه مجدّداً للمذهب في القرن الثّاني، ونحن قد عددنا في كتاب هديّة الزّائر أغلب العلماء المدفُونين في المشاهد الشّريفة فليرجع اليه من شاء ."}],"preview":"وهم أبو عمرو عثمان بن سعيد الاسدي ، وأبو جعفر محمّد بن عثمان ، والشّيخ أبو القاسم حسين بن روح النّوبختي ، والشّيخ الجليل أبو الحسن علي بن محمّد السّمري رضي الله عنهم .","hasTranslate":false},{"id":"mf_ar_241","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"المَطْلَبُ الرّابِعُ : في زيارة سلمان (رضي الله عنه)","blocks":[{"type":"AboutText","content":"اعلم انّ من وظائف الزّوار في مدينة الكاظمين التّوجّه الى المدائن لزيارة عبد الله الصّالح سلمان المحمّدي رضوان الله عليه وهو اوّل الاركان الاربعة، وقد خصّه النّبي (صلى الله عليه وآله وسلم) بقوله : سَلْمانُ مِنّا اَهْلَ الْبَيْتِ، فجعله في زُمرة أهل بيت النّبوة والعصمة، وقال (صلى الله عليه وآله وسلم) ايضاً في فضله : سَلْمانُ بَحْرٌ لا يُنْزَفُ وَكَنْزٌ لا يَنْفَدُ سَلْمانُ مِنّا اَهْلَ الْبَيْتِ يُمْنَحُ الْحِكْمَةَ وَيُؤْتَى الْبُرْهانَ . وشبّهه أمير المؤمنين (عليه السلام) بلقمان الحكيم، بل عدّه الصّادق (عليه السلام)أفضل منه، وعدّه الباقر (عليه السلام)من المتوسّمين، ويستفاد من الاحاديث انّه كان يعرف الاسم الاعظم، وانّه كان من المحدَّثين (بفتح الدّال) وانّ للايمان عشر مراتب وهُو قد نال المرتبة العاشرة، وانّه كان يعلم الغيب والمنايا، وانّه كان قد أكل وهو في الدّنيا من تحف الجنّة، وانّ الجنّة كانت تشتاق اليه وتعشقه، وانّه كان يحبّه الله ورسوله، وانّ الله تعالى قد أمر النّبي (صلى الله عليه وآله وسلم) بحُبّ أربعة كان سلمان أحدهم، وانّه قد نزل في الثّناء عليه وعلى أقرانه آيات من القرآن الكريم، وانّ جبرئيل كان اذا هبط على النّبي (صلى الله عليه وآله وسلم)يأمره أن يبلغ سلمان سلاماً عن الله تعالى ويطلعه على علم المنايا والبلايا والانساب، وانّه كان له ليلاً مجلس يخلو فيه برسُول الله (صلى الله عليه وآله وسلم) وانّ النّبي (صلى الله عليه وآله وسلم) وأمير المؤمنين (عليه السلام)قد علّماه من علم الله المخزون المكنُون ما لا يطيق حمله سواه، وانّه قد بلغ مبلغاً شهد في حقّه الصّادق (عليه السلام) قائلاً : اَدْرَكَ سَلْمانُ الْعِلْمَ الاَْوَّلَ وَالْعِلْمَ الاْخِرَ وَهُوَ بَحْرٌ لا يُنْزَحُ وَهُوَ مِنّا اَهْلَ الْبَيْتِ . وحسب الزّائر ترغيباً في زيارته التّأمّل في اختصاص سلمان وانفراده بين الصّحابة والامّة بمنقبة عظيمة هي انّ أمير المؤمنين (عليه السلام) طوى المسافة بين المدينة والمدائن في ليلة واحدة فحضر جنازته وباشر بنفسه غُسله وتكفينُه ثمّ صلّى عليه بصُفُوف من الملائكة، فعاد الى المدينة في ليلته، فيا له من الشّرف الرّفيع ولاءُ آل الرّسول وحبّهم حيث يبلغ به المرء مثل هذه الدّرجة الرّفيعة والمرتبة السّامية ."},{"type":"Text","content":"وأمّا في صفة زيارته فاعلم انّ السّيد ابن طاوُس قد ذكر له في مصباح الزّائر أربع زيارات ونحن نقتصر هُنا بالاُولى من تلك الزّيارات، وقد أثبتنا الزّيارة الرّابعة منها في كتاب الهديّة، وقد أوردها الشّيخ أيضاً في التّهذيب، فاذا شئت زيارته فقف على قبره مستقبل القبلة وقُل :"},{"type":"Text","content":"اَلسَّلامُ عَلى رَسُولِ اللهِ مُحَمَّدِ بْنِ عَبْدِ اللهِ خاتَمِ النَّبِيَّينَ، اَلسَّلامُ عَلى اَميرِ الْمُؤْمِنينَ سَيِّدِ الْوَصِيّينَ، اَلسَّلامُ عَلى الاَْئِمَّةِ الْمَعْصُومينَ الرّاشِدينَ، اَلسَّلامُ عَلى الْمَلائِكَةِ الْمُقَرّبينَ، اَلسَّلامُ عَلَيْكَ يا صاحِبَ رَسُولِ اللهِ الاَْمينَ، اَلسَّلامُ عَلَيْكَ يا وَلِيَّ اَميرِ الْمُؤْمِنينَ، اَلسَّلامُ عَلَيْكَ يا مُودَعَ اَسْرارِ السَّادَةِ الْمَيامينَ، اَلسَّلامُ عَلَيْكَ يا بَقِيَّةَ اللهِ مِنَ الْبَرَرَةِ الْماضينَ، اَلسَّلامُ عَلَيْكَ يا اَبا عَبْدِ اللهِ وَ رَحْمَةُ اللهِ وَبَرَكاتُهُ، اَشْهَدُ أنَّكَ اَطَعْتَ اللهِ كَما اَمَرَكَ، وَاتَّبَعْتَ الرَّسُولَ كَما نَدَبَكَ، وَتَوَلَّيْتَ خَليفَتَهُ كَما اَلْزَمَكَ، وَدَعَوْتَ اِلَى الاِْهْتِمامِ بِذُرِّيَّتِهِ كَما وَقَفَكَ، وَعَلِمْتَ الْحَقَّ يَقيناً وَاعْتَمَدْتَهُ كَما اَمَرَكَ، اَشْهَدُ أنَّكَ بابُ وَصِيِّ الْمُصْطَفى، وَطَريقُ حُجَّةِ اللهِ الْمُرْتَضى، وَاَمينُ اللهِ فيـما اسْتُوْدِعْتَ مِنْ عُلُومِ الاَْصْفِياءِ، اَشْهَدُ اَنَّكَ مِنْ اَهْلِ بَيْتِ النَّبِيِّ النُّجَباءِ الُْمخْتارينَ لِنُصْرَةِ الْوَصِيِّ، اَشْهَدُ اَنَّكَ صاحِبُ الْعاشِرَةِ وَالْبَراهينِ وَالدَّلائِلِ الْقاهِرَةِ، وَاَقَمْتَ الصَّلاةَ وَآتَيْتَ الزَّكاةَ، وَاَمَرْتَ بِالْمَعْرُوفِ، وَنَهَيْتَ عَنِ الْمُنْكَرِ، وَاَدَّيْتَ الاَْمانَةَ وَنَصَحْتَ للهِ وَلِرَسُولِهِ، وَصَبَرْتَ عَلَى الاَْذى في جَنْبِهِ حَتّى أتاكَ الْيَقينُ، لَعَنَ اللهُ مَنْ جَحَدَكَ حَقَّكَ وَحَطَّ مِنْ قَدْرِكَ، لَعَنَ اللهُ مَنْ آذاكَ في مَواليكَ، لَعَنَ اللهُ مَنْ اَعْنَتَكَ في اَهْلِ بَيْتِ نَبِيِّكَ، لَعَنَ اللهُ مَنْ لامَكَ في ساداتِكَ، لَعَنَ اللهُ عَدُوَّ آلِ مُحَمَّد مِنَ الْجِنِّ وَالاِْنْسِ مِنَ الاَْوَّلينَ وَالاْخِرينَ وَضاعَفَ عَلَيْهِمُ الْعَذابَ الاَْليمَ، صَلَّى اللهُ عَلَيْكَ يا اَبا عَبْدِاللهِ، صَلَّى اللهُ عَلَيْكَ يا صاحِبَ رَسُولِ اللهِ، صَلَّى اللهِ عَلَيْهِ وَآلِهِ وَعَلَيْكَ يا مَوْلى اَميرِ الْمُؤْمِنينَ وَصَلَّى اللهِ عَلى رُوحِكَ الطَّيِّبَةِ، وَجَسَدِكَ الطّاهِر وَألْحَقْنا بِمَنِّهِ وَرأفَتِهِ اِذا تَوَفّانا بِكَ وَبِمَحَلِّ السّادَةِ الْمَيامينَ وَجَمَعَنا مَعَهُمْ بِجِوارِهِمْ في جَنّاتِ النَّعيِمِ، صَلَّى اللهِ عَلَيْكَ يا اَبا عَبْدِ اللهِ، وَصَلَّى اللهُ عَلى اِخْوانِكَ الشّيعَةِ الْبَرَرَةِ مِنَ السَّلَفِ الْمَيامينَ، وَادْخَلَ الرُّوحَ وَالرِّضْوانَ عَلَى الْخَلَفِ مِنَ الْمُؤْمِنينَ، وَالْحَقْنا وَاَيّاهُمْ بِمَنْ تَوَلاّهُ مِنْ الْعِتْرَةِ الطّاهِرينَ، وَعَلَيْكَ وَعليهم السلام وَرَحْمَةُ اللهِ وَبَرَكاتُهُ ."},{"type":"Text","content":"ثمّ اقرأ اِنّا اَنْزَلْناهُ في لَيْلَةِ الْقَدْرِ سبع مرّات ثمّ صلّ مندُوباً ما بدا لك ."},{"type":"AboutText","content":"أقول : فاذا عزمت على الانصراف من زيارته فقِف عليه مودّعاً وقُل ما ذيّل به السّيد زيارته الرّابعة وهُوَ : اَلسَّلامُ عَلَيْكَ يا اَبا عَبْدِ اللهِ، اَنْتَ بابُ اللهِ الْمُؤْتى مِنْهُ وَالْمَأخُوذُ عَنْهُ، اَشْهَدُ اَنَّكَ قُلْتَ حَقّاً وَنَطَقْتَ صِدْقاً، وَدَعَوْتَ اِلى مَوْلايَ وَمَوْلاكَ عَلانِيَةً وَسِرّاً، اَتَيْتُكَ زائِراً وَحاجاتي لَكَ مُسْتَوْدِعاً، وَها اَنَا ذا مُوَدِّعُكَ، اَسْتَوْدِعُكَ ديني وَاَمانَتي وَخَواتيمَ عَمَلي وَجَوامِعَ اَمَلي اِلى مُنْتَهى اَجَلي، وَاَلسَّلامُ عَلَيْكَ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، وَصَلَّى اللهُ عَلى مُحَمَّد وَآلِهِ الاَْخْيارِ . ثمّ ادعُ كثيراً وانصرف ."}],"preview":"اعلم انّ من وظائف الزّوار في مدينة الكاظمين التّوجّه الى المدائن لزيارة عبد الله الصّالح سلمان المحمّدي رضوان الله عليه وهو اوّل الاركان الاربعة، وقد خصّه النّبي (صلى الله عليه وآل","hasTranslate":false},{"id":"mf_ar_242","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"أقول : اذا فرغ الزّائر من زيارة سلمان (رحمه الله) فعليه وظيفتان :","blocks":[{"type":"Text","content":"الاُولى : الصّلاة ركعتين أو اكثر عند طاق كسرى فقد صلّى هُناك أمير المؤمنين (عليه السلام) ، روي عن عمّار السّاباطي قال : قدم أمير المؤمنين (عليه السلام)المدائن ونزل أيوان كسرى وكان معه دلف بن بحير ، فلمّا صلّى قام وقال لدلف : قُم معي، وكان معه جماعة من أهل ساباط، فما زال يطوف منازل كسرى ويقول لدلف : كان لكسرى في هذا المكان كذا وكذا ويقول دلف : هو والله كذا، حتّى طاف المواضِع بجميع من كان عنده ودلف يقول : يا سيّدي ومولاي كأنّك وضعت هذه الاشياء في هذه المساكن ."},{"type":"Text","content":"وروي انّ أمير المؤمنين (عليه السلام) مرّ على المدائن فلمّا رأى آثار كسرى ، قال رجل ممّن معه :"},{"type":"Text","content":"جَرَتِ الرِّياحُ عَلى رُسُومِ دِيارِهِمْ فَكَاَنَّهُمْ كانُوا عَلى ميعاد"},{"type":"Text","content":"فقال (عليه السلام) : أفلا قُلت : (كَمْ تَرَكُوا مِنْ جَنّات وَعُيُون * وَزُرُوع وَمَقام كَريم * وَنَعْمَة كانُوا فيها فاكِهينَ * كَذلِكَ وَاَوْرَثْناها قَوْماً آخَرينَ * فَما بَكَتْ عَلَيْهِمُ السَّماءُ وَالاَْرْضُ وَما كانُوا مُنْظَرينَ) ثمّ قال (عليه السلام) : اِنَّ هـؤلاءِ كانُوا وارِثينَ، فَاَصْبَحُوا مَوْرُوثينَ لَمْ يَشْكُرُوا النِّعْمَةَ فَسُلِبُوا دُنْياهُمْ بِالْمَعْصِيَةِ، اِيّاكُمْ وَكُفْرَ النِّعَمِ لا تَحُلُّ بِكُمُ النِّقَمُ ."},{"type":"AboutText","content":"أقول : قد نظم الحكيم الخاقاني بالفارسيّة في شأن الايوان قائلاً :"},{"type":"Text","content":"هان اى دل عبرت بين از ديده نظر كن هان ايوان مدائن را آيينه عبرت دان"},{"type":"AboutText","content":"ورد هنا بيت فارسي في الاعتبار بزوال زينة الدنيا وخراب الملك، والمقصود منه الدعوة إلى الاتعاظ وعدم الاغترار ببهارج الحياة."},{"type":"Text","content":"الثّانية : أن يزور حُذيفة بن اليمان وهُو من كبار صحابة رسُول الله (صلى الله عليه وآله وسلم)، ومن خواصّ أصحاب أمير المؤمنين (عليه السلام)وكان في الصّحابة يمتاز بمعرفة المنافقين ومعرفة اسمائهم، وكان الخليفة الثّاني لا يصلّي على جنازة لم يحضرها حذيفة بن اليمان، وكان حذيفة والياً له على المدائن سنين عديدة ثمّ عزله وأقرّ سلمان في مقامه، فلمّا توفّي عاد حذيفة والياً على المدائن واستمرّ عليها حتّى عادت الخلافة الى امير المؤمنين (عليه السلام)، فأصدر (عليه السلام) من المدينة مرسومه الملكي الى حذيفة والى أهل المدائن يبنئ باستقرار الامر له ويعين حذيفة والياً ولكن حذيفة مات في المدائن ودُفنَ هناك قبلما يحلّ امير المؤمنين (عليه السلام)بجيشه بالكوفة بعد مغادرته المدينة الى البصرة دفعاً لشّر أصحاب الجمل ."},{"type":"Text","content":"عن أبي حمزة الثّمالي قال : دعا حذيفة بن اليماني ابنه عند موته فأوصى اليه وقال : يا بني أظهر اليأس عمّا في أيدي النّاس فانّ فيه الغنى، وايّاك وطلب الحاجات الى النّاس فانّه فقر حاضِر، وكُن اليوم خيراً منك أمس، واذا أنت صلّيت فصلّ صلاة مودّع للدّنيا كأنّك لا ترجع، وايّاك وما يعتذر منه ."},{"type":"AboutText","content":"واعلم انّ الى جانب مرقد سلمان يقع المسجد الجامع للمدائن وهو منسُوب الى الامام الحسن العسكريّ (عليه السلام) ولم يعرف سبب النّسبة فهل هو (عليه السلام) قد أمر ببنائه أم انّه صلّى فيه، فلا تجعل نفسك محرُوماً من فضيلة الصّلاة فيه ركعتين ."}],"preview":"الاُولى : الصّلاة ركعتين أو اكثر عند طاق كسرى فقد صلّى هُناك أمير المؤمنين (عليه السلام) ، روي عن عمّار السّاباطي قال : قدم أمير المؤمنين (عليه السلام)المدائن ونزل أيوان كسرى وكان","hasTranslate":false},{"id":"mf_ar_243","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"في فضل زيارة مولانا أبي الحسن عليّ بن موسى الرّضا صلوات الله عليه","blocks":[{"type":"Text","content":"في فضل زيارة امام الانس والجنّ المدفون بأرض الغُربة ، بضعة سيّد الورى مولانا أبي الحسن عليّ بن موسى الرّضا صلوات الله عليه وعلى آبائه وأولاده ائمّة الهدى، وفي كيفيّة زيارته وفضيلتها أكثر من أن يُحصى، ونحن هُنا نتبرّك بذكر عدّة احاديث ننقل اكثرها عن تحفة الزّائر :"},{"type":"Text","content":"الاوّل : عن النّبي (صلى الله عليه وآله وسلم) قال : ستدفن بضعة منّي بخراسان ما زارها مؤمن الاّ أوجب الله له الجنّة وحرّم جسده على النّار ."},{"type":"Text","content":"وقال في حديث معتبر آخر : ستدفن بضعة منّي بخراسان ما زارها مكروب الاّ نفّس الله كُربته، ولا مُذنب الاّ غفر الله ذنُوبه ."},{"type":"Text","content":"الثّاني : روي بسند معتبر عن موسى بن جعفر صلوات الله وسلامه عليهما قال : من زار قبر ولدي علي (عليه السلام) كان له عند الله عزّوجلّ سبعون حجّة مبرورة . قال الرّاوي مستبعداً سبعين حجّة مبرورة ، قال : نعم ، سبعين ألف حجّة . قال : سبعين ألف حجّة ؟! قال : ربّ حجّة لا تقبل، من زاره أو بات عنده ليلة كان كمن زارَ الله في عرشه ، قُلت : كمن زار الله في عرشه ؟! قال : نعم ، اذا كان يوم القيامة كان على عرش الله عزّوجلّ أربعة من الاوّلين وأربعة من الاخرين، فأمّا الاوّلون فنوح وابراهيم وموسى وعيسى (عليهم السلام)، وأمّا الاربعة الاخرون فمحمّد وعلي والحسن والحسين (عليهم السلام)، ثمّ يمد المطمار ، فيقعد معنا زوّار قبور الائمة، الاّ وانّ أعلاهم درجة وأوفرهم حبوة زوّار قبر ولدي علي (عليه السلام) ."},{"type":"Text","content":"الثّالث : روي عن الامام الرّضا (عليه السلام) قال : انّ في خراسان بقعة سيأتي عليها زمان تكون مختلف الملائكة لا تزال تهبط فيها فوج من الملائكة وتصعد فوج حتّى ينفخ في الصّور ، فقالوا : يا ابن رسُول الله (صلى الله عليه وآله وسلم) وما هي البقعة ؟ قال : هي بأرض طُوس وانّها والله رُوضة من رياض الجنّة، مَن زارني فيها كان كما لو زار رسُول الله (صلى الله عليه وآله وسلم) وكتب الله له بذلك ألف حجّة مقبولة، وألف عمرة مقبولة، وكنتُ أنا وآبائي شفعاؤه يوم القيامة ."},{"type":"Text","content":"الرّابع : بأسانيد صحاح عن ابن أبي نصر قال : قرأت كتاب أبي الحسن الرّضا (عليه السلام) أبلغ شيعتي انّ زيارتي تعدل عند الله عزّوجلّ ألف حجّة ، فرويت الحديث عند الامام محمّد التّقي صلوات الله عليه ، قال : اي والله ألف ألف حجّة لمن زاره عارفاً بحقّه ."},{"type":"Text","content":"الخامس : روي بسندين معتبرين عن الرّضا صلوات الله وسلامه عليه قال : من زارني على بُعد داري أتيته يوم القيامة في ثلاث مواطن حتّى أخلّصه مِن أهوالها : اذا تطايرت الكتب يميناً وشمالاً ، وعند الصّراط ، وعند الميزان ."},{"type":"Text","content":"السّادس : قال ايضاً في حديث معتبر آخر: انّي سأقتل مسمُوماً مظلوماً واُقبر الى جنب هارون، ويجعل الله عزّوجلّ تربتي مختلف شيعتي، فمن زارني في غُربتي وجبت له زيارتي يوم القيامة ، والّذي اكرم محمّداً (صلى الله عليه وآله وسلم)بالنبوّة واصطفاه على جميع الخليقة لا يصلّي أحد منكم عند قبري ركعتين الاّ استحقّ المغفرة من الله عزّوجلّ يوم يلقاه ، والّذي أكرمنا بعد محمّد (صلى الله عليه وآله وسلم) بالامامة وخصّنا بالوصيّة انّ زوّار قبري لاكرم الوفود على الله يوم القيامة، وما من مؤمن يزورني فتصيب وجهه قطرة من السّماء الاّ حرّم الله جسده على النّار ."},{"type":"Text","content":"السّابع : بسند معتبر عن محمّد بن سليمان انّه سأل الامام محمّد التّقي صلوات الله وسلامه عليه عن رجل حجّ حجّة الاسلام فدخل متمتّعاً بالعُمرة الى الحجّ، فأعانه الله تعالى على حجّة وعُمرة، ثمّ أتى المدينة فسلّم على النّبي (صلى الله عليه وآله وسلم)، ثمّ أتى أباك أمير المؤمنين (عليه السلام) عارفاً بحقّه يعلم انّه حجّة الله على خلقه وبابه الّذي يؤتى منه فسلّم عليه، ثمّ أتى أبا عبد الله (عليه السلام)، فسلّم عليه ثمّ أتى بغداد فسلّم على أبي الحسن موسى (عليه السلام)، ثمّ انصرف الى بلاده، فلمّا كان في هذا الوقت رزقه الله تعالى ما يحجّ به فأيّهما أفضل هذا الّذي حجّ حجّة الاسلام يرجع ايضاً فيحجّ أو يخرج الى خراسان الى أبيك عليّ بن مُوسى الرّضا (عليه السلام)فيسلّم عليه ؟ قال : بل يأتي خراسان فيسلّم على أبي أفضل، وليكن ذلك في رجب ولا ينبغي أن تفعلوا هذا اليوم فانّ علينا وعليكم من السّلطان شنعة ."},{"type":"Text","content":"الثّامن : روى الصّدوق في كتاب مَن لا يحضره الفقيه عن الامام محمّد التّقي (عليه السلام) قال : انّ بين جبلي طوس قبضة قبضت من الجنّة مَن دخلها كان آمناً يوم القيامة من النّار ."},{"type":"Text","content":"التّاسع : وروي عنه (عليه السلام) قال : ضمنت لمن زار أبي بطُوس عارفاً بحقّه الجنّة على الله تعالى ."},{"type":"Text","content":"العاشر : روى الصّدوق في عُيون أخبار الرّضا (عليه السلام) عن رجل من الصّالحين انّه رأى في المنام رسُول الله (صلى الله عليه وآله وسلم) فقال له : يا رسُول الله أيّاً من أبنائك أزور ؟ قال : بعضهم وفدوا عليّ مسمُوماً وبعضهم وفدوا مقتولاً ، فقال : أيّهم أزور مع تفرّق مشاهدهم ؟ قال : زُر أقربهم اليك وهُو مدفُون بأرض الغربة ، قُلت : يا رسُول الله تعني بذلك الرّضا (عليه السلام) ؟ قال : قُل : صَلَّى اللهُ عَلَيْهِ قُل : صَلَّى اللهُ عَلَيْهِ قُل : صَلَّى اللهُ عَلَيْهِ قاله ثلاثاً ."},{"type":"AboutText","content":"أقول : قد عقد في كتاب الوسائل وكتاب المُستدرك أبواباً في استحباب التبرّك بمشهد الرّضا ومشاهد الائمة (عليهم السلام)واستحباب اختيار زيارة الرّضا على زيارة الحسين (عليهما السلام) وعلى زيارة كلّ من الائمة (عليهم السلام) وعلى الحجّ المندوب والعُمرة المندُوبة، ولما كان هذا الكتاب لا يسعُ التّطويل فقد اكتفينا بهذه العشرة الكاملة من الاخبار ."},{"type":"Text","content":"وأمّا كيفيّة زيارته (عليه السلام) فاعلم انّه قد ذكر له زيارات عديدة والمشهورة منها هي ما وردت في الكتب المعتبرة ونسبت الى الشّيخ الجليل محمّد بن الحسن بن الوليد وهو من مشايخ الصّدوق (رحمه الله)، ويظهر من مزار ابن قولويه انّها مرويّة عن الائمّة (عليهم السلام)، وكيفيّتها على ما يوافق كتاب مَن لا يحضره الفقيه : انّك اذا أردت زيارة قبر الرّضا (عليه السلام) بطُوس فاغتسل قبلما تخرج من الدّار وقُل وأنت تغتسل :"},{"type":"Text","content":"اَللّـهُمَّ طَهِّرْني وَطَهِّرْ لي قَلْبي وَاشْرَحْ لي صَدْري وَاَجْرِ عَلى لِساني مِدْحَتَكَ وَمَحَبَّتَكَ وَالثَّناءَ عَلَيْكَ، فَاِنَّهُ لا قُوَّةَ اِلاّ بِكَ، اَللّـهُمَّ اجْعَلْهُ لي طَهُوراً وَشِفاءً ."}],"preview":"في فضل زيارة امام الانس والجنّ المدفون بأرض الغُربة ، بضعة سيّد الورى مولانا أبي الحسن عليّ بن موسى الرّضا صلوات الله عليه وعلى آبائه وأولاده ائمّة الهدى، وفي كيفيّة زيارته وفضيلته","hasTranslate":false},{"id":"mf_ar_244","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"وقل وأنت تخرج :","blocks":[{"type":"Text","content":"بِسْمِ اللهِ وَبِاللهِ وَاِلَى اللهِ وَاِلَى ابْنِ رَسُولِ اللهِ، حَسْبِىَ اللهُ تَوَكَّلْتُ عَلَى اللهِ، اَللّـهُمَّ اِلَيْكَ تَوَجَّهْتُ وَاِلَيْكَ قَصَدْتُ وَما عِنْدَكَ اَرَدْتُ ."},{"type":"Text","content":"فاذا خرجت فقف على باب دارك وقُل :"},{"type":"Text","content":"اَللّـهُمَّ اِلَيْكَ وَجَّهْتُ وَجْهي، وَعَلَيْكَ خَلَّفْتُ اَهْلي وَمالي وَما خَوَّلْتَني، وَبِكَ وَثِقْتُ فَلا تُخَيِّبْني، يا مَنْ لا يُخَيِّبُ مَنْ اَرادَهُ، وَلا يُضَيِّعُ مَنْ حَفِظَهُ، صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاحْفَظْني بِحِفْظِكَ فَاِنَّهُ لا يَضيعُ مَنْ حَفِظْتَ ."},{"type":"Text","content":"فاذا وافيت سالماً ان شاء الله فاغتسل اذا أردت أن تزُور وقُل حين تغتسل :"},{"type":"Text","content":"اَللّـهُمَّ طَهِّرْني وَطَهِّرْ لي قَلْبي وَاشْرَحْ لي صَدْري وَاَجْرِ عَلى لِساني مِدْحَتَكَ وَمَحَبَّتَكَ وَالثَّناءَ عَلَيْكَ، فَاِنَّهُ لا قُوَّةَ اِلاّ بِكَ، وَقَدْ عَلِمْتُ اَنَّ قِوامَ ديني التَّسْليمُ لاَِمْرِكَ وَالاِْتِّباعُ لِسُنَّةِ نَبِيِّكَ، وَالشَّهاَدَةُ عَلى جَميعِ خَلْقِكَ، اَللّـهُمَّ اجْعَلْهُ لي شِفاءً وَنُوراً اِنَّكَ عَلى كُلِّ شَىْء قَديرٌ ."},{"type":"Text","content":"والبس أطهر ثيابك وامشِ حافياً، وعليك السّكينة والوقار واذكُرِ الله بقلبك وقُل : اَللهُ اَكْبَرُ ولا اِلـهَ اِلاّ اللهُ وسُبْحانَ اللهِ والْحَمْدُ للهِ، وقصّر خطاك، وقُل حين تدخل الرّوضة المُقدّسة : بِسْمِ اللهِ وَبِاللهِ وَعَلى مِلَّةِ رَسُولِ اللهِ صَلَّى اللهُ عَلَيْهِ وَآلِهِ، اَشْهَدُ اَنْ لا اِلـهَ اِلاّ اللهُ وَحْدَهُ لا شَريكَ لَهُ، وَاَشْهَدُ اَنَّ مُحَمَّداً عَبْدُهُ وَرَسُولُهُ، وَاَنَّ عَلِيّاً وَلِيُّ اللهِ، وسِر حتّى تقف على قبره وتستقبل وجهه بوجهك وقُل :"},{"type":"Text","content":"اَشْهَدُ اَنْ لا اِلـهَ اِلاَّ اللهُ وَحْدَهُ لا شَريكَ لَهُ، وَاَشْهَدُ اَنَّ مُحَمَّداً عَبْدُهُ وَرَسُولُهُ، وَاَنَّهُ سَيِّدُ الاَْوَّلينَ وَالاْخِرينَ، وَاَنَّهُ سَيِّدُ الاَْنْبِياءِ وَالْمُرْسَلينَ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد عَبْدِكَ وَرَسُولِكَ وَنَبِيِّكَ وَسَيِّدِ خَلْقِكَ اَجْمَعينَ صَلاةً لا يَقْوى عَلى اِحْصائِها غَيْرُكَ، اَللّـهُمَّ صَلِّ عَلى اَميرِ الْمُؤمِنينَ عَلِيِّ بْنِ اَبي طالِب عَبْدِكَ وَاَخي رَسُولِكَ الَّذِي انْتَجَبْتَهُ بِعِلْمِكَ وَجَعَلْتَهُ هادِياً لِمَنْ شِئْتَ مِنْ خَلْقِكَ، وَالدَّليلَ عَلى مَنْ بَعَثْتَهُ بِرِسالاتِكَ، وَدَيّانَ الدّينِ بِعَدْلِكَ، وَفَصْلِ قَضائِكَ بَيْنَ خَلْقِكَ، وَالْمُهَيْمِنَ عَلى ذلِكَ كُلِّهِ، وَالسَّلامُ عَلَيْهِ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَللّـهُمَّ صَلِّ عَلى فاطِمَةَ بِنْتِ نَبِيِّكَ وَزَوْجَةِ وَلِيِّكَ وَاُمِّ السِّبْطَيْنِ الْحَسَنِ وَالْحُسَيْنِ سَيِّدَيْ شَبابِ اَهْلِ الْجَنَّةِ، الطُّهْرَةِ الطّاهِرَةِ الْمُطَهَّرَةِ التَّقِيَّةِ النَّقِيَّةِ الرَّضِيَّةِ الزَّكِيَّةِ، سَيِّدَةِ نِساءِ اَهْلِ الْجَنَّةِ اَجْمَعينَ صَلاةً لا يَقْوى عَلى اِحْصائِها غَيْرُكَ، اَللّـهُمَّ صَلِّ عَلَى الْحَسَنِ وَالْحُسَيْنِ سِبْطَيْ نَبِيِّكَ وَسَيِّدَيْ شَبابِ اَهْلِ الْجَنَّةِ الْقائِمَيْنِ في خَلْقِكَ، وَالدَّليلَيْنِ عَلى مَنْ بَعَثْتَ بِرِسالاتِكَ، وَدَيّانَيِ الدّينِ بِعَدْلِكَ وَفَصْلَيْ قَضائِكَ بَيْنَ خَلْقِكَ، اَللّـهُمَّ صَلِّ عَلى عَلِيِّ بْنِ الْحُسَيْنِ عَبْدِكَ الْقائِمِ في خَلْقِكَ، وَالدَّليلِ عَلى مَنْ بَعَثْتَ بِرِسالاتِكَ، وَدَيّانِ الدّينِ بِعَدْلِكَ، وَفَصْلِ قَضائِكَ بَيْنَ خَلْقِكَ سَيِّدِ الْعابِدينَ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّدِ بْنِ عَلِيٍّ عَبْدِكَ وَخَليفَتِكَ في اَرْضِكَ باقِرِ عِلْمِ النَّبِيّينَ، اَللّـهُمَّ صَلِّ عَلى جَعْفَرِ بْنِ مُحَمَّد الصّادِقِ عَبْدِكَ وَوَلِيِّ دينِكَ وَحُجَّتِكَ عَلى خَلْقِكَ اَجْمَعينَ الصّادِقِ الْبارِّ، اَللّـهُمَّ صَلِّ عَلى مُوسَى بْنِ جَعْفَر عَبْدِكَ الصّالِحِ وَلِسانِكَ في خَلْقِكَ النّاطِقِ بِحُكْمِكَ وَالْحُجَّةِ عَلى بَرِيَّتِكَ، اَللّـهُمَّ صَلِّ عَلى عَليِّ بْنِ مُوسَى الرِّضَا الْمُرْتَضى عَبْدِكَ وَوَلِيِّ دينِكَ الْقائِمِ بِعَدْلِكَ وَالدّاعي اِلى دينِكَ وَدينِ آبائِهِ الصّادِقينَ صَلاةً لا يَقْوى عَلى اِحْصائِها غَيْرُكَ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّدِ بْنِ عَلِيٍّ عَبْدِكَ وَوَلِيِّكَ الْقائِمِ بِاَمْرِكَ وَالدّاعي اِلى سَبيلِكَ، اَللّـهُمَّ صَلِّ عَلى عَليِّ بْنِ مُحَمَّد عَبْدِكَ وَوَلِيِّ دينِكَ، اَللّـهُمَّ صَلِّ عَلَى الْحَسَنِ بْنِ عَلِيٍّ الْعامِلِ بِاَمْرِكَ الْقائِمِ في خَـلْقِكَ وَحُجَّتِكَ الْمُؤَدّي عَنْ نَبِيِّكَ وَشاهِدِكَ عَلى خَلْقِكَ، الَْمخْصُوصِ بِكَرامَتِكَ الدّاعي اِلى طاعَتِكَ وَطاعَةِ رَسُولِكَ صَلَواتُكَ عَلَيْهِمْ اَجْمَعينَ، اَللّـهُمَّ صَلِّ عَلى حُجَّتِكَ وَوَلِيِّكَ الْقائِمِ في خَلْقِكَ صَلاةً تامَّةً نامِيَةً باقِيَةً تُعَجِّلُ بِها فَرَجَهُ وَتَنْصُرُهُ بِها وَتَجْعَلُنا مَعَهُ في الدُّنْيا وَالاْخِرَةِ، اَللّـهُمَّ اِنّي اَتَقَرَّبُ اِلَيْكَ بِحُبِّهِمْ وَاُوالي وَلِيَّهُمْ وَاُعادي عَدُوَّهُمْ، فَارْزُقْني بِهِمْ خَيْرَ الدُّنْيا وَالاْخِرَةِ، وَاصْرِفْ عَنّي بِهِمْ شَرَّ الدُّنْيا والاْخِرَةِ وَاَهْوالَ يَوْمِ الْقِيامَةِ ."}],"preview":"بِسْمِ اللهِ وَبِاللهِ وَاِلَى اللهِ وَاِلَى ابْنِ رَسُولِ اللهِ، حَسْبِىَ اللهُ تَوَكَّلْتُ عَلَى اللهِ، اَللّـهُمَّ اِلَيْكَ تَوَجَّهْتُ وَاِلَيْكَ قَصَدْتُ وَما عِنْدَكَ اَرَدْت","hasTranslate":false},{"id":"mf_ar_245","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"ثمّ تجلس عند رأسه وتقُول :","blocks":[{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا وَلِيَّ اللهِ، اَلسَّلامُ عَلَيْكَ يا حُجَّةَ اللهِ، اَلسَّلامُ عَلَيْكَ يا نُورَ اللهِ في ظُلُماتِ الاَْرْضِ، اَلسَّلامُ عَلَيْكَ يا عَمُودَ الدّينِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ آدَمَ صِفْوَةِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ نُوح نَبِيِّ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ اِبْراهيمَ خَليلِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ اِسْماعيلَ ذَبيحِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ مُوسى كَليمِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ عيسى رُوحِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ مُحَمَّد رَسُولِ اللهِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ اَميرِ الْمُؤْمِنينَ عَلِيٍّ وَلِيِّ اللهِ وَوَصِيِّ رَسُولِ رَبِّ الْعالَمينَ، اَلسَّلامُ عَلَيْكَ يا وارِثَ فاطِمَةَ الزَّهْراءِ اَلسَّلامُ عَلَيْكَ يا وارِثَ الْحَسَنِ وَالْحُسَيْنِ سَيِّدَيْ شَبابِ اَهْلِ الجَنَّةِ، اَلسَّلامُ عَلَيْكَ يا وارِثَ عَليِّ بْنِ الْحُسَيْنِ زَيْنِ الْعابِدينَ، اَلسَّلامُ عَلَيْكَ يا وارِثَ مُحَمَّدِ بْنِ عَلِيٍّ باقِرِ عِلْمِ الاَْوَّلينَ وَالاْخِرينَ، اَلسَّلامُ عَلَيْكَ يا وارِثَ جَعْفَرِ بْنِ مُحَمَّد الصّادِقِ الْبارّ، اَلسَّلامُ عَلَيْكَ يا وارِثَ مُوسَى بْنِ جَعْفَر، اَلسَّلامُ عَلَيْكَ اَيُّهَا الصِّدّيقُ الشَّهيدُ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الْوَصِيُّ الْبارُّ التَّقِيُّ، اَشْهَدُ اَنَّكَ قَدْ اَقَمْتَ الصَّلاةَ وَآتَيْتَ الزَّكاةَ، وَاَمَرْتَ بِالْمَعْرُوفِ، وَنَهَيْتَ عَنِ الْمُنْكَرِ، وَعَبَدْتَ اللهَ حَتّى أتاكَ الْيَقينُ، اَلسَّلامُ عَلَيْكَ يا اَبَا الْحَسَنِ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ ."}],"preview":"اَلسَّلامُ عَلَيْكَ يا وَلِيَّ اللهِ، اَلسَّلامُ عَلَيْكَ يا حُجَّةَ اللهِ، اَلسَّلامُ عَلَيْكَ يا نُورَ اللهِ في ظُلُماتِ الاَْرْضِ، اَلسَّلامُ عَلَيْكَ يا عَمُودَ الدّينِ، اَلسَّ","hasTranslate":false},{"id":"mf_ar_246","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"ثمّ تنكبّ على القبر وتقول :","blocks":[{"type":"Text","content":"اَللّـهُمَّ اِلَيْكَ صَمَدْتُ مِنْ اَرْضي وَقَطَعْتُ الْبِلادَ رَجاءَ رَحْمَتِكَ فَلا تُخَيِّبْني وَلا تَرُدَّني بِغَيْرِ قَضاءِ حاجَتي، وَارْحَمْ تَقَلُّبي عَلى قَبْرِ ابْنِ اَخي رَسُولِكَ صَلَواتُكَ عَلَيْهِ وَآلِهِ، بِاَبي اَنْتَ وَاُمّي يا مَوْلايَ اَتَيْتُكَ زائِراً وافِداً عائِذاً مِمّا جَنَيْتُ عَلى نَفْسي، وَاحْتَطَبْتُ عَلى ظَهْري، فَكُنْ لي شافِعاً اِلَى اللهِ يَوْمَ فَقْري وَفاقَتي فَلَكَ عِنْدَ اللهِ مَقامٌ مَحْمُودٌ وَاَنْتَ عِنْدَهُ وَجيهٌ ."},{"type":"Text","content":"ثمّ ترفع يدك اليُمنى وتبسط اليُسرى عَلى القبر وتقول :"},{"type":"Text","content":"اَللّـهُمَّ اِنّي اَتَقَرَّبُ اِلَيْكَ بِحُبِّهِمْ وَبِوِلايَتِهِمْ، اَتَوَلّى آخِرَهُمْ بِما تَوَلَّيْتُ بِهِ اَوَّلَهُمْ، وَاَبْرَءُ مِنْ كُلِّ وَليجَة دُونَهُمْ، اَللّـهُمَّ الْعَنِ الَّذينَ بَدَّلُوا نِعْمَتَكَ، وَاتَّهَمُوا نَبيَّكَ، وَجَحَدُوا بِاياتِكَ، وَسَخِرُوا بِاِمامِكَ، وَحَمَلُوا النّاسَ عَلى اَكْتافِ آلِ مُحَمَّد، اَللّـهُمَّ اِنّي اَتَقَرَّبُ اِلَيْكَ بِالْلَّعْنَةِ عَلَيْهِمْ وَالْبَراءَةِ مِنْهُمْ في الدُّنْيا وَالاْخِرَةِ يا رَحْمنُ ."}],"preview":"اَللّـهُمَّ اِلَيْكَ صَمَدْتُ مِنْ اَرْضي وَقَطَعْتُ الْبِلادَ رَجاءَ رَحْمَتِكَ فَلا تُخَيِّبْني وَلا تَرُدَّني بِغَيْرِ قَضاءِ حاجَتي، وَارْحَمْ تَقَلُّبي عَلى قَبْرِ ابْنِ اَخي","hasTranslate":false},{"id":"mf_ar_247","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"ثمّ تحوّل عند رجليه وتقُولُ :","blocks":[{"type":"Text","content":"صَلَّى اللهُ عَلَيْكَ يا اَبَا الْحَسَنِ، صَلَّى اللهُ عَلى رُوحِكَ وَبَدَنِكَ، صَبَرْتَ وَاَنْتَ الصّادِقُ الْمُصَدَّقُ، قَتَلَ اللهُ مَنْ قَتَلَكَ بِالاَْيْدي وَالاَْلْسُنِ ."},{"type":"Text","content":"ثمّ ابتهل في اللّعنة على قاتل أمير المؤمنين (عليه السلام) وعلى قتلة الحسن والحسين وعلى جميع قتلة أهل بيت رسُول الله، ثمّ تحوّل عند رأسه من خلفه وصلّ ركعتين تقرأ في احداهما يس وفي الاُخرى الرّحمن وتجتهد في الدّعاء والتّضرّع واكثر من الدّعاء لنفسك ولوالديك ولجميع اخوانك من المؤمنين وأقم عند رأسه ما شئت ولتكن صلوتك عند القبر ."},{"type":"AboutText","content":"أقول : هذه الزّيارة هي أحسن زياراته (عليه السلام) وكلمة وَسَخِرُوا بِاِمامَتِكَ الواردة في آخر هذه الزّيارة قد ضبطت في كتاب الفقيه والعيون وكُتب العلاّمة المجلسي وغيره بميمين كما صنعنا نحن هُنا فيكون المعنى سخرُوا بامامة الّذي أنت قد عيّنته لهم، ولكن الكلمة تجدها مضبوطة في كتاب مصباح الزّائر هكذا : وَسَخِرُوا بِاَيّامِكَ وعلى هذا ايضاً يصحّ المعنى بل هُو الاولى من بعض الوجُوه فالايّام هم الائمّة (عليهم السلام) كما يُعرف من خبر صقر بن أبي دلف الماضي في الفصل الخامس من الباب الاوّل ."},{"type":"AboutText","content":"واعلم ايضاً انّ اللّعن على قاتلي الائمة (عليهم السلام) حسن بأيّ لغة كان، ولعلّ الانسب أن يكون اللّعن بهذه العبارة المتّخذة من بعض الادعية :"},{"type":"Text","content":"اَللّـهُمَّ الْعَنْ قَتَلَةَ اَميرِ الْمُؤْمِنينَ، وَقَتَلَةَ الْحَسَنِ وَالْحُسَيْنِ عليهم السلام، وَقَتَلَةَ اَهْلِ بَيْتِ نَبِيِّكَ، اَللّـهُمَّ الْعَنْ اَعْداءَ آلِ مُحَمَّد وَقَتَلَتَهُمْ وَزِدْهُمْ عَذاباً فَوْقَ الْعَذابِ وَهَواناً فَوْقَ هَوان وَذُلاًّ فَوْقَ ذُلٍّ وَخِزْياً فَوْقَ خِزْى، اَللّـهُمَّ دُعَّهُمْ اِلَى النّارِ دَعّاً، وَاَرْكِسْهُمْ في اَليمِ عَذابِكَ رَكْساً، وَاحْشُرْهُمْ وَاَتْباعَهُمْ اِلى جَهَنَّمَ زُمَراً."},{"type":"Text","content":"وفي كتاب تحفة الزّائر انّه قال المفيد : يستحبّ أن يُدعى بهذا الدّعاء بعد صلاة زيارة الرّضا (عليه السلام) :"},{"type":"Text","content":"اَللّـهُمَّ اِنّي اَسْاَلُكَ يا اَللهُ الدّائِمُ في مُلْكِهِ، الْقائِمُ في عِزِّهِ، الْمُطاعُ في سُلْطانِهِ، الْمُتَفَرِّدُ في كِبْرِيائِهِ، الْمُتَوَحِّدُ في دَيْمُومَةِ بَقائِهِ، الْعادِلُ في بَرِيَّتِهِ، الْعالِمُ في قَضِيَّتِهِ، الْكَريمُ في تَأْخيرِ عُقُوبَتِهِ، اِلهي حاجاتي مَصْرُوفَةٌ اِلَيْكَ، وَآمالي مَوْقُوفَةٌ لَدَيْكَ، وَكُلَّما وَفَّقْتَني مِنْ خَيْر فَاَنْتَ دَليلي عَلَيْهِ وَطَريقي اِلَيْهِ، يا قَديراً لا تَؤُودُهُ الْمَطالِبُ، يا مَلِيّاً يَلْجأُ اِلَيْهِ كُلُّ راغِب، ما زِلْتُ مَصْحُوباً مِنْكَ بِالنِّعَمِ جارِياً عَلى عاداتِ الاِْحْسانِ وَالْكَرَمِ، اَسْاَلُكَ بِالْقُدْرَةِ النّافِذَةِ في جَميعِ الاَْشْياءِ، وَقَضائِكَ الْمُبْرَمِ الَّذي تَحْجُبُهُ بِاَيْسَرِ الدُّعاءِ، وَبِالنَّظْرَةِ الَّتي نَظَـرْتَ بِها اِلَى الْجِبالِ فَتَشامَخَتْ، وَاِلى الاَْرَضينَ فَتَسَطَّحَتْ، وَاِلَى السَّماواتِ فَارْتَفَعْت، وَاِلَى الْبِحارِ فَتَفَجَّرَتْ، يا مَنْ جَلَّ عَنْ اَدَواتِ لَحَظاتِ الْبَشَرِ، وَلَطُفَ عَنْ دَقائِقِ خَطَراتِ الْفِكَرِ، لا تُحْمَدُ يا سَيِّدي اِلاّ بِتَوْفيق مِنْكَ يَقْتَضي حَمْداً، وَلا تُشْكَرُ عَلى اَصْغَرِ مِنَّة اِلاَّ اسْتَوْجَبْتَ بِها شُكْراً، فَمَتى تُحْصى نَعْماؤُكَ يا اِلهي وَتُجازى آلاؤُكَ يا مَوْلايَ وَتُكافَأُ صَنايِعُكَ يا سَيِّدي، وَمِنْ نِعَمِكَ يَحْمَدُ الْحامِدُونَ، وَمِنْ شُكْرِكَ يَشْكُرُ الشّاكِرُونَ، وَاَنْتَ الْمُعْتَمَدُ لِلذُّنُوبِ في عَفْوِكَ، وَالنّاشِرُ عَلَى الْخاطِئينَ جَناحَ سِتْرِكَ، وَاَنْتَ الْكاشِفُ لِلضُّرِّ بِيَدِكَ، فَكَمْ مِنْ سَيِّئَة اَخْفاها حِلْمُكَ حَتّى دَخِلَتْ، وَحَسَنَة ضاعَفَها فَضْلُكَ حَتّى عَظُمَتْ عَلَيْها مُجازاتُكَ، جَلَلْتَ اَنْ يُخافَ مِنْكَ اِلاَّ الْعَدْلُ، وَاَنْ يُرْجى مِنْكَ اِلاَّ الاِْحْسانُ وَالْفَضْلُ، فَامْنُنْ عَلَيَّ بِما اَوْجَبَهُ فَضْلُكَ، وَلا تَخْذُلْني بِما يَحْكُمُ بِهِ عَدْلُكَ، سَيِّدي لَوْ عَلِمَتِ الاَْرْضُ بِذُنُوبي لَساخَتْ بي، اَوْ الْجِبالُ لَهَدَّتْني، اَوِ السَّماواتُ لاَخْتَطَفَتْني، اَوِ الْبِحارُ لاََغْرَقَتْني، سَيِّدي سَيِّدي سَيِّدي، مَوْلايَ مَوْلايَ مَوْلايَ، قَدْ تَكَرَّرَ وُقُوفي لِضِيافَتِكَ فَلا تَحْرِمْني ما وَعَدْتَ الْمُتَعَرِّضينَ لِمَسْأَلَتِكَ يا مَعْرُوفَ الْعارِفيِنَ، يا مَعْبُودَ الْعابِدينَ، يا مَشْكُورَ الشّاكِرينَ، يا جَليسَ الذّاكِرينَ، يا مَحْمُودَ مَنْ حَمِدَهُ، يا مَوْجُودَ مَنْ طَلَبَهُ، يا مَوْصُوفَ مَنْ وَحَّدَهُ، يا مَحْبُوبَ مَنْ اَحَبَّهُ، يا غَوْثَ مَنْ اَرادَهُ، يا مَقْصُودَ مَنْ اَنابَ اِلَيْهِ، يا مَنْ لا يَعْلَمُ الْغَيْبَ اِلاّ هُوَ، يا مَنْ لا يَصْرِفُ السُّوءَ اِلاّ هُوَ، يا مَنْ لا يُدَبِّرُ الاَْمْرَ اِلاّ هُوَ، يا مَنْ لا يَغْفِرُ الذَّنْبَ اِلاّ هُوَ، يا مَنْ لا يَخْلُقُ الْخَلْقَ اِلاّ هُوَ، يا مَنْ لا يُنَزِّلُ الْغَيْثَ اِلاّ هُوَ، صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاغْفِرْ لي يا خَيْرَ الْغافِرينَ، رَبِّ اِنّي اَسْتَغْفِرُكَ اسْتِغْفارَ حَياء، وَاَسْتَغْفِرُكَ اسْتِغْفارَ رَجاء، وَاَسْتَغْفِرُكَ اسْتِغْفارَ، اِنابَة، وَاَسْتَغْفِرُكَ اسْتِغْفارَ رَغْبَة، وَاَسْتَغْفِرُكَ اسْتِغْفارَ رَهْبَة، وَاَسْتَغْفِرُكَ اسْتِغْفارَ طاعَة، وَاَسْتَغْفِرُكَ اسْتِغْفارَ ايمان، وَاَسْتَغْفِرُكَ اسْتِغْفارَ اِقْرار، وَاَسْتَغْفِرُكَ اسْتِغْفارَ اِخْلاص، وَاَسْتَغْفِرُكَ اسْتِغْفارَ تَقْوى، وَاَسْتَغْفِرُكَ اسْتِغْفارَ تَوَكُّل، وَاَسْتَغْفِرُكَ اسْتِغْفارَ ذِلَّة، وَاَسْتَغْفِرُكَ اسْتِغْفارَ عامِل لَكَ هارِب مِنْكَ اِلَيْكَ، فَصَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَتُبْ عَلَيَّ وَعَلى والِدَيَّ بِما تُبْتَ وَتَتُوبُ عَلى جَميعِ خَلْقِكَ، يا اَرْحَمَ الرّاحِمينَ، يا مَنْ يُسَمّى بِالْغَفُورِ الرَّحيمِ، يا مَنْ يُسَمّى بِالْغَفُورِ الرَّحيمِ، يا مَنْ يُسَمّى بِالْغَفُورِ الرَّحيمِ، صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاقْبَلْ تَوْبَتي، وَزَكِّ عَمَلي، وَاْشُكرْ سَعْيي، وَارْحَمْ ضَراعَتي، وَلا تَحْجُبْ صَوْتي، وَلا تُخَيِّبْ مَسْأَلَتي يا غَوْثَ الْمُسْتَغيثينَ، وَاَبْلِغْ اَئِمَّتي سَلامي وَدُعائي وَشَفِّعْهُمْ في جَميعِ ما سَأَلْتُكَ، وَاَوْصِلْ هَدِيَّتي اِلَيْهِمِ كَما يَنْبَغي لَهُمْ، وزِدْهُمْ مِنْ ذلِكَ ما يَنْبَغي لَكَ بِاَضْعاف لا يُحْصيها غَيْرُكَ، وَلا حَوْلَ وَلا قُوَّةَ اِلاّ بِاللهِ الْعَلِيِّ الْعَظيمِ، وَصَلَّى اللهُ عَلى اَطْيَبِ الْمُرْسَلينَ مُحَمَّد وَآلِهِ الطّاهِرينَ ."},{"type":"AboutText","content":"أقول : أورد العلاّمة المجلسي في البحار نقلاً عن بعض مؤلّفات القدماء من الاصحاب زيارة للرّضا (عليه السلام) تُعرف بالزّيارة الجواديّة وفي آخر تلك الزّيارة : ثمّ صلّ للزّيارة وسبّح واهدها اليه (عليه السلام) ثمّ قُل : اَللّـهُمَّ اِنّي اَسْاَلُكَ يا اَللهُ الدّائِمُ، وأورد هذا الدّعاء بكامله فلا تذر الدّعاء به في ذلك المشهد المقدّس اذا زرت بتلك الزّيارة ."},{"type":"Text","content":"زِيارَة اُخرى"},{"type":"Text","content":"روى ابن قولويه عن بعض الائمة (عليهم السلام) انّه قال : اذا صرت الى قبر الامام الرّضا (عليه السلام) فقُل :"},{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلى عَلِيِّ بْنِ مُوسَى الرِّضا الْمُرْتَضَى الاِْمامِ التَّقِيِّ النَّقِيِّ وَحُجَّتِكَ عَلى مَنْ فَوْقَ الاَْرْضِ وَمَنْ تَحْتَ الثَّرى، الصِّدّيقِ الشَّهيدِ، صَلاةً كَثيرَةً تامَّةً زاكِيَةً مُتَواصِلَةً مُتَواتِرَةً مُتَرادِفَةً، كَاَفْضَلِ ما صَلَّيْتَ عَلى اَحَد مِنْ اَوْلِيائِكَ."},{"type":"Text","content":"زِيارَة اُخرى"},{"type":"Text","content":"وهي ما أوردها المفيد في المقنعة ، قال : تقف عند قبره (عليه السلام) بعد ما اغتسلت غُسل الزّيارة ولبست أنظف ثِيابك وتقول :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا وَلِيَّ اللهِ وَابْنَ وَلِيِّهِ، اَلسَّلامُ عَلَيْكَ يا حُجَّةَ اللهِ وَابْنَ حُجَّتِهِ، اَلسَّلامُ عَلَيْكَ يا اِمامَ الْهُدى وَاَلْعُرْوَةُ الْوُثْقى وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَشْهَدُ اَنَّكَ مَضَيْتَ عَلى ما مَضى عَلَيْهِ آباؤُكَ الطّاهِرُونَ صَلَواتُ اللهِ عَلَيْهِمْ، لَمْ تُؤْثِرْ عَمىً عَلى هُدىً وَلَمْ تَمِلْ مِنْ حَقٍّ اِلى باطِل، وَاَنَّكَ نَصَحْتَ للهِ وَلِرَسُولِهِ وَاَدَّيْتَ الاَْمانَةَ، فَجَزاكَ اللهُ عَنِ الاِْسْلامِ وَاَهْلِهِ خَيْرَ الْجَزاءِ، اَتَيْتُكَ بِاَبي وَاُمّي زائراً عارِفاً، بِحَقِّكَ مُوالِياً لاَِوْلِيائِكَ مُعادِياً لاَِعْدائِكَ فَاشْفَعْ لي عِنْدَ رَبِّكَ."},{"type":"Text","content":"ثمّ انكبّ على القبر وقبّله وضَع جانبي وجهك عليه ثمّ تحوّل الى جانب الرّأس وقُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا مَوْلايَ يَا بْنَ رَسُولِ اللهِ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَشْهَدُ اَنَّكَ الاِْمامُ الْهادي وَالْوَلِيُّ الْمُرْشِدُ، اَبْرَأُ اِلَى اللهِ مِنْ اَعْدائِكَ، وَاَتَقَرَّبُ اِلَى اللهِ بِوِلايَتِكَ صَلَّى اللهُ عَلَيْكَ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ ."},{"type":"Text","content":"ثمّ صلّ للزّيارة وصلّ بعدها ما شئت، ثمّ تحوّل الى جانب الرّجل فادعُ بما شئت ان شاء الله ."},{"type":"AboutText","content":"أقول : لزيارته (عليه السلام) في السّاعات والايّام الشّريفة المنتمية اليه بنوع من المناسبات فضل كثير ولا سيّما في شهر رجب، وفي الثّالث والعشرين من ذي القعدة، والخامس والعشرين منه، وفي السّادس من شهر رمضان كما ذكر في مواقعها من أعمال الشّهور والايّام، وكذلك غير هذه الايّام ممّا ينتمي اليه، واذا أردتَ أن تودّعه (عليه السلام) فودّعه بما كنت تودّع به النّبي (صلى الله عليه وآله وسلم) :"},{"type":"Text","content":"لا جَعَلَهُ اللهُ آخِرَ تَسْليمي عَلَيْكَ (واذا أردت قُل): اَلسَّلامُ عَلَيْكَ يا وَلِيَّ اللهِ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَللّـهُمَّ لا تَجْعَلْهُ آخِرَ الْعَهْدِ مِنْ زِيارَتي اِبْنَ نَبِيِّكَ وَحُجَّتِكَ عَلى خَلْقِكَ، وَاجْمَعْني وَاِيّاهُ في جَنَّتِكَ وَاحْشُرْني مَعَهُ وَفي حِزْبِهِ مَعَ الشُّهَداءِ وَالصّالِحينَ وَحَسُنَ اُولئِكَ رَفيقاً، وَاَسْتَوْدِعُكَ اللهَ وَاَسْتَرْعيكَ وَاَقْرَأُ عَلَيْكَ اَلسَّلامَ، آمَنّا بِاللهِ وَبِالرَّسُولِ وَبِما جِئْتَ بِهِ وَدَلَلْتَ عَلَيْهِ فَاكْتُبْنا مَعَ الشّاهِدينَ ."}],"preview":"صَلَّى اللهُ عَلَيْكَ يا اَبَا الْحَسَنِ، صَلَّى اللهُ عَلى رُوحِكَ وَبَدَنِكَ، صَبَرْتَ وَاَنْتَ الصّادِقُ الْمُصَدَّقُ، قَتَلَ اللهُ مَنْ قَتَلَكَ بِالاَْيْدي وَالاَْلْسُنِ .","hasTranslate":false},{"id":"mf_ar_248","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"أقول : ينبغي هُنا ذكر أمور :","blocks":[{"type":"Text","content":"الاوّل : بسند معتبر عن الامام عليّ النّقي صلوات الله وسلامه عليه انّه قال : من كانت له الى الله حاجة فليزُر قبر جدّي الرّضا(عليه السلام) بطوس مغتسلاً فيصلّي عند رأسه ركعتين فيذكر حاجته في قنوت صلاته فتستجاب له حاجته الاّ اذا كانت في معصية أو قطيعة رحم، انّ موضِع قبره بقعة من بُقَعِ الجنّة ولا يزُوره مؤمن الاّ اعتقه الله من النّار وأدخله الجنّة ."},{"type":"Text","content":"الثّاني : حكى العلاّمة المجلسي (رحمه الله) عن خطّ الشّيخ الجليل الشّيخ حسين بن عبد الصّمد والد الشّيخ البهائي انّ الشّيخ أبي الطّيب حسين بن احمد الفقيه الرّازي (رحمه الله) ذكر انّه : مَن زارَ الرّضا صلوات الله وسلامه عليه أو غيره من الائمة (عليه السلام) فصلّى عنده صلاة جعفر كتب له بكلّ ركعة أجر من حجّ ألف حجّة واعتمر ألف عمرة، وأعتق في سبيل الله ألف رقبة، ووقف للجهاد مَعَ نبيّ مُرسل ألف مرّة، وكان له بكلّ خطوة يخطوها أجر مائة حجّة، ومائة عمرة، وعتق مائة رقبة في سبيل الله تعالى، وكتب له مائة حسنة، ومحى عنه مائة سيّئة، وصفة صلاة جعفر قد مضت في خلال أعمال يوم الجُمعة ."},{"type":"Text","content":"الثّالث : روي عن محوّل السّجستاني قال : لما ورد البريد بإشخاص الرّضا (عليه السلام) الى خراسان دخل المسجد ليودّع رسُول الله (صلى الله عليه وآله وسلم) فودّعه مراراً كلّ ذلك يرجع الى القبر ويعلو صوته بالبُكاء والنّحيب ، فتقدّمت اليه وسلّمت عليه ، فردّ السّلام وهنّأته فقال : زُرني فانّي أخرج من جوار جدّي(صلى الله عليه وآله وسلم) فأموت في غُربة وأدفن في جنب هارون ."},{"type":"AboutText","content":"وروى الشّيخ يوسف بن حاتم الشّامي في كتاب الدّرّ النّظيم عن جمع من الاصحاب عن الرّضا(عليه السلام) قال : لما أردتُ الخرُوج من المدينة الى خراسان جمعت عيالي فأمرتهم أن يبكوا عليّ حتّى اسمع بكاءهم، ثمّ فرقت فيهم اثني عشر ألف دينار ثمّ قلت لهم : انّي لا أرجع الى عيالي أبداً ، ثمّ أخذت أبا جعفر الجواد فأدخلته المسجد ووضعت يده على حافة القبر وألصقته واستخفظته برسُول الله (صلى الله عليه وآله وسلم)وأمرت جميع وكلائي وحشمي له بالسّمع والطّاعة وترك مخالفته وعرفتهم انّه القيّم مقامي ."},{"type":"AboutText","content":"وروى السّيد عبد الكريم ابن طاوُس (رحمه الله): انّه لما طلب المأمون الرّضا (عليه السلام)من المدينة الى خراسان سار (عليه السلام) من المدينة الى البصرة ولم يذهب الى الكوفة ثمّ توجّه من البصرة الى بغداد على طريق الكوفة ومن هُناك الى مدينة قم ودخل قُم فاستقبله أهلها، فتخاصموا في ضيافته كلّ يبغي أن يحلّ (عليه السلام) داره ، فقال (عليه السلام) : انّ جملي هُو المأمُور أي انّه (عليه السلام)يحلّ حيثما برك الجمل، فأتي الجمل داراً واستناخ على بابه وكان صاحب الدّار قد رأى في المنام في ليلته انّ الرّضا (عليه السلام) سيكُون ضيفه غداً، فلم تمض مدّة طويلة حتّى صار ذلك الدّار مقاماً من المقامات الرّفيعة وهو في عصرنا مدرسة معمورة ."},{"type":"AboutText","content":"وروى الصدّوق بسنده عن اسحاق بن راهويه قال : لما وافى أبو الحسن الرّضا (عليه السلام) نيسابور وأراد أن يرحل منها اجتمع اليه أصحاب الحديث ، فقالوا له : يا ابن رسول الله (صلى الله عليه وآله وسلم) ترحل عنّا ولا تحدّثنا بحديث فنستفيده منك، وقد كان قعد في العمارية فاطلع رأسه وقال : سمعتُ أبي مُوسى بن جعفر يقول : سمعتُ أبي جعفر بن محمّد يقُول : سمعتُ أبي محمّد بن علي يقول : سمعتُ أبي عليّ بن الحسين يقول : سمعتُ أبي الحسين بن علي يقول : سمعتُ أبي أمير المؤمنين علي بن أبي طالب عليه الصّلاة والسّلام يقول : سمعتُ رسُول الله (صلى الله عليه وآله وسلم) يقول : سمعتُ جبرئيل يقول : سمعتُ الله عزّوجلّ يقُول : لا اِلـهَ اِلاَّ اللهُ حِصْني فَمَنْ دَخَلَ حِصْني اَمِنَ مِنْ عَذابي، فلمّا مرّت الرّاحلة نادانا بِشُرُوطِها وَاَنَا مِنْ شُرُوطِها."},{"type":"AboutText","content":"وروى أبو الصّلت انّ الرّضا (عليه السلام) في طريقه الى المأمون لما بلغ القرية الحمراء } ده سُرخ { قيل له : يا ابن رسُول الله (صلى الله عليه وآله وسلم) قد زالت الشّمس أفلا نصلّي، فنزل (عليه السلام) فقال : إئتوني بماء، فقيل : ما معنا ماء ، فبحث بيده الارض فنبع من الماء ما توضّأ به هُو ومن معه وأثره باق الى اليوم . فلمّا دخل سناباد أسند الى الجبل الّذي ينحت منهُ القدُور ، فقال : اَللّهُمَّ انفَعْ به وبارِك فيما يجعل فيما ينحت منه ، ثمّ أمر (عليه السلام) فنحت له قُدور من الجبل وقال : لا يأكل الاّ ما طبخ فيها فاهتدى النّاس اليه من ذلك اليوم وظهرت بركة دعائه فيه ."},{"type":"Text","content":"الرّابع : ارّخ صاحب مطلع الشّمس انّ الملك (الشاه) عبّاس الاوّل نزل مشهد الرّضا (عليه السلام) في الخامس والعشرين من ذي الحجّة سنة ألف وستّ وذلك بعد ما نهب عبد الرّحمن الاوزبكي الحرم الطّاهر، فلم يترك فيها شيئاً سوى السّاج الذهبي، وفي الثّامن والعشرين من الشّهر شهر ذي الحجّة توجّه الملك الى مدينة هرات فاستردّها ونظم شؤونها فقفل الى مدينة خراسان ولبث فيها شهراً رمّم خلاله الصحن المقدّس وأنعم على خدّام البقعة المباركة ورعاهم بعطفه ثمّ عاد الى العراق، وفي أواخر السّنة الثّامنة بعد الالف قدم الملك ثانياً خراسان فقضى فيه فصل الشّتاء وتقلّد خدمة الاستانة المقدّسة وباشرها بنفسه فكان في بعض اللّيالي وهو يقرض فضُول فتائل الشّموع بالمقراضين فانشأ الشّيخ البهائي على البديهة قائلاً بالفارسيّة:"},{"type":"AboutText","content":"وردت في هذا الموضع أبيات فارسية في وصف خدمة الروضة الشريفة ومدح المسير إلى زيارة الإمام الرضا عليه السلام مشياً، ومعناها الثناء على حرمة المشهد المبارك وتعظيم قصد الزيارة بإخلاص."},{"type":"Text","content":"وكان الشّاه قد نذر أن يرحل الى زيارة الرّضا (عليه السلام) راجلاً فوفى بنذره في السّنة التّاسعة بعد الالف وقطع تلك المسافة الشّاسعة على قدميه خلال ثمانية وعشرين يوماً، وبهذه المناسبة أورد صاحب كتاب تاريخ عالم آرا هذه الابيات :"}],"preview":"الاوّل : بسند معتبر عن الامام عليّ النّقي صلوات الله وسلامه عليه انّه قال : من كانت له الى الله حاجة فليزُر قبر جدّي الرّضا(عليه السلام) بطوس مغتسلاً فيصلّي عند رأسه ركعتين فيذكر ح","hasTranslate":false},{"id":"mf_ar_249","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"الى أن قال :","blocks":[{"type":"AboutText","content":"تتضمن الأبيات الفارسية هنا مدح الإمام علي بن موسى الرضا عليه السلام والثناء على شرف مقامه وفضل التعلق ببابه الشريف والتجرد عما سواه."},{"type":"Text","content":"فلمّا بلغ مدينة خراسان أمر بأن يرحّب الصّحن المبارك وكان المدخل الى الرّوضة حينذاك في ايوان علي شير في جانب من جوانب الصّحن الشّريف بشكل غير أنيق، فأمر بتشييد الصّحن بحيث يتوسّطه الايوان وبنى ايواناً آخر في الجانب المقابل ومدّ شارعاً مركزيّاً يجتاز بابي الصّحن والايوان ويطوي المدينة من بابها الغربي الى بابها الشّرقي واحدث للمدينة عيوناً وقنوات ومدّ في منتصف الشّارع المركزي ساقية تجري الى حوض كبير قد أحدثه في وسط الصّحن الشّريف فتخترقه الى الجانب الشّرقي من الشّارع والكتابات الموجودة في هذه الابنية هي من آثار الميرزا محمّد رضا صدر الكتّاب وعليرضا العبّاسي ومحمّد رضا الامامي، وممّا أجراه الشّاه عباس أيضاً انّه كسى القبّة الطّاهرة بالذهب كما تنطق به الكتابة الموجودة على القبّة الطّاهرة وهي :"},{"type":"Text","content":"بِسْمِ اللهِ الرَّحْمنِ الرَّحيمِ مِنْ عَظائِمِ تَوفيقاتِ اللهِ سُبحانه أن وفّق السّلطان الاعظم مولى العجم صاحب النّسب الطّاهر النّبوي والحسب الباهر العلوي تراب أقدام خدّام هذه القبّة المطهّرة اللاّهية زوّار هذه الرّوضة المنوّرة الملكوتيّة مروّج آثار أجداده المعصومين السّلطان بن السّلطان أبو المظفّر شاه عبّاس الحسيني الموسوي الصّفوي بهادر خان، فاستسعد بالمجيء ماشياً على قدميه من دار السّلطنة اصفهان الى زيارة هذا الحرم الاشرف وقد تشرّف بزينة هذه القبّة من خلصّ ما له في سنة ألف وعشر وتمّ سنة ألف وستّ وعشر ."},{"type":"Text","content":"الخامس : قال الطّبرسي في كتاب أعلام الورى بعدما أورد جملة من معجزات الرّضا (عليه السلام) : وأمّا ما ظهر للنّاس بعد وفاته من بركة مشهده المقدّس والعلامات والعجائب الّتي شاهدها الخلق فيه وأذعن العام والخاص له وأقرّ المخالف والمؤالف به الى يومنا هذا فكثير خارج عن حدّ الاحصاء والعدّ، ولقد أبرئ فيه الاكم والابرص واستجيبت الدّعوات وقضيت ببركته الحاجات وكشفت المسلّمات، وشاهدنا كثيراً من ذلك وتيقناه وعلمناه لا يتخالج الشّك والرّيب في معناه، والشّيخ الاجلّ الشّيخ الحُرّ العاملي في كتابه اثبات الهداة بعدما حكى هذا الكلام للطّبرسي ، قال : يقول مؤلف هذا الكتاب محمّد بن الحسن الحرّاني : قد شاهدت كثيراً من هذه المعجزات كما شاهدها الشّيخ الطّبرسي وتيقّنت بها كما تيقّن هو بها وذلك في مدّة مجاورتي للمشهد المقدس وهي ستّ وعشرون سنة، وقد سمعت في ذلك ما يفوق التّواتر ولم أتخطر حاجة دعوت الله بها في هذا المشهد الاّ وقضيت والحمد لله، والمقام لا يسع التّفصيل فاكتفينا بالاجمال ."},{"type":"Text","content":"ويقول عباس القمّي مؤلّف هذا الكتاب : انّنا في غنىً عن ذكر الكرامات الّتي برزت من تلك الرّوضة المقدّسة في سوالف الازمان بما يتجدّد منها في كلّ عصر وزمان وقد ألمحنا الى ما يناسب المقام في الباب الثّاني في خلال أعمال اللّيلة السّابعة والعشرين من شهر رجب، فلنختم هذا الفصل بعدّة أبيات ممّا انشأه الجامي في مدحه (عليه السلام) :"},{"type":"Text","content":"سَلامٌ عَلى آلِ طه وَيس سَلامٌ عَلى آلِ خَيْرِ النَّبِيّين"},{"type":"Text","content":"سَلامٌ عَلى رَوْضَة حَلَّ فيها اِمامٌ يُباهي بِهِ المُلْكُ وَالدّين"}],"preview":"تتضمن الأبيات الفارسية هنا مدح الإمام علي بن موسى الرضا عليه السلام والثناء على شرف مقامه وفضل التعلق ببابه الشريف والتجرد عما سواه.","hasTranslate":false},{"id":"mf_ar_250","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"ويحتوي على مقامين :","blocks":[{"type":"Text","content":"المقام الاوّل"},{"type":"Text","content":"في زيارة الامامين المعصومين عليّ بن محمّد النّقي والحسن بن عليّ العسكري صلوات الله عليهم، اذا دخلت سرّ من رأى ان شاء الله وقصدت زيارتهما (عليهما السلام) فاغتسل وتأدّب بآداب دخول المشاهد الشّريفة ثمّ سر بسكينة ووقار حتّى تبلغ باب الحرم الطّاهر واستأذن للدّخول بالاستيذان العام السّالف في اوائل هذا الباب، ثمّ ادخل الحرم الشّريف وزرهما (عليهما السلام) بهذه الزّيارة وهي أصحّ الزّيارات :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكُما يا وَلِيَّى اللهِ، اَلسَّلامُ عَلَيْكُما يا حُجَّتَىِ اللهِ، اَلسَّلامُ عَلَيْكُما يا نُورَىِ اللهِ فِى ظُلُماتِ الاَْرْضِ اَلسَّلامُ عَلَيْكُما يا مَنْ بَدا للهِ فى شَأْنِكُما، اَتَيْتُكُما زائِراً وعارِفاً بِحَقِّكُما مُعادِياً لاَِعْدآئِكُما مُوالِياً لاَِوْلِيآئِكُما مُؤْمِناً بِما آمَنْتُما بِهِ، كافِراً بِما كَفَرْتُما بِهِ، مُحَقِّقاً لِما حَقَّقْتُـما، مُبْطِلاً لِمَا اَبْطَلْتُـما، اَسْاَلُ اللهَ رَبّي وَرَبَّكُما اَنْ يَجْعَلَ حَظّي مِنْ زِيارَتِكُمَا الصَّلاةَ عَلى مُحَمَّد وَآلِهِ، وَاَنْ يَرْزُقَني مُرافَقَتَكُما فِي الْجِنانِ مَعَ آبائِكُمَا الصّالِحينَ وَاَسْأَلَهُ اَنْ يُعْتِقَ رَقَبَتي مِنَ النّارِ وَيَرْزُقَني شَفاعَتَكُما وَمُصاحَبَتَكُما وَيُعَرِّفْ بَيْني وَبَيْنَكُما، وَلا يَسْلُبَني حُبُّكُما وَحُبَّ آبائِكُمَا الصّالِحينَ، وَاَنْ لا يَجْعَلَهُ آخِرَ الْعَهْدِ مِنْ زِيارَتِكُما، وَيَحْشُرَني مَعَكُما فِي الْجَنَّةِ بِرَحْمَتِهِ، اَللّـهُمَّ ارْزُقْني حُبَّهُما وَتَوَفَّني عَلى مِلَِّتِهِما، اَللّهُمَّ الْعَنْ ظالِمي آلَ مُحَمَّد حَقَّهُمْ وَانْتَقِمْ مِنْهُمْ، اَللّـهُمَّ الْعَنِ الاَْوَّلينَ مِنْهُمْ وَالاْخِرينَ وَضاعِفْ عَلَيْهِمْ الْعَذابَ، وَاَبْلِغْ بِهِمْ وَبِاَشْياعِهِمْ وَمُحِبّيهِمْ وَمُتَّبِعيهِمْ اَسْفَلَ دَرْك مِنَ الْجَحيمِ اِنَّكَ عَلى كُلِّ شَىء قَديرٌ، اَللّـهُمَّ عَجِّلْ فَرَجَ وَلِيِّكَ وَابْنِ وَلِيِّكَ وَاجْعَلْ فَرَجَنا مَعَ فَرَجِهِمْ يا اَرْحَمَ الرّاحِمينَ ."},{"type":"Text","content":"وتجتهد في الدّعاء لنفسك ولوالديك وتخيّر من الدّعاء فان وصلت اليهما (أي إن أمكنك الوصول الى قبرهما) صلوات الله عليهما فصلّ عند قبريهما ركعتين واذا دخلت المسجد (أين لم تتمكن من القبر) وصلّيت دعوت الله بما احببت امّه قريب مجيب وهذا المسجد الى جانب الدّار وفيه كانا يصلّيان (عليهما السلام) ."},{"type":"AboutText","content":"أقول : قد أثبتنا هذه الزّيارة طبقاً لكتاب كامل الزّيارة، وقد روى الزّيارة باختلاف يسير الشّيخ محمّد ابن المشهدي والشّيخ المفيد والشّهيد ايضاً في مزاراتهم، وقد ورد في نسخهم بعد الفقرة فِى الْجَنَّةِ بِرَحْمَتِهِ : ثمّ اذهب وانكبّ على كلّ من القبرين وقبّلهما وضع جانبي وجهك عليهما ثمّ ارفع رأسك وقُل : اَللّـهُمَّ ارْزُقْني حُبَّهُمْ وَتَوَفَّنى عَلى مِلَّتِهِمْ الى آخر الزّيارة السّالفة . ثمّ قالوا : صلّ أربع ركعات عند الرّأس المقدّس وصلّ ما شئت بعد صلاة الزّيارة .. الخ ."},{"type":"Text","content":"ولا يخفى انّهما (عليهما السلام) مدفونان في دارهما وكان للدّار باب يفتح حيناً فتدخل الشّيعة منه وتزور قريباً من القبر ويغلق حيناً فتقف الشّيعة للزّيارة أمام نافذة في الجدار المقابل للقبر، ويلاحظ في مفتتح الرّواية الّتي وردت فيها هذه الزّيارة هذه العبارة : تقول بعد الغُسل إن وصلت الى قبرهما والاّ أومأت بالسّلام من عند الباب الّذي على الشّارع الشّباك، وهذا الزّائر الذي لم يتمكّن من الاقتراب من القبر يصلّي الصّلاة في المسجد وقد أهتم للامر الشّيعة الموالون فنسفوا الدّار وشدّوا في موضعه القبّة والحرم والرّواق والايوان فأصبح المسجد داخل الحرم الشّريف والمشهور الان انّ الايوان المستطيل المتّصل بالرّواق خلف العسكريّين (عليهما السلام) هو المسجد المذكور، بل قيل انّ الرواق الواقع خلف القبر من المسجد وكذا عرض ذراع من الحرم الطاهر منه، وعلى كلّ حال فقد نجى الزّائر من هذا الضّيق ولهما (عليهما السلام)زيارات خاصّة تخصّ كلاً منهما، وعامّة مشتركة بينهما وهي مذكورة في كتب الزّيارات ونسخها كثيرة شايعة لمن رغب في الزّيارة بها، والزّائر اذا أسعفه الحال والمجال فمن المناسب أن يزور بالزّيارة الجامعة الكبيرة الاتية ان شاء الله تعالى فهي بما تحتويه من الكلمات الفصيحة البليغة المعبّرة عن أقصى مراتب الطّاعة والخضوع والاقرار بعظمة الائمة (عليهم السلام) وجلالهم، هي قد صدرت من منبع الجلال والعظمة الامام الهادي (عليه السلام) ، والسّيد ابن طاوُس قد خصّ في مصباح الزّائر كلّ واحد منهما (عليهما السلام) بزيارة مبسُوطة وصلاة عليه ودعاء يُدعى به بعد صلاة زيارته وهي بما يحتويها من الفوائد تبعثنا على ايرادها هُنا وإن أوجبت التّطويل ، قال : اذا وصلت الى محلّه الشّريف بسرّ من رأى فاغتسل عند وصُولك غُسل الزّيارة والبس اطهر ثيابك وامش على سكينة ووقار الى أن تصل الباب الشّريف ، فاذا بلغته فاستأذن وقُل :"},{"type":"Text","content":"أاَدْخُلُ يا نَبِيَّ اللهِ، أاَدْخُلُ يا اَميرَ الْمُؤْمِنينَ، ءَاَدْخُلُ يا فاطِمَةُ الزَّهْراءُ سَيِّدَة نِساءِ الْعالَمينَ، أاَدْخُلُ يا مَوْلايَ الْحَسَنَ بْنَ عَلِيٍّ، أاَدْخُلُ يا مَوْلايَ الْحُسَيْنَ بْنَ عَلِيٍّ، أاَدْخُلُ يا مَوْلايَ عَلِيَّ بْنَ الْحُسَيْنِ، أاَدْخُلُ يا مَوْلايَ مُحَمَّدَ بْنَ عَلِيٍّ أاَدْخُلُ يا مَوْلايَ جَعْفَرَ بْنَ مُحَمَّد، أاَدْخُلُ يا مَوْلايَ مُوسَى بْنَ جَعْفَر، أاَدْخُلُ يا مَوْلايَ عَلِيَّ بْنَ مُوسَى، أاَدْخُلُ يا مَوْلايَ مُحَمَّدَ بْنَ عَلِيٍّ، أاَدْخُلُ يا مَوْلايَ يا اَبَا الْحَسَنِ عَلِيَّ بْنَ مُحَمَّد، أاَدْخُلُ يا مَوْلايَ يا اَبا مُحَمَّد الْحَسَنَ بْنَ عَلِيٍّ، أاَدْخُلُ يا مَلائِكَةَ اللهِ الْمُوَكَّلينَ بِهذَا الْحَرَمِ الشَّريفِ ."},{"type":"Text","content":"ثمّ تدخل مقدّماً رجلك اليمنى وتقف على ضريح الامام أبي الحسن الهادي (عليه السلام) مستقبل القبر ومستدبر القبلة وتقول مائة مرّة اَللهُ اَكْبَرُ وتقول :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا اَبَا الْحَسَنِ عَلِيَّ بْنَ مُحَمَّد الزَّكِيُّ الرّاشِدُ النُّورُ الثّاقِبُ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَلسَّلامُ عَلَيْكَ يا صَفِيَّ، اللهِ اَلسَّلامُ عَلَيْكَ يا سِرَّ اللهِ، اَلسَّلامُ عَلَيْكَ يا حَبْلَ اللهِ، اَلسَّلامُ عَلَيْكَ يا آلَ اللهِ، اَلسَّلامُ عَلَيْكَ يا خِيَرةِ اللهِ، اَلسَّلامُ عَلَيْكَ يا صِفْوَةَ اللهِ، اَلسَّلامُ عَلَيْكَ يا اَمينَ اللهِ، اَلسَّلامُ عَلَيْكَ يا حَقَّ اللهِ، اَلسَّلامُ عَلَيْكَ يا حَبيبَ اللهِ، اَلسَّلامُ عَلَيْكَ يا نُورَ الاَْنْوارِ، اَلسَّلامُ عَلَيْكَ يا زَيْنَ الاَْبْرارِ، اَلسَّلامُ عَلَيْكَ يا سَليلَ الاَْخْيارِ، اَلسَّلامُ عَلَيْكَ يا عُنْصُرَ الاَْطْهارِ، اَلسَّلامُ عَلَيْكَ يا حُجَّةَ الرَّحْمنِ، اَلسَّلامُ عَلَيْكَ يا رُكْنَ الاْيمانِ، اَلسَّلامُ عَلَيْكَ يا مَوْلَى الْمُؤْمِنينَ، اَلسَّلامُ عَلَيْكَ ياوَلِيَّ الصّالِحينَ، اَلسَّلامُ عَلَيْكَ يا عَلَمَ الْهُدى، اَلسَّلامُ عَلَيْكَ يا حَليفَ التُّقى، اَلسَّلامُ عَلَيْكَ يا عَمُودَ الدّينِ، اَلسَّلامُ عَلَيْكَ يَا بْنَ خاتَمِ النَّبِيّينَ، اَلسَّلامُ عَلَيْكَ يَا بْنَ سَيِّدِ الْوَصِيّينَ، اَلسَّلامُ عَلَيْكَ يَا بْنَ فاطِمَةَ الزَّهْراءِ سَيِّدَةِ نِساءِ الْعالَمينَ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الاَْمينُ الْوَفِيُّ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الْعَلَمُ الرَّضِيُّ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الزّاهِدُ التَّقِيُّ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الْحُجَّةُ عَلَى الْخَلْقِ اَجْمَعينَ، اَلسَّلامُ عَلَيْكَ اَيُّهَا التّالي لِلْقُرْآنِ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الْمُبَيِّنُ لِلْحَلالِ مِنَ الْحَرامِ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الْوَلِيُّ النّاصِحُ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الطَّريقُ الْواضِحُ، اَلسَّلامُ عَلَيْكَ اَيُّها النَّجْمُ اللاّئِحُ، اَشْهَدُ يا مَوْلايَ يا اَبـَا الْحَسَنِ اَنَّكَ حُجَّةُ اللهِ عَلى خَلْقِهِ، وَخَليفَتُهُ في بَرِيَّتِهِ، وَاَمينُهُ في بِلادِهِ، وَشاهِدُهُ عَلى عِبادِهِ، وَاَشْهَدُ اَنَّكَ كَلِمَةُ التَّقْوى، وَبابُ الْهُدى، وَالْعُرْوَةُ الْوُثْقى، وَالْحُجَّةُ عَلى مَنْ فَوْقَ الاَْرْضِ وَمَنْ تَحْتَ الثَّرى، وَاَشْهَدُ اَنَّكَ الْمُطَهَّرُ مِنَ الذُّنُوبِ، الْمُبَرَّأُ مِنَ الْعُيُوبِ، وَالُْمخْتَصُّ بِكَرامَةِ اللهِ، وَالَْمحْبُوُّ بِحُجَّةِ اللهِ، وَالْمَوْهُوبُ لَهُ كَلِمَةُ اللهِ، وَالرُّكْنُ الَّذى يَلْجَأُ اِلَيْهِ الْعِبادُ، وَتُحْيى بِهِ الْبِلادُ، وَاَشْهَدُ يامَوْلاىَ أنّي بِكَ وَبِابآئِكَ وَاَبْنائِكَ مُوقِنٌ مُقِرٌّ، وَلَكُمْ تابِعٌ في ذاتِ نَفْسي وَشَرايِعِ ديني وَخاتِمَةِ عَمَلي وَمُنْقَلَبي وَمَثْوايَ، وَاَنّي وَلِيٌّ لِمَنْ والاكُمْ وَعَدُوٌّ لِمَنْ عاداكُمْ، مُؤْمِنٌ بِسِرِّكُمْ وَعَلا نِيَتِكُمْ وَاَوَّلِكُمْ وَآخِرِكُمْ بِاَبي اَنْتَ وَاُمّي وَالسَّلامُ عَلَيْكَ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ ."},{"type":"Text","content":"ثمّ قبّل ضريحه وضع خدّك الايمن عليه ثمّ الايسر وقُل :"},{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَصَلِّ عَلى حُجَّتِكَ الْوَفِيِّ، وَوَلِيِّكَ الزَّكِيِّ، وَاَمينِكَ الْمُرْتَضى، وَصَفِيِّكَ الْهادي، وَصِراطِكَ الْمُسْتَقيمِ، وَالْجآدَّةِ الْعُظْمى، وَالطَّريقَةِ الْوُسْطى، نُورِ قُلُوبِ الْمُؤْمِنينَ، وَوَلِيِّ الْمُتَّقينَ، وَصاحِبِ اْلُمخْلَصينَ، اَللّـهُمَّ صَلِّ عَلى سَيِّدِنا مُحَمَّد وَاَهْلِ بَيْتِهِ، وَصَلِّ عَلى عَلِيِّ بْنِ مُحَمَّد الرّاشِدِ الْمَعْصُومِ مِنَ الزَّلَلِ، وَالطّاهِرِ مِنَ الْخَلَلِ، وَالْمُنْقَطِعِ اِلَيْكَ بِالاَْمَلِ، الْمَبْلُوِّ بِالْفِتَنِ، وَالُْمخْتَبَرِ بِاْلِمحَنِ، وَالْمُمْتَحَنِ بِحُسْنِ الْبَلْوى، وَصَبْرِالشَّكْوى، مُرْشِدِ عِبادِكَ وَبَرَكَةِ بِلادِكَ، وَمَحَلِّ رَحْمَتِكَ، ومُسْتَوْدَعِ حِكْمَتِكَ، وَالْقآئِدِ اِلى جَنَّتِكَ الْعالِمِ في بَرِيَّتِكَ، وَالْهادي في خَليقَتِكَ الَّذِي ارْتَضَيْتَهُ وَانْتَجَبْتَهُ وَاخْتَرْتَهُ لِمَقامِ رَسُولِكَ في اُمَّتِهِ، وَاَلْزَمْتَهُ حِفْظَ شَريعَتِهِ، فَاسْتَقَلَّ بِاَعْبآءِ الْوَصِيَّةِ ناهِضاً بِها، ومُضْطَلِعاً بِحَمْلِها، لَمْ يَعْثُرْ في مُشْكِل، وَلا هَفافي مُعْضِل، بَلْ كَشَفَ الْغُمَّةَ وَسَدَّ الْفُرْجَةَ وَاَدَّى الْمُفْتَرَضَ، اَللّـهُمَّ فَكَما اَقْرَرْتَ ناظِرَ نَبِيِّكَ بِهِ، فَرَقِّهِ دَرَجَتَهُ، وَاَجْزِلْ لَدَيْكَ مَثُوبَتَهُ، وَصَلِّ عَلَيْهِ وَبَلِّغْهُ مِنّا تَحِيَّةً وَسَلاماً، وَآتِنا مِنْ لَدُنْكَ في مُوالاتِهِ فَضْلاً وَاِحْساناً وَمَغْفِرَةً وَرِضْواناً، اِنَّكَ ذُو الْفَضْلِ الْعَظيمِ ."}],"preview":"المقام الاوّل","hasTranslate":false},{"id":"mf_ar_251","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"ثمّ تصلّي صلاة الزّيارة فاذا سلّمت فقُل :","blocks":[{"type":"Text","content":"يا ذَا الْقُدْرَةِ الْجامِعَةِ، وَالرَّحْمَةِ الْواسِعَةِ، وَالْمِنَنِ الْمُتَتابِعَةِ، وَالاْلاءِ الْمُتَواتِرَةِ، وَالاَْيادِى الْجَليلَةِ، وَالْمَواهِبِ الْجَزيلَةِ، صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد الصّادِقينَ، وَاَعْطِني سُؤْلي وَاجْمَعْ شَمْلي وَلُمَّ شَعْثي وَزَكِّ عَمَلي، وَلا تُزِ غْ قَلْبي بَعْدَ اِذْ هَدَيْتَني، وَلا تُزِلَّ قَدَمي، وَلا تَكِلْني اِلى نَفْسي طَرْفَةَ عَيْن اَبَداً، وَلا تُخَيِّبْ طَمَعي، وَلا تُبْدِ عَوْرَتي، وَلا تَهْتِكْ سِتْري، وَلا تُوحِشْني وَلا تُؤْيِسْني، وَكُنْ بى رَؤوفاً رَحيماً، وَاهْدِني وَزَكِّني وَطَهِّرْني وَصَفِّني وَاصْطَفِني وَخَلِّصْني وَاسْتَخْلِصْني وَاصْنَعْني وَاصْطَنِعْني، وَقَرِّبْني اِلَيْكَ وَلا تُباعِدْني مِنْكَ، وَالْطُفْ بي وَلا تَجْفُني، وَاَكْرِمْني وَلا تُهِنّي، وَمآ اَسْاَلُكَ فَلا تَحْرِمْني، وَما لا اَسْاَلُكَ فَاجْمَعْهُ لي بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ، وَاَسْاَلُكَ بِحُرْمَةِ وَجْهِكَ الْكَريمِ، وَبِحُرْمَةِ نَبِيِّكَ مُحَمَّد صَلَواتُكَ عَلَيْهِ وَآلِهِ، وَبِحُرْمَةِ اَهْلِ بَيْتِ رَسُولِكَ اَميرِ الْمُؤْمِنينَ عَلِيٍّ وَالْحَسَنِ وَالْحُسَيْنِ وَعَلِيٍّ وَمُحَمَّد وَجَعْفَر ومُوسى وَعَلَيٍّ وَمُحَمَّد وَعَلِىٍّ وَالْحَسَنِ وَالْخَلَفِ الْباقي صَلَواتُكَ وَبَرَكاتُكَ عَلَيْهِمِ اَنْ تُصَّلِيَ عَلَيْهِمْ اَجْمَعينَ، وَتُعَجِّلَ فَرَجَ قائِمِهِمْ بِاَمْرِكَ، وَتَنْصُرَهُ وَتَنْتَصِرَ بِهِ لِدينِكَ وَتَجْعَلَني فى جُمْلَةِ النّاجينَ بِهِ، وَالُْمخْلِصينَ في طاعَتِهِ، وَاَسْاَلُكَ بِحَقِّهِمْ لَمَّا اسْتَجَبْتَ لي دَعْوَتي وَقَضَيْتَ لي حاجَتي وَاَعْطَيْتَني سُؤْلي وَكَفَيْتَني ما اَهَمَّني مِنْ اَمْرِ دُنْيايَ وَآخِرَتي يا اَرْحَمَ الرّاحِمينَ، يا نُورُ يا بُرْهانُ يا مُنيرُ يا مُبَينُ، يا رَبِّ اكْفِني شَرَّ الشُّرُورِ وَآفاتِ الدُّهُورِ، وَاَسْاَلُكَ النَّجاةَ يَوْمَ يُنْفَخُ فِي الصُّورِ ."}],"preview":"يا ذَا الْقُدْرَةِ الْجامِعَةِ، وَالرَّحْمَةِ الْواسِعَةِ، وَالْمِنَنِ الْمُتَتابِعَةِ، وَالاْلاءِ الْمُتَواتِرَةِ، وَالاَْيادِى الْجَليلَةِ، وَالْمَواهِبِ الْجَزيلَةِ، صَلِّ عَلى","hasTranslate":false},{"id":"mf_ar_252","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"وادعُ بما شئت واكثر مِن قولك :","blocks":[{"type":"Text","content":"يا عُدَّتي عِنْدَ الْعُدَدِ، وَيا رَجائي وَالْمُعْتَمَدَ، وَيا كَهْفي وَالسَّنَدَ، يا واحِدُ يا اَحَدُ، وَيا قُلْ هُوَ اللهُ اَحَدٌ، اَسْاَلُكَ الّلهُمَّ بِحَقِّ مَنْ خَلَقْتَ مِنْ خَلْقِكَ وَلَمْ تَجْعَلْ في خَلْقِكَ مِثْلَهُمْ اَحَداً صَلِّ عَلى جَماعَتِهِمْ، وَافْعَلْ بي كَذا وَكَذا ."},{"type":"Text","content":"وسل حوائجك عوض هذه الكلمة فقد روى عنه صلوات الله عليه انّه قال : انّني دعوت الله عزّ وجلّ أن لا يخيب مَن دعا به في مشهدي بعدي ."}],"preview":"يا عُدَّتي عِنْدَ الْعُدَدِ، وَيا رَجائي وَالْمُعْتَمَدَ، وَيا كَهْفي وَالسَّنَدَ، يا واحِدُ يا اَحَدُ، وَيا قُلْ هُوَ اللهُ اَحَدٌ، اَسْاَلُكَ الّلهُمَّ بِحَقِّ مَنْ خَلَقْتَ مِنْ","hasTranslate":false},{"id":"mf_ar_253","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"زيارة الامام الحسن العسكري (عليه السلام)","blocks":[{"type":"Text","content":"روى الشّيخ بسند معتبر عنه (عليه السلام) قال : قبري بسرّ من رأى أمان لاهل الجانبين وقد فسّر المجلسي الاوّل كلمة أهل الجانبين بالشّيعة وأهل السّنة وقال : انّ فضله (عليه السلام) يعمّ الموالي والمُعادي كما انّ قبر الكاظمين أمان لبغداد .. الخ ."},{"type":"Text","content":"وقال السّيد ابن طاوُس : اذا أردت زيارة أبي محمّد الحسن العسكري (عليه السلام) فليكن بعد عمل جميع ما قدّمناه في زيارة أبيه الهادي (عليه السلام) ثمّ قف على ضريحه (عليه السلام) وقُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا مَوْلايَ يا اَبا مُحَمَّد الْحَسَنَ بْنَ عَلِيٍّ الْهادِيَ الْمُهْتَدِيَ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَلسَّلامُ عَلَيْكَ يا وَلِيَّ اللهِ وَابْنَ اَوْلِيآئِهِ، اَلسَّلامُ عَلَيْكَ يا حُجَّةَ اللهِ وَابْنَ حُجَجِهِ، اَلسَّلامُ عَلَيْكَ يا صَفِيَّ اللهِ وَابْنَ اَصْفِيآئِهِ، اَلسَّلامُ عَلَيْكَ يا خَليفَةَ اللهِ وَابْنَ خُلَفائِهِ وَاَبا خَليفَتِهِ، اَلسَّلامُ عَلَيْكَ يَا بْنَ خاتَمِ النَّبِيّينَ، اَلسَّلامُ عَلَيْكَ يَا بْنَ سَيِّدِ الْوَصِيّينَ، اَلسَّلامُ عَلَيْكَ يَا بْنَ اَميرِ الْمُؤْمِنينَ، اَلسَّلامُ عَلَيْكَ يَا بْنَ سَيِّدَةِ نِساءِ الْعالَمينَ، اَلسَّلامُ عَلَيْكَ يَا ابْنَ الاَْئِّمَةِ الْهادينَ، اَلسَّلامُ عَلَيْكَ يَا بْنَ الاَْوْصِياءِ الرّاشِدينَ، اَلسَّلامُ عَلَيْكَ يا عِصْمَةَ الْمُتَّقينَ، اَلسَّلامُ عَلَيْكَ يا اِمامَ الْفائِزينَ، اَلسَّلامُ عَلَيْكَ يا رُكْنَ الْمُؤْمِنينَ، اَلسَّلامُ عَلَيْكَ يا فَرَجَ الْمَلْهُوفينَ، اَلسَّلامُ عَلَيْكَ يا وارِثَ الاَْنْبِياءِ الْمُنْتَجَبينَ، اَلسَّلامُ عَلَيْكَ يا خازِنَ عِلْمِ وَصِيِّ رَسُولِ اللهِ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الدّاعي بِحُكْمِ اللهِ، اَلسَّلامُ عَلَيْكَ اَيُّهَا النّاطِقُ بِكِتابِ اللهِ، اَلسَّلامُ عَلَيْكَ يا حُجَّةَ الْحُجَجِ، اَلسَّلامُ عَلَيْكَ يا هادِيَ الاُْمَمِ، اَلسَّلامُ عَلَيْكَ يا وَلِيَّ النِّعَمِ، اَلسَّلامُ عَلَيْكَ يا عَيْبَةَ الْعِلْمِ، اَلسَّلامُ عَلَيْكَ يا سَفينَةَ الْحِلْمِ، اَلسَّلامُ عَلَيْكَ يا اَبَا الاِْمامِ الْمُنْتَظَرِ، الظّاهِرَةِ لِلْعاقِلِ حُجَّتُهُ، وَالثّابِتَةِ فِي الْيَقينِ مَعْرِفَتُهُ، الُْمحْتَجَبِ عَنْ اَعْيُنِ الظّالِمينَ، وَالْمُغَيِّبِ عَنْ دَوْلَةِ الْفاسِقينَ، وَالْمُعيدِ رَبُّنا بِهِ الاِْسْلامَ جَديداً بَعْدَ الاْنْطِماسِ، وَالْقُرْآنَ غَضّاً بَعْدَ الاْنْدِراسِ، اَشْهَدُ يامَوْلايَ اَنَّكَ اَقَمْتَ الصّلاةَ، وَآتَيْتَ الزَّكاةَ، وَاَمَرْتَ بِالْمَعْرُوفِ، وَنَهَيْتَ عَنِ الْمُنْكَرِ، وَدَعَوْتَ اِلى سَبيلِ رَبِّكَ بِالْحِكْمَةِ وَالْمَوْعِظَةِ الْحَسَنَةِ، وَعَبَدْتَ اللهَ مُخْلِصاً حَتّى اَتاكَ الْيَقينُ، اَسْأَلُ اللهَ بِالشَّأنِ الَّذي لَكُمْ عِنْدَهُ اَنْ يَتَقَبَّلَ زِيارَتي لَكُمْ، وَيَشْكُرَ سَعْيي اِلَيْكُمْ، وَيَسْتَجيبَ دُعائي بِكُمْ، وَيَجْعَلَني مِنْ اَنْصارِ الْحَقِّ وَاَتْباعِهِ وَاَشْياعِهِ وَمَواليهِ وَمُحِبّيهِ، وَالسَّلامُ عَلَيْكَ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ ."},{"type":"Text","content":"ثمّ قبّل ضريحه وضع خدّك الايمن عليه ثمّ الايسر وقُل :"},{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلى سَيِّدِنا مُحَمَّد وَاَهْلِ بَيْتِهِ، وَصَلِّ عَلى الْحَسَنِ بْنِ عَلِيٍّ الْهادِي اِلى دينِكَ، وَالدّاعي اِلى سَبيلِكَ، عَلَمِ الْهُدى، وَمَنارِ التُّقى، وَمَعْدِنِ الْحِجى، وَماْوَى النُّهى، وَغَيْثِ الْوَرى، وَسَحابِ الْحِكْمَةِ، وَبَحْرِ الْمَوْعِظَةِ، وَوارِثِ الاَئِمَّةِ وَالشَّهيدِ عَلىَ الاُْمَّةِ، الْمَعْصُومِ الْمُهَذَّبِ، وَالْفاضِلِ الْمُقَرَّبِ، وَالْمُطَهَّرِ مِنَ الرِّجْسِ، الَّذى وَرَّثْتَهُ عِلْمَ الْكِتابِ، وَاَلْهَمْتَهُ فَصْلَ الْخِطابِ، وَنَصَبْتَهُ عَلَماً لاَِهْلِ قِبْلَتِكَ، وَقَرَنْتَ طاعَتَهُ بِطاعَتِكَ، وَفَرَضْتَ مَوَدَّتَهُ عَلى جَميعِ خَليقَتِكَ، اَللّـهُمَّ فَكَما اَنابَ بِحُسْنِ الاِْخْلاصِ في تَوْحيدِكَ، وَاَرْدى مَنْ خاضَ في تَشْبيهِكَ، وَحامى عَنْ اَهْلِ الاْيمانِ بِكَ، فَصَلِّ يا رَبِّ عَلَيْهِ صَلاةً يَلْحَقُ بِها مَحَلَّ الْخاشِعينَ وَيَعْلُو فِي الْجَنَّةِ بِدَرَجَةِ جَدِّهِ خاتَمِ النَّبِيّينَ، وَبَلِّغْهُ مِنّا تَحِيَّةً وَسَلاماً، وَآتِنا مِنْ لَدُنْكَ في مُوالاتِهِ فَضْلاً وَاِحْساناً وَمَغْفِرَةً وَرِضْواناً، اِنَّكَ ذُو فَضْل عَظيم وَمَنٍّ جَسيم ."},{"type":"Text","content":"ثمّ تصلّي صلاة الزّيارة ، فاذا فرغت قُل :"},{"type":"Text","content":"يا دائِمُ يا دَيْمُومُ، يا حَيُّ يا قَيُّومُ، يا كاشِفَ الْكَرْبِ وَالْهَمِّ، وَيا فارِجَ الْغَمِّ، وَيا باعِثَ الرُّسُلِ، وَيا صادِقَ الْوَعْدِ، وَيا حَيُّ لا اِلـهَ اِلاّ اَنْتَ، اَتَوَسَّلُ اِلَيْكَ بِحَبيبِكَ مُحَمَّد وَوَصِيِّهِ عَلِيٍّ ابْنِ عَمِّهِ، وَصِهْرِهِ عَلَى ابْنَتِهِ اللَّذيْنِ خَتَمْتَ بِهِمَا الشَّرايِعَ، وَفَتَحْتَ بِهِمَا التَّأويلَ وَالطَّلايِـعَ، فَصَلِّ عَلَيْهِما صَلاةً يَشْهَدُ بِهَا الاَْوَّلُونَ وَالاْخِرُونَ وَيَنْجُوبِهَا الاَْوْلِياءُ وَالصّالِحُونَ، وَاَتَوَسَّلُ اِلَيْكَ بِفاطِمَةَ الزَّهْراءِ والِدَةِ الاَْئِّمَةِ الْمَهْدِيّينَ وَسَيِّدَةِ نِساءِ الْعالَمينَ، الْمُشَفَّعَةِ في شيعَةِ اَوْلادِهَا الطَّيِّبينَ، فَصَلِّ عَلَيْها صَلاةً دائِمَةً اَبَدَ الاْبِدينَ وَدَهْرَ الدّاهِرينَ، وَاَتَوَسَّلُ اِلَيْكَ بِالْحَسَنِ الرَّضِيِّ الطّاهِرِالزَّكِيِّ وَالْحُسَينِ الْمَظْلُومِ الْمَرْضِيِّ الْبَرِّ التَّقِيِّ سَيِّدَيْ شَبابِ اَهْلِ الْجَنَّةِ، الاِْمامَيْنِ الْخَيِّرَيْنِ الطَّيِّبَيْنِ التَّقِيَّيْنِ النَّقِيَّيْنِ الطّاهِرَيْنِ الشَّهيدَيْنِ الْمَظْلُومَيْنِ الْمَقْتُولَيْنِ، فَصَلِّ عَلَيْهِما ما طَلَعَتْ شَمْسٌ وَما غَرَبَتْ، صَلاةً مُتَوالِيَةً مُتَتالِيَةً، وَاَتَوَسَّلُ اِلَيْكَ بِعَلِيِّ بْنِ الْحُسَيْنِ سَيِّدِالْعابِدينَ الَْمحْجُوبِ مِنْ خَوْفِ الظّالِمينَ، وَبِمُحَمَّدِ بْنِ عَلِيٍّ الْباقِرِ الطّاهِرِ النُّورِ الزّاهِرِ، الاِْمامَيْنِ السَّيِّدَيْنِ مِفْتاحَيِ الْبَرَكاتِ وَمِصْباحَيِ الظُّلُمُاتِ فَصَلِّ عَلَيْهِما ما سَرى لَيْلٌ وَما اَضآءَ نَهارٌ، صَلاةً تَغْدُو وَتَرُوحُ، وَاَتَوَسَّلُ اِلَيْكَ بِجَعْفَرِ بْنِ مُحَمَّد الصّادِقِ عَنِ اللهِ وَالنّاطِقِ في عِلْمِ اللهِ، وَبِمُوسَى بْنِ جَعْفَر الْعَبْدِ الصّالِحِ في نَفْسِهِ وَاْلَوصِيِّ النّاصِحِ، الاِْمامَيْنِ الْهادِيَيْنِ الْمَهْدِيَّيْنِ الْوافِيَيْنِ الْكافِيَيْنِ، فَصَلِّ عَلَيْهِما ما سَبَّحَ لَكَ مَلَكٌ وَتَحَرَّكَ لَكَ فَلَكٌ، صَلاةً تُنْمى وَتَزيدُ وَلا تَفْنى وَلا تَبيدُ، وَاَتَوَسَّلُ اِلَيْكَ بِعَلِىِّ بْنِ مُوسَى الرِّضا، وَبِمُحَّمَدِ بْنِ عَلِيٍّ الْمُرْتَضَى الاِْمامَيْنِ الْمُطَهَّرَيْنِ الْمُنْتَجَبَيْنِ، فَصَلِّ عَلَيْهِما ما اَضاءَ صُبْحٌ وَدامَ، صَلاةً تُرَقّيهِما اِلى رِضْوانِكَ فِي الْعِلِّيّينَ مِنْ جِنانِكَ، وَاَتَوَسَّلُ اِلَيْكَ بِعَليِّ بْنِ مُحَمَّد الرّاشِدِ، وَالْحَسَنِ بْنِ عَلِيٍّ الْهادِي، الْقائِمَيْنِ بِاَمْرِ عِبادِكَ الُْمخْتَبَرَيْنِ بِالِْمحَنِ الْهايِلَةِ وَالصّابِرَيْنِ فِي الاِْحَنِ الْمائِلَةِ، فَصَلِّ عَلَيْهِما كِفاءَ اَجْرِ الصّابِرينَ وَاِزاءَ ثَوابِ الْفائِزينَ، صَلاةً تُمَهِّدُ لَهُمَا الرِّفْعَةَ، وَاَتَوَسَّلُ اِلَيْكَ يا رَبِّ بِاِمامِنا وَمُحَقِّقِ زَمانِنَا، الْيَوْمِ الْمَوْعُودِ وَالشّاهِدِ الْمَشْهُودِ، وَالنُّورِ الاَْزْهَرِ وَالْضِّياءِ الاَْنْوَرِ، الْمَنْصُورِ بِالْرُّعْبِ وَالْمُظَفَّرِ بِالسَّعادَةِ، فَصَلِّ عَلَيْهِ عَدَدَ الَّثمَرِ وَاَوْراقِ الشَّجَرِ وَاَجْزاءِ الْمَدَرِ وَعَدَدَ الشَّعْرِ وَالْوَبَرِ، وَعَدَدَ ما اَحاطَ بِهِ عِلْمُكَ وَاَحْصاهُ كِتابُكَ، صَلاةً يَغْبِطُهُ بَها الاَْوَّلُونَ وَالاْخِروُنَ اَللّـهُمَّ وَاحْشُرْنا في زُمْرَتِهِ، وَاحْفَظْنا عَلى طاعَتِهِ، وَاحْرُسْنا بِدَوْلَتِهِ، وَاَتْحِفْنا بِوِلايَتِهِ، وَانْصُرْنا عَلى اَعْدائِنا بِعِزَّتِهِ، وَاجْعَلْنا يارَبِّ مِنَ التَّوّابينَ يا اَرْحَمَ الرّاحِمينَ، اَللّـهُمَّ وَاِنَّ اِبْليسَ الْمُتَمَرِّدَ الّلَّعينَ قَد اسْتَنْظَرَكَ لاِِغْواءِ خَلْقِكَ فَاَنْظَرْتَهُ، وَاسْتَمْهَلَكَ لاِِضْلالِ عَبيدِكَ فَامْهَلْتَهُ، بِسابِقِ عِلْمِكَ فيهِ، وَقَدْ عَشَّشَ وَكَثُرَتْ جُنُودُهُ، وَازْدَحَمَتْ جُيُوشُهُ، وَانْتَشَرَتْ دُعاتُهُ في اَقْطارِ الاَْرْضِ، فَاَضَلُّوا عِبادَكَ وَاَفْسَدُوا دينَكَ، وَحَرَّفُوا الْكَلِمَ عَنْ مَواضِعِهِ، وَجَعَلُوا عِبادَكَ شِيَعاً مُتَفَرِّقينَ وَاَحْزاباً مُتَمَرِّدينَ، وَقَدْ وَعَدْتَ نَقْضَ بُنْيانِهِ وَتَمْزيقَ شَأنِهِ، فَاَهْلِكْ اَوْلادَهُ وَجُيُوشَهُ، وَطَهِّرْ بِلادَكَ مِنِ اخْتِراعاتِهِ وَاخْتِلافاتِهِ، وَاَرِحْ عِبادَكَ مِنْ مَذاهِبِهِ وَقِياساتِهِ، وَاجْعَلْ دائِرَةَ السَّوْءِ عَلَيْهِمْ، وَابْسُطْ عَدْلَكَ وَاَظْهِرْ دينَكَ، وَقَوِّ اَوْلِيآءَكَ وَاَوْهِنْ اَعْدآءَكَ وَاَوْرِثْ دِيارَ اِبْليسَ وَدِيارَ اَوْلِيائِهِ اَوْلِياءَكَ وَخَلِّدْهُمْ فِي الْجَحيمِ وَاَذِقْهُمْ مِنْ الْعَذابِ الاَْليمِ، وَاجْعَلْ لَعائِنَكَ الْمُسْتَوْدَعَةَ في مَناحِسِ الْخِلْقَةِ وَمَشاويهِ الْفِطْرَةِ دائِرَةً عَلَيْهِمْ وَمُوَكَّلَةً بِهِمْ وَجارِيَةً فيهِمْ كُلَّ صَباح وَمَسآء وَغُدُوّ وَرَواح، رَبَّنا آتِنا فِي الدُّنْيا حَسَنَةً وَفِي الاْخِرَةِ حَسَنَةً وَقِنا بِرَحْمَتِكَ عَذابَ النّارِ يا اَرْحَمَ الرّاحِمينَ ."},{"type":"Text","content":"ثمّ ادعُ بما تحبّ لنفسك ولاخوانك ثمّ تزُور مليكة الدّنيا والاخرة أمّ القائم، (عليها السلام) وقبرها خلف ضريح مولانا الحسن العسكري (عليه السلام) ، فتقول :"},{"type":"Text","content":"اَلسَّلامُ عَلى رَسُولِ اللهِ صَلَّى اللهُ عَلَيْهِ وَآلِهِ الصّادِقِ الاَْمينِ، اَلسَّلامُ عَلى مَوْلانا اَميرِ الْمُؤْمِنينَ، اَلسَّلامُ عَلَى الاَْئِمَّةِ الطّاهِرينَ الْحُجَجِ الْمَيامينِ، اَلسَّلامُ عَلى والِدَةِ الاِْمامِ وَالْمُودَعَةِ اَسْرارَ الْمَلِكِ الْعَلاّمِ، وَالْحامِلَةِ لاَِشْرَفِ الاَْنامِ، اَلسَّلامُ عَلَيْكِ اَيَّتُهَا الصِّدّيقَةُ الْمَرضِيَّةُ، اَلسَّلامُ عَلَيْكِ يا شَبيهَةَ اُمِّ مُوسى وَابْنَةَ حَوارِيِّ عيسى، اَلسَّلامُ عَلَيْكِ اَيَّتُهَا التَّقِيَّةُ النَّقِيَّةُ، اَلسَّلامُ عَلَيْكِ اَيَّتُهَا الرَّضِيَّةُ الْمَرْضِيَّةُ، اَلسَّلامُ عَلَيْكِ اَيَّتُهَا اْلمَنْعُوتَةُ فِي الاِْنْجيلِ الَْمخْطُوبَةُ مِنْ رُوحِ اللهِ الاَْمينِ، وَمَنْ رَغِبَ في وُصْلَتِها مُحَمَّدٌ سَيِّدُ الْمُرْسَلينَ، وَالْمُسْتَوْدَعَةُ اَسْرارَ رَبِّ الْعالَمينَ، اَلسَّلامُ عَلَيْكِ وَعَلى آبائِكِ الْحَوارِيّينَ، اَلسَّلامُ عَلَيْكِ وَعَلى بَعْلِكِ وَوَلَدِكِ، اَلسَّلامُ عَلَيْكِ وَعَلى رُوحِكِ وَبَدَنِكِ الطّاهِرِ، اَشْهَدُ اَنَّكِ اَحْسَنْتِ الْكَفالَةَ، وَاَدَّيْتِ الاَْمانَةَ، وَاجْتَهَدْتِ في مَرْضاتِ اللهِ، وَصَبَرْتِ في ذاتِ اللهِ، وَحَفِظْتِ سِرَّ اللهِ، وَحَمَلْتِ وَلِىَّ اللهِ، وَبالَغْتِ في حِفْظِ حُجَّةِ اللهِ، وَرَغِبْتِ في وُصْلَةِ اَبْناءِ رَسُولِ اللهِ، عارِفَةً بِحَقِّهِمْ، مُؤْمِنَةً بِصِدْقِهِمْ، مُعْتَرِفَةً بِمَنْزِلَتِهِمْ، مُسْتَبْصِرَةً بِاَمْرِهِمْ، مُشْفِقَةً عَلَيْهِمْ، مُؤْثِرَةً هَواهُمْ، وَاَشْهَدُ اَنَّكِ مَضَيْتِ عَلى بَصيرَة مِنْ اَمْرِكِ، مُقْتَدِيَةً بِالصّالِحينَ، راضِيَةً مَرْضِيَّةً تَقِيَّةً نَقِيَّةً زَكِيَّةً، فَرَضِيَ اللهُ عَنْكِ وَاَرْضاكِ، وَجَعَلَ اْلجَنَّةَ مَنْزِلَكِ وَمَأواكِ فَلَقَدْ اَوْلاكِ مِنَ الْخَيْراتِ ما اَوْلاكِ، وَاَعْطاكِ مِنَ الشَّرَفِ ما بِهِ اَغْناكِ، فَهَنّاكِ اللهُ بِما مَنَحَكِ مِنَ الْكَرامَةِ وَأمْرَاَكِ ."}],"preview":"روى الشّيخ بسند معتبر عنه (عليه السلام) قال : قبري بسرّ من رأى أمان لاهل الجانبين وقد فسّر المجلسي الاوّل كلمة أهل الجانبين بالشّيعة وأهل السّنة وقال : انّ فضله (عليه السلام) يعمّ","hasTranslate":false},{"id":"mf_ar_254","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"ثمّ ترفع رأسك وتقول :","blocks":[{"type":"Text","content":"اَللّـهُمَّ اِيّاكَ اعْتَمَدْتُ، وَلِرِضاكَ طَلَبْتُ، وَبِاَوْلِيائِكَ اِلَيْكَ تَوَسَّلْتُ، وَعَلى غُفْرانِكَ وَحِلْمِكَ اتَّكَلْتُ، وَبِكَ اعْتَصَمْتُ، وَبِقَبْرِ اُمِّ وَلِيِّكَ لُذْتُ، فَصَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَانْفَعْني بِزِيارَتِها، وَثَبِّتْني عَلى مَحَبَّتِها، وَلا تَحْرِمْني شَفاعَتَها، وَشَفاعَةَ وَلَدِها، وَارْزُقْني مُرافَقَتَها، وَاحْشُرْني مَعَها وَمَعَ وَلَدِها كَما وَفَّقْتَني لِزِيارَةِ وَلَدِها وَزِيارَتِها، اَللّـهُمَّ اِنّي اَتَوَجَّهُ اِلَيْكَ بِالاَْئِمَّةِ الطّاهِرينَ، وَاَتَوَسَّلُ اِلَيْكَ بِالْحُجَجِ الْمَيامينِ مِنْ آلِ طه وَيس، اَنْ تُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد الطَّيِّبينَ، وَاَنْ تَجْعَلَنى مِنَ الْمُطْمَئِنّينَ الْفائِزينَ الْفَرِحينَ الْمُسْتَبْشِرينَ، الَّذينَ لا خَوْفٌ عَلَيْهِمْ وَلا هُمْ يَحْزَنُونَ وَاجْعَلْني مِمَّنْ قَبِلْتَ سَعْيَهُ، وَيَسَّرْتَ اَمْرَهُ، وَكَشَفْتَ ضُرَّهُ، وَآمَنْتَ خَوْفَهُ، اَللّـهُمَّ بِحَقِّ مُحَمَّد وَآلِ مُحَمَّد، صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَلا تَجْعَلْهُ آخِرَ الْعَهْدِ مِنْ زِيارَتي اِيّاها، وَاْرزُقْني الْعَوْدَ اِلَيْها اَبَداً ما اَبْقَيْتَني، وَاِذا تَوَفَّيْتَني فَاحْشُرْني في زُمْرَتِها، وَاَدْخِلْني في شَفاعَةِ وَلَدِها وَشَفَاعَتِها، وَاغْفِرْ لي وَلِوالِدَيَّ وَلِلْمُؤْمِنينَ وَالْمُؤْمِناتِ، وَآتِنا فِي الدُّنْيا حَسَنَةً وَفِي الاْخِرَةِ حَسَنَةً وَقِنا بِرَحْمَتِكَ عَذابَ النّارِ، وَاَلسَّلامُ عَلَيْكُمْ يا ساداتي وَرَحْمَةُ اللهِ وَبَرَكاتُهُ ."},{"type":"AboutText","content":"أقول : روى عن زيد الشّحّام ، قال : قلت للصّادق (عليه السلام) : ما لمن زار واحداً منكم ؟ قال : كمن زار رسول الله (صلى الله عليه وآله وسلم)، وقد أسلفنا الرّواية عن الصّادق (عليه السلام) قال : من زار اماماً مفترض الطّاعة وصلّى عنده أربع ركعات كتبت له حجّة وعمرة. وقد ذكرنا في كتاب هديّة الزّائرين فضائل حكيمة بنت الامام محمّد التّقي (عليه السلام)وقبرها الشّريف ممّا يلي رجلي العسكريّين (عليهما السلام) مُتّصل بضريحيهما وقلنا هناك انّ كتب الزّيارة لم تخصها بزيارة خاصة مع ما لها من رفيع المنزلة، فينبغي أن تُزار بالزيارة العامّة لاولاد الائمة (عليهم السلام) أو تُزار بما ورد لزيارة عمّتها الكريمة فاطِمة بنت موسى)عليه السلام)بأن تستقبل القبلة وتقول :"},{"type":"Text","content":"اَلسَّلامُ عَلى آدَمَ صَفْوَةِ اللهِ، اَلسَّلامُ عَلى نُوح نَبِيِّ اللهِ، اَلسَّلامُ عَلى اِبْراهيَم خَليلِ اللهِ، اَلسَّلامُ عَلى مُوسى كَليمِ اللهِ، اَلسَّلامُ عَلى عيسى رُوحِ اللهِ، اَلسَّلامُ عَلَيْكَ يا رَسُولَ اللهِ، اَلسَّلامُ عَلَيْكَ يا خَيْرَ خَلْقِ اللهِ، اَلسَّلامُ عَلَيْكَ يا صَفِىَّ اللهِ، اَلسَّلامُ عَلَيْكَ يا مُحَمَّدَ بْنَ عَبْدِ اللهِ خاتَمِ النَّبِيّينَ، اَلسَّلامُ عَلَيْكَ يا اَميرَ الْمُؤْمِنينَ عَلِيَّ بْنَ أبي طالِب وَصِيَّ رَسُولِ اللهِ، اَلسَّلامُ عَلَيْكِ يا فاطِمَةُ سَيِّدَةُ نِساءِ الْعالَمينَ، اَلسَّلامُ عَلَيْكُما يا سِبْطَيِ الرَّحْمَةِ وَسَيَّدَيْ شَبابِ اَهْلِ الْجَنَّةِ، اَلسَّلامُ عَلَيْكَ يا عَلِيَّ بْنَ الْحُسَيْنِ سَيِّدَ الْعابِدينَ وَقُرَّةَ عَيْنِ النّاظِرينَ، اَلسَّلامُ عَلَيْكَ يا مُحَمَّدَ بْنَ عَلِيٍّ باقِرَ الْعِلْمِ بَعْدَ النَّبِىِّ، اَلسَّلامُ عَلَيْكَ يا جَعْفَرَ بْنَ مُحَمَّد الصّادِقَ الْبارَّ الاَْمينَ، اَلسَّلامُ عَلَيْكَ يا مُوسَى بْنَ جَعْفَر الطّاهِرَ الْطُّهْرَ، اَلسَّلامُ عَلَيْكَ يا عَلِيَّ بْنَ مُوسَى الرِّضَا الْمُرْتَضى، اَلسَّلامُ عَلَيْكَ يا مُحَمَّدَ بْنَ عَلِىٍّ التَّقِىَّ، اَلسَّلامُ عَلَيْكَ يا عَلِيَّ بْنَ مُحَمَّد النِّقِيَّ النّاصِحَ الاَْمينَ، اَلسَّلامُ عَلَيْكَ يا حَسَنَ بْنَ عَلِيٍّ اَلسَّلامُ عَلَى الْوَصِىِّ مِنْ بَعْدِهِ، اَللّـهُمَّ صَلِّ عَلى نُورِكَ وَسِراجِكَ وَوَلِيِّ وَلِيِّكَ وَوَصِى،ِّ وَصِيِّكَ وَحُجَّتِكَ عَلى خَلْقِكَ، اَلسَّلامُ عَلَيْكِ يا بِنْتَ رَسُولِ اللهِ، السَّلامُ عَلَيْكَ يا بِنْتَ فاطِمَةَ وَخَديجَةَ، السَّلامُ عَلَيْكِ يا بِنْتَ اَميرِ الْمُؤمِنينَ، السَّلامُ عَلَيْكِ يا بِنْتَ الْحَسَنِ وَالْحُسَيْنِ، السَّلامُ عَلَيْكِ يا بِنْتَ وَلِيِّ اللهِ، السَّلامُ عَلَيْكِ يا اُخْتَ وَلِيِّ اللهِ، السَّلامُ عَلَيْكِ يا عَمَّةَ وَلِيِّ اللهِ، السَّلامُ عَلَيْكِ يا بِنْتَ مُحَمَّدِ بْنِ عَلِيٍّ التَّقِيِّ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، السَّلامُ عَلَيْكِ عَرَّفَ اللهُ بَيْنَنا وَبَيْنَكُمْ في الْجَنَّةِ، وَحَشَرَنا في زُمْرَتِكُمْ وَاَوْرَدَنا حَوْضَ نَبِيِّكُمْ، وَسَقانا بِكَأسِ جَدِّكُمْ مِنْ يَدِ عَلِيِّ بْنِ أبي طالِب صَلَواتُ اللهِ عَلَيكُمْ اَسْأَلُ اللهَ اَنْ يُرِيَنا فيكُمُ السُّرُورَ وَالْفَرَجَ، وَاَنْ يَجْمَعَنا وَاِيّاكُمْ فى زُمْرَةِ جَدِّكُمْ مُحَمَّد صَلَّى اللهُ عَلَيْهِ وَآلِهِ، وَاَنْ لا يَسْلُبَنا مَعْرِفَتَكُمْ اِنَّهُ وَلِيٌّ قَديرٌ، اَتَقَرَّبُ اِلَى اللهِ بِحُبِّكُمْ وَالْبَراءَةِ مِنْ اَعْدائِكُمْ، وَالتَّسْليمِ اِلَى اللهِ راضِياً بِهِ غَيْرَ مُنْكِر وَلا مُسْتَكْبِر، وَعَلى يَقينِ ما اَتى بِهِ مُحَمَّدٌ، وَ بِهِ راض نَطْلُبُ بِذلِكَ وَجْهَكَ يا سَيِّدي اَللّـهُمَّ وَرِضاكَ وَالدّارَ الاْخِرَةَ، يا حَكيمَةُ اشْفَعي لي فِي الْجَنَّةِ فَاِنَّ لَكِ عِنْدَ اللهِ شَأناً مِنَ الشَّأن،ِ اَللّـهُمَّ اِنّى اَسْاَلُكَ اَنْ تَخْتِمَ لي بِالسَّعادَةِ فَلا تَسْلُبْ مِنّي ما اَنَا فيهِ، وَلا حَوْلَ وَلا قُوَّةَ اِلّا بِاللهِ الْعَلِيِّ الْعَظيمِ، اَللّـهُمَّ اسْتَجِبْ لَنا وَتَقَبَّلْهُ بِكَرَمِكَ وَعِزَّتِكَ وَبِرَحْمَتِكَ وَعافِيَتِكَ، وَصَلَّى اللهُ عَلى مُحَمَّد وَآلِهِ اَجْمَعينَ وَسَلَّمَ تَسْليماً يا اَرْحَمَ الرّاحِمينَ ."},{"type":"AboutText","content":"أقول : عند قبر العسكريّين (عليهما السلام) على المشهور قبُور عصبة من السادة العظام منهم حسين ابن الامام علي النّقي (عليه السلام)، وانّي لم أقف على حال الحسين هذا وقوفاً، ويبدو لي انّه من أعاظم السّادة واجلاّئهم ، فقد استفدت من بعض الاحاديث انّه كان يعبّر عن مولانا الامام الحسن العسكريّ (عليه السلام) وأخيه الحسين هذا بالسّبطين تشبيهاً لهما بسبطي نبيّ الرحمة جدّيهما الامامين الحسن والحسين (عليهما السلام) ."},{"type":"Text","content":"وقد ورد في حديث أبي الطّيب انّ صوت الحجّة صلوات الله عليه كان يشبه صوت الحسين .. وقد قال والفقيه المحدّث الحكيم السّيد أحمد الاردكاني اليزدي في كتاب شجرة الاولياء عند ذكره أولاد الامام عليّ النّقي (عليه السلام) : انّ ابنه الحسين كان من الزّهاد والعبّاد وكان يقرّ لاخيه بالامامة، ولعلّ المتتبّع البصير يعثر على غير ما وقفنا عليه ممّا يؤمى الى فضله وجلاله ."},{"type":"AboutText","content":"واعلم ايضاً انّ للسّيد محمّد ابن الامام عليّ النّقي (عليه السلام) مزار مشهور قرب قرية البلد، وهو معروف بالفضل والجلال وبما يبديه من الكرامات الخارقة للعادات، ويتشرّف زيارته عامّة الخلايق ينذرُون له النّذر ويهدون اليه الهدايا الكثيرة ويسألون عنده حوائجهم والعرب في تلك المنطقة تهابه وتخشاه وتحسب له الحساب ."},{"type":"Text","content":"وقد برز منه كما يحكى كرامات كثيرة لا يسع المقام ذكرها، ويكفيه فضلاً وشرفاً انّه كان أهلاً للامامة وكان أكبر أولاد الامام الهادي (عليه السلام) وقد شقّ جيبه في عزائه الامام الحسن العسكري (عليه السلام)، وكان شيخنا ثقة الاسلام النّوري نوّر الله مرقده يعتقد في زيارته اعتقاداً راسخاً وهو قد سعى لتعمير بقعته الشّريفة وضريحه وكتب على ضريحه الشّريف : هذا مرقد السّيد الجليل أبي جعفر محمّد ابن الامام أبي الحسن عليّ الهادي (عليه السلام) عظيم الشّأن ، جليل القدر ، كانت الشّيعة تزعم انّه الامام بعد أبيه (عليه السلام) ، فلمّا توفي نصّ أبوه على أخيه أبي محمّد الزّكي (عليه السلام) وقال له : أحدث لله شكراً فقد أحدث فيك أمراً، خلّفه أبوه في المدينة طفلاً وقدم عليه في سامِرّاء مشتدّاً ونهض الى الرّجوع الى الحجاز، ولمّا بلغ بلد على تِسعة فراسخ مرض وتوفّي ومشهده هناك، ولمّا توفّي شقّ أبو محمّد (عليه السلام) عليه ثوبه وقال في جواب من عابه عليه : قد شقّ موسى على أخيه هارون . وكانت وفاته في حدود اثنين وخمسين بعد المائتين، وعلى أيّ حال فاذا شئت أن تودع العسكريّين (عليهما السلام) فقف على القبر الطاهر وقُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكُما يا وَلِيَّيِ اللهِ، اَسْتَوْدِعُكُمَا اللهَ وَاَقْرَأُ عَلَيْكُما اَلسَّلامُ، آمَنّا بِاللهِ وَبِالرَّسُولِ وَبِما جِئْتُما بِهِ وَدَلَلْتُما عَلَيْهِ، اَللّـهُمَّ اكْتُبْنا مَعَ الشّاهِدينَ، اَللّـهُمَّ لا تَجْعَلْهُ آخِرَ الْعَهْدِ مِنْ زِيارَتي اِيّاهُما، وَارْزُقْنِى الْعَوْدَ اِلَيْهِما، وَاحْشُرْنى مَعَهُما وَمَعَ آبائِهِمَا الطّاهِرينَ وَالْقآئِمِ الْحُجَّةِ مِنْ ذُرِّيَّتِهِما يا اَرْحَمَ الرّاحِمينَ ."},{"type":"Text","content":"المقامُ الثّاني : في آداب السّرداب الطّاهر وصفة زيارة حجّة الله على العباد وبقيّة الله في البلاد الامام المهدي الحجّة بن الحسن صاحب الزّمان صلوات الله عليه وعلى آبائه ."},{"type":"Text","content":"وعلينا أن نصدّر المقصد بالتّنبيه على أمر تحدّثنا عنه في كتاب الهدية نقلاً عن كتاب التحيّة وهو انّ هذا السّرداب الطّاهر هو قسم من دارهما (عليهما السلام(، وقبلما يشيد هذا البناء الحديث (الصّحن والحرم والقبّة) كان المدخل الى السّرداب خلف القبر عند مرقد السّيدة نرجس (نرجس خاتون) ولعلّه الان واقع في الرّواق ، فكان ينحدر الى مسلك مظلم طويل ينتهي بباب يفتح وسط سرداب الغيبة، والسّرداب في عصرنا الحاضر مزخرف بالمرايا وله في جانب القبلة نافذة الى صحن العسكريّين (عليهما السلام)، وموضع الباب السّابق معلّم بصورة المحراب منقوشة بالقاشاني ، فكانت الزّيارات وغيرها لهؤلاء الائمة الثّلاث تؤدّي كلّها من حرم واحد ولذلك نجد الشهيد الاول في المزار يعقب زيارة العسكريّين (عليهما السلام) بزيارة السّرداب ثمّ يذكر زيارة السّيدة نرجس، ومنذ مائة وبضعة سنين تأهّب للبناء المؤيّد المُسدّد احمد خان الدّنبلي وافرز بما أنفقه من المبلغ الخطير صحن الامامين (عليهما السلام) كما هو الان، وشيّد الرّوضة والرّواق والقبّة الشّامخة واسّس للسّرداب الطّاهر الصّحن الخاص والايوان والمدخل والدّهليز، كما شيّد للنّساء سرداباً خاصّاً كما هو قائم الان، فطمست معالم ما كان من قبل المدخل والدّرج والباب وانمحى جميع آثاره ، فزال بذلك مورد بعض الاداب المأثورة، ولكن أصل السّرداب الشّريف وهو موضِع جملة من الزّيارات باق لم يتغيّر ، وأمّا الاستئذان لدخول السّرداب فلم يسقط بانسداد المدخل السّابق فلكلّ زيارة استئذان كما دلّ عليه الاستقراء ، ونجد العلماء كذلك يصرحون بلزوم الاستئذان تأدّباً للدّخول من أيّ باب اعتيد الدّخول منه الى حرم امام من الائمة (عليهم السلام) . والان نبدأ في صفة الزّيارة ."},{"type":"AboutText","content":"اعلم انّ الاستئذان الخاص المأثور لدخول السّرداب هو الزّيارة الاتية التي مفتتحها اَلسَّلامُ عَلَيْكَ يا خَليفَةَ اللهِ وتنتهي بالاستئذان ويُزار بها على باب السّرداب قبل النّزول اليه ."},{"type":"Text","content":"وقد أورد السّيد ابن طاوُس (رحمه الله) استئذاناً آخر يقرب من الاستئذان العام الاوّل الذي أوردناه في الفصل الثّاني من باب الزّيارات وأورد العلامة المجلسي (رحمه الله) استئذاناً آخر حكاه عن نسخة قديمة وأوّلها اَللّـهُمَّ اِنَّ هـذِهِ بُقْعَةٌ طَهَّرْتَها وَعَقْوَةٌ شَرَّفْتَها وهو ما عقّبنا به الاستئذان العامّ المذكور ، فارجع اليه واستأذن به ثمّ انزل الى السّرداب وزره (عليه السلام) بما روي عنه نفسه الشّريفة كما عن الشّيخ الجليل احمد بن أبي طالب الطّبرسي في كتاب الاحتجاج انّه خرج من النّاحية المقدّسة الى محمّد الحميري بعد الجواب عن المسائل التي سألها بِسْمِ اللهِ الرَّحْمنِ الرَّحيمِ لا لاَِمْرِهِ تَعْقِلُونَ وَلا مِنْ اَوْلِيائِهِ تَقْبَلُونَ حِكْمَةٌ بالِغَةٌ فَما تُغْنِي النُّذُرِ (عن قوم لايؤمنون) اَلسَّلامُ عَلَيْنا وَعَلى عِبادِ اللهِ الصّالِحينَ، اذا أردتم التّوجه بنا الى الله تعالى والينا فتقولوا كما قال الله تعالى :"},{"type":"Text","content":"سَلامٌ عَلى آلِ يس، اَلسَّلامُ عَلَيْكَ يا داعِيَ اللهِ وَرَبّانِيَ آياتِهِ، اَلسَّلامُ عَلَيْكَ يا بابَ اللهِ وَدَيّانَ دينِهِ، اَلسَّلامُ عَلَيْكَ يا خَليفَةَ اللهِ وَناصِرَ حَقِّهِ، اَلسَّلامُ عَلَيْكَ يا حُجَّةَ اللهِ وَدَليلَ اِرادَتِهِ، اَلسَّلامُ عَلَيْكَ يا تالِيَ كِتابِ اللهِ وَتَرْجُمانَهُ اَلسَّلامُ عَلَيْكَ في آناءِ لَيْلِكَ وَاَطْرافِ نَهارِكَ، اَلسَّلامُ عَلَيْكَ يا بَقِيَّةَ اللهِ في اَرْضِهِ، اَلسَّلامُ عَلَيْكَ يا ميثاقَ اللهِ الَّذي اَخَذَهُ وَوَكَّدَهُ، اَلسَّلامُ عَلَيْكَ يا وَعْدَ اللهِ الَّذي ضَمِنَهُ، اَلسَّلامُ عَلَيْكَ اَيُّهَا الْعَلَمُ الْمَنْصُوبُ وَالْعِلْمُ الْمَصْبُوبُ وَالْغَوْثُ وَالرَّحْمَةُ الْواسِعَةُ، وَعْداً غَيْرَ مَكْذوُب، اَلسَّلامُ عَلَيْكَ حينَ تَقوُمُ، اَلسَّلامُ عَلَيْكَ حينَ تَقْعُدُ، اَلسَّلامُ عَلَيْكَ حينَ تَقْرَأُ وَتُبَيِّنُ، اَلسَّلامُ عَلَيْكَ حينَ تُصَلّي وَتَقْنُتُ، اَلسَّلامُ عَلَيْكَ حينَ تَرْكَعُ وَتَسْجُدُ، اَلسَّلامُ عَلَيْكَ حينَ تُهَلِّلُ وَتُكَبِّرُ، اَلسَّلامُ عَلَيْكَ حينَ تَحْمَدُ وَتَسْتَغْفِرُ، اَلسَّلامُ عَلَيْكَ حينَ تُصْبِحُ وَتُمْسي، اَلسَّلامُ عَلَيْكَ فِي اللَّيْلِ اِذا يَغْشى وَالنَّهارِ اِذا تَجَلّى، اَلسَّلامُ عَلَيْكَ اَيُّهَا الاِْمامُ الْمَأمُونِ اَلسَّلامُ عَلَيْكَ اَيُّهَا الْمُقَدَّمُ الْمَأمُولُ، اَلسَّلامُ عَلَيْكَ بِجَوامِعِ السَّلام اُشْهِدُكَ يا مَوْلاىَ اَنّى اَشْهَدُ اَنْ لا اِلـهَ اِلا اللهُ وَحْدَهُ لا شَريكَ لَهُ، وَاَنَّ مُحَمَّداً عَبْدُهُ وَرَسوُلُهُ لا حَبيبَ اِلا هُوَ وَاَهْلُهُ، وَاُشْهِدُكَ يا مَوْلايَ اَنَّ عَلِيّاً اَميرَ الْمُؤْمِنينَ حُجَّتُهُ وَالْحَسَنَ حُجَّتُهُ وَالْحُسَيْنَ حُجَّتُهُ وَعَلِيَّ بْنَ الْحُسَيْنِ حُجَّتُهُ وَمُحَمَّدَ بْنَ عَلِيٍّ حُجَّتُهُ، وَجَعْفَرَ بْنَ مُحَمَّدٍّ حُجَّتُهُ، وَموُسَى بْنَ جَعْفَر حُجَّتُهُ، وَعَلِيَّ بْنَ موُسى حُجَّتُهُ، وَمُحَمَّدَ بْنَ عَلِيٍّ حُجَّتُهُ، وَعَلِيَّ بْنَ مُحَمَّد حُجَّتُهُ، وَالْحَسَنَ بْنَ عَلِيٍّ حُجَّتُهُ، وَاَشْهَدُ اَنَّكَ حُجَّةُ اللهِ، اَنْتُمُ الاَْوَّلُ وَالاْخِرُ وَاَنَّ رَجْعَتَكُمْ حَقٌّ لا رَيْبَ فيها يَوْمَ لا يَنْفَعُ نَفْساً ايمانُها لَمْ تَكُنْ آمَنَتْ مِنْ قَبْلُ اَوْ كَسَبَتْ في ايمانِها خَيْراً، وَاَنَّ الْمَوْتَ حَقٌّ، وَاَنَّ ناكِراً وَنَكيراً حَقٌّ، وَاَشْهَدُ اَنَّ النَّشْرَ حَقٌّ، وَالْبَعَثَ حَقٌّ، وَاَنَّ الصِّراطَ حَقٌّ، وَالْمِرْصادَ حَقٌّ، وَالْميزانَ حَقٌّ، وَالْحَشْرَ حَقٌّ، وَالْحِسابَ حَقٌّ، وَالْجَنَّةَ وَالنّارَ حَقٌّ، وَالْوَعْدَ وَالْوَعيدَ بِهِما حَّق، يا مَوْلايَ شَقِيَ مَنْ خالَفَكُمْ وَسَعِدَ مَنْ اَطاعَكُمْ، فَاَشْهَدْ عَلى ما اَشْهَدْتُكَ عَلَيْهِ، وَاَنَا وَلِيٌّ لَكَ بَريٌ مِنْ عَدُوِّكَ، فَالْحَقُّ ما رَضيتُمُوهُ، وَالْباطِلُ ما اَسْخَطْتُمُوهُ، وَالْمَعْرُوفُ ما اَمَرْتُمْ بِهِ، وَالْمُنْكَرُ ما نَهَيْتُمْ عَنْهُ، فَنَفْسي مُؤْمِنَةٌ بِاللهِ وَحْدَهُ لا شَريكَ لَهُ وَبِرَسُولِهِ وَبِاَميرِ الْمُؤْمِنينَ وَبِكُمْ يا مَوْلايَ اَوَّلِكُمْ وَآخِرِكُمْ، وَنُصْرَتي مُعَدَّةٌ لَكُمْ وَمَوَدَّتى خالِصَةٌ لَكُمْ آمينَ آمينَ ."}],"preview":"اَللّـهُمَّ اِيّاكَ اعْتَمَدْتُ، وَلِرِضاكَ طَلَبْتُ، وَبِاَوْلِيائِكَ اِلَيْكَ تَوَسَّلْتُ، وَعَلى غُفْرانِكَ وَحِلْمِكَ اتَّكَلْتُ، وَبِكَ اعْتَصَمْتُ، وَبِقَبْرِ اُمِّ وَلِيِّكَ","hasTranslate":false},{"id":"mf_ar_255","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"الدّعآء عقيب هذا القول :","blocks":[{"type":"Text","content":"اَللّـهُمَّ اِنّي اَسْاَلُكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد نَبِيِّ رَحْمَتِكَ وَكَلِمَةِ نُورِكَ، وَاَنْ تَمْلاََ قَلْبى نُورَ الْيَقينِ وَصَدْري نوُرَ الاْيمانِ وَفِكْري نُورَ النِّيّاتِ، وَعَزْمي نُورَ الْعِلْمِ، وَقُوَّتي نُورَ الْعَمَلِ، وَلِساني نُورَ الصِّدْقِ، وَديني نُورَ الْبَصائِرِ مِنْ عِنْدِكَ، وَبَصَري نُورَ الضِّياءِ، وَسَمْعي نُورَ الْحِكْمَةِ، وَمَوَدَّتي نُورَ الْمُوالاةِ لُِمحَمَّد وَآلِهِ عليهم السلام حَتّى اَلْقاكَ وَقَدْ وَفَيْتُ بِعَهْدِكَ وَميثاقِكَ فَتُغَشّيَنى رَحْمَتَكَ يا وَلِىُّ يا حَميدُ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد حُجَّتِكَ في اَرْضِكَ، وَخَليفَتِكَ في بِلادِكَ، وَالدّاعي اِلى سَبيلِكَ، وَالْقائِمِ بِقِسْطِكَ، وَالثّائِرِ بِاَمْرِكَ، وَلِيِّ الْمُؤْمِنينَ وَبَوارِ الْكافِرينَ، وَمُجَلِّي الظُّلْمَةِ، وَمُنيرِ الْحَقِّ، وَالنّاطِقِ بِالْحِكْمَةِ وَالصِّدْقِ، وَكَلِمَتِكَ التّآمَّةِ في اَرْضِكَ، الْمُرْتَقِبِ الْخآئِفِ وَالْوَلِيِّ النّاصِحِ، سَفينَةِ النَّجاةِ وَعَلَمِ الْهُدى وَنُورِ اَبْصارِ الْوَرى، وَخَيْرِ مَنْ تَقَمَّصَ وَارْتَدى، وَمُجَلِّي الْعَمَى الَّذي يَمْلاَُ الاَْرْضَ عَدْلاً وَقِسْطاً كَما مُلِئَتْ ظُلْماً وَجَوْراً، اِنَّكَ عَلى كُلِّ شَىْء قَديرٌ، اَللّـهُمَّ صَلِّ عَلى وَلِيِّكَ وَابْنِ اَوْلِيائِكَ الَّذينَ فَرَضْتَ طاعَتَهُمْ، وَاَوْجَبْتَ حَقَّهُمْ، وَاَذْهَبْتَ عَنْهُمُ الرِّجْسَ وَطَهَّرْتَهُمْ تَطْهيراً، اَللّـهُمَّ انْصُرْهُ وَانْتَصِرْ بِهِ لِدينِكَ وَانْصُرْ بِهِ اَوْلِياءِكَ وَاَوْلِياءِهِ وَشيعَتَهُ وَاَنْصارَهُ وَاجْعَلْنا مِنْهُمْ، اَللّـهُمَّ اَعِذْهُ مِنْ شَرِّ كُلِّ باغ وَطاغ وَمِنْ شَرِّ جَميعِ خَلْقِكَ، وَاحْفَظْهُ مِنْ بَيْنَ يَدَيْهِ وَمِنْ خَلْفِهِ وَعَنْ يَمينِهِ وَعَنْ شَمالِهِ، وَاحْرُسْهُ وَامْنَعْهُ مِنْ اَنْ يوُصَلَ اِلَيْهِ بِسُوء وَاحْفَظْ فيهِ رَسُولَكَ، وَآلِ رَسوُلِكَ وَاَظْهِرْ بِهِ الْعَدْلَ وَاَيِّدْهُ بِالنَّصْرِ، وَانْصُرْ ناصِريهِ، وَاخْذُلْ خاذِليهِ، وَاقْصِمْ قاصِميهِ، وَاقْصِمْ بِهِ جَبابِرَةَ الْكُفْرِ، وَاقْتُلْ بِهِ الْكُفّارَ وَالْمُنافِقينَ وَجَميعَ الْمُلْحِدينَ حَيْثُ كانُوا مِنْ مَشارِقِ الاَْرْضِ وَمَغارِبِها بَرِّها وَبَحْرِها، وَامْلاَْ بِهِ الاَْرْضَ عَدْلاً وَاَظْهِرْ بِهِ دينَ نَبِيِّكَ صَلَّى اللهُ عَلَيْهِ وَآلِهِ، وَاجْعَلْنِي اللّهُمَّ مِنْ اَنْصارِهِ وَاَعْوانِهِ وَاَتْباعِهِ وَشيعَتِهِ، وَاَرِني في آلِ مُحَمَّد عليهم السلام ما يَأمُلُونَ وَفي عَدُوِّهِمْ ما يَحْذَرُونَ، اِلـهَ الْحَقِّ آمينَ، يا ذَا الْجَلالِ وَالاِْكْرامِ يا اَرْحَمَ الرّاحِمينَ ."}],"preview":"اَللّـهُمَّ اِنّي اَسْاَلُكَ اَنْ تُصَلِّيَ عَلى مُحَمَّد نَبِيِّ رَحْمَتِكَ وَكَلِمَةِ نُورِكَ، وَاَنْ تَمْلاََ قَلْبى نُورَ الْيَقينِ وَصَدْري نوُرَ الاْيمانِ وَفِكْري نُورَ النّ","hasTranslate":false},{"id":"mf_ar_256","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"قِف على باب حرمه الشريف وقُل :","blocks":[{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا خَليفةَ اللهِ وَخَلَيفةَ آبائِهِ الْمَهْدِيّينَ، اَلسَّلامُ عَلَيْكَ يا وَصِيَّ الاَْوْصِياءِ الْماضينَ، اَلسَّلامُ عَلَيْكَ يا حافِظَ اَسْرارِ رَبِّ الْعالَمينَ، اَلسَّلامُ عَلَيْكَ يا بَقِيَّةَ اللهِ مِنَ الصَّفْوَةِ الْمُنْتَجَبينَ، اَلسَّلامُ عَلَيْكَ يَا بْنَ الاَْنْوارِ الزّاهِرَةِ، اَلسَّلامُ عَلَيْكَ يَا بْنَ الاَْعْلامِ الْباهِرَةِ، اَلسَّلامُ عَلَيْكَ يَا بْنَ الْعِتْرَةِ الطّاهِرَةِ، اَلسَّلامُ عَلَيْكَ يا مَعْدِنَ الْعُلُومِ النَّبَوِيَّةِ، اَلسَّلامُ عَلَيْكَ يا بابَ اللهِ الَّذي لا يُؤْتى اِلّا مِنْهُ، اَلسَّلامُ عَلَيْكَ يا سَبيلَ اللهِ الَّذي مَنْ سَلَكَ غَيْرَهُ هَلَكَ، اَلسَّلامُ عَلَيْكَ يا ناظِرَ شَجَرَةِ طُوبى وَسِدْرَةِ الْمُنْتَهى، اَلسَّلامُ عَلَيْكَ يا نُورَ اللهِ الَّذي لا يُطْفى، اَلسَّلامُ عَلَيْكَ يا حُجَّةَ اللهِ الَّتي لا تَخْفى، اَلسَّلامُ عَلَيْكَ يا حُجَّةَ اللهِ عَلى مَنْ فِي الاَْرْضِ وَالسَّمآءِ، اَلسَّلامُ عَلَيْكَ سَلامَ مَنْ عَرَفَكَ بِما عَرَّفَكَ بِهِ اللهُ، وَنَعَتَكَ بِبَعْضِ نُعُوتِكَ الَّتي اَنْتَ اَهْلُها وَفَوْقُها، اَشْهَدُ اَنَّكَ الْحُجَّةُ عَلى مَنْ مَضى وَمَنْ بَقِيَ، وَاَنَّ حِزْبَكَ هُمُ الْغالِبُونَ وَاَوْلِياءَكَ هُمُ الْفائِزُونَ وَاَعْداءَكَ هُمُ الْخاسِرُونَ، وَاَنَّكَ خازِنُ كُلِّ عِلْم، وَفاتِقُ كُلِّ رَتْق، وَمُحَقِّقُ كُلِّ حَقٍّ، وَمُبْطِلُ كُلِّ باطِل، رَضيتُكَ يا مَوْلايَ اِماماً وَهادِياً وَوَلِيّاً وَمُرْشِداً، لا اَبْتَغي بِكَ بَدَلاً وَلا اَتَّخِذُ مِنْ دُونِكَ وَلِيّاً، اَشْهَدُ اَنَّكَ الْحَقُّ الثّابِتُ الَّذي لا عَيْبَ فيهِ، وَاَنَّ وَعْدَ اللهِ فيكَ حَقٌّ لا اَرْتابُ لِطُولِ الغَيْبَةِ وَبُعْدِ الاَْمَدِ، وَلا اَتَحَيَّرُ مَعَ مَنْ جَهِلَكَ وَجَهِلَ بِكَ، مُنْتَظِرٌ مُتَوَقِّعٌ لاَِيّامِكَ، وَاَنْتَ الشّافِعُ الَّذي لا تُنازَعُ، و الْوَلِيُّ الَّذى لا تُدافَعُ، ذَخَرَكَ اللهُ لِنُصْرَةِ الدّينِ وَاِعْزازِ الْمُؤْمِنينَ، وَالاْنْتِقامِ مِنَ الْجاحِدينَ الْمارِقينَ، اَشْهَدُ اَنَّ بِوِلايَتِكَ تُقْبَلُ الاَْعْمالُ، وَتُزَكَّى الاَْفْعالُ، وَتُضاعَفُ الْحَسَناتُ، وَتُمْحَى السَّيِّئاتُ، فَمَنْ جاءَ بِوِلايَتِكَ وَاعْتَرَفَ بِاِمامَتِكَ قُبِلَتْ اَعْمالُهُ وَصُدِّقَتْ اَقْوالُهُ وَتَضاعَفَتْ حَسَناتُهُ وَمُحِيَتْ سَيِّئاتُهُ، وَمَنْ عَدَلَ عَنْ وِلايَتِكَ وَجَهِلَ مَعْرِفَتَكَ وَاسْتَبْدَلَ بِكَ غَيْرَكَ كَبَّهُ اللهُ عَلى مَنْخَرِهِ فِي النّارِ، وَلَمْ يَقْبَلِ اللهُ لَهُ عَمَلاً وَلَمْ يُقِمْ لَهُ يَوْمَ الْقِيامَةِ وَزْناً، اُشْهِدُ اللهَ و اُشْهِدُ مَلائِكَتَهُ وَاُشْهِدُكَ يا مَوْلايَ بِهذا، ظاهِرُهُ كَباطِنِهِ وَسِرُّهُ كَعَلانِيَتِهِ، وَاَنْتَ الشّاهِدُ عَلى ذلِكَ، وَهُوَ عَهْدي اِلَيْكَ وَميثاقي لَدَيْكَ، اِذْ اَنْتَ نِظامُ الدّينِ، وَيَعْسُوبُ الْمُتَّقينَ، وَعِزُّ الْمُوَحِّدينَ، وَبِذلِكَ اَمَرَني رَبُّ الْعالَمينَ، فَلَوْ تَطاوَلَتِ الدُّهُورُ، وَتَمادَتِ الاَْعْمارُ، لَمْ اَزْدَدْ فيكَ اِلّا يَقيناً وَلَكَ اِلّا حُبّاً، وَعَلَيْكَ اِلّا مُتَّكَلاً وَمُعْتَمَداً، وَلِظُهُورِكَ اِلّا مُتَوَقِّعاً وَمُنْتَظِرَاً، وَلِجِهادي بَيْنَ يَدَيْكَ مُتَرَقِّباً، فَاَبْذُلُ نَفْسي وَمالي وَوَلَدي وَاَهْلي وَجَميعَ ما خَوَّلَني رَبّي بَيْنَ يَدَيْكَ وَالتَّصَرُّفَ بَيْنَ اَمْرِكَ وَنَهْيِكَ، مَوْلايَ فَاِنْ اَدْرَكْتُ اَيّامَكَ الزّاهِرَةَ وَاَعْلامَكَ الْباهِرَةَ فَها اَنـَا ذا عَبْدُكَ الْمُتَصَرِّفُ بَيْنَ اَمْرِكَ وَنَهْيِكَ، اَرْجُو بِهِ الشَهادَةَ بَيْنَ يَدَيْكَ وَالْفَوْزَ لَدَيْكَ، مَوْلايَ فَاِنْ اَدْرَكَنِي الْمَوْتُ قَبْلَ ظُهُورِكَ فَاِنّي اَتَوَسَّلُ بِكَ وَبِابائِكَ الطّاهِرينَ اِلَى اللهِ تَعالى وَاَسْأَلُهُ اَنْ يُصَلِّيَ عَلى مُحَمَّد وَآلِ مُحَمَّد، وَاَنْ يَجْعَلَ لي كَرَّةً في ظُهُورِكَ وَرَجْعَةً في اَيّامِكَ، لاَِبْلُغَ مِنْ طاعَتِكَ مُرادي وَاَشْفِيَ مِنْ اَعْدآئِكَ فُؤادي، مَوْلايَ وَقَفْتُ في زِيارَتِكَ مَوْقِفَ الْخاطِئينَ النّادِمينَ الْخائِفينَ مِنْ عِقابِ رَبِّ الْعالَمينَ، وَقَدِ اتَّكَلْتُ عَلى شَفاعَتِكَ، وَرَجَوْتُ بِمُوالاتِكَ وَشَفاعَتِكَ مَحْوَ ذُنُوبي، وَسَتْرَ عُيُوبي، وَمَغْفِرَةَ زَلَلي، فَكُنْ لِوَلِيِّكَ يا مَوْلايَ عِنْدَ تَحْقيقِ اَمَلِهِ وَاسْأَلِ اللهَ غُفْرانَ زَلَلِهِ، فَقَدْ تَعَلَّقَ بِحَبْلِكَ، وَتَمَسَّكَ بِوِلايَتِكَ، وَتَبَرَّأَ مِنْ اَعْدائِكَ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِهِ وَاَنْجِزْ لِوَلِيِّكَ ما وَعَدْتَهُ، اَللّـهُمَّ اَظْهِرْ كَلِمَتَهُ، وَاَعْلِ دَعْوَتَهُ، وَانْصُرْهُ عَلى عَدُوِّهِ وَعَدُوِّكَ يا رَبَّ الْعالَمينَ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاَظْهِرْ كَلِمَتَكَ التّامَّةَ وَمُغَيَّبَكَ في اَرْضِكَ الْخآئِفَ الْمُتَرَقِّبَ، اَللّـهُمَّ انْصُرْهُ نَصْراً عَزيزاً وَافْتَحْ لَهُ فَتْحاًيَسيراً، اَللّـهُمَّ وَاَعِزَّ بِهِ الدّينَ بَعْدَ الْخُمُولِ، وَاَطْلِعْ بِهِ الْحَقَّ بَعْدَ الاُْفُولِ، وَاَجْلِ بِهِ الظُّلْمَةَ وَاكْشِفْ بِهِ الْغُمَّةَ، اَللّـهُمَّ وَآمِنْ بِهِ الْبِلادَ، وَاهْدِ بِهِ الْعِبادَ، اَللّـهُمَّ امْلاَْ بِهِ الاَْرْضَ عَدْلاً وَقِسْطاً كَما مُلِئَتْ ظُلْماً وَجَوراً اِنَّكَ سَميعٌ مُجيبٌ، اَلسَّلامُ عَلَيْكَ يا وَلِيَّ اللهِ، اْئْذَنْ لِوَلِيِّكَ في الدُّخُولِ اِلى حَرَمِكَ صَلَواتُ اللهِ عَلَيْكَ وَعَلى آبائِكَ الطّاهِرينَ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ ."},{"type":"Text","content":"ثمّ ائت سرداب الغيبة وقف بين البابين ماسكاً جانب الباب بيدك ثمّ تنحنح كالمُستأذن وقُل : بِسْمِ اللهِ الرَّحْمنِ الرَّحيمِ وانزل بسكينة وحضور قلب وصلّ ركعتين في عرصة السّرداب وقُل :"},{"type":"Text","content":"اللهُ اَكْبَرُ اللهُ اَكْبَرُ اللهُ اَكْبَرُ، لا اِلـهَ اِلّا اللهُ وَاللهُ اَكْبَرُ وَللهِ الْحَمْدُ، اَلْحَمْدُ للهِ الَّذي هَدانا لِهذا وَعَرَّفَنا اَوْلِياءَهُ وَاَعْداءَهُ وَوَفَّقَنا لِزِيارَةِ اَئِمَّتِنا، وَلَمْ يَجْعَلْنا مِنَ الْمُعانِدينَ النّاصِبينَ، وَلا مِنَ الْغُلاةِ الْمُفَوِّضينَ، وَلا مِنَ الْمُرْتابينَ الْمُقَصِّرينَ، اَلسَّلامُ عَلى وَلِىِّ اللهِ وَابْنِ اَوْلِيآئِهِ، اَلسَّلامُ عَلى الْمُدَّخَرِ لِكَرامَةِ اَوْلِياءِ اللهِ وَبَوارِ اَعْداءِهِ، اَلسَّلامُ عَلَى النُّورِ الَّذي اَرادَ اَهْلُ الْكُفْرِ اِطْفاءَهُ فَاَبَى اللهُ اِلّا اَنْ يُتِمَّ نُورَهُ بِكُرْهِهِمْ، وَاَيَّدَهُ بِالْحَياةِ حَتّى يُظْهِرَ عَلى يَدِهِ الْحَقَّ بِرَغْمِهِمْ، اَشْهَدُ اَنَّ الله اصْطَفاكَ صَغيراً وَاَكْمَلَ لَكَ عُلُومَهُ كَبيراً، وَاَنَّكَ حَيٌّ لا تَمُوتُ حَتّى تُبْطِلَ الْجِبْتَ وَالطّاغُوتَ، اَللّـهُمَّ صَلِّ عَلَيْهِ وَعَلى خُدّامِهِ وَاَعْوانِهِ عَلى غَيْبَتِهِ وَنَأيِهِ وَاسْتُرْهُ سَتْراً عَزيزاً، وَاجْعَلْ لَهُ مَعْقِلاً حَريزاً، وَاشْدُدِ اَللّـهُمَّ وَطْأَتَكَ عَلى مُعانِديه، وَاحْرُس مَوالِيَهُ وَزائِريهِ، اَللّـهُمَّ كَما جَعَلْتَ قَلْبي بِذِكْرِهِ مَعْمُوراً فَاجْعَلْ سِلاحي بِنُصْرَتِهِ مَشْهُوراً، وَاِنْ حالَ بَيْني وَبَيْنَ لِقائِهِ الْمَوْتُ الَّذي جَعَلْتَهُ عَلى عِبادِكَ حَتْماً وَاَقْدَرْتَ بِهِ عَلى خَليقَتِكَ رَغْماً، فَابْعَثْني عِنْدَ خُرُوجِهِ ظـاهِراً مِنْ حُفْرَتي مُؤْتَزِراً كَفَني حَتّى اُجاهِدَ بَيْنَ يَدَيْهِ في الصَّفِّ الَّذي اَثْنَيْتَ عَلى اَهْلِهِ في كِتابِكَ فَقُلْتَ: «كَاَنَّهُمْ بُنْيانٌ مَرْصُوصٌ» اَللّـهُمَّ طالَ الاْنْتِظارُ وَشَمِتَ مِنَّا الْفُجّارُ، وَصَعُبَ عَلَيْنَا الاِْنْتِصارُ، اَللّـهُمَّ اَرِنا وَجْهَ وَلِيِّكَ الْمَيْمُونِ في حَياتِنا وَبَعْدَ اْلَمنُونِ، اَللّـهُمَّ اِنّي اَدينُ لَكَ بِالرَّجْعَةِ بَيْنَ يَدَيْ صاحِبِ هذِهِ اَلْبُقْعَةِ، الْغَوْثَ الْغَوْثَ الْغَوْثَ يا صاحِبَ الزَّمانِ، قَطَعْتُ في وُصْلَتِكَ الْخُلاّنَ، وَهَجَرْتُ لِزِيارَتِكَ الاَْوْطانَ، وَاَخْفَيْتُ اَمْري عَنْ اَهْلِ الْبُلْدانِ، لِتَكُونَ شَفيعاً عِنْدَ رَبِّكَ وَرَبّي اِلى آبآئِكَ وَمَوالِيَّ في حُسْنِ التَّوْفيقِ لي وِاِسْباغِ النِّعْمَةِ عَلِىَّ، وَسَوْقِ الاِْحْسانِ اِلَىَّ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد اَصْحابِ الْحَقِّ وَقادَةِ الْخَلْقِ، وَاْسْتَجِبْ مِنّي ما دَعَوْتُكَ، وَاَعْطِني ما لَمْ اَنْطِقْ بِهِ في دُعآئي مِنْ صَلاحِ ديني وَدُنْيايَ، اِنَّكَ حَميدٌ مَجيدٌ وَصَلِّى اللهُ عَلى مُحَمَّد وَآلِهِ الطّاهِرينَ ."}],"preview":"اَلسَّلامُ عَلَيْكَ يا خَليفةَ اللهِ وَخَلَيفةَ آبائِهِ الْمَهْدِيّينَ، اَلسَّلامُ عَلَيْكَ يا وَصِيَّ الاَْوْصِياءِ الْماضينَ، اَلسَّلامُ عَلَيْكَ يا حافِظَ اَسْرارِ رَبِّ الْعالَ","hasTranslate":false},{"id":"mf_ar_257","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"ثمّ ادخل الصّفة فصلّ ركعتين وقُل :","blocks":[{"type":"Text","content":"اَللّـهُمَّ عَبْدُكَ الزّائِرُ في فِناءِ وَلِيِّكَ الْمَزُورِ الَّذي فَرَضْتَ طـاعَتَهُ عَلَى الْعَبيدِ وَالاَْحْرارِ، وَاَنْقَذْتَ بِهِ اَوْلِياءَكَ مِنْ عَذابِ النّارِ، اَللّـهُمَّ اجْعَلْها زِيارَةً مَقْبُولَةً ذاتَ دُعآء مُسْتَجاب مِنْ مُصَدِّق بِوَلِيِّكَ غَيْرِمُرْتاب،اَللّـهُمَّ لا تَجْعَلْهُ آخِرَ الْعَهْدِ بِهِ وَلا بِزِيارَتِهِ، وَلا تَقْطَعْ اَثَري مِنْ مَشْهَدِهِ وَزِيارَةِ اَبيهِ وَجَدِّهِ، اَللّـهُمَّ اَخْلِفْ عَلَيَّ نَفَقَتي وَانْفَعْني بِما رَزَقْتَني في دُنْيايَ وَآخِرَتي لي ولاِِخْواني وَاَبَوَيَّ وَجَميعِ عِتْرَتي، اَسْتَودِعُكَ اللهَ اَيُّهَا الاِْمامُ الَّذي يَفُوزُ بِهِ الْمُؤْمِنُونَ، وَيَهْلِكُ عَلى يَدَيْهِ الْكافِرُونَ الْمُكَذِّبُونَ، يا مَوْلايَ يَا بْنَ الْحَسَنِ بْنِ عَلِيٍّ جِئْتُكَ زآئِراً لَكَ وَلاَِبيكَ وَجَدِّكَ، مُتَيَقِّناً الْفَوْزَ بِكُمْ، مُعْتَقِداً اِمامَتَكُمْ، اَللّـهُمَّ اَكْتُبْ هذِهِ الشَّهادَةَ وَالزِّيارَةَ لي عِنْدَكَ في عِلّيّينَ، وَبَلِّغْني بَلاغَ الصّالِحينَ، وَانْفَعْني بِحُبِّهِمْ يا رَبَّ الْعالَمينَ ."}],"preview":"اَللّـهُمَّ عَبْدُكَ الزّائِرُ في فِناءِ وَلِيِّكَ الْمَزُورِ الَّذي فَرَضْتَ طـاعَتَهُ عَلَى الْعَبيدِ وَالاَْحْرارِ، وَاَنْقَذْتَ بِهِ اَوْلِياءَكَ مِنْ عَذابِ النّارِ، اَللّـهُم","hasTranslate":false},{"id":"mf_ar_258","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"زيارة أخرى","blocks":[{"type":"Text","content":"وهي ما رواها السّيد ابن طاووس ، تقول :"},{"type":"Text","content":"اَلسَّلامُ عَلَى الْحَقِّ الْجَديدِ وَالْعالِمِ الَّذي عِلْمُهُ لا يَبيدُ اَلسَّلامُ عَلى مُحْيِي الْمُؤْمِنينَ وَمُبيرِ الْكافِرينَ، اَلسَّلامُ عَلى مَهْدِيِّ الاُْمَمِ وَجامِعِ الْكَلِمِ، اَلسَّلامُ عَلى خَلَفِ السَّلَفِ وَصاحِبِ الشَّرَفِ، اَلسَّلامُ عَلى حُجَّةِ الْمَعْبُودِ وَكَلِمَةِ الَْمحْمُودِ، اَلسَّلامُ عَلى مُعِزِّ الاَْوْلِياءِ وَمُذِلِّ الاَْعْداءِ، اَلسَّلامُ عَلى وارِثِ الاَْنْبِياءِ وَخاتِمِ الاَْوْصِياءِ، اَلسَّلامُ عَلَى الْقائِمِ الْمُنْتَظَرِ وَالْعَدْلِ الْمُشْتَهَرِ، اَلسَّلامُ عَلَى السَّيْفِ الشّاهِرِ وَالْقَمَرِ الزّاهِرِ وَالنُّوُرِ الْباهِرِ، اَلسَّلامُ عَلى شَمْسِ الظَّلامِ وَبَدْرِ الَّتمامِ، اَلسَّلامُ عَلى رَبيعِ الاَْنامِ وَنَضْرَةِ الاَْيّامِ، اَلسَّلامُ عَلى صاحِبِ الصَّمْصامِ وَفَلّاقِ الْهامِ، اَلسَّلامُ عَلَى الدّينِ الْمَأثُورِ وَالْكِتابِ الْمَسْطُورِ، اَلسَّلامُ عَلى بَقِيَّةِ اللهِ في بِلادِهِ وَحُجَّتِهِ عَلى عِبادِهِ، الْمُنْتَهى اِلَيْهِ مَواريثُ الاَْنْبِياءِ، وَلَدَيْهِ مَوْجوُدٌ آثارُ الاَْصْفِياءِ، الْمُؤْتَمَنِ عَلَى السِّرِّ وَالْوَلِيِّ لِلاَْمْرِ، اَلسَّلامُ عَلَى الْمَهْدِيِّ الَّذي وَعَدَ اللهُ عَزَّوَجَلَّ بِهِ الاُْمَمَ اَنْ يَجْمَعَ بِهِ الْكَلِمَ، وَيَلُمَّ بِهِ الشَّعَثَ، وَيَمْلاََ بِهِ الاَْرْضَ قِسْطاً وَعَدْلاً، وَيُمَكِّنَ لَهُ وَيُنْجِزَ بِهِ وَعْدَ الْمُؤْمِنينَ، اَشْهَدُ يا مَوْلايَ اَنَّكَ وَالاَْئِمَّةَ مِنْ آبائِكَ اَئِمَّتي وَمَوالِىَّ فِي الْحَياةِ الدُّنْيا وَيَوْمَ يَقُومُ الاَْشْهادُ، اَسْاَلُكَ يا مَوْلايَ اَنْ تَسْأَلَ اللهَ تَبارَكَ وَتَعالى في صَلاحِ شَأني وَقَضاءِ حَوائِجى وَغُفْرانِ ذُنُوبي وَالاَْخْذِ بِيَدي في ديني وَآخِرَتي لي وَلاِِخْواني وَاَخَواتِي الْمُؤْمِنينَ وَالْمُؤْمِناتِ كآفَّةً اِنَّهُ غَفوُرٌ رَحيمٌ ."},{"type":"Text","content":"ثمّ صلّ صلاة الزّيارة بما قدمناه أي اثنتى عشرة ركعة تسلّم بعد كلّ ركعتين منها وتسبّح تسبيح الزّهراء (عليها السلام)وأهدها اليه (عليه السلام) فاذا فرغت من صلاة الزّيارة فقُل :"},{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلى حُجَّتِكَ في أرضِكَ وَ خَليفَتِكَ في بِلادِكَ، الدّاعي إلى سَبيلِك، وَالقائِمِ بِقِسْطِكَ، وَالفائِز بأَمرِكَ، وَليِّ المؤمِنينَ، ومُبيرِ الكافرينَ، وَمُجَلِّي الظُّلْمَةِ، وَمُنيرِ الحقِّ، وَالصّادِعِ بالحِكمةِ وَالموْعِظَةث الحسَنَةِ وَالصِّدْقِ، وَكَلمَتِكَ وَعَيْبَتِكَ وَعَيْنِكَ في أرْضِكَ، المُتَقِّبِ الخائفِ، الوَليِّ النّاصحِ، سَفينَةِ النَّجاةِ، وَعَلَمِ الهُدى، وَنُورِ أَبْصارِ الوَرى، وَخَيْرِ مَنْ تَقَمَّصَ وازتَدى، وَالوِتْرِ الموْتوِر، وَمُفَرِّجِ الكُرَبِ، وَمُزِيلِ الهَمَّ، وَكاشِفِ البلْوى، صَلَواتُ الله عَلَيْهِ وَ عَلى آبائِهِ الائِمَّةِ الهادينَ، وَالقادَةِ الميامينَ، ما طَلَعَتْ كَواكِبُ الاسحارَ، وَ أوْرَقَتِ الاشْجارُ، وَ أينَعَتِ الاثمارُ، واخْتَلَفَ الليلُ والنَّهارُ، وغَرَّدَتِ الاطْيارُ، الّلهُمَّ انْفَعْنا بحُبِّهِ وَ احْشُرْنا في زُمْرَتِهِ، وتَحْتَ لِوائِهِ، إلهَ الحَقِّ آمينَ رَبَّ العالمينَ."}],"preview":"وهي ما رواها السّيد ابن طاووس ، تقول :","hasTranslate":false},{"id":"mf_ar_259","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"الصَّلاة عليه (عليه السلام)","blocks":[{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَاَهْلِ بَيْتِهِ، وَصَلِّ عَلى وَلِيِّ الْحَسَنِ وَوَصِيِّهِ وَوارِثِهِ الْقائِمِ بِاَمْرِكَ، وَالْغائِبِ فى خَلْقِكَ، وَالْمُنْتَظِرِ لاِِذْنِكَ، اَللّـهُمَّ صَلِّ عَلَيْهِ وَقَرِّبْ بُعْدَهُ وَاَنْجِزْ وَعْدَهُ وَاَوْفِ عَهْدِهِ وَاكْشِفْ عَنْ بَأسِهِ حِجابَ الْغَيْبَةِ وَاَظْهِرْ بِظُهُورِهِ صَحائِفَ الِْمحْنَةِ، وَقَدِّمْ اَمامَهُ الرُّعْبَ وَثَبِّتْ بِهِ الْقَلْبَ وَاَقِمْ بِهِ الْحَرْبَ، وَاَيِّدْهُ بِجُنْد مِنَ الْمَلائِكَةِ مُسَوِّمينَ وَسَلِّطْهُ عَلى اَعْداءِ دينِكَ اَجْمَعينَ، وَاَلْهِمْهُ اَنْ لا يَدَعَ مِنْهُمْ رُكْناً الّا هَدَّهُ، وَلا هاماً الّا قَدَّهُ، وَلا كَيْداً الّا رَدَّهُ، وَلا فاسِقاً الّا حَدَّهُ، وَلا فِرْعَوْنَ الّا اَهْلَكَهُ، وَلا سِتْراً الّا هَتَكَهُ، وَلا عِلْماًالّا نَكَّسَهُ، وَلا سُلْطاناً الّا كَسَبَهُ، وَلا رُمْحاً الّا قَصَفَهُ، وَلا مِطْرَداً الّا خَرَقَهُ، وَلا جُنْداً الّا فَرَّقَهُ، وَلا مِنْبَراً الّا اَحْرَقَهُ، وَلا سَيْفاً الّا كَسَرَهُ، وَلا صَنَماً الّا رَضَّهُ، وَلا دَماً الّا اَراقَهُ، وَلا جَوْراً الّا اَبادَهُ، وَلا حِصْناً الّا هَدَمَهُ، وَلا باباً الّا رَدَمَهُ، وَلا قَصْراً الّا خَرَّبَهُ، وَلا مَسْكَناً الّا فَتَّشَهُ، وَلا سَهْلاً الّا أَوْطَأَهُ، وَلا جَبَلاً الّا صَعِدَهُ، وَلاكَنْزاً الّا اَخْرَجَهُ، بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ ."},{"type":"AboutText","content":"أقول : أورد المفيد الزّيارة السّالفة الّتي أوّلها اَللهُ اَكْبَرُ لا اِلـهَ اِلاَّ اللهُ وَاللهُ اَكْبَرُ ثمّ قال : روى بطريق آخر تقول عند نزول السّرداب : اَلسَّلامُ عَلَى الْحَقِّ الْجَديدِ فأورد الزّيارة الى موضع صلاتها . ثمّ قال : ثمّ تصلّي صلاة الزّيارة اثنتي عشرة ركعة كلّ ركعتين بتسليمة ، ثمّ تدعو بعدها بالدّعاء المرويّ عنه (عليه السلام) وهو :"},{"type":"Text","content":"اِللهمَّ عَظُمَ الْبَلاءُ، وَبَرِحَ الْخَفاءُ، وَانْكَشَفَ الْغِطاءُ، وَضاقَتِ الاَْرْضُ وَمُنِعَتِ السَّماءُ وَاِلَيْكَ يا ربّ الْمُشْتَكى وَعَلَيْكَ الْمُعَوَّلُ فِى الشِّدَّةِ وَالرَّخاءِ اَللّـهُمَّ صَلِّ عَلى مُحَمَّدٍ وَ آله الَّذينَ فَرَضْتَ عَلَيْنا طاعَتَهُمْ َفعَرَّفْتَنا بِذلِكَ مَنْزِلَتَهُمْ فَرِّجْ عَنّا بِحَقِّهِمْ فَرَجاً عاجِلاً كَلَمْحِ الْبَصَرِ اَوْ هُوَ اَقْرَبُ مِنْ ذلكَ يا مُحَمَّدُ يا عَلِيُّ، يا عَلِيُّ يا مُحَمَّدُ َانْصُراني فَاِنَّكُما ناصِرايِ وَاَكْفياني فَاَنَّكُما كافِياي يا مَوْلاي يا صاحِبَ الزَّمانِ الْغَوْثَ الْغَوْثَ الْغَوْثَ، اَدْرِكْني اَدْرِكْني اَدْرِكْني ."},{"type":"AboutText","content":"أقول : هذا دعاء شريف وينبغي أن يكرّر الدّعاء به في ذلك الحرم الشّريف وفي غيره من الأماكن ونحن قد أثبتناه في الباب الأوّل باختلاف يسير ."},{"type":"Text","content":"الزّيارة الاُخرى"},{"type":"Text","content":"ما رواها السّيد ابن طاووس قال : صلّ ركعتين وقُل بعدها : سَلامُ اللهِ الْكامِلُ التّامُّ الشّامِلُ ... الخ ، ونحن قد أثبتناها في الفصل السّابع من الباب الأوّل تحت عنوان الاستغاثة به (عليه السلام) نقلاً عن كتاب الكلم الطّيب فراجعها هناك."},{"type":"AboutText","content":"أقول : أفرد السيد ابن طاووس في كتاب مصباح الزائر فصلاً لأعمال السّرداب المقدّس فأثبت فيه ستّ زيارات ثمّ قال : ويلحق بهذا الفصل دعاء النّدبة وما يُزار به مولانا صاحب الأمر (عليه السلام) في كلّ يوم بعد فريضة الفجر، وهي السّابعة من الزّيارات، ودعاء العهد الذي أمرنا بتلاوته في زمان الغيبة وما يدعى به عند إرادة الخروج من ذلك الحرم الشّريف، ثمّ بدأ في ذكر هذه الاُمور الأربعة ونحن نتابعه في هذا الكتاب المبارك بذكر تلك الاُمور. الأمر الأول دعاء الندبة: ويستحب أن يدعى به في الأعياد الأربعة أي عيد الفطر والأضحى والغدير ويوم الجُمعة وهو :"},{"type":"Text","content":"اَلْحَمْدُ للهِ رَبِّ الْعالَمينَ وَصَلَّى اللهُ عَلى سَيِّدِنا مُحَمَّدٍ نَبِيِّهِ وَآلِهِ وَسَلَّمَ تَسْليماً، اَللّـهُمَّ لَكَ الْحَمْدُ عَلى ما جَرى بِهِ قَضاؤكَ في اَوْلِيائِكَ الَّذينَ اسْتَخْلَصْتَهُمْ لِنَفْسِكَ وَدينِكَ، اِذِ اخْتَرْتَ لَهُمْ جَزيلَ ما عِنْدَكَ مِنَ النَّعيمِ الْمُقيمِ الَّذي لا زَوالَ لَهُ وَلاَ اضْمِحْلالَ، بَعْدَ اَنْ شَرَطْتَ عَلَيْهِمُ الزُّهْدَ في دَرَجاتِ هذِهِ الدُّنْيَا الدَّنِيَّةِ وَزُخْرُفِها وَزِبْرِجِها، فَشَرَطُوا لَكَ ذلِكَ وَعَلِمْتَ مِنْهُمُ الْوَفاءَ بِهِ فَقَبِلْتَهُمْ وَقَرَّبْتَهُمْ، وَقَدَّمْتَ لَهُمُ الذِّكْرَ الْعَلِيَّ وَالثَّناءَ الْجَلِىَّ، وَاَهْبَطْتَ عَلَيْهِمْ مَلائِكَتَكَ وَكَرَّمْتَهُمْ بِوَحْيِكَ، وَرَفَدْتَهُمْ بِعِلْمِكَ، وَجَعَلْتَهُمُ الذَّريعَةَ اِلَيْكَ وَالْوَسيلَةَ اِلى رِضْوانِكَ، فَبَعْضٌ اَسْكَنْتَهُ جَنَّتَكَ اِلى اَنْ اَخْرَجْتَهُ مِنْها، وَبَعْضٌ حَمَلْتَهُ في فُلْكِكَ وَنَجَّيْتَهُ وَمَنْ آمَنَ مَعَهُ مِنَ الْهَلَكَةِ بِرَحْمَتِكَ، وَبَعْضٌ اتَّخَذْتَهُ لِنَفْسِكَ خَليلاً وَسَأَلَكَ لِسانَ صِدْق فِي الاْخِرينَ فَاَجَبْتَهُ وَجَعَلْتَ ذلِكَ عَلِيّاً، وَبَعْضٌ كَلَّمْتَهُ مِنْ شَجَـرَةٍ تَكْليماً وَجَعَلْتَ لَهُ مِنْ اَخيهِ رِدْءاً وَوَزيراً، وَبَعْضٌ اَوْلَدْتَهُ مِنْ غَيْرِ اَب وَآتَيْتَهُ الْبَيِّناتِ وَاَيَّدْتَهُ بِرُوحِ الْقُدُسِ، وَكُلٌّ شَرَعْتَ لَهُ شَريعَةً، وَنَهَجْتَ لَهُ مِنْهاجاً، وَتَخَيَّرْتَ لَهُ اَوْصِياءَ، مُسْتَحْفِظاً بَعْدَ مُسْتَحْفِظ مِنْ مُدَّةٍ اِلى مُدَّةٍ، اِقامَةً لِدينِكَ، وَحُجَّةً عَلى عِبادِكَ، وَلِئَلّا يَزُولَ الْحَقُّ عَنْ مَقَرِّهِ وَيَغْلِبَ الْباطِلُ عَلى اَهْلِهِ، وَلا يَقُولَ اَحَدٌ لَوْلا اَرْسَلْتَ اِلَيْنا رَسُولاً مُنْذِراً وَاَقَمْتَ لَنا عَلَماً هادِياً فَنَتَّبِـعَ آياتِكَ مِنْ قَبْلِ اَنْ نَذِلَّ وَنَخْزى، اِلى اَنِ انْتَهَيْتَ بِالاَْمْرِ اِلى حَبيبِكَ وَنَجيبِكَ مُحَمَّدٍ صَلَّى اللهُ عَلَيْهِ وَآلِهِ، فَكانَ كَمَا انْتَجَبْتَهُ سَيِّدَ مَنْ خَلَقْتَهُ، وَصَفْوَةَ مَنِ اصْطَفَيْتَهُ، وَاَفْضَلَ مَنِ اجْتَبَيْتَهُ، وَاَكْرَمَ مَنِ اعْتَمَدْتَهُ، قَدَّمْتَهُ عَلى اَنْبِيائِكَ، وَبَعَثْتَهُ اِلَى الثَّقَلَيْنِ مِنْ عِبادِكَ، وَاَوْطَأتَهُ مَشارِقَكَ وَمَغارِبَكَ، وَسَخَّرْتَ لَهُ الْبُراقَ، وَعَرَجْتَ) به( بِرُوْحِهِ اِلى سَمائِكَ، وَاَوْدَعْتَهُ عِلْمَ ما كانَ وَما يَكُونُ اِلَى انْقِضاءِ خَلْقِكَ، ثُمَّ نَصَرْتَهُ بِالرُّعْبِ، وَحَفَفْتَهُ بِجَبْرَئيلَ وَميكائيلَ وَالْمُسَوِّمينَ مِنْ مَلائِكَتِكَ وَوَعَدْتَهُ اَنْ تُظْهِرَ دينَهُ عَلَى الدّينِ كُلِّهِ وَلَوْ كَرِهَ الْمُشْرِكُونَ، وَذلِكَ بَعْدَ اَنْ بَوَّأتَهُ مَبَوَّأَ صِدْقٍ مِنْ اَهْلِهِ، وَجَعَلْتَ لَهُ وَلَهُمْ اَوَّلَ بَيْتٍ وُضِعَ لِلنّاسِ لَلَّذي بِبَكَّةَ مُبارَكاً وَهُدىً لِلْعالَمينَ، فيهِ آياتٌ بَيِّناتٌ مَقامُ اِبْراهيمَ وَمَنْ دَخَلَهُ كانَ آمِناً، وَقُلْتَ (اِنَّما يُريدُ اللهُ لِيُذْهِبَ عَنْكُمُ الرِّجْسَ اَهْلَ الْبَيْتِ وَيُطَهِّرَكُمْ تَطْهيراً) ثُمَّ جَعَلْتَ اَجْرَ مُحَمَّدٍ صَلَواتُكَ عَلَيْهِ وَآلِهِ مَوَدَّتَهُمْ في كِتابِكَ فَقُلْتَ: (قُلْ لا اَسْاَلُكُمْ عَلَيْهِ اَجْراً اِلاَّ الْمَوَدَّةَ فِى الْقُرْبى) وَقُلْتَ (ما سَألْتُكُمْ مِنْ اَجْر فَهُوَلَكُمْ) وَقُلْتَ: (ما اَسْاَلُكُمْ عَلَيْهِ مِنْ اَجْر الّا مَنْ شاءَ اَنْ يَتَّخِذَ اِلى رَبِّهِ سَبيلاً)، فَكانُوا هُمُ السَّبيلَ اِلَيْكَ وَالْمَسْلَكَ اِلى رِضْوانِكَ، فَلَمَّا انْقَضَتْ اَيّامُهُ اَقامَ وَلِيَّهُ عَلِيَّ بْنَ اَبي طالِب صَلَواتُكَ عَلَيْهِما وَآلِهِما هادِياً، اِذْ كانَ هُوَ الْمُنْذِرَ وَلِكُلِّ قَوْم هاد، فَقالَ وَالْمَلأُ اَمامَهُ: مَنْ كُنْتُ مَوْلاهُ فَعَلِيٌّ مَوْلاهُ اَللّـهُمَّ والِ مَنْ والاهُ وَعادِ مَنْ عاداهُ وَانْصُرْ مَنْ نَصَرَهُ وَاخْذُلْ مَنْ خَذَلَهُ، وَقالَ: مَنْ كُنْتُ اَنَا نَبِيَّهُ فَعَلِيٌّ اَميرُهُ، وَقالَ اَنَا وَعَلِيٌّ مِنْ شَجَرَة واحِدَة وَسائِرُالنَّاسِ مِنْ شَجَر شَتّى، وَاَحَلَّهُ مَحَلَّ هارُونَ مِنْ مُوسى، فَقال لَهُ اَنْتَ مِنّي بِمَنْزِلَةِ هارُونَ مِنْ مُوسى الّا اَنَّهُ لا نَبِيَّ بَعْدي، وَزَوَّجَهُ ابْنَتَهُ سَيِّدَةَ نِساءِ الْعالَمينَ، وَاَحَلَّ لَهُ مِنْ مَسْجِدِهِ ما حَلَّ لَهُ، وَسَدَّ الاَْبْوابَ اِلاّ بابَهُ، ثُمَّ اَوْدَعَهُ عِلْمَهُ وَحِكْمَتَهُ فَقالَ: اَنـَا مَدينَةُ الْعِلْمِ وَعَلِىٌّ بابُها، فَمَنْ اَرادَ الْمَدينَةَ وَالْحِكْمَةَ فَلْيَاْتِها مِنْ بابِها، ثُمَّ قالَ: اَنْتَ اَخي وَوَصِيّي وَوارِثي، لَحْمُكَ مِنْ لَحْمي وَدَمُكَ مِنْ دَمي وَسِلْمُكَ سِلْمي وَحَرْبُكَ حَرْبي وَالإيمانُ مُخالِطٌ لَحْمَكَ وَدَمَكَ كَما خالَطَ لَحْمي وَدَمي، وَاَنْتَ غَداً عَلَى الْحَوْضِ خَليفَتي وَاَنْتَ تَقْضي دَيْني وَتُنْجِزُ عِداتي وَشيعَتُكَ عَلى مَنابِرَ مِنْ نُور مُبْيَضَّةً وُجُوهُهُمْ حَوْلي فِي الْجَنَّةِ وَهُمْ جيراني، وَلَوْلا اَنْتَ يا عَلِيُّ لَمْ يُعْرَفِ الْمُؤْمِنُونَ بَعْدي، وَكانَ بَعْدَهُ هُدىً مِنَ الضَّلالِ وَنُوراً مِنَ الْعَمى، وَحَبْلَ اللهِ الْمَتينَ وَصِراطَهُ الْمُسْتَقيمَ، لا يُسْبَقُ بِقَرابَةٍ في رَحِمٍ وَلا بِسابِقَةٍ في دينٍ، وَلا يُلْحَقُ في مَنْقَبَةٍ مِنْ مَناقِبِهِ، يَحْذُو حَذْوَ الرَّسُولِ صَلَّى اللهُ عَلَيْهِما وَآلِهِما، وَيُقاتِلُ عَلَى التَّأويلِ وَلا تَأخُذُهُ فِي اللهِ لَوْمَةُ لائِمٍ، قَدْ وَتَرَ فيهِ صَناديدَ الْعَرَبِ وَقَتَلَ اَبْطالَهُمْ وَناوَشَ (ناهش) ذُؤْبانَهُمْ، فَاَوْدَعَ قُلُوبَهُمْ اَحْقاداً بَدْرِيَّةً وَخَيْبَرِيَّةً وَحُنَيْنِيَّةً وَغَيْرَهُنَّ، فَاَضَبَّتْ عَلى عَداوَتِهِ وَاَكَبَّتْ عَلى مُنابَذَتِهِ، حَتّى قَتَلَ النّاكِثينَ وَالْقاسِطينَ وَالْمارِقينَ، وَلَمّا قَضى نَحْبَهُ وَقَتَلَهُ اَشْقَى الاْخِرينَ يَتْبَعُ اَشْقَى الاَْوَّلينَ، لَمْ يُمْتَثَلْ اَمْرُ رَسُولِ اللهِ صَلَّى اللهُ عَلَيْهِ وَآلِهِ فِي الْهادينَ بَعْدَ الْهادينَ، وَالاُْمَّةُ مُصِرَّةٌ عَلى مَقْتِهِ مُجْتَمِعَةٌ عَلى قَطيعَةِ رَحِمِهِ وَاِقْصاءِ وُلْدِهِ اِلّا الْقَليلَ مِمَّنْ وَفى لِرِعايَةِ الْحَقِّ فيهِمْ، فَقُتِلَ مَنْ قُتِلَ، وَسُبِيَ مَنْ سُبِيَ وَاُقْصِيَ مَنْ اُقْصِيَ وَجَرَى الْقَضاءُ لَهُمْ بِما يُرْجى لَهُ حُسْنُ الْمَثُوبَةِ، اِذْ كانَتِ الاَْرْضُ للهِ يُورِثُها مَنْ يَشاءُ مِنْ عِبادِهِ وَالْعاقِبَةُ لِلْمُتَّقينَ، وَسُبْحانَ رَبِّنا اِنْ كانَ وَعْدُ رَبِّنا لَمَفْعُولاً، وَلَنْ يُخْلِفَ اللهُ وَعْدَهُ وَهُوَ الْعَزيزُ الْحَكيمُ، فَعَلَى الاَْطائِبِ مِنْ اَهْلِ بَيْتِ مُحَمَّدٍ وَعَلِيٍّ صَلَّى اللهُ عَلَيْهِما وَآلِهِما فَلْيَبْكِ الْباكُونَ، وَاِيّاهُمْ فَلْيَنْدُبِ النّادِبُونَ، وَلِمِثْلِهِمْ فَلْتَذْرِفِ (فَلْتًدرِ) الدُّمُوعُ، وَلْيَصْرُخِ الصّارِخُونَ، وَيَضِجَّ الضّاجُّونَ، وَيَعِـجَّ الْعاجُّوَن، اَيْنَ الْحَسَنُ اَيْنَ الْحُسَيْنُ اَيْنَ اَبْناءُ الْحُسَيْنِ، صالِحٌ بَعْدَ صالِـحٍ، وَصادِقٌ بَعْدَ صادِقٍ، اَيْنَ السَّبيلُ بَعْدَ السَّبيلِ، اَيْنَ الْخِيَرَةُ بَعْدَ الْخِيَرَةِ، اَيْنَ الشُّمُوسُ الطّالِعَةُ، اَيْنَ الاَْقْمارُ الْمُنيرَةُ، اَيْنَ الاَْنْجُمُ الزّاهِرَةُ، اَيْنَ اَعْلامُ الدّينِ وَقَواعِدُ الْعِلْمِ، اَيْنَ بَقِيَّةُ اللهِ الَّتي لا تَخْلُو مِنَ الْعِتْرَةِ الْهادِيـَةِ، اَيـْنَ الـْمُعَدُّ لِـقَطْعِ دابِرِ الظَّلَمَةِ، اَيْنَ الْمُنْتَظَرُ لاِِقامَةِ الاَْمْتِ وَاْلعِوَجِ، اَيْنَ الْمُرْتَجى لاِزالَةِ الْجَوْرِ وَالْعُدْوانِ، اَيْنَ الْمُدَّخَرُ لِتَجْديدِ الْفَرآئِضِ و َالسُّنَنِ، اَيْنَ الْمُتَخَيَّرُ لاِِعادَةِ الْمِلَّةِ وَالشَّريعَةِ، اَيْنَ الْمُؤَمَّلُ لاِِحْياءِ الْكِتابِ وَحُدُودِهِ، اَيْنَ مُحْيي مَعالِمِ الدّينِ وَاَهْلِهِ، اَيْنَ قاصِمُ شَوْكَةِ الْمُعْتَدينَ، اَيْنَ هادِمُ اَبْنِيَةِ الشِّرْكِ وَالنِّفاقِ، اَيْنَ مُبيدُ اَهْلِ الْفُسُوقِ وَالْعِصْيانِ وَالطُّغْيانِ، اَيْنَ حاصِدُ فُرُوعِ الْغَيِّ وَالشِّقاقِ (النِفاقِ)، اَيْنَ طامِسُ آثارِ الزَّيْغِ وَالاَْهْواء،ِ اَيْنَ قاطِعُ حَبائِلِ الْكِذْبِ (الكَذِبِ) وَالاِْفْتِراءِ، اَيْنَ مُبيدُ الْعُتاةِ وَالْمَرَدَةِ، اَيْنَ مُسْتَأصِلُ اَهْلِ الْعِنادِ وَالتَّضْليلِ وَالاِْلْحادِ، اَيْنَ مُـعِزُّ الاَْوْلِياءِ وَمُذِلُّ الاَْعْداءِ، اَيْنَ جامِعُ الْكَلِمَةِ (الكَلِمِ)عَلَى التَّقْوى، اَيْنَ بابُ اللهِ الَّذى مِنْهُ يُؤْتى، اَيْنَ وَجْهُ اللهِ الَّذى اِلَيْهِ يَتَوَجَّهُ الاَْوْلِياءُ، اَيْنَ السَّبَبُ الْمُتَّصِلُ بَيْنَ الاَْرْضِ وَالسَّماءِ، اَيْنَ صاحِبُ يَوْمِ الْفَتْحِ وَناشِرُ رايَةِ الْهُدى، اَيْنَ مُؤَلِّفُ شَمْلِ الصَّلاحِ وَالرِّضا، اَيْنَ الطّالِبُ بِذُحُولِ الاَْنْبِياءِ وَاَبْناءِ الاَْنْبِياءِ، اَيْنَ الطّالِبُ (المُطالِبُ) بِدَمِ الْمَقْتُولِ بِكَرْبَلاءَ، اَيْنَ الْمَنْصُورُ عَلى مَنِ اعْتَدى عَلَيْهِ وَافْتَرى، اَيْنَ الْمُضْطَرُّ الَّذي يُجابُ اِذا دَعا اَيْنَ صَدْرُ الْخَلائِقِ ذُوالْبِرِّ وَالتَّقْوى، اَيْنَ ابْنُ النَّبِىِّ الْمُصْطَفى، وَابْنُ عَلِيٍّ الْمُرْتَضى، وَابْنُ خَديجَةَ الْغَرّآءِ، وَابْنُ فاطِمَةَ الْكُبْرى، بِاَبي اَنْتَ وَاُمّي وَنَفْسي لَكَ الْوِقاءُ وَالْحِمى، يَا بْنَ السّادَةِ الْمُقَرَّبينَ، يَا بْنَ النُّجَباءِ الاَْكْرَمينَ، يَا بْنَ الْهُداةِ الْمَهْدِيّينَ (المُهْتَدينَ)، يَا بْنَ الْخِيَرَةِ الْمُهَذَّبينَ، يَا بْنَ الْغَطارِفَةِ الاَْنْجَبينَ، يَا بْنَ الاَْطائِبِ الْمُطَهَّرينَ (المُتَطَهْريِِنَ)، يَا بْنَ الْخَضارِمَةِ الْمُنْتَجَبينَ، يَا بْنَ الْقَماقِمَةِ الاَْكْرَمينَ (الأكْبَرينَ)، يَا بْنَ الْبُدُورِ الْمُنيرَةِ، يَا بْنَ السُّرُجِ الْمُضيئَةِ، يَا بْنَ الشُّهُبِ الثّاقِبَةِ، يَا بْنَ الاَْنْجُمِ الزّاهِرَةِ، يَا بْنَ السُّبُلِ الْواضِحَةِ، يَا بْنَ الاَْعْلامِ الّلائِحَةِ، يَا بْنَ الْعُلُومِ الْكامِلَةِ، يَا بْنَ السُّنَنِ الْمَشْهُورَةِ، يَا بْنَ الْمَعالِمِ الْمَأثُورَةِ، يَا بْنَ الْمُعْجِزاتِ الْمَوْجُودَةِ، يَا بْنَ الدَّلائِلِ الْمَشْهُودَةِ (المَشْهُورَةِ)، يَا بْنَ الصـِّراطِ الْمُسْتَقيمِ، يَا بْنَ النَّبَأِ الْعَظيمِ، يَا بْنَ مَنْ هُوَ في اُمِّ الْكِتابِ لَدَى اللهِ عَلِيٌّ حَكيمٌ، يَا بْنَ الآياتِ وَالْبَيِّناتِ، يَا بْنَ الدَّلائِلِ الظّاهِراتِ، يَا بْنَ الْبَراهينِ الْواضِحاتِ الْباهِراتِ، يَا بْنَ الْحُجَجِ الْبالِغاتِ، يَا بْنَ النِّعَمِ السّابِغاتِ، يَا بْنَ طه وَالْـمُحْكَماتِ، يَا بْنَ يس وَالذّارِياتِ، يَا بْنَ الطُّورِ وَالْعادِياتِ، يَا بْنَ مَنْ دَنا فَتَدَلّى فَكانَ قابَ قَوْسَيْنِ اَوْ اَدْنى دُنُوّاً وَاقْتِراباً مِنَ الْعَلِيِّ الاَْعْلى، لَيْتَ شِعْري اَيْنَ اسْتَقَرَّتْ بِكَ النَّوى، بَلْ اَيُّ اَرْض تُقِلُّكَ اَوْ ثَرى، اَبِرَضْوى اَوْ غَيْرِها اَمْ ذي طُوى، عَزيزٌ عَلَيَّ اَنْ اَرَى الْخَلْقَ وَلا تُرى وَلا اَسْمَعُ لَكَ حَسيساً وَلا نَجْوى، عَزيزٌ عَلَيَّ اَنْ (لا تُحِيطَ بِِيَ دُونكَ) تُحيطَ بِكَ دُونِيَ الْبَلْوى وَلا يَنالُكَ مِنّي ضَجيجٌ وَلا شَكْوى، بِنَفْسي اَنْتَ مِنْ مُغَيَّبٍ لَمْ يَخْلُ مِنّا، بِنَفْسي اَنْتَ مِنْ نازِحٍ ما نَزَحَ (يَنْزِحُ) عَنّا، بِنَفْسي اَنْتَ اُمْنِيَّةُ شائِقٍ يَتَمَنّى، مِنْ مُؤْمِن وَمُؤْمِنَةٍ ذَكَرا فَحَنّا، بِنَفْسي اَنْتَ مِنْ عَقيدِ عِزٍّ لايُسامى، بِنَفْسي اَنْتَ مِنْ اَثيلِ مَجْدٍ لا يُجارى، بِنَفْسي اَنْتَ مِنْ تِلادِ نِعَمٍ لا تُضاهى، بِنَفْسي اَنْتَ مِنْ نَصيفِ شَرَف لا يُساوى، اِلى مَتى اَحارُ فيكَ يا مَوْلايَ وَاِلى مَتي، وَاَىَّ خِطابٍ اَصِفُ فيكَ وَاَيَّ نَجْوى، عَزيزٌ عَلَيَّ اَنْ اُجابَ دُونَكَ وَاُناغى، عَزيزٌ عَلَيَّ اَنْ اَبْكِيَكَ وَيَخْذُلَكَ الْوَرى، عَزيزٌ عَلَيَّ اَنْ يَجْرِيَ عَلَيْكَ دُونَهُمْ ما جَرى، هَلْ مِنْ مُعينٍ فَاُطيلَ مَعَهُ الْعَويلَ وَالْبُكاءَ، هَلْ مِنْ جَزُوعٍ فَاُساعِدَ جَزَعَهُ اِذا خَلا، هَلْ قَذِيَتْ عَيْنٌ فَساعَدَتْها عَيْني عَلَى الْقَذى، هَلْ اِلَيْكَ يَا بْنَ اَحْمَدَ سَبيلٌ فَتُلْقى، هَلْ يَتَّصِلُ يَوْمُنا مِنْكَ بِعِدَةٍ فَنَحْظى، مَتى نَرِدُ مَناهِلَكَ الرَّوِيَّةَ فَنَرْوى، مَتى نَنْتَقِعُ مِنْ عَذْبِ مائِكَ فَقَدْ طالَ الصَّدى، مَتى نُغاديكَ وَنُراوِحُكَ فَنُقِرَّ عَيْناً (فَتَقُرُ عًُيًُوننا)، مَتى تَرانا وَنَراكَ وَقَدْ نَشَرْتَ لِواءَ النَّصْرِ تُرى، اَتَرانا نَحُفُّ بِكَ وَاَنْتَ تَاُمُّ الْمَلاََ وَقَدْ مَلأْتَ الاَْرْضَ عَدْلاً وَاَذَقْتَ اَعْداءَكَ هَواناً وَعِقاباً، وَاَبَرْتَ الْعُتاةَ وَجَحَدَةَ الْحَقِّ، وَقَطَعْتَ دابِرَ الْمُتَكَبِّرينَ، وَاجْتَثَثْتَ اُصُولَ الظّالِمينَ، وَنَحْنُ نَقُولُ الْحَمْدُ للهِ رَبِّ الْعالَمينَ، اَللّـهُمَّ اَنْتَ كَشّافُ ْالكُرَبِ وَالْبَلْوى، وَاِلَيْكَ اَسْتَعْدى فَعِنْدَكَ الْعَدْوى، وَاَنْتَ رَبُّ الاْخِرَةِ وَالدُّنْيا (الاُولي)، فَاَغِثْ يا غِياثَ الْمُسْتَغيثينَ عُبَيْدَكَ الْمُبْتَلى، وَاَرِهِ سَيِّدَهُ يا شَديدَ الْقُوى، وَاَزِلْ عَنْهُ بِهِ الاَْسى وَالْجَوى، وَبَرِّدْ غَليلَهُ يا مَنْ عَلَى الْعَرْشِ اسْتَوى، وَمَنْ اِلَيْهِ الرُّجْعى وَالْمُنْتَهى، اَللّـهُمَّ وَنَحْنُ عَبيدُكَ التّائِقُونَ (الشائقون) اِلى وَلِيِّكَ الْمُذَكِّرِ بِكَ وَبِنَبِيِّكَ، خَلَقْتَهُ لَنا عِصْمَةً وَمَلاذاً، وَاَقَمْتَهُ لَنا قِواماً وَمَعاذاً، وَجَعَلْتَهُ لِلْمُؤْمِنينَ مِنّا اِماماً، فَبَلِّغْهُ مِنّا تَحِيَّةً وَسَلاماً، وَزِدْنا بِذلِكَ يارَبِّ اِكْراماً، وَاجْعَلْ مُسْتَقَرَّهُ لَنا مُسْتَقَرّاً وَمُقاماً، وَاَتْمِمْ نِعْمَتَكَ بِتَقْديمِكَ اِيّاهُ اَمامَنا حَتّى تُورِدَنا جِنانَكَ (جَنّاتِكَ) وَمُرافَقَةَ الشُّهَداءِ مِنْ خُلَصائِكَ، اَللّـهُمَّ صَلِّ عَلى مُحَمَّدٍ وَآلِ مُحَمَّدٍ، وَصَلِّ عَلى مُحَمَّدٍ جَدِّهِ وَرَسُولِكَ السَّيِّدِ الاَكْبَرِ، وَعَلى اَبيهِ السَّيِّدِ الاَصْغَرِ، وَجَدَّتِهِ الصِّدّيقَةِ الْكُبْرى فاطِمَةَ بِنْتِ مُحَمَّدٍ صَلَّى اللهُ عَلَيْهِ وَآلِهِ، وَعَلى مَنِ اصْطَفَيْتَ مِنْ آبائِهِ الْبَرَرَةِ، وَعَلَيْهِ اَفْضَلَ وَاَكْمَلَ وَاَتَمَّ وَاَدْوَمَ وَاَكْثَرَ وَاَوْفَرَ ما صَلَّيْتَ عَلى اَحَدٍ مِنْ اَصْفِيائِكَ وَخِيَرَتِكَ مِنْ خَلْقِكَ، وَصَلِّ عَلَيْهِ صَلاةً لا غايَةَ لِعَدَدِها وَلا نِهايَةَ لِمَدَدِها وَلا نَفادَ لاَِمَدِها، اَللّـهُمَّ وَاَقِمْ بِهِ الْحَقَّ وَاَدْحِضْ بِهِ الْباطِلَ وَاَدِلْ بِهِ اَوْلِياءَكَ وَاَذْلِلْ بِهِ اَعْداءَكَ وَصِلِ اللّهُمَّ بَيْنَنا وَبَيْنَهُ وُصْلَةً تُؤَدّى اِلى مُرافَقَةِ سَلَفِهِ، وَاجْعَلْنا مِمَّنْ يَأخُذُ بِحُجْزَتِهِمْ، وَيَمْكُثُ في ظِلِّهِمْ، وَاَعِنّا عَلى تَأدِيَةِ حُقُوقِهِ اِلَيْهِ، وَالاْجْتِهادِ في طاعَتِهِ، وَاجْتِنابِ مَعْصِيَتِهِ، وَامْنُنْ عَلَيْنا بِرِضاهُ، وَهَبْ لَنا رَأَفَتَهُ وَرَحْمَتَهُ وَدُعاءَهُ وَخَيْرَهُ مانَنالُ بِهِ سَعَةً مِنْ رَحْمَتِكَ وَفَوْزاً عِنْدَكَ، وَاجْعَلْ صَلاتَنا بِهِ مَقبُولَةً، وَذُنُوبَنا بِهِ مَغْفُورَةً، وَدُعاءَنا بِهِ مُسْتَجاباً وَاجْعَلْ اَرْزاقَنا بِهِ مَبْسُوطَةً، وَهُمُومَنا بِهِ مَكْفِيَّةً، وَحَوآئِجَنا بِهِ مَقْضِيَّةً، وَاَقْبِلْ اِلَيْنا بِوَجْهِكَ الْكَريمِ وَاقْبَلْ تَقَرُّبَنا اِلَيْكَ، وَانْظُرْ اِلَيْنا نَظْرَةً رَحيمَةً نَسْتَكْمِلُ بِهَا الْكَرامَةَ عِنْدَكَ، ثُمَّ لا تَصْرِفْها عَنّا بِجُودِكَ، وَاسْقِنا مِنْ حَوْضِ جَدِّهِ صَلَّى اللهُ عَلَيْهِ وَآلِهِ بِكَأسِهِ وَبِيَدِهِ رَيّاً رَوِيّاً هَنيئاً سائِغاً لا ظَمَاَ بَعْدَهُ يا اَرْحَمَ الرّاحِمينَ ."}],"preview":"اَللّـهُمَّ صَلِّ عَلى مُحَمَّد وَاَهْلِ بَيْتِهِ، وَصَلِّ عَلى وَلِيِّ الْحَسَنِ وَوَصِيِّهِ وَوارِثِهِ الْقائِمِ بِاَمْرِكَ، وَالْغائِبِ فى خَلْقِكَ، وَالْمُنْتَظِرِ لاِِذْنِكَ،","hasTranslate":false},{"id":"mf_ar_260","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"ثمّ صلّ صلاة الزّيارة وقد تقدّم وصفها ثمّ تدعو بما أحببت فيجاب لك ان شاء الله تعالى","blocks":[{"type":"Text","content":"الثّاني : ما يُزار به مولانا صاحب الزمان صلوات الله وسلامه عليه كلّ يوم بعد صلاة الفجر وهي :"},{"type":"Text","content":"اَللّـهُمَّ بَلِّغْ مَوْلاىَ صاحِبَ الزَّمانِ صَلَواتُ اللهِ عَلَيْهِ عَنْ جَميعِ الْمُؤْمِنينَ وَالْمُؤْمِناتِ في مَشارِقِ الاَْرْضِ وَمَغارِبِها، وَبَرِّها وَبَحْرِها وَسَهْلِها وَجَبَلِها، حَيِّهِمْ وَمَيِّتِهِمْ، وَعَنْ والِدِيَّ وَوَُلَْدي وَعَنّي مِنَ الصَّلَواتِ وَالتَّحِيّاتِ زِنَةَ عَرْشِ اللهِ وَمِدادَ كَلِماتِهِ، وَمُنْتَهى رِضاهُ وَعَدَدَ ما اَحْصاهُ كِتابُهُ وَاَحاطَ بِهِ عِلْمُهُ، اَللّـهُمَّ اِنّي اُجَدِّدُ لَهُ في هذَا الْيَوْمِ وَفي كُلِّ يَوْم عَهْداً وَعَقْداً وَبَيْعَةً في رَقَبَتي اَللّـهُمَّ كَما شَرَّفْتَني بِهذَا التَّشْريفِ وَفَضَّلْتَنى بِهذِهِ الْفَضيلَةِ وَخَصَصْتَنى بِهذِهِ النِّعْمَةِ، فَصَلِّ عَلى مَوْلايَ وَسَيِّدي صاحِبِ الزَّمانِ، وَاجْعَلْني مِنْ اَنْصارِهِ وَاَشْياعِهِ وَالذّابّينَ عَنْهُ، وَاجْعَلْني مِنَ الْمُسْتَشْهَدينَ بَيْنَ يَدَيْهِ طائِعاً غَيْرَ مُكْرَه فِي الصَّفِّ الَّذي نَعَتَّ اَهْلَهُ في كِتابِكَ فَقُلْتَ: (صَفّاً كَاَنَّهُمْ بُنْيانٌ مَرْصوُصٌ) عَلى طاعَتِكَ وَطاعَةِ رَسُولِكَ وَآلِهِ عليهم السلام، اَللّـهُمَّ هذِهِ بَيْعَةٌ لَهُ في عُنُقي اِلى يَوْمِ الْقِيامَةِ ."},{"type":"AboutText","content":"أقول : قال العلامة المجلسي في البحار : وجدت في بعض الكتب القديمة بعد ذلك، ويصفق بيده اليمنى على اليسرى كتصفيق البيعة ."},{"type":"AboutText","content":"واعلم أيضاً انّا قد ذكرنا في أعمال السّرداب المقدّس زيارات أربع فهذه هي خامسة الزّيارات في كتابنا هذا، وقد أوردنا أيضاً زيارة له (عليه السلام) في أيّام الجُمَع في الباب الاوّل عند ذكر زيارات الحجج الطّاهرين (عليهم السلام)في أيّام الاسبوع ."}],"preview":"الثّاني : ما يُزار به مولانا صاحب الزمان صلوات الله وسلامه عليه كلّ يوم بعد صلاة الفجر وهي :","hasTranslate":false},{"id":"mf_ar_261","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"الثّالث : دعاء العهد","blocks":[{"type":"AboutText","content":"روي عن الصّادق (عليه السلام) انّه قال : من دعا الى الله تعالى أربعين صباحاً بهذا العهد كان من أنصار قائمنا، فإن مات قبله أخرجه الله تعالى من قبره وأعطاه بكلّ كلمة ألف حسنة ومَحا عنه ألف سيّئة، وهو هذا :"},{"type":"Text","content":"اَللّـهُمَّ رَبَّ النُّورِ الْعَظيمِ، وَرَبَّ الْكُرْسِيِّ الرَّفيعِ، وَرَبَّ الْبَحْرِ الْمَسْجُورِ، وَمُنْزِلَ التَّوْراةِ وَالاِْنْجيلِ وَالزَّبُورِ، وَرَبَّ الظِّلِّ وَالْحَرُورِ، وَمُنْزِلَ الْقُرْآنِ الْعَظيمِ، وَرَبَّ الْمَلائِكَةِ الْمُقَرَّبينَ وَالاَْنْبِياءِ وَالْمُرْسَلينَ، اَللّـهُمَّ اِنّي اَسْاَلُكَ بِاِسْمِكَ الْكَريمِ، وَبِنُورِ وَجْهِكَ الْمُنيرِ وَمُلْكِكَ الْقَديمِ، يا حَيُّ يا قَيُّومُ اَسْاَلُكَ بِاسْمِكَ الَّذي اَشْرَقَتْ بِهِ السَّماواتُ وَالاَْرَضُونَ، وَبِاسْمِكَ الَّذي يَصْلَحُ بِهِ الاَْوَّلُونَ وَالاْخِرُونَ، يا حَيّاً قَبْلَ كُلِّ حَيٍّ وَيا حَيّاً بَعْدَ كُلِّ حَيٍّ وَيا حَيّاً حينَ لا حَيَّ يا مُحْيِيَ الْمَوْتى وَمُميتَ الاَْحْياءِ، يا حَيُّ لا اِلـهَ اِلّا اَنْتَ، اَللّـهُمَّ بَلِّغْ مَوْلانَا الاِْمامَ الْهادِيَ الْمَهْدِيَّ الْقائِمَ بِاَمْرِكَ صَلَواتُ اللهِ عَلَيْهِ و عَلى آبائِهِ الطّاهِرينَ عَنْ جَميعِ الْمُؤْمِنينَ وَالْمُؤْمِناتِ في مَشارِقِ الاَْرْضِ وَمَغارِبِها سَهْلِها وَجَبَلِها وَبَرِّها وَبَحْرِها، وَعَنّي وَعَنْ والِدَيَّ مِنَ الصَّلَواتِ زِنَةَ عَرْشِ اللهِ وَمِدادَ كَلِماتِهِ، وَما اَحْصاهُ عِلْمُهُ وَاَحاطَ بِهِ كِتابُهُ، اَللّـهُمَّ اِنّي اُجَدِّدُ لَهُ في صَبيحَةِ يَوْمي هذا وَما عِشْتُ مِنْ اَيّامي عَهْداً وَعَقْداً وَبَيْعَةً لَهُ في عُنُقي، لا اَحُولُ عَنْها وَلا اَزُولُ اَبَداً، اَللّـهُمَّ اجْعَلْني مِنْ اَنْصارِهِ وَاَعْوانِهِ وَالذّابّينَ عَنْهُ وَالْمُسارِعينَ اِلَيْهِ في قَضاءِ حَوائِجِهِ، وَالْمُمْتَثِلينَ لاَِوامِرِهِ وَالُْمحامينَ عَنْهُ، وَالسّابِقينَ اِلى اِرادَتِهِ وَالْمُسْتَشْهَدينَ بَيْنَ يَدَيْهِ، اَللّـهُمَّ اِنْ حالَ بَيْني وَبَيْنَهُ الْمَوْتُ الَّذي جَعَلْتَهُ عَلى عِبادِكَ حَتْماً مَقْضِيّاً فَاَخْرِجْني مِنْ قَبْري مُؤْتَزِراً كَفَنى شاهِراً سَيْفي مُجَرِّداً قَناتي مُلَبِّياً دَعْوَةَ الدّاعي فِي الْحاضِرِ وَالْبادي، اَللّـهُمَّ اَرِنيِ الطَّلْعَةَ الرَّشيدَةَ، وَالْغُرَّةَ الْحَميدَةَ، وَاكْحُلْ ناظِري بِنَظْرَة منِّي اِلَيْهِ، وَعَجِّلْ فَرَجَهُ وَسَهِّلْ مَخْرَجَهُ، وَاَوْسِعْ مَنْهَجَهُ وَاسْلُكْ بي مَحَجَّتَهُ، وَاَنْفِذْ اَمْرَهُ وَاشْدُدْ اَزْرَهُ، وَاعْمُرِ اللّـهُمَّ بِهِ بِلادَكَ، وَاَحْيِ بِهِ عِبادَكَ، فَاِنَّكَ قُلْتَ وَقَوْلُكَ الْحَقُّ : (ظَهَرَ الْفَسادُ فِي الْبَرِّ وَالْبَحْرِ بِما كَسَبَتْ اَيْدِي النّاسِ)، فَاَظْهِرِ الّلهُمَّ لَنا وَلِيَّكَ وَابْنَ بِنْتِ نَبِيِّكَ الْمُسَمّى بِاسْمِ رَسُولِكَ حَتّى لا يَظْفَرَ بِشَيْء مِنَ الْباطِلِ اِالّا مَزَّقَهُ، وَيُحِقَّ الْحَقَّ وَيُحَقِّقَهُ، وَاجْعَلْهُ اَللّـهُمَّ مَفْزَعاً لِمَظْلُومِ عِبادِكَ، وَناصِراً لِمَنْ لا يَجِدُ لَهُ ناصِراً غَيْرَكَ، وَمُجَدِّداً لِما عُطِّلَ مِنْ اَحْكامِ كِتابِكَ، وَمُشَيِّداً لِما وَرَدَ مِنْ اَعْلامِ دينِكَ وَسُنَنِ نَبِيِّكَ صَلَّى اللهُ عَلَيْهِ وَآلِهِ، وَاجْعَلْهُ اَللّـهُمَّ مِمَّنْ حَصَّنْتَهُ مِن بَأسِ الْمُعْتَدينَ، اَللّـهُمَّ وَسُرَّ نَبِيَّكَ مُحَمَّداً صَلَّى اللهُ عَلَيْهِ وَآلِهِ بِرُؤْيَتِهِ وَمَنْ تَبِعَهُ عَلى دَعْوَتِهِ، وَارْحَمِ اسْتِكانَتَنا بَعْدَهُ، اَللّـهُمَّ اكْشِفْ هذِهِ الْغُمَّةَ عَنْ هذِهِ الاُْمَّةِ بِحُضُورِهِ، وَعَجِّلْ لَنا ظُهُورَهُ، اِنَّهُمْ يَرَوْنَهُ بَعيداً وَنَراهُ قَريباً، بِرَحْمَتِـكَ يـا اَرْحَمَ الرّاحِمينَ ."},{"type":"Text","content":"ثمّ تضرب على فخذك الايمن بيدك ثلاث مرّات وتقول كلّ مرّة : اَلْعَجَلَ الْعَجَلَ يا مَوْلاىَ يا صاحِبَ الزَّمانِ ."},{"type":"Text","content":"الرّابع : قال السّيد ابن طاووس : فاذا أردت الانصراف من حرمه الشّريف فعُد الى السّرداب المنيف وصلّ فيه ما شئت ، ثمّ قم مستقبل القبلة وقُل : اَللّـهُمَّ ادْفَعْ عَنْ وَلِيِّكَ وأورد الدّعاء بتمامه ، ثمّ قال : ثمّ ادعُ الله كثيراً وانصرف مسعوداً إن شاء الله تعالى ."},{"type":"AboutText","content":"أقول : هذا الدعاء قد رواه الشّيخ في المصباح عن الرّضا (عليه السلام) في خلال أعمال يوم الجمعة ونحن أيضاً سنروي الدّعاء طبقاً لرواية الشّيخ . قال : روى يونس بن عبد الرّحمن عن الرّضا صلوات الله عليه انّه كان يأمر بالدّعاء لصاحب الامر (عليه السلام) بهذا الدّعاء :"},{"type":"Text","content":"اَللّـهُمَّ ادْفَعْ عَنْ وَلِيِّكَ وَخَليفَتِكَ وَحُجَّتِكَ عَلى خَلْقِكَ وَلِسانِكَ الْمُعَبِّرِ عَنْكَ النّاطِقِ بِحِكْمَتِكَ، وَعَيْنِكَ النّاظِرَةِ بِاِذْنِكَ، وَشاهِدِكَ عَلى عِبادِكَ، الْجَحْجاحِ الُْمجاهِدِ الْعائِذِ بِكَ الْعابِدِ عِنْدَكَ، وَاَعِذْهُ مِنْ شَرِّ جَميعِ ما خَلَقْتَ وَبَرَأتَ وَاَنْشَأتَ وَصَوَّرْتَ، وَاحْفَظْهُ مِنْ بَيْنَ يَدَيْهِ وَمِنْ خَلْفِهِ وَعَنْ يَمينِهِ وَعَنْ شِمالِهِ وَمِنْ فَوْقِهِ وَمِنْ تَحْتِهِ بِحِفْظِكَ الَّذي لا يَضيعُ مَنْ حَفِظْتَهُ بِهِ، وَاحْفَظْ فيهِ رَسوُلَكَ وَآباءِهِ اَئِمَّتَكَ وَدَعائِمَ دينِكَ، وَاجْعَلْهُ في وَديعَتِكَ الَّتي لا تَضيعُ، وَفي جَوارِكَ الَّذي لا يُخْفَرُ، وَفي مَنْعِكَ وَعِزِّكَ الَّذي لا يُقْهَرُ، وَآمِنْهُ بِاَمانِكَ الْوَثيقِ الَّذي لا يُخْذَلُ مَنْ آمَنْتَهُ بِهِ، وَاجْعَلْهُ في كَنَفِكَ الَّذي لا يُرامُ مَنْ كانَ فيهِ، وَانْصُرْهُ بِنَصْرِكَ الْعَزيزِ، وَاَيِّدْهُ بِجُنْدِكَ الْغالِبِ، وَقَوِّهِ بِقُوَّتِكَ، وَاَرْدِفْهُ بِملائِكَتِكَ، وَوالِ مَنْ والاهِ وَعادِ مَنْ عاداهُ، وَاَلْبِسْهُ دِرْعَكَ الْحَصينَةَ وَحُفَّهُ بِالْمَلائِكَةِ حَفّاً، اَللّـهُمَّ اشْعَبْ بِهِ الصَّدْعَ، وَارْتُقْ بِهِ الْفَتْقَ، وَاَمِتْ بِهِ الْجَوْرَ، وَاَظْهِرْ بِهِ الْعَدْلَ، وَزَيِّنْ بِطُولِ بَقائِهِ الاَْرْضَ، وَاَيِّدْهُ بِالنَّصْرَ، وَانْصُرْهُ بِالرُّعْبِ، وَقَوِّ ناصِريهِ، وَاخْذُلْ خاذِليهِ، وَدَمْدِمْ مَنْ نَصَبَ لَهُ، وَدَمِّرْ مِنْ غَشَّهُ، وَاقْتُلْ بِهِ جَبابِرَةَ الْكُفْرِ وَعَمَدَهُ وَدَعائِمَهُ، وَاقْصِمْ بِهِ رُؤُوسَ الضَّلالَةِ وَشارِعَةَ الْبِدَعِ وَمُميتَةَ السُّنَّةِ وَمُقَوِّيَةَ الْباطِلِ، وَذَلِّلْ بِهِ الْجَبّارينَ، وَأَبْرِ بِهِ الْكافِرينَ وَجميعَ الْمُلْحِدينَ في مَشارِقِ الاَْرْضِ وَمَغارِبِها وَبَرِّها وَبَحْرِها وَسَهْلِها وَجَبَلِها، حَتّى لا تَدَعَ مِنْهُمْ دَيّاراً وَلا تَبْقِىَ لَهُمْ آثاراً، اَللّـهُمَّ طَهِّرْ مِنْهُمْ بِلادَكَ وَاشْفِ مِنْهُمْ عِبادَكَ، وَاَعِزَّ بِهِ الْمُؤْمِنينَ وَاَحْيِ بِهِ سُنَنَ الْمُرْسَلينَ، وَدارِسَ حُكْمِ النَّبِيّينَ، وَجَدِّدْ بِهِ مَا امْتَحى مِنْ دينِكَ، وَبُدِّلَ مِنْ حُكْمِكَ، حَتّى تُعيدَ دينَكَ بِهِ وَعَلى يَدَيْهِ جَديداً غَضّاً مَحْضاً صَحيحاً لا عِوَجَ فيهِ وَلا بِدْعَةَ مَعَهُ، وَحَتّى تُنيرَ بِعَدْلِهِ ظُلَمَ الْجَوْرِ، وَتُطْفِئَ بِهِ نيرانَ الْكُفْرِ، وَتوُضِحَ بِهِ مَعاقِدَ الْحَقِّ وَمَجْهُولَ الْعَدْلِ، فَاِنَّهُ عَبْدُكَ الَّذيِ اسْتَخْلَصْتَهُ لِنَفْسِكَ، وَاصْطَفَيْتَهُ عَلى غَيْبِكَ، وَعَصَمْتَهُ مِنَ الذُّنُوبِ وَبَرَّأتَهُ مِنَ الْعُيوُبِ، وَطَهَّرْتَهُ مِنَ الرِّجْسِ، وَسَلَّمْتَهُ مِنَ الدَّنَسِ، اَللّـهُمَّ فَاِنّا نَشْهَدُ لَهُ يَوْمَ الْقِيامَةِ وَيَوْمَ حُلُولِ الطّامَّةِ اَنَّهُ لَمْ يُذْنِبْ ذَنْباً وَلا اَتى حوُباً، وَلَمْ يَرْتَكِبْ مَعْصِيَةً، وَلَمْ يُضَيِّعْ لَكَ طاعَةً، وَلَمْ يَهْتِكْ لَكَ حُرْمَةً، وَلَمْ يُبَدِّلْ لَكَ فَريضَةً، وَلَمْ يُغَيِّرْ لَكَ شَريعَةً، وَاَنَّهُ الْهاديِ الْمُهْتَديِ الطّاهِرُ التَّقِيُّ النَّقِيُّ الرَّضِيُّ الزَّكِيُّ، اَللّـهُمَّ اَعْطِهِ في نَفْسِهِ وَاَهْلِهِ وَوَلَدِهِ وَذُرِّيَّتِهِ وَاُمَّتِهِ وَجَميعِ رَعِيَّتِهِ ما تُقِرُّ بِهِ عَيْنَهُ، وَتَسُرُّ بِهِ نَفْسَهُ وَتَجْمَعُ لَهُ مُلْكَ الْمُمْلَكاتِ كُلِّها قَريبِها وَبَعيدِها وَعَزيزِها وَذَليلِها، حَتّى تُجْرِيَ حُكْمَهُ عَلى كُلِّ حُكْم، وَتَغْلِبَ بِحَقِّهِ كُلَّ باطِل، اَللّـهُمَّ اسْلُكْ بِنا عَلى يَدَيْهِ مِنْهاجَ الْهُدى وَالَْمحَجَّةَ الْعُظْمى، وَالطَّريقَةَ الْوُسْطَى الَّتى يَرْجِعُ اِلَيْهَا الْغالي، وَيَلْحَقُ بِهَا التّالي، وَقَوِّنا عَلى طاعَتِهِ، وَثَبِّتْنا عَلى مُشايَعَتِهِ، وَامْنُنْ عَلَيْنا بِمُتابَعَتِهِ، وَاجْعَلْنا في حِزْبِهِ الْقَوّامينَ بِاَمْرِهِ الصّابِرينَ مَعَهُ الطّالِبينَ رِضاكَ بِمُناصَحَتِهِ، حَتّى تَحْشُرَنا يَوْمَ الْقِيامَةِ في اَنْصارِهِ وَاَعْوانِهِ وَمُقَوِّيَةِ سُلْطانِهِ، اَللّـهُمَّ وَاجْعَلْ ذلِكَ لَنا خالِصاً مِنْ كُلِّ شَكٍّ وَشُبْهَة وَرِياء وَسُمْعَة، حَتّى لا نَعْتَمِدَ بِهِ غَيْرَكَ، وَلا نَطْلُبَ بِهِ اِلّا وَجْهَكَ، وَحَتّى تُحِلَّنا مَحَلَّهُ وَتَجْعَلَنا فِي الْجَنَّةِ مَعَهُ، وَاَعِذْنا مِنَ السَّاْمَةِ وَالْكَسَلِ وَالْفَتْرَةِ، وَاجْعَلْنا مِمَّنْ تَنْتَصِرُ بِهِ لِدينِكَ وَتُعِزُّ بِهِ نَصْرَ وَلِيِّكَ، وَلا تَسْتَبْدِلْ بِنا غَيْرَنا فَاِنَّ اسْتِبْدالَكَ بِنا غَيْرَنا عَلَيْكَ يَسيرٌ وَهُوَ عَلَيْنا كَثيرٌ، اَللّـهُمَّ صَلِّ عَلى وُلاةِ عَهْدِهِ، وَالاَْئِمَّةِ مِنْ بَعْدِهِ، وَبَلِّغْهُمْ آمالَهُمْ، وَزِدْ في آجالِهِمْ، وَاَعِزَّ نَصْرَهُمْ، وَتَمِّمْ لَهُمْ ما اَسْنَدْتَ اِلَيْهِمْ مِنْ اَمْرِكَ لَهُمْ، وَثَبِّتْ دَعائِمَهُمْ، وَاجْعَلْنا لَهُمْ اَعْواناً وَعَلى دينِكَ اَنْصاراً، فَاِنَّهُمْ مَعادِنُ كَلِماتِكَ، وَخُزّانُ عِلْمِكَ، وَاَرْكانُ تَوْحيدِكَ، وَدَعائِمُ دينِكَ، وَوُلاةُ اَمْرِكَ، وَخالِصَتُكَ مِنْ عِبادِكَ، وَصَفْوَتُكَ مِنْ خَلْقِكَ، وَاَوْلِياؤُكَ وَسَلائِلُ اَوْلِيائِكَ، وَصَفْوَةُ اَوْلادِ نَبِيِّكَ وَالسَّلامُ عَلَيْهِ وَعَلَيْهِمْ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ ."},{"type":"Text","content":"فصلٌ"}],"preview":"روي عن الصّادق (عليه السلام) انّه قال : من دعا الى الله تعالى أربعين صباحاً بهذا العهد كان من أنصار قائمنا، فإن مات قبله أخرجه الله تعالى من قبره وأعطاه بكلّ كلمة ألف حسنة ومَحا عن","hasTranslate":false},{"id":"mf_ar_262","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"وهي ما يُزار به كلّ إمام من الأئمة (عليهم السلام) وهي عديدة ونحن نكتفي بذكر بعضها :","blocks":[{"type":"Text","content":"الزّيارة الأولى : روى الصّدوق في كتاب من لا يحضره الفقيه أنّه سئل الرّضا (عليه السلام) عن إتيان أبي الحسن موسى (عليه السلام) قال : صلّوا في المساجد حوله ويجزي في المواضِع كلّها (أي يجزي في زيارة كلّ من الأئمة أو في مطلق المزارات الشّريفة المقدّسة كمراقد الأنبياء وسائر الأوصياء (عليهم السلام) كما هو الظّاهر) أن تقول :"},{"type":"Text","content":"اَلسَّلامُ عَلى اَوْلِياءَ اللهِ وَاَصْفِيائِهِ، اَلسَّلامُ عَلى اُمَناءِ اللهِ وَاَحِبّائِهِ، اَلسَّلامُ عَلى اَنْصارِ اللهِ وَخُلَفائِهِ، اَلسَّلامُ عَلى مَحالِّ مَعْرِفَةِ اللهِ، اَلسَّلامُ عَلى مَساكِنِ ذِكْرِ اللهِ، اَلسَّلامُ عَلى مُظْهِرى اَمْرِ اللهِ وَنَهْيِهِ، اَلسَّلامُ عَلَى الدُّعاةِ اِلَى اللهِ، اَلسَّلامُ عَلَى الْمُسْتَقِرّينَ فى مَرْضاتِ اللهِ، اَلسَّلامُ عَلَى الُْمخْلِصينَ فى طاعَةِ اللهِ، اَلسَّلامُ عَلَى الاَْدِلاّءِ عَلَى اللهِ، اَلسَّلامُ عَلَى الَّذينَ مَنْ والاهُمْ فَقَدْ والَى اللهَ، وَمَنْ عاداهُمْ فَقَدْ عادَى اللهِ، وَمَنْ عَرَفَهُمْ فَقَدْ عَرَفَ اللهَ، وَمَنْ جَهِلَهُمْ فَقَدْ جَهِلَ اللهَ، وَمَنِ اعْتَصَمَ بِهِمْ فَقَدِ اعْتَصَمَ بِاللهِ، وَمَنْ تَخَلّى مِنْهُمْ فَقَدْ تَخَلّى مِنَ اللهِ عَزَّوَجَلَّ، وَاُشْهِدُ اللهَ اَنّى سِلْمٌ لِمَنْ سالَمْتُمْ، وَحَرْبٌ لِمَنْ حارَبْتُمْ، مُؤْمِنٌ بِسِرِّكُمْ وَعَلانِيَتِكُمْ، مُفَوِّضٌ فى ذلِكَ كُلِّهِ اِلَيْكُمْ، لَعَنَ اللهُ عَدُوَّ آلِ مُحَمَّدٍ مِنَ الْجِنِّ وَالاِْنْسِ وَاَبْرَأُ اِلَى اللهِ مِنْهُمْ، وَصَلَّى اللهُ عَلى مُحَمَّدٍ وَآلِهِ ."},{"type":"Text","content":"وهذه الزّيارة موجودة في الكافي والتّهذيب وكامل الزّيارة، وقد ورد بعد هذه الزّيارة في جميع مصادرها ."},{"type":"Text","content":"إنّ هذا (أي القول والمراد به هذه الزّيارة) يجزي في الزّيارات كلّها، وتكثر من الصّلاة على محمّدٍ وآله وتسمّي واحداً واحداً بأسمائهم وتبرأ من أعدائهم ، وتخيّر ما شئت من الدّعاء لنفسك والمؤمنين والمؤمنات ."},{"type":"AboutText","content":"أقول : هذه التتمّة على الظّاهر جزء الرّواية ومن كلام المعصوم (عليه السلام) ولكن حتّى لو فرضناها خارجة عن الرّواية وقلنا انّها من كلام بعض المحدّثين فنحن مطمئنّون بأنّ الزّيارة جامعة، فالأعاظم من مشايخ الحديث قد ارتأوا طبقاً لما يدلّ عليه مفتتح الحديث انّها تجزي في كافّة المشاهد فرووها في باب الزّيارات الجامعة، والتّعابير الواردة في الزّيارة هي أيضاً كافّة من الصّفات الجامعة التي لا تخصّ بعضاً دون بعض ، فمن المناسب أن يُزار بها في جميع المشاهد حتّى مشاهد الأنبياء والأوصياء (عليهم السلام) كما أوردها جمع من العلماء لمشهد يونس (عليه السلام) وقد أمر في ذيل الرّواية بالصّلاة على محمّدٍ وآله واحداً واحداً ، فمن المناسب لذلك جدّاً قراءة الصّلاة المنسوبة الى أبي الحسن الضّرّاب التي مضت في أعمال يوم الجمعة ."},{"type":"Text","content":"الزّيارة الثّانية : روى الصّدوق أيضاً في الفقيه والعيون عن موسى بن عبد الله النّخعي انّه قال للإمام عليّ النّقي (عليه السلام) : علّمني يا ابن رسول الله (صلى الله عليه وآله وسلم) قولاً أقوله بليغاً كاملاً إذا زُرت واحداً منكم ، فقال : إذا صرت الى الباب فقف واشهد الشّهادتين أي قُل : اَشْهَدُ اَنْ لا اِلـهَ اِلاَّ اللهُ وَحْدَهُ لا شَريكَ لَهُ، وَاَشْهَدُ اَنَّ مُحَمَّداً صَلَّى اللهُ عَلَيْهِ وَآلِهِ عَبْدُهُ وَرَسُولُهُ وأنت على غُسل ، فاذا دخلت ورأيت القبر فقف وقُل : اَللهُ اَكْبَرُ ثلاثين مرّة ، ثمّ امشِ قليلاً وعليك السّكينة والوقار وقارب بين خطاك ثمّ قف وكبّر الله عزّ وجلّ ثلاثين مرّة ، ثمّ ادنُ من القبر وكبّر الله أربعين مرّة تمام مائة تكبيرة ، ولعلّ الوجه في الامر بهذه التّكبيرات هو الاحتراز عمّا قد تورثه أمثال هذه العباير الواردة في الزّيارة من الغُلوّ أو الغفلة عن عظمة الله سبحانه وتعالى فالطّباع مائلة الى الغلوّ أو غير ذلك من الوجوه ، ثمّ قُل :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكُمْ يا اَهْلَ بَيْتِ النُّبُوَّةِ، وَمَوْضِعَ الرِّسالَةِ، وَمُخْتَلَفَ الْمَلائِكَةِ، وَمَهْبِطَ الْوَحْىِ، وَمَعْدِنَ الرَّحْمَةِ، وَخُزّانَ الْعِلْمِ، وَمُنْتَهَى الْحِلْمِ، وَاُصُولَ الْكَرَمِ، وَقادَةَ الاُْمَمِ، وَاَوْلِياءَ النِّعَمِ، وَعَناصِرَ الاَْبْرارِ، وَدَعائِمَ الاَْخْيارِ، وَساسَةَ الْعِبادِ، وَاَرْكانَ الْبِلادِ، وَاَبْوابَ الاْيمانِ، وَاُمَناءَ الرَّحْمنِ، وَسُلالَةَ النَّبِيّينَ، وَصَفْوَةَ الْمُرْسَلينَ، وَعِتْرَةَ خِيَرَةِ رَبِّ الْعالَمينَ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَلسَّلامُ عَلى اَئِمَّةِ الْهُدى، وَمَصابيحِ الدُّجى، وَاَعْلامِ التُّقى، وَذَوِى النُّهى، وَاُولِى الْحِجى، وَكَهْفِ الْوَرى، وَوَرَثَةِ الاَْنْبِياءِ، وَالْمَثَلِ الاَْعْلى، وَالدَّعْوَةِ الْحُسْنى، وَحُجَجِ اللهِ عَلى اَهْلِ الدُّنْيا وَالاْخِرَةِ وَالاُْولى وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَلسَّلامُ عَلى مَحالِّ مَعْرِفَةِ اللهِ، وَمَساكِنِ بَرَكَةِ اللهِ، وَمَعادِنِ حِكْمَةِ اللهِ، وَحَفَظَةِ سِرِّ اللهِ، وَحَمَلَةِ كِتابِ اللهِ، وَاَوْصِياءِ نَبِىِّ اللهِ، وَذُرِّيَّةِ رَسُولِ اللهِ صَلَّى اللهُ عَلَيْهِ وَآلِهِ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَلسَّلامُ عَلَى الدُّعاةِ اِلَى اللهِ، وَالاَْدِلاّءِ عَلى مَرْضاتِ اللهِ، وَالْمُسْتَقِرّينَ فى اَمْرِ اللهِ، وَالتّامّينَ فى مَحَبَّةِ اللهِ، وَالُْمخْلِصينَ فـى تَوْحيدِ اللهِ، وَالْمُظْهِرينَ لاَِمْرِ اللهِ وَنَهْيِهِ، وَعِبادِهِ الْمُكْرَمينَ الَّذينَ لا يَسْبِقُونَهُ بِالْقَوْلِ وَهُمْ بِاَمْرِهِ يَعْمَلُونَ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَلسَّلامُ عَلَى الاَْئِمَّةِ الدُّعاةِ، وَالْقادَةِ الْهُداةِ، وَالسّادَةِ الْوُلاةِ، وَالذّادَةِ الْحُماةِ، وَاَهْلِ الذِّكْرِ وَاُولِى الاَْمْرِ، وَبَقِيَّةِ اللهِ وَخِيَرَتِهِ وَحِزْبِهِ وَعَيْبَةِ عِلْمِهِ وَحُجَّتِهِ وَصِراطِهِ وَنُورِهِ وَبُرْهانِهِ وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَشْهَدُ اَنْ لا اِلـهَ اِلاَّ اللهُ وَحْدَهُ لا شَريكَ لَهُ كَما شَهِدَ اللهُ لِنَفْسِهِ وَشَهِدَتْ لَهُ مَلائِكَتُهُ وَاُولُو الْعِلْمِ مِنْ خَلْقِهِ، لا اِلـهَ اِلاّ هُوَ الْعَزِيزُ الْحَكيمُ، وَاَشْهَدُ اَنَّ مُحَمَّداً عَبْدُهُ الْمُنْتَجَبُ، وَرَسُولُهُ الْمُرْتَضى، اَرْسَلَهُ بِالْهُدى وَدينِ الْحَقِّ لِيُظْهِرَهُ عَلَى الدِّينِ كُلِّهِ وَلَوْ كَرِهَ الْمُشْرِكُونَ، وَاَشْهَدُ اَنَّكُمُ الاَْئِمَّةُ الرّاشِدُونَ الْـمَهْدِيُّونَ الْمَعْصُومُونَ الْمُكَرَّمُونَ الْمُقَرَّبُونَ الْمُتَّقُونَ الصّادِقُونَ الْمُصْطَفَوْنَ الْمُطيعُونَ للهِ، الْقَوّامُونَ بِاَمْرِهِ، الْعامِلُونَ بِاِرادَتِهِ، الْفائِزُونَ بِكَرامَتِهِ، اصْطَفاكُمْ بِعِلْمِهِ، وَارْتَضاكُمْ لِغَيْبِهِ، وَاخْتارَكُمْ لِسِرِّهِ، وَاجْتَباكُمْ بِقُدْرَتِهِ، وَاَعَزَّكُمْ بِهُداهُ، وَخَصَّكُمْ بِبُرْهانِهِ، وَانْتَجَبَكُمْ لِنُورِهِ، وَاَيَّدَكُمْ بِرُوحِهِ، وَرَضِيَكُمْ خُلَفاءَ فى اَرْضِهِ، وَحُجَجاً عَلى بَرِيَّتِهِ، وَاَنْصاراً لِدينِهِ، وَ حَفَظَةً لِسِرِّهِ، وَخَزَنَةً لِعِلْمِهِ، وَمُسْتَوْدَعاً لِحِكْمَتِهِ، وَتَراجِمَةً لِوَحْيِهِ، وَاَرْكاناً لِتَوْحيدِهِ، وَشُهَداءَ عَلى خَلْقِهِ، وَاَعْلاماً لِعِبادِهِ، وَمَناراً فى بِلادِهِ، وَاَدِلاّءَ عَلى صِراطِهِ، عَصَمَكُمُ اللهُ مِنَ الزَّلَلِ، وَآمَنَكُمْ مِنَ الْفِتَنِ، وَطَهَّرَكُمْ مِنَ الدَّنَسِ، وَاَذْهَبَ عَنْكُمُ الرِّجْسَ وَطَهَّرَكُمْ تَطْهيراً، فَعَظَّمْتُمْ جَلالَهُ، وَاَكْبَرْتُمْ شَأْنَهُ، وَمَجَّدْتُمْ كَرَمَهُ، وَاَدَمْتُمْ ذِكْرَهُ، وَوَكَّدْتُمْ ميثاقَهُ، وَاَحْكَمْتُمْ عَقْدَ طاعَتِهِ، وَنَصَحْتُمْ لَهُ فِى السِّرِّ وَالْعَلانِيَةِ، وَدَعَوْتُمْ اِلى سَبيلِهِ بِالْحِكْمَةِ وَالْمَوْعِظَةِ الْحَسَنَةِ، وَبَذَلْتُمْ اَنْفُسَكُمْ فى مَرْضاتِهِ، وَصَبَرْتُمْ عَلى ما اَصابَكُمْ فى جَنْبِهِ، وَاَقَمْتُمُ الصَّلاةَ، وَآتَيْتُمُ الزَّكاةَ، وَاَمَرْتُمْ بِالْمَعْرُوفِ، وَنَهَيْتُمْ عَنِ الْمُنْكَرِ، وَجاهَدْتُمْ فِى اللهِ حَقَّ جِهادِهِ حَتّى اَعْلَنْتُمْ دَعْوَتَهُ، وَبَيَّنْتُمْ فَرائِضَهُ، وَاَقَمْتُمْ حُدُودَهُ، وَنَشَرْتُمْ شَرايِعَ اَحْكامِهِ، وَسَنَنْتُمْ سُنَّتَهُ، وَصِرْتُمْ فى ذلِكَ مِنْهُ اِلَى الرِّضا، وَسَلَّمْتُمْ لَهُ الْقَضاءَ، وَصَدَّقْتُمْ مِنْ رُسُلِهِ مَنْ مَضى، فَالرّاغِبُ عَنْكُمْ مارِقٌ، وَاللاّزِمُ لَكُمْ لاحِقٌ، وَالْمُقَصِّرُ فى حَقِّكُمْ زاهِقٌ، وَالْحَقُّ مَعَكُمْ وَفيكُمْ وَمِنْكُمْ وَاِلَيْكُمْ وَاَنْتُمْ اَهْلُهُ وَمَعْدِنُهُ، وَميراثُ النُّبُوَّةِ عِنْدَكُمْ، وَاِيابُ الْخَلْقِ اِلَيْكُمْ، وَحِسابُهُمْ عَلَيْكُمْ، وَفَصْلُ الْخِطابِ عِنْدَكُمْ، وَآياتُ اللهِ لَدَيْكُمْ، وَعَزائِمُهُ فيكُمْ، وَنُورُهُ وَبُرْهانُهُ عِنْدَكُمْ، وَاَمْرُهُ اِلَيْكُمْ، مَنْ والاكُمْ فَقَدْ والَى اللهَ، وَمَنْ عاداكُمْ فَقَدْ عادَ اللهَ، وَ مَنْ اَحَبَّكُمْ فَقَدْ اَحَبَّ اللهَ، وَمَنْ اَبْغَضَكُمْ فَقَدْ اَبْغَضَ اللهَ، وَمَنِ اعْتَصَمَ بِكُمْ فَقَدِ اعْتَصَمَ بِاللهِ، اَنْتُمُ الصِّراطُ الاَْقْوَمُ، وَشُهَداءُ دارِ الْفَناءِ، وَشُفَعاءُ دارِ الْبَقاءِ، وَالرَّحْمَةُ الْمَوْصُولَةُ، وَالاْيَةُ الَْمخْزُونَةُ، وَالاَْمانَةُ الُْمحْفُوظَةُ، وَالْبابُ الْمُبْتَلى بِهِ النّاسُ، مَنْ اَتاكُمْ نَجا، وَمَنْ لَمْ يَأتِكُمْ هَلَكَ، اِلَى اللهِ تَدْعُونَ، وَعَلَيْهِ تَدُلُّونَ، وَبِهِ تُؤْمِنُونَ، وَلَهُ تُسَلِّمُونَ، وَبِاَمْرِهِ تَعْمَلُونَ، وَاِلى سَبيلِهِ تُرْشِدُونَ، وَبِقَوْلِهِ تَحْكُمُونَ، سَعَدَ مَنْ والاكُمْ، وَهَلَكَ مَنْ عاداكُمْ، وَخابَ مَنْ جَحَدَكُمْ، وَضَلَّ مَنْ فارَقَكُمْ، وَفازَ مَنْ تَمَسَّكَ بِكُمْ، وَاَمِنَ مَنْ لَجَاَ اِلَيْكُمْ، وَسَلِمَ مَنْ صَدَّقَكُمْ، وَهُدِىَ مَنِ اعْتَصَمَ بِكُمْ، مَنِ اتَّبَعَكُمْ فَالْجَنَّةُ مَأواهُ، وَمَنْ خالَفَكُمْ فَالنّارُ مَثْوايهُ، وَمَنْ جَحَدَكُمْ كافِرٌ، وَمَنْ حارَبَكُمْ مُشْرِكٌ، وَمَنْ رَدَّ عَلَيْكُمْ فى اَسْفَلِ دَرْك مِنَ الْجَحيمِ، اَشْهَدُ اَنَّ هذا سابِقٌ لَكُمْ فيما مَضى، وَجارٍ لَكُمْ فيما بَقِىَ، وَاَنَّ اَرْواحَكُمْ وَنُورَكُمْ وَطينَتَكُمْ واحِدَةٌ، طابَتْ وَطَهُرَتْ بَعْضُها مِنْ بَعْض، خَلَقَكُمُ اللهُ اَنْواراً فَجَعَلَكُمْ بِعَرْشِهِ مُحْدِقينَ حَتّى مَنَّ عَلَيْنا بِكُمْ، فَجَعَلَكُمْ فى بُيُوت اَذِنَ اللهُ اَنْ تُرْفَعَ وَيُذْكَرَ فيهَا اسْمُهُ، وَجَعَلَ صَلَواتِنا عَلَيْكُمْ وَما خَصَّنا بِهِ مِنْ وِلايَتِكُمْ طيباً لِخَلْقِنا، وَطَهارَةً لاَِنْفُسِنا، وَتَزْكِيَةً لَنا، وَكَفّارَةً لِذُنُوبِنا، فَكُنّا عِنْدَهُ مُسَلِّمينَ بِفَضْلِكُمْ، وَمَعْرُوفينَ بِتَصْديقِنا اِيّاكُمْ، فَبَلَغَ اللهُ بِكُمْ اَشْرَفَ مَحَلِّ الْمُكَرَّمينَ، وَاَعْلى مَنازِلِ الْمُقَرَّبينَ، وَاَرْفَعَ دَرَجاتِ الْمُرْسَلينَ، حَيْثُ لا يَلْحَقُهُ لاحِقٌ، وَلا يَفُوقُهُ فائِقٌ، وَلا يَسْبِقُهُ سابِقٌ، وَلا يَطْمَعُ فى اِدْراكِهِ طامِعٌ، حَتّى لا يَبْقى مَلَكٌ مُقَرَّبٌ، وَلا نَبِىٌّ مُرْسَلٌ، وَلا صِدّيقٌ وَلا شَهيدٌ، وَلا عالِمٌ وَلا جاهِلٌ، وَلا دَنِىٌّ وَلا فاضِلٌ، وَلا مُؤْمِنٌ صالِحٌ، وَلا فِاجِرٌ طالِحٌ، وَلاجَبّارٌ عَنيدٌ، وَلا شَيْطانٌ مَريدٌ، وَلا خَلْقٌ فيما بَيْنَ ذلِكَ شَهيدٌ اِلاّ عَرَّفَهُمْ جَلالَةَ اَمْرِكُمْ، وَعِظَمَ خَطَرِكُمْ، وَكِبَرَ شَأنِكُمْ وَتَمامَ نُورِكُمْ، وَصِدْقَ مَقاعِدِكُمْ، وَثَباتَ مَقامِكُمْ، وَشَرَفَ مَحَلِّكُمْ وَمَنْزِلَتِكُمْ عِنْدَهُ، وَكَرامَتَكُمْ عَلَيْهِ، وَخاصَّتَكُمْ لَدَيْهِ، وَقُرْبَ مَنْزِلَتِكُمْ مِنْهُ ،بِاَبى اَنْتُمْ وَاُمّى وَاَهْلى وَمالى وَاُسْرَتى اُشْهِدُ اللهَ وَاُشْهِدُكُمْ اَنّى مُؤْمِنٌ بِكُمْ وَبِما آمَنْتُمْ بِهِ، كافِرٌ بَعَدُوِّكُمْ وَبِما كَفَرْتُمْ بِهِ، مُسْتَبْصِرٌ بِشَأنِكُمْ وَبِضَلالَةِ مَنْ خالَفَكُمْ، مُوالٍ لَكُمْ وَلاَِوْلِيائِكُمْ، مُبْغِضٌ لاَِعْدائِكُمْ وَمُعادٍ لَهُمْ، سِلْمٌ لِمَنْ سالَمَكُمْ، وَحَرْبٌ لِمَنْ حارَبَكُمْ، مُحَقِّقٌ لِما حَقَّقْتُمْ، مُبْطِلٌ لِما اَبْطَلْتُمْ، مُطيعٌ لَكُمْ، عارِفٌ بِحَقِّكُمْ، مُقِرٌّ بِفَضْلِكُمْ، مُحْتَمِلٌ لِعِلْمِكُمْ، مُحْتَجِبٌ بِذِمَّتِكُمْ، مُعْتَرِفٌ بِكُمْ، مُؤْمِنٌ بِاِيابِكُمْ، مُصَدِّقٌ بِرَجْعَتِكُمْ، مُنْتَظِرٌ لاَِمْرِكُمْ، مُرْتَقِبٌ لِدَوْلَتِكُمْ، آخِذٌ بِقَوْلِكُمْ، عامِلٌ بِاَمْرِكُمْ، مُسْتَجيرٌ بِكُمْ، زائِرٌ لَكُمْ، لائِذٌ عائِذٌ بِقُبُورِكُمْ، مُسْتَشْفِعٌ اِلَى اللهِ عَزَّوَجَلَّ بِكُمْ، وَمُتَقَرِّبٌ بِكُمْ اِلَيْهِ، وَمُقَدِّمُكُمْ اَمامَ طَلِبَتى وَحَوائِجى وَاِرادَتى فى كُلِّ اَحْوالي وَاُمُورى مُؤْمِنٌ بِسِرِّكُمْ وَعَلانِيَتِكُمْ وَشاهِدِكُمْ وَغائِبِكُمْ وَاَوَّلِكُمْ وَآخِرِكُمْ، وَمُفَوِّضٌ فى ذلِكَ كُلِّهِ اِلَيْكُمْ وَمُسَلِّمٌ فيهِ مَعَكُمْ، وَقَلْبى لَكُمْ مُسَلِّمٌ، وَرَأيى لَكُمْ تَبَعٌ، وَنُصْرَتى لَكُمْ مُعَدَّةٌ حَتّى يُحْيِىَ اللهُ تَعالى دينَهُ بِكُمْ، وَيَرُدَّكُمْ فى اَيّامِهِ، وَيُظْهِرَكُمْ لِعَدْلِهِ، وَيُمَكِّنَكُمْ فى اَرْضِهِ، فَمَعَكُمْ مَعَكُمْ لا مَعَ غَيْرِكُمْ، آمَنْتُ بِكُمْ وَتَوَلَّيْتُ آخِرَكُمْ بِما تَوَلَّيْتُ بِهِ اَوَّلَكُمْ، وَبَرِئْتُ اِلَى اللهِ عَزَّوَجَلَّ مِنْ اَعْدائِكُمْ وَمِنَ الْجِبْتِ وَالطّاغُوتِ وَالشَّياطينِ وَحِزْبِهِمُ الظّالِمينَ لَكُمُ، الْجاحِدينَ لِحَقِّكُمْ، وَالْمارِقينَ مِنْ وِلايَتِكُمْ، وَالْغاصِبينَ لاِِرْثِكُمُ الشّاكّينَ فيكُمُ الْمُنْحَرِفينَ عَنْكُمْ، وَمِنْ كُلِّ وَليجَةٍ دُونَكُمْ وَكُلِّ مُطاعٍ سِواكُمْ، وَمِنَ الاَْئِمَّةِ الَّذينَ يَدْعُونَ اِلَى النّارِ، فَثَبَّتَنِىَ اللهُ اَبَداً ما حَييتُ عَلى مُوالاتِكُمْ وَمَحَبَّتِكُمْ وَدينِكُمْ، وَوَفَّقَنى لِطاعَتِكُمْ، وَرَزَقَنى شَفاعَتَكُمْ، وَجَعَلَنى مِنْ خِيارِ مَواليكُمْ التّابِعينَ لِما دَعَوْتُمْ اِلَيْهِ، وَ جَعَلَنى مِمَّنْ يَقْتَصُّ آثارَكُمْ، وَيَسْلُكُ سَبيلَكُمْ، وَيَهْتَدى بِهُداكُمْ وَيُحْشَرُ فى زُمْرَتِكُمْ، وَيَكِرُّ فى رَجْعَتِكُمْ، وَيُمَلَّكُ فى دَوْلَتِكُـمْ، وَ يُشَـرَّفُ فى عافِيَتِكُمْ، وَيُمَكَّنُ فى اَيّامِكُمْ، وَتَقِرُّ عَيْنُهُ غَداً بِرُؤْيَتِكُمْ، بِاَبى اَنْتُمْ وَاُمّى وَنَفْسى وَاَهْلى وَمالى مَنْ اَرادَ اللهَ بَدَأَ بِكُمْ، وَمَنْ وَحَّدَهُ قَبِلَ عَنْكُمْ، وَمَنْ قَصَدَهُ تَوَجَّهَ بِكُمْ، مَوالِىَّ لا اُحْصـى ثَنائَكُمْ وَلا اَبْلُغُ مِنَ الْمَدْحِ كُنْهَكُمْ وَمِنَ الْوَصْفِ قَدْرَكُمْ، وَاَنْتُمْ نُورُ الاَْخْيارِ وَهُداةُ الاَْبْرارِ وَحُجَجُ الْجَبّارِ، بِكُمْ فَتَحَ اللهُ وَبِكُمْ يَخْتِمُ، وَبِكُمْ يُنَزِّلُ الْغَيْثَ، وَبِكُمْ يُمْسِكُ السَّماءَ اَنْ تَقَعَ عَلَى الاَْرْضِ اِلاّ بِاِذْنِهِ، وَبِكُمْ يُنَفِّسُ الْهَمَّ وَيَكْشِفُ الضُّرَّ، وَعِنْدَكُمْ ما نَزَلَتْ بِهِ رُسُلُهُ، وَهَبَطَتْ بِهِ مَلائِكَتُهُ وَاِلى جَدِّكُمْ ."},{"type":"Text","content":"وإن كانت الزّيارة لأمير المؤمنين (عليه السلام) فعوض وَاِلى جَدِّكُمْ قُل :"},{"type":"Text","content":"وَاِلى اَخيكَ بُعِثَ الرُّوحُ الاَْمينُ، آتاكُمُ اللهُ ما لَمْ يُؤْتِ اَحَداً مِنَ الْعالَمينَ، طَأطَاَ كُلُّ شَريفٍ لِشَرَفِكُمْ، وَبَخَعَ كُلُّ مُتَكَبِّرٍ لِطاعَتِكُمْ، وَخَضَعَ كُلُّ جَبّارٍ لِفَضْلِكُمْ، وَذَلَّ كُلُّ شَىْءٍ لَكُمْ، وَاَشْرَقَتِ الاَْرْضُ بِنُورِكُمْ، وَفازَ الْفائِزُونَ بِوِلايَتِكُمْ، بِكُمْ يُسْلَكُ اِلَى الرِّضْوانِ، وَعَلى مَنْ جَحَدَ وِلايَتَكُمْ غَضَبُ الرَّحْمنِ، بِاَبى اَنْتُمْ وَاُمّى وَنَفسى وَاَهْلى وَمالى، ذِكْرُكُمْ فِى الذّاكِرينَ، وَاَسْماؤُكُمْ فِى الاَْسْماءِ، وَاَجْسادُكُمْ فِى الاَْجْسادِ، وَاَرْواحُكُمْ فِى اْلاََرْواحِ، وَاَنْفُسُكُمْ فِى النُّفُوسِ، وَآثارُكُمْ فِى الاْثارِ، وَقُبُورُكُمْ فِى الْقُبُورِ، فَما اَحْلى اَسْمائَكُمْ وَاَكْرَمَ اَنْفُسَكُمْ، وَاَعْظَمَ شَأنَكُمْ، وَاَجَلَّ خَطَرَكُمْ، وَاَوْفى عَهْدَكُمْ، وَاَصْدَقَ وَعْدَكُمْ، كَلامُكُمْ نُورٌ وَاَمْرُكُمْ رُشْدٌ وَوَصِيَّتُكُمُ التَّقْوى، وَفِعْلُكُمُ الْخَيْرُ، وَعادَتُكُمُ الاِْحْسانُ، وَسَجِيَّتُكُمُ الْكَرَمُ، وَشَأنُكُمُ الْحَقُّ وَالصِّدْقُ وَالرِّفْقُ، وَقَوْلُكُمْ حُكْمٌ وَحَتْمٌ، وَرَأيُكُمْ عِلْمٌ وَحِلْمٌ وَحَزْمٌ، اِنْ ذُكِرَ الْخَيْرُ كُنْتُمْ اَوَّلَهُ وَاَصْلَهُ وَفَرْعَهُ وَمَعْدِنَهُ وَمَأويهُ وَمُنْتَهاهُ، بِاَبى اَنْتُمْ وَاُمّى وَنَفْسى كَيْفَ اَصِفُ حُسْنَ ثَنائِكُمْ، وَاُحْصى جَميلَ بَلائِكُمْ، وَبِكُمْ اَخْرَجَنَا اللهُ مِنَ الذُّلِّ وَفَرَّجَ عَنّا غَمَراتِ الْكُرُوبِ، وَاَنْقَذَنا مِنْ شَفا جُرُفِ الْهَلَكاتِ وَمِنَ النّارِ، بِاَبى اَنْتُمْ وَاُمّى وَنَفْسى بِمُوالاتِكُمْ عَلَّمَنَا اللهُ مَعالِمَ دِينِنا، وَاَصْلَحَ ماكانَ فَسَدَ مِنْ دُنْيانا، وَبِمُوالاتِكُمْ تَمَّتِ الْكَلِمَةُ، وَعَظُمَتِ النِّعْمَةُ، وَائْتَلَفَتِ الْفُرْقَةُ، وَبِمُوالاتِكُمْ تُقْبَلُ الطّاعَةُ الْمُفْتَرَضَةُ، وَلَكُمُ الْمَوَدَّةُ الْواجِبَةُ، وَالدَّرَجاتُ الرَّفيعَةُ، وَالْمَقامُ الَْمحْمُودُ، وَالْمَكانُ الْمَعْلُومُ عِنْدَ اللهِ عَزَّوَجَلَّ، وَالْجاهُ الْعَظيمُ، وَالشَّأنُ الْكَبيرُ، وَالشَّفاعَةُ الْمَقْبُولَةُ، رَبَّنا آمَنّا بِما اَنْزَلْتَ وَاتَّبَعْنَا الرَّسُولَ فَاكْتُبْنا مَعَ الشّاهِدينَ، رَبَّنا لا تُزِ غْ قُلُوبَنا بَعْدَ اِذْ هَدَيْتَنا وَهَبْ لَنا مِنْ لَدُنْكَ رَحْمَةً اِنَّكَ اَنْتَ الْوَهّابُ، سُبْحانَ رَبِّنا اِنْ كانَ وَعْدُ رَبِّنا لَمَفْعُولاً، يا وَلِىَّ اللهِ اِنَّ بَيْنى وَبيْنَ اللهِ عَزَّوَجَلَّ ذُنُوباً لا يَأتى عَلَيْها اِلاّ رِضاكُمْ، فَبِحَقِّ مَنِ ائْتَمَنَكُمْ عَلى سِرِّهِ وَاسْتَرْعاكُمْ اَمْرَ خَلْقِهِ وَقَرَنَ طاعَتَكُمْ بِطاعَتِهِ، لَمَّا اسْتَوْهَبْتُمْ ذُنُوبى وَكُنْتُمْ شُفَعائى، فَاِنّى لَكُمْ مُطيعٌ، مَنْ اَطاعَكُمْ فَقَدْ اَطاعَ اللهَ، وَمَنْ عَصاكُمْ فَقَدْ عَصَى اللهَ، وَمَنْ اَحَبَّكُمْ فَقَدْ اَحَبَّ اللهَ، وَمَنْ اَبْغَضَكُمْ فَقَدْ اَبْغَضَ اللهَ، اَللّـهُمَّ اِنّى لَوْ وَجَدْتُ شُفَعاءَ اَقْرَبَ اِلَيْكَ مِنْ مُحَمِّدٍ وَاَهْلِ بَيْتِهِ الاَْخْيارِ الاَْئِمَّةِ الاَْبْرارِ لَجَعَلْتُهُمْ شُفَعائي، فَبِحَقِّهِمُ الَّذى اَوْجَبْتَ لَهُمْ عَلَيْكَ اَسْاَلُكَ اَنْ تُدْخِلَنى فى جُمْلَةِ الْعارِفينَ بِهِمْ وَبِحَقِّهِمْ، وَفى زُمْرَةِ الْمَرْحُومينَ بِشَفاعَتِهِمْ، اِنَّكَ اَرْحَمُ الرّاحِمينَ، وَصَلَّى اللهُ عَلى مُحَمَّدٍ وَآلِهِ الطّاهِرينَ وَسَلَّمَ تَسْليماً كَثيراً، وَحَسْبُنَا اللهُ وَنِعْـمَ الْوَكيلُ ."},{"type":"AboutText","content":"أقول : أورد الشّيخ أيضاً هذه الزّيارة في التّهذيب ثمّ ذيلها بوداع تركناه اختصاراً، وهذه الزّيارة كما صرّح به العلامة المجلسي (رحمه الله) إنّما هي أرقى الزّيارات الجامعة متناً وسنداً وهي أفصحها وأبلغها . وقال والده في شرح الفقيه : إنّ هذه الزّيارة أحسن الزّيارات وأكملها وإنّي لم أزر الأئمّة (عليهم السلام) ما دمت في الاعتاب المقدّسة الاّ بها، وقد أورد شيخنا في كتابه النجم الثّاقب قصّة تبدي لزوم المواظبة على هذه الزّيارة والاهتمام بها . قال : قدم النّجف الأشرف منذ سبع عشرة سنة تقريباً التّقيّ الصّالح السّيد أحمد ابن السّيد هاشم ابن السّيد حسن الموسوي الرّشتي أيّده الله وهو من تجّار مدينة رشت، فزارني في بيتي بصحبة العالم الرّباني والفاضل الصّمداني الشّيخ علي الرّشتي طاب ثراه الآتي ذكره في القصّة الآتية إن شاء الله، فلمّا نهضا للخروج نبّهني الشّيخ الى أنّ السّيد أحمد من الصّلحاء المسدّدين ولمح الى أنّ له قصّة غريبة والمجال حينذاك لم يسمح بأن تفصّل وصادفت الشّيخ بعد بضعة أيّام ينبّئني بارتحال السّيد من النّجف ويحدث لي عن سيرته ويوقفني على قصّته الغريبة، فأسفت أسفاً بالغاً على ما فاتني من سماع القصّة منه نفسه وإن كنت أجل الشّيخ عن أن يخالف ما يرويه شيئاً ممّا وعته أذناه من السّيد نفسه، ولكنّي صادفت السّيد ثانياً في مدينة الكاظمين منذ عدّة أشهر وذلك في شهر جمادى الثّانية من سنتنا هذه حينما عُدت من النّجف الأشرف وكان السيّد راجعاً من سامراء وهو يؤمّ ايران، فطلبت اليه أن يحدث لي عن نفسه وعمّا كنت قد وقفت عليه ممّا عرض له في حياته فأجابني الى ذلك وكان ممّا حكاه قضيّتنا المعهودة حكاها برمّتها طبقاً لما كنت قد سمعته من قبل ، قال : غادرت سنة 1280 } دار المرز {مدينة رشت الى تبريز متوخياً حجّ بيت الله الحرام فحللت دار الحاج صفر عليّ التبريزي التّاجر المعروف وظللت هناك حائراً لم أجد قافلة ارتحل معها حتّى جهز الحاج جبّار الرّائد } جلو دار{ السدّهي الأصبهاني قافلة الي طرابوزن فأكريت منه مركوباً وصرت مع القافلة مفرداً من دون صديق وفي أول منزل من منازل السفر التحق بي رجال ثلاثة كان قد رغبهم في ذلك الحاج صفر علي وهم المولي الحاج باقر التبريزي الذي كان يحج بالنيابة عن الغير المعروف لدي العلماﺀ والحاج السيد حسين التبريزي التاجر ورجل يسمي الحاج علي وكان يخدم فتصاحبنا في الطريق حتي بلغنا ارزنة الروم ثم قصدنا من هناك الطرابوزن وفي احد المنازل التي بين البلدين أتانا الحاج جبار الرائد } جلو دار{ ينبئنا بأنّ أمامنا اليوم طريقاً مخيفاً ويحذرنا عن التّخلّف عن الركب فقد كنّا نحن نبتعد غالباً عن القافلة ونتخلّف، فامتثلنا وعجلنا الى السّير واستأنفنا المسير معاً قبل الفجر بساعتين ونصف أو بثلاث ساعات فما سرنا نصف الفرسخ أو ثلاثة أرباعه إلاّ وقد أظلم الجوّ وتساقط الثّلج بحيث كان كلّ منّا قد غطّى رأسه بما لديه من الغطاء واسرع في المسير ، أما أنا فلم يسعني اللّحوق بهم مهما اجتهدت في ذلك فتخلّفت عنهم وانفردت بنفسي في الطّريق فنزلت من ظهر فرسي وجلست في ناحية من الطّريق وأنا مضطرب غاية الاضطراب، فنفقة السّفر كانت كلّها معي وهي ستمائة توماناً، ففكرت في أمري مليّاً فقرّرت على أن لا أبرح مقامي حتّى يطلع الفجر ، ثمّ أعود الى المنزل الذي بتنا فيه ليلتنا الماضية ثم ارجع ثانياً مع عدّة من الحرس فالتحق بالقافلة وإذا بستان يبدو أمامي فيها فلاّح بيده مسحاة يضرب بها فروع الأشجار فيتساقط ما تراكم عليها من الثّلج، فدنا منّي وسألني من أنت؟ فأجبت : انّي قدتخلّفت عن الركب لا اهتدي الطريق، فخاطبني باللّغة الفارسية قائلاً : عليك بالنّافلة كي تهتدي، فأخذت في النّافلة وعندما فرغت من التهجّد أتاني ثانياً قائلاً : ألم تمض بعد ؟ قلت : والله لا اهتدي الى الطّريق ، قال : عليك بالزّيارة الجامعة الكبيرة وما كنت حافظاً لها والى الآن لا أقدر أن أقرأها من ظهر القلب مع تكرّر ارتحالي الى الأعتاب المقدّسة للزّيارة، فوقفت قائماً وقرأت الزّيارة كاملة من ظهر القلب ، فبدالي الرّجل لما انتهيت قائلاً : ألم تبرح مكانك بعد ، فعرض لي البكاء وأجبته : لم اُغادر مكاني بعد فإنّي لا أعرف بالطريق ، فقال : عليك بزيارة العاشوراء ولم أكن مستظهراً لها أيضاً والى الآن لا أقدر أن أقرأها من ظهر قلبي ، فنهضت وأخذت في قراءتها من ظهر القلب حتى انتهيت من اللّعن والسّلام ودعاء علقمة ، فعاد الرّجل إليّ وقال : ألم تنطلق؟ فأجبته انّي سأظل هنا الى الصّباح ، فقال لي : أنا الآن ألحقك بالقافلة ، فركب حماراً وحمل المسحاة على عاتقه وقال لي : اردف لي على ظهر الحمار ، فردفت له ، ثمّ سحبت عنان فرسي فقاومني ولم يجر معي ، فقال صاحبي : ناولني العنان . فناولته إيّاه ، فأخذ العنان بيمناه ووضع المسحاة على عاتقه الأيسر وأخذ في المسير فطاوعه الفرس أيسر المطاوعة، ثمّ وضع يده على ركبتي وقال : لماذا لا تؤدّون صلاة النّافلة النّافلة النّافلة، قالها ثلاث مرّات ، ثمّ قال أيضاً : لماذا تتركون زيارة عاشوراء } زيارة { عاشوراء } زيارة { عاشوراء كرّرها ثلاث مرّات ، ثمّ قال : لماذا لا تزورون بالزّيارة الجامعة } الكبيرة { الجامعة الجامعة الجامعة، وكان يدور في مسلكه واذا به يلتفت الى الوراء ويقول : اولئك، أصحابك قد وردوا النّهر يتوضّؤون لفريضة الصبح ، فنزلت من ظهر الحمار وأردت أن أركب فرسي ، فلم أتمكّن من ذلك فنزل هو من ظهر حماره وأقام المسحاة في الثّلج وأركبني فحوّل بالفرس الى جانب الصّحب وإذا بي يجول في خاطري السّؤال من عساه يكون هذا الذي ينطق باللغة الفارسيّة في منطقة التّرك اليسوعيّين؟ وكيف ألحقني بالصّحب خلال هذه الفترة القصيرة من الزّمان، فنظرت الى الوراء فلم أجد أحداً ولم أعثر على أثر يدلّ عليه فالتحقت بأصدقائي ."},{"type":"Text","content":"الزّيارة الثّالثة : ما جعلها العلامة المجلسي الثّامنة من الزّيارات الجامعة في كتابه تحفة الزائر ، وقال : هذه زيارة رواها السّيد ابن طاووس في خلال أدعية عرفة عن الصّادق صلوات الله عليه ويُزار بها في كلّ مكان وزمان لا سيّما في يوم عرفة وهي هذه الزّيارة :"},{"type":"Text","content":"اَلسَّلامُ عَلَيْكَ يا رَسُولَ اللهِ، اَلسَّلامُ عَلَيْكَ يا نَبِىَّ اللهِ، اَلسَّلامُ عَلَيْكَ يا خِيَرَةَ اللهِ مِنْ خَلْقِهِ وَاَمينَهُ عَلى وَحْيِهِ، اَلسَّلامُ عَلَيْكَ يا مَوْلاىَ يا اَميرَ الْمُؤْمِنينَ، اَلسَّلامُ عَلَيْكَ يا مَوْلاىَ، اَنْتَ حُجَّةُ اللهِ عَلى خَلْقِهِ وَبابُ عِلْمِهِ وَوَصِىُّ نَبِيِّهِ وَالْخَليفَةُ مِنْ بَعْدِهِ فى اُمَّتِهِ، لَعَنَ اللهُ اُمَّةً غَصَبَتْكَ حَقَّكَ وَقَعَدَتْ مَقْعَدَكَ، اَنَا بَريٌ مِنْهُمْ وَمِنْ شيعَتِهِمْ اِلَيْكَ، اَلسَّلامُ عَلَيْكِ يا فاطِمَةُ الْبَتُولُ، اَلسَّلامُ عَلَيْكِ يا زَيْنَ نِساءِ الْعالَمينَ، اَلسَّلامُ عَلَيْكِ يا بِنْتَ رَسُولِ اللهِ رَبِّ الْعالَمينَ صَلَّى اللهُ عَلَيكِ وَعَلَيْهِ، اَلسَّلامُ عَلَيْكِ يا اُمَّ الْحَسَنِ وَالْحُسَيْنِ، لَعَنَ اللهُ اُمَّةً غَصَبَتْكِ حَقَّكِ وَمَنَعَتْكِ ما جَعَلَهُ الله لَكِ حَلالاً، اَنَا بَريٌ اِلَيْكِ مِنْهُمْ وَمِنْ شيعَتِهِمْ، اَلسَّلامُ عَلَيْكَ يا مَوْلاىَ يا اَبا مُحَمَّد الْحَسَنِ الزَّكِىَّ، اَلسَّلامُ عَلَيْكَ يا مَوْلاىَ لَعَنَ اللهُ اُمَّةً قَتَلَتْكَ وَبايَعَتْ فى اَمْرِكَ وَشايَعَتْ اَنَا بَرئٌ اِلَيْكَ مِنْهُمْ وَمِنْ شيعَتِهِمْ، اَلسَّلامُ عَلَيْكَ يا مَوْلاىَ يا اَبا عَبْدَاللهِ الْحُسَيْنَ بْنَ عَلِىٍّ صَلَواتُ اللهِ عَلَيْكَ وَعَلى اَبيكَ وَجَدِّكَ مُحَمَّدٍ صَلَّى اللهُ عَلَيْهِ وَآلِهِ، لَعَنَ اللهُ اُمَّةً اسْتَحَلَّتْ دَمَكَ، وَلَعَنَ اللهُ اُمَّةً قَتَلَتْكَ وَاسْتَباحَتْ حَريمَكَ، وَلَعَنَ اللهُ اَشْياعَهُمْ وَاَتْباعَهُمْ، وَلَعَنَ اللهُ الْمُمَهِّدينَ لَهُمْ بِالَّتمْكينِ مِنْ قِتالِكُمْ، اَنَا بَرئٌ اِلَى اللهِ وَاِلَيْكَ مِنْهُمْ، اَلسَّلامُ عَلَيْكَ يا مَوْلاىَ يا اَبا مُحَمَّد عَلِىَّ بْنَ الْحُسَيْنِ، اَلسَّلامُ عَلَيْكَ يا مَوْلاىَ يا اَبا جَعْفَر مُحَمَّدَ بْنَ عَلِىٍّ، اَلسَّلامُ عَلَيْكَ يا مَوْلاىَ يا اَبا عَبْدِاللهِ جَعْفَرَ بْنَ مُحَمَّد، اَلسَّلامُ عَلَيْكَ يا مَوْلاىَ يا اَبَا الْحَسَنِ مُوسَى بْنَ جَعْفَر، اَلسَّلامُ عَلَيْكَ يا مَوْلاىَ يا اَبَا الْحَسَنِ عَلِىَّ بْنَ موُسى، اَلسَّلامُ عَلَيْكَ يا مَوْلاىَ يا اَبا جَعْفَر مُحَمَّدَ بْنَ عَلِىٍّ، اَلسَّلامُ عَلَيْكَ يا مَوْلاىَ يا اَبَا الْحَسَنِ عَلِىَّ بْنَ مُحَمَّد، اَلسَّلامُ عَلَيْكَ يا مَوْلاىَ يا اَبا مُحَمَّد الْحَسَنَ بْنَ عَلِىٍّ، اَلسَّلامُ عَلَيْكَ يا مَوْلاىَ يا اَبَا الْقاسِمِ مُحَمَّدَ بْنَ الْحَسَنِ صاحِبَ الزَّمانِ، صَلَّى اللهُ عَلَيْكَ وَعَلى عِتْرَتِكَ الطّاهِرَةِ الطَّيِّبَةِ، يا مَوالِىَّ كُونُوا شُفَعائي فى حَطِّ وِزْرى وَخَطاياىَ، آمَنْتُ بِاللهِ وَبِما اُنْزِلَ اِلَيْكُمْ، وَاَتَوالى آخِرَكُمْ بِما اَتَوالى اَوَّلَكُمْ، وَبَرِئْتُ مِنَ الْجِبْتِ وَالطّاغوُتِ وَاللاّتِ وَالْعُزّى، يا مَوالِىَّ اَنَا سِلْمٌ لِمَنْ سالَمَكُمْ، وَحَرْبٌ لِمَنْ حارَبَكُمْ، وَعَدُوٌّ لِمَنْ عاداكُمْ، وَوَلِىٌّ لِمَنْ والاكُمْ اِلى يَوْمِ الْقِيامَةِ وَلَعَنَ اللهُ ظالِميكُمْ وَغاصِبيكُمْ، وَلَعَنَ اللهُ اَشْياعَهُمْ وَاَتْباعَهُمْ وَاَهْلَ مَذْهَبِهِمْ، وَاَبْرَأُ اِلىَ اللهِ وَاِلَيْكُمْ مِنْهُمْ ."},{"type":"Text","content":"الزّيارة الرّابعة : هي الزّيارة المعروفة بزيارة أمين الله أوّلها اَلسَّلامُ عَلَيْكَ يا اَمينَ اللهِ فى اَرْضِهِ وَحُجَّتَهُ عَلى عِبادِهِ اَشْهَدُ اَنَّكَ جاهَدْتَ فِى اللهِ الى آخر ما مضى في زيارات الامير (عليه السلام) ، فنحن قد جعلناها الزّيارة الثّانية من زيارات امير المؤمنين (عليه السلام) ."},{"type":"Text","content":"الزّيارة الخامسة : زيارة اَلْحَمْدُ للهِ الَّذى اَشْهَدَنا مَشْهَدَ اَوْلِيآئِهِ فى رَجَب، الماضية في أعمال شهر رجب، فمجموع ما في هذا الكتاب من الزّيارات الجامعة يبلغ خمس زيارات وهي كافية إن شاء الله تعالى ."},{"type":"Text","content":"المقام الثّاني"}],"preview":"الزّيارة الأولى : روى الصّدوق في كتاب من لا يحضره الفقيه أنّه سئل الرّضا (عليه السلام) عن إتيان أبي الحسن موسى (عليه السلام) قال : صلّوا في المساجد حوله ويجزي في المواضِع كلّها (أي","hasTranslate":false},{"id":"mf_ar_263","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"قال السيد ابن طاووس : يستحبّ أن يدعى بهذا الدّعاء عقيب زيارات الائمة (عليهم السلام) :","blocks":[{"type":"Text","content":"اَللّـهُمَّ اِنْ كانَتْ ذُنوُبى قَدْ اَخْلَقَتْ وَجْهى عِنْدَكَ وَحَجَبَتْ دُعائى عَنْكَ وَحالَتْ بَيْنى وَبَيْنَكَ، فَاَسْاَلُكَ اَنْ تُقْبِلَ عَلَىَّ بِوَجْهِكَ الْكَريمِ وَتَنْشُرَ عَلَىَّ رَحْمَتَكَ وَتُنَزِّلَ عَلىَّ بَرَكاتِكَ، وَاِنْ كانَتْ قَدْ مَنَعَتْ اَنْ تَرْفَعَ لى اِلَيْكَ صَوتاً اَوْ تَغْفِرَ لى ذَنْباً اَوْ تَتَجاوَزَ عَنْ خَطيئَة مُهْلِكَة فَها اَنَاذا مُسْتَجيرٌ بِكَرَمِ وَجْهِكَ وَعِزِّ جَلالِكَ، مُتَوَسِّلٌ اِلَيْكَ مُتَقَرِّبٌ اِلَيْكَ بِاَحَبِّ خَلْقِكَ اِلَيْكَ وَاَكْرَمِهِمْ عَلَيْكَ وَاَوْلاهُمْ بِكَ، وَاَطْوَعِهِمْ لَكَ، وَاَعْظَمِهِمْ مَنْزِلَةً وَمَكاناً عِنْدَكَ مُحَمَّد، وَبِعِتْرَتِهِ الطّاهِرينَ الاَْئِمَّةِ الْهُداةِ الْمَهْدِيّينَ، الَّذينَ فَرَضْتَ عَلى خَلْقِكَ طاعَتَهُمْ وَاَمَرْتَ بِمَوَدَّتِهِمْ، وَجَعَلْتَهُمْ وُلاةَ الاَْمْرِ مِنْ بَعْدِ رَسُولِكَ صَلَّى اللهُ عَلَيْهِ وَآلِهِ، يا مُذِلَّ كُلِّ جَبّار عَنيد، وَيا مُعِزَّ الْمُؤْمِنينَ بَلَغَ مَجْهُودى فَهَبْ لى نَفْسِىَ السّاعَةَ وَرَحْمَةً مِنْكَ تَمُنُّ بِها عَلَىَّ يا اَرْحَمَ الرّاحِمينَ ."},{"type":"Text","content":"ثمّ قبّل الضّريح وضع خدّيك عليه وقُل :"},{"type":"Text","content":"اَللّـهُمَّ اِنَّ هذا مَشْهَدٌ لا يَرْجُو مَنْ فاتَتْهُ فيهِ رَحْمَتُكَ اَنْ يَنالَها فى غَيْرِهِ، وَلا اَحَدٌ اَشْقى مِنْ امْرِئ قَصَدَهُ مُؤَمِّلاً فَآبَ عَنْهُ خائِباً، اَللّـهُمَّ اِنّى اَعوُذُ بِكَ مِنْ شَرِّ الاِْيابِ وَخَيْبَةِ الْمُنْقَلَبِ وَالْمُناقَشَةِ عِنْدَ الْحِسابِ، وَحاشاكَ يا رَبِّ اَنْ تَقْرِنَ طاعَةَ وَلِيِّكَ بِطاعَتِكَ وَمُوالاتَهُ بِمُوالاتِكَ وَمَعْصِيَتَهُ بِمَعْصِيَتِكَ ثُمَّ تُؤْيِسْ زآئِرَهُ وَالْمُتَحَمِّلَ مِنْ بُعْدِ الْبِلادِ اِلى قَبْرِهِ، وَعِزَّتِكَ يا رَبِّ لا يَنْعَقِدُ عَلى ذلِكَ ضَميرى، اِذْ كانَتِ الْقُلُوبُ اِلَيْكَ بِالْجَميلِ تُشيرُ ."},{"type":"Text","content":"ثمّ صلّ للزّيارة ، فاذا شئت أن تودع وتنصرف فقُل : اَلسَّلامُ عَلَيْكُمْ يا اَهْلَ بَيْتِ النُّبُوَّةِ وَمَعْدِنَ الرِّسالَةِ سَلامَ مُوَدِّع لا سَئم وَلا قال وَرَحْمَةُ اللهِ وَبَرَكاتُهُ ."},{"type":"Text","content":"والشّيخ المفيد (رحمه الله) ايضاً قد ذكر هذا الدّعاء ولكنّه بعد كلمة (وبالجميل تشير) ، قال : ثمّ قل :"},{"type":"Text","content":"يا وَلِىَّ اللهِ اِنَّ بَيْنى وَبَيْنَ اللهِ عَزَوَجَلَّ ذُنوُباً لا يَأتى عَلَيْها اِلاّ رِضاكَ، فَبِحَقِّ مَنِ ائْتَمَنَكَ عَلى سِرِّهِ، وَاسْتَرْعاكَ اَمْرَ خَلْقِهِ، وَقَرَنَ طاعَتَكَ بِطاعَتِهِ، وَمُوالاتَكَ بِمُوالاتِهِ، تَوَلَّ صَلاحَ حالى مَعَ اللهِ عَزَّوَجَلَّ، وَاجْعَلْ حَظّى مِنْ زِيارَتِكَ تَخْليطى بِخالِصى زُوّارِكَ الَّذينَ تَسْأَلُ اللهَ عَزَّوَجَلَّ فى عِتْقِ رِقابِهِمْ، وَتَرْغَبُ اِلَيْهِ فى حُسْنِ ثَوابِهِمْ، وَها اَنَا الْيَوْمَ بِقَبْرِكَ لائِذٌ، وَبِحُسْنِ دِفاعِكَ عَنّى عائِذٌ، فَتَلافَنى يا مَوْلاىَ وَاَدْرِكْنى وَاَسْأَلِ اللهَ عَزَّوَجَلَّ فى اَمْرى، فَاِنَّ لَكَ عِنْدَاللهِ مَقاماً كَريماً وَجاهاً عَظيماً صَلَّى اللهُ عَلَيْكَ وَسَلَّمَ تَسْليماً ."},{"type":"AboutText","content":"أقول : الافضل للزّائر اذا أراد أن يدعو في مشهد من المشاهد الشّريفة بل الافضل للدّاعي أينما كان وأيّا ما كانت حاجته ، أن يبدأ بالدّعاء لصحّة حجّة العصر وصاحب الامر (عليه السلام) وهذا أمر هامّ ذا فوائد هامّة لا يناسب المقام شرحها والشّيخ (رحمه الله) قد بسط الكلام في ذلك في الباب العاشر من كتاب النّجم الثّاقب وذكر أدعية تخصّ المقام فليراجعه من شاء، وأخصر تلك الدّعوات هو ما مرّ في أعمال اللّيلة الثّالثة والعشرين من شهر رمضان في خلال أدعية العشر الاواخر ونحن قد أوردنا في خلال آداب زيارة الحسين (عليه السلام) دعاء يدعى به في كافّة المشاهد الشّريفة ."},{"type":"Text","content":"المقام الثّالث"}],"preview":"اَللّـهُمَّ اِنْ كانَتْ ذُنوُبى قَدْ اَخْلَقَتْ وَجْهى عِنْدَكَ وَحَجَبَتْ دُعائى عَنْكَ وَحالَتْ بَيْنى وَبَيْنَكَ، فَاَسْاَلُكَ اَنْ تُقْبِلَ عَلَىَّ بِوَجْهِكَ الْكَريمِ وَتَنْش","hasTranslate":false},{"id":"mf_ar_264","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"في ذكر الصّلوات على الحجج الطّاهرين )عليهم السلام(","blocks":[{"type":"AboutText","content":"قال الطّوسي في المصباح في خلال أعمال يوم الجمعة : أخبرنا جماعة من أصحابنا عن أبي المفضّل الشّيباني ، قال : حدّثنا أبو محمّد عبد الله بن محمّد العابد بالدالية لفظاً ، قال : سألت مولاي الامام الحسن العسكري (عليه السلام) في منزله بسرّ من رأى سنة خمس وخمسين ومائتين يملي عليّ الصّلاة على النّبي وأوصيائه (عليهم السلام) وأحضرت معي قرطاساً كبيراً، فأملى عليّ لفظاً من غير كتاب وقال : أكتب ."},{"type":"Text","content":"الصّلاة على النّبي (صلى الله عليه وآله وسلم("},{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلى مُحَمَّد كَما حَمَلَ وَحْيَكَ، وَبَلَّغَ رِسالاتِكَ، وَصَلِّ عَلى مُحَمَّد كَما اَحَلَّ حَلالَكَ، وَحَرَّمَ حَرامَكَ، وَعَلَّمَ كِتابَكَ، وَصَلِّ عَلى مُحَمَّد كَما اَقامَ الصَّلاةَ، وَآتَى الزَّكاةَ، وَدَعا اِلى دينِكَ، وَصَلِّ عَلى مُحَمَّد كَما صَدَّقَ بِوَعْدِكَ، وَاَشْفَقَ مِنْ وَعيدِكَ، وَصَلِّ عَلى مُحَمَّد كَما غَفَرْتَ بِهِ الذُّنُوبَ، وَسَتَرْتَ بِهِ الْعُيُوبَ وَفَرَّجْتَ بِهِ الْكُرُوبَ، وَصَلِّ عَلى مُحَمَّد كَما دَفَعْتَ بِهِ الشَّقاءَ، وَكَشَفْتَ بِهِ الْغَمّاءَ، وَاَجَبْتَ بِهِ الدُّعاءَ، وَنَجَّيْتَ بِهِ مِنَ الْبَلاءِ، وَصَلِّ عَلى مُحَمَّد كَما رَحِمْتَ بِهِ الْعِبادَ، وَاَحْيَيْتَ بِهِ الْبِلادَ، وَقَصَمْتَ بِهِ الْجَبابِرَةَ، وَاَهْلَكْتَ بِهِ الْفَراعِنَةَ، وَصَلِّ عَلى مُحَمَّد كَما اَضْعَفْتَ بِهِ الاَْمْوالَ، وَاَحْرَزْتَ بِهِ مِنَ الاَْهْوالِ، وَكَسَرْتَ بِهِ الاَْصْنامَ، وَرَحِمْتَ بِهِ الاَْنامَ، وَصَلِّ عَلى مُحَمَّد كَما بَعَثْتَهُ بِخَيْرِ الاَْدْيانِ، وَاَعْزَزْتَ بِهِ الاْيمانَ، وَتَبَّرْتَ بِهِ الاَْوْثانَ، وَعَظَّمْتَ بِهِ الْبَيْتَ الْحَرامَ، وَصَلِّ عَلى مُحَمَّد وَاَهْلِ بَيْتِهِ الطّاهِرينَ الاَْخْيارِ وَسَلِّمْ تَسْليماً ."}],"preview":"قال الطّوسي في المصباح في خلال أعمال يوم الجمعة : أخبرنا جماعة من أصحابنا عن أبي المفضّل الشّيباني ، قال : حدّثنا أبو محمّد عبد الله بن محمّد العابد بالدالية لفظاً ، قال : سألت مول","hasTranslate":false},{"id":"mf_ar_265","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"الصّلاة على أمير المؤمنين (عليه السلام(","blocks":[{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلى اَميرِ الْمُؤْمِنينَ عَلِىِّ بْنِ اَبى طالِب اَخى نَبِيِّكَ وَوَلِيِّهِ وَصَفِيِّهِ وَوَزيرِهِ، وَمُسْتَوْدَعِ عَلْمِهِ، وَمَوْضِعِ سِرِّهِ، وَبابِ حِكْمَتِهِ، وَالنّاطِقِ بِحُجَّتِهِ، وَالدّاعى اِلى شَريعَتِهِ، وَخَليفَتِهِ فى اُمَّتِهِ، وَمُفَرِّجِ الْكرْبِ عَنْ وَجْهِهِ، قاصِمِ الْكَفَرَةِ وَمُرْغِمِ الْفَجَرَةِ الَّذى جَعَلْتَهُ مِنْ نَبِيِّكَ بِمَنْزِلَةِ هاروُنَ مِنْ مُوسى، اَللّـهُمَّ والِ مَنْ والاهُ وَعادِ مَنْ عاداهُ، وَانْصُرْ مَنْ نَصَرَهُ، وَاخْذُلْ مَنْ خَذَلَهُ، وَالْعَنْ مَنْ نَصَبَ لَهُ مِنَ الاَْوَّلينَ وَالاْخِرينَ، وَصَلِّ عَلَيْهِ اَفْضَلَ ما صَلَّيْتَ عَلى اَحَد مِنْ اَوْصِياءِ اَنْبِيائِكَ يا رَبَّ الْعالَمينَ ."}],"preview":"اَللّـهُمَّ صَلِّ عَلى اَميرِ الْمُؤْمِنينَ عَلِىِّ بْنِ اَبى طالِب اَخى نَبِيِّكَ وَوَلِيِّهِ وَصَفِيِّهِ وَوَزيرِهِ، وَمُسْتَوْدَعِ عَلْمِهِ، وَمَوْضِعِ سِرِّهِ، وَبابِ حِكْمَتِه","hasTranslate":false},{"id":"mf_ar_266","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"الصّلاة على سيّدة النّساء فاطمة (عليها السلام(","blocks":[{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلَى الصِّدّيقَةِ فاطِمَةَ الزَّكِيَّةِ حَبيبَةِ حَبيبِكَ وَنَبِيِّكَ، وَاُمِّ اَحِبّائِكَ وَاَصْفِيائِكَ، الَّتِى انْتَجَبْتَها وَفَضَّلْتَها وَاخْتَرْتَها عَلى نِساءِ الْعالَمينَ، اَللّـهُمَّ كُنِ الطّالِبَ لَها مِمَّنْ ظَلَمَها وَاسْتَخَفَّ بِحَقِّها، وَكُنِ الثّائِرَ اَللّـهُمَّ بِدَمِ اَوْلادِها، اَللّـهُمَّ وَكَما جَعَلْتَها اُمَّ اَئِمَّةِ الْهُدى، وَحَليلَةَ صاحِبِ اللِّواءِ، وَالْكَريمَةَ عِنْدَ الْمَلاَءِ الاَْعْلى، فَصَلِّ عَلَيْها وَعَلى اُمِّها صَلاةً تُكْرِمُ بِها وَجْهَ أبيها مُحَمَّد صَلَّى اللهُ عَلَيْهِ وَآلِهِ، وَتُقِرُّ بِها اَعْيُنَ ذُرِّيَّتِها، وَاَبْلِغْهُمْ عَنّى فى هذِهِ السّاعَةِ اَفْضَلَ التَّحِيَّةِ وَالسَّلامِ ."}],"preview":"اَللّـهُمَّ صَلِّ عَلَى الصِّدّيقَةِ فاطِمَةَ الزَّكِيَّةِ حَبيبَةِ حَبيبِكَ وَنَبِيِّكَ، وَاُمِّ اَحِبّائِكَ وَاَصْفِيائِكَ، الَّتِى انْتَجَبْتَها وَفَضَّلْتَها وَاخْتَرْتَها عَلى","hasTranslate":false},{"id":"mf_ar_267","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"الصّلاة على الحسن والحسين (عليهما السلام(","blocks":[{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلَى الْحَسَنِ وَالْحُسَيْنِ عَبْدَيْكَ وَوَلِيَّيْكَ، وَابْنَىْ رَسُولِكَ، وَسِبْطَى الرَّحْمَةِ، وَسَيِّدَىْ شَبابِ اَهْلِ الْجَنَّةِ، اَفْضَلَ ما صَلَّيْتَ عَلى اَحَد مِنْ اَوْلادِ النَّبِيّينَ وَالْمُرْسَلينَ، اَللّـهُمَّ صَلِّ عَلَى الْحَسَنِ ابْنِ سَيِّدِ النَّبِيّينَ وَوَصِىِّ اَميرِ الْمُؤْمِنينَ، اَلسَّلامُ عَلَيْكَ يَا بْنَ رَسُولِ اللهِ، اَلسَّلامُ عَلَيْكَ يَا ابْنَ سَيِّدِ الْوَصِيّينَ، اَشْهَدُ اَنَّكَ يَا ابْنَ اَميرِ الْمُؤْمِنينَ اَمينُ اللهِ وَابْنُ اَمينِهِ، عِشْتَ مَظْلُوماً وَمَضَيْتَ شَهيداً، وَاَشْهَدُ اَنَّكَ الاِْمامُ الزَّكِىُّ الْهادِى الْمَهْدِىُّ، اَللّـهُمَّ صَلِّ عَلَيْهِ وَبَلِّغْ رُوحَهُ وَجَسَدَهُ عَنّى فى هذِهِ السّاعَةِ اَفْضَلَ التَّحِيَّةِ وَالسَّلامِ، اَللّـهُمَّ صَلِّ عَلَى الْحُسَيْنِ بْنِ عَلِىٍّ الْمَظْلُومِ الشَّهيدِ، قَتيلِ الْكَفَرَةِ وَطَريحِ الْفَجَرَةِ، اَلسَّلامُ عَلَيْكَ يا اَبا عَبْدِاللهِ، اَلسَّلامُ عَلَيْكَ يَا بْنَ رَسُولِ اللهِ، اَلسَّلامُ عَلَيْكَ يَا ابْنَ اَميرِ الْمُؤْمِنينَ اَشْهَدُ موُقِناً اَنَّكَ اَمينُ اللهِ وَابْنُ اَمينِهِ، قُتِلْتَ مَظْلُوماً وَمَضَيْتَ شَهيداً، وَاَشْهَدُ اَنَّ اللهَ تَعالى الطّالِبُ بِثارِكَ، وَمُنْجَزٌ ما وَعَدَكَ مِنَ النَّصْرِ وَالتَّاْييدِ فى هَلاكِ عَدُوِّكَ وَاِظْهارِ دَعْوَتِكَ، وَاَشْهَدُ اَنَّكَ وَفَيْتَ بِعَهْدِ اللهِ، وَجاهَدْتَ فى سَبيلِ، اللهِ وَعَبْدتَ اللهَ مُخْلِصاً حَتّى أتاكَ الْيَقينُ لَعَنَ اللهُ اُمَّةً قَتَلَتْكَ، وَلَعَنَ اللهُ اُمَّةً خَذَلَتْكَ، وَلَعَنَ اللهُ اُمَّةً اَلَبَّتْ عَلَيْكَ، وَاَبْرَأُ اِلَى اللهِ تَعالى مِمَّنْ اَكْذَبَكَ وَاسْتَخَفَّ بِحَقِّكَ وَاسْتَحَلَّ دَمَكَ، بِاَبى اَنْتَ وَاُمّى يا اَبا عَبْدِاللهِ لَعَنَ اللهُ قاتِلَكَ، وَلَعَنَ اللهُ خاذِلَكَ، وَلَعَنَ اللهُ مَنْ سَمِعَ وَاعِيَتَكَ فَلَمْ يُجِبْكَ وَلَمْ يَنْصُرْكَ، وَلَعَنَ اللهُ مَنْ سَبا نِساءَكَ اَنَا اِلَى اللهِ مِنْهُمْ بَرئٌ وَمِمَّنْ والاهُمْ وَمالاََهُمْ وَاَعانَهُمْ عَلَيْهِ، وَاَشْهَدُ اَنَّكَ وَالاَْئِمَّةَ مِنْ وُلْدِكَ كَلِمَةُ التَّقْوى وَبابُ الْهُدى وَالْعُرْوَةُ الْوُثْقى وَالْحُجَّةُ عَلى اَهْلِ الدُّنْيا، وَاَشْهَدُ اَنّى بِكُمْ مُؤْمِنٌ وَبِمَنْزِلَتِكُمْ موُقِنٌ، وَلَكُمْ تابِعٌ بِذاتِ نَفْسى وَشَرايِعِ دينى وَخَواتيمِ عَمَلى وَمُنْقَلَبى فى دُنْياىَ وَآخِرَتى ."}],"preview":"اَللّـهُمَّ صَلِّ عَلَى الْحَسَنِ وَالْحُسَيْنِ عَبْدَيْكَ وَوَلِيَّيْكَ، وَابْنَىْ رَسُولِكَ، وَسِبْطَى الرَّحْمَةِ، وَسَيِّدَىْ شَبابِ اَهْلِ الْجَنَّةِ، اَفْضَلَ ما صَلَّيْتَ عَ","hasTranslate":false},{"id":"mf_ar_268","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"الصّلاة على عليّ بن الحسين (عليهما السلام(","blocks":[{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلى عَلِىِّ بْنِ الْحُسَيْنِ سَيِّدِ الْعابِدينَ الَّذىِ اسْتَخْلَصْتَهُ لِنَفْسِكَ، وَجَعَلْتَ مِنْهُ اَئِمَّةَ الْهُدىَ الَّذينَ يَهدُونَ بِالْحَقِّ وَبِهِ يَعْدِلُونَ اخْتَرْتَهُ لِنَفْسِكَ، وَطَهَّرْتَهُ مِنَ الرِّجْسِ، وَاصْطَفَيْتَهُ وَجَعَلْتَهُ هادِياً مَهْدِيّاً، اَللّـهُمَّ فَصَلِّ عَلَيْهِ اَفْضَلَ ما صَلَّيْتَ عَلى اَحَد مِنْ ذُرِّيَةِ اَنْبِيائِكَ حَتّى تَبْلُغَ بِهِ ما تَقِرُّ بِهِ عَيْنُهُ فِى الدُّنْيا وَالاْخِرَةِ،اِنَّكَ عَزيزٌ حَكيمٌ ."}],"preview":"اَللّـهُمَّ صَلِّ عَلى عَلِىِّ بْنِ الْحُسَيْنِ سَيِّدِ الْعابِدينَ الَّذىِ اسْتَخْلَصْتَهُ لِنَفْسِكَ، وَجَعَلْتَ مِنْهُ اَئِمَّةَ الْهُدىَ الَّذينَ يَهدُونَ بِالْحَقِّ وَبِهِ يَع","hasTranslate":false},{"id":"mf_ar_269","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"الصّلاة على محمّد بن عليّ (عليهما السلام(","blocks":[{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلى مُحَمَّدِ بْنِ عَلِىٍّ، باقِرِ الْعِلْمِ وَاِمامِ الْهُدى، وَقائِدِ اَهْلِ التَّقْوى وَالْمُنْتَجَبِ مِنْ عِبادِكَ، اَللّـهُمَّ وَكَما جَعَلْتَهُ عَلَماً لِعِبادِكَ وَمَناراً لِبِلادِكَ، وَمُسْتَوْدَعاً لِحِكْمَتِكَ وَمُتَرْجِماً لِوَحْيِكَ، وَاَمَرْتَ بِطاعَتِهِ وَحَذَّرْتَ مِنْ مَعْصِيَتِهِ، فَصَلِّ عَلَيْهِ يا رَبِّ اَفْضَلَ ما صَلَّيْتَ عَلى اَحَد مِنْ ذُرِّيَةِ اَنْبِيائِكَ وَاَصْفِيائِكَ وَرُسُلِكَ وَاُمَنائِكَ يا رَبَّ الْعالَمينَ ."}],"preview":"اَللّـهُمَّ صَلِّ عَلى مُحَمَّدِ بْنِ عَلِىٍّ، باقِرِ الْعِلْمِ وَاِمامِ الْهُدى، وَقائِدِ اَهْلِ التَّقْوى وَالْمُنْتَجَبِ مِنْ عِبادِكَ، اَللّـهُمَّ وَكَما جَعَلْتَهُ عَلَماً لِع","hasTranslate":false},{"id":"mf_ar_270","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"الصّلاة على جعفر بن محمّد (عليهما السلام(","blocks":[{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلى جَعْفَرِ بْنِ مُحَمَّد الصّادِقِ، خازِنِ الْعِلْمِ، الدّاعى اِلَيْكَ بِالْحَقِّ، النُّورِ الْمُبينِ، اَللّـهُمَّ وَكَما جَعَلْتَهُ مَعْدِنَ كَلامِكَ وَوَحْيِكَ وَخازِنَ عِلْمِكَ وَلِسانَ تَوْحيدِكَ، وَوَلِىَّ اَمْرِكَ وَمُسْتَحْفِظَ دينِكَ، فَصَلِّ عَلَيْهِ اَفْضَلَ ما صَلَّيْتَ عَلى اَحَد مِنْ اَصْفِيائِكَ وَحُجَجِكَ اِنَّكَ حَميدٌ مَجيدٌ ."}],"preview":"اَللّـهُمَّ صَلِّ عَلى جَعْفَرِ بْنِ مُحَمَّد الصّادِقِ، خازِنِ الْعِلْمِ، الدّاعى اِلَيْكَ بِالْحَقِّ، النُّورِ الْمُبينِ، اَللّـهُمَّ وَكَما جَعَلْتَهُ مَعْدِنَ كَلامِكَ وَوَحْيِ","hasTranslate":false},{"id":"mf_ar_271","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"الصّلاة على موسى بن جعفر (عليهما السلام(","blocks":[{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلَى الاَْمينِ الْمُؤْتَمَنِ مُوسَى بْنِ جَعْفَر، الْبَرِّ الْوَفِىِّ الطّاهِرِ الزَّكِىِّ، النُّورِ الْمُبينِ الُْمجْتَهِدِ الُْمحْتَسِبِ، الصّابِرِ عَلَى الاَْذى فيكَ، اَللّـهُمَّ وَكَما بَلَّغَ عَنْ آبائِهِ مَا اسْتُوْدِعَ مِنْ اَمْرِكَ وَنَهْيِكَ، وَحَمَلَ عَلَى الَْمحَجَّةَ وَكابَدَ اَهْلَ الْعِزَّةِ وَالشِّدَّةِ فيما كانَ يَلْقى مِنْ جُهّالِ قَوْمِهِ، رَبِّ فَصَلِّ عَلَيْهِ اَفْضَلَ وَاَكْمَلَ ما صَلَّيْتَ عَلى اَحَد مِمَّنْ اَطاعَكَ وَنَصَحَ لِعِبادِكَ، اِنَّكَ غَفوُرٌ رَحيمٌ ."}],"preview":"اَللّـهُمَّ صَلِّ عَلَى الاَْمينِ الْمُؤْتَمَنِ مُوسَى بْنِ جَعْفَر، الْبَرِّ الْوَفِىِّ الطّاهِرِ الزَّكِىِّ، النُّورِ الْمُبينِ الُْمجْتَهِدِ الُْمحْتَسِبِ، الصّابِرِ عَلَى الاَْ","hasTranslate":false},{"id":"mf_ar_272","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"الصّلاة على عليّ بن موسى (عليهما السلام(","blocks":[{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلى عَلِىِّ بْنِ مُوسىَ الَّذِى ارْتَضَيْتَهُ وَرَضيتَ بِهِ مَنْ شِئْتَ مِنْ خَلْقِكَ، اَللّـهُمَّ وَكَما جَعَلْتَهُ حُجَّةً عَلى خَلْقِكَ وَقائِماً بِاَمْرِكَ وَناصِراً لِدينِكَ وَشاهِداً عَلى عِبادِكَ، وَكَما نَصَحَ لَهُمْ فِى السِّرِ وَالْعَلانِيَةِ وَدَعا اِلى سَبيلِكَ بِالْحِكْمَةِ وَالْمَوْعِظَةِ الْحَسَنَةِ، فَصَلِّ عَلَيْهِ اَفْضَلَ ما صَلَّيْتَ عَلى اَحَد مِنْ اَوْلِيآئِكَ وَخِيَرَتِكَ مِنْ خَلْقِكَ، اِنَّكَ جَوادٌ كَريمٌ ."},{"type":"Text","content":"الصّلاة على محمّد بن عليّ بن موسى (عليهم السلام("},{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلى مُحَمَّدِ بْنِ عَلِىِّ بْنِ مُوسى عَلَمِ التُّقى وَنُورِ الْهُدى، وَمَعْدِنِ الْوَفاءِ وَفَرْعِ الاَْزْكِياءِ، وَخَليفَةِ الاَْوْصِياءِ، وَاَمينِكَ عَلى وَحْيِكَ، اَللّـهُمَّ فَكَما هَدَيْتَ بِهِ مِنَ الضَّلالَةِ وَاسْتَنْقَذْتَ بِهِ مِنَ الْحَيْرَةِ، وَاَرْشَدْتَ بِهِ مِنْ اهْتَدى وَزَكَّيْتَ بِهِ مَنْ تَزَكّى، فَصَلِّ عَلَيْهِ اَفْضَلَ ما صَلَّيْتَ عَلى اَحَد مِنْ اَوْلِيائِكَ وَبَقِيَّةِ اَوْصِيائِكَ اِنَّكَ عَزيزٌ حَكيمٌ ."}],"preview":"اَللّـهُمَّ صَلِّ عَلى عَلِىِّ بْنِ مُوسىَ الَّذِى ارْتَضَيْتَهُ وَرَضيتَ بِهِ مَنْ شِئْتَ مِنْ خَلْقِكَ، اَللّـهُمَّ وَكَما جَعَلْتَهُ حُجَّةً عَلى خَلْقِكَ وَقائِماً بِاَمْرِكَ و","hasTranslate":false},{"id":"mf_ar_273","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"الصّلاة على عليّ بن محمّد (عليهما السلام(","blocks":[{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلى عَلِىِّ بْنِ مُحَمَّد، وَصِىِّ الاَْوْصِياءِ وَاِمامِ الاَْتْقِياءِ، وَخَلَفِ اَئِمَّةِ الدّينِ وَالْحُجَّةِ عَلَى الْخَلائِقِ اَجْمَعينَ، اَللّـهُمَّ كَما جَعَلْتَهُ نُوراً يَسْتَضيءُ بِهِ الْمُؤْمِنُونَ، فَبَشَّرَ بِالْجَزيلِ مِنْ ثَوابِكَ وَاَنْذَرَ بِالاَْليمِ مِنْ عِقابِكَ، وَحَذَّرَ بَأسَكَ وَذَكَّرَ بِاياتِكَ وَاَحَلَّ حَلالَكَ وَحَرَّمَ حَرامَكَ، وَبَيَّنَ شَرايِعَكَ وَفَرايِضَكَ، وَحَضَّ عَلى عِبادَتِكَ وَاَمَرَ بِطاعَتِكَ وَنَهى عَنْ مَعْصِيَتِكَ، فَصَلِّ عَلَيْهِ اَفْضَلَ ما صَلَّيْتَ عَلى اَحَد مِنْ اَوْلِيائِكَ وَذُرِّيَّةِ اَنْبِيائِكَ، يا اِلـهَ الْعالَمينَ ."},{"type":"AboutText","content":"قال الرّاوي أبو محمّد اليمني : فلمّا انتهيت الى الصّلاة عليه أمسك ، فقلت له في ذلك ، فقال : لو لا انّه دين أمرنا أن نبلغه ونؤدّيه الى أهله لاحببت الامساك ولكنّه الدّين ، أكتب به ."},{"type":"Text","content":"الصّلاة على الحسن بن عليّ بن محمّد (عليهم السلام("},{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلَى الْحَسَنِ بْنِ عَلِىِّ بْنِ مُحَمَّد، الْبَرِّ التَّقِىُّ الصّادِقِ الْوَفِىِّ، النُّورِ الْمُضيءِ خازِنِ عِلْمِكَ وَالْمُذَكِّرِ بِتَوْحيدِكَ، وَوَلِىِّ اَمْرِكَ وَخَلَفِ اَئِمَّةِ الدّينَ الْهُداةِ الرّاشِدينَ، وَالْحُجَّةِ عَلى اَهْلِ الدُّنْيا، فَصَلِّ عَلَيْهِ يا رَبِّ اَفْضَلَ ما صَلَّيْتَ عَلى اَحَد مِنْ اَصْفِيائِكَ وَحُجَجِكَ وَاَوْلادِ رُسُلِكَ، يا اِلـهَ الْعالَمينَ ."}],"preview":"اَللّـهُمَّ صَلِّ عَلى عَلِىِّ بْنِ مُحَمَّد، وَصِىِّ الاَْوْصِياءِ وَاِمامِ الاَْتْقِياءِ، وَخَلَفِ اَئِمَّةِ الدّينِ وَالْحُجَّةِ عَلَى الْخَلائِقِ اَجْمَعينَ، اَللّـهُمَّ كَما ج","hasTranslate":false},{"id":"mf_ar_274","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلبُ الثّاني : في الذّهاب الى المسجد الشّريف مسجد براثا والصّلاة فيه :","title":"الصّلاة على وليّ الامر المنتظر (عليه السلام(","blocks":[{"type":"Text","content":"اَللّـهُمَّ صَلِّ عَلى وَلِيِّكَ وَابْنِ اَوْلِيائِكَ الَّذينَ فَرَضْتَ طاعَتَهُمْ وَاَوْجَبْتَ حَقَّهُمْ وَاَذْهَبْتَ عَنْهُمُ الرِّجْسَ وَطَهَّرْتَهُمْ تَطْهيراً، اَللّـهُمَّ انْصُرْهُ وَانْتَصِرْ بِهِ لِدينِكَ وَانْصُرْ بِهِ اَوْلِياءَكَ وَاَوْلِياءَهُ وَشيعَتَهُ وَاَنْصارَهُ، وَاجْعَلْنا مِنْهُمْ، اَللّـهُمَّ اَعِذْهُ مِنْ شَرِّ كُلِّ باغ وَطاغ وَمِنْ شَرِّ جَميعِ خَلْقِكَ، وَاحْفُظْهُ مِنْ بَيْنِ يَديهِ وَمِنْ خَلْفِهِ وَعَنْ يَمينِهِ وَعَنْ شِمالِهِ، وَاحْرُسْهُ وَامْنَعْهُ اَنْ يوُصَلَ اِلَيْهِ بِسوُء، وَاحْفَظْ فيهِ رَسُولَكَ، وَآلِ رَسوُلِكَ وَاَظْهِرْ بِهِ الْعَدْلَ وَاَيِّدْهُ بِالنَّصْرِ، وَانْصُرْ ناصِريهِ وَاخْذُلْ خاذِليهِ، وَاقْصِمْ بِهِ جَبابِرَةَ الْكُفْرِ وَاقْتُلْ بِهِ الْكُفّارَ وَالْمُنافِقينَ وَجَميعَ الْمُلْحِدينَ حيثُ كانُوا مِنْ مَشارِقِ الاَْرْضَ وَمَغارِبِها وَبَرِّها وَبَحْرِها وَامْلاَْ بِهِ الاَْرْضِ عَدْلاً وَاَظْهِرْ بِهِ دينَ نَبِيِّكَ عَلَيْهِ وَآلِهِ السَّلامُ، وَاجْعَلْنِى اللّهُمَّ مِنْ اَنْصارِهِ وَاَعْوانِهِ وَاَتْباعِهِ وَشيعَتِهِ وَاَرِنى فى آلِ مُحَمَّد ما يَأمَلوُنَ وَفى عَدُوِّهُمْ ما يَحْذَرُونَ اِلـهَ الْحَقِّ آمينَ ."},{"type":"Text","content":"في زيارة الانبياء العظام (عليهم السلام) وابناء الائمة الكرام وقبور المؤمنين اسكنهم الله دار السّلام وتحتوي على مطالب ثلاثة :"}],"preview":"اَللّـهُمَّ صَلِّ عَلى وَلِيِّكَ وَابْنِ اَوْلِيائِكَ الَّذينَ فَرَضْتَ طاعَتَهُمْ وَاَوْجَبْتَ حَقَّهُمْ وَاَذْهَبْتَ عَنْهُمُ الرِّجْسَ وَطَهَّرْتَهُمْ تَطْهيراً، اَللّـهُمَّ انْ","hasTranslate":false},{"id":"mf_ar_275","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلب الاوّل :","title":"في زيارة الانبياء العظام (عليهم السلام(","blocks":[{"type":"AboutText","content":"اعلم انّ تكريم الانبياء (عليهم السلام) وتعظيمهم واجب عقلاً وشرعاً لا نفرّق بين أحد من رسله وزيارتهم راجحة مستحسنة والعلماء قد صرّحوا باستحباب زيارتهم وليس في الانبياء (عليهم السلام) وإن كثروا من يعرف موضع قبره الاّ القليلون وهم على ما أعهد آدم (عليه السلام) ، ونوح (عليه السلام) ، وهما مدفونان عند مرقد امير المؤمنين (عليه السلام) ، وابراهيم (عليه السلام) ، وقبره في القدس الخليل قُرب بيت المقدس وبجواره مراقد سارة زوجته واسحاق ويعقوب ويوسف (عليهم السلام) ، واسماعيل (عليه السلام) ، وامّه هاجر مدفونان في الحجر في المسجد الحرام وفيه قبور الانبياء (عليهم السلام) وعن الباقر (عليه السلام) قال : ما بين الركن والمقام مكتظ بقبور الانبياء ."},{"type":"AboutText","content":"وعن الصادق (عليه السلام) قال : ما بين الرّكن اليماني والحجر الاسود مراقد سبعين نبيّاً من الانبياء (عليهم السلام) ."},{"type":"Text","content":"وفي بيت المقدّس قبور عدّة من الانبياء كداوُد (عليه السلام) وسليمان وغيرهما من الانبياء المعروفين هناك سلام الله عليهم أجمعين، وقبر زكريّا (عليه السلام) معروف في حلب، وليونس (عليه السلام) على شريعة الكوفة بقعة ذات قبّة معروفة ، وقبرا هود (عليه السلام)وصالح (عليه السلام) في النّجف الاشرف مشهوران، ومرقد ذي الكفل على شاطئ الفرات مشهور ، وهو يبعد عن الكوفة . والنّبي جرجيس قبره مدينة الموصل ، وفي خارج المدينة قبر شيث هبة الله ، وقبر النّبي دانيال في شوش ، وقبر يوشع مقابل مسجد براثا وغيرهم سلام الله عليهم أجمعين، وأمّا كيفية زيارتهم (عليهم السلام) ، فلم أظفر بزيارة مأثورة تخصّهم عدا ما سلف في باب زيارة أمير المؤمنين (عليه السلام) من زيارة آدم ونوح (عليهما السلام) ، ولكن ما جعلناها الاولى من الزّيارات الجامعة يُزار بها الانبياء أيضاً (عليهم السلام) كما يبدو من روايتها ويشهد لذلك أن الشّيخ الجليل محمّد بن المشهدي والسّيد الاجلّ عليّ بن طاووس في مصباح الزّائر وغيرهما رضوان الله عليهم قد أوردوا هذه الزّيارة لمشهد يونس (عليه السلام) عند بيانهم آداب دخول مدينة الكوفة، والمظنون انّ ذكرهم هذه الزّيارة لهذا المشهد ليس الاّ لما يبدو من العموم من روايتها، وكيف كان فمن المناسب الزّيارة بها في المراقد الشّريفة للانبياء (صلى الله عليه وآله وسلم) وقد أثبتنا الزّيارة فيما سلف فلا حاجة الى اعادتها هنا فمن شاء فليرجع الى الزّيارة الجامعة الاولى وينتفع بفضلها العظيم ."}],"preview":"اعلم انّ تكريم الانبياء (عليهم السلام) وتعظيمهم واجب عقلاً وشرعاً لا نفرّق بين أحد من رسله وزيارتهم راجحة مستحسنة والعلماء قد صرّحوا باستحباب زيارتهم وليس في الانبياء (عليهم السلام","hasTranslate":false},{"id":"mf_ar_276","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلب الثّاني :","title":"في زيارة الابناء العظام للائمة (عليهم السلام)","blocks":[{"type":"Text","content":"وهم ابناء الملوك بالحقّ وقبورهم منابع الفيض والبركة ومهابط الرّحمة والعناية الالهيّة والعلماء قد صرّحوا باستحباب زيارة قبورهم وهي والحمد لله منتشرة في غالب بلاد الشّيعة بل وفي القرى والبراري واطراف الجبال والاودية وهي دائماً ملاذ المضطرّين وملجأ البائسين وغياث المظلومين وتسلية للقلوب الذّابلة وستضلّ كذلك الى يوم القيامة، وقد برز من كثير من هذه المراقد الشّريفة كرامات وخوارق للعادات ولكن لا يخفى انّ الزائر اذا شاء أن يشدّ الرّحل الى شيء من هذه المراقد موقناً ببلوغه فيض رحمة الله وبكشف كروبه فينبغي أن يحرز فيه شرطان :"},{"type":"Text","content":"الاوّل : جلالة صاحب ذلك المرقد وعظمة شأنه اضافة الى ما حازه من شرافة النّسب وتعرف هذه من كتب الاحاديث والانساب والتّواريخ ."},{"type":"Text","content":"الثّاني : التأكّد من صحّة نسبة هذا المرقد اليه، وما حاز كلا الشّرطين من المشاهد قليل جدّاً ونحن قد أشرنا في كتاب هديّة الزّائر الى عدّة مراقد قد اجتمع فيه الشّرطان واشرنا في كتاب نفثة المصدور وكتاب منتهى الامال الى مرقد محسن بن الحسين (عليه السلام) وهذا الكتاب لا يسع التّفصيل فنقتصر على ذكر اثنين منها :"},{"type":"Text","content":"الاوّل : مشهد السّيدة الجليلة العظيمة فاطمة بنت موسى بن جعفر (عليه السلام) وقبرها الشّريف في بلدة قم الطّيبة معروف مشهور وله قبّة شامخة وضريح وصحون وخدم كثيرون وأوقاف وافرة وهو قرّة العين لاهالي قم وملاذ لعامّة الخلق مما يشدّ اليه الرّحال في كلّ سنة خلق كثير من أقاصي البلاد فيتحمّلون متاعب السّفر ابتغاء فضيلة زيارتها وفضلها وجلالها يعرف من كثير من الاخبار ."},{"type":"Text","content":"روى الصّدوق بسند كالصّحيح عن سعد بن سعد ، قال : سألت الرّضا (عليه السلام) عن فاطمة بنت موسى بن جعفر (عليهما السلام) ، فقال : من زارها فله الجنّة ."},{"type":"AboutText","content":"وروى بسند معتبر آخر عن محمّد التّقي بن الرّضا (عليهما السلام) قال : من زار قبر عمّتي بقم فله الجنّة ."},{"type":"AboutText","content":"وروى العلامة المجلسي (رحمه الله) عن بعض كتب الزّيارات عن عليّ بن ابراهيم عن أبيه عن سعد الاشعريّ القميّ عن الرّضا صلوات الله عليه ، قال : قال : يا سعد عندكم لنا قبر ، قلت : جعلت فداك قبر فاطمة (عليها السلام)بنت موسى بن جعفر (عليه السلام) ، قال : بلى، من زارها عارفاً بحقّها فله الجنّة، فاذا أتيت القبر فقم عند رأسها مستقبل القبلة وقُل أربعاً وثلاثين مرّة اَللهُ اَكْبَرُ وثلاثاً وثلاثين مرّة سُبْحانَ اللهِ وثلاثاً وثلاثين مرّة اَلْحَمْدُ للهِ ثمّ قُل :"},{"type":"Text","content":"اَلسَّلامُ عَلى آدَمَ صَفْوَةِ اللهِ، اَلسَّلامُ عَلى نُوح نَبِىِّ اللهِ، اَلسَّلامُ عَلى اِبْراهيمَ خَليلِ اللهِ، اَلسَّلامُ عَلى مُوسى كَليمِ اللهِ، اَلسَّلامُ عَلى عيسى رُوحِ اللهِ، اَلسَّلامُ عَلَيْكَ يا رَسُولَ اللهِ، اَلسَّلامُ عَلَيْكَ يا خَيْرَ خَلْقِ اللهِ، اَلسَّلامُ عَلَيْكَ يا صَفِىَّ اللهِ، اَلسَّلامُ عَلَيْكَ يا مُحَمَّدَ بْنَ عَبْدِ اللهِ خاتَمَ النَّبِيّينَ، اَلسَّلامُ عَلَيْكَ يا اَميرَ الْمُؤْمِنينَ عَلِىَّ بْنَ اَبى طالِب وَصِىَّ رَسُولِ اللهِ، اَلسَّلامُ عَلَيْكِ يا فاطِمَةُ سَيِّدَةَ نِساءِ الْعالَمينَ، اَلسَّلامُ عَلَيْكُما يا سِبْطَىْ نَبِىِّ الرَّحْمَةِ وَسَيِّدَىْ شَبابِ اَهْلِ الْجَّنَةِ، اَلسَّلامُ عَلَيْكَ يا عَلىَّ بْنَ الْحُسَيْنِ سَيِّدَ الْعابِدينَ وَقُرَّةَ عَيْنِ النّاظِرينَ، اَلسَّلامُ عَلَيْكَ يا مُحَمَّدَ بْنَ عَلِىٍّ باقِرَ الْعِلْمِ بَعْدَ النَّبِىِّ، اَلسَّلامُ عَلَيْكَ يا جَعْفَرَ بْنَ مُحَمَّد الصّادِقَ الْبارَّ الاَْمينَ، اَلسَّلامُ عَلَيْكَ يا مُوسَى بْنَ جَعْفَر الطّاهِرَ الطُّهْرَ، اَلسَّلامُ عَلَيْكَ يا عَلِىَّ بْنَ مُوسَى الرِّضا الْمُرْتَضى، اَلسَّلامُ عَلَيْكَ يا مُحَمَّدَ بْنَ عَلِىٍّ التَّقِىَّ، اَلسَّلامُ عَلَيْكَ يا عَلِىَّ بْنَ مُحَمَّد النَّقِىَّ النّاصِحَ الاَْمينَ، اَلسَّلامُ عَلَيْكَ يا حَسَنَ بْنَ عَلِىٍّ، اَلسَّلامُ عَلَى الْوَصىِّ مِنْ بَعْدِهِ، اَللّـهُمَّ صَلِّ عَلى نُورِكَ وَسِراجِكَ وَوَلِىِّ وَلِيِّكَ وَوَصِىِّ وَصِيِّكَ، وَحُجَّتِكَ عَلى خَلْقِكَ، اَلسَّلامُ عَلَيْكِ يا بِنْتَ رَسُولِ اللهِ، اَلسَّلامُ عَلَيْكِ يا بِنْتَ فاطِمَةَ و خَديجَةَ، اَلسَّلامُ عَلَيْكِ يا بِنْتَ اَميرِالْمُؤْمِنينَ، اَلسَّلامُ عَلَيْكِ يا بِنْتَ الْحَسَنِ وَالْحُسَيْنِ، اَلسَّلامُ عَلَيْكِ يا بِنْتَ وَلِىِّ اللهِ اَلسَّلامُ عَلَيْكِ يا اُخْتَ وَلِىِّ اللهِ، اَلسَّلامُ عَلَيْكِ يا عَمَّةَ وَلِىِّ اللهِ، اَلسَّلامُ عَلَيْكِ يا بِنْتَ مُوسَى بْنِ جَعْفَر وَرَحْمَةُ اللهِ وَبَرَكاتُهُ، اَلسَّلامُ عَلَيْكِ عَرَّفَ اللهُ بَيْنَنا وَبَيْنَكُمْ فِى الْجَنَّةِ، وَحَشَرَنا فى زُمْرَتِكُمْ وَاَوْرَدَنا حَوْضَ نَبِيِّكُمْ، وَسَقانا بِكَأسِ جَدِّكُمْ مِنْ يَدِ عَلِىِّ بْنِ اَبى طالِب صَلَواتُ اللهِ عَلَيْكُمْ اَسْأَلُ اللهَ اَنْ يُرِيَنا فيكُمُ السُّرُورَ وَالْفَرَجَ، وَاَنْ يَجْمَعَنا وِاِيّاكُمْ فى زُمْرَةِ جَدِّكُمْ مُحَمَّد صَلَّى اللهُ عَلَيْهِ وَآلِهِ، وَاَنْ لا يَسْلُبَنا مَعْرِفَتَكُمْ اِنَّهُ وِلِىٌّ قَديرٌ، اَتَقَرَّبُ اِلَى اللهِ بِحُبِّكُمْ وَالْبَرائَةِ مِنْ اَعْدائِكُمْ، وَالتَّسْليمِ اِلَى اللهِ راضِياً بِهِ غَيْرَ مُنْكِر وَلا مُسْتَكْبِر وَعَلى يَقين ما اَتى بِهِ مُحَمَّدٌ وَبِهِ راض، نَطْلُبُ بِذلِكَ وَجْهَكَ يا سَيِّدى اَللّـهُمَّ وَرِضاكَ وَالدّارَ الاْخِرَةَ، يا فاطِمَةُ اشْفَعى لى فى الْجَنَّةِ فَاِنَّ لَكِ عِنْدَ اللهِ شَأناً مِنَ الشَّأنِ، اَللّـهُمَّ اِنّى اَسْاَلُكَ اَنْ تَخْتِمَ لى بِالسَّعادَةِ فَلا تَسْلُبْ مِنّى ما اَنـَا فيهِ وَلا حَوْلَ وَلا قُوَّةَ اِلاّ بِاللهِ الْعَلِىِّ الْعَظيمِ، اَللّـهُمَّ اسْتَجِبْ لَنا وَتَقَبَّلْهُ بِكَرَمِكَ وَعِزَّتِكَ وَبِرَحْمَتِكَ وَعافِيَتِكَ، وَصَلَّى اللهُ عَلى مُحَمَّد وَآلِهِ اَجْمَعينَ وَسَلَّمَ تَسْليماً يا اَرْحَمَ الرّاحِمينَ ."},{"type":"Text","content":"الثّاني : عبد العظيم } شاهزاده عبد العظيم { اللاّزم التعظيم وينتهي نسبه الشّريف بوسائط أربع الى سبط خير الورى الامام الحسن المجتبى (عليه السلام) فهو عبد العظيم بن عبد الله بن علي بن الحسن بن زيد بن الحسن بن عليّ بن أبي طالب (عليهم السلام) ومرقده الشّريف في الرّي معروف مشهور وملاذ ومعاذ لعامّة الخلق وعلوّ مقامه وجلالة شأنه أظهر من الشّمس، فانّه من سُلالة خاتم النّبيين وهو مع ذلك من أكابر المحدّثين وأعاظم العلماء والزّهاد والعبّاد وذوي الورع والتّقوى وهو من اصحاب الجواد والهادي (عليهما السلام) ، وكان متوسّلاً بهما أقصى درجات التّوسّل ومنقطعاً اليهما غاية الانقطاع . وقد روى عنهما أحاديث كثيرة وهو المؤلّف لكتاب «خطب أمير المؤمنين (عليه السلام)» وكتاب «اليوم والليلة» وهو الذي عرض دينه على امام زمانه الامام الهاديّ (عليه السلام) فاقره وصدّقه وقال : يا أبا القاسم هذا والله دين الله الّذي ارتضاه فاثبت عليه ثبّتَكَ الله بالقول الثّابت في الدّنيا والاخرة ."},{"type":"Text","content":"وقد ألّف الصاحب بن عبّاد رسالة وجيزة في أحواله وشيخنا ثقة الاسلام النّوري قد أورد الوجيزة في خاتمة كتاب المستدرك وروى هناك وفي كتاب الرّجال للنّجاشي انّه خاف من السّلطان فطاف بالبلدان على انّه فيج } الرّسول { ثمّ ورد الرّي وسكن بساربانان ، وعلى رواية النّجاشي : سكن سرباً في دار رجل من الشّيعة في سكة المولى وكان يعبد الله في ذلك السرب ويصوم نهاره ويقوم ليله وكان يخرج مستتراً يزور القبر المقابل قبره وبينها الطّريق ويقول : هو رجل من ولد موسى بن جعفر (عليهما السلام) فلم يزل يأوى الى ذلك السّرب ويقع خبره ا لى الواحد بعد الواحد من شيعة آل محمّد عليه وعليهم السلام حتّى عرفه أكثرهم فرأى رجل من الشّيعة في المنام رسول الله (صلى الله عليه وآله وسلم)قال له : انّ رجلاً من ولدي يحمل من سكة الموالي ويدفن عند شجرة التّفاح في باغ } بستان { عبد الجبّار بن عبد الوهّاب وأشار الى المكان الّذي دفن فيه، فذهب الرّجل ليشتري الشّجرة ومكانها من صاحبها ، فقال له : لايّ شيء تطلب الشّجرة ومكانها فأخبره بالرّؤيا ، فذكر صاحب الشّجرة انّه كان رأى مثل هذه الرؤيا وانّه جعل موضع الشّجرة مع جميع الباغ { البستان { وقفاً على الشّريف والشّيعة يدفنون فيه، فمرض عبد العظيم ومات (رحمه الله) ، فلمّا جرّد ليغسل وجد في جيبه رقعة فيها ذكر نسبه فاذا فيها أنا أبو القاسم عبد العظيم بن عبد الله بن عليّ بن الحسن بن زيد بن الحسن بن عليّ بن أبي طالب (عليهم السلام) ."},{"type":"Text","content":"وقال أيضاً الصّاحب بن عبّاد في وصف علم عبد العظيم انّه روى أبو تراب الروياني ، قال : سمعت أبا حماد الرّازي يقول : دخلت على الامام عليّ النّقي (عليه السلام) في سرّ من رأى فسألته عن أشياء من حلالي وحرامي ، فأجابني . فلمّا ودّعته قال لي : يا حماد اذا أشكل عليك شيء من أمور دينك بناحيتك أي في بلدة الرّي فسل عنه عبد العظيم بن عبد الله الحسني واقرأه منّي السّلام ."},{"type":"Text","content":"وقال المحقّق الدّاماد في كتاب الرّواشح انّ في فضل زيارة عبد العظيم روايات متظافرة ، وروى : انّ من زار قبره وجبت له الجنّة، وهذا الحديث رواه أيضاً الشّهيد الثّاني (رحمه الله) في حواشي الخلاصة عن بعض النسّابين ."},{"type":"AboutText","content":"وروى ابن بابويه وابن قولويه بسند معتبر عن رجل من أهل الرّي عن الامام عليّ النّقي صلوات الله عليه ، قال : دخلت عليه ، فقال : أين كنت ؟ فقلت : زُرت الحسين (عليه السلام) ، قال : أما لو انّك زرت قبر عبد العظيم (عليه السلام) عندكم لكنت كمن زار الحسين بن عليّ صلوات الله عليهما ."},{"type":"AboutText","content":"أقول : لم يذكر العلماء زيارة خاصّة وانّما قال فخر المحقّقين جمال الدّين في مزاره انّ من المناسب أن يُزار هكذا :"},{"type":"Text","content":"اَلسَّلامُ عَلى آدَمَ صَفْوَةِ اللهِ، اَلسَّلامُ عَلى نُوح نَبِىِّ اللهِ، اَلسَّلامُ عَلى اِبْراهيَم خَليلِ اللهِ، اَلسَّلامُ عَلى مُوسى كَليمِ اللهِ، اَلسَّلامُ عَلى عيسى رُوحِ اللهِ، اَلسَّلامُ عَلَيْكَ يا رَسُولَ اللهِ، اَلسَّلامُ عَلَيْكَ يا خَيْرَ خَلْقِ اللهِ، اَلسَّلامُ عَلَيْكَ يا صَفِىَّ اللهِ، اَلسَّلامُ عَلَيْكَ يا مُحَمَّدَ بْنَ عَبْدِ اللهِ خاتَمَ النَّبِيّينَ، اَلسَّلامُ عَلَيْكَ يا اَميرَ الْمُؤْمِنينَ عَلِىَّ بْنَ اَبى طالِب وَصِىَّ رَسُولِ اللهِ، اَلسَّلامُ عَلَيْكِ يا فاطِمَةُ سَيِّدَةَ نِساءِ الْعالَمينَ، اَلسَّلامُ عَلَيْكُما يا سِبْطَىِ الرَّحْمَةِ وَسَيَّدَىْ شَبابِ اَهْلِ الْجَنَّةِ، اَلسَّلامُ عَلَيْكَ يا عَلِىَّ بْنَ الْحُسَيْنِ سَيِّدَ الْعابِدينَ وَقُرَّةَ عَيْنِ النّاظِرينَ، اَلسَّلامُ عَلَيْكَ يا مُحَمَّدَ بْنَ عَلِىٍّ باقِرَ الْعِلْمِ بَعْدَ النَّبِىِّ، اَلسَّلامُ عَلَيْكَ يا جَعْفَرَ بْنَ مُحَمَّد الصّادِقَ الْبارَّ الاَْمينَ، اَلسَّلامُ عَلَيْكَ يا مُوسَى بْنَ جَعْفَر الطّاهِرِ الْطُّهْرِ اَلسَّلامُ عَلَيْكَ يا عَلِىَّ بْنَ مُوسَى الرِّضَا الْمُرْتَضى، اَلسَّلامُ عَلَيْكَ يا مُحَمَّدَ بْنَ عَلِىٍّ التَّقِىَّ، اَلسَّلامُ عَلَيْكَ يا عَلِىَّ بْنَ مُحَمَّد النِّقِىَّ النّاصِحَ الاَْمينَ، اَلسَّلامُ عَلَيْكَ يا حَسَنَ بْنَ عَلِىٍّ، اَلسَّلامُ عَلَى الْوَصِىِّ مِنْ بَعْدِهِ، اَللّـهُمَّ صَلِّ عَلى نُورِكَ وَسِراجِكَ وَوَلِىِّ وَلِيِّكَ وَوَصِىِّ وَصِيِّكَ وَحُجَّتِكَ عَلى خَلْقِكَ، اَلسَّلامُ عَلَيْكَ اَيُّهَا السَّيِّدُ الزَّكِىُّ وَالطّاهِرُ الصَّفِىُّ، اَلسَّلامُ عَلَيْكَ يَا بْنَ السّادَةِ الاَْطْهارِ، اَلسَّلامُ عَلَيْكَ يَا بْنَ الْمُصْطَفِيْنَ الاَْخْيارِ، اَلسَّلامُ عَلى رَسُولِ اللهِ و عَلى ذُرِّيَّةِ رَسُولِ اللهِ وَرَحْمَةُ اللهِ و بَرَكاتُهُ، اَلسَّلامُ عَلَى الْعَبْدِ الصّالِحِ الْمُطيعِ للهِ رَبِّ الْعالَمينَ وَلِرَسُولِهِ وَلاَِميرِ الْمُؤْمِنينَ، اَلسَّلامُ عَلَيْكَ يا اَبَا الْقاسِمِ ابْنَ السِّبْطِ الْمُنْتَجَبِ، الُْمجْتَبى السَّلامُ عَلَيْكَ يا مَنْ بِزِيارَتِهِ ثَوابُ زِيارَةِ سَيِّدِ الْشُّهَداءِ يُرْتَجى، اَلسَّلامُ عَلَيْكَ عَرَّفَ اللهُ بَيْنَنا وَبَيْنَكُمْ فى الْجَنَّةِ وَحَشَرَنا فى زُمْرَتِكُمْ، وَاَوْرَدَنا حَوْضَ نَبِيِّكُمْ وَسَقانا بِكَأسِ جَدِّكُمْ مِنْ يَدِ عَلِىِّ بْنِ اَبى طالِب صَلَواتُ اللهِ عَلَيكُمْ اَسْأَلُ اللهَ اَنْ يُرِيَنا فيكُمُ السُّرُورَ وَالْفَرَجَ، وَاَنْ يَجْمَعَنا وَاِيّاكُمْ فى زُمْرَةِ جَدِّكُمْ مُحَمَّد صَلَّى اللهُ عَلَيْهِ وَآلِهِ، وَاَنْ لا يَسْلُبَنا مَعْرِفَتَكُمْ اِنَّهُ وَلِىٌّ قَديرٌ، اَتَقَرَّبُ اِلَى اللهِ بِحُبِّكُمْ وَالْبَراءَةِ مِنْ اَعْدآئِكُمْ، وَالتَّسْليمِ اِلَى اللهِ راضِياً بِهِ غَيْرَ مُنْكِر وَلا مُسْتَكْبِر، وَعَلى يَقين مااَتى بِهِ مُحَمَّدٌ نَطْلُبُ بِذلِكَ وَجْهَكَ يا سَيِّدى اَللّـهُمَّ وَرِضاكَ وَالدّارَ الاْخِرَةِ يا سَيِّدى وَابْنَ سَيِّدى اِشْفَعْ لِى فِى الْجَنَّةِ فَاِنَّ لَكَ عِنْدَ اللهِ شَأناً مِنَ الشَّأنِ اَللّـهُمَّ اِنّى اَسْاَلُكَ اَنْ تَخْتِمَ لى بِالسَّعادَةِ فَلا تَسْلُبْ مِنّى ما اَنَا فيهِ وَلا حَوْلَ وَلا قُوَّةَ اِلاّ بِاللهِ الْعَلِىِّ الْعَظيمِ اَللّـهُمَّ اسْتَجِبْ لَنا وَتَقَبَّلْهُ بِكَرَمِكَ وَعِزَّتِكَ وَبِرَحْمَتِكَ وَعافِيَتِكَ وَصَلَّى اللهُ عَلى مُحَمَّد وَآلِهِ اَجْمَعينَ وَسَلَّمَ تَسْليماً يا اَرْحَمَ الرّاحِمينَ ."},{"type":"Text","content":"ثمّ قال المحقّق المذكور : ورد في بعض الاحاديث انّ عبد العظيم كان يخرج عند اقامته بالرّي مستتراً يزور القبر المقابل لقبره وبينهما الطّريق ويقول : هو رجل من ولد موسى بن جعفر (عليهما السلام) ونجد هناك في عصرنا قبراً ينسب الى حمزة بن الامام موسى (عليه السلام) ، والظاهر انّه القبر الذي كان يزوره عبد العظيم وينبغي زيارته ايضاً ان شاء الله ولا بأس بأن يزار بهذه الزّيارة الاّ انّه يحذف منها الجملة : اَلسَّلامُ عَلَيْكَ يا اَبَا الْقاسِمِ والجملة الّتي تليها ، انتهى ."},{"type":"Text","content":"لا يخفى عليك انّ قبر الشّيخ الجليل السّعيد قدوة المفسّرين جمال الدّين أبي الفتوح حسين بن علي الخزاعي (رحمه الله)صاحب التّفسير المعروف واقع في صحن حمزة (عليه السلام) وينبغي زيارته ، والشّيخ الصّدوق رئيس المحدّثين المعروف بابن بابويه قبره بقرب بلدة شاهزاده عبد العظيم فلا تغفل عن زيارته ايضاً ."},{"type":"Text","content":"روى الثّقة الجليل الشّيخ جعفر بن قولويه القمي عن عمرو بن عثمان الرّازي ، قال : سمعت أبا الحسن الامام موسى بن جعفر (عليهما السلام) يقول : من لم يقدر أن يزورنا فليزر صالحي موالينا يكتب له ثواب زيارتنا ، ومن لم يقدر على صلتنا فليصل صالحي موالينا يكتب له ثواب صلتنا ."},{"type":"AboutText","content":"وروى أيضاً بسند صحيح عن محمّد بن أحمد بن يحيى الاشعري قال : كنت بفيد (وهو اسم منزل في طريق مكة) فمشيت مع عليّ بن بلال الى قبر محمّد بن اسماعيل بن بزيع ، قال : فقال لي عليّ بن بلال : قال لي صاحب هذا القبر عن الرّضا (عليه السلام) ، قال : من أتى قبر أخيه المؤمن ثمّ وضع يده على القبر وقرأ (اِنّا اَنْزَلناهُ فى لَيْلَةِ الْقَدْرِ) سبع مرّات ، أمن يوم الفزع الاكبر . ومثله حديث آخر ولكن زاد فيه واستقبل القبلة ."},{"type":"AboutText","content":"أقول : ظاهر الحديث انّ الضّمير في قوله (عليه السلام) أمن يوم الفزع الاكبر راجع الى القاري نفسه ومن المحتمل رجوعه الى صاحب القبر ويؤيد هذا المعنى ما سيأتي من الرّواية عن السّيد ابن طاووس وروي أيضاً في كامل الزّيارة بسند معتبر عن عبد الرحمن بن أبي عبد الله قال : سألت الصّادق (عليه السلام) كيف أضع يدي على قبور المسلمين ؟ فأشار بيده الى الارض فوضعها عليها وهو مستقبل القبلة ."},{"type":"AboutText","content":"وروى أيضاً بسند صحيح عن عبد الله بن سنان قال : قلت للصّادق (عليه السلام) كيف أسلم على أهل القبور ؟ قال : نعم تقول: السَّلامُ على أهْلِ الدِّيار مِنَ المُؤمنين والمسلمين أنتم لنا فرط ونحن إن شاء الله بكم لا حقون ، وعن الحسين (عليه السلام) قال : من دخل المقابر فقال : اَللّـهُمَّ رَبَّ هذِهِ الاَْرْواحِ الْفانِيَةِ وَالاَْجْسادِ الْبالِيَةِ وَالْعِظامِ النَّخِرَةِ الَّتى خَرَجَتْ مِنَ الدُّنْيا وَهِىَ بِكَ مُؤْمِنَةٌ، اَدْخِلْ عَلَيْهِمْ رَوْحاً مِنْكَ وَسَلاماً مِنّى، كتب الله له بعدد الخلق من لدن آدم الى أن تقوم السّاعة حسنات . وعن عليّ (عليه السلام) قال : من دخل المقابر فقال : بِسْمِ اللهِ الرَّحْمنِ الرَّحيمِ،اَلسَّلامُ عَلى اَهْلِ لا اِلـهَ اِلاَّ اللهُ، مِنْ اَهْلِ لا اِلـهَ اِلاَّ اللهُ، يا اَهْلَ لا اِلـهَ اِلاَّ اللهُ، بِحَقِّ لا اِلـهَ اِلاَّ اللهُ، كَيْفَ وَجَدْتُمْ قَوْلَ لا اِلـهَ اِلاَّ اللهُ، مِنْ لا اِلـهَ اِلاَّ اللهُ، يا لا اِلـهَ اِلاَّ اللهُ، بِحَقِّ لا اِلـهَ اِلاَّ اللهُ، اغْفِرْ لِمَنْ قالَ لا اِلـهَ اِلاَّ اللهُ، وَاحْشُرْنا فى زُمْرَةِ مَنْ قالَ لا اِلـهَ اِلاَّ اللهُ، مُحَمَّدٌ رَسُولُ اللهِ عَلِىٌّ وَلِىُّ اللهِ، أعطاه الله سبحانه وتعالى ثواب خمسين سنة وكفّر عنه وعن أبويه سيّئات خمسين سنة ."},{"type":"AboutText","content":"وفي رواية اخرى انّ أحسن ما يقال في المقابر اذا مررت عليه أن تقف وتقول : اَللّـهُمَّ وَلِّهِمْ ما تَوَلَّوْا وَاحْشُرْهُمْ مَعَ مَنْ اَحَبُّوا ."},{"type":"Text","content":"وقال السّيد ابن طاووس في مصباح الزّائر : اذا أردت زيارة المؤمنين فينبغي أن يكون يوم الخميس والاّ ففي أيّ وقت شئت وصفتها أن تستقبل القبلة وتضع يدك على القبر وتقول : اَللّـهُمَّ ارْحَمْ غُرْبَتَهُ وَصِلْ وَحْدَتَهُ وَآنِسْ وَحْشَتَهُ وَآمِنْ رَوْعَتَهُ، وَاَسْكِنْ اِلَيْهِ مِنْ رَحْمَتِكَ رَحْمَةً يَسْتَغْنى بِها عَنْ رَحْمَةِ مَنْ سِواكَ، وَاَلْحِقْهُ بِمَنْ كانَ يَتَوَلاّهُ ثمّ اقرأ (اِنّا اَنْزَلْناهُ فى لَيْلَةِ الْقَدْرِ (سبع مرّات) ."},{"type":"Text","content":"وروي في صفة زيارتهم وثوابها حديث آخر عن فضيل قال : من قرأ اِنّا اَنْزَلْناهُ عند قبر مؤمن سبع مرّات بعث الله اليه ملكاً يبعد الله عند قبره ويكتب للميّت ثواب ما يعمل ذلك الملك فاذا بعثه الله من قبره لم يمر على هول الاّ صرفه الله عنه بذلك الملك حتّى يدخله الجنّة ويقرأ مع (اِنّا اَنْزَلْناهُ) سورة الحمد والمعوّذتين و (قُلْ هُوَ اللهُ اَحَدٌ) وآية الكرسي ثلاث مرّات كلّ سورة ."},{"type":"Text","content":"وروي أيضاً في صفة زيارتهم رواية أخرى عن محمّد بن مسلم قال : قلت للصّادق صلوات الله وسلامه عليه نزور الموتى قال : نعم ، قلت : فيعلمون بنا اذا أتيناهم ، قال : اي والله ليعلمون بكم ويفرحون بكم وليستأنسون اليكم ، قال : قلت : فأيّ شيء نقول اذا أتيناهم ؟ قال : قُل :"},{"type":"Text","content":"اَللّـهُمَّ جافِ الاَْرْضَ عَنْ جُنُوبِهِمْ، وَصاعِدْ اِلَيْكَ اَرْواحَهُمْ، وَلَقِّهِمْ مِنْكَ رِضْواناً، وَاَسْكِنْ اِلَيْهِمْ مِنْ رَحْمَتِكَ ما تَصِلُ بِهِ وَحْدَتَهُمْ وَتُونِسُ بِهِ وَحْشَتَهُمْ، اِنَّكَ عَلى كُلِّ شَىْء قَديرٌ ."},{"type":"Text","content":"ثم قال السّيد : فاذا كنت بين القبور فاقرأ (قُلْ هُوَ اللهُ اَحَدٌ) احدى عشر مرّة واهد ذلك لهم ، فقد روي انّ الله يثيبه على عدد الاموات ."},{"type":"Text","content":"وروي في كامل الزّيارة عن الصّادق (عليه السلام) قال : اذا زُرتم موتاكم قبل طلوع الشمس سمعوا وأجابوكم واذا زُرتموهم بعد طلوع الشمس سمعوا ولم يجيبوكم ."},{"type":"Text","content":"وقد روي في كتاب الدّعوات للرّاوندي حديث عن رسول الله (صلى الله عليه وآله وسلم) في كراهة زيارة الاموات ليلاً ، كما قال لابي ذر : ولا تزُرهم احياناً بالليل ."},{"type":"Text","content":"وروي في مجموعة الشّيخ الشّهيد عن رسول الله (صلى الله عليه وآله وسلم) قال : لا يقول أحد عند قبر ميّت ثلاث مرّات اَللّـهُمَّ اِنّى اَسْاَلُكَ بِحَقِّ مُحَمَّد وَآلِ مُحَمَّد اَنْ لا تُعَذِّبَ هـذَا الْمَيِّتَ الاّ واقصى الله عنه عذاب يوم القيامة ."},{"type":"AboutText","content":"وعن جامع الاخبار عن بعض أصحاب النّبي (صلى الله عليه وآله وسلم) قال : قال رسول الله (صلى الله عليه وآله وسلم) : اهدوا لموتاكم ، فقلنا : يا رسول الله وما نهدي الاموات ؟ قال : الصّدقة والدّعاء ، وقال : انّ أرواح المؤمنين تأتي كلّ جمعة الى السّماء الدّنيا بحذاء دورهم وبيوتهم ينادى كلّ واحد منهم بصوت حزين باكين : يا أهلي ويا ولدي ويا أبي ويا أمّي واقربائي اعطفوا علينا يرحمكم الله بالّذي كان في أيدينا والويل والحساب علينا والمنفعة لغيرنا، وينادي كلّ واحد منهم الى أقربائه : اعطفوا علينا بدرهم أو رغيف أو بكسوة يكسوكم الله من لباس الجنّة، ثمّ بكى النّبي (صلى الله عليه وآله وسلم) وبكينا معه ، فلم يستطع النّبي (صلى الله عليه وآله وسلم)أن يتكلّم من كثرة بكائه ، ثمّ قال (صلى الله عليه وآله وسلم) : اولئك اخوانكم في الدين فصاروا تراباً رميماً بعد السّرور والنعيم فينادون بالويل والثّبور على أنفسهم ، يقولون : يا ويلنا لو أنفقنا ما كان في أيدينا في طاعة الله ورضائه ما كنّا نحتاج اليكم ، فيرجعون بحسرة وندامة وينادون : أسرعوا صدقة الاموات ."},{"type":"Text","content":"وروي عنه أيضاً قال : ما تصدّقت لميّت فيأخذها ملك في طبق من نور ساطع ضوؤها يبلغ سبع سماوات ثمّ يقوم على شفير الخندق فينادي : اَلسَّلامُ عَلَيْكُمْ يا اَهْلَ الْقُبُورِ اهلكم اهدوا اليكم بهذه الهديّة ، فيأخذها ويدخل بها في قبره توسع عليه مضاجعه ، فقال (صلى الله عليه وآله وسلم) : ألا مَن أعطف لميّت بصدقة فله عند الله من الاجر مثل اُحُد ويكون يوم القيامة في ظلّ عرش الله يوم لا ظلّ الاّ ظلّ العرش وحيّ وميّت نجا بهذه الصّدقة ."},{"type":"Text","content":"وحكى انّ والي خراسان شوهد في المنام وهو يقول : ابعثوا اليّ ما تطرحونه الى الكلاب فانّي مفتقر اليه ."},{"type":"AboutText","content":"واعلم انّ لزيارة قبور المؤمنين أجراً جزيلاً وهي على ما له من جزيل الاجر ذات فوائد وآثار عظيمة فهي تورث العبرة والانتباه والزّهد والاعراض عن الدّنيا والرّغبة في الاخرة وينبغي زيارة المقابر اذا اشتدّ السّرور أو الغم . فالعاقل من اتّخذ المقابر عبرة ينزع بها حلاوة الدّنيا من قلبه ويحوّل شهدها مرّاً في ذائقته وتفكّر في فناء الدّنيا وتقلّب أحواله واستحضر بالبال انّه هو نفسه سيكون عمّا قريب مثلهم ويقصر يده عن الصّالحات ويكون عبرة لغيره ."}],"preview":"وهم ابناء الملوك بالحقّ وقبورهم منابع الفيض والبركة ومهابط الرّحمة والعناية الالهيّة والعلماء قد صرّحوا باستحباب زيارة قبورهم وهي والحمد لله منتشرة في غالب بلاد الشّيعة بل وفي القر","hasTranslate":false},{"id":"mf_ar_277","bookId":"الباب_الث_ال_ث_","book":"البابُ الثّالِثُ","section":"المطلب الثّالث : في زيارة قبور المؤمنين رضي الله عنهم أجمعين .","title":"ولقد أجاد الشّيخ النّظامي في قوله :","blocks":[{"type":"AboutText","content":"ومعنى الأبيات الفارسية هنا: إن الوقوف عند القبور يوقظ القلب ويبعث على العبرة، وإن مجاورة الصالحين تذكّر بفناء الدنيا وتدعو إلى حياة القلب والرجوع إلى الله."},{"type":"Text","content":"وَقُلْ اِنّى لاحِقٌ بِهِمْ فِى اللاّحِقينَ ."},{"type":"Text","content":"تمّ ما قدّر تسجيله في هذا الكتاب الشّريف ليلة الاحد الموافق عاشر شهر ذي القعدة الحرام سنة ألف وثلاثمائة وأربع وأربعين (1344) وهي ليلة ميلاد أبي الحسن الرّضا صلوات الله عليه وقد بلغني اليوم رسالة تنبئني بوفاة والدتي فلذلك أرجو من اخواني المؤمنين من انتفع منهم بهذا الكتاب الدّعاء والزّيارة لها رحمة الله وغفرانه عليها ولي ولوالدي في الحياة وبعد الممات والحمد لله أوّلاً وآخراً وصلّى الله على محمّد وآله الطّاهرين"}],"preview":"ومعنى الأبيات الفارسية هنا: إن الوقوف عند القبور يوقظ القلب ويبعث على العبرة، وإن مجاورة الصالحين تذكّر بفناء الدنيا وتدعو إلى حياة القلب والرجوع إلى الله.","hasTranslate":false}]};
